/**
 * Invokes the function when the jca framework is ready to layout objects.
 * This wraps the Ext.onReady and handles some issues with wizard steps such that the tables were
 * not rendering correctly.
 *
 * @see Ext.util.Observable.addListener for details about options
 * @param {Object} fn
 * @param {Object} scope
 * @param {options} options parameter (e.g. delay: number, once: true )
 */
PTC.onReady = function(fn, scope, options){
    if (PTC.isReady()) {
        fn();
        fn = null;
    } else {
        PTC.on('ready', fn, scope, options);
    }
};
/**
 * Check gecko engine used by browser
 * return true if detected browser uses a pre-Gecko 1.9 layout engine (e.g. Firefox 2.x, seamonkey on unix)
 * added this check for SPR #2068434 (workspace page load performance on unix)
 */
PTC.isOldGecko = function () {
  return (Ext.isGecko && Ext.isGecko2 && !Ext.isGecko3);
};
