PTC.isWindowLoaded = function() {
    if (PTC.windowLoaded) {
        return true;
    } 
    return false;
};

/**
 * Runs the specified function after the window load event fires. If the event has already
 * fired, runs the function immediately.<br/>
 * <br/>
 * The load event happens after all linked static assets have been loaded 
 * (images, css stylesheets, etc.). 
 */
PTC.onWindowLoad = function(fn) {
    if (PTC.windowLoaded) {
        fn();
    } else {
        Ext.EventManager.on(window, "load", fn);
    }
};

Ext.EventManager.on(window, "load", function() {
    PTC.windowLoaded = true;
});

