/**
 * @namespace PTC.log
 *
 * Base logger for all Windchill pages
 * Create your own logger as a sub package to the PTC package:
 * <pre>
 *   var mylogger = log4javascript.getLogger("PTC.mypackage");
 *   mylogger.trace("...");
 * </pre>
 *   See documentation on the log4javaScript website about the details and methods of the logger object:
 *   <a href="http://www.log4javacript.org">Log4Javascript</a>
 *
 */
PTC.log = {};
PTC.log = log4javascript.getLogger('PTC');
PTC.log.setLevel(log4javascript.Level.ERROR);
log4javascript.logLog.setQuietMode(true); // suppresses alert popups for some errors
var ajaxAppender = new log4javascript.AjaxAppender(getBaseHref() + 'ptc1/log4javascript');
ajaxAppender.setBatchSize(5);
ajaxAppender.setTimerInterval(8000);
ajaxAppender.setTimed(true);
ajaxAppender.setLayout(new log4javascript.JsonLayout());
PTC.log.addAppender(ajaxAppender);
PTC.log.ajaxAppender = ajaxAppender;
var appender = new log4javascript.BrowserConsoleAppender();
//need to up the threshold to see all level logs in the firefox console window (default threshold is DEBUG)
appender.setThreshold(log4javascript.Level.ALL);
PTC.log.addAppender(appender);

/**
 * Enabling PopupAppender will popup a "console" window to display logging.
 * But then anything logged at error level will popup a window.
 * Very useful for debugging issues in Creo,
 * but annoying in standalone browsers which already have good dev tools which are easily accessible.
 * And could be an unwanted popup for customers so not enabled unless jsDebug is enabled.
 */
PTC.log.enablePopupAppender = function() {
    var isCreo = isWf && isWf();
    //using getMainWindow() because isJsDebug function is only set correctly by shell.jsp
    if (isCreo && PTC.getMainWindow().PTC && PTC.getMainWindow().PTC.debug && PTC.getMainWindow().PTC.debug.isJsDebug()) {
        PTC.log.addAppender(new log4javascript.PopUpAppender());
    }
};

/**
 * Keep track of all the log levels, to allow entering them by name.
 */
log4javascript.Level.prototype.ALL_LEVELS = [log4javascript.Level.ALL, log4javascript.Level.TRACE, log4javascript.Level.DEBUG, log4javascript.Level.INFO, log4javascript.Level.WARN, log4javascript.Level.ERROR, log4javascript.Level.FATAL, log4javascript.Level.OFF];
/**
 * Extending the log package to get a level instance by its name
 * @param {String} name
 */
log4javascript.Level.getLevel = function(name){
    var logLevel = log4javascript.Level.TRACE;
    log4javascript.Level.prototype.ALL_LEVELS.each(function(item){
        if (item.name === name) {
            logLevel = item;
        }
    });
    return logLevel;
};

/**
 * Parse input string like PTC.navigation=TRACE for the Logger
 * @private
 * @param {String} str
 * @return {log4javascript.Logger} logger specified in the input
 */
PTC.log._getLoggerFromInputStr = function (str) {
    if (str.indexOf('=') >= 0) {
        str = str.substring(0, str.indexOf('='));
    }
    var logger = log4javascript.getLogger(str);
    return logger;
};

/**
 * Parse input string like PTC.navigation=TRACE for the Level object
 * @private
 * @param {String} str
 * @return {log4javascript.Level} level
 */
PTC.log._getLevelFromInputStr = function (str) {
    var level = log4javascript.Level.TRACE;
    if (str.indexOf('=') >= 0) {
        level = log4javascript.Level.getLevel(str.substring(str.indexOf('=') + 1));
    }
    return level;
};

/**
 * Sets the logger to the given log level, as defined by the input string
 * The default logger is PTC, and the default level is TRACE if they are not defined on the input
 *
 * @param {String} inputStr - typed in on window.prompt such as PTC.navigation=DEBUG
 */
PTC.log.startLogger = function (inputStr) {

    if (inputStr === null || inputStr === '') {
        inputStr = 'PTC';
    }
    var logger = PTC.log._getLoggerFromInputStr(inputStr);
    var level = PTC.log._getLevelFromInputStr(inputStr);
    logger.setLevel(level);
};

PTC.log.isChromeClientLoggerEnabled = function() {
    // For now, only Creo chrome enables Client logs
    // These logs are generated in debug.log located at /<rundir>/.ssvrd/<version>/CreoAgent folder
    // For standalone Chrome client logs are not yet enabled. This could be taken as backlog for radar team
    return Ext.isChrome && isWf();
};

/**
 * checks if it is an automation test running on Creo Chrome browser
 * and removes ajax appender from log4javascript logger.
 * Logs all remaining messages in other cases.
 */
PTC.log.sendAllMessages = function() {
    if(typeof PTC.automation !=='undefined' && PTC.automation.isAutomationTest() && PTC.log.isChromeClientLoggerEnabled()) {
        PTC.log.debug('remove AjaxAppender from JS logger');
        PTC.log.removeAppender(PTC.log.ajaxAppender);
    } else {
        if (PTC.log !== undefined && typeof PTC.log.ajaxAppender.sendAllRemaining !== 'undefined') {
           PTC.log.ajaxAppender.sendAllRemaining();
        }
    }
};

/**
 * checks to see if the given url has a jsLog parameter,
 * if it does the logging is enabled for PTC (or a comma separated list)
 * @example
 * &jsLog=true
 * &jsLog=PTC.navigation,PTC.automation
 *
 * Note that we want to leverage log4javascript hierarchical loggers support
 * (see http://log4javascript.org/docs/manual.html#loggers for more detail)
 * in the same way as we use hierarchical logger in log4j. This allows us to
 * limit as what JS package (or object) logs we want to see by enabling just
 * that log. Accordingly it's expected that all the logger namespaces start with a
 * root namespace object such as 'PTC'.
 *
 * @return true
 */
PTC.log.enableLogging = function(url) {
    var jsLogParam = extractParamValue(url, 'jsLog');
    jsLogParam = decodeURIComponent(jsLogParam);
    if (sessionStorage) {
        var jsLogFromSessionStorage = sessionStorage.getItem('jsLog');
        if(jsLogFromSessionStorage && jsLogFromSessionStorage !== jsLogParam) {
            jsLogFromSessionStorage = decodeURIComponent(jsLogFromSessionStorage);
            //Combine the two sets of loggers and remove dups
            var fromUrlArray = jsLogParam.split(/,/);
            var fromSessionArray = jsLogFromSessionStorage.split(/,/);
            fromSessionArray.each(function(theLogger) {
                if (fromUrlArray.indexOf(theLogger) < 0) {
                    fromUrlArray.push(theLogger);
                }
                jsLogParam = fromUrlArray.toString();
            });
        }
    }
    if (jsLogParam === '') {
        return true;
    } else {
        if (sessionStorage) {
            sessionStorage.setItem('jsLog', jsLogParam);
        }
        if(jsLogParam.indexOf("PTC") >= 0) {
            //assume its a comma separated list of logger names to turn on
            jsLogParam.split(/,/).each( function(loggerName) {
                // Show a warning message when logger namespace object name does not
                // begin with root namespace 'PTC.' Refer to jsdoc above for detail.
                if (loggerName.indexOf("PTC") !== 0) {
                    // temporarily set log level to warning so as to show this message as warning
                    var origLevel = PTC.log.getLevel();
                    PTC.log.setLevel(log4javascript.Level.WARN);
                    PTC.log.warn("logger name ", loggerName, " does not begin with root namespace 'PTC'? logging not enabled for it.");
                    PTC.log.setLevel(origLevel);
                }
                var logger = log4javascript.getLogger(loggerName); // Note that logs don't get written unless logger name begins with 'PTC'
                logger.setLevel(log4javascript.Level.TRACE);
                logger.info("turned on logger ", loggerName);
            });
        } else {
            //assume we turn on all PTC loggers
            var logger = log4javascript.getLogger('PTC');
            logger.setLevel(log4javascript.Level.TRACE);
            PTC.log.info("logger name(s) does not start with root namespace PTC?");
            PTC.log.info("turned on the PTC logger in that case");
        }
    }
    return true;
};

PTC.log._enableLogging = function() {
    PTC.log.enableLogging(getWindow().location.href);
    if ('navigation' in PTC) {
        PTC.navigation.on("historyChange", PTC.log.enableLogging);
    } else {
        PTC.onReady(function() {
            PTC.navigation.on("historyChange", PTC.log.enableLogging);
        });
    }
};

if ('log4javascript' in window) {
    // if log4javascript has already been loaded, enable logging now itself
    // so that logging for prior queued onready event handlers works.
    PTC.log._enableLogging();
} else {
    PTC.onReady(PTC.log._enableLogging);
}


/**
 * This file is ONLY for small snippets of code that cause the jslint tool to fail. This file should stay as small
 * as possible--it is only in existence to allow our other files to pass jslint validation.
 * Before adding anything to this file, make sure you cannot write your code another way.
 * @namespace
 */
PTC.jslint = {};

/**
 * constant which elsewhere causes the "Script URL" jslint error
 */
PTC.jslint.SCRIPT_URL_STRING = "javascript:";

PTC.jslint.allowNamespaceRegEx = /^(?:([\[\{])(?:@)?([\w-]+(?:\:[\w-]+))\s?(?:(=|.=)\s?['"]?(.*?)["']?)?[\]\}])/;

/**
 * This function helps to avoid the jslint error "This is better written in dot notation".
 * Of course, before using this fuction, you should attempt to fix the statement to use dot notation instead
 * 
 * @example
 *  PTC.jslint.betterWrittenInDotNotation(Ext.Ajax.defaultHeaders, 'Accept-Language') = getLocale();
 *  var errorMsg = PTC.jslint.betterWrittenInDotNotation(cache,'com.ptc.core.ui.navigationRB.UNABLE_TO_CONNECT');
 *  
 * @param {Array} obj object to retrieve a value from
 * @param {string} key property to retrieve
 * @return value of key in object
 */
PTC.jslint.betterWrittenInDotNotation = function(obj, key) {
    return obj[key];
};

/**
 * This function helps avoid the jslint error "Do not use the String function as a constructor."
 * This should only be used when there needs to be a new string object created.
 * 
 * @example
 *   if (typeof data === 'string') {
 *      data = PTC.jslint.newString(data);
 *   }
 *   
 * @param {string} str string to be created
 * @return new String object
 */
PTC.jslint.doNotUseStringFunctionAsConstructor = function(str) {
    return (new String(str));
};

/**
 * This functions helps avoid the following errors: "Expected an identifier and instead saw 'eval' (a reserved word)."
 * and "eval is evil"
 * 
 * @example
 * if: PTC.navigation_this.eval(text);, instead use: PTC.jslint.foundEvalReservedWord(text,PTC.navigation_this);
 * PTC.jslint.foundEvalReservedWord(string);
 * 
 * @param {string} str String to call eval on
 * @param {Object} [context] Optional
 * @return return of the evaled script
 */
PTC.jslint.foundEvalReservedWord = function(str, context) {
    if (context) {
        return context.eval(str);
    } else {
        return eval(str);
    }
};



