  function replaceAll(s, findString, replaceString) {
     var st = s;
     if (findString.length === 0) {
         return st;
     }
     var idx = st.indexOf(findString);
     while (idx >= 0) {
        st = st.substring(0,idx) + replaceString + st.substr(idx+findString.length);
        idx = st.indexOf(findString);
     }
     return st;
  }

