  function newHiddenInputElement(name, value, form){
     var parentDoc = document;
     if (form && form.ownerDocument) {
        parentDoc = form.ownerDocument;
     }

     var hiddenInput = parentDoc.createElement("INPUT");
     hiddenInput.id = name;
     hiddenInput.name = name;
     hiddenInput.type = "hidden";
     hiddenInput.value = value;
     return hiddenInput;
  }
  var JCAnewHiddenInputElement = newHiddenInputElement;

  function appendFormHiddenInput(form, name, value){
      /**
       * @private
       * SPR 2105572: the "=" sign is not required if the value is empty string, eg. "...&u8=1&cscontext"
       * @param {Object} value the value for a html input field or form val
       */
      function getNonNullValue(value){
          return (value !== null && value !== "null" && value !== undefined && value !== 'undefined') ? value : "";
      }

      if (form) {
          if (name === null || name === "null") {
              return;
          }
          // Only append if the hidden element does not
          // already exist in the form
          // If it does then just reset value.
          var targetel = form[name];
          if (targetel && (targetel.tagName || targetel.tagName === '') && targetel.tagName === 'INPUT') {

              targetel.setAttribute("name", name);
              targetel.setAttribute("value", getNonNullValue(value));
              return targetel;
          }
          else {
              var hiddenInput = JCAnewHiddenInputElement(name, getNonNullValue(value), form);
              if (form.appendChild) {
                  form.appendChild(hiddenInput);
              } else {
                  PTC.util.log.error('appendFormHiddenInput(): invalid form (missing appendChild function)');                  
              }
              return hiddenInput;
          }
      }
      else {
          throw new Error("Implementation ERROR: invalid form");
      }
  }

  var JCAappendFormHiddenInput = appendFormHiddenInput;

  // Extract string from fromString between start_mark and end_mark
  function extractString(fromString, start_mark, end_mark){
      var result = "";
      var index1 = fromString.indexOf(start_mark);
      var index2 = fromString.indexOf(end_mark);
      if (index1 >= 0 && index2 > 0) {
          result = fromString.substring(index1 + start_mark.length, index2);
      }
      return result;
  }

