/**
 * gets the localized string, unescapes the quot and puts the inserts in.
 * @param {String} key - example -
 * @param {Array} inserts - the array of inserts to replace the {n} parameters with
 *
 * @example
 * bundleHandler.getBundleStringAndInserts("com.ptc.core.ui.navigationRB.INFO_PAGE_NEW_TAB", new Array("1"));
 */
bundleHandler.getBundleStringAndInserts = function(key, inserts){
    var alertmess = bundleHandler.get(key);
    if (inserts && inserts.length > 0) {
        var inserts_length = inserts.length;
        for (var i = 0; i < inserts_length; i++) {
            alertmess = alertmess.replace("{" + i + "}", inserts[i]);
        }
    }
    alertmess = alertmess.gsub('&quot;', '"');
    return alertmess;
};

/**
 * @deprecated replaced by bundleHandler.getBundleStringAndInserts
 * @see bundleHandler.getBundleStringAndInserts
 */
getBundleStringAndInserts = bundleHandler.getBundleStringAndInserts;

/**
 * @param {String} key - the rbInfo key to use to get the localized value (e.g. "com.ptc.core.ui.tableRB.DEFAULT_TABLE_VIEW_NAME")
 * @param {Array} namesArray - the current names already in use
 * @return the first name not already in use (e.g. returns "User View 2" if "User View 1" is already in the names)
 */
bundleHandler.getUniqueName = function(key, namesArray){
    var result = null;
    if (namesArray) {
        var index = 0;
        var tempName;
        var arrayString = namesArray.toString().toLowerCase();
        /*
         * arrayString is formated back with single quote and double quote as below before indexOf called because
         * tempName will have name including single quote and double quote.
         */
        arrayString = arrayString.replace(/&#39;/g, "'").replace(/&quot;/g, '"');
        while (index < 999 && result === null) {
            index++;
            tempName = getBundleStringAndInserts(key, ["" + index]);
            if (arrayString.indexOf(tempName.toLowerCase()) < 0) {
                result = tempName;
            }
        }
    }
    return result;
};

/**
 * Returns the first mainform found as a parent of the given domElementId
 * If no domElementId is given, returns first mainform found as parent of MAINFORM_STARTING_DOM_ELEMENT
 * If MAINFORM_STARTING_DOM_ELEMENT is not defined, returns the first mainform found in the dom
 *
 * MAINFORM_STARTING_DOM_ELEMENT gets updated each time the context menu is opened on a table.
 *
 * @param {Object} [domElement] Optional child of the mainform either dom element itself or dom element id. Use to ensure the right mainform is returned.
 *                   For example, the info page rendering code uses getMainForm('infoPageDivID') to ensure the info page's mainform is returned
 */
function getMainForm(domElement){
    PTC.mainform.debug("begin getMainForm() MAINFORM_STARTING_DOM_ELEMENT ID: ", MAINFORM_STARTING_DOM_ELEMENT?MAINFORM_STARTING_DOM_ELEMENT.id:null, " domElement id: ", domElement?domElement.id:null);
    if(!document.body) {
        PTC.mainform.error("getMainForm() called before DOM was loaded, code should be wrapped in PTC.onReady() ");
        return undefined;
    }
    var startingElement = domElement ? domElement : MAINFORM_STARTING_DOM_ELEMENT;
    var mform;
    if (startingElement) {
        mform = PTC.util.getForm(startingElement);
    }

    if (mform === undefined) {
        // first try to get the form from getWindow() function
        var win = getWindow();
        if (win && win.document && win.document.forms) {
            mform = win.document.forms.mainform;
        }
    }
    if (mform === undefined) {
        // then try to get the form from window variable
        if (window && window.document && window.document.forms) {
            mform = window.document.forms.mainform;
        }
    }
    if (mform && mform[0] !== undefined && mform[0].action !== undefined) {
        // will need to change this based on the current panel, for now need to keep page from breaking
        mform = mform[0];
    }

   //For TP pages, there is no PTC.nonce value, capture its version in our own
    if (!PTC.nonce && 'csrf_nonce' in window) {
        PTC.nonce = csrf_nonce;
    }

    //mainform may not exist at all, for example in a GWT popup app that launches a JCAAction
    //in that case make a form on the fly
    if (mform === undefined) {
        mform = PTC.util.getMainformDummy();
    }
    //setting an action so PTC.navigation.reload() would work for this form - SPR 1842606
    var formAction = PTC.util.getFormAction(mform);
    if(!formAction) {
        PTC.util.setFormAction(mform, getWindow().location.href);
    }
    //If the main form somehow lost its nonce, add it back
    if (!mform.CSRF_NONCE || !mform.CSRF_NONCE.value) {
        if (!mform.CSRF_NONCE || !(mform.CSRF_NONCE[0] && mform.CSRF_NONCE[0].value)) {
            JCAappendFormHiddenInput(mform, "CSRF_NONCE", PTC.nonce);
        }
    }

    PTC.mainform.debug("end getMainForm() returning form: ", mform?mform.name:null);

    return mform;
}

/**
 * Gets a "dummy" mainform.
 * If a "mainformDummy" form already exists, it is returned.  
 * Otherwise a new "mainformDummy" form is created and a new
 * CSRF_NONCE hidden input (with the current PTC.nonce value) is added to it .
 * @param {Object} form Optional current mainform if available.
 * @return the dummy mainform.
 * @private
 */
 PTC.util.getMainformDummy = function(form) {
     mform = $("mainformDummy");
     if (!mform) {
        mform = window.document.createElement("FORM");
        mform.setAttribute("name", "mainformDummy");
        mform.setAttribute("id", "mainformDummy");
        mform.setAttribute("method", "POST");
        var parent = $(PTC.navigation.activeContentID) ? $(PTC.navigation.activeContentID) : document.body;
        parent.appendChild(mform);
        JCAappendFormHiddenInput(mform, "CSRF_NONCE", PTC.nonce);
     }
     // check if there is a passed-in form and if it has a windowNameForCookie field
     if (form && form.windowNameForCookie) {
         // add the windowNameForCookie in case this is a wizard so the correct window size & location are retrieved
         JCAappendFormHiddenInput(mform, "windowNameForCookie", form.windowNameForCookie.value);
     }
     return mform;
};

