/**
 * Evals the given html string without executing any script blocks strings that might be in HTML values/tooltips.
 *
 * @param {String} html
 */
PTC.util._evalHTML = function(html) {
    try {
        var div = document.createElement('div');
        //the '_' is required to workaround IE NoScope issue, see unit test
        div.innerHTML = '_'+html;
        var children = div.children;
        for(var i=0,l=children.length;i<l;i++) {
            var child = children[i];
            if(child && child.tagName === 'SCRIPT') {
                eval(child.innerHTML);
            }
        }
    } catch(e) {
        PTC.util.log.error('Error in _evalHTML ', e);
    }
};

