/**
 * Will deep clone an object.
 * Note that prototype will only do shallow clone.
 * @param {Object} obj
 */
function JCAClone(obj) {
    if (obj === null || typeof(obj) !== 'object') {
        return obj;
    }

    var temp;
    if (typeof obj.constructor === 'function') {
        temp = new obj.constructor();
    }
    else {  // IE basic type from JSON.parse have constructor of 'object'
       if (isArray(obj)) {
           temp = [];
       }
       else {
          temp = {};
       }
    }

    for (var property in obj) {
        if (obj.hasOwnProperty(property)) {
            temp[property] = JCAClone(obj[property]);
        }
    }
    return temp;
}
/**
 * Utility function to add generic loggers to an object
 *   i.e.  PTC.util.addFuncWrapper( PTC.navigation, PTC.util.addTimeWrapper);
 * @param {Object} obj
 * @param {Object} func
 */
    PTC.util.addFuncWrapper = function(obj, func){
        for (var key in obj) {
            if (typeof obj[key] === "function") {
                func(obj, key);
            }
        }
    };

    /**
     * Logs the time it takes for each method call on the object.
     * @param {Object} obj
     * @param {Object} key
     */
    PTC.util.addTimeWrapper = function(obj, key){
        obj[key] = obj[key].wrap(function(proceed){
            var start = (new Date()).getTime();
            try {
                return proceed.apply(this, $A(arguments).slice(1));
            }
            finally {
                var end = (new Date()).getTime();
                jsca.log(key, 'took', (end - start), 'ms');
            }
        });
    };
    /**
     * adds a log statement at the beginning and end of each method call on the object passed in.
     * @param {Object} obj
     * @param {Object} key
     */
    PTC.util.addLoggingWrapper = function(obj, key){
        obj[key] = obj[key].wrap(function(proceed){
            jsca.log('starting function ', key);
            try {
                return proceed.apply(this, $A(arguments).slice(1));
            }
            finally {
                jsca.log('end funciton ', key);
            }
        });
    };

    /**
     * Add the param from the MainForm to the params map, only will add if the value is not null, not empty
     * @param {String} name
     * @param {Object} params
     */
    PTC.util.addFormParam = function(name, params){
        var mform = getMainForm();
        if (mform === undefined || params === undefined) {
            return;
        }

        var names = mform[name];
        if (names === undefined || params[name]!== undefined) {
            return;
        }
        if (names.length>0) {
           names = names[0];
        }
        if (names.value !== undefined && names.value !== '') {
            // Only add operations param if its in the form in a valid way, it  may be an array
            params[name] = names.value;
        }
    };


/**
 * Returns the given function wrapped with a delayed Task.  This causes all calls to the function to be both delayed and to
 * occur just 1 time when many calls are made in quick succession.
 * Be very careful about redifining global functions if they can apply to different objects.  For example if a global function
 * can update any table on the page, if it gets 2 calls, one for each table then only 1 of the tables will be udpated.  In that case
 * it works better to create a table specific function that gets called instead.
 * @see Ext.util.DelayedTask
 * @param {Function} func
 * @param {long} delay
 */
PTC.util.delayAllCalls = function(func, delay){
    if (delay === undefined) {
       delay = 100;
    }
    func = func.wrap(function(proceed,a,b,c,d,e,f,g){
        if (func.task === undefined) {
            func.task = new Ext.util.DelayedTask(proceed);
        }
        if (arguments.length > 7) {
            func.task.delay(delay, proceed, this, $A(arguments).slice(1));
        }
        else {
            // Mozilla runs faster without using $A, even though we've optimized $A a bit
            func.task.delay(delay, proceed, this, [a,b,c,d,e,f,g]);
        }
    });
    return func;
};

/**
 * Replaces the current page url with a new one without reloading the page.
 * If the url is the same as the current token, no url replacement will be done
 *
 * @param {String} newUrl the new url to specify
 *
 */

PTC.util.replaceURLNoReload = function(newUrl) {
    // Prevent the page reloading, as we've already updated the relevant portions.
    // Using single:true ensures that future pages load as normal.
    if(Ext.History.getToken() !== PTC.navigation.getTokenFromUrl(newUrl)) {

    PTC.navigation.on('historyChange', FALSE_FUNC, PTC.navigation, {
        single: true
    });

    //remove the params from the current url and replace it.
    window.location.replace(newUrl);
        return true;
    }
    return false;
};


/**
 * Replaces the old window.location url with a newUrl.
 * @param {String} newUrl
 * @param {boolean} suppressHistoryChange optionally squashes the historyChange event. Defaults to true.
 */
PTC.util.replaceURL = function(newUrl, suppressHistoryChange) {
    if (typeof(suppressHistoryChange) === "undefined" || suppressHistoryChange === true) {
        PTC.util.replaceURLNoReload(newUrl);
    } else {
        window.location.replace(newUrl);
    }
};

/**
 * Removes a list of params from this window's url without reloading the page.
 *
 * @example
 * PTC.util.removeURLParamsFromThisWindow(['key']);
 * and a url like this: 'http://ptc.com/?key=value'
 * will return 'http://ptc.com/'
 *
 * PTC.util.removeURLParams(['first','third']);
 * and a url like this: 'http://ptc/info?first=val&second=val&third=val'
 * will return 'http://ptc/info?second=val'
 *
 * @param {Array} params array of params to remove
 * @return {String} the new window url
 */
PTC.util.removeURLParamsFromThisWindow = function(params) {
    var newUrl = PTC.util.removeURLParams(window.location.href,params);
    PTC.util.replaceURL(newUrl);
    return newUrl;
};

/**
 * @private
 * @see PTC.util.removeURLParamsFromThisWindow
 */
PTC.util.removeURLParams = function(url, params){
    for(var i = 0; i < params.length; i++) {
        // Regex matches a '&' or '?', the param key, '=', the param value, an optional '&'
        var regex = new RegExp('([&?])' + params[i] + '=[^&#?]*(&?)');
        var groups = url.match(regex);

        // does the param exist?
        if (groups !== null) {
            // Are we removing the first param that isn't the only param?
            if (groups[1] === '?' && groups[2] !== '') {
                // If so, remove a trailing '&' rather than the leading '?'
                url = url.replace(groups[0].substr(1), '');
            } else {
                // otherwise, replace the match with group 2 ('' or '&', depending on whether it is the last value)
                url = url.replace(regex, groups[2]);
            }
        }
    }
    return url;
};

/**
 * @private
 * @see PTC.util.replaceURLParamInThisWindow
 */
PTC.util.replaceURLParam = function(url, paramToReplace, newVal){
    // Regex matches a '&' or '?', the param key, '=', the param value
    var regex = new RegExp('([&?]' + paramToReplace + '=)[^&#?]*');
    var groups = url.match(regex);
    if (groups !== null) {
        // replace on the entire param with the new value
        var newParam = groups[1] + newVal;
        url = url.replace(regex, newParam);
    }
    return url;
};

/**
 * Replaces the first instance of a url param in the current window without reloading the page. This api does NOT
 * encode the param to be used in the url for you (to avoid cases of double encoding). If you want the new param
 * to be encoded you are required to do this yourself before-hand. If a match is not found in the given url, the
 * unchanged url is returned.
 *
 * @example
 * PTC.util.replaceURLParamInThisWindow('key','newValue');
 * and a url like this: 'http://ptc.com/?key=val'
 * will return 'http://ptc.com/?key=newValue'
 *
 * @param {String} paramToReplace param you want to replace
 * @param {String} newVal new value of your param
 * @param {boolean} suppressHistoryChange optionally squashes the historyChange event. Defaults to true.
 * @return {String} the new window url
 */
PTC.util.replaceURLParamInThisWindow = function(paramToReplace, newVal, suppressHistoryChange) {
    var newUrl = PTC.util.replaceURLParam(window.location.href,paramToReplace,newVal);
    PTC.util.replaceURL(newUrl, suppressHistoryChange);
    return newUrl;
};

/**
 * Extracts all params out of a url as key/value pairs and returns them as an associated array (Useful for making ajax
 * requests). All params are also decoded.
 *
 * @param {String} url
 * @return associative array of url params (e.g {oid:"OR%3Awt.part.WTPart%3A48037"})
 */
PTC.util.extractAllParams = function(url) {
    // if there are not url params present, return empty array
    if (!url || (url.indexOf("?") < 0 && url.indexOf("&") < 0)) {
        return {};
    }
    // get everything after the "?"
    var params = url.substr(url.indexOf("?")+1);
    return Ext.urlDecode(params);
};

/**
 * Gets a unique number that will be based on the number of milliseconds between now and midnight of January 1, 1970.
 * @return - {String} a unique id string based on timestamp of when function was called
 * @example
 * var id = "someId_" + getUniqueId();
 * //results with id equal to something like "someId_58706410565682_0"
 */
PTC.util.getUniqueId = function() {
    //get a unique number that will be number of milliseconds since midnight of January 1, 1970
    var d = new Date();
    var uniqueNumber = Date.UTC(d.getYear(),d.getMonth(),d.getDay(),d.getHours(),d.getMinutes(),d.getSeconds(),d.getMilliseconds())*-1;
    return uniqueNumber + "_" + PTC.util.getUniqueId.counter++;
};
//need to ensure the numer is unique, if tabs are added quickly the timestamp doesn't change fast enough
PTC.util.getUniqueId.counter = 0;

  /**
   * This unescapes html - both in firefox and ie.
   * A neat way to unescape HTML wihtout calling homebrewed methods replacing each character.
   * @param html
   */

PTC.util.unescapeHTML = function(html){
    var htmlNode = document.createElement("DIV");
    // TODO: remove when IE8 is no longer supported.
    // force IE8 to treat the content as HTML by always having the content enclosed in an HTML tag.
    if (html.indexOf("<") !== 0) {
        html = "<span>" + html + "</span>";
    }
    htmlNode.innerHTML = html;
    return PTC.util.getTextContent(htmlNode);
};

/**
 * Gets the text content from the given html node.
 * @param {HTMLElement} element - a dom element
 */
PTC.util.getTextContent = function(element) {
    if(!element || !("nodeType" in element)) {
        return '';
    }
    var text = '';
    if (element.nodeType == 3 /* Text */) {
        text = element.data;
        // browser converts newlines and tabs to just space
        // currently ignoring complexity that these could be preserved by PRE tag or whitespace:pre css style
        // also, convert non-breaking spaces (\xA0) to regular space for search/export/dom dump purposes
        text = text.replace(/\n|\r|\t|\xA0/g, ' ');
        return text;
    }
    // text input, text area, div, span, table etc. are all Elements (nodeType === 1)
    if (element.nodeType === 1/* Element */ && element.nodeName !== 'SCRIPT') {
        // get value from text input because it has no child text node
        // textarea contains 1 child Text node, but 'data' of that child is not as expected in IE
        if(element.type === "text" || element.type === "textarea") {
            text = element.value;
        } else if(element.type === "select-one") {
            text = PTC.util.getTextContent(element.options[element.selectedIndex]);
        } else if(element.type === "select-multiple") {
            for (var j = 0; j < element.options.length; j++) {
                var option = element.options[j];
                if(option.selected) {
                    text += PTC.util.getTextContent(option);
                }
            }
        } else if(element.tagName === "BR") {
            text = "\n";
        } else {
            for (var i = 0; i < element.childNodes.length; i++) {
                var child = element.childNodes[i];
                text += PTC.util.getTextContent(child);
            }
        }
    }
    return text;
};


/**
 * Converts a string like 'jsca.columns.iconRenderer' into a function reference
 * without using eval.
 * @param {String} funcString like 'jsca.columns.iconRenderer'
 * @return {Function} a function reference for the given funcString,
 *              if the given funcString is already a function then that is just returned
 */
PTC.util.convertStringToFunc = function(funcString){
    var originalFuncString = funcString;
    //if its already a function, just return it
    if(typeof funcString === 'function') {
        return funcString;
    }
    var scope = window;
    while (funcString.indexOf('.') > 0) {
        var index = funcString.indexOf('.');
        var scopeString = funcString.substring(0, index);
        funcString = funcString.substring(index + 1);
        scope = scope[scopeString];
    }
    //B-91888 keep a backup copy of the original string in case func has to be 'deflated'
    if (typeof scope[funcString] === 'function') {
        scope[funcString]._originalFuncString_ = originalFuncString;
    }
    return scope[funcString];
};

/**
 * Returns true if the event is not defined or if the key pressed is a character input key
 * (e.g NOT the following buttons: delete, backspace, direction arrows, etc)
 * @param {Object} e user key event from the browser (most likely a "onkeyup" in this case)
 */
PTC.util.isCharInputKey = function(e) {
    if(!e || !e.keyCode) {
        return true;
    }
    // return is only an input key for textarea
    if (13 === e.keyCode) {
        var target = e.target ? e.target : e.srcElement; /* Firefox: IE */
        if (target && target.type && "textarea" == target.type) {
            return true;
        } else {
            return false;
        }
    }
    if( 8 === e.keyCode || // backspace
        9 === e.keyCode || // tab
        16 === e.keyCode || // shift
        17 === e.keyCode || // ctrl
        18 === e.keyCode || // alt
        35 === e.keyCode || // end
        36 === e.keyCode || // home
        37 === e.keyCode || // left arrow
        38 === e.keyCode || // up arrow
        39 === e.keyCode || // right arrow
        40 === e.keyCode || // down arrow
        46 === e.keyCode // delete
        ){
        return false;
    }
    return true;
};

/**
 * Returns true if the target object of an event has text selected
 * @param {Object} e event from the browser
 */
PTC.util.eventTargetHasSelection = function(e) {
    var target = e.target ? e.target /*Firefox*/ : e.srcElement /* IE */;
    if (target) {
        if (typeof target.selectionStart == "number") { // firefox, etc
            var selection = target.selectionEnd - target.selectionStart;
            if (selection > 0) {
                return true;
            }
        } else if (document.selection) { //Internet Explorer
            var textRange = document.selection.createRange();
            var rangeParent = textRange.parentElement ();
            if (rangeParent === target && textRange.text.length > 0){
                return true;
            }
        }
    }
    return false;
};

/**
 * Given an Ext.EventObject, returns true if it is the left mouse-click.
 * Note that the event should be an Ext.EventObject, since Ext normalizes
 * the mouse-button mappings across browsers.  Also note that this is not
 * a determination of absolute left click, rather it determines if the "primary"
 * mouse button was clicked (left is the default "primary" mouse button)
 * @link http://www.extjs.com/forum/showthread.php?19689-can-Ext-track-left-mouse-button-down
 * @param {Ext.EventObject} evt
 * @return {Boolean} true if the event is a left mouse-click
 */
PTC.util.isLeftClick = function(evt) {
    if (!evt) {
        return false;
    }
    return evt.button === 0;
};

/**
 * Given an Ext.EventObject, returns true if it is the right mouse-click.
 * Note that the event should be an Ext.EventObject, since Ext normalizes
 * the mouse-button mappings across browsers.  Also note that this is not
 * a determination of absolute right click, rather it determines if the "secondary"
 * mouse button was clicked (right is the default "secondary" mouse button)
 *
 * Note the button is not correct when in IE - it is always -1
 * so we saved it earlier when it was correct in PTC.navigation.mouseUpButtonClick
 *
 * @link http://www.extjs.com/forum/showthread.php?19689-can-Ext-track-left-mouse-button-down
 * @param {Ext.EventObject} evt
 * @return {Boolean} true if the event is a right mouse-click
 */
PTC.util.isRightClick = function(evt) {
    if (!evt) {
        return false;
    }
    return evt.button === 2 || PTC.navigation.mouseUpButtonClick === 2;
};

/**
 * Given a URL, this function will initiate a download by creating an iframe in the dom, with src = url.
 * This will not interrupt any currently running ajax requests.
 * @param {String} url
 * @return {String} url
 */
PTC.util.downloadUrl = function(url) {
    // Append the base href if this is a relative url starting with '/'.
    if (url !== null && url.indexOf('/') === 0 && url.length > 1) {
        url = getBaseHref() + url.substring(1, url.length);
    }

    // Wait for document ready.
    Ext.onReady(PTC.util._createDownloadIframe, {url:url}, {single: true});

    return url; // For testing.
};

/**
 * @private
 * Should only be called after document is ready.
 */
PTC.util._createDownloadIframe = function() {
    var iframe = document.createElement('iframe');
    iframe.src = this.url;
    iframe.style.display = 'none';
    document.body.appendChild(iframe);
};
/**
 * Converts Ext.Element & Ext.component to a DOM element
 * @param {Mixed} obj
 */
PTC.util.getDom = function(obj){
    if (obj && typeof obj.getEl === 'function') {
        obj = obj.getEl().dom;
    }
    if (obj && obj.dom) {
        obj = obj.dom;
    }
    return obj;
};

/**
 * Destory all subcomponents with a certain class.  Should only be used for components that use renderTo or applyTo.
 *
 * @param {DOMElement} dom parent DOM element to search within
 * @param {String} selector CSS selector
 */
PTC.jca.deleteAllCmpsWithCls = function(dom, selector) {
    if (!dom || !selector) {
        return;
    }
    var divs = Ext.DomQuery.select(selector, dom);
    for (var i = divs.length; --i >= 0;) {
        var panel = Ext.getCmp(divs[i].id);
        if (panel) {
            panel.removeAll(true);
            panel.destroy();
        }
    }
};

/**
 * Returns the byte length of the given string based on the unicode value of each character in the string
 * @param {Object} str
 * @return {Integer} byte length of the given string
 */
PTC.util.getByteLength = function(str){
    var totalLength = 0;
    // assumes str is not null or undefined
    if (str !== null && str !== undefined) {
        str = str.toString(); // convert to string in case it is not already a string
        // in order to get the exact length new line should be converted to carriage return
        str = str.replace(/\n/g, "\n\r");
        for (var i = str.length; i--;) { // loop backwards for performance
            var c = str.charCodeAt(i);
            if ((c >= 0x0001) // decimal 1
                && (c <= 0x007F)) { // decimal 127
                totalLength++;
            }
            else if (c > 0x07FF) { // decimal 2047
                totalLength += 3;
            }
            else { // all characters between decimal 127 and 2048 are considered 2 byte
                totalLength += 2;
            }
        }
    }
    return totalLength;
};

/**
 * Quicktips are shown by swapping in new text into a single div in the dom to save on extra dom elements. Look there
 * to find the active quicktip text
 * @return {String} current quicktip text
 */
PTC.util.getGlobalQuickTipText = function(){
    // make sure quick tips are enabled, otherwise no sense is looking for one
    if (Ext.QuickTips.isEnabled()) {
        var pNode = document.getElementById(Ext.QuickTips.getQuickTip().id);
        var divs = pNode.getElementsByTagName('div');
        for (var x = 0; x < divs.length; x++) {
            if (divs[x].className === 'x-tip-body') {
                return divs[x].innerHTML;
            }
        }
    }
    return "";
};
/**
 * Returns a date that is unique to every last sunday.
 * This is useful to allowing some caching on ajax urls but still ensure it will pick up
 * new changes at least weekly (assuming weekends are when MORs and patches are applied)
 * @param {Date} - date to change back to last sunday.
 * @return {Date} Date of last Sunday, or if jsDebug is enabled just new Date()
 */
PTC.util.getWeeklyCacheBuster = function(date){
   if(PTC.debug.isJsDebug()) {
       return new Date();
   }
   if(date.getPreviousSunday) {
       return date.getPreviousSunday();
   }
   return date;
};

/**
 * recursively release dom properties
 * This is for IE8+ memory leaks ONLY.
 *    Firefox and chrome do not have the memory leak problem,
 *    Memory leaks still observed in IE11, so this hack still needed at that version.
 *    In IE7 this process is too expensive and doesn't work for a solution, it is faster to refresh each page completely 
 *    (but we no longer support IE7 anyway)
 * http://javascript.crockford.com/memory/leak.html
 * @param {DomElement} d
 * @param {boolean} onlyChildren - to only purge the childnodes of the dom element.
 */
PTC.util.purge = function(d, onlyChildren){
  if (PTC.navigation._attemptAggressiveCleanup) {
    var a = d.attributes, i, l, n;
    if (a && onlyChildren !== true) {
        l = a.length;
        for (i = 0; i < l; i += 1) {
            if (a[i]) { //PTC OVERRIDE, this check was added to avoid js error.
                n = a[i].name;
                if (typeof d[n] === 'function') {
                    if (n.toLowerCase() === 'onunload') {
                        PTC.util.log.debug('PTC.util.purge - Not purging onunload handler so that its executed as expected');
                        continue;
                    }
                    d[n] = null;
                }
            }
        }
    }
    a = d.childNodes;
    if (a) {
        l = a.length;
        for (i = 0; i < l; i += 1) {
            PTC.util.purge(d.childNodes[i]);
        }
    }
  }
};

/**
 * Calls window.open with given parameters.
 * For IE does the window.open in a special way that will spawn a new process.
 * This results in better memory footprint as that process dies when the window is closed.
 * Note that due to limitations in creo, a new process is not started so this feature is not enabled for any embedded browser
 * @see <a href="http://rdwiki.ptcnet.ptc.com/mediawiki/index.php?title=Memory_leak_tips#IE_child_window_Memory_leaks">Memory leak tips wiki</a>
 *
 * @param {Object} url
 * @param {Object} windowName
 * @param {Object} params
 */
PTC.util.openWindow = function(url, windowName, params) {
    var win;
    if (PTC.navigation._attemptAggressiveCleanup && !isWf() && !Ext.isIE64BIT) {
        var emptyForm = document.getElementById("emptyForm");
        if(!emptyForm) {
            emptyForm = window.document.createElement("FORM");
            emptyForm.setAttribute("id", "emptyForm");
            emptyForm.setAttribute("method", "POST");
            document.body.appendChild(emptyForm);
        }
        emptyForm.setAttribute("action", url);
        emptyForm.setAttribute("target", windowName);
        win = window.open("", windowName, params);
        emptyForm.submit();
    } else {
        win = window.open(url, windowName, params);
    }
    return win;
};

/**
 * Method to check empty javascript object.
 * Ext.isEmpty doesnt help with javascript objects.
 *
 * @param {Object} obj
 * @return {boolean} flag whether passed object is empty or not
 */

PTC.util.isEmptyObject = function(obj){
	if(obj !== undefined){
		for(var i in obj ){
			if(obj.hasOwnProperty(i)){
				return false;
			}
		}
	}
	return true;
};

/**
 * Removes any child element with a tagName of script
 * @param {DomElement} node
 */
PTC.util.removeChildScriptNodes = function(node){
    if (!node) {
        return;
    }
    var formNodes = node.childNodes;
    var i = formNodes.length;
    while (i--) {
        var child = formNodes[i];
        if (child && child.tagName && child.tagName.toLowerCase() === 'script') {
            //Remove all script blocks
            node.removeChild(child);
        }
    }
};

/**
 * Iterates through the properties on the object calling the callback for each property
 * that is not a function.
 *
 * The callback function is passed the key, value, and any params passed through
 *
 * Throws an error if the obj or func is not valid
 * @param {Object} obj
 * @param {Function} func
 * @param {Array} params
 */
PTC.util.propertyIterator = function(obj, contextObj, func, params){
    if(!obj) {
        return;
    }
    if (!func || typeof func !== 'function') {
       throw new Error("iterator function was not provided");
    }
    for (var key in obj) {
        if (key && typeof obj[key] !== 'function') {
            func.apply(contextObj || obj, [key, obj[key]].concat(params));
        }
    }
};


/**
 * Get all known windows that have PTC namespace, to fire events in all of them
 */
PTC.util.getAllPTCWindows = function(){
    var i, contextWindow, allWindows = [];
    try {
        contextWindow = getWindow();
        do {
            if (!(contextWindow.PTC === undefined || contextWindow.PTC === null)) {
                allWindows.push(contextWindow);
                if (contextWindow.PTC.action.actionWindows) {
                    allWindows = allWindows.concat(contextWindow.PTC.action.actionWindows);
                }
                if (PTC.lightbox.isLightbox(contextWindow)) {
                    contextWindow = contextWindow.parent;
                }
                else {
                    contextWindow = contextWindow.opener;
                }
            }
            else {
                contextWindow = null;
            }
        }
        while (!(contextWindow === undefined || contextWindow === null));
    }
    catch (e) {
    }

    //remove duplicate entries, a child actionWindow may be included twice for example if the event originated in the popup.
    i=allWindows.length;
    var names = [];
    while (i--) {
        var win = allWindows[i];
        if(win) {
            var name = win.name;
            if (!win.PTC || names.indexOf(name)>=0) {
                allWindows.splice(i,1);
            }
            names.push(name);
        }
    }

    return allWindows;
};

/**
 * Get all known iframes that have PTC namespace, to fire events in all of them
 */
PTC.util.getAllPTCIframes = function(){
    var allIframes = [];
    var iframes = document.getElementsByTagName("iframe");
    var i = iframes.length;
    while (i--) {
        var iframeEl = iframes[i];
        if (PTC.util.isPTCFrame(iframeEl)) {
            try {
                allIframes.push(iframeEl.contentWindow);
            } catch(e) {
                PTC.util.log.debug("Error getting contentWindow of iframe", iframeEl, e);
            }
        }
    }
    return allIframes;
};

/**
 * Determine if given frame is a PTC frame. This window may not have access to the contentWindow/contentDocument of non-PTC frames 
 * so care should be taken when looping across all iframes. (spr 4886823)
 *
 * @param frame is a frame that may or may not have Windchill content and PTC namespace.
 *
 * @return true if the given frame has PTC and Ext namespaces, false if frame doesn't have PTC or Ext namespace.
 *         Not having those namespaces means it is some non-Windchill frame
 *         such as the Ext history iframe, or the ThingWorx content frame embedded into Windchill UI.
 */
PTC.util.isPTCFrame = function(frame) {
    return (frame && "PTC" in frame && "Ext" in frame);
};

/**
 * Determine if given frame is a PartStructureBrowser frame
 */
PTC.util.isPSBFrame = function(frame) {
    return (frame && frame.id === "psbIFrame");
};

/**
 * Determine if given frame is a msr frame
 */
PTC.util.isMSRFrame = function(frame) {
    return (frame && frame.id === "msrIFrame");
};

/**
 * returns an array of values.  Converts single obj to array, array to array
 * and handles a funny scenario in IE where a json [] is not reported correctly and lies that its an object
 * @param {Mixed} value
 */
PTC.util.extractAllValues = function(value) {
    var oids = [];
    if( typeof value === 'object' && value[0]) {
        var i = 0;
        //Convert IE's funny object/array into a real array
        while(value[i]) {
            oids = oids.concat(value[i++]);
        }
    } else {
        oids = oids.concat(value);
    }
    return oids;
};

/**
 * Return true if oidHolderString matches regexp.
 *
 * Looks for a "?" in oidHolderString; if found, extracts OID.  Otherwise, assumes
 * oidHolderString is an OID.
 *
 * Returns 'true' if obtained OID matches regexp; otherwise, returns false.
 *
 * @param {String} oidHolderString - string containing an OID
 * @param {String} regexp - pattern to match against OID
 *
 * @return {Boolean} 'true' if OID matches pattern; otherwise, 'false'
 *
 */
PTC.util.oidStringMatches = function (oidHolderString, regexp)
{
    var match = false;

    if (Ext.isString (oidHolderString))
    {
        var oid = oidUtils.normalize (oidHolderString);

        if (oid && oid.indexOf ("?") > 0)
        {
            oid = getOidFromURL (oid);
        }

        if (oid)
        {
            match = !! oid.match (regexp); //double bang converts null to false
        }
    }
    return match;
};

/**
 * Determine whether supplied OID is a WTContainer or not.
 *
 * @param {String} oidString - an NmContext, URL, or URL parameter string
 *
 * @return {Boolean} true if oidString identifies a WTContainer
 *
 */
PTC.util.isAContainer = function (oidString)
{
    // In the regexp, "Project" suffices for both "Project" and "Project2",
    var containerRegexp = /pdmlink\.PDMLinkProduct|admin\.Project|library\.WTLibrary|container\.OrgContainer|container\.ExchangeContainer/;
    return PTC.util.oidStringMatches (oidString, containerRegexp);
};

/**
 * Determine whether supplied OID is a Folder or not.
 *
 * @param {String} oidString - an NmContext, URL, or URL parameter string
 *
 * @return {Boolean} true if oidString identifies a Folder (Cabinet or SubFolder)
 *
 */
PTC.util.isAFolder = function (oidString)
{
    var folderRegexp = /folder\.SubFolder|folder\.Cabinet/;
    return PTC.util.oidStringMatches (oidString, folderRegexp);
};

/**
 * Utility functions to find plugins like applet, object etc. from overall DOM.
 * @param domElement - to look inside for plugins
 * @param iframeLookupDomElement - optional dom element to look for iframes recursively
 * @return {Array}
 */
PTC.util.getPlugins = function (domElement, iframeLookupDomElement) {
    var plugins = [];
    var domEl = iframeLookupDomElement || domElement;
    if (domEl) {
        var iframes = Ext.DomQuery.select("IFRAME, FRAME", domEl);

        for (var i = 0; i < iframes.length; i++) {
            var iframe = iframes[i];
            if ((PTC.util.isPTCFrame(iframe) || PTC.util.isPSBFrame(iframe) || PTC.util.isMSRFrame(iframe)) && (!iframe.style || !iframe.style.visibility || iframe.style.visibility != "hidden")) {
                try {
                    plugins = plugins.concat(PTC.util.getPlugins(iframe.contentDocument.body));
                } catch(e) {
                    PTC.util.log.debug("Exception getting plugins for iframe ", iframe, e);
                }
            }
        }
        plugins = plugins.concat(Ext.DomQuery.select("APPLET, EMBED, OBJECT", domElement));
    }
    return plugins;
};

/**
 * check sizes and state and determine to show or hide the plugin
 * @param el {Ext.Element}  plugin object
 * @param visible {boolean} is the plugin currently visible
 * @param canBeVisible {boolean} is the Parent div visible?
 * @param offsets [Number] top and left offsets to the body tag of the element
 * @param size {Object} width and height of the element
 * @param reEnable {boolean}  If object is minimized or being closed or moving inline (pinned navigator) where
 *   a hidden plugin would become available
 */
PTC.util._showOrHidePlugin = function(el, visible, canBeVisible, offsets, size, reEnable) {
    var left = offsets[0];
    var top = offsets[1];
    //If size is too small, such as navigator being closed then consider it minimized
    if(!visible && canBeVisible && (size.width<30 || reEnable)) {
        el.show();
    } else if(visible && !reEnable) {
        //Here is the check for the coordinates being under the element element (lightbox or navigator)
        var elOffsets = el.getOffsetsTo(document.body);
        var elLeft = elOffsets[0];
        var elTop = elOffsets[1];
        // SPR 2168856: If the visualization panel is on the left most side of the window, as in the case of Related
        // Part Tree Picker in PPB, then navigator panel in collapsed state instersects with the visualization
        // panel at 0,0 co-ordinates for left and top. This leads to hiding of plugin even when it should be displayed.
        // If left, top, height and width of the component are 0, assumption is that the navigator panel is in collapsed state
        // and left and top coordinates of viz panel are intersecting with it because the visualization is launched
        // on the left-most side of the window. Skip the intersection check in this case.
        if(!(left === 0 && top === 0 && size.height === 0 && size.width === 0 && elLeft === left && elTop === top)) {
            if (PTC.util.intersect({x:elLeft, y:elTop, size:el.getSize()}, {x:left, y:top, size:size})) {
                el.hide();
            }
        }
    }
};

/**
 * Any plugins in the document body will be checked for overlap with the passed component
 *
 * @param {Ext.Component} dom object for which to look for plugins overlapping
 * @param {boolean} reEnable true if the component is now closed or back inline with the page, nolonger overlapping anything
 */
PTC.util.handlePlugins = function(comp, reEnable) {
    var contentArea = Ext.DomQuery.select("div[id='" + PTC.navigation.contentTabID + "_contentArea']");
    var els = PTC.util.getPlugins(contentArea[0], document.body);
    var size = 0;
    var offsets = 0;

    if (!reEnable) {
        size = comp.getSize();
        offsets = comp.getEl().getOffsetsTo(document.body);
    }

    var i = els.length;

    while(i--) {
        var parentNodeName = els[i].parentNode.nodeName;
        var el = (parentNodeName === "BODY") ? Ext.get(els[i]) : Ext.get(els[i].parentNode);
        var visible = el.isVisible(true);
        //hide the parent when opening the nav
        var canBeVisible = (parentNodeName === "BODY") ? true : Ext.get(el.dom.parentNode).isVisible(true);
        //grandparent should still be visible
        PTC.util._showOrHidePlugin(el, visible, canBeVisible, offsets, size, reEnable);
    }
};

/**
 * Turns all plugins back on, then re-runs all listeners that may want to hide them again
 * This method should be called whenever a component that may hide or expose a plugin is
 * displayed or hidden.
 */
PTC.util.firePluginChecks = function() {
   PTC.util.handlePlugins(null, true);
   PTC.util.fireEvent('checkplugins');
};

/**
 * Returns true if the 2 lines overlap each other on a single axis.
 *
 * @param {Number} x1 coordinate for the first line
 * @param {Number} x2 coordinate for the second line
 * @param {Number} width1 for width of the 1st line (aka distance or length)
 * @param {Number} width2 for width of the 2nd line (aka distance or length)
 */
PTC.util.linearOverLap = function (x1, x2, width1, width2) {
   if ((x1 <= x2 && (x1 + width1) >= x2) ||
       (x1 >= x2 && x1 <= x2+width2)) {
       return true;
   }
   return false;
};

/**
 * Returns true if either of the squares overlap each other
 */
PTC.util.intersect = function (box1, box2) {
   var xoverlap = PTC.util.linearOverLap(box1.x, box2.x, box1.size.width, box2.size.width);
   var yoverlap = PTC.util.linearOverLap(box1.y, box2.y, box1.size.height, box2.size.height);
   return (xoverlap && yoverlap);
};

/**
 * destroys an Ext element such as a button that needs to work around MS IE bugs with mixed content
 * More info at: http://support.microsoft.com/kb/925014
 *
 * @param {Ext.Component} comp
 */
PTC.util.deleteComponentWithBackgroundSrc = function(comp) {
    if (comp) {
        if (Ext.isIE8 && comp.el.dom) {
            //Need to wipe outerhtml to avoid mixed content warning
            comp.el.dom.outerHTML = '';
        }
        Ext.destroy(comp);
    }
};

/**
 * USes the ServerState Controller to retrieve the value of a preference from the server
 * The preference is returned raw exactely as it is returned from the controller.
 * It will be a string and may need to be converted to other formats (eg number)
 *
 * @param keyValue the name of the preference to get
 */
PTC.util.getPreference = function (keyValue) {
	var responseresult = requestHandler.doRequest(getBaseHref() + 'ptc1/stateManager/', {method: 'get', asynchronous: false, parameters: {key: keyValue}});
	var pref = responseresult.responseText;
	return pref;
};

/**
 * Returns the Ext component present on the page. Looks for it in iframes, if not found in current namespace.
 * @param {String} cmpId = the component id.
 * @return Ext.Component
 */

PTC.util.getCmpInAllPTCnameSpaces = function (componentid) {
    var comp = Ext.getCmp(componentid);
    if (!comp) {
        for (var i = 0, l = frames.length; i < l; i++) {
            // skip iframes that don't have Ext (for example, ones created by JS framework libraries)
            if (PTC.util.isPTCFrame(frames[i])) {
                comp = frames[i].Ext.getCmp(componentid);
                if (comp) {
                    break;
                }
            }
        }
    }
    return comp;
};

/**
 * Returns the fully-qualified "action" attribute from the specified form.
 * Use this helper (instead of accessing form.action directly) to prevent issues where
 * a DOM element or url param is also named "action".
 * @param {Form} mform = the form to search
 * @return {String} value of the "action" attribute if available, null otherwise
 */
PTC.util.getFormAction = function (mform) {
    var actionValue = null;
    // validate the parameters are as expected before doing anything
    if (mform) {
        // default to the action property on the form
        actionValue = mform.action ? mform.action : null;
        // try to get the action from the form's "attributes" array
        if(mform.attributes) {
            // get the "action" item value from this array
            if (mform.attributes['action'] && mform.attributes['action'].value) {
                actionValue = mform.attributes['action'].value;
                // check if the action starts with our base href (this is a faster version of .startsWith())
                if (!PTC.util.isFullyQualified(actionValue)) {
                    // if not, then prefix the value with it
                    actionValue = getBaseHref() + actionValue;
                }
            }
        }
    }
    PTC.mainform.debug("getFormAction() returning action: ", actionValue);
    return actionValue;
};

/**
 * Sets the "action" attribute on the specified form.
 * Use this helper (instead of accessing form.action directly) to prevent issues where
 * a DOM element or url param is also named "action".
 * @param {Form} mform = the form that has the action to update
 * @param {String} value =  the value for the action attribute, which should be a URL.
 *   If the given URL is not fully qualified already, then the base href will be added to it.
 */
PTC.util.setFormAction = function (mform, value) {
    // validate the parameters are as expected before doing anything
    if (mform && value && (typeof value === 'string' || value instanceof String)) {
        var actionValue = value + "";
        if (!PTC.util.isFullyQualified(value)) {
            // if not, then prefix the value with it
            actionValue = getBaseHref() + value;
        }
        var oldValue;
        // try to get the "action" item value on the attributes array
        if (mform.attributes && mform.attributes['action']) {
            oldValue = mform.attributes['action'].value;
            // set the "action" entry value on the attributes array
            mform.attributes['action'].value = actionValue;
        } else  {
            oldValue = mform.action;
            // else there is a form, but no action attribute, so set the action directly on the form
            // (to mimic what "form.action = value" would do)
            mform.action = actionValue;
        }
        PTC.mainform.debug("setFormAction() old mform action was: ", oldValue);
        PTC.mainform.debug("setFormAction() changing mform action to: ", actionValue);
    } else {
        PTC.mainform.debug("setFormAction() given value was not a string. Do nothing.", value);
    }
};

/**
 * Use a regular expression to determine if a url string is already fully qualified or not.
 *  Explain the RegExp
 *    ^ - beginning of the string
 *    (?: - beginning of a non-captured group
 *    [a-z]+ - any character of 'a' to 'z' 1 or more times
 *    : - string (colon character)
 *    )? - end of the non-captured group. Group appearing 0 or 1 times
 *    // - string (two forward slash characters)
 *    'i' - non case-sensitive flag
 *
 * @param url a string url
 * @return true if it is already fully qualified, false if not.
 */
PTC.util.isFullyQualified = function(url) {
        // check if the url is already fully qualified
        var r = new RegExp('^(?:[a-z]+:)?//', 'i');
        return r.test(url);
};


/**
 * Contains some useful table sort functions pulled forward from 9.1.  Expect these functions 
 * to be moved to PTC
 * @namespace
 * @deprecated 
 */
var jsca = function() {
    var direction;
    return /**@scope jsca */ {
        /** the jsca.compare function checks if the cell value has a text property,
         * and if it does, it compares on that instead of the cell itself. This is
         * wired in by setting the sortFunction on the JSColumnDescriptor */
        
        compare : function(cellA,cellB) {
            // some default sorting columns often don't exist
            if (cellA === undefined && cellB === undefined) {
                return true;
            }
            var comparableA = jsca.getComparable(cellA);
            var comparableB = jsca.getComparable(cellB);
            return jsca.cmp(comparableA,comparableB);
        },
        /**
         * This compare method has inlined the sub-compare methods and also expects the data to be pre-figured out
         * Once IE8 and IE7 are no longer the prime browsers to support, remove the inlined functions
         *
         * @param {Object} cellA should have boolean .isFolder and compare object .cmp
         * @param {Object} cellB
         */
        optimizedCompare: function(cellA, cellB){
            var result = jsca._folderCompare(cellA.isFolder, cellB.isFolder, cellA.cmp, cellB.cmp);
            if(direction === 'DESC'){
                result = -1 * result;
            }
            if(result === 0){
             //it is a tie,so fall back mechanism for chrome browsers
                result =  cellA.index < cellB.index ? -1 : 1;   
            }
            return result;
        },
         /**
         * Set direction of the sort
         *
         * @param {String} asc/desc
         */
        setDirection: function(dir){
            direction = dir;
        },
        versionCompare: function(cellA, cellB, rowA, rowB){
            var result;
            var isFolderA = rowA._isFolder;
            if(isFolderA === undefined){
                isFolderA = jsca.isFolderRow(rowA);
            }
            var isFolderB = rowB._isFolder;
            if(isFolderB === undefined){
                isFolderB = jsca.isFolderRow(rowA);
            }
            if(isFolderA === isFolderB){
                result = rowA.vindex - rowB.vindex;
                if (this.direction === 'DESC') {
                    result = -1 * result;
                }
            }else{
                if (isFolderA) {
                    result = -1;
                }
                else {
                    result = 1;
                }
                if (this.direction === 'DESC') {
                    result = -1 * result;
                }
            }
            return result;
        },
        /**
         * customize the compare method to separate the folders from regular objects
         * * Once IE8 and IE7 are no longer the prime browsers to support, remove the inlined functions
         */
        folderCompare: function(cellA, cellB, rowA, rowB){
            return jsca._folderCompare(jsca.isFolderRow(rowA), jsca.isFolderRow(rowB),
                                       jsca.getComparable(cellA), jsca.getComparable(cellB));
        },

        _folderCompare : function(isFolderA, isFolderB, comparableValueA, comparableValueB ) {

            if (isFolderA === isFolderB) {

                //undefined, null, "" treated as null
                var a_is_null = comparableValueA === undefined || comparableValueA === null || comparableValueA === "";
                var b_is_null = comparableValueB === undefined || comparableValueB === null || comparableValueB === "";

                if (b_is_null) {
                    if (a_is_null) {
                        return 0;
                    }
                    return -1;
                }
                /* If first arg "a" is null then "b" comes before. */
                if (a_is_null) {
                    return 1;
                }

                /* For strings uses localeCompare to get correct order for the locale/language.
                 * Neither value should be null or of a different type. */
                if ((typeof comparableValueA === "string" || comparableValueA instanceof String) &&
                    (typeof comparableValueB === "string" || comparableValueB instanceof String)){
                    return comparableValueA.localeCompare(comparableValueB);
                }
                if (comparableValueA > comparableValueB) {
                    return 1;
                }
                else if (comparableValueA < comparableValueB) {
                    return -1;
                }
                return 0;
            }
            var result;
            if (isFolderA) {
                result = -1;
            }
            else {
                result = 1;
            }
            if (direction === 'DESC') {
                result = -1 * result;
            }
            return result;
        },

        getComparable : function(data) {
             // Integrity item #4518927 : sort order of '' and ' ' is different though look the same on a page
             // for consistency, treat '' and ' ' as the same comparable
             if (data === undefined || data === null || data === '') {
                 // some default sorting columns often don't exist (objNumber etc)
                 return " ";
             } else if(typeof data === 'string' || typeof data === 'number') {
                 return data;
             }
             if (typeof data.getComparable === 'function') {
                return data.getComparable();
             }

             if (data.comparable !== undefined) {
                return data.comparable;
             }
             else if (data.gui && data.gui.comparable!== undefined) {
                data.getComparable = function(){
                    return this.gui.comparable;
                };
                return data.gui.comparable;
             }
             else if (data.gui && typeof data.gui.getComparable === 'string') {
                var compareFunc = PTC.attributeHelper.get('Compare_' + data.gui.getComparable);
                if(typeof compareFunc !== 'function'){
                    compareFunc = PTC.util.convertStringToFunc(data.gui.getComparable);
                    // caching the function so that we don't need to convert string to function for each object
                    PTC.attributeHelper.set('Compare_' + data.gui.getComparable, compareFunc);
                }
                return compareFunc(data);
             }

             else if (data[0] && data[0].gui && typeof data[0].gui.comparable !== 'undefined') {
                data.getComparable = jsca.guiComparable;
                return data[0].gui.comparable;
             }
             else if (data.cellValue!== undefined) {
                 // tree sorting has cellvalue at the object to traverse through first.
                 return jsca.getComparable(data.cellValue);
             }
             else {
                return (data.text || data);
             }
        },
        /**
         * This function has been inlined into the folderCompare and optimizedCompare functions
         * Once IE8 and IE7 are no longer the prime browsers to support, remove the inlined functions
         * @param {Object} a
         * @param {Object} b
         */
        cmp : function(a,b) {
            /* If second argument is null then "a" is always considered before "b"
            * unless a is also null. Also modified logic to treat
            * null and "" as equivalent for sort purposes.
            *
            * When comparing the value against an empty string
            * we need to use the triple equal operator so that both value
            * and type are compared.
            * If stdtable is not used when comparing 0 (zero) to empty string
            * it returns true (believe it or not)
            */
            var a_is_null = a === null || a === "";
            if ( b === null || b === "" ) {
                if ( a_is_null ){
                    return 0;
                }
                return -1;
            }
            /* If first arg "a" is null then "b" comes before. */
            if ( a_is_null ) {
                return 1;
            }

            /* For strings uses localeCompare to get correct order for the locale/language.
             * Neither value should be null or of a different type. */
            if ( typeof a === "string" || a instanceof String ) {
                return a.localeCompare(b);
            }
            if ( a > b ){
                return 1;
            }else if (a < b){
                return -1;
            }
            return 0;
        },

        /**
         * This will try and figure out if this row is a folder. 
         * @param {Object} row
         * @return whether the row represents a folder or not ( folder group sorting )
         */
        isFolderRow : function (row) {
            if (row === undefined) {
                return true;
            }
            if (row._isFolder !== undefined) {
                return row._isFolder;
            }
            var oid = row.get('oid');

            //In some cases where only a string is sent down to the client it will use that as the oid and
            //if that string contains the word "folder" then it will think it's a folder and not sort correctly.
            if (jsca.isFolderOid(oid)) {
                row._isFolder = true;
            }
            else {
                row._isFolder = false;
            }
            return row._isFolder;
        },

         /**
         * This will try and figure out if this row is a folder.
         * @param {String} oid
         * @return true if the oid String contains a folder/Cabinet.
         */
        isFolderOid : function(oid){
           if (typeof oid==='string' && (oid.indexOf("Folder:") >= 0 || oid.indexOf("Cabinet:") >= 0)) {
               return true;
           }
               return false;
        },
        
        /**
        * This will return true if the oid contains cabinet.
        * @param {String} oid
        * @return true if the oid String contains a Cabinet.
        */
         isCabinetOid : function(oid){
             if (typeof oid==='string' && oid.indexOf("Cabinet") !== -1) {
                 return true;
              }
                 return false;
          },

        guiComparable : function(){
            return this[0].gui.comparable;
        },
        /**
         * This is called after the renderers have been executed.  This will post process
         * anything additionally needed for the js table infrastructure.  For example, we
         * need to add in the ability to truncate columns.
         * @param {Object} tabledesc
         * @param {Object} column
         * @param {Object} row
         * @param {Object} cell - The actual html of the cell that the renderer produced.
         */
        postRenderer : function(tabledesc, column, row, cell) {
           return cell;
        }

    };
}();

jsca.compare.funcname = "jsca.compare";
jsca.postRenderer.funcname = "jsca.postRenderer";


