jsca.JCA_CHECKBOX_NAME = 'pjl_selPJLsa1__1';

/**
 * Unselect all the rows present in the hidden DIV for the given tableId.
 *
 * @param tableId --- id of the table
 */

jsca.unSelectHiddenCheckboxes = function(tableId){
    var selectedRowsDiv = getWindow().document.getElementById("checkboxesFor_" + tableId);

    if (selectedRowsDiv) {
        selectedRowsDiv.parentNode.removeChild(selectedRowsDiv);
    }
    var table = tableUtils.getTable(tableId);
    if (table && tableUtils.isExt() && typeof table.getSelectionModel().clearSelections === 'function') {
        // TODO: Need to provide a generic API to remove all selections across pages.
        var clearAllButton = Ext.getCmp(tableId + '_clearacrosspg');
        if (clearAllButton && !clearAllButton.disabled) {
            clearAllButton.fireEvent("click", clearAllButton);
        }
        else {
            table.getSelectionModel().clearSelections();
        }
    }
};


/**
 * override the unSelectAll so that the js row objects also get "unselected"
 *
 * @param inputs is an array of input elements
 * @param tableID id of the table to be unselected
 * @param root unselect all the tables in the root
 */
jsca._unSelectAll = function(inputs, tableID, root){
    var tableId;
    if (tableID !== null && tableID !== undefined) {// if tableId is mentioned only unselect that table
        jsca.unSelectHiddenCheckboxes(tableID);
    }
    else {
        var xTables = tableUtils.getExtTables(root);
        xTables.each(function(table){
            jsca.unSelectHiddenCheckboxes(table.id);
        });
    }

};

jsca.unSelectAll = jsca._unSelectAll;
JCA_UNSELECT_ALL = unSelectAll;
unSelectAll = jsca.unSelectAll;


