/**
 * Attempt to go back one page in the Ext history.  If that is
 * not possible, return to the home page.
 */
PTC.navigation.goBack = function() {
    if (Ext.History.getToken()) {
        Ext.History.back();
    } else {
        PTC.navigation.goHome();
    }
};

/**
 * IE doesn't reclaim memory properly IE 8 mode or IE 11 in Edge mode. To mitigate the severity of IE's memory footprint:
 * -added more cleanup listeners
 * -forced IE to reload the page periodically
 * -purged dom elements
 * -open popup windows in special way that allows IE to reclaim memory
 * @see http://com.hemiola.com/?p=5
 * PTC.navigation.MAX_IE_PAGE_COUNT, PTC.navigation.pageCount, PTC.util.purge, PTC.util.openWindow
 * @internal
 */
PTC.navigation._attemptAggressiveCleanup = Ext.isIE || PTC_isIE11;

//Keep track of the number of pages visited
PTC.navigation.pageCount = 0;
// Constant determines how many page loads occur before reloading
// the whole shell to unload memory: http://com.hemiola.com/?p=5
PTC.navigation.MAX_IE_PAGE_COUNT = 30;

/**
 * An array of all open navigation ajax requests to keep track.
 * - will abort any open request when a new page is clicked
 * - will be used by selenium to determine if the page is loaded.
 */
PTC.navigation.openRequests = [];
/**
 * Are all Navigation pages loaded?
 */
PTC.navigation.default_isPageLoaded = function(){
    // default return false, once shell loads, this method will be replaced
    // The core method only makes sense when the main shell has loaded.
    return isWizardWindow();
};
/**
 * @return the currently active card
 */
PTC.navigation.getActiveCard = function(){
    var cp = Ext.getCmp(PTC.navigation.cardManager);
    if (cp) {
        return cp.layout.activeItem;
    }else {
        return null;
    }
};
/**
 *   This core method only makes sense when the main shell has loaded.
 *   @return true if any "loadContent" ajax requests are still pending, false otherwise
 */
PTC.navigation._isPageLoaded = function(){
    var found = false;
    PTC.navigation.log.debug("PTC.navigation._isPageLoaded checking to see if there are any pending 'loadContent' requests", PTC.navigation.openRequests);
    if (PTC.navigation.openRequests.length > 0) {
        var i=PTC.navigation.openRequests.length;
        while (i--) {
            var item = PTC.navigation.openRequests[i];
            var state = null;
            try {
                state = item.readyState;
            } catch (e) {
                PTC.navigation.log.debug("PTC.navigation._isPageLoaded readyState may not be a property on item", item, e);
            }
            if (state != 4) {
                found = true;
                try {
                   if (state != 1) {
                       PTC.navigation.log.debug("PTC.navigation._isPageLoaded found pending request. status: ", item.status, ' readyState: ', item.readyState);
                   }
                }
                catch (e2) {
                 // 2077439-01 no access to the request obj?
                }
            } else {
                PTC.navigation.openRequests.splice(i,1);
                PTC.navigation.log.debug("PTC.navigation._isPageLoaded removed request. status: ", item.status, ' readyState: ', item.readyState);
            }
        }
    }
    PTC.navigation.log.debug("PTC.navigation._isPageLoaded returning ", !found);
    return !found;
};
/**
 *   @return true if any "loadContent" ajax requests are still pending, false otherwise
 */
PTC.navigation.isPageLoaded = PTC.navigation.default_isPageLoaded;
/**
 * Stops any active navigation ajax requests
 */
PTC.navigation.stopInProgressPages = function(){
    if (!PTC.navigation.isPageLoaded()) {
        PTC.navigation.openRequests.each(function(item){
            item.abort();
        });
    }
    PTC.navigation.openRequests = [];
};
/**
 * adds a request to the navigation list
 * @param {Object} req Ajax request object that is still open
 */
PTC.navigation.addOpenRequest = function(req){
    if (!req.jcaid) {
        // Relying on the request object equality check may not work
        // adding a custom id to check.
        req.jcaid = PTC.navigation.addOpenRequest.counter++;
    }
    PTC.navigation.openRequests.push(req);
};
/**
 * Keeps track of the open page content requests.  Its not the total number of ajax requests, just navigation pages.
 */
PTC.navigation.addOpenRequest.counter =0;
/**
 * The method used by the onSuccess ajax event handler
 */
PTC.navigation.onSuccessRequest = function(req, contentDivId){
    var id = req.transport.jcaid;
    var i = PTC.navigation.openRequests.length;
    while (i--) {
        if (PTC.navigation.openRequests[i].jcaid === id) {
            PTC.navigation.openRequests.splice(i,1);
        }
    }
    PTC.navigation.log.timeEnd("loadContent");
    PTC.log.sendAllMessages();
    //need to update the mainform after response request has been processed (so the dom elements exist)
    //TODO - is there some event to listen to instead of using this timeout?
    var contentId = (contentDivId) ? contentDivId : PTC.navigation.contentID;
    setTimeout(function(){
        PTC.util._setMainFormStartingElementFromParent(contentId);
    }, 10);
};
/**
 * Default Error handler for navigation ajax errors.
 * @param {Object} req
 * @param {String} [contentId] the Dom element id where the error message should be shown
 */
PTC.navigation.onFail = function(req, contentId){
    var domElementId;
    if(contentId){
        domElementId = contentId;
    }else{
        domElementId = PTC.navigation.activeContentID;
    }
    PTC.navigation.overwrite(Ext.getDom(domElementId), req.responseText);
};
navigation = PTC.navigation;
PTC.navigation.mouseUpButtonClick = null;
/**
 * SPR 2087797: Keeps track of the mouse button click from the mouseup event. This is necessary because the ext event
 * object that we get in IE on click does not have the correct info on it (a middle click registers as a left click)
 *
 * @param {Ext.EventObject} evt the Ext.EventObject to handle - note this is required to be an Ext.EventObject, not a normal browser event or other library's event object
 */
PTC.navigation.saveMouseUpButtonClickInfo = function(evt){
    PTC.navigation.mouseUpButtonClick = evt.button;
};
/**
 * Listens to click on the document body, and gets the link from the event target and loads it in the shell.
 * Will only load the content into the shell if the url contains the same base href and if the event is a left-mouse click.
 *
 * SPR 2087797: stops click event propigation (will NOT follow link) if:
 * 1. is a left click and
 * 2. the click was on an "a" tag with an invalid href (an "invalid" href is determined by PTC.navigation.isEmbeddedUrl)
 * e.g., if the href is "#", the link will NOT be followed (considered no-op)
 *
 * @param {Ext.EventObject} evt the Ext.EventObject to handle - note this is required to be an Ext.EventObject, not a normal browser event or other library's event object
 * @return {Boolean} false if the event target is a Windchill link and the content loaded, true otherwise
 */
PTC.navigation.remapNavigationLinks = function(evt){
    var mouseUpEvtButton = PTC.navigation.mouseUpButtonClick;
    PTC.navigation.mouseUpButtonClick = null;
    if (mouseUpEvtButton) {
        //SPR 2087797: in IE, the click event will come through as a left click even when it's a middle click
        //if mouseUpEvtButton is a left click, it will be "0"
        return true;
    }
    var link = evt.getTarget("A");
    if (link && PTC.navigation.isEmbeddedUrl(getParentNodeByTag(link, "A"))) {
        evt.stopEvent();
        var href = getParentNodeByTag(link, "A").href;
        if (!(!href || href === "#" || href === getBaseHref() + "#")) {
            //for Iframe links to replace content area, need to use getWindow() here
            var win = getWindow();
            win.PTC.navigation.loadContent(href);
            if (win.PTC.navigator && win.PTC.navigator.isExpanded()) { // On any href click on Navigator, it should get collapsed.
                win.PTC.navigator.collapseNavigator();
            }
        }
        return false;
    }
    return true;
};
/**
 * Gets a token appropriate for the ext history. Makes it relative and removes app/#
 * @param {String} url - the url of the new content page to display in the navigation shell.
 */
PTC.navigation.getTokenFromUrl = function(url) {
    if (!url) {
        return url;
    }
    var baseHref = getBaseHref();
    var token = url.replace(baseHref, "");
    if (token === url && url.toLowerCase().indexOf(baseHref.toLowerCase()) === 0) {
        PTC.navigation.log.debug('URL property has a case mismatch compared to the urls actually used!', url, baseHref);
        var index = url.toLowerCase().indexOf(baseHref.toLowerCase());
        token = url.substring(index+baseHref.length);
    }
    //tokens can't have app/# in it. It messes up the URL.
    token = token.strip().replace(PTC.navigation.APP_TOKEN_REGEX, '');
    //tokens can't have any fragments in them (# + anchor)
    token = token.split("#")[0];
    return token;
};
/**
 *
 * @param {String} url (can be token or fully qualified url with app/ embedded
 * @return {String} url with timestamp param added before the token   <base>/app/<unique>#token
 */
PTC.navigation.getTimeStampedUrl = function(url){
   var token = PTC.navigation.getTokenFromUrl(url);
   var newPage = getBaseHref() + 'app/?iemem='+new Date().getTime()+'#' + token;
   return newPage;
};
/**
 * Strip the base href out of the url, to create a relative path in the token.
 * @param {String} url - the url of the new content page to display in the navigation shell.
 * @example
 * url = <baseHref with http>/app/#ptc1/tcomp/infoPage?oid=OR%3Awt.part.WTPart%3A194056&u8=1;
 * var token = ptc1/tcomp/infoPage?oid=OR%3Awt.part.WTPart%3A194056&u8=1;
 */
PTC.navigation.addHistoryToken = function(url){
    var token = PTC.navigation.getTokenFromUrl(url);
    Ext.History.add(token);
};

/**
 * returns true if the url is specific to a custom CAD prototocl
 * such as wtws:  instead of http:
 */
 PTC.navigation.isCADURL = function(url) {
    return (PTC.navigation.isArbortextURL(url) ||
            url.indexOf("wtpub:") >= 0 ||
            url.indexOf("wtws:") >= 0);
};

/**
 * returns true if the url is specific to a Arbortext protocol
 * such as arbortext-editor:  instead of http:
 */
PTC.navigation.isArbortextURL = function(url) {
    return url.indexOf("arbortext-editor:") >= 0;
};

/**
 * returns true if the url is specific to a known PTC download file url
 */
 PTC.navigation.isDownloadURL = function(url) {
    return (url.indexOf("redirectRecipient") >= 0 ||
            url.indexOf("doDirectDownload") >= 0 ||
            url.indexOf("wt.content.ContentHttp/viewContent") >= 0);
};

/**
 * returns the window used when opening a file with Arbortext Editor
 */
function getWindowForArbortextProtocol() {
    return window;
}

/**
 * On a page with the navigation shell (accordion on the left content area on the right),
 * this function does an ajax call with the given url to get the new content area for the right.
 *
 * On pages without the shell, this function just sets the window.location.href to the given url.
 *
 * @param {String} url the new content page to display in the navigation shell.
 * @param {boolean} forceDuplicates (default: true) pass false to not reload the page when the url is identical to the current window token
 */
PTC.navigation.loadContent = function(url, forceDuplicates){
    if (forceDuplicates === undefined) {
        forceDuplicates = true;
    }
    if (PTC.navigation.fireEvent("beforeLoadContent", url) !== false) {
        var isDownload = PTC.navigation.isDownloadURL(url);

        if (!PTC.navigation.isShell() || isDownload || PTC.navigation.isCADURL(url)) {
            if (Ext.isGCF && isDownload) {
                //2124494 GCF runs some unload listeners of the main window starts a download
                //The downloadUrl might handle some doc types differently
               PTC.util.downloadUrl (url);
            }
            else {
                if (PTC.navigation.isArbortextURL(url) ) {
                    // SPR 2227429: Windchill page shows blank screen While Opening Any Dynamic Documents in Arbortext Editor. [Issue Specific to Internet Exlprorer 10].
                    getWindowForArbortextProtocol().location.href = url;
                }
                else {
                    getWindow().location.href = url;
                }
            }
            return;
        }
        //Force IE to unload window.top after MAX page hits, see doc on MAX_IE_PAGE_COUNT for more info.
        if (PTC.navigation._attemptAggressiveCleanup && PTC.navigation.pageCount >= PTC.navigation.MAX_IE_PAGE_COUNT) {
            var newPage = PTC.navigation.getTimeStampedUrl(url);
            getWindow().location.href = newPage;
            return;
        }
        if (PTC.navigation.HISTORY_STARTED === true && Ext.getDom(PTC.navigation.activeContentID) !== undefined && (forceDuplicates!==true || Ext.History.getToken() !== PTC.navigation.getTokenFromUrl(url))) {
            PTC.navigation.addHistoryToken(url);
        }
        else {
            PTC.navigation._loadContent(url);
        }
    }
};

/**
 * Determines if the url is appropriate in the content area of the shell (ie. it contains the same base href)
 * # is ignored since that is often used for no-op links
 * javascripts hrefs are not added as part of the history
 * @param {String} url
 */
PTC.navigation.isEmbeddedUrl = function(link){
    if (!link) {
        return false;
    }
    var url = link.href;
    var target = link.target;
    if (target && target !== "" && target !== "_parent" && target !== "_top") {
        return false;
    }
    if (!url) {
        return false;
    }
    if (PTC.util.isJSUrl(url)) {
        return false;
    }
    if (url.indexOf(getBaseHref()) >= 0 && url.length >= (getBaseHref().length + 1)) {
        return true;
    }
    return false;
};
/**
 * isShell=true means the current window has a content area that content should be loaded into.
 * @return {boolean} true if this window is a shell or if this window is an iframe inside
 *         the content area of a shell window (e.g. the workspace table),
 *         false if this window is not a shell (e.g. is a wizard or lightbox iframe)
 */
PTC.navigation.isShell = function(){
    var shellWindow = getWindow();
    if (!("Ext" in shellWindow)) {
        return false;
    }
    var cp = shellWindow.Ext.getCmp(PTC.navigation.cardManager);
    if (cp) {
        return true;
    }
    // look for "/app/" in the pathname of the window URL
    var appPatt = new RegExp("/app/");
    var shellPatt = new RegExp("shell.jsp");
    try {
        return shellWindow.location.pathname.search(appPatt) > 0 ||
        shellWindow.location.pathname.search(shellPatt) > 0;
    }
    catch (e) {
        return window.location.pathname.search(appPatt) > 0 ||
        window.location.pathname.search(shellPatt) > 0;
    }
};
/**
 * Reload the content area of the shell based on the form's action.
 * @param form - the form to submit to refresh the page, will use mainform if null
 */
PTC.navigation._reloadShellContentArea = function(form){
    if (!form) {
        form = getMainForm();
    }
    var params = Form.serialize(form);
    var contentId = PTC.navigation.activeContentID;
    // Take form's parent div to perform form's action (for example so actions launched from navigator search page reload search tab)
    // But NOT for htmlcompMF form since parent of that dom element is often not the correct one to refresh - SPR 1842606
    if (form.parentNode && form.parentNode.id !== undefined && form.name !== 'htmlcompMF') {
        contentId = form.parentNode.id;
    }
    PTC.navigation.initiateRequest(form.action, contentId, params,
        function(req){
            PTC.navigation.onSuccessRequest(req, contentId);
        },
        function(req){
            PTC.navigation.onFail(req, contentId);
        });
};
/**
 * id of the content area panel
 */
PTC.navigation.contentTabID = 'contentPanel';
PTC.navigation.cardManager = 'contentPanel_parent';
/**
 * Does the actual content loading, Will not add history event or a token to the location address
 * @param {Object} page
 */
PTC.navigation._loadContent = function(page){
    //TODO: set document.title of shell and title of iframe to content title
    PTC.navigation.log.time("loadContent");
    if (PTC.navigation.fireEvent("historyChange", page) !== false) {
        if (!PTC.navigation.isShell()) {
            getWindow().location.href = page;
            return;
        }
        if (!page || page === "#") {
            page = PTC.navigation.NAVIGATION_DEFAULT_HOME_PAGE;
            var value = PTC.jca.state.ServerStateProvider.get(PTC.navigation.CLOSE_WELCOME_PAGE);
            if (!value) {
                page = PTC.navigation.NAVIGATION_WELCOME_PAGE;
            }
        }
        PTC.navigation.pageCount++;
        PTC.navigation._setActiveLayout(page);
        page = PTC.navigation._updateLoadContentURL(page);
        PTC.navigation.initiateRequest(page);
        PTC.navigation.fireEvent("afterLoadContent", page);
    } else {
        PTC.navigation.log.debug('PTC.navigation._loadContent: content not loaded for ', page, ' as historyChange event returned false');
    }
};
/**
 * Update the loadContentURL, to add portlet query paramater if not present
 * @private
 *
 * @param {String} url
 */
PTC.navigation._updateLoadContentURL = function(url){
    if (!(extractParamValue(url, "portlet"))) {
        // force a page fragment, avoid rendering the top, such as the <html>,<meta>,and <script> tags.
        var token = url.split("#")[1];
        if(token){
            url = url.replace(token, requestHandler.addURIParam(token, 'portlet', 'component', true)); 
        } else {
            url = requestHandler.addURIParam(url, 'portlet', 'component', true);
        }
    }
    return url;
};
/**
 * Does all the work needed to initiate a request for new content in the shell.
 * Such as cleaning up the current card, displaying the load indicator, and caching the request in case it needs to be aborted later.
 *
 * @param {string} page - url to load into the given id
 * @param {string} [id] - id of the content area to fill. For example id from main content area or from navigator
 * @param {string} [params] - serialized form data
 * @param {function} [onSuccess] - function to call onsuccess
 * @param {function} [onFail] - function to call onfail
 */
PTC.navigation.initiateRequest = function(page, id, params, onSuccess, onFail) {
    id = id || PTC.navigation.activeContentID;
    PTC.navigation.stopInProgressPages();
    if(!$(id)) {
        PTC.navigation.log.error('Cannot load new content into id ' + id +
                                 ' because no dom element with that id exists in this window ' + window.location.href +
                                 '. Attempting to reload the window...');
        getWindow().location.reload();
        return;
    }
    params = params || '';
    onSuccess = onSuccess || PTC.navigation.onSuccessRequest;
    onFail = onFail || PTC.navigation.onFail;
    var cp = Ext.getCmp(PTC.navigation.cardManager);
    var cd = Ext.get(id);
    if (cd) {
        PTC.navigation.setInProgress(cd.dom, cp.getInnerHeight() * 0.85);
    }
    PTC.pageTitleSet = false;
    PTC.navigation.addOpenRequest(getElementHtml(params, id, true, PTC.navigation.getTokenFromUrl(page), false, onSuccess, onFail));
};
/**
 * Ensures that only the first attempt to set the title of the page is successful.
 */
PTC.pageTitleSet = false;
/**
 * Sets the title of the page. First checks to see if the page title has been set yet and, if not, sets it.
 * To override the page title you must reset pageTitleSet to false or call document.title directly.
 *
 * This API was created for the type manager which is calling getItemIDItems twice and therefore trying to set the page title
 * twice. Simply setting document.title in this case does not work. In most cases it is not necessary to use this or any method to set the
 * page title and simply setting document.title is sufficient
 *
 * @param {Object} title string to set as the new page title
 */
PTC.navigation.setPageTitle = function(title) {
    if (!PTC.pageTitleSet && title!== "") {
        document.title = title;
        PTC.pageTitleSet = true;
    }
};
/**
 * Reloads the current page using the browser reload function
 */
PTC.navigation.reloadWholeWindow = function() {
    getWindow().location.reload();
};
/**
 * Reloads the current page. If the context is the main window (the shell) only reload the content area
 * Use PTC.navigation.submitForm(form) if a form needs to be posted for the reload.
 */
PTC.navigation.reload = function(){
    if (PTC.navigation.isShell()) {
        PTC.navigation._reloadShellContentArea();
    }
    else {
        var mainPageHref = getWindow().location.href;
        getWindow().location.href = mainPageHref;
    }
};
/**
 * Submits the form of the current page to refresh, if the shell is active then it will use ajax post
 * @param form - the form to submit to refresh the page, will use mainform if no form specified
 */
PTC.navigation.submitForm = function(form){
    if (PTC.navigation.isShell()) {
        PTC.navigation._reloadShellContentArea(form);
        // the selected objects for tables are outside the main form and will not be cleared automatically anymore
        var root = (form) ? form : getMainForm();
        unSelectAll(document.getElementsByTagName("input"), undefined, root);
    }
    else {
        if (!form) {
            form = getMainForm();
        }
        form.submit();
    }
};

/**
 * Initialize listeners to keep content in the shell area.
 * Called by loadMainShell() (and also as the page is loading)
 */
PTC.navigation.initShellListeners = function() {
    //SPR 2087797: click event does not have correct mouse buttons mapped in IE. mouseup does.
    Ext.EventManager.on(window.document, 'mouseup', PTC.navigation.saveMouseUpButtonClickInfo);
    Ext.EventManager.on(window.document, 'click', PTC.navigation.remapNavigationLinks);
    // make it no-op to ensure these listeners are only attached once per page
    PTC.navigation.initShellListeners = TRUE_FUNC;
};
// Necessary so 'shell' pages that don't call loadMainShell() still get shell listeners
// For example, workspace iframe nested inside the shell will also get the listeners
if(PTC.navigation.isShell()) {
    PTC.navigation.initShellListeners();
}

/**
 * puts the two-panes layout card active, and uses the two urls to load content into the 2 panes.
 * The headerUrl is optional, and loads the content above the two-panes. This is only available for the horizontal orientation.
 * @param {Object} leftPaneUrl
 * @param {Object} rightPaneUrl
 * @param {Object} clickHandler
 * @param {Object} orientation Layout of the panes, expected to be one of two strings: vertical | horizontal
 * @param {Object} paneSizes JSON object that has a 'left' and/or a 'right' attribute and optionally a 'header' attribute.
 *                 For example: {left: 25, right: 75} or {left: 250, right: 850}
 * @param {Object} [headerPaneUrl] Optional header url
 */
PTC.navigation.loadTwoPanes = function(leftPaneUrl, rightPaneUrl, clickHandler, orientation, paneSizes, headerPaneUrl){
    var cp = Ext.getCmp(PTC.navigation.cardManager);
    if (!cp) {
        var recallFunc = function(){
            PTC.navigation.loadTwoPanes(leftPaneUrl, rightPaneUrl, clickHandler, orientation, paneSizes, headerPaneUrl);
        };
        //if ext is already loaded, we must defer the new call  this loadTwoPane function because there would be an infinite recursion.
        //The card manager is probably scheduled to run but after this load call
        Ext.onReady(function() { recallFunc.defer(1);});
        return;
    }
    PTC.navigation.clearCurrentCard();
    var activeItemId = PTC.navigation.contentTabID + "_twoPanes_" + orientation;
    cp.layout.setActiveItem(activeItemId);
    PTC.navigation.setActiveContentArea(cp.layout.activeItem.CONTENT_DIV);
    cp.layout.activeItemId = activeItemId;
    cp.layout.leftPaneBaseUrl = encodeURIComponent(leftPaneUrl.split("?")[0]);
    cp.layout.paneSizes = paneSizes;
    cp.layout.orientation = orientation;
    var hasPanesResized = PTC.navigation.resizePanes(Ext.getCmp(activeItemId), paneSizes, orientation);
    // Load the Header Pane
    if (headerPaneUrl && headerPaneUrl !== 'null') {
        PTC.navigation.loadHeaderPane(headerPaneUrl);
    }
    else if (orientation === 'horizontal' && typeof cp.getHeaderPane === 'function') {
        var headerPane = cp.getHeaderPane();
        headerPane.hide();
    }
    // Load the Left/Top Pane
    if (PTC.isDefined(leftPaneUrl) && leftPaneUrl !== "#" && paneSizes.left > 0) {
        PTC.navigation.loadLeftPane(leftPaneUrl);
    } else {
        if (typeof cp.getNavPane !== 'function') {
           cp.getNavPane = function(){
               // remove when all usages have defined the function
               return this.findById(PTC.navigation.contentTabID + '_twoPanes_left');
           };
        }
        cp.getNavPane().hide();
    }
    // Load the Right/Bottom Pane
    if (PTC.isDefined(rightPaneUrl) && rightPaneUrl !== "#" && paneSizes.right > 0) {
        PTC.navigation.loadRightPane(rightPaneUrl, false);
    } else {
        if (typeof cp.getDetailPane !== 'function') {
           // remove when all usages have defined the function
            cp.getDetailPane = function() {
                return this.findById(PTC.navigation.contentTabID + '_twoPanes_center');
            };
        }
        cp.getDetailPane().hide();
    }
    // the left or right panes have changed size so re-load the layout of the top panel
    if(hasPanesResized) {
        cp.doLayout(false, true);
    }
    if (clickHandler) {
    Event.stopObserving(cp.layout.activeItem.getEl().dom, 'click');
    Event.observe(cp.layout.activeItem.getEl().dom, 'click', clickHandler);
    }
};
/**
 * Handy method for loading a url into the active layout's header pane
 * This will fail if the current card is not a two-panes card with horizontal orientation.
 * @param {String} url
 */
PTC.navigation.loadHeaderPane = function(url){
    var cp = Ext.getCmp(PTC.navigation.cardManager);
    cp.layout.activeItem.headerPaneUrl = url;

    var options = {};
    options.parameters = '';
    options.asynchronous = true;
    options.on501 = PTC.navigation.navPanesHandlerOn501;     //Setting function to handle 501 exception.
    getElementHtml('', cp.layout.activeItem.header_id, true, cp.layout.activeItem.headerPaneUrl, false, '', '', options);
};

/**
 * Method to display error message in layout's header pane in case of 501 exception. The method also resize layout's
 * header pane and hide left and centre pane to accomodate the message.
 * @param {Object} response
 */
PTC.navigation.navPanesHandlerOn501=function(response) {

     var headerPaneDiv = Ext.getDom('headerPane');
     if (headerPaneDiv && response.responseText.indexOf('ATTENTION:  Secured Action') > 0) {
          headerPaneDiv.childNodes[0].childNodes[0].childNodes[0].innerHTML = response.responseText;

          var headerPaneCmp = Ext.getCmp('headerPane');
          headerPaneCmp.resizedDueException = true; // set a flag
          headerPaneCmp.setHeight(200);
          var contentPanelTwoPanesLeftCmp = Ext.getCmp('contentPanel_twoPanes_left');
          contentPanelTwoPanesLeftCmp.hide(); // hide it
          contentPanelTwoPanesLeftCmp.resizedDueException = true;
          var contentPanelTwoPanesCenterCmp = Ext.getCmp('contentPanel_twoPanes_center');
          contentPanelTwoPanesCenterCmp.hide();
          contentPanelTwoPanesCenterCmp.resizedDueException = true;
     }
};

/**
 * Method to reset the flag indicating resizing of navigation panes.
 * @param {Ext.Panel} navSubPanel- Navigation Pane Table Container
 * @param {boolean} showFlag- if true, then show the panel
 */
PTC.navigation.resetNavPanesFlag=function(navSubPanel, showFlag) {
     if (navSubPanel.resizedDueException) {
          navSubPanel.resizedDueException = undefined;
         if (showFlag===true) {
               navSubPanel.show();
          }
     }
};

/**
 * Handy method for loading a url into the active layout's left_id pane
 * This will fail if the current card is not a two-panes card.
 * @param {String} url
 */
PTC.navigation.loadLeftPane = function(url){
    var cp = Ext.getCmp(PTC.navigation.cardManager);
    url = url + '&portlet=poppedup&leftPaneOnly=true';
    cp.layout.activeItem.leftPaneUrl = url;
    getElementHtml('', cp.layout.activeItem.left_id, true, cp.layout.activeItem.leftPaneUrl, false);
};
/**
 * Handy method for loading a url into the active layout's content pane
 * @param {String} url
 * @param {boolean} addHistoryEntry to make the url become a history entry
 */
PTC.navigation.loadRightPane = function(url, addHistoryEntry){
    var cp = Ext.getCmp(PTC.navigation.cardManager);
    url += url.indexOf("?")>0? '&':'?';
    url = url + 'portlet=poppedup&rightPaneOnly=true';
    url = url + '&setActiveLayout=' + cp.layout.activeItemId;
    url = url + '&leftPane=' + cp.layout.leftPaneBaseUrl;
    cp.layout.activeItem.rightPaneUrl = url;
    if (addHistoryEntry) {
        PTC.navigation.loadContent(cp.layout.activeItem.rightPaneUrl);
    }
    else {
        PTC.navigation._loadContent(cp.layout.activeItem.rightPaneUrl);
    }
};
/**
 * Get the url of the current active right pane
 */
PTC.navigation.getRightPaneUrl = function(){
    var cp = Ext.getCmp(PTC.navigation.cardManager);
    return cp.layout.activeItem.rightPaneUrl;
};
/**
 * Get the url of the current active header pane
 */
PTC.navigation.getHeaderPaneUrl = function(){
    var cp = Ext.getCmp(PTC.navigation.cardManager);
    return cp.layout.activeItem.headerPaneUrl;
};
/**
 * Will resize the panes in the paneHolder.items array to the specified sizes.
 * If the orientation is set to vertical it will change the height of the panes,
 * otheriwise it will change the width of the panes.
 *
 * @param {Ext.Component} paneHolder The Ext component that holds the two panes
 * @param {Object} paneSizes JSON object that has a 'left' and/or a 'right' attribtute.
 * If the values of the left and right equal 100, then it's assumed to be a percentage otherwise it will use the pixel value.
 * Example usages: {left: 25, right: 75} or {left: 250, right: 850}
 * @param {String} orientation Layout of the panes, expected to be one of two strings: vertical | horizontal
 */
PTC.navigation.resizePanes  = function(paneHolder, paneSizes, orientation) {
    var hasResizedPanes = false;
    if(!paneHolder || paneHolder.ctype !== 'Ext.Component') {
        return hasResizedPanes;
    }
    if(paneSizes) {
        var pane1Size = Math.abs(paneSizes.left);
        var pane2Size = Math.abs(paneSizes.right);
        // calculate the appropriate sizes of the left/top and right/bottom panels if
        // the provided sizes equal 100(%)
        if(!isNaN(pane1Size) && !isNaN(pane2Size)) {
            var parentSize = (orientation === 'horizontal') ? paneHolder.getWidth() : paneHolder.getHeight();
            // if the sum of the left and right widths add up to 100, assume they are percentages
            if((pane1Size + pane2Size) === 100) {
                pane1Size = (pane1Size/100) * parentSize;
                pane2Size = (pane2Size/100) * parentSize;
                pane1Size = Math.floor(pane1Size);
                pane2Size = Math.round(pane2Size);
            }
        }
        // set the height/width of the top/left pane
        var paneToResize = paneHolder.getNavPane();
        if (PTC.navigation.resizePane(paneToResize, pane1Size, orientation)) {
            hasResizedPanes = true;
        }
        // set the height/width of the bottom/right pane
        paneToResize = paneHolder.getDetailPane();
        if (PTC.navigation.resizePane(paneToResize, pane2Size, orientation)) {
            hasResizedPanes = true;
        }
        // set the height of the header pane if it exists and the orientation is horizontal.
        if (orientation === "horizontal") {
            if (paneSizes.header) {
                var headerPaneSize = Math.abs(paneSizes.header);
                var headerPane = paneHolder.findById('headerPane');
                if(headerPane && !isNaN(headerPaneSize)) {
                    headerPane.setHeight(headerPaneSize);
                    hasResizedPanes = true;
                }
            }
        }
    }
    return hasResizedPanes;
};
/**
 * Will resize the pane to the specified size.
 * If the orientation is set to vertical it will change the height of the pane,
 * otheriwise it will change the width of the pane.
 *
 * @param {Ext.Component} pane The Ext component for either the top/left of bottom/right pane.
 * @param {Object} paneSize The size of the pane in pixels.
 * @param {String} orientation Layout of the panes, expected to be one of two strings: vertical | horizontal
 **/
PTC.navigation.resizePane = function(pane, paneSize, orientation) {
    var hasResizedPane = false;
    if(pane && !isNaN(paneSize)) {
        if (orientation === "vertical") {
            pane.setHeight(paneSize);
        } else {
            pane.setWidth(paneSize);
        }
        hasResizedPane = true;
    }
    return hasResizedPane;
};
/**
 * Internal event listener to resize the 2 panes after a pinned navigator move
 */
PTC.navigation._resizeTwoPanesAfterLayout = function() {
    var tables = PTC.jca.table.Utils.getExtTables(this.el.dom);
    var len = tables.length;
    for (var i=0; i<len; i++) {
       tables[i].setHeight(tables[i].oldHeight+6);
    }
};
/**
 * Resets the two pane component to the original sizes and reruns the layout on the panel
 * and tables.  Useful after a substantial browser resize or pinning or unpinning the
 * navigator, for example.
 */
PTC.navigation.resetTwoPanes = function() {
    var cp = Ext.getCmp(PTC.navigation.cardManager);

    if (cp && cp.layout.activeItemId && cp.layout.activeItem.id.indexOf("_twoPanes_") > 0) {
        var tables = PTC.jca.table.Utils.getExtTables(cp.el.dom);
        for (var i=0; i<tables.length; i++) {
            tables[i].oldHeight = tables[i].height;
        }
        if (PTC.navigation.resizePanes(Ext.getCmp(cp.layout.activeItemId), cp.layout.paneSizes, cp.layout.orientation)) {
            cp.doLayout(false, true);
            cp.on("afterLayout", PTC.navigation._resizeTwoPanesAfterLayout, null, {single:true});
        }
    }
};
/**
 * Removes the content of the active card and sets the in progress image.
 */
PTC.navigation.clearCurrentCard = function(){
    var cp = Ext.getCmp(PTC.navigation.cardManager);
    if (!cp || !cp.layout || !cp.getEl().dom) {
        return false;
    }
    var activeItem = cp.layout.activeItem;
    //If there is ever an error setting a card panel, the active item may not be set
    // this lets the system continue from a crash without a hard restart
    if (activeItem) {
        return activeItem.clearCardContents();
    }
};
/**
 * Changes the div to have an in progress loading image.
 * @param {HTMLElement} obj - dom element to overwrite with in progress image
 * @param {Number} height - in pixels.
 */
PTC.navigation.setInProgress = function(obj, height){
    if (!obj) {
        return;
    }
    if (!height) {
        height = 200;
        if (obj) {
            height = obj.offsetHeight * 0.9;
        }
        else {
            height = window.document.height * 0.4;
        }
        if (height < 200) {
            height = 200;
        }
    }
    var contentLoadingMaskId = "contentLoadingMask";
    if (obj.id) {
        contentLoadingMaskId += "_" + obj.id;
    }
    PTC.navigation.overwrite(obj, '<div id="' + contentLoadingMaskId + '" style="height:' + height + 'px">&nbsp;</div>');
    // show a loading indicator after a short delay.
    PTC.navigation.startProgressTask(contentLoadingMaskId);
    //garbage collect after overwrite in case there were Ext components tied to those dom elements that can be trashed
    Ext.garbageCollect();
};
/**
 * Adds the contentLoading CSS class to the element specified by the id parameter after
 * a pause of several milliseconds.  That class sets a loading indicator on the background of the element.
 *
 * This increases perceived performance by only showing a loading indicator if there is a delay.
 *
 * @param {String} id
 */
PTC.navigation.startProgressTask = function(id){
    var progressTaskFunc = function(){
        var mask = Ext.getDom(id);
        if (mask) {
            Ext.fly(mask).addClass("contentloading");
        }
        progressTaskFunc = null;
    };
    var taskid = setTimeout(progressTaskFunc, 400);
    return taskid;
};
PTC.navigation_this = this;
/**
 * Evaluates all the script blocks on the page in the global scope after concatenating them together to act more like the browser.
 * @param {String} text that contains the script blocks (page source).
 */
PTC.navigation.evalPageScripts = function(text){
    var sts = text.extractScripts();
    if (!sts || sts.length <= 0) {
        return false;
    }
    var item = sts.join(";\n ");
    PTC.navigation._evalScripts(item);
};
/**
 * evals the given js text
 * @param {String} text - a string of javascript
 */
PTC.navigation._evalScripts = function(text){
    if (PTC.navigation_this.execScript) {
        PTC.navigation_this.execScript(text, "javascript");
    }
    else {
        PTC.jslint.foundEvalReservedWord(text,PTC.navigation_this);
    }
};
PTC.navigation.loadedscripts = [];
/**
 * Adds new js files to the page, using ajax call to get the js content and execScript/eval on the response.
 * Will keep track of already loaded scripts so as not to pay penalty for loading again.
 *
 * Firefox will always reload the js file after any modifications are made, but IE caches the js responses
 * so modifications to the js file may not immediately be loaded.
 * If jsDebug is enabled the changes are loaded immediately, otherwise the changes would be picked up the next Sunday.
 *
 * @example
 * PTC.navigation.loadScript('netmarkets/javascript/change2/changeWizard.js');
 * PTC.navigation.loadScript('tempaltes/uwgm/cadx/caddoc/references/referenceLink.js');
 *
 * @param {String} src Path of the new file to add relative to codebase.
 * @param {boolean} reload - force reload even if the script was already loaded
 */
PTC.navigation.loadScript = function(src, reload){
    var srcNotLoadedYet = src.indexOf(".js") > 0 && PTC.navigation.loadedscripts.indexOf(src) < 0;
    if (srcNotLoadedYet || reload) {
        //if given src string is already fully qualified, don't add base href again
        var base = getBaseHref();
        var fullyQualifiedSrc = (src.indexOf(base) === 0) ? src : base + src;
        var options = {
            method: 'get',
            asynchronous: false, // wait for js file load to be completed before continuing
            evalJS: false, // plan to eval later in window execution context
            onSuccess: function(transport){
                var forDebugger = "\n//# sourceURL="+fullyQualifiedSrc;
                PTC.navigation._evalScripts(transport.responseText + forDebugger);
                //could be multiple tables loading in parallel on the info page trying to load the same js
                //make sure script is fully loaded before counting it as a loaded script
                if(PTC.navigation.loadedscripts.indexOf(src) < 0) {
                    PTC.navigation.loadedscripts.push(src);
                }
            }
        };
        //with no cacheBuster param, browsers skip the request entirely and use response from their cache regardless of timestamps
        //with cacheBuster param browsers will pick up changes at least once a week, or every time if jsDebug is enabled.
        //          NOTE: bizarrely firefox adds 'If-Modified-Since' and 'If-None-Match' request headers once some param is on the URL
        //                so cacheBuster param could be a constant for firefox instead of changing based on current date
        var cacheBuster = reload ? new Date() : PTC.util.getWeeklyCacheBuster(new Date());
        var url = fullyQualifiedSrc + ((fullyQualifiedSrc.indexOf("?")<0)? '?cb=':'&cb=') + cacheBuster.getTime();
        return (new Ajax.Request(url, options));
    }
};
/**
 * D-11184 Makes the anchor around each node larger, conceptually. So a user doesn't have to click the text of
 * each node to navigate. This will enlarge the anchor for the root node as well as the children.
 *
 * @param {Ext.tree.TreeLoader} treeLoader
 * @param {Ext.tree.TreeNode} treeNode
 */
PTC.navigation.increaseNodesClickableArea = function(treeLoader, treeNode) {
    treeNode.on('click', PTC.navigation.navigateToNodeHref);
    treeNode.childNodes.each(function(childNode) {
        childNode.on('click', PTC.navigation.navigateToNodeHref);
    });
};
/**
 * Takes the user to the node's anchor location by 'clicking' the anchor.
 *
 * @param {Ext.tree.TreeNode} treeNode
 * @param {Ext.EventObject} event
 */
PTC.navigation.navigateToNodeHref = function(treeNode, event) {
    var link = null;
    var eventTarget = null;
    // sometimes event is null, gracefully handle that case
    if (event) {
        link = event.getTarget("A");
        eventTarget = event.target;
    }
    if (!link) { // if a link is the target, don't follow the link twice
        var anchorFromDom = treeNode.ui.anchor;
        if (anchorFromDom.click) {
            // just call click if its available (Chrome, Firefox, IE)
            anchorFromDom.click();
        }
        else if (document.createEvent && eventTarget !== anchorFromDom) {
            // Handle case when there is no click method.
            // Is this logic for older versions Firefox/Gecko (Creo/UWGM)?
            // Perform the eventTarget check so this isn't recursively clicked a bunch of times.
            var e = document.createEvent("MouseEvents");
            // Firefox requires the extra security to prevent popups and such, so initMouseEvent is ugly.
            // See https://developer.mozilla.org/en/DOM/document.createEvent
            e.initMouseEvent('click', true, true, window, 0, 0, 0, 0, 0, false, false, false, false, 0, null);
            anchorFromDom.dispatchEvent(e);
        }
    }
};
/**
 * Parses the given navigation object into accordion items for the accordion nav tree.
 * @param {Object} mainNavItems
 * @return {Array} an array of accordion items.
 */
PTC.navigation.getAccordionItems = function(mainNavItems){
    var accordionItems = [];
    var accordionStyles = "";
    // declare functions outside the loop
    var getStateFunc = function(){ // Returns expanded nodes array to save it in client session.
        var state = {};
        var expanded = [];
        for (var id in this.nodeHash) {
            if (this.nodeHash.hasOwnProperty(id)) {
                var node = this.nodeHash[id];
                if (node.expanded) {
                    expanded.push(node.getPath());
                    if (!node.isRoot) {
                        expanded.remove(node.parentNode.getPath());
                    }
                }
            }
        }
        state = {
            "expanded": expanded
        };
        return state;
    };
    var applyStateFunc = function(state){ // Expands nodes in client session.
        if (state.expanded && state.expanded.length > 0) {
            this.addListener('load', function(node){
                if (!this.rendered) {
                    return;
                }
                var treeState = Ext.state.Manager.get(node.getOwnerTree().getId());
                var expandedLen = treeState.expanded.length;
                for (var i = 0; i < expandedLen; i++) {
                    var path = treeState.expanded[i];
                    this.expandPath(path);
                }
            });
        }
    };
    var onNodeClickFunc= function(e, node){
        onNodeClick_orig(e, node);
        node.ui.removeClass('x-tree-selected');
    };
    for (var i = 0, l = mainNavItems.length; i < l; i++) {
        var action = mainNavItems[i];
        if (action.icon) {
            accordionStyles += "." + action.id + "-icon { background: url(" + action.icon + ") no-repeat !important; } \n";
            action.iconCls = action.id + "-icon";
            action.tabTip = action.title;
            action.title = null;
        }
        var navigatorPanelEnabled = PTC.navigator.isNavigatorEnabled();
        var treePanel;
        if(action.actionModelName===null || action.actionModelName===undefined){
            action.useArrows = true;
            action.animate = true;
            action.autoScroll = true;
            var _treeLoaderConfig = action.treeLoader;
            if(_treeLoaderConfig){
                _treeLoaderConfig.requestMethod='GET';
            }
            action.loader = new Ext.tree.TreeLoader(_treeLoaderConfig);
            // Expand the clickable area for each node once they load.
            action.loader.on('load', PTC.navigation.increaseNodesClickableArea);
            action.containerScroll = true;
            action.rootVisible = false;
            if (navigatorPanelEnabled) {
                action.tools = [];
                if(action.listActionUrl) { // View all link for particular context.
                    action.tools.push({
                        title: action.listActionTitle,
                        id: 'viewAll',
                        qtip: action.listActionTip,
                        href: action.listActionUrl,
                        handler: PTC.navigator.viewAllHandler
                    });
                    action.toolTemplate= new Ext.XTemplate('<div class="x-tool navigator-treePanel-tool-{id}"><a href="{href}">{title}</a></div>');
                }
                action.bodyCssClass = 'navigator-treePanel-body';
                action.headerCfg  = {
                    tag: 'div',
                    cls: 'x-panel-header navigator-treePanel-header',
                    html: action.tabTip
                };
                action.headerAsText = false;
                action.stateful = true;
                action.stateEvents = ['expandnode', 'collapsenode'];
                action.getState = getStateFunc;
                action.applyState = applyStateFunc;
                Ext.state.Manager.setProvider(new PTC.jca.state.ClientStateProvider()); // Maintain session stickiness.
                treePanel = new Ext.tree.TreePanel(action);
            }
            else {
                treePanel = new Ext.ux.TreePanelStateful(action);
            }
            var onNodeClick_orig = treePanel.eventModel.onNodeClick;
            treePanel.eventModel.onNodeClick = onNodeClickFunc;
            treePanel.autoWidth = true;
            treePanel.tabCls = 'navigator-tab';
            var treePanelRoot = new Ext.tree.AsyncTreeNode(action.root);
            treePanel.setRootNode(treePanelRoot);
            // Should we just do the single expansion by default or
            // expand them all to the saved expansion state?
            if (!navigatorPanelEnabled) {
                treePanelRoot.expand(false, false);
            }
            //treePanel.restoreState();
        } else { // SPR #1968095 Jackie - For the Action Model Report in the Browse tab.
            var debugurl = action.url;
            if(debugurl!==null && debugurl!==undefined){
                if(action.actionModelName!==null && action.actionModelName!==undefined){
                    if(debugurl.indexOf("?")>-1){
                        debugurl = debugurl + "&actionModelName=" + action.actionModelName + "&modelType=" + action.modelType;
                    }else{
                        debugurl = debugurl + "?actionModelName=" + action.actionModelName + "&modelType=" + action.modelType;
                    }
                }
            }
            var panelConfig = {
                id: action.id,
                icon: action.icon,
                iconCls: action.id + "-icon",
                tabTip: action.title,
                title: null,
                autoScroll: true,
                html:'<div id="' + action.id + '-contentDiv' + '"></div>',
                url: debugurl,
                tabCls: 'navigator-tab navigator-tab-text',
                autoWidth: true,
                listeners: {
                    activate: PTC.navigator.activatePanelListener
                }
            };
            treePanel = new Ext.Panel(panelConfig);
        }
        accordionItems.push(treePanel);
    }
    Ext.util.CSS.createStyleSheet(accordionStyles);
    return accordionItems;
};
/**
 * Gets the Ext Accordion Panel used for navigation
 */
PTC.navigation.getAccordionPanel = function(){
    var accordionItems = PTC.navigation.getAccordionItems(mainNavActions); //MainNavActions is global var from server
    var width = PTC.navigation.stateProvider.get('AccordionPanelWidth');
    if (!width) {
        width = 200;
    }
    var accordionPanel = new Ext.Panel({
        id: 'accordion',
        title: PTC.navigation.NAVIGATION_TITLE, // var set in shell.jsp
        region: 'west',
        width: width,
        split: true,
        minSize: 100,
        maxSize: 400,
        margins: '-2 0 0 0',
        cmargins: {
            left:0,
            top:-3,
            bottom:-3
        },
        collapsible: true,
        collapsed: false,
        layout: 'accordion',
        defaults: {
            collapsed: true
        },
        items: accordionItems
    });
    accordionPanel.on('afterlayout', function(c) {
        this.syncSize();
    }, accordionPanel, {
        single: true,
        delay: 500
    });
    return accordionPanel;
};
/**
 * Gets the panels needed by basic jca layouts
 */
PTC.navigation.getCommonPanels = function(){
    /* Main Content Area */
    var contentCenterTab = new PTC.jca.table.TableContainer({
        id: PTC.navigation.contentTabID,
        bodyCssClass: 'contentBody',
        split: true,
        autoScroll: true,
        bufferResize: false,
        autoWidth: true,
        margins: '5 5 1 0',
        CONTENT_DIV: PTC.navigation.contentID,
        html: '<div id="' + PTC.navigation.contentID + '"></div>'
    });
    /* Default Top Pane Area for the Horizontal Orientation */
    var headerPane = new Ext.Panel({
        id: 'headerPane',
        region: 'north',
        height: 64,
        bufferResize: false,
        width: '100%',
        autoWidth: false,
        html: '<div id="twoPanes_HEADERPANE"></div>',
        clearCardContents: function() {
            this.removeAll(true);
            var itemDisplayID = (this.itemIdLinePanelID) ? this.itemIdLinePanelID : 'itemDisplayID';
            var oldItemIdPanel = Ext.getCmp(itemDisplayID);
            if (oldItemIdPanel) {
                oldItemIdPanel.destroy();
            }
            Ext.getDom('twoPanes_HEADERPANE').innerHTML='';
            PTC.navigation.resetNavPanesFlag(this);
        },
        border: false
    });
    /* Default Horizontal Right Pane Area */
    var twoPanesCenter = new PTC.jca.table.TableContainer({
        id: PTC.navigation.contentTabID + '_twoPanes_center',
        cls: '',
        split: true,
        region: 'center',
        bufferResize: 10,
        autoScroll: true,
        clearCardContents: function() {
            Ext.getDom('twoPanes_RIGHTPANE2').innerHTML='';
            PTC.navigation.resetNavPanesFlag(this, true /*show the panel*/);
        },
        html: '<div id="twoPanes_RIGHTPANE2"></div>'
    });
    /* Default Horizontal Left Pane Area */
    var contentLeftTab = new PTC.jca.table.TableContainer({
        id: PTC.navigation.contentTabID + '_twoPanes_left',
        cls: '',
        region: 'west',
        collapsible: true,
        header: false,
        autoScroll: true,
        bufferResize: false,
        html: '<div id="twoPanes_LEFTPANE"></div>',
        split: true,
        clearCardContents: function() {
            Ext.getDom('twoPanes_LEFTPANE').innerHTML='';
            PTC.navigation.resetNavPanesFlag(this);
        }
    });
    /* Contains Border Layout for previous Two Panels */
    var twoPanesHorizontal = new Ext.Panel({
        id: PTC.navigation.contentTabID + "_twoPanes_horizontal",
        bodyCssClass: 'contentBody',
        layout: 'border',
        split: true,
        bufferResize: false,
        right_id: 'twoPanes_RIGHTPANE',
        left_id: 'twoPanes_LEFTPANE',
        header_id: 'twoPanes_HEADERPANE',
        CONTENT_DIV: 'twoPanes_RIGHTPANE2',
        items: [contentLeftTab, twoPanesCenter, headerPane],
        getHeaderPane: function() {
            return this.get('headerPane');
        },
        getNavPane: function() {
            return this.get(PTC.navigation.contentTabID + '_twoPanes_left');
        },
        getDetailPane: function() {
            return this.get(PTC.navigation.contentTabID + '_twoPanes_center');
        }
    });
    /* Default Vertical Bottom Pane Area */
    var twoPanesbottom = new PTC.jca.table.TableContainer({
        id: PTC.navigation.contentTabID + '_twoPanes_bottom',
        cls: '',
        split: true,
        bufferResize: false,
        region: 'center',
        autoScroll: true,
        clearCardContents: function() {
            Ext.getDom('twoPanes_BOTTOMPANE').innerHTML='';
        },
        html: '<div id="twoPanes_BOTTOMPANE"></div>'
    });
    /* Default Vertical Top Pane Area */
    var twoPanesTop = new PTC.jca.table.TableContainer({
        id: PTC.navigation.contentTabID + '_twoPanes_top',
        cls: '',
        region: 'north',
        collapsible: true,
        header: false,
        height: 200,
        bufferResize: false,
        autoScroll: true,
        clearCardContents: function() {
            Ext.getDom('twoPanes_TOPPANE').innerHTML='';
        },
        html: '<div id="twoPanes_TOPPANE"></div>',
        split: true
    });
    /* Contains Border Layout for previous two panels  */
    var twoPanesVertical = new Ext.Panel({
        id: PTC.navigation.contentTabID + "_twoPanes_vertical",
        bodyCssClass: 'contentBody',
        layout: 'border',
        split: true,
        bufferResize: false,
        CONTENT_DIV: 'twoPanes_BOTTOMPANE',
        right_id: 'twoPanes_BOTTOMPANE',
        left_id: 'twoPanes_TOPPANE',
        items: [twoPanesTop, twoPanesbottom],
        getNavPane: function() {
            return this.get(PTC.navigation.contentTabID + '_twoPanes_top');
        },
        getDetailPane: function() {
            return this.get(PTC.navigation.contentTabID + '_twoPanes_bottom');
        }
    });
    /* Card Manager for layouts just defined*/
    var contentCardManager = new Ext.Panel({
        id: PTC.navigation.cardManager,
        cls: 'contentTab',
        baseCls: 'x-box',
        frame: true,
        layout: 'card',
        region: 'center',
        margins: '0 6 0 6',
        activeItem: 0,
        bufferResize: false,
        width: '100%',
        border: false,
        split: true,
        flex : 1,
        items: [contentCenterTab, twoPanesHorizontal, twoPanesVertical]
    });
    /* Container for contentCardManager (two above panels)  */
    var contentArea = new Ext.Panel({
        id: PTC.navigation.contentTabID + "_contentArea",
        layout : {
            type : 'vbox',
            align : 'stretch' //required for IE to render horizontally
        },
        margins: '-2 0 0 -2',
        border: false,
        bufferResize: false,
        region: 'center',
        items: [contentCardManager]
    });
    return [contentArea];
};
/**
 * Removes the appropriate HTML DOM nodes and Ext components from the card when it becomes inactive.
 * This must be used to clear out the 'mainform' at a minimum but also it is best to remove any heavy DOM structures and intensive Ext components.
 * The card by default just hides its div element, so all the objects are still available.
 * This is the default implementation but it is expected that custom navigation cards will override this method.
 */
Ext.Panel.prototype.clearCardContents = function(){
    //set to null to ensure we don't have handle to obsolete mainform element
    PTC.util._setMainFormStartingElement(null);
    if (this.getEl()) {
        PTC.jca.table.Utils.cleanUp(this.getEl().dom);
    }
    if (this.items) {
        this.items.each(function(item){
            if (typeof item.clearCardContents === 'function') {
                item.clearCardContents();
            }
        });
    }
    if (Ext.getDom(this.CONTENT_DIV)) {
        return PTC.navigation.setInProgress(Ext.getDom(this.CONTENT_DIV));
    }
};
PTC.navigation.loadViewPort = function(pageItems){
   (function(){
    var viewport = new Ext.Viewport({
        layout: 'border',
        layoutConfig: {
            getNavigator: function(){
                return this.west;
            }
        },
        id: 'jca_viewport',
        items: pageItems,
        bufferResize: 50,
        autoWidth: true,
        listeners : {
            afterrender : function(v){
                // Navigator panel will continue to display until the user clicks outside of it.
                var navigator = v.layout.getNavigator();
                //make sure we are not in the type manager loading the accordion
                if(navigator && navigator.id === 'navigatorPanel') {
                    PTC.navigator.initialize(navigator);
                }
            },
            resize: PTC.navigator.onViewportResize,
            afterlayout : function(container, layout){
               if(layout.getNavigator() !== undefined && layout.getNavigator().isSlid){
                    PTC.navigator.moveNavigatorRight();
                    // Adjust width of content area when window is resized.
                    if(PTC.navigator.isPinned()) {
                        PTC.navigator.adjustWidthWhenPinned("unpin");
                    }
                }
            }
        }
    });
    })();
};

PTC.navigation.loadPopupShell = function(){
    Ext.EventManager.on(window, 'unload', PTC.wizard.unloadWizard);
    return PTC.navigation.loadViewPort(PTC.navigation.getCommonPanels());
};
PTC.mainWindow = null;
/**
 * PTC.mainWindow is set by loadMainShell, below.
 * If this window does not have its own reference to mainWindow,
 * it asks its opener for its version of the value, recursively.
 */
PTC.getMainWindow = function() {
    var returnVal = PTC.mainWindow;
    var found = false;
    if (!returnVal) {
        try {
            if (top.window.opener && top.window.opener.PTC) {
                returnVal = top.window.opener.PTC.getMainWindow();
                found = true;
            }
        }
        catch (e) {}
        if (!found) {
            // if the opener does not have this function, it doesn't have main.js
            // so this is the bottom of the chain, and it may as well be the main :-)
            returnVal = getWindow();
            if (returnVal && returnVal.PTC && returnVal.PTC.navigation && !returnVal.PTC.navigation.isShell() && returnVal.parent && returnVal.parent.PTC) {
                // for iframes in the main window. step out of the iframe and use the top shell window
                returnVal = returnVal.parent;
            }
        }
    }
    return returnVal;
};
/**
 * Clean up code, attempting to release memory in IE
 * Purging the doc seems to help, removing tables did not
 * @internal
 */
PTC.navigation.unloadShell = function() {
    PTC.navigation.log.trace('Entered PTC.navigation.unloadShell');
    PTC.util._setMainFormStartingElement(null);
    //Leave the DOM intact, but remove possible custom attributes or listeners
    PTC.util.purge(window.document);
    window.onload = null;
    window.onresize = null;
    window.onbeforeunload = null;
    window.onerror = null;

    var iframes = document.getElementsByTagName("iframe");
    var i = iframes.length;
    while (i--) {
        var iframeEl = iframes[i];
        try {
            var iframeNameOrId = iframeEl.getAttribute('name');
            if (!iframeNameOrId) { // if name is not found, then look for id. As such most of PTC defined iframes are named.
                iframeNameOrId = iframeEl.getAttribute('id');
            }
            PTC.navigation.log.debug('PTC.navigation.unloadShell: purging iframe ', iframeNameOrId, ' from dom');
            PTC.util.purge(iframeEl.contentWindow.document);
         } catch(e) {
            PTC.navigation.log.debug("PTC.navigation.unloadShell : Exception thrown while purging iframe contents.", iframeEl, e);
         }
    }
    PTC.purgeListeners();
    PTC.navigation.purgeListeners();
    PTC.wizard.purgeListeners();
    PTC.search.purgeListeners();
    PTC.driverAttributes.purgeListeners();
    PTC.attributePanel.purgeListeners();
    PTC.jca.dataSource.purgeListeners();
    PTC.menu.purgeListeners();
    PTC.infoPage.purgeListeners();
    delete PTC.navigation_this;
    Ext.destroy(PTC.infoPage, PTC.navigation, PTC.wizard, PTC.menu);
    Ext.EventManager.un(window, 'unload', PTC.navigation.unloadShell);
    PTC.navigation.unloadShell = null;
};
(function() {
if(PTC.navigation._attemptAggressiveCleanup && window.attachEvent) {
    var fnCleanUp = function () {
        var p = Function.prototype;
        delete p.createSequence;
        delete p.defer;
        delete p.createDelegate;
        delete p.createCallback;
        delete p.createInterceptor;
        delete p.argumentNames;
        delete p.bind;
        delete p.bindAsEventListener;
        delete p.curry;
        delete p.delay;
        delete p.prototype_defer;
        delete p.wrap;
        delete p.methodize;
        window.detachEvent("onunload", fnCleanUp);
        fnCleanUp=null;
    };
    window.attachEvent("onunload", fnCleanUp);
}
})();
PTC.navigation.loadMainShell = function(){
    PTC.mainWindow = window;
    PTC.navigation.initShellListeners();
    // logic in isShell is not robust enough to correctly identify all shells
    // so set isShell to TRUE_FUNC to be sure this window is identified as a shell
    PTC.navigation.isShell = TRUE_FUNC;
    if (! ('onhashchange' in window)) {
       //Fields required for history management in IE7 and SeaMonkey 1.1.18
       var historyDiv = document.createElement('DIV');
       historyDiv = document.body.appendChild(historyDiv);
       historyDiv.innerHTML = '<form id="history-form" class="x-hidden" style="visibility:hidden">'+
            '<input type="hidden" id="x-history-field" />'+
            '<iframe id="x-history-frame"></iframe>'+
            '</form>';
    }
    Ext.History.init();
    PTC.navigation.HISTORY_STARTED = true;
    var header = new Ext.Panel({
        id: 'header',
        header: false,
        region: 'north',
        bufferResize: false,
        margins: '0 0 0 0',
        height: 80, //upped this from 59 to 80 for the Ext 3.0 to 3.2 upgrade. Otherwise the header content was getting cutoff?
        bwrapCfg: {
            style:'height:41px'
        }, // 59(Panel height) - 18(Panel body padding-top) = 41 ?? panel height is up to 80 now, header looks fine so apparently this doesn't have to change??
        html: '<div id="pageHeaderActions"></div><div id="globalSearch"></div><div id="typeChooserTrigger"></div><div id="divider"></div>'
            + '<table><tr><td><div id="logoNav" class="' + PTC.navigation.HEADER_CLASS + '"></div></td><td><span id="globalUser"></span></td></tr></table>',
        listeners: {
            afterrender: function(headerCmp) {
                PTC.navigation.fireEvent("afterHeaderRender", headerCmp);
            }
        }
    });
    var pageItems = PTC.navigation.getCommonPanels();
    pageItems.push(header);
    var breadcrumb = new PTC.navigation.breadcrumb.HeaderPanel();
    Ext.getCmp(PTC.navigation.contentTabID + "_contentArea").insert(0, breadcrumb);
    var navigatorPanelEnabled = PTC.navigator.isNavigatorEnabled();
    var accordion = null;
    if(!navigatorPanelEnabled) {
        accordion = PTC.navigation.getAccordionPanel();
        pageItems.push(accordion);
    } else {
        var navigatorPanel = PTC.navigator.getNavigatorPanel();
        pageItems.push(navigatorPanel);
        Ext.EventManager.on(window.document, 'click', PTC.navigator.slideInIf);
    }
    PTC.navigation.loadViewPort(pageItems);

    // Handle this change event in order to restore the UI to the appropriate history state
    Ext.History.on('change', PTC.navigation._loadContent);
    // only one # is expected.  If other anchors are present, they are ignored
    //Using href inplace of document.location.hash , becuase mozilla incorrectly decodes URLS with document.location.hash.
    var token = document.location.href.split("#")[1];
    var rightPaneOnly = extractParamValue(token, "rightPaneOnly");
    if ('true' == rightPaneOnly) {
        // restoring 2 pane component
        token = decodeURIComponent(token);
        var leftPaneUrl = extractParamValue(token, "leftPane");
        var tokenSplit = token.split("?");
        var leftToken = decodeURIComponent(leftPaneUrl + "?" + tokenSplit[1]);
        PTC.navigation._setActiveLayout(leftToken);
        PTC.navigation.loadLeftPane(leftToken);
    }
    PTC.navigation.isPageLoaded = PTC.navigation._isPageLoaded;
    PTC.navigation._loadContent(token);
    if(!navigatorPanelEnabled) {
        Ext.ux.TreePanelStateful.restore(accordion);
    }
    var bodyProgress = Ext.fly('bodyProgress');
    if (bodyProgress) {
        bodyProgress.removeClass("progress");
    }
    if (PTC.navigation._attemptAggressiveCleanup) {
       Ext.EventManager.on(window, 'unload', PTC.navigation.unloadShell);
    }
    PTC.navigation.showIE8CompatibilityModeMessage();
    PTC.navigation.fireEvent('afterLoadMainShell');
};
/**
 * Switches to the card specified by the setActiveLayout url parameter
 * and clears the previous card.
 * @param {String} page
 */
PTC.navigation._setActiveLayout = function(page){
    var cp = Ext.getCmp(PTC.navigation.cardManager);
    var layout = 0;
    if (page.indexOf("setActiveLayout") > 0) {
        layout = extractParamValue(page, "setActiveLayout");
    }
    if (!cp.layout.activeItem || layout !== cp.layout.activeItem.id) {
        if (cp.layout.activeItem && cp.layout.activeItem.getEl()) {
            PTC.navigation.removeIframes(cp.layout.activeItem.getEl().dom);
        }
        PTC.navigation.clearCurrentCard();
        cp.layout.setActiveItem(layout);
        PTC.navigation.setActiveContentArea(cp.layout.activeItem.CONTENT_DIV);
    }
};
/**
 * Set iframe src to '' for any embedded iframe to reduce IE memory
 * 2034119
 *
 * @param {DOMElement} dom
 * @param {boolean} removeJCATables to also call tableUtils.cleanUp at each level
 * of recursion (lightboxes seem to benefit from that while the workspaces page does not)
 * @param {boolean} purgeGivenDomElementPlusChildren - true to purge given dom element plus children, false to only purge children
 */
PTC.navigation.removeIframes = function(dom, removeJCATables, purgeGivenDomElementPlusChildren){
    if (dom) {
        PTC.navigation.fireEvent("removeIframe", dom);
        var iframes = dom.getElementsByTagName("iframe");
        var i = iframes.length;
        while (i--) {
            var iframeEl = iframes[i];
            var iframeNameOrId = iframeEl.getAttribute('name');
            if (!iframeNameOrId) { // if name is not found, then look for id. As such most of PTC defined iframes are named.
                iframeNameOrId = iframeEl.getAttribute('id');
            }
            PTC.navigation.log.debug('PTC.navigation.removeIframes: purging iframe ', iframeNameOrId, ' from dom');
            try {
                var iframeWin = iframeEl.contentWindow;
                if (iframeWin && iframeWin.PTC) {
                    iframeWin.PTC.navigation.removeIframes.call(iframeWin, iframeWin.document, removeJCATables, true);
                }
                if (iframeWin && iframeWin.document) {
                    PTC.util.purge(iframeWin.document);
                    iframeWin.close();
                } else {
                    PTC.navigation.log.debug('PTC.navigation.removeIframes: content document not found for iframe ', iframeNameOrId, '? Document not purged.');
                }
                iframeWin.location.replace('about:blank');
            }
            catch (e) {
              // 2056810 Some iframes may throw an access error trying to access the document or content window
              PTC.navigation.log.debug('PTC.navigation.removeIframes: access error trying to access the document or content window for iframe ',  iframeNameOrId);
            }
            try {
                Ext.removeNode(iframeEl);
                iframeEl = null;
            } catch (erm) {
                PTC.navigation.log.debug('PTC.navigation.removeIframes: access error trying to delete iframeEl');
            }
        }
        PTC.util.purge(dom, purgeGivenDomElementPlusChildren !== true);
        if (removeJCATables === true) {
           tableUtils.cleanUp(dom);
        }
        if ('CollectGarbage' in window) {
           // IE specific js garbage collector
           CollectGarbage();
        }
    }
};
