PTC.navigation.overwrite = function(obj, newhtml){
    if(PTC.navigation.log.isTraceEnabled()) {
        var id = obj ? obj.id : "obj is null or undefined";
        PTC.navigation.log.trace('Entered PTC.navigation.overwrite to overwrite dom: ' + id);
    }
    PTC.navigation.removeIframes(obj);
    tableUtils.cleanUp(obj);
    Ext.DomHelper.overwrite(obj, newhtml);
};
