/**
 * Capture errors that bubble up and out of the application and log them to the server and
 * the log4javascript console if IE and in jsDebug mode.
 * @param {String} e
 * @param {String} url
 * @param {String} lineNum
 */
PTC.onError = function(e, url, lineNum){
    try {
        PTC.log.error(e, url, lineNum);
        //returning true will suppress IE's popup script error notification, returning false does not
        //suppressing the notification for production systems is handy because many of IE's js errors are benign
        //also, till SPR 1307460 is fixed there is no way for Creo users to suppress those notifications themselves
        return !PTC.getMainWindow().PTC.debug.isJsDebug();
    } catch(e2) {
        return false;
    }
};
