PTC.infoPage._tabSetRenderers = [];
/**
 * Register a renderer function for one of the top tabs in the info page ("Details", "Structure", "My Tab")
 * @param {String} id - id of the action (e.g. "details", "productStructure", "myTab")
 * @param {Function} func - a function that takes an actionConfig and infoModel as parameters
 *                      and returns an Ext component to be added as items of an Ext TabPanel
 */
