    showWorkingCopy = "&showWorkingCopy="+ showWorkingCopy;
    var url = window.pickedDataFetcher;
    var loader = new pAjax.ContentLoader(url, updateParent, null, 'POST', "attributes=" + window.pickedAttributes+selectedOids + pickerObjectType + iterationValue + versionValue +searchTypeForTask + pickerIncludeTypeInstanceId + showRecentlyUsed + showWorkingCopy);
    if ("doNothing" != window.pickerCallback) {//Delay added for closing the parent window as the new child pop up needs some time for intialization. SPR 2145465 - Issue only in IE8 + GCF
        setTimeout( function(){
            PTC.wizard.close();
        },1000);

        return false;
    }
