/**
 * Returns the record from the table's store that corresponds to the object in the given contextString.
 * Since we're in a picker, it's assumed there's only one table on the page.
 *
 * @param selectedRowContextString - the contextString for a selected object in the table (i.e. search$searchPicker$$com.ptc.windchill.option.model.Choice^org.rnd.testchoice$com_ptc_windchill_option_model_Choice!*)
 * @return Ext.data.Record
 */
function getSelectedRow (selectedRowContextString) {
    var tables = tableUtils.getTables();
    if(!tables || tables.length < 1) {
        throw new Error('no table found on the page');
    }
    return tableUtils.getTableRowFromContext(tables[0].id, selectedRowContextString);
}

