function updateParent() {
    var calledFromAdvSearch = "";
    var myJSONObject = eval("(" + this.req.responseText + ")");

    var context = "";
    if (document.getElementsByName("pickerComponent")) {
        var pc = document.getElementsByName("pickerComponent");
        if (pc != null && pc.length > 0 && pc[0].value == "true") {
           var ctx = document.getElementsByName("openerCompContext");
           if (ctx != null && ctx.length > 0) {
              context = ctx[0].value;
           }
        }
    }

    var displayFieldId = "";
    if (document.getElementsByName("displayFieldId")) {
        var obj = document.getElementsByName("displayFieldId");
        if (obj != null && obj.length > 0) {
            displayFieldId = context + obj[0].value;
        }
    }

    var hiddenId = "";
    if (document.getElementsByName("hiddenId")) {
        var obj = document.getElementsByName("hiddenId");
        if (obj != null && obj.length > 0) {
            // if a hidden id is provided we don't want to append context to the picker id
            context = "";
        }
    }

    var pickerId = "";
    if (document.getElementsByName("pickerId")) {
        var obj = document.getElementsByName("pickerId");
        if (obj != null && obj.length > 0) {
            pickerId = context + obj[0].value;
        }
    }

    if (document.getElementsByName("calledFromAdvSearch")) {
        var obj = document.getElementsByName("calledFromAdvSearch");
        if (obj != null && obj.length > 0) {
            calledFromAdvSearch = obj[0].value;
        }
    }

    var displayAttr = "";
    if ("true" == calledFromAdvSearch) {
        displayAttr = window.pickedAttributes;
    }

    // DTI specific checking.  Checking if opener window is available or not.

    var openerAvailable = "true";
    try {
        if (!eval("opener.window." + window.pickerCallback)) {
            openerAvailable = "false";
        }
    }catch(exception ) {
        openerAvailable = "false";
    }

    var callBackFunctionFound = "false";

    // if opener window is not available, try in in it's own window.
    if (typeof window.callback == 'function') {
    	// CAT (GWT-EXT based) action dynamically attach javascript callback function directly to wizard and picker
    	window.callback(myJSONObject, pickerId);
    } else if("false" == openerAvailable) {
        try {
            var openerPrefix = "";
            // check if this picker was opened into a lightbox iframe
            if (parent && PTC.lightbox.isLightbox(window)) {
                openerPrefix = "parent.";
            }
            // if called from Advanced Search then call pickerCallback with 4 params
            if ("true" == calledFromAdvSearch) {
                eval(openerPrefix + window.pickerCallback + "(myJSONObject,pickerId,displayAttr,displayFieldId)");
            } else {
                eval(openerPrefix + window.pickerCallback + "(myJSONObject,pickerId)");
            }
        }catch(exception ){
            JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.PICKER_CALL_BACK_ERROR",window.pickerCallback+" exception: "+exception);
        }
    } else {
        try {
            // looping 100 times just to check that updateJSDOM has actually updated the DOM and the
            // callback function is available in opener window.
            for (var i = 0; i <= 100; i++) {
                if (eval("opener.window." + window.pickerCallback)) {
                    callBackFunctionFound = "true";
                    break;
                }
            }
            if (callBackFunctionFound == "true") {
                // if called from Advanced Search then call pickerCallback with 4 params
                if ("true" == calledFromAdvSearch) {
                    eval("opener.window." + window.pickerCallback + "(myJSONObject,pickerId,displayAttr,displayFieldId)");
                } else {
                   eval("opener.window." + window.pickerCallback + "(myJSONObject,pickerId)");
                }
            } else { // try in own window.
                // if called from Advanced Search then call pickerCallback with 4 params
                if ("true" == calledFromAdvSearch) {
                    eval(window.pickerCallback + "(myJSONObject,pickerId,displayAttr,displayFieldId)");
                } else {
                    eval(window.pickerCallback + "(myJSONObject,pickerId)");
                }
            }
        } catch(exception) {
            JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.PICKER_CALL_BACK_ERROR",window.pickerCallback+" exception: "+exception);
        }
    }
}// function updateParent ends here


// Dynamic object creation - minding the namespace issues...
var pAjax = new Object();
pAjax.ContentLoader = function(url, onload, onerror, method, params) {
    // Where url is .. the url
    // Where onload is the callback function on success
    // Where onerror is a custom error handler on failure
    // Where method is either GET or POST
    // Where params are form parameters to be passed to the url

    this.url = url;
    this.req = null;
    this.shouldContinue = true;
    // pass the reference to the callback function
    this.onload = onload;
    this.onerror = (onerror) ? onerror : this.defaultError
    this.shouldContinue = this.loadXMLDoc(url, method, params);
    return this.shouldContinue;
}

// Use JSON to dynamically build our additional functions for our ContentLoader object
// Alt method can use pAjax.ContentLoader.prototype.loadXMLDoc = function(){};, but that too long for me.
pAjax.ContentLoader.prototype = {
    //-------------------
    loadXMLDoc:function(url, method, params) {
        var contentType;

        if (!method) method = "GET";
        if (method == "POST") contentType = "application/x-www-form-urlencoded";
        this.req = newHttp();
        if (this.req) {
            try {
                var loader = this;

                this.req.open(method, url, false);

                if (contentType) {
                    this.req.setRequestHeader("Content-Type", contentType);
                }
                this.req.send(params);
                loader.onReadyState();
            } catch (err) { }
        }
        return loader.shouldContinue;
    },
    //-------------------
    onReadyState:function() {
        var req  = this.req;
        var ready   = req.readyState;

        var httpStatus = req.status;

        // if all is dandy, call the callback function
        if (httpStatus == 200 || httpStatus == 0) {
            this.onload.call(this);
        } else { // something is wrong, call the registered error handler
            this.onerror.call(this);
            this.shouldContinue = false;
        }
    },
    //-------------------
    defaultError:function() {
        alert("Error : " + "\n\n ready state :  " + this.req.readyState
                + "\n\n status : " + this.req.status
                + "\n\n\ headers : " + this.req.getAllResponseHeaders());
    }
}

