function addToMainFormAction(containerRef){

	var mainForm = getMainForm();

	// remove containerRef from action
	mainForm.action = removeParamFromString( "containerRef", mainForm.action);
	mainForm.action = removeParamFromString( "oid", mainForm.action);
	if(containerRef.indexOf(':') > -1) {
		// container oid selected
		// add new container to action
		var containerRefStr = containerRef;
		if(! containerRef.startsWith('OR:')) {
	        containerRefStr = 'OR:'+containerRef;
	    }
		mainForm.action = mainForm.action+"&containerRef="+containerRefStr;	//adding OR: to containerRef for SPR 2147148
	    //the oids should not be added to form action in case of multiple context. Some actions in search results are failing becuase of this. SPR 2153478
	    if(containerRef.indexOf(',') == -1)
	    {
	    	mainForm.action = mainForm.action+"&oid="+containerRefStr;
	    }

	}
}

