function contextPickerCallBackMultiSelect(objects,pickerId)
{
	var multiSelectPrefVal = 5;
	//Get the pref value set by user, from the hidden field

	if(document.getElementById("multiSelectPrefVal")!=null)
	{
		multiSelectPrefVal = document.getElementById("multiSelectPrefVal").value;
	}

	var arrPickedObjects = objects.pickedObject;
	var arrAlreadyAddedContexts = new Array();
    var optionDisplayVal = objects.pickedObject[0]["containerInfo.name"];
    var optionInternalVal = objects.pickedObject[0]["oid"];
    var firstPanel=Ext.getCmp('chkGroupContextPicker');
	var isAlreadyAdded = false;
	var contextSelected = "";
	var counter = 0;
	//Create temp array to hold all the checkbox items from panel
	var tempArray = new Array();
	for(var j=0;j <  firstPanel.items.getCount(); j++)
	{
		var tempItem = firstPanel.items.get(j);
		tempArray[j] = tempItem;
	}

	//Iterate on picked objects array and find if some or all of it are already added or not
	for(var j=0;j<arrPickedObjects.length;j++)
	{
		var optionDisplayVal = objects.pickedObject[j]["containerInfo.name"];
		var optionInternalVal = objects.pickedObject[j]["oid"];

		for ( var i = 0; i < firstPanel.items.getCount(); i++)
		{
			if ((firstPanel.items.get(i).getName() == optionInternalVal))
			{
				var tempItem = firstPanel.items.get(i);
				arrAlreadyAddedContexts[counter] = tempItem;
				counter++;

			}
		}
	}

	//Iterate on already added checkbox array and remove those from the initial temp array created
	//so that initial array will contain the recently visited checkbox items not selected currently
	for(var aa=0; aa<arrAlreadyAddedContexts.length; aa++)
	{
		var item =arrAlreadyAddedContexts[aa];
		var optionInternalVal = item.getName();
		for(var ab=0;ab<tempArray.length;ab++)
		{
			var item1 =tempArray[ab];
			var optionInternalVal1 = item1.getName();
			if(optionInternalVal1==optionInternalVal)
			{
				tempArray.splice(ab,1);
			}
		}

	}


	//create the new checkbox items for selected checkboxes
	var itemsArray= new Array();
	for(var k=0;k<arrPickedObjects.length;k++)
	{
		var optionDisplayVal = objects.pickedObject[k]["containerInfo.name"];
		var optionInternalVal = objects.pickedObject[k]["oid"];

		//Add newly picked objects at the start
		var newItem = null;
		var imageStr="";
			if(optionInternalVal.indexOf('Product') > -1)
			{
				 imageStr = 'prod.gif';
			}
			else if(optionInternalVal.indexOf('Project') > -1)
			{
				 imageStr = 'project.gif';
			}
			else if(optionInternalVal.indexOf('Library') > -1)
			{
				 imageStr = 'navigation_library.gif';
			}

		if($(pickerId+'$label$').value=='FIND_CONTEXT')
		{
			newItem= new PTC.search.RemovableCheckbox({
               boxLabel :'<img src="netmarkets/images/'+imageStr+'" /> ' +optionDisplayVal,
               name :'' +optionInternalVal,id:'' + optionInternalVal,
               checked :true,
               disabled:false,
               listeners : {
                  check :changeListener
               },
               onRemoveFunction: PTC.search.RemoveContextCheckbox
         });
		}
		else
		{
			//If combo selected value is other than Find Selected Contexts make it Find Selected Contexts
			//and Disable the member of checkboxes
			$(pickerId+'$label$').value='FIND_CONTEXT';
			disableMemberOfCheckBoxes();
			newItem= new PTC.search.RemovableCheckbox({
            boxLabel :'<img src="netmarkets/images/'+imageStr+'" /> ' + optionDisplayVal,
            name :'' + optionInternalVal,id:'' + optionInternalVal,
            checked :true,
            disabled:false,
            listeners:{
               check :changeListener
            },
            onRemoveFunction: PTC.search.RemoveContextCheckbox
         });
		}
		//Add this new Item at 0th position
		itemsArray[k] = newItem;
	}
	//Populate the final array containing the currently selected checkbox items and the older recently visited
	  var tempLength = itemsArray.length;
		for(var j=0;j <  tempArray.length; j++)
		{
			var tempItem = tempArray[j];

			itemsArray[tempLength] = tempItem;
			tempLength++;
		}

        //remove the last recently visited context
		itemsArray.splice(multiSelectPrefVal,multiSelectPrefVal);
		//destroy the group(panel) and create new panel for rerendering
		firstPanel.destroy();

		var fp = new Ext.Panel({renderTo:'recentlyUsedContexts',id:'chkGroupContextPicker',xtype :'container',cls :'x-form-check-group',layout :'table',defaultType :'checkbox',border:false});

		var panel2 = Ext.getCmp('chkGroupContextPicker');

		//alert("panel2.items.getCount() before=="+panel2.items.getCount());
		for ( var k = 0; k < itemsArray.size(); k++)
		{
			var item =itemsArray[k];
			var optionInternalVal = item.initialConfig.name;
			var isChecked = item.initialConfig.checked;
			//alert(item.initialConfig.boxLabel);
			//alert("isChecked== "+isChecked);
			if(isChecked==true)
			{

				if(contextSelected.length==0)
				{
					contextSelected= contextSelected + optionInternalVal;
				}
				else
				{
					contextSelected= contextSelected +","+ optionInternalVal;
				}
			}

			var	newItemToAdd= new PTC.search.RemovableCheckbox({
            boxLabel :'' + item.initialConfig.boxLabel,
            name :'' + optionInternalVal,
            id:'' + optionInternalVal,
            checked :isChecked,
            listeners:{
               check :changeListener
            },
            onRemoveFunction: PTC.search.RemoveContextCheckbox
         });
			panel2.add(newItemToAdd);
			panel2.doLayout();
		}
		if($(pickerId+'$label$').value!='FIND_CONTEXT')
		{

			for ( var i = 0; i < panel2.items.getCount(); i++)
			{
				panel2.items.get(i).disable();

			}

		}


	//Set selected value to hidden field
    $(pickerId).value = contextSelected;
}

function contextPickerCallBackMultiSelectSearchPage(objects,pickerId)
{
    var arrPickedObjects = objects.pickedObject;

    // update context list preference
    var contextList = '';
    for(var j=0;j<arrPickedObjects.length;j++) {
        var oid = objects.pickedObject[j]["oid"];
        if(contextList.length != 0) {
            contextList = contextList + ',';
        }
        contextList = contextList + oid;
    }
    updateSearchContextPreference(contextList);

    // form list of checked context ids
    var checkedContextList = new Array();
    var indexCheckedContextList = 0;

    // add currenly checked contexts to checked list
    for(var i=0; i< PTC.search.recentlyUsedContexts.getCount(); i++){
        var item = Ext.getCmp(PTC.search.recentlyUsedContexts.itemAt(i).id);
        if(item.getValue() == true && item.getName() != 'all_contexts') {
            // item is checked
            checkedContextList[indexCheckedContextList++] = item.getName();
        }
    }

    for(var i=0;i<arrPickedObjects.length;i++) {

        // check if already present
        var alreadyPresent = false;
        for(var j=0; j< PTC.search.recentlyUsedContexts.getCount(); j++){
            //if(arrPickedObjects[i]["oid"] == PTC.search.recentlyUsedContexts.itemAt(j).id) {
            var itemId = PTC.search.recentlyUsedContexts.itemAt(j).id;
            var areEqual = compareOids(arrPickedObjects[i]["oid"], itemId);
            if(areEqual) {
                alreadyPresent = true;
                checkedContextList[indexCheckedContextList++] = itemId;
                break;
            }
        }

        // add to list if not already present
        if(!alreadyPresent) {
            var newItem = createNewItem(arrPickedObjects[i]);
            PTC.search.recentlyUsedContexts.add(newItem);
            checkedContextList[indexCheckedContextList++] = newItem.id;;
        }
    }

    //sorting before rendering
    PTC.search.sortRecentlyUsedContexts();

    // destroy and render
    PTC.search.renderRecentlyUsedContexts();


    var selectedContexts = '';
    // check everything from checked list
    for(var i=0; i< checkedContextList.length; i++){
        var item = Ext.getCmp(checkedContextList[i]);

        var isFolder = false;
        if(item.getId().indexOf('folder') !=-1)
        	isFolder = true;

        if(item.getValue() == false && !isFolder) {
            // check the context
            item.suspendEvents();
            item.setValue(true);
            item.resumeEvents();

            if(selectedContexts != '') {
                selectedContexts = selectedContexts + ',';
            }
            selectedContexts = selectedContexts + checkedContextList[i];
        }
    }

    // set "All Context" appropriately
    if(checkedContextList.length == 0) {
        // check all contexts
        var allContexts = Ext.getCmp('all_contexts');
        if(allContexts.getValue() == false) {
            allContexts.suspendEvents();
            allContexts.setValue(true);
            allContexts.resumeEvents();
        }
    }
    else {
        // specific context is checked so uncheck all contexts
        var allContexts = Ext.getCmp('all_contexts');
        if(allContexts.getValue() == true) {
            allContexts.suspendEvents();
            allContexts.setValue(false);
            allContexts.resumeEvents();
        }
    }

    // set picker hidden value, same as checked list
    $(pickerId).value = selectedContexts;

	if(parent.allContextsCheckedStatus != 0){
	    parent.allContextsCheckedStatus = 0;
	    PTC.search.callUpdateAllContextOnServer('updateallContextsSelectedItem', PTC.search.ContexPickerData.allContextsSelectedName+"##0");
    }
	PTC.search.checkAllFavSelected();
}

function compareOids(oid1, oid2){
    if(oid1.startsWith('OR:') || oid1.startsWith('VR:')) {
        oid1 = oid1.substring(3);
    }
    if(oid2.startsWith('OR:') || oid2.startsWith('VR:')) {
        oid2 = oid2.substring(3);
    }

    return (oid1 == oid2);
}

