function selectRecentlyVisitedContextJCACombo(pickerId)
{
	$(pickerId).value = $(pickerId+'$label$').value;
	addToMainFormAction($(pickerId).value);
}


function contextPickerCallBackJCACombo(objects,pickerId)
{
  var comboBox = document.getElementById(pickerId+"$label$");
  var totalNoOfOptions = comboBox.length;
  var isObjectAlreadyAdded = false;
  var alreadyAddedIndex = 0;
  for(var optionLength=0;optionLength <totalNoOfOptions;optionLength++)
  {
      theElement = comboBox.options[optionLength].value;
      if(theElement==objects.pickedObject[0]["oid"])
      {
          isObjectAlreadyAdded = true;
          alreadyAddedIndex = optionLength;
      }
  }
  if(isObjectAlreadyAdded == true)
  {
      comboBox.options[alreadyAddedIndex].selected=true;
      $(pickerId).value = $(pickerId+'$label$').value;
  }
  else
  {
      var optionsArrayDisplayValues= new Array(1);
	    var optionsArrayInternalValues= new Array(1);
		//Add newly picked object at 0'th position
		optionsArrayDisplayValues[0] = objects.pickedObject[0]["containerInfo.name"];
		optionsArrayInternalValues[0] = objects.pickedObject[0]["oid"];
		document.getElementById(pickerId).value = objects.pickedObject[0]["oid"];

		for(var optionLengthn=0;optionLengthn <totalNoOfOptions;optionLengthn++)
		{
			var tempInternalVal = comboBox.options[optionLengthn].value;
			var tempDisplayVal = comboBox.options[optionLengthn].text;

			optionsArrayDisplayValues[optionLengthn+1] = tempDisplayVal;
			optionsArrayInternalValues[optionLengthn+1] = tempInternalVal;
		}

      //remove the last recently visited context
      optionsArrayInternalValues.splice(5,1);
		optionsArrayDisplayValues.splice(5,1);
      //recreate the combo with new values
      for(var k=0; k<optionsArrayInternalValues.length;k++)
		{
			if(comboBox.options[k]!=null)
			{
				comboBox.options[k].text = optionsArrayDisplayValues[k];
				comboBox.options[k].value = optionsArrayInternalValues[k];
			}
			else // combo size is less than 5
			{
				comboBox.options.add(document.createElement("OPTION"));
				comboBox.options[k].text=optionsArrayDisplayValues[k];
				comboBox.options[k].value = optionsArrayInternalValues[k];
			}
		}
      comboBox.options[0].selected=true;
      document.getElementById(pickerId).value = objects.pickedObject[0]["oid"];
  }
}




/*
 * Constant for the picker iframe ID when used in a lightbox.
 * Must keep in synch with com.ptc.core.components.rendering.PickerRenderConfigs.LIGHTBOX_FRAME_ID
 * and PTC.lightbox.LB_CONTENT_IFRAME_ID (in lightbox.jsfrag)
 */
PTC.search.picker.LB_CONTENT_IFRAME_ID = 'lbContentIframe';
/*The following API takes care pre-selection in the structured enumeration tree picker.
 *
 */


PTC.search.picker.populateFunc= function(grid) {
		grid.populatePreSelectionsConfig = function(preSelecionObj) {
		preSelecionObj.comparableFn = "PTC.search.picker.cmpFunction";
		//2 hidden fields are rendered for opener context one by JCA and one of them is our hidden field. The value is the same however.
		var openerCompContext = "";

			var openerContext = getMainForm().openerCompContext;
		if (typeof openerContext == 'string') {
			openerCompContext = getMainForm().openerCompContext.value;
		} else {
			openerCompContext = getMainForm().openerCompContext[0].value;
		}
		var pickerId = getMainForm().pickerId.value;
		var hiddenFieldId = openerCompContext + pickerId;
		var targetElement = eval(window.opener.document.getElementById(""+ hiddenFieldId + ""));
		var defaultValues="";
		if (targetElement != null) {
			if ((targetElement.type == "text")	|| (targetElement.type == "hidden")) { // Target element is textbox or hidden field
				defaultValues = targetElement.value;
			} else { // Target element is combo box
				for ( var j = 0; j < targetElement.options.length; j++) {
					if (j == 0)
						defaultValues = targetElement.options[j].value;
					else
						defaultValues = defaultValues + ","
						+ targetElement.options[j].value;
				}
			}
		}
		if (defaultValues !== "") {
			preSelecionObj.oids = defaultValues.split(',');
		}
	}
}



PTC.search.picker.cmpFunction = function(record, giventype) {

	var id = record.id;
   // For example: if CHIPSET is selected the id var is as :
	//"search$callSearchPicker$$|components$loadWizardStep$$|structuredenumerationpicker$structuredEnumerationTreePicker$$SENUM\\|PTC_DYNAMIC_ENUM\\|com.ptc.windchill.csm.provider.CSMEnumerationInfoProvider\\|ns=com.ptc.csm.default_clf_namespace~SEE\\|org.rnd.wtpartWTPart!*"

	var node = id.substring((id.lastIndexOf("$") + 1), id.lastIndexOf("!*"));
	node = PTC.search.picker.removeEscapeChar(node);
	//eventually the value of node considering the above eg: "org.rnd.wtpartWTPart"

	if (node == giventype) {
		return true;
	} else {
		return false;
	}

};

PTC.search.picker.removeEscapeChar = function(node) {
	//We need to extract just the node internal name from the externalForm
	var sNode = node.replace(new RegExp("[\\\\]+", "gm"), ""); //ex: "SENUM\\|PTC_DYNAMIC_ENUM\\|com.ptc.windchill.csm.provider.CSMEnumerationInfoProvider\\|ns=com.ptc.csm.default_clf_namespace~SEE\\|org.rnd.wtpartWTPart"
	sNode = sNode.substring((sNode.lastIndexOf("^") + 1)); //ex: "SENUM|PTC_DYNAMIC_ENUM|com.ptc.windchill.csm.provider.CSMEnumerationInfoProvider|ns=com.ptc.csm.default_clf_namespace~SEE|org.rnd.wtpartWTPart"
	sNode = sNode.substring((sNode.lastIndexOf("|") + 1));//ex: "org.rnd.wtpartWTPart"
	return sNode;
}

// Returns value of field by field name
PTC.search.picker.getFieldValue = function(fieldId, attName){
    attName = attName.toLowerCase();  // JSAction code does a toLowerCase when rendering the keys...
    var field = $(fieldId);

    if (field) {
        return field.getAttribute(attName);
    }
    return '';
}

// Returns value of display field for picker
PTC.search.picker.getDisplayFieldValue =function(displayFieldName){
	var displayField = document.getElementsByName(displayFieldName)[0];
	var displayValue = '';
	if(displayField) {
		displayValue = displayField.value;
		if(displayField.options) { // combo box so need not send selection to picker
			displayValue = '';
		}
	}
	return displayValue;
}

PTC.search.picker.getPickerFields = function(findBtnId) {
    var jsonString = PTC.search.picker.getFieldValue(findBtnId, 'pickerJson');
    return Ext.util.JSON.decode(jsonString);
}

PTC.search.picker.getPickerAction = function(findBtnId) {
    return PTC.search.picker.getFieldValue(findBtnId, 'pickerAction');
}

PTC.search.picker.getPickerInfo = function(pickerId){
	var findBtnId = pickerId + '_FIND_BTN';
	var action = PTC.search.picker.getPickerAction(findBtnId);
	var fields = PTC.search.picker.getPickerFields(findBtnId);

	var info = {};
	info.action = action;
	info.fields = fields;

	return info;
}

PTC.search.picker.loadPicker = function(pickerId, displayId, target, initialSelectedPickerValues){
    var pickerInfo;
    // Determine if we are rendering ourself in a lightbox or a normal pop-up window
    // by checking the "target" parameter.  This will be "_self" if caller wants a normal pop-up, or
    // "lbContentIframe" if the caller wants the picker to appear in a lightbox iframe.
    if (target === PTC.search.picker.LB_CONTENT_IFRAME_ID && parent) { // target === "lbContentIframe"
        // call getPickerInfo() on the parent (owning) iframe
	    pickerInfo = parent.PTC.search.picker.getPickerInfo(pickerId);
	} else { // target === "_self"
        pickerInfo = opener.window.PTC.search.picker.getPickerInfo(pickerId);
	}
	var action = pickerInfo.action;
	var fields = pickerInfo.fields;

	var defaultKeyword = PTC.search.picker.getDisplayFieldValue(displayId);
	if(defaultKeyword.length > 0) {
		// pass defaultKeyword param only if it is not empty
		fields.defaultKeyword = defaultKeyword;
	}
	//carry forward the portlet property to search picker window as the styles and some other stuff
	//are decided based on if it is pop window or not. SPR 1971572.
    if (window.location.href.indexOf("portlet=poppedup") >= 0) {
		fields.portlet = "poppedup";
	}

	//Attaching preselected picker values with URL.Variable "initialSelectedPickerValues" must keep in synch with PickerRenderConfigs.INITIAL_SELECTED_PICKER_VALUES.
	fields.initialSelectedPickerValues = initialSelectedPickerValues;
	var myForm = new JsonForm(pickerId+'_FORM', action, fields, target);
	myForm.submit();
}

/*
 * Following is a standard call back for structured enumeration picker.
*/

PTC.search.picker.structuredEnumerationCallBack = function(pickerObject,
		fieldId, attr, displayFieldId) {

	var pickedObjects = pickerObject.pickedObject;
	var internalFieldToUpdate = document.getElementById(fieldId)
	var displayFieldToUpdate = document.getElementById(displayFieldId);
	if (displayFieldToUpdate === null) {
	    var displayFieldByName = document.getElementsByName(displayFieldId);
	    if (displayFieldByName !== null && displayFieldByName.length > 0) {
	        displayFieldToUpdate = displayFieldByName[0];
	    }
	}
	var newInternalValue = '';
	var newDisplayValue = '';

	for ( var i = 0; i < pickedObjects.length; i++) {
		var internalName = pickedObjects[i]["internalName"];
		var displayAttribute = pickedObjects[i]["name"];
		newDisplayValue += displayAttribute + ', ';
		newInternalValue += internalName + ',';
		//Setting the title field so tah we can get fullPath on ToolTip.
		displayFieldToUpdate.title = pickedObjects[i]["fullPath"];
	}

	newInternalValue = newInternalValue.substring(0,newInternalValue.length - 1);
	newDisplayValue = newDisplayValue.substring(0, newDisplayValue.length - 2);

	internalFieldToUpdate.value = newInternalValue;
	displayFieldToUpdate.value = newDisplayValue;

}


/*Following is the callback for clear action of picker
*/
PTC.search.picker.clearStructuredEnumerationPickerValue = function(fieldId, displayFieldId)
{

	var internalFieldToUpdate = document.getElementById(fieldId)
	var displayFieldToUpdate = document.getElementById(displayFieldId);

	internalFieldToUpdate.value = '';
	displayFieldToUpdate.value = '';
	displayFieldToUpdate.title = '';
}

PTC.search.picker.loadTypePicker = function(pickerId,target){
    var pickerInfo;
    pickerInfo = opener.window.PTC.search.picker.getTypePickerInfo(pickerId);
    var action = pickerInfo.action;
    var fields = pickerInfo.fields;
    if (window.location.href.indexOf("portlet=poppedup") >= 0) {
        fields.portlet = "poppedup";
    }
    var myForm = new JsonForm(pickerId+'_FORM', action, fields, target);
    myForm.submit();
}

PTC.search.picker.getTypePickerInfo = function(pickerId){
    var findBtnId = pickerId+'_b';
    var action = PTC.search.picker.getPickerAction(findBtnId);
    var fields = PTC.search.picker.getPickerFields(findBtnId);

    var info = {};
    info.action = action;
    info.fields = fields;

    return info;
}





/**
 * @class PTC.infoPage.ActiveTab
 * This keeps all the active tab information specific to this class.
 *
 */
PTC.infoPage.ActiveTab = Ext.extend(Object, {

    init: function(infoModel){
        this.log = log4javascript.getLogger("PTC.infoPage.ActiveTab");
        this.infoModel = infoModel;
        this.stickinessKey = "infoPage_lastActiveTab_";
    },
    
    /**
     * This get's the active tab id for a given info page model.
     *
     * @param {Object} tabSet
     * @return The id of the active tab for this infoModel.
     * If no tab was in client store and it wasn't overridden by
     * parameters then it will return 0 for picking the left most tab.
     * @name PTC.infoPage.ActiveTab.getActiveTabId 
     */
    getActiveTabId: function(tabSet){
        var activeTabId = this.getClientStoredActiveTabId(tabSet, this.infoModel);
        
        // make sure tab was found in the client store
        var tabIdOverride = this.getActiveTabOverride(tabSet, activeTabId);
        if (tabIdOverride) {
            this.log.debug("getActiveTab - sticky active tab overriden by URL params");
            activeTabId = tabIdOverride;
        }
        
        // If there wasn't a tab in the client store and nothing was overridden then it will be null
        // We want to pick the left most tab.
        if (!activeTabId) {
            activeTabId = 0;
        }
        
        this.log.debug("getActiveTab - returning ", activeTabId);
        return activeTabId;
    },
    
    /**
     * Returns the id of the selected tab from the user's client storage mechanism.
     * If none of the tabs match the stored value, it will return null.
     *
     * @private
     * @param tabList List of tabs for the given info page
     * @param infoModel
     * @return The id of the active tab, null if not found
     * @name PTC.infoPage.ActiveTab.getClientStoredActiveTabId
     */
    getClientStoredActiveTabId: function(tabList, infoModel){
        if (infoModel && tabList && tabList.length > 0) {
            var activeTabKey = this.stickinessKey + PTC.infoPage.TabUtils.getObjectType(infoModel);
            var tabId = infoModel.getClientStorage().get(activeTabKey);
            
            this.log.debug("getClientStoredActiveTabId - get key ", activeTabKey, ", found value ", tabId);
            if (tabId) {
                for (var i = 0, l = tabList.length; i < l; i++) {
                    //actionID was stored for comparison. For example 'object_partInfoDetailsTab'.
                    if (tabList[i].actionID === tabId) {
                        //returning the actual tab id. For example 'infoPage_myTab_object_partInfoDetailsTab'.
                        this.log.debug("getClientStoredActiveTabId - returning active tab ", tabList[i].id);
                        return tabList[i].id;
                    }
                }
            }
        }
        this.log.debug("getClientStoredActiveTabId - returning null");
        
        return null;
    },
    
    /**
     * Stores the name of the currently selected tab to the user's client storage mechanism. The next time the user
     * visits an info page of the given tab's object type, the given tab will be the active tab.
     *
     * @param {Object} tab
     * @return true if setting the active tab was successful
     * @name PTC.infoPage.ActiveTab.setActiveTab
     */
    setActiveTab: function(tab){
        this.log.debug("set active tab called for tab ", tab.id);
        if (tab && tab.initialConfig && tab.ownerCt) {
            var infoModel = tab.ownerCt.infoModel;
            var activeTabKey = this.stickinessKey + PTC.infoPage.TabUtils.getObjectType(infoModel);
            infoModel.getClientStorage().set(activeTabKey, tab.actionID);
            this.log.debug("set active tab with key ", activeTabKey, ", and value ", tab.actionID);
            return true;
        }
        return false;
    },
    
    /**
     * This will check the parameters on the url to see if the active tab should be overridden to be something else.
     * 
     * Supported for the following scenarios (given tab and table is specified via the url):
     * 1. if the given table exists on the given tab, scroll to it
     * 2. if the given table exists NOT on the given tab but on a different tab, switch to that tab
     *    and scroll to the table
     * 3. if the given table is NOT on any tab but is available to the user, create a new tab and
     *    add the table there.
     * 4. if the given table does NOT exist in the system, give the user an error message
     * 5. if the given tab does NOT exist in the tabSet, give the user an error message
     *
     * NOTE: Overriding is not supported for Type Manager.
     *
     * @private
     * @param {Object} tabSet set of tabs (on the info page)
     * @param {String} activeTabId current active tab. Looks something like: 'infoPage_myTab_object_changesTab'
     * @return The id of the tab that will be set as the active tab.
     * @name PTC.infoPage.ActiveTab.getActiveTabOverride
     */
    getActiveTabOverride: function(tabSet, activeTabId){
        // table params
        var tlnAction = extractParamValue(window.location.href, 'tlnAction');
        var tlnType = extractParamValue(window.location.href, 'tlnType');
        
        // tab params
        var tabAction = extractParamValue(window.location.href, 'tabAction');
        var tabType = extractParamValue(window.location.href, 'tabType');
        
        if (!tlnAction && !tlnType && !tabAction && !tabType) {
            // if none of the params exist, so there is nothing to override
            return activeTabId;
        }
        else if (tlnAction && tlnType && tabAction && tabType) {
            // if all params exist, first try to find table on given tab
            var tabId = this.infoModel.myTabConfig.id + '_' + tabType + '_' + tabAction;
            activeTabId = this.scrollToTabTable(tabSet, tabId, tlnType, tlnAction);
        }
        else if (tlnAction && tlnType) {
            // if only table params exist, attempt to scroll to table on active tab
            if (!activeTabId) {
                // no tab is active, use the leftmost tab by default
                activeTabId = tabSet[0].id;
            }
            activeTabId = this.scrollToTabTable(tabSet, activeTabId, tlnType, tlnAction);
        }
        else if (tabAction && tabType) {
            // if only tab params exist, attempt to forward to that tab
            var newActiveTabId = this.infoModel.myTabConfig.id + '_' + tabType + '_' + tabAction;
            var newActiveTab = PTC.infoPage.TabUtils.getTabById(tabSet, newActiveTabId);
            if (!newActiveTab) {
                //unable to find tab on the info page
                this.log.debug("WARNING: bad tab id. The url params specifying the tab forwarding may be invalid. ",
                    "newActiveTabId:'", newActiveTab, "'");
                this.showFailureMessage();
            }
            else {
                activeTabId = newActiveTab.id;
            }
        }
        else {
            // invalid param combination (one or three param(s) was sent, so one table or tab param is missing)
            this.log.debug("WARNING: invalid url params sent. You are missing a required param when attempting to forward ",
                "to an info page tab or content item. Please update your url link with the correct params.");
            this.showFailureMessage();
        }
        
        this.removeURLTabParameters();
        
        return activeTabId;
    },
    
    /**
     * Removes the url parameters so that on a page refresh it will default to the last selected tab.
     * @name PTC.infoPage.ActiveTab.removeURLTabParameters
     */
    removeURLTabParameters: function(){
        // remove the url params and reload the page
        PTC.util.removeURLParamsFromThisWindow(['tlnAction', 'tlnType', 'tabAction', 'tabType']);
    },
    
    /**
     * Scroll to the given table id on the current active tab.
     * @param {Object} tableId id to scroll to
     * @name PTC.infoPage.ActiveTab.scrollToActiveTabTableId
     */
    scrollToActiveTabTableId: function(tableId){
        var tableContainer = PTC.infoPage.getTabPanel().getActiveTab().getTableContainer();
        //TODO: works, however still having problems with tables not always being rendered fast enough
        tableContainer.scrollTo.defer(2000, tableContainer, [tableId]);
    },
    
    /**
     * scroll to the given table id once it becomes available on the current active tab
     * @param {Object} tableId id to scroll to
     * @name PTC.infoPage.ActiveTab.scrollToActiveTabTableOnAvailable
     */
    scrollToActiveTabTableOnAvailable: function(tableId) {
        Ext.ComponentMgr.onAvailable('wrap_' + tableId, this.scrollToActiveTabTableId.createCallback(tableId));
    },
    
    /**
     * Scrolls to the specified table on the specified tab.
     * NOTE: Assumed that this function will not be called after the user has navigated around on the infopage.
     *
     * @see getActiveTabOverride
     * @param {Array} tabSet
     * @param {String} tabId the id of the tab to look for the table on first
     * @param {String} actionType
     * @param {String} actionName
     * @return The tab id to be selected or null if we could not find the table on any tab.
     * @name PTC.infoPage.ActiveTab.scrollToTabTable
     */
    scrollToTabTable: function(tabSet, tabId, actionType, actionName){
        var result = null;
		
        if (tabSet && tabId && actionType && actionName) {
            var tableAction = actionType + actionName;
            var tableId = tabId + '_' + tableAction;
            var newTab = PTC.infoPage.TabUtils.getTabById(tabSet, tabId);
            
            if (newTab && PTC.infoPage.TabUtils.isTableOnTab(newTab, tableAction)) {
                //Table exists on the given tab, scroll to it.
                this.scrollToActiveTabTableOnAvailable(tableId);
                result = tabId;
            }
            else {
                if (!newTab) {
                    // unable to find tab in tabSet (possible bad tabId sent in)
                    this.log.debug("WARNING: bad tab id. The url params specifying the tab forwarding may be invalid. ", "tabId:'", tabId, "'. Still attempting to find the tab on a different tab...");
                }
                // Check to see if table is on different tab (returns the first tab it finds the table on, starting on
                // the left-most tab and moving right)
                for (var i = 0; i < tabSet.length; i++) {
                    if (PTC.infoPage.TabUtils.isTableOnTab(tabSet[i], tableAction)) {
                        this.scrollToActiveTabTableOnAvailable(tableId);
                        return tabSet[i].id;
                    }
                }
                
                // If the table could not be found on any existing tab, make sure it's available in the system at all. If it
                // is available, add it to a new tab and go there.
                var foundTable = PTC.infoPage.TabUtils.getTableOnActionModel(this.infoModel.thirdLevelNavModel.items, tableAction);
                if (foundTable) {
                    PTC.infoPage.TabUtils.isTabPanelRendered(function(){
                        var tabPanel = PTC.infoPage.getTabPanel();
                        
                        PTC.infoPage.getTabManager(tabPanel).add(function(newTab, tabPanel){
                            PTC.infoPage.myTab.addCallback(newTab, tabPanel);
                            (function(){
                                var menuItem = newTab.getCustomizeMenuItem(actionType,actionName);
                                // this calls myTab.addItem, which adds the table to the tab
                                menuItem.setChecked(true);
                                //Needed so that the component will show up properly on the page such that the ajax
                                //call to add the item will find the drag and drop loading div.  Otherwise it doesn't
                                //find the element and then error on evaling the response.  It then preceeds to refresh
                                //the entire infopage.  The dolayout will show the div properly and prevent the refresh.
                                newTab.doLayout();                                
                            }).defer(2000);
                        });
                    });
                }
                else {
                    //Table does not exist in the system as an action available to the user.
                    this.showFailureMessage();
                }
            }
        }
        else {
            this.log.error("ERROR: javascript func ActiveTab.scrollToTabTable invoked with incorrect params...");
        }
        
        return result;
    },
    
    /**
     * Displays a failure message to the user saying we could not display the requested data.
     * @name PTC.infoPage.ActiveTab.showFailureMessage
     */
    showFailureMessage: function(){
        var title = bundleHandler.get('com.ptc.core.ui.errorMessagesRB.REQUESTED_INFORMATION_NOT_AVAILABLE_HEADER');
        var msg = bundleHandler.get('com.ptc.core.ui.errorMessagesRB.REQUESTED_INFORMATION_NOT_AVAILABLE');
        PTC.messaging.showWarningMessage(title, msg);
    }
});




PTC.AdaptersAdmin = {};

PTC.AdaptersAdmin.utils = function () {

	return {
		getParentByTagAndID : function( node, tagName, id ) {
			while ( node && ( node.tagName != "DIV" ) && ( node.id != id ) )
				node = node.parentNode;

			return node;
    	},

		maskMe : function( url, options ) {
			var myMask = new Ext.LoadMask( Ext.getBody(), { msg: bundleHandler.get( "com.ptc.core.ui.navigationRB.LOADING" ) } );
			var isEnabled = isOKEnabled();
			if ( isEnabled )
				disableOkButton();
			myMask.show();
			requestHandler.doRequest( url, options ) ;
			myMask.hide();
			if ( isEnabled )
				enableOkButton();
		}
	}
}();

PTC.AdaptersAdmin.AdapterAdminUtils = function () {

	return {

		showHideLcMappingIterationList : function( containerOid, lcTemplateOid ) {

			var options = {
							asynchronous: false,
							method: 'get',
							parameters: 'containerOid=' + containerOid + '&oid=' + lcTemplateOid,
							onSuccess: function( xmlhttpObject, jsonHeaderObject ) {
								var iterationList = document.getElementById( "integrityLCMapping.templates.iteration" );
								for ( var i = iterationList.options.length - 1; i >= 0; i-- )
									iterationList.remove( i );

								var iterationInfo = Ext.util.JSON.decode( xmlhttpObject.responseText );

								var parent = iterationList.parentNode.parentNode;
								parent.style.visibility = "hidden";

								var selectedOid = Ext.get( 'integrityLCMapping.template.selected' );
								selectedOid.dom.value = lcTemplateOid;
								if ( iterationInfo && iterationInfo.length > 0 ) {
									for ( var i = 0; i < iterationInfo.length; i++ ) {
										var iteration = iterationInfo[ i ];
										iterationList.add( new Option( iteration.id, iteration.oid ), null );
									}
									selectedOid.dom.value = iterationInfo[ 0 ].oid;
									parent.style.visibility = "visible";
								}
								PTC.jca.table.Utils.reload( 'com.ptc.swlink.adaptersAdminUI.IntegrityLCMapping.stateTable', true );
							}
			};

			PTC.AdaptersAdmin.utils.maskMe( 'ptc1/SWLinkAdapterAdminUtils/showHideLcMappingIterationList', options ) ;
		},

		updateRefObjects : function( containerOid, adapterOid, refTypeElement, refObjElementId ) {

			var refType = refTypeElement.value;

			var options = {
							asynchronous: false,
							method: 'get',
							parameters: 'adapterOid=' + adapterOid + '&refType=' + refType + '&containerRef=' + containerOid,
							onSuccess: function( xmlhttpObject, jsonHeaderObject ) {
								var response = Ext.util.JSON.decode( xmlhttpObject.responseText );
								var internalValues = response[ "RefObjectInternalValues" ];
								var displayValues = response[ "RefObjectDisplayValues" ];
								if ( displayValues == null || displayValues.length <= 0 )
									displayValues = internalValues;

								var hiddenRefObjectElement = getElementByName( refObjElementId + "_hidden" );
								hiddenRefObjectElement.value = "";

								var refObjectElement = document.getElementById( refObjElementId );
								for ( var i = refObjectElement.options.length - 1; i >= 0; i-- )
									refObjectElement.remove( i );

								if ( internalValues ) {
									hiddenRefObjectElement.value = internalValues;
									for ( var i = 0; i < internalValues.length; i++ )
										refObjectElement.add( new Option( displayValues[ i ], internalValues[ i ] ), null );
								}
							}
			};

			PTC.AdaptersAdmin.utils.maskMe( 'ptc1/SWLinkAdapterAdminUtils/updateRefObjects', options ) ;
		},

		validateMapFile : function( adapterOid, mapFile, shouldAlertSuccessMsg ) {

			var status = false;
			var options = {
							asynchronous: false,
							method: 'get',
							parameters: 'adapterOid=' + adapterOid + '&mapFile=' + mapFile,
							onSuccess: function( xmlhttpObject, jsonHeaderObject ) {
								var response = Ext.util.JSON.decode( xmlhttpObject.responseText );
								var message = response[ "validationMessage" ];
								status = ( response[ "validationStatus" ] === "true" );
								if ( !status || ( shouldAlertSuccessMsg && status ) )
									wfalert_gen( message );
							}
			};

			PTC.AdaptersAdmin.utils.maskMe( 'ptc1/SWLinkAdapterAdminUtils/validateMapFile', options ) ;
			return status;
		},

		getMapFileDownloadUrl : function( repositoryName, mapFile, urlElementId ) {

			var options = {
							asynchronous: true,
							method: 'get',
							parameters: 'repositoryName=' + repositoryName + '&mapFile=' + mapFile,
							onSuccess: function( xmlhttpObject, jsonHeaderObject ) {
								var response = Ext.util.JSON.decode( xmlhttpObject.responseText );
								var url = response[ "downloadUrl" ];
								var element = document.getElementById( urlElementId );
								if ( element )
									element.href = url;
							}
			};

			requestHandler.doRequest( 'ptc1/SWLinkAdapterAdminUtils/MapFileDownloadUrl', options ) ;
		},

		isAdapterRunning : function( adapterName ) {

			var status = false;
			var options = {
							asynchronous: false,
							method: 'get',
							parameters: 'adapterName=' + adapterName,
							onSuccess: function( xmlhttpObject, jsonHeaderObject ) {
								var response = Ext.util.JSON.decode( xmlhttpObject.responseText );
								status = response[ "isAdapterRunning" ];
							}
			};

			requestHandler.doRequest( 'ptc1/SWLinkAdapterAdminUtils/checkAdapterStatus', options ) ;
			return status;
		},

		deletePersistentObject : function( oid ) {

			var status = true;
			var options = {
							asynchronous: false,
							method: 'get',
							parameters: 'oid=' + oid,
							onSuccess: function( xmlhttpObject, jsonHeaderObject ) {
								var response = Ext.util.JSON.decode( xmlhttpObject.responseText );
								status = response[ "isDeleted" ];
								var errorMsg = response[ "errorMsg" ];
								if ( status === false )
									PTC.AdaptersAdmin.AdapterAdminUtils.showAlertMsg( errorMsg );
							}
			};

			requestHandler.doRequest( 'ptc1/SWLinkAdapterAdminUtils/deletePersistentObject', options ) ;
			return status;
		},

		isAdapterOrRepositoryPresent : function( adapterName, repositoryName ) {

			var msg = null;
			var options = {
							asynchronous: false,
							method: 'get',
							parameters: 'adapterName=' + adapterName + '&repositoryName=' + repositoryName,
							onSuccess: function( xmlhttpObject, jsonHeaderObject ) {
								var response = Ext.util.JSON.decode( xmlhttpObject.responseText );
								msg = response[ "errorMessage" ];
							}
			};

			requestHandler.doRequest( 'ptc1/SWLinkAdapterAdminUtils/isAdapterOrRepositoryPresent', options ) ;
			return msg;
		},

		createUpdateConfigSpec : function( name, desc, labels, oid ) {

			var status = false;
			var options = {
							asynchronous: false,
							method: 'post',
							parameters: 'csName=' + name + '&csDesc=' + desc + '&csLabels=' + labels + '&oid=' + oid,
							onSuccess: function( xmlhttpObject, jsonHeaderObject ) {
								var response = Ext.util.JSON.decode( xmlhttpObject.responseText );
								status = response[ "status" ];
							}
			};

			PTC.AdaptersAdmin.utils.maskMe( 'ptc1/SWLinkAdapterAdminUtils/createUpdateConfigSpec', options ) ;
			return status;
		},

		showAlertMsg : function( message, waitToClose ) {
			var closeAction = window.close;
			var width = Math.min( 500, message.length + 300 );
			Ext.Msg.show({
				title: getBundleString( "com.ptc.swlink.adaptersAdminUI.AdaptersAdminRB.ERROR_TITLE" ),
				msg: message,
				minWidth: width,
				maxWidth: 800,
				buttons: { ok: getBundleString( "com.ptc.swlink.adaptersAdminUI.AdaptersAdminRB.WARNING_OK" ) },
				icon: Ext.MessageBox.ERROR,
				fn: function( buttonId, text, opt ) {
					if ( waitToClose ) {
						closeAction();
						return false;
					}

					resetOkButton();
					resetNextBackButton(getCurrentStep());
					Ext.ComponentMgr.get( "PJL_wizard_cancel" ).enable();
				}
			});
			if ( waitToClose ) {
				window.close = function() {};
			}
		},

		showAlert : function( msgKey, inserts, waitToClose ) {
			this.showAlertMsg( getBundleStringAndInserts( msgKey, inserts ), waitToClose );
		},

		showConfirmMsg : function( message, successAction, waitToClose, cancelAction ) {
			var closeAction = window.close;
			var width = Math.min( 500, message.length + 300 );
			Ext.Msg.show({
				title: getBundleString( "com.ptc.swlink.adaptersAdminUI.AdaptersAdminRB.WARNING_TITLE" ),
				msg: message,
				minWidth: width,
				maxWidth: 800,
				buttons: {
					ok: getBundleString( "com.ptc.swlink.adaptersAdminUI.AdaptersAdminRB.WARNING_OK" ),
					cancel: getBundleString( "com.ptc.swlink.adaptersAdminUI.AdaptersAdminRB.WARNING_CANCEL" )
				},
				icon: Ext.MessageBox.WARNING,
				fn: function( buttonId, text, opt ) {
					if ( buttonId === 'ok' ) {
						if ( waitToClose ) {
							closeAction();
							return false;
						}

						if ( successAction )
							successAction();
					} else {
						if ( waitToClose )
							window.close = closeAction;

						if ( cancelAction )
							cancelAction();
					}

					return false;
				}
			});
			if ( waitToClose ) {
				window.close = function() {};
			}
			return false;
		},

		showConfirm : function( msgKey, inserts, successAction, waitToClose, cancelAction ) {
			return this.showConfirmMsg( getBundleStringAndInserts( msgKey, inserts ), successAction, waitToClose, cancelAction );
		},

		removeAllSelected : function( tableId, msgKey, inserts, removeVisually, callback ) {
			var count = tableUtils.getTableSelectedRowsCountById( tableId );
			if ( count == 0 ) {
				this.showAlert( 'com.ptc.netmarkets.util.utilResource.NONE_CHECKED' );
			} else {
				var onSuccess = function() {
					var selectionModel = tableUtils.getTable( tableId ).getSelectionModel();
					var selectedRows = selectionModel.getSelections();

					var oids = '';
					for ( var i = 0; i < selectedRows.length; i++ ) {
						oids += '__@@__' + selectedRows[ i ].get( 'oid' );
					}

					var status = removeVisually;
					if ( removeVisually === false ) {
						status = PTC.AdaptersAdmin.AdapterAdminUtils.deletePersistentObject( oids );
					}

					if ( status === true ) {
						rowHandler.removeRows( oids.split( '__@@__' ), tableId, true );
						PTC.jca.table.handleSelectAllCheckbox( selectionModel );
					}

					if ( callback )
						callback();
				};
				var onCancel = function() {
					tableUtils.getTable( tableId ).getSelectionModel().clearSelections();
				};
				this.showConfirm( msgKey, inserts, onSuccess, false, onCancel );
			}
			return false;
		},

		confirmOnCancel : function( msgKey, showConfirmIf ) {

			function setCancelAction() {

				Ext.ComponentMgr.get( "PJL_wizard_cancel" ).on(
					'click',
					function() {
						var shouldProceed = true;
						if ( showConfirmIf )
							shouldProceed = showConfirmIf();
						if ( shouldProceed )
							return PTC.AdaptersAdmin.AdapterAdminUtils.showConfirm( msgKey, '', null, true );
						else
							return true;
					});
			}

			Ext.ComponentMgr.onAvailable( "PJL_wizard_cancel", setCancelAction );
		}
	}; 
}();


/**
 *@namespace
 */
PTC.jca.batch = {};

/**
 * This object handles the batching of ajax requests.  The batch request is sent when either the max batch size is reached
 * or the the timer interval has been exceeded.  The object will cancel all pending requests when the user navigates away from the page.
 *
 * For example:
 * <code>
 * var batchRequests = new PTC.jca.batch.BatchRequest({
 *    url: getBaseHref() + "ptc1/<your_controller>/",
 *    maxBatchSize: 50,  //The maximum number of requests that should be batched before sent
 *    onSuccess: function(response) {},
 *    onFailure: function(response) {}
 *  });
 * </code>
 *
 * Then to add requests:
 * <code>
 * batchRequests.addRequest(<your_params>);
 * </code>
 *
 * Future ideas: <br />
 * We would have a BatchRequestController that would manage the uniqueIds and
 * would delegate to a controller of choice that encapsulate the creation of the
 * response content.
 */
PTC.jca.batch.BatchRequest = Ext.extend(Object, {
    log: log4javascript.getLogger('PTC.jca.batch.BatchRequest'),
    requestsInHolding: [],
    timerInterval: 200,
    maxBatchSize: 20,
    waitForResponse: false, //TODO in the future when needed
    sending: false,
    
    /**
     * @constructor
     * @name PTC.jca.batch.BatchRequest.constructor
     * @param {Object} config This will setup the batch request with your specific config options.
     * {
     *   url: getBaseHref() + 'ptc1/example',
     *   timerInterval: 500, //This is in milliseconds
     *   onSuccess: yourFunction,
     *   onFailure: yourFunction
     * }
     */
    constructor: function(config){
        config = config || {};
        Ext.apply(this, config);
        
        PTC.navigation.on("historyChange", this.cancelRequests, this, {
            single: true
        });
        
        this.scheduleSending();
    },
    
    /**
     * @private
     */
    scheduleSending: function(){
        var self = this;
        this.sending = true;
        this.timeout = setInterval(function(){
            self.processRequests();
        }, this.timerInterval);
    },
    /**
     * Adds a request to the batch
     * @name PTC.jca.batch.BatchRequest.addRequest
     * @param {Object} params
     */
    addRequest: function(params){
        this.log.debug("Adding request to the queue", params);
        this.requestsInHolding.push(params);
        
        if (this.maxBatchSize > 0 && this.requestsInHolding.length >= this.maxBatchSize) {
            this.processRequests();
        }
    },
    /**
     * @name PTC.jca.batch.BatchRequest.cancelRequests
     */
    cancelRequests: function(){
        this.log.debug("Cleaning up the batch request for page change.");
        
        clearInterval(this.timeout);
        this.sending = false;
        this.requestsInHolding = [];
    },
    /**
     * @name PTC.jca.batch.BatchRequest.processRequests
     */
    processRequests: function(){
        if (this.requestsInHolding.length > 0) {
            this.log.debug("Processing requests in holding");
            var currentRequest;
            var requestsToProcess = [];
            var options = this.initializeRequest();
            
            while ((currentRequest = this.requestsInHolding.shift())) {
                requestsToProcess.push(currentRequest);
            }
            
            options.parameters.data = Ext.encode(requestsToProcess);
            this.sendRequest(options);
        }
        
    },
    /**
     * @name PTC.jca.batch.BatchRequest.initializeRequest
     */
    initializeRequest: function(){
        var options = {
            method: 'post',
            onFailure: this.onFailure,
            onSuccess: this.onSuccess,
            parameters: {
                data: null
            }
        };
        
        return options;
    },
    /**
     * @name PTC.jca.batch.BatchRequest.sendRequest
     * @param {Object} options
     */
    sendRequest: function(options){
        this.log.debug("Calling ajax request with the following options", options);
        requestHandler.doRequest(this.url, options);
    }
    
});


/**
 * Provides client state management.  The underlying implementation may be different depending on the client's
 * configuration.  It will try to use the "best" available client persistence mechanism for the client.  
 * <br/><br/>
 * Note that in the case of IE (pre-IE8), it will attempt to use an IE-specific form of client persistence.
 * To use this, it creates and operates on a hidden DOM element - because of this, make sure to create a new
 * ClientStateProvider only when the document is ready.
 * <br/><br/>
 * ClientStateProvider will <i>not</i> use cookies as a form of state management, due to the limitations of
 * the amount and size of cookies that can be stored.   
 * <br/><br/>
 * <b>NOTE: </b>IE 7's userData store does not allow key names that begin with a "." or a digit.  It also restricts keys to contain only characters, digits,
 * "_" and ".".  Calling get, set, or clear with a key name that violates these rules when using the userData store will result in the offending characters
 * being replaced with underscores.
 * @param config an object literal representing configuration options for the ClientStateProvider.
 *      properties: domstorage - optional.  Pass 'local' to force the use of local storage (across sessions).
 *      Defaults to 'session'. 
 * 
 * @example
 * // Create a ClientStateProvider - make sure the DOM is loaded first!
 * // Note that specifiying session domstorage is not necessary, as it is the default.
 * var provider = new PTC.jca.state.ClientStateProvider({domstorage: 'session' });
 * 
 * // store a value
 * provider.set('someKey', 'someValue');
 * 
 * // get a value - if no value is found for the given key, the default value passed in will be returned.
 * var val = provider.get('someKey', 'someDefaultValue');
 * 
 * // remove a value
 * provider.clear('someKey');
 */
PTC.jca.state.ClientStateProvider = function(config) {
    PTC.jca.state.ClientStateProvider.superclass.constructor.call(this);
    
    // Keep a reference to our specific provider, which should be automagically the best store for this client environment:
    var provider = PTC.jca.state.ClientStateStore.getProvider(config);
    this.provider = provider;
    
    // A simple hash of cleansed keys, save some regex computation if we've already computed it
    this.cleansedKeyCache = {};
    Ext.apply(this, config);
};

Ext.extend(PTC.jca.state.ClientStateProvider, Ext.state.Provider, {
    /**
     * Store a value by the given name
     * @name PTC.jca.state.ClientStateProvider.set
     * @param {Object} name - the key name
     * @param {Object} value - the value to set
     */
	set : function(name, value) {        
        if (!this.provider) {
            return;
        }
        
        name = this.cleanseKey(name);
        
        if (typeof value == "undefined" || value === null) {
            this.clear(name);
            return;
        }
        
        var val = this.encodeValue(value);
        this.provider.set(name, val);
        this.fireEvent("statechange", this, name, value);
	},

    /**
     * Returns the current value for a key
     * @name PTC.jca.state.ClientStateProvider.get
     * @param {Object} name - the key name
     * @param {Object} defaultValue - a default value to return if the key's value is not found.
     */	
	get : function(name, defaultValue) {        
        if (!this.provider) {
            return defaultValue;
        }
        
        name = this.cleanseKey(name);
        
        var val = this.provider.get(name);
        if (val === null || typeof val == 'undefined') {
            return defaultValue;
        }
        return this.decodeValue(val);
	},

    /**
     * Clears a value from the state
     * @name PTC.jca.state.ClientStateProvider.clear
     * @param {Object} name - the key name
     */	
	clear : function(name) {        
        if (!this.provider) {
            return;
        }
        
        name = this.cleanseKey(name);
        
        this.provider.clear(name);
        this.fireEvent("statechange", this, name, null);
	},

    /**
     * This function will replace all invalid characters in the given key. It will only
     * replace the invalid characters when storing the data in userData (i.e. IE7).
     * 
     * It will replace all non-character or non-numerical characters (except periods and
     * underscores) with an underscore.  It also will also replace any leading periods or
     * numbers with an underscore.
     * @name PTC.jca.state.ClientStateProvider.cleanseKey
     * @param {String} key - a key that may contain invalid characters
     * @throws {Error} If the key is not defined
     * @return The key with the offending characters removed
     */
    cleanseKey: function(key){
        var cleansedKey = key;
        if (!key) {
            throw new Error('The key name should not be null or empty');
        }
        else if (this.provider.name === "userData") {
            if (this.cleansedKeyCache[key]) {
                return this.cleansedKeyCache[key];
            }
            cleansedKey = key.replace(/^\d/, '_').replace(/^\./, '_');
            cleansedKey = cleansedKey.replace(/[^a-zA-Z0-9_\.]/g, '_');
            this.cleansedKeyCache[key] = cleansedKey;
        }
        return cleansedKey;
    }
});

/**
 * Default implementation of the ClientStateProvider, using sessionStorage if available.
 * NOTE: Will only be available AFTER the DOM is ready (see Ext.onReady for more information)!
 */
PTC.jca.state.getSessionStateStore = function(){
    if(PTC.jca.state.sessionStateStore === undefined){
        PTC.jca.state.sessionStateStore = new PTC.jca.state.ClientStateProvider({
            domstorage: 'session'
        });
    }
    return PTC.jca.state.sessionStateStore;
};

Ext.onReady(PTC.jca.state.getSessionStateStore);

/**
 * Default implementation of ClientStateProvider, using localStorage or globalStorage, if available.
 * NOTE: Will only be available AFTER the DOM is ready (see Ext.onReady for more information)!
 */
PTC.jca.state.getLocalStateStore = function(){
    if(PTC.jca.state.localStateStore === undefined){
        PTC.jca.state.localStateStore = new PTC.jca.state.ClientStateProvider({
            domstorage: 'local'
        });
    }
    return PTC.jca.state.localStateStore;
};

Ext.onReady(PTC.jca.state.getLocalStateStore);


/**
 * Provides the internal implementation of client-side persistence using the best storage mechanisms available.
 * <br/><br/>
 * This should NOT be used directly, as it does not provide any serialization or escaping of values.  Use ClientStateProvider
 * for client-side storage.
 * <br/><br/>
 * Using DOM storage available in HTML 5.  These are implemented in firefox 2+
 * and IE 8.  The call to getProvider can be passed a config object to force the use of local storage (across
 * sessions) if available.  The default is to use session storage.
 * <br/>
 * @private
 * @see <a href="http://dev.w3.org/html5/webstorage/#dom-sessionstorage">http://dev.w3.org/html5/webstorage/#dom-sessionstorage</a>
 * @see <a href="https://developer.mozilla.org/en/DOM/Storage">https://developer.mozilla.org/en/DOM/Storage</a>
 * @see <a href="http://msdn.microsoft.com/en-us/library/cc197062(VS.85).aspx">http://msdn.microsoft.com/en-us/library/cc197062(VS.85).aspx</a>
 * @return {Object} returns an object with one method, getProvider(config).  Use this method to get specific provider store
 *                  for this instance.  The config is an optional parameter with one optional property, 'domstorage'.  Pass domstorage: 'local' to force
 *                  the use of local storage.  The default is 'session', which uses session storage.
 */
PTC.jca.state.ClientStateStore = (function(){

    function constructor(config){

        var log = log4javascript.getLogger('PTC.jca.state.ClientStateStore');
        var useLocal = false;
        if (config && config.domstorage === 'local') {
            useLocal = true;
        }

        // Any storage object should implement the following methods:
        //    isAvailable: boolean
        //    set(name, value): void
        //    get(name): string
        //    clear(name): void
        //    name : string

        /**
         * sessionStorage defined in HTML5 spec; implemented in FF 2+ and IE 8.
         */
        var sessionStorage = {
            name: 'sessionStorage',

            /**
             * Determine if sessionStorage is available for this client
             * @private
             * @return {Boolean}
             */
            isAvailable: function(){
                try {
                    if (window.sessionStorage) {
                        // In firefox, sessionStorage exists if turned off.  To see if it's
                        // really available (not turned off), try to set and remove an item.
                        // If it's turned off, it will throw an exception.
                        window.sessionStorage.setItem('testKey', 'testValue');
                        window.sessionStorage.removeItem('testKey');
                        return true;
                    }
                } catch (e) {
                    return false;
                }
                return false;
            },
            /**
             * Set a value for the given key name
             * @param {String} name
             * @param {String} value
             */
            set: function(name, value){
                try {
                    log.debug(this.name, ' store will try to set key ', name, ' to value ', value);
                    window.sessionStorage.setItem(name, value);
                } catch (e) {
                    // may have ran out of space.  Just silently fail.
                    log.debug(this.name, ' store caught exception in set method for key ', name, ' and value ', value, e);
                    return;
                }
            },
            /**
             * Get a value for a given key name
             * @param {String} name
             */
            get: function(name){
                var val;
                try {
                    val = window.sessionStorage.getItem(name);
                    log.debug(this.name, ' store.get: for key ', name, ' got value ', val);
                } catch (e) {
                    log.error('session storage would not allow a getItem', name);
                }
                return val;
            },

            /**
             * Clear a value for a given key name
             * @param {String} name
             */
            clear: function(name){
                try {
                    window.sessionStorage.removeItem(name);
                } catch (e) {
                    log.error('session storage would not allow a getItem', name);
                }
            }
        };

        /**
         * localStorage is supported in firefox 3.5+ and IE 8
         */
        var localStorage = {
            name: 'localStorage',

            /**
             * Determine if this provider is available for this client
             */
            isAvailable: function(){
                try {
                    return window.localStorage ? true : false;
                } catch (e) {
                    return false;
                }
            },

            /**
             * Set a value for the given key name
             * @param {String} name
             * @param {String} value
             */
            set: function(name, value){
                try {
                    log.debug(this.name, ' store will try to set key ', name, ' to value ', value);
                    window.localStorage.setItem(name, value);
                } catch (e) {
                    // may have ran out of space.  Just silently fail.
                    log.debug(this.name, ' store caught exception in set method for key ', name, ' and value ', value, e);
                    return;
                }
            },

            /**
             * Get a value for the given key name
             * @param {String} name
             * @return the value for this key name
             */
            get: function(name){
                var val;
                try {
                    val = window.localStorage.getItem(name);
                    log.debug(this.name, ' store.get: for key ', name, ' got value ', val);
                } catch (e) {
                    log.error('localStorage would not allow a getItem', name);
                }
                return val;
            },

            /**
             * Clear a value for the given key name
             * @param {String} name
             */
            clear: function(name){
                try {
                    window.localStorage.removeItem(name);
                } catch (e) {
                    log.error('localStorage would not allow a removeItem', name);
                }
            }
        };

        /**
         * Global storage similar to localStorage; available in FF 2+
         */
        var globalStorage = {
            name: 'globalStorage',

            /**
             * Determine if this provider is available for this client
             */
            isAvailable: function(){
                try {
                    return window.globalStorage[location.host] ? true : false;
                } catch (e) {
                    return false;
                }
            },

            /**
             * Set the value for the given key name
             * @param {String} name
             * @param {String} value
             */
            set: function(name, value){
                try {
                    log.debug(this.name, ' store will try to set key ', name, ' to value ', value);
                    window.globalStorage[location.host].setItem(name, value);
                } catch (e) {
                    // may have ran out of space.  Just silently fail.
                    log.debug(this.name, ' store caught exception in set method for key ', name, ' and value ', value, e);
                    return;
                }
            },

            /**
             * Get the value for a given key name
             * @param {String} name
             * @return {String} the value for this key name
             */
            get: function(name){
                var val;
                try {
                    val = window.globalStorage[location.host].getItem(name);
                    log.debug(this.name, ' store.get: for key ', name, ' got value ', val);
                } catch (e) {
                    log.error('global storage would not allow a getItem', name);
                }
                return val;
            },

            /**
             * Clear the value for the given key name
             * @param {String} name
             */
            clear: function(name){
                try {
                window.globalStorage[location.host].removeItem(name);
                } catch (e) {
                    log.error('global storage would not allow a removeItem', name);
                }
            }
        };

        // order important!  We'll try to use the storage mechanism best suited for this client,
        // so try them in order.
        var stores;

        if (useLocal === true) {
            stores = [localStorage, globalStorage];
        } else {
            stores = [sessionStorage];
        }

        //falling back to sessionStorage in case localStorage/globalStorage are not available in case of useLocal=true condition
        stores.push(sessionStorage);

        for (var i = 0; i < stores.length; i++) {
            log.debug("trying store ", stores[i].name);
            if (stores[i].isAvailable()) {
                log.debug("will use store ", stores[i].name);
                return stores[i];
            }
        }
        return null;

    }

    return {
        /**
         * Get the store for this client
         */
        getProvider: function(config){
            return constructor(config);
        }
    };

})();


/**
 * @namespace
 */
PTC.jca.dataSource = {};
PTC.jca.dataSource.log = log4javascript.getLogger('PTC.jca.dataSource');
PTC.jca.requestPath = 'ptc1';
PTC.jca.jsonSupport = ("JSON" in window);
Ext.apply(PTC.jca.dataSource, new Ext.util.Observable());

PTC.jca.dataSource.addEvents(
/**
 * Event is dispatched when  dataSource has completed.
 *
 * @name PTC.jca.dataSource#complete
 * @event
 * @param {String} id - id of the data source
 */
"complete", /**
 * Event is dispatched when  a dynamic operation involving dataSource is performed.
 *
 * @name PTC.jca.dataSource#dynamicOperation
 * @event
 * @param {Object} config  - jcaTableConfig of the grid
 */
"dynamicOperation", /**
 * Event is dispatched when  dataSource is explicitly canceled by the user
 *
 * @name PTC.jca.dataSource#dscancelforced
 * @event
 * @param {Object} store  - dataStore of the component
 */
"dscancelforced");

/**
 * @class PTC.jca.ChunkIterator
 * Returned by a PTC.jca.ChunkReader to allow for iteration over a large block of response json.
 * This approach lets the chunks begin to be processed before the entire response text is analyzed
 */
PTC.jca.ChunkIterator = function(text, separatorText){
    this.text = text;
    this.cursor = 0;
    // control comes here indicating response is successful
    // (reference: Ext.lib.Ajax.handleTransactionResponse())
    this.success = true;
};

PTC.jca.ChunkIterator.prototype = {
    hasNext: function(){
        return (this.cursor != -1);
    },
    next: function(){
        this.cursor = -1;
        return this.text;
    }
};

/**
 * @class PTC.jca.ChunkReader
 * Reads response text into a ChunkIterator
 */
PTC.jca.ChunkReader = function(config){
    config = config || {};
    PTC.jca.ChunkReader.superclass.constructor.call(this, config);
};

Ext.extend(PTC.jca.ChunkReader, Ext.data.DataReader, {
    read: function(response){
        var text = response.responseText;
        return new PTC.jca.ChunkIterator(text, this.separatorText);
    },
    readRecords: function(json){
        return json;
    }
});

/**
 * @class PTC.jca.DataSourceRegistry
 * A singleton that polls the server for DataChunks on behalf of DataSourceProxys.
 */
PTC.jca.DataSourceRegistry = (function(){

    // This value should be in sink with the value in ClientFeedbackType.
    var SERVER_ERROR = 1;
    var MAX_DATA_SOURCE_LIMIT = 201;
    var PARTIAL_RESULTS_DISPLAYED = 202;
    var AVAILABLE_DATA_EXCEEDS_RESULT_LIMIT = 203;
    var PARTIAL_RESULTS_TIMEOUT_DISPLAYED = 204;
    var TABLE_DATA_FEEDBACK_TYPE = 501;
    var MAX_REQUESTS = 3;

    /**
     * Pending poll requests
     */
    var pendingRequests = new Ext.util.MixedCollection();

    /**
     * Map of table id vss DS id .
     */
    var tableIdContainer = new Ext.util.MixedCollection();

    var chunkReader = new PTC.jca.ChunkReader();

    var pollingParams = {
        method: 'GET'
    };
    if (typeof getBaseHref === 'function') {
        //TODO don't hard-code polling URL
        pollingParams.url = getBaseHref() + PTC.jca.requestPath + '/ds';
    }

    var poller = new Ext.data.HttpProxy(pollingParams);

    /**
     * pending dataSourceRequests
     */
    var pendingDataSourceRequests = [];

    /**
     * Cancel all the data source requests currently in progress.
     */
    function killAllDataSources(){
        var ids = [];
        //Populates ids array with the pending requests
        pendingRequests.eachKey(keyIterator, ids);
        PTC.jca.dataSource.log.debug("cancelling Data Source through killAllDataSources with id :-- " + ids);
        PTC.jca.DataSourceRegistry.cancelServerDataSources(ids);
    }

    /**
     * Register the function for page refresh event
     */
    Ext.EventManager.on(window, 'unload', killAllDataSources);

    /**
     * Determine if another polling call is necessary for the given chunk
     * @param {Object} chunk
     */
    function needsPolling(chunk){
        if (!chunk || !chunk.id) {
            return false;
        }
        if (chunk.transmissionState && chunk.transmissionState !== 'COMPLETED') {
            return true;
        }
        return false;
    }

    /**
     * Load the chunk of data and add it to the backing proxy
     * @param {Object} request
     * @param {Object} chunk
     * @return true if more polling is needed, -1 if deferred till later
     */
    function loadChunk(request, chunk) {

        if(request.arg !== undefined) {
            if(request.arg.params !== undefined && request.arg.params.dynamicDataSource !== undefined) {
                var params = request.arg.params;
            }
            request.arg = {};
            request.arg.params = params;
        }
        request.arg.chunk = chunk;

        var records, result;

        var data;
        if(PTC.isDefined(chunk)) {
            data = chunk.data || [];
        } else {
            data = [];
        }
        var totalCount = 0;
        if(request.scope.getTotalCount() > 0) {
            totalCount = request.scope.getTotalCount();
        }
        //chunk.totalCount can be equal to chunk.fromIndex if the DS is open
        if(chunk.fromIndex === chunk.totalCount && chunk.transmissionState !='OPEN' ) {
            if((chunk.fromIndex !== 0 || (totalCount>0 && chunk.fromIndex === 0)) && chunk.resultState != 'FAILED') {
                //Only return true from this spot if the store is loaded.  If the fromIndex is 0 this empty chunk
                //is the only chunk being loaded so it must pass through and go and complete the datasource normally

                //now if the table is filtered, the last chunk may not contain new rows but could still be completed.
                //when the datasource has already sent a complete chunk with rows,
                //any further ds requests will be complete with 0 fromIndex.
                if (chunk.transmissionState !='COMPLETED' || chunk.fromIndex === 0) {
                 // If expand action on tree node doesn't have any nodes(may be filtered), then stop loading indicator on tree node.
                   unmaskExpandNode(request);
                   return true;
                }
            }
            if (PTC.jca.DataSourceRegistry.openRequests > 0) {
                //Other download requests may still have data for this component
                loadChunk.defer(100, this, [request, chunk]);
                return -1;
            }
        }
        if(chunk.fromIndex > (totalCount + 1)) {
            //This is a chunk that is recieved out of order, try loading again in the near future.
            //This occurs if the last chunk is really small, and the 2nd to last chunk is taking longer to download.
            loadChunk.defer(100, this, [request, chunk]);
            return -1;
        } else {
            result = needsPolling(chunk);
            if(result) {
                poll();
                //Poll again as soon as we know that one is needed
            }
            try {
                records = request.reader.readRecords(data);
                if(PTC.isDefined(chunk) && chunk.totalCount !== undefined) {
                    records.totalRecords = chunk.totalCount;
                }
            } catch (e) {
                request.proxy.fireEvent('loadexception', this, request.arg, null, e);
                processRecords(request, chunk, null, false, false);
                return false;
            }
            processRecords(request, chunk, records, true, result);
        }
        return result;
    }

    /**
     * Unmask the loading indicator for tree node enabled through expand action.
     * @param {Object} request
     */
    function unmaskExpandNode(req) {
         var expandNode = req && req.arg && req.arg.params && req.arg.params.e;
         if(expandNode) {
            var s = req.scope;
            s.fireEvent('unmaskExpandNode', s, req.arg.params.e);
         }
    }

    /**
     * Process feedbacks after loading
     * @param {Object} request - The request
     * @param {Object} store - Existing DataStore to be used
     * @param {Array} feedbacks - all the feedbacks available with a chunk
     * @param {Array} records
     */
    function processFeedbacks(request, store, feedbacks, records){
        var paging_session_id;
        var resultLimitHit = false;
        var moreData = false;
        var partialResultException = false;
        var customFeedback = [];
        var i, j;

        for( i = 0, j = feedbacks.length; i < j; i++) {
            var feedback = feedbacks[i];
            if(feedback !== undefined) {
                if(feedback.type === MAX_DATA_SOURCE_LIMIT) {
                    resultLimitHit = true;
                    store.resultLimitReached = true;
                } else if(feedback.type === PARTIAL_RESULTS_DISPLAYED) {
                    partialResultException = true;
                } else if(feedback.type === AVAILABLE_DATA_EXCEEDS_RESULT_LIMIT) {
                    moreData = true;
                } else if(feedback.type === PARTIAL_RESULTS_TIMEOUT_DISPLAYED) {
                    request.scope.fireEvent('DSLoadingInterupted', bundleHandler.get('com.ptc.netmarkets.util.utilResource.PARTIAL_RESULTS_TIMEOUT'));
                } else if(feedback.type === TABLE_DATA_FEEDBACK_TYPE) {
                    paging_session_id = feedback.data.PAGING_SESSION_ID;
                } else if(feedback.type === SERVER_ERROR) {
                    request.scope.fireEvent('ServerError', bundleHandler.get('com.ptc.netmarkets.util.utilResource.SERVER_ERROR') + feedback.exceptionMessage, feedback.type);
                } else {
                    //its a custom feedback
                    customFeedback.push(feedback);
                }
            }
        }

        if (customFeedback.length > 0) {
            //fire an event on store that we have received some customFeedback
            store.fireEvent('customfeedbackavailable', customFeedback);
        }
        if (store.moreData === false) {
            store.moreData = moreData;
        }
        if (store.pagingSessionId === undefined) {
            store.pagingSessionId = paging_session_id;
        }
        if (resultLimitHit) {
            store.resultLimitHit = true;
            if (!store.tree) {

                //for story B-74832
                //If there is searchTerm in a client-session or there are selected oids in a client-session,
                //"Table size limit reached" will not showed up in client-side at start.
                //But the filtered result size exceeded limit table size, "Table size limit reached" will be showed up in client-side.
                var table = tableUtils.getTable(store.jscaTableID);
                var isTableFilteredOnServer = PTC.jca.table.findInTable.isTableFilteredOnServer(table);
                var savedSearchTerm = PTC.jca.table.getObjectFromSession(store.jscaTableID, "searchInListTextBox");
                var selectedOnlyItem = Ext.getCmp(PTC.jca.table.getWTablePanelID(store.jscaTableID) + '.selectedOnlyViewItem');
                var isExistingSavedSelectedOidList = false;
                if (selectedOnlyItem) {
                    var savedSelectedOidList = PTC.jca.table.getObjectFromSession(store.jscaTableID, selectedOnlyItem.id);
                    if ( typeof(savedSelectedOidList) === 'object' ) {
                        isExistingSavedSelectedOidList = true;
                    }
                }
                if ( ( !isTableFilteredOnServer &&  savedSearchTerm !== "" ) || isExistingSavedSelectedOidList ) {
                    return true;
                }

                request.scope.fireEvent('DSLoadingInterupted', bundleHandler.get('com.ptc.netmarkets.util.utilResource.MAX_DATASOURCE_LIMIT_REACHED_MESSAGE_TABLE_LEVEL'));
                PTC.jca.DataSourceRegistry.showIncompleteDataWarning('com.ptc.netmarkets.util.utilResource.MAX_DATASOURCE_LIMIT_REACHED_MESSAGE', 'com.ptc.netmarkets.util.utilResource.MAX_DATASOURCE_LIMIT_REACHED_MESSAGE_2');
            } else {
                request.scope.fireEvent('handlecanceltreeds', store, records);
                request.scope.fireEvent('DSLoadingInteruptedTree', store, records);
            }
        } else {
            store.resultLimitHit = false;
        }
        if (!moreData && partialResultException) {// Warning for partial result exception
            request.scope.fireEvent('DSLoadingInterupted', bundleHandler.get('com.ptc.netmarkets.util.utilResource.QUERY_LIMIT_REACHED'));
            PTC.jca.DataSourceRegistry.showIncompleteDataWarning('com.ptc.netmarkets.util.utilResource.QUERY_LIMIT_REACHED', 'com.ptc.netmarkets.util.utilResource.QUERY_LIMIT_REACHED_DETAILED_MESSAGE');
        }
    }

    /**
     * The delayed update function when a new chunk is processed.
     * Matches signature of the fireEvent('datachanged')
     */
    function delayedStoreUpdate(astore, options){
        if (astore._sortChanged === true || astore.clientSortRequired === true) {
            astore.suspendEvents();
            if (astore.groupField) {
                astore.groupBy(astore.groupField, true);
            } else {
                astore.applySort();
            }
            // store.shiftKeyOn indicates user is explicitly requesting a sort
            if (typeof astore.shiftKeyOn !== 'undefined' && astore.warningDisplayed !== true) {
                PTC.jca.DataSourceRegistry.showIncompleteDataWarning('com.ptc.netmarkets.util.utilResource.SORTING_ON_INCOMPLETE_DATA_WARNING_MESSAGE', 'com.ptc.netmarkets.util.utilResource.SORTING_ON_INCOMPLETE_DATA_DETAILED_MESSAGE');
                astore.warningDisplayed = true;
            }
            astore.resumeEvents();
        }

        if (astore.jsca_table === undefined) {
            astore.jsca_table = tableUtils.getTable(astore.jscaTableID);
        }

        //for story B-74832
        //If there is searchTerm in a client-session or there are selected oids in a client-session,
        //fit rows will be filtered from table using searchTerm or selected oids.
        var isTableFilteredOnServer = PTC.jca.table.findInTable.isTableFilteredOnServer(tableUtils.getTable(astore.jscaTableID));
        var savedSearchTerm = PTC.jca.table.getObjectFromSession(astore.jscaTableID, "searchInListTextBox");
        if (savedSearchTerm !== "" && !isTableFilteredOnServer) {
            //If astore.jsca_table.searchInString value is existing, isTableFilteredOnClient will be returned true.
            astore.jsca_table.searchInString = PTC.jca.table.fit.getSafeSearchTerm(savedSearchTerm);
            var searchField = Ext.getCmp(astore.jscaTableID + '.searchInListTextBox');
            searchField.clearTrigger.show();
        }

        var selectedOnlyItem = Ext.getCmp(PTC.jca.table.getWTablePanelID(astore.jscaTableID) + '.selectedOnlyViewItem');
        if (selectedOnlyItem && astore.load_complete && !isTableFilteredOnServer ){
            var savedSelectedOidList = PTC.jca.table.getObjectFromSession(astore.jscaTableID, selectedOnlyItem.id);
            if (typeof(savedSelectedOidList) === 'object') {
                PTC.jca.table.setSelectRowStatus(astore.jsca_table, savedSelectedOidList,  true);
                selectedOnlyItem.checked = true;
            }
        }

        var searchInListFiltered = PTC.jca.table.findInTable.isTableFilteredOnClient(astore.jsca_table) ||
        (!isTableFilteredOnServer && PTC.jca.table.stickiness.initializeSearchInListFilter(astore.jsca_table));

        if (searchInListFiltered && !(selectedOnlyItem && selectedOnlyItem.checked) ) {
            // applySearchInList event handler will fire datachanged after applying filter
            astore.jsca_table.fireEvent('applySearchInList', astore.jsca_table);
        } else if (!searchInListFiltered && (selectedOnlyItem && selectedOnlyItem.checked) ) {
            selectedOnlyItem.fireEvent('applySelectOnlyView', selectedOnlyItem, true);
        } else if (searchInListFiltered && (selectedOnlyItem && selectedOnlyItem.checked)) {
            astore.jsca_table.fireEvent('applySearchInList', astore.jsca_table);
            selectedOnlyItem.fireEvent('applySelectOnlyView', selectedOnlyItem, true);
        } else {
            astore.fireEvent('datachanged', astore, options);
        }
        astore.fireEvent('asyncdatachunkloaded', astore);
    }

    /**
     * Process records after loading
     * @param {Object} request
     * @param {Object} chunk
     * @param {Array} records
     * @param {Boolean} success
     * @param {Boolean} needsPolling
     * @return true if loading was successful
     */
    function processRecords(request, chunk, records, success, needsPolling){
        var chunkIsNull = (chunk === null || chunk === undefined);
        var store = request.scope, proxy = request.proxy;
        if (!chunkIsNull && chunk.feedback !== undefined) {
            processFeedbacks(request, store, chunk.feedback, records);
        }
        if((chunkIsNull && !proxy) || (!chunkIsNull && isChunkProcessed(proxy, chunk.fromIndex))) {
            return false;
        }
        request.proxy.dataSourceLoading = needsPolling;
        var delay = 5000;

        var recordsLength = 0;
        if (records && records.records && records.records.length) {
            recordsLength = records.records.length;
        }
        var dataLength = 0;
        if (store) {
            //till now how many records are processed by the store
            dataLength = store.processedCounter;
        }

        if (!chunkIsNull){
             //6113922 handle use case where the last COMPLETED/CLOSED chunk came before an OPEN
             if(chunk.transmissionState === 'COMPLETED' || chunk.transmissionState === 'CLOSED'){
                 //temporary flag on store
                 store._tsCompleted = true;
                 // store._totalCount : total count available in the closed/completed chunk
                 store._totalCount = chunk.totalCount;
             }
             if(store._tsCompleted === true && ((dataLength + recordsLength) >= store._totalCount)) {
                 store.load_complete = true;
                 store._tsCompleted = undefined; //unset the flag
                 store._totalCount = undefined;  //unset totalCount
                 delay = 0;
             }
        }
        PTC.jca.dataSource.log.debug("is load complete? ", store.load_complete,  (dataLength + recordsLength),
            chunkIsNull? 'null' : chunk.totalCount, chunkIsNull? 'null' : chunk.transmissionState, 'needs polling?', needsPolling);
        request.arg.add = true;
        if (!chunkIsNull && recordsLength > 0) {
            store.suspendEvents();
            store.processedCounter += recordsLength;
            request.callback.call(store, records, request.arg, success);
            var countChanged = false;
            //if totalcount is more than 50 and all data is already added to Datasource then we need to resize.
            if (store.getTotalCount() <= 50 || !needsPolling) {
                delay = 0;
                // Take care of resizing columns now before the table gets too big when it becomes more expensive.
                // Even though this may be called later, it'll be a no-op mostly.
                PTC.jca.table.scroll.updateTableSize.defer(10, PTC.jca.table.scroll, [store.jscaTableID]);
            }

            if(request.arg && request.arg.params && request.arg.params.e) {
                store._loadingCount = -1;
            }

            /*  For out of order chunk, Chunk with OPEN transmissionState can arrive after
             *  chunk with COMPLETED transmissionState.
             *  In that case store._loadingCount will be greater than chunk.totalCount.
             *  Having 'countChanged=false' for those won't render it in the in the UI :
             *  SPR 6701995 (store.load_complete && chunk.transmissionState == 'OPEN') handles out of order OPEN chunk that came after
             *  the load_complete
             */
            if (store._loadingCount <= chunk.totalCount || (store.load_complete && chunk.transmissionState == 'OPEN')) {
                store._loadingCount = Math.max(store._loadingCount, chunk.totalCount);
                countChanged = true;
            } else {
                if (delay > 0) {
                    delay = -1; // do not need an update actually
                }
            }
            if (store.tree) {
                // Expand the tree now, to avoid a repaint
                store.each(PTC.jca.expandRowIfAuto);
            }
            store.resumeEvents();
            var options = {
                countChanged: countChanged,
                chunk: chunk
            };

            if (store.dataChangeTask === undefined) {
                store.dataChangeTask = new Ext.util.DelayedTask(delayedStoreUpdate);
            }
            PTC.jca.dataSource.log.debug("datachanged? ", countChanged, delay, store._loadingCount, chunk.totalCount);
            PTC.jca.dataSource.log.debug("number of rows in each chunk ", chunk.totalCount - chunk.fromIndex);
            if (delay >= 0) {
                store.dataChangeTask.delay_time = delay;
                store.dataChangeTask.delay(delay, null, store, [store, options]);
            }
            // Set processed chunks
            setChunkProcessed(proxy, chunk.fromIndex);
        } else if (records && records.records){
            var totalRecords = records.totalRecords || 0;
            if (store.tree) {
                store.page_offset = store.getPageOffsetFromOptions(request.arg);
                store.totalLength = Math.max(totalRecords || recordsLength, store.data.length);
            } else {
                store.totalLength = Math.max(totalRecords, store.data.length + recordsLength);
            }
        }

        if (store.load_complete) {
            if (store.getTotalCount() <= 50) {
                PTC.jca.table.scroll.updateTableSize.defer(10, PTC.jca.table.scroll, [store.jscaTableID]);
            }
            store.fireEvent('asyncdatachunkloaded', store);
            store.fireEvent('dataSourceComplete', store);
            if (!chunkIsNull) {
                PTC.jca.dataSource.fireEvent('complete', chunk.id);
            }
            store.DATA_RENDERED = true;
            if (!chunkIsNull && !needsPolling) {
                removeStaleIdIfPresent(store.jscaTableID);
                pendingRequests.removeKey(chunk.id);
            }
            // For expand action on tree node stop loading indicator if all records are loaded.
            if(!needsPolling) {
               unmaskExpandNode(request);
            }
        }
        delete request.arg.chunk;
        return true;
    }

    /**
     * Poll for pending ids from the polling service
     */
    function _poll(){
        var ids = [];
        pendingRequests.eachKey(keyIterator, ids);
        PTC.jca.DataSourceRegistry.pollingService(ids, pollingCallback);
    }

    /**
     * Poll for pending ids from the polling service, initiate many requests if there is room for more open spots
     *
     */
    function poll() {
        _poll();

        var i = PTC.jca.DataSourceRegistry.openRequests;
        while(i++ < poller.max_requests) {
            // schedule a poll request for all available slots
            _poll.defer((100 * i) + 10, this);
            //add a small delay into the poll to space out the initial load
        }
    }

    /**
     * Iterate over the ids in pendingRequests and add to an array. This function must be called in the
     * scope of the array
     * @param {String} id
     */
    function keyIterator(id){
        this.push(id);
    }

    /**
     * Process chunks from the server
     * @param {PTC.jca.ChunkIterator} iterator An iterator over the chunk text returned by the server, if any
     * @param {Array} ids The requested ids
     * @param {Boolean} success Whether or not the request succeeded
     */
    var pollingCallback = function(iterator, ids, success){
        PTC.jca.DataSourceRegistry.openRequests--;
        if (PTC.jca.DataSourceRegistry.openRequests<0) {
            PTC.jca.DataSourceRegistry.openRequests = 0;
        }
        if (success) {
            if (iterator && iterator.hasNext()) {
                loadEachChunk.call(iterator, ids);
            }
        } else {
            handleFailedPoll(iterator, ids);
        }
    };

    /*
         * This method will check if the chunk is already processed or not for chrome browser.
         * NOTE: On chrome, chunks are getting processed twice so causing the duplicate data.
         * TO avoid checking if chunk is already processed, fromIndex is used to identify the chunk for given proxy.
         *
         * @param proxy
         * @param fromIndex fromIndex of chunk to identify chunk
         * @returns boolean true if chunk already processed
         */
        function isChunkProcessed(proxy, fromIndex) {
        //We are checking chrome, as duplicate chunk process issue is observed specific to chrome
        return Ext.isChrome && PTC.isDefined(proxy) && proxy.processedChunks
                && (proxy.processedChunks.indexOf(fromIndex) > -1) ? true : false;
        }

   /*
        * This method will set the processed chunks fromIndex into proxy
        *
        * @param proxy
        * @param fromIndex fromIndex of chunk to identify chunk
        */
    function setChunkProcessed(proxy, fromIndex) {
        //We are checking for chrome, as duplicate chunk process issue is observed specific to chrome
        if(!Ext.isChrome) {
            return;
        }

        /*
         * Objects are being duplicated on chrome. Adding the chunks to processed set to avoid the duplicate
         * processing of same chunk. chunk  fromIndex will be unique when there is data in chunk.
         */
        if (!PTC.isDefined(proxy.processedChunks)) {
            proxy.processedChunks = [];
        }

        proxy.processedChunks.push(fromIndex);
        PTC.jca.dataSource.log.debug("Number of chunks processed on chrome browser " + proxy.processedChunks);
        }

    /**
     * Load each chunk string in this chunk iterator. Called in scope of the chunk iterator.
     * @param {Array} ids The ids that were requested
     */
    function loadEachChunk(ids){

        if (this.hasNext()) {
            var text = this.next();
            var chunk;
            try {
                if (PTC.jca.jsonSupport) {
                    chunk = JSON.parse(text);
                } else {
                    chunk = eval(text);
                }
            } catch (e) {
                PTC.jca.dataSource.log.error("json parse failed", ids.join());
            }
            if (chunk === null || chunk === undefined || chunk[0] === null) {
                PTC.jca.dataSource.log.error('Unable to eval text: ', text, ' for ids: ', ids.join());
                handleFailedPoll(null, ids);
            } else {
                var i;
                for (i = 0; i < chunk.length; i++) {
                    var request = pendingRequests.key(chunk[i].id);
                    PTC.jca.dataSource.log.debug('pendingDataSourceRequests.remove:', chunk[i].id);
                    pendingDataSourceRequests.remove(chunk[i].id);
                    if (request !== undefined && !isChunkProcessed(request.proxy,chunk[i].fromIndex)) {
                        loadChunk(request, chunk[i]);
                    } else {
                        PTC.jca.dataSource.log.info('No pending request found for id: ', chunk.id);
                    }
                }
                loadEachChunk.call(this);
            }
        }
    }

    /**
     * Polling failed, remove the requests if possible
     * @param {PTC.jca.ChunkIterator} chunks - The chunks returned by the server, if any
     * @param {Array} ids - The requested ids
     */
    function handleFailedPoll(chunks, ids){
        if (ids && ids.length) {
            var i, j;
            for (i = 0, j = ids.length; i < j; i++) {
                var request = pendingRequests.removeKey(ids[i]);
                if (request !== undefined) {
                    if (request.scope) {
                        removeStaleIdIfPresent.defer(400, this, [request.scope.jscaTableID, true]);
                    }
                    processRecords(request, null, false, false);
                }
            }
        }
    }

    /**
     * Removes the stale DS id so that polling will happen only for the fresh DS id .
     * @param {String} tableId - Tableid of the table under consideraion.
     * Incase of a tree there can be multiple ds running for the same tree id so dont delete
     * if ds request is still pending.DS pending request in this case is put it in pendingDataSourceRequests array.
     * @param {tableId} Tableid of the table under consideraion.
     * @param {forceRemove} forcibily remove ds id
     */
    function removeStaleIdIfPresent(tableId, forceRemove){
        if (tableIdContainer.containsKey(tableId)) {
            var staleDSId = tableIdContainer.get(tableId);
            tableIdContainer.removeKey(tableId);
            PTC.jca.dataSource.log.debug('removeStaleIdIfPresent remove tableidcontainer:', tableId, staleDSId);
            //if request is pending then dont remove it
            if (!((pendingDataSourceRequests.indexOf(staleDSId)) >= 0) || (forceRemove === true)) {
                return pendingRequests.removeKey(staleDSId);
            }
        }
        return false;
    }
    /**
     * Add new DS id for polling.
     * @param {String} dsId - New datasource id to poll.
     * @param {Object} request - proxy for this id.
     */
    function addDSIdForPolling(dsId, request){
        PTC.jca.dataSource.log.debug('addDSIdForPolling:', request.scope.jscaTableID, dsId);
        pendingRequests.add(dsId, request);
        tableIdContainer.add(request.scope.jscaTableID, dsId);
    }

    return {
        /**
         * Registers a chunk from a DataSource
         * A chunk has the following possible properties:
         * <ul>
         * <li>id: (required) The id of the DataSource
         * <li>data: (required) A subset of the data in the DataSource
         * <li>resultState: (required) One of 'SUCCESS', 'FAILURE', or 'CANCELLED'
         * <li>transmissionState: (required) One of 'OPEN', 'CLOSED', or 'COMPLETED'
         * <li>fromIndex: (required) The index of the first data object in this chunk, relative to
         *                           the DataSource as a whole
         * <li>totalCount: (required) The totaly amount of data in this DataSource
         * <li>feedback: (optional) An optional array of feedback objects
         * </ul>
         * @param {Object} chunk The initial chunk
         * @param {Object} request Has proxy, reader, callback, scope, and arg properties
         * component
         * @param {Boolean} nodeExpand   true if node is expanded.
         */
        register: function(chunk, request,nodeExpand){

            var max_requests;
            if(nodeExpand) {  // There should be single Ajax reequest in case of a Node Expand.
                poller.max_requests = 1;
            } else {
                poller.max_requests = MAX_REQUESTS;
            }
            var cid = chunk.id;
            var completeFunc = function(id){
                if (id === cid) {
                    var store = request.scope;
                    if(store) {
                        delete store.dataChangeTask;
                        store._loadingCount = -1;
                        store.isLoading = FALSE_FUNC;
                    }

                    PTC.jca.dataSource.un('complete', completeFunc);
                    pendingRequests.remove(cid);
                    completeFunc = null;
                }
            };
            PTC.jca.dataSource.on('complete', completeFunc);
            var store = request.scope;
            if (store && getWindow().PTC.performance.Timer.InfoEnabled) {
                store.firstChunk = true;
            }

            //Always want to add addtl data to what is already there
            request.arg.add = true;
            /* Call to removeStaleIdIfPresentensures that stale id is not getting polled if the table with the same id is rendered frequently. */
            PTC.jca.dataSource.log.debug('pendingDataSourceRequests.push:', chunk.id);
            pendingDataSourceRequests.push(chunk.id);
            removeStaleIdIfPresent(request.scope.jscaTableID);
            var comp = Ext.getCmp(request.scope.jscaTableID);
            if (comp) {
                var tid = request.scope.jscaTableID;
                comp.on('beforedestroy', function() {
                    removeStaleIdIfPresent(tid, true);
                    PTC.jca.dataSource.log.debug('pendingDataSourceRequests.remove:', cid);
                    pendingDataSourceRequests.remove(cid);
                    pendingRequests.remove(cid);
                    chunk = null;
                    request = null;
                });
            }
            addDSIdForPolling(chunk.id, request);
            if(needsPolling(chunk)) {
                //polling is required
                poll();
            }
            return loadChunk(request, chunk);
        },
        /**
         * Determine if there is a pending request for the given DataSource ID
         * @param {String} id The DataSource ID
         * @return The request object or null
         */
        getRequest: function(id){
            return pendingRequests.key(id);
        },

        /** For unit tests */
        killAllDataSources: killAllDataSources,

        /**
         * The polling service to use with the registry
         * The service is a function that takes the list of ids to poll for
         * and the callback to use when the chunks are found.
         * The callback must  be supplied with the resulting chunks, the ids, and a success boolean.
         * @param {Array} ids The ids to poll for
         * @param {Function} callback The callback
         * @param {Object} scope The scope to call the callback in
         */
        pollingService: function(ids, callback, scope){
            if (!ids || ids.length<=0) {
                return;
            }
            if (PTC.jca.DataSourceRegistry.openRequests >= poller.max_requests) {
                //If there are no slots open, delay until one is
                _poll.defer(24);
                return;
            }
            PTC.jca.dataSource.log.debug("Polling for :-- ",  ids);
            Ext.Ajax.disableCaching=false;
            if (poller.conn) {
                PTC.jca.dataSource.log.debug("Preparing connection for Datasource with ID for :-- " + ids);
                poller.conn.url = getBaseHref() + 'ptc1/ds';
                if(PTC.jca.jsonSupport){
                    poller.conn.headers = {Accept : 'application/json'};
                }
                PTC.jca.DataSourceRegistry.openRequests++;
                poller.doRequest(Ext.data.Api.actions.read, null, {
                    ids: ids.join(),
                    jsonSupport: PTC.jca.jsonSupport
                }, chunkReader, callback, scope, ids);
            } else {
                callback.call(scope, null, ids, false);
            }
            Ext.Ajax.disableCaching=true;
        },

        /**
         * The parameters used by the default
         * polling HttpProxy
         */
        pollingParams: poller.conn,

        /**
         * This will call the server to cancel the data source requests to the client.
         * @param {Array} ids The store chunk ids that should be appended to the url for canceling.
         */
        cancelServerDataSources: function(ids){
            if (ids === null || ids.length === 0) {
                return;
            }
            var url = PTC.jca.requestPath + '/ds?ids=';
            var i, l;
            for (i = 0, l = ids.length; i < l; i++) {
                var request = pendingRequests.key(ids[i]);
                if (PTC.isDefined(request)) {
                    PTC.jca.dataSource.log.debug("cancelling data source in cancelServerDataSources with id:-- ", ids[i]);
                    pendingRequests.removeKey(ids[i]);
                    //Make request to cancel the loading data sources based off of ids
                    if (ids.length > 0) {
                        Ext.Ajax.request({
                            url: getBaseHref() + url + ids,
                            method: 'DELETE'
                        });
                    }
                } else {
                    PTC.jca.dataSource.log.debug("DS not found for id :-- " + ids[i]);
                }
            }
        },

        /**
         * Facade API to create a new proxy for a DataChunk
         * @param {Object} chunk
         */
        newProxy: function(chunk){
            return new PTC.jca.DataSourceProxy(chunk);
        },

        /**
         * Facade API to create a new store that can receive DataChunk updates
         * Config options:
         * jscaSort - boolean
         * @param {Object} config
         */
        newStore: function(config){
            if (config !== undefined && config.chunk !== undefined && config.proxy === undefined) {
                config.proxy = this.newProxy(config.chunk);
            }
            return new PTC.jca.DataSourcePagingStore(config);
        },

        newTreeStore: function(config){
            if (config && config.chunk && !config.proxy) {
                config.proxy = this.newProxy(config.chunk);
            }
            return new PTC.jca.DataSourceTreePagingStore(config);
        },

        /** For JsUnit test purpose only */
        processFeedbacks_jsUnit: function(request, store, feedbacks){
            if (store.jsunit === undefined) {
            } else {
                processFeedbacks(request, store, feedbacks);
            }
            return;
        },

        _pendingRequests:pendingRequests,
        _loadChunk: loadChunk,
        _poller:poller,
        needsPolling:needsPolling,
        _MAX_REQUESTS: MAX_REQUESTS,
        openRequests:0,
        _setTestMethod: function(name, func) {
            //To override private methods
            eval(name + ' = ' + func);
        },
        _getTestMethod: function(name) {
            //To get and cache private methods
            return eval(name);
        }
    };
})();

/**
 *  Kill all datasources after an ext component is closed.  For example, closing a tab with many tables.
 */
PTC.jca.DataSourceRegistry.killInternalDataSources = function(extComponent){
    var ids = [];
    if (extComponent && extComponent.getEl === 'function' && extComponent.getEl() !== null) {
        //Get all the tables on this component
        var tables = PTC.jca.table.Utils.getExtTables(extComponent.getEl().dom);
        var i, l;
        // Kill all the datasources in the given component.
        for (i = 0, l = tables.length; i < l; i++) {
            var store = tables[i].getStore();
            if (typeof store.isLoading == 'function' && store.isLoading()) {
                ids.push(tables[i].store.chunk.id);
            }
        }

        PTC.jca.DataSourceRegistry.cancelServerDataSources(ids);
        if (store !== undefined) {
            store.fireEvent('DSLoadingInterupted', bundleHandler.get('com.ptc.netmarkets.util.utilResource.LOADING_CANCELLED_BY_USER'));
        }
    }
};

/**
 *  Kill rededundant datasources on server side after user cancel the datasource loading.
 */
PTC.jca.DataSourceRegistry.killDataSource = function(store, dsId){
    if (store && store.cancelBtnClicked) {
        try {
            store.fireEvent('DSLoadingInterupted', bundleHandler.get('com.ptc.netmarkets.util.utilResource.LOADING_CANCELLED_BY_USER'));
            PTC.jca.dataSource.log.debug("DataSource cancelled by user with id :-- ", dsId);
        }
        catch (e) {
            PTC.jca.dataSource.log.error("Could not fire the DSLoadingInterpupted Event", e);
        }

        PTC.jca.DataSourceRegistry.cancelServerDataSources(dsId);
        PTC.jca.dataSource.fireEvent('dscancelforced', store);
        if (store.proxy) {
            store.proxy.dataSourceLoading = false;
            store.fireEvent('datachanged', store);
        }
    }
};

PTC.jca.DataSourceToolbar = function(barConfig){
    var tableID = barConfig.tableID;
    var barID = (barConfig.isFooter === true) ? 'footer_' : 'header_';
    // Mask field for table loading indicator in title bar
    var mask = new Ext.Toolbar.TextItem({
        xtype: 'tbtext',
        id: barID + tableID + '_titleBarMask',
        height: 20
    });
    // cancel data source button
    var cancelButton = new PTC.jca.CancelDataLoadButton({
        id: barID + tableID + '_cancelDataSourceButton',
        tableid: tableID
    });
    return {
        isFooter: barConfig.isFooter,
        mask: mask,
        cancelButton: cancelButton,
        dsMaskListener: function(){
            var titleBarMaskEle = this.mask.el;
            var titleBarMask = new Ext.LoadMask(titleBarMaskEle, {
                msg: bundleHandler.get("com.ptc.core.ui.navigationRB.LOADING"),
                msgCls: "titleBarMask"
            });
            titleBarMask.show(); // Show loading indicator when title bar is loaded
            var extraMaskDiv = getElementsByClassNameAndTag("ext-el-mask", titleBarMask.el.dom, "div")[0];
            if (extraMaskDiv) {
                Ext.removeNode(extraMaskDiv);
            }
            var maskWheelDiv = getElementsByClassNameAndTag("titleBarMask", titleBarMask.el.dom, "div")[0];
            if (maskWheelDiv) {
                var maskMsgDiv = maskWheelDiv.firstChild;
                if (maskMsgDiv) {
                    maskMsgDiv.className = "titleBarkMaskMsg";
                }
            }

            this.showTitleMasks();
            var store = this.store;

            if (!store.isLoading()) {
                this.hideTitleMasks();
            }
            store.on('reload', this.showTitleMasks, this);
            store.on('dataSourceComplete', this.hideTitleMasks, this);
            store.on('tableResize', this.hideTitleMasks, this);
            store.on('loadexception', this.hideTitleMasks, this);
            store.on('DSLoadingInterupted', this.hideTitleMasks, this);
        },
        showTitleMasks: function(){
            var titleBarMask = this.mask.el;
            if (titleBarMask.cachedWidth) {
                titleBarMask.setWidth(titleBarMask.cachedWidth);
            }
            titleBarMask.show(); // Show loading indicator when data loading is complete
            this.cancelButton.setVisible(true); // Show cancel button on the header
            this.doLayout(true, true);
        },
        hideTitleMasks: function(){
            var titleBarMask = this.mask.el;
            if (titleBarMask && titleBarMask.dom) {
                if (titleBarMask.cachedWidth === undefined || titleBarMask.cachedWidth < titleBarMask.getWidth()) {
                    // Save the old width so it can be restored on show. Never decrease cachedWidth.
                    titleBarMask.cachedWidth = titleBarMask.getWidth();
                }
                titleBarMask.setWidth(0);
                titleBarMask.hide(); // Hide loading indicator when data loading is complete
            }
            if (this.cancelButton && this.cancelButton.el && this.cancelButton.el.dom) {
                this.cancelButton.setVisible(false); // Hide cancel button on the header
            }
            this.doLayout(true, true);
        }
    };
};

/**
 * Displays a warning message with the given title and message resource strings
 *
 * @param {String} warningTitleResource such as 'com.ptc.netmarkets.util.utilResource.SORTING_ON_INCOMPLETE_DATA_WARNING_MESSAGE'
 * @param {String} detailedMessageResource such as 'com.ptc.netmarkets.util.utilResource.SORTING_ON_INCOMPLETE_DATA_DETAILED_MESSAGE'
 */
PTC.jca.DataSourceRegistry.showIncompleteDataWarning = function(warningTitleResource, detailedMessageResource){

    var incompleteDataMsg = {
        MessageTitle: bundleHandler.get(warningTitleResource),
        Messages: [bundleHandler.get(detailedMessageResource)],
        MessageType: 'WARNING'
    };
    var currentWindow = getWindow();
    /*
     * If table is in wizard and reaches "result limit" it should not show the Banner message informing that the table has hit the
     * "result limit" in parent window.
     * In case of automation test(selenium tests) Basic Windchill Browser have a opener window as it gets opened thorugh selenium. Hence this showing message on browser will not work.
     */
    if (!PTC.isDefined(currentWindow.opener) || PTC.automation.isAutomationTest()) {
        currentWindow.PTC.getMainWindow().PTC.messaging.showInlineMessage([incompleteDataMsg]);
    }
};
/**
 * Fires when the data is done streaming down from the server, or when it has been canceled.
 * @name PTC.jca.DataSourcePagingStore#dataSourceComplete
 * @event
 */
/**
 * A paging store that enables appending data to the global data set rather than
 * the current page, when options.chunk is true.  These functions and events should be available
 * on any table or tree store created by JCA as long as its data source enabled.
 * @constructor
 * @param {Object} config
 */
PTC.jca.DataSourcePagingStore = function(config){
    PTC.jca.DataSourcePagingStore.superclass.constructor.call(this, config);
    this.isLoading = function(){
        var proxy = this.proxy;
        return (proxy !== undefined && proxy.dataSourceLoading);
    };
    PTC.jca._addDataSourceStoreCommonBehavior(this);
    this.addEvents('tableResize');
};

Ext.extend(PTC.jca.DataSourcePagingStore, Ext.data.GroupingStore, {

    /**
     * Determine if this store currently is loading data via DataSources
     * @name PTC.jca.DataSourcePagingStore.isLoading
     * @return boolean
     */
    isLoading: function(){
        var proxy = this.proxy;
        return (proxy !== undefined && proxy.dataSourceLoading);
    },

    /**
     * gets the size of the store ignoring the filter. This returns the number of records that could be loaded
     * into the Store if the Store contained all data
     *
     * Not overriding on base Ext.data.Store to avoid issues where stores are used in other components
     * <b>Note</b>: see also {@link #getRecordsCount}.</p>
     * @returns Number
     */
    getTotalCount: function() {
        var totalLength = this.totalLength || 0;
        var result = Math.max(totalLength, this.getRecordsCount());
        if (isNaN(result)) {
            result = 0;
        }
        return result;
    }
});

/**
 * This will give number of records loaded into the Store at the moment ignoring the filter.
 *
 * <b>Note</b>: see also {@link #getTotalCount}.</p>
 * @returns Number
 */
Ext.data.Store.prototype.getRecordsCount =  function getRecordsCount () {
    // Note that the snapshot var is the backup variable when the store is filtered
    // Not sure if the allData check is still needed.  Might have been from Ext2.
    var result = (this.allData || this.snapshot || this.data).length;
    if (!PTC.isDefined(result) || isNaN(result)) {
        result = 0;
    }
    return result;
};
/**
 * Fires when the data is done streaming down from the server, or when it has been canceled.
 * @name PTC.jca.DataSourcePagingStore#dataSourceComplete
 * @event
 */
/**
 * A paging store that enables appending data to the global data set rather than
 * the current page, when options.chunk is true
 * @constructor
 * @param {Object} config
 */
PTC.jca.DataSourceTreePagingStore = function(config){
    PTC.jca.DataSourceTreePagingStore.superclass.constructor.call(this, config);
    PTC.jca._addDataSourceStoreCommonBehavior(this);
    this.addEvents('unmaskExpandNode');
};

/**
 * @access private
 * Add the common behavior for DataSourceStore (PTC.jca.DataSourcePagingStore & PTC.jca.DataSourceTreePagingStore)
 * */
PTC.jca._addDataSourceStoreCommonBehavior = function(store){
    //counter for the records processed by the store
    //note that the records that are processed and available in store could be different in case of handling duplicate rows
    store.processedCounter=0;
    store.addEvents('dataSourceComplete');
};

Ext.extend(PTC.jca.DataSourceTreePagingStore, Ext.ux.maximgb.tg.AdjacencyListStore, {

    /**
     * Determine if this store currently is loading data via DataSources
     * @name PTC.jca.DataSourceTreePagingStore.isLoading
     * @return boolean
     */
    isLoading: function(){
        var proxy = this.proxy;
        return (proxy && proxy.dataSourceLoading);
    },

    loadRecords: function(o, options, success){
        var chunk = options.chunk;

        if (options.add && chunk) {
            if (this.allData !== undefined) {
                this.data = this.allData;
                delete this.allData;
            }
            if (options.params !== undefined) {
                options.params.anode = "dummyNode";
            }
            //Suspend events so the table doesn't redraw itself before we apply paging
            var eventsSuspendedAlready = this.eventsSuspended;
            this.suspendEvents();
            PTC.jca.DataSourceTreePagingStore.superclass.loadRecords.call(this, o, options, success);
            //append the data for each chunk and adjust the total count
            var r = o.records;
            this.totalLength = Math.max(o.totalRecords || r.length, this.data.length);
            if (!eventsSuspendedAlready) {
                this.resumeEvents();
            }
        } else {
            PTC.jca.DataSourceTreePagingStore.superclass.loadRecords.call(this, o, options, success);
        }
    },

    /**
     * gets the size of the store ignoring the filter.
     * Note that the snapshot var is the backup variable when the store is filtered
     * Not sure if the allData check is still needed.  Might have been from Ext2.
     * Not overriding on base Ext.data.Store to avoid issues where stores are used in other components
     */
    getTotalCount: function() {
        var result = Math.max(this.totalLength, (this.allData || this.snapshot || this.data).length);
        if (isNaN(result)) {
            result = 0;
        }
        return result;
    },
    remove: function(record){
        PTC.jca.DataSourceTreePagingStore.superclass.remove.call(this, record);
        // ----- Modification start
        var removeExpandCollapseNorgie = function(store, record){

            if (store.isLoading()) {
                var removeExpandCollapseNorgieDelegate = removeExpandCollapseNorgie.createDelegate(store, [store, record], 0);
                store.on('dataSourceComplete', removeExpandCollapseNorgieDelegate, store, {
                    single: true
                });
            } else {
                PTC.jca.TreeGrid.removeNorgie(store, record);
            }
            removeExpandCollapseNorgie(store, record);
        };
    }
});

/**
 * Callback function which will eval the response
 * */
PTC.jca.dynamicRequestCallback = function(r, o, s){
    if (r && r.text) {
        try {
            var BEGIN_FLAG = "<!-- BEGIN PURE JSON -->";
            var END_FLAG = "<!-- END PURE JSON -->";
            var jsonText = r.text;
            var iBegin = jsonText.indexOf(BEGIN_FLAG) + BEGIN_FLAG.length;
            var iEnd = jsonText.indexOf(END_FLAG, iBegin);
            // Eval only the required script.
            jsonText = jsonText.substring(iBegin, iEnd);
            PTC.jca.dataSource.on("dynamicOperation", PTC.jca.dataSource._registerDynamic);
            PTC.navigation.evalPageScripts(jsonText);
        } catch (e) {
            jsca.log(e);
        }
    }
};

// added for JSUnit test
PTC.jca.dataSource.getStore = function(tableID){
    var table = tableUtils.getTable(tableID);
    if (table) {
        return table.store;
    }
};

/**
 * Creates a new  proxy for existing store and then fires a request for '/ds ' url
 * @param jcaTableConfig : tableConfig to be used for fetching chunk
 * @param callback : callback function for post processing
 *
 * */
PTC.jca.dataSource._registerDynamic = function(jcaTableConfig, callback){
    var store = PTC.jca.dataSource.getStore(jcaTableConfig.tableID);
    if (!store) {
        PTC.jca.dataSource._registerDynamic.defer(100, this, [jcaTableConfig, callback]);
        return;
    }
    var expandProxy = new PTC.jca.DataSourceRegistry.newProxy(jcaTableConfig.chunk);
    expandProxy.setApi('read', getBaseHref() + PTC.jca.requestPath + '/ds');
    this.dataSourceLoading = true;

    var nodeExpand;
    if(store.tree) {
        nodeExpand = true;
    }

    PTC.jca.DataSourceRegistry.register(jcaTableConfig.chunk, {
        proxy: expandProxy,
        reader: store.reader,
        callback: eval(jcaTableConfig.dynamicCallback),
        scope: store,
        arg: {
            chunk: jcaTableConfig.chunk,
            params: jcaTableConfig.storeURL.params
        }
    },nodeExpand);
    delete this.chunk;
    delete this.dynamicCallback;
};

/**
 * fires an event for a dynamic operation
 * */
PTC.jca.dataSource.registerDynamic = function(jcaTableConfig){
    var grid = PTC.jca.table.Utils.getTable(jcaTableConfig.tableID);
    //decode url params that came from server
    if(jcaTableConfig.storeURL && jcaTableConfig.storeURL.pve === true){
        jcaTableConfig.storeURL.params = PTC.util.decode.paramsForJS(jcaTableConfig.storeURL.params);
        jcaTableConfig.storeURL.pve=undefined;
    }
    grid.jcaTableConfig = Ext.applyIf(eval(jcaTableConfig), grid.jcaTableConfig);
    PTC.jca.dataSource.fireEvent("dynamicOperation", grid.jcaTableConfig);
};

/**
 * This function bypasses direct request datasource.
 * It fires a request to URL which is registered on existing store.
 * The callback function should be used to fire a request to dataSource.
 * @param {Object} store - Existing DataStore to be used
 * @param {Object} pollingParams - parameters specific to polling request
 * @param {Object} params - request parameters
 * @param {Object} arg - arguments to be passed
 * @param {Object} proxy - Existing DataProxy
 * @param {Function} callback - Callback function
 * @param {String} queryString - String to be appended to url as querystring. QueryString should not start with '?' or '&'
 * */
PTC.jca.dataSource.doRequestWithExistingStore = function(store, pollingParams, params, arg, proxy, callback, queryString){
    if (pollingParams === undefined || pollingParams === null) {
        pollingParams = {
            method: 'POST'
        };
    } else {
        if (pollingParams.method === null) {
            pollingParams.method = 'POST';
        }
    }
    pollingParams.url = proxy.api.read.url;
    pollingParams.url = Ext.urlAppend(pollingParams.url, queryString);
    var newPoller = new Ext.data.HttpProxy(pollingParams);
    var rowReader = new PTC.jca.ChunkReader();// required for parsing as chunks before registering to datasource proxy.
    newPoller.doRequest(Ext.data.Api.actions.read, null, params, rowReader, callback, store, arg);
};

/**
 * Create params for a dynamic datasource request
 * */
PTC.jca.dataSource.createParams = function(params){
    if (params === undefined) {
        params = {};
    }

    params.acquire = 'false';
    return params;
};

PTC.jca.dataSource.createQueryStringParams = function(params){
    var queryString = "dynamicDataSource=true&tableId=" + params.tableID;
    return queryString;
};

/**
 * When Query params are to be sent as JsonData, then we need to set params.jsonData to
 * a '&'-separated key value pair, and all the params that would have gone into URL query
 * parameters should now go into params.jsonData, from where it is picked up by the Ext.Ajax
 * request() function. We assume here that the original 'params' as passed to the function
 * has only Array data in its jsonData field, since this is the only case where we need
 *  to make a POST request via json Data (since array data is the only one so far that we know
 *  can be too big for a URL). This array data and the rest of the non-array valued fields in
 *  params, as also the existing parameters in the queryString argument, are concatenated as
 *  &-separated key-value pairs and reassigned to params.jsonData.
 */
PTC.jca.dataSource.createParameterDataFromJson = function (params, queryStringInput) {
    var data = "";
    var queryString = queryStringInput;
    if (params.jsonData) {
        for (var field in params) {
            if (params.hasOwnProperty(field)) {
                if ("jsonData" === field)  {
                    continue;
                }
                var ampersand = "";
                if (data)  {
                    ampersand='&';
                }
                data = data + ampersand + field + '=' + params[field];
            }
        }
        for (field in params.jsonData) {
            if ( params.jsonData.hasOwnProperty(field)) {
                data = data + ampersand + field + '=[' + params.jsonData[field] + "]" ;
            }
        }
        if (data) {
            queryString = queryString + '&' + data;
        }
        params.jsonData = queryString;
    }
};

/**
 * Create args for a dynamic datasource request
 * */
PTC.jca.dataSource.createArguments = function(arg){
    arg = (arg === undefined) ? {} : arg;
    return arg;
};

/**
 * Create pollingParams for a dynamic datasource request
 * */
PTC.jca.dataSource.createPollingParams = function(proxy, pollingParams){
    pollingParams = (pollingParams === undefined || pollingParams === null) ? {} : pollingParams;
    pollingParams.url = proxy.api.read.url;
    return pollingParams;
};

/**
 * Generic function for reload action
 * */
PTC.jca.dataSource.reload = function(r, o, s){
    this.loadRecords.call(this, r, o, s);
};

/**
 * @access private
 * Callback for trees so that the loaded nodes are expanded in UI
 * */
PTC.jca.expandNodes = function(r, o, s,scope){
    if(!scope){
        scope = this;
    }
    var record;
    var isReload = false;
    scope.loadRecords.call(scope, r, o, s);
    if (o.params && o.params.reload && o.params.reload[0] === 'true') {
        isReload = true;
    }
    if (o.params === undefined) {
        if (scope.lastJsonData && scope.lastJsonData.e) {
            // An example of this case is that of async DS tree, for Expand All on a selection of tree nodes,
            // where the POST request goes with the node data sent as Json Post data, rather than as URL query
            // params. The node ids selected for expansion are temporarily stored with the data store in
            // store.lastJsonData.
            var ll = scope.lastJsonData.e.length;
            for (var i =0; i< ll; ++i) {
                o.params = {anode: scope.lastJsonData.e[i]};
                scope.expandNodeCallback.call(scope, record, o, s);
            }
            scope.lastJsonData = undefined;
            o.params = undefined;
        }
    } else if (o.params.e !== undefined) {
        record = scope.getById(o.params.e);
        o.params.anode = o.params.e;
        scope.expandNodeCallback.call(scope, record, o, s);
    } else if (r.records !== null) {
        var ii, j;
        for (ii = 0, j = r.records.length; ii < j; ii++) {
            var rec=r.records[ii];
            o.params.anode = rec.id;
            var callExpand=true;
            if (isReload) {
                rec.reloadExpand = true;
                if(!scope.isExpandedNode(rec)){
                    callExpand=false;
                }
            }
            if(callExpand){
                scope.expandNodeCallback.call(scope, rec, o, s);
            }
        }
    }
};

/**
 * @class PTC.jca.DataSourceProxy
 * @extends Ext.data.DataProxy
 * An implementation of Ext.data.DataProxy that loads chunks of data from a server DataSource
 * @constructor
 * @param {Object} chunk The initial chunk of data for this proxy
 */
PTC.jca.DataSourceProxy = function(chunk){
    PTC.jca.DataSourceProxy.superclass.constructor.call(this);
    this.chunk = chunk;
};

Ext.extend(PTC.jca.DataSourceProxy, Ext.data.DataProxy, {
    doRequest: function(action, rs, params, reader, callback, scope, arg){
        // Flag that data chunks are loading
        this.dataSourceLoading = true;
        PTC.jca.DataSourceRegistry.register(this.chunk, {
            proxy: this,
            reader: reader,
            callback: callback,
            scope: scope,
            arg: arg || {}
        });
        // Don't need the initial chunk once we've loaded
        delete this.chunk;
    }
});

PTC.jca.DataSourceProxy.prototype.doRequest = PTC.jca.DataSourceProxy.prototype.doRequest.wrap(function(proceed, action, rs, params, reader, callback, scope, arg){
    var queryString;
    if (scope !== undefined && (scope.norgieClicked === 1 || scope.performExpand)) {
        delete scope.chunk;
        // When result limit is reached in case of tree an alert is launched, which provide user an option , whether to continue loading remaining nodes.
        var userConformation = scope.expandBeyondLimit?true:PTC.jca.table.Utils.getDataLoadUserConfirmation(scope, "com.ptc.netmarkets.util.utilResource.UNBOUNDED_LOAD");
        if (!userConformation) { // User chooses to "cancel" data loading
            if (scope.norgieClicked == 1 || scope.postCancelHandlerInfo === null) { // Implies that it is a normal expand norgie clicked.
                var record = scope.getById(params.e);
                scope.jsca_table.handleLoadingIndicator(scope, record);
                return;
            }
        }
        //Fix for SPR 2219621.In case of expandAll action, expandBeyondLimit variable had used to store user selection to avoid extra limit reached warning popup.As action is complete,reseting the variable for further use.
        scope.expandBeyondLimit = null;
        scope.norgieClicked = null;
        /*SPR 2217390 :Where Used Tab->Expand all fails to load after a find in tree operation causing the user to refresh the page
        * The performexpand is similar to norgieCliked, but used when norgie is expanded programatically, e.g. search in tree. The false on store makes sure that the performExpand variable is reset correctly with norgieClicked
        */
        scope.performExpand = false;
        params = PTC.jca.dataSource.createParams(params);
        queryString = PTC.jca.dataSource.createQueryStringParams(params);
        var rowCount = scope.data !== null && scope.data !== undefined ? scope.data.length : 0; // required for applying limit on expanded nodes.
        if ("jsonData" in params) {
            // An example of this case is that of async DS tree, for Expand All on a selection of tree nodes,
            // where the POST request goes with the node data sent as Json Post data, rather than as URL query
            // params. The node ids selected for expansion are temporarily stored with the scope in
            // scope.lastJsonData and used later in the callback PTC.jca.expandNodes.
            scope.lastJsonData = params.jsonData;
            queryString = queryString + "&rowCount=" + rowCount;
            PTC.jca.dataSource.createParameterDataFromJson(params,queryString);
            // URL should contain no parameters in this case, so set queryString to empty
            queryString="";
        } else {
            queryString = queryString + "&rowCount=" + rowCount + "&e=" + params.e;
        }
        var pollingParams = PTC.jca.dataSource.createPollingParams(this, null);
        arg = PTC.jca.dataSource.createArguments(arg);
        PTC.jca.dataSource.doRequestWithExistingStore(scope, pollingParams, params, arg, this, PTC.jca.dynamicRequestCallback, queryString);
        params.oidToPopulate = null;
    } else if (arg !== undefined && arg.reload === true) {
            params = PTC.jca.dataSource.createParams(params);
            queryString = PTC.jca.dataSource.createQueryStringParams(params);
            queryString += "&rowCount=0&reload=true";
            pollingParams = PTC.jca.dataSource.createPollingParams(this, null);
            arg = PTC.jca.dataSource.createArguments(arg);
            PTC.jca.dataSource.doRequestWithExistingStore(scope, pollingParams, params, arg, this, PTC.jca.dynamicRequestCallback, queryString);
        } else {
            proceed.call(this, action, rs, params, reader, callback, scope, arg);
        }
});


Ext.ns('PTC.ux.grid');

/**
 * @class PTC.ux.grid.DetailsPopupGrid - for the functions specific to a WizardGrid with "edit details" popup
 * @extends Object
 * Plugin (ptype = 'detailspopupgrid') Plugin to support details popup action in grids with rows in CREATE/EDIT mode.
 * 
 * Grids that use this plugin must have operation/itemTypeInstanceId/editObjectRef data store only columns. 
 * TableBuilders should use MultiObjectHelper.java or CloneWizardHelper.java getTableConfig() APIs 
 * to construct a table config setup with these columns. 
 * 
 * @constructor
 * @param {Object} config Configuration options
 * @ptype detailspopupgrid
 */
PTC.ux.grid.DetailsPopupGrid = Ext.extend(Object, {
    constructor: function(config){
        config = config || {};
        Ext.apply(this, config);
    },    
    /**
     * @private
     */
    init: function(grid){        
        //define couple new helper APIs on the grid
        grid._launchEditDialog = this._launchEditDialog;
        grid._addQueryParams = this._addQueryParams;
        grid.saveDetailsPopup = this.saveDetailsPopup;
        grid.initializeDetailsPopup = this.initializeDetailsPopup;
        grid._cloneCellForDetailsPopup = this._cloneCellForDetailsPopup;
        grid._cleanClonedHtml = this._cleanClonedHtml;
        
        grid.getStore().on('remove', function(store, record) {
            if(!store._updateInProgress && record.detailsPopupHiddenDivId) {
                var element = $(record.detailsPopupHiddenDivId);
                if(element && element.parentNode) {
                    element.parentNode.removeChild(element);
                }
            }    
        });
    },
    /**
     * Called before the attribute panel is rendered to initialize the attribute panel store with values from the table store. 
     * 
     * @param {PTC.attributePanel.AttributePanel} ap
     * @param {String} oid of the row the details popup was launched from so we can find the Ext.data.Record from the table store. 
     *                  This should be the oid parameter on the request to the details popup.
     */
    initializeDetailsPopup: function(ap, oid) {
        try {
            //get the table, record, columns for the row that this details popup was launched from
            var table = this;
            var record = table.getStore().getAt(table.getStore().find('oid', oid));
            var columns = table.getColumnModel();
            
            //get the array of attribute ids shown in the panel
            var panelAttributes = ap.getAttributeIDs();
            for (var i = 0, l = panelAttributes.length; i < l; i++) {
                var attrId = panelAttributes[i];
                //have to replace the dots with _ so they can match the column ids 
                var potentialColumnId = attrId.replace('.', '_');
                var cell = record.get(potentialColumnId);
                //if we found a cell value in the table store, copy it into the attribute panel store
                if(cell) {
                    var clonedCell = table._cloneCellForDetailsPopup(cell);
                    ap.setAttributeValue(attrId, clonedCell);
                }
            }            
        } catch(e) {
            PTC.log.error("Error in DetailsPopupGrid.initializeDetailsPopup().", e);
        }
    },
    /**
     * Call prior to closing the lightbox window so the table can take values from the attribute panel and store them as needed 
     * in the record and/or in a hidden div on the main main page.
     * 
     * @param {String} attributePanelName - such as 'attributesTable'
     * @param {String} oid of the row the details popup was launched from so we can find the Ext.data.Record from the table store. 
     *                  This should be the oid parameter on the request to the details popup.
     */    
    saveDetailsPopup : function(attributePanelName, oid) {
        try {
            //get the attribute panel
            var lightboxWindow = PTC.lightbox.getLightboxIframeWindow();
            var apDiv = lightboxWindow.Ext.query("div[id*='" + attributePanelName + "__AttributesTablePaneOuter']")[0];
            var ap = lightboxWindow.Ext.getCmp(apDiv.id);
            
            //get the array of attribute ids shown in the panel
            var panelAttributes = ap.getAttributeIDs();
            
            //get the table, record, columns for the row that this details popup was launched from
            var table = this;
            var record = table.getStore().getAt(table.getStore().find('oid', oid));
            var columns = table.getColumnModel();
                                    
            //for each attribute in the panel, save the value back to the table row 
            //even if the user has not modified the value, attribute may have a default value so need to save all attributes back to the store
            record.beginEdit();                
            record.detailsPopupHiddenDivId = 'detailsPopupHiddenDivForRow_'+record.id;
            var div = this.getHiddenDiv(record.detailsPopupHiddenDivId);
            for (var i = 0, l = panelAttributes.length; i < l; i++) {
                var attrId = panelAttributes[i];
                try {
                    //only 1 TD has this attrId property (unless we enhance to support multiple object types in the popup)
                    var cell_TD = lightboxWindow.Ext.query('TD[attrId*=' + attrId + ']')[0];
                    //have to replace the dots with _ so they can match the column ids 
                    var potentialColumnId = attrId.replace('.', '_');
                    
                    //copy value from attribute panel store into table record
                    var cell = ap.getAttributeValue(attrId);
                    var clonedCell = table._cloneCellForDetailsPopup(cell);
                    record.set(potentialColumnId, clonedCell);
                    
                    //some attributes in the details popup are not in the column model (not visible in the table)
                    var column = columns.getColumnById(potentialColumnId);
                    //if the attribute is not one of the visible columns, then save it to HTML so data is sent when the form is posted
                    if (!column) {
                        //else just copy the HTML for the attribute into hidden div so it is posted on subsequent requests 
                        //when details popup is reopened or wizard is finished
                        var attributeDivId = div.id + attrId;
                        var attributeDiv = $(attributeDivId);
                        if (!attributeDiv) {
                            attributeDiv = document.createElement('div');
                            attributeDiv.id = attributeDivId;
                            div.appendChild(attributeDiv);
                        }
                        attributeDiv.innerHTML = table._cleanClonedHtml(cell_TD.innerHTML);
                    }
                } catch(e) {
                    PTC.log.error('DetailsPopupGrid Error saving attrId ', attrId, e);
                }
            }
            record.endEdit();
            record.commit();
            
            return true;
        } catch(ee) {
            PTC.log.error("Error in DetailsPopupGrid.saveDetailsPopup().", ee);
        }
        return false;
    },
    /**
     * Launches a popup which allows the end user to edit more of the attributes when the object is rendered as an Editable Grid.
     * Parameters record and tableId are required only if the browser event (evt) is null
     * @private
     * @param {Event} evt - browser event 
     * @param {String} url of the details popup
     * @param {Object} formProcessorClasses - like {create: 'com.ptc.core.components.forms.CreateObjectFormProcessor', edit: 'com.ptc.core.components.forms.EditWorkableFormProcessor'}
     * @param {Object} record - (Optional) - Ext.Record
     */
    _launchEditDialog : function(evt, url, formProcessorClasses, record) {
        var table = this;
        if (!record) {
            // get the record from the table store
            if (PTC.menu.contextOid) {
                var store = table.getStore();
                record = store.getAt(store.find('oid', PTC.menu.contextOid));
            }
            else {
                record = PTC.jca.table.Utils.findRecord(evt, table);
            }
        }
        
        // from the values in the store, add some of them as parameters on the URL and launch the Edit Details dialog
        if (record) {
            var context = record.get('jsca_context');
            
            var oid = record.get('oid');
            var operation = record.get('operation');
            var formProcessor = (operation === 'CREATE') ? formProcessorClasses.create : formProcessorClasses.edit;
            
            newLightBoxAction('editObject', this._addQueryParams(url, record), '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', context, oid, formProcessor, 'execute', 'null', '', '', false, '', 'row', '', false, tableUtils.getFormattedTableId(table.id));
        }
        
        if (evt) {
            Event.stop(evt);
        }
        return false;  
    },
    /**
     * With the given record, add some of the values as URL params on the specified URL
     * @private
     * @return {String} url with the parameters added
     */
    _addQueryParams : function(url, record) {
        var params = {};
        params.portlet='poppedup';
        params.oid=record.get('oid');

        var objectHandle = record.get('objectHandle');
        params.currentObjectHandle=objectHandle;
        
        var operation = record.get('operation');
        params[objectHandle + 'operation']=operation;
        if(operation === 'CREATE') {
            params[objectHandle + PTC.wizard.ITIID]=record.get(PTC.wizard.ITIID);   
        } else {
            params[objectHandle + 'editObjectRef']=record.get('editObjectRef');  
        }

        var queryParams = $H(params).toQueryString();
        
        if(url.indexOf('?') > 0) {
            return url.concat('&').concat(queryParams);
        } else {
            return url.concat('?').concat(queryParams);
        }
    }, 
    /**
     * A clone API that will shed all functions of the given object - only the properties of the object are cloned.
     * If function has _originalFuncString_, the function will be 'deflated' back to a string rather than removed. 
     * This is necessary so that we don't get IE errors "Can't execute code from a freed script".
     * For instance, that error would happen if the cell.renderer function was used.
     * <p>
     * When the html of the cloned object is malformed it will be corrected.

     * @private
     * @param {Object} obj a cell value from an attribute panel or a table. Typically like {gui:{html:"..."},renderer:func}
     */
    _cloneCellForDetailsPopup: function(obj){
        if (obj === null || typeof(obj) !== 'object') {
            return obj;
        }
        
        var temp = isArray(obj) ? [] : {};
        for (var property in obj) {
            if (obj.hasOwnProperty(property)) {
                if (typeof obj[property] === 'function') {
                    temp[property] = obj[property]._originalFuncString_;
                } else {
                    temp[property] = this._cloneCellForDetailsPopup(obj[property]);
                }
            }
        }

        if (temp && temp.html) {
            temp.html = this._cleanClonedHtml(temp.html);
        }

        if (temp && temp.gui && temp.gui.html) {
            temp.gui.html = this._cleanClonedHtml(temp.gui.html);
        }

        return temp;
    },

    /**
     * Clean up the html attribute as sometimes it contains malformed html.
     * 
     * @private
     * @param {String) html A String containing html markup.
     */
    _cleanClonedHtml: function(html) {
        // IE11-Edge leaves behind selected="" tags inside options that used to be selected. The currently 
        // selected option has the value select="true". If html has options with both values the selected="" will be
        // removed.
        if (html && html.indexOf('<select') >= 0 && html.indexOf('selected=""') >= 0 && html.indexOf('selected="true"') >= 0) {
            html = html.replace(/selected=""/g, '');
        }

        return html;
    }
});

/**
 * Launches a popup which allows the end user to edit more of the attributes when the object is rendered as an Editable Grid
 * 
 * @param {Object} evt - browser event or Ext.EventObject
 * @param {String} url of the details popup
 * @param {Object} formProcessorClasses - like {create: 'com.ptc.core.components.forms.CreateObjectFormProcessor', edit: 'com.ptc.core.components.forms.EditWorkableFormProcessor'}
 */
PTC.ux.grid.DetailsPopupGrid.launchEditDialog = function(evt, url, formProcessorClasses) {
        evt = evt || event; // to get global event object if evt sent in is undefined (which happens IE)
        evt = evt.browserEvent || evt; // to get browser event in case sent in evt was Ext event (which happens for right click menu)
        
        var tableId = PTC.jca.table.Utils.findTableID(evt);
        if (!tableId){
          //get the table id from right click row menu
          var rowMenu = Ext.getCmp('gridRowContextMenu');
          if(rowMenu) { 
             tableId = rowMenu.tableId;
          } 
        }       
        // get the table object from the table ID        
        var table = PTC.jca.table.Utils.getTable(tableId);
        table._launchEditDialog(evt, url, formProcessorClasses);
};

/**
 * Launches a popup on a table Add row action which allows the end user to edit more of the attributes when the object is rendered as an Editable Grid
 * 
 * @param {Object} record - Ext.Record
 * @param {String} url of the details popup
 * @param {Object} formProcessorClasses - like {create: 'com.ptc.core.components.forms.CreateObjectFormProcessor', edit: 'com.ptc.core.components.forms.EditWorkableFormProcessor'}
 * @param {String} table Id
 */
PTC.ux.grid.DetailsPopupGrid.launchEditDialogOnAdd = function(record, url, formProcessorClasses, tableId){
    // from the values in the store, add some of them as parameters on the URL and launch the Edit Details dialog
    if (record) {
        // get the table object from the table ID        
        var table = PTC.jca.table.Utils.getTable(tableId);
        table._launchEditDialog(null, url, formProcessorClasses, record);
    }
    return false;
};
Ext.preg('detailspopupgrid', PTC.ux.grid.DetailsPopupGrid);


/**
 * @class
 */
PTC.action.FormResult = function(config) {
    if(config) {
        // Remove the table prefix and suffix that is present from create wizards
        config.tableID = tableUtils.getUnformattedTableId(config.tableID);
          
        Ext.apply(this, config);
    }  
};

PTC.action.FormResult.prototype = {
    /**
     * get the array of added oids
     */
    getAddedOids: function(){
        return this._getOids(this.A);
    },
    /**
     * Gets the array of deleted oids
     */
    getUpdatedOids: function(){
        return this._getOids(this.U);
    },    
    /**
     * Gets the deleted oids
     */
    getDeletedOids: function(){
        return this._getOids(this.Del);
    },
    _isEmpty: function (ob) {
        var i;
        for(i in ob) {
            if(ob[i] !== 'function') {
                return false;
            }
        }
        return true;

    },
    /**
     * are any oids added
     */
    hasAddedOids: function(){
        return !this._isEmpty(this.A);
    },
    /**
     * are any oids updated
     */
    hasUpdatedOids: function(){
        return !this._isEmpty(this.U);
    },
    /**
     * are any oids deleted
     */
    hasDeletedOids: function(){
        return !this._isEmpty(this.Del);
    },
    /**
     * Do any oids existe for added, updated, or deleted fields
     */
    hasAnyOids: function() {
      return this.hasAddedOids() || this.hasUpdatedOids() || this.hasDeletedOids();  
    },
      
    _iterator: function(property, value){
        this.oids = this.oids.concat(PTC.util.extractAllValues(value));
    },
    
     _collecAllOidsIterator: function(property, value){
         this.oids = this.oids.concat(PTC.util.extractAllValues(value));
         this.oids.push(property);
    },
    
    _locationIterator: function(key, value){
        this.location.push(key);
    },
    
    _getOids: function(anArray, iterator){
        if (!iterator) {
            iterator = this._iterator;
        }
        var iteratorScope = {
            oids: []
        };
        PTC.util.propertyIterator(anArray, iteratorScope, iterator, []);
        
        return iteratorScope.oids;
    },
    
    /**
     * For a tree, this value would be the parent oid where the new oid should appear under
     * @return [String] Array of oid strings of all the locations the given oid is found
     */
    getLocations: function(){
        var iteratorScope = {
            location: []
        };
        PTC.util.propertyIterator(this.A, iteratorScope, this._locationIterator);
        PTC.util.propertyIterator(this.U, iteratorScope, this._locationIterator);
        PTC.util.propertyIterator(this.Del, iteratorScope, this._locationIterator);
        
        return iteratorScope.location;
    },
    
    getAddedLocations: function(){
        var iteratorScope = {
            location: []
        };
        PTC.util.propertyIterator(this.A, iteratorScope, this._locationIterator);
        
        return iteratorScope.location;
    },
    
    /**
     * @return {boolean} returns true if the action was successful.
     */
    isSuccess: function () {
        return this.status === 0;
    },
    
    /**
     * If the action was performed within a table, the table id will be returned otherwise it will return undefined
     * @return {String} The id of the table where the action was executed from
     */
    getTableId: function () {
        return this.tableID;
    },
    

    /**
     * Converts the OR to a VR and vice versa.  If the given oid is an OR, the corresponding VR is returned.  Likewise, if the oid is a VR, the corresponding OR is returned.
     * @param {String} oid Oid of the object, either the OR or VR
     * @return {String} returns the OR or VR, if the given oid was a OR the VR is returned (or visa versa)
     */ 
     convertOidReference: function(oid) {
        return PTC.action.FormResult.Utils.convertOidReference(oid, this.OR_TO_VR_MAP);
    },

    
    /**
     * iterates through the list looking to see if either the oid or location value matches the passed in oid
     * Note that some checkin operations have 2 possible oids that are to be replaced by 1 new oid
     * 
     */
    _updatedOidCheckIterator: function(key,value,oid) {
        var oids = PTC.util.extractAllValues(value);

        var index = oids.indexOf(oid);
        if(index >= 0) {
            // verify the oid at this index matches the oid sent in
            if(oids[index] === oid) {
                this.oid = oids[index];
            }
        }

        // verify the key matches the oid sent in
        if(key === oid) {
            this.oid = oids[0];
        }

    },
    /**
     * For a specific oid, find the new value for the oid.  
     * Note that some checkin operations have 2 possible oids that are to be replaced by 1 new oid.
     * @return {String} new oid value if the oid has changed (eg. a checkout), the same oid if the oid has been changed (eg. edit) 
     * and returns null if the oid has not been updated
     * 
     */
    getUpdatedOid: function(oid) {
        var iteratorScope = {
            oid : null
        };
        PTC.util.propertyIterator(this.U, iteratorScope, this._updatedOidCheckIterator, [oid]);
        if(!iteratorScope.oid && oid && oid.indexOf("OR") >= 0) {
            oid = this.convertOidReference(oid);
            PTC.util.propertyIterator(this.U, iteratorScope, this._updatedOidCheckIterator, [oid]);
        }

        return iteratorScope.oid;
    }
  
};

/**
 * @class
 */
PTC.action.FormResult.Utils = function(){
    return {
        /**
         * Converts the OR to a VR and vice versa.  If the given oid is an OR, the corresponding VR is returned.  Likewise, if the oid is a VR, the corresponding OR is returned.
         * @param {String} oid Oid of the object, either the OR or VR
         * @param {Object} o2vMap - OR to VR map
         * @return {String} returns the OR or VR, if the given oid was a OR the VR is returned (or visa versa)
         */
        convertOidReference: function(oid, o2vMap) {
            var reference;
            if(!o2vMap) {
                return reference;
            }
            if(oid.indexOf("OR:") >= 0) {
                reference = o2vMap[oid];
            } else {
                PTC.util.propertyIterator(o2vMap, o2vMap, function(key, value) {
                    if(value === oid) {
                        reference = key;
                        // Keys are OR, values are VR
                    }
                });
            }
            return reference;
        }
    };
}();


Ext.ns('Ext.ux.grid');
/**
 * @class Ext.ux.grid.GridFileInputHandler
 * @extends Object
 * Plugin (ptype = 'gridfileinputhandler') for handling browser file input fields in an editable grid.  This will turn off any grid 
 * feature that will cause rows to be re-rendered which causes the browser file field to lose its value becuase of security restrictions.
 * @constructor
 * @param {Object} config Configuration options
 * @ptype gridfileinputhandler
 */
Ext.ux.grid.GridFileInputHandler = Ext.extend(Object, {

    constructor: function(config){
        config = config || {};
        Ext.apply(this, config);
    },
    
    /**
     * @private
     */
    init: function(grid){
        this.view = grid.getView();
        
        grid.addClass("gridfileinputhandler");
        
        // if it's a buffered view, we need to account for the dynamic removal/addition to the dom from
        // the backing store, so override the appropriate methods
        Ext.apply(this.view, this.viewOverrides);
        
        grid.enableColLock = false;
        grid.enableColumnMove = false;
        grid.enableSelectedOnly = false;
        grid.initialConfig.jcaTableConfig.findInTableMode = FindInTableMode.DISABLED;
        
        // removing many rows causes the fields to be refreshed from the store, which causes the file field to lose its value.
        grid.disableMassUpdateOnRemove = true;

        this.view.doPartialDataChange = this.view.doPartialDataChange.wrap(this.doPartialDataChangeWrapper);
    },
    
    /**
     * Turn off features that refresh the row
     */
    viewOverrides: {
        doClean: Ext.emptyFn,
        onDenyColumnLock: TRUE_FUNC,
        enableGroupingMenu: false
    },

    doPartialDataChangeWrapper: function(p, full) {
        //If the store is not sorted, then do not re-create visible rows as it will lose file input fields
        if (this.grid && this.grid.store && !this.grid.store.sortInfo) {
            full = false;
        }
        return p.call(this, full);
    }
});

Ext.preg('gridfileinputhandler', Ext.ux.grid.GridFileInputHandler);


/**
 * @class Grid state manager.
* Restores state using the column id as the restore reference.
*
* API notes: id used rather than dataIndex because the required id methods are public,
* some of the dataIndex methods are private.
* The "config" property is misleadingly described as "The config passed into the constructor",
* when in fact it gets updated every time the columns change.
*
* Stores the following:
* 1. lock state
* 2. hidden state
* 3. column widths
* 4. order of columns
* 5. column to sort by, and sort direction.
*
* TODO :
* 1. This could be made more efficient, particularly for large grids, by only saving
* changes to the original config. However, the original config is not readily available,
* so we would need to store the orignal config or a reference to it.
* 2. Store state for a paging grid.
* 3. Automatically sort if a local grid during initialisation. (Not for a remote grid.)
*/
Ext.grid.GridStateManager2 = function() {
    this.state = {};
};

PTC.jca.table.stickiness = {};
PTC.jca.table.stickiness.log = {};

PTC.jca.table.getActiveViewInfo = function( grid) {
    var activeViewInfo;
    if (grid.jcaTableConfig && grid.jcaTableConfig.pickView) {
        var pv =  grid.jcaTableConfig.pickView;
        var activeViewUpdateCount = pv.activeViewUpdateCount;
        if (activeViewUpdateCount && pv.activeViewOid) {
            activeViewInfo = {viewId : pv.activeViewOid, updateCount : parseInt(activeViewUpdateCount,10)};
        }
    }
    return activeViewInfo;
};

/**
 * Initialises <code>grid</code> with states in <code>provider</code>.
 *
 * @param {Grid} grid
 * @param {Provider} provider
 */
Ext.grid.GridStateManager2.prototype = {
    init : function(grid, provider) {
        this.provider = provider;
        this.grid = grid;
        var restoreState = true;

        this.cm = grid.getColumnModel();
        // Get the state to be restored to the grid.
        var state = provider.get(this.getStateKey());
        var activeViewInfo_state = (state)?state.activeViewInfo:undefined;
        var activeViewInfo_config = PTC.jca.table.getActiveViewInfo(grid);

        if (activeViewInfo_state) {
            if (activeViewInfo_config) {
                if (activeViewInfo_state["viewId"] === activeViewInfo_config["viewId"] &&
                    activeViewInfo_state["updateCount"] < activeViewInfo_config["updateCount"] ) {
                    //This is the case where the view is the same, but was modified 
                    //and persisted, say via the Tableview Manager. This will
                    //cause the update count (activeViewInfo_*[1]) of the state to be less
                    //than that in the server. So this is a clear indication that user made
                    //changes to view config and that needs to be reflect in the UI and be 
                    //updated in the cached state. And of course restoreState() shouldn't 
                    //be called
                    Ext.grid.GridStateManager2.updateState(grid, provider);
                    //view is updated so clear the sorting
                    PTC.jca.clearMultiColumnSortString(grid.getId());
                    //clear locking stickiness
                    PTC.jca.table.stickiness.clearLockingStickiness(grid.getId());
                    state=provider.get(this.getStateKey());
                    restoreState = false;
                }
                else if (activeViewInfo_state["viewId"] !== activeViewInfo_config["viewId"] ){
                    //This is a defensive condition block. It is not likely the control will come
                    //here. It is the case where active view has changed and still the grid state
                    //object was not cleared for the table id in question. 
                    provider.clear(this.getStateKey());
                    restoreState = false;
                }
            }
        }
        if (restoreState && state) {
            this.restoreState(state);
        }

        // Set listeners on all events that relate to grid changes.
        // Hence, state should be updated every time the grid changes.
        this.grid.addEvents('columnConfigChange'); //custom event that will store the updated config 
        this.grid.addEvents('updateTableSize');//custom event that will get fire when table gets resized. 

        this.grid.on("columnConfigChange", Ext.grid.GridStateManager2.updateState.createCallback(this.grid,this.provider));
        // NB: widthchange event on ColumnModel does not fire when columns are resized. Must use grid columnresize event.
        this.grid.on("columnresize", Ext.grid.GridStateManager2.updateState.createCallback(this.grid,this.provider));
        this.grid.on("updateTableSize", Ext.grid.GridStateManager2.updateTableHeight.createCallback(this.grid,this.provider));
        this.cm.on("hiddenchange", Ext.grid.GridStateManager2.updateState.createCallback(this.grid,this.provider));
        this.cm.on("columnmoved", Ext.grid.GridStateManager2.updateState.createCallback(this.grid,this.provider));
        this.cm.on("afterWrap", Ext.grid.GridStateManager2.updateState.createCallback(this.grid,this.provider));
    },

    restoreState : function(state) {
        var col, colConfig, config, i, sort;
        if ("config" in state) {
            config = state.config;
            var configLength = config.length;
            PTC.jca.table.stickiness.log.debug('Restoring table component state, number of columns : ', configLength);
            this.grid.view.variableRowHeight = state.variableRowHeight;
            // there are few UIs where a component refresh could change the no of columns
            // to be displayed, in that case sticky values won't be picked.
            if(this.cm.config && this.cm.config.length === configLength){
                // Restore Column Model config.
                for (i = 0; i < configLength; i++) {
                    colConfig = config[i];
                    col = this.cm.getIndexById(colConfig.id);
                    if (col != -1) {
                        // Only override values in the column if they are defined in the state.config object
                        if (PTC.isDefined(colConfig.width)) {
                            this.cm.config[col].width = colConfig.width;
                        }
                        if (PTC.isDefined(colConfig.isWrapped)) {
                            this.cm.config[col].isWrapped=colConfig.isWrapped;
                        }
                        if (col != i) {
                            this.cm.moveColumn(col, i);
                        }
                        if ("hidden" in colConfig) {
                            this.cm.setHidden(i, colConfig.hidden);
                        } else {
                            this.cm.setHidden(i, false);
                        }
                    }
                }
            }
            // there are few UIs where a component refresh could change the no of columns
            // In that case clear the grid state object.
            else {
              this.provider.clear(this.getStateKey());
            }
        }
    },
    resetState: function() {
        this.state.config = this.origConfig;
        this.restoreState(this.state);
    },
    getStateKey : function() {
        return this.grid.id + "-grid-state";
    },
    getState : function() {
        var cachedState = this.provider.get(this.getStateKey());
        return PTC.isDefined(cachedState) ? cachedState :{};
    },
    storeState : function(state){
          var stateKey = this.getStateKey();
          this.provider.set(stateKey, state);
     },
     
     destroy: function(){
        this.grid = undefined;
        this.cm = undefined;
        this.provider = undefined;
     }  
};



/**
 * Handler functin for table resize event
 * @param {String} grid Grid Panel of tha table
 * @param {String} provider - cache provider
 */
 Ext.grid.GridStateManager2.updateTableHeight = function(grid,provider){
        var gridManager = grid.getStateManager();
        var state = gridManager.getState();
        state.tableHeight = grid.el.getHeight();
         gridManager.storeState(state);
  };
/**
 * Handler functin for colum properties (Resize, hide, show) stickyness
 * @param {String} grid Grid Panel of tha table
 * @param {String} provider - cache provider
 */
Ext.grid.GridStateManager2.updateState = function(grid,provider){
        var cm = grid.getColumnModel();
        var gridManager = grid.getStateManager();
        var state = gridManager.getState();
        var activeViewInfo_config = PTC.jca.table.getActiveViewInfo(grid);

        // Copy column model config array.
        var c = [];
        for (var i = 0; i < cm.config.length; i++) {
            c.push({id: cm.config[i].id,
                    hidden: cm.config[i].hidden,
                    width: cm.config[i].width,
                    isWrapped: cm.config[i].isWrapped
            });
        }
        var obj = Ext.encode(c);
        state.config = Ext.decode(obj);
        state.variableRowHeight = grid.view.variableRowHeight;
        //Sync the State manager update count and of the active view
        if (activeViewInfo_config) {
            state.activeViewInfo = activeViewInfo_config;
        }
        gridManager.storeState(state);
};

Ext.apply(Ext.grid.GridPanel.prototype, {
    restoreState: function (provider) {
        if (!provider) {
            provider = Ext.state.Manager;
        }
        this.gsm = new Ext.grid.GridStateManager2();
        this.gsm.init(this, provider);
    },
    getStateManager : function() {
        return this.gsm;
    },
    getStickyConfig : function(){
        var configState = this.getStateManager().getState();
        var currentConfig = null;
        if(configState && "config" in configState){
            currentConfig = configState.config;
        }
        return currentConfig;
    },
    setStickyConfig : function(cfg) {
        if (cfg)  {
            var gridManager = this.getStateManager();
            var state = gridManager.getState();
            if (state) {
                state.config = cfg;
                gridManager.storeState(state); 
            }
        }  
    },
    clearStickyConfig : function(){
        var sm = this.getStateManager();
        if(sm){
            sm.provider.clear(sm.getStateKey());
        }
    },
    clearStickyConfigWidth : function(){
        var stickyConfig = this.getStickyConfig();
        if(stickyConfig){
            for(var i=0; i<stickyConfig.length;i++){
                delete stickyConfig[i].width;
            }
            if(this.readyForWidthCalculation) {
                //remove the flag - SPR 4909413
                delete this.readyForWidthCalculation;
            }
            this.setStickyConfig(stickyConfig);
        }
    },
    setStickyConfigHidden : function( hide, colId){
        var gridManager = this.getStateManager();
        if (gridManager){
            var configState = gridManager.getState();
            var currentConfig = null;
            if(configState && "config" in configState){
                currentConfig = configState.config;
                if(currentConfig){
                    for(var i=0; i<currentConfig.length;i++){
                        if (currentConfig[i].id == colId){
                            currentConfig[i].hidden = hide;
                            break;
                        }
                    }
                    configState.config = currentConfig;
                    gridManager.storeState(configState); 
                }
            }
        }
    },
    getCachedTableHeight : function(){
        var sm = this.getStateManager();
        var tableHeight;
        if(sm){
            var stateConfig = sm.provider.get(sm.getStateKey());
        }
         if(PTC.isDefined(stateConfig)){
           return stateConfig.tableHeight;
         }
         return tableHeight;
    }
});

/**
 * @class PTC.jca.table.stickiness
 */
PTC.jca.table.stickiness = function(){
    var FOCUSED_ROW = '_focusedRow';
    var FOCUSED_OFFSET = '_focusOffset';

    var SEARCH_IN_LIST = '_searchInList';
    //To store the last locked index column Id.
    var LOCKED_COLUMN_ID = '_lockedColumnId';

    // the value corresponds to the extra rows that are rendered in addition to visible rows in bufferView. 
    // overridden method getVisibleRows using bufferview.cacheSize which has value 5.
    var BUFFER_VIEW_OFFSET = 5;

    function clearAllTableStickiness(){
        var tables = tableUtils.getTables();
        for (var i = 0, l = tables.length; i < l; i++) {
            var gridId = tables[i].id;
            clearStickiness(gridId);
        }
    }

    PTC.navigation.on('historyChange', clearAllTableStickiness);

    var clearStickiness = function(gridId){
        PTC.attributeHelper.set(gridId + FOCUSED_ROW, null);
        PTC.attributeHelper.set(gridId + FOCUSED_OFFSET, null);
        PTC.attributeHelper.set(gridId + SEARCH_IN_LIST, null);
        PTC.jca.table.stickiness.log.debug('Cleared stickiness for table component : ', gridId);
    };

    return {
    	clearAllTablesStickiness : function(){
    	    clearAllTableStickiness();
        },
        clearTableStickiness : function(gridId){
            clearStickiness(gridId);
        },

        /**
         * Clears the stickiness of the tables present in the tab
         */
        clearTableStickinessInTab : function(tabId){
            var tables = PTC.jca.table.Utils.getExtTables(Ext.get(tabId).dom);
            for(var i=0, length=tables.length; i<length; i++){
                PTC.jca.table.stickiness.clearTableStickiness(tables[i].id);
            }
        },

        setFocusRow : function(gridId, focusedRow){
            PTC.attributeHelper.set(gridId + FOCUSED_ROW, focusedRow);
        },

        getFocusRow : function(gridId){
            return PTC.attributeHelper.get(gridId + FOCUSED_ROW);
        },

        clearFocusRow : function(gridId){
            PTC.attributeHelper.set(gridId + FOCUSED_ROW, null);
            PTC.attributeHelper.set(gridId + FOCUSED_OFFSET, null);
        },

        setSearchInListText : function(gridId, searchText){
            PTC.attributeHelper.set(gridId + SEARCH_IN_LIST, searchText);
        },

        getSearchInListText : function(gridId){
            return PTC.attributeHelper.get(gridId + SEARCH_IN_LIST);
        },

        clearSearchInListText : function(gridId){
            PTC.attributeHelper.set(gridId + SEARCH_IN_LIST, null);
        },
        setLockedColumnId : function(gridId, lockColumnId){
            PTC.jca.table.setObjectToSession(gridId, gridId + LOCKED_COLUMN_ID, lockColumnId);
        },
        getLockedColumnId : function(gridId){
            return PTC.jca.table.getObjectFromSession(gridId, gridId + LOCKED_COLUMN_ID);
        },
        clearLockingStickiness : function(gridId){
            PTC.jca.table.clearObjectFromSession(gridId, gridId + LOCKED_COLUMN_ID);
        },

        /* Sets the focus row offset from the bottom of the table. The value is used while scrolling to 
           the focused row after a component refresh */
        setFocusOffset : function(gridId, offset){
            PTC.attributeHelper.set(gridId + FOCUSED_OFFSET, offset);
        },

        getFocusOffset : function(gridId){
            return PTC.attributeHelper.get(gridId + FOCUSED_OFFSET);
        },

        clearFocusOffset : function(gridId){
            PTC.attributeHelper.set(gridId + FOCUSED_OFFSET, null);
        },

        getBufferViewOffset : function(){
            return BUFFER_VIEW_OFFSET;
        },

        /**
         * Initialize the search in list filter
         */
        initializeSearchInListFilter : function(grid){
            if(grid) {
            var searchText = PTC.jca.table.stickiness.getSearchInListText(grid.id);
            if(searchText && searchText.trim().length > 0){
                 grid.searchInString = PTC.jca.table.fit.getSafeSearchTerm(searchText);
                 var searchInListTextBox = Ext.getCmp(PTC.jca.table.findInTable.getSearchInListTextBoxName(grid.id));
                 searchInListTextBox.setValue(searchText);
                 return true;
            }
            }
            return false;
        },

        /**
         * Applies various table stickiness such as focus row stickiness
         */
        applyTableStickiness : function(){
           // apply focused row stickiness
           var focusRowId = this.grid.scrollIndex;
           var alreadyCached = false;
           if(this.grid.skipFocusCheck !== true){
              if(focusRowId){
                  alreadyCached = true;
              } else {
                  focusRowId = PTC.jca.table.stickiness.getFocusRow(this.grid.id);
              }
           }

           if(focusRowId){
               var fRowIndex = PTC.jca.table.Utils.getRowByUniqueIdentifier(this.grid.getStore(), focusRowId);
               if(fRowIndex > -1){
                   PTC.jca.table.Utils.focusRow(this.grid, fRowIndex, false, alreadyCached);
                   if(this.grid.alreadyScrolled !== true){
                       PTC.jca.table.Utils.scrollToFocusRow(this.grid, fRowIndex);
                   }
               }
           }else{
                // cached so that no need to recheck state manager on every refresh
                this.grid.skipFocusCheck = true;
           }
           // apply column locking state
           PTC.jca.table.Utils.applyColumnLock(this.grid, true);
        }
    };
}();

PTC.jca.table.stickiness.log = log4javascript.getLogger('PTC.jca.table.stickiness');


/**
 * Javascript port of HTMLEncoder.java, used for encoding untrusted data to prevent cross site scripting attacks.
 * In some cases we cannot do necessary XSS and html encoding on the server (e.g. new EPM docs in pro/e),
 * so this object contains the different utility functions for encoding strings
 */
PTC.util.HTMLEncoder = {

    NBSP: "&nbsp;",
    AMPERSAND_HTML_ENCODED: "&#38;",
    LESS_THAN_HTML_ENCODED: "&lt;",
    GREATER_THAN_HTML_ENCODED: "&gt;",
    DOUBLE_QUOTE_HTML_ENCODED: "&quot;",
    SINGLE_QUOTE_HTML_ENCODED: "&#39;",
    
    /**
     * Replaces multiple adjacent spaces with &nsbp;'s.
     * @param {String} str
     */
    handleAdjacentSpaces: function(str){
        /**
         * @private
         * @param {String} spaces
         * @return {String} amount of consecutive &nbsp;'s matches the length of the passed in string
         */
        function getReplacementString(spaces){
            var returnVal = '';
            var i = spaces.length;
            while (i--) {
                returnVal += PTC.util.HTMLEncoder.NBSP;
            }
            return returnVal;
        }
        
        if (typeof str === 'string') {
            //only capture 2 or more spaces
            str = str.replace(/( ){2,}/g, getReplacementString);
        }
        return str;
    },
    
    /**
     * Encodes the given string for use in HTML content. HTML content is generally defined as text displayed
     * in the page body and not within the &lt;..&gt; delimiters of a tag or directive.
     * <p>
     * This should be called before rendering untrusted data in HTML content.
     * <p>
     * Examples of HTML content:
     * <ul>
     * <li>&lt;body&gt; This is HTML content &lt;&#47;body&gt;
     * <li>&lt;div&gt; This is HTML content &lt;&#47;div&gt;
     * <li>&lt;p&gt; This is HTML content &lt;&#47;p&gt;
     * <li>&lt;td&gt; This is HTML content &lt;&#47;td&gt;
     * <li>&lt;textarea&gt; This is HTML content &lt;&#47;textarea&gt;
     * </ul>
     *
     * Only HTML-encodes the following characters: &, &lt;, &gt;, ', ". These characters should be sufficient as long
     * as HTML attributes are properly quoted.
     *
     * @param {String} Input str
     * @return {String} Encoded characters within the input string.
     */
    encodeForHTMLContent: function(str){
        if (typeof str === 'string') {
            str = str.replace(/[&]/g, this.AMPERSAND_HTML_ENCODED);
            str = str.replace(/[<]/g, this.LESS_THAN_HTML_ENCODED);
            str = str.replace(/[>]/g, this.GREATER_THAN_HTML_ENCODED);
            str = str.replace(/[\"]/g, this.DOUBLE_QUOTE_HTML_ENCODED);
            str = str.replace(/[\']/g, this.SINGLE_QUOTE_HTML_ENCODED);
        }
        return str;
    },
    
    /**
     * Placeholder function. Currently just calls encodeForHTMLContent()
     * @param {String} str
     * @return {Object} Encoded string for use in a non-URI HTML tag attribute value or as the value of a text area or
     * select field.
     */
    encodeForHTMLAttribute: function(str){
        return this.encodeForHTMLContent(str);
    },
    
    /**
     * calls encodeForHTMLContent() and also replaces all occurrences of multiple spaces with &nsbp;'s.
     * @param {String} str
     * @return {Object} Encoded string for display in HTML content.
     */
    encodeAndFormatForHTMLContent: function(str){
        return this.handleAdjacentSpaces(this.encodeForHTMLContent(str));
    },
    
    /**
     * Placeholder function. Currently just calls encodeForHTMLContent()
     * @param {String} str
     * @return {Object} Encoded string for use in HTML content with URL string patterns converted to hyperlinks.
     */
    encodeForHTMLContentAndCreateHyperLinks: function(str){
        return this.encodeForHTMLContent(str);
    },
    
    /**
     * Placeholder function. Currently just calls encodeForHTMLContent()
     * @param {String} str
     * @return {Object} Encoded string for use in a HTTPServletResponse header.
     */
    encodeForHTTPServletResponse: function(str){
        return this.encodeForHTMLContent(str);
    }
};


Ext.ns('PTC.ux.grid');

/**
 * @class PTC.ux.grid.RichTextGrid
 * @extends Object
 * Plugin (ptype = 'richtextgrid') Plugin so the grid has functionality/styles necessary for rich text to display properly.
 * Resolves SPR 2124748. 
 * 
 * @constructor
 * @param {Object} config Configuration options
 * @ptype richtextgrid
 */
PTC.ux.grid.RichTextGrid = Ext.extend(Object, {
    constructor: function(config){
        config = config || {};
        Ext.apply(this, config);
    },    
    init: function(grid) {
        //preventBodyReset so Ext styles that override bullets/lists/bold/italics etc will be reset to the browsers default look 
        grid.preventBodyReset = true;
        
        var view = grid.getView();
        if(view && Ext.isFunction(view.setVariableRowHeight)){
            view.setVariableRowHeight(true);
        }
    }
});

