/**
 * global singleton server state manager for information like infopage tab order, set of tables on 'My Tab', etc.
 * <br/><br/>
 * The stickiness is meant to be per user, per object type. The sticky info is stored using PTC.jca.state.ServerStateProvider which is already per user.
 * Keys given to PTC.jca.state.ServerStateProvider.set(key) should have the object type in them to achieve the per object type.
 * <br/><br/>
 * This information is sticky across sessions:
 * <ul>
 * <li>last tab visited
 * <li>tab order
 * <li>set of tables on each tab
 * </ul>
 * <br/><br/>
 * How to clear your stickiness is still TBD.antcf
 */
PTC.jca.state.ServerStateProvider = (function(){

    /**
     * This is a private singleton constructor for the one server state provider.
     * @param {Object} config
     */
    function ServerStateProviderSingleton(config){
        ServerStateProviderSingleton.superclass.constructor.call(this);
        Ext.apply(this, config);
        this.url = getBaseHref() + "ptc1/stateManager/";
        this.cache = new Hash();
    }
    
    /**
     * The server state provider singleton class is private, 
     * it's methods are all accessed through the singleton via the public interface defined below.
     * @param {Object} key
     * @param {Object} value
     */
    Ext.extend(ServerStateProviderSingleton, Ext.state.Provider, {
    
        set: function(key, value){
            this.checkKey(key);
            if (this.cache.get(key) === value) {
                return; // don't set a value when its the same 
            }
            var encodedValue = this.encodeValue(value);
            var options = {
                method: 'post',
                parameters: {
                    key: key,
                    value: encodedValue
                }
            };
            var transport = requestHandler.doRequest(this.url, options);
            
            //cache it right away to ensures correct value is in the cache if get is called immediately after a set
            this.cache.set(key, value);
            this.fireEvent("statechange", this, key, value);
        },
        
        get: function(key, defaultValue){
            this.checkKey(key);
            
            var value = this.cache.get(key);
            if (value !== null && value !== undefined) {
                //found value on the client
                return value;
            }
            else {
                //get the value from the server
                var options = {
                    method: 'get',
                    asynchronous: false,
                    parameters: {
                        key: key
                    }
                };
                var transport = requestHandler.doRequest(this.url, options);
                value = transport.responseText;
                
                if (value === '') {
                    value = defaultValue;
                }
                else {
                    value = this.decodeValue(value);
                }
                this.cache.set(key, value);
                return value;
            }
            
        },
        
        clear: function(key){
            this.set(key, '');
        },
        
        checkKey: function(key){
            if (!key) {
                throw new Error('The key key should not be null or empty');
            }
        }
        
    });
    
    
    var singleton = new ServerStateProviderSingleton({
        id: 'infoPage.tabState'
    });
    
    /**
     * The public interface to access the singleton
     */
    return {
        /**
         * Returns the current value for a key
         * name PTC.jca.state.ServerStateProvider.get
         * @param {Object} key - the key key
         * @param {Object} defaultValue - a default value to return if the key's value is not found.
         */
        get: function(key, defaultVal){
            return singleton.get(key, defaultVal);
        },
        
        /**
         * Store a value by the given key
         * @name PTC.jca.state.ServerStateProvider.set
         * @param {Object} key - the key key
         * @param {Object} value - the value to set
         */
        set: function(key, value){
            singleton.set(key, value);
        },
        
        /**
         * Clears a value from the state
         * @name PTC.jca.state.ServerStateProvider.clear
         * @param {Object} key - the key key
         */
        clear: function(key){
            singleton.clear(key);
        },
        
        /**
         * Check if the given key is invalid.
         * @name PTC.jca.state.ServerStateProvider.checkKey
         * @param {String} key - a key to check for invalid characters
         * @throws {Error} If there are any invalid characters in the key an Error is thrown
         */
        checkKey: function(key){
            singleton.checkKey(key);
        },
        
        /**
         * Pass through to allow the setting of event handlers on the private singleton instance. \
         * This object can fire a "statechange" event.
         * @name PTC.jca.state.ServerStateProvider.on
         * @param {Object} event - the event to handler, "statechange" 
         * @param {Object} eventhandler - the function to call to handle the event
         */
        on: function(event, eventhandler){
            singleton.on(event, eventhandler);
        },
        
        /**
         * Clears all the sticky preferences for the current user.
         * Currently just invokes the controller with a key of 'clearSticky'.
         * Also reloads the page to force clear the server store cache.
         * @name PTC.jca.state.ServerStateProvider.clearAll
         */
        clearAll: function() {
            singleton.cache = new Hash();
            singleton.set('clearAll', '');
            
            var msg = {
                MessageTitle: bundleHandler.get('com.ptc.core.ui.successMessagesRB.SERVER_STICKINESS_CLEARED'),
                MessageType: 'SUCCESS',
                Messages: [bundleHandler.get('com.ptc.core.ui.successMessagesRB.SERVER_STICKINESS_CLEARED_MSG')]
            };
            
            PTC.getMainWindow().PTC.messaging.showInlineMessage([msg]);
            
        }
    };
    
})();

/**
 * Pops up a JCA confirmation box asking the user if they want to clear server stickiness. 
 * If yes, stickiness is cleared (storageProvider.clearAll())
 */
PTC.jca.state.clearServerStickinessConfirmation = function(){
    var storageProvider = PTC.jca.state.ServerStateProvider;
    var clearSticky = JCAConfirm("com.ptc.netmarkets.software.softwareResource.SERVER_STORAGE_CONFIRMATION");
    if (clearSticky) {
        storageProvider.clearAll();
    }
};

PTC.SysNav = {};
PTC.SysNav.CLOSE_SYSNAV_WELCOME_PAGE = "CloseSysNavWelcomePage";


/**
 * A plugin to display a context menu for an Ext tab.  The context menu may contain many actions, defined in the actionService
 * based on the actionModel defined for the clientTab 
 * Tab
 * <br/></br>
 * To use this plugin, create an instance of it as a plugin of a TabPanel.
 * To specifiy that a tab within the tabPanel should not have a context menu, add the config option 
 * "allowContextMenu" and set it to false (defaults to true).
 * <br/><br/>
 * To specifiy that a tab within the TabPanel cannot be renamed, add a config option,
 * allowTitleChange, to the specific Panel, and set it to false (defaults to true).
 * <br/><br/>
 * The menu will only allow the Close Tab menu item to be available if the panel is closable.
 * 
 * @example
 * var myTabPanel = new Ext.TabPanel({
 *      id: 'someId',
 *      ...
 *      plugins: new Ext.ux.TabContextMenu(),
 *      items: [{
 *          id: 'somePanelId',
 *          html: 'this panel can be renamed and closed',
 *          closable: true,
 *          closeAction: 'close'
 *      }, {
 *          id: 'someOtherPanel',
 *          html: 'this panel will not have a context menu!'
 *          allowContextMenu: false
 *      }, {
 *          id: 'someOtherOtherPanel',
 *          html: 'this panel CANNOT not be renamed'
 *          allowTitleChange: false
 *      }]
 * });
 * 
 */
Ext.ux.TabContextMenu = function(){   
    /**
     * Handler for the right-click context menu event of a TabPanel.
     * Displays a context menu for the TabPanel with two possible menu items: Close Tab and Rename Tab
     * @param {TabPanel} tabPanel the TabPanel
     * @param {Panel} item the item clicked
     * @param {EventObject} e the event
     */
    function onContextMenu(tabPanel, item, e) {
		e.stopEvent();
        if (item.allowContextMenu === false) {
            // To stop the basic browser right click menu from appearing
            return;
        }
        var formAction = PTC.util.getFormAction(getMainForm());
        var params = {
            context : decodeURIComponent(extractParamValue(formAction, "ContainerOid")),
            oid : item.oid,//current tab oid.
            infopageOid : decodeURIComponent(extractParamValue(formAction, "oid")), //current page oid, which is the infopage
            tableID : item.id,  //Its a component id, need to be renamed
            actionName : 'actionsMenu' // certain action delegates such as MoveURLActionDelegate expect this parameter
    	};
        PTC.menu.showActionsMenu(e, params, item);
     }
     
    this.init = function(tp){
        tp.on('contextmenu', onContextMenu);
    };
};


/**
 * The Tab Manager is used to maintain the current state of the top-level tabs on the
 * info page.  As tabs are added/removed/moved in the Tab Panel, the corresponding
 * functions will persist the current state of the Tab/Tab Panel in the database via
 * AJAX requests.
 * <br><br>
 * Likewise, as items are added/removed/moved on a particular tab, the corresponding
 * functions will persist the current state of the tab in the database via AJAX requests.
 *
 */
/**
 *@namespace
 */
PTC.jca.manager = {};

// logger for the namespace
PTC.jca.manager.log = log4javascript.getLogger('PTC.jca.manager');

//prototype only supports post and get, so we overload the post method and
//send an "action" parameter to call our specific add, delete, etc.
PTC.jca.manager.jsonMethod = 'post';

/**
 * This object is used to maintain the current state of the top-level tabs on the Info Page.
 */
PTC.jca.manager.TabManager = Ext.extend(Object, {

    constructor: function(config) {
        config = config || {};
        config.url = config.url || getBaseHref() + "ptc1/tab/";
        Ext.apply(this, config);
    },

    /**
     * Initializes this object with the given tab panel.
     *
     * @param {Object} tabPanel - the tab panel that the tabs should be added to
     */
    init: function(tabPanel){
        this.tabPanel = tabPanel;
    },

    invokeAction: function(tab, options){
        Ext.applyIf(options, {
            method: PTC.jca.manager.jsonMethod,
            onFailure: PTC.jca.manager.showFailureMessage
        });
        return requestHandler.doRequest(this.url, options);
    },


    /**
     * Adds the new tab to the tab panel. It also persists the tab in the database via
     * an AJAX request.
     * TODO: refactor to use server tab rendering for code reuse (PTC.infoPage.registerTabRenderer('defaultTabRenderer')
     * @param {Function} callback - function to call if the tab is saved successfully in the database
     * @param {Object} [params] Optional parameters can be passed to the request
     */
    add: function(callback, params){
        PTC.jca.manager.log.debug("Calling add() in TabManager, saving tab...");

        // local reference to be used in the onSuccess handler
        var tabPanel = this.tabPanel;
        var newTab = null;

        //get a temp name when first created (e.g "New Tab 1")
        var title = PTC.infoPage.myTab.getUniqueTabName(tabPanel);
        Ext.applyIf((params = params ? params:{}),{
            data: Ext.encode({
                name: title,
                tabSetKey: PTC.infoPage.TabUtils.getTabSetKey(tabPanel.infoModel),
                objectType:PTC.infoPage.TabUtils.getObjectType(tabPanel.infoModel),                    
                isPublic: false
            }),action: 'create'});
        var options = {
            parameters: params,                
            onSuccess: function(response){
                var json = response.responseJSON;

                //init tab with attributes from db
                var tabPanelConfig = PTC.infoPage.myTab.getNewTabConfig(tabPanel, json);
                newTab = new PTC.infoPage.myTab.MyTabPanel(tabPanelConfig);

                //add tab to panel
                var addTabTab = Ext.get(tabPanel.id + "__new_tab_action");
                if (addTabTab) {
                    tabPanel.insert(tabPanel.items.length - 1, newTab);
                }
                else {
                    tabPanel.insert(tabPanel.items.length, newTab);
                } 

                tabPanel.setActiveTab(newTab.id);

                //any extra functionality
                if (callback) {
                    callback(newTab, tabPanel);
                }
                
                tabPanel.tabSet.saveTabOrderAddTab(tabPanel,newTab.actionID);
            }
        };

        this.invokeAction(null, options);
        //at this point newTab should have an object associated with it
        return newTab;
    },

    /**
     * Changes the displayed name and/or the public/private status of the given tab
     * and persists the new tab name in the database via an AJAX request.
     * 
     * @param {PTC.infoPage.myTab.MyTabPanel} tab - The tab to be updated
     * @param {String} [name] If non-null, the new name for the tab
     * @param {String} [visibility] - If non-null, the new state for the tab ('public' or 'private').
     * @param {Function} [callback] Optional function to run additional code after successfully updating the tab
     * @param {Object} [params] Optional parameters can be passed to the request
     * @param {Object} [params] If non-null, decides weather tab to be inherited or not to its subtypes
     */
    updateTab: function(tab, name, visibility, callback, failureCallback, params, isInherit){
        PTC.jca.manager.log.debug("entered TabManager.updateTab(). tab = ", tab, "name = ", name, "visibility = ", visibility);

        //Empty string in the case that we don't need to update the visibility.
        var isPublic = "";
        if(visibility) {
            isPublic = (visibility === 'public');
        }

        var infoModel = this.tabPanel.infoModel ? this.tabPanel.infoModel : tab.getOwner().infoModel;
        
		Ext.applyIf((params = params ? params:{}), {
                data: Ext.encode({
                    oid: tab.oid,
                    name: name,
                    isPublic: isPublic,
                    tabSetKey: PTC.infoPage.TabUtils.getTabSetKey(infoModel),
                    objectType:PTC.infoPage.TabUtils.getObjectType(infoModel),
                    inherit:isInherit
                }),
                action: 'update'
            });

		var options = {
            parameters: params,
            onSuccess: function(response){
                if (callback) {
                    tab = callback(tab, options.parameters);
                }
            }
        };

        if(failureCallback) {
        	Ext.applyIf(options, { 
				onFailure: function(response) {
			   		failureCallback(tab, response);
	        	}
			});
	    }        
        this.invokeAction(tab, options);
        return true;
    },

    /**
     * Deletes a given tab and its tables out of the UI if the user confirms the deletion.
     * @param {Object} tab The tab to delete
     * @param {Function} [callback] Optional function to run additional code after successfully deleting the tab
     * @return true if deleting the tab was successful
     */
    deleteTab: function(tab, callback){
        // local reference to be used in the onSuccess handler
        var tabPanel = this.tabPanel;
        var okButtonText = bundleHandler.get('com.ptc.core.ui.navigationRB.okButton');
        var cancelButtonText = bundleHandler.get('com.ptc.core.ui.navigationRB.cancelButton');
        Ext.Msg.show({
            title: bundleHandler.get('com.ptc.core.ui.confirmationMessagesRB.DELETE_TAB_CONFIRMATION_TITLE'),
            msg: bundleHandler.get('com.ptc.core.ui.confirmationMessagesRB.DELETE_TAB_CONFIRMATION_MESSAGE'),
            buttons: {ok: okButtonText, cancel: cancelButtonText},
            icon: 'deleteTab-confirm-icon',
            fn: function(buttonId, text, opt){
                if (buttonId === 'ok') {
                    PTC.jca.manager.log.debug("calling deleteTab() in TabManager, deleting tab: ", tab);
                    var options = {
                        parameters: {
                            data: Ext.encode({
                            oid: tab.oid
                        }),
                        action: 'delete'
                    },
                    onSuccess: function(response){
                        // remove tables from the dom
                        var oldTables = PTC.infoPageTableMgr._getRenderedTablesForTab(tab.id);
                            for (var i = 0; i < oldTables.length; i++) {
                                PTC.infoPageTableMgr.removeRenderedTable(oldTables[i].containerDiv, oldTables[i].tabId);
                        }
                        // clear the stickiness of the tables present on the closing tab
                        if(typeof tab.getTableContainer === 'function'){
                            var tabContainer = tab.getTableContainer();
                            if(tabContainer && typeof tabContainer.clearTableStickinessInTab === 'function'){
                                tabContainer.clearTableStickinessInTab(tab.id);
                            }
                         }
                        // call Ext's remove tab api on Ext.TabPanel
                        tabPanel.remove(tab);
                        // optional function for additional work
                        return (callback) ? callback(tab) : TRUE_FUNC;
                    }
                };
                PTC.infoPage.getTabManager(tabPanel).invokeAction(tab, options);
                return true;
                }
            }
        });
        return false;
    },

    /**
     * @return tab set for this tab manager's tab panel
     */
    getTabSet : function() {
        return this.tabPanel.items.items;
    },

    /**
     * Sets the active tab object for this info page tab set
     * @param {Object} activeTab
     */
    setActiveTab : function(activeTab) {
        this.activeTab = activeTab;
    },

    /**
     * @return the active tab for this info page tab set
     */
    getActiveTab : function() {
        return this.activeTab;
    },
    
    destroy: function(){
        delete this.activeTab;
        delete this.tabPanel;
    }
});


/**
* This object is used to maintain the content of a info page tab.  As items are
* added/removed/moved on the tab, the corresponding functions are called.
*
*/
PTC.jca.manager.TabContentManager = Ext.extend(Object, {
    constructor: function(config) {
        config = config || {};
        config.url = config.url || getBaseHref() + "ptc1/tab/";
        Ext.apply(this, config);
    },

    /**
     * Initializes this object with the given tab.
     *
     * @param {Object} tab - the tab to add the items to
     */
    init: function(tab){
        this.tab = tab;
        //for add/remove of multiple tables at once, just do one ajax call to update the server - v1 defect D-12418
        //otherwise may end up with the wrong set of tables persisted if the server recieves the requests out of order
        this.invokeAction = PTC.util.delayAllCalls(this.invokeAction);
    },

    /**
     *
     * @param {Object} item table/panel being modified on the tab
     * @param {Object} options ajax request options, (expecting onSuccess at a minimum)  Default method is 'post', default
     *                    action is 'update', default data is the tab oid and the component ids.
     * @param {Function} componentFilter (item, tableid) - if not all table ids should be saved, pass in filter function
     *                      that returns true for each component id that should be persisted
     */
    invokeAction: function(item, options, componentFilter){
        if(!this.tab.oid) {
            return;
        }

        var tabItems = [];

        this.tab.getTableContainer().items.each(function(table){
            if (componentFilter(item, table)) {
                 tabItems.push({name: table.actionName, type: table.actionType});
            }
        });

        // if a non-admin user is modifying the OOTB homepage, save the changes as a new user defined tab
        if (this.tab.isHomepageTab && this.tab.isSiteConfig) {
            this.createHomePageTab(tabItems);
            return;
        }

        var obj = {oid: this.tab.oid, components: tabItems};

        Ext.applyIf(options, {
                method: PTC.jca.manager.jsonMethod,
                parameters: {
                    data: Ext.encode(obj),
                    action: 'update'
                },
                onFailure: PTC.jca.manager.showFailureMessage
            }
        );

        // persist the tab changes
        requestHandler.doRequest(this.url, options);
    },

    /**
     * This will create the home page "tab" in the database and on the same request it will
     * persist the components.
     *
     * @private
     */
    createHomePageTab: function(tabItems) {
        var tab = this.tab;

        // We're updating the home page configuration (isSiteConfig is only set for the homepage configuration)
        // a user has the default site settings, they're trying to make a change
        // we need to create some setting specific to this user.
        var newClientTabOptions = {
            parameters: {
                data: Ext.encode({
                    name: "homepage",
                    objectType: "home-page",
                    tabSetKey: "home-page",
                    components: tabItems
                }),
                action: 'create'
            },
            onSuccess: function(response){
                var json = response.responseJSON;

                //init tab with attributes from db
                tab.oid = json.oid;
                tab.isSiteConfig = false;
                tab.editable = true;
            },
            onFailure: PTC.jca.manager.showFailureMessage
        };

        requestHandler.doRequest(this.url, newClientTabOptions);
    },

    /**
     * Adds the item to the tab. It also saves the current state of the tab in the
     * database via an AJAX request.
     * @param {Object} item - the item to add to the tab
     * @param {Function} callback - function to call if the tab is saved successfully in the database
     */
    add: function(item, callback){
        PTC.jca.manager.log.debug("calling add() in TabContentManager, adding item: ", item);
        return this.invokeAction(item, {onSucess: callback}, TRUE_FUNC);
    },

    /**
     * Removes the item from the tab. It also saves the current state of the tab in the
     * database via an AJAX request.
     * @param {Object} item - the item to remove from the tab
     */
    remove: function(item){
        PTC.jca.manager.log.debug("calling remove() in TabContentManager, removing item: ", item);
        var tab = this.tab;
        var successFunc = function(){
            tab.remove(item);
        };
        var filter = function(item, table){
            return (table.actionName !== item.actionName || table.actionType !== item.actionType);
        };
        return this.invokeAction(item, {onSuccess: successFunc},filter);
    },

    /**
     * Saves the current state of the tab in the database via an AJAX request
     *
     * @param {Function} callback - function to call if the tab is saved successfully in the database
     */
    saveItems: function (callback) {
        PTC.jca.manager.log.debug("calling saveItems() in TabContentManager, saving item: ", this.tab.items);
        return this.invokeAction(this.tab.items, {onSuccess: callback},TRUE_FUNC);
    },
    
    /**
     * Returns the actively displayed items for this tab. If the tab has never been rendered, the default items will
     * be returned.
     */
    getContents: function () {
        var items = [];
        if (PTC.infoPageTableMgr._getRenderedTablesForTab(this.tab.id).length === 0) {
            // tab may not have been rendered yet
            if (this.tab.initialConfig && this.tab.initialConfig.defaultItems) {
                items = this.tab.initialConfig.defaultItems;
            }
        } else {
            items = PTC.infoPageTableMgr._getRenderedTablesForTab(this.tab.id);
        }
        
        return items;
    },

    /**
     * Returns the top level info page object, starting at some child component in the info page (i.e. a tab or an item on a tab)
     * @returns {Object} The top level element representing the info page
     */
    _getInfoPage: function (infoPageChild) {

        if(!infoPageChild) {
            return false;
        }

        // can't check the info page id since that's dependent on the infoPage model so check some other
        // attribute on the Ext cmp to see if it's the top level info page object
        if(infoPageChild.initialConfig && infoPageChild.initialConfig.cls === 'infoPage') {
            return infoPageChild;
        } else {
            // navigate up the component hierarchy to find the top level info page object
            return !infoPageChild.ownerCt ? undefined : this._getInfoPage(infoPageChild.ownerCt);
        }
    },

    /**
     * Reloads each item on the tab from the server.  This will re-request the URL for each item.
     */
    reloadContents: function() {
        
        var items = this.getContents();
        var thirdLevelNavModel = this.tab.thirdLevelNavModel;
        var serializedMainForm = Ext.lib.Ajax.serializeForm(getMainForm(this._getInfoPage(this.tab).getEl().dom));

        // for each item on the tab, reload it with the new information from the server
        for(var i=0, l=items.length; i<l; i++) {
            var item = items[i];
            var itemCconfig = PTC.actionModel.getActionConfig(item.id, thirdLevelNavModel);
            var itemDivId = item.containerDiv;

            // re-paint the item with the new data
            var dom = Ext.get(itemDivId).dom;
            PTC.navigation.overwrite(dom, '<div style="background: url(netmarkets/javascript/ext/resources/images/default/shared/blue-loading.gif) no-repeat center center; height: 100px">&nbsp;</div>');
            getElementHtml(serializedMainForm, itemDivId, true, itemCconfig.actionURL, false);
        }
    },
        
    destroy: function(){
        delete this.tab;
        delete this.invokeAction;
    }
});

PTC.jca.manager.PortalContentManager = Ext.extend(Object, {
    constructor: function(config) {
        config = config || {};
        config.url = config.url || getBaseHref() + "ptc1/tab/";
        Ext.apply(this, config);
    },

    /**
     * Initializes this object with the given portal column.
     *
     * @param {PTC.miniNavigator.PortalColumn} column - the portal column managed by this content manager
     */
    init: function(column){
        this.column = column;
        //for add/remove of multiple tables at once, just do one ajax call to update the server - v1 defect D-12418
        //otherwise may end up with the wrong set of tables persisted if the server recieves the requests out of order
        this.invokeAction = PTC.util.delayAllCalls(this.invokeAction);
    },
    
    /**
     * Invoke the desired action.
     * 
     * @param {Object} paramData - extra data parameters
     * @param {String} action - create/update
     * @param {Function} onSuccess - onSuccess callback
     */
    invokeAction: function(paramData, action, onSuccess) {
        var column = this.column;
        var components = [];
        var portlets = column.getPortlets();
        for (var i = 0, l = portlets.length; i < l; i++) {
            var portlet = portlets[i];
            components.push({
                name: portlet.actionName,
                type: portlet.actionType,
                collapse: portlet.collapsed
            });
        }
        var data = {
            name: 'miniNavWidgets',
            components: components,
            isPublic: false
        };
        Ext.apply(data, paramData);
        var options = {
            method: PTC.jca.manager.jsonMethod,
            parameters: {
                data: Ext.encode(data),
                action: action
            },
            onSuccess: onSuccess,
            onFailure: PTC.jca.manager.showFailureMessage
        };
        return requestHandler.doRequest(this.url, options);
    },
    
    
    create: function() {
        PTC.jca.manager.log.debug("Calling create() in PortalContentManager, saving portal column...");
        var column = this.column;
        var onSuccess = function(response){
            var json = response.responseJSON;
            column.oid = json.oid;
        };

        this.invokeAction({objectType: column.objectType, tabSetKey:column.tabSetKey}, 'create', onSuccess);
    },
    
    update: function() {
        PTC.jca.manager.log.debug("Calling update() in PortalContentManager, updating portlets...");

        this.invokeAction({oid: this.column.oid}, 'update', Ext.emptyFn);
    }
});

/**
 * Displays a warning message in a lightbox window. If no title and message is passed in, the default message is 
 * something like : 'WARNING: Changes to your tab layout were not saved'
 * 'The changes you attempted to make were not saved.  Contact your system administrator for assistance.'
 */
PTC.jca.manager.showFailureMessage = function(){
    var title = bundleHandler.get('com.ptc.core.ui.errorMessagesRB.PERSIST_TAB_ERROR_HEADER');
    var msg = bundleHandler.get('com.ptc.core.ui.errorMessagesRB.PERSISTENCE_ERROR');
    PTC.messaging.showWarningMessage(title, msg);
};


Ext.ux.TabScrollerAddTabButton =  Ext.extend(Object, {
	constructor    : function(config) {
		config = config || {};
		Ext.apply(this, config);
	},
	init : function(tabPanel) {
		Ext.apply(tabPanel, this.tabPanelMethods);
		
		tabPanel.TabScrollerAddTabButton = this;
		var thisRef = this;
		
		tabPanel.on({
			render : {
				scope  : tabPanel,
				single : true,
				fn     : function() { 
					var newFn = tabPanel.createScrollers.createSequence(thisRef.createPanelsAddTabButton, this);
					tabPanel.createScrollers = newFn;
				}
			}
		});
	},
	// private && sequeneced
	createPanelsAddTabButton : function() {
		var h = this.stripWrap.dom.offsetHeight;
		//move the right menu item to the left 18px
		var rtScrBtn = this.header.dom.firstChild;
		Ext.fly(rtScrBtn).applyStyles({
			right : '18px'
		});
		
		var stripWrap = Ext.get(this.strip.dom.parentNode);
		stripWrap.applyStyles({
			 'margin-right' : '36px'
		});
		
		// Add the new righthand menu
		var addTabButton = this.header.insertFirst({
			cls:'x-tab-addTabButton-right'            
		});
        Ext.QuickTips.register({
          target: addTabButton,
          text: bundleHandler.getBundleStringAndInserts("com.ptc.core.ui.navigationRB.INFO_PAGE_NEW_TAB", [''])
        });
        var rightScroller = Ext.query('.x-tab-scroller-right');
        if (rightScroller.size() > 0) {
            Ext.QuickTips.register({
              target: rightScroller[0],
              text: bundleHandler.get("com.ptc.core.ui.navigationRB.SCROLL_TABS_RIGHT")
            });
        }
          
		addTabButton.setHeight(h);
		addTabButton.addClassOnOver('x-tab-addTabButton-over');
		addTabButton.on('click', this.addTabButtonHandler, this);	

        //The first time, this method is called but not the show and hides, so on create of the button also hide the tab that creates tabs.
        var addTabTab = Ext.get("infoPageinfoPanelID__new_tab_action");
        if (addTabTab) {
            addTabTab.hide();
        }

		this.scrollLeft.show = this.scrollLeft.show.createSequence(function() {
			addTabButton.show();
			if (addTabTab === null) {
				//sometimes when we get here this is null if so try to get it so we can hide it.
				addTabTab = Ext.get("infoPageinfoPanelID__new_tab_action");
			}
			if (addTabTab) {
				addTabTab.hide();
			}       
			//The tab strip must hide the overflow or the scrolling doesn't work
			stripWrap.applyStyles({
				 'overflow' : 'hidden'
			});
		});
        Ext.QuickTips.register({
          target: this.scrollLeft,
          text: bundleHandler.get("com.ptc.core.ui.navigationRB.SCROLL_TABS_LEFT")
        });
		var tabPanel = this;
		this.scrollLeft.hide = this.scrollLeft.hide.createSequence(function() {
			if (addTabTab === null) {
				//sometimes when we get here this is null if so try to get it so we can show it.
				addTabTab = Ext.get("infoPageinfoPanelID__new_tab_action");
			}
			if (addTabTab) {
				addTabTab.show();
			}else {
				PTC.infoPage.myTab.addNewTabAction(tabPanel.id);
			}
			addTabButton.hide();
			//If the overflow is hidden when there is no scrolling sometimes the left and right edges are messed up
			//Either the first tab is too far left or the line going under the panel is too short on the far right.
			stripWrap.applyStyles({
				 'overflow' : 'visible'
			});
		});
		
	},	
	// private && applied to the tab panel itself.
	tabPanelMethods : {
		// all execute within the scope of the tab panel
		// private	
		addTabButtonHandler : function(e) {
            PTC.infoPage.myTab.addNewTab(this);		
	    }
	}	
});


/**
 * Object that represents the set of tabs on an info page. This object is typically used on a tabPanel as the tabPanel's
 * items.
 * @namespace
 * @name PTC.infoPage.TabSet
 */
PTC.infoPage.TabSet = Ext.extend(Object, {

    /**
     * @param {Array} serverTabSet set of ext tabs
     * @param {String} tabSetKey key for the object being displayed.
     * @param {String} objectType Persistable Type Identifier representation of the type of object.
     * @see PTC.infoPage.TabUtils.getTabSetKey(infoModel) to get the correct key.
     * @see PTC.infoPage.TabUtils.getObjectType(infoModel) to get the correct type instance representation.
     * @name PTC.infoPage.TabSet.constructor
     */
    constructor: function(config){
        config = config || {};
        Ext.apply(this, config);
    },
    
    /**
     * Prefix for getting and setting tab order to the preference manager
     * @constant
     * @name PTC.infoPage.TabSet.TAB_ORDER_PREFIX
     */
    TAB_ORDER_PREFIX: 'infoPage_tabOrder_',
    
    /**
     * max number of new tabs allowed to be added by an admin before completely replacing what is already stored
     * as the user's tab order in their preferences
     * @name PTC.infoPage.TabSet.MAX_NEW_TAB_LENGTH
     * @constant
     */
    MAX_NEW_TAB_LENGTH: 9,
    
    /**
     * First position in an array
     * @name PTC.infoPage.TabSet.FIRST_ARRAY_POSTION
     * @constant
     */
    FIRST_ARRAY_POSTION: 0,
    
    /**
     * Offset to get the the index of a tab left of this current tab in an array
     * @name PTC.infoPage.TabSet.LEFT_TAB_OFFSET
     * @constant
     */
    LEFT_TAB_OFFSET: -1,
    
    /**
     * Offset to get the the index of a tab right of this current tab in an array
     * @name PTC.infoPage.TabSet.RIGHT_TAB_OFFSET
     * @constant
     */
    RIGHT_TAB_OFFSET: 1,
    
    /**
     * return all real tab ids--the 'new_tab_action' tab (the 'plus' tab) does not have an actionID so it is excluded
     * @return {Array}
     * @name PTC.infoPage.TabSet.getAllServerTabIds
     */
    getAllServerTabIds: function() {
        return Ext.pluck(this.serverTabSet, 'actionID');
    },
    /**
     * return preference key. This key will be of format "infoPage_tabOrder_objectType_tabSetKey" 
     * e.g. 
     * infoPage_tabOrder_wt.epm.EPMDocument|456_|PROE|CADCOMPONENT|
     * infoPage_tabOrder_wt.epm.EPMDocument|456 |PROE|CADASSEMBLY|
     * infoPage_tabOrder_wt.part.WTPart|123_infoPage
     * @return {String}
     * @name PTC.infoPage.TabSet.getPreferenceKey
     * 
     */
    getPreferenceKey: function (){
        return this.TAB_ORDER_PREFIX + this.objectType + '_' + this.tabSetKey;
    },
    
    /**
     * Save the order of tabs into the preference manager when a user adds a new tab
     * @param {Ext.TabPanel} tabPanel
     * @param {Object} actionID
     * @param {Object} toPosition
     * @name PTC.infoPage.TabSet.saveTabOrderAddTab
     */
    saveTabOrderAddTab: function(tabPanel, actionID){       
        //Update cached super set
        this.superSetIds[this.superSetIds.length] = actionID;
        //save to preference (ajax call)
        this.setPreferenceTabOrder(this.superSetIds);
    },
    
    /**
     * Save the order of tabs into the preference manager when a user removes a tab
     * @param {Ext.TabPanel} tabPanel
     * @param {Object} actionID
     * @param {Object} toPosition
     * @name PTC.infoPage.TabSet.saveTabOrderRemoveTab
     */
    saveTabOrderRemoveTab: function(tabPanel, actionID){
        //Update cache
        this.superSetIds.remove(actionID);
        //save to preference (ajax call)
        this.setPreferenceTabOrder(this.superSetIds);
    },
    
    /**
     * Save the tab panel order of the given tabPanel.
     * This gets called when a tab is drag/dropped.
     * @param {Ext.TabPanel} tabPanel
     * @param {Object} actionID
     * @param {Object} toPosition
     * @name PTC.infoPage.TabSet.saveTabOrderDrag
     */
    saveTabOrderDrag: function(tabPanel, actionID, toPosition){
        if (toPosition === this.FIRST_ARRAY_POSTION) {
            this.superSetIds.remove(actionID);
            this.superSetIds.splice(this.FIRST_ARRAY_POSTION, 0, actionID);
        }
        else {
            // tab was dragged somewhere else than the 1st position
            var leftTabActionId = tabPanel.items.items[toPosition + this.LEFT_TAB_OFFSET].actionID;
            
            //remove actionID from old location
            this.superSetIds.remove(actionID);
            
            //this is the index of the tab to the left of where our tab will go
            var leftTabIndex = 0;
            for (var i = 0; i < this.superSetIds.length; i++) {
                if (this.superSetIds[i] === leftTabActionId) {
                    leftTabIndex = i;
                    break;
                }
            }
            
            //add tab to right of left tab index
            this.superSetIds.splice(leftTabIndex + this.RIGHT_TAB_OFFSET, 0, actionID);
        }
        //save to preference (ajax call)
        this.setPreferenceTabOrder(this.superSetIds);
    },
    
    /**
     * @private
     * Returns the value for this user's tab order stored in the preference manager
     * @return {String} common separated list of tabs on infopage for the given object type
     */
    getPreferenceTabOrderString: function(){
        return PTC.jca.state.ServerStateProvider.get(this.getPreferenceKey());
    },
    
    /**
     * @private
     * save array of tab ids to the preference manager for this object type (e.g. "wt.part.WTPart")
     * @param {Array} idList array of tab ids
     */
    setPreferenceTabOrder: function(idList){
        var idListString = idList.join(',');
        PTC.jca.state.ServerStateProvider.set(this.getPreferenceKey(), idListString);
    },
    
    /**
     * @private
     * Get the tab panel order for the given tabSetKey
     * @see PTC.infoPage.TabUtils.getTabSetKey(infoModel) to get the correct key.
     * (most types get their own key, but some types like NewEPMDocument and EPMDocument have the same key to share
     * tab order)
     *
     * @return {Array} ids - an array of action/action model actionIDs for the tabs. For example:
     *  ['psb_productStructureGWT','object_partInfoDetailsTab','object_partInfoRelatedItemsTab','tab_jcaGen_67221']
     */
    getPreferenceTabOrder: function(){
        var idList = this.getPreferenceTabOrderString();
        if (!idList) {
            return null;
        }
        return idList.split(',');
    },
    
    /**
     * @private
     * convert array of actionIDs to an array of tab objects
     * @param {Array} orderedTabIds array of tab actionIds
     * @return {Array} array of tab objects
     */
    convertActionIdArrayToTabObjectArray: function(orderedTabIds){
        var orderResult = [];
        for (var j = orderedTabIds.length; j--;) { // loop backwards for performance
            for (var k = this.serverTabSet.length; k--;) {
                if (this.serverTabSet[k].actionID === orderedTabIds[j]) {
                    orderResult[j] = this.serverTabSet[k];
                    break;
                }
            }
        }
        return orderResult;
    },
    
    /**
     * Re-orders the tabSet based off the order stored in the preference manager
     *
     * @return {Array} a new serverTabSet with the corrected order
     * @name PTC.infoPage.TabSet.getCalculatedTabOrder
     */
    getCalculatedTabOrder: function(){
        var serverIds = this.getAllServerTabIds();
        this.superSetIds = serverIds.clone();
        
        var prefIds = this.getPreferenceTabOrder();
        if (prefIds === null || this.serverTabSet === null) {
            // no preference for this object stored yet, so just return the tabSet
            PTC.infoPage.TabUtils.log.debug("no preference for this object currently exists so just returning it");
            return this.serverTabSet;
        }
        
        // keep track of newly added tabs
        var addedServerIds = serverIds.clone();
        
        // throw away any ids that were stored but don't exist on the tabSet
        // e.g. Saved CAD Doc vs Persisted CAD Doc
        var validIds = prefIds.findAll(function(id){
            if (serverIds.include(id)) {
                addedServerIds.remove(id); // used to keep track of all newly added tabs
                return true;
            }
        });
        
        if (validIds.length === 0 || addedServerIds.length > this.MAX_NEW_TAB_LENGTH) {
            // we don't have any valid ids to show so all the tabs must be new. 
            // Therefore, just return the getTabSet()
            PTC.infoPage.TabUtils.log.debug("no valid tabs to return so returning unchanged tabSet");
            return this.serverTabSet;
        }
        
        var orderedTabIds = prefIds.clone();
        
        // add all new tabs to preference list
        this.serverTabSet.each(function(tab){
            if (!orderedTabIds.include(tab.actionID)) {
                orderedTabIds[orderedTabIds.length] = tab.actionID;
            }
        });
        
        // This is ordered and all the new tabs are in the lorderedTabIds. This is the full tab set.
        this.superSetIds = orderedTabIds.clone();  
        
        // remove all deleted tabs from preference list
        prefIds.each(function(tab){
            if (!serverIds.include(tab)) {
                orderedTabIds.remove(tab);
            }
        });
                
        return this.convertActionIdArrayToTabObjectArray(orderedTabIds);
    }
});



/**
 * @class
 * This is a collection of tab utilities.
 *
 * @singleton
 *
 * @example
 * //get a tab by id
 * var tab = PTC.infoPage.TabUtils.getTabById(tabSet, tabId);
 *
 * //get the tab set key to use when saving tab order, tab content or last active tab
 * var tabSetKey = PTC.infoPage.TabUtils.getTabSetKey(infoModel);
 *
 *
 */
PTC.infoPage.TabUtils = (function(){

    return {
        /**
         * logger for the PTC.infoPage.TabUtils
         */
        log: log4javascript.getLogger("PTC.infoPage.TabUtils"),
        
        /**
         * get a tab id prefix based on the infoModel id.
         * gets a common tab prefix for user-created tabs.
         * @param {Object} infoModel
         * @return {String} a string based on the infoModel id that can be used for tabPanel IDs.
         */
        getTabIdPrefix: function(infoModel){
            return infoModel.id + "_myTab";
        },
        
        /**
         * Given a tab id it returns the tab object within the tabset
         * @param {Object} tabSet The set of tabs to search in
         * @param {String} tabId The tabId to find in the tabset
         * @return Gives back the tab given the tabId otherwise will return null.
         */
        getTabById: function(tabSet, tabId){
            for (var i = 0; i < tabSet.length; i++) {
                if (tabSet[i].id === tabId) {
                    return tabSet[i];
                }
            }
            
            return null;
        },
        
        /**
         * Is the given table on the given tab. Uses the list of rendered tables for a given tab. If tab has not been
         * rendered yet, the default set of tables is used.
         *
         * @param {Object} tab The tab in which to search for tables
         * @param {Object} tableAction This is a combination of table actionName and actionObject (ie. objectprimaryattributes).
         * @return True if the table is on the tab and false otherwise.
         */
        isTableOnTab: function(tab, tableAction){
            // if the tab has already been rendered and is a "normal" tab (eg. NOT the structure browser), it will have
            // a contentManager. If there is no contentManager, check to see if it has a defaultItems array (meaning
            // the tab has not been rendered yet)
            var tables = tab.tabContentManager ? tab.tabContentManager.getContents() : (tab.defaultItems ? tab.defaultItems : []);
            
            for (var i = 0, numTables = tables.length; i < numTables; i++) {
                if (tables[i].id === tableAction) {
                    return true;
                }
            }
            
            return false;
        },
        
        /**
         * Returns a component/table that is on the action model.  If no
         * component found it will return null/undefined.
         *
         * @param {Object} items The action model items
         * @param {Object} actionId The component id as a string
         * @param {Object} foundTable leave this blank - used for recursive function.
         */
        getTableOnActionModel: function(items, actionId, foundTable){
        
            for (var i = 0; i < items.size(); i++) {
                if (items[i].items) {
                    foundTable = PTC.infoPage.TabUtils.getTableOnActionModel(items[i].items, actionId, foundTable);
                    if (foundTable) {
                        break;
                    }
                }
                else {
                    //Check our passed in action against the one in the model
                    var action = items[i].actionID;
                    if (action && action === actionId) {
                        foundTable = items[i];
                        break;
                    }
                }
            }
            
            return foundTable;
        },
        
        /**
         * Used to store the timeout function.
         */
        isTabPanelRenderedTimeout: null,
        
        /**
         * Utility method to check if the tab panel has been rendered.
         * This should only be used if we do not have access to the
         * tab panel currently because it has not yet been constructed.
         *
         * @param {Function} callback The function you want executed when
         * the tab panel becomes rendered.
         */
        isTabPanelRendered: function(callback){
            if (PTC.infoPage.getTabPanel() && PTC.infoPage.getTabPanel().getActiveTab()) {
                clearTimeout(PTC.infoPage.TabUtils.isTabPanelRendered);
                if (callback) {
                    callback.defer(1000);
                }
            }
            else if (!PTC.infoPage.isTabPanelRenderedTimeout) {
                this.isTabPanelRenderedTimeout = setTimeout(function(){
                    PTC.infoPage.TabUtils.isTabPanelRendered(callback);
                }, 1000);
            }
        },
        
        /**
         * @param {PTC.infoPage.InfoModel} infoModel
         * @return {String} the key to use for saving information about this info page's tab set.
         * e.g. for part info page "infoPage"
         * for home page "home-page"
         */
        getTabSetKey: function(infoModel){
            return infoModel.tabSet.tabSetKey;
        },
        
        /**
         * @param {PTC.infoPage.InfoModel} infoModel
         * @return {String} the persistable type instance representation for an object to use for saving information about this info page's tab set.
         *  For example, part info page has objctType "wt.part.WTPart", 
         *  electrical part info page has objctType "wt.part.WTPart|12345"
         */
        getObjectType: function(infoModel){
            return infoModel.tabSet.objectType;
        }
        
    };
})();


if (typeof Ext !== 'undefined') {
// We use our new ClientStateProvider insead of the default Ext.state.CookieProvider
// because we may store many oids in this cookie for each node that is expanded,
// if all the expanded nodes in the cookies were sent to the server for every request
// it could (actually did) cause an HTTP 413 error
// This change fixes defects D-24985 and D-24726
// use local storage (instead of default session storage) so tree state persists across browser sessions
PTC.navigation.stateProvider = new PTC.jca.state.ClientStateProvider({domstorage: 'local'});

Ext.ux.TreePanelStateful = Ext.extend(Ext.tree.TreePanel, {
    //TreePanel state - simple array
    state: null,
    //stateful option set to true
    stateful: true,
    //Last selected node
    lastSelectedNode: null,

    stateEvents: [{
        click: {
            fn: function(node) {
                PTC.navigation.stateProvider.set('LastSelectedNodePath_' + this.id, node.getPath());
                PTC.navigation.stateProvider.set('LastSelectedNodeId_' + this.id, node.id);
            }
        },
        expandnode: {
            fn: function(node) {
                var currentPath = node.getPath();
                var newState = [];

                for (var i = 0; i < this.state.length; ++i)
                {
                    var path = this.state[i];

                    if (currentPath.indexOf(path) == -1) {
                        // this path does not already exist
                        newState.push(path);
                    }
                }

                // now add the new path
                newState.push(currentPath);
                this.saveState(newState);
            }
        },
        collapsenode: {
            fn: function(node) {
                if(node.id == this.root.id) {
                    return;
                }

                var closedPath = node.getPath();
                var newState = [];
                var parentNode;
                for (var i = 0; i < this.state.length; ++i)
                {
                    var path = this.state[i];
                    if (path.indexOf(closedPath) == -1) {
                        // this path is not a subpath of the closed path
                        newState.push(path);
                    }
                    else {
                        parentNode = node.parentNode;

                        if(parentNode.id != this.root.id) {
                            newState.push(parentNode.getPath());
                        }
                    }
                }

                if (newState.length === 0) {
                    parentNode = node.parentNode;
                    newState.push((!parentNode) ? this.pathSeparator : parentNode.getPath());
                }

                this.saveState(newState);
            }
        },
        load: {
            fn: function(node) {
                var lastSelectedNodePath = PTC.navigation.stateProvider.get('LastSelectedNodePath_' + this.id);
                var lastSelectedNodeId = PTC.navigation.stateProvider.get('LastSelectedNodeId_' + this.id);

                var rootNode = this.getRootNode();
                if(node.id == rootNode.id == lastSelectedNodeId) {
                    this.selectPath(lastSelectedNodePath);
                    node.fireEvent('click', node);
                    return;
                }

                if(node.id == lastSelectedNodeId) {
                    node.fireEvent('click', node);
                }
                else {
                    var childNode = node.findChild('id', lastSelectedNodeId);

                    if(childNode && childNode.isLeaf()) {
                        childNode.ensureVisible();
                        this.selectPath(lastSelectedNodePath);
                        childNode.fireEvent('click', childNode);
                    }
                    else if(childNode && !childNode.isLeaf()) {
                        this.selectPath(lastSelectedNodePath);
                        childNode.fireEvent('click', childNode);
                    }
                }
            }
        },
        textchange: {
            fn: function(node, text, oldText) {
                var lastSelectedNodePath = PTC.navigation.stateProvider.get('LastSelectedNodePath_' + this.id);
                var newSelectedNodePath = lastSelectedNodePath.replace(oldText, text);

                PTC.navigation.stateProvider.set('LastSelectedNodePath_' + this.id, newSelectedNodePath);

                this.expandPath(node.getPath());
                this.selectPath(node.getPath());
            }
        },
        remove: {
            fn: function(tree, parent, node) {
                var lastSelectedNodePath = PTC.navigation.stateProvider.get('LastSelectedNodePath_' + this.id);
                var lastSelectedNodeId = PTC.navigation.stateProvider.get('LastSelectedNodeId_' + this.id);
                if(node.id == lastSelectedNodeId) {
                    PTC.navigation.stateProvider.set('LastSelectedNodePath_' + this.id, parent.getPath());
                    PTC.navigation.stateProvider.set('LastSelectedNodeId_' + this.id, parent.id);
                }
            }
        },
        expand: {
            fn: function() {
                PTC.navigation.stateProvider.set('AccordionPanelExpanded', this.id);
            }
        },
        /**
         * The collapse is called when clicking on either a new accordion panel or the same accordion panel.
         * When you click on a accordion panel the current open panel is first collapsed and then the newly clicked
         * panel is then expanded.  So this means that in order to figure out if the same panel was clicked again we
         * need to make sure that the last expanded panel is saved before calling the collapse.
         * 
         * @param {Object} node
         */
	    collapse: {
            fn: function(node) {
                exc = function(node) {
                    var lastExpanded = PTC.navigation.stateProvider.get('AccordionPanelExpanded');
                    if(lastExpanded == this.id)
                    {
                        PTC.navigation.stateProvider.set('AccordionPanelExpanded', '');
                    }
                };
                exc.defer(1, this, [node]);
            }
        },
        resize: {
            fn: function() {
                PTC.navigation.stateProvider.set('AccordionPanelWidth', this.ownerCt.getInnerWidth());
            }
        }
    }],

    //Function which saves TreePanel state
    saveState : function(newState) {
        this.state = newState;
        PTC.navigation.stateProvider.set('TreePanelStateful_' + this.id, this.state);
    },

    //Function which restores TreePanel state
    restoreState : function(defaultPath) {
        var lastSelectedNode = PTC.navigation.stateProvider.get('LastSelectedNodeId_' + this.id);
        var stateToRestore = this.state;

        if (this.state.length === 0) {
            var newState = [defaultPath];
            this.saveState(newState);
            this.expandPath(defaultPath);
            return;
        }

        for (var i = 0; i < stateToRestore.length; ++i)
        {
            // activate all path strings from the state
            try {
                var path = stateToRestore[i];
                this.expandPath(path);
            }
            catch(e) {
                // TODO fix state at this point
            }
        }
    },

    initComponent: function() {
        Ext.ux.TreePanelStateful.superclass.initComponent.call(this);
        if(!this.stateful) {
            this.stateful = true;
        }

        if(!this.lastSelectedNode) {
            var cookieLastSelectedNode = PTC.navigation.stateProvider.get('LastSelectedNodeId_' + this.id);

            if(!cookieLastSelectedNode) {
                this.lastSelectedNode = this.root;
            }
            else {
                this.lastSelectedNode = cookieLastSelectedNode;
            }
        }

        if(!this.state) {
            var cookieState = PTC.navigation.stateProvider.get('TreePanelStateful_' + this.id);

            if(!cookieState) {
                this.state = [];
            }
            else {
                this.state = cookieState;
            }
        }
    }
});

Ext.ux.TreePanelStateful.restore = function(accordion) {
    var expandedPanel = PTC.navigation.stateProvider.get('AccordionPanelExpanded');
    if (expandedPanel) {
        var panelToRestore = accordion.getComponent(expandedPanel);
        if (panelToRestore) {
            panelToRestore.expand(false);
            panelToRestore.restoreState();
        }
    }
};
}

