function RemoveLinkConfirm(evt, table, confirm_message) {
    if (table){
        var checked = isSomethingChecked(table.id);
        if (checked === false) {
            JCAAlert("com.ptc.netmarkets.util.utilResource.NONE_CHECKED");
            Event.stop(evt);
            return false;
        }
    }
    if (!confirm_message) {
            confirm_message = "com.ptc.windchill.enterprise.traceability.traceabilityResource.CONFIRM_LINK_REMOVE";
    }
    return JCAConfirm(evt, confirm_message);
}

function ClearSuspectFlagConfirm(evt, table, confirm_message) {
    if (table){
        var checked = isSomethingChecked(table.id);
        var errorMessage;
        if (checked === false) {
            errorMessage = "com.ptc.netmarkets.util.utilResource.NONE_CHECKED";
        }
        else{
            //Validates whether the selected items are marked as suspect. 
            var selectedItems = getJCASelectedTableItems(table.id);
            var selectedItemsLength = selectedItems.length;
            for (var i = 0; i < selectedItemsLength; i++) {
                var selectedOid = selectedItems[i].value;
                var record = PTC.jca.table.Utils.getTableRowFromOid(table.id, selectedOid);
                var suspectFlag = record.get("suspectFlag");
                if(!suspectFlag || !suspectFlag.gui) {
                   errorMessage = "com.ptc.windchill.enterprise.traceability.traceabilityResource.INVALID_OBJECTS_FOR_CLEAR_SUSPECT";
                   break;
                }
            }
        }
    }

    if (errorMessage) {
        JCAAlert(errorMessage);
        Event.stop(evt);
        return false;
    }

    if (!confirm_message) {
        confirm_message = "com.ptc.windchill.enterprise.traceability.traceabilityResource.CONFIRM_CLEAR_SUSPECT_FLAG";
    }
    return JCAConfirm(evt, confirm_message);
}

