Traceability.components.renderMiniInfo = function(event, objectId) {
    var htmlText = '';
    var table = Ext.getCmp('traceable.mvc.listTraces');
    if(table) {
        var store = table.getStore();
        var rowNumber = store.findExact('oid', objectId);
        var record = store.getAt(rowNumber);
        if(record) {
            htmlText = Ext.util.Format.htmlDecode(record.get("targetDescription"));

        }
    }

    var miniInfo = Ext.getCmp('traceability.components.miniInfo');
    if(!miniInfo) {
        miniInfo = new Ext.Window({
             width:400
            ,id:'traceability.components.miniInfo'
            ,height:200
            ,layout: 'fit'
            ,draggable:false
            ,header:false
           	,border:false
            ,closable:false
            ,plain:true
            ,frame:false
            ,bodyClicked : false
            ,style: { border: 0 }
            ,mouseOverMe : false
            ,shadow: 'sides'
            ,shadowOffset: 4         
            ,listeners :  {
                afterrender : function(window) {
                    var closeTime = 3000;
                    window.body.on('mouseout', function(mouseevt){
                        window.mouseOverMe = false;
                        if(!window.bodyClicked && 
                           !mouseevt.within(window.body, true)){
                            window.close();
                        }
                    }, miniInfo);
                    
                    window.body.on('mouseover', function(mouseevt){
                        window.mouseOverMe = true;                    
                    }, miniInfo);
                    
                    window.body.on('mousedown', function(mouseevt){
                        window.bodyClicked = true;
                        closeTime = 3000;
                        setTimeout(function(){ 
                            window.bodyClicked = false; 
                        }, 3000);
                    }, miniInfo);

                    //set a timeout to close.
                    setTimeout(function(){ 
                        if(!window.bodyClicked && !window.mouseOverMe) {
                            window.close(); 
                        }
                    }, closeTime);
                }
            }
            ,items : [ {
                id:'traceability.components.miniInfo.panel'
                ,title: bundleHandler.get('com.ptc.windchill.enterprise.traceability.traceabilityResource.LABEL_PREVIEW')
                ,autoScroll:true
                ,style:'background:#ffffff'
                ,html: htmlText            
            }]
        });
        miniInfo.show();
    }

    //update the panel and set window's position.
    var panel = Ext.getCmp('traceability.components.miniInfo.panel');
    panel.update(htmlText);
    var topX = parseInt(event.clientX, 10) + 10;
    var topY = parseInt(event.clientY, 10) + 10;    
    miniInfo.setPagePosition(topX, topY);    
};


Ext.ns('PTC.ux.grid');

/**
 * @class PTC.ux.grid.WizardGrid
 * @extends Object
 * Plugin (ptype = 'wizardgrid') Plugin to support grids with rows in CREATE/EDIT mode
 * as well as potentially different types per row.
 * Grids that use this plugin must have operation/itemTypeInstanceId/editObjectRef data store only columns. 
 * TableBuilders should use MultiObjectHelper.java or CloneWizardHelper.java getTableConfig() APIs 
 * to construct a table config setup with these columns. 
 * 
 * There are many QMS wizards where there are multiple panels/tables all on the same wizard step, 
 * each creating different object types. TableBuilders for tables that allow both CREATE and EDIT in the table
 * should use MultiObjectHelper.java getTableConfig() API. 
 * In CREATE wizards all the rows are generally in CREATE mode. However, during EDIT, the initially displayed rows would 
 * be in EDIT mode, but newly added rows would be in CREATE mode. 
 * 
 * There are also various clone wizards such as Paste, Send to PDM that can have object types per row. 
 * TableBuilders for tables that allow cloning of objects should use CloneWizardHelper.java getTableConfig() API. 
 * 
 * @constructor
 * @param {Object} config Configuration options
 * @ptype wizardgrid
 */
PTC.ux.grid.WizardGrid = Ext.extend(Object, {
    constructor: function(config){
        config = config || {};
        Ext.apply(this, config);
    },    
    /**
     * @private
     */
    init: function(grid){
        grid.on('submit', this.onSubmit, grid);
        grid.getHiddenDiv = this.getHiddenDiv;
        grid.ObjHandleHiddenInputTemplate = this.ObjHandleHiddenInputTemplate;
    },
    /**
     * Default submit event handler for tables to add extra data to the form before submitting. 
     * The extra data is only needed when isRowBasedObjectHandle=true. 
     * 
     * isRowBasedObjectHandle flag true means each table row will be a separate ObjectBean for form processing.
     * This extra row data is needed so default form processing logic can properly separate and handle row data.
     * @param {Array} rows is the array of Ext.data.Records for this table
     */
    onSubmit : function() {
        var table = this;
        var store = table.getStore();
        var html = [];
                
        var ITIID = PTC.wizard.ITIID; 
        var hiddenInputTemplate = table.ObjHandleHiddenInputTemplate;
        store.each(function(row) {
            //adding tiid/operation/editObjectRef with object handle for each row will allow default form processor logic to know which type to create for the row
            //this helps support use cases where there are multiple panels/tables all on the same wizard step, each creating different object types
            //also, should help support use case where there is a type picker in the row 
            var objectHandle = row.get('objectHandle');
            var config = {
                objectHandle: objectHandle
            };
            var tiid = row.get(ITIID);
            if (tiid) {
                config.name = ITIID;
                config.value = tiid;
                html[html.length] = hiddenInputTemplate.apply(config);
            } 
            var editObjectRef = row.get('editObjectRef');
            if(editObjectRef){
                config.name = 'editObjectRef';
                config.value = editObjectRef;
                html[html.length] = hiddenInputTemplate.apply(config);
            }
            var operation = row.get('operation');
            if(operation) {
                config.name = 'operation';
                config.value = operation;
                html[html.length] = hiddenInputTemplate.apply(config);                
            }
        });
        var id = table.id + '_FormDataFromOnSubmitListener';        
        var div = table.getHiddenDiv(id);
        div.innerHTML = html.join('');        
    }, 
    getHiddenDiv : function(id) {
        var form = getMainForm();
        var div = $(id);
        if (!div) {
            div = form.ownerDocument.createElement('div');
            div.style.display = 'none';
            div.id = id;
            form.appendChild(div);
        }
        return div;  
    },
    ObjHandleHiddenInputTemplate : new Ext.Template('<input type="hidden" name="{objectHandle}{name}" value="{value}"/>', {
        compiled: true,
        disableFormats: true
    })
});

Ext.preg('wizardgrid', PTC.ux.grid.WizardGrid);


