/**
 * Hides and shows the Action Group component content using the toggle control
 * in the upper left corner. The toggle control graphic is switch based on the
 * state of the component.
 * 
 * @param {Ext.Panel}
 *            panel The panel to be expanded or collapsed
 * @param {Ext.Button}
 *            button The button the controls the expand/collapse behavior of the
 *            panel
 */
PTC.actionGroup.actionGroupToggle = function(panel, button) {
    if (panel.jcaCollapsed) {
        // expand
        panel.body.dom.style.display = "block";
        button.setIconClass('expandCollapse_collapsed');
        button.setTooltip(bundleHandler.get('com.ptc.netmarkets.util.utilResource.COLLAPSE'));
        panel.jcaCollapsed = false;
    } else {
        // collapse
        panel.body.dom.style.display = "none";
        button.setIconClass('expandCollapse_expanded');
        button.setTooltip(bundleHandler.get('com.ptc.netmarkets.util.utilResource.EXPAND'));
        panel.jcaCollapsed = true;
    }
};

/**
 * Create the action group combo box control for selecting the action group.
 * 
 * The combo box is rendered with the default value selected. Each time the user
 * changes the selection is saved as the default selection to a server side
 * preference so the users current selection is used the next time the component
 * is rendered.
 * 
 * @param {Object}
 *            config The configuration object for the Action Group component
 */
PTC.actionGroup.createActionGroupCombo = function(config) {
    var actionGroupComboStore = new Ext.data.ArrayStore({
        fields : [ 'actionGroupSelector', 'actionGroupName' ],
        idIndex : 0,
        data : config.actionGroups,
        autoDestroy : true,
        sortInfo : {
            field : 'actionGroupName',
            direction : 'ASC'
        }
    });

    // Set the selection to the default value or the first item
    var value = null;
    if (actionGroupComboStore.data && actionGroupComboStore.getAt(0)) {
        value = actionGroupComboStore.getAt(0).data.actionGroupSelector;
        if (config.defaultActionGroup && actionGroupComboStore.getById(config.defaultActionGroup)) {
            value = config.defaultActionGroup;
        }
    }

    var actionGroupCombo = new Ext.form.ComboBox({
        id : 'actionGroup.contextSelect',
        store : actionGroupComboStore,
        displayField : 'actionGroupName',
        valueField : 'actionGroupSelector',
        typeAhead : true,
        mode : 'local',
        triggerAction : 'all',
        selectOnFocus : true,
        resizable : true,
        forceSelection : true,
        lazyInit : false,
        title : bundleHandler.get('com.ptc.core.ui.actionGroupRB.PICK_AN_ACTION_GROUP'),
        value : value,
        style : 'height: 16px',
        width : 350
    });

    actionGroupCombo.on('select', function(index, b, c) {
        PTC.actionGroup.updateSubjectCombo(this.value);
        PTC.actionGroup.updateActionGroupPanel(this.value);
    });

    actionGroupCombo.on('select', function(index, b, c) {
        PTC.actionGroup.actionGroupSaveSelection(this.value);
    });

    actionGroupCombo.on('blur', function() {
        PTC.actionGroup.actionGroupSaveSelection(this.value);
    });

    return actionGroupCombo;
};

/**
 * Return the display value with the first text matching the search term
 * enclosed in a span tag.
 * 
 * @param displayValue
 *            {String} The value containing the search term
 * @param searchTerm
 *            {String} The search term which may include '*' wild cards.
 */
PTC.actionGroup.highlightSearchTerm = function(displayValue, searchTerm) {
    if (displayValue && searchTerm) {
        // remove trailing and leading wildcards
        searchTerm = searchTerm.replace(/^\**/, '');
        searchTerm = searchTerm.replace(/\**$/, '');

        // escape regular expression symbols
        searchTerm = searchTerm.replace(/[\-\[\]\/\{\}\(\)\+\?\.\\\^\$\|]/g, "\\$&");

        // convert '*' to regular expression wild card '.*?'
        searchTerm = searchTerm.replace(/\*/, '.*?');

        return displayValue.replace(new RegExp('(' + searchTerm + ')', 'i'),
                '<span class="action-group-highlight-search-results">$1</span>');
    } else {
        return displayValue;
    }
};

/**
 * Create the subject combo box.
 * 
 * The first value in the list is used as the default value.
 * 
 * @param {Object}
 *            config The configuration object for the Action Group component
 */
PTC.actionGroup.createSubjectCombo = function(config) {
    var subjectComboStore = new Ext.data.Store({
        proxy : new Ext.data.HttpProxy({
            url : 'ptc1/actionGroupController/subjectsForActionGroup'
        }),
        reader : new Ext.data.ArrayReader({
            fields : [ 'subjectOID', 'subjectName' ],
            idIndex : 0,
            root : 'subjects'
        }),
        baseParams : {
            actionGroupSelector : config.defaultActionGroup
        },
        autoLoad : false
    });

    resultTpl = new Ext.XTemplate(
            '<tpl for="."><div class="x-combo-list-item">{[this.processSearchTerm(values.subjectOID, values.subjectName)]}</div></tpl>', {
                compiled : true,
                disableFormats : false,
                processSearchTerm : function(value, displayValue) {
                    var result;
                    var encodedDisplayValue = PTC.util.HTMLEncoder.encodeForHTMLContent(displayValue);
                    if (value === '') {
                        // group heading
                        result = '<span class="action-group-highlight-search-group">' + encodedDisplayValue + '</span>';
                    } else if (value === '-->') {
                        // too many results
                        result = '<span class="action-group-subject">' + encodedDisplayValue + '</span>';
                    } else {
                        // suggest result
                        var encodedQuery = PTC.util.HTMLEncoder.encodeForHTMLContent(subjectCombo.lastQuery);
                        result = '<span class="action-group-subject">' + 
                                PTC.actionGroup.highlightSearchTerm(encodedDisplayValue, encodedQuery) +
                                '</span>';
                    }

                    return result;
                }
            });

    var subjectCombo = new Ext.form.ComboBox({
        id : 'actionGroup.subjectSelect',
        store : subjectComboStore,
        displayField : 'subjectName',
        valueField : 'subjectOID',
        typeAhead : false,
        mode : 'remote',
        triggerAction : 'all',
        selectOnFocus : true,
        resizable : true,
        forceSelection : true,
        lazyInit : false,
        title : bundleHandler.get('com.ptc.core.ui.actionGroupRB.PICK_A_SUBJECT'),
        style : 'height: 16px',
        value : config.defaultSubject.subjectOID,
        valueNotFoundText : config.defaultSubject.subjectName,
        emptyClass : '',
        listEmptyText : bundleHandler.get('com.ptc.core.ui.actionGroupRB.NO_APPLICABLE_SUBJECTS'),
        minChars : 1,
        width : 200,
        listWidth : 500,
        tpl : resultTpl
    });

    /**
     * Replace the contents of the subject combo box with new values.
     * 
     * @param config
     *            Configuration containing the new subject combo box values.
     */
    subjectCombo.refresh = function(config) {
        var defaultSubject = config.defaultSubject;
        subjectCombo.enable();

        // clear old values from combo box including the last query so fresh
        // results are retrieved based on the new actionGroupSelect
        subjectCombo.valueNotFoundText = defaultSubject.subjectName;
        subjectCombo.setValue(defaultSubject.subjectOID);
        subjectCombo.getStore().setBaseParam('actionGroupSelector', config.actionGroupSelector);
        delete subjectCombo.lastQuery;

        PTC.actionGroup.updateActionLinks(defaultSubject.subjectOID);

    };

    subjectCombo.on('beforeselect', function (component, record) {
        // labels can not be selected.
        return Ext.isDefined(record.data.subjectOID) && 
                !(record.data.subjectOID === '' || record.data.subjectOID === '-->');
    });

    subjectCombo.on('select', function(index, b, c) {
        delete subjectCombo.lastQuery;
        PTC.actionGroup.updateActionLinks(this.value);
        PTC.actionGroup.subjectSaveSelection(this.value);
    });

    subjectCombo.on('blur', function() {
        PTC.actionGroup.subjectSaveSelection(this.value);
    });


    return subjectCombo;
};

/**
 * Create the title bar and expand/collapse button for the Action Group
 * component. The Action Group component is rendered in the expanded state when
 * it is initially rendered.
 */
PTC.actionGroup.createTitleBar = function() {
    var actionGroupExpandButton = new Ext.Button({
        cls : 'tableToggle',
        iconCls : 'expandCollapse_collapsed',
        tooltip : bundleHandler.get('com.ptc.netmarkets.util.utilResource.COLLAPSE'),
        style : 'padding-left: 2px;'
    });

    actionGroupExpandButton.actionGroupToggle = function() {
        PTC.actionGroup.actionGroupToggle(this.actionGroupPanel, this);
    };
    actionGroupExpandButton.handler = actionGroupExpandButton.actionGroupToggle;

    var title = bundleHandler.get('com.ptc.core.ui.actionGroupRB.ACTIONS_SECTION_TILE');
    var titleBarItems = [ actionGroupExpandButton, {
        xtype : 'tbspacer'
    }, {
        xtype : 'tbtext',
        text : title
    } ];

    var titleBar = new Ext.Toolbar({
        id : 'actionGroup.titleBar',
        items : titleBarItems,
        style : 'background: white; border: none;'
    });

    titleBar.expandButton = actionGroupExpandButton;

    return titleBar;
};

/**
 * Renders the actions based upon the configuration. If no actions are provided
 * a message is displayed.
 * 
 * @param {Object}
 *            config Configuration containing the actions.
 */
PTC.actionGroup.createActionLinks = function(config) {
    PTC.actionGroup.displayNoActionsMessage(config);
    var toolBar = new Ext.Toolbar({
        id : 'actionGroup.toolBar',
        cls : 'action-group-toolbar',
        items : config.actionModel.items,
        enableOverflow : true,
        subjectOID : config.actionModel.subjectOID
    });

    toolBar.mon(PTC.action, 'objectsaffected', PTC.actionGroup.refreshActionsForObjectsAffected, toolBar);

    toolBar.refresh = function(config) {
        PTC.actionGroup.displayNoActionsMessage(config);
        toolBar.removeAll();
        toolBar.add(config.actionModel.items);
        toolBar.doLayout();
    };
    return toolBar;
};

/**
 * Renders the More Menu based on the total width of the items of the toolbar
 * 
 * @param {Ext.Component}
 *          toolbar Toolbar component
*/
PTC.actionGroup.displayMoreMenu = function(toolBar) {
    var toolbarLayout = toolBar.layout;
    var itemssize = 0;
    var items = toolBar.items;
    for (i=0; i<items.getCount(); ++i) {
        var comp = items.get(i);
        //Get the offsetWidth of the parent cell holding the buttons, if the buttons overflow from the toolbar get the xtbWidth 
        var prefixParent = Ext.fly(comp.el.dom.parentNode);
        if(prefixParent.dom.offsetWidth){
            itemssize += prefixParent.dom.offsetWidth;
        } else if(comp.xtbWidth){
            itemssize += comp.xtbWidth; 
        }
    }
    if(toolbarLayout.more){
        itemssize += toolbarLayout.more.getEl().dom.offsetWidth;
     }
    var t = toolBar.getWidth();
    //Display the more menu icon, by comparing the size of the items in the toolbar with the toolbar width.
    if(itemssize  >= toolBar.getWidth()){
        if(toolbarLayout.more){
            toolbarLayout.more.getEl().dom.hidden = false;
         }
    } else {
        if(toolbarLayout.more){
            toolbarLayout.more.getEl().dom.hidden = true;
         }
    }

  //  toolBar.doLayout();
};

/**
 * Adds No Actions to Display message to toolBar items if there are no actions
 * to display
 * 
 * @param {Object}
 *            config Configuration containing the actions.
 */
PTC.actionGroup.displayNoActionsMessage = function(config) {
    if (!config.actionModel.items || config.actionModel.items.length === 0) {
        config.actionModel.items = [ bundleHandler.get('com.ptc.core.ui.navigationRB.NO_ACTIONS_TO_DISPLAY') ];
    }
};

/**
 * Refresh the actions when a formResult contains the Oid of the subject
 * 
 * @param {PTC.action.FormResult}
 *            formResult the result of an invoked action.
 */
PTC.actionGroup.refreshActionsForObjectsAffected = function(formResult) {
    // get the updated OID in case it changed due to checkout/checkin process
    var updatedOID = formResult.getUpdatedOid(this.initialConfig.subjectOID);

    // The Oids that were returned by the form result as changed
    var oidsChangedByAction = formResult.getUpdatedOids();

    if (oidsChangedByAction.indexOf(updatedOID) >= 0) {
        PTC.actionGroup.updateActionLinks(updatedOID);
    }
};

/**
 * Combines the individual elements into the Action Group Component.
 * 
 * @param {String}
 *            renderLocation the id of the html element where the Action Group
 *            component is rendered
 * @param {Object}
 *            config Action Group configuration
 * @param {Ext.Component}
 *            titleBar Action Group component title bar
 * @param {Ext.Component}
 *            actionGroupCombo Action Group selection component
 * @param {Ext.Component}
 *            subjetCombo Action Group subject selection component
 * @param {Ext.Component}
 *            actionLink Action Group links component
 */
PTC.actionGroup.createActionGroupPanel = function(renderLocation, config, titleBar, actionGroupCombo, subjectCombo,
        actionLinks) {

    var componentCount = 4;

    var items = [];
    // The first row is the Action Group combo box thus it spans all collumns.
    items.push(Ext.apply(actionGroupCombo, {
        colspan : componentCount
    }));

    var prefixLabel = new Ext.form.Label({
        id : 'actionGroup.prefixLabel',
        cls : 'action-group-label'
    });
    items.push(prefixLabel);

    items.push(subjectCombo);

    var postfixLabel = new Ext.form.Label({
        id : 'actionGroup.postfixLabel',
        cls : 'action-group-label'
    });
    items.push(postfixLabel);

    items.push(actionLinks);

    var actionGroupPanel = new Ext.Panel({
        id : 'actionGroup.actiionGroupPanel',
        tbar : titleBar,
        renderTo : renderLocation,
        bodyStyle : 'border: 1px solid #D0D0D0',
        items : items,
        layout : 'table',
        style : {'margin-right' : '8px'},
        layoutConfig : {
            tableAttrs : {
                style : {
                    'padding-top' : '5px',
                    'padding-bottom' : '10px'
                }
            },
            columns : componentCount
        },
        defaults : {
            cellCls : 'action-group-cell'
        }
    });
    PTC.actionGroup.setPrefixProperties(config, prefixLabel);
    PTC.actionGroup.setPostfixProperties(config, postfixLabel);

    // Refresh the prefix and postfix labels of the actionGroupPanel based on
    // the Action Group selected
    actionGroupPanel.refresh = function(config) {
        var preLabel = Ext.getCmp('actionGroup.prefixLabel');
        var postLabel = Ext.getCmp('actionGroup.postfixLabel');

        PTC.actionGroup.setPrefixProperties(config, preLabel);
        items.push(preLabel);

        PTC.actionGroup.setPostfixProperties(config, postLabel);
        items.push(postLabel);

        actionGroupPanel.add(items);
        actionGroupPanel.doLayout();
    };

    // Set the panel into the title bar so it will be expanded and collapsed.
    titleBar.expandButton.actionGroupPanel = actionGroupPanel;

    return actionGroupPanel;
};

/**
 * Sets the prefix label with the value and the appropriate style class.
 * 
 * @param {Object}
 *            config The configuration for the Action Group component
 * @param {Ext.Component}
 *            prefixLabel Prefix label component
 */
PTC.actionGroup.setPrefixProperties = function(config, prefixLabel) {
    var prefixParent = Ext.fly(prefixLabel.el.dom.parentNode);
    if (config.prefixLabel && config.prefixLabel.length > 0) {
        prefixLabel.setText(config.prefixLabel);
        if (prefixParent) {
            prefixParent.replaceClass('action-group-cell-for-no-action', 'action-group-cell');
        }
    } else {
        prefixLabel.setText('');
        if (prefixParent) {
            prefixParent.replaceClass('action-group-cell', 'action-group-cell-for-no-action');
        }
    }
};

/**
 * Sets the postfix label with the value and the appropriate style class.
 * 
 * @param {Object}
 *            config The configuration for the Action Group component
 * @param {Ext.Component}
 *            postfixLabel Postfix label component
 */
PTC.actionGroup.setPostfixProperties = function(config, postfixLabel) {
    var postfixParent = Ext.fly(postfixLabel.el.dom.parentNode);
    if (config.postfixLabel && config.postfixLabel.length > 0) {
        postfixLabel.setText(config.postfixLabel);
        if (postfixParent) {
            postfixParent.replaceClass('action-group-cell-for-no-action', 'action-group-cell');
        }
    } else {
        postfixLabel.setText('');
        if (postfixParent) {
            postfixParent.replaceClass('action-group-cell', 'action-group-cell-for-no-action');
        }
    }
};

/**
 * Render the toolbar component to the width of the actionGroupPanel.
 * 
 * @param {Ext.Component}
 *          toobar ToolBar component
 */
PTC.actionGroup.scaleToolbarToHomePage = function(toolbar) {
    var homePagePanel = Ext.getCmp("homePageTableContainermainInfoPagePanel");
    var subjectCombo = Ext.getCmp("actionGroup.subjectSelect");
    var prefixLabel = Ext.getCmp("actionGroup.prefixLabel");
    var postfixLabel = Ext.getCmp("actionGroup.postfixLabel");
    var actionGroupPanel = Ext.getCmp("actionGroup.actiionGroupPanel");
  
    if (homePagePanel) {
        var w = homePagePanel.getWidth();
        var subjectComboWidth = subjectCombo.initialConfig.width;
        var prefixWidth = prefixLabel.el.getComputedWidth();
        var postfixWidth = postfixLabel.el.getComputedWidth();
        var actionGroupPanelWidth = actionGroupPanel.el.getComputedWidth();
        var scrollbarWidth = PTC.jca.table.scroll.getWindowScrollbarWidth() + 20;

        var t1 = w - actionGroupPanelWidth;
        var t = actionGroupPanelWidth - subjectComboWidth - prefixWidth - postfixWidth - t1 - scrollbarWidth;
        toolbar.setWidth(t);
        PTC.actionGroup.displayMoreMenu(toolbar);


        homePagePanel.addListener("bodyresize", function(panel, w, h) {
            var panelWidth = homePagePanel.getWidth();
            var subjectComboWidth = subjectCombo.initialConfig.width;
            var prefixWidth = prefixLabel.el.getComputedWidth();
            var postfixWidth = postfixLabel.el.getComputedWidth();
            var actionGroupPanelWidth = actionGroupPanel.el.getComputedWidth();

            var t1 = panelWidth - actionGroupPanelWidth;
            var t = actionGroupPanelWidth - subjectComboWidth - prefixWidth - postfixWidth - t1;
            toolbar.setWidth(t);
            PTC.actionGroup.displayMoreMenu(toolbar);
        });
    }
};

/**
 * Replace the contents of the Subject combo box with the results returned by
 * the Action Group controller for the selected Action Group.
 * 
 * @param {String}
 *            actionGroupSelector the Action Group values
 */
PTC.actionGroup.updateSubjectCombo = function(actionGroupSelector) {
    var subject_combo_url = 'ptc1/actionGroupController/defaultSubjectForActionGroup';
    var options = {
        asynchronous : true,
        parameters : {
            actionGroupSelector : actionGroupSelector
        },
        onSuccess : function(response) {
            var data = response.responseText;
            var config = Ext.util.JSON.decode(data);
            config.actionGroupSelector = actionGroupSelector;
            var subjectCombo = Ext.getCmp('actionGroup.subjectSelect');
            subjectCombo.refresh(config);
        }
    };
    requestHandler.doRequest(subject_combo_url, options);
};

/**
 * Replace the contents of the action links with the results returned by the
 * action group controller for the selected Action Group
 * 
 * @param {String}
 *            subjectSelector the selected Subject
 */
PTC.actionGroup.updateActionLinks = function(subjectSelector) {
    var action_links_url = 'ptc1/actionGroupController/actionsForSelectedActionGroup';
    var actionGroupCombo = Ext.getCmp('actionGroup.contextSelect');
    var actionGroupSelector = actionGroupCombo.getValue();
    var options = {
        asynchronous : true,
        parameters : {
            subjectSelector : subjectSelector,
            actionGroupSelector : actionGroupSelector
        },
        onSuccess : function(response) {
            var data = response.responseText;
            var config = Ext.util.JSON.decode(data);
            var actionLinks = Ext.getCmp('actionGroup.toolBar');
            actionLinks.refresh(config);
            PTC.actionGroup.displayMoreMenu(actionLinks);
            actionLinks.initialConfig.subjectOID = config.actionModel.subjectOID;
        },
        onFailure : function(response) {
            // Set to empty action model on failure
            var actionLinks = Ext.getCmp('actionGroup.toolBar');
            actionLinks.refresh({actionModel:{}});
            PTC.actionGroup.displayMoreMenu(actionLinks);
            actionLinks.initialConfig.subjectOID = null;
        }
    };
    requestHandler.doRequest(action_links_url, options);
};

/**
 * Replace the contents of the prefix and postifx for the selected Action Group.
 * 
 * @param {String}
 *            actionGroupSelector the Action Group values
 */
PTC.actionGroup.updateActionGroupPanel = function(actionGroupSelector) {
    var action_links_url = 'ptc1/actionGroupController/labelsForSelectedActionGroup';
    var options = {
        asynchronous : true,
        parameters : {
            actionGroupSelector : actionGroupSelector
        },
        onSuccess : function(response) {
            var data = response.responseText;
            var config = Ext.util.JSON.decode(data);
            var actionGroupPanel = Ext.getCmp('actionGroup.actiionGroupPanel');
            actionGroupPanel.refresh(config);
        }
    };
    requestHandler.doRequest(action_links_url, options);
};

/**
 * Initialize the Action Group component based on the configuration.
 * 
 * @param {String}
 *            renderLocation The ID of the html element where the Action Group
 *            component will be rendered
 * @param {Object}
 *            config The configuration for the Action Group component
 */
PTC.actionGroup.createUI = function(renderLocation, config) {
    Ext.onReady(function() {
        var titleBar = PTC.actionGroup.createTitleBar();
        var actionGroupCombo = PTC.actionGroup.createActionGroupCombo(config);
        var subjectCombo = PTC.actionGroup.createSubjectCombo(config);
        var actionLinks = PTC.actionGroup.createActionLinks(config);

        var actionGroupPanel = PTC.actionGroup.createActionGroupPanel(renderLocation, config, titleBar,
                actionGroupCombo, subjectCombo, actionLinks);
        PTC.actionGroup.scaleToolbarToHomePage(actionLinks);
    });
};

