Ext.apply(PTC.action, new Ext.util.Observable());
PTC.action.addEvents ("objectsaffected");
/**
 * Event is dispatched after the afteraction event takes care of any refresh needed
 * for the component the action was launched from.
 * The purpose of objectsaffected event is to allow any random set of components on the page to update their data stores
 * if any object contained in the store was affected by the action.
 *
 * For example, when you checkout a part from the mini info navigator on the folders table,
 * the afteraction listener of the mini info component takes care of refreshing the mini info.
 * The objectsaffected listener of search and folders tables takes care of row refresh in those tables if they contain the oid of the affected part.
 *
 * This event handler will not necessarily be invoked for generic refresh responses if no objects are specified or if the there was an error returned.
 * Also, this event handler
 *
 * @name PTC.action#objectsaffected
 * @event
 * @param {PTC.action.FormResult} formResult - FormResult object that contains the oids affected by the action that was just executed
 */
/**
 * Storage for the open windows (typically wizard windows)
 */
PTC.action.actionWindows = [];
/**
 * Adds a window to the storage
 */
PTC.action.addActionWindow = function (window) {
    if(window) {
    PTC.action.actionWindows.push(window);
    }
};
/**
 * Removes a window from the storage of open windows
 * @param {Mixed} window or windowname of the window being removed.
 */
PTC.action.removeActionWindow = function (window) {
    var i, name;
    if (Ext.isString(window)) {
        name = window;
    }
    else {
        name = window.name;
    }

    i = PTC.action.actionWindows.length;
    while (i--) {
        try {
            if(name === PTC.action.actionWindows[i].name || PTC.action.actionWindows[i].closed) {
                PTC.action.actionWindows.splice(i, 1);
            }
        } catch (e) {
            PTC.action.log.warn('could not access a property on a cached window reference in PTC.action.actionWindows');
        }
    }
};

/**
 * window unload listener to keep the actionWindows up to date.
 */
PTC.action.removeWindowOnUnloadListener = function () {
    if (opener && opener.PTC) {
        opener.PTC.action.removeActionWindow(window.name);
    }
};

Ext.EventManager.on(window, 'unload', PTC.action.removeWindowOnUnloadListener);

