/**
 * This handles some legacy setup, but it would be good to remove
 */
function initPopupForm(){
    try {
        if(isWizardWindow()) {
          PTC.wizard.on('wizardLoadComplete', function(){
             //In IE, the window.resize event is fired when any element on the page is resized.
             //It does not matter whether the page element is resized, assigning/changing its height or style attribute,
             //by simply adding a child element to it, or whatever -- even though the element resizing does not affect the dimensions of the viewport itself.
             //This works fine with all the other browser so NOT adding it as special case for IE
             window.onresize = onResizeWindow;
          });
        } else {
          window.onresize = onResizeWindow;
        }
        var mform = getMainForm();

        if (getPopupOpenerWindow() && !getPopupOpenerWindow().closed) {
            if (getPopupOpenerWindow().document && getPopupOpenerWindow().getMainForm) {
                var opform = getPopupOpenerWindow().getMainForm();
                var windowNameForCookie = opform.windowNameForCookie;
                if (windowNameForCookie) {
                    JCAappendFormHiddenInput(mform, "windowNameForCookie", windowNameForCookie.value);
                }

                var skipInit = extractParamValue(window.location.href, "skipInit");
                //This block needs to be ripped out,  The skipInit flag is passed in when the opener
                //window is not valid to use to find relevant action information such as launching into
                //a new action from an existing wizard.
                if (mform.openerCompContext.value === "none" && skipInit !== 'true') {
                    mform.nmwindowname.value = window.name;

                    if (opform && opform.popupCompContext) {
                        mform.openerCompContext.value = opform.popupCompContext.value;
                        mform.openerElemAddress.value = opform.popupElemAddress.value;
                        mform.openerActionClass.value = opform.popupActionClass.value;
                        mform.openerActionMethod.value = opform.popupActionMethod.value;
                        mform.openerExecuteLocation.value = opform.popupExecuteLocation.value;

                        //set value of selectedInOpener
                        var selectedFromWizardTag = mform.selectedInOpener_FromWizardTag;
                        if (selectedFromWizardTag) {
                            //for jca wizards use value that WizardTag would have output
                            mform.selectedInOpener.value = selectedFromWizardTag.value;
                            //set input value to empty string so its not serialized when the form is posted
                            mform.selectedInOpener_FromWizardTag.value = "";
                        }
                        else {
                            // else calculate value by determining what's selected in the opener window
                            var sset = false;
                            var opformsels = getPopupOpenerWindow().document.getElementsByTagName('input');
                            if (opformsels) {
                                if (opformsels.length > 0) {
                                    var count = 0;
                                    var alength = opformsels.length;
                                    for (var i = 0; i < alength; i++) {
                                        if (opformsels[i].type === "checkbox" && opformsels[i].checked) {
                                            count++;
                                        }
                                    }

                                    if (count > 0) {
                                        var sarr = [];
                                        var ind = 0;
                                        for (var m = 0; m < alength; m++) {
                                            if (opformsels[m].type === "checkbox" && opformsels[m].checked) {
                                                sarr[ind++] = opformsels[m].value;
                                            }
                                        }

                                        mform.selectedInOpener.value = sarr.join("-");
                                        sset = true;
                                    }
                                }
                                else {
                                    try {
                                        if (opformsels && opformsels.type === "checkbox" && opformsels.checked) {
                                            mform.selectedInOpener.value = opformsels.value;
                                            sset = true;
                                        }
                                    }
                                    catch (e) {
                                        PTC.action.log.debug("Exception caught and ignored in initPopupForm()", e);
                                    }
                                }
                            }
                            if (!sset) {
                                mform.selectedInOpener.value = "none";
                            }
                        }
                    }
                }
            }
        }
    //ensure this initialization is not done twice
    }
    catch (ex) {
    }
    finally {
        initPopupForm = TRUE_FUNC;
    }

}

