/**
 * Refreshes the parent window.
 */
refreshOpenerOnly = function(){
    if (getPopupOpenerWindow()) {
        var _opener = getPopupOpenerWindow();
        var extraFormElems;
        var refreshByAction = null;
        var openerDocument;
        try {
            try {
                //just incase there are non-jca pages being refreshed through this method, don't fail on this.   If it fails here, its not the search page anyway.
                refreshByAction = _opener.JCAappendFormHiddenInput(_opener.getMainForm(), "refreshByAction", "true");

                if (getWindow().location.href.indexOf("fireSearchOnActionRefresh") > 0) {
                    extraFormElems = _opener.JCAappendFormHiddenInput(_opener.getMainForm(), "fireSearchOnActionRefresh", extractParamValue(getWindow().location.href, "fireSearchOnActionRefresh"));
                }
                else {
                    extraFormElems = [];
                }
                extraFormElems.push(refreshByAction);
                //IE always has opener object even though there is no opener BUT it throws exception if any properties is accessed of opener.
                openerDocument = _opener.document;
            }
            catch (e) {
                PTC.action.log.debug("Exception caught and ignored in refreshOpenerOnly()",e);
            }
            //if there is no opener, no need to do any of the below code.
            if (!openerDocument){
               return;
            }
            if (_opener && _opener.document && _opener.getMainForm()) {
                var mainform = _opener.getMainForm();
                var urlstr = window.location.href;
                urlstr = urlstr.substring(urlstr.indexOf("?") + 1);
                var params = urlstr.parseQuery();
                if (params.tableID && isArray(params.tableID)) {
                    params.tableID = params.tableID[0];
                }

                if (!_opener.handleDynamicAction(mainform, "", "", "", "", "", "dynamicUpdate", "true", "", "", "", "", "", "", "", "", "", "", "", "", "", "", "", "", true, window.location.href, "", null, params.tableID, true, true, true)) {
                    // SPR 1150038
                    var refreshSearchTable = _opener.document.createElement("INPUT");
                    refreshSearchTable.type = 'hidden';
                    refreshSearchTable.name = 'refreshSearchTable';
                    refreshSearchTable.value = 'Yes';

                    mainform.appendChild(refreshSearchTable);
                    if (_opener.currentStepStrName) {
                        _opener.refreshCurrentStep();
                        _opener.clearActionFormData();
                    }
                    else if (params.AjaxEnabled && (params.AjaxEnabled !== 'null') &&
                    ((params.AjaxEnabled === "row") || (params.AjaxEnabled === "component")) &&
                    params.tableID &&
                    (params.tableID !== 'null')) {

                        _opener.refreshCurrentElement(params.tableID, !PTC.isOldGecko(), false);
                        try {
                            _opener.clearActionFormData();
                        }
                        catch (ex) {
                            PTC.action.log.debug("opener may not exist anymore, may be closing...",ex);
                        }
                    }
                    else {
                        try {
                            _opener.PTC.navigation.submitForm();
                        }
                        catch (exe) {
                            PTC.action.log.debug("opener may not exist anymore, may be closing...",exe);
                        }
                    }
                }
                else {
                    clearActionFormData();
                }

            }
            else {
                if (window.opener.deleteChangeObject) {
                    // the change management details pages require special refresh handling
                    // the CM details page is identified by the presence of the deleteChangeObject() Javascript function,
                    // since other pages also have refreshForAssociation()
                    window.opener.refreshForAssociation();
                }
                else {
                    PTC.navigation.reload();
                }
            }
        }
        finally {
            if (openerDocument) {
                try {
                    _opener.removeFormElements(extraFormElems);
                    _opener.removeFormElements(refreshByAction);
                } catch(e_removeForm) {
                    PTC.action.log.debug("Could not remove form elements from opener. Opener may be refreshing form.", e_removeForm);
                }
            }
        }
    }
    else {
        if (getPopupOpenerWindow()) {
            var mainPageHref = window.opener.location.href;
            window.opener.location.href = mainPageHref;
        }
        else {
            // could be a window opened by applet, just close those when the action is done.
            wfWindowClose1();
        }
    }
};

closePopupAndRefreshOpener = function(){
    prepareToRefreshOpener();
    //callUserSubmitFunction();
    refreshOpenerOnly();
    wfWindowClose1();
};

