function setWindowLocation(aUrl){
    // Fix IE specific problem where relative urls in javascript don't work like relateive urls in anchor tags
    if (aUrl && aUrl.indexOf('http') < 0 && !PTC.util.isJSUrl(aUrl)) {
        // might need to worry about ending and trailing slashes?
        aUrl = getBaseHref() + aUrl;
    }
    // See if action in this URL should be rendered as lightbox
    if (!PTC.util.isJSUrl(aUrl) && PTC.lightbox.isActionRenderedAsLightbox({
        actionURL: aUrl
    })) {
        PTC.lightbox.activate({
            contentHref: aUrl
        });
    }
    else {
        if (PTC.navigator && PTC.navigator.isExpanded()) { // On any URL load in content area from Navigator, it should get collapsed.
            PTC.navigator.collapseNavigator();
        }
        // SPR 2147779 - IE 8 mode throws 'can't execute code from a freed script an error' when closing the 'gridRowContextMenu' in the case where
        // the context from which the menu was launched destroyed. Manually, close the context menu before loading new url
        Ext.menu.MenuMgr.hideAll();

        //When called from Iframe window to replace content area, getWindow() needs to be used here
        getWindow().PTC.navigation.loadContent(aUrl);
    }
    return false;
}

