/**
 * Executes the closure on each item in an action model
 * THIS FUNCTION HAS SIDE EFFECTS it will change the passed in model
 *
 * This method applies the function only to the actions you can also apply the function to the
 * sub models or to both actions and sub models.
 *
 * @see walkActionModelAndApplyToChildModels, walkActionModelAndApplyToAll
 * @param {Object} model The action model to walk
 * @param {Object} method A closer to be applied to all items
 */
PTC.actionModel.walkActionModelAndApply = function(model, method){
    if (model && model.items) {
        PTC.actionModel.applyFunctionToItems(model.items, method, true, false);
    }
};

/**
 * Executes the closure on each item in an action model
 * THIS FUNCTION HAS SIDE EFFECTS it will change the passed in model
 *
 * This method applies the function only to the sub models you can also apply the function to the
 * actions or to both actions and sub models.
 *
 * @see walkActionModelAndApply, walkActionModelAndApplyToAll
 * @param {Object} model The action model to walk
 * @param {Object} method A closer to be applied to all items
 */
PTC.actionModel.walkActionModelAndApplyToChildModels = function(model, method){
    if (model && model.items) {
        PTC.actionModel.applyFunctionToItems(model.items, method, false, true);
    }
};

/**
 * Executes the closure on each item in an action model
 * THIS FUNCTION HAS SIDE EFFECTS it will change the passed in model
 *
 * This method applies the function to both actions and sub models you can also apply the function to just the actions
 * opr just the sub models.
 *
 * @see walkActionModelAndApply, walkActionModelAndApplyToChildModels
 * @param {Object} model The action model to walk
 * @param {Object} method A closer to be applied to all items
 */
PTC.actionModel.walkActionModelAndApplyToAll = function(model, method){
    if (model && model.items) {
        PTC.actionModel.applyFunctionToItems(model.items, method, true, true);
    }
};


/**
 * Handles the recursion of walking the action model and it's submodels. Should not be called directly
 * could have had one method, but it seemed more intuitive to use just to pass the action model to the method
 * above rather than passing items. This method also does not handle the null cases, those are handled by the calling methods
 *
 * @see walkActionModelAndApply, walkActionModelAndApplyToChildModels, walkActionModelAndApplyToAll
 */
PTC.actionModel.applyFunctionToItems = function(items, method, applyToItems, applyToSubMenus){
    for (var i = 0; i < items.size(); i++) {
        if (items[i].items) {
            //handle the sub menu
            if (applyToSubMenus) {
                method(items[i]);
            }
            PTC.actionModel.applyFunctionToItems(items[i].items, method, applyToItems, applyToSubMenus);
        }
        else if (applyToItems) {
            //not a submenu
            method(items[i]);
        }
    }
};

/**
 * Returns the action config for the given id.
 * Stores an array of actionIDs to action configs on the given model so future calls to this method don't have to walk the model to find the config.
 *
 * @param {String} id - the actionID of the JSONActionConfig to return
 * @param {JSONActionModel} actionModel - a JSONActionModel config produced, see JSONActionModel.java
 * @return {JSONActionConfig} the action config for the given id, see JSONActionConfig.java
 */
PTC.actionModel.getActionConfig = function(id, actionModel){
    var actionConfigs = actionModel.actionConfigs;
    if (!actionConfigs) {
        actionConfigs = [];
        PTC.actionModel.walkActionModelAndApply(actionModel, function(actionConfig){
            actionConfigs[actionConfig.actionID] = actionConfig;
        });
        actionModel.actionConfigs = actionConfigs;
    }
    return actionConfigs[id];
};

