/**
 * Launches the UI for the export action in the commonspace. Also does some simple, non-server validation.
 *
 * @param event The browser event
 * @param target The Ext object representing the UI component that was ˇ®clickedˇŻ
 * @param table The Ext table that contains the action. This is null if the action is not contained within a table
 */
PTC.cadexport.launchExportWindow = function(event, target, table) {
    var selectionsSpan = $('checkboxesFor_' + table.getId());

    // If no selections exist, give a warning and do not submit form.
    if (selectionsSpan === null || selectionsSpan.children.length === 0) {
        JCAAlert('com.ptc.windchill.uwgm.cadx.export.exportResource.NOTHING_SELECTED');
        return;
    }

    // Check if selections are valid.
    var hasValidElements = false, invalidElements = [], selectionInputs = selectionsSpan.children;
    for (var i = 0; i < selectionInputs.length; i++) {
        var input = selectionInputs[i];
        if (input.getValue().indexOf('wt.epm.EPMDocument') !== -1) {
            hasValidElements = true;
        } else {
            invalidElements.push(input);
        }
    }

    if (!hasValidElements) {
        // No EPM documents selected. Notify with a jcaalert and do not submit form.
        JCAAlert('com.ptc.windchill.uwgm.cadx.export.exportResource.NO_EPM_DOCS_SELECTED');
        return;
    }

    if (invalidElements.length > 0) {
        // There were some invalid selections. Ask user if it is OK to continue and ignore invalid selections.
        if (JCAConfirm('com.ptc.windchill.uwgm.cadx.export.exportResource.SOME_NON_EPM_DOCS_SELECTED')) {
            // Remove selections from the form. We will add them back after sending the form data.
            for (var i = 0; i < invalidElements.length; i++) {
                selectionsSpan.removeChild(invalidElements[i]);
            }
        } else {
            // User canceled. Do not submit form.
            return;
        }
    }

    // Made it past any possible pitfalls. Launch export UI.
    var url = getBaseHref() + 'servlet/WindchillAuthGW/wt.enterprise.URLProcessor/URLTemplateAction?u8&action=' + target.actionName;
    submitFormToNewPJLWindow(url, null, '', getMainForm(), true);

    // Replace any form selections that may have been removed above.
    for (var i = 0; i < invalidElements.length; i++) {
        selectionsSpan.appendChild(invalidElements[i]);
    }
};



/**
* @class
*/
var asyncResponseHandler = function() {

   var ERROR_FLAG = 'Error: ';
   var REFRESH_FLAG = 'Refresh: ';
   var CONSOLE_FLAG = 'CONSOLE_URL::';

   var PAGE_START = 'DYNAMIC_PAGE_START:-->';
   var PAGE_END = '<!--DYNAMIC_PAGE_END:';
   var FORM_START = '<!-- FORM_RESULT -->';
   var FORM_END = '<!-- END_FORM_RESULT -->';

   /**
    * Parses actions from an asynchronous response
    */
   function processResponse(responseText, response) {
      var processed = false;
      var skipScripts = (response.isAjaxEnabled=='row');
      response.dynamicText = asyncResponseHandler.stripText(responseText, null, skipScripts);
      if ( (!response.dynamicText || response.dynamicText === '')){
         // some pages just have the row update tags, not the full start end tags, should fix renderer too?
         response.dynamicText = responseText;
      }
      if (response.dynamicText) {
         processErrors(response);
         if (processRefresh(response)) {
            processed = true;
         }

         if (tableUtils.isExt()) {
             if (PTC.jca.processUpdate(response)) {
                 processed = true;
             }
             if (PTC.jca.processDelete(response)) {
                 processed = true;
             }
         }
         if (processConsole(response)) {
            processed = true;
         }
      }
      if (processForm(responseText, response)) {
         processed = true;
      }
      if (!processed && response.refreshOnNoOp) {
         processed = processCurrentStep(response);
         if (!processed) {
             getUpdateOpenerWindow().PTC.navigation.submitForm();
         }
      }
      if (response.disableSelected) {
         enableIds(response, true);
      }
   }

   function processErrors(response) {
      var errorText = getErrorText(response.dynamicText);
      if (errorText) {
         enableIds(response);
         wfalert(errorText);
      }
   }

   function enableIds(response, toggleChecked) {
      if (response.selectedItems) {
          response.selectedItems.enable(toggleChecked);
      }
   }

   function getErrorText(text) {
      var result = null;
      var idx = text.indexOf(ERROR_FLAG);
      if ((idx != -1) && text.indexOf('"' + ERROR_FLAG)==-1) {
         result = text.substring(idx+7);
      }
      return result;
   }

   function processRefresh(response) {
      if (response.dynamicText.indexOf(REFRESH_FLAG)==-1) {
         return false;
      }
      clearActionFormData();

      if (currentStepStrName) {
         refreshCurrentStep();
      }
      else {
         PTC.navigation.reload();
      }
      return true;
   }

   function processDelete(response) {
      if (response.ajaxClass!='NONE') {
         return false;
      }

      if (response.selectedItems && response.tableID) {
         var tID = tableUtils.getUnformattedTableId(response.tableID);

         //done for performance fix: in case of delete action it doesn't make sense to keep the
         //hidden selected div in DOM.
         var divEle = getWindow().$("checkboxesFor_" + tID);
         if(divEle){
            divEle.remove();
         }
         tableUtils.updateHeader(response.tableID);
         tableUtils.updateFooterCount(response.tableID, 0);
      }
      return true;
   }

   function processConsole(response) {
      var result = false;
      var text = response.dynamicText;
      var idx = text.indexOf(CONSOLE_FLAG);
      if (idx != -1) {
         result = true;
          text = text.substring(idx+13);
          eval(text);
          enableIds(response);
      }
        return result;
   }

   function parseUrl(text, start, end) {
      if (!end) {
         end = '>';
      }
      var result = null;
      var idx = text.indexOf(start);
      if (idx != -1) {
         idx+=start.length;
         var closeIdx = text.indexOf(end,idx);
         if (closeIdx == -1) {
            closeIdx = text.length;
         }
         result = text.substring(idx,closeIdx);
      }
      return result;
   }

   function processForm(responseText, response) {
      var result = false;
      if (responseText.indexOf(FORM_START) != -1) {
         var formResultText = asyncResponseHandler.stripText(responseText, null, true, FORM_START, FORM_END);
         if (formResultText && formResultText.length > 10) {
            PTC.navigation.evalPageScripts(formResultText);
            result = true;
         }
     }
      return result;
   }

   function processCurrentStep(response) {
      var result = true;
      if (response.isAjaxEnabled=='row') {
         response.disableSelected = false;
         // Some Ajax action on the details page can't update rows
         var flushInput = JCAappendFormHiddenInput(getMainForm(), 'dynamicFlush', 'true');
         if (currentStepStrName) {
               refreshCurrentStep();
               getMainForm().removeChild(flushInput);
         }
         else {
            PTC.navigation.submitForm();
         }
      }
      else {
         if (currentStepStrName) {
            var curStep = $(currentStepStrName);
            if (curStep) {
               //TODO: May need to handle formresult here too
               PTC.util.purge(curStep, true);
               curStep.innerHTML = response.dynamicText;
            }
         }
         else if (getUpdateOpenerWindow().getCurrentStep) {
            var step = getUpdateOpenerWindow().getCurrentStep();
            if (step && step.length > 0) {
               getupdateOpenerWindow().refreshCurrentStep();
            }
         }
         else {
            result = false;
         }
      }
      return result;
   }

   return /**@scope asyncResponseHandler */{
      /**
       * The response can have the following properties:
       * xmlhttp, mform, elemAddress, actionMethod,
       * selectedItems, ajaxClass, tableID, isAjaxEnabled,
       * disableSelected, addRows, refreshOnNoOp, iframeForm
       */
      handleResponse : function(responseText, response) {
      try {
         if (response.preProcessor) {
            response.preProcessor();
         }
         processResponse(responseText, response);
      }
      catch (e) {
          var message = "Error in handleResponse. Will try to recover by re-submitting the form for this page.";
          if(PTC.getMainWindow().PTC.debug.isJsDebug()) {
              // when debugging need to know this error happened and is ok that it will end up in MS log
              PTC.log.error(message, e);
          } else {
              // else just debug level so this 'alarming' message would not show up for any customer MS logs
              PTC.log.debug(message, e);
          }
         var mform = getMainForm();
         if (mform) {
            clearActionFormData();
            // don't want to submit the wizard if that is where the error happened
            if (!isWizardWindow()) {
                PTC.navigation.submitForm();
            }
         }
      }
      clearActionFormData();
      },
      /**
       * Gets rid of unwanted text from the response.  Substrings out anything not in between the html comment.
       * Can execute javascript blocks conditionally.
       * Start/end are the html comment strings to use to find the response in.
       * @param {String} text
       * @param {String} divId id of the div that wraps the new html content
       * @param {Boolean} skipScriptEval
       * @param {int} start
       * @param {int} end
       */
      stripText : function(text, divId, skipScriptEval, start, end) {
         if (!start) {
            start = PAGE_START;
            end = PAGE_END;
         }
         var startIdx = text.indexOf(start);
         if (startIdx == -1) {
            startIdx = 0;
         }
         else {
            startIdx += start.length;
         }

         var endIdx = text.lastIndexOf(end);
         if (endIdx == -1) {
            endIdx = text.length;
         }

         if (divId && divId !== '') {
            var divStart = '<div id="'+divId + '"';
            var divStartIdx = text.indexOf(divStart, startIdx);
            if (divStartIdx != -1) {
               divStartIdx = text.indexOf('>', divStartIdx);
               if (divStartIdx != -1) {
                     divStartIdx++;
                  var divEndIdx = text.lastIndexOf('</div>');
                  if (divStartIdx < divEndIdx < endIdx) {
                     startIdx = divStartIdx;
                     endIdx = divEndIdx;
                  }
               }
            }
         }

         if (startIdx !== 0 || endIdx != text.length) {
            text = text.substring(startIdx,endIdx);
            if (!skipScriptEval) {
               PTC.navigation.evalPageScripts(text);
            }
         }
         else if (text.indexOf('<html>')!=-1) {
            text = '';
         }
         return text;
      }
   };
}();


Ext.namespace("ATO.util");
Ext.namespace("ATO.choicerule");
Ext.namespace("ATO.components");
Ext.namespace("ATO.components.ChoiceComponent");

ATO.util.replaceURL = function(url, post) {
    PTC.onReady( function() {
        //if not post just replace the url.
        if(!post) {
            PTC.util.replaceURL(url);
            return;
        } 
        //handle post by submitting the form.
        var postForm = getMainForm();
        PTC.util.setFormAction(postForm, url);
        postForm.submit();
    });
}

$ato = function(id) {
    var r = $(id);

    // some of the hidden fields has only 'name' attribute.
    // look for the the field with the given name.
    // ideally there should be only one field, get the first one.
    if (!r) {
        var ar = Ext.DomQuery.select("[name='"+id+"']");
        if (ar.length > 0) {
            r = ar[0]; // get the first element
        }
    }
    return r;
};

function deleteConfirm(evt, table, confirm_message) {
    if (table){
        var checked = isSomethingChecked(table.id);
        if (checked === false) {
            JCAAlert("com.ptc.netmarkets.util.utilResource.NONE_CHECKED");
            Event.stop(evt);
            return false;
        }
    }
    if (!confirm_message) {
            confirm_message = "com.ptc.netmarkets.util.utilResource.CONFIRM_DELETE";
    }
    return JCAConfirm(evt, confirm_message);
}

ATO.util.handleSubmitResult = function(orig, status, nextAction, js, URL, dynamicRefreshInfo, doRefresh) {
    nextAction = 4; // Change to none since refresh opener is not handle correctly for undo checkout
    orig(status, nextAction, js, URL, dynamicRefreshInfo);
    if(opener && doRefresh !== false) {
        opener.location.reload();
    }
    if (window.closed === false) {
        window.close();
    }    
    wfWindowClose();
};

ATO.util.handleSubmitResultNoRefresh = function(orig, status, nextAction, js, URL, dynamicRefreshInfo) {
    ATO.util.handleSubmitResult(orig, status, nextAction, js, URL, dynamicRefreshInfo, false);
};

ATO.util.editCancelPrepare = function(orig) {   
    var isCheckedout = $("isCheckedOutByUser") ? $("isCheckedOutByUser").value : "false";
    //undo checkout only when we do autocheckout
    var indAssignedExpMode = $("indAssignedExpMode") ? $("indAssignedExpMode").value : "false";
    var isGWT = $("isGWTAction") ? $("isGWTAction").value : "false";
    if (isGWT === "true"){
    	if(indAssignedExpMode === "true") {
        	// upon cancel always do undo checkout of Ind Assigned expression
        	handleSubmitResult = handleSubmitResult.wrap( ATO.util.handleSubmitResultNoRefresh );
        	return true;
        } else {
        	// for Dep Assigned Expression system, part is checkedout by system if not already checked out
        	// on cancel just leave the part checked out even if it is checkedout by system.
        	return orig();
        }
    }
    if((indAssignedExpMode === "true" || 
      isCheckedout === "false") && JCAConfirm('com.ptc.netmarkets.util.utilResource.CONFIRM_UNDO_CHECKOUT')) {
        handleSubmitResult = handleSubmitResult.wrap( ATO.util.handleSubmitResult );
        return true;
    } 
    return orig();
    
};

/**
    Iterate through the table store items and push them into a new array.
    Then, if the table is filtered, get the items in the snapshot and add
    those into the array as well.  Return the array which should contain all
    of those records.
*/
ATO.util.getFilteredAndNonFilteredItems = function(table) {
    var items = [];
    if(table) {
        var records = table.store.data.items;
        for (var rIdx = 0, rlen = records.length; rIdx < rlen; rIdx++) {
            items.push(records[rIdx]);
        }
        if (table.store.isFiltered() === true) {
            var filteredItems = tableUtils.getFilteredOutTableRows(table.store);
            for (var snapIdx =0, len=filteredItems.length; snapIdx < len; snapIdx++){
                items.push(filteredItems[snapIdx]);
            }
        }
    }
    return items;
};

ATO.util.setHiddenFieldValue = function (id, value) {
    var form = getMainForm();
    !$ato(id) ? JCAappendFormHiddenInput(form, id , value) : $ato(id).value = value;
};

ATO.util.handleSpecialChars = function(str) {
    var specialChars  = {};
    specialChars["&quot;"] = "\"";
    specialChars["&amp;"] = "&";
    specialChars["&gt;"] = ">";
    specialChars["&lt;"] = "<";
    specialChars["&#39;"] = "'";

    for (key in specialChars) {
        str =  replaceAll(str, key, specialChars[key]);
    }
    return str;
};

ATO.util.getAdvancedExpressionData = function(tableId) {
    // if table id is not provided, try to find the table.
    if (!tableId) {
        var tables = tableUtils.getTables();
        var len = tables.length;
        for (var i = 0;i < len; i++) {
            tableId = tables[i].id;
            // is there a better way to get the expression table?
            if (tableId.startsWith("expressionable.mvc.")) {
                break;
            }
            tableId = null;
        }
    }

    var table = tableUtils.getTable(tableId);
    if (table) {
        var jsonExpr = {
            expressions : []
        };
        var rows =  ATO.util.getFilteredAndNonFilteredItems(table);
        var length = rows.length;
        for (var i = 0;i < length; i++) {
            var json =  {};
            var record = rows[i];
            if(!record) {
                continue;
            }
            var expression = ATO.util.handleSpecialChars(record.get('expressionField').gui.displayValue);
            var description = ATO.util.handleSpecialChars(record.get('description').gui.displayValue);
            json.expression = expression;
            json.description = description;
            json.oid = record.get('oid');
            jsonExpr.expressions.push(json);
        }
        //add to hidden field
        var ruleMembers = Ext.getDom("hdnExpressionMembers");
        if (!ruleMembers) {
            var mainForm = getMainForm(tableId);
            ruleMembers = JCAappendFormHiddenInput(mainForm, "hdnExpressionMembers", "");
        }
        var expstr = Ext.encode(jsonExpr);
        ruleMembers.value=expstr;
    }
    return true;
};




/**
 * GUI component is internal representation of an attribute and it has all the information required to represent an attribute.
 * GUI components can be interpreted in many different ways. It has internal functionality which can be used
 * to do render, search, export operations.
 */
Ext.namespace('PTC.attribute.gui');

PTC.attribute.gui = function() {
    var ATTR_TYPE_BOOLEAN = "Boolean";
    var ATTR_TYPE_STR = "String";
    var ATTR_TYPE_DATE = "Date";
    var ATTR_TYPE_TIMESTAMP = "Timestamp";
    var ATTR_TYPE_INT = "Integer";
    var ATTR_TYPE_REAL = "Real";
    var ATTR_TYPE_FLOAT = "Float";
    var ATTR_TYPE_REALWITHUNITS = "RealWithUnits";
    var ATTR_TYPE_UNITS = "Unit";
    var ATTR_TYPE_URL = "URL";
    var ATTR_TYPE_URL_S = "Url";

    var NMACTION_RENDERER = "jsca.columns.nmActionRenderer";
    var NUM_RENDERER = "jsca.columns.numericRenderer";
    var BOOLEAN_RENDERER = "jsca.columns.booleanRenderer";
    var LINK_RENDERER = "jsca.columns.linkRenderer";
    var TYPE_INT = "java.lang.Integer";
    var TYPE_FLOAT = "com.ptc.core.meta.common.FloatingPoint";
    var TYPE_FLOAT_WITH_UNITS = "wt.units.FloatingPointWithUnits";

    var isLink = function(value) {
        if (value !== null && ((value.indexOf('://') > 0 ))) {
            return true;
        }
        return false;
    };

    var getStringValue = function(value) {
        var htmlCont = "";
        if (PTC.isDefined(value)) {
            if (PTC.attribute.gui.Utils.allowLinkRendering() && isLink(value)) {
                htmlCont = "<A HREF=\'" + value + "\'>" + value + "</A>";
            } else {
                htmlCont = Ext.util.Format.htmlEncode(value);
            }
        }
        return htmlCont;
    };

    var getBooleanValue = function(value) {
        if (typeof value === "string") {
            value = (value.toUpperCase() === "TRUE");
        }
        if (PTC.isDefined(value)) {
            value = (value ? "TRUE" : "FALSE");
        } else {
            value = "";
        }
        return value;
    };

    var getDatevalue = function(value) {
        var date = "";
        if (typeof value === "string") {
            date = Ext.util.Format.htmlEncode(value);
        } else {
            date = value;
        }
        return date;
    };

    var isSupported = function(attrType, value) {

        //two value type we support
        if (typeof value === "boolean" || value instanceof Date) {
            return true;
        }
        //attrType we support
        if ( (PTC.isDefined(attrType)) && (
               ATTR_TYPE_STR === attrType ||
               ATTR_TYPE_INT === attrType ||
               ATTR_TYPE_BOOLEAN === attrType ||
               ATTR_TYPE_DATE === attrType ||
               ATTR_TYPE_TIMESTAMP === attrType ||
               ATTR_TYPE_REAL === attrType ||
               ATTR_TYPE_FLOAT === attrType ||
               ATTR_TYPE_REALWITHUNITS === attrType ||
               ATTR_TYPE_UNITS === attrType ||
               ATTR_TYPE_URL === attrType ||
               ATTR_TYPE_URL_S === attrType )) {
            return true;
        }
        return false;
    };

    /**
     * Updates value associated with an attribute depending upon the attribute type.
     * @param {Object} attrValue - Current value associated with an attribute.
     * @param {Object} newValue - New value which needs to be assigned to an attribute
     * @param {Object} attrType - Type of an attribute. It could be string, real, integer, boolean etc.
     * @param {Object} options - Extra options which can be set on gui component
     */
    var _update = function(attrValue, newValue, attrType, options) {

        //First reset the values associated with an attribute.
        PTC.attribute.gui.Utils.resetForUpdate(attrValue.gui);

        //Update string GUI component.
        if (ATTR_TYPE_STR === attrType) {
            attrValue.gui.html = getStringValue(newValue);
            return attrValue;
        }

        //Update boolean GUI component.
        if (typeof newValue === "boolean" || ATTR_TYPE_BOOLEAN === attrType) {
            attrValue.gui.rawValue = getBooleanValue(newValue);
            return attrValue;
        }

        //Update date GUI component.
        if (ATTR_TYPE_DATE === attrType || ATTR_TYPE_TIMESTAMP === attrType  ||  newValue instanceof Date) {
            attrValue.gui.html = (PTC.isDefined(newValue)) ? PTC.attribute.gui.Utils.getFormatedDate(newValue): "";
            return attrValue;
        }

        //Update integer GUI component.
        if (ATTR_TYPE_INT === attrType) {
            attrValue.gui.type = "java.lang.Integer";
            attrValue.gui.rawValue = (PTC.isDefined(newValue)) ? (newValue) : '';
            return attrValue;
        }

        //Update real GUI component.
        if (ATTR_TYPE_REAL === attrType || ATTR_TYPE_FLOAT === attrType) {
            attrValue.gui.type = "com.ptc.core.meta.common.FloatingPoint";
            attrValue.gui.rawValue = newValue;
            return attrValue;
        }

        //Update real with units GUI component.
        if (ATTR_TYPE_REALWITHUNITS === attrType || ATTR_TYPE_UNITS === attrType) {
            attrValue.gui.type = "wt.units.FloatingPointWithUnits";
            if (ATTR_TYPE_REALWITHUNITS === attrType) {
                var precision = "";
                var unitOfMeasure = attrValue.gui.unitOfMeasure ;
                if(PTC.isDefined(options)){
                    if(PTC.isDefined(options.precision)){
                        precision = options.precision;
                    }
                    if(PTC.isDefined(options.unitOfMeasure)){
                        unitOfMeasure = options.unitOfMeasure;
                    }
                }
                attrValue.gui.rawValue = "" + newValue + "|" + precision + "|" + unitOfMeasure;
            } else {
                attrValue.gui.rawValue = newValue;
            }
            return attrValue;
        }

        //Update URL GUI component.
        if (ATTR_TYPE_URL === attrType || ATTR_TYPE_URL_S === attrType ) {
            attrValue.gui.rawValue = newValue;
            return attrValue;
        }

        //last option  - here attrType is not defined
        var _newValue = (PTC.isDefined(newValue)) ? (newValue) : '';
        //special handling based on the attrValue.renderer
        if(attrValue.renderer === NMACTION_RENDERER){
            //required as nmActionRenderer looks on html value only
            attrValue.gui.html = _newValue;
        }else{
            //set the rawValue
            attrValue.gui.rawValue = _newValue;
        }
        return attrValue;
    };

    /**
     * Creates a GUI object depending upon the attribute type which can be set as attribute value.
     * This object also has information about how to render an attribute value.
     * @param {Object} newValue - attribute value
     * @param {Object} attrType - attribute tupe, it could be string, boolean, integer, real etc.
     */
    var _create = function(newValue, attrType) {

        //String GUI component
        if (ATTR_TYPE_STR === attrType) {
            return {
                gui: {
                    html: getStringValue(newValue)
                }
            };
        }

        //Boolean GUI component
        if (typeof newValue === "boolean" || ATTR_TYPE_BOOLEAN === attrType) {
            return {
                gui: {
                    rawValue: getBooleanValue(newValue)
                },
                renderer: BOOLEAN_RENDERER
            };
        }

        //Date GUI component
        if (ATTR_TYPE_DATE === attrType || ATTR_TYPE_TIMESTAMP === attrType || newValue instanceof Date) {
            var date = (PTC.isDefined(newValue)) ? PTC.attribute.gui.Utils.getFormatedDate(newValue): "";
            return {
                gui: {
                    html: date
                }
            };
        }

        //Integer GUI component
        if (ATTR_TYPE_INT === attrType) {
            return {
                gui: {
                    type: TYPE_INT,
                    rawValue: (PTC.isDefined(newValue)) ? (newValue) : ''
                },
                renderer: NUM_RENDERER
            };
        }

        //Real GUI component
        if (ATTR_TYPE_REAL === attrType || ATTR_TYPE_FLOAT === attrType) {
            return {
                gui: {
                    type: TYPE_FLOAT,
                    rawValue: newValue
                },
                renderer: NUM_RENDERER
            };
        }

        //Real with units GUI component
        if (ATTR_TYPE_REALWITHUNITS === attrType || ATTR_TYPE_UNITS === attrType) {
            return {
                gui: {
                    type: TYPE_FLOAT_WITH_UNITS,
                    rawValue: newValue
                },
                renderer: NUM_RENDERER
            };
        }

        //URL GUI component
        if (ATTR_TYPE_URL === attrType || ATTR_TYPE_URL_S === attrType) {
            return {
                gui: {
                    "rawValue": newValue
                },
                renderer: LINK_RENDERER
            };
        }

        //last option
        return {
            gui: {
                rawValue: (PTC.isDefined(newValue)) ? (newValue) : ''
            }
        };
    };

    return {
        /**
         * Create gui value of a attribute, and if there is no gui object associated with attribute, tries to create gui object.
         * @param {Object} value - New value which needs to be assigned to an attribute
         * @param {Object} attrType - Type of an attribute. It could be string, real, integer, boolean etc.
         */
        create: function(value, attrType){
            var gui = _create(value, attrType);
            //SPR  2040141: make sure all attributes are properly encoded
            return PTC.util.HTMLEncoder.handleAdjacentSpaces(gui);
        },

        /**
         * Update gui value of a attribute, and if there is no gui object associated with attribute, tries to create gui object.
         * @param {Object} attrValue - Current value associated with an attribute.
         * @param {Object} value - New value which needs to be assigned to an attribute
         * @param {Object} attrType - Type of an attribute. It could be string, real, integer, boolean etc.
         * @param {Object} options - Extra options which can be set on gui component
         */
        update: function(attrValue, value, attrType, options){

            if(!PTC.isDefined(attrValue)){
                //attrValue is not defined, but from attrType & value can we create a gui
                if(isSupported(attrType, value)){
                    return _create(value, attrType);
                }else{
                    if(attrType === undefined && typeof value == "string"){
                        return getStringValue(value);
                    }
                    //cannot help here, return the value as it is
                    return value;
                }
            }

            //attrValue is defined here
            var gui;
            if (typeof attrValue === "object" && attrValue.gui) {
                //its a gui, go for update
                gui = _update(attrValue, value, attrType, options);
            } else if(typeof attrValue == "string" && typeof value == "string"){
                //its NOT gui, but old value and new value are strings
                gui = getStringValue(value);
            } else {
                if(attrType === undefined){
                    if(typeof value == "string"){
                        return getStringValue(value);
                    }
                    return value;
                }
                //don't know how to handle, return original value itself
                gui = attrValue;
            }
            //SPR  2040141: make sure all attributes are properly encoded
            return PTC.util.HTMLEncoder.handleAdjacentSpaces(gui);
        }
    };
} ();

/**
 * @class
 * Utility methods on PTC.attribute.gui
 */
 PTC.attribute.gui.Utils = function(){

    return {
        /**
         * Do we need to allow link rendering?
         * @name PTC.attribute.gui.Utils.allowLinkRendering
         * @return {boolean}
         */
        allowLinkRendering : function (){
            return PTC.attributeHelper.get("createHyperlinks");
        },

        /**
         * Reset the value related properties of the gui (html, displayValue, value, rawValue)
         * @name PTC.attribute.gui.Utils.resetForUpdate
         * @param {Object} gui
         */
        resetForUpdate : function (gui){
            if(PTC.isDefined(gui)){
                gui.html=undefined;
                gui.displayValue=undefined;
                gui.value=undefined;
                gui.rawValue=undefined;
                gui.comparable=undefined;
            }
        },

        /**
         * Format the date
         * @name PTC.attribute.gui.Utils.getFormatedDate
         * @param {Object} value
         * @return {Object} formated date
         */
        getFormatedDate : function (value){
            // convert string to date object
            if(typeof value == "string" && value.indexOf("new Date") != -1) {
                value = ( new Date (eval(value)));
            }
            if(value instanceof Date){
                try {
                    var formatdatefunc = PTC.attributeHelper.get('DateRenderer');
                    return formatdatefunc(value);
                }
                catch(e) {
                    return Ext.util.Format.htmlEncode(value);
                }
            } else {
                return Ext.util.Format.htmlEncode(value);
            }
        }
    };
}();


/**
 * @namespace
 * For storing localized attribute data values on the client. The values are currently not saved across refreshes or across sessions. 
 * Could use ClientStateProvider to save across refreshes, but may run out of storage space. 
 * Possibly using the provider is not worth the extra complexity since refreshes are not frequent. 
 */
PTC.attributeHelper = function(){
};


PTC.attributeHelper._cache = {};

/**
 * Gets the data for the given key. 
 * If the data is not already cached on the client, an ajax call is made to get the data from localizedData.jsp. 
 * 
 * @param {String} key
 * @return {Object} data for a the given key
 */
PTC.attributeHelper.get = function(key){
	PTC.attributeHelper._initializeCache();
	try {
      return PTC.attributeHelper._cache[key];
    }catch(e){
      //IE throws exception in wizard if there is no opener window.
      return null;
    }
};

/**
 * Stores the given data with the given key. 
 * 
 * @param {String} key
 * @param {Object} attributeData - the data to store with the given key
 */
PTC.attributeHelper.set = function(key, attributeData){
   try {
      PTC.attributeHelper._cache[key] = attributeData;
   }catch(e){
     //ignore
   }
};

/**
 * Makes ajax call to get attribute data
 */
PTC.attributeHelper._initializeCache = function(){
    try {
        var win = PTC.getMainWindow();
        var windowHref = window.location.href;
        if (win && win.PTC && win.location.href === windowHref) {
            // try the parent window in case of iframes
            if (parent && parent.PTC) {
                win = parent;
            }
        }
        // Compare the href's of the window for equality, not the window objects themselves, 
        // since IE handles window object equality strangely (see SPR 1984605 for an example). 
        if (win && win.location.href !== window.location.href && win.PTC) {
            //copy caches from main window to reduce the number of ajax calls made for localized values
            
            //Note: With IE 7 there are issues sharing arrays between window and opener. 
            //Resulting in an error like: 
            //          "Error: The callee (server [not server application]) is not available and disappeared; 
            //           all connections are invalid. The call did not execute."
            //To avoid this issue, logic below just copies the cache objects instead of
            //copying the whole namespace, PTC.attributeHelper or bundleHandler, from the main window
            //SPRs - 1976776, 1976759, 1976467
            
            //ensure top/opener cache is intialized 
            win.PTC.attributeHelper._initializeCache();
            //copy the cache from the top/opener
            PTC.attributeHelper._cache = win.PTC.attributeHelper._cache;
            bundleHandler._setCache(win.bundleHandler._getCache());
            //initialize other variables if any
            if (typeof win.PTC.attributeHelper.initializeVariables === 'function') {
                win.PTC.attributeHelper.initializeVariables.call(window);
            }
            //make init functions no-op so we don't do any of this work again
            PTC.attributeHelper._initializeCache = Ext.emptyFn;
            bundleHandler._initializeCache = Ext.emptyFn;
            return;
        }
    } 
    catch (e) {
        PTC.log.error(e);
    }
    
    var options = {
        method: 'get',
        asynchronous: false
    };
    //IE caches the response and does not re-request if browser is refreshed, so added unique id to force re-request.
    var url = getBaseHref() + "netmarkets/jsp/util/localizedData.jsp?d=" + PTC.util.getUniqueId();
    options.onSuccess = function(transport) {
        //the script in localizedData.jsp initializes the attributeHelper _cache
        PTC.navigation.evalPageScripts(transport.responseText);
    };
    options.onFailure = options.onException = function() {
        PTC.attributeHelper._initializeCache = PTC.attributeHelper._initializeCacheOld;
        PTC.log.error("could not load the attribute cache");
    };

    PTC.attributeHelper._initializeCacheOld = PTC.attributeHelper._initializeCache;
    //Need to set initialize function to no-op before making the call to avoid infinite loops in the success
    //function for form-based auth.  2176310
    PTC.attributeHelper._initializeCache = Ext.emptyFn;
    requestHandler.doRequest(url, options);
};



/**
 * The namespace for the attribute panel information.
 * @namespace
 * @name PTC.attributePanel
 */
Ext.namespace('PTC.attributePanel');
Ext.apply(PTC.attributePanel, new Ext.util.Observable());
PTC.attributePanel.log = log4javascript.getLogger("PTC.attributePanel");

/**
 * Listen to this event to change the info page model before the page is rendered.
 * For example, the cadx info page can get attributes from ProE and put them in the attributes table.
 *
 * This listener will apply for all info pages. To change the data model for only certain types, check the type on the info model.
 * The type String is whatever type was set in the ComponentBuilder for the info page.
 *
 * @example
 * //modifies some attribute data in the info page model before the page is rendered
 * PTC.attributePanel.on("beforeRender", function(attributePanel) {
 *   if(attributePanel.type === 'wt.epm.EPMDocument') {
 *      var oldName = attributePanel.getAttributeValue("name");
 *      var newName = oldName + "more text";
 *      attributePanel.setAttributeValue("name", newName);
 *   }
 * });
 *
 *
 * @name PTC.attributePanel#beforeRender
 * @event
 * @param {PTC.attributePanel.AttributePanel} attributePanel
 */
PTC.attributePanel.addEvents("beforeRender", "afterRender");

/**
 * This is the template to use for generating the attribute panel.
 *
 * It will first send the data through the jsca renderers and then use the template to display the information correctly on the attribute panel.
 *
 * @param {Object} groupData - Has the group label, id and data rows. See com.ptc.core.components.tags.attributePanel.AttributeGroupModel.java
 */
PTC.attributePanel.attributeGroup = function(groupData) {

    if (groupData.nestedFlag) {
        // rendering nested group
        var nestedItems = [];
        for ( var j = 0; j < groupData.groups.length; j++) {
            nestedItems.push(new PTC.attributePanel.attributeGroup(groupData.groups[j]));
        }

        var useAutoWidth = PTC.attributePanel._useAutoWidth(groupData);
        var outerFieldSet = {
            id: groupData.id,
            xtype: 'fieldset',
            title: '<span class="attributePanel-fieldset-title">' + (groupData.label || "") + '</span>',
            collapsed: false,
            autoHeight: true,
            autoWidth: useAutoWidth,
            collapsible: true,
            items: nestedItems,
            listeners: {}
        };

        // in IE add a resize listener to resize the outerFieldset to the size of the table containing the
        // attributes.
        if (!useAutoWidth) {
            outerFieldSet.listeners.resize = function(attGroup, resizedWidth) {
                PTC.attributePanel.resizeGroupWidth(attGroup, resizedWidth);
            };
        }

        PTC.attributePanel.attributeGroup.superclass.constructor.call(this, outerFieldSet);
    } else {
        var store = new Ext.data.JsonStore({
            data: groupData,
            root: 'rows',
            fields: ['columns']
        });

        //when the record is rendered using the template, it need reference of attributeGroup
        //updating the records to add a place holder to refer attributeGroup
        var attrGrp = this;
        //get records
        var dataSet =store.data;
        dataSet.each(function(rowDef){
            var allCols = rowDef.data.columns;
            allCols.each(function(col){
                col.columnAttributeGroup = attrGrp;
            });
        });

        var groupId = PTC.wizard.getCurrentObjectHandle() + groupData.id;
        //groups id can't have spaces in it, replace it with underscore.
        groupId = groupId.replace(/ /g, "_");
        // attributeGroupId is used by the PTC.jca.table.Utils.evalCellContent logic
        this.attributeGroupId = groupId;
        var tpl = PTC.attributePanel.getXTemplate(groupData.renderOnTop);

        useAutoWidth = PTC.attributePanel._useAutoWidth(groupData);
        var groupConfig = {
            title: '<span class="attributePanel-fieldset-title">' + (groupData.label || "") + '</span>',
            id: groupId,
            batchAttrId:groupData.batchAttrId,
            xtype: 'fieldset',
            collapsible: true,
            autoHeight: true,
            autoWidth: useAutoWidth, //see the IE logic in the resize listener below
            renderOnTop: groupData.renderOnTop,
            hideIfNullValueInClient: groupData.hideIfNullValueInClient,
            clientValueUpdatesComplete : true,   //default value is true (values get updated before rendering)
                                                                          //If its true, hideIfNullValue is applied in client while rendering.
                                                                          //If value need to updated after the group is rendered, then this has to be made
                                                                          //false and hideIfNullValueInClient has to be explicitly invoked after value updates.
            items: [{
                xtype: 'dataview',
                id: 'dataStore' + groupId,
                store: store,
                tpl: tpl,
                autoHeight: true,
                autoWidth: true,
                itemSelector: 'table.attributePanel-group-panel'
            }],
            listeners: {
                afterLayout: function(group){
                    this.setLabelWidths(group);
                }
            }
        };

        // in IE add a resize listener to resize the fieldset to the size of the table containing the attributes.
        if (!useAutoWidth) {
            groupConfig.listeners.resize = function(attGroup, resizedWidth){
                PTC.attributePanel.resizeGroupWidth(attGroup,resizedWidth);
            };
            groupConfig.listeners.resize = PTC.util.delayAllCalls(groupConfig.listeners.resize);
        }

        PTC.attributePanel.attributeGroup.superclass.constructor.call(this, groupConfig);
        // SPR 2038402: afterLayout sometimes being called multiple times per group - also causing issue with calculating correct label widths.
        // Adding the delayAllCalls after the constructor otherwise the 'this' reference is undefined
        this.setLabelWidths = PTC.util.delayAllCalls(this.setLabelWidths);
    }
};

/**
 * The miniNavigator correctly handles the wrapping and scrollbars so the extra logic here only hurts
 * The custom width still fixes a problem in wizards with the input attributes not getting a scrollbar in IE
 */
PTC.attributePanel._useAutoWidth = function(groupData) {
    // rather than checking for IE directly, we will check if the browser has support
    // for the CSS 'resize' tag, which appears to allow the browser to auto-resize a panel
    // (which can cause a scrollbar to appear).
    var supportsCSSResizeTag = PTC.browser.browserSupportsCSSTag('resize');
    return supportsCSSResizeTag || groupData.forceAutoWidth === true;
};

/**
 * Method to set custom width to resolve scrollbar IE issue
 */
PTC.attributePanel.resizeGroupWidth = function(attGroup, resizedWidth) {

var fieldsetDomEl = attGroup.getEl();
    
    // get the DOM element that controls the actual width of the fieldset
    var contentDomNode = Ext.DomQuery.select('table[class="attributePanel-group-panel"]', fieldsetDomEl.dom);

    if (contentDomNode && contentDomNode[0]) {
        // get the padding of the fieldset 
        var fieldSetPadding = parseInt(fieldsetDomEl.getStyle("padding-left"), 10) + parseInt(fieldsetDomEl.getStyle("padding-right"), 10);

        var newFieldsetWidth = contentDomNode[0].offsetWidth + fieldSetPadding;

        // if the width of the fieldset is larger than the current window size, set the size of the fieldset to
        // the actual size of the fieldset contents
        if (newFieldsetWidth >= resizedWidth) {
            attGroup.setWidth(newFieldsetWidth);
        } else {
            // otherwise the window is larger than the fieldset content size so allow the fieldset border to fill up the set of the space
            attGroup.setWidth('auto');
        }
    }

};

PTC.attributePanel.getRenderOnTopTemplate = function(){
    if(PTC.attributePanel.renderOnTopTemplate === undefined){
        PTC.attributePanel.renderOnTopTemplate = new Ext.XTemplate(//labels and values to be rendered on separate rows, with values on row beneath label row.
            '<table class="attributePanel-group-panel">',
                '<tpl for=".">',
                    '<tr>',
                        '<tpl for="columns">', // Since value is rendered as separate row, we have one column less in the colSpan expression (values.colSpan * 2) - 1
                            '<td class="attributePanel-asterisk">{asteriskValue}</td><td id="{labelId}"',
                            '<tpl if="PTC.automation.isAutomationTest()">',
                            ' attrid="{id}"',
                            '</tpl>',
                            ' class="attributePanel-label{[(values.colSpan && values.colSpan > 1) ? " fullWidth" : ""]}"',
                            ' {[(values.colSpan && values.colSpan > 1) ? " colspan=" + ((values.colSpan * 2) - 1) : ""]}',
                            '>{label}{[(values.label && values.label != "&nbsp;") ? ":" : ""]}</td>',
                        '</tpl>',
                    '</tr>',
                    '<tr>',
                        '<tpl for="columns">',
                            '<td class="attributePanel-asterisk"></td><td',
                            ' class="attributePanel-value{[(values.colSpan && values.colSpan > 1) ? " fullWidth" : ""]}"',
                            ' attrId="{values.id}"{[(values.colSpan && values.colSpan > 1) ? " colspan=" + ((values.colSpan * 2) - 1) : ""]}> {[this.attributePanelJSCACellRenderer(values.value, values.id, values.columnAttributeGroup, values.columnRenderer) ]} </td>',
                        '</tpl>',
                    '</tr>',
                '</tpl>',
            '</table>'
        );
    }
    return PTC.attributePanel.renderOnTopTemplate;
};

PTC.attributePanel.getDefaultTemplate = function(){
    if(PTC.attributePanel.defaultTemplate === undefined){
        PTC.attributePanel.defaultTemplate = new Ext.XTemplate(//labels and values rendered in same row
            '<table class="attributePanel-group-panel">',
                '<tpl for=".">',
                    '<tr>',
                    '<tpl for="columns">',
                       '<td class="attributePanel-asterisk">{asteriskValue}</td><td id="{labelId}" class="attributePanel-label">{label}{[(values.label && values.label != "&nbsp;") ? ":" : ""]}</td><td',
                       ' class="attributePanel-value{[(values.colSpan && values.colSpan > 1) ? " fullWidth" : ""]}"',
                       ' attrId="{values.id}"{[(values.colSpan && values.colSpan > 1) ? " colspan=" + ((values.colSpan * 3) - 2) : ""]}> {[this.attributePanelJSCACellRenderer(values.value, values.id, values.columnAttributeGroup, values.columnRenderer) ]} </td>',
                    '</tpl>',
                    '</tr>',
                '</tpl>',
            '</table>'
        );
    }
    return PTC.attributePanel.defaultTemplate;
};

/**
 * Returns the XTemplate for the attribute panel depending upon the layout required. If argument renderOnTop is true, it returns the XTemplate wherein
 * the attribute panel will be rendered with labels and values on separate rows. Values row will be rendered below the label row in this case.
 * If the argument is not true, labels and values shall be rendered in a single row.
 *
 * @private
 * @param {boolean} renderOnTop
 * @return {Ext.XTemplate}
 */
PTC.attributePanel.getXTemplate = function(renderOnTop){
    var tpl = renderOnTop ? PTC.attributePanel.getRenderOnTopTemplate() : PTC.attributePanel.getDefaultTemplate();
    /**
     * Used to create a fake column and row object which will contain the data to be renderered via the jsca
     * renderers.
     *
     * @param {array} data - This object has the renderer function along with the gui object to be renderered.
     *                       If data is undefined or null, then empty string is returned.
     * @param {String} attrId - The attribute id.
     * @param {PTC.attributePanel.attributeGroup} columnAttributeGroup - attribute group in which this attribute belongs to
     * @param {String} columnRenderer - The js renderer to use for the attribute. If undefined the data.renderer will be used.
     *                                  If data.renderer is undefined then jsca.columns.simpleRenderer is used.
     * @return the result from the jsca renderer, or an error message in case of any exception.
     */
    tpl.attributePanelJSCACellRenderer = function(data, attrId, columnAttributeGroup, columnRenderer){
        var jsca_value = '';
        try {
            if (data === undefined || data === null) {
                return jsca_value;
            }
            var jsca_renderer = columnRenderer || data.renderer || jsca.columns.simpleRenderer;

            //call the cell renderer.
            if (typeof jsca_renderer === 'string') {
                jsca_renderer = PTC.util.convertStringToFunc(jsca_renderer);
            }
            if (typeof jsca_renderer === 'function') {
                //create a row with item and get function.
                var jsca_row = {
                    item: data
                };
                jsca_row.get = function(id){
                    return data;
                };

                //create row with just id. Needed for renderers.
                var jsca_col = {
                    id: attrId
                };
                jsca_value = jsca_renderer(columnAttributeGroup, jsca_col, jsca_row);
                jsca_value = PTC.debug.addDebugInfo(jsca_value, jsca_col, jsca_row);
            }
        } catch(e) {
            PTC.attributePanel.log.error("Error rendering attribute: "+attrId, e);
            jsca_value = '<span style="color:red;">Error rendering attribute '+attrId+'. Check javascript console for stack trace.</span>';
        }

        return jsca_value;
    };
    return tpl;
};

/**
 *  Calculates the length of the string.
 *  An occurance of '&nbsp;' character is considered with 1 as length.
 *  @param {String/Text}
 *  @return {integer}
 */
PTC.attributePanel.getStringLength=function(string){
  var SPACE_CONSTANT = '&nbsp;';
  var originalStrLen = string.length;
  var regExp = new RegExp(SPACE_CONSTANT,'g');
  var occurenceArray = string.match(regExp);
  if(occurenceArray){
    var totalOccurances = occurenceArray.length;
    // 'space' has 6 characters in it, consider only 1 while calculating length.
    return (originalStrLen-(totalOccurances*5));
  }
  return (originalStrLen);
};

/**
 * PTC.attributePanel.attributeGroup extends Ext.form.FieldSet
 */
Ext.extend(PTC.attributePanel.attributeGroup, Ext.form.FieldSet, {
    /**
     * Sets the CSS "width" property for each attribute-label cell in this component.
     * The label cell is only allowed to take up 1/3 of the combined attribute label/value width.
     * It checks the current length of the label and sets the CSS "width" property to
     * either the current label length or the maximum allowed width.  It also sets the
     * CSS "white-space" property to either "nowrap" if the label is less than than
     * the maximum width or set to "normal" if the label is longer than the maximum width.
     *
     * @name PTC.attributePanel.attributeGroup.setLabelWidths
     * @param {Ext.Component} parentContainer - the component the contains the Field Set
     */
    setLabelWidths: function (parentContainer) {
        var cmp = this.getComponent("dataStore" + this.id);
        if (!cmp || !cmp.store) {
            // because this func is delayed, it could fire after its destroyed or in a bad state
            return;
        }
        try {
            var dataSet = cmp.store.data;

            var widthCache = {};
            var maxColumns = [];
            var i, j;
            // Run through the data (which is very fast) and figure out the largest size label in each column
            for (i = dataSet.items.length; i--;) {
                var cols = dataSet.items[i].data.columns;

                for (j = cols.length; j--;) {
                    var col = cols[j];
                    var l = col.label;

                    // Its valid to have label as space and have only value for the attribute.
                    // If the all labels in a panel have lengths less than length of "&nbsp;" then style was being added
                    // on nbsp label and the rest of the label became vertical. See SPR 2089390 for more details.
                    if (l === '&nbsp;') {
                        continue;
                    }

                    // if maxlabelsizes not defined or length is larger then whatever is in maxlabel
                    if (l) {
                        var currentMax = maxColumns[j];
                        var lengthOfLabel = PTC.attributePanel.getStringLength(l);
                        // for label with '*', the length needs to be consider by adding 2 to it.
                        if(col.asteriskValue){
                           lengthOfLabel = lengthOfLabel + 2;
                        }
                        // if current label is longer in length, then replace current max
                        if (!currentMax || lengthOfLabel > currentMax.length) {
                            maxColumns[j] = {
                                id: col.labelId,
                                length: lengthOfLabel
                            };
                        // if the current label is the same size, then we need to calculate the actual widths of each and
                        // compare to find the right one.
                        } else if (lengthOfLabel === currentMax.length) {
                            var currentMaxWidth = this.getLabelWidth(currentMax.id, widthCache);
                            var potentialMaxWidth = this.getLabelWidth(col.labelId, widthCache);
                            if (potentialMaxWidth > currentMaxWidth) {
                                currentMax.id =  col.labelId;
                            }
                        }
                    }
                }
            }

            // calculate the maximum width for the attribute label/value combo
            var attrColumnWidth = parentContainer.getWidth() / maxColumns.length;
            if (attrColumnWidth === 0) {
                //2155249 Hidden panels cannot be resized because the size is not correct
                return ;
            }
            // the width of the attribute label cell should be a maximum of 1/3 of the label/value combined width
            var maxWidth = Math.round(attrColumnWidth / 3);
            if(parentContainer.renderOnTop  === true) {
                maxWidth = attrColumnWidth; // Equally distribute width for the columns with labels on top
            }

            // iterate through widest columns and apply styling
            for (i = maxColumns.length; i--;) {
                // Some labels may just be whitespace, so will be represented in the maxColumns array as undefined.
                // We can safely skip them.
                if (maxColumns[i]) {
                    var labelId = maxColumns[i].id;
                    var labelWidth = this.getLabelWidth(labelId, widthCache);
                    var dom = Ext.getDom(labelId);
                    var maxed = (labelWidth < maxWidth);
                    if(parentContainer.renderOnTop === true) {
                        dom.style.width = maxWidth + "px";  // width is constant across all the columns
                    } else {
                        dom.style.width = maxed ? labelWidth + "px" : maxWidth + "px";
                    }
                    dom.style.whiteSpace = maxed ? "nowrap" : "normal";
                }
            }
        } catch(e) {
            PTC.attributePanel.log.error('attributes panel cannot reset the widths, the panel is gone');
        }
    },
    /**
     * Returns the length of the label (in pixels).
     * @name PTC.attributePanel.attributeGroup.getLabelWidth
     * @param {String} id - id of dom element to meansure innerHTML of
     * @param {Object} widthCache - cache of label width lookup results
     * @return {Number} the length of the label in pixels
     */
    getLabelWidth: function (id, widthCache) {
        var result = widthCache[id];
        if (!result) {
            var dom = Ext.getDom(id);
            if (!PTC.attributePanel.labelTextMetric) {
                PTC.attributePanel.labelTextMetric = Ext.util.TextMetrics.createInstance(dom);
            }
            result = PTC.attributePanel.labelTextMetric.getWidth(dom.innerHTML);
            widthCache[id] = result;
        }
        return result;
    },

    /**
     * Gets a list of ids of the attributes contained in this group.
     * @name PTC.attributePanel.attributeGroup.getAttributeIDs
     * @return an array of attribute ids
     */
    getAttributeIDs: function(){
        var idList = [];
        var index = 0;
        var _item = this.items.get(0);
        if(_item.id === ("dataStore" + this.id)){
            var dataSet = this.items.get(0).store.data;
            dataSet.each(function(rowDef){
                var allCols = rowDef.data.columns;
                allCols.each(function(col){
                    idList[index] = col.id;
                    index++;
                });
            });
        }
        return idList;
    },
    /**
     * Gets the list of rows.
     * @name PTC.attributePanel.attributeGroup.getRows
     * @return an array of rows
     */
    getRows : function(){
        var dataSet = this.items.get(0).store.data;
        return dataSet;
    },

    /**
     * Gets the row.
     * @name PTC.attributePanel.attributeGroup.getRow
     * @param {Number} index - a record index(Number)
     * @return the row
     */
    getRow : function(index){
        var dataSet = this.items.get(0).store.data;
        return dataSet.get(index);
    },

    /**
     * Remove all rows in the Group.
     * @name PTC.attributePanel.attributeGroup.removeAllRows
     */
    removeAllRows : function(){
        var dataSet = this.items.get(0).store.data;
        dataSet.clear();
    },

    /**
     * Create an Ext.data.Record with one column and adds
     * @name PTC.attributePanel.attributeGroup.addOneColumnRow
     * @param {String} id - the id of the attribute
     * @param {String} label - label of the attribute
     * @param {Object} value - value of the attribute
     */
    addOneColumnRow : function(id, label, value){

        PTC.attributePanel.log.debug("addOneColumnRow : id : " + id + "\tvalue : [" + value + "]\tlabel : " + label);
        var group = this.items.get(0);
        //create a new Record
        var rowRecord = new Ext.data.Record(
            {'allColsInRowHidden':false,
            'columns':[
                {'id':id,
                'colSpan':1,
                'value':value,
                'class':'class com.ptc.core.components.tags.attributePanel.RenderAttributePanelTag$AttributeModel',
                'label':label,
                'labelId':id+(new Date()).getTime(),
                'columnAttributeGroup':group
                }
            ],
            'class':'class com.ptc.core.components.tags.attributePanel.RenderAttributePanelTag$AttributesInRowModel'
            }
        );
        var dataSet = group.store.data;
        //add it
        dataSet.add(rowRecord);
    },

    /**
     * Adds the record
     * @name PTC.attributePanel.attributeGroup.addRowRecord
     * @param {Ext.data.Record} record - the record to be added
     */
    addRowRecord : function(record){
        var dataSet = this.items.get(0).store.data;
        dataSet.add(record);
    },

    /**
     * Return the store attached to this attributeGroup
     * @name PTC.attributePanel.attributeGroup.getStore
     * @return the Ext.data.JsonStore
     */
    getStore : function(){
        return this.items.get(0).store;
    },

    /**
     * Sort the records on the attributeGroup based on First Column's label
     * @name PTC.attributePanel.attributeGroup.sortOnFirstColumn
    */
    sortOnFirstColumn : function (){
        var direction ='ASC';
        var store = this.getStore();
        var custSortFunc = function(r1, r2) {
            var v1 =  r1.data.columns[0].label;
            var v2 =  r2.data.columns[0].label;
            return v1 > v2 ? 1 : (v1 < v2 ? -1 : 0);
        };
        //sort the data
        store.data.sort(direction, custSortFunc);
        if (store.snapshot && store.snapshot != store.data) {
            store.snapshot.sort(direction, custSortFunc);
        }
    },

    /**
     * Inform the group whether the value updates in client are over or not
     * If true, handleHideifNullValue handling will be done as applicable
     * @name PTC.attributePanel.attributeGroup.setClientValueUpdatesComplete
    */
    setClientValueUpdatesComplete : function(value){
        this.clientValueUpdatesComplete=value;
        this.datachangedEventFired = false;
        var remove = this._handleHideifNullValue();
        if(remove){
            //remove this group
            var panel = this.findParentByType(PTC.attributePanel.AttributePanel);
            panel.remove(this);
            PTC.attributePanel.log.debug("setClientValueUpdatesComplete groups2remove : " + this.label);
        }else if(this.datachangedEventFired === false){
            //fire data changed event on store
            var store = this.getStore();
            store.fireEvent('datachanged', store);
        }
    },

    /**
     * @private
     * Hide null value attributes using a filter.
     * If its a single column, then filter is applied
     * @name PTC.attributePanel.attributeGroup._handleHideifNullValueByFilter
     * @return Boolean - applied the filter or not
    */
    _handleHideifNullValueByFilter : function(){

        var applyFilter = true;
        var dataSet = this.getRows();
        dataSet.each(function (rowDef) {
            var allCols = rowDef.data.columns;
             //not a single column group? cannot apply filter
             if(allCols && allCols.length > 1){
                applyFilter = false;
                return applyFilter;
            }
        });
        PTC.attributePanel.log.debug("_handleHideifNullValueByFilter : " + this.label +  "\t"+ applyFilter );
        if(applyFilter){
            var store = this.getStore();
            store.filterBy(function(record){
                var _ret =false;
                if(record.data.columns[0]){
                    var empty_value =  PTC.attributePanel.attributeGroup.Utils.isHideIfNullValue(record.data.columns[0].value);
                    //value is empty, filter it out (return false)
                    _ret = !empty_value ;
                }
                return _ret ;
            });
            //applying filter will internally fire 'datachanged' on store, mark so that its not fired again
            this.datachangedEventFired=true;
        }
        return applyFilter;
    },

    /**
     * @private
     * Hide null value attributes by set attribute label to null.
     * If all the attributes in the row is hidden, remove the row
     * @name PTC.attributePanel.attributeGroup._handleHideifNullValueByLabelUpdate
    */
    _handleHideifNullValueByLabelUpdate : function(){
        var rows2remove = [];
        var dataSet = this.getRows();
        dataSet.each(function (rowDef) {
            var allCols = rowDef.data.columns;
            var remove = true;
            allCols.each(function(col){
               if (PTC.attributePanel.attributeGroup.Utils.isHideIfNullValue(col.value)) {
                    col.label='';
                }else{
                    remove = false;
                }
                PTC.attributePanel.log.debug("_handleHideifNullValueByLabelUpdate : id : " + col.id + "\tvalue : [" + col.value + "]\tlabel : " + col.label);
            });
            if(remove){
                rows2remove.push(rowDef);
            }
        });
        //remove if the all the attributes in the row are hidden
        for(var k = 0;k<rows2remove.length;k++){
            dataSet.remove(rows2remove[k]);
        }
    },

    /**
     * @private
     * Hide null value attributes.
     * If attribute data is null, set attribute label to null
     * If all the attributes are to be hidden in a row, remove the row
     * If there is no row after the hiding, mark this group for removal
     * @name PTC.attributePanel.attributeGroup._handleHideifNullValue
     * @return Boolean - can this group be marked for removal
    */
    _handleHideifNullValue : function(){
        var removeGroup = false;
        if(this.clientValueUpdatesComplete){
            if(this.hideIfNullValueInClient){
                //if more than one row, start hiding
                var appliedFilter = this._handleHideifNullValueByFilter();
                if(!appliedFilter){
                    this._handleHideifNullValueByLabelUpdate();
                }
            }
            //if no rows left out, remove the empty group
            if(this.getRows().length === 0){
                removeGroup=true;
            }
        }
        return removeGroup;
    }
});

/**
 * This is the main attribute panel object.  This will setup the configuration for the panel and
 * When configuring the attribute panel we need to know what page we are on because the panel needs an outer and inner div for rendering.
 *
 * @param {Ext.data.Store} panelData - The data needed to display the attribute panel.  This comes from the server in a json object
 *    pass panelData.useExistingDUniqueDivs=false if creating a new panel on the client.  The Default value is true because most
 *    panels are rendered to an existing DIV
 */
PTC.attributePanel.AttributePanel = function(panelData) {
    var panelItems = [];

    var jcaDebugInfo = PTC.debug.getJCADebugHTML(panelData);

    if (panelData.record) {
        this.populateDataFromRecord(panelData);
    }

    for (var i = 0, l = panelData.groups.length; i < l; i++) {
        // Add jcaDebug information for this attribute panel to each group
        if (jcaDebugInfo) {
            panelData.groups[i].label = panelData.groups[i].label + jcaDebugInfo;
        }
        if (panelData.forceAutoWidth) {
            panelData.groups[i].forceAutoWidth = true;
        }
        panelItems.push(new PTC.attributePanel.attributeGroup(panelData.groups[i]));
    }

    var builderId = "";
    var uniqId = "";
    if (typeof PTC.attributePanel.AttributePanel.ap != 'undefined' && panelData.useExistingDUniqueDivs !== false) {
        builderId = PTC.attributePanel.AttributePanel.ap.builderId();
        uniqId = PTC.attributePanel.AttributePanel.ap.uniqueValue();
    }
    var objectHandle = PTC.wizard.getCurrentObjectHandle();
    var titleDiv = objectHandle + builderId + '__AttributesTablePaneOuter_' + uniqId;
    var fieldsetDiv = objectHandle + builderId + '__AttributesTablePaneInner_' + uniqId;

    var panelConfig = {
        id:titleDiv,
        screenType: panelData.id,
        title: panelData.title,
        items: panelItems,
        //need x-reset class so rich text values will display properly - SPR 2124748
        cls: 'attribute-apanel x-reset',
        storeURL : panelData.storeURL,
        applyTo: panelData.applyTo,
        renderTo: panelData.renderTo,
        existingFormId: panelData.existingFormId,
        monitorResize: true
    };
    if (isIE){
      //panel is not displayed in firefox with this config. Firefox is not displaying border without this anyway.
       //We need this in IE to not display border.
       panelConfig.border = false;
    }


    if(panelData.render !== false) {
        if(panelData.componentType === 'MINI_INFO') {
            //These div are created in doLayout of miniInfo
            panelConfig.applyTo = 'attributesPanel';
            panelConfig.existingFormId = 'attributesPanelInner';
        } else {
            panelConfig.applyTo = titleDiv;
            // The id of outer div.  EXT usually wants the id of the div tag containing the form tag for mainform.
            panelConfig.existingFormId = fieldsetDiv;
            // This is where the fieldsets get rendered.  Usually EXT wants a mainform but it still works with a regular div.
        }
    }

    if(!Ext.getDom(panelConfig.existingFormId)) {

        var div = document.createElement("div");
        div.id = panelConfig.applyTo;

        var innerDiv = document.createElement("div");
        innerDiv.id = panelConfig.existingFormId;

        div.appendChild(innerDiv);
        if (Ext.getDom(panelData.parentID)) {
            Ext.getDom(panelData.parentID).appendChild(div);
        }
    }
    PTC.attributePanel.AttributePanel.superclass.constructor.call(this, panelConfig);
};

PTC.attributePanel.AttributePanel.ap = function() {
    var builder_id = null;

    // private space
    return {
        // public methods
        init: function(panelJSON, builderId, uniqVal) {
           builder_id = builderId;
           unique_val = uniqVal;

           //decode url params that came from server
           if(panelJSON.storeURL.pve === true){
               panelJSON.storeURL.params = PTC.util.decode.paramsForJS(panelJSON.storeURL.params);
               panelJSON.storeURL.pve=undefined;
           }

           // componentDef needs to be passed in for case of nested component.
           var panel = new PTC.attributePanel.AttributePanel(panelJSON);
        },

        builderId : function() {
            return builder_id;
        },

        uniqueValue : function() {
            return unique_val;
        }
    };
}();


/**
 * PTC.attributePanel extends Ext.form.FormPanel.
 *
 * PTC EXT OVERRIDE
 * In our subclass, we override the createForm() and onRender() functions so
 * that we can render the panel inside of the form with the id "mainform" instead on
 * inside an Ext-generated form.  This code is based on example code in http://extjs.com/forum/showthread.php?t=24525.
 */
Ext.extend(PTC.attributePanel.AttributePanel, Ext.form.FormPanel, {
        existingFormId: null,

    createForm: function() {
        var config = Ext.applyIf({listeners: {}}, this.initialConfig);
        return new Ext.form.BasicForm(this.initialConfig.existingFormId, config);
    },

    /**
     * Note that onRender method defined for FormPanel is automatically executed
     * during form dom rendering. This is executed before component is unhidden
     * & before render event is fired.
     */
    onRender: function(ct, position) {
       PTC.attributePanel.fireEvent("beforeRender", this);
       this.initFields();

       //hide attributes that has null value
       this._handleHideifNullValue();

       // In IE this is not null and then a form is then attempted to be created
       if (isIE) {
           this.bodyCfg = null;
       }

       Ext.FormPanel.superclass.onRender.call(this, ct, position);

       // This is added so that a extra form is not created and thus using our mainform.
       if (!this.existingFormId) {
            var o = {
                tag: 'form',
                method : this.method || 'POST',
                id : this.formId || Ext.id()
            };
            if(this.fileUpload) {
                o.enctype = 'multipart/form-data';
            }
            this.form.initEl(this.body.createChild(o));
        }
       //need this since the panel does not have frame and render attribute panel does not work without this.
       var header = Ext.getCmp(this.id).header;
       if (header) {
           Ext.getCmp(this.id).header.setDisplayed(false);
       }
    },

    /**
     * afterRender method defined for FormPanel is automatically executed
     * after rendering is completed. Put any generic post render logic here.
     */
    afterRender: function(ct) {
       PTC.attributePanel.AttributePanel.superclass.afterRender.apply(this, arguments);
       PTC.attributePanel.fireEvent("afterRender", this);
    },

    /**
     * @private
     * Hide null value attributes.
     * If any group doesn't have rows after the hiding, remove those empty groups
     * @name PTC.attributePanel.AttributePanel._handleHideifNullValue
    */
    _handleHideifNullValue:function(){

        var groups = this.getGroups();
        var groups2remove = [];
        groups.each(function(group){
            var removeGrp = group._handleHideifNullValue();
            if(removeGrp){
                PTC.attributePanel.log.debug("groups2remove : " + group.label);
                groups2remove.push(group);
            }
        });
        //remove empty groups (has no row)
        for(var j= 0;j<groups2remove.length;j++){
            groups.remove(groups2remove[j]);
        }
    },

   /**
     * Gets the attribute with the given id.
     * @name PTC.attributePanel.AttributePanel.getAttributeValue
     * @param {Object} id - the id of an attribute
     * @return the value of the attribute with the given id. Currently an HTML string or an object like {gui: {...}, renderer: rendererFunction}.
     */
    getAttributeValue: function(id){
        var result;

        this.iterateAttributes(function(col){
            if (col.id === id) {
                result = col.value;
                return result;
            }
        });
        return result;
    },

   /**
     * Gets the group that contain the attribute with the given id.
     * @name PTC.attributePanel.AttributePanel.getAttributeGroup
     * @param {String} id - the id of an attribute
     * @return {PTC.attributePanel.attributeGroup} the group
     */
    getAttributeGroup: function(id){
        var matchingGroup = null;
        this.items.each(function(item){
            var group = item.getComponent("dataStore" + item.id);
            var dataSet = group.store.data;
            dataSet.each(function(rowDef){
                var allCols = rowDef.data.columns;
                allCols.each(function(col){
                    if(id === col.id){
                        matchingGroup = group;
                        return false;
                    }
                });
                if(matchingGroup !== null){
                    //found match, return
                    return false;
                }
            });
            if(matchingGroup !== null){
                //found match, return
                return false;
            }
        });
        return matchingGroup;
    },

    /**
     * Sets the value of the attribute with the given id to the given value.
     * @name getAttributeValue.setAttributeValue
     * @param {String} id - the id of attribute
     * @param {Object} value
     * @return true if attribute was set, false if attribute was not found
     */
    setAttributeValue: function(id, value){
        var returnVal = false;
        this.iterateAttributes(function(col){
            if (col.id === id) {
               //SPR  2040141: make sure all attributes are properly encoded
               col.value =  PTC.util.HTMLEncoder.handleAdjacentSpaces(value);
               returnVal = true;
               return true;
            }
        });
        return returnVal;
    },

    /**
     * Update the value of the attribute with the given id to the given value.
     * @name getAttributeValue.setAttributeValue
     * @param {String} id - the id of attribute
     * @param {Object} value - Currently the jsca.columns.simpleRenderer is used for all attributes. This renderer can handle a String value or an object with gui and renderer attributes like {gui: {...}, renderer: rendererFunction}.
     * @param {String} attrType - Type of an attribute. It could be string, real, integer, boolean etc.
     * @param {Object] options - Extra options which can be set on gui component
     * @return true if attribute was set, false if attribute was not found
     */
    updateAttributeValue: function(id, value, attrType, options){
        var returnVal = false;
        this.iterateAttributes(function(col){
            if (col.id === id) {
                if ("true"  !== col.valueHidden) {
                    col.value =  PTC.attribute.gui.update(col.value, value, attrType, options);
                    returnVal = true;
                    return true;
                }
                else {
                    PTC.attributePanel.log.debug("updateAttributeValue : Can't update value for hidden-value attribute with id " + id);
                }
            }
        });
        return returnVal;
    },
    /**
     * Operates callback function on each store cell attribute i.e. on each attribute in the panel.
     * @param {Object} callback
     */
    iterateAttributes: function(callback) {
        this.items.each(function(item) {
            var dataSet = item.getComponent("dataStore" + item.id).store.data;
            dataSet.each( function(rowDef) {
                var allCols = rowDef.data.columns;
                allCols.each(callback);
            });
        });
    },

    /**
     * Populate values from an ext Record
     *
     * @param {Object} config panel config containing group configs and record
     */
    populateDataFromRecord: function(config) {
        var rec = config.record;
        var i = config.groups.length;
        while (i--) {
            var g = config.groups[i];
            var j = g.rows.length;
            while (j--) {
                var row = g.rows[j];
                var k = row.columns.length;
                while (k--) {
                    var cell = row.columns[k];
                    cell.value = rec.get(cell.id);
                }
            }
        }
    },

    /**
     * Gets a list of the ids of the attributes contained in the attribute panel from all groups.
     * @name PTC.attributePanel.AttributePanel.getAttributeIDs
     * @return an array of attribute ids
     */
    getAttributeIDs: function(){
        var idList = [];
        var index = 0;
        this.items.each(function(item){
            var dataSet = item.getComponent("dataStore" + item.id).store.data;
            dataSet.each(function(rowDef){
                var allCols = rowDef.data.columns;
                allCols.each(function(col){
                    idList[index] = col.id;
                    index++;
                });
            });
        });
        return idList;
    },

    /**
     * Gets a list of ids of the groups contained in the attribute panel
     * @name PTC.attributePanel.AttributePanel.getGroupIDs
     * @return an array of group ids
     */
    getGroupIDs: function(){
        var idList = [];
        var index = 0;
        this.items.each(function(item){
            idList[index] = item.id;
            index++;
        });
        return idList;
    },

    /**
     * Gets the group.
     * @name PTC.attributePanel.AttributePanel.getGroup
     * @param {String} id - the id of the group
     * @return {PTC.attributePanel.attributeGroup} the group
     */
    getGroup: function(groupId){
        var group;
        this.items.each(function(item){
            if(item.id === groupId){
                group=item;
                return;
            }
        });
        return group;
    },

    /**
     * Get the Group that has the provided batch attribute
     * @name PTC.attributePanel.AttributePanel.getGroupWithBatchAttr
     * @param {String} batchAttrId - id of the batch attribute.
     * @return group {PTC.attributePanel.attributeGroup}
    */
    getGroupWithBatchAttr : function (batchAttrId){
        var groups = this.getGroups();
        var result;
        groups.each(function(group){
            if(batchAttrId === group.batchAttrId){
                result = group;
                return;
            }
        });
        return result;
    },

    /**
     * Gets a list of the groups of contained in the attribute panel
     * @name PTC.attributePanel.AttributePanel.getGroups
     * @return Array of groups {PTC.attributePanel.attributeGroup}
     */
    getGroups: function(){
        return this.items;
    },

    /**
     * Add a group.
     * @name PTC.attributePanel.AttributePanel.addGroup
     * @param {PTC.attributePanel.attributeGroup} group - the group
     */
    addGroup: function(group){
        this.items.add(group);
    },

    /**
     * If an onChange event occurs inside the attribute panel, then try to save the changed value into
     * the attribute panel store so that we can later store the value back into the grid when the details popup is closed.
     * Since the edit components displayed in the wizards have not all been converted to javascript
     * or to ext the default save handling is simply saving the innerHTML
     * of the component into the store whenever the change event is fired.
     * Components which are converted or are being developed new can include their own change event handlers
     * that save only the value. The change event handles have been hooked up at the attribute panel level
     * rather than at the individual component level as the Standards specify that these events should
     * propogate up and this works for Firefox and Chrome.
     *
     * Individual Cell components can customize how the value gets updated in the rows data,
     * simply specify an updateCellValue(cell, value) function on the cell object to have it override
     * the default behavior.  The value passed in is the value typed in by the user.  The default cell
     * objects follow the pattern of having the cell.gui.value be the attribute to display
     *
     * @see PTC.wizard.saveTableData.domChangeEventListener
     * @param {Ext.EventObject} evt - the event (change, keyup)
     * @param {DOMElement} element - dom element that was just changed
     */
    domChangeEventListener : function(evt, element){
        var tag = element.tagName.toLowerCase();
        if (tag === 'input' || tag === 'select' || tag === 'textarea') {
            var panel = this;
            var cell_TD = getParentNodeByTag(element, 'TD');
            var attrId = cell_TD.getAttribute('attrId');
            var cell = panel.getAttributeValue(attrId);
            if (cell) {
                PTC.wizard.saveTableData.saveNewValueToCell(element, cell, cell_TD);
            }
        }
    }
});

/**
 * Returns the Attribute Panel that the child element is contained in.
 * @param {DOMElement} childElement A dom element or an id of a dom element within the Attribute Panel
 */
PTC.attributePanel.findParentAttributePanel = function (childElement) {
    var attributePanel;

    var childEl = Ext.get(childElement);
    if(childEl) {
        var attrPanelEl = childEl.findParent('div.attribute-apanel');

        if(attrPanelEl) {
            attributePanel = Ext.getCmp(attrPanelEl.id);
        }
    }
    return attributePanel;
};

/**
 * @class
 * Utility methods on PTC.attributePanel
 */
PTC.attributePanel.Utils = function(){

    return {

        /**
         * Use the storeURL of the provided attributePanel to go to server with attributeIDArray & windchillObjectType
         * also as request parameters. The respective builder will create an AttributePanelConfig on the fly from the
         * provided request paramaters. In th client, a dynamic attribute panel will be created from the response.
         * callBackFunction will be invoked passing this dynamic attribute panel as an argument.
         * @name PTC.attributePanel.Utils.createDynamicAttributePanel
         * @param {PTC.attributePanel} attributePanel - existing attributePanel
         * @param {String} attributeIDArray - array of attribute ids.
         * @param {function} callBackFunction - The function invoked after the dynamic attributePanel is created.
         * @param {Object} params - request paramater.
         */
        createDynamicAttributePanel : function (attributePanel, attributeIDArray, callBackFunction, params){

            var successFunction = function(response ) {
                var panelData = Ext.util.JSON.decode(response.responseText.trim());
                panelData.id = attributePanel.id +'_dynamic';    //provide an id
                panelData.render=false;    //don't render the panel
                panelData.useExistingDUniqueDivs=false;    //don't mess the existing panel
                //create the panel
                var dynamic_attrpanel = new PTC.attributePanel.AttributePanel(panelData);
                if(typeof callBackFunction == 'function'){
                    //invoke callBackFunction
                    callBackFunction(dynamic_attrpanel);
                }
            };

            var params_combo = (params !== undefined) ? params : {};
            params_combo.dynamicProperty =  attributeIDArray.toString(); //pass the attribute ids

            var  ajax_url = getBaseHref() + Ext.urlAppend(attributePanel.storeURL.url, Ext.urlEncode(attributePanel.storeURL.params));
            var options = {
                method: 'get',
                asynchronous: true,         //make it async
                requestHeaders : ['Accept', 'application/json'],          //require JSON
                onSuccess: successFunction,
                parameters: params_combo
            };
            requestHandler.doRequest(ajax_url,options);
        },

        /**
         * Get the attribute panel component's id
         * @name PTC.attributePanel.Utils.getAttributePanelCmpId
         * @param {String} builderId
         * @param {String} attrPanelConfigId
         * @param {String} contextObjectType - the Windchill type of the object that is being shown
         * @return {PTC.attributePanel}
         */
        getAttributePanelCmpId : function (builderId, attrPanelConfigId, contextObjectType) {
            return PTC.wizard.getCurrentObjectHandle() +
                      attrPanelConfigId+ '_' + builderId + '__AttributesTablePaneOuter_' + 
                      (PTC.isDefined(contextObjectType) ? contextObjectType : '');
        },

        /**
         * Get the attribute panel component
         * @name PTC.attributePanel.Utils.getAttributePanel
         * @param {String} builderId
         * @param {String} attrPanelConfigId
         * @param {String} contextObjectType - the Windchill type of the object that is being shown
         * @return {PTC.attributePanel}
         */
        getAttributePanel : function (builderId, attrPanelConfigId, contextObjectType) {
            return Ext.getCmp(PTC.attributePanel.Utils.getAttributePanelCmpId(builderId, attrPanelConfigId, contextObjectType));
        }
    };
}();

/**
 * @class
 * Utility methods on PTC.attributePanel.attributeGroup
 */
 PTC.attributePanel.attributeGroup.Utils = function(){

    return {
        /**
         * Check whether the data is candidate for hideIfNullValue
         * @param {Object} data
         * @return {boolean}
         */
        isHideIfNullValue : function (data){
            var value = data;
            if(data && data.gui){
                if(PTC.isDefined(data.gui.html)){
                    value = data.gui.html;
                }else if(PTC.isDefined(data.gui.displayValue)){
                    value = data.gui.displayValue;
                }else if(PTC.isDefined(data.gui.value)){
                    value = data.gui.value;
                }else {
                    value = data.gui.rawValue;
                }
            }
             if(typeof value === 'string'){
                value=value.trim();
            }
            if(!value || value === '' || value === '&nbsp;'){
                return true;
            }
            return false;
        }
    };
}();
Ext.reg("attributePanel", PTC.attributePanel.AttributePanel);


Ext.namespace("PTC.auditing");

/**
 *
 * @namespace
 * a namespace for functions that relate to the autosuggest combobox
 */
PTC.autosuggest = {log:  log4javascript.getLogger("PTC.autosuggest")};

PTC.autosuggest.suggestBoxHandler = function() {
    // set of suggest text box ids that will eventually be renderered
    var suggestIds = {};

    // maps hidden field name to suggest box component
    var suggestBoxes = {};

    // maps hidden field name to change listener function to add once the component registers itself
    var listeners = {};

    return {
    /**
     * Register listener once the suggest box component is registered.  Ext.ComponentMgr.onAvailable can not be used,
     * because we wish to do this based on the hidden id and not the text field id.  The text field id might be
     * generated and not easily obtained.
     *
     * @param {String} hiddenId - the hidden field id
     * @param {Function} listener - the change listener
     */
    addSuggestBoxValueListener: function(hiddenId, listener) {
        if (typeof listener === 'function') {
            // if it has been registered already, then execute the listener immediately
                var suggestBox = suggestBoxes[hiddenId];
            if (suggestBox !== undefined) {
                    suggestBox.on('select', listener);
            } else {
                    listeners[hiddenId] = listener;
            }
        }
    },

    registerSuggestBox: function(suggestBox) {
            suggestBoxes[suggestBox.hiddenName] = suggestBox;
            var listener = listeners[suggestBox.hiddenName];
        if (listener !== undefined) {
                suggestBox.on('select', listener);
        }
        },

        addSuggestBoxId: function(id) {
            suggestIds[id] = true;
        },

        isAutoSuggest: function(id) {
            return suggestIds[id] === true;
    }
};
}();

/**
 * A combo box that provides auto suggest support.
 *
 * @class PTC.autosuggest.SuggestBox
 * @extends Ext.form.ComboBox
 * @property {Object} storeConfig - addition store config options
 */
PTC.autosuggest.SuggestBox = Ext.extend(Ext.form.ComboBox, {

    /**
     * Override initComponent to recreate the underlying DOM element if required and if the configuration allows
     * This method is called by the constructor of the superclass (Ext.Component),  after the preInitComponent call
     * where it may have  deleted any
     * old SuggestBox component constructed earlier during rendering and registered with the same id. While doing that
     * the underlying DOM input element to which
     * the Suggest box applies, will also get deleted, screwing up the working of this constructor call ( there is an exception
     * in the Ext.Component.applyToMarkup() call). Such double calling of the SuggestBox constructor, while weird, seems to be
     * a fact of life during Page load owing to the way that a SuggestBox is constructed using markup and an Ext
     * component that applies to the markup. (SPR 2250154, 2214495)
     */
    initComponent: function() {
        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- Start initComponent for ' + this.id);
        PTC.autosuggest.SuggestBox.superclass.initComponent.call(this);
        if (this.hasOwnProperty("id") && this.hasOwnProperty("applyTo")) {
            var ele = Ext.get(this.id);
            var spanEl;
            if (this.underlyingDOMElementSpanId) {
                spanEl = Ext.get(this.underlyingDOMElementSpanId);
            }
            if (!ele)  {
                // This case will only ever be satisfied if the constructor gets called a second time in the rendering of the page
                // In this case preInitComponent() which gets called before this method, will have deleted the Ext object constructed
                // in the first constructor call. This will in turn result in the <INPUT> markup received from the server to be deleted
                // and this second construction will be unsuccessful resulting in no text box being shown (SPR 2250154, 2214495). The
                //following code tries to reconstruct that deleted DOM element using the htmlOfUnderlyingDOMelement field received in the
                //config of the constructor, and available as a field of this.
                if (spanEl && spanEl.dom ) {
                    if (this.htmlOfUnderlyingDOMelement) {
                        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- Inserting HTML for underlying DOM element of ' + this.id);
                        spanEl.dom.innerHTML = this.htmlOfUnderlyingDOMelement;
                    }
                    else {
                        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- ERROR !!! No HTML received for underlying DOM element of ' + this.id);

                    }
                    //This is a call to check if ele indeed got created, and spew out some log messages if it did or didn't
                    // It has only debug value, and could arguably be removed - may be not.
                    ele =  Ext.get(this.id);
                    if (!ele) {
                        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- DOM element didnt get  created yet !!! for ' + this.id);
                    }
                    else {
                        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- Successfully recreated DOM element for ' + this.id);
                    }
                }
                else {
                    PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- No  spanEl or spanEl.dom !!! for ' + this.id);
                }

            }
        }
        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- End initComponent for ' + this.id + '\n');
    },

    initEvents: Ext.form.ComboBox.prototype.initEvents.createSequence(function () {
        this.mon(this.el, {
            cut: this.onCutPaste,
            paste: this.onCutPaste,
            scope: this
        });
    }),

    onCutPaste: function () {
        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- Start onCutPaste for ' + this.id);
        if (this.editable !== false && this.readOnly !== true) {
            // â€śonKeyUpâ€? function stores the last key pressed against â€śthis.lastKeyâ€?, so when Cut/Paste is performed using context menu it should get cleared (as there is no key pressed).
            delete this.lastKey;
            // dqTask is a DelayedTask with a callback function to execute a query to get the suggest result.  
            this.dqTask.delay(this.queryDelay);
        }
        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- End onCutPaste for ' + this.id);
    },

    //Override applyToMarkup for the noble task of putting log statements
    applyToMarkup: function(applyTo) {
        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- Start applyToMarkup for ' + this.id);
        PTC.autosuggest.SuggestBox.superclass.applyToMarkup.call(this,this.id);
        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- End applyToMarkup for ' + this.id);

    },
    /**
     * This is the SuggestBox constructor. It is what is called by the java side to tell the browser to create this object. After setting
     * values it received in the config object, it goes on to call the superclass (Ext.Component) constructor, which performs
     * the bulk of the construction lifecycle - preInitComponent, initComponent, and finally applyToMarkup.
     */
    constructor: function(suggestConfig) {
        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- Start constructor for ' + suggestConfig.id);
        Ext.applyIf(suggestConfig.storeConfig, {
            proxy: new Ext.data.HttpProxy({
                url: 'servlet/SuggestServlet',
                restful: true
            }),
            reader: new Ext.data.JsonReader({
                idProperty: 'valueText',
                root: 'results',
                totalProperty: 'totalCount',
                successProperty: 'success',
                fields: [
                    {name: 'valueText'},
                    {name: 'displayText'},
                    {name: 'additionalText'}
                ]
            }),
            listeners: {'beforeload' : function(store) {
                    if (store.proxy.activeRequest && store.proxy.activeRequest.read && store.proxy.activeRequest.read.conn) {
                        //SPR 2183816 kill any previous request, in case an earlier request were to be slower, we don't want earlier results showing
                        requestHandler.abort(store.proxy.activeRequest.read.conn);
                    }
                }
            }
        });

        var resultTpl = new Ext.XTemplate(
            '<tpl for="."><div id="autoSuggestEntry_{valueText}" ext:qtip="{suggestDisplayText}<tpl if="additionalText"> ({additionalText})</tpl>" class="x-combo-list-item">{suggestDisplayText}<tpl if="additionalText"> ({additionalText})</tpl></div></tpl>',
            {
                compiled: true,
                disableFormats: true
            }
        );

        Ext.applyIf(suggestConfig, {
            store: new Ext.data.Store(suggestConfig.storeConfig),
            displayField: 'displayText',
            valueField: 'valueText',
            submitValue: true,
            loadingText: bundleHandler.get('com.ptc.core.ui.tableRB.SEARCH_IN_PROGRESS'),
            minChars: 3,
            queryDelay: 600, // 0.6s
            resizable: true,
            selectOnFocus: true,
            forceSelection: true,
            minListWidth: 300,
            hideTrigger: true,
            tpl: resultTpl,
            listeners: {
                'afterrender' : function(component) {
                    // remove Ext styling after render to revert to browser default
                    var autoSuggestField = component.getEl();
                    autoSuggestField.removeClass('x-form-text');
                    autoSuggestField.parent().addClass('autoSuggestField-wrap');
                },
                'beforeselect' : function (component, record) {
                    // make sure empty and too many items messages can not be selected.
                    return Ext.isDefined(record.data.valueText) && record.data.valueText !== '';
                },
                'focus' : function(component) {
                    // remove Ext styling on focus to keep the browser default
                    component.getEl().removeClass('x-form-focus');
                    // update the last selection text on focus in case a new value has been selected using a picker
                    this.lastSelectionText = component.el.dom.value;
                },
                'select' : function(component) {
                    // It tries to apply the focus style during select but after this is called.
                    // Need to wait a second before calling the remove.
                    (function(){ component.getEl().removeClass('x-form-focus'); }).defer(1);

                    //B-91888 so value is stored back to panel/table store
                    PTC.wizard.saveTableData.callDomChangeListener(component.el.dom);
                }
            }
        });

        PTC.autosuggest.SuggestBox.superclass.constructor.call(this, suggestConfig);
        PTC.autosuggest.suggestBoxHandler.registerSuggestBox(this);

        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- End constructor for ' + suggestConfig.id);

    },
    //Override destroy for the noble task of putting log statements
    destroy: function() {

        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- Start Destroyer for ' + this.id);
        PTC.autosuggest.SuggestBox.superclass.destroy.call(this);
        PTC.autosuggest.log.debug('PTC.autosuggest.SuggestBox- End Destroyer for ' + this.id);

    },

    /**
     * Add a function to the combo box to find out if there is more than one record that could be found 
     */
    hasMultipleRecords: function(prop, value) {
        var count = 0;
        if (this.store.getCount() > 0) {
            this.store.each(function(r){
               if (r.data[prop] == value) {
                   count++;
                   if (count > 1) {
                       //returning false breaks us out of the each loop and stops processing more records, 
                       //it doesn't return from the hasMultipleRecords function, only from the anonymous 
                       //function being used by each(), we don't need to keep going once we've found 2 records
                       return false; 
                   }
               }
            });
        }
        return count > 1;
    },

    /**
     * SPR 4449652 When there are two values with the same display value you can never select the second one
     * because assert value replaces it with the first one when it is called. Only call assert value if there
     * is only one possible match in the store
     */
    beforeBlur : function() {
        if (!this.hasMultipleRecords(this.displayField, this.getRawValue())) {
            this.assertValue();
        }
    }
});


