var myCalendarWindow;

function newCalendarWindow(evnt, url, moreUrlInfo) {
    var properties = "left=" + (evnt.screenX + 20);
    properties += ",top=" + (evnt.screenY + 1);
    properties += ",dependent=1,titlebar=0,resizable=no,";
    properties += moreUrlInfo + ", location=0, fullscreen=0, channelmode=0,directories=0, menubar=0,scrollbars=0, status=0,toolbar=0";

    if(isWf()) {
        myCalendarWindow = wfWindowOpen(url, 'cal', properties);
        PTC.Calendar.initializeCalendarPicker(myCalendarWindow);        
    } else {
        myCalendarWindow = wfWindowOpen(url, 'cal', properties);
        // defer the call to prevent chrome frame (GCF) from crashing - SPR 2133087
        PTC.Calendar.initializeCalendarPicker.defer(200, PTC.Calendar, [myCalendarWindow, url]);
    }
}

function getLastDayOfMonth(targetMonth, targetYear) {
    var dayList = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];

    if(((targetYear % 4 === 0) && (targetYear % 100 !== 0)) || (targetYear % 400 === 0)) {
        dayList[1] = 29;
    }

    if(targetMonth === 0) {
        targetMonth = 12;
    }

    return dayList[(targetMonth - 1)];
}

function formatReportDate(formStr) {
    if(formStr === 0) {
        formStr = 12;
    }

    var outputStr = formStr;

    if(outputStr.length == 1) {
        outputStr = "0" + outputStr;
    }

    return outputStr;
}

/**
 * Calendar object that contains convenience methods to support the Date Input Component
 * @namespace
 */
PTC.Calendar = {
    
    /**
     * Returns the HTML input field for a particular instance of the date input component.
     *
     * @param {HTMLElement}calendarPicker - the calendar picker (image) that's paired with date input field
     */
    getDateInputField: function (calendarPicker) {
        var dateInputField;

        if(calendarPicker) {
            var sibling = calendarPicker.previousSibling;
            var siblingCount = 1;
            
            // find the input field that's related to this instance of the calendar picker.
            // The input field should not be any farther than 4 siblings away.
            while(sibling && siblingCount <= 4) {
                
                // check if the sibling is the date input field
                if(sibling.tagName && sibling.tagName.toUpperCase() === 'INPUT' && 
                    sibling.type && sibling.type.toLowerCase() === 'text') {
                    dateInputField = sibling;
                    break;
                }
                
                // if the date input field was not found, check the next sibling
                sibling = sibling.previousSibling;
                siblingCount++;
            }
            
            // if the date input field was not found, get the first text input field starting from the 
            // calendar pickers parent
            if (!dateInputField && calendarPicker.parentNode) {
                var inputFields = calendarPicker.parentNode.getElementsByTagName('input');
                for (var i = 0; i < inputFields.length; i++) {
                    if (inputFields[i].type.toLowerCase() === 'text') {
                        dateInputField = inputFields[i];
                        break;
                    }
                }
            }
        }
        
        return dateInputField;
    },
    
    /**
     * Sets the URL on the calendar window and sets the opener property to itself if it's not already defined
     * @private
     */
    initializeCalendarPicker: function (calendarWindow, url) {
        if(url) {
            calendarWindow.location.href = url;
        }

        if(calendarWindow && !calendarWindow.opener) {
            calendarWindow.opener = self;
        }        
    }
};


