        PTC.charting._setFormValue(form, chartIndex, 'displayValueCount', chartConfig.displayValueCount);
        PTC.charting._setFormValue(form, chartIndex, 'fontSize', chartConfig.fontSize);
        PTC.charting._setFormValue(form, chartIndex, 'horizontalAxisLabels', chartConfig.horizontalAxisLabels);
        PTC.charting._setFormValue(form, chartIndex, 'reportTemplateOid', chartConfig.reportTemplateOid);
        PTC.charting._setFormValue(form, chartIndex, 'savedChartLoadedOid', chartConfig.savedChartLoadedOid);
        PTC.charting._setFormValue(form, chartIndex, 'savedChartName', chartConfig.savedChartName);
