        PTC.charting._setFormValue(form, chartIndex, 'showDataLabels', chartConfig.showDataLabels);
        PTC.charting._setFormValue(form, chartIndex, 'showLegend', chartConfig.showLegend);
        PTC.charting._setFormValue(form, chartIndex, 'showPieAsDonut', chartConfig.showPieAsDonut);
        PTC.charting._setFormValue(form, chartIndex, 'showTooltips', chartConfig.showTooltips);
        PTC.charting._setFormValue(form, chartIndex, 'showXAxisGrid', chartConfig.showXAxisGrid);
        PTC.charting._setFormValue(form, chartIndex, 'showYAxisGrid', chartConfig.showYAxisGrid);
        PTC.charting._setFormValue(form, chartIndex, 'tableId', chartConfig.tableId);
        PTC.charting._setFormValue(form, chartIndex, 'xField', chartConfig.xField);
        PTC.charting._setFormValue(form, chartIndex, 'xFieldDataType', chartConfig.xFieldDataType);
        PTC.charting._setFormValue(form, chartIndex, 'xFieldLabel', chartConfig.xFieldLabel);
        PTC.charting._setFormValue(form, chartIndex, 'yField', chartConfig.yField);
        PTC.charting._setFormValue(form, chartIndex, 'yFieldDataType', chartConfig.yFieldDataType);
        PTC.charting._setFormValue(form, chartIndex, 'yFieldLabel', chartConfig.yFieldLabel);
        
        var chartButton = Ext.getCmp(chartConfig.chartType + chartIndex);
        if (chartButton) {
            chartButton.toggle(true);
        }
        PTC.charting._manageChartButtons(chartIndex, false);
        PTC.charting._setChartOptions(chartConfig.chartType, chartIndex);
        PTC.charting._updateChartPreview(chartIndex, true);
