/**
 * @private
 * Format the text for saved chart menu
 */
PTC.charting._getSaveChartMenuText = function(oid, displayText, toolTip, deleteTooltip, chartIndex, disabled){
    var href = PTC.jslint.SCRIPT_URL_STRING + 'PTC.charting._getSavedChartData("' + oid + '","' + chartIndex + '");';
    displayText = PTC.util.HTMLEncoder.encodeForHTMLContent(displayText);
    var display = '<table ><tr><td >';
    if (disabled) {
        display += '<div id="savedChartMenu' + oid + '" class="x-menu-list-item x-item-disabled" style="width:225px;">';
        href = '"' + PTC.jslint.SCRIPT_URL_STRING + 'var abc = doNothing();"';
    }
    else {
        display += '<div id="savedChartMenu' + oid + '" class="x-menu-list-item" style="width:225px;">';
    }
    
    display += '<div id="savedChartMenu' + oid + '" class="x-menu-list-item" style="width:225px;">';
    if (toolTip === '') {
        display += '<a id="load' + displayText + '" href=' + href + '>' + displayText + '</a></div>';
    }
    else {
        display += '<a  ext:qtip="' + toolTip + '" href=' + href + '>' + displayText + '</a></div>';
    }
    display += '</td><td align="right">';
    display += '<a id="delete' + displayText + '" href=javascript:PTC.charting._deleteSavedChartData("' + oid + '","' + chartIndex + '"); >' + '<img ext:qtip="' + deleteTooltip + '" height="9" width="9" BORDER=0 src="netmarkets/images/delete9x9.png"/></a>';
    display += '</td></tr></table>';
    return display;
};

/**
 * @private
 * Save the chart to the database
 */
PTC.charting._saveChartSettings = function(chartIndex, newChartName, saveType){
    var form = PTC.charting._getForm(chartIndex);
    var tableId = form.findField('tableId' + chartIndex).getValue();
    var reportTemplateOid = form.findField('reportTemplateOid' + chartIndex).getValue();
    var savedChartLoadedOid = form.findField('savedChartLoadedOid' + chartIndex).getValue();
    // Clear form variables that don't apply in Save As
    if (saveType == "saveAs") {
        form.findField('savedChartLoadedOid' + chartIndex).setValue("");
        form.findField('savedReportOid' + chartIndex).setValue("");
        savedChartLoadedOid = "";
        PTC.charting._getChartConfigFromForm(chartIndex);
    }
    // Don't save the chart data with the saved chart since chart is always generated with the latest data
    var saveChartData = form.findField('chartData' + chartIndex).getValue();
    form.findField('chartData' + chartIndex).setValue(null); // don't save chart data to database
    var formData = Ext.Ajax.serializeForm(Ext.getDom('chartSettingsForm' + chartIndex));
    form.findField('chartData' + chartIndex).setValue(saveChartData);
    
    Ext.Ajax.request({
        url: getBaseHref() + "netmarkets/jsp/components/charts/saveChartSettings.jsp",
        success: PTC.charting._processSaveChartRequest,
        faulure: PTC.charting._processFailedRequest,
        params: {
            chartIndex: chartIndex,
            tableId: tableId,
            reportTemplateOid: reportTemplateOid,
            savedChartLoadedOid: savedChartLoadedOid,
            newChartName: newChartName,
            saveType: saveType,
            saveWithReport: false,
            formData: formData,
            chartOptions: PTC.charting.chartOptions
        }
    });
};

/**
 * @private
 * Save the chart to the database
 */
PTC.charting._saveChartSettingsWithReport = function(newOrModify, thisSavedReportOid){

    Ext.Ajax.request({
        url: getBaseHref() + "netmarkets/jsp/components/charts/saveChartSettings.jsp",
        success: PTC.charting._processSaveChartRequest,
        faulure: PTC.charting._processFailedRequest,
        params: {
            saveWithReport: true,
            newOrModify: newOrModify,
            thisSavedReportOid: thisSavedReportOid,
            chartOptions: PTC.charting.chartOptions
        }
    });
};

/**
 * @private
 * Process user request to save a chart
 */
PTC.charting._processSaveChartRequest = function(response, options){
    var responseJSON = Ext.util.JSON.decode(response.responseText);
    var form = PTC.charting._getForm(options.params.chartIndex);
    var saveWithReport = options.params.saveWithReport;
    var success = true;
    var errorMessage = null;
    var tokens = null;
    var chartOptionsIndex = null;
    var savedReportOid = null;
    var savedChartLoadedOid = null;
    for (var key in responseJSON) {
        if (responseJSON.hasOwnProperty(key)) {
            var name = decodeURIComponent(responseJSON[key].name).replace(/\+/g, ' ');
            var value = decodeURIComponent(responseJSON[key].value).replace(/\+/g, ' ');
            if (name == 'success') {
                if (value == 'true') {
                    success = true;
                }
                else {
                    success = false;
                }
            }
            else if (name == 'errorMessage') {
                errorMessage = value;
                errorMessage = errorMessage.replace(/\s/g, '&nbsp;');
            }
            else if (name == 'savedChartLoadedOid') {
                form.findField('savedChartLoadedOid' + options.params.chartIndex).setValue(value);
            }
            else if (saveWithReport === true) {
                tokens = name.split("|");
                if (name.startsWith("savedReportOid")) {
                    PTC.charting._modifyChartOption(tokens[1], tokens[0], value);
                    PTC.charting._modifyChartOption(tokens[1], "chartIndex", tokens[1]);
                }
                else if (name.startsWith("savedChartLoadedOid")) {
                    PTC.charting._modifyChartOption(tokens[1], tokens[0], value);
                }
                else if (name.startsWith("savedChartName")) {
                    PTC.charting._modifyChartOption(tokens[1], tokens[0], value);
                }
            }
        }
    }
    
    if (success === true) {
        PTC.charting._getSavedChartsMenuData(options.params.chartIndex);
        if (!saveWithReport) {
            var title = bundleHandler.get('com.ptc.core.components.chart.chartResource.MESSAGE_TITLE_SAVE_SUCCESSFUL');
            var message = bundleHandler.getBundleStringAndInserts('com.ptc.core.components.chart.chartResource.MESSAGE_SAVE_SUCCESSFUL', 
                [PTC.util.HTMLEncoder.encodeForHTMLContent(options.params.newChartName)]);
            PTC.messaging.showInlineMessage([{
                MessageTitle: title,
                Messages: [message],
                MessageType: 'SUCCESS'
            }]);
            var triggerItem = Ext.getCmp("triggerSaveChartName" + options.params.chartIndex);
            triggerItem.setValue(options.params.newChartName);
            form.findField('savedChartName' + options.params.chartIndex).setValue(options.params.newChartName);
        }
    }
    else {
        var titleFailed = bundleHandler.get('com.ptc.core.components.chart.chartResource.MESSAGE_TITLE_SAVE_FAILED');
        PTC.messaging.showInlineMessage([{
            MessageTitle: titleFailed,
            Messages: [errorMessage],
            MessageType: 'FAILURE'
        }]);
    }
};

/**
 * @private
 * Get the data for the saved charts dropdown
 */
PTC.charting._getSavedChartsMenuData = function(chartIndex){
    var form = PTC.charting._getForm(chartIndex);
    if (form) {
        var savedChartLoadedOid = form.findField('savedChartLoadedOid' + chartIndex).getValue();
        var reportTemplateOid = form.findField('reportTemplateOid' + chartIndex).getValue();
        var tableId = form.findField('tableId' + chartIndex).getValue();
        Ext.Ajax.request({
            url: getBaseHref() + "netmarkets/jsp/components/charts/getSavedChartMenuData.jsp",
            success: PTC.charting._loadSavedChartMenu,
            faulure: PTC.charting._processFailedRequest,
            params: {
                savedChartLoadedOid: savedChartLoadedOid,
                reportTemplateOid: reportTemplateOid,
                tableId: tableId,
                chartIndex: chartIndex
            }
        });
    }
};

/**
 * @private
 * Load the saved charts menu data into the dropdown
 */
PTC.charting._loadSavedChartMenu = function(response, options){
    var form = PTC.charting._getForm(options.params.chartIndex);
    var loadMenu = Ext.getCmp("menuSaveChartName" + options.params.chartIndex);
    var triggerItem = Ext.getCmp("triggerSaveChartName" + options.params.chartIndex);
    loadMenu.removeAll();
    PTC.charting.savedChartNames = [];
    var savedChartLoadedOid = options.params.savedChartLoadedOid;
    var deleteTooltip = PTC.util.unescapeHTML(bundleHandler.get('com.ptc.core.components.chart.chartResource.DELETE_CHART_TOOLTIP'));
    var missingColumnTooltip = PTC.util.unescapeHTML(bundleHandler.get('com.ptc.core.components.chart.chartResource.TABLE_MISSING_CHART_COLUMNS'));
    var toolTip = '';
    var columns = PTC.charting._getTableColumnData(form.findField('tableId' + options.params.chartIndex).getValue());
    var responseJSON = Ext.util.JSON.decode(response.responseText);
    for (var key in responseJSON) {
        if (responseJSON.hasOwnProperty(key)) {
            var menuId = decodeURIComponent(responseJSON[key].menuId).replace(/\+/g, ' ');
            var name = decodeURIComponent(responseJSON[key].name).replace(/\+/g, ' ');
            // get columns, which are appended to name
            var tokens = name.split("|");
            name = tokens[0];
            var yField = tokens[1];
            var xField = tokens[2];
            if (savedChartLoadedOid == menuId) {
                triggerItem.setValue(name);
            }
            var savedChartArray = [menuId, name];
            PTC.charting.savedChartNames.push(savedChartArray);
            toolTip = '';
            
            // disable menu and add tooltip if chart columns are not in table
            var disabled = false;
            if (columns.indexOf(yField) < 0) {
                disabled = true;
                toolTip = missingColumnTooltip + yField;
            }
            if (xField !== "" && columns.indexOf(xField) < 0) {
                if (disabled) {
                    toolTip = toolTip + "," + xField;
                }
                else {
                    disabled = true;
                    toolTip = missingColumnTooltip + xField;
                }
            }
            
            // trim menu item and add tooltip for long labels
            var labelWidth = Ext.util.TextMetrics.createInstance(document.body).getWidth(PTC.util.HTMLEncoder.encodeForHTMLContent(name));
            if (labelWidth > 270 || name.length > 40) {
                if (toolTip === "") {
                    toolTip = name;
                }
                name = Ext.util.Format.ellipsis(name, 33, false);
            }
            
            loadMenu.addItem(new Ext.menu.Item({
                text: PTC.charting._getSaveChartMenuText(menuId, name, toolTip, deleteTooltip, options.params.chartIndex, disabled),
                id: menuId,
                data: menuId,
                hideOnClick: false
            }));
        }
    }
    loadMenu.addSeparator();
    PTC.charting._addSavedChartMenuActions(options.params.chartIndex);
};

/**
 * @private
 * Load the saved charts menu data into the dropdown
 */
PTC.charting._addSavedChartMenuActions = function(chartIndex){
    var loadMenu = Ext.getCmp("menuSaveChartName" + chartIndex);
    var disabled = true;
    if (PTC.charting._getFormValue(chartIndex, 'chartExists') == 'false') {
        saveIcon = 'netmarkets/images/save_disabled.png';
        saveAsIcon = 'netmarkets/images/save_as_disabled.png';
    }
    else {
        disabled = false;
        saveIcon = 'netmarkets/images/save.png';
        saveAsIcon = 'netmarkets/images/saveas.png';
    }
    
    loadMenu.addItem(new Ext.menu.Item({
        id: 'triggerSave' + chartIndex,
        text: bundleHandler.get('com.ptc.core.components.chart.chartResource.SAVE_MENU_ITEM'),
        hideOnClick: true,
        disabled: disabled,
        handler: PTC.charting._saveChartRequest.createDelegate(this, [chartIndex, 'save']),
        data: '',
        icon: saveIcon
    }));
    loadMenu.addItem(new Ext.menu.Item({
        id: 'triggerSaveAs' + chartIndex,
        text: bundleHandler.get('com.ptc.core.components.chart.chartResource.SAVE_AS_MENU_ITEM'),
        hideOnClick: true,
        disabled: disabled,
        handler: PTC.charting._saveChartRequest.createDelegate(this, [chartIndex, 'saveAs']),
        data: '',
        icon: saveAsIcon
    }));
};

/**
 * @private
 * Enable the save and save as icons and menu items after a chart is drawn
 */
PTC.charting._enableSavedChartActions = function(chartIndex){
    var form = PTC.charting._getForm(chartIndex);
    if (form && form.findField('chartExists' + chartIndex).getValue() == 'false') {
        form.findField('chartExists' + chartIndex).setValue(true);
        var saveMenuItem = Ext.getCmp('triggerSave' + chartIndex);
        var saveAsMenuItem = Ext.getCmp('triggerSaveAs' + chartIndex);
        var loadMenu = Ext.getCmp("menuSaveChartName" + chartIndex);
        loadMenu.remove(saveAsMenuItem);
        loadMenu.remove(saveMenuItem);
        PTC.charting._addSavedChartMenuActions(chartIndex);
        
        var saveChartIcon = Ext.getCmp('saveChartIcon' + chartIndex);
        saveChartIcon.el.dom.href = PTC.jslint.SCRIPT_URL_STRING + "PTC.charting._saveChartRequest('" + chartIndex + "','save')";
        saveChartIcon.el.dom.firstChild.src = 'netmarkets/images/save.png';
        var saveAsChartIcon = Ext.getCmp('saveAsChartIcon' + chartIndex);
        saveAsChartIcon.el.dom.href = PTC.jslint.SCRIPT_URL_STRING + "PTC.charting._saveChartRequest('" + chartIndex + "','saveAs')";
        saveAsChartIcon.el.dom.firstChild.src = 'netmarkets/images/saveas.png';
    }
};

/**
 * @private
 * Retrieve the data for a selected saved chart from the database
 */
PTC.charting._getSavedChartData = function(savedChartOid, chartIndex){
    var savedChartName = PTC.charting._getSavedChartNameFromOid(savedChartOid);
    var triggerItem = Ext.getCmp("triggerSaveChartName" + chartIndex);
    triggerItem.setValue(savedChartName);
    var loadMenu = Ext.getCmp("menuSaveChartName" + chartIndex);
    loadMenu.hide();
    Ext.Ajax.request({
        url: getBaseHref() + "netmarkets/jsp/components/charts/getSavedChart.jsp",
        success: PTC.charting._loadSavedChartData,
        faulure: PTC.charting._processFailedRequest,
        params: {
            savedChartOid: savedChartOid,
            getChartsForSavedReport: false,
            chartIndex: chartIndex,
            savedChartName: savedChartName
        }
    });
};

/**
 * @private
 * Retrieve the data for a selected saved chart from the database
 */
PTC.charting._getSavedChartsForReport = function(savedReportOid){
    Ext.Ajax.request({
        url: getBaseHref() + "netmarkets/jsp/components/charts/getSavedChart.jsp",
        success: PTC.charting._loadSavedChartsFromReport,
        faulure: PTC.charting._processFailedRequest,
        params: {
            getChartsForSavedReport: true,
            savedReportOid: savedReportOid
        }
    });
};

/**
 * @private
 * Modify a value in the chart options array
 */
PTC.charting._modifyChartOption = function(chartOptionsIndex, name, value){
    var config = Ext.util.JSON.decode(PTC.charting.chartOptions[chartOptionsIndex]);
    config[name] = value;
    PTC.charting.chartOptions[chartOptionsIndex] = JSON.stringify(config);
    if (PTC.reportBuilder.chartOptions) {
        PTC.reportBuilder.chartOptions = PTC.charting.chartOptions;
    }
};

/**
 * @private
 * Retrieve the data for a selected saved chart from the database
 */
PTC.charting._getSavedChartNameFromOid = function(oid){
    for (var i = 0, len = PTC.charting.savedChartNames.length; i < len; i++) {
        if (PTC.charting.savedChartNames[i][0] === oid) {
            return PTC.charting.savedChartNames[i][1];
        }
    }
    return '';
};

/**
 * @private
 * Load the data for a selected saved chart into the chart options dialog
 */
PTC.charting._loadSavedChartData = function(response, options){
    var chartIndex = options.params.chartIndex;
    var form = PTC.charting._getForm(chartIndex);
    PTC.charting._clearChartData(form, chartIndex);
    var responseJSON = Ext.util.JSON.decode(response.responseText);
    var chartType = '';
    for (var key in responseJSON) {
        if (responseJSON.hasOwnProperty(key)) {
            var name = decodeURIComponent(responseJSON[key].name).replace(/\+/g, ' ');
            var value = decodeURIComponent(responseJSON[key].value).replace(/\+/g, ' ');
            PTC.charting._setFormValue(form, chartIndex, name, value);
            if (name == 'chartType') {
                chartType = value;
            }
        }
    }
    form.findField('savedChartName' + chartIndex).setValue(options.params.savedChartName);
    Ext.getCmp(chartType + options.params.chartIndex).toggle(true);
    PTC.charting._manageChartButtons(options.params.chartIndex, false);
    PTC.charting._setChartOptions(chartType, options.params.chartIndex);
    PTC.charting._updateChartPreview(options.params.chartIndex, true);
};

/**
 * @private
 * Load the data for a selected saved chart into the chart options dialog
 */
PTC.charting._loadSavedChartsFromReport = function(response, options){
    var responseJSON = Ext.util.JSON.decode(response.responseText);
    var count = responseJSON.length;
    PTC.charting.chartOptions = [];
    var chartConfig = {};
    Ext.applyIf(chartConfig, PTC.charting._getDefaultChartConfig());
    for (var i = 0, l = count; i < l; i++) {
        var jsonItem = responseJSON[i];
        for (var key in jsonItem) {
            if (jsonItem.hasOwnProperty(key)) {
                var name = decodeURIComponent(jsonItem[key].name).replace(/\+/g, ' ');
                var value = decodeURIComponent(jsonItem[key].value).replace(/\+/g, ' ');
                if (PTC.charting.checkBoxes.indexOf(name) > -1) {
                    chartConfig[name] = PTC.charting._getCheckboxValue(value);
                }
                else {
                    chartConfig[name] = value;
                }
            }
        }
        chartConfig.showChartInline = "true";
        chartConfig.chartIndex = i;
        chartConfig.savedReportOid = options.params.savedReportOid;
        // Since no form is involved, load combo box values
        chartConfig.colorPalette = chartConfig.colorPaletteValue;
        chartConfig.displayValueCount = chartConfig.displayValueCountValue;
        chartConfig.fontSize = chartConfig.fontSizeValue;
        chartConfig.xField = chartConfig.xFieldValue;
        chartConfig.yField = chartConfig.yFieldValue;
        
        var jsonString = JSON.stringify(chartConfig);
        PTC.charting.chartOptions[i] = jsonString;
    }
    PTC.reportBuilder.chartOptions = PTC.charting.chartOptions;
};

/**
 * @private
 * Sets an individual form value.  Disable events while setting the form value.
 */
PTC.charting._setFormValue = function(form, chartIndex, fieldName, value){
    var formField = form.findField(fieldName + chartIndex);
    if (formField) {
        if (formField.disabled) {
            formField.enable();
        }
        formField.suspendEvents(false);
        formField.setValue(value);
        formField.resumeEvents();
    }
};

/**
 * @private
 * Returns correct setting for a checkbox
 */
PTC.charting._getCheckboxValue = function(value){
    if (value) {
        if (value === 'on' || value === 'true') {
            return true;
        }
        else {
            return false;
        }
    }
    return false;
};

/**
 * @private
 * Clear current chart settings before loading a chart
 */
PTC.charting._clearChartData = function(form, chartIndex){
    PTC.charting.checkBoxes.each(function(item){
        PTC.charting._clearCheckbox(item, form, chartIndex);
    });
    ['yFieldPrevious', 'xFieldPrevious', 'chartTypePrevious', 'chartTitle', 'yFieldLabel', 'xFieldLabel', 'yField', 'xField'].each(function(item){
        PTC.charting._clearFormSetting(item, form, chartIndex);
    });
};

/**
 * @private
 * Clear specified checkbox
 */
PTC.charting._clearCheckbox = function(formFieldName, form, chartIndex){
    var formField = form.findField(formFieldName + chartIndex);
    if (formField) {
        if (formField.disabled) {
            formField.enable();
        }
        formField.suspendEvents(false);
        formField.setValue(false);
        formField.resumeEvents();
        if (formFieldName == 'showXAxisGrid' ||
        formFieldName == 'showLegend' ||
        formFieldName == 'showPieAsDonut' ||
        formFieldName == 'showLine' ||
        formFieldName == 'showRegressionLine') {
            formField.disable();
            var label = Ext.getCmp(formFieldName + '_Label' + chartIndex);
            label.disable();
        }
    }
};

/**
 * @private
 * Clear specified checkbox
 */
PTC.charting._clearFormSetting = function(formFieldName, form, chartIndex){
    var formField = form.findField(formFieldName + chartIndex);
    if (formField) {
        if (formField.disabled) {
            formField.enable();
        }
        formField.suspendEvents(false);
        formField.setValue('');
        formField.resumeEvents();
    }
};

/**
 * @private
 * Load the data for a selected saved chart into the chart options dialog
 */
PTC.charting._deleteSavedChartData = function(savedChartOid, chartIndex){
    var triggerItem = Ext.getCmp("triggerSaveChartName" + chartIndex);
    var loadMenu = Ext.getCmp("menuSaveChartName" + chartIndex);
    loadMenu.hide();
    
    Ext.Msg.show({
        title: bundleHandler.get('com.ptc.core.components.chart.chartResource.MESSAGE_TITLE_CONFIRM_DELETE'),
        msg: bundleHandler.getBundleStringAndInserts('com.ptc.core.components.chart.chartResource.MESSAGE_CONFIRM_DELETE', [PTC.charting._getSavedChartNameFromOid(savedChartOid)]),
        minWidth: 600,
        maxWidth: 600,
        closable: false,
        buttons: {
            yes: bundleHandler.get('com.ptc.core.components.chart.chartResource.MESSAGE_CONFIRM_YES'),
            no: bundleHandler.get('com.ptc.core.components.chart.chartResource.MESSAGE_CONFIRM_NO')
        },
        icon: Ext.MessageBox.QUESTION,
        fn: function(buttonId){
            if (buttonId == 'yes') {
                Ext.Ajax.request({
                    url: getBaseHref() + "netmarkets/jsp/components/charts/deleteSavedChart.jsp",
                    success: PTC.charting._processDeleteChartRequest,
                    params: {
                        savedChartOid: savedChartOid,
                        chartIndex: chartIndex
                    }
                });
            }
        }
    });
};

PTC.charting._getForm = function(chartIndex){
    var panel = Ext.getCmp('chartSettingsPanel' + chartIndex);
    if (panel) {
        return Ext.getCmp('chartSettingsPanel' + chartIndex).getForm();
    }
    return null;
};

PTC.charting._getFormValue = function(chartIndex, formField){
    return PTC.charting._getForm(chartIndex).findField(formField + chartIndex).getValue();
};

PTC.charting._getFormfieldValue = function(chartIndex, formField, form){
    return form.findField(formField + chartIndex).getValue();
};

PTC.charting._getFormfield = function(chartIndex, formField, form){
    return form.findField(formField + chartIndex);
};


/**
 * @private
 * Called after chart data is retrieved from the server.  Gets chart config from form and requests chart generation.
 */
PTC.charting._processDeleteChartRequest = function(response, options){
    var responseJSON = Ext.util.JSON.decode((response.responseText).replace(/&quot;/g, "\""));
    var errorMessage = PTC.charting._checkForServerError(responseJSON);
    var triggerItem = Ext.getCmp("triggerSaveChartName" + options.params.chartIndex);
    var loadMenu = Ext.getCmp("menuSaveChartName" + options.params.chartIndex);
    var savedChartLoadedOid = PTC.charting._getFormValue(options.params.chartIndex, 'savedChartLoadedOid');
    
    if (errorMessage) {
        var title = bundleHandler.get('com.ptc.core.components.chart.chartResource.SAVED_CHART_FAILED_TITLE');
        showInlineMessage(title, errorMessage, "FAILURE");
    }
    else {
    
        // Check if deleted chart is loaded
        // if so, clear menu name and disable icons
        var allItems = loadMenu.items;
        var removeItem = null;
        for (var i = 0, len = allItems.length; i < len; i++) {
            var mItem = allItems.get(i);
            if (mItem.id == options.params.savedChartOid) {
                removeItem = mItem;
                // Remove the item from the saved chart names array
                var deleteIndex = -1;
                for (var j = 0, len2 = PTC.charting.savedChartNames.length; j < len2; j++) {
                    if (PTC.charting.savedChartNames[j][0] == mItem.data) {
                        deleteIndex = j;
                        break;
                    }
                }
                if (deleteIndex != -1) {
                    PTC.charting.savedChartNames.splice(deleteIndex, 1);
                }
                break;
            }
        }
        if (removeItem) {
            if (savedChartLoadedOid == removeItem.id) {
                triggerItem.reset();
            }
            loadMenu.remove(mItem);
        }
    }
    loadMenu.hide();
};

/**
 * @private
 * Called after chart data is retrieved from the server.  Prompts user for chart name (for save as),
 * gets chart config from form and requests chart generation.
 */
PTC.charting._saveChartRequest = function(chartIndex, saveType){
    var form = PTC.charting._getForm(chartIndex);
    var chartName = PTC.charting._getFormfieldValue(chartIndex, 'savedChartName', form);
    var chartTitle = PTC.charting._getFormfieldValue(chartIndex, 'chartTitle', form);
    var savedReportOid = PTC.charting._getFormfieldValue(chartIndex, 'savedReportOid', form);
    if (PTC.isDefinedAndNotEmptyString(savedReportOid) && saveType == 'save') {
        Ext.Msg.show({
            title: bundleHandler.get('com.ptc.core.components.chart.chartResource.MESSAGE_TITLE_CONFIRM_MODIFY'),
            msg: bundleHandler.getBundleStringAndInserts('com.ptc.core.components.chart.chartResource.MESSAGE_CONFIRM_MODIFY'),
            minWidth: 600,
            maxWidth: 600,
            closable: false,
            buttons: {
                yes: bundleHandler.get('com.ptc.core.components.chart.chartResource.MESSAGE_CONFIRM_YES'),
                no: bundleHandler.get('com.ptc.core.components.chart.chartResource.MESSAGE_CONFIRM_NO')
            },
            icon: Ext.MessageBox.QUESTION,
            fn: function(buttonId){
                if (buttonId == 'yes') {
                    PTC.charting._completeSaveChartRequest(chartIndex, chartName, chartTitle, saveType);
                }
            }
        });
    }
    else {
        PTC.charting._completeSaveChartRequest(chartIndex, chartName, chartTitle, saveType);
    }
};

/**
 * @private
 * Complete the save from above, user may have been prompted to continue
 */
PTC.charting._completeSaveChartRequest = function(chartIndex, chartName, chartTitle, saveType){
    // 'Save as' if chart name is blank or 'save as' is picked, otherwise just save
    if (saveType == 'saveAs') {
        if (chartName === '') {
            chartName = chartTitle;
        }
        PTC.charting._createSaveChartDialog(chartIndex, chartName);
    }
    else if (chartName === '') {
        PTC.charting._createSaveChartDialog(chartIndex, chartTitle);
    }
    else {
        PTC.charting._saveChartSettings(chartIndex, chartName, 'save');
    }
};

/**
 * @private
 * When saving a chart, creates a light box to prompt the user for saved chart name
 */
PTC.charting._createSaveChartDialog = function(chartIndex, defaultText){
    var windowId = 'saveChartDialog'; // used by cancel and passed in to create the window
    /**
     * Logic to create the OKButton
     */
    var OKButtonText = bundleHandler.get('com.ptc.core.components.chart.chartResource.OK_DIALOG_BUTTON');
    var duplicateErrorMessage = bundleHandler.get('com.ptc.core.components.chart.chartResource.SAVED_CHART_DUPLICATE_NAME');
    var OKButton = new Ext.Button({
        text: OKButtonText,
        formBind: true,
        handler: function(button, event){
            var nameField = Ext.getCmp('newName');
            var newChartName = nameField.getValue().strip();
            var dupFound = false;
            for (var i = 0, len = PTC.charting.savedChartNames.length; i < len; i++) {
                var nm = PTC.charting.savedChartNames[i][1].toLowerCase();
                if (PTC.charting.savedChartNames[i][1].toLowerCase() === newChartName.toLowerCase()) {
                    dupFound = true;
                    break;
                }
            }
            
            // don't allow a chart be renamed to the name of an existing chart
            if (dupFound) {
                nameField.markInvalid(duplicateErrorMessage);
            }
            else {
                PTC.charting._saveChartSettings(chartIndex, newChartName, 'saveAs');
                Ext.getCmp(windowId).close();
            }
        }
    });
    
    /**
     * Logic to create the cancelButton
     */
    var cancelButtonText = bundleHandler.get('com.ptc.core.components.chart.chartResource.CANCEL_DIALOG_BUTTON');
    var cancelButton = new Ext.Button({
        text: cancelButtonText,
        handler: function(button, event){
            Ext.getCmp(windowId).close();
        }
    });
    
    /**
     * Logic to create light box window/form
     */
    var label = bundleHandler.get('com.ptc.core.components.chart.chartResource.SAVED_CHART_PROMPT_TEXT');
    var labelWidth = Ext.util.TextMetrics.createInstance(document.body).getWidth(label) + 30;
    var maxLabelWidth = 120;
    var extraWindowWidth = 0;
    // Expand label and window if necessary for long translations of prompt text
    if (labelWidth > 120) {
        extraWindowWidth = labelWidth - 120;
        maxLabelWidth = labelWidth;
    }
    var lightboxConfig = {
        windowId: windowId,
        formId: 'saveChartForm',
        defaultFieldValue: defaultText,
        maxLabelWidth: maxLabelWidth,
        fieldWidth: 325,
        windowWidth: 480 + extraWindowWidth,
        OKButton: OKButton,
        cancelButton: cancelButton,
        promptText: label,
        promptTitle: bundleHandler.get('com.ptc.core.components.chart.chartResource.SAVED_CHART_PROMPT_TITLE'),
        charsExceededMessage: bundleHandler.get('com.ptc.core.components.chart.chartResource.SAVED_CHART_CHARS_EXCEEDED'),
        blankTextMessage: bundleHandler.get('com.ptc.core.components.chart.chartResource.SAVED_CHART_NAME_EMPTY'),
        maxLengthField: 60
    };
    var win = PTC.lightbox.createSimpleLightBoxWindowAndFormFromConfig(lightboxConfig);
    win.show();
};

/**
 * @private
 * Warning in case of ajax request error
 */
PTC.charting._processFailedRequest = function(){
    alert('Error processing ajax request');
};

/**
 * @private
 * Processes selection of the x or y axis column.  Determines valid chart types,
 * makes appropriate chart tye buttons available, determines default chart type or uses
 * selected chart type if applicable.  Draws a chart for chart type.
 */
PTC.charting._processDataSelection = function(combo, dataType, index){
    var form = PTC.charting._getForm(index);
    var axis = combo.getId();
    if (axis == 'yField' + index) {
        form.findField('yFieldDataType' + index).setValue(dataType);
    }
    else {
        form.findField('xFieldDataType' + index).setValue(dataType);
    }
    PTC.charting._manageChartButtons(index, true);
};


/**
 * @private
 * Manage the chart buttons after a data selection is made, or after
 * a saved chart is loaded.
 */
PTC.charting._manageChartButtons = function(index, setDefaultChart){
    var form = PTC.charting._getForm(index);
    var yField = form.findField('yField' + index).getValue();
    var yFieldDataType = form.findField('yFieldDataType' + index).getValue();
    var xField = form.findField('xField' + index).getValue();
    var xFieldDataType = form.findField('xFieldDataType' + index).getValue();
    var chartType = form.findField('chartType' + index).getValue();
    var chartTypePrevious = form.findField('chartTypePrevious' + index).getValue();
    // Enable x axis selection after y axis is selected
    var xAxisField = Ext.getCmp('xField' + index);
    if (xAxisField.disabled) {
        xAxisField.enable();
        var label = Ext.getCmp('xFieldComboLabel' + index);
        label.enable();
    }
    
    var singleVariable = false;
    var multiVariable = false;
    if ((yField === '') && (xField !== '')) {
        singleVariable = true;
        dataType = xFieldDataType;
    }
    else if ((yField !== '') && (xField === '')) {
        singleVariable = true;
        dataType = yFieldDataType;
    }
    else if ((yField !== '') && (xField !== '')) {
        multiVariable = true;
    }
    
    if (singleVariable && ((dataType == 'string') || (dataType == 'number'))) {
        PTC.charting._disableMultiVariableButtons(index);
        ['column', 'bar', 'pie', 'pareto', 'line'].each(function(item){
            PTC.charting._enableChartButton(item, index);
        });
        PTC.charting._disableChartButton('aging', index);
        
        if (dataType == 'number') {
            PTC.charting._enableChartButton('histogram', index);
            PTC.charting._enableChartButton('histogram_horz', index);
            
            if (setDefaultChart) {
                // Set default chart type for numbers if axis was selected, but not if loading saved chart
            if ((chartTypePrevious === "") ||
            ((chartTypePrevious != 'column' + index) &&
            (chartTypePrevious != 'bar' + index) &&
            (chartTypePrevious != 'pie' + index) &&
            (chartTypePrevious != 'pareto' + index) &&
            (chartTypePrevious != 'line' + index) &&
            (chartTypePrevious != 'histogram_horz' + index) &&
            (chartTypePrevious != 'histogram' + index))) {
            
                Ext.getCmp('histogram' + index).toggle(true);
                PTC.charting._setChartType(Ext.getCmp('histogram' + index));
            }
            else {
                PTC.charting._setChartType(Ext.getCmp(chartTypePrevious));
            }
        }
        }
        else {
            PTC.charting._disableChartButton('histogram', index);
            PTC.charting._disableChartButton('histogram_horz', index);
            // Set default chart type for strings if axis was selected, but not if loading saved chart
            if (setDefaultChart) {
            if ((chartTypePrevious === "") ||
            ((chartTypePrevious != 'column' + index) &&
            (chartTypePrevious != 'bar' + index) &&
            (chartTypePrevious != 'pie' + index) &&
            (chartTypePrevious != 'pareto' + index) &&
            (chartTypePrevious != 'line' + index))) {
                Ext.getCmp('column' + index).toggle(true);
                PTC.charting._setChartType(Ext.getCmp('column' + index));
            }
            else {
                PTC.charting._setChartType(Ext.getCmp(chartTypePrevious));
            }
        }
    }
    }
    else if (singleVariable && (dataType == 'date')) {
        PTC.charting._disableMultiVariableButtons(index);
        ['histogram', 'histogram_horz'].each(function(item){
            PTC.charting._enableChartButton(item, index);
        });
        ['column', 'bar', 'pie', 'pareto', 'line', 'aging'].each(function(item){ // move aging to enabled when implemented
            PTC.charting._disableChartButton(item, index);
        });
        
        if (setDefaultChart) {
        // Default to histogram chart for single date variable
        if ((chartTypePrevious === "") ||
        ((chartTypePrevious != 'histogram' + index) &&
        (chartTypePrevious != 'histogram_horz' + index) &&
        (chartTypePrevious != 'aging' + index))) {
            Ext.getCmp('histogram' + index).toggle(true);
            PTC.charting._setChartType(Ext.getCmp('histogram' + index));
        }
    }
    }
    else if (multiVariable) {
        PTC.charting._disableSingleVariableButtons(index);
        var yFieldCategorical = false;
        var xFieldCategorical = false;
        if ((yFieldDataType == 'string') || (yFieldDataType == 'number')) {
            yFieldCategorical = true;
        }
        if ((xFieldDataType == 'string') || (xFieldDataType == 'number')) {
            xFieldCategorical = true;
        }
        
        if (yFieldCategorical && xFieldCategorical) {
            ['columnstacked', 'barstacked', 'columnclustered'].each(function(item){
                PTC.charting._enableChartButton(item, index);
            });
            if ((yFieldDataType == 'number') || (xFieldDataType == 'number')) {
                PTC.charting._disableChartButton('scattergroup', index); // change to enable when scatter group implemented
            }
            else {
                PTC.charting._disableChartButton('scattergroup', index);
            }
            if ((yFieldDataType == 'number') && (xFieldDataType == 'number')) {
                PTC.charting._disableChartButton('scatterplot', index); // change to enable when scatter plot implemented
            }
            else {
                PTC.charting._disableChartButton('scatterplot', index);
            }
        }
        else {
            PTC.charting._disableMultiVariableButtons(index);
            PTC.charting._displayErrorMessage('MESSAGE_CHART_NOT_AVAILABLE', index);
            return;
        }
        
        // Default chart type
        if (setDefaultChart) {
        if (((yFieldDataType == 'number') && (xFieldDataType == 'number')) &&
        ((chartTypePrevious === "") ||
        ((chartTypePrevious != 'columnstacked' + index) &&
        (chartTypePrevious != 'barstacked' + index) &&
        (chartTypePrevious != 'columnclustered' + index) &&
        (chartTypePrevious != 'scattergroup' + index)))) {
            //Ext.getCmp('scatterplot' + index).toggle(true);    // Make the scatter plot the default when implemented
            //PTC.charting._setChartType(Ext.getCmp('scatterplot' + index));
            Ext.getCmp('columnstacked' + index).toggle(true);
            PTC.charting._setChartType(Ext.getCmp('columnstacked' + index));
        }
        else if (((yFieldDataType == 'number') || (xFieldDataType == 'number')) &&
        ((chartTypePrevious === "") ||
        ((chartTypePrevious != 'columnstacked' + index) &&
        (chartTypePrevious != 'barstacked' + index) &&
        (chartTypePrevious != 'columnclustered' + index)))) {
            //Ext.getCmp('scattergroup' + index).toggle(true);    // Make the scatter group the default when implemented
            //PTC.charting._setChartType(Ext.getCmp('scattergroup' + index));
            Ext.getCmp('columnstacked' + index).toggle(true);
            PTC.charting._setChartType(Ext.getCmp('columnstacked' + index));
        }
        else if (((yFieldCategorical && xFieldCategorical)) &&
        ((chartTypePrevious === "") ||
        ((chartTypePrevious != 'columnstacked' + index) &&
        (chartTypePrevious != 'barstacked' + index) &&
        (chartTypePrevious != 'columnclustered' + index)))) {
            Ext.getCmp('columnstacked' + index).toggle(true);
            PTC.charting._setChartType(Ext.getCmp('columnstacked' + index));
        }
    }
    }
};

/**
 * @private
 * Disables all buttons for single variable charts, called when a multivariable chart is enabled.
 */
PTC.charting._disableSingleVariableButtons = function(index, chartType){
    ['column', 'bar', 'pie', 'pareto', 'line', 'histogram', 'histogram_horz', 'aging'].each(function(item){
        PTC.charting._disableChartButton(item, index);
    });
};

/**
 * @private
 * Disables all buttons for multivariable charts, called when a single variable chart is enabled.
 */
PTC.charting._disableMultiVariableButtons = function(index, chartType){
    ['columnstacked', 'barstacked', 'columnclustered', 'scattergroup', 'scatterplot'].each(function(item){
        PTC.charting._disableChartButton(item, index);
    });
};

/**
 * @private
 * Disables all buttons for single variable charts, called when a multivariable chart is enabled.
 */
PTC.charting._disableSingleVariableButtons = function(index, chartType){
    ['column', 'bar', 'pie', 'pareto', 'line', 'histogram', 'histogram_horz', 'aging'].each(function(item){
        PTC.charting._disableChartButton(item, index);
    });
};

/**
 * @private
 * Presets axis labels where applicable  UNDER DEVELOPMENT
 */
PTC.charting._setAxisLabels = function(chartConfig, previousChartType, dataChanged, chartTypeChanged){
    var form = PTC.charting._getForm(chartConfig.chartIndex);
    var chartType = chartConfig.chartType;
    var horizontalLabel = PTC.charting._getFormfield(chartConfig.chartIndex, 'xFieldLabel', form);
    var verticalLabel = PTC.charting._getFormfield(chartConfig.chartIndex, 'yFieldLabel', form);
    var chartTitleLabel = PTC.charting._getFormfield(chartConfig.chartIndex, 'chartTitle', form);
    var chartTitleDivider = PTC.util.unescapeHTML(bundleHandler.get('com.ptc.core.components.chart.chartResource.CHART_TITLE_DIVIDER'));
    var count = PTC.util.unescapeHTML(bundleHandler.get('com.ptc.core.components.chart.chartResource.AXES_LABEL_COUNT'));
    var range = PTC.util.unescapeHTML(bundleHandler.get('com.ptc.core.components.chart.chartResource.AXES_LABEL_RANGE'));
    var percentage = PTC.util.unescapeHTML(bundleHandler.get('com.ptc.core.components.chart.chartResource.AXES_LABEL_PERCENTAGE'));
    
    // Set horizontal axis and chart title if data has changed
    if (dataChanged === true) {
        if ((chartType == 'histogram') || (chartType == 'histogram_horz')) {
            horizontalLabel.setValue(chartConfig.yField + " " + range);
        }
        else if (chartType !== 'pie') {
            horizontalLabel.setValue(chartConfig.yField);
        }
        if ((chartType == 'columnstacked') || (chartType == 'columnclustered') || (chartType == 'barstacked')) {
            chartTitleLabel.setValue(chartConfig.yField + " " + chartTitleDivider + " " + chartConfig.xField);
        }
        else {
            chartTitleLabel.setValue(chartConfig.yField);
        }
    }
    
    if (dataChanged === true || chartTypeChanged === true) {
        if (chartType == 'pareto') {
            verticalLabel.setValue(percentage);
        }
        else {
            verticalLabel.setValue(count);
        }
    }
    // Update saved chart options with any changes
    chartConfig.xFieldLabel = horizontalLabel.getValue();
    chartConfig.yFieldLabel = verticalLabel.getValue();
    chartConfig.chartTitle = chartTitleLabel.getValue();
    return chartConfig;
};

/**
 * @private
 * Sets the valid chart options when a chart type is selected.
 * Greys out non-applicable chart options for each chart type.
 */
PTC.charting._setChartOptions = function(chartType, index){

    if ((chartType == 'column') ||
    (chartType == 'bar') ||
    (chartType == 'pareto') ||
    (chartType == 'histogram') ||
    (chartType == 'histogram_horz') ||
    (chartType == 'scattergroup') ||
    (chartType == 'aging') ||
    (chartType == 'line')) {
    
        ['showXAxisGrid', 'showYAxisGrid', 'horizontalAxisLabels'].each(function(item){
            PTC.charting._enableChartOption(item, index);
        });
        
        ['showLegend', 'showPieAsDonut', 'showRegressionLine', 'showLine'].each(function(item){
            PTC.charting._disableChartOption(item, index);
        });
        
        if (chartType != 'bar' && chartType != 'histogram_horz') {
            PTC.charting._enableChartOption('horizontalAxisLabels', index);
        }
        else {
            PTC.charting._disableChartOption('horizontalAxisLabels', index);
        }
        
        if (chartType != 'aging') {
            PTC.charting._disableChartOption('agingChartUnits', index);
        }
        else {
            PTC.charting._enableChartOption('agingChartUnits', index);
        }
        
        if (chartType != 'histogram' && chartType != 'histogram_horz') {
            PTC.charting._enableChartOption('displayValueCount', index);
        }
        else {
            PTC.charting._disableChartOption('displayValueCount', index);
        }
        
    }
    else if (chartType == 'pie') {
    
        ['showXAxisGrid', 'showYAxisGrid', 'horizontalAxisLabels', 'showRegressionLine', 'showLine', 'agingChartUnits'].each(function(item){
            PTC.charting._disableChartOption(item, index);
        });
        PTC.charting._enableChartOption('showLegend', index);
        PTC.charting._enableChartOption('showPieAsDonut', index);
        PTC.charting._enableChartOption('displayValueCount', index);
    }
    else if ((chartType == 'columnstacked') ||
    (chartType == 'barstacked') ||
    (chartType == 'columnclustered')) {
    
        ['showXAxisGrid', 'showYAxisGrid', 'horizontalAxisLabels', 'showLegend'].each(function(item){
            PTC.charting._enableChartOption(item, index);
        });
        ['showPieAsDonut', 'showRegressionLine', 'showLine', 'agingChartUnits'].each(function(item){
            PTC.charting._disableChartOption(item, index);
        });
        
        if (chartType == 'barstacked') {
            PTC.charting._disableChartOption('horizontalAxisLabels', index);
        }
        
    }
    else if (chartType == 'scatterplot') {
    
        ['showXAxisGrid', 'showYAxisGrid', 'horizontalAxisLabels', 'showRegressionLine', 'showLine'].each(function(item){
            PTC.charting._enableChartOption(item, index);
        });
        ['showLegend', 'showPieAsDonut', 'agingChartUnits'].each(function(item){
            PTC.charting._disableChartOption(item, index);
        });
    }
};

/**
 * @private
 * Enable the specified chart type button.
 */
PTC.charting._enableChartButton = function(chartType, index){
    var button = Ext.getCmp(chartType + index);
    if (button && button.disabled === true) {
        var iconName = 'netmarkets/images/charts/chart_' + chartType + '.png';
        button.enable();
        button.setIcon(iconName);
    }
};

/**
 * @private
 * Disable the specified chart type button.
 */
PTC.charting._disableChartButton = function(chartType, index){
    var button = Ext.getCmp(chartType + index);
    if (button && button.disabled === false) {
        var iconName = 'netmarkets/images/charts/chart_' + chartType + '_disabled.png';
        button.disable();
        button.setIcon(iconName);
        if (button.pressed) {
            button.toggle(false);
        }
    }
};

/**
 * @private
 * Enable the specified chart type option and its label.
 */
PTC.charting._enableChartOption = function(optionName, index){
    var option = Ext.getCmp(optionName + index);
    if (option && option.disabled === true) {
        option.enable();
    }
        var label = Ext.getCmp(optionName + '_Label' + index);
    if (label && label.disabled === true) {
        label.enable();
    }
};

/**
 * @private
 * Disable the specified chart type option and its label.
 */
PTC.charting._disableChartOption = function(optionName, index){
    var option = Ext.getCmp(optionName + index);
    if (option && option.disabled === false) {
        option.disable();
        var label = Ext.getCmp(optionName + '_Label' + index);
        label.disable();
    }
};

/**
 * @private
 * Find the index for a value in an array
 */
PTC.charting._findIndex = function(array, value){
    var ctr = "";
    for (var i = 0, l = array.length; i < l; i++) {
        if (array[i] == value) {
            return i;
        }
    }
    return ctr;
};

/**
 * @private
 * Find the max value in an array of data
 */
PTC.charting._getMaxValue = function(dataArray, numericField){
    var max = 0;
    var i;
    var chartData = Ext.util.JSON.decode(dataArray);
    if (numericField.length == 1) {
        for (i = 0, l = chartData.length; i < l; i++) {
            if (!isNaN(chartData[i][numericField]) && chartData[i][numericField] > max) {
                max = chartData[i][numericField];
            }
        }
    }
    else {
        for (i = 0, l = chartData.length; i < l; i++) {
            var rowMax = 0;
            for (var j = 0, k = numericField.length; j < k; j++) {
                if (!isNaN(chartData[i][numericField[j]])) {
                    rowMax = rowMax + chartData[i][numericField[j]];
                }
            }
            if (rowMax > max) {
                max = rowMax;
            }
        }
    }
    return max;
};

/**
 * @private
 * Formats error message for display in chart preview window.
 */
PTC.charting._formatErrorMessage = function(errorMsgId, chartConfig){
    PTC.charting._displayErrorMessage(errorMsgId, chartConfig.chartIndex, chartConfig.chartDivId);
};

/**
 * @private
 * Formats error message for display in chart preview window.
 */
PTC.charting._displayErrorMessage = function(errorMsgId, chartIndex, chartDiv){
    if (!chartDiv) {
        chartDiv = "chartingDiv" + chartIndex;
    }
    // Clear existing charts
    div = document.getElementById(chartDiv);
    if (div !== null) {
        div.innerHTML = "";
    }
    // Format error message for display
    var messageText = PTC.util.unescapeHTML(bundleHandler.get('com.ptc.core.components.chart.chartResource.' + errorMsgId));
    var errorMessageHtml = "<br/><img src='netmarkets/images/warning_16x16.gif' border='0'>&nbsp;&nbsp;&nbsp;" + messageText;
    // Show error message
    var errorMsg = new Ext.Container({
        border: 0,
        id: 'chartPanel' + chartIndex,
        renderTo: chartDiv,
        items: [{
            cls: 'msgLabel',
            html: errorMessageHtml
        }]
    });
};

/**
 * @private
 * Formats error message for display in chart preview window.
 */
PTC.charting._displayLoadingIcon = function(chartIndex, chartDiv){
    if (!chartDiv) {
        chartDiv = "chartingDiv" + chartIndex;
    }
    // Clear existing charts
    var div = document.getElementById(chartDiv);
    if (div !== null) {
        div.innerHTML = "";
        // Display loading icon
        var divHtml = '<div id="' + chartDiv + '" style="height: 500px"></div>';
        var divContent = new Ext.Container({
            border: 0,
            cls: 'contentloading',
            id: 'chartPanel' + chartIndex,
            renderTo: chartDiv,
            items: [{
                html: divHtml
            }]
        });
    }
};

/**
 * @private
 * Shows an error message at the top of the page
 */
PTC.charting._formatPageMessage = function(messageTitleId, messageId, messageType){
    var messageTitle = bundleHandler.get(messageTitleId);
    var message = bundleHandler.get(messageId);
    var msgObject = [{
        MessageTitle: messageTitle,
        Messages: [message],
        MessageType: messageType
    }];
    PTC.messaging.showInlineMessage(msgObject);
};

/**
 * @private
 * Formats error message for display in chart preview window.
 */
PTC.charting._getErrorMessageHtml = function(errorMsgId){
    return "<br/><br/><img src='netmarkets/images/warning_16x16.gif' border='0'>&nbsp;&nbsp;&nbsp;" + PTC.util.unescapeHTML(bundleHandler.get('com.ptc.core.components.chart.chartResource.' + errorMsgId));
};

/**
 * @private
 * Formats labels for data labels and axis
 */
PTC.charting._stringLabelRenderer = function(label){
    if (!label) {
        return "";
    }
    else {
        return Ext.util.Format.ellipsis(label, 25, false);
    }
};

/**
 * @private
 * This takes the chart config and chart data and draws the chart to be displayed either
 * in the preview window or on a page.
 */
PTC.charting._getChartItem = function(chartConfig, dataStore, colorPalette){ // remove all but chartConfig
    var series = null;
    var chartIndex = chartConfig.chartIndex;
    var axisLabelFont = null;
    var axisLabelTitleFont = null;
    var axisTitleFont = null;
    var legendFont = null;
    var dataLabelFont = null;
    
    // Set the font size based on the user selected font.  The default is small.
    if (chartConfig.fontSize == "FONT_SIZE_LARGE") {
        axisLabelFont = '13px Arial';
        axisLabelTitleFont = 'bold 14px Arial';
        axisTitleFont = 'bold 16px Arial';
        legendFont = '13px Arial';
        dataLabelFont = '13px Arial';
    }
    else if (chartConfig.fontSize == "FONT_SIZE_MEDIUM") {
        axisLabelFont = '11px Arial';
        axisLabelTitleFont = 'bold 12px Arial';
        axisTitleFont = 'bold 14px Arial';
        legendFont = '11px Arial';
        dataLabelFont = '11px Arial';
    }
    else { // Defaults to small
        axisLabelFont = '9px Arial';
        axisLabelTitleFont = 'bold 11px Arial';
        axisTitleFont = 'bold 12px Arial';
        legendFont = '9px Arial';
        dataLabelFont = '9px Arial';
    }
    
    // This is the chart item to be returned for display.
    var chartItemId = 'chartItem' + chartIndex;
    if (chartConfig.showChartInline === "true") {
        chartItemId = chartItemId + 'inline';
    }
    
    // This is the chart item to be returned for display.
    var chartItem = {
        flex: 1,
        xtype: 'chart',
        id: chartItemId,
        store: dataStore,
        theme: 'WindchillChart',
        resizable: false,
        shadow: true,
        animate: true
    };
    
    // Turn on background if requested by the user
    if (chartConfig.showBackground) {
        var backgroundConfig = {
            background: {
                fill: '#F2F2F2'
            }
        };
        Ext.apply(chartItem, backgroundConfig);
    }
    
    // Get chart axes configuration and apply it to the chart
    var axesConfig = PTC.charting._getChartAxes(chartConfig, axisLabelFont, axisLabelTitleFont, axisTitleFont);
    Ext.apply(chartItem, axesConfig);
    
    // Get chart series configuration and apply it to the chart
    var seriesConfig = PTC.charting._getChartSeries(chartConfig, dataStore, colorPalette, dataLabelFont);
    Ext.apply(chartItem, seriesConfig);
    
    // Turn on legend if pie chart and if requested by the user
    if ((chartConfig.chartType == "pie" || chartConfig.chartType == "columnstacked" || chartConfig.chartType == "barstacked" || chartConfig.chartType == "columnclustered") && (chartConfig.showLegend)) {
        var legendConfig = {
            legend: {
                position: 'right',
                visible: true,
                labelFont: legendFont,
                itemSpacing: 2,
                padding: 1
            }
        };
        Ext.apply(chartItem, legendConfig);
    }
    
    return chartItem;
};

/**
 * @private
 * This adds the chart series to the chart item.  Processing is different for each chart type.
 */
PTC.charting._getChartSeries = function(chartConfig, dataStore, colorPalette, dataLabelFont){

    var seriesConfig = null;
    var highlightFillColor = '#a2b5ca';
    var displayFields = null;
    
    // Series configuration for a pie chart
    if (chartConfig.chartType == "pie") {
        seriesConfig = {
            series: [{
                type: 'pie',
                field: 'yData',
                showInLegend: chartConfig.showLegend,
                highlight: {
                    segment: {
                        margin: 8
                    },
                    lineWidth: 3,
                    stroke: '#000'
                },
                listeners: {
                    itemmousedown: function(item){
                        PTC.charting._selectTableRows(chartConfig.tableId, item.storeItem.get("xData"), chartConfig.yField);
                    }
                }
            }]
        };
        // Donut setting for pie charts only
        if (chartConfig.showPieAsDonut) {
            var donutConfig = {
                donut: 30
            };
            Ext.apply(seriesConfig.series[0], donutConfig);
        }
    }
    
    // Series configuration for a column chart
    else if (chartConfig.chartType == "column") {
    
        seriesConfig = {
            series: [{
                type: 'column',
                column: true,
                xField: "xData",
                yField: "yData",
                xPadding: 0,
                yPadding: 1,
                highlight: true,
                highlightCfg: {
                    lineWidth: 3,
                    stroke: '#000'
                },
                renderer: function(sprite, storeItem, barAttr, i, store){
                    barAttr.fill = colorPalette[i % colorPalette.length];
                    return barAttr;
                },
                listeners: {
                    itemmousedown: function(item){
                        PTC.charting._selectTableRows(chartConfig.tableId, item.storeItem.get("xData"), chartConfig.yField);
                    }
                }
            }]
        };
    }
    
    // Series configuration for a histogram chart
    else if (chartConfig.chartType == "histogram") {
    
        seriesConfig = {
            series: [{
                type: 'column',
                column: true,
                xField: "xData",
                yField: "yData",
                gutter: 3,
                xPadding: 25,
                yPadding: 1,
                highlight: true,
                highlightCfg: {
                    lineWidth: 3,
                    stroke: '#000'
                },
                renderer: function(sprite, storeItem, barAttr, i, store){
                    barAttr.fill = colorPalette[i % colorPalette.length];
                    return barAttr;
                }
            }]
        };
    }
    
    // Series configuration for a histogram chart
    else if (chartConfig.chartType == "histogram_horz") {
    
        seriesConfig = {
            series: [{
                type: 'bar',
                axis: 'bottom',
                column: false,
                xField: 'xData',
                yField: ['yData'],
                gutter: 4,
                xPadding: 0,
                yPadding: 25,
                highlight: true,
                highlightCfg: {
                    lineWidth: 3,
                    stroke: '#000'
                },
                renderer: function(sprite, storeItem, barAttr, i, store){
                    barAttr.fill = colorPalette[i % colorPalette.length];
                    return barAttr;
                }
            }]
        };
    }
    
    // Series configuration for a bar chart
    else if (chartConfig.chartType == "bar") {
    
        seriesConfig = {
            series: [{
                type: 'bar',
                axis: 'bottom',
                column: false,
                xField: 'xData',
                yField: ['yData'],
                xPadding: 1,
                yPadding: 0,
                highlight: true,
                highlightCfg: {
                    lineWidth: 3,
                    stroke: '#000'
                },
                renderer: function(sprite, storeItem, barAttr, i, store){
                    barAttr.fill = colorPalette[i % colorPalette.length];
                    return barAttr;
                },
                listeners: {
                    itemmousedown: function(item){
                        PTC.charting._selectTableRows(chartConfig.tableId, item.storeItem.get("xData"), chartConfig.yField);
                    }
                }
            }]
        };
    }
    
    // Series configuration for a pareto chart
    else if (chartConfig.chartType == "pareto") {
    
        seriesConfig = {
            series: [{
                type: "column",
                column: true,
                xField: "xData",
                yField: "yData",
                gutter: 3,
                xPadding: 0,
                yPadding: 1,
                highlight: true,
                highlightCfg: {
                    lineWidth: 3,
                    stroke: '#000'
                },
                renderer: function(sprite, storeItem, barAttr, i, store){
                    barAttr.fill = colorPalette[i % colorPalette.length];
                    return barAttr;
                },
                listeners: {
                    itemmousedown: function(item){
                        PTC.charting._selectTableRows(chartConfig.tableId, item.storeItem.get("xData"), chartConfig.yField);
                    }
                }
            }, {
                type: "line",
                axis: "left",
                smooth: true,
                xField: "xData",
                yField: "yData2",
                markerConfig: {
                    type: 'circle',
                    size: 4
                }
            }]
        };
    }
    
    // Series configuration for a line chart
    else if (chartConfig.chartType == "line") {
    
        seriesConfig = {
            series: [{
                type: chartConfig.chartType,
                xField: "xData",
                yField: "yData",
                axis: "left",
                fill: true,
                markerCfg: {
                    type: 'circle',
                    size: 3,
                    radius: 3,
                    'stroke-width': 0
                },
                listeners: {
                    itemmousedown: function(item){
                        PTC.charting._selectTableRows(chartConfig.tableId, item.storeItem.get("xData"), chartConfig.yField);
                    }
                }
            }]
        };
    }
    
    // Series configuration for a stacked column, stacked bar, or clustered column
    else if (chartConfig.chartType == "columnstacked" || chartConfig.chartType == "barstacked" || chartConfig.chartType == "columnclustered") {
        displayFields = PTC.charting._getFieldsFromChartData(Ext.util.JSON.decode(chartConfig.chartData), false);
        var series_colors = new Array(displayFields.length);
        var type = 'column';
        var stacked = true;
        if (chartConfig.chartType == "barstacked") {
            type = 'bar';
        }
        else if (chartConfig.chartType == "columnclustered") {
            stacked = false;
        }
        
        // Setup series for a column stacked chart
        seriesConfig = {
            series: [{
                type: type,
                axis: 'left',
                xField: 'xData',
                yField: displayFields,
                showInLegend: chartConfig.showLegend,
                stacked: stacked,
                listeners: {
                    afterrender: function(){
                        for (var i = 0, l = displayFields.length; i <= l; i++) {
                            series_colors[i] = this.getLegendColor(i);
                        }
                    },
                    itemmousedown: function(item){
                        var index = PTC.charting._findIndex(series_colors, item.attr.fill);
                        PTC.charting._selectTableRows(chartConfig.tableId, displayFields[index], chartConfig.yField);
                    }
                },
                highlightCfg: {
                    lineWidth: 3,
                    stroke: '#000'
                }
            }]
        };
    }
    
    // Setup tooltips for all charts
    if (chartConfig.showTooltips === true) {
        var tooltipConfig = null;
        if (chartConfig.chartType == "pie" || chartConfig.chartType == "column" || chartConfig.chartType == "histogram" || chartConfig.chartType == "histogram_horz" || chartConfig.chartType == "bar" || chartConfig.chartType == "line") {
            tooltipConfig = {
                tips: {
                    trackMouse: true,
                    anchorToTarget: true,
                    hideDelay: 0,
                    showDelay: 0,
                    width: 500,
                    height: 40,
                    border: '0',
                    renderer: function(storeItem, item){
                        // calculate percentage.
                        var total = 0;
                        dataStore.each(function(rec){
                            total += rec.get("yData");
                        });
                        this.setTitle(Math.round(storeItem.get("yData") / total * 100) + '% ' + ' ' + storeItem.get("xData"));
                    }
                }
            };
        }
        else if (chartConfig.chartType == "pareto") {
            tooltipConfig = {
                tips: {
                    trackMouse: true,
                    anchorToTarget: true,
                    hideDelay: 0,
                    showDelay: 0,
                    width: 500,
                    height: 20,
                    renderer: function(storeItem, item){
                        this.setTitle(Math.round(storeItem.get("yData") * 100) + '% ' + ' ' + storeItem.get("xData"));
                    }
                }
            };
        }
        else if (chartConfig.chartType == "columnstacked" || chartConfig.chartType == "barstacked" || chartConfig.chartType == "columnclustered") {
            tooltipConfig = {
                tips: {
                    trackMouse: true,
                    anchorToTarget: true,
                    hideDelay: 0,
                    showDelay: 0,
                    width: 500,
                    height: 20,
                    renderer: function(storeItem, item){
                        var index = PTC.charting._findIndex(series_colors, item.attr.fill);
                        this.update('<b>' + displayFields[index] + '</b> - ' + String(item.value[1]));
                    }
                }
            };
        }
        Ext.apply(seriesConfig.series[0], tooltipConfig);
    }
    
    // Setup data labels for all charts
    if (chartConfig.showDataLabels === true) {
        var labelConfig = null;
        var labelDisplay = 'outside';
        var labelField = 'yData';
        var labelContrast = false;
        var renderer = function(v){
            return v;
        };
        if (chartConfig.chartType == 'column' || chartConfig.chartType == 'histogram' || chartConfig.chartType == 'histogram_horz' || chartConfig.chartType == 'bar') {
            renderer = Ext.util.Format.numberRenderer('0');
        }
        else if (chartConfig.chartType == 'pie') {
            labelDisplay = 'rotate';
            labelField = 'xData';
            labelContrast = true;
            renderer = function(v){
                return PTC.charting._stringLabelRenderer(v);
            };
        }
        else if (chartConfig.chartType == 'pareto') {
            renderer = function(v){
                return Math.round(v * 100) + '% ';
            };
        }
        else if (chartConfig.chartType == 'columnstacked' || chartConfig.chartType == 'barstacked' || chartConfig.chartType == 'columnclustered') {
            labelField = displayFields;
            labelDisplay = 'middle';
            if (chartConfig.chartType == "columnclustered") {
                labelDisplay = 'outside';
            }
            renderer = function(v){
                if (!v || v < 1) {
                    return "";
                }
                else {
                    return v;
                }
            };
        }
        labelConfig = {
            label: {
                field: labelField,
                minMargin: 10,
                contrast: labelContrast,
                font: dataLabelFont,
                renderer: renderer,
                display: labelDisplay,
                orientation: 'horizontal',
                'text-anchor': 'middle'
            }
        };
        Ext.apply(seriesConfig.series[0], labelConfig);
    }
    else if (chartConfig.showLegend && (chartConfig.chartType == 'pie' || chartConfig.chartType == 'columnstacked' || chartConfig.chartType == 'barstacked' || chartConfig.chartType == 'columnclustered')) {
        // Need a label config if legend is on for pie chart
        renderer = function(v){
            return PTC.charting._stringLabelRenderer(v);
        };
        if (chartConfig.chartType == 'pie') {
            labelField = 'xData';
        }
        else {
            labelField = displayFields;
        }
        labelConfig = {
            label: {
                field: labelField,
                renderer: renderer,
                display: 'none'
            }
        };
        Ext.apply(seriesConfig.series[0], labelConfig);
    }
    return seriesConfig;
};

/**
 * @private
 * This adds the chart axes to the chart item.
 */
PTC.charting._getChartAxes = function(chartConfig, axisLabelFont, axisLabelTitleFont, axisTitleFont){

    var axesConfig = null;
    var rotateLabelDegrees = 270;
    if (chartConfig.horizontalAxisLabels) {
        rotateLabelDegrees = 0;
    }
    
    // Settings for numeric axis
    var numericField = ["yData"];
    var numericPosition = "left";
    var numericTitle = chartConfig.yFieldLabel;
    var numericGrid = chartConfig.showYAxisGrid;
    var numberFormat = '0,0';
    
    // Settings for category axis
    var categoryField = "xData";
    var categoryPosition = "bottom";
    var categoryTitle = chartConfig.xFieldLabel;
    var categoryGrid = chartConfig.showXAxisGrid;
    
    var labelFillColor = '#FFFFFF';
    var labelStrokeColor = '#FFFFFF';
    // Hide axis used to show the chart title by making color same as the background
    if (chartConfig.showBackground) {
        labelFillColor = '#F2F2F2';
        labelStrokeColor = '#F2F2F2';
    }
    
    // Custom settings for some charts
    if (chartConfig.chartType == "bar" || chartConfig.chartType == "histogram_horz" || chartConfig.chartType == "barstacked") {
        rotateLabelDegrees = 0;
        numericPosition = "bottom";
        categoryPosition = "left";
        if (chartConfig.chartType == "barstacked") {
            numericField = PTC.charting._getFieldsFromChartData(Ext.util.JSON.decode(chartConfig.chartData), false);
        }
    }
    else if (chartConfig.chartType == "pareto") {
        numberFormat = '0.00';
    }
    else if (chartConfig.chartType == "columnstacked" || chartConfig.chartType == "barstacked" || chartConfig.chartType == "columnclustered") {
        numericField = PTC.charting._getFieldsFromChartData(Ext.util.JSON.decode(chartConfig.chartData), false);
    }
    
    if (((chartConfig.chartTitle === null || chartConfig.showChartInline === "true")) && chartConfig.chartType != "pie") {
        axesConfig = {
            axes: [{
                type: 'Numeric',
                minimum: 0,
                position: numericPosition,
                fields: numericField,
                title: numericTitle,
                grid: numericGrid,
                labelTitle: {
                    font: axisLabelTitleFont
                },
                label: {
                    font: axisLabelFont,
                    renderer: Ext.util.Format.numberRenderer(numberFormat)
                }
            }, {
                type: 'Category',
                position: categoryPosition,
                fields: [categoryField],
                grid: categoryGrid,
                title: categoryTitle,
                calculateCategoryCount: false,
                labelTitle: {
                    font: axisLabelTitleFont
                },
                label: {
                    font: axisLabelFont,
                    rotate: {
                        degrees: rotateLabelDegrees
                    },
                    renderer: function(v){
                        return PTC.charting._stringLabelRenderer(v);
                    }
                }
            }]
        };
    }
    else {
        // Pie only has a title so skip x and y axis
        if (chartConfig.chartType != "pie") {
        
            axesConfig = {
                axes: [{
                    type: 'Numeric',
                    minimum: 0,
                    position: numericPosition,
                    fields: numericField,
                    title: numericTitle,
                    grid: numericGrid,
                    labelTitle: {
                        font: axisLabelTitleFont
                    },
                    label: {
                        font: axisLabelFont,
                        renderer: Ext.util.Format.numberRenderer(numberFormat)
                    }
                }, {
                    type: 'Category',
                    position: categoryPosition,
                    fields: [categoryField],
                    grid: categoryGrid,
                    title: categoryTitle,
                    calculateCategoryCount: false,
                    labelTitle: {
                        font: axisLabelTitleFont
                    },
                    label: {
                        font: axisLabelFont,
                        rotate: {
                            degrees: rotateLabelDegrees
                        },
                        renderer: function(v){
                            return PTC.charting._stringLabelRenderer(v);
                        }
                    }
                }, {
                    // This is used to show the chart title in preview mode only, axis not shown, just label
                    type: 'Numeric',
                    position: 'top',
                    fields: numericField,
                    title: chartConfig.chartTitle,
                    dashSize: 0,
                    labelTitle: {
                        font: axisTitleFont
                    },
                    label: {
                        fill: labelFillColor,
                        stroke: labelFillColor,
                        font: '7px Arial' //  make small so it takes up less room, not actually shown
                    },
                    axisStyle: {
                        fill: labelFillColor,
                        stroke: labelFillColor
                    }
                }]
            };
        }
        else {
            // Only title for pie chart in preview mode
            if (chartConfig.showChartInline == "false") {
                axesConfig = {
                    axes: [{
                        // This is used to show the chart title in preview mode only, axis not shown, just label
                        type: 'Numeric',
                        position: 'top',
                        fields: ['yData'],
                        title: chartConfig.chartTitle,
                        dashSize: 0,
                        labelTitle: {
                            font: axisTitleFont
                        },
                        label: {
                            fill: labelFillColor,
                            stroke: labelFillColor,
                            font: '7px Arial' //  make small so it takes up less room, not actually shown
                        },
                        axisStyle: {
                            fill: labelFillColor,
                            stroke: labelFillColor
                        }
                    }]
                };
            }
        }
    }
    // Set max ticks if less than 6 ticks, else ExtJs repeats y axis labels
    if (chartConfig.chartType != "pie" && chartConfig.chartType != "pareto") {
        var maxNumericValue = PTC.charting._getMaxValue(chartConfig.chartData, numericField);
        var axisConfigAddition;
        if (maxNumericValue > 0 && maxNumericValue < 11) {
            axisConfigAddition = {
                majorTickSteps: maxNumericValue - 1,
                maximum: maxNumericValue
            };
            Ext.apply(axesConfig.axes[0], axisConfigAddition);
        }
        
        if (chartConfig.chartType == "histogram") {
            axisConfigAddition = {
                dashSize: 0
            };
            Ext.apply(axesConfig.axes[1], axisConfigAddition);
        }
        else if (chartConfig.chartType == "histogram_horz") {
            axisConfigAddition = {
                dashSize: 0
            };
            Ext.apply(axesConfig.axes[1], axisConfigAddition);
        }
    }
    return axesConfig;
};


/*
 * Namespace for Structured Enumeration Picker
 */

Ext.namespace('PTC.search.clfComp');

PTC.search.clfComp.logger = log4javascript.getLogger("PTC.search.clfComp");

/*
 * Following function is used when we select node vlaue from clasification search picker is advance search page. It
 * renders selected node value in respective Classification binding attribute i.e. fieldId Also updated searchNodes
 * hidden parameter value and makes AJAX call to render classification node attributes in QB.
 */
PTC.search.clfComp.classificationPickerCallBack = function(pickerObject, fieldId, attr, displayFieldId) {

    PTC.search.clfComp.logger.debug("Entering to PTC.search.clfComp.classificationPickerCallBack");
    PTC.search.clfComp.logger.debug("fieldId-->" + fieldId);
    PTC.search.clfComp.logger.debug("displayFieldId-->" + displayFieldId);

    // call default call back of picker which renders selected node value in binding attribute picker.
    PTC.search.picker.structuredEnumerationCallBack(pickerObject, fieldId, attr, displayFieldId);

    // change class name of value field so that it is consistent to autosuggest.
    document.getElementById(displayFieldId).className = "pickerInputValueComponent x-form-field";

    var internalName = '';
    // its radio button selection so probably run only once.
    var pickedObjects = pickerObject.pickedObject;
    for (var i = 0; i < pickedObjects.length; i++) {
        internalName = pickedObjects[i]["internalName"];
    }

    // we need only internal value which is present after last occurance of |
    internalName = internalName.substring(internalName.lastIndexOf("|") + 1, internalName.length);

    PTC.search.clfComp.logger.debug("Internal Name Without Binding Attribute-->" + internalName);
    // get Previous searchNodes value if present then add as comma separated value.
    var searchNodes = document.getElementById('searchNodes').value;
    PTC.search.clfComp.logger.debug("Existing Search Nodes-->" + searchNodes);

    // update classification node value in search nodes at appropriate row number.
    searchNodes = PTC.search.clfComp.updateClfNodeValue(searchNodes, fieldId.substring(fieldId.lastIndexOf('$') + 1, fieldId.length), internalName);

    document.getElementById('searchNodes').value = searchNodes;
    // make ajax call to render classification node attribute in QB.
    PTC.search.handleQueryBuilder();
    PTC.search.clfComp.logger.debug("exiting from PTC.search.clfComp.classificationPickerCallBack");
};

/*
 * Following function is used in Callback for Classification node search picker is advance search page. It renders
 * Selected node value in respective Classification binding attribute i.e. fieldId Also updated SearchNodes hidden
 * parameter value and makes AJAX call to render classification node attributes in QB.
 */
PTC.search.clfComp.clearClassificationPickerValue = function(fieldId, displayFieldId) {
    PTC.search.clfComp.logger.debug("Entering to PTC.search.clfComp.clearClassificationPickerValue");

    var displayField = document.getElementById(displayFieldId);

    // get previous selected node value for binding attribute
    var nodeValue = displayField.value;
    PTC.search.clfComp.logger.debug("Previous Node Value -->" + nodeValue);

    // call default picker clear function which clears picker value
    PTC.search.picker.clearStructuredEnumerationPickerValue(fieldId, displayFieldId);

    if(displayField!==null && displayField.contentEditable){
    	displayField.focus();
    }

    // remove entry from searchNodes hidden parameter value
    var searchNodes = document.getElementById('searchNodes').value;
    PTC.search.clfComp.logger.debug("Existing SearchNodes -->" + searchNodes);
    if (searchNodes !== '') {
        var rowNum = fieldId.substring(fieldId.lastIndexOf('$') + 1, fieldId.length);
        searchNodes = PTC.search.clfComp.updateClfNodeValue(searchNodes, rowNum, ' ');
    }
    document.getElementById('searchNodes').value = searchNodes;
    // call to re-render QB using updated classification node values.
    PTC.search.handleQueryBuilder();

    PTC.search.clfComp.logger.debug("Exiting from PTC.search.clfComp.clearClassificationPickerValue");
};

/*
 * Function is used to remove a value from list which is constructed using delimiter - separator and return updated list
 */
PTC.search.clfComp.removeValue = function(list, separator, rowNum) {
    PTC.search.clfComp.logger.debug("Entering in PTC.search.clfComp.removeValue");
    PTC.search.clfComp.logger.debug("list --> " + list);
    PTC.search.clfComp.logger.debug("separator --> " + separator);
    var refreshQB = false;
    separator = separator || ",";
    var values = list.split(separator);
    for (var i = 0; i < values.length; i++) {
        if (values[i].split(':')[2] == rowNum) {
            if (values[i].split(':')[1].trim() !== '') {
                refreshQB = true;
            }
            values.splice(i, 1);
            values.join(separator);
            break;
        }
    }
    document.getElementById("searchNodes").value = values;
    PTC.search.clfComp.logger.debug("Exiting from PTC.search.clfComp.removeValue");
    return list;
};

PTC.search.clfComp.onClfSearchSuggestSelect = function(event, displayField, hiddenId, attr) {
    var pickerObject = PTC.search.clfComp.onSuggestSelect(event, displayField, hiddenId, attr);
    PTC.search.clfComp.classificationPickerCallBack(pickerObject, hiddenId, attr, displayField);
};

PTC.search.clfComp.onClfPartSuggestSelect = function(event, displayField, hiddenId, attr) {
    var pickerObject = PTC.search.clfComp.onSuggestSelect(event, displayField, hiddenId, attr);
    PTC.csm.classificationPickerCallBack(pickerObject, hiddenId, attr, displayField);
};

PTC.search.clfComp.onSuggestSelect = function(event, displayField, hiddenId, attr) {
    PTC.search.clfComp.logger.debug("Entering in PTC.search.clfComp.onSuggestSelect");
    var pickerObject = {};

    var elements = event.storeConfig.reader.jsonData.results;
    var suggestSep = '~~SEP~~';

    for (var i = 0; i < elements.length; i++) {
        // Value text comes as Internal name and Full Path of classification node combined with ~~SEP~~, For Example
        // CHIPSET~~SEP~~PART/Electronic Parts/CHIPSET
        var selectedValText = elements[i].valueText;

        // Display text comes as Display name of classification node combined with count of parts classified against
        // that
        // node For Example, Chipset(1)
        var selectedDispText = elements[i].displayText;

        // Additional text comes as full path of classification node is spilt at the center with ellipsis if the length
        // is
        // more than defined limit, default 100
        var selectedPath = elements[i].additionalText;

        if (selectedValText === event.value) {
            var valueTextList = selectedValText.split(suggestSep);

            if (valueTextList.length > 0) {
                var jsonPickedObject = {};

                var partCountIndex = selectedDispText.lastIndexOf(' (');
                if (partCountIndex > -1) {
                    var nodeName = selectedDispText.substring(0, partCountIndex);
                    document.getElementById(displayField).value = nodeName;
                    elements[i].displayText = nodeName;
                    event.lastSelectionText = nodeName;

                    jsonPickedObject["name"] = nodeName;
                } else {
                    jsonPickedObject["name"] = selectedDispText;
                }

                jsonPickedObject["parent"] = "";
                jsonPickedObject["internalName"] = valueTextList[0];
                //SPR #4818006 - this is to convert "boolean" to boolean
                jsonPickedObject["enforceAutoNamingRule"] = JSON.parse(valueTextList[1]);
                jsonPickedObject["fullPath"] = valueTextList[2];

                var jsonArray = [];
                jsonArray.push(jsonPickedObject);

                pickerObject["pickedObject"] = jsonArray;

                // PTC.search.clfComp.classificationPickerCallBack(pickerObject,hiddenId,attr,displayField);
            }
            break;
        }
    }
    PTC.search.clfComp.logger.debug("Exiting from PTC.search.clfComp.onSuggestSelect");

    return pickerObject;
};

/*
 * This method is called to update classification node value in searchNodes
 */
PTC.search.clfComp.updateClfNodeValue = function(searchNodes, rowNum, clfNodeValue) {
    var values = searchNodes.split(',');
    for (var i = 0; i < values.length; i++) {
        var bArr = values[i].split(':');
        if (bArr[2] == rowNum) {
            var updatedNode = bArr[0] + ':' + clfNodeValue + ':' + rowNum;
            values[i] = updatedNode;
            return values.join(',');
        }
    }
};

/*
 * This method is called on onchange event of classificationPickerComponent. It removes old entry from searchNodes
 * hidden input and puts current value. e is event , textBoxElement is value component for picker and attrId is binding
 * attribute value.
 */

PTC.search.clfComp.changeSearchNodes = function(e, textBoxElement, attrId, rowNum) {
    PTC.search.clfComp.logger.debug("Entering to PTC.search.clfComp.changeSearchNodes");
    var searchNodeEle = document.getElementById('searchNodes');

    var displayValue = document.getElementById(textBoxElement.id).value;
    PTC.search.clfComp.logger.debug("Display value -->" + displayValue);

    var hiddenValue = document.getElementById(attrId + '$' + rowNum).value;
    PTC.search.clfComp.logger.debug("Hidden value -->" + hiddenValue);

    var searchNodes = searchNodeEle.value;
    searchNodes = PTC.search.clfComp.updateClfNodeValue(searchNodes, rowNum, displayValue.trim() === '' ? ' ' : hiddenValue);

    searchNodeEle.value = searchNodes;
    PTC.search.handleQueryBuilder();

    PTC.search.clfComp.logger.debug("Exiting from PTC.search.clfComp.changeSearchNodes");
};

/*
 * update search nodes depending upon type selection.
 */

PTC.search.clfComp.updateSearchNodes = function() {
    PTC.search.clfComp.logger.debug("Entering to PTC.search.clfComp.updateSearchNodes");
    var typeBindAttr = PTC.search.clfComp.typeWiseClfBindAttr;
    var searchTypes = document.getElementById('searchType').value;
    var searchNodes = document.getElementById('searchNodes');

    PTC.search.clfComp.logger.debug("Type Wise binding attribute json :" + typeBindAttr);
    PTC.search.clfComp.logger.debug("selected search Types :" + searchTypes);
    PTC.search.clfComp.logger.debug("search Nodes :" + searchNodes);
    // if All types selected then clear searchNodes and return
    if (searchTypes == 'wt.fc.Persistable') {
        searchNodes.value = '';
        return;
    }

    // check whether selected types are present in type wise binding attribute Json. If not then remove from Json.
    for ( var type in typeBindAttr) {
        var typePresent = false;
        var values = searchTypes.split(",");
        for (var typeCnt = 0; typeCnt < values.length; typeCnt++) {
            var selectedType = values[typeCnt];
            if (selectedType.indexOf('WCTYPE|') == -1) {
                selectedType = 'WCTYPE|' + selectedType;
            }
            if (selectedType == type) {
                typePresent = true;
                break;
            }
        }
        if (typePresent !== true) {
            if (typeBindAttr.hasOwnProperty(type)) {
                delete typeBindAttr[type];
            }
        }
    }

    // keep binding attribute values in searchNodes field only for those whose type is present in Json.
    if (searchNodes.value !== '') {
        var searchNodeValues = searchNodes.value.split(",");
        for (var nodeCnt = 0; nodeCnt < searchNodeValues.length; nodeCnt++) {
            var clfAttr = searchNodeValues[nodeCnt].split(":")[0];
            var rowNum = searchNodeValues[nodeCnt].split(":")[2];
            var attrPresent = false;

            for ( var typeName in typeBindAttr) {
                var data = typeBindAttr[typeName].attributes;
                for (var i = 0; i < data.length; i++) {
                    if (clfAttr == data[i]) {
                        attrPresent = true;
                        break;
                    }
                }
                if (attrPresent) {
                    break;
                }
            }

            // if Attribute is not present for any selected type then remove it from searchNodes.
            if (!attrPresent) {
                searchNodes.value = PTC.search.clfComp.removeValue(searchNodes.value, ',', rowNum);
            }
        }
    }
    PTC.search.clfComp.logger.debug("Exiting from PTC.search.clfComp.updateSearchNodes");
};

/*
 * Renders the clf row again after the clf criteria is changed
 */
PTC.search.clfComp.loadClfTableAfterChange = function(response, options) {

    var responseJSON = Ext.util.JSON.decode(response.responseText);
    var rowElement = document.getElementById('clfQbrow' + options.params['rownum']);

    Element.update(rowElement, responseJSON.htmlRow);

    rowElement.id = 'clfQbrow' + options.params['rownum'];
    rowElement.onmouseover = PTC.search.clfComp.highlightClfRow;
    rowElement.onmouseout = PTC.search.clfComp.deHighlightClfRow;
    PTC.search.clfComp.drawClfCriteriaComboFromData(options.params['rownum'], options.params['attributeName'], options.params['isObsolete']);
    document.getElementById("searchNodes").value = responseJSON.searchNodes;
    PTC.search.handleQueryBuilder();
};

/*
 * Removes the entry for a particular row from searchNodes
 */
PTC.search.clfComp.updateSearchNodeDiv = function(rowNum) {

    PTC.search.clfComp.logger.debug("Deletes the content of row " + rowNum + " from searchNodes div");
    var nodes = document.getElementById("searchNodes").value;
    var refreshQB = false;

    if (nodes !== '') {
        var values = nodes.split(',');
        for (var i = 0; i < values.length; i++) {
            var nodesArr = values[i];
            var tempArr = nodesArr.split(':');
            if (tempArr[2] == rowNum) {
                var updatedNode = tempArr[0] + ': :' + rowNum;
                values[i] = updatedNode;
                values.join(',');
                if (tempArr[1].trim() !== '') {
                    refreshQB = true;
                }
                break;
            }
        }
        document.getElementById("searchNodes").value = values;
    }
    return refreshQB;
};

/*
 * Changes clf binding attribute row after making any selection from clf dropdown
 */
PTC.search.clfComp.changeClfRow = function(combo) {

    PTC.search.clfComp.logger.debug("Changing clf criteria to " + combo.getValue);
    PTC.search.clfComp.updateSearchNodeDiv(combo.rowNum);
    var searchNodes = document.getElementById('searchNodes').value;
    var form = getMainForm();
    var CSRF_NONCE = (form.CSRF_NONCE) ? form.CSRF_NONCE.value : "";
    Ext.Ajax.request({
        url: getBaseHref() + 'ptc1/classificationUI/addChangeClfRow',
        success: PTC.search.clfComp.loadClfTableAfterChange,
        params: {
            searchtypes: document.getElementById('searchType').value,
            rownum: combo.rowNum,
            attributeID: clfBindingAttributes.getAt(combo.selectedIndex).get('AttributeInternalValue'),
            attributeName: combo.getValue(),
            searchNodes: searchNodes,
            CSRF_NONCE : CSRF_NONCE
        }
    });

    clfCriteriaStore.removeAt(combo.rowNum);
    clfCriteriaStore.insert(combo.rowNum, new clfCriteriaStore.recordType({
        "RowNum": combo.rowNum,
        "AttributeDisplayName": combo.getValue(),
        "AttributeInternalValue": clfBindingAttributes.getAt(combo.selectedIndex).get('AttributeInternalValue')
    }));
};

/*
 * Draw clf criteria combo from searchNodes
 */
PTC.search.clfComp.drawClfCriteriaCombo = function() {
    PTC.search.clfComp.logger.debug("Draw clf criteria combo box");
    for (var i = 0; i < clfCriteriaStore.getCount(); i++) {
        PTC.search.clfComp.drawClfCriteriaComboFromData(clfCriteriaStore.getAt(i).data.RowNum, clfCriteriaStore.getAt(i).data.AttributeDisplayName, clfCriteriaStore.getAt(i).data.isObsolete);
    }
};

// deletes the specified clf criteria row
PTC.search.clfComp.deleteMyClfRow = function(rowId, rownum) {
    PTC.search.logger.debug("Deleting row number " + rownum);
    var mytable = document.getElementById('clfQbtable');
    var rowElement = document.getElementById(rowId);
    var rowindex = rowElement.rowIndex;
    mytable.deleteRow(rowindex);
    clfCriteriaStore.removeAt(rownum);
    var searchNodes = document.getElementById('searchNodes').value;
    var refreshQb = PTC.search.clfComp.removeValue(searchNodes, ',', rownum);
    if (refreshQb) {
        PTC.search.handleQueryBuilder();
    }
};

// adds clf binding attribute row below the given row
PTC.search.clfComp.addClfCriteriaRow = function(rowNum) {
    PTC.search.logger.debug("Adding row under row number " + rowNum);
    var searchNodes = document.getElementById('searchNodes').value;
    var nextAvailableRowNo = PTC.search.clfComp.getMaxRowNumber(clfCriteriaStore);
    var form = getMainForm();
    var CSRF_NONCE = (form.CSRF_NONCE) ? form.CSRF_NONCE.value : "";
    Ext.Ajax.request({
        url: getBaseHref() + 'ptc1/classificationUI/addChangeClfRow',
        success: PTC.search.clfComp.loadClfTable,
        failure: PTC.search.clfComp.refreshSearchPage,
        params: {
            searchtypes: document.getElementById('searchType').value,
            rownum: nextAvailableRowNo,
            rowNumToInsertUnder: rowNum,
            attributeID: clfBindingAttributes.getAt(0).get('AttributeInternalValue'),
            searchNodes: searchNodes,
            CSRF_NONCE : CSRF_NONCE
        }
    });

};

//Refresh the search page when session is expire
PTC.search.clfComp.refreshSearchPage = function() {
	
    JCAAlert('com.ptc.windchill.enterprise.search.client.searchClientResource.SESSION_EXPIRED_MSG');
    loadAdvSearchPage(null,"wtcore/jsp/com/ptc/windchill/search/Search.jsp"); 
	   
}

// This function iterates classification stores and gets maximum available rowNumber to ensure it is not duplicate
PTC.search.clfComp.getMaxRowNumber = function(store) {
    var nextAvailableRowNo = 0;
    for (var i = 0; i < store.getCount(); i++) {
        var rowNum = parseInt(store.data.items[i].data.RowNum, 10);
        if (rowNum > nextAvailableRowNo) {
            nextAvailableRowNo = rowNum;
        }
    }
    return nextAvailableRowNo + 1;
};

// this function does the rendering of new row
PTC.search.clfComp.loadClfTable = function(response, options) {

    PTC.search.logger.debug("Load clf row after the add row button is clicked");
    var responseJSON = Ext.util.JSON.decode(response.responseText);

    var rowElementToInsertUnder = document.getElementById('clfQbrow' + options.params['rowNumToInsertUnder']).rowIndex;
    var rowElement = document.getElementById('clfQbtable').insertRow(rowElementToInsertUnder + 1);
    Element.update(rowElement, responseJSON.htmlRow);
    rowElement.id = 'clfQbrow' + options.params['rownum'];
    rowElement.onmouseover = PTC.search.clfComp.highlightClfRow;
    rowElement.onmouseout = PTC.search.clfComp.deHighlightClfRow;

    var nextAvailableRowNo = PTC.search.clfComp.getMaxRowNumber(clfCriteriaStore);

    clfCriteriaStore.add(new clfCriteriaStore.recordType({
        "RowNum": options.params['rownum'],
        "AttributeDisplayName": clfBindingAttributes.getAt(0).get('AttributeDisplayName'),
        "AttributeInternalValue": clfBindingAttributes.getAt(0).get('AttributeInternalValue'),
        "isObsolete": false
    }));

    PTC.search.clfComp.drawClfCriteriaComboFromData(nextAvailableRowNo, clfBindingAttributes.getAt(0).get('AttributeDisplayName'), clfBindingAttributes.getAt(0).get('isObsolete'));
    document.getElementById("searchNodes").value = responseJSON.searchNodes;
};

PTC.search.clfComp.drawClfCriteriaComboFromData = function(rowNum, attributeDisplayName, isObsolete) {
    // render obsolete image with criteria before criteria
    if (isObsolete) {
        var obsoleteToolTip = bundleHandler.get('com.ptc.windchill.enterprise.search.client.searchClientResource.INVALID_QUERYBUILDER_ROW');
        var tooltip = 'ext:qtip="' + obsoleteToolTip + '"';
        var obimg = "<img " + tooltip + " width='11' height='11' align='middle' src='netmarkets/images/not_synched.gif' border='0'/>";
        var bottomLabelCtrl = new Ext.form.Label({
            cellCls: 'pbarLabel',
            renderTo: 'clfCriteriaIconDiv' + rowNum,
            autoWidth: true,
            defaultAlign: 'tl-bl',
            cls: 'x-tip-header-text',
            style: {
                marginRight: '5px'
            },
            html: obimg
        });
    }
    var combo = new Ext.form.ComboBox({
        fieldLabel: ' ',
        width: 159,
        tpl: '<tpl for="."><div ext:qtip="{AttributeDisplayName}" class="x-combo-list-item">{AttributeDisplayName}</div></tpl>',
        xtype: 'combo',
        store: clfBindingAttributes,
        displayField: 'AttributeDisplayName',
        valueField: 'AttributeDisplayName',
        value: attributeDisplayName,
        triggerAction: 'all',
        typeAhead: true,
        mode: 'local',
        forceSelection: true,
        renderTo: 'clfCriteriaDiv' + rowNum,
        id: 'clfCriteriaCombo' + rowNum,
        rowNum: rowNum,
        disabled: isObsolete,
        // decoded the last selected value
        setValue: function(v) {
            PTC.search.decodeSelectedValueOfExtJSCombo(v, this);
        },
        listeners: {
            'afterrender': function() {
                PTC.search.setWidthToParentElementOfExtCombo(this);
            },
            select: function(combo) {
                PTC.search.clfComp.changeClfRow(combo);
            }
        }
    });
};

// Highlight classification criteria row on mouse over
PTC.search.clfComp.highlightClfRow = function() {
    this.childNodes[0].className = 'QBRowHighlight';
    this.childNodes[3].className = 'QBRowHighlight';
    if (this.childNodes[3].childNodes[0].lastChild.tagName == 'SPAN') {
        this.childNodes[3].childNodes[0].lastChild.style.visibility = 'visible';
    }
};

// Dehighlight classification criteria row on mouse out
PTC.search.clfComp.deHighlightClfRow = function() {
    this.childNodes[0].className = '';
    this.childNodes[3].className = '';
    if (this.childNodes[3].childNodes[0].lastChild.tagName == 'SPAN') {
        this.childNodes[3].childNodes[0].lastChild.style.visibility = 'hidden';
    }
};


Ext.namespace('PTC.search.ClfExplorer');

/**
 * This is to get the dropDown data i.e. classification binding attributes. It
 * calls the controller - ClassificationExplorerTreeController and processes the
 * JSON result received from the controller.
 */

PTC.search.ClfExplorer.cbaList = {};
var preference = "";
PTC.search.ClfExplorer.getDropDownData=function()
{
	PTC.search.logger.debug('Inside PTC.search.ClfExplorer.getDropDownData');
	Ext.Ajax.request({
		url : 'ptc1/clfExplorerTree',
	    success : function(response) {
			PTC.search.logger.debug('Returned successfully inside PTC.search.ClfExplorer.getDropDownData');
	    	var _response = Ext.util.JSON.decode(response.responseText);
	    	PTC.search.logger.debug(_response.dropDownData);

	    	PTC.search.ClfExplorer.cbaList = new Ext.data.JsonStore({
				id: 'cbaList',
	    		data : _response.dropDownData,
	    		autoLoad: true,
	    		fields: [ 'typeInternal', 'typeDisplay', 'cbaInternal', 'cbaDisplay', 'cbaAndTypeInternal','cbaPreference']
			});
	    	preference = _response.preferenceData.cbaPreference;
	        if(_response.dropDownData.length > 1){
	        	PTC.search.ClfExplorer.showDropDown(_response);
	        }else{
	        	PTC.search.logger.debug('Going to hide the dropDown and show the label instead');
	        	document.getElementById('singleCBALabel').visibility='visible';
	        	//get the defaultValue . It could either be Preference or (1st) entry in the JSONStore.
	        	var defaultValue = PTC.search.ClfExplorer.getDefaultCBA(PTC.search.ClfExplorer.cbaList);
	        	PTC.search.logger.debug('Got the default value as :'+ defaultValue);
	        	var index = Ext.StoreMgr.lookup("cbaList").findExact('cbaAndTypeInternal', defaultValue);
	        	//get display value from the internalValue
	        	var defaultDispValue = PTC.search.ClfExplorer.cbaList.data.items[index].data.cbaDisplay;
	        	PTC.search.logger.debug('Going to set the default displayValue as :'+ defaultDispValue);
	        	document.getElementById('singleCBALabel').innerHTML = defaultDispValue;
	        	//referesh the clf tree
	        	PTC.search.ClfExplorer.refreshClfTree(_response.dropDownData[0].cbaAndTypeInternal, PTC.search.ClfExplorer.cbaList);
	        }
	    },
	    failure : function(response) {
	    	PTC.search.logger.debug('server-side failure with status code ' + response.status);
	    }

	});
}

/**
 * This is to actaully draw the extJS dropdown with the store data as JSON data
 * received from the controller
*/

PTC.search.ClfExplorer.showDropDown=function(_response)
{

	PTC.search.logger.debug('Inside PTC.search.ClfExplorer.showDropDown');
	Ext.QuickTips.init();
	Ext.apply(Ext.QuickTips.getQuickTip(), {
        dismissDelay: 0,
        showDelay: 0
    });

    var myCombo = new Ext.form.ComboBox({
		xtype : 'combo',
		id: 'cbaDropDown',
		tpl: '<tpl for="."><div ext:qtip="{cbaDisplay}" class="x-combo-list-item">{cbaDisplay}</div></tpl>',
		store: 'cbaList',
		displayField:'cbaDisplay',
		valueField: 'cbaAndTypeInternal',
		triggerAction:'all',
		mode: 'local',
		forceSelection: true,
		typeahead: true,
		width:160 ,
	    renderTo: 'CBADropDown',
	    listeners:{
            'afterrender' :function(combo) {
                PTC.search.setWidthToParentElementOfExtCombo(this);
                var defaultValue = PTC.search.ClfExplorer.getDefaultCBA(PTC.search.ClfExplorer.cbaList);
                //set defaultValue. It could either be preference OR the first entry in the list.
                combo.setValue(defaultValue);
                combo.fireEvent('select',combo,combo.valueModels);
            },
            select : function(combo) {
                PTC.search.ClfExplorer.refreshClfTree(combo.getValue());
            }

     	}
	});
}

/*
* Render clf tree and refresh browse page in clfExplorerTree div based on the constraint defined on
* binding attribute selected through dropdown
*/
PTC.search.ClfExplorer.refreshClfTree = function(value) {

	var index = 0;

	if (value != '') {
	   index = Ext.StoreMgr.lookup("cbaList").findExact('cbaAndTypeInternal', value);
	}

	var typeInternalName = PTC.search.ClfExplorer.cbaList.data.items[index].data.typeInternal;
	var attrInternalName = PTC.search.ClfExplorer.cbaList.data.items[index].data.cbaInternal;

	// send request to refreshClfTree using parameters attributeName, objectTypeName and selectedObjectTypes
	// and render the response in clfExplorerTree
	var sForm = Ext.Ajax.serializeForm(getMainForm(Ext.get('CBADropDown')));
	var url = "ptc1/clfExplorerTree/refreshClfTree?attributeName="+attrInternalName+"&objectTypeName="+typeInternalName;
   	getElementHtml(sForm, 'clfExplorerTree', true /*async*/, url, false /*fade*/);

   	// pass without class name because on selection of dropdown we want to refresh browse page
   	// based on the constraint defined on the binding attribute selected
   	PTC.search.ClfExplorer.refreshClfBrowsePage("");

}

//Story#2657031 : maintain globalBrowseNode to make the clf explorer sticky.
PTC.search.globalBrowseNode = "";
PTC.search.ClfExplorer.refreshClfBrowsePage = function(className) {

	var index = 0;
	if (PTC.search.ClfExplorer.cbaList.data.items.length > 1) {
		var value = Ext.getCmp('cbaDropDown').getValue();
		index = Ext.StoreMgr.lookup("cbaList").findExact('cbaAndTypeInternal', value);
	}
        var typeInternalName = PTC.search.ClfExplorer.cbaList.data.items[index].data.typeInternal;
        var attrInternalName = PTC.search.ClfExplorer.cbaList.data.items[index].data.cbaInternal;

    	PTC.search.logger.debug('Inside refreshClfBrowsePage...');
    	PTC.search.logger.debug('received className as= ' + className);
    	var localClassName = "";
    	if(PTC.search.LeafFromTree){
    		//this is to clear the breadcrumb node when search was actually performed by clicking a leaf node in clf tree
    		PTC.search.globalBrowseNode ="";
    	}
    	if(className != ''){
    		//update PTC.search.globalBrowseNode with the one selected earlier.
    		PTC.search.globalBrowseNode = className;
    	}
    	if(PTC.search.doNotMaintainStickiness){
    		//this is when stickiness is not to be maintained.
    		PTC.search.globalBrowseNode = "";
    		PTC.search.oldFreeFormText = "";
    	}else{
    		//set it to true by default not to maintain stickiness further till next Search is performed.
    		PTC.search.doNotMaintainStickiness = true;
    	}
    	//class variable also comes into picture when a parent node is clicked from the tree.
    	if(PTC.search.globalBrowseNode == ''){
    		localClassName = className;
    	}else{
    		localClassName = PTC.search.globalBrowseNode;
    	}

    	PTC.search.logger.debug('Values before exiting refreshClfBrowsePage=> ');
    	PTC.search.logger.debug('PTC.search.doNotMaintainStickiness= ' + PTC.search.doNotMaintainStickiness);
    	PTC.search.logger.debug('PTC.search.globalBrowseNode= ' + PTC.search.globalBrowseNode);
    	PTC.search.logger.debug('class= ' + localClassName);

    	var sForm = Ext.Ajax.serializeForm(getMainForm(Ext.get('CBADropDown')));
    	url = "ptc1/clfExplorerTree/refreshClfBrowsePage?attributeName="+attrInternalName+"&objectTypeName="+typeInternalName+
    	        "&class="+localClassName+"&currentBreadCrumbNode="+PTC.search.globalBrowseNode+"&freeFormSearchBox="+PTC.search.oldFreeFormText;
        	PTC.search.ClfExplorer.refreshClfContentArea(url,PTC.search.globalBrowseNode);
}

/*
* Render search result table in clfSplitPanelDiv by setting search type and search nodes
* parameters. This function gets called when: 1) a leaf node from clf tree is clicked.
* 2) a leaf node in the browse model is clicked.
* 3) Search button on breadcrumb is clicked from Classification Explorer
*/
PTC.search.LeafFromTree = "";
PTC.search.ClfExplorer.searchWithClf = function(nodeName,currentBreadCrumbNode,fromTree) {

	PTC.search.logger.debug('Inside searchWithClf...');
	PTC.search.logger.debug('nodeName= '+ nodeName + 'currentBreadCrumbNode= '+ currentBreadCrumbNode + 'fromTree= ' + fromTree);

	PTC.search.LeafFromTree = fromTree;

	//this case needs to be handled to maintain stickiness on breadcrumb when
	// a parent node is clicked from the tree and then the search is performed from breadcrumb.
	//'fromTree' is passed in the URL from freeFormRedirect.jsp when a leaf node is clicked from the tree.
	if(currentBreadCrumbNode == undefined && !PTC.search.LeafFromTree){
		currentBreadCrumbNode=nodeName;
	}

	//this is to maintain stickiness for browse and freeform when search is performed.
	PTC.search.doNotMaintainStickiness = false;

	//reset PTC.search.oldFreeFormText to blank
	PTC.search.oldFreeFormText ="";

	//Story#2650731 :-> this is to store the latest ancestor when clicked on a child node.
	if(currentBreadCrumbNode){
			PTC.search.globalBrowseNode = currentBreadCrumbNode;
	}

	var index = 0;
	if (PTC.search.ClfExplorer.cbaList.data.items.length > 1) {
		var value = Ext.getCmp('cbaDropDown').getValue();
		index = Ext.StoreMgr.lookup("cbaList").findExact('cbaAndTypeInternal', value);
	}

	var typeInternalName = PTC.search.ClfExplorer.cbaList.data.items[index].data.typeInternal;
	var attrInternalName = PTC.search.ClfExplorer.cbaList.data.items[index].data.cbaInternal;

	var searchNodes = attrInternalName+":"+nodeName+":0";

	// send request to searchResults for searching classified parts on the given node
	var sForm = Ext.Ajax.serializeForm(getMainForm(Ext.get('CBADropDown')));
	//Story#2657031 -> Changed the url to clfSearchResults controller.
	var url = "ptc1/clfSearchResults?searchType="+typeInternalName+"&searchNodes="+encodeURI(searchNodes);

	loadAdvSearchPage("event",url);
	}

/*
* This is to set the default value in the CBA dropdown .
* It could either be the preference value OR the first value present in the dropdown
*/
 PTC.search.ClfExplorer.getDefaultCBA = function(){

 	PTC.search.logger.debug('Preference value read from the JSON response is : ' +preference);
 	if((preference == '')||(preference == null)||(preference === undefined)){
		var defaultValue = PTC.search.ClfExplorer.cbaList.data.items[0].data.cbaAndTypeInternal;
		PTC.search.logger.debug('Returning default value as : ' +defaultValue);
		return defaultValue;
 	}
	else {
		PTC.search.logger.debug('Returning default value as : ' +preference);
		return preference;
 	}
 }



/**
 * This method is used to expand the Panel, this method will get call on click on Classification Explorer tab. Method
 * will set the classification panel width to 70% of window if it is not pinned.
 */
PTC.search.ClfExplorer.expandClfExplorerPanel = function() {
    	PTC.search.ClfExplorer.navigatorPanel = Ext.getCmp("navigatorPanel");
    	PTC.search.ClfExplorer.navigatorWidth = getWindowWidth() * 0.70;
    	// When user navigates to classification explorer link from search results page, the SearchInTable field needs to be cleared.
		if (!PTC.navigator.getNavigator().pinned) {
    		var navigatorLeftPosition=Ext.get("navigatorPanel-xcollapsed").getStyle("left");
    		if(navigatorLeftPosition != "0px"){
            		PTC.search.ClfExplorer.navigatorPanel.setWidth(PTC.search.ClfExplorer.navigatorWidth);
         		PTC.search.ClfExplorer.navigatorPanel.doLayout();

	        	var navigatorWidthInPx = PTC.search.ClfExplorer.navigatorWidth + "px";
       			Ext.get("navigatorPanel-xcollapsed").setStyle("left", navigatorWidthInPx);
        		navigatorWidthInPx = PTC.search.ClfExplorer.navigatorWidth + Ext.get("navigatorPanel-xcollapsed").getWidth() + "px";
        		Ext.get(Ext.select('.x-resizable-handle-east').item(0).id).setStyle("left", navigatorWidthInPx);

        		Ext.getCmp('contentPanel_contentArea').doLayout();
        }
    }
    PTC.search.clearSearchInTable();   
}

