/**
 * @namespace
 * For functions and properties used by the 'Copy Page' option available in the 'Quick Links' menu in the header
 */
PTC.copyPageAction = {};

function copyObjectMainAll(fe, copyurl, copyelements, isDCA, alertMessage, noneSelectMessage, skipCount, unselectwhendone, dontDecode, skipValidation){

    // var soid = getSelectedObjectsExternal(copyelements, isDCA);
    var soid = [];
    if (!copyelements) {
        copyelements = getSelectedItems();
    }
    var alength = copyelements.length;
    for (var i = 0; i < alength; i++) {
        var copyelement = copyelements[i];
        if (copyelement.checked && copyelement.name.indexOf("select_all") < 0 && copyelement.value != 'select_all' && copyelement.name != "checkbox3") {
            var param = new P();
            param.n = "soid";
            if (isDCA) {
                param.v = requestHandler.processDCAInputValue(copyelement);
            } else {
                param.v = copyelement.value;
            }
            soid.push(param);
        }
    }

    // build the URL to the copy JSP page with the OID's as params

    //create a new array that is the size of the selected elements from method above

    paramurl = buildStringParam(soid);
    if (copyurl.indexOf("soid") <= 0 && paramurl.length < 1) {
        if (noneSelectMessage) {
            wfalert(noneSelectMessage);
        } else {
            wfalert("Nothing Selected.");
        }
    } else {
        // only need to validate clipboard when not doing a multi-select, clipboard doesn't want 2 versions of the same object
        if (skipValidation || callAJAXValidation('copy')) {
            postToUrl(fe, copyurl, paramurl, false, alertMessage, skipCount, noneSelectMessage, isDCA, unselectwhendone, dontDecode);
        }
    }
}

/**
 * function called when 'Copy Page' is clicked
 * @param {String} url - the url to the copy action (e.g. ptc1/object/copy
 * @param {Object} event - the browser click event
 */
PTC.copyPageAction.onclick = function(url, event){
    var copyMessage = bundleHandler.get('com.ptc.netmarkets.util.utilResource.COPY_PAGE_MESSAGE');
    var pageUrl = window.location.href;
    url = getBaseHref() + url;

    var params = [];
    var dTitle = document.title;
    if (!dTitle || dTitle.length <= 0) {
      dTitle = "Windchill";
    }else{
      // SPR 1941489: localization in the display identifier shouldn't be escaped
      dTitle = getUnescapedText(dTitle);
    }
    params.push('title', dTitle);
    var soidValue;
    var mform = getMainForm();
    if (mform && mform.sv_current_name) {
      var svParams = [mform.sv_current_name.value, mform.sv_current_value.value];
      soidValue = requestHandler.addURIParams(pageUrl, svParams, true);
    } else {
      soidValue = pageUrl;
    }
    params.push('soid', soidValue);

    // for third level bookmark
    var tlnType = mform.tlnType;
    var tlnAction = mform.tlnAction;
    if (tlnType && tlnAction) {
      params.push('tlnType', tlnType.value);
      params.push('tlnAction', tlnAction.value);
    }
    var copyurl = requestHandler.addURIParams(url, params, true);
    var skipValidation = true;
    copyObjectMainAll(mform, copyurl, null, false, copyMessage, null, true, true, true, skipValidation);
    Event.stop(event);
    return false;
};

      function multiSelectObjects(mform) {
         var baseurl = document.getElementsByTagName('base')[0].href;
         var copyurl = baseurl+'netmarkets/jsp/object/list_copy.jsp?multiSelect=true';
         // If the form passed isn't valid, try to get the mainform.
         if (!mform) {
            mform = getMainForm();
         }
         copyObjectMainAll(mform,copyurl,getSelectedItems(),false,null,null,true,false,false, true);
      }

      // DCA calls this.
      function copyObjectMain(fe, copyurl, alertMessage) {
         copyObjectMainAll(fe, copyurl, fe.elements, true, alertMessage,false,true,false);
      }

      function getSelectedObjectsExternal(copyelements) {
         var result = [];
         if (!copyelements) {
            copyelements = getSelectedItems();
         }
         if (copyelements) {
            var alength = copyelements.length;
             for (var i = 0; i < alength; i++) {
                 var copyelement = copyelements[i];
                 if (copyelement.checked && copyelement.name.indexOf("select_all") < 0 && copyelement.value != 'select_all' && copyelement.name != "checkbox3" && (copyelement.type == "checkbox" || copyelement.type == "radio")) {
                     var param = new P();
                     param.n = "soid";
                     param.v = copyelement.value;
                     result.push(param);
                 }
            }
         }

         return result;
      }

      function isRBEntryKey(alertMessage){
         var isKey = false;
         if(alertMessage){
           var alertText = alertMessage.trim();
           // if the text starts with '[', the text most probably is numKey prepended , if locale is pseudolanguage.
           if(!alertText.startsWith('[') && alertMessage.indexOf(".") > 0 && !alertText.endsWith('.')){
             isKey = true;
           }
         }
         return isKey;
      }

      function showCBMess(showCBMessage, alertMessage, num, skipCount, noneMessage){

         if (skipCount || skipCount === false) {
            if (num <= 0) {
                num = 1;
            }
         }
         if (skipCount === true) {
            num="";
         }

         if (showCBMessage && alertMessage) {
            if(isRBEntryKey(alertMessage)){
                var myarr = [];
                myarr[0] = num;
                var message = bundleHandler.getBundleStringAndInserts(alertMessage, myarr);

                var messageTitle = "";
                if (alertMessage.indexOf(".COPY_SUCCESS_MSG") > 0) {
                    messageTitle = bundleHandler.get("com.ptc.netmarkets.util.utilResource.COPY_SUCCESS_MSG_TITLE");
                }
                else if (alertMessage.indexOf(".CUT_SUCCESS_MSG") > 0) {
                    messageTitle = bundleHandler.get("com.ptc.netmarkets.util.utilResource.CUT_SUCCESS_MSG_TITLE");
                }

                var msgObject = [{
                    MessageTitle : messageTitle,
                    Messages : [message],
                    MessageType : 'SUCCESS'
                }];
                PTC.messaging.showInlineMessage(msgObject);
            }
            else {
               // support legacy pages passing in already translated strings
                if (!skipCount || skipCount === false) {
                   alertMessage = alertMessage.replace("{0}", num);
                }
                wfalert_gen(alertMessage );
            }
         }
      }

      function launchUtilityWindow(linkText,winName,props) {
         wfWindowOpen(linkText,winName,props);
      }

      function getSearchResult(ufid) {
         var mform = getMainForm();
          JCAappendFormHiddenInput(mform, "url_oid", ufid);
         PTC.navigation.submitForm();
      }


