jsca.columns.comboBoxRenderer = function(table,column,row) {
    var result = '';
    var data = jsca.columns.getCellValue(column, row);
    if(data && data.enabled) {
        if (typeof row.get === 'function'){
            var jsca_column = row.get(column.id);
            if(jsca_column){
                jsca_column.updateCellValue = jsca.columns.comboBoxRenderer.updateCellValue;
            }
        }
        result = '<select ';
        if (data.id) {
            result += jsca.columns.idStr(data.id);
        }
        if (data.multiSelect) {
            result += 'multiple ';
        }
        if (data.size) {
            result += jsca.columns.sizeStr(data.size);
        }
        result += jsca.columns.nameStr(data.name)
                + (data.disabled ? 'disabled ' : '');
        if (data.tooltip) {
            result += jsca.columns.tooltipStr(data.tooltip);
        }

        result += jsca.columns.jsActionsStr(data.jsActions);

        result += data.styleClasses;

        result += '/>';

        var i=0;
        var size=0;
        if (data.options && data.options.length) {
           size = data.options.length;
        }
        var _origValues = "";
        for (i=0; i < size;i++) {
            result += '<option '
                    + jsca.columns.idStr(data.options[i].id);
            if (data.options[i].selected) {
                 result += "selected ";
                 if(data.origOldValues === undefined){
                    _origValues += "<input type=\"hidden\" "
                        + jsca.columns.idStr(data.id + jsca.columns.OLDSTR)
                        + jsca.columns.nameStr(data.name + jsca.columns.OLDSTR)
                        + jsca.columns.valueStr(data.options[i].intVal) + '/>';
                 }
            }
            result += 'value=\"'+ data.options[i].intVal +'\">'
                   + data.options[i].dispVal
                   + '</option>';
        }
        result += '</select>';
        if(data.origOldValues === undefined){
            data.origOldValues = _origValues;
        }
        result +=data.origOldValues;
    } else {
        //Not sure what should be outputed if it is disabled - RA
        for (i=0; i < size; i++) {
            if(data.options[i].selected) {
                result += data.options[i].dispVal + '<br />';
            }
        }
    }

    result = result + jsca.columns.getHiddenInputs(data.hiddenData);
    return result;

};

jsca.columns.comboBoxRenderer.updateCellValue = function(cell, value) {
    if(cell.gui && cell.gui.options){
        var select_options_length = cell.gui.options.length;
        for (var i = 0; i < select_options_length; i++) {
            /* currently the comparable value from server is the intVal of the column and not dispValue (which is probably
               the localized value that is displayed in the combo boxes). This might require a fix in server code and dispVal
               can be used here below in that case*/
            if (cell.gui.options[i].intVal === value) {
                cell.gui.options[i].selected = true;
                cell.gui.comparable = value;
            }
            else {
                cell.gui.options[i].selected = false;
            }
        }
    }
};

jsca.columns.comboBoxRenderer.searchFunc = function(table, column, row) {
    return PTC.util.unescapeHTML(jsca.columns.comboBoxRenderer.exportRenderer(table, column, row));
};

jsca.columns.comboBoxRenderer.exportRenderer = function(table, column, row) {
    var result = '';
    var data = jsca.columns.getCellValue(column, row);
    var optionsCount = data.options.length;
    for (i=0; i < optionsCount; i++) {
        if(data.options[i].selected) {
            result += data.options[i].dispVal + ' ';
        }
    }
    return result;
};

/**
 * functionality related to the event manager, apis to launch and look for changes on the server
 * @namespace
 * @name PTC.console
 */
  Ext.ns('PTC.console');
  /**
   * Initialize the checkConsole interval function and cache the url for further use
   * @param {String} ccurl of the console manager state checker
   */
  PTC.console.setConsoleInterval = function(ccurl){
      ccurl = getBaseHref() + PTC.navigation.getTokenFromUrl(ccurl);
      PTC.console.url = ccurl;
      PTC.console.consoleIntervalId = setInterval(PTC.console.checkConsole, 300000);
  };
  
  PTC.console.clearInterval = function(id) { clearInterval(id); };
  /**
   * Check the server for new event manager entries.  Will popup the event manager if entries are found
   */
  PTC.console.checkConsole = function() {
      var ccurl = PTC.console.url;
      var options = {
          method: 'get',
          onSuccess: function(transport){
              var response = transport.responseText;
              if (response.length === 1 && response === '0') {
                  PTC.console.clearInterval(PTC.console.consoleIntervalId);
              }
              else if (response.length > 2) {
                  eval(response);
              }
          },
          onException: function() {              
              PTC.console.clearInterval(PTC.console.consoleIntervalId);
          }
      };
      requestHandler.doRequest(ccurl, options);
  };
  /**
   * Will re-start the interval for checking the server console for errors
   */
  PTC.console.checkConsolePeriodically = function() {
      PTC.console.checkConsole.defer(4000);  // check now
      PTC.console.setConsoleInterval(PTC.console.url); // check after awhile
  };

/**
 * Launches the event console in a window named 'console'
 */
  PTC.console.launchConsole = function () {
      window.open(getBaseHref()+'servlet/WindchillAuthGW/wt.enterprise.URLProcessor/URLTemplateAction?u8&action=EventConsole',
              'console',
              'resizable=yes,scrollbars=yes,menubar=no,toolbar=no,location=no,status=no,width=900,height=600');
  };
  
  /**
   * action listener looking for a message that indicates the console/conflict manager window should be displayed
   */
  PTC.console.checkForOpenConsole = function(formResult) {
      if (formResult && formResult.extraData && formResult.extraData.launchConsole) {
          PTC.console.launchConsole();
      }
      return true;
  };
  
  PTC.console.registerConsoleMainListeners = function() {
      PTC.action.on('objectsaffected', PTC.console.checkForOpenConsole);    
  };
  
  PTC.navigation.on('afterLoadMainShell', PTC.console.registerConsoleMainListeners);

