//network type picker call back when user launches picker and selects context type for networks search
PTC.search.ContexPickerData.processContainerTypes = function(Objects, pickerID, targetId) {
    getMainForm().networkType.value = "";
    var netDiv = document.getElementById("NetworkContextDiv");
    netDiv.innerHTML = "";
    PTC.search.ContexPickerData.createPersistableCheckBox();

    var elements = Objects.pickedObjects;
    var pickedSelection = elements.length; 
    
    for (i = 0; i < pickedSelection; i++) {

        var theNetworkType = elements[i].theType;
        var Type = elements[i].type;
        var item = new Ext.form.Checkbox({
            name : 'netWorkContainerType',
            id : '' + theNetworkType + PTC.search.ContexPickerData.netorkContextPickerId,
            boxLabel : '' + Type,
            value : '' + theNetworkType,
            renderTo : 'NetworkContextDiv',
            checked : true,
            listeners : {
                check : PTC.search.ContexPickerData.listenrforSpecificCheckBox
            }
        });
        item.wrap.addClass("chk-same-line");

        if ((theNetworkType.indexOf("|") > 0)
                && (theNetworkType.indexOf("WCTYPE") == -1)) {
            theNetworkType = "WCTYPE|" + theNetworkType;
        }

        if (i === 0) {
            getMainForm().networkType.value = theNetworkType;
            getMainForm().networkCheckedList.value = theNetworkType;
        } else {
            getMainForm().networkType.value = getMainForm().networkType.value
                    + "," + theNetworkType;
            getMainForm().networkCheckedList.value = getMainForm().networkCheckedList.value
                    + "," + theNetworkType;
        }
    }

    getMainForm().actionClass.value = "com.ptc.netmarkets.search.NmSearchCommands";
    getMainForm().actionMethod.value = "containerTypeChange";
    getMainForm().executeLocation.value = "inbegin";
    PTC.navigation.ContexPickerData.submitForm();
    PTC.search.ContexPickerData.setCheckBoxAfterRendering();
};

//Creates checkbox wher user perform search action as well as when user comes first time to network search page
PTC.search.ContexPickerData.createCheckBox = function() {

    var internalName = getMainForm().networkType.value.split(",");
    var displayName = getMainForm().displayNames.value.split(",");

    var checkedListTemp = getMainForm().networkCheckedList.value.split(",");
    // createPersistableCheckBox();
    var isDisable = false;
    if (internalName === '' && displayName ===''
            && internalName === 'Persistable'
            || getMainForm().networkCheckedList.value === 'Persistable') {
        isDisable = true;
    }
    PTC.search.ContexPickerData.createPersistableCheckBox(isDisable);
    if (internalName !== '' && displayName !== ''
            && internalName !== 'Persistable') {
        for (i = 0; i < internalName.length; i++) {
            var theNetworkType = internalName[i];
            var checkedValue = "";

            for ( var k = 0; k < checkedListTemp.length; k++) {
                if (theNetworkType == checkedListTemp[k]) {
                    checkedValue = true;
                }
            }
            var Type = internalName[i];
            var checkBoxId = theNetworkType + PTC.search.ContexPickerData.netorkContextPickerId;
            var item = new Ext.form.Checkbox({
                name : 'netWorkContainerType',
                id : '' + checkBoxId,
                value : '' + Type,
                boxLabel : '' + displayName[i],
                renderTo : 'NetworkContextDiv',
                type : 'checkbox',
                checked : checkedValue,
                listeners : {
                    check : PTC.search.ContexPickerData.listenrforSpecificCheckBox
                }
            });
            item.wrap.addClass("chk-same-line");
        }
    }

    // setCheckBoxAfterRendering();
    var networklist = getMainForm().netWorkContainerType;
    for ( var i = 0; i < networklist.length; i++) {
        for ( var k = 0; k < checkedListTemp.length; k++) {
            if (checkedListTemp[k] == 'Persistable'
                    && networklist[i].id != 'Persistable') {
                networklist[i].disabled = true;
            }
        }
    }
};

//Listener function for context type specifc check box
PTC.search.ContexPickerData.listenrforSpecificCheckBox = function() {
    var checkListValue = "";
    var networklist = getMainForm().netWorkContainerType;

    for ( var i = 0; i < networklist.length; i++) {
        if (networklist[i].checked && networklist[i].id != 'Persistable') {
            // removing "_containerTtypePicker" from the id
            var index = networklist[i].id.indexOf(PTC.search.ContexPickerData.netorkContextPickerId);
            if (index > -1){
                checkListValue = checkListValue
                + networklist[i].id.substring(0, index) + ",";
            }  
        }
        if (networklist[i].id === 'Persistable') {
            networklist[i].checked == false;// networklist[i].setValue(false);
        }
    }

    getMainForm().networkCheckedList.value = checkListValue.substring(0,
            checkListValue.length - 1);
};

//function for maintaining checked/unchecked state of checkboxes after rendering
PTC.search.ContexPickerData.setCheckBoxAfterRendering = function(){

    var networklist = getMainForm().netWorkContainerType;
    var checkedListTemp = getMainForm().networkCheckedList.value.split(",");
    var checkListValue = "";

    for ( var i = 0; i < networklist.length; i++) {
        for ( var k = 0; k < checkedListTemp.length; k++) {
            if (networklist[i].id == checkedListTemp[k]) {
                networklist[i].setValue(true);
            }
            if (checkedListTemp[k] == 'Persistable' && networklist[i].id != 'Persistable') {
                networklist[i].disabled = true;
            }
        }

        if (networklist[i].checked && networklist[i].id != 'Persistable') {
            // removing "_containerTtypePicker" from the id
            var index = networklist[i].id
                    .indexOf(PTC.search.ContexPickerData.netorkContextPickerId);
            if (index > -1){
                checkListValue = checkListValue
                + networklist[i].id.substring(0, index) + ",";
            }
        }
    }
    getMainForm().networkCheckedList.value = checkListValue.substring(0,
            checkListValue.length - 1);

    if (getMainForm().netWorkContainerType.id == 'Persistable') {
        Ext.getCmp('Persistable').setValue(true);
        getMainForm().networkCheckedList.value = 'Persistable';
    }
};

//Creating All context type check box
PTC.search.ContexPickerData.createPersistableCheckBox = function(checkedValue) {
    var netDiv = document.getElementById("NetworkContextDiv");
    netDiv.innerHTML = '&nbsp;';

    var chkItem = new Ext.form.Checkbox({
        name : 'netWorkContainerType',
        id : 'Persistable',
        boxLabel : PTC.search.contextComp.strAllContainers,
        renderTo : 'NetworkContextDiv',
        type : 'checkbox',
        checked : checkedValue,
        listeners : {
            check : PTC.search.ContexPickerData.listenrforPersistableCheckBox
        }
    });
    chkItem.wrap.addClass("chk-same-line");
};

// Listener function for All context type check box
PTC.search.ContexPickerData.listenrforPersistableCheckBox = function() {
    var networklist = getMainForm().netWorkContainerType;
    var checkListValue = "";

    for ( var i = 0; i < networklist.length; i++) {
        if (networklist[i].id != 'Persistable' && Ext.getCmp('Persistable').checked) {
            networklist[i].disable();
            getMainForm().networkCheckedList.value = '';
        } else {
            networklist[i].enable();
            if (networklist[i].checked) {
                checkListValue = checkListValue + networklist[i].id + ",";
            }
        }
    }
    getMainForm().networkCheckedList.value = checkListValue.substring(0,
            checkListValue.length - 1);
};


