PTC.search.ContexPickerData.initContextComp = function() {
    PTC.search.ContexPickerData.radioGroupItems = [];

    PTC.search.ContexPickerData.searchInMoreOptionJson.each(function(record) {
        PTC.search.ContexPickerData.radioGroupItems.push({
            boxLabel : record.label,
            name : 'search',
            id : record.id,
            autoWidth : true

        });
    });

    PTC.search.ContexPickerData.contextMoreOptionsDialog = (PTC.search.ContexPickerData.contextMoreOptionsDialog !== undefined && PTC.search.ContexPickerData.contextMoreOptionsDialog !== null) ? (PTC.search.ContexPickerData.contextMoreOptionsDialog)
            : new Ext.Window(
                    {
                        modal : true,
                        title : PTC.search.ContexPickerData.moreOptionLabel,
                        closeAction : 'hide',
                        buttons : [
                                new Ext.Button({
                                    text : PTC.search.ContexPickerData.okLabel,
                                    handler : function(button, event) {
                                        PTC.search.ContexPickerData.contextMoreOptionsOkHandler(button, event); //end button callback handler
                                    }
                                }), //end button
                                new Ext.Button(
                                        {
                                            text : PTC.search.ContexPickerData.cancelLabel,
                                            handler : function(button, event) {
                                                PTC.search.ContexPickerData.contextMoreOptionsDialog
                                                        .hide();
                                            }
                                        })

                        ], //end window's button list
                        buttonAlign : 'right',
                        items : [ new Ext.form.FormPanel(
                                {
                                    id : 'moreOptionsDialogForm',
                                    items : [
                                            new Ext.form.RadioGroup(
                                                    {
                                                        fieldLabel : PTC.search.ContexPickerData.searchInLabel,
                                                        id : 'searchInRadio',
                                                        name : 'searchInRadio',
                                                        autoWidth : true,
                                                        items : PTC.search.ContexPickerData.radioGroupItems,
                                                        vertical : true,
                                                        columns : 1,
                                                        autoScroll : false
                                                    }),
                                            new Ext.form.CheckboxGroup(
                                                    {
                                                        fieldLabel : PTC.search.ContexPickerData.membershipLabel,
                                                        autoWidth : true,
                                                        items : [
                                                                new Ext.form.Checkbox(
                                                                        {
                                                                            boxLabel : PTC.search.ContexPickerData.iAmAMemberOfLabel,
                                                                            autoWidth : true,
                                                                            autoHeight : true,
                                                                            id : 'membershipCheckbox_memberOf'
                                                                        }),
                                                                new Ext.form.Checkbox(
                                                                        {
                                                                            boxLabel : PTC.search.ContexPickerData.areInMyOrganizationLabel,
                                                                            autoWidth : true,
                                                                            autoHeight : true,
                                                                            id : 'membershipCheckbox_inOrg'
                                                                        }) ],
                                                        vertical : true,
                                                        columns : 1,
                                                        autoScroll : false
                                                    }) ]
                                //end items of form panel
                                }) //end form panel
                        ], //end items of window
                        width : 350,
                        height : 300,
                        listeners : {
                            'show' : function(window) {
                                //grab the state of the context options and use it to set our defaults
                                searchInCombo = document.getElementById('containerTypeList$label$');
                                selected = searchInCombo.options[searchInCombo.selectedIndex].value;
                                form = PTC.search.ContexPickerData.contextMoreOptionsDialog
                                        .get(0);
                                radioGroup = form.get(0);
                                //if 'specific contexts' is selected, default to 'all contexts'
                                if (selected != "FIND_CONTEXT") {
                                    radioGroup.setValue('searchInRadio_'
                                            + selected, true);
                                } else {
                                    radioGroup.setValue('searchInRadio_', true);
                                }
                                memberOfCheckbox = document.getElementById('memberOfContainer');
                                if (memberOfCheckbox.value==1) {
                                    Ext.getCmp('membershipCheckbox_memberOf')
                                            .setValue(true);
                                } else {
                                    Ext.getCmp('membershipCheckbox_memberOf')
                                            .setValue(false);
                                }
                                inOrgCheckbox = document.getElementById('searchInUserOrg');
                                if (inOrgCheckbox.value==1) {
                                    Ext.getCmp('membershipCheckbox_inOrg')
                                            .setValue(true);
                                } else {
                                    Ext.getCmp('membershipCheckbox_inOrg')
                                            .setValue(false);
                                }
                            }
                        }
                    });
};

PTC.search.ContexPickerData.contextMoreOptionsOkHandler = function(button,
        event) {

    //on ok, populate the choices to the (now) hidden old form fields so that
    //server-side processing can complete as before
    PTC.search.ContexPickerData.allContextsCheckedStatus = 1;
    form = PTC.search.ContexPickerData.contextMoreOptionsDialog.get(0);
    radioGroup = form.get(0);
    checkboxGroup = form.get(1);
    radio = radioGroup.getValue().getId();
    checkboxes = checkboxGroup.getValue();
    searchInCombo = document.getElementById('containerTypeList$label$');
    //radio id's have the form searchInRadio_[combobox value]
    selectedOpt = radio.substring(radio.indexOf('_') + 1);
    selectedIndex = -1;
    for (i = 0, l = searchInCombo.options.length; i < l; i++) {
        if (searchInCombo.options[i].value === selectedOpt) {
            searchInCombo.selectedIndex = i;
            selectedIndex = i;
            PTC.search.ContexPickerData.allContextsSelectedName = selectedOpt;
            PTC.search.ContexPickerData.allContextsCheckedIndex = PTC.search
                    .getIndexOfOptionFromValue(
                            document.getElementById(PTC.search.ContexPickerData.pickerId + '$label$'),
                            PTC.search.ContexPickerData.allContextsSelectedName);
            PTC.search.ContexPickerData.allContextsCheckedStatus = 1;
            break;
        }
    }
    //call the onchange handler of teh combo-box since it's not fired when changed from js
    selectRecentlyVisitedContextMultiSelectSearchPage('containerTypeList');
    memberOfCheckbox = document.getElementById('memberOfContainer');
    inOrgCheckbox = document.getElementById('searchInUserOrg');
    memberOfCheckbox.checked = false;
    memberOfCheckbox.value = '0';
    inOrgCheckbox.checked = false;
    inOrgCheckbox.value = '0';
    for (i = 0, l = checkboxes.length; i < l; i++) {
        switch (checkboxes[i].getId()) {
        case 'membershipCheckbox_memberOf':
            memberOfCheckbox.checked = true;
            memberOfCheckbox.value = '1';
            break;
        case 'membershipCheckbox_inOrg':
            inOrgCheckbox.checked = true;
            inOrgCheckbox.value = '1';
            break;
        }
    }
    //also, ensure the all_contexts check-box is updated appropriatly for the search-in selection
    newAllContextCheckbox = PTC.search.recentlyUsedContexts.get('all_contexts');
    newAllContextCheckbox.boxLabel = '<img src="netmarkets/jsp/search/small_blank_value.gif" />'
            + searchInCombo.options[selectedIndex].text;
    newAllContextCheckbox.currentContainer = selectedIndex;
    selectedContextDisplayName = selectedIndex;
    PTC.search.recentlyUsedContexts.replace(newAllContextCheckbox);

    PTC.search.renderRecentlyUsedContexts();
    contextCB = Ext.getCmp('all_contexts');
    contextCB.suspendEvents(false);
    contextCB.setValue(true);
    contextCB.resumeEvents();
    PTC.search.ContexPickerData.contextMoreOptionsDialog.hide();
    PTC.search.callUpdateAllContextOnServer('updateallContextsSelectedItem',
            PTC.search.ContexPickerData.allContextsSelectedName + "##1");
    //If context checkbox selected then My fav context should be unselected.
    if (contextCB.checked) {
        var favContexts = Ext.getCmp('myFavContext');
        if (favContexts.checked) {
            favContexts.suspendEvents();
            favContexts.setValue(false);
            favContexts.resumeEvents();
        }
    }
    PTC.search.updateMemberShipMessage();

};



//listener for Fav Checkbox
PTC.search.checkListenerFavContext = function() {
    var favContexts = Ext.getCmp('myFavContext');
    var myFavChecked = favContexts.checked;
    var isOnlyFolder = PTC.search.isContainsOnlyFolders();
    /* individual context and/or folder count */
    var contextCount = PTC.search.recentlyUsedContexts.getCount() - 1; // -1
    // for all_context

    for ( var j = 0; j < PTC.search.recentlyUsedContexts.getCount(); j++) {
        var item = Ext.getCmp(PTC.search.recentlyUsedContexts.itemAt(j).id);
        if (item.id == 'all_contexts') {
            // All Context
            if (myFavChecked) {
                // if my fav context is checked then uncheck all context
                item.suspendEvents();
                item.setValue(false);
                item.resumeEvents();
            } else {
                if (PTC.search.ContexPickerData.allContextsCheckedIndex <= 0) { // 'All  Context' is present (not 'All Products')
                    // if my fav is unchecked and 'All Contexts' is present then check all context
                    item.suspendEvents();
                    item.setValue(true);
                    item.resumeEvents();
                }
            }
        } else {
            // individual context or folder
            if (myFavChecked) {
                // multiple folder
                if (isOnlyFolder && contextCount > 1) {
                    PTC.search.showMessageForMultiFolder();

                    // un-check 'My Favorite'
                    favContexts.suspendEvents();
                    favContexts.setValue(false);
                    favContexts.resumeEvents();
                }
                if (item.id.indexOf('folder') == -1) { // context
                    var cb = new Ext.getCmp(item.id);
                    cb.suspendEvents();
                    cb.setValue(true);
                    cb.resumeEvents();
                } else { // folder
                    if (isOnlyFolder) { // must be single folder as multi-folder
                        // case is already handled.
                        if (contextCount === 1) {
                            var cb = new Ext.getCmp(item.id);
                            cb.suspendEvents();
                            cb.setValue(true);
                            cb.resumeEvents();
                        }
                    } else { // if other context is there then un-check
                        // folder
                        var cb = new Ext.getCmp(item.id);
                        cb.suspendEvents();
                        cb.setValue(false);
                        cb.resumeEvents();
                    }
                }
            } else {
                var cb = new Ext.getCmp(item.id);
                cb.suspendEvents();
                cb.setValue(false);
                cb.resumeEvents();
            }
        }
    }
    PTC.search.HiddenContextPicker.setStatusFromUserSelection();
};

PTC.search.showMessageForMultiFolder = function() {
    PTC.search.log.debug("PTC.search.checkListenerFavContext", "Detecting  Multiple folders");
    var msg = bundleHandler.get("com.ptc.windchill.enterprise.search.client.searchClientResource.MULTIPLE_FOLDER_SELECTION_MSG");
    var title = bundleHandler.get("com.ptc.windchill.enterprise.search.client.searchClientResource.MULTIPLE_FOLDER_SELECTION_HEADING");

    PTC.search.showBannerMessage(title, [msg], 'WARNING');
};
/**
 * This function returns true if My Favorite Contexts contains only folder else false.
 * 
 */
PTC.search.isContainsOnlyFolders = function() {
    var onlyFolders = false;
    for ( var j = 0; j < PTC.search.recentlyUsedContexts.getCount(); j++) {
        var id = PTC.search.recentlyUsedContexts.itemAt(j).id;
        if (id == 'all_contexts') {
            continue;
        }
        if (id.indexOf('folder') == -1) {
            onlyFolders = false;
            break;
        } else {
            onlyFolders = true;
        }
    }
    PTC.search.log.debug("PTC.search.isContainsOnlyFolders = " + onlyFolders);
    return onlyFolders;
};

PTC.search.showFavContextCheckBox = function(displayName, addContextLabel) {
    var myFavContext = new Ext.form.Checkbox({
        name: 'myFavContext',
        id: 'myFavContext',
        checked: false,
        boxLabel: '<img src="netmarkets/jsp/search/small_blank_value.gif">' + displayName + '&nbsp; &nbsp;<a href="javascript:PTC.search.showAddContextLink()" id="contextOptionsMenuAnchor">' + addContextLabel + '</a>',
        renderTo: 'myFavContextDiv',
        listeners: {
            check: PTC.search.checkListenerFavContext
        }
    });
};

//renders context checkboxes into chkGroupContextPicker TD.
//It reads context list from recentlyUsedContexts Ext Mixed Collection.
PTC.search.renderRecentlyUsedContexts = function() {
    PTC.search.log.debug("PTC.search.renderRecentlyUsedContexts ", PTC.search.recentlyUsedContexts);
    var contextRow = document.getElementById('chkGroupContextPicker');
    for ( var i = 0, l = contextRow.childNodes.length; i < l; i++) {
        var comp = Ext.getCmp(contextRow.childNodes[0].firstChild.id);
        comp.destroy();
    }
    PTC.search.recentlyUsedContexts.each(function(item, index, length) {
        if (item.id.indexOf("folder") == -1) // If item is not folder
        {
            if (item.id == 'all_contexts') {
                var cb = new Ext.form.Checkbox(item);
            } else {
                item.renderTo = 'chkGroupContextPicker';
                var cb = new PTC.search.RemovableCheckbox(item);
                cb.wrap.addClass('chk-same-line');
                cb.wrap.addClass('removableCheckBoxItem');
            }

        }
    });

    // rendering of folder
    PTC.search.recentlyUsedContexts.each(function(item, index, length) {
        if (item.id.indexOf("folder") != -1) {
            item.renderTo = 'chkGroupContextPicker';
            var cb = new PTC.search.RemovableCheckbox(item);
            cb.wrap.addClass('chk-same-line');
            cb.wrap.addClass('removableCheckBoxItem');
        }
    });
};

/*
 * This function decide the state of 'All Contexts' check-box and 'My Favorite Contexts' check-box.
 * 
 */
PTC.search.setMyFavAndAllContextStatus = function() {
    PTC.search.checkAllContextChecked();
    PTC.search.checkAllFavSelected();
};

/**
 * This function decides the state of 'My Favorite Contexts' on changing state of individual context/folder.  
 * 
 */
PTC.search.checkAllFavSelected = function() {
    PTC.search.log.debug("PTC.search.checkAllFavSelected ");
    var allContextsCheckedStatus = PTC.search.ContexPickerData.allContextsCheckedStatus;
    var allContextsChecked = (allContextsCheckedStatus == 1) ? true : false;
    var allContexts = Ext.getCmp('all_contexts');
    if (allContexts.checked || allContextsChecked) {
        var favContexts = Ext.getCmp('myFavContext'); 
        favContexts.suspendEvents();
        favContexts.setValue(false);
        favContexts.resumeEvents();
    } else {
        var favState = true;
        // if exist any un-checked context then 'My Favorite' state should be un-checked
        for ( var i = 0; i < PTC.search.recentlyUsedContexts.getCount(); i++) {
            var item = PTC.search.recentlyUsedContexts.itemAt(i);
            var cb = Ext.getCmp(item.id);
            if (item.id != 'all_contexts' && (item.id.indexOf("folder") == -1)) {
                if (!cb.checked) {
                    favState = false;
                    break;
                }
            }
        }
        // If it contains only folders
        if (PTC.search.isContainsOnlyFolders()) {
            // Case 1: If multiple folders then unchecked My Fav Contexts.
            if (PTC.search.recentlyUsedContexts.getCount() > 2) {
                favState = false;
            } else {// Case 2: Contains single folder and which is unchecked.
                var item = PTC.search.recentlyUsedContexts.itemAt(1);
                var cb = Ext.getCmp(item.id);
                if (!cb.checked) {
                    favState = false;
                }
            }
        }
        var favContexts = Ext.getCmp('myFavContext');
        favContexts.suspendEvents();
        favContexts.setValue(favState);
        favContexts.resumeEvents();
    }
    if(favState){
        document.getElementById('memberOfContainer').checked = false;
        document.getElementById('searchInUserOrg').checked = false;
        PTC.search.updateMemberShipMessage();
    }
};

/**
 * This function decides the state of All Contexts on changing state of individual context/folder.  
 * 
 */
PTC.search.checkAllContextChecked = function() {
    PTC.search.log.debug("PTC.search.checkAllContextChecked ", PTC.search.recentlyUsedContexts);
    var allContxtSetStatus = true;
    // if any context is checked then sets 'All Contexts' to false.
    for ( var i = 0; i < PTC.search.recentlyUsedContexts.getCount(); i++) {
        var item = PTC.search.recentlyUsedContexts.itemAt(i);
        var cb = Ext.getCmp(item.id);
        if (item.id != 'all_contexts' && cb.checked) {
            allContxtSetStatus = false;
            break;
        }
    }
    var cb = Ext.getCmp('all_contexts');

    if (allContxtSetStatus && PTC.search.ContexPickerData.allContextsCheckedIndex <= 0) {
        cb.suspendEvents();
        cb.setValue(true);
        cb.resumeEvents();
        PTC.search.ContexPickerData.allContextsCheckedStatus = 1;
    } else {
        cb.suspendEvents();
        cb.setValue(false);
        cb.resumeEvents();
        PTC.search.ContexPickerData.allContextsCheckedStatus = 0;
    }
};

//Does the Alphabetical sorting of Recently used context: Java script sort
//function expects integer value for IE9+
PTC.search.sortRecentlyUsedContexts = function() {
    PTC.search.recentlyUsedContexts.sort('ASC', function(a, b) {
        if (a.id.indexOf('folder') == -1 || b.id.indexOf('folder') == -1) {
            if (a.label > b.label) {
                return 1;
            } else if (a.label < b.label) {
                return -1;
            } else {
                return 0;
            }
        }
    });
};

//Called for checkbox rendering.
//Populates PTC.search.recentlyUsedContexts, then calls PTC.search.renderRecentlyUsedContexts
PTC.search.renderRecentlyUsedContextCheckBox = function() {
    PTC.search.log.debug("PTC.search.renderRecentlyUsedContextCheckBox: PTC.search.ContexPickerData ",
            PTC.search.ContexPickerData);
    var pickerId = PTC.search.ContexPickerData.pickerId;
    var displayValues = PTC.search.ContexPickerData.displayValues;
    var InternalValues = PTC.search.ContexPickerData.InternalValues;
    var imageValues = PTC.search.ContexPickerData.imageValues;
    var contextDispLength = PTC.search.ContexPickerData.contextDispLength;
    var allContextsSelectedName = PTC.search.ContexPickerData.allContextsSelectedName;
    var allContextsCheckedIndex = PTC.search.ContexPickerData.allContextsCheckedIndex;
    var allContextsCheckedStatus = PTC.search.ContexPickerData.allContextsCheckedStatus;

    var displayNameArr = null;
    if (displayValues.length > 0) {
        displayNameArr = displayValues.split("~~COMMA~~");
    }
    var internalNameArr = null;
    if (InternalValues.length > 0) {
        internalNameArr = InternalValues.split(",");
    }
    var imageValuesArr = null;
    if (imageValues.length > 0) {
        imageValuesArr = imageValues.split(",");
    }

    // add current container context, default to 'All Contexts'
    var contextCombo = document.getElementById(pickerId + '$label$');
    // var allContextsSelectedChecked = '<%=allContextsSelectedChecked%>';
    var allContextsChecked = (allContextsCheckedStatus == 1) ? true : false;
    allContextsCheckedIndex = (allContextsCheckedIndex == -1) ? 0 : allContextsCheckedIndex;
    var allContextsLabel = (contextCombo.options[allContextsCheckedIndex].text);

    var allContexts = Ext.getCmp('all_contexts');
    if (allContexts !== null && allContexts !== undefined ) {
        allContexts.destroy();
    }
    allContexts = {
        boxLabel: '<img src="netmarkets/jsp/search/small_blank_value.gif" />' + allContextsLabel,
        name: 'all_contexts',
        id: 'all_contexts',
        checked: allContextsChecked,
        disabled: false,
        listeners: {
            check: PTC.search.changeListener
        },
        renderTo: 'allContextTD',
        label: allContextsLabel
    };

    PTC.search.recentlyUsedContexts.add(allContexts);
    // Create new checkboxes as per recently visited list
    if (displayNameArr !== undefined && displayNameArr !== null && displayNameArr.length > 0 && internalNameArr !== undefined && internalNameArr !== null) {
        for ( var i = 0; i < displayNameArr.length; i++) {
            var internalNameFromArr = internalNameArr[i];

            var dispName = displayNameArr[i];
            if (displayNameArr[i].length > contextDispLength) {
                dispName = displayNameArr[i].substring(0, contextDispLength - 3) + '...';
            }

            // alert(internalNameFromArr);
            var imageStr = imageValuesArr[i];

            var newItem = {
                boxLabel: '<div class="removableCheckBoxLabel"><img src="' + imageStr + '" /> ' + dispName + '</div>',
                name: '' + internalNameFromArr,
                id: '' + internalNameFromArr,
                checked: false,
                disabled: false,
                qtip: '' + displayNameArr[i],
                listeners: {
                    check: PTC.search.changeListener
                },
                onRemoveFunction: PTC.search.RemoveContextCheckbox,
                renderTo: 'chkGroupContextPicker',
                label: dispName
            };

            PTC.search.recentlyUsedContexts.add(newItem);
        }
    }

    // Sort before render
    PTC.search.sortRecentlyUsedContexts();
    PTC.search.log.debug("PTC.search.renderRecentlyUsedContextCheckBox", PTC.search.recentlyUsedContexts);

    // Now renders context check boxes
    PTC.search.renderRecentlyUsedContexts();
    // check selected contexts after rendering.

    // check selected contexts
    var otherContextChecked = false;
    var checkboxesCheckedBeforeSearch = document.getElementById(pickerId).value;

    var arrCheckBoxesCheckedBeforeSearch = checkboxesCheckedBeforeSearch.split(",");

    for ( var i = 0; i < arrCheckBoxesCheckedBeforeSearch.length; i++) {
        var optionInternalVal = arrCheckBoxesCheckedBeforeSearch[i];
        // removing "OR:"/"VR:" for comparision
        if (optionInternalVal.startsWith("OR:") || optionInternalVal.startsWith("VR:")) {
            optionInternalVal = optionInternalVal.substring(3);
        }
        for ( var j = 0; j < PTC.search.recentlyUsedContexts.getCount(); j++) {
            var item = Ext.getCmp(PTC.search.recentlyUsedContexts.itemAt(j).id);
            var itemName = item.getName();
            // removing "OR:"/"VR:" for comparision
            if (itemName.startsWith("OR:") || itemName.startsWith("VR:")) {
                itemName = itemName.substring(3);
            }

            if (itemName == optionInternalVal) {
                // selected context. So set checkbox to true.
                item.suspendEvents();
                // Ext.getCmp(PTC.search.recentlyUsedContexts.itemAt(j).id).setValue(true);
                item.setValue(true);
                item.resumeEvents();
                otherContextChecked = true;
            }
        }
    }

    if (!otherContextChecked) {
        if (allContextsSelectedName === '') {
            if (allContextsCheckedStatus !== '1') {
                var favContexts = Ext.getCmp('myFavContext');
                favContexts.suspendEvents();
                favContexts.setValue(false);
                favContexts.resumeEvents();

                var allContextsItem = Ext.getCmp('all_contexts');
                allContextsItem.suspendEvents();
                allContextsItem.setValue(true);
                allContextsItem.resumeEvents();
                PTC.search.callUpdateAllContextOnServer('updateallContextsSelectedItem', "##1");
                allContextsCheckedStatus = 1;
            }
            allContextsChecked = true;
        }
    } else {
        // As specific contexts are selected disable the i am member of checkboxes
        disableMemberOfCheckBoxes();
        var allContextsItem = Ext.getCmp('all_contexts');
        allContextsItem.suspendEvents();
        allContextsItem.setValue(false);
        allContextsItem.resumeEvents();
        allContextsChecked = false;
    }

    if (Ext.getCmp('all_contexts').getValue() === true) {
        var favContexts = Ext.getCmp('myFavContext');
        favContexts.suspendEvents();
        favContexts.setValue(false);
        favContexts.resumeEvents();
    }
    if (allContextsChecked) {
        contextCombo.selectedIndex = allContextsCheckedIndex;
    } else {
        allContextsCheckedIndex = PTC.search.getIndexOfOptionFromValue(contextCombo, 'FIND_CONTEXT');
        contextCombo.selectedIndex = allContextsCheckedIndex;
    }
    allContexts.currentContainer = allContextsCheckedIndex;

    // check and set proper status for All Context and My Favorite

    PTC.search.setMyFavAndAllContextStatus();
    // check More option messages + Context
    PTC.search.updateMemberShipMessage();
    PTC.search.ContexPickerData.otherContextChecked = otherContextChecked;

}; // end of renderRecentlyUsedContextCheckBox

PTC.search.changeListener = function(node) {
    var picID = PTC.search.ContexPickerData.pickerId;
    // var allContextsSelectedChecked = '<%=allContextsSelectedChecked%>';

    var all_contexts = Ext.getCmp('all_contexts');
    // reference index to selected container from light box: All Xxxxxxx
    var currentContainer = all_contexts.currentContainer;
    // update hidden containerTypeList$label$ => is a "javascript select object"
    // if "All Context" is checked, uncheck all other
    var allContextsChecked = false;
    if (node.getName() === 'all_contexts') {

        if (node.getValue() === true) {
            //if All Context Checkbox Selected then My Fav context bar also unslected.
            var favContexts = Ext.getCmp('myFavContext');
            favContexts.suspendEvents();
            favContexts.setValue(false);
            favContexts.resumeEvents();

            allContextsChecked = true;
            if (PTC.search.ContexPickerData.allContextsCheckedStatus !== 1) {
                PTC.search.ContexPickerData.allContextsCheckedStatus = 1;
            }
        } else {
            allContextsChecked = false;
            if (PTC.search.ContexPickerData.allContextsCheckedStatus !== 0) {
                PTC.search.ContexPickerData.allContextsCheckedStatus = 0;
            }
        }
    }
    for ( var i = 0; i < PTC.search.recentlyUsedContexts.getCount(); i++) {
        var item = Ext.getCmp(PTC.search.recentlyUsedContexts.itemAt(i).id);
        item.enable();

        if (allContextsChecked && item.getName() !== 'all_contexts') {
            item.suspendEvents();
            item.setValue(false);
            item.resumeEvents();
        }
    }
    // if the specific context is checked.
    if (node.getName() !== 'all_contexts' && node.getValue() === true) {
        //if the checked context is a Folder then only folder is to be selected. Rest all
        // contexts should be unchecked.
        if (node.getId().indexOf("folder") !== -1) {
            for ( var i = 0; i < PTC.search.recentlyUsedContexts.getCount(); i++) {
                var item = Ext.getCmp(PTC.search.recentlyUsedContexts.itemAt(i).id);
                item.enable();

                if (node.getName() !== item.getName()) {
                    item.suspendEvents();
                    item.setValue(false);
                    item.resumeEvents();
                }
            }
        }
        // If any context other than folder is selected.
        else {
            for ( var i = 0; i < PTC.search.recentlyUsedContexts.getCount(); i++) {
                var item = Ext.getCmp(PTC.search.recentlyUsedContexts.itemAt(i).id);
                item.enable();
                var isFolderItem = false;
                var isAllContextItem = false;

                if (item.getName() == 'all_contexts'){
                    isAllContextItem = true;
                }
                    

                if (item.getId().indexOf("folder") != -1){
                    isFolderItem = true;
                }
                    

                //Uncheck all_context and any folder selected but keep other previously selected context.
                if (node.getName() != item.getName() && (isFolderItem || isAllContextItem)) {
                    item.suspendEvents();
                    item.setValue(false);
                    item.resumeEvents();
                }
            }
        }

    }
    // this sets value of hidden containerTypeList
    
    PTC.search.HiddenContextPicker.setStatusFromUserSelection();    
    
    //If all checkbox in myFav context box are selected then myFav context will be selected.
    if (node.getName() != 'all_contexts') {
        PTC.search.setMyFavAndAllContextStatus();
    }

};

