Ext.namespace("PTC.domainAdmin");

/**
 * @namespace
 */
PTC.dd = function() {
    // private scope
    var globalDDGroupId = 'globalDDGroup';

    return {
        /**
         * Create a drag and drop proxy for the given element.  id is required.  A sGroup should be provided, otherwise
         * it will default to a global drag and drop group.
         * @param {Object} proxyConfig - proxy config
         * @param {Function} ProxyConstructor - proxy constructor
         */
        createDDProxy: function (proxyConfig, ProxyConstructor) {
            // id is required
            if (proxyConfig.id) {
                // if no group is provided, set to global
                if (!proxyConfig.sGroup) {
                    proxyConfig.sGroup = this.globalDDGroupId;
                }
                Ext.get(proxyConfig.id).dd = new ProxyConstructor(proxyConfig.id, proxyConfig.sGroup, proxyConfig.config);
            }
        },

        /**
         * Creates a drag and drop target zone.
         * @param {Object} dropZoneConfig - drop zone config json
         */
        createDropZone: function(dropZoneConfig) {
            // id is required
            if (dropZoneConfig.id) {
                // if no group is provided, set to global
                if (!dropZoneConfig.sGroup) {
                    dropZoneConfig.sGroup = this.globalDDGroupId;
                }
                (new Ext.dd.DropZone(dropZoneConfig.id, {ddGroup: dropZoneConfig.sGroup}));
            }
        }
    };
}();

/**
 * The drag and drop table proxy.  Defines event handlers for drag and drop events.
 * @param {String} id - id of the draggable panel.  May contain multiple tables.
 * @param {String} sGroup - the drag and drop group
 * @param {Object} config - additional proxy config
 * @param {Function} isDragAfter - called to determine direction of dragging
 * @class
 */
PTC.dd.DDProxy = function(id, sGroup, config, isDragAfter) {
    this.isDragAfter = isDragAfter;
    PTC.dd.DDProxy.superclass.constructor.call(this, id, sGroup, config);
    //When you grab the scroll bar on a table or attribute panel that shouldn't drag the object, add the styles for those locations to the invalid class list.
    this.addInvalidHandleClass("x-grid3-scroller");
    this.addInvalidHandleClass("attributePanelSpan");
    this.addInvalidHandleClass("invalidDrag");
};

/**
 * PTC.dd.DDProxy extends Ext.dd.DDProxy
 */
Ext.extend(PTC.dd.DDProxy, Ext.dd.DDProxy, {

    /**
     * Reset the drag and drop styling.
     */
    reset: function() {
        if (this.lastTarget) {
            this.lastTarget.removeClass('dragDrop-over');
            this.lastTarget = null;
        }
    },
    
    

    /**
     * Handles the start drag event.  Copies the inner HTML of the drag source into the drag proxy.
     * @param {number} x - the x coordinate of the start drag
     * @param {number} y - the y coordinate of the start drag
     */
    startDrag: function(x, y) {
        var dragEl = Ext.get(this.getDragEl());
        var el = Ext.get(this.getEl());

        this.startX = x;
        this.startY = y;
        el.addClass('dragDrop-fade');
        dragEl.applyStyles({border: '', 'z-index': 2000});
        dragEl.addClass(el.dom.className);
        dragEl.update(el.dom.innerHTML);
    },

    /**
     * This event gets fired when entering a drag zone.
     * @param {Object} e - the event
     * @param {String} targetId - the drag zone id
     */
    onDragEnter: function(e, targetId) {
        this.onDragOver(e, targetId);
    },

    /**
     * This event gets fired when we enter a drop zone while dragging.
     * @param {Object} e - the event
     * @param {String} targetId - the drag zone id
     */
    onDragOver: function(e, targetId) {
        this.reset();

        // don't count the drag source element as a drop zone
        if (targetId !== this.getEl().id) {
            // style the target drop zone
            var target = Ext.get(targetId);
            target.addClass('dragDrop-over');

            // remove the no drop class from the proxy, since we are over a drop zone
            var dragEl = Ext.get(this.getDragEl());
            dragEl.removeClass('dragDrop-noDrop');

            // store target and divider for later events to use
            this.lastTarget = target;

            // update the start x and y
            this.insertAfter = this.isDragAfter(e);
            this.startX = e.getPageX();
            this.startY = e.getPageY();
        }
    },

    /**
     * This event gets fired when we exit a drop zone while dragging.
     */
    onDragOut: function() {
        // set no drop style, since we are no longer over a drop zone
        var dragEl = Ext.get(this.getDragEl());
        dragEl.addClass('dragDrop-noDrop');

        this.reset();
    },

    /**
     * This event gets fired when the drag source is released.
     */
    endDrag: function() {
        // unfade the drag source and proxy
        var el = Ext.get(this.getEl());
        var dragEl = Ext.get(this.getDragEl());
        dragEl.removeClass(el.dom.className);
        el.removeClass('dragDrop-fade');                
        // clean up drag element inner HTML to avoid duplicate ids on el and dragEl
        dragEl.update('');
        this.reset();
    }
});

/**
 * Determine if we are dragging up or down.
 * @param {Object} e - the event
 * @returns {boolean} trus if dragging down, false if dragging up
 */
PTC.dd.DDProxy.isDragDown = function(e) {
    return this.startY < e.getPageY();
};

/**
 * Determine if we are dragging left or right.
 * @param {Object} e - the event
 * @returns {boolean} trus if dragging right, false if dragging left
 */
PTC.dd.DDProxy.isDragRight = function(e) {
    return this.startX < e.getPageX();
};

/**
 * A container panel for managing multiple drop zone tables
 * @param {Object} containerConfig - configuration of the drop zone container
 * @param {String} group - drop zone group
 * @class
 */
PTC.dd.DropZoneTableContainer = function(containerConfig, group) {
    // initialize table container defaults
    Ext.applyIf(containerConfig, {
        autoScroll: true,
        border: false
    });

    // id and drag drop group are required
    if (containerConfig.id && group) {
        PTC.dd.DropZoneTableContainer.superclass.constructor.call(this, containerConfig);
        this.ddGroup = group;
    }
    this.tabId = containerConfig.tabId;
};

/**
 * PTC.dd.DropZoneTableContainer extends Ext.Panel
 * @property {Object} tables - map of item ids to tables
 */
Ext.extend(PTC.dd.DropZoneTableContainer, Ext.Panel, {

    tables: {},

    /**
     * Add a table to the container in the ui and updates internal object to reflect the change
     * @param {Object} config - drop zone table config
     * @returns {PTC.dd.DropZoneTable} the drop zone table
     */
    addTable: function(config) {
        config.sGroup = this.ddGroup;
        var tableId = config.id;
        config.tabId = this.tabId;
        var dropZone = new PTC.dd.DropZoneTable(config);
        this.tables[tableId] = dropZone.id;
        this.insert(0, dropZone);
        return dropZone;
    },
    
    /**
    * Add a widget to the container in the ui and updates internal object to reflect the change
    * @param {Object} config - drop zone table config
    * @returns {PTC.dd.DropZoneTable} the drop zone table
    */
    addWidget: function(config) {
        config.sGroup = this.ddGroup;
        var tableId = config.id;
        config.tabId = this.tabId;

        // Settings tool handler
        var settingsHandler = function(e, target, panel) {
            Ext.Msg.alert('Message', 'The Settings tool was clicked.');
        };

        var WIDGET_ID_PREFIX = "widget_";

        // Close tool handler
        var closeHandler = function(e, target, panel) {
            var menuItemId = panel.id.substring(WIDGET_ID_PREFIX.length);
            var menuItem = Ext.getCmp(menuItemId);
            if(menuItem) {
                menuItem.checkHandler(menuItem, false);
                PTC.infoPage.myTab.setSelection(menuItem, false, true);
            }
        };

        var dropZoneWidget= new Ext.Panel({items:[{
            id:"dropZone_"+tableId,
            xtype:'portal',
            items: [{
                columnWidth:1.0,
                items: [{
                        title: config.actionText,
                        id: WIDGET_ID_PREFIX + config.id,
                        tools: [{id: 'gear',handler: settingsHandler},
                                {id: 'close',handler: closeHandler}],
                            items:new PTC.dd.DropZoneTable(config)
                        }]
                    }]
                }]
                   
            });
            this.tables[tableId] = dropZoneWidget.id;
            this.insert(0,dropZoneWidget);
            return dropZoneWidget;
    },

    /**
     * Remove a table from the container in the ui and updates internal object to reflect the change
     * @param {String} itemId - item id
     */
    removeTable: function(itemId) {
        requestHandler.abort(PTC.dd.inProgressAddRequests[itemId]);
        var dropZoneId = this.tables[itemId];
        var tables = PTC.jca.table.Utils.getExtTables(dropZoneId);
        var length=tables.length;
        for(var i=0;i<length;i++){
            tables[i].getEl().parent().contentAreaPanel = null;
            PTC.jca.table.stickiness.clearTableStickiness(tables[i].id);
        }
        var dropZone = Ext.getCmp(dropZoneId);
        PTC.navigation.removeIframes(Ext.getDom(dropZoneId), true);
        this.remove(dropZone, true);

        // Keep rendered tables updated.
        PTC.infoPageTableMgr.removeRenderedTable(dropZoneId, this.tabId);
        delete this.tables[itemId];
    },

    /**
     * Inserts the one table before another in the ui and updates internal object to reflect the change
     * @param {String} movedItemId - the item id of the item being moved
     * @param {String} targetItemId - the item id of the item to place the moved item above
     */
    insertTableBefore: function(movedItemId, targetItemId) {
        var movedTable = Ext.get(this.tables[movedItemId]);
        var targetTable = Ext.get(this.tables[targetItemId]);
        //updated ui
        movedTable.insertBefore(targetTable);
        //persist table change
        var iMoved = this.items.indexOfKey(movedItemId);
        var iTarget = this.items.indexOfKey(targetItemId);
        //should not insert table into the same location it is already in (causes issues)
        if (!(iMoved + 1 == iTarget)) {
        	this.insert(iTarget, this.tables[movedItemId]);
        }
    },

    /**
     * Inserts the one table after another in the ui and updates internal object to reflect the change
     * @param {String} movedItemId - the item id of the item being moved
     * @param {String} targetItemId - the item id of the item to place the moved item after
     */
    insertTableAfter: function(movedItemId, targetItemId) {
        var movedTable = Ext.get(this.tables[movedItemId]);
        var targetTable = Ext.get(this.tables[targetItemId]);
        //updated ui
        movedTable.insertAfter(targetTable);
        //persist table change
        var iMoved = this.items.indexOfKey(movedItemId);
        var iTarget = this.items.indexOfKey(targetItemId);
        //should not insert table into the same location it is already in (causes issues)
        if (!(iMoved - 1 == iTarget)) {
            this.insert(iTarget, this.tables[movedItemId]);
        }
    },

    /**
     * Scroll to the table in the container.
     * @param {String} itemId - item id
     */
    scrollTo: function(itemId) {
        var tablePanel = Ext.getCmp(this.tables[itemId]);
	    var tablePosition = tablePanel.getPosition(false);
	    var centerPosition = this.getPosition(false);
	    // scrollbar is on body and getEl() is wrapper on top of it
	    // scrollIntoView does not seem to work
	    this.body.scrollTo("top", tablePosition[1]-(centerPosition[1]-this.body.dom.scrollTop), true);		
    },

    /**
     * Clears the stickiness of the tables present in the container
     * @param {String} itemId - item id
     */
    clearTableStickinessInTab: function(itemId) {
        if(itemId){
            var tables = PTC.jca.table.Utils.getExtTables(this.tables[itemId]);
            for(var i=0, length=tables.length; i<length; i++){
                PTC.jca.table.stickiness.clearTableStickiness(tables[i].id);
            }
        }
    }
});

/**
 * Used to keep track of all open requests for adding content to the tab so requests can be aborted when tables are removed. 
 * The requests are stored with keys that are the item id of the table/panel like 'infoPage_myTab_tab_jcaGen_94841_objectrelatedBaselines'. 
 * SPR 1974586
 */
PTC.dd.inProgressAddRequests = {};
/**
 * A table that supports drag and drop.
 * @param {Object} dropZoneConfig - drop zone json
 * @property {String} itemId - the item id
 * @class
 */
PTC.dd.DropZoneTable = function(dropZoneConfig){
    this.itemId = dropZoneConfig.id;
    dropZoneConfig.id = 'wrap_' + this.itemId;
    Ext.applyIf(dropZoneConfig, {
        html: '<div id="' + this.itemId + '_loading" style="height: 100px">&nbsp;</div>'
    });
    
    PTC.navigation.startProgressTask(this.itemId + "_loading");
    
    PTC.dd.DropZoneTable.superclass.constructor.call(this, dropZoneConfig);
    this.tabId = dropZoneConfig.tabId;
    //The validators for Customize menu actions need comp context info for validation. SPR 1955750.
    var compCtx = "$" + dropZoneConfig.actionType + "$" + dropZoneConfig.actionName + "$" + extractParamValue(dropZoneConfig.actionURL, "oid") + "$";
    setActionFormData(compCtx, null, null, null, null, getMainForm());
    PTC.dd.inProgressAddRequests[this.itemId] = getElementHtml(Form.serialize(getMainForm()), this.id, true, dropZoneConfig.actionURL, false);
    clearActionFormData();
    
    PTC.infoPageTableMgr.addRenderedTable(dropZoneConfig.actionID, this.id, this.tabId);
};

/**
 * PTC.dd.DropZoneTable extends Ext.Panel
 */
Ext.extend(PTC.dd.DropZoneTable, Ext.Panel);

/*
 * This file is reused by multiple define item steps, including the main component one owned by the Component team
 * The js in this file is responsible for initial setup of the on change events for the attributes
 * in the driver attributes panel
 *
 * The functions defined in this file must be declared as variables so they can be can be called by both
 * pre-loaded and non-preloaded steps.
 *
 * This file is loaded in begin.jspf via NmPresentationData.getScriptFiles().
 */
// Following are the required function definitions for the driver attributes

Ext.apply(PTC.driverAttributes, new Ext.util.Observable());

/**
 * Listen to afterRefresh event to detect when the driver attributes have been refreshed.
 * For example, the attributesTableWizComponent listens to this event so it can refresh the
 * attributes table when the driver attributes change.
 *
 * @example
 * PTC.driverAttriubtes.on("afterRefresh", PTC.wizard.attributePanelLoader.reloadAttributesTable);
 *
 * @name PTC.driverAttributes#afterRefresh
 * @event
 */
/**
 * Listen to beforeRefresh event to detect before the driver attributes have been refreshed.
 * For example, the attributesTableWizComponent listens to this event so it can remove obsolete attributes
 * before the request is made to refresh the driver attributes.
 * This is to prevent exceptions in preparing the type instance (can't have attributes coming from a different type)
 *
 * @example
 * PTC.driverAttriubtes.on("beforeRefresh", PTC.wizard.attributePanelLoader.clearAttributePanelDiv);
 *
 * @name PTC.driverAttributes#beforeRefresh
 * @event
 */
PTC.driverAttributes.addEvents("afterRefresh", "beforeRefresh");

/**
 * This function is called on the on change event of pickers that effect the
 * driver attribute panel to properly refresh the panel and make sure the change
 * events are hooked up. Currently this applies to the type and template pickers.
 */
PTC.driverAttributes.refreshDriverAttributes = function(url) {
    PTC.driverAttributes.log.trace('Entered PTC.driverAttributes.refreshDriverAttributes');
    // SPR 2225744 disable ok/apply buttons so user can't attempt to submit wizard before reload completes
    disableOkButton();
    PTC.driverAttributes.fireEvent("beforeRefresh");
    var objectHandle = PTC.wizard.getCurrentObjectHandle();
    var driverAttributesElement = Ext.getDom(objectHandle + 'driverAttributes');
    var driverAttributesErrorElement = Ext.getDom(objectHandle + 'driverAttributesErrorDiv');

    if (driverAttributesElement.tagName == 'DIV') {
        refreshElement(driverAttributesElement.id, url);
        // re-enable ok/apply buttons
        resetOkButton();
    }
    else if (driverAttributesElement.tagName == 'TBODY') {
        if (driverAttributesErrorElement) {
            PTC.util.purge(driverAttributesErrorElement, true);
            driverAttributesErrorElement.innerHTML = "";
        }
        var tbody = driverAttributesElement; //the tbody to put the driver attributes into so they align with the Type picker
        if (tbody) {
            //remove the current rows in the tbody
            PTC.util.purge(tbody, true);
            while (tbody.rows.length > 0) {
                tbody.deleteRow(0);
            }
            //get the new rows to put in the tbody
            if (PTC.driverAttributes._ajaxRequest) {
                try {
                    PTC.driverAttributes._ajaxRequest.abort();
                } catch(e) {
                    PTC.driverAttributes.log.debug('Abort ajax request failed in PTC.driverAttributes');
                }
            }
            var formData = Ext.lib.Ajax.serializeForm(getMainForm()) + "&portlet=component";
            var soupedUpUrl = getPageUrl(url, 'foo');
            var options = {
                asynchronous: true,
                parameters: formData,
                //if an exception occur from the controller, flush the
                //error message into driverAttributes area
                on501: PTC.driverAttributes.driverAttributesOnSuccess,
                onSuccess: PTC.driverAttributes.driverAttributesOnSuccess
            };
            PTC.driverAttributes._ajaxRequest = requestHandler.doRequest(soupedUpUrl, options);
        }
    }
};

/**
 * On success of getting driver attribute response.  This was pulled out into asynchronous since
 * it would freeze up IE - making it hang.
 *
 * @param {Object} transport The response and headers.
 */
PTC.driverAttributes.driverAttributesOnSuccess = function(transport){
    PTC.driverAttributes.log.trace('Entered PTC.driverAttributes.driverAttributesOnSuccess');
    delete PTC.driverAttributes._ajaxRequest;
    var objectHandle = PTC.wizard.getCurrentObjectHandle();
    var driverAttributesId = objectHandle + 'driverAttributes';
    var driverAttributesErrorId = objectHandle + 'driverAttributesErrorDiv';
    var tbody = document.getElementById(driverAttributesId); //the tbody to put the driver attributes into so they align with the Type picker

    var response = transport.responseText;

    //html will be <tr>s from the response, assumption is that the driver attributes are inside <table ....</table>.
    var html = asyncResponseHandler.stripText(response, "", false);
    if (html.indexOf("</tr>") >= 0) {
        var rows = PTC.driverAttributes.getTRStringArray(html);

        //put the new rows into the tbody
        rows.each(function(rowHTML){
            if (rowHTML) {
                var newRow = tbody.insertRow(-1);
                if (newRow) {
                    if (Ext.isIE) {
                        // in IE 8 mode need to insert the rows as DOM element objects instead of as string
                        PTC.tableResponseHandler.insertNewRowHTMLForIE(newRow, rowHTML);
                    }
                    else {
                        // in other 'modern' browsers can just set the innerHTML (IE Edge mode/Firefox/Chrome)
                        newRow.innerHTML = rowHTML;
                    }
                }
            }
        });
    }
    else {
        //no <table> in the response so can't do alignment, just try to display whatever the response was
        //repsonse maybe some html that is not in a property panel or maybe a 404 page not found error
        //IE fails to display the entire response, so use the stripped text
        if (!$(driverAttributesErrorId)) {
            //create a div to display the error in
            var parent = getParentNodeByTag(tbody, "DIV");
            var errorDiv = document.createElement("div");
            errorDiv.id = driverAttributesErrorId;
            parent.appendChild(errorDiv);
        }
        $(driverAttributesErrorId).innerHTML = html;
    }
    PTC.navigation.evalPageScripts(response);

    PTC.driverAttributes.setupJavascriptForDriverAttributes();
    // re-enable ok/apply buttons
    resetOkButton();            

	// wait 1 millisecond to put firing the event at the end of the javascript queue, 
	// sometimes there's no listeners yet, this is for possible race condition avoidance found in
	// SPR 2241161 where attributesTableWizComponent.tag doesn't always get the listener registered in time.
	setTimeout(function(){PTC.driverAttributes.fireEvent("afterRefresh");}, 1);   
};


/**
 * expects the given string ends with &lt;/tr&gt;, extracts contents of each &lt;tr&gt;...&lt;/tr&gt; into a string array.
 * @example
 * PTC.driverAttributes.getTRStringArray("&lt;tr&gt;&lt;td&gt;ABC&lt;/td&gt;&lt;td&gt;XYZ&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;123&lt;/td&gt;&lt;td&gt;456&lt;/td&gt;&lt;/tr&gt;");
 * // returns ["&lt;td&gt;ABC&lt;/td&gt;&lt;td&gt;XYZ&lt;/td&gt;", "&lt;td&gt;123&lt;/td&gt;&lt;td&gt;456&lt;/td&gt;"]
 **/
PTC.driverAttributes.getTRStringArray = function(html) {
    html = "</tr>" + html.substring(html.indexOf("<tr>")) + "<tr>";
    var rows = html.split("</tr><tr>").without('');
    return rows;
};

/**
 * Attributes in the driver attribute panel need to have js added to them to mark
 * downstream steps dirty when they change. This js function finds them and adds the required function calls.
 */
PTC.driverAttributes.setupJavascriptForDriverAttributes = function() {
    PTC.driverAttributes.log.trace('Entered PTC.driverAttributes.setupJavascriptForDriverAttributes');
    var driverAttributesId = PTC.wizard.getCurrentObjectHandle() + 'driverAttributes';
    var driverAttributes = document.getElementById(driverAttributesId);
    if (driverAttributes) {
        // Handle the input tag
        var inputs = driverAttributes.getElementsByTagName("input");
        PTC.driverAttributes.addOnChangeEventsToApplicableItemsInArray(inputs);

        // Handle the select tag
        var selects = driverAttributes.getElementsByTagName("select");
        PTC.driverAttributes.addOnChangeEventsToApplicableItemsInArray(selects);

        // Handle the textarea tag
        var textareas = driverAttributes.getElementsByTagName("textarea");
        PTC.driverAttributes.addOnChangeEventsToApplicableItemsInArray(textareas);
    } else {
        PTC.driverAttributes.log.debug('Dom element not found for driver attribute ', driverAttributesId);
    }
};


/**
 * listener to be called everytime a driver attribute changes
 */
PTC.driverAttributes.onChangeHandler = function(){
    //SPR Task: 6199329 Disable the buttons as going to reloadAttributesTable.
    disableOkButton();

    PTC.driverAttributes.log.trace('Called PTC.driverAttributes.onChangeHandler');
    markDownstreamNonPreloadedWizStepsDirty();
    deleteDownstreamFormContent();
    //If any driver attributes changes then reload the attributes table. SPR 1963934
    PTC.driverAttributes.log.trace('Calling PTC.wizard.attributePanelLoader.reloadAttributesTable to reload attributes table');
    PTC.wizard.attributePanelLoader.reloadAttributesTable();
};

/**
 * This function is used by setupJavascriptForDriverAttributes to go through
 * An array of HTML components and add the correct js to the change event for
 * each one that is not hidden and to the hidden field, if it is for an auto suggest
 * picker.
 */
PTC.driverAttributes.addOnChangeEventsToApplicableItemsInArray = function(componentArray) {
    if (componentArray) {
        var length = componentArray.length;
        if (length > 0) {
            PTC.driverAttributes.log.debug('performing addOnChangeEventsToApplicableItemsInArray for ', length, componentArray[0].nodeName, ' elements');
        }
        var registerExtListeners = function() {
            this.on('select', PTC.driverAttributes.onChangeHandler);
            this.on('click', PTC.driverAttributes.onChangeHandler);
            this.on('blur', function() {
                if (this.getValue() === '') {
                    PTC.driverAttributes.onChangeHandler();
                }
            });
        };
        for (var i = 0; i < length; i++) {
            var component = componentArray[i];
            if (component.type !== "hidden") {
                if (PTC.autosuggest.suggestBoxHandler.isAutoSuggest(component.id)) {
                    Ext.ComponentMgr.onAvailable(component.id, registerExtListeners);
                } else {
                Event.observe(component, 'change', PTC.driverAttributes.onChangeHandler);
            }
        }
    }
    }
};

