jsca.columns.enumeratedTypeRenderer = function(table, column, row){
    var data = jsca.columns.getCellValue(column, row);
    //this value should never be displayed, should always find the currentValue
    var result = "undefined";
    if (data && data.currentValue !== undefined) {
        result = data.currentValue;
        if (data.allValues) {
            result = '';
            for(var i=0, l=data.allValues.keys.length; i<l; i++) {
                var value = data.allValues.values[i];
                var key = data.allValues.keys[i];
                if (result.length > 0) {
                    result = result + data.separator;
                }
                if (key === data.rawValue) {
                    //"Active State"
                    var title = data.activePrefix + " " + data.label;
                    //the img is so that JAWS (screen reader for 508 compliance) can read the active state
                    value = '<img src="netmarkets/images/sp.gif" alt="' + title + '" title="' + title + '" height="1" width="1"/><b>' + value + '</b>';
                }
                result = result + value;
            }
        }

        if(data.id) {
            result = '<span id=\'' + data.id + '\'>' + result + '</span>';
        }
    }
    //need this for export list to file to work
    data.value = result;
    result = result + jsca.columns.getHiddenInputs(data.hiddenData);
    return result;
};

jsca.columns.enumeratedTypeRenderer.searchFunc = function(table, column, row) {
    var data = jsca.columns.getCellValue(column, row);
    var result = data.value;
    if(!result) {
        result = jsca.columns.enumeratedTypeRenderer(table, column, row);
    }
    return getUnescapedText(result);
};

