/**
 * @namespace Deprecated use expand/collapse Ext panels instead.
 * @deprecated use expand/collapse Ext panels instead
 * @private
 */
expandCollapse = {
   /**
    * function to initialize some dynamic values on the expandCollapse.Header
    * or expandCollapse.AttributesPanel object
    * @param collapsed - boolean - the current state of the panel
    * @param expandTT - string - localized and html escaped expand tooltip
    * @param collapseTT - string - localized and html escaped collapse tooltip 
    * @param id - string - id of the DOM element to put the expand/collapse "button" in
    * @param object - either the expandCollapse.Header or expandCollapse.AttributesPanel
    * @private
    */
   init : function(collapsed, expandTT, collapseTT, id, object) {
      object.collapsed = collapsed;
      object.expand.tooltip = expandTT;
      object.collapse.tooltip = collapseTT;
      object.id = id;
      expandCollapse.setHtml(object);
   },
   /**
    * creates the html for an expand/collapse "button"
    * and sets it as the innerHTML of the DOM element with the given object.id
    * @private
    */
   setHtml : function(object) {
      if($(object.id)) {
         var state = object.collapsed ? object.expand : object.collapse;
         var tooltip = 'title="'+state.tooltip+'" alt="'+state.tooltip+'" ';
         var imgHtml = '<img src="'+state.img+'" '+tooltip+'/>';
         var onclick = 'expandCollapse.slideIt(expandCollapse.'+object.name+');Event.stop(event);';
         var linkHtml = '<a href="#" onclick="'+onclick+'" '+tooltip+'>'+imgHtml+'</a>';
         $(object.id).innerHTML = linkHtml;
      }
   },
   /**
    * expands or collapses the header/footer or attributes panel (sliding it up and down)
    * and updates the expand/collapse state in the session bean
    * @private
    */
   slideIt : function(it) {
   
      if(it.collapsed) {
         //expand the header
         expandCollapse.show(it.divIds, 0.4);
      } else {
         //collapse the header
         expandCollapse.hide(it.divIds, 0.4);
      }
      
      it.collapsed = !it.collapsed;      
      //change the tooltip/image to match the new expand/collapse state
      expandCollapse.setHtml(it);
      
      var options = {asynchronous: false};
      var url = "netmarkets/jsp/components/setCollapseHeaderInfo.jsp?" + it.name + "="  + it.collapsed;
      //update the expand/collapse state on the session bean
      this.req = requestHandler.doRequest(url, options);
      
      // Adjust workspace table based on the vertical height of the window
      if (typeof wsJSTableResize === "function" ) {
          setTimeout(wsJSTableResize,400);
      }      
   }
};

