/**
 * This is a handler function for table \ tree expand-collapse button
 * @param {String} tableID
 * 
 * Future consideration: Seperate out titlebar from other components of
 * table and group other components, so that expand and collapse can
 * be implemented easily.  
 */
PTC.jca.expandCollapse = function(tableID) {
    if (!tableID || !Ext.isString(tableID)) {
        tableID = this.initialConfig.tableid;
     }
     var wTable = Ext.getCmp(PTC.jca.table.getWTablePanelID(tableID));
     var gridPanel = wTable.gridPanel;
     var expandCollapseButton = Ext.getCmp(tableID + "_toggle");
     if (gridPanel !== undefined) {
         var panels = [gridPanel.body, gridPanel.bbar, wTable.toolBar, gridPanel.menuBar, gridPanel.footer];
         if(gridPanel.jcaCollapsed) {
             // Expand table / tree
             gridPanel.el.removeClass(this.collapsedCls);
             panels.each(function(panel){
                 if (panel !== undefined) {
                 	if(panel.dom){
                 		panel.dom.style.display="block";
                 	}
                 	else{
                 		panel.show();
                 	}
                     
                 }
             });
             gridPanel.jcaCollapsed = false;
             expandCollapseButton.setIconClass('expandCollapse_collapsed');
             expandCollapseButton.setTooltip(bundleHandler.get('com.ptc.netmarkets.util.utilResource.COLLAPSE_TABLE'));
             if (gridPanel.view._scrollStateCache) {
                 gridPanel.view.restoreScroll(gridPanel.view._scrollStateCache);
                 delete gridPanel.view._scrollStateCache;
             }
         } else {
             // Collapse table / tree
             gridPanel.view._scrollStateCache = gridPanel.view.getScrollState();
             panels.each(function(panel) {
                 if (panel !== undefined) {
                 	if(panel.dom){
                 		panel.dom.style.display="none";
                 	}
                 	else{
                 		panel.hide();
                 	}
                     
                 }
             });
             gridPanel.jcaCollapsed = true;
             expandCollapseButton.setIconClass('expandCollapse_expanded');
             expandCollapseButton.setTooltip(bundleHandler.get('com.ptc.netmarkets.util.utilResource.EXPAND_TABLE'));
         }
       gridPanel.fireEvent('afterExpandCollapse');
     }
};



