/**
 * @namespace for export common functions
 */
var exportListUtilities = function(){

    return {
        resetExportTableFile: function(){
            var inputFilePath = document.getElementById("exportTableFile");
            if (!inputFilePath) {
                jsca.error("No \'exportTableFile\' element is defined in the DOM.  Verify that" +
                " an input field with this id is included in the export client jsp file. ");
                return;
            }
            var strValue = inputFilePath.value;
            if (!strValue) { // generate default
                strValue = exportListUtilities.getTableName();
                inputFilePath.value = strValue;
            } // end if inputFilePath
        },

        /**
         * Because this function only exists in the opener page we want to redefine
         * it for the wizard step for use with js tables.
         * This function is called for js tables in renderers.jsfrag.
         */
        remapFormatDate: function(){
            if (typeof formatDate === 'undefined' && opener && typeof opener.formatDate !== 'undefined') {
                formatDate = opener.formatDate;
            }
        },

        /**
         * Returns the the opener table object
         */
        getOpenerTable: function(){
            var tableId = getWindow().location.href.parseQuery().tableID;
            tableId = tableUtils.getUnformattedTableId(tableId);
            return opener.tableUtils.getTable(tableId);
        },

        /**
         * Gets the table name for a JSCA table (ex. Folder Browser)
         */
        getTableName: function(){
            var tableName = null;
            var paraTableID = getWindow().location.href.parseQuery().tableID;
            var tableComp = exportListUtilities.getOpener().Ext.getCmp(tableUtils.getUnformattedTableId(paraTableID) + '_WTablePanel');
            if (tableComp) {
                tableName = tableComp.initialConfig.tableName;
                if(!tableName){
                    tableName = tableComp.initialConfig.tableID;
                }
            }
            return exportListUtilities.getGeneratedFileName(tableName);

        },

        /**
         *  Populates the nonExportableColumns from cache using bundleHandler
         */
       getNonExportableColumns: function() {
            var nonExportableColumnsList = bundleHandler.get("com.ptc.core.ui.tableRB.NON_EXPORTABLE_COLUMNS");
            var nonExportableColumns = {};
            if (nonExportableColumnsList.length) {
                nonExportableColumnsList.split(/\s*\,\s*/).each(function(column_name){
                    if(column_name.length){
                        nonExportableColumns[column_name] = true;
                    }
                });
            }
            return nonExportableColumns;
        },

        /**
         * Gets the table name for a JS table (ex. Workspace)
         */
        getJSTableName: function(){
            var filelist = opener.document.getElementById("fileList");
            if (!filelist) {
                return "";
            }
            var html = filelist.innerHTML.toLowerCase(); // ie generates upper case and firefox generates lowercase
            var tableName = html.substring(0, html.indexOf("<span")); // ie cannot index '\n'
            return exportListUtilities.getGeneratedFileName(tableName);
        },


        defaultExportRenderer: function(table, col, row, getRowFunc, getCellFunc){
            var text = '';
            var gui = jsca.columns.getCellValue(col, row);
            text = getJSCASearchTextForCell(gui);
            return text;
        },

        /**
         * Generate the file name using the table name, user id, and time stamp.
         */
        getGeneratedFileName: function(tableName){
            var strFileNameDelimiter="~";
            if (fileNameDelimiter) {
                strFileNameDelimiter = fileNameDelimiter;
            }
            var tableNameTrim = tableName.replace(/\s/g, '');
            return tableNameTrim + strFileNameDelimiter + userID + strFileNameDelimiter + timeStamp;
        },

        getOpener: function(){
            if (opener) {
                return opener;
            }
            else if (top.opener) {
                return top.opener;
            }

            return window;
        },

        /**
         * This function modifies the value of the exportTableFile hidden text element to append the
         * file format for the legacy types (xml, xls, and suma.xls)
         */
        appendFormatTypeIfNeeded: function(formattype){
            if (formattype == 'xml' || formattype == 'xls' || formattype == 'suma.xls') {
                //the legacy stuff expects the formattype to be on the file name
                $('exportTableFile').value += "." + formattype;
            }
        },

        /**
         * Checks for the existence of the part.report.closeReportSession() function in the opening window.  If this exists
         * it indicates that the export was performed from a part report.  This is used in determining if part.report.closeReportSession()
         * should be called on the opener to clear out the cache that was used to build the report used for the export.
         *
         *@return part.report object if it exists, else returns null
         */
        getReportExport: function() {
            var opener = exportListUtilities.getOpener();
            if(opener && opener.part && opener.part.report) {
               return opener.part.report;
            }
            return null;
        },

        /**
         * Two places this function gets called:
         *
         * 1) From ExportTableRenderer - it finishes the export by redirecting to the new url.
         * 2) Legacy search export requires this code,
         * the default wizard processing will call NmSearchCommands.exportSearchResultsDownload which builds up
         * the task params for the info engine task and adds them to the response.
         * The href returned by NmSearchCommands (exportSearchResultsDisplay.jsp) calls SearchHelper.exportSearchResults
         * which executes the infoengine task that does the actual exporting. The task returns a file as it's result which is then
         * downloaded by the browser. Note that the headers on the file download can sometimes cause the browser to fail to download.
         * There is currently an IE 7 issue when "attachment;" is on the front of the header.
         */
        finishServerExport: function(href) {
            PTC.exportTable.log.trace("Entering exportListUtilities.finishServerExport ()");
            PTC.exportTable.log.debug("href for redirection:",href);
            // This is invoked to clear a cache that was used to generate part reports.
            var reportExport = this.getReportExport();
            if(reportExport) {
                reportExport.closeReportSession();
            }
            //because the window is closing, mozilla will shut down the open/save dialog so have the opener show the open/save dialog
            //Open is opening an additional window, in IE and FF this closes fine but in ProE/Chrome  it does not so in proE/Chrome we set href instead
            if (!isWf() && !Ext.isChrome) {
                // IE and FF
                exportListUtilities.getOpener().open(href);
            } else {
                exportListUtilities.getOpener().location.href = href;
            }           
            WaitAndClose();
        },
        
        /**
         * Check if view selected only is on
         * This will not be needed if we go to a model where no tables are paged  and use server side export,
         * for now it has been updated to work with the new EXT
         */
        isViewSelectedOnly: function(table){
            if (table && table.getTopToolbar()) {
                var selectedOnlyMenu = table.getTopToolbar().findById(table.getId() + '_WTablePanel_selectedOnlyMenu');
                if (selectedOnlyMenu) {
                    return selectedOnlyMenu.menu.items.items[0].checked;
                }
            }
            return false;
        },

        /**
         * Returns information about sort order and visible columns for the specified table,
         * in a HTML escaped String suitable for POSTing to the server in a "Export List" request.
         *
         * @param {Object} table
         * @returns {JSONObject} column visibility and sort parameters to pass to server for "Export List"
         *
         * Column IDs are combined into a comma-delimted string (see ExportTableRenderer.hideFilteredColumns()).
         * Sort columns and directions are named with the table ID plus sc, sc2, sc3 (column ID),
         * sd, sd2, sd3 (direction) (see SortRequestBean.populateFromRequest()).
         */
        getTableColumnServerParameters: function(table){
            var parametersStr = "";

            var visibleColumns = PTC.jca.table.Utils.getTableVisibleColumnsServerIds(table);

            // Add visible columns.
            parametersStr += "visibleColumns=" + encodeURI(visibleColumns) + "&";

            // Add column sort order and direction.
            var sortInfo = PTC.jca.table.Utils.getTableSortInfo(table);
            for (var i = 0; i < sortInfo.length; i++) {
                var colIndex = i === 0 ? '' : (i + 1); // since server expects parameters in order sd, sd2, sd3
                //need to send the serverId for the column
                parametersStr += table.id + "sc" + colIndex + "=" + escape(PTC.jca.getServerIdFromJSColumnId(table,sortInfo[i].columnID)) + "&";
                parametersStr += table.id + "sd" + colIndex + "=" + escape(sortInfo[i].sortDirection) + "&";
            }

            return parametersStr;
        },

        /**
         * display message to tell that legacy formats do not support exporting view selected only
         */
        legacyExportViewOnlyMessage: function(event){
            var tableId = tableUtils.findTableID(event);
            if (exportListUtilities.isViewSelectedOnly(window.tableUtils.getTable(tableId))) {
                return JCAConfirm(event, 'com.ptc.core.ui.confirmationMessagesRB.LEGACY_EXPORT_TABLE_CONFIRMATION');
            }
            return true;
        },
        
        /**
         * Fire an event for others to listen for and to consume the created file when a Download dialog is
         * not wanted or more file manipulation is desired.
         * Example listener:
         * PTC.exportTable.on("ExportFileCreationComplete", function(data) {
         *		var url = data.url;
         *		// add custom code here
         * });
         */
        fireExportContentEvent: function(formData) {
            if (formData.url && formData.actionName) {
                PTC.exportTable.log.debug("Firing 'ExportFileCreationComplete' event");
                PTC.exportTable.fireEvent("ExportFileCreationComplete",formData);
            } else {
                PTC.exportTable.log.error("actionName and url are necessary, but not included - formData: ",JSON.stringify(formData));
            }
            WaitAndClose();
        },
        
        /**
         * Utility function used to decide which of the two completion operations should be run.
         * The Options are:
         * 1. initiate download in browser
         * 2. fire listener and close window
         */
        doCompleteAction: function(extraData) {
            if (extraData.contentOnly) { 
                exportListUtilities.fireExportContentEvent(extraData);
            } else {
                var url = extraData.url;
                exportListUtilities.finishServerExport(url);
            }
        }
        
    };
}();

/**
 * ExportTable action related function
 *
 * @namespace
 * @name PTC.exportTable
 */
Ext.namespace ('PTC.exportTable');
PTC.exportTable.log = log4javascript.getLogger('PTC.exportTable');
Ext.apply(PTC.exportTable, new Ext.util.Observable());
PTC.exportTable.addEvents('ExportFileCreationComplete');

/**
 * Handles the response from the server - Upon failure, this function calls for the
 * creation of a file if the table was paged. If not paged, this will either kick off
 * a download or fire a Listener for others to consume the created file based on contentOnly flag.
 */
PTC.exportTable.exportTableSuccessListener = function (formResult) {
    PTC.exportTable.log.trace("Entering PTC.exportTable.exportTableSuccessListener ()");
    var downloadNow = formResult.extraData.downloadNow;
    
    if (downloadNow) { // Non-paged table functionality - file content was already created
        exportListUtilities.doCompleteAction(formResult.extraData);
    } else { // Paged table functionality - file content not created yet
        top.finishServerSideExport();
    }

    return false; //No need to run default processing
};

/**
 * For basic export operation, should work on any jca table/tree
 *
 * It also allows for extension and facilitate unit testing.
 * @class
 */
var exportListOperation = function(){
    this.isJCADebug = false;
    this.totalPages = null;
    this.DELIM = "|$|";
    this.ROW_DELIM = "|$%$|";
    this.FIRST_INDEX = "fi";
    this.cachedExporter = null;
};

exportListOperation.prototype.getExporter = function(){
    PTC.exportTable.log.trace("Entering exportListOperation.prototype.getExporter ()");
    if (!this.cachedExporter) {
        var Exporter = Class.create({
            allRowData: '',
            DELIM: '',
            ROW_DELIM: '',
            form: '',

            initialize: function(){
                var o = new exportListOperation(); //Just to get the delim.
                this.DELIM = o.DELIM;
                this.ROW_DELIM = o.ROW_DELIM;
                this.form = getMainForm();
            },

            appendColumnHeadersToForm: function(data){
                PTC.exportTable.log.debug("Appending 'fileHeaders' hidden input to form");
                var elem = new JCAnewHiddenInputElement("fileHeaders", data, this.form);
                this.form.appendChild(elem);
            },

            appendOidsToForm: function(data){
                PTC.exportTable.log.debug("Appending 'oidsToExport' hidden input to form");
                var elem = new JCAnewHiddenInputElement("oidsToExport", data, this.form);
                this.form.appendChild(elem);
            },

            appendRowsToForm: function(allRows){
                PTC.exportTable.log.debug("Appending Delimiters to all Rows");
                var rows = [];
                for (var i = 0, rowsLength = allRows.length; i < rowsLength; i++) {
                    rows.push(allRows[i].join(this.DELIM));
                }
                this.allRowData = rows.join(this.ROW_DELIM);
            },

            submitForm: function(){
                PTC.exportTable.log.debug("Adding fileContent and Delimiters to form.");
                var elem = new JCAnewHiddenInputElement("fileContent", this.allRowData, this.form);
                PTC.exportTable.log.debug("fileContent: ",elem.value);
                this.form.appendChild(elem);
                this.form.appendChild(new JCAnewHiddenInputElement("delim", this.DELIM, this.form));
                this.form.appendChild(new JCAnewHiddenInputElement("row_delim", this.ROW_DELIM, this.form));
                PTC.exportTable.log.debug("Delimiter: ",this.DELIM,"Row Delimiter: ",this.ROW_DELIM);
                PTC.wizard.submitWizard({skipAllValidation: true, successFunc: PTC.exportTable.exportTableSuccessListener});
            }
        });
        this.cachedExporter = new Exporter();
    }
    return this.cachedExporter;
};

/**
 * Wrapping this call to get a parameter from the query string for unit testing.
 */
exportListOperation.prototype.getFileType = function(){
    return getWindow().location.href.parseQuery().fileType;
};

/**
 * Gets the table id from the window params.
 */
exportListOperation.prototype.getTableId = function(){
    var tableId = getWindow().location.href.parseQuery().tableID;
    tableId = tableUtils.getUnformattedTableId(tableId);
    return tableId;
};

/**
 * gets header values of a table
 * @return array of header strings to be used in the export file
 */
exportListOperation.prototype.getHeaders = function(exportColumns){
    PTC.exportTable.log.trace("Entering exportListOperation.prototype.getHeaders ()");
    var headers = [];
    var exportColumns_length = exportColumns.length;
    for (var i = 0, colWritten = 0; i < exportColumns_length; i++) {
        var header = tableUtils.getHeaderLabel(exportColumns[i]);
        if (!header) {
            header = " ";
        }
        headers[colWritten++] = header;
    } // end for i
    PTC.exportTable.log.debug("Headers: ",headers.toString());
    return headers;
};

/**
 * Gets all the row arrays for export.
 */
exportListOperation.prototype.getAllExportRows = function(table, exportColumns){
    PTC.exportTable.log.trace("Entering exportListOperation.prototype.getAllExportRows ()");
    var colLen = exportColumns.length;
    var rowData = tableUtils.getFilteredRowData(table);
    var exportFunc = this.getSingleRowExportArray;
    var exportArrayFunc = this.getExportValue;
    var getRowFunc = getRowItem;
    var getCellFunc = jsca.columns.getCellValue;
    var allRows = [];
    var allOids = [];
    var isTree = table.tree;
    rowData.each(function(row, index){
        allOids.push(row.data.oid);
        row.item = row; //JS renderers expect a row.item to be present.
        var isVisible = true;
        if(typeof row.isHideNotSel == "function"){
            isVisible = !row.isHideNotSel();
        } else {
            if(isTree === true){
                var store = table.store;
                if(store && (typeof store.isVisibleNode == 'function')){
                    isVisible = store.isVisibleNode(row, index);
                }
            }
        }
        if (isVisible) {
            allRows.push(exportFunc(table, row, colLen, exportColumns, exportArrayFunc, getRowFunc, getCellFunc));
        }
    });
    allRows.exportOids = allOids;
    if(PTC.exportTable.log.isDebugEnabled()){
        allRows.each(function(row,index){
            PTC.exportTable.log.debug("Export Row Number:",index+1,"Row Data:",JSON.stringify(row),"Row Oid:",allRows.exportOids[index]);
        });
    }
    return allRows;
};

/**
 * Returns an array of the cell values to be used in the export file.
 *
 * The export function used is the efunc property from the column if defined. Otherwise, the jscaRenderer.exportRenderer property from the column is used.
 * If neither of those properties is found the default export function is the jsca.columns.simpleExportRenderer.
 *
 * Many columns just end up with the default export function. But when that default is overriden,
 * typically an efunc overrides it for jstable columns and an exportRenderer overrides it for JSCA columns.
 */
exportListOperation.prototype.getSingleRowExportArray = function(table, row, colLen, exportColumns, exportFunc, getRowFunc, getCellFunc){
    var rowOut = [];
    for (var k = 0; k < colLen; k++) {
        var col = exportColumns[k];
        var efunc = col.efunc;
        if (typeof efunc === 'undefined' && typeof col.jscaRenderer !== 'undefined') {
            col.jscaRenderer = PTC.util.convertStringToFunc(col.jscaRenderer);
            efunc = col.jscaRenderer.exportRenderer;
        }
        if (typeof efunc === 'undefined') {
            efunc = jsca.columns.simpleExportRenderer;
        }
        col = tableUtils.getColumnObject(col);
        var retObj = exportFunc(table, col, row, efunc, getRowFunc, getCellFunc);
        if (retObj === "") {
            retObj = " ";
        }
        rowOut.push(retObj);
    }
    return rowOut;
};

/**
 * Filters the table rows so that only exportable values are included
 *
 * @param table - This is the table to export - containing row data
 */
exportListOperation.prototype.getExportColumns = function(table){
    PTC.exportTable.log.trace("Entering exportListOperation.prototype.getExportColumns ()");
    var exportColumnsTemp = PTC.jca.ColumnUtils.getVisibleColumns(table.getColumnModel());
    PTC.exportTable.log.debug("Number of Visible Columns in Table: ",exportColumnsTemp.length);
    var exportColumns = [];
    for (var i = 0, l = exportColumnsTemp.length; i < l; i++) {
        var columnTemp = exportColumnsTemp[i];
        if (this.isExportable(columnTemp)) {
            // 2043577 create a clone of the column to avoid changing any renderer references
            exportColumns.push(PTC.jca._getJscaCol(columnTemp));
        }else if (columnTemp.id !== null){
            PTC.exportTable.log.debug(columnTemp.id,"column is Visible, but NOT exportable");
        }
    } // end for i
    return exportColumns;
};

/**
 * Checks the column to see if it is exportable
 *
 * @param column - the column to be checked for exportability
 */
exportListOperation.prototype.isExportable = function(column){
    var exportable = true;
    var nonExportableColumns = exportListUtilities.getNonExportableColumns();
    if(nonExportableColumns[column.id] || column.grid || column.id.startsWith("infoPageActionReporting")){
        exportable = false;
    }
    return exportable;
};

/**
 * Exports the table data to the file specified.
 *
 * @param table - This is the table to export, if null, the table will be looked up
 */
exportListOperation.prototype.exportDataToFile = function(table){
    PTC.exportTable.log.trace("Entering exportListOperation.prototype.exportDataToFile ()");
    var allRows = null;
    if (!table) {
        table = this.getTable();
    }
    var exportColumns = this.getExportColumns(table);
    PTC.exportTable.log.debug("Number of Columns being Exported: ",exportColumns.length);
    allRows = this.getAllExportRows(table, exportColumns);
    PTC.exportTable.log.debug("Number of Rows being Exported: ",allRows.length);
    allRows.headers = this.getHeaders(exportColumns);
    return allRows;
};

/** This method will call the registered efunc renderer for each cell, if one exists.
 * If one doesn't exist, it calls the sfunc (search) renderer.
 *
 * Currently, jsca.columns.simpleExportRenderer is the default efunc if no efunc/attrRenderer.exportRenderer function is defined on the column.
 */
exportListOperation.prototype.getExportValue = function(table, column, row, efunc, getRowFunc, getCellFunc){
    var text = ' ';
    if (efunc) {
        text = efunc(table, column, row, getRowFunc, getCellFunc);
        if (text === null) {
            text = " ";
        }
        text = getUnescapedText(text);
    }
    else {
        jsca.error("No efunc defined for column. " +
        "Need to add this column to the list of non-exportable columns or we need to add an efunc." +
        "Column: " + column);
    }
    return text;
};

exportListOperation.prototype.showProgressIndicator = function(){
    PTC.exportTable.log.trace("Entering exportListOperation.prototype.showProgressIndicator()");
    //Skip if we are debugging
    if (this.isJCADebug) {
        return;
    }
    goProgress();
};


/**
 * This will retrieve the correct table depending on whether it is
 * in the iframe or not.
 */
exportListOperation.prototype.getTable = function(){
    PTC.exportTable.log.trace("Entering exportListOperation.prototype.getTable ()");
    var tableId = this.getTableId();
    var table = this.getTableWindow().tableUtils.getTable(tableId);
    if (table && table.tabled) {
        table = table.tabled;
    }

    return table;
};

/**
 * This will get the window for the table.
 */
exportListOperation.prototype.getTableWindow = function(){
    return opener;
};

/**
 * Checks the opener window for whether the table has all the export data local or not
 * Once it checks the first time then it will store the value so we
 * do not continually go to the opener to see if it is paged.
 */
exportListOperation.prototype.isTablePaged = function(aWindow){
    PTC.exportTable.log.trace("Entering exportListOperation.prototype.isTablePaged ()");
    if (!aWindow) {
        aWindow = opener;
        if (!aWindow) {
            aWindow = window;
        }
    }
    var tableId = this.getTableId();
    tableId = tableUtils.getUnformattedTableId(tableId);
    var table = aWindow.tableUtils.getTable(tableId);

    // view selected object only should use non paged mode
    if (exportListUtilities.isViewSelectedOnly(table)) {
        PTC.exportTable.log.debug("Table is NOT Paged - is 'View Selected Object Only'");
        return false;
    }
    var nextLink = aWindow.Ext.getCmp("nextResultSet_" + tableId);
    var prevLink = aWindow.Ext.getCmp("previousResultSet_" + tableId);

    if (nextLink || prevLink) {
        PTC.exportTable.log.debug("Table is Paged - Contains Next or Prev Link");
        return true;
    }
    else {
        PTC.exportTable.log.debug("Table is NOT Paged - does NOT Contain next or Prev Link");
        return false;
    }
};

exportListOperation.prototype.isTree = function(){
    var table = this.getTable();
    var config = table.jcaTableConfig;
    if (config && config.tree) {
        PTC.exportTable.log.debug("Table is a tree structure");
        return true;
    }
    else {
        PTC.exportTable.log.debug("Table is NOT a tree structure");
        return false;
    }
};

exportListOperation.prototype.endExportAndClose = function(exportData){
    PTC.exportTable.log.trace("Entering exportListOperation.prototype.endExportAndClose ()");
    if (!exportData) {
        PTC.exportTable.log.debug("No export data passed in - using window.JSCA_EXPORT_DATA");
        exportData = window.JSCA_EXPORT_DATA;
    }
    var exporter = this.getExporter();
    if (exporter) {
        if (exportData.headers) {
            exporter.appendColumnHeadersToForm(exportData.headers.join(this.DELIM));
        }
        if (exportData.exportOids) {
            exporter.appendOidsToForm(exportData.exportOids.join(this.DELIM));
        }
        exporter.appendRowsToForm(exportData);
        exporter.submitForm();
    }
};

exportListOperation.prototype.doExport = function(table){
    PTC.exportTable.log.trace("Entering exportListOperation.prototype.doExport ()");
    if (!table) {
        table = this.getTable();
    }
    var exportData = this.exportDataToFile(table);
    return exportData;
};

/**
 * @class for exporting a paged table
 * At one time an iframe was used to step through the pages, but now is done server side in one request
 * @internal
 * @deprecated
 */
IframeExportOperation = function(){
    exportListOperation.call(this);
};
IframeExportOperation.prototype = new exportListOperation();

/**
 * Sets up a method for the server side export to call when its done creating its writer
 */
IframeExportOperation.prototype.getIframeLocation = function() {
    PTC.exportTable.log.trace("Entering IframeExportOperation.prototype.getIframeLocation ()");
    var tableID = this.getTableId();
    var href = opener.PTC.jca.table.Utils.getTableUrl(tableID);
    href = URL_utils.removeAnchor(href);
    var sessionkey = (new Date()).getTime();
    href += "&" + tableID + "lmt=-1&" + tableID + "fi=0&noSession=true&format=" + this.getFileType() + "&exportSessionKey=" + sessionkey + "&refreshTable=" + tableID + "&portlet=poppedup";

    var mainform = getMainForm();
    mainform.appendChild(new JCAnewHiddenInputElement("exportSessionKey", sessionkey, mainform));

    top.finishServerSideExport = function() {
        PTC.exportTable.log.trace("Entering top.finishServerSideExport ()");
        var opener = exportListUtilities.getOpener();
        var table = opener.tableUtils.getTable(tableID);
        var parametersStr = exportListUtilities.getTableColumnServerParameters(table);
        parametersStr += opener.getSerializedMainForm();
        removeParamFromString(parametersStr, 'refreshTable');

        var options = {
            method: 'post',
            onSuccess: function(transport){
                asyncResponseHandler.handleResponse(transport.responseText, {});
            },
            onFailure:   handleExportError,
            onException: handleExportError
        };

        options.parameters = parametersStr;
        requestHandler.doRequest(href, options);
    };

    function handleExportError(transport) {
        Ext.MessageBox.show({
            title: '',
                msg: transport.responseText,
                buttons: Ext.MessageBox.OK,
                icon: Ext.MessageBox.ERROR
        });
        WaitAndClose();
    }
};

 /**
 * This method is called when the action for a particular format type is executed.
 * Calling This method is configured in actions.xml on the before js of the wizard step for the
 * export wizard
 *
 * endExportAndClose (called at the end of the processing fires the formsubmit and that in turn
 *  executes the command configured on the
 *  particular action for the selected file type. Usually ExportListCommands.export
 */
exportListUtilities.jcaExportDataToFile = function() {
    PTC.exportTable.log.trace("Entering exportListUtilities.jcaExportDataToFile ()");
    //Load Iframe
    var exportObj = new exportListOperation();
    var formattype = exportObj.getFileType();
    PTC.exportTable.log.debug("File Type: ",formattype);

    //exportListUtilities.appendFormatTypeIfNeeded(formattype);
    //If data is not local, go to the server
    var table = exportObj.getTable();
    if (exportObj.isTree() || !PTC.jca.table.Utils.isAllDataLoaded(table)) {
        exportObj = new IframeExportOperation();
        exportObj.getIframeLocation();

        PTC.wizard.submitWizard({skipAllValidation: true,
                                 successFunc: PTC.exportTable.exportTableSuccessListener});
        stopProgress = function(){};
        setTimeout(goProgress, 100);
        return false;
    }
    else {
        var exportData = exportListUtilities.getOpener().exportListUtilities.jcaExportData(table);

        exportObj.showProgressIndicator();
        exportObj.endExportAndClose(exportData);
        return true;
    }
};

exportListUtilities.jcaExportData = function(table){
    PTC.exportTable.log.trace("Entering exportListUtilities.jcaExportData ()");
    var exportObj = new exportListOperation();
    return exportObj.doExport(table);
};

exportListUtilities.jcaExport = function(clickedButton) {
    PTC.exportTable.log.trace("Entering exportListUtilities.jcaExport ()");
      if (clickedButton) {
          clickedButton.disable();
      }

    exportListUtilities.resetExportTableFile();
    exportListUtilities.jcaExportDataToFile();
};

PTC.exportTable.isLoading = function(table) {
    try {
        if (table) {
            var store = table.getStore();
            if(Ext.isFunction(store.isLoading) && store.isLoading()) {
                return true;
            }
            // check if cancel loading button is still visible
            var titleBar = table.getTopToolbar();
            if (titleBar) {
                var cancelButton = titleBar.findById(table.cancelBtnId);
				if (cancelButton && cancelButton.isVisible()) {
                    return true;
                }
            }
            var isDataLoaded = table.getStore().DATA_RENDERED;
            return !isDataLoaded;
        }
    } catch (e) {
        PTC.exportTable.log.debug("Error in table.isLoading(" + table.id + ")", e);
    }
    return false;
};


PTC.exportTable.on("ExportFileCreationComplete", function(data) {       
       var actionName = data.actionName;
       if(actionName !== "exportBOMToCEDM"){
        return;
       }
       
       var url = data.url;
       
       var params = {
            "ExportURL"      : url,
            "AuthApp"    : "COCRMOD"   
        };
        
        var reqOptions = {
        
                asynchronous: false,
                onSuccess:function(response){ 
                    //do Nothing
                },

                onFailure: function(statusCode, statusText){
                    //do Nothing                         
                }

            };

        PTC.JSBridge.Request.Run("JSONB_GetWTPartBOMReport", params,reqOptions);
       
});


/**
 * @namespace A set of utility functions related to EXT-JS  Table / Tree columns.
 */
PTC.jca.ColumnUtils = {

    log: log4javascript.getLogger("PTC.jca.ColumnUtils"),

    /**
     * represents a cache of the calculated column widths, stored by grid.
     * <br/>
     * Cache will use a javascript object, so it will not persist across page refreshes.
     * Cache is in the attributeHelper so that the data is available in the popup windows
     *
     */
    columnSizeCache:(function () {

        return {
            /**
             * Get the top-level cache for the column size
             * @return an object representing the cached column widths.
             *         Object structure of cache is: {columnSizeCache: {gridId: {colId: width, someOtherColId: width}, someOtherGridId: {colId: width}}
             */
            getTableColumnCache: function () {
                var all = PTC.attributeHelper.get('columnSizeCache');
                if (!all) {
                    all = {};
                    PTC.attributeHelper.set('columnSizeCache', all);
                }
                return all;
            },

            /**
             * Set a width for a given grid and column in the cache
             * @param {String} gridId
             * @param {String} columnId
             * @param {Integer} size
             */
            set: function (gridId, columnId, size) {
                var all = this.getTableColumnCache(),
                    gridColSizes = all[gridId];
                if (!gridColSizes) {
                    gridColSizes = all[gridId] = {};
                }
                gridColSizes[columnId] = size;
            },

            /**
             * Get the cached width for a given column for a table
             * @param {String} gridId
             * @param {String} columnId
             * @return the cell width if it is in the cache, null otherwise.
             */
            get: function (gridId, columnId) {
                var all = this.getTableColumnCache();
                var gridColSizes = all[gridId];
                var colSize = null;
                if (gridColSizes && gridColSizes[columnId]) {
                    colSize = gridColSizes[columnId];
                }
                return colSize;
            }
        };
    }()),

    /**
     * Applies any cached column width values to the column model
     * @param {String} gridId
     * @param {Array} colModel - an array of column model configs
     */
    applySavedColumnWidthValues: function (gridId, colModel) {
        var cachedWidth, col;
        var colModelConfigArray = colModel.config;
        if (!colModelConfigArray) {
            return colModel;
        }
        for (var i = 0, l = colModelConfigArray.length; i < l; i++) {
            col = colModelConfigArray[i];
            cachedWidth = this.columnSizeCache.get(gridId, col.id);
            if (cachedWidth !== null) {
                col.width = cachedWidth;
            }
            else if (l === 1) {
                // for single column tables, the col is not resizable, but the default width should be a bit higher?
                col.width = 200;
            }
        }
        return colModel;
    },
    /**
     * Determines if a given column is a visible "data column", ie a column which is not hidden, and is not the
     * stretcher column, which is for display only, and contains no data. 
     * @param {Ext.grid.Column} column
     * @return {boolean} true if this is a visible data column
     */
    isVisibleDataColumn: function(column){
            return column.id != PTC.jca.table._STRETCHER_ID && !column.hidden;
    },
    /**
     * This method will return the Index of last Visible column for given ColumnModel, excluding the stretcher column.
     * @param {object} ColumnModel
     */
    getLastVisibleColumnIndex: function (columnModel) {
        var count = columnModel.getColumnCount();
        for (var index = count - 1; index > -1; index--) {
            if (PTC.jca.ColumnUtils.isVisibleDataColumn(columnModel.config[index])) {
                break;
            }
        }
        return index;
    },

    /**
     * This method will check whether the column is a 'checker' column or not
     * @param {object} ColumnModel
     * @param {int} colIndex
     */
    isCheckerColumn : function(colModel, colIndex){
        return (colModel && colModel.getColumnId(colIndex) === "checker");
    },

    /**
     * When a table is prepared, this is the first attempt to resizeAllColumns.
     * If all the data is availble (DATA_RENDERED flag is true) , then go for resizeAllColumns, else try again after a delay.
     */
    initialResizeAllColumns: function () {
        var rowStore = this;
        if(rowStore.DATA_RENDERED !== true){
            // observed with large data tables(SPR 4909413)
            PTC.jca.ColumnUtils.initialResizeAllColumns.defer(100, this);
        } else {
            var grid = PTC.jca.table.Utils.getTable(rowStore.jscaTableID);
            PTC.jca.ColumnUtils.resizeAllColumns(grid, null, null, true);
        }
    },
    /**
     * Resize all the columns.
     * Only following columns would be resized:
     * 1) Columns which are not hidden
     * 2) Columns which are resizable.
     *
     * After resizing columns, if there is any blank space available,
     * add the blank space to the last column.
     * @param {object} grid
     * @param {int} width
     * @param {int} height
     * @param {boolean} resizeLastColumn
     */
    resizeAllColumns: function (grid, width, height, resizeLastColumn) {
        PTC.performance.startComponentActionTimer('Column Resized', grid.id);
        var colModel = grid.getColumnModel();
        //if colModel doesn't exist, it may be a timing issue due to a redirect,
        //in which case we don't want to go through the trouble of resizing
        var stickyConfig = grid.getStickyConfig();
        if (colModel) {
            var colCount = colModel.getColumnCount();
            var c;

            //is the grid ready for column width calculation - SPR 4909413
            var readyForWidthCalculation = this.initialReadyForWidthCalculation(grid);

            var skip = false;
            if(readyForWidthCalculation === 1 /*notReady*/) {
                if(grid.readyForWidthCalculation === undefined){
                    if(grid.store.load_complete === true){
                        PTC.jca.ColumnUtils.resizeAllColumns.defer(50, PTC.jca.ColumnUtils,[grid, null, null, true]);
                    } else {
                        //attach the listener - to resize the columns based on cell data
                        grid.store.on('dataSourceComplete', PTC.jca.ColumnUtils.initialResizeAllColumns);
                    }
                } else if( grid.readyForWidthCalculation === 1){
                    skip = true;
                  //If data is still loading defer call again with delay as cell data is not ready
                    if(grid.store.isLoading() === true){
                        PTC.jca.ColumnUtils.resizeAllColumns.defer(50, PTC.jca.ColumnUtils,[grid, null, null, true]);
                    }
                }
            } else if(readyForWidthCalculation === 2 /*Ready*/){
                if(grid.readyForWidthCalculation === 1){
                    //don't respect stickyConfig, need to force recalculate the width
                    stickyConfig = undefined;
                }
            }

            var columnResized = false;
            if(!skip){
                for (c = 0; c < colCount; c++) {
                if (PTC.jca.ColumnUtils.isVisibleDataColumn(colModel.config[c])){
                    if(colModel.isResizable(c)) {
                        if (this.resizeColumn(grid, c, false, stickyConfig) && !columnResized) {
                            columnResized = true;
                         }
                    //if the column is not resizable and width < MIN_COL_WIDTH
                    //set it to MIN_COL_WIDTH, so that there is enough space to show sorting level status(if any)
                    } else if (!PTC.jca.ColumnUtils.isCheckerColumn(colModel, c) && colModel.getColumnWidth(c) < PTC.jca.ColumnUtils.MIN_COL_WIDTH) {
                        colModel.setColumnWidth(c, PTC.jca.ColumnUtils.MIN_COL_WIDTH);
                        PTC.jca.ColumnUtils.log.debug("resizeColumn-setWidth:", c, ' newWidth: ', PTC.jca.ColumnUtils.MIN_COL_WIDTH);
                    }
                }
            }
            if (!resizeLastColumn) {
                this.resizeLastColumn(grid, null, height);
                 }
            }
            grid.readyForWidthCalculation = readyForWidthCalculation;
        }
        if (columnResized === true) {
            grid.fireEvent('columnConfigChange', grid); // update the state to client state manager
        }
        PTC.performance.stopComponentTimer(grid.id, null, 'tableResized');
    },

    /**
     * Checks whether the grid is ready for column width calculation - SPR 4909413
     * This function checks if there is any value in sticky config if not it will call isCellDefined to check if cell data is ready or not (SPR 4909413)
     * @param {object} grid
     * @returns {int}
     *     1 : not ready
     *     2 : ready
     */
    initialReadyForWidthCalculation: function(grid) {
        var widthCalculation = grid.readyForWidthCalculation;
        if(widthCalculation === undefined || widthCalculation === 1){
            var colModel = grid.getColumnModel();
            var colCount = colModel.getColumnCount();
            var noColumnVisibleOrResizable = true;
            for (var c = 0; c < colCount; c++) {
                if (PTC.jca.ColumnUtils.isVisibleDataColumn(colModel.config[c]) && colModel.isResizable(c) ){
                    noColumnVisibleOrResizable = false;
                    if(widthCalculation === undefined){
                        //this is the first time, we are coming for this check, look whether there is anything in stickyConfig
                        var stickyConfig = grid.getStickyConfig();
                        var cachedWidth = undefined;
                        if(stickyConfig){
                            cachedWidth = stickyConfig[c].width;
                        }
                        if(cachedWidth !== undefined){
                            widthCalculation = 2; //stickyconfig is there and is ready
                            break; //don't want to loop for all the columns
                        } else {
                            widthCalculation = 1;
                        }
                    }
                    if(widthCalculation === 1){
                        if(this.isCellDefined(grid, c)){
                            widthCalculation = 2; //cell data is there and is ready
                        }
                        break; //don't want to loop for all the columns
                    }
                }
            }
            if(noColumnVisibleOrResizable){
                //no column is either visible or resizable - ready
                widthCalculation = 2;
            }
        }
        return widthCalculation;
    },

    /**
     * This function checks if the cell is defined for the column in the row or not (SPR 4909413)
     * @param {object} grid
     * @param {int} colIndex
     * @returns {boolean}
     */
    isCellDefined: function (grid, colIndex){
        var view = grid.getView();
        var cellDefined = false;
        var  firstRowInViewPortIndex = -1;
        if (typeof view.getVisibleRowCount === 'function') {
            var visibleRows = view.getVisibleRows();
            firstRowInViewPortIndex = visibleRows.first;
        }
        if (view.mainBody && view.getRow(firstRowInViewPortIndex)) {
            var cell = view.getCell(firstRowInViewPortIndex, colIndex);
            if(typeof cell !== 'undefined') {
                cellDefined =true;
            }
        }
        return cellDefined;
    },

    /**
     * The last column is now always the blank stretcher column, so we don't need to remember its width or do anything special with it. 
     */
    resizeLastColumn: function (grid, width, height) {
        var colModel = grid.getColumnModel();
        var lastColIndx = colModel.getIndexById(PTC.jca.table._STRETCHER_ID);
        var lastColWidth = 1; // By default the blank last column will be only 1 px wide (effectively hidden)
        var cachedVal = null;

        // We subtract the current width of the stretcher column, and work with the data columns only to determine width.
        var totalColWidth = colModel.getTotalWidth(false) - colModel.getColumnWidth(lastColIndx) + lastColWidth;
        if (!width) {
            width = grid.getInnerWidth();
            // check if overflow is present on the info page
            var tabP = PTC.infoPage.getTabPanel();
            var activeTab = tabP ? tabP.activeTab : tabP;
            var tc = activeTab && typeof activeTab.getTableContainer === 'function'? activeTab.getTableContainer() : activeTab;
            // if overflow is not present then make sure to account for it in the width subtraction below in case it appears later
            if (tc && tc.body && tc.body.dom && !(tc.body.dom.scrollHeight > tc.body.dom.clientHeight)) {
                width -= 15;
            }
        }
        if (totalColWidth < width) {
            var extraSpace = parseInt(width - totalColWidth, 10);
            if (extraSpace > 0) {
                // Using the calculated value, not the actual column value. This is mostly likely just 1 + extraSpace.
                var newWidth = lastColWidth + extraSpace;
                var totalRowHeight;
                var wTable = Ext.getCmp(PTC.jca.table.getWTablePanelID(grid.id));
                var defaultTableHeight = PTC.jca.table.scroll.getDefaultTableHeight(wTable);
                if (grid.view.cumulativeRowHeight) {
                    totalRowHeight = grid.view.cumulativeRowHeight + defaultTableHeight;
                } else {
                    var rHeight = typeof grid.view.getCalculatedRowHeight === 'function' ? grid.view.getCalculatedRowHeight() : grid.view.rowHeight;
                    var noRows = grid.store.getCount();
                    totalRowHeight = (rHeight * noRows) + defaultTableHeight;
                }
                if (!height) {
                    height = grid.getHeight();
                }

                if (!grid.jcaCollapsed && totalRowHeight > height) {
                    newWidth = newWidth - Ext.getScrollBarWidth();
                }

                // TODO: Try to remove the hardcoded value.
                PTC.jca.ColumnUtils.log.debug("resizeLastColumn-setwidth:", grid.id, ' ', lastColIndx,' ',  lastColWidth, ' ', colModel.getColumnWidth(lastColIndx), ' ', newWidth);

                colModel.setColumnWidth(lastColIndx, newWidth - 4);
            }
        } else if (grid.view.isLocked) {
            // With tables being width:auto for locking it seems that the absolute positioning and other
            // css rules prevent the auto resize so we needed to add this for the column locking case.
            // To reproduce the issue - turn column locking on and keep making the browser bigger
            // eventually the grid will not continue to resize to the window.
            grid.view.updateLockedWidth();
        } else {
           // If the data columns go over the right edge of the table, just let the stretcher column be very narrow.
           colModel.setColumnWidth(lastColIndx, lastColWidth);
        }
    },
    /**
     * Resize the column.
     *
     * The column width should not be less than the column header width.
     * @param {object} tableGridPanel
     * @param {integer} columnIndex
     * @param {boolean} canReduce - if we need to resize the column.  this will be true if the column header is double-clicked.
     * @param {boolean} stickyConfig - the config containing width for each column if already present in state manager
     * @return true if the column was resized, false if a cached size was used.
     */
    resizeColumn: function (grid, index, canReduce, stickyConfig) {

        var view = grid.getView();
        var colModel = grid.getColumnModel();

        var colId = colModel.getColumnId(index);
        var cachedVal = null;
        if (stickyConfig && stickyConfig[index]) {
            cachedVal = stickyConfig[index].width;
        }
        var column = grid.getColumnModel().getColumnAt(index);
        if ((!canReduce && PTC.isDefined(cachedVal)) || (column.columnResizeProperty && column.columnResizeProperty.indexOf(PTC.jca.ColumnUtils.DO_NOT_CALCULATE) > -1)) {
            return false;
        }
        var origWidth = colModel.getColumnWidth(index);
        var newWidth = this.getCalculatedColumnWidth(grid, canReduce, index);
        if (canReduce || (newWidth > origWidth && (Math.abs(newWidth - origWidth) > 10)) || column.modifiable || column.useExact) {
            PTC.jca.ColumnUtils.log.debug("resizeColumn-setWidth:", index, ' ', origWidth,' ',  newWidth);
            colModel.setColumnWidth(index, newWidth);
            return true;
        }

        return false;
    },
    getCalculatedColumnWidth: function (grid, canReduce, index) {
        var l1 = new Date().getTime();
        try {
            var view = grid.getView();
            var colModel = grid.getColumnModel();

            var newWidth = 0, first = 0, last = 0;
            if (typeof view.getVisibleRowCount === 'function') {
                var visibleRows = view.getVisibleRows();
                first = visibleRows.first;
                last = visibleRows.last;
            } else {
                last = grid.getStore().getCount();
                last = (last > 15) ? 15 : last;
            }
            newWidth = this.getColumnHeaderWidth(grid, index);
            // To find our maximum width, iterate through visible cells of the column only.
            var cell;
            var column = grid.getColumnModel().getColumnAt(index);
            if (column.columnResizeProperty && column.columnResizeProperty.indexOf(PTC.jca.ColumnUtils.USE_EXACT) > -1) {
                column.useExact = true;
            }
            var isTree = grid.tree && column.id === grid.master_column_id;
            var longestString = ""; // Keep track of the longest string to find exact width
            var dom; // Keep track of the dom object that contained the longest string for TextMtrics usage.
            var cellPadding = 0;
            for (var r = first; r <= last; r++) {
                if (view.mainBody && view.getRow(r)) {
                    cell = view.getCell(r, index);
                }
                var cellWidth = 0;
                if (typeof cell === 'undefined') {
                    break;
                }
                if (isTree) {
                    if(cell.firstChild){
                        // nextSibling does not exist on a tree on the info page (eg. "My Notebook")
                        cell = (cell.firstChild.lastChild) ? cell.firstChild.lastChild : cell.firstChild;
                    }
                } else {
                    cell = cell.firstChild;
                }
                if (typeof cell === 'undefined' || cell === null) {
                    break;
                }
                if (canReduce || !cell.jcaScrollWidth) {
                    if (!column.useExact && this.hasEditableChild(cell)) {
                        column.useExact = true;
                    }
                    var cellString;
                    if (!canReduce) { //only need to get text width if not using the slow dom stategy
                        if (column.modifiable === true || column.useExact) {
                            column.useExact = true;
                        } else {
                            cellString = this.getCellString(cell);  // text of the cell node
                            if (cellString && cellString.length > longestString.length) {
                                longestString = cellString;
                                dom = cell;
                            }
                        }
                    }
                    if (typeof column.getCellWidth === 'function') {
                        cellWidth = column.getCellWidth(cell, grid, column);
                    } else {
                        cellWidth = this.getCellWidth(cell, cellString, grid, column.useExact || canReduce);
                    }
                }
                if (!cellPadding) {
                    cellPadding = this.getCellPadding(cell); // only get this once
                }
                cellWidth += cellPadding; // left and right padding are both 1
                if (isTree) {
                    // Now add in the icon widths, to the text of the tree node
                    var rec = grid.getStore().getAt(r);
                    if (rec) {
                        var level = rec.get('_level');
                        if (Ext.isNumber(level)) {
                            cellWidth += (16 * level) + 5; //assuming 16px for the tree icons
                        }
                    }
                }
                newWidth = Math.max(newWidth, cellWidth, cell.jcaScrollWidth ? cell.jcaScrollWidth : 0);
            }
            // Now calculate exact width for the longest string, using TextMetrics
            if (dom) {
                if (longestString && !column.useExact) {
                    PTC.jca.ColumnUtils.log.debug(" longestString for calculation " + longestString);
                    var longestStringWidth = this._calculateTotalWidth(dom, longestString) + cellPadding + 2;
                    PTC.jca.ColumnUtils.log.debug("  longestStringWidth " + longestStringWidth + " newWidth " + newWidth);
                    newWidth = Math.max(newWidth, longestStringWidth);
                }
            }
            return newWidth;
        } finally {
            var l2 = new Date().getTime();
            PTC.jca.ColumnUtils.log.debug("getCalculatedColumnWidth took: ", (l2 - l1), grid.id, index);
        }
    },

     /**
      * If the argument text is not encoded for html content, encode it and return - unhandled text
      * gets executed in Ext.util.TextMetrics.getWidth() - SPR 5699129
      *
      * @private
      * @param {String} lString The text to handle
      * @return html safe text
      */
    _handleStrForWidthCal: function (lString) {

        //Encoding if longestString is not encoded.
        if(typeof lString === 'string' && lString.indexOf("<") > -1) {
            return PTC.util.HTMLEncoder.encodeForHTMLContent(lString);
        }
        return lString;
    },

    /**
     * Calculate the String width and the images width in the given DOM
     * 
     * @private
     * @param {DOM} Dom Element of Cell
     * @param {String} longestString width to be calculated
     * @return {int} calculated width for longestString and the images if present in the given DOM
     */
    _calculateTotalWidth: function(dom, longestString) {
        var tm = Ext.util.TextMetrics.createInstance(dom);
        var calculatedWidth = 0;
        if(typeof longestString === 'string' && longestString.toLowerCase().indexOf("img") > -1) {
            longestString = longestString.replace(/<img[^>]*>/gi, " ");
            calculatedWidth = this._calculateImgWidth(dom);
        }
        return calculatedWidth + tm.getWidth(this._handleStrForWidthCal(longestString));
    },

    /**
     * Return the sum of image widths that are in the dom and zero if none found
     *
     * @private
     * @param {dom} dom that might contain img tags.
     * @return {int} width of all image tag
     */
    _calculateImgWidth: function(dom) {
        // Handle Img Tag
        var imgs = dom.getElementsByTagName('img'), len = imgs.length, i, totalImgWidth = 0;

        if(len > 0) {
            var imageDom = document.createElement("IMG");
            imageDom.style.visibility = "hidden";
            document.body.appendChild(imageDom);
            for (i = 0; i < len; i++) {
                imageDom.src= imgs[i].src;
                var imgSrc = imageDom.src;
                var imgWidth = imageDom.width;
                totalImgWidth = totalImgWidth + (isNaN(imgWidth)?0: imgWidth);
                PTC.jca.ColumnUtils.log.debug("_calculateImgWidth:: src "+ imageDom.src  + " width " + imgWidth + " Total Width " + totalImgWidth);
            }
            imageDom = imageDom.parentNode.removeChild(imageDom);
            imageDom = null;
        }

        return totalImgWidth;
    },

    /**
     * Gets the text from a Dom node (just plain text, single <a>) - handle till childNodes.length === 1
     * @private
     * @param {DOMElement} cell
     * @param {Boolean} getText true to return text value if there is no innerHTML
     * @return inner text of common table cells
     */
    _getCellString: function (cell, getText) {
        if (cell.innerHTML && cell.innerHTML.indexOf("<") < 0) {
            return cell.innerHTML;
        }
        else if (cell.childNodes && cell.childNodes.length == 1 && cell.firstChild.tagName === 'A') {
            // single anchor tag with label like the name/number columns
            return cell.firstChild.innerHTML;
        }
        if(getText === true){
            return cell.innerText ? cell.innerText : cell.textContent;
        }
        return undefined;
    },
    /**
     * Gets the text from a Dom node.  Does not handle complicated html structure, just plain text, single <a> (handle one level deep child nodes)
     * @param {DOMElement} cell
     * @return inner text of common table cells
     */
    getCellString: function (cell) {
        //TO DO: May think of cleaning of the code later
        if (!cell) {
            return cell;
        }
        if (Ext.isString(cell)) {
            return cell;
        }
        var _cellString = this._getCellString(cell);
        if(_cellString){
            return _cellString;
        } else if(cell.childNodes && cell.childNodes.length > 1){
            var cString="";
            var childNodes = cell.childNodes;
            var alength = childNodes.length;
            for (var i = 0; i < alength; i++) {
                var _cString=this._getCellString(childNodes[i], true);
                if (_cString && !_cString.blank()){
                    cString = cString + _cString;
                }
            }
            return cString;
        }
        var text = cell.innerText ? cell.innerText : cell.textContent;
        if (text && !text.blank())//Making it last to check as we don't want to break the existing working scenarios. We will need to clean up this code later.
        {
            return text;
        }
        return null;
    },
    /**
     * Gets exact width of a DOM Node using SLOW dom apis
     * Uses position: absolute to force element to shrink to fit content
     * 
     * @param {DOMElement} cell
     * @return {Number} width
     */
    getExactCellWidth: function (cell) {
        var cellWidth = 0;
        if (cell && cell.style) {
            var orig_position = cell.style.position;
            cell.style.position = "absolute";
            cell.jcaScrollWidth = cell.scrollWidth + 5;
            cell.style.position = orig_position;
            cellWidth = cell.jcaScrollWidth;
        }
        return cellWidth;
    },
    /**
     * Determines if there are editable fields in the tree of nodes rooted at "cell" that are not hidden type.
     * @param {DOMElement} cell
     * @return {boolean} if this cell or its children contains editable fields (which all have the attribute "type") 
     */
    hasEditableChild: function (cell) {
        var returnVal = false;
        if (cell.type && cell.type != "hidden") {
            // we assume that any dom element with a "type" attribute is an input field
            returnVal = true;
        } else if (cell.hasChildNodes()) {
            for (var i=0; i<cell.childNodes.length; i++) {
                if (this.hasEditableChild(cell.childNodes[i])) {
                    returnVal = true;
                    break;
                }
            }
        }
        return returnVal;
    },
    /**
     * Get the estimated width of the dom object.   Will get the dispalyed text and estimate the width from it.
     * If the object has complex children, the scrollWidth will be used.
     * @param {DomElement} cell
     * @param {String} cellString - string text displayed in the cell (null if html tag)
     * @param {Ext.grid.GridPanel} grid
     * @param {Boolean} useExact true to force a slower but more exact width calculation
     */
    getCellWidth: function (cell, cellString, grid, useExact) {
        var cellWidth = 0;
        if (useExact && cell) {
            // get the precise width
            cellWidth = this.getExactCellWidth(cell);
        } else {
            if (cellString) {
                // first, get a crude estimate based on the cell's innerText
                cellWidth = PTC.jca.ColumnUtils.getStringWidth(cellString, grid, cell);
            }
            if (cell && cell.childNodes && cell.childNodes.length === 1) {
                // try to improve the estimate with known special cases for one-child cells
                var ch = cell.firstChild;
                if (ch.firstChild && ch.firstChild.tagName === 'IMG') {
                    cellWidth = Ext.fly(ch).getWidth() + 5;
                } else if (ch.tagName === 'A') {
                    // single anchor tag with label like the name/number columns
                    cellWidth = PTC.jca.ColumnUtils.getStringWidth(ch.innerHTML, grid, cell) + 10;
                }
            }
        }
        return cellWidth;
    },

    /**
     * This function returns the column header width.
     * @param {object} tableGridPanel
     * @param {integer} columnIndex
     */
    getColumnHeaderWidth: function (grid, index) {
        var headerWidth = 0;
        var view = grid.getView();
        var headerCell = view.getHeaderCell(index);
        if (headerCell && headerCell.firstChild) {
            //For IE if a columnHeader is blank its it as a blan string without spaces. I am setting it as empty string with single space for every browser
            //keeping in mind that in furture there could be some possibility where in mozzila also we get the empty string without space.
            if (headerCell.innerText === '') {
                headerCell.innerText = ' ';
            }
            if (headerCell.textContent === '') {
                headerCell.textContent = ' ';
            }
            // Get just the size of the text of the column header, don't inlude any empty images beyond
            var ele = headerCell.innerText || headerCell.textContent;
            return this.getCellWidth(null, this.getCellString(ele), grid) + 5;
        }
        return 0;
    },
    /**
     * Gets an array of column ids of non-hidden data columns, excluding the stretcher column
     * @param {Ext.grid.ColumnModel} columnModel
     * @return {array} visible columns
     */
    getVisibleColumns: function (columnModel) {
        var visibleColumns = columnModel.getColumnsBy(PTC.jca.ColumnUtils.isVisibleDataColumn);
        return visibleColumns;
    },
    /**
     * Gets an array of column ids of non-hidden data columns, excluding the stretcher column
     * @param {Ext.grid.ColumnModel} columnModel
     * @return {array} visible column's id
     */
    getVisibleColumnIds: function (columnModel) {
        var count = columnModel.getColumnCount(),
            visibleColumnIds = [], colConfigs = columnModel.config;
        for (var index = 0; index < count; index++) {
            if (PTC.jca.ColumnUtils.isVisibleDataColumn(colConfigs[index])) {
                visibleColumnIds.push(colConfigs[index].id);
            }
        }
        return visibleColumnIds;
    }
};

/**
 * Find the average width of text in a grid
 * @param {String} text
 * @param {Ext.grid.GridPanel} grid
 */
PTC.jca.ColumnUtils.getStringWidth = function(text, grid, dom){
    if (text) {
        var maxCellWidth = (PTC.jca.ColumnUtils.getAverageCharacterPixelWidth(text, grid, dom)*150)+10;
        var cellWidth =(text.length * PTC.jca.ColumnUtils.getAverageCharacterPixelWidth(text, grid, dom))+10;
        return maxCellWidth<cellWidth? maxCellWidth:cellWidth;
    }
    return 0;
};

/**
 * Find the constant for the average pixel per character width.
 * The Ext text metrics can be used to get exact size, but this method is
 * created so to be much faster when estimates sizes of many table cells.
 * The TABLE_TEXT value is engineered to contain an average character frequency
 * and sufficient length so that the average is as accurate as possible.
 *
 * Note the answer is memoized.
 */
PTC.jca.ColumnUtils.getAverageCharacterPixelWidth = function (text, grid, dom) {
    if (!dom) {
        dom = grid.getEl().dom;
    }
    var tm = Ext.util.TextMetrics.createInstance(dom);
    var TABLE_TEXT = bundleHandler.get('com.ptc.core.ui.tableRB.TABLE_TEXT');
    var avgSize = tm.getWidth(TABLE_TEXT) / TABLE_TEXT.length;
    PTC.jca.ColumnUtils.getAverageCharacterPixelWidth = function () {
        return avgSize;
    };
    return avgSize;
};

/**
 * Find the padding of a cell, then memo-ize the answer
 * @param {DomElement} cell
 */
PTC.jca.ColumnUtils.getCellPadding = function (cell) {
    var newWidth = 0;
    var leftPadding = 0;
    var rightPadding = 0;
    if (cell.currentStyle) {
        leftPadding = parseInt(cell.currentStyle.paddingLeft, 10);
        rightPadding = parseInt(cell.currentStyle.paddingRight, 10);
    }
    else {
        var currentStyle = document.defaultView.getComputedStyle(cell, null);
        leftPadding = parseInt(currentStyle.getPropertyValue("padding-left"), 10);
        rightPadding = parseInt(currentStyle.getPropertyValue("padding-right"), 10);
    }
    if (!isNaN(leftPadding)) {
        newWidth += leftPadding;
    }
    if (!isNaN(rightPadding)) {
        newWidth += rightPadding;
    }
    PTC.jca.ColumnUtils.getCellPadding = function () {
        return newWidth;
    };
    return newWidth;
};

PTC.jca.ColumnUtils.USE_EXACT = "USE_EXACT";
PTC.jca.ColumnUtils.AUTO_SIZE = "AUTO_SIZE";
PTC.jca.ColumnUtils.DO_NOT_CALCULATE = "DO_NOT_CALCULATE";
