PTC.jca.ColumnUtils.MIN_COL_WIDTH = 32;


PTC.jca.SORT_DELIMITER = "$";
PTC.jca.VERSION_COLUMN_NAME = ['version','iteration','revision'];
PTC.jca.BACKING_VERSION_COLUMN_NAME = 'backingVersionOid';


