/**
 *
 */
PTC.jca.table.destroyContainedTables = function () {
    var containerDom = PTC.util.getDom(this);
    if (containerDom) {
        PTC.jca.table.Utils.cleanUp(containerDom);
    }
};

/**
 * Resize all child tables, resize event listener
 */
PTC.jca.table.resizeContainedTables = function (comp, adjWidth, adjHeight, rawWidth, rawHeight) {
    var root = PTC.util.getDom(this);
    var tables = tableUtils.getExtTables(root);
    PTC.jca.table.resizeTables(adjWidth, tables);

    //Resize the tables inside iframes
    PTC.jca.table.resizeTablesFromIframes(adjWidth);
};

/**
 *  Resize child tables
 *  @param adjWidth
 *  @param tables Array of tables to be resized
 *  @param frame frame document if iframe exists
 */
PTC.jca.table.resizeTables = function (adjWidth, tables, frame) {
    //Leave 30px margin between grid and panel, keeps grid from being underneath possible scrollbars
    var scrollbarWidth = 0;
    var adjustGridWidth = 0;
    for (var i = 0, l = tables.length; i < l; i++) {
        if (!scrollbarWidth) {
            scrollbarWidth = PTC.jca.table.scroll.getWindowScrollbarWidth(PTC.jca.table.scroll.getContentArea(tables[i].getEl()));
            adjustGridWidth = adjWidth - scrollbarWidth;
        }
        if(frame) {
            frame.PTC.jca.table.scroll.getContentArea(tables[i].getEl());
            frame.PTC.jca.table.scroll.updateTableSize(tables[i].id, false, adjustGridWidth);
        } else {
             PTC.jca.table.scroll.getContentArea(tables[i].getEl());
             PTC.jca.table.scroll.updateTableSize(tables[i].id, false, adjustGridWidth);
        }
    }
};

/**
 * Resize child tables inside iframes
 */
PTC.jca.table.resizeTablesFromIframes = function (adjWidth) {
    var frames = PTC.util.getAllPTCIframes();
    for (var i = 0, l = frames.length; i < l; i++) {
        var tables = frames[i].PTC.jca.table.Utils.getExtTables();
        PTC.jca.table.resizeTables(adjWidth, tables, frames[i]);
    }
};

/**
 * Determines whether a given recordId is selected.
 */
PTC.jca.table.selectedOnlyOn = function (recordBody, recordId) {
    return recordBody.store.jsca_table.selModel.isIdSelected(recordId);
};

/**
 * A panel that contains WTablePanels and will adjust the width of those WTablePanels on resize.
 */
PTC.jca.table.TableContainer = function (config) {
    PTC.jca.table.TableContainer.superclass.constructor.call(this, config);
    this.on('bodyresize', PTC.jca.table.resizeContainedTables);
    this.on('destroy', PTC.jca.table.destroyContainedTables);
    this.tablePanelContainer = true;
};
Ext.extend(PTC.jca.table.TableContainer, Ext.Panel, {});

PTC.jca.table._initializeColumnHeaderLabels = function (columns) {
    for (var i = 0, li = columns.length; i < li; i++) {
        columns[i].displayName = columns[i].header;
        if (!columns[i].displayHeaderLabel) {
            columns[i].header = "<span class=\"hiddenHeader\">" + columns[i].header + "</span>";
        }

        // initializing groupRenderer for each column
        // version fields are sorted on the server and not client so grouping needs to be done differently.
        if (PTC.jca.isVersionField(columns[i].id)) {
            columns[i].groupRenderer = PTC.jca.versionGroupingRenderer;
        } else if (columns[i].groupRenderer === undefined) {
            columns[i].groupRenderer = PTC.jca.groupingRenderer;
        }
    }
};

/**
 *
 * @param {Array} namesArray - the array of current view names
 * @return a unique view name for the ad hoc view (e.g. "User View 1", "User View 2")
 */
PTC.jca.table._getUniqueViewName = function (namesArray) {
    return bundleHandler.getUniqueName("com.ptc.core.ui.tableRB.DEFAULT_TABLE_VIEW_NAME", namesArray);
};

/** renderer that will call a jsca renderer */
PTC.jca.jscaCellRenderer = function (val, metadata, record, rowIndex, colIndex, store) {
    if (val === undefined) {
        return '';
    }

    var jsca_value = val;
    var jsca_table = store.jsca_table;
    if (jsca_table === undefined) {
        //for performance, avoid calling getTable for every cell
        var grid = tableUtils.getTable(store.jscaTableID);
        jsca_table = grid;
        store.jsca_table = grid;
    }

    var colConfig = this;
    var jsca_col = PTC.jca._getJscaCol(colConfig);

    var jsca_row = record;
    jsca_row.item = record.data;

    var jsca_renderer = colConfig.jscaRenderer;
    if (typeof jsca_renderer === 'string') {
        colConfig.jscaRenderer = PTC.util.convertStringToFunc(colConfig.jscaRenderer);
        jsca_renderer = colConfig.jscaRenderer;
    }
    if (typeof jsca_renderer === 'function') {
        jsca_value = jsca_renderer(jsca_table, jsca_col, jsca_row);
        jsca_value = PTC.debug.addDebugInfo(jsca_value, jsca_col, jsca_row);
    }


    if ((colConfig.resizable !== false || colConfig.initialResizable !== false) && jsca_value !== '' && (typeof jsca_value.indexOf === 'function')) {
        //Set variableRowHeight=true if content of cell is either multiline or image.
        if (jsca_table.view.variableRowHeight !== true && (jsca_value.indexOf('<br>') !== -1)) {
            if (Ext.isFunction(jsca_table.view.setVariableRowHeight)) {
                jsca_table.view.setVariableRowHeight(true);
            }
        }
        //Don't add the qtip if it is alrady there and if the column is editable. But add the tooltip if column as plain text in it like life cycle template
        if ((colConfig.modifiable !== true || jsca_value.indexOf('<') < 0) && jsca_value.indexOf("qtip") < 0) {
            // non-resizable columns are the status glyph columns with no visible text, skip the unescape code
            jsca_table._buildQTipForValue(jsca_value, metadata, false, true);
        }
    }

    return jsca_value;
};

PTC.jca._getJscaCol = function (colConfig) {
    var jsca_col = colConfig.jsca_col;
    if (jsca_col === undefined) {
        jsca_col = Object.clone(colConfig);
        jsca_col.renderer = undefined;  // can't pass in renderer, that would be infinite loop
        colConfig.jsca_col = jsca_col;
    }
    return jsca_col;
};

/**
 * Search function for jscaCellRenderer.  Creates a new column without a renderer set to avoid
 * an infinite loop and calls the column.jscaRenderer if it exists.
 */
PTC.jca.jscaCellRenderer.searchFunc = function (table, column, row) {
    var jsca_col = PTC.jca._getJscaCol(column);
    row.item = row.data;
    // Just like the renderer, call the column's jscaRenderer if it exists.
    if (column.jscaRenderer && typeof column.jscaRenderer.searchFunc === 'function') {
        return column.jscaRenderer.searchFunc(table, jsca_col, row);
    } else {
        return null;
    }
};

/**
 * Group function for jscaCellRenderer.  Creates a new column without a renderer set to avoid
 * an infinite loop and calls the column.jscaRenderer if it exists.
 */
PTC.jca.jscaCellRenderer.groupFunc = function(table, column, row) {
    var jsca_col = PTC.jca._getJscaCol(column);
    row.item = row.data;
    // Just like the renderer, call the column's jscaRenderer if it exists.
    if(column.jscaRenderer && typeof column.jscaRenderer.groupFunc === 'function') {
        return column.jscaRenderer.groupFunc(table, jsca_col, row);
    } else {
        return null;
    }
};

/**
 * Build an ext qtip from the value
 * @changecomment [x-22] Moved to the GridPanel prototype class to allow overriding on specific grid instances
 * @param {Object} val the data value for the cell
 * @param {Object} metadata an object for which properties can be set on the cell itself
 * @param {boolean} [noEncoding] Send true to skip encoding, otherwise encode by default
 * @param {boolean} [escape] Send true to escape values for e.g. when you want to retrieve text between opening and closing of anchor tag,otherwise no escape by default
 */
Ext.grid.GridPanel.prototype._buildQTipForValue = function (val, metadata, noEncoding, escape) {
    var value;
    if (!escape) {
        value = val;
    } else {
        value = getUnescapedText(val);
    }
    if (value) {
        value = value.trim();
        if (value !== '' && value !== '&nbsp;') {
            if (!noEncoding) { //encodes qtip by default
                // encoding the tooltip because qtips are decoded by Ext
                value =  Ext.util.Format.htmlEncode(value);
            }
            //add qtip as an attribute on the given dom element
            if (metadata.dom) { //for special cases (eg. grid checkbox)
                metadata.dom.setAttribute('ext:qtip', value);
            }
            else {
                metadata.attr = 'ext:qtip="' + value + '"';
            }
        }
    }
};
/**
 * re-render visible rows if variableRowHeight is set to true at clientside. This is needed to render rows with proper height to show com
 * contents in the row.
 */
PTC.jca.reRenderRowsIfVariableRowHeight = function () {
    if (!this.jcaTableConfig.variableRowHeight && this.getView().variableRowHeight) {
        this.getView().doPartialDataChange();// re-render visible rows once again if variableRowHeight is set to true from JS not from serverside.
    }
};

/**
 * Renders the EXT table with given table configuration.
 * @param {Object} jcaTableConfig - json config for table
 */
PTC.jca.renderTable = function (jcaTableConfig) { // param jscaTable is old style data, will be deleted
    if (typeof jcaTableConfig === 'undefined') {
        return;
    }
    //decode url params that came from server
    if(jcaTableConfig.storeURL.pve === true){
        jcaTableConfig.storeURL.params = PTC.util.decode.paramsForJS(jcaTableConfig.storeURL.params);
        jcaTableConfig.storeURL.pve=undefined;
    }
    PTC.onReady(function () {

        var componentTimerBean = PTC.performance.startComponentTimer(jcaTableConfig.tableID);
        var tableId = tableUtils.getFormattedTableId(jcaTableConfig.tableID);
        var g = new PTC.jca.WTablePanel(jcaTableConfig);

        PTC.jca.renderTable.log = log4javascript.getLogger('PTC.jca.renderTable');
        g.gridPanel.on('renderTableStart', timeLogStart, 'renderTable');
        g.gridPanel.on('renderTableEnd', timeLogEnd, 'renderTable');
        g.gridPanel.on('renderTableEnd', PTC.jca.reRenderRowsIfVariableRowHeight);
        g.gridPanel.fireEvent('renderTableStart', tableId, PTC.jca.renderTable.log);

        PTC.jca.initializeSortInfo(jcaTableConfig, g);
        PTC.jca.table.registerHiddenRowsHandler(g, this);

        var tableEle = null;
        if (g.getEl()) {
            tableEle = g.getEl();
        } else {
            tableEle = Ext.get(tableId);
        }
        var ca, caSize = g.gridPanel.getCachedTableHeight();

        if (!caSize) {
            if (tableEle) {
                tableEle.contentAreaPanel = null;
                ca = PTC.jca.table.scroll.getContentArea(tableEle);
                if (ca && typeof ca.getInnerHeight === 'function') {
                    // trying to match what the calculateTableHeight function will produce later.
                    // This will cause the table to start out being full screen and will shorten as necessary
                    caSize = ca.getInnerHeight() - 20; //
                }
                else if (ca && ca.dom && typeof ca.getHeight === 'function') {
                    caSize = ca.getHeight() - 28; //
                }
                else {
                    caSize = 400;
                }
            }
            else {
                caSize = 400;
            }
        }

        g.gridPanel.render(tableId);
        g.gridPanel.setHeight(caSize);
        //setting content area
        PTC.jca.table.scroll.setContentArea(ca, g.gridPanel.getEl());

        if (typeof g.gridPanel.initialLoad === 'function') {
            g.gridPanel.initialLoad();
        }

        g.gridPanel.store.remoteSort = false;
        g.gridPanel.fireEvent('renderTableEnd', tableId, PTC.jca.renderTable.log);
        PTC.performance.stopComponentTimer(tableId, componentTimerBean, "emptyTable");
        jcaTableConfig = null;
    });
};

PTC.jca.processDelete = function (response) {
    if (response.ajaxClass !== 'NONE') {
        return false;
    }
    if (response.selectedItems && response.tableID) {
        var tid = tableUtils.getUnformattedTableId(response.tableID);
        var wTableId = PTC.jca.table.getWTablePanelID(tid);
        var wTable = Ext.getCmp(wTableId);
        var oids = [];
        for (var oid in response.selectedItems.data) {
            if (typeof oid === 'string') {
                oids.push(oid);
            }
        }
        wTable.deleteRowsByOids(oids);

        jsca.unSelectHiddenCheckboxes(tid);
    } // end if tableID
    return true;
};

PTC.jca.processUpdate = function (response) {
    if (response.dynamicText.indexOf('PURE JSON') === -1) {
        //update Column Filters
        if(response.tableID){
            PTC.jca.table.gridFilters.updateGridFilters(Ext.getCmp(response.tableID));
        }
        return false;
    }
	
    if (response.tableID) {
        var tid = tableUtils.getUnformattedTableId(response.tableID);
        var wTableId = PTC.jca.table.getWTablePanelID(tid);
        var wTable = Ext.getCmp(wTableId);
        if (wTable) {
            var BEGIN_FLAG = "<!-- BEGIN PURE JSON -->";
            var END_FLAG = "<!-- END PURE JSON -->";
            var jsonText = response.dynamicText;
            var iBegin = jsonText.indexOf(BEGIN_FLAG) + BEGIN_FLAG.length;
            var iEnd = jsonText.indexOf(END_FLAG, iBegin);
            jsonText = jsonText.substring(iBegin, iEnd);
            var theData;
            try {
                theData = Ext.util.JSON.decode(jsonText);
            } catch (e) {
                var re = /\n/g;
                jsonText = jsonText.replace(re, '\\n');
                re = /\r/g;
                jsonText = jsonText.replace(re, '\\r');
                theData = Ext.util.JSON.decode(jsonText);
            }
            theData.parentOid = response.parentOid;
            theData.addSorted = response.addSorted;
            theData.newRowsOnly = response.addRows;
            jsca.unSelectHiddenCheckboxes(tid);
            wTable.updateData(theData);
        }
        //update Column Filters
        PTC.jca.table.gridFilters.updateGridFilters(Ext.getCmp(response.tableID));
    } // end if tableID
    return true;
};


/**
 * Create some standard listeners to the table/tree
 * @param g
 * @param store
 */
PTC.jca.createListeners = function (g, store) {
    //Overridden by extensions, tree, etc.
};

/**
 * For legacy reason, tableID is used for grid.
 * This function is to convert that tableID to ID for WTablePanel
 * @param {Object} tableID - String id of the table
 */
PTC.jca.table.getWTablePanelID = function (tableID) {
    return tableID + '_WTablePanel';
};

/**
 * Maintains the appropriate state of the Select All checkbox.
 * If all items are selected, ensure that the Select All checkbox is selected.
 * If all itmes are not selected, ensure tha the Select All checkbox is unselected.
 * @param {Object} selModel the SelectionModel
 */
PTC.jca.table._handleSelectAllCheckbox = function (selModel) {

    // EXT manages checkbox selection by appling a CSS class to the checker div.
    // Since the Ext Select all checkbox behavior differs from what we want, we need to handle this case.
    // We get the appropriate div, and apply the appropriate class depending on
    // the selected state of the grid's rows.  See CheckboxSelectionModel.onHdMouseDown
    // in ext-all.js for more info.

    var checkerOnClass = 'x-grid3-hd-checker-on',
        grid = selModel.grid,
        selectAll = selModel.getSelectAll && selModel.getSelectAll();

    if (!selectAll) {
        return;
    }

    var store = grid.getStore(), collapsedRecordCount = 0;
    if (grid.tree && grid.deselectRowsOnCollapse === true) {
        var rec, allRenderable = grid.view.getAllRenderableRows(), allRenderableMap = {};
        // remove "handleSelectAllCheckbox listener temoporarily to avoid firing them in a loop when deselecting rows
        selModel.un("selectionchange", PTC.jca.table.handleSelectAllCheckbox);
        for(var m = 0, len1 = allRenderable.length; m < len1; m++) {
            allRenderableMap[allRenderable[m]] = true;
        }
        for(var n = 0, len2 = store.getCount(); n < len2; n++) {
            rec = store.getAt(n);
            if (allRenderableMap[rec._index] !== true) {
                selModel.deselectRow(undefined, false, rec);
                if (PTC.jca.table.isRowSelectable(rec, store)) {
                    collapsedRecordCount++;
                }
            }
        }
        selModel.on("selectionchange", PTC.jca.table.handleSelectAllCheckbox);
    }


    //In store there could be non -selectable rows so subtracting the non selectable row count from count.

    var nonSelectableRowCount = store.nonSelectableRowCount > 0 ? store.nonSelectableRowCount : 0;
    if (!selModel.hasSelection() || selModel.getCount() < (store.getCount() - nonSelectableRowCount - collapsedRecordCount)) {
        selectAll.removeClass(checkerOnClass);
    }
    else {
        selectAll.addClass(checkerOnClass);
    }
};

/*
 * This method will call _handleSelectAllCheckbox with some delay
 */
PTC.jca.table.handleSelectAllCheckbox = function (selModel) {
    if(!PTC.isDefined(selModel)){
        return;
    }
    if(selModel._handleSelectAllCheckboxTask  ===  undefined) {
        selModel._handleSelectAllCheckboxTask = new Ext.util.DelayedTask(PTC.jca.table._handleSelectAllCheckbox);
    }
    selModel._handleSelectAllCheckboxTask.delay(100, null,null, [selModel]);
};

/**
 * Function to determine if the row data is to be updated or added as a new row
 */
PTC.jca.table.isUpdateRow = function (data, rowData, rowStore, isTree) {
    var isUpdate = false;
    if (rowData.dynamicAction === 'U') {
        isUpdate = true;
    } else if (rowData.dynamicAction === 'A' || (rowData.dynamicAction === undefined || rowData.dynamicAction === null)) {
        // We are adding a row
        // We are checking for null and undefined for 'dynamicAction' as IE does not have the 'dynamicAction' set for an add operation
        isUpdate = false;
        if (isTree === true) {
            // for trees, check if we are adding the same row under the same parent
            var existingRowIndex = rowStore.findBy(function (record, id) {
                if (rowData.oid === record.data.oid && rowData.dynamicLocation === record.data._parent) {
                    return true;
                }
            });

            isUpdate = (existingRowIndex >= 0);

            if (isUpdate === false) {
                if (data.parentOid === undefined && rowData._parent !== undefined) {
                    // for tree updates, the row may not have the actual parent set, but itself so that it gets replaced
                    isUpdate = rowData.oid === rowData.dynamicLocation;
                } else {
                    isUpdate = rowData.oid === data.parentOid;
                }
            }
        } else {
            var existingRowIndex1 = rowStore.findBy(function (record, id) {
                if (rowData.oid === record.data.oid || rowData.jsca_context === record.data.jsca_context) {
                    return true;
                }
            });

	        isUpdate = (existingRowIndex1 >= 0);
        }
    }
    return isUpdate;
};

/**
 * Function to create record considering if record id is auto-generated or not.
 * @param {PTC.jca.WTablePanel} tableGrid
 * @param {Ext.data.Record []} rowData
 * @return {Ext.data.Record}
 */
PTC.jca.table.createRecord = function (tableGrid, rowData) {
    var updated;
    if (tableGrid.gridPanel.jcaTableConfig.generateRowId !== true) {
        // create a new record with row context
        updated = new tableGrid.rowRecord(rowData, rowData.jsca_context);
    } else {
        // for tables with auto-generated ids, excluding the jsca_context argument so that Ext generates the record id
        updated = new tableGrid.rowRecord(rowData);
    }
    return updated;
};

/**
 * Focuses the first of the updated rows or previously focus row if present
 * @param {Ext.data.Record []} updatedRecords array
 * @param {PTC.jca.WTablePanel} grid
 */
PTC.jca.table.handleFocusRow = function (updatedRecords, grid) {
    var totalUpdated = updatedRecords.length;
    var firstRowIndex = -1;
    var rowStore = grid.getStore();
    var isTree = (grid.tree === true);

    // search for the updated rows, first row of them would be ensured to be visible in the view port
    if (isTree) {
        firstRowIndex = rowStore.findBy(function (record, id) {
            var rowOid = record.data.oid;
            var rowContext = record.data.jsca_context;
            for (var i = 0; i < totalUpdated; i++) {
                if (updatedRecords[i].data.oid === rowOid && updatedRecords[i].data.jsca_context === rowContext) {
                    return true;
                }
            }
        });
    } else {
        firstRowIndex = rowStore.findBy(function (record, id) {
            var rowOid = record.data.oid;
            for (var i = 0; i < totalUpdated; i++) {
                if (updatedRecords[i].data.oid === rowOid) {
                    return true;
                }
            }
        });
    }

    // look for the initially focused row if any
    if (grid.scrollIndex) {
        var fRowIndex = PTC.jca.table.Utils.getRowByUniqueIdentifier(grid.getStore(), grid.scrollIndex);
        if (fRowIndex > -1) {
            PTC.jca.table.Utils.focusRow(grid, fRowIndex, false, true);
            if (firstRowIndex === -1) {
                firstRowIndex = fRowIndex;
            }
        }
    }

    if (firstRowIndex > -1) {
        grid.getView().ensureVisible(firstRowIndex, 0, false);
        grid.alreadyScrolled = true;//to ensure that the table is not again re-scrolled after view refresh
    }
};

/**
 * Adds the data to table store after evaluating search in list filter
 */
PTC.jca.table.addRowsToFilteredData = function (rowStore, addRows) {
    var addToData = [];
    var addToSnapShot = [];

    for (var i = 0, len = addRows.length; i < len; i++) {
        var fitsFilter = rowStore.searchInListFilterByFunc(addRows[i]);
        if (fitsFilter === true) {
            addToData.push(addRows[i]);
        } else {
            addToSnapShot.push(addRows[i]);
        }
    }

    if (addToData.length > 0) {
        rowStore.add(addToData);
    }
    if (addToSnapShot.length > 0) {
        rowStore.add(addToSnapShot, true);//2nd argument to indicate only snapshot would be updated
        rowStore.sortSnapShotData = true;//so that snapshot data will also be sorted
    }
};

/**
 * Update the selection count message in the footer.
 */
Ext.grid.GridPanel.prototype.updateSelCountMsg = function () {
    if (this.isDestroyed || !this.initialConfig.jcaTableConfig || !this.initialConfig.jcaTableConfig.selectedMessageTemplate) {
        return;
    }
    var sm = this.selModel,
        smCount = sm.getCount(),
        iSelNum = sm.snapshot ? sm.snapshot.length + smCount : smCount;    
    var inserts = { selected : iSelNum };
    var selMsg = this.initialConfig.jcaTableConfig.selectedMessageTemplate.evaluate(inserts);
    var pagingBar = this.getBottomToolbar();
    var tbSelectionCount = pagingBar.getComponent("selectionMessageCount");
    if (tbSelectionCount !== undefined && tbSelectionCount.getEl() && tbSelectionCount.getEl().dom && tbSelectionCount.last_update_value !== iSelNum) {
        tbSelectionCount.last_update_value = iSelNum;
        tbSelectionCount.setText(selMsg);
    }
};

/**
 * Selection model listener, add selections should update select count
 * @param {Object} selModel
 */
PTC.jca.table.addSelectedListener = function (selModel) {
    selModel.grid.updateSelCountMsg();
};

/**
 * hides the select box on the rows if it is marked as not selectable
 */
PTC.jca.table.nonSelectablesListener = function (sm, rowIndex, keep, rec) {
    return PTC.jca.table.isRowSelectable(rec, sm.grid.getStore());
};

/**
 * Selection model listener, remove selections should update select count
 */
PTC.jca.table.removeSelectionListener = function (selModel, rowIndex, record) {
    selModel.grid.updateSelCountMsg();
    var view = selModel.grid.getView();
    view.removeRowClass(rowIndex, view.focusedRowCheckerClass);
};
/**
 * This code registers the checkbox events and upadete the select count message
 */
Ext.grid.GridPanel.prototype.registerSelCount = function () {
    var gridPanel = this;
    var selectionModel = gridPanel.getSelectionModel();
    if (selectionModel) {
        gridPanel.updateSelCountMsg = PTC.util.delayAllCalls(gridPanel.updateSelCountMsg);
        selectionModel.on('beforerowselect', PTC.jca.table.nonSelectablesListener);
        selectionModel.on('rowselect', PTC.jca.table.addSelectedListener);
        selectionModel.on('rowdeselect', PTC.jca.table.removeSelectionListener);
        var rowStore = gridPanel.getStore();
        if (rowStore) {
            rowStore.on('datachanged', gridPanel.updateSelCountMsg, gridPanel);
            rowStore.on('add', gridPanel.updateSelCountMsg, gridPanel);
            rowStore.on('remove', gridPanel.updateSelCountMsg, gridPanel);
        }
        gridPanel.on('afterrender', gridPanel.updateSelCountMsg, gridPanel);
    }
};
PTC.jca.TableGrid.prototype.initComponent = function () {
    PTC.jca.TableGrid.superclass.initComponent.apply(this, arguments);
    if (isWizardWindow()) {
        // because the listeners are only added in wizard to submit the table data, there is no need to
        // add the document listeners to save the data.   This improves performance by not haveing some many broad listeners
        this.domChangeEventListener = PTC.wizard.saveTableData.domChangeEventListener;
        this.on('renderTableEnd', PTC.wizard.saveTableData.registerDomChangeEvents);
    }
    this.registerSelCount();
    this.on('afteraction', this.onAfterAction);
    this.mon(PTC.action, 'objectsaffected', this.onObjectsAffected, this);
};

/**
 * Performance override of setHeight function, only change when the value is different
 * @param {number} newHeight
 */
PTC.jca.TableGrid.prototype.setHeight = function (newHeight) {
    if (newHeight !== this.jcaHeight) {
        PTC.jca.TableGrid.superclass.setHeight.apply(this, arguments);
        this.jcaHeight = newHeight;
    }
};

/**
 * @return {Ext.Toolbar} toolbar for this table (the toolbar with the shortcut actions and actions menu)
 */
PTC.jca.TableGrid.prototype.getToolbar = function () {
    //noinspection JSValidateTypes
    return Ext.getCmp(this.id + '.toolBar');
};

/**
 * @param {String} name - the action name from the actions.xml definition of the toolbar action
 * @param {String} type - the objecttype from the actions.xml definition of the toolbar action
 * @return {Ext.Toolbar.Item} toolbar item for the given action name and object type,
 *                            or null if no toolbar item for the given params is found.
 */
PTC.jca.TableGrid.prototype.getToolbarItem = function (name, type) {
    var actionFilter = function (item) {
        return item.actionName === name && item.actionType === type;
    };
    var items = this.getToolbar().findBy(actionFilter);
    if (items && items.length >= 0) {
        return items[0];
    }
    actionFilter = null;
    return null;
};


/**
 * Filter data for paginated as well as non-paginated tables also.
 */
Ext.data.Store.prototype.filterBySelections = function (checked, gridPanel) {
    if (checked) {
        var selections = this.gridPanel.getSelectionModel().getSelections();
        var selectedCollection = new Ext.util.MixedCollection();
        selectedCollection.addAll(selections);
        this.currentData = this.data;
        this.data = selectedCollection;
        var gridView = gridPanel.getView();
        this.fireEvent("datachanged", this);
        var selectedCount = selectedCollection.getCount();
        for (var i = 0; i < selectedCount; i++) {
            gridView.addRowClass(i, gridView.selectedRowClass);
        }
    } else {
        // TODO: need to check as user might have moved to different page and then if he unselects, it would fail
        if (this.currentData) {
            this.data = this.currentData;
        }
        this.fireEvent("datachanged", this);
    }
};

Ext.grid.GridPanel.prototype.initPagingBar = function () {
    var gridPanel = this;
    var store = gridPanel.getStore();
    var pagingBar = gridPanel.getBottomToolbar();
    var tableSelectable = gridPanel.jcaTableConfig.selectable;
    var jcaTableConfig = gridPanel.jcaTableConfig;
    if (tableSelectable) {
        var selCountMsg = pagingBar.getComponent("selectionMessageCount");
        if (selCountMsg === undefined) {
            selCountMsg = new Ext.Toolbar.TextItem({
                itemId:'selectionMessageCount',
                text:'          ',
                xtype:'tbtext' // cannot be empty or null for ie
            });
            pagingBar.insert(0, selCountMsg);
        }
    } // end if selCountMsg
    if (store.DATA_RENDERED === true && !jcaTableConfig.chunk && store.tree === undefined || store.tree === false) {
        store.handleResultLimitActions();
    }
    pagingBar.show();
};

/**
 * Override the default EXT 'rowmousedown' event listener (handleMouseDown), so that we can provide row focus behavior.
 * @param {Object} g
 * @param {Object} rowIndex
 * @param {Object} e
 */
Ext.grid.GridPanel.prototype.jcaRowMouseDown = function (g, rowIndex, e) {
    if (e.shiftKey) {
        e.preventDefault();//preventing the selection of the row text
    }
    var selectionModel = g.getSelectionModel();
    var isSelected = g.jcaTableConfig.selectable && selectionModel.isSelected(rowIndex);
    PTC.jca.table.Utils.focusRow(g, rowIndex, isSelected);
};

/**
 * column resize listener
 * @param {Object} i
 * @param {Object} nw
 */
Ext.grid.GridPanel.prototype.jcaColumnResize = function (i, nw) {
    var gridPanel = this;
    var columnModel = gridPanel.colModel;
    var gridView = gridPanel.getView();

    PTC.jca.ColumnUtils.resizeLastColumn(gridPanel);

    //If the variable row height is true and the column resized is wrappable, called doUpdate to reset the row-height.
    if (gridView.variableRowHeight === true && columnModel.getColumnAt(i).isWrapped) {
        gridView.doUpdate(true);
    }

};

/**
 * When we double click on table / tree header, Ext by default fires two click events.
 * Suppress the click events when double click event is fired on column seperators.
 */
Ext.grid.GridPanel.prototype.jcaHeaderClick = function (grid, columnIndex, e) {
    var h = grid.getView().getHeaderCell(columnIndex);
    if (h.style.cursor === 'col-resize') {
        e.stopEvent();
        return false;
    }
};

/**
 * Resize the table/tree column header for its data to fit the column.
 * @param {Object} grid
 * @param {integer} columnIndex
 */
Ext.grid.GridPanel.prototype.jcaHeaderResize  = function (grid, columnIndex) {

    if (grid.colModel.isResizable(columnIndex)) {
        var columnResized = PTC.jca.ColumnUtils.resizeColumn(grid, columnIndex, true);
        if(columnResized === true) {
            //Resize the last column to avoid white space. This method gets called on columnresize event
            grid.jcaColumnResize(columnIndex, grid.colModel.getColumnWidth(columnIndex));
        }
    }
    grid.fireEvent('columnConfigChange', grid); // updating the config to state manager
};

/**
 * Listener for table/tree column header double click that will resize the column to fit its content
 * @param {Object} grid
 * @param {integer} columnIndex
 * @param {EventObject} e - EventObject
 */
Ext.grid.GridPanel.prototype.jcaHeaderDBClick = function (grid, columnIndex, e) {
    var h = grid.getView().getHeaderCell(columnIndex);
    if (h.style.cursor !== 'col-resize') {
        return;
    }
    grid.jcaHeaderResize(grid, columnIndex);
};

/**
 *
 * @param {Object} grid
 * @param {Object} sortInfo
 */
Ext.grid.GridPanel.prototype.jcaSortChange = function (grid, sortInfo) {
    //Code to move scrollbar to the last selected/focused row. focused row will be given preference.
    if (grid.store.remoteSort) {
        // TODO: code to evaluate the page number where user should be navigated to the page containing
        // the last selected record row, etc. scenarios. For now, it can always be navigated to the first page?
        // grid.getBottomToolbar().doLoad(0);
        // We need to ensure remoteSort is made false after sorting or it will continuously send an POST request
        grid.store.remoteSort = false;
    }
    var view = grid.getView();
    var rowIndex = PTC.jca.table.Utils.getRowByUniqueIdentifier(grid.getStore(), grid.scrollIndex);
    if (typeof rowIndex === 'number' && rowIndex > -1) {
        view.ensureVisible(rowIndex, 0, false);
        PTC.jca.table.Utils.focusRow(grid, rowIndex, grid.getSelectionModel().isSelected(rowIndex));
    }
    else {
        var selectionModel = grid.getSelectionModel();
        var record = selectionModel.getSelections();
        if (record.length > 0) {
            view.ensureVisible(grid.getStore().indexOf(record[record.length - 1]), 0, false);
        }
        else {
            view.scrollToTop();
        }
    }
};
Ext.grid.GridPanel.prototype.jcaOnRowSelect = function (selectionModel, rowIndex, record) {
    jsca.rowSelectionHandler(selectionModel.grid.id, null, record, true, selectionModel.grid);
    return true;
};

Ext.grid.GridPanel.prototype.jcaOnRowDeSelect = function (selectionModel, rowIndex, record) {
    jsca.rowSelectionHandler(selectionModel.grid.id, null, record, false, selectionModel.grid);
    return true;
};
Ext.grid.GridPanel.prototype.jcaOnRowMassDeselection = function (selectionModel, records) {
    var snapShotItems;
    if(selectionModel.snapshot){
       snapShotItems = selectionModel.snapshot.items;
    }
    jsca.rowSelectionHandler(selectionModel.grid.id, records, null, false, selectionModel.grid, true, snapShotItems);
    selectionModel.grid.updateSelCountMsg();
    selectionModel.fireEvent('selectionchange', selectionModel);
    return true;
};
Ext.grid.GridPanel.prototype.jcaOnRowMassSelection = function (selectionModel, records) {
    var snapShotItems;
    if(selectionModel.snapshot){
       snapShotItems = selectionModel.snapshot.items;
    }
    jsca.rowSelectionHandler(selectionModel.grid.id, records, null, true, selectionModel.grid, true, snapShotItems);
    selectionModel.grid.updateSelCountMsg();
    selectionModel.fireEvent('selectionchange', selectionModel);
    return true;
};

/**
 * Pre-select if only a single row
 * @param {Object} grid
 */
Ext.grid.GridPanel.prototype.jcaSingleRowPreSelect = function (grid) {
    var store = grid.store;
    var count = store.getCount();
    if (count === 1 && grid.singleRowPreSelected !== true) {
        var selectionModel = grid.getSelectionModel();
        selectionModel.selectRow(0);
        grid.singleRowPreSelected = true;
    }
    return true;
};
/**
 * @class PTC.jca.handleFooterButtons
 * handles the footer message buttons
 */
PTC.jca.handleFooterButtons = (function () {
    /**
     * Get paging bar
     * @private
     * @param {String} tableId
     * @returns Ext.ToolBar object
     */
    function getPagingBar(tableId) {
        return PTC.jca.table.Utils.getTable(tableId).getBottomToolbar();
    }

    /**
     * Force container's layout to be recalculated.
     * @private
     * @param {String} tableId
     * @param {Object}pagingBar
     */
    function doLayout(tableId, pagingBar) {
        if (pagingBar) {
            pagingBar.doLayout(true, true);
        } else {
            getPagingBar(tableId).doLayout(true, true);
        }
    }

    return /**@scope PTC.jca.handleFooterButtons */{

        /**
         * Make the message button visible and set the message as tooltip
         * @param {Ext.Toolbar.Button} msgBtn : button to be displayed
         * @param {String} message : message to be shown as tooltip
         * @param {String} tableId : table ID
         */
        showMsgButton:function (msgBtn, message, tableId) {
            if (!msgBtn.isVisible()) {
                msgBtn.show();
                msgBtn.setTooltip(message);
                doLayout(tableId);
            }
        },

        /**
         * Create message button
         * @param {String} id : The unique id of button
         * @param {String} tooltip : tooltip for the button
         * @param {String} itemId : button id
         * @param {String} iconCls class
         * @returns {Ext.Toolbar.Button} Object
         */
        createMsgButton:function (id, tooltip, itemId, iconCls) {
            return new Ext.Toolbar.Button({
                id:id,
                tooltip:tooltip,
                itemId:itemId,
                iconCls:iconCls,
                disabled:true,
                disabledClass:'' //Default class is 'x-item-disabled' which made button gray, overwrote 'x-item-disabled' class with blank.
            });
        },

        /**
         * Insert button to the toolbar
         * @param {int} index : location at which the button to be inserted
         * @param {Ext.Toolbar.Button} button : button to be inserted
         * @param {String} tableId : table ID
         */
        insertButton:function (index, button, tableId) {
            var pagingBar = getPagingBar(tableId);
            pagingBar.insertButton(index, button);
            doLayout(tableId, pagingBar);
        },

        /**
         * find button component from the toolbar
         * @param {String} tableId : table ID
         * @param {String} buttonId : Button id
         * @returns Ext.Toolbar.Button object for the given buttonId
         */
        findButton:function (tableId, buttonId) {
            return getPagingBar(tableId).findById(buttonId);
        }
    };
})();
/**
 * Add message to footer based on feedback type.
 * @param {String} message : message to be shown as tooltip on the icon
 * @param {String} feedbackType : type of feedback
 */
PTC.jca.WTablePanel.prototype.addFooterMessage = function (message, feedbackType) {
    var btnId = this.jscaTableID + '_tablelvlmesg';
    var msgBtn = null;
    if ('1' === feedbackType) {// show error message icon
        btnId = btnId + "_Err";
        msgBtn = PTC.jca.handleFooterButtons.findButton(this.jscaTableID, btnId);
        if (msgBtn) {
            PTC.jca.handleFooterButtons.showMsgButton(msgBtn, message, this.jscaTableID);
        } else {
            var tableLvlMsgButtonErr = PTC.jca.handleFooterButtons.createMsgButton(btnId, message, 'tableLevelMessageBtnErr', 'table-level-error-message');
            PTC.jca.handleFooterButtons.insertButton(1, tableLvlMsgButtonErr, this.jscaTableID);
        }
    } else {// show warning icon
        msgBtn = PTC.jca.handleFooterButtons.findButton(this.jscaTableID, btnId);
        if (msgBtn) {
            PTC.jca.handleFooterButtons.showMsgButton(msgBtn, message, this.jscaTableID);
        }
        else {
            var tableLvlMsgButton = PTC.jca.handleFooterButtons.createMsgButton(btnId, message, 'tableLevelMessageBtn', 'table-level-message');
            PTC.jca.handleFooterButtons.insertButton(0, tableLvlMsgButton, this.jscaTableID);
        }
    }
};

PTC.jca.WTablePanel.prototype.updateTitle = function () {
    var rowStore = this;
    var grid = PTC.jca.table.Utils.getTable(rowStore.jscaTableID);
    if (!PTC.isDefined(grid) || !PTC.isDefined(rowStore.data)) {
        return;
    }
    var jcaTableConfig = grid.jcaTableConfig;
    var displayedRows;
    if (jcaTableConfig.tree) {
        displayedRows = grid.getView().getAllRenderableRows().length;
    }
    else {
        displayedRows = rowStore.getCount();
    }
    // Servers total number of rows (y) in the data set
    var totalRows = jcaTableConfig.totalRows;
    var fills = {
        total:displayedRows
    };
    // Page Offsets gives the initial Index of Data on current page
    var pageOffset = jcaTableConfig.pageOffset;
    var wTable = Ext.getCmp(PTC.jca.table.getWTablePanelID(grid.id));
    var titleMessageTemplate = new Template(wTable.displayedLoadCompleteMessage);
    if (jcaTableConfig.chunk && !jcaTableConfig.tree) {
        // All table data is loaded that the table count is displayed as "x objects"
        var titleDisplayMsgTemplate = new Template(wTable.displayedMessage);
        var titleDisplayMoreMsgTemplate = new Template(wTable.displayedMoreMessage);

        var rowsUptoPage = displayedRows;
        if (pageOffset > 0) {
            rowsUptoPage = rowsUptoPage + pageOffset;
        }
        //more data will specify result limit is reached and moredata yet to come.
        var moreData = rowStore.moreData;
        if (rowStore.load_complete === true) {// All Chunks are loaded

            if (totalRows <= 0) {// We are not aware of total rows of server

                // This will display x of more than (n+1)x message.
                if (moreData === true) {
                    titleMessageTemplate = titleDisplayMoreMsgTemplate;
                    fills = {
                        displayed:displayedRows,
                        total:rowsUptoPage
                    };
                }
                /*
                 * This means, No more data to come, we are on last page as offset is greater than 0.
                 * At this stage we know the total objects so we will disply message x of y objects.
                 */
                else if (moreData === false && pageOffset > 0) {
                    titleMessageTemplate = titleDisplayMsgTemplate;
                    fills = {
                        displayed:displayedRows,
                        total:rowsUptoPage
                    };
                }
            }
            else { // We know, Servers total number of rows (y) in the data set

                /*
                 * Check if we are reached result limit or we are on last page,
                 * then we will disply message x of y objects.
                 */
                if (moreData === true || pageOffset > 0) {
                    titleMessageTemplate = titleDisplayMsgTemplate;
                    fills = {
                        displayed:displayedRows,
                        total:totalRows
                    };
                }
            }
        }
        else { // Chunks are still loading

            if (totalRows <= 0) {
                // We are not aware of total rows so we will display x of more than (n+1)x message
                titleMessageTemplate = titleDisplayMoreMsgTemplate;
                fills = {
                    displayed:displayedRows,
                    total:rowsUptoPage
                };
            }
            else {
                // At this stage we know the total objects so we will disply message x of y objects.
                titleMessageTemplate = titleDisplayMsgTemplate;
                fills = {
                    displayed:displayedRows,
                    total:totalRows
                };
            }
        }
    }
    //set the title message template (Number of Objects in Table (for eg. x Objects Next to table Title)).
    var titleStatusCmp = grid.getTopToolbar();
    if (titleStatusCmp) {
        var titleMessage = titleMessageTemplate.evaluate(fills);
        var tbTitleCount = titleStatusCmp.getComponent("titleMessageCount");
        if (tbTitleCount !== undefined) {
            tbTitleCount.setText(titleMessage);
        }
    }
};

PTC.jca.WTablePanel.prototype.renderToolbars = function (gridPanel) {
    var jcaTableConfig = gridPanel.jcaTableConfig;
    // On mouse click, Ext 3.0 by default, selects the row and deselects other rows.
    // Remove the default event handler and provide a new one (with the required behaviour).
    if (jcaTableConfig.selectable) {
        gridPanel.removeListener('rowmousedown', gridPanel.getSelectionModel().handleMouseDown, gridPanel.getSelectionModel());
    }
    // Remove the default Ext-JS 3 event handlers, so that we can provide
    // hover, focus, highlight behavior for rows.
    var wid = PTC.jca.table.getWTablePanelID(gridPanel.id);
    var wTable = Ext.getCmp(wid);
    // +++ Set menu bar +++
    if (jcaTableConfig.menubar) {
        if (!PTC.isDefined(wTable.menuBar)) {
            // because the id is the same, some previous menu items were showing up too
            var menubarConfig = PTC.jca.ActionModelToMenubar(jcaTableConfig.menubar, gridPanel);
            wTable.menuBar = new Ext.Toolbar({
                id:gridPanel.id + '.menuBar',
                renderTo:gridPanel.tbar,
                anchor:'100%',
                items:menubarConfig.items
            });
            PTC.jca.setIgnoreParentClick(wTable.menuBar);
        }
    }
    // +++ Set Shortcut area and toolbar actions menu +++
    if (!PTC.isDefined(wTable.toolBar)) {
        // This array will hold all shortcut area items and toolbar actions menu items
        var toolbarConfigItems = [];
        //  Set shortcut items and multiselect items
        var tableId = jcaTableConfig.tableID;
        var actionsBarConfig = wTable.createtoolbarToShortcutbarMultiSelectbarConfig(jcaTableConfig.toolbar, tableId);
        var shortcutItemsConfig = [];
        if (actionsBarConfig) {
            shortcutItemsConfig = actionsBarConfig[0];
            jcaTableConfig.shortcutbar = shortcutItemsConfig;
            jcaTableConfig.multiSelectbar = actionsBarConfig[1];
        }

        /*
         * Set toolbar shortcut actions and actions menu. Enclose the jcaTableConfig.toolbar into a actions object. So It will
         * become a sub-model and all the toolbar actions will get displayed Vertically. If all actions are marked as a shortcutbar
         * then do not show actions menu.
         */
        if (Ext.isEmpty(shortcutItemsConfig)) {
            // Add the actions menu.
            toolbarConfigItems.push(PTC.jca.table.getActionsMenuConfig(gridPanel));
        } else {
            // Always add the shortcut items if they exist
            toolbarConfigItems.push(shortcutItemsConfig.items);

            if (shortcutItemsConfig.allShortcutItems === false) {
                // Add Separator between the toolbar items and actions menu.
                toolbarConfigItems.push(new Ext.Toolbar.Separator());
                // Add the actions menu.
                toolbarConfigItems.push(PTC.jca.table.getActionsMenuConfig(gridPanel));
            }
        }

        // This will make all components after this one right justified.
        toolbarConfigItems.push('->');

        // Show "Search in list" on tables that aren't trees and when it is not disabled.
        if (!jcaTableConfig.tree && jcaTableConfig.findInTableMode !== FindInTableMode.DISABLED) {
            var searchInListComponents = PTC.jca.table.findInTable(tableId);
            toolbarConfigItems = toolbarConfigItems.concat(searchInListComponents);
            this.on('clearSearchInList', PTC.jca.table.findInTable.clearSearchInListHandler, this);
            this.on('applySearchInList', PTC.jca.table.findInTable.applySearchInListHandler, this);
        }

        // If search is only at client side and not tree then handle the next prev link.
        if (!jcaTableConfig.tree && jcaTableConfig.findInTableMode === FindInTableMode.CLIENT_ONLY) {
            this.on('clearSearchInList', PTC.jca.table.showNxtPrevLink, this);
            this.on('applySearchInList', PTC.jca.table.hideNxtPrevLink, this);
        }
        this.optionsButton = wTable.getOptionsButton();
        if (this.optionsButton !== null) {
            toolbarConfigItems.push(this.optionsButton);
        }

        // +++ Set table help link +++
        this.helpButton = PTC.help.getHelpButtonConfig(jcaTableConfig.help);
        if (this.helpButton !== null) {
            toolbarConfigItems.push(this.helpButton);
        }

        // Special PTC layout that fixes Ext's overflow menu.
        // adjust triggerWidth which has a (default value of 17, the vlue is used to determine toolbar overflow clip width)
        var toolbarLayout = new PTC.jca.table.ToolbarLayout({
            tableId:tableId,
            triggerWidth:40
        });

        wTable.toolBar = new Ext.Toolbar({
            id:gridPanel.id + '.toolBar',
            renderTo:gridPanel.tbar,
            anchor:'100%',
            autoWidth:true,
            cls:'ecaToolbar',
            items:toolbarConfigItems,
            layout:toolbarLayout,
            enableOverflow:true
        });
        this.actionsToolBar = wTable.toolBar;
        PTC.jca.setIgnoreParentClick(wTable.toolBar);
    }

    if (jcaTableConfig.tree && jcaTableConfig.findInTableMode && jcaTableConfig.findInTableMode !== FindInTableMode.DISABLED) {
        PTC.jca.table.installFindInTreeFeature(gridPanel);
    }

};

PTC.jca.WTablePanel.prototype.getBarsItemsConfig = function (toolbarConfig, tableId, shortcutItems, multiSelectItems) {
    if (!toolbarConfig || !toolbarConfig.items) {
        return;
    }
    // Code to create a list of shortcut area items from jcaTableConfig.toolbar
    var toolbarItems = toolbarConfig.items;


    var toolbarItemsCount = toolbarItems.length;
    var allShortcutItems = true;
    for (var count = 0; count < toolbarItemsCount; count++) {
        var toolbarItem = toolbarItems[count];
        // Code to create a list of multiselect bar tems from jcaTableConfig.toolbar
        if (toolbarItem.selectRequired && toolbarItem.multiSelect) {
            var multiSelectItem = JCAClone(toolbarItem);
            if (multiSelectItem.id !== undefined) {
                multiSelectItem.id = tableId + multiSelectItem.id + "_mbar";
            }
            multiSelectItems.push(multiSelectItem);
        }
        var isPanel = toolbarItem.xtype === "panel";
        if (toolbarItem.items && isPanel === false) {
            allShortcutItems = this.getBarsItemsConfig(toolbarItem, tableId, shortcutItems, multiSelectItems) && allShortcutItems;
        } else {
            // For applets and suggest widgets, they should only be in the toolbar.
            var shortCutOnly = false;
            if (isPanel) {
                toolbarItems.splice(count, 1);
                count--;
                toolbarItemsCount--;
                // Mark this action as shortcut action so that it will get displayed in toolbar.
                toolbarItem.shortCut = true;
                shortCutOnly = true;
            }
            if (toolbarItem.shortCut === true) {
                // we are changing the id property for shortcutbar items because at the time of rendering toolbar required different id to uniquely identify item.
                if (shortCutOnly) {
                    // Just use it since you don't need to clone because only one copy used.
                    shortcutItems.push(toolbarItem);
                }
                else {
                    var shortcutItem = JCAClone(toolbarItem);
                    if (shortcutItem.id !== undefined) {
                        shortcutItem.id = tableId + shortcutItem.id + "_shortcutbar";
                    }
                    shortcutItems.push(shortcutItem);
                }
            }
            else if (toolbarItem !== "-") {//Exclude the Spacer Action which do not have any information except "-"
                allShortcutItems = false;
            }
        }
    }
    return allShortcutItems;
};


/**
 * This method will create a shortcut toolbar configuration for all toolbar items that are marked as shortcut items
 * and multiselect bar for all toolbar items that are marked as selectRequied && multiselect
 * @param toolbarConfig ToolbarConfiguration action model that we receive from JCATableConfig.
 * @param tableId The table Id for which we are setting the action model.
 */
PTC.jca.WTablePanel.prototype.createtoolbarToShortcutbarMultiSelectbarConfig = function (toolbarConfig, tableId) {
    // Code to create a list of shortcut area items from jcaTableConfig.toolbar
    var shortcutItems = [];
    var multiSelectItems = [];
    var allShortcutItems = this.getBarsItemsConfig(toolbarConfig, tableId, shortcutItems, multiSelectItems);
    // add shortcut item list to action model
    var shortcutItemsCount = shortcutItems.length;
    var shortcutbarActionsConfig = null;
    var actionsBarConfig = [];
    if (shortcutItemsCount > 0) {
        var shortcutActions = {};
        shortcutActions.actionsId = tableId + "_shortcutActions";
        shortcutActions.defaultActionName = "";
        shortcutActions.items = shortcutItems;
        shortcutbarActionsConfig = PTC.jca.ActionModelToToolbar(shortcutActions, this.gridPanel);
        shortcutbarActionsConfig.allShortcutItems = allShortcutItems;
        actionsBarConfig[0] = shortcutbarActionsConfig;
    }
    var multiSelectbarActionsConfig = null;
    if (multiSelectItems && multiSelectItems.length > 0) {
        var multiSelectActions = {};
        multiSelectActions.actionsId = tableId + "multiSelectActions";
        multiSelectActions.defaultActionName = "";
        multiSelectActions.items = multiSelectItems;
        //as it is right click actions menu do not hide text so sending true to ActionModelToToolbar
        multiSelectbarActionsConfig = PTC.jca.ActionModelToToolbar(multiSelectActions, this.gridPanel, true);
        actionsBarConfig[1] = multiSelectbarActionsConfig;
    }
    return actionsBarConfig;
};

//This method will show or hide the next/Previous links and warning message if present.
PTC.jca.table.setVisibleNxtPrevLink = function (grid, visible) {
    var jcaTableConfig = grid.jcaTableConfig;
    var previousLinkID = PTC.jca.nextPreviousActions.getPreviousLinkId(jcaTableConfig.tableID);
    var nextLinkID = PTC.jca.nextPreviousActions.getNextLinkId(jcaTableConfig.tableID);
    var warningMsgID = jcaTableConfig.tableID + '_tablelvlmesg';
    var pagingBar = grid.getBottomToolbar();
    var nxtLink = pagingBar.getComponent(nextLinkID);
    var prevLink = pagingBar.getComponent(previousLinkID);
    var warningMsg = pagingBar.findById(warningMsgID);
    if (nxtLink) {
        nxtLink.setVisible(visible);
    }
    if (prevLink) {
        prevLink.setVisible(visible);
    }
    if (warningMsg) {
        warningMsg.setVisible(visible);
    }
    pagingBar.doLayout();
};

//this method will hide next previous link.
PTC.jca.table.hideNxtPrevLink = function (grid) {
    PTC.jca.table.setVisibleNxtPrevLink(grid, false);
};

//This method will show next previous link.
PTC.jca.table.showNxtPrevLink = function (grid) {
    PTC.jca.table.setVisibleNxtPrevLink(grid, true);
};

Ext.data.Store.prototype.handleResultLimitActions = function (store) {
    if (!store) {
        store = this;
    }
    var grid = PTC.jca.table.Utils.getTable(store.jscaTableID);
    var pagingBar = grid.getBottomToolbar();
    var jcaTableConfig = grid.jcaTableConfig;
    var doLayout = false;
    var previousLinkID = PTC.jca.nextPreviousActions.getPreviousLinkId(jcaTableConfig.tableID);
    var nextLinkID = PTC.jca.nextPreviousActions.getNextLinkId(jcaTableConfig.tableID);
    var linkSpacerID = PTC.jca.nextPreviousActions.getLinkeSpacerId(jcaTableConfig.tableID);

    // previous link required
    if (jcaTableConfig.pageOffset !== 0) {
        if (!pagingBar.getComponent(previousLinkID)) {
            pagingBar.remove(nextLinkID);
            pagingBar.remove(linkSpacerID);
            pagingBar.add(PTC.jca.table.Utils.makeExtPagingLink({
                text:bundleHandler.get('com.ptc.netmarkets.util.utilResource.PREVIOUS_PAGE'),
                id:previousLinkID,
                tooltip:bundleHandler.get('com.ptc.netmarkets.util.utilResource.PREVIOUS_RESULT_TOOLTIP'),
                handler:store.nextPreviousResultSetOnClickHandler.createCallback(store, previousLinkID)
            }));
            doLayout = true;
        }
    } else {
        pagingBar.remove(previousLinkID);
        pagingBar.remove(linkSpacerID);
    }

    // next link required
    if (store.moreData) {
        if (!pagingBar.getComponent(nextLinkID)) {
            // if both links exist and it hasn't already been created, create spacer
            if (pagingBar.getComponent(previousLinkID) && !pagingBar.getComponent(linkSpacerID)) {
                pagingBar.add({
                    xtype:'tbspacer',
                    width:12,
                    id:linkSpacerID
                });
            }
            pagingBar.add(PTC.jca.table.Utils.makeExtPagingLink({
                text:bundleHandler.get('com.ptc.netmarkets.util.utilResource.NEXT_PAGE'),
                id:nextLinkID,
                tooltip:bundleHandler.get('com.ptc.netmarkets.util.utilResource.MORE_RESULTS_TOOLTIP'),
                handler:store.nextPreviousResultSetOnClickHandler.createCallback(store, nextLinkID)
            }));
            doLayout = true;
        }
    } else {
        pagingBar.remove(linkSpacerID);
        pagingBar.remove(nextLinkID);
    }
    if (doLayout) {
        pagingBar.doLayout();
    }
};

Ext.data.Store.prototype.PTC_OnBeforeLoadState = function () {
    this.DATA_RENDERED = false;
};
Ext.data.Store.prototype.PTC_OnLoadState = function () {

    this.DATA_RENDERED = true;
};

PTC.jca.nextPreviousActions = (function () {
    var nextLinkSuffix = "nextResultSet_";
    var previousLinkSuffix = "previousResultSet_";
    var nextPreviousLinkSpacer = "nextPrevLinkSpacer_";

    return /**@scope PTC.jca.nextPreviousActions */{

        validate:function (tableId) {
            if (PTC.jca.table.Utils.getTableSelectedRowsCountById(tableId) > 0) {
                if (!JCAConfirm(null, "com.ptc.netmarkets.util.utilResource.NXT_PRE_WARNING_MSG")) {
                    return false;
                }
                jsca.unSelectHiddenCheckboxes(tableId);
                PTC.jca.table.Utils.clearSelectAllCheckbox(PTC.jca.table.Utils.getTable(tableId));
            }
            return true;
        },
        getNextLinkId:function (tableId) {
            return nextLinkSuffix + tableId;
        },
        getPreviousLinkId:function (tableId) {
            return previousLinkSuffix + tableId;
        },
        getLinkeSpacerId:function (tableId) {
            return nextPreviousLinkSpacer + tableId;
        }
    };
})();

/**
 * click handler for the paging links (next/previous)
 * @param {Ext.data.Store} store
 * @param {String} id
 * @param {Object} params
 */
Ext.data.Store.prototype.nextPreviousResultSetOnClickHandler = function (store, id, params) {
    PTC.performance.startTimeGauge(store.jscaTableID);
    var grid = PTC.jca.table.Utils.getTable(store.jscaTableID);
    var jcaTableConfig = grid.jcaTableConfig;
    if (!PTC.jca.nextPreviousActions.validate(store.jscaTableID)) {
        return;
    }
    var pagingBar = grid.getBottomToolbar();
    var warningMsg = grid.getBottomToolbar().findById(store.jscaTableID + '_tablelvlmesg');
    if (warningMsg !== null) {
        warningMsg.hide();
    }
    var errorMsg = grid.getBottomToolbar().findById(store.jscaTableID + '_tablelvlmesg_Err');
    if (errorMsg !== null) {
        errorMsg.hide();
    }
    var fire = true;
    var offset = 0;
    var nxtLinkId = PTC.jca.nextPreviousActions.getNextLinkId(jcaTableConfig.tableID);
    if (id === nxtLinkId) {
        if (jcaTableConfig.pageOffset === undefined) {
            var titleBar = grid.getTopToolbar();
            titleBar.getComponent(grid.cancelBtnId).hide();
            offset = jcaTableConfig.pageSize;
        }
        else {
            if (store.moreData) {
                offset = jcaTableConfig.pageOffset + jcaTableConfig.pageLimit;
            }
            else {
                fire = false;
            }
        }
        pagingBar.items.items[1].show();
    }
    else {
        if (jcaTableConfig.pageOffset === undefined || jcaTableConfig.pageOffset === 0) {
            fire = false;
        }
        else {
            offset = jcaTableConfig.pageOffset - jcaTableConfig.pageLimit;
        }
    }
    if (fire) {
        store.baseParams.offset = offset;
        store.baseParams.tableId = jcaTableConfig.tableID;
        if (store.pagingSessionId !== undefined) {
            store.baseParams.PAGING_SESSION_ID = store.pagingSessionId;
        }
        store.moreData = false;
        store.load_complete = false;
        params = params || {};
        params = Ext.applyIf(params, grid.initRequestParams);
        PTC.jca.table.Utils.reload(jcaTableConfig.tableID, params, true);
    }
    PTC.performance.stopTimeGauge(store.jscaTableID, 'Empty Table Displayed', true, 1);
};

/**
 * Constructs the config object that represents the Actions dropdown for a table.
 * Also destroys the existing actions menu to ensure that only one exists per table.
 * @param {Ext.grid.GridPanel} gridPanel
 * @return {Array} an array of the items in the actions menu (empty array if no actions exist)
 */
PTC.jca.table.getActionsMenuConfig = function (gridPanel) {
    var toolbarActionsMenu = {};
    var menuItems = gridPanel.jcaTableConfig.toolbar;
    if (!menuItems) {
        return [];
    }
    toolbarActionsMenu.actionsId = gridPanel.getId() + "_toolbarActionsMenu";
    toolbarActionsMenu.defaultActionName = "";
    toolbarActionsMenu.items = [menuItems];
    // Set the label for actions toolbar menu.
    toolbarActionsMenu.items[0].text = bundleHandler.get('com.ptc.core.ui.componentRB.ACTIONS');
    toolbarActionsMenu.items[0].cls = 'actions-menu';
    var toolbarActionsMenuConfig = PTC.jca.ActionModelToMenubar(toolbarActionsMenu, gridPanel);
    if (Ext.getCmp(toolbarActionsMenu.items[0].id)) {
        // Don't allow 2 menus, after column lock view is recreated and 2 menus will appear.
        Ext.getCmp(toolbarActionsMenu.items[0].id).destroy();
    }
    return toolbarActionsMenuConfig.items;
};


/**
 * Get PreSelections config object
 * Also binds an event for data available in next chunk
 */
Ext.grid.GridPanel.prototype.getPreSelectionsConfig = function () {
    if (typeof this.populatePreSelectionsConfig === 'function') {
        var preSelecionObj = {
            oids:[],
            comparableFn:"PTC.jca.table.Utils.compareOid"
        };
        this.populatePreSelectionsConfig.call(this, preSelecionObj);
        var oids = preSelecionObj.oids;
        var customCompareFunc = preSelecionObj.comparableFn;
        var store = this.store;
        //whenever we get a row we see if we have to pre select it.
        if (this.jcaTableConfig.tree && !(PTC.jca.isAsync(store))) {
            //for tree there is a condition in TreeGrid.js to not to fire datachanged event if
            //record length is less than 2 so listening on load event
            store.on('load', store.selectPreSelectOids);
        } else {
            //for other async cases
            store.on('datachanged', store.selectPreSelectOids);
        }
        store.on('datachanged', store.selectPreSelectOids);
        var tableId = this.id;
        var matchedOids = [];
        if (typeof customCompareFunc === 'string') {
            var cmpFunction = PTC.util.convertStringToFunc(customCompareFunc);
            if (typeof cmpFunction === 'function') {
                preSelecionObj.comparableFn = cmpFunction;
                //put it in store,as i need it when i get next chunk
                store.preSelecionObj = preSelecionObj;
                //if rows available upfront then select it
                var rows = tableUtils.getTableRows(tableId);
                var selModel = this.getSelectionModel();
                if (rows && rows.items) {
                    var items = rows.items;
                    for (var i = 0, l = items.length; i < l; i++) {
                        var j = oids.length;
                        while (j--) {
                            //call comparator func defined and if true select row
                            if (store.selectPreselctedItem(items[i], oids[j], cmpFunction, selModel, i)) {
                                matchedOids.push(oids[j]);
                            }
                        }

                    }
                }
            }
        }
        if (matchedOids && matchedOids.length > 0) {
            //get the notMatched oids which would be processed further when corresponding row comes in the UI
            var notMatched = PTC.jca.table.Utils.getNotMatchedOids(matchedOids, oids);
            PTC.jca.addSelectionCheckbox(notMatched, tableId);
        } else {
            PTC.jca.addSelectionCheckbox(oids, tableId);
        }
    }
};


/**
 * Selects row when store is updated with data.
 * Also remove earlier representation of the row from hidden div
 */
Ext.data.Store.prototype._selectPreSelectOids = function () {
    var tableId = this.jscaTableID;
    var rows = tableUtils.getTableRows(tableId);
    var oids = this.preSelecionObj.oids;
    var cmpFunction = this.preSelecionObj.comparableFn;
    var grid = PTC.jca.table.Utils.getTable(tableId);
    var selModel = grid.getSelectionModel();
    if (rows && rows.items) {
        var items = rows.items;
        for (var i = 0, l = items.length; i < l; i++) {
            var j = oids.length;
            while (j--) {
                if (this.selectPreselctedItem(items[i], oids[j], cmpFunction, selModel, i)) {
                    //remove earlier representation of the row in the hidden div
                    var cbox = Ext.fly(oids[j]);
                    if (cbox) {
                        cbox.remove();
                    }
                }
            }

        }
    }
};

Ext.data.Store.prototype.selectPreSelectOids = PTC.util.delayAllCalls(Ext.data.Store.prototype._selectPreSelectOids, 200);

/**
 * If the row is to be preselected, does the selection and return true, else false
 *
 * @param {Ext.data.Record} item Record to check
 * @param {Array} oid pre-selection required oids
 * @param {Function} cmpFunction oid compare fuction
 * @param {Object} selModel the SelectionModel
 * @param {Object} rowIndex index of row to be preselected
 * @returns {boolean} true if the record is selected, else false
 */
Ext.data.Store.prototype.selectPreselctedItem = function(item, oid, cmpFunction, selModel, rowIndex) {
    if(!item || !oid || !cmpFunction || !selModel || rowIndex < 0) {
        return false;
    }
    if (item.preSelected !== true && cmpFunction.call(this, item, oid)) {
        selModel.selectRow(rowIndex, true);
        //SPR: 2201158 adding variable to avoid selecting again preselcted rows.
        item.preSelected = true;
        return true;
    } else {
        return false;
    }
};

/**
 * Calls method to add the table suggest toolbar when the configuration is populated.
 * @param {Ext.grid.GridPanel} gridPanel
 */
PTC.jca.WTablePanel.prototype.renderPickerToolbar = function (gridPanel) {
    var tableSuggestPickerConfig, toolbar;
    if (gridPanel.jcaTableConfig.tableSuggestPickerConfig) {
        tableSuggestPickerConfig = gridPanel.jcaTableConfig.tableSuggestPickerConfig;

        toolbar = new PTC.autosuggest.toolbar.SuggestToolbar(tableSuggestPickerConfig);
    }
};


/**
 * @function
 * Registers the PTC.jca.table.handleHiddenRows on the load event of the table store.
 * The event is registered as the first load event to be called. This event needs to
 * be filtered before it is rendered for performance and to prevent display issues.
 * 
 * @param {PTC.jca.WTablePanel} tablePanel
 * @listenerScope {Object} the scope to pass to the event handler
 */
PTC.jca.table.registerHiddenRowsHandler = function(tablePanel, listenerScope ) {
    
    var loadListeners = tablePanel.gridPanel.store.events.load.listeners;
    tablePanel.gridPanel.store.events.load.listeners = [{
        options : {},
        fireFn: function() {PTC.jca.table.handleHiddenRows(tablePanel);},
        fn: function() {PTC.jca.table.handleHiddenRows(tablePanel);},
        scope: listenerScope 
    }].concat(loadListeners);
};

/**
 * @function
 * Hides any rows marked with the rowHidden attribute using the store.filter
 * @param {PTC.jca.WTablePanel} tablePanel
 * @returns {boolean} true if rows were hidden
 */
PTC.jca.table.handleHiddenRows = function(tablePanel){
    var HIDDEN_ROW_DIV = 'PTC.jca.table.hiddenRowDiv_';
    //check for hidden div and clear
    var div = $(HIDDEN_ROW_DIV+tablePanel.id);
    if(div) {
        div.innerHTML = "";
    }
    var someRowsHidden = false;
    if (!tablePanel.gridPanel) {
        // Somehow this can be hit before the table is associated?
        return true;
    }
    var tableStore = tablePanel.gridPanel.store;
    if(!tableStore) {
        return true;
    }
    
    // filtering causes a repaint of the table, even if no rows were filtered.
    // only filtere is a row if found as hidden which is rare.
    if (tableStore.findExact('rowHidden', true) < 0) {
        return false;
    }

    // append hidden div
    if(!div) {
        div = document.createElement('div');
     	div.id = HIDDEN_ROW_DIV+tablePanel.id;
     	div.style.display = 'none';
     	getMainForm().appendChild(div);
    }
    var hiddenHTML = [];

    //SPR 4823507 When grid filter is enabled, hiddenRow is handled in PTC.jca.table.gridFilters.overideFilterImplementation.
    if(PTC.jca.table.gridFilters.isEnabled() !== true) {
       someRowsHidden = PTC.jca.table.findInTable.makeRowHidden(tableStore,hiddenHTML);
    }

    if (someRowsHidden) {
    	// append hiddenHTML to hidden div
    	div.innerHTML = hiddenHTML;
        if (tablePanel.selectable) {
            tablePanel.updateTitle();
            if(typeof tablePanel.gridPanel.updateSelCountMsg === 'function'){
                tablePanel.gridPanel.updateSelCountMsg();
            }
        }
    }
    return someRowsHidden;
};
/**
 * For other event listeners, cannot return false or else the event will stop firing
 * @param {Object} t
 */
PTC.jca.table.handleHiddenRowsEvent = function(t){
  PTC.jca.table.handleHiddenRows(t);
};

/**
 * Generates the html for an input field or hidden input field given the record.
 * @param {PTC.jca.WTablePanel} table
 * @param {Ext.data.Record} record
 * @returns {String} html
 */
PTC.jca.table.handleHiddenRowRenderer = function(table, record) {
    var html = [];
    if(record && record.data && record.fields && record.fields.keys) {
        var keys = record.fields.keys;
        keys.each(function(key) {
            var data = record.get(key);
            if(data && data.gui && data.renderer && typeof data.renderer === 'function') {
                var gui = data.gui;
                var renderer = data.renderer;
                // check if cell should be stored
                if(gui.name) {
                    html.push(renderer(table, {id:key}, record));
                }
                // check for hidden fields
                else if(gui.hiddenData && gui.hiddenData.hiddenFields) {
                    html.push(renderer(table, {id:key}, record));
                }
            }
        });
    }
    return html;
};


/**
 * Creates a paging bar for a table.
 * @param {Object} pagingConfig - the paging config
 * @param {boolean} chunkingEnabled - whether or not data chunking is enabled
 * @returns {PTC.jca.WTablePagingBar} the paging bar
 */
PTC.jca.WTablePagingBar = function(pagingConfig, chunkingEnabled, isTree){
    var pSize = isTree ? 5000 : pagingConfig.pageSize;
    if (chunkingEnabled) {
        Ext.apply(pagingConfig, new PTC.jca.DataSourceToolbar(pagingConfig));
        pagingConfig.mask.on('render', pagingConfig.dsMaskListener, this);
        Ext.apply(pagingConfig, {
            pageSize: pSize,
            displayInfo: false,
            items: [pagingConfig.mask, pagingConfig.cancelButton]
        });
    }
    PTC.jca.WTablePagingBar.superclass.constructor.call(this, pagingConfig);
};

PTC.onReady(function(){
    Ext.apply(Ext.Toolbar.prototype, bundleHandler.get('Ext_PagingToolbar_strings'));
});

/**
 * PTC.jca.WTablePagingBar extends Ext.PagingToolbar
 */
Ext.extend(PTC.jca.WTablePagingBar, Ext.Toolbar, PTC.jca.PagingBarFunctions);



/**
 * Convert action config to button config
 *
 * If there is button icon, hide text
 * if it is a right click multi select action do not hide text
 */
PTC.jca.ActionToButton = function(actionConfig, table, actionsMenuRequest){
    if (actionConfig) {
        if (actionConfig.html) {
            actionConfig.html = actionConfig.html.replace(/__SCRIPT__/g, "<script>");
            actionConfig.html = actionConfig.html.replace(/__CLOSE_SCRIPT__/g, "</script>");
            // the javascript may try to reference something in the toolbar panel, need to yield to the toolbar rendere and then evalscripts.
            actionConfig.html.evalScripts.defer(100, actionConfig.html);
        }
        if (actionConfig.icon) {
            if (actionConfig.text) {
                if (actionConfig.toolBarDesc) {
                    // if we're showing toolbar labels, set the icon to display on top of the text.
                    actionConfig.iconAlign = "top";
                }
                else {
                    // hide text when icon is showing and the label preference is not set
                    actionConfig.label = actionConfig.text;
                    if(!actionsMenuRequest){
                        actionConfig.text = null;
                    }
                }
            }

            actionConfig.iconCls = 'blist';
        } // end if icon
        if (actionConfig.handler !== undefined) {
            PTC.jca.setActionHandler(actionConfig, table);
        }

    } // end if actionConfig
    return actionConfig;
};

/**
 * Convert action model config to toolbar config
 *
 * If there is button icon, hide button text,if it is a right click multi select action do not hide text
 */
PTC.jca.ActionModelToToolbar = function(actionModel, table, actionsMenuRequest){
    var buttonsFunc = function(item){
        item = PTC.jca.ActionToButton(item, table,actionsMenuRequest);
        // convert text tooltip into Quicktip spec to apply css class.
        item.tooltip = {
            text: item.tooltip,
            cls: "wctip"
        };
    };
    PTC.actionModel.walkActionModelAndApply(actionModel, buttonsFunc);
    buttonsFunc = null;
    return actionModel;
};

/**
 * Convert action model config to menubar
 */
PTC.jca.ActionModelToMenubar = function(actionModel, table){
    PTC.menu.ActionModelToMenu(actionModel);
    if (actionModel.items && actionModel.items[0]) {
         actionModel.items[0].id += "__" + table.id;
    }

    var buttonMenuFunc = function(item){
        PTC.jca.setActionHandler(item, table);
    };
    var idfunc = function(item){
        if (item.id) {
            item.id += "__" + table.id;
        }
        else if (item.actionID) {
            item.id = item.actionID + "__" + table.id;
        }
    };
    PTC.actionModel.walkActionModelAndApply(actionModel, buttonMenuFunc);
    //Propogate the id to all sub menus and items to avoid duplicating ids.
    // skips jstables (based on sensing the jsttd object in the config)
    if (!(PTC.jca.table.Utils.isjsttd(table))) {
        PTC.actionModel.walkActionModelAndApplyToAll(actionModel, idfunc);
    }
    buttonMenuFunc = null;
    idfunc = null;
    return actionModel;
};

PTC.jca.setActionHandler = function(item, container){
    item._handler = item.handler;
    item.handler = function(target, event){
        event.jcacontainer = container;
        target.jcacontainer = container;
        var ret = false;
        try{
            ret = item._handler(target, event, container);
        }finally{
            //reset
            event.jcacontainer = undefined;
            target.jcacontainer = undefined;
        }
        return ret;
    };
};

/**
 * Given an ExtToolbar this method will loop through all the children and
 * for any Menu it finds it will set the menu's ignoreParentClicks attribute to true
 *
 * This method doesn't recurse through for menus within menus.
 */
PTC.jca.setIgnoreParentClick = function(toolBar) {
    try {
        var size = toolBar.items.items.size();
        for (var i = 0; i < size; i++) {
            var theItem = toolBar.items.items[i];
            if (theItem.menu) {
                theItem.menu.ignoreParentClicks = true;
            }
        }
    } catch (e) {
        //do nothing we were unable to ignore parent clicks but that is minor so just keep going.
    }
};

/**
 * Handle combo-box select action
 */
PTC.jca.ComboActionHandler = function(theCombo, viewRecord, viewIndex){
    var viewAction = viewRecord.get('handler');
    //only if a function
    if (typeof viewAction === 'function') {
        viewAction();
    }
};


/**
 *
 * To clear searchTerm value and selected items in Client-Session using tableId.
 * @param {tableId} tableId
 */
PTC.jca.clearStickyFromSession = function (tableId){
    var gridPanel = Ext.getCmp(tableId);
    var selectedOnlyItem = Ext.getCmp(PTC.jca.table.getWTablePanelID(tableId) + '.selectedOnlyViewItem');
    if (selectedOnlyItem && gridPanel.selectedOnlyChecked) {
        //SPR 2187765
        // To clear View selected Only
        selectedOnlyItem.setChecked(false);
        gridPanel.store.clearFilter(false);

        gridPanel.selectedOnlyChecked = false;
        PTC.jca.table.clearObjectFromSession(tableId, selectedOnlyItem.id);
    }

    var searchField = Ext.getCmp(PTC.jca.table.findInTable.getSearchInListTextBoxName(tableId));
    if (searchField) {
       PTC.jca.table.clearObjectFromSession(tableId, "searchInListTextBox");
    }
};

PTC.jca.ConfirmViewChangeIgnoreSelections = false;

/**
 * Handle the view change for a table.  If there are any selections for the table's store,
 * confirm that selections will be lost before changing the view
 * @param {Object} theCombo the ComboBox
 * @param {Object} viewRecord the data record returned from the underlying store
 * @param {Object} viewIndex the index of the selected item in the dropdown list
 */
PTC.jca.ConfirmViewChange = function(theCombo, viewRecord, viewIndex){
    var grid = this.gridPanel;
    var store = grid.getStore();
    if(viewRecord.id === PTC.action.SEPARATOR_KEY) {
        return false;
    } else if(viewRecord.id === 'Customize') {
        var gridManager = grid.getStateManager();
        var state = gridManager.getState();
        if (!state.activeViewInfo) {
            //save current active view update count
            var activeViewInfo_config = PTC.jca.table.getActiveViewInfo(grid);
            if (activeViewInfo_config) {
                state.activeViewInfo = activeViewInfo_config;
                gridManager.storeState(state);
            }
        }
        //if its Customize option, then collapse the combo box and fire select event
        //this special handling is required otherwise, the combo box selection will be Customize
        //which is not the current active table view and cause issue as in SPR 2158203
        theCombo.collapse();
        theCombo.fireEvent('select', theCombo, viewRecord, viewIndex);
        return false;
    }

    var isTableFiltered = PTC.jca.table.findInTable.isTableFiltered(grid);
    var confirmMessage = null;
    if (PTC.jca.ConfirmViewChangeIgnoreSelections  === false && tableUtils.getTableSelectedRowsCountById(grid.getId()) > 0) {
        confirmMessage = isTableFiltered ?
            "com.ptc.netmarkets.util.utilResource.CONFIRM_VIEW_CHANGE_WITH_SELECTIONS_FILTER"
            : "com.ptc.netmarkets.util.utilResource.CONFIRM_VIEW_CHANGE";
    } else {
        if (isTableFiltered) {
            // only filter message
            confirmMessage = "com.ptc.netmarkets.util.utilResource.CONFIRM_VIEW_CHANGE_WITH_FILTER";
        }

        //PTC EXT OVERRIDE
        var gridFilters = PTC.jca.table.getObjectFromSession(store.jscaTableID, "gridFilters");
        if ((gridFilters)&&(gridFilters!="[]")) {
            // only filter message
            confirmMessage = "com.ptc.netmarkets.util.utilResource.CONFIRM_VIEW_CHANGE_WITH_FILTER";
        }
    }

    if (confirmMessage !== null) {
        if (!JCAConfirm(null, confirmMessage)) {
            theCombo.collapse();
            return false;
        }
    }

    var tableId = grid.getId();

    //PTC EXT OVERRIDE
    //clearing GridFilters parameter
    PTC.jca.table.setObjectToSession(tableId, "gridFilters", null);

    //To clear searchTerm value and selected items in Client-Session
    PTC.jca.clearStickyFromSession(tableId);

    // clearing the sorting info
   
    delete store.sortInfo;
    /*
     * Clearing the ServerSide Search In List. 
     */
    if (PTC.jca.table.findInTable.isTableFilteredOnServer(grid)) {
        PTC.jca.table.findInTable.deleteSearchTermServerSide(store);
    }
    
    grid.fireEvent('sortchange', grid);
    grid.fireEvent('clearSearchInList', grid, true);
    PTC.jca.previousMultiColumnSortString = PTC.jca.getMultiColumnSortString(tableId);
    PTC.jca.clearMultiColumnSortAndGroupingString(tableId);
    PTC.jca.clearGroupingChangedByClient(tableId);
    PTC.jca.table.stickiness.clearTableStickiness(tableId);
    grid.clearStickyConfig();
    //clearing Locking stickiness on view change.
    PTC.jca.table.stickiness.clearLockingStickiness(tableId);

    //Clear Hidden Div for Checkboxes
    if(PTC.jca.ConfirmViewChangeIgnoreSelections === false) {
        jsca.unSelectHiddenCheckboxes(tableId);
    }
    return true;
};

/**
 * Event handler for keypress event on views combo box. It avoids the default browser handling if
 * user enters an non-existing view name or same current view again
 *
 * @param {Ext.form.ComboBox} textField the view combobox textField
 * @param {Ext.EventObject} e
 */
PTC.jca.table.viewChangeValidate = function(textField, e){
    var keyValue = e.getKey();
    if(keyValue === e.ENTER){
        var changedView = textField.isDirty();
        if(changedView === true){
            var views = textField.getStore();
            var validViewValue = false;
            var currentValue = textField.getRawValue();
            var noOfViews = views.getCount();
            for(var ia = 0; ia < noOfViews; ia++) {
                var record = views.getAt(ia);
                var viewName = record.get('text');
                if(viewName === currentValue){
                     validViewValue = true;
                     break;
                }
            }

            if(validViewValue !== true){
                // wrong view name specified, ignore the event and present an alert
                var currentValueArr = [];
                currentValueArr.push(currentValue);
                var defaultActionName = textField.initialConfig.defaultActionName;
                if (defaultActionName) {
                    textField.setValue(defaultActionName);
                }
                e.preventDefault();
                JCAAlert('com.ptc.netmarkets.util.utilResource.VIEW_NOT_FOUND_ALERT', null, currentValueArr);
             }
         } else {
             // ignore the event if the view value has not changed
             e.preventDefault();
         }
     }
};

/**
 * Convert action model config to combo-box
 */
PTC.jca.ActionModelToComboBox = function(actionModel){
    var cbStore;
    if (!actionModel || !actionModel.items) {
        cbStore = new Ext.data.JsonStore({});
    }
    else {
        cbStore = new Ext.data.JsonStore({
        fields: ['text', 'handler', 'tooltip'],
        autoLoad: true,
        data: actionModel,
        root: 'items'
    });
    }
    if (actionModel.tooltip) {
        actionModel.title = actionModel.tooltip;
    }
    actionModel.store = cbStore;
    actionModel.displayField = 'text';
    actionModel.typeAhead = true;
    actionModel.mode = 'local';
    actionModel.triggerAction = 'all';
    actionModel.selectOnFocus = true;
    actionModel.resizable = true;
    actionModel.forceSelection = true;
    actionModel.valueNotFoundText = 'Not Found';
    if (actionModel.defaultActionName) {
        actionModel.value = actionModel.defaultActionName;
    }
    actionModel.listeners = {
        select: PTC.jca.ComboActionHandler
    };

    // This template renders each item in the combo box, giving each of them a class, name, and tooltip.
    actionModel.tpl = new Ext.XTemplate([
        '<tpl for=".">',
            '<div ext:qtip="{tooltip}" class="x-combo-list-item">{text}</div>',
        '</tpl>'
    ]);
    return actionModel;
};

/**
 * Common functions for table and tree paging bars.
 */
PTC.jca.PagingBarFunctions = {
    // if we can change the server code to not need acquire = 'row' on paging actions, this customization can be removed.
    doLoad: function(start){
        // Ext3 is changing to use this.getParams in final release.
        var domEl;
        if (this.getEl && this.getEl()) {
           domEl = this.getEl.dom;
        }
        var o = Form.serialize(getMainForm(domEl), true);
        o.acquire = 'row';
        var pn = this.getParams();
        o.tableID = this.store.jscaTableID;

        o[pn.start] = start;
        o[pn.limit] = this.pageSize;
        var table;
        if(o.tableID){
            table = tableUtils.getTable(o.tableID);
        }
        this.store.remoteSort = PTC.jca.isRemoteSort(this.store,table);// may be can be directly set to true
        if (this.fireEvent('beforechange', this, o) !== false) {
            this.store.load({
                params: o
            });
        }
    },
    /**
     * This method will show only the message count and will hide others component on table footer like clearacross message icon
     * and paging toolbar.
     */
    showSelCountMsgOnly: function(){
        var extItems = this.items.items;
        for (var iti = 0; iti < extItems.length; iti++) {
            extItems[iti].hide();
        }
        this.getComponent("selectionMessageCount").show();
    },
    /**
     * This method will show all standard paging bar and others icons.
     */
    showPagingBar: function(){
        var extItems = this.items.items;
        for (var iti = 0; iti < extItems.length - 1; iti++) {
            extItems[iti].show();
        }
    }
};


/**		
 * Check whether the value provided for the new view name is a duplicate of the existing view names
 * @param {Object} name field
 * @param {Object} viewNames
 * @return true if found a duplicate, else false
 *@private
 */
PTC.jca.table._isDuplicateViewName = function(nameField, viewNames){
    var val = nameField.getValue().strip();
    var encodeValLC = PTC.util.HTMLEncoder.encodeForHTMLContent(val).toLowerCase();
    var dupFound = false;
    viewNames.each(function(item) {
        if (item.toLowerCase() === encodeValLC) {
            dupFound = true;
            return false; //terminate loop
        }
        return true;
    });
    return dupFound;
};

/**
 * Confirm the view change, in case some user actions will be lost
 * @param {Object} tableID
 */
PTC.jca.table.confirmAdhocView = function(tableID){

    /**
    * Common variables used in multiple locations of this function
    */
    var tPanel = Ext.getCmp(PTC.jca.table.getWTablePanelID(tableID));
    var windowId = 'saveAsViewWindow'; // used by cancel and passed in to create the window

    /**
    * Logic to create the OKButton
    */
    var OKButtonText = bundleHandler.get('com.ptc.core.ui.navigationRB.okDialogButton');
    var duplicateErrorMessage = bundleHandler.get('com.ptc.core.ui.navigationRB.SAVE_AS_VIEW_DUPLICATE_NAME');
    var viewNames = [];
    var views = tPanel.getViewsCombo().store;
    for (var ia = 0; ia < views.getCount(); ia++) {
        var record = views.getAt(ia);
        viewNames.push(record.get('text'));
    }
    var OKButton = new Ext.Button({
        text: OKButtonText,
        formBind: true,
        handler: function(button, event) {
            var nameField = Ext.getCmp('newName');
            var dupFound = PTC.jca.table._isDuplicateViewName(nameField, viewNames);
            // don't allow a tab to be renamed to the name of another tab
            if (dupFound) {
                nameField.markInvalid(duplicateErrorMessage);
            } else {
                PTC.jca.table.saveAsViewCallback(tableID, nameField.getValue().strip());
                Ext.getCmp(windowId).close();
            }
         }
    });

    /**
    * Logic to create the cancelButton
    */
    var cancelButtonText = bundleHandler.get('com.ptc.core.ui.navigationRB.cancelDialogButton');
    var cancelButton = new Ext.Button({
        text: cancelButtonText,
        handler: function(button, event) {
            PTC.jca.table.resetToDefaultView(tPanel);
            Ext.getCmp(windowId).close();
        }
    });

    /**
    * Logic to create light box window/form
    */
    var preKey = 'SAVE_AS_VIEW';
    var formId = 'saveAsViewForm';
    var defaultFieldValue = getUnescapedText(PTC.jca.table._getUniqueViewName(viewNames));
    var win = PTC.lightbox.createSimpleLightBoxWindowAndForm(windowId, formId, defaultFieldValue, preKey, OKButton, cancelButton);

    /**
    * Show the light box window
    */
    win.show();
};

/**
 * Saves the table column changes to current active view
 *
 * @param {String} tableID
 * @param {boolean} saveButtonClicked
 */
PTC.jca.table.saveCurrentView = function(tableID, saveButtonClicked){
    var activeView, tPanel = Ext.getCmp(PTC.jca.table.getWTablePanelID(tableID));
    var viewsCombo = tPanel.getViewsCombo();
    if(saveButtonClicked === true){//
        activeView = viewsCombo.value || viewsCombo.startValue || viewsCombo.originalValue;
    } else {
        activeView = viewsCombo.startValue || viewsCombo.originalValue;
    }
    PTC.jca.table.saveAsViewCallback(tableID, activeView, true);
};

PTC.jca.table.resetToDefaultView = function (tPanel) {
        var defaultActionName = tPanel.getViewsCombo().initialConfig.defaultActionName;
        if (defaultActionName) {
            tPanel.getViewsCombo().setValue(defaultActionName);
        }
};

/* ALL_SECURITY_LABEL_COLUMNS handling: want to ensure ALL_SECURITY_LABELS remains within the table view manager list of columns
 * @private
 * @param {Object} table
*/
PTC.jca.table._saveAsViewCallback_handleSL = function(table){
    var columnAttributes;
    if(table.jcaTableConfig.aslcV === true){
        JCAAlert ("com.ptc.core.security.securityResource.JCA_TABLE_VIEW_MANAGER_SECURITY_LABELS_ALTERED");
        columnAttributes = {origId:'ALL_SECURITY_LABELS',
                width:0,
                hidden:false};
    }
    return columnAttributes;
};
/**
 * handle the sort related changes when we are calling save as view.
 * 
 * @param{Object} table
 * @param{String} sort string
 * @return {String} sort string with organization id
 */
PTC.jca.table.saveAsViewCallbackSortStringHandler = function (table, sort_info) {

    //Viewchange event removes the sort info. We need this sort info in case of saveAsViewCallback
    PTC.jca.setMultiColumnSortString(table.id, sort_info);
    PTC.jca.syncStoreSortInfo(table.store, sort_info);

    var sort_info_array = sort_info.split(PTC.jca.SORT_DELIMITER);
    var clientSortString_withOrgID = '';
    for ( var i = 0; i < sort_info_array.length - 1; i += 2) {
        var sinfo = sort_info_array[i];
        if(PTC.isDefinedAndNotEmptyString(sinfo)) {
            clientSortString_withOrgID += PTC.jca.getServerIdFromJSColumnId(table, sinfo) + PTC.jca.SORT_DELIMITER +
            sort_info_array[i+1] + PTC.jca.SORT_DELIMITER;
        }
    }
    return clientSortString_withOrgID;
};

/**
 * Save the current table changes to the table view.
 *
 * @param {String} tableID table id
 * @param {String} newViewName table view name
 * @param {boolean} modifyCurrentView true in case the function is called for current table view
 */
PTC.jca.table.saveAsViewCallback = function(tableID, newViewName, modifyCurrentView) {
        var tPanel = Ext.getCmp(PTC.jca.table.getWTablePanelID(tableID));
        var table = PTC.jca.table.Utils.getTable(tableID);
        // To fire datarendered event which in turn does version sorting.
        if(PTC.jca.isVersionField(table.store.groupField)) {
             table.firedDataRenderedEvent = false;
        }
        //Get active view's oid.
        var viewsCombo = tPanel.getViewsCombo();
        var activeViewOid = viewsCombo.activeViewOid;

        // set hidden fields
        var mform = getMainForm(tableID);
        var elemsToRemove = [];
        try {
            elemsToRemove.push(appendFormHiddenInput(mform, 'groupBy', table.store.groupField));
            elemsToRemove.push(appendFormHiddenInput(mform, 'vName', newViewName));
            elemsToRemove.push(appendFormHiddenInput(mform, 'vOid', activeViewOid));

        var colModel = tPanel.getColumnModel();
        var sCols = [];
        var sColsIndex = 0;
        var cmConfig = colModel.config;
            var lockedColumnIndex = -1;
        for (var colix = 0; colix < cmConfig.length; colix++) {
            var columnConfig = cmConfig[colix];
            if (columnConfig.id != 'checker' && columnConfig.id != 'stretcher') {
                var columnAttributes = {origId:columnConfig.origId,
                                width:columnConfig.width,
                                hidden:colModel.isHidden(colix),
                                displayName:columnConfig.displayName};
                sCols[sColsIndex] = {ColumnObject: columnAttributes};
                    if(columnConfig.locked === true){
                        lockedColumnIndex = colix;
                    }
                sColsIndex++;
            }
        }
        var slColumnAttributes = PTC.jca.table._saveAsViewCallback_handleSL(table);
        if(slColumnAttributes !== undefined){
            sCols[sColsIndex] = {ColumnObject: slColumnAttributes};
            sColsIndex++;
        }

            elemsToRemove.push(appendFormHiddenInput(mform, 'columns_set', 'true'));
            elemsToRemove.push(appendFormHiddenInput(mform, 'columnConfigInformation', Ext.util.JSON.encode(sCols)));

            // use previous sort string because this sort string value has been saved specifically for this use
            if(PTC.isDefinedAndNotEmptyString(PTC.jca.previousMultiColumnSortString)) {
                var clientSortString_withOrgID = PTC.jca.table.saveAsViewCallbackSortStringHandler(table, PTC.jca.previousMultiColumnSortString);
                elemsToRemove.push(appendFormHiddenInput(mform, 'sortInfo', clientSortString_withOrgID));
            }
            elemsToRemove.push(appendFormHiddenInput(mform, 'freezeColumn', lockedColumnIndex));

            var viewJavascriptUrl;
            if(modifyCurrentView === true){ //save view action
                viewJavascriptUrl = document.getElementById('saveViewJavascriptUrl_' + tableUtils.getFormattedTableId(tableID));
            }else { //save as view action
                viewJavascriptUrl = document.getElementById('saveAsViewJavascriptUrl_' + tableUtils.getFormattedTableId(tableID));
            }
            if(viewJavascriptUrl){
                PTC.jslint.foundEvalReservedWord(viewJavascriptUrl.value);
            }
        } finally {
            removeFormElements(elemsToRemove);
        }
};

/**
 * Handles the save as view action.
 * After new view is saved, this will dynamically add the view to the combo box and select that view.
 * @param {String} tableId, the table id corresponding to the table for which the new view has been saved.
 * @param {String} viewName, the view that was just saved.
 */
PTC.jca.table.saveAsViewResponseHandler = function(tableId, viewName, viewOid) {
    var viewsCombo = PTC.jca.table.Utils.getTableViewComboBox(tableId);
    var currentView = viewsCombo.startValue || viewsCombo.originalValue || viewsCombo.value;
    var decoded_viewname  = PTC.search.decodeForHTMLContent(viewName);
    if(currentView !== decoded_viewname){ // no need to insert the record in case of save view
    var adhocViewRecord = new Ext.data.Record({
        text: viewName,
        tooltip: viewName
    });

        // we are clearing the views filter now to bring back the save view action to the view list
        if(viewsCombo.store.isFiltered()){
            viewsCombo.store.clearFilter();
        }
        var index = viewsCombo.store.data.length;
        for (var i = 0; i < index; i++){
            if(viewsCombo.store.data.items[i].data.actionID === "separator"){
                index = i;
                break;
            }
        }
        //Newly created view is added just before separator
        viewsCombo.store.insert(index,adhocViewRecord);
        var saveButton = Ext.getCmp(tableId + '_saveView');
        if(!saveButton.isVisible()){
           saveButton.setVisible(true);
        }
     }
    // Set the text in the combo box input to the new view name.
    viewsCombo.setValue(viewName);
    viewsCombo.startValue = decoded_viewname;//startValue also needs to be reset to the new value or duplicates will be added to views combo list
    if (viewOid && currentView !== decoded_viewname) {
        viewsCombo.activeViewOid = viewOid;
    }
};

/**
 * Custom toolbar layout extension so the large toolbar buttons work with Ext's 'more' toolbar.
 * @cfg {String} tableId The id for the table that contains this toolbar.
 */
PTC.jca.table.ToolbarLayout = Ext.extend(Ext.layout.ToolbarLayout, {
    
    /**
     * Private method to register _runToolbarLayout method on table height or width change
     * @param {GridPanel} table
     */
    _registerRunToolbarLayout: function (table) {
        this._runToolbarLayout = PTC.util.delayAllCalls(this._runToolbarLayout, 10);
        var _runToolbarLayoutDelegate = this._runToolbarLayout.createDelegate(this, [this]);

        table.on('resize', _runToolbarLayoutDelegate);
        //When table resizes only by width many times is just last column width change. As a result resize event 
        //doesnt get fire so registering against the widthchange event also
        if(table.colModel) {
            table.colModel.on('widthchange', _runToolbarLayoutDelegate);
        }
    },
    
    /**
     * private method to explicitly call run layout
     */
    _runToolbarLayout: function(toobarLayout) {
        toobarLayout.runLayout();
    },

    /**
     * @override
     * @name PTC.jca.table.ToolbarLayout.constructor
     */
    constructor: function(config) {
        config = config || {};
        PTC.jca.table.ToolbarLayout.superclass.constructor.call(this, config);
        this.tableId = config.tableId; // Table may not exist at this point, so just store the id.
        //When we change the width of column, we need to call the run toolbarlayout
        var table = Ext.getCmp(config.tableId);        
       
         if(table){
             this._registerRunToolbarLayout(table);
         }else {
             Ext.ComponentMgr.onAvailable(this.tableId, function(table) {
                 this._registerRunToolbarLayout(table);
             });
         }
     },

     /**
     * @override
     * Insert a 'moreBtn' button on the original toolbar, and create a new hidden toolbar underneath
     * that will be shown upon clicking that button. The new toolbar will contain all the action
     * items that could not fit in the original toolbar.
     * @name PTC.jca.table.ToolbarLayout.initMore
     */
    initMore: function() {
        if (!this.moreBtn) {
            if (Ext.isEmpty(this.table)) {
                // Since this function is only called after layout, we can assume the table has been created.
                this.table = Ext.getCmp(this.tableId);
            }
            this.moreToolbar = new Ext.Toolbar({
                id : this.tableId + ".moreToolbar",
                hidden : true,
                renderTo : this.table.tbar//This will take care of rendering moretoolbar as a unit of tbar
                // If needed, can add PTC.jca.table.ToolbarLayout to this new toolbar.
                // That will recursively allow as many toolbars to be created as necessary.
                //layout: new PTC.jca.table.ToolbarLayout(this.tableId)
            });
            // Add all the overflow items to the new toolbar.
            var len = this.hiddenItems.length;
            // Keep track of toolbar item heights, so the new toolbar can be sized.
            var maxChildHeight = 0;
            for (var i = len - 1; i >= 0; i--) {
                var item = this.hiddenItems[i];
                this.container.remove(item, false/*don't autodestroy*/);
                // Insert at 0th position.
                this.moreToolbar.insert(0, item);
                this.unhideItem(item);
                // Tell the layout that the item is no longer hidden (off screen).
                maxChildHeight = Ext.max([maxChildHeight, item.getHeight()]);
            }
            // Right-align components in the new toolbar.
            this.moreToolbar.insert(0, '->');
            // Size the new toolbar appropriately.
            this.moreToolbar.setHeight(maxChildHeight + 5/*buffer*/);

            // Create the 'moreBtn' button that will be added to the original toolbar.
            this.moreBtn = new Ext.Button({
                iconCls : 'x-toolbar-more-icon',
                cls : 'x-toolbar-more',
                handler : this.moreButtonHandler,
                ownerCt : this.container,
                table : this.table,
                moreToolbar : this.moreToolbar // For use in moreButtonHandler.
            });

            // Render the 'moreBtn' button at the END of the extras section in the original toolbar
            var position = this.extrasTr.childNodes ? this.extrasTr.childNodes.length : 0;
            var td = this.insertCell(this.moreBtn, this.extrasTr, position);
            this.moreBtn.render(td);
            this.table.on('beforedestroy', this.destroyMoreToolbar);
            var resizeFn = this.syncSize, toolbarLayout = this;
            if (!resizeFn) {
                resizeFn = function() {
                    if (!toolbarLayout._resizeMoreTask) {
                        toolbarLayout._resizeMoreTask = new Ext.util.DelayedTask(toolbarLayout.moreToolbarResizeListener);
                    }
                    toolbarLayout._resizeMoreTask.delay(10, null, null, [toolbarLayout /* toolbarLayout */ ]);
                };
            }
            this.table.on('resize', resizeFn);
          //When table resizes only by width many times is just last column width change. As a result resize event 
            //doesnt get fire so registering against the widthchange event
            if(this.table.colModel) {
                this.table.colModel.on('widthchange', resizeFn);
            }
        } else if (this.hiddenItems) {
            var hLen = this.hiddenItems.length;
            // preservce the oder of the items by iterating backwards and inserting at the 0th position
            for (var j = hLen - 1; j >= 0; j--) {
                var hitem = this.hiddenItems[j];
                // Insert at 0th position.
                this.moreToolbar.insert(0, hitem);
                if (this.remove) {
                    this.remove(hitem, false);
                } else {
                    this.container.remove(hitem, false);
                }
            }
            while (this.hiddenItems.length > 0) {
                this.unhideItem(this.hiddenItems[this.hiddenItems.length - 1]);
            }
        }
    },

    /**
     * Listens for table 'resize' event to re-distribute all toolbar items/buttons
     * based on table width into the regular table toolbar and the hidden more toolbar
     */ 
     moreToolbarResizeListener: function(toolbarLayout) {
        var toolbar = toolbarLayout.container;
        var moreToolbar = toolbarLayout.moreToolbar;
        var moreToolbarItems = moreToolbar.items.items || [];
        // copy toolbar and moreToolbar items to hiddenArray in order to iterate over them
        toolbarLayout.hiddenItems = (toolbar.items.items || []).concat(moreToolbarItems);
        toolbar.items.addAll(moreToolbarItems);
        moreToolbar.items.clear();
        // show moreToolbar in order to get correct width of moreToolbar items
        Ext.fly(moreToolbar.id).removeClass('x-hide-display');
        var layoutTarget = toolbar.getLayoutTarget();
        var len = toolbarLayout.hiddenItems.length, item, triggerWidth = toolbarLayout.triggerWidth || 0;
        var loopWidth = 0, clipWidth = layoutTarget.dom.clientWidth - triggerWidth;
        var searchInListId = toolbarLayout.tableId + '.searchInListLoadingWheel';
        var selectedOnlyId = toolbarLayout.tableId + '_WTablePanel_selectedOnlyMenu';
        var fillInserted = false;
        var maxChildHeight = 0;
        for (var i = 0; i < len; i++) {
            item = toolbarLayout.hiddenItems[i];
            if (!item.isFill) {
                // starting with .searchInListLoadingWheel the items in the toolbar should be right aligned
                if (!fillInserted && (item.id === searchInListId || item.id === selectedOnlyId || item.iconCls === "helpButton")) {
                    // add right align flag
                    toolbar.add('->');
                    fillInserted = true;
                }
                loopWidth += toolbarLayout.getItemWidth(item);
                if (loopWidth > clipWidth) {
                    moreToolbar.insert(moreToolbar.items.length, item);
                    // remeber the maximum height of all items
                    maxChildHeight = Ext.max([maxChildHeight, item.getHeight()]);
                    toolbar.remove(item, false);
                }
                if (fillInserted) {
                    // if we right aligning the items, the items should be added after '->'
                    // re-insert the item into the toolbar items array after the '->' comp
                    var c = toolbar.items.remove(item);
                    if (c) {
                        toolbar.items.add(item);
                    }
                }
            } else {
                // remove fills
                toolbar.remove(item, false);
            }
        }
        // Size the new toolbar height appropriately.
        moreToolbar.setHeight(maxChildHeight + 5/*buffer*/);

        // hide moreToolbar
        Ext.fly(moreToolbar.id).addClass('x-hide-display');
        toolbarLayout.hiddenItems = [];
        var hasHidden = moreToolbar.items.length !== 0;
        // right alight moreToolbar items
        moreToolbar.insert(0, '->');
        if (hasHidden) {
            toolbarLayout.moreBtn.show();
        } else {
            toolbarLayout.moreBtn.hide();
        }
        // run layout to refresh toolbar
        toolbarLayout.runLayout();
        moreToolbar.layout.layout();
    },

    /**
     * Handles the 'more' button click, by showing or hiding the extra toolbar.
     * @name PTC.jca.table.ToolbarLayout.moreButtonHandler
     * @param {Ext.Button} button
     * @param {Ext.EventObject} e
     */
    moreButtonHandler: function(button, e) {
        var moreToolbar = button.moreToolbar;
        var csize = this.table.getGridEl().getSize(true);
        var hdHeight = this.table.view.mainHd.getHeight();
        if (moreToolbar.hidden) {
            moreToolbar.show();
            hdHeight= hdHeight+moreToolbar.getHeight();
        } else {
            moreToolbar.hide();
        }
    },

    destroyMoreToolbar: function(){
        this.table = undefined;
        Ext.destroy(this.moreToolbar, this.more);
    }
});



