/**
 * Whether loadMask can be hidden on parent. If any of the record's parent id match that of the parent, return true
 * @private
 * @param {Array} recs is an array of Ext.data.Record or an array of row uniqueIds
 * @param {Ext.data.Record} parent
 * @param {Object} store - Existing DataStore to be used
 * @return {Boolean} true if LoadMask can be hide, else false
 */
PTC.jca.tree._canHideLoadMask = function(recs, parent, store){
    var hide = false;
    recs.forEach( function(rec) {
        if(rec){
            if (typeof rec === "string" || rec instanceof String ){
                rec = PTC.jca.table.Utils.getRecordByUniqueIdentifier(store, rec);
            }
            if(rec.get('_parent') === parent.id){
                hide = true;
                return false;
            }
        }
    });
    return hide;
};

/**
 * Load mask for expand action
 * @param {Ext.data.Record} rc
 */
PTC.jca.tree.expandLoadMask = function(store,rc){
    //Show loading indicator on expansion
    var tableCmp = Ext.getCmp(this.baseParams.tableID);
    if (tableCmp) {
        var view = tableCmp.getView();
        if (view) {
            try {
                var rcIndex = this.indexOf(rc);
                if (rcIndex !== -1) {
                    var rowEle = view.getRow(rcIndex);
                    if (rowEle) {
                        var maskEle = Ext.fly(rowEle).child('.ux-maximgb-tg-elbow-active');// Target Element which is masked by indicator
                        if (maskEle) {
                            var treeNodeMask = new Ext.LoadMask(maskEle, {
                                msg: "",
                                msgCls: "treeNodeMask"
                            });
                            treeNodeMask.show();
                            if (this.isLoadedNode(rc)) {
                                treeNodeMask.hide(); //Hide indicator when node is already loaded in store.
                            }
                            else {
                                // Listener to unmask the loading indicator.
                                var ln = function(store, recs, options) {
                                    if(PTC.jca.tree._canHideLoadMask(recs, rc, store)){
                                        //Unmask loading indicator
                                        treeNodeMask.hide();

                                        //Remove +/- norgie if there are no children for expanded node.
                                        if(this.getNodeChildrenCount(rc) === 0) {
                                            PTC.jca.TreeGrid.removeNorgie(store, null, rc);
                                        }
                                    }
                                 };
                                 // Register a listener to unmask the loading indicator.
                                 this.on({
                                    "load" : ln,
                                    "unmaskExpandNode": ln,
                                    scope: this,
                                    options :{single: true}
                                 });
                            }
                        }
                    }
                }
            }
            catch (e) {
                jsca.log(e);
            }
        }
    }
    tableCmp = null;
    view = null;
    rowEle = null;
    maskEle = null;
};
/**
 * PTC.jca.TableGrid.GroupingView extends and overrides Ext.grid.GroupingView
 * PTC EXT OVERRIDE
 */
Ext.extend(PTC.jca.TreeGrid, Ext.ux.maximgb.tg.GridPanel);

PTC.jca.TreeGrid.prototype.initComponent = function(){
    PTC.jca.TreeGrid.superclass.initComponent.apply(this, arguments);
    if (isWizardWindow()) {
        // because the listeners are only added in wizard to submit the table data, there is no need to
        // add the document listeners to save the data.   This improves performance by not haveing some many broad listeners
        this.domChangeEventListener = PTC.wizard.saveTableData.domChangeEventListener;
        this.on('renderTableEnd', PTC.wizard.saveTableData.registerDomChangeEvents);
    }
    this.on('renderTableEnd', this.expandInitialRootNode);
    this.registerSelCount();
    this.on('afteraction', this.onAfterAction);
    this.mon(PTC.action, 'objectsaffected', this.onObjectsAffected, this);
};

PTC.jca.TreeGrid.prototype.onAfterAction = function(formResult) {
    if(formResult &&  'component' === formResult.ajaxEnabled && !formResult.js && !formResult.URL) {
        //Trees can be hard to updated, if the actions is specified as a component refresh then do it
        //TODO remove and turn on error logging to help get this cleaned up
        PTC.jca.table.log.warn("Action used a component refresh", formResult.nextAction, this.id);
        PTC.jca.table.Utils.reload(this);
        return false;
    }
    return PTC.jca.TableGrid.prototype.onAfterAction.call(this, formResult);
};

/**
 * Overriding onTreeGridSelectionChange function from TreeGrid.js
 * @param {Object} sm
 * @param {Object} selection
 */
Ext.ux.maximgb.tg.GridPanel.prototype.onTreeGridSelectionChange = function(sm, selection){
    var record, store;
    // Row selection model
    if (sm.getSelected) {
        record = sm.getSelected();
        //commenting out this line made selection across paging worked in Tree table.
        //this.getStore().setActiveNode(record);
    } // Cell selection model

    else if (Ext.type(selection) == 'array' && selection.length > 0) {
        record = store.getAt(selection[0]);
        this.getStore().setActiveNode(record);
    }
    else {
        throw "Unknown selection model applyed to the grid.";
    }
};
/**
 * Expands all the rows set to be initially expanded
 *
 * @param {Object} record
 */
PTC.jca.expandRowIfAuto = function(record){
    if (record.get('autoexpand')) {
        //If the node doesn't have its children yet, wait for the next event
        var store = record.store;
        // if the store is done loading, skip the getNodeChildren check ( expensive )
        // but need to wait until mvc ds code sends correct values for autoexpand,
        // currently it is sending some true values when no children are ever present
        if (store.hasChildNodes(record)) {
            var eventsSuspendedAlready = store.eventsSuspended;
            store.suspendEvents();
            store.setNodeLoaded(record, true);
            record.set('autoexpand', false);
            if (!eventsSuspendedAlready) {
                store.resumeEvents();
            }
            store.expandNode(record);
        }
    }
};

PTC.jca.autoExpandRows = function(store){
    store.enableChildNodeCache();
    try {
        store.each(PTC.jca.expandRowIfAuto);
    }
    finally {
        store.disableChildNodeCache();
    }
    // In Chrome, expansion takes a bit more time, must defer to avoid unnecessary scrollbars
    PTC.jca.table.scroll.updateTableSize.defer(100, store, [store.jscaTableID]);
};

/**
 * Called after a row is expanded to update Tree height and scroll to focussed row.
 */
PTC.jca.expandRows = function(tableid){
    var g = tableUtils.getTable(tableid);
    //resize tree height
    PTC.jca.table.scroll.updateTableSize.defer(100, PTC.jca.table.scroll, [tableid]);
    //clear cache/stickiness related to focus/visibility as node is going to expand
    //bringing children - SPR 5696632
    if(g){
        if (g.getView() && typeof g.getView().clearVisibleCaches === 'function') {
            g.getView().clearVisibleCaches();
        }
        PTC.jca.table.stickiness.clearFocusRow(g.id);
        PTC.jca.table.Utils.scrollToFocusRow(g);
    }

};

/**
 * Called after a row is collapsed to update Tree height.
 */
PTC.jca.collapseRows = function(tableid){
    PTC.jca.table.scroll.updateTableSize(tableid);
};

PTC.jca.isAsync = function(store){
    return !Ext.isEmpty(store.chunk);
};

/**
 * This method will return the QueryString from FormAction for given object.
 *
 * @param g Object
 * @return queryString returns query stinrg from FormAction if present.
 */
PTC.jca.getQueryStringFromAction = function(g) {
    var formAction = getMainForm(g.getEl().dom).attributes["action"].value;
    var index = formAction.indexOf("?");
    var queryString = "";
    if(index > -1) {
        queryString = "&" + formAction.substring(formAction.indexOf("?") + 1);
    }
    return queryString;
};

PTC.jca.autoExpandRows = PTC.util.delayAllCalls(PTC.jca.autoExpandRows, 200);
PTC.jca.expandRows = PTC.util.delayAllCalls(PTC.jca.expandRows , 100);
PTC.jca.collapseRows = PTC.util.delayAllCalls(PTC.jca.collapseRows, 100);
PTC.jca.tree.onCollapse = function(target, node){
    if (this.collapseAll !== true) {
        var g = tableUtils.getTable(this.jscaTableID);
        var queryString = PTC.jca.getQueryStringFromAction(g);
        treeHandler.asyncCollapse(node.data.oid, g.id, node.data.jsca_context, queryString,g.jcaTableConfig.uniqueCompKey);
    }
    PTC.jca.collapseRows(this.jscaTableID);
};

PTC.jca.tree.onExpand = function(target, node){
    // This will fire the request to add oid in expanded node list, for clicked node which is already loaded.
    if (this.norgieClicked === 1 && this.isLoadedNode(node)) {
        var g = tableUtils.getTable(this.jscaTableID);
        var queryString = PTC.jca.getQueryStringFromAction(g);
        treeHandler.expandNode(node.data.oid, g.id, node.data.jsca_context, queryString, g.jcaTableConfig.uniqueCompKey);
    }
    PTC.jca.expandRows(this.jscaTableID);
};

/**
 * Handles the tree result limit case. Shows popup for user confirmation to continue/discontinue data loading.
 * If user choice is "yes" data loading will be continued till end of data otherwise halted.
 * @param {Object} store
 * @param {Object} records
 */
PTC.jca.WTablePanel.prototype.handleTreeResultLimit = function(store, records) {
    var treeId = store.jscaTableID;
    var isTreeVisible  = store.proceed === false ? false : tableUtils.isTableVisible(treeId);
    var gridPanel = tableUtils.getTable(store.jscaTableID);
    var isOidBasedProcessing = store.postCancelHandlerInfo && store.postCancelHandlerInfo.oid; // check if postCancleHandler has set any OID
    if(isTreeVisible === false){
        store.proceed = false;
    }
    try{
        var showPopUp = store.showPopUp;// check if the confirmation popup was already shown
        if(showPopUp === undefined){
            var storeCanAbsorb = store.resultLimit - store.data.items.length;
            if(records.totalRecords > storeCanAbsorb){// check if store can accomodate more data.
                showPopUp = true;
            }
        }else{
            showPopUp = false;
        }
        var belowResultLimit =  store.resultLimitCrossed === undefined || store.resultLimitCrossed === false ;
        var singleNodeExpand = store.norgieClicked || store.proceed === false;
        var proceed = store.showPopUp;
        if(showPopUp){
            proceed = JCAConfirm("com.ptc.netmarkets.util.utilResource.UNBOUNDED_LOAD");
        }
        if (proceed) {// if user selects to load all don't process further.
            store.resultLimitCrossed = true;
            return;
        }
        if (store.resultLimitReached === true && isOidBasedProcessing ){// run postCancelHandler
            PTC.jca.tree.postCancelHandler(store, records);
        }
        var displayWarning = true;
        if(store.displayWarning!== undefined){
            displayWarning = store.displayWarning;
        }
        if (belowResultLimit && (proceed === false || store.proceed === false || singleNodeExpand === true )) {
            PTC.jca.tree.adjustTreeStoreContents (store, records,gridPanel);
        }
        var postCancelRecords = store.postCancelRecords ? store.postCancelRecords: [];
        if(!proceed && showPopup){
            // user has cancelled the confirmation popup launched from this function,
            //strip the contents to store size and append the postCancel records
            PTC.jca.tree.adjustTreeStoreContents(store, records,gridPanel);
            records.records = records.records.concat(postCancelRecords);
        }
        else{// Size limit is already reached before calling this function and user has cancelled the loading.
            records.records = postCancelRecords;
        }
    }finally{
        store.postCancelRecords = [];
        store.showPopUp = undefined;
    }
    if(gridPanel){
        gridPanel.getView().refresh();
    }
    if(displayWarning && (belowResultLimit === true || proceed === false)){// display warning message
        var msg1 = bundleHandler.get('com.ptc.netmarkets.util.utilResource.MAX_DATASOURCE_LIMIT_REACHED_MESSAGE_TREE_LEVEL');
        var key1 = "com.ptc.netmarkets.util.utilResource.MAX_DATASOURCE_LIMIT_REACHED_MESSAGE_TREE_LEVEL";
        var key2 = "com.ptc.netmarkets.util.utilResource.MAX_DATASOURCE_LIMIT_REACHED_MESSAGE_TREE";
        PTC.jca.table.Utils.renderPageNcomponentLevelFeedback(store, msg1, key1, key2);
    }
};
/**
 * Performs required action after the cancel button is hit after tree result size limit is reached.
 * @param (Object) store
 * @param (Object) records
 */
PTC.jca.tree.postCancelHandler = function(store, records){
    var requiredNodes = [];
    store.postCancelRecords= []; // initialize to avoid null;
    if(!store.postCancelHandlerInfo || !store.postCancelHandlerInfo.oid){
        return;
    }
    var length = records.records.length;
    var requiredNodeObject = null;
    var oidToPopulate = store.postCancelHandlerInfo.oid;
    var gridPanel = store.jsca_table ? store.jsca_table : tableUtils.getTable(store.jscaTableID);
    var dsId = gridPanel.jcaTableConfig.chunk.id;
    if (length === undefined || length === 0) {
        return;
    }
    for (var i = 0; i < length; i++) { // find the record for required OID
        if (records.records[i].data.oid == oidToPopulate) {
            requiredNodeObject = records.records[i];
            requiredNodes.push(requiredNodeObject);
            PTC.jca.DataSourceRegistry.cancelServerDataSources(dsId);
            break;
        }
    }
    if(!requiredNodeObject){
        return;
    }
    var parent = requiredNodeObject.data._parent;
    var findParent = function() {
        for ( var i = 0; i < length; i++) {// find parent records for  the OID
            if (records.records[i].data.jsca_context == parent) {
                records.records[i].ux_maximgb_tg_expanded = true;
                records.records[i].ux_maximgb_tg_loaded = true;
                requiredNodes.push(records.records[i]);
                parent = records.records[i].data._parent;
                break;
            }
        }
        if (i >= length) {
            return false;
        } else {
            return true;
        }
    };
    while (parent && findParent()){
    }
    store.postCancelRecords = requiredNodes;

};

/**
 * Strips the records to match the result limit
 * @param (Object) store
 * @param (Object) records
 * @param (Object) gridPanel
 */
PTC.jca.tree.adjustTreeStoreContents = function(store, records,gridPanel){
    store.loadContinue = false;
    var storeItemsLength = store.data.items.length;
    var ids = store.chunk ? [store.chunk.id] : gridPanel ? [gridPanel.jcaTableConfig.chunk.id] : [] ;
    PTC.jca.DataSourceRegistry.cancelServerDataSources(ids);
    var resultLimit = store.resultLimit;
    if (storeItemsLength < resultLimit) {
        var recordPivotPoint = resultLimit - storeItemsLength;
        records.records.splice(recordPivotPoint, records.records.length);
    } else {
        store.data.items.splice(resultLimit, store.data.items.length);
        records.records.splice(0, records.records.length);
    }
    store.data.length = store.data.items.length;
};

PTC.jca.createTreeListeners = function(proceed, g, store){
    proceed(g, store);
    if (g.tree && g.initialConfig.jcaTableConfig.initialDisplayCollapsed !== true) {
        PTC.jca.enableAutoExpand(g);
    }

    store.on("collapsenode", PTC.jca.tree.onCollapse);
    store.on("beforeexpandnode", PTC.jca.tree.onExpand);
    store.on("after_expand_collapse", PTC.jca.table.handleSelectAllCheckbox);
};

/**
 * Allows rows to be automatically expanded to preserve state during a page refresh.
 *
 * @param {PTC.jca.TreeGrid} table
 */
PTC.jca.enableAutoExpand = function(table) {
    var store = table.getStore();
    if (PTC.jca.isAsync(store)) {
        store.on('datasourcecomplete', PTC.jca.autoExpandRows);
    } else {
        store.on('datachanged', PTC.jca.autoExpandRows);
    }
};

/**
 * Disables the automatic expanding of nodes in a tree.
 *
 * @param {PTC.jca.TreeGrid} table
 */
PTC.jca.disableAutoExpand = function(table) {
    var store = table.getStore();
    if (PTC.jca.isAsync(store)) {
        store.un('datasourcecomplete', PTC.jca.autoExpandRows);
    } else {
        store.un('datachanged', PTC.jca.autoExpandRows);
    }
};

PTC.jca.createListeners = PTC.jca.createListeners.wrap(PTC.jca.createTreeListeners);

/**
 * Onclick handler for the Collapse action.
 * @param {Object} target
 * @param {Object} event
 * @param {Object} table
 */
PTC.jca.collapseAll = function(target, event, table){
    if (table) {
        var gview = table.getView();
        var store = table.store;
        delete store.norgieClicked;
        var selectedRows = getJCASelectedTableItems(table.id);
        var formAction = getMainForm(table.getEl().dom).attributes["action"].value;
        var queryString = "";
        var allSelected = selectedRows.length == store.getCount();
        // "collapseAll" will be set to false whenever we want to preserve table row selection and collapse ALL table store rows 
	    // "PTC.jst.tree.collapseAll" is one of the wrapper functions that configures "collapseAll" to false
        var collapseAll = !(event && event.clearSelections === false);
        store.enableChildNodeCache();
        try {
            if (selectedRows.length > 0 && !allSelected && collapseAll) {
                for (var i = 0; i < selectedRows.length; i++) {
                    var sel = selectedRows[i];
                    var rowRecord = tableUtils.getTableRowFromContext(table.id, sel.value);
                    if(rowRecord === null) {
                        var oid = getOidFromRowValue(sel.value);
                        rowRecord = tableUtils.getTableRowFromOid(table.id, oid);
                    }
                    store.collapseNode(rowRecord);
                    queryString += "&soid=" + oid;
                }
            }
            else {
                //collapse all the nodes
                store.collapseAll = true;
                try {
                    store.each(store.collapseNode, store);
                }
                finally {
                    store.collapseAll = false;
                }
                queryString = "&" + formAction.substring(formAction.indexOf("?") + 1);
            }
        }
        finally {
            store.disableChildNodeCache();
        }
        if (collapseAll && (selectedRows.length > 0)) {
            // Unselect all the checkboxes for table
            jsca.unSelectAll(null, table.id);
            table.updateViewOnRadioSelect(table);

        }
        //makes an ajax request to inform the server about the user's collapse action so the session state can be updated.
        treeHandler.asyncCollapse("", table.id, "", queryString + "&implode=true", table.jcaTableConfig.uniqueCompKey);

        return false;
    }
    else {
        return true;
    }
};
/**
 * Onclick handler for the Expand action.
 * @param {Object} target
 * @param {Object} event
 * @param {Object} table
 */

PTC.jca.expandAll = function(target, event, table){

    if (table) {
        var store = table.getStore();
        var i,l,len,sel, oid, rowRecord;
        var selectedRows = getJCASelectedTableItems(table.id);
        delete store.norgieClicked;
        var proceed = PTC.jca.table.Utils.getDataLoadUserConfirmation(store,"com.ptc.netmarkets.util.utilResource.UNBOUNDED_LOAD");
        if (proceed === false) {
            return;
        }
        //Fix for spr 2219621.In the store "expandBeyondLimit" is set to true to avoid extra result limit reached warning popup in doRequest method.
        store.expandBeyondLimit = proceed;
        var allLoaded = true;
        var scrollToFocusRow = true;
        var allSelected = selectedRows.length == store.getCount();
        // "expandAll" will be set to false whenever we want to preserve table row selection and expand ALL table store rows 
        // "PTC.jst.tree.expandAll" is one of the wrapper functions that configures "expandAll" to false
        var expandAll = !(event && event.clearSelections === false);
        if (selectedRows.length <= 0 || allSelected) {
            i = store.getCount();
            while (i--) {
                var rec = store.getAt(i);
                if (!store.isLeafNode(rec) && !store.hasChildNodes(rec)) {
                    allLoaded = false;
                    i = len;
                }
            }
        }
        if (allSelected) {
            //remove leaf nodes if a select-all expand-all scenario
            //Otherwise, ajax request is made per row to expand even for leaf nodes
            selectedRows = PTC.jca.tree._removeLeafNodes(selectedRows, table);

        }
        if (selectedRows.length > 0 && !(allLoaded && allSelected) && expandAll) {
            store.expandAllwithSelections = true;
            if (store.chunkEnabled) {
                PTC.jca.expandNodeListAsync(selectedRows,table);
            }
            else {
                for (i = 0, l=selectedRows.length; i<l; i++) {
                    sel = selectedRows[i];
                    if (sel) {
                        rowRecord = tableUtils.getTableRowFromContext(table.id, sel.value);
                        if(rowRecord === null){
                            oid = getOidFromRowValue(sel.value);
                            rowRecord = tableUtils.getTableRowFromOid(table.id, oid);
                        }
                        rowRecord.ux_maximgb_tg_expanded = false; //sware
                        store.norgieClicked = 1;
                        store.expandNode(rowRecord);
                    }
                }
            }
        }
        else if (allLoaded) {
            try {
                store.enableChildNodeCache();
                for (i = 0, len = store.getCount(); i < len; i++) {
                    rec = store.getAt(i);
                    store.expandNode(rec);
                }
            }
            finally {
                store.disableChildNodeCache();
            }
        }
        else {
            table.getView().resetCaches();
            PTC.jca.table.Utils.reload(table.id, {
                'initTree': 'true',
                'explode': 'true',
                'acquire': 'row'
            }, true);
            store.DATA_RENDERED = true;
            scrollToFocusRow = false;
        }
        if (expandAll && (selectedRows.length > 0)) {
            // Unselect all the checkboxes for table
            jsca.unSelectAll(null, table.id);
            table.updateViewOnRadioSelect(table);
        }

        if(scrollToFocusRow){
            PTC.jca.table.Utils.scrollToFocusRow(table);
            table.alreadyScrolled = true;
        }
    }
    return !table;
};

/**
 * Utility function for sending expand node requests for a node list in async manner
 * 
 * @param {Object} selectedRows
 * @param {Object} table
 */
PTC.jca.expandNodeListAsync = function(selectedRows,table){
    var nodeList=[];
    var sel, rowRecord,oid,i,l;
    var store = table.getStore();
    for (i = 0, l=selectedRows.length; i<l; i++) {
        sel = selectedRows[i];
        if (sel) {
            rowRecord = tableUtils.getTableRowFromContext(table.id, sel.value);
            if(rowRecord === null){
                oid = getOidFromRowValue(sel.value);
                rowRecord = tableUtils.getTableRowFromOid(table.id, oid);
            }
            rowRecord.ux_maximgb_tg_expanded = false; //sware
            store.norgieClicked = 1;
            nodeList.push(rowRecord);
        }
    }
    store.expandNodeList(nodeList);    
};

PTC.jca.expandNode = function(rowRecord, store ){
    store.performExpand = true;
    if(typeof store.expandNode ==='function'){
        store.expandNode(rowRecord);
    }
};

/**
 * Method event listener, to expand root node based on saved preference
 */
PTC.jca.TreeGrid.prototype.expandInitialRootNode = function(){
    var gridPanel = this;
    if (gridPanel.store.getRootNodes().length == 1) {
        //Get page oid free of special characters.
        var oid = extractParamValue(window.location.href, "oid");
        while (oid.indexOf('%3A') > -1) {
            oid = oid.replace('%3A', '_');
        }
        // Generate unique key for a table using page oid and table id.
        var key = "rootExpanded_" + gridPanel.id + "_" + oid;
        var provider = new PTC.jca.state.ClientStateProvider();
        if (!provider.get(key)) {
            var record = gridPanel.store.getAt(0);
            if (record) {
                gridPanel.store.expandNode(record);
                // Store the flag in session to indicate that, do not expand the root node, in case of user has explicitly collapsed it.
                provider.set(key, true);
            }
        }
    }
};

Ext.override(Ext.ux.maximgb.tg.GridView, {
    // PTC EXT OVERRIDE
    expandRow: function(record, initial, suppress){
        var ds = this.ds, i, len, row, pmel, children, index, child_index, sm = this.grid.selModel;
        if (typeof record == 'number') {
            index = record;
            record = ds.getAt(index);
        }
        else {
            index = ds.indexOf(record);
        }
        row = this.getRow(index);
        var fly = Ext.fly(row);
        if (!fly) {
            return;
        }
        pmel = fly.child('.ux-maximgb-tg-elbow-active');
        if (pmel) {
            if (ds.hasNextSiblingNode(record)) {
                pmel.removeClass('ux-maximgb-tg-elbow-plus');
                pmel.removeClass('ux-maximgb-tg-elbow-end-plus');
                pmel.addClass('ux-maximgb-tg-elbow-minus');
            }
            else {
                pmel.removeClass('ux-maximgb-tg-elbow-plus');
                pmel.removeClass('ux-maximgb-tg-elbow-end-plus');
                pmel.addClass('ux-maximgb-tg-elbow-end-minus');
            }
        }
        if (ds.isVisibleNode(record)) {
            children = ds.getNodeChildren(record);
            len = children.length;
            for (i = 0; i < len; i++) {
                var child_record = ds.indexOf(children[i]);
                row = this.getRow(child_record);
                Ext.fly(row).setStyle('display', 'block');
                if (ds.isExpandedNode(children[i])) {
                    this.expandRow(child_record, undefined, true);
                }
            }            
        }        

        if (!suppress) {
            ds.fireEvent("after_expand_collapse", sm);
        }
    },
    collapseRow: function(record,suppress){
        var ds = this.ds, i, len, children, row, index, sm = this.grid.selModel;
        if (typeof record == 'number') {
            index = record;
            record = ds.getAt(index);
        }
        else {
            index = ds.indexOf(record);
        }
        row = this.getRow(index);
        var selectedCount = PTC.jca.table.Utils.getTableSelectedRowsCountById(ds.jscaTableID);
        var rowCount = ds.data !== null && ds.data !== undefined ? ds.data.length : 0;

        // PTC EXT OVERRIDE remove rows from the tree to allow user to expand more----Modification start
        //if selectedCount === rowCount that means all data is selected so skipping in that case
        if (ds.resultLimitReached && ds.chunkEnabled && selectedCount !== rowCount) {
            ds.suspendEvents();
            try {
                ds.not_removed_ids = ds.getNotRemovedIDs(ds);
                ds.removeNodeDescendants(record);
            }catch(exception){
                record.ux_maximgb_tg_loaded = false;
                record.ux_maximgb_tg_expanded = false;
            }
            ds.resumeEvents();
            record.data._is_leaf = false;//this is needed as store now considers it as a leaf node so making it false
            record.ux_maximgb_tg_loaded = false;
            record.ux_maximgb_tg_expanded = false;
            ds.fireEvent("datachanged", ds);
            var params ={};
            params.countChanged = true;
            this.onDataChange(ds, params);
            index = ds.indexOf(record);
            row = this.getRow(index);
            var totalRowCount = ds.data !== null && ds.data !== undefined ? ds.data.length : 0;
            if(totalRowCount < ds.resultLimit){
                ds.resultLimitReached = false;
                ds.resultLimitCrossed  = false;
            }
            var pmel = Ext.fly(row).child('.ux-maximgb-tg-elbow-end');
            if(!pmel){
                pmel = Ext.fly(row).child('.ux-maximgb-tg-elbow');
            }
            if (pmel) {
                PTC.jca.TreeGrid.updateClass(pmel,ds,record);
                pmel.addClass('ux-maximgb-tg-elbow-active');
            }
            if(this.grid.store._delete === undefined){
                //special flag to mark no children could be deleted from store for this node as child record/s is/are selected
                record.ptc_clientsidecollapse = true;
            }
            if (ds.resultLimitCrossed  === false && this.grid.store._delete) {
                var tableLevMsg = Ext.getCmp(ds.jscaTableID + '_tablelvlmesg');
                if (PTC.isDefined(tableLevMsg)) {
                    tableLevMsg.hide();
                }
                this.grid.store._delete = false;
            }
        } // ----- Modification end

        else {
            pmel = Ext.fly(row).child('.ux-maximgb-tg-elbow-active');
            if (pmel) {
                PTC.jca.TreeGrid.updateClass(pmel,ds,record);
            }
            children = ds.getNodeChildren(record);
            len = children.length;
            for (i = 0; i < len; i++) {
                index = ds.indexOf(children[i]);
                row = this.getRow(index);
                Ext.fly(row).setStyle('display', 'none');
                this.collapseRow(index, true);
            }            
        }
        if (!suppress) {
            ds.fireEvent("after_expand_collapse", sm);
        }
    }
});
Ext.override(Ext.ux.maximgb.tg.GridView, {
    // PTC EXT OVERRIDE
    renderCellTreeUI : function(record, store)
    {
        var tpl = this.templates.treeui,
        line_tpl = this.templates.elbow_line,
        tpl_data = {},
        rec, parent,
        depth = store.getNodeDepth(record),
        level = store.getNodeDepth(record);

        tpl_data.wrap_width = (depth + 1) * 16;
        if (level > 0) {
            tpl_data.elbow_line = '';
            rec = record;
            var left = 0;
            while(level--) {
                parent = store.getNodeParent(rec);
                if (parent) {
                    if (store.hasNextSiblingNode(parent)) {
                        tpl_data.elbow_line =
                            line_tpl.apply({
                                left : level * 16,
                                cls : 'ux-maximgb-tg-elbow-line'}) +
                                tpl_data.elbow_line;
                    }
                    else {
                        tpl_data.elbow_line =
                            line_tpl.apply({
                                left : level * 16,
                                cls : 'ux-maximgb-tg-elbow-empty'
                            }) +
                            tpl_data.elbow_line;
                    }
                }
                else {
                    throw [
                           "Tree inconsistency can't get level ",
                           level + 1,
                           " node(id=", rec.id, ") parent."
                           ].join("");
                }
                rec = parent;
            }
        }
        if (store.isLeafNode(record)) {
            if (store.hasNextSiblingNode(record)) {
                tpl_data.cls = 'ux-maximgb-tg-elbow';
            }
            else {
                tpl_data.cls = 'ux-maximgb-tg-elbow-end';
            }
        }
        else {
            tpl_data.cls = 'ux-maximgb-tg-elbow-active ';
            if (store.isExpandedNode(record)) {
                if (store.hasNextSiblingNode(record)) {
                    tpl_data.cls += 'ux-maximgb-tg-elbow-minus';
                }
                else {
                    tpl_data.cls += 'ux-maximgb-tg-elbow-end-minus';
                }
            }
            else {
                if (store.hasNextSiblingNode(record)) {
                    tpl_data.cls += 'ux-maximgb-tg-elbow-plus';
                }
                else {
                    tpl_data.cls += 'ux-maximgb-tg-elbow-end-plus';
                }
            }
        }
        tpl_data.left = 1 + depth * 16;
        if (store.disableAction) {
            tpl_data.cls = "";
        }
        return tpl.apply(tpl_data);
    }
});
Ext.override(Ext.ux.maximgb.tg.GridPanel, {
    // PTC EXT OVERRIDE
    onClick: function(e){
        var target = e.getTarget(), view = this.getView(), row = view.findRowIndex(target), store = this.getStore(), sm = this.getSelectionModel(), record, record_id, do_default = true;
        // Row click
        if (row !== false) {
            if (Ext.fly(target).hasClass('ux-maximgb-tg-elbow-active')) {
                //Focus the row for which norgie have been clicked.
                this.fireEvent('rowmousedown', this, row, e);
                record = store.getAt(row);
                if (store.isExpandedNode(record)) {
                    store.collapseNode(record);
                }else if(record.ptc_clientsidecollapse){
                    //ptc_clientsidecollapse is a special flag to mark no children could be deleted from store for this node as child record/s is/are selected
                    //this flag is in existence only when result limit is hit n user collapses a node.
                    store.setNodeExpanded(record, true);
                    store.fireEvent('expandnode', store, record);
                    record.ptc_clientsidecollapse = undefined;
                }
                else {
                    store.norgieClicked = 1;
                    store.expandNode(record);
                }
                do_default = false;
            }
        }
        // Breadcrumb click
        else if (Ext.fly(target).hasClass('ux-maximgb-tg-brditem')) {
            record_id = Ext.id(target);
            record_id = record_id.substr(record_id.lastIndexOf('-') + 1);
            if (record_id) {
                record = store.getById(record_id);
                row = store.indexOf(record);
                if (e.hasModifier()) {
                    if (store.isExpandedNode(record)) {
                        store.collapseNode(record);
                    }
                    else {
                        store.expandNode(record);
                    }
                }
                else if (sm.isSelected && !sm.isSelected(row)) {
                    sm.selectRow(row);
                }
            }
            else {
                sm.clearSelections();
            }
            e.preventDefault();
        }
        if (do_default) {
            Ext.ux.maximgb.tg.GridPanel.superclass.onClick.call(this, e);
        }
    }
});

/**
 * Update the css class
 * @param {Object} pmel
 * @param {Object} store
 * @param {Object} record
 */
PTC.jca.TreeGrid.updateClass = function(pmel,ds,record){
    if (ds.hasNextSiblingNode(record)) {
        pmel.removeClass('ux-maximgb-tg-elbow-minus');
        pmel.removeClass('ux-maximgb-t-tg-bow-end-minus');
        pmel.addClass('ux-maximgb-tg-elbow-plus');
    } else {
        pmel.removeClass('ux-maximgb-tg-elbow-minus');
        pmel.removeClass('ux-maximgb-tg-elbow-end-minus');
        pmel.addClass('ux-maximgb-tg-elbow-end-plus');
    }
};

/**
 * Removes the norgie if the last row is removed
 * @param {Object} store
 * @param {Object} record
 * @param (Object) parentRecord - record for which the norgie needs to be removed
 */
PTC.jca.TreeGrid.removeNorgie = function(store, record, parentRecord) {
    var parentNode;
    if (parentRecord) {
        parentNode = parentRecord;
    } else {
        parentNode = store.getNodeParent(record);
    }
    if (parentNode !== undefined && parentNode !== null
            && store.getNodeChildrenCount(parentNode) === 0) {
        // Set node as leaf node
        parentNode.beginEdit();
        store.collapseNode(parentNode);
        // Remove the collapse / expand button
        parentNode.data._is_leaf = true;
        parentNode.data.autoexpand = false;
        // Commit the changes to the record
        parentNode.afterEdit();
        // required for folderBrowser or a two pane component where a prent
        // record in a
        // tree is collpased and its children are removed from other pane.
        tableUtils.getTable(store.jscaTableID).getView().update();

    }
};

Ext.override(Ext.ux.maximgb.tg.AbstractTreeStore,{

    not_removed_ids : null,
    /**
     * Code will not remove a record if it is selected.It will also not remove any of its parent node.
     * @param {Object} record - record
     */
    remove : function(record){
        // ----- Modification start
        if (Ext.isArray(record)) {
            var i = record.length;
            while (i--) {
                this.remove(record[i]);
            }
            return;
        }
        var id = record.id;
        var j,size;
        if(PTC.isDefined(this.not_removed_ids)){
            for(j = 0 ,size = this.not_removed_ids.length;j<size;j++){
                //if a record is selected,do not remove and return.Also set a flag childselected in parent node as true
                if(this.not_removed_ids[j].id.indexOf(id) >= 0){
                    var parent = this.getById(record.data._parent);
                    parent.childselected = true;
                    this.removeNodeDescendants(record);
                    return;
                }
            }

        }

        this.removeNodeDescendants(record);

        //if record has a flag childselected as true then set childselected flag to true even for its parent node as we have to maintain tree structure.
        if(record.childselected){
            parent = this.getById(record.data._parent);
            parent.childselected = true;

        }else{
            if (record === this.active_node) {
                this.setActiveNode(null);
            }
            Ext.ux.maximgb.tg.AbstractTreeStore.superclass.remove.call(this, record);
            PTC.jca.TreeGrid.removeNorgie(this, record);// check if norgie needs to be removed.
            this._delete = true;
        }
        // ----- End of modification
    },
    /**
     * Will return records which are not candidate for removal
     * @param {Object} store - store
     */
    getNotRemovedIDs : function(store){
        return tableUtils.getTableSelectedRowsById(store.jscaTableID);
    },

    expandNodeList : function(nodeList)  {
        var params={};
        params.jsonData = {};
        var len = nodeList.length;
        var rowList = [];
        var levelList = [];
        for (var i =0; i < len ; i++) {
            var rc = nodeList[i];
            if (
                    !this.isExpandedNode(rc) &&
                    this.fireEvent('beforeexpandnode', this, rc) !== false
            ) {
                // If node is already loaded then expanding now. THIS if part is probably redundant now - TODO remove
                if (this.isLoadedNode(rc)) {
                    this.setNodeExpanded(rc, true);
                    this.fireEvent('expandnode', this, rc);
                }
                // If node isn't loaded yet then expanding after load.
                else {
                    //Todo :- The following 2 lines may need change 
                    PTC.jca.tree.fireEvent('beforeexpandnodeserver', rc,params,this.jscaTableID);
                    params[this.paramNames.active_node] = rc.id;
                    //--- PTC Override
                    rowList.push(rc.id);
                    params.actionMethod = "expand";
                    params.acquire = 'row';
                    levelList.push( rc.data._level);
                    //mark that json response is acceptable but request has Content type such that server side 
                    //treats it as Form data (it specifies the MIME type of request body)
                    Ext.lib.Ajax.headers = {Accept : 'application/json', 
                            "Content-Type" : "application/x-www-form-urlencoded"};
                    //--- end PTC Override
                }
            }
        }
        params.jsonData["e"]=rowList;
        params.jsonData["level"]=levelList;
        if ( 0 < rowList.length) {
            this.load({
                add : true,
                params : params,
                callback : this.expandNodeCallback,
                scope : this
            });
        }
    }
});


/**
 * From a list of selection objects, remove any that are leaf nodes
 * @param {Array} selectedRows, where arrayItem.value is the context string for the row
 * @param {PTC.jca.TableGrid} table
 */
PTC.jca.tree._removeLeafNodes = function(selectedRows, table){
    var sel, rec;
    var i = selectedRows.length;
    var result = [];
    var store = table.store;
    while (i--) {
        sel = selectedRows[i];
        rec = tableUtils.getTableRowFromContext(table.id, sel.value);
        if (!store.isLeafNode(rec)) {
            result.push(sel);
        }
    }
    return result;
};


/**
 * Expand a node, to bring latest children from server.
 * @param {Object} parentRecord
 * @param {Object} grid
 * @param {Object} removeExistingChildren
 * @param {Object} [children]
 */
PTC.jca.tree.forceServerSideExpand = function(parentRecord, grid, removeExistingChildren,children){
    if (removeExistingChildren) {
        PTC.jca.tree.removeChildren(parentRecord, grid, children);
    }
    parentRecord.data._is_leaf = false;//this is needed as store now considers it as a leaf node so making it false
    parentRecord.ux_maximgb_tg_loaded = false;
    parentRecord.ux_maximgb_tg_expanded = false;

    PTC.jca.expandNode(parentRecord, grid.getStore());
};

/**
 * Collapse the node and removes children
 * @param {Object} parentRecord
 * @param {Object} grid
 * @param {Object} children
 */
PTC.jca.tree.removeChildren = function(parentRecord, grid, children){
    if (!children) {
        children = grid.getStore().getNodeChildren(parentRecord);
    }
    grid.getView().collapseRow(parentRecord);
    for (var i = 0; i < children.length; i++) {
        grid.getStore().removeFromNode(parentRecord, children[i]);
    }
};

/**
 * Resetting _allRenderableCache so that tree count will come correct after deleting nodes from Tree.
 */
Ext.ux.maximgb.tg.GridView.prototype.onRemove = Ext.ux.maximgb.tg.GridView.prototype.onRemove.wrap(function(proceed,ds, record, index, isUpdate) {
    this._allRenderableCache = undefined;
    proceed.call(this, ds, record, index, isUpdate);
});

/**
 * Partially update bufferview when radio selection is cleared while doing expandAll/collapseAll toolbar action
 * @param {PTC.jca.TreeGrid} table
 */
PTC.jca.TreeGrid.prototype.updateViewOnRadioSelect = function(table){
    //for Radio buttons view is not getting refreshed after selections are cleared so explicitly updating view
    if(table.jcaTableConfig.singleSelect){
        var v = table.getView();
        if(v){
            //this wud update visible rows
            v.doPartialDataChange(true);
        }
    }
};

/**
 * Replace loading indicator with a collapse sign when user cancels dataloading while expanding a node/record
 * @param {PTC.data.Store} store
 * @param {Object} record
 */
PTC.jca.TreeGrid.prototype.handleLoadingIndicator = function(store, record){
    var index = store.indexOfId(record.id);
    var row = store.jsca_table.getView().getRow(index);
    var fly = Ext.fly(row);
    if (!fly) {
        return;
    }
    var pmel = fly.child('.ux-maximgb-tg-elbow-active');
    var maskEle = fly.child('.treeNodeMask');
    if (maskEle) {
        maskEle.hide();
    }
    if (pmel) {
        PTC.jca.TreeGrid.updateClass(pmel, store, record);
        //removing of ext-el-mask is required,kind of a bug with ext 3.2.Further release has a fix for it so revisit this when extjs upgrade happens
        var temp = pmel.child('.ext-el-mask');
        temp.removeClass('ext-el-mask');
        pmel.addClass('ux-maximgb-tg-elbow-active');//this is required so that further click of expand can occur for the record
    }
};

PTC.jca.TreeGrid.prototype._onUpdateIterator = function(oid, value, formResult, rowsToAdd, locations) {
    PTC.jca.table.Utils._onUpdateTableTreeIterator(this,oid, value, formResult, rowsToAdd, locations);
};

PTC.jca.TreeGrid.prototype._handleUpdateObjects = function(formResult){
    var rows = [];
    var locations = [];
    PTC.util.propertyIterator(formResult.U, this, this._onUpdateIterator, [formResult, rows, locations]);

    if (rows.length > 0) {
        clearActionFormData();
        this._updateRows(rows, locations);
    }
};

PTC.jca.TreeGrid.prototype._addRows = function(added_new_rows, locations){
    if (locations.size() > 1) {
        // SPR 2125696. Old value of the preference is visible in Preference
        // Management until you refresh the page.
        tableUtils.reload(this);
    }
    else {
        var locationRef = PTC.jca.table.Utils.getTableRowFromOid(this, locations[0]);
        var location = locations[0];
        if (locationRef) {
            location = locationRef.get('jsca_context');
        }
        rowHandler.addRows(added_new_rows, this.id, null, {
            doAjaxUpdate: true,
            addSorted: true,
            parameters: 'dynamicLocationContext=' + location
        });
    }
};

PTC.jca.TreeGrid.prototype._updateRows = function(added_new_rows, locations){
    if (locations.size() > 1) {
        // SPR 2125696. Old value of the preference is visible in Preference
        // Management until you refresh the page.
        tableUtils.reload(this);
    }
    else {
        rowHandler.updateRows(added_new_rows, this.id, {
            doAjaxUpdate: true,
            addSorted: true,
            parameters: 'dynamicLocationContext=' + locations[0]
        });
    }
};

PTC.jca.TreeGrid.prototype._handleAddObjects = function(formResult){
    var iteratorScope = {
            oidsToAdd: [],
            locations: []
    };
    PTC.util.propertyIterator(formResult.A, iteratorScope, function(property, value){
        this.oidsToAdd = this.oidsToAdd.concat(PTC.util.extractAllValues(value));
        this.locations.push(property);
    }, []);
    if (iteratorScope.oidsToAdd.length) {
        this._addRows(iteratorScope.oidsToAdd, iteratorScope.locations);
    }
};


PTC.external = {};
PTC.external.log = log4javascript.getLogger("PTC.external");
PTC.external.externalParams = null;
PTC.external.msgObjects = null;

/**
 * Generates array of oids from the msgObjects passed into the PTC.external.showInlineMessage.
 */
PTC.external.getMessageObjects = function(){
    var objs = [];
    var msgObjects = PTC.external.msgObjects;
    if (msgObjects === null) {
        return objs;
    }
    var msgObjLength = msgObjects.length;
    for (var i = 0; i < msgObjLength; i++) {
        var oids = msgObjects[i];
        var objIds = oids.OidIdentity;
        var objLen = objIds.length;
        for (var j = 0; j < objLen; j++) {
            var oid = objIds[j].oid;
            PTC.external.log.debug('Adding oid from msgObjects : ' + oid);
            objs.push(oid);
        }
    }
    return objs;
};

/**
 * Converts the oids in the msgObjects to ufids if the externalURL is set.
 * @param {Object} orig the original wrapped function
 * @param {Object} msgObjects
 */
PTC.external.showInlineMessage = function(orig, msgObjects){
    var externalURL = PTC.external.getExternalURL();
    PTC.external.msgObjects = msgObjects;
    if (externalURL !== null) {
        PTC.external.log.debug('Processing msgObjects for generating externalURL.');
        var msgObjLength = msgObjects.length;
        var objs = PTC.external.getMessageObjects();
        
        var options = {
            asynchronous: false,
            method: 'get',
            parameters: {
                oids: objs
            },
            onSuccess: PTC.external.handleSuccess
        };
        //getting the ufids for the newly created windchill objects
        requestHandler.doRequest('ptc1/externalRequestCallBack', options);
    }
    orig(msgObjects);
};

/**
 * Gets oid of object to redirect to if unable to close window.
 */
PTC.external.getRedirectOid = function(){
    var oid = null;
    var objOids = PTC.external.getMessageObjects();
    if (objOids.length === 1) {
        PTC.external.log.debug('Using oid from msgObjects for redirect : ' + oid);
        oid = objOids[0];
    }
    if (oid === null) {
        var params = location.search.parseQuery();
        if (typeof params.oid === 'string') {
            oid = params.oid;
        }
        else {
            oid = params.oid[0];
        }
        PTC.external.log.debug('Using oid from url for redirect : ' + oid);
    }
    return oid;
};

PTC.external.handleSuccess = function(response){
    PTC.external.externalParams = response.responseJSON;
};

/**
 * Gets the externalURL to redirect to from the hidden element named "externalURL".
 */
PTC.external.getExternalURL = function(){
    var externalURL = getElementByName("externalURL");
    var value = null;
    if (externalURL && externalURL.value) {
        value = externalURL.value;
        PTC.external.log.debug('External url : ' + value);
    }
    return value;
};

/**
 * Overrides the handling of the wizard window to redirect to the external url if set or tries to close the window.
 */
PTC.external.handleWizWindow = function(){
    if (PTC.external.externalParams !== null) {
        var params = Ext.urlEncode(PTC.external.externalParams);
        var externalUrl = Ext.urlAppend(PTC.external.getExternalURL(), params);
        PTC.external.log.debug('Redirecting to external url.');
        window.location = externalUrl;
    }
    setTimeout(wfWindowClose1, 1000);
};

PTC.external.refreshOpenerOnly = function() {
	// do nothing parent is a different domain
};

/**
 * Overrides closing the window.  If the window is not able to be closed will try to redirect to the newly created
 * context object or modified context object.
 * @param {Object} orig the original wrapped function
 */
PTC.external.wfWindowClose = function(orig){
    orig();
    if (window.closed === false) {
        // redirect feedback message url or object info page if unable to close window.
        PTC.external.log.debug('Unable to close window.');
        var oid = PTC.external.getRedirectOid();
        if (oid !== null) {
            var url = PTC.infoPage.getURL(oid);
            PTC.external.log.debug('Redirecting to : ' + url);
            window.location = url;
        }
    }
};

PTC.external.init = function(){
    var isExternalRequest = Ext.getDom('isExternalRequest');
    if (isExternalRequest && isExternalRequest.value === "true") {
        PTC.external.log.debug('Initializing window for external request.');
        getPopupOpenerWindow = function(){
            return false;
        };
        refreshOpenerOnly = PTC.external.refreshOpenerOnly;
        PTC.mainWindow = window;
        PTC.messaging.showInlineMessage = PTC.messaging.showInlineMessage.wrap(PTC.external.showInlineMessage);
        wfWindowClose1 = wfWindowClose1.wrap(PTC.external.wfWindowClose);
        handleWizWindow = PTC.external.handleWizWindow;
		refreshOpenerOnly = PTC.external.refreshOpenerOnly;
    }
};


