/*
 * Save the Data from the Combobox to the Table Store and rerender combo box
 */
PTC.fedInfraUI.saveUpdatedComboBoxToTableStore = function(comboBoxId) { 
      var lcTemplateCombo=document.getElementById(comboBoxId);
      var table = tableUtils.getTable(PTC.fedInfraUI.getCurrentTableID());
       var view = table.getView();
       var colIndex = view.findCellIndex(lcTemplateCombo);
       var rowIndex = view.findRowIndex(lcTemplateCombo);
       if (colIndex >= 0 && rowIndex >= 0) {
           var record = table.getStore().getAt(rowIndex);
           if (record !== undefined) {
               var cell = record.get(table.getColumnModel().config[colIndex].id);
               if (cell !== undefined && cell.gui !== undefined) {
                   cell.gui.options=lcTemplateCombo.options;
                   cell.gui.value=lcTemplateCombo.value;
                   PTC.fedInfraUI.doRendering(table,record,rowIndex,colIndex,
                           table.getColumnModel().config,table.getColumnModel(),table.getStore());

               }
           }
       }  
};


PTC.fedInfraUI.doRendering = function(table, rec, rowIndex, colIndex, columnConfigs, cols, store){
       var col;
       var p = {};
       var cb = [];
       col = columnConfigs[colIndex];
       p.id = col.id;
       p.attr = p.cellAttr = '';
       col.renderer.call(col.scope, rec.get(columnConfigs[colIndex].id), p, rec, rowIndex, colIndex, store);
};



/**
 * Modes for the Find in Table class
 */
FindInTableMode = {DISABLED: "DISABLED", CLIENT_ONLY: "CLIENT_ONLY", CLIENT_AND_SERVER: "CLIENT_AND_SERVER"};

/**
 * @class
 * A set of utility functions to perform client side "Search in list" functionality.
 * Not to be used with the new operator, this returns an array of components to add to the toolbar
 */
PTC.jca.table.findInTable = function(tableId){

    /**
     * The text box which is used to specify the search/filter criteria.
     */
    var searchInListTextBox = new PTC.jca.table.SearchField({
        id: PTC.jca.table.findInTable.getSearchInListTextBoxName(tableId),
        tableId: tableId
    });

    /**
     * The search status text. It would have values 'searching...' while filtering
     *  or matches found message
     */
    var searchStatusText = PTC.jca.table.findInTable.getFindStatusText();
    /**
     * Search in list spinning mask item
     */
    var searchIndicator = new Ext.Toolbar.TextItem({
        id: tableId + ".searchInListLoadingWheel",
        width: 30,
        height: 20,
        xtype: 'tbtext'
    });

    /**
     * Search status box is replaced by label
     * The search status text. It would have values 'searching...' while filtering
     * or matches found message. It was replaced from search text box.
     */
    var searchStatusLabel = new Ext.form.Label({
        id: tableId + ".searchStatusLabel",
        autoWidth: true,
        defaultAlign: 'tl-bl',
        cls: 'x-tip-header-text',
        style: {
            marginRight: '5px'
        }
    });

    //Adding text width may push items into overflow on the toolbar, make sure to recalculate the size
    searchStatusLabel.setText = searchStatusLabel.setText.wrap(function(p, t){
        var result = p.call(this, t);
        var table = tableUtils.getTable(tableId);
        if (table) {
            var tb = table.getToolbar();
            if (tb) {
                var tableWidth = tb.getWidth();
                var toolbarContentWidth = tb.getEl().first().getWidth();
                if (toolbarContentWidth > tableWidth) {
                    tb.syncSize();
                }
            }
        }
        return result;
    });

    return [searchIndicator, searchStatusLabel, searchInListTextBox];
};

/**
 * Show a message about how many objects were found in the search.
 * @param {Ext.grid.GridPanel} table
 */
PTC.jca.table.findInTable.showCount = function(table){

    //if the searchInListStatusText is available then only the match count can be updated
    if(table.searchInListStatusText === undefined){
        return;
    }

    if (typeof table.getStore().isLoading === 'function' && table.getStore().isLoading()) {
        //For story B-74832. Search status box is replaced by search status label. So we have to set text for new search status label.
        table.searchInListStatusText.setText(bundleHandler.get('com.ptc.core.ui.tableRB.SEARCH_IN_PROGRESS'), false);
        table.getStore().on("datasourcecomplete", PTC.jca.table.findInTable.showCount.createCallback(table), table, { single: true});
    } else {
        var count = table.getStore().getCount();

        if (count > 0) {
            if (table.getStore().resultLimitHit === true) {
                // we have more than page size matches.
                //For story B-74832.
                //Search status box is replaced by search status label. So we have to set text for new search status label.
                table.searchInListStatusText.setText(bundleHandler.getBundleStringAndInserts('com.ptc.core.ui.tableRB.SEARCH_MATCHES_PAGE_LIMIT_MESSAGE', [count]), false);
            } else {
                var matchesCountMessage;
                //SPR 2125174-02 if count 1 then the localized message should be the singular
                if(count == 1) {
                    matchesCountMessage = bundleHandler.getBundleStringAndInserts('com.ptc.core.ui.tableRB.SEARCH_ONE_MATCH_MESSAGE', [count]);
                } else {
                    matchesCountMessage = bundleHandler.getBundleStringAndInserts('com.ptc.core.ui.tableRB.SEARCH_MATCHES_MESSAGE', [count]);
                }
                //For story B-74832.
                //Search status box is replaced by search status label. So we have to set text for new search status label.
                table.searchInListStatusText.setText(matchesCountMessage, false);
            }
        } else {
            // no matches found message text
            //For story B-74832. Search status box is replaced by search status label. So we have to set text for new search status label.
            table.searchInListStatusText.setText(bundleHandler.get('com.ptc.core.ui.tableRB.SEARCH_NO_MATCHES_MESSAGE'), false);
        }

        //For story B-74832.
        //set searchTerm value in Session
        //defaultSearchView is not use cached filter condition
        if ("wt.fc.Persistable.defaultSearchView" !== table.id) {
            //For SPR 2128751. If this table is located in a lightbox or popup, searchTerm will not be saved to client-seesion, therefore sticky function will not be applied.
            var isPopup = ( PTC.lightbox.isLightbox(window) || isWizardWindow() ) && !PTC.automation.isAutomationTest();
            if (!isPopup) {
                PTC.jca.table.setObjectToSession(table.id, "searchInListTextBox", table.searchInListTextBox.getValue());
            }
        }
    }
};

/**
 * Runs after records are filtered. It updates the table size and hide the searching indicators.
 */
PTC.jca.table.findInTable.afterSearch = function(table){
    PTC.jca.table.scroll.updateTableSize(table.store.jscaTableID);
    table.searchInListLoadingWheel.hide();
    if (table.searchInString === undefined || table.searchInString === '') {
        // if no search string entered no need for the search status message
        table.fireEvent('clearSearchInList', table);
        return;
    }

    //For story B-74832.
    //If there is  selected row, It will not set search status text.
    if (table.isSelectedOnlyItemsFilter) {
        table.isSelectedOnlyItemsFilter = false;
        return;
    }

    PTC.jca.table.findInTable.showCount(table);
};

/**
 * Get (or create) the singleton Find in tree/table status tooltip.
 * @return {PTC.jca.table.findInTable.FindStatus} Find in tree/table status tooltip.
 */
PTC.jca.table.findInTable.getFindStatusText = function(){
    var findStatusText = Ext.getCmp('findStatusText');
    if (findStatusText === undefined) {
        findStatusText = new PTC.jca.table.FindStatus();
    }
    return findStatusText;
};

/**
 * Checks if search in list filter is applied for the table on the client side
 * @param {Ext.grid.GridPanel} table
 * @return {boolean}
 */
PTC.jca.table.findInTable.isTableFilteredOnClient = function(table){
    return (table && !PTC.jca.table.findInTable.isTableFilteredOnServer(table) && table.searchInString && table.searchInString !== '');
};

/**
 * Checks if search in list filter is applied for the table on the server side
 * @param {Ext.grid.GridPanel} table
 * @return {boolean}
 */
PTC.jca.table.findInTable.isTableFilteredOnServer = function(table){
    if (table && PTC.isDefined(table.getStore()) && PTC.isDefined(table.getStore().baseParams)) {
        return table.getStore().baseParams.findInTableSearchTerm !== undefined;
    } else {
        return false;
    }
};

/**
 * Checks if search in list filter is applied for the table on either the client or the server side.
 * @param {Ext.grid.GridPanel} table
 * @return {boolean}
 */
PTC.jca.table.findInTable.isTableFiltered = function(table){
    return (PTC.jca.table.findInTable.isTableFilteredOnServer(table) || PTC.jca.table.findInTable.isTableFilteredOnClient(table));
};

/**
 * Perform a server side find in table search.  The component is refreshed.
 * @param {PTC.jca.TreeGrid} table
 * @param {String} searchTerm
 */
PTC.jca.table.findInTable.sendSearchRequest = function(table, searchTerm){
    if (!responseProcessor.containsHandler(PTC.jca.table.findInTable.postTableRefreshHandler)) {
        responseProcessor.addHandler(PTC.jca.table.findInTable.postTableRefreshHandler);
    }
    var store = table.getStore();
    var params = Ext.lib.Ajax.serializeForm(getMainForm(table.getEl().dom)) + "&refreshTable="+table.jcaTableConfig.tableID;

    // If this isn't an array, after the table is refreshed it becomes an array.
    store.baseParams.findInTableSearchTerm = [searchTerm];
    store.baseParams.fitVisibleCols = PTC.jca.table.findInTable.getColumnsToSearch(table);
    var url = PTC.jca.table.Utils.getTableUrl(table.jcaTableConfig.tableID);
    url = PTC.jca.table.findInTable.resetOffsetToZero(url);
    var divID = "table__" + table.jcaTableConfig.tableID + "_TABLE";
    // Send a request to the server that will result in a table refresh.
    getElementHtml(params, divID, true, url);
};

PTC.jca.table.findInTable.getColumnsToSearch = function(table) {
    var visibleColumns = PTC.jca.table.Utils.getTableVisibleColumnsServerIds(table);
    var columnsToSearch;
    if (visibleColumns) {
        columnsToSearch = visibleColumns.split(',');
    }
    var hiddenColumnsToSearch = table.findInTableHiddenColumns;
    if (hiddenColumnsToSearch) {
        columnsToSearch = columnsToSearch.concat(hiddenColumnsToSearch);
    }
    return columnsToSearch.join(",");

}; 
/**
 * return oid list of selected object from Session.
 * @param {String} tableId
 */
PTC.jca.table.findInTable.getSavedSelectedOidList = function(tableId){
    var selectedOnlyItem = Ext.getCmp(PTC.jca.table.getWTablePanelID(tableId) + '.selectedOnlyViewItem');
    if (!selectedOnlyItem) {
        return null;
    }
    var savedSelectedOidList = PTC.jca.table.getObjectFromSession(tableId, selectedOnlyItem.id);
    if (typeof(savedSelectedOidList) !== 'object' || savedSelectedOidList.size() === 0) {
        return null;
    }
    return savedSelectedOidList;
};

/**
 * Handler to add the search text box after refresh
 */
PTC.jca.table.findInTable.postTableRefreshHandler = function(){
    var responseDiv = this.responseDiv;
    var responseID = responseDiv.id;
    var tableId = getTableIDFromResponse(this.responseText);
    if (!tableId) {
        return;
    }
    tableId = tableUtils.getUnformattedTableId(tableId);
    var table = Ext.getCmp(tableId);
    var store = table.getStore();
    table.searchInListTextBox = Ext.getCmp(PTC.jca.table.findInTable.getSearchInListTextBoxName(tableId));
    //For story B-74832.
    //Search status box is replaced by search status label. So we need a new search status label.
    table.searchInListStatusText = Ext.getCmp(tableId + ".searchStatusLabel");


    table.searchInListTextBox.focus();

    if (Ext.isArray(store.baseParams.findInTableSearchTerm) && store.baseParams.findInTableSearchTerm.length === 1) {
        var searchTerm = store.baseParams.findInTableSearchTerm[0];
        table.searchInListTextBox.setValue(searchTerm);
        if (searchTerm !== '') {
            table.searchInListTextBox.clearTrigger.show();
            // Wait for the table to load rows, then show the search status message.
            setTimeout(function(){
                PTC.jca.table.findInTable.showCount(table);
            }, 600);
        }
    }
};

/**
 * If the offset params exists in the url set it to 0
 */
PTC.jca.table.findInTable.resetOffsetToZero = function(url){
    var urlParams = url.toQueryParams();
    if (urlParams.offset && urlParams.offset !== 0) {
        urlParams.offset = 0;
        return Ext.urlAppend(url.substring(0, url.indexOf('?')), Ext.urlEncode(urlParams));
    }
    return url;
};

PTC.jca.table.findInTable.clearSearchInList = function(table){
    if (PTC.jca.table.findInTable.isTableFilteredOnServer(table)) {
        PTC.jca.table.findInTable.clearSearchInListServerSide(table);
    } else {
        table.fireEvent('clearSearchInList', table);
    }
};

/**
 * Returns true if table is filtered on client and search term present.
 * 
 * @param {Ext.grid.GridPanel} grid
 * @return {boolean} true if filtered on client and search term present
 */
PTC.jca.table.findInTable.isTableSearchFiltered = function(grid) {
    var store = grid.store;
    var searchInListFiltered = PTC.jca.table.findInTable.isTableFilteredOnClient(store.jsca_table);
    var savedSearchTerm = PTC.jca.table.getObjectFromSession(store.jscaTableID, "searchInListTextBox");
    return savedSearchTerm && savedSearchTerm.length > 0 && searchInListFiltered;
};
/**
 * This will remove the search term for SearchInList from server side
 * 
 * @param {Object} rowStore : the row store
 */
PTC.jca.table.findInTable.deleteSearchTermServerSide = function(store) {
    if (PTC.isDefined(store.baseParams)) {
        delete store.baseParams.findInTableSearchTerm;
        delete store.baseParams.fitVisibleCols;
    }
};
/**
 * Refresh the table to its orignal state.
 * @param {Ext.grid.GridPanel} table
 * @param {boolean} nullOrEmptySearchTerm is the searchTerm null or empty
 */
PTC.jca.table.findInTable.clearSearchInListServerSide = function(table, nullOrEmptySearchTerm){
    if (!PTC.jca.table.findInTable.clearSelectionConfirmation(table,
             'com.ptc.netmarkets.util.misc.miscResource.CLEAR_SELECTION_CONFIRM_ON_CLOSE',
             true/*stashed*/)) {
        return;
    }

    // remove baseParams previously set
    var store = table.getStore();
    PTC.jca.table.findInTable.deleteSearchTermServerSide(store);

    // remove the search in list stickiness
    PTC.jca.table.stickiness.clearSearchInListText(table.id);

    if(nullOrEmptySearchTerm){
        //we want to keep the search text field to be open after the refresh
    } else {
        // hide search status text
        if (table.searchInListStatusText !== undefined) {
            //For story B-74832.
            //Search status box is replaced by search status label. So we have to set text for new search status label.
            table.searchInListStatusText.setText('');
        }
        // remove refresh handler
        responseProcessor.removeHandler(PTC.jca.table.findInTable.postTableRefreshHandler);
    }

    // Do a component refresh to get the table back to its original state since it only has rows that contain the search term.
    var params = Ext.lib.Ajax.serializeForm(getMainForm(table.getEl().dom))+ "&refreshTable="+table.jcaTableConfig.tableID;
    var url = PTC.jca.table.Utils.getTableUrl(table.jcaTableConfig.tableID);
    url = PTC.jca.table.findInTable.resetOffsetToZero(url);
    var divID = "table__" + table.jcaTableConfig.tableID + "_TABLE";
    // Send a request to the server that will result in a table refresh.
    getElementHtml(params, divID, true, url);
};

/**
 * This function will create new unique key using grid and elementName.
 * And then return unique key.
 * This unique key is composed of table id and OID(or url) and element name.
 * e.x) folderbrowser_PDM_OR:wt.folder.Cabinet:37263_searchInListTextBox
 * @param  {String} tableId
 * @param  {String} elementName
 * @return {String} unique key
 */
PTC.jca.table.findInTable.findUniqueKey = function(tableId, elementName){
    var table = tableUtils.getTable(tableId), uniqueKey = tableId;

    if (table && !table.store.baseParams.oid) {
        var urlOid = getOidFromURL(window.top.location.href);
        if (urlOid.length > 0) {
            uniqueKey = uniqueKey + "_" + urlOid;
        } else {
            uniqueKey = uniqueKey + "_" + top.window.location.href.split("&u8=")[0];
        }
    } else if (table) {
        uniqueKey = uniqueKey + "_" + table.store.baseParams.oid[0].split("~")[0];
    }
    return uniqueKey + "_" + elementName;
};


/**
 * If we have a cached filter condition, It will be automatically filtered using cached filter condition.
 * @param {Object} rowStore the row store
 */
PTC.jca.table.findInTable.dataLoadComplete = function(rowStore){
    var table = PTC.jca.table.Utils.getTable(rowStore.jscaTableID);
    var isTableFilteredOnServer = PTC.jca.table.findInTable.isTableFilteredOnServer(table);
    if ((table.jcaTableConfig.chunk && rowStore.load_complete && ( rowStore.resultLimitHit || isTableFilteredOnServer ) )
            || (!table.jcaTableConfig.chunk && rowStore.DATA_RENDERED)) {
        //If search action goes to server side, table will be reloaded, so in this case data load complete event will be occurred again.
        //so this condition can avoid to data load complete event again.
        if (isTableFilteredOnServer) {
            //only for server side request.
            PTC.jca.table.applyFilterFromSelectedOnlyItemsCache(rowStore);
            return true;
        }

        var searchTerm = PTC.jca.table.getObjectFromSession(rowStore.jscaTableID, "searchInListTextBox");
        var searchField = table.searchInListTextBox || Ext.getCmp(PTC.jca.table.findInTable.getSearchInListTextBoxName(rowStore.jscaTableID));
        var validSearchTerm = !(searchTerm === null || searchTerm.length === 0);

        if (searchField.cachedSearchTerm === searchField.getValue() || validSearchTerm) {
            // SPR 2253991 - cached term may not equal to search term when 2 sessions are using the same cache
            // updated search field with the cached search term before executing search 
            if (validSearchTerm && searchField.getValue() !== searchTerm) {
                searchField.setValue(searchTerm);
            }
            if (!PTC.jca.table.findInTable.fireSearchEvent(rowStore)) {
                //only "Veiw Selected Objectes Only"
                PTC.jca.table.applyFilterFromSelectedOnlyItemsCache(rowStore);
            } else {
                if (!rowStore.resultLimitHit && !isTableFilteredOnServer) {
                    //If there is selected row, It will not set search status text.
                     var selectedOnlyItem = Ext.getCmp(PTC.jca.table.getWTablePanelID(rowStore.jscaTableID) + '.selectedOnlyViewItem');
                     if (selectedOnlyItem) {
                         var savedSelectedOidList = PTC.jca.table.getObjectFromSession(rowStore.jscaTableID, selectedOnlyItem.id);
                         if (typeof(savedSelectedOidList) === 'object') {
                             table.isSelectedOnlyItemsFilter = true;
                         }
                     }
                    PTC.jca.table.applyFilterFromSelectedOnlyItemsCache(rowStore);
                    searchField.clearTrigger.show();
                }
            }
        }

        if (table.jcaTableConfig.chunk) {
            Event.stopObserving(table.store, 'datasourcecomplete', PTC.jca.table.findInTable.dataLoadComplete);
        } else {
            Event.stopObserving(table.store, 'load', PTC.jca.table.findInTable.dataLoadComplete);
        }
    }
};

/**
 * create sticky object collection of specific table id's selected rows
 * returned sticky object collection that consist of table id and array of oid
 * @param {Ext.grid.GridPanel} table
 */
PTC.jca.table.createViewSelectedOnlyItemsCacheValue = function(table){

    var selections = table.getSelectionModel().selections.items;
    var selectedOnlyItems = [];
    var dataLength = selections.length;
    for (var i = 0; i < dataLength; i++) {
        selectedOnlyItems.push(selections[i].data.oid);
    }
    return selectedOnlyItems;
};

/**
 * showing previous selected object only
 * @param {Object} rowStore of current table. this is used to compare with previous data on session
 */
PTC.jca.table.applyFilterFromSelectedOnlyItemsCache = function(rowStore){

    var table = PTC.jca.table.Utils.getTable(rowStore.jscaTableID);
    var tableId = table.jcaTableConfig.tableID;

    var selectedOnlyItem = Ext.getCmp(PTC.jca.table.getWTablePanelID(tableId) + '.selectedOnlyViewItem');
    if (!selectedOnlyItem) {
        return false;
    }

    var savedSelectedOidList = PTC.jca.table.getObjectFromSession(tableId, selectedOnlyItem.id);
    if (typeof(savedSelectedOidList) !== 'object') {
        return false;
    }

    PTC.jca.table.setSelectRowStatus(table, savedSelectedOidList, true);
    selectedOnlyItem.checked = true;
    selectedOnlyItem.fireEvent('applySelectOnlyView', selectedOnlyItem, true);
};

/**
 * The row's select status will be set "true" by savedSelectedOidList.
 * @param {Ext.grid.GridPanel} table
 * @param {Array} The oid list of selected items on a table. it's from session.
 * @param {Boolean} selectStatus
 */
PTC.jca.table.setSelectRowStatus = function(table, savedSelectedOidList, selectStatus){

    var savedSelectedOidListSize = savedSelectedOidList.size();
    var items = table.store.data.items;
    var rowStoreDataLength = items.length;
    var m = table.wtableRef.gridPanel.selModel;
    var tempSavedSelectedOid = null;
    for (var i = 0; i < savedSelectedOidListSize; i++) {
        tempSavedSelectedOid = savedSelectedOidList[i];
        for (var j = 0; j < rowStoreDataLength; j++) {
            if (tempSavedSelectedOid === items[j].data.oid) {
                m.selectRow(j, selectStatus, false);
                break;
            }
        }
    }
};

/**
 * If we have a cached search word, It will be automatically filtered using cached search word.
 * @param {Object} rowStore the row store
 */
PTC.jca.table.findInTable.fireSearchEvent = function(rowStore){

    var savedSearchTerm = PTC.jca.table.getObjectFromSession(rowStore.jscaTableID, "searchInListTextBox");
    if (savedSearchTerm.length > 0) {
        var table = PTC.jca.table.Utils.getTable(rowStore.jscaTableID);
        PTC.jca.table.findInTable.filter(table, savedSearchTerm);
        return true;
    } else {
        return false;
    }
};

/**
 * If there are selected rows, confirm with the user whether it is OK to lose the selection.
 *
 * @param {Ext.grid.GridPanel} table
 * @param {String} rbInfoEntry the rbInfo tag for the confirmation message
 * @param {boolean} stashed indicates whether the table is keeping a snapshot copy of the current selection
 * @return false if the user selected cancel and the action should be canceled
 */
PTC.jca.table.findInTable.clearSelectionConfirmation = function(table, rbInfoEntry, stashed){
    var selModel = table.getSelectionModel();
    // clear row selections if this is a paged table, or if the datasource is still running
    if (selModel.hasSelection() && (!stashed || (PTC.jca.table.Utils.isAllDataLoaded(table) === false))) {
        if (JCAConfirm(rbInfoEntry)) {
            selModel.clearSelections();
            tableUtils.clearSelectAllCheckbox(table);
            PTC.jca.table.findInTable.clearViewSelected(table);
        } else {
            return false;
        }
    }
    return true;
};

/**
 * If the view selected only filter is applied, warn the user that that filter will be removed before proceeding.
 * @param {Ext.grid.GridPanel} table
 * @return false if the user selected cancel and the action should be canceled
 */
PTC.jca.table.findInTable.clearViewSelectedConfirmation = function(table, rbInfoEntry){
    if (table.selectedOnlyChecked) {
        if (JCAConfirm(rbInfoEntry)) {
            PTC.jca.table.findInTable.clearViewSelected(table);
        } else {
            return false;
        }
    }
    return true;
};

/**
 * Clears the "View Selected Objects Only" checkbox and resets any associated filtering.
 *
 * @param {Ext.grid.GridPanel} table
 */
PTC.jca.table.findInTable.clearViewSelected = function(table) {
    var viewSelectedOnly = Ext.getCmp(table.id + "_WTablePanel.selectedOnlyViewItem");
    if (viewSelectedOnly) {
        // arbitrarily turn off "View Selected Objects Only" mode.
        viewSelectedOnly.setChecked(false);
        viewSelectedOnly.fireEvent('applySelectOnlyView', viewSelectedOnly, false);
    }
};

/**
 * This is the status message tooltip for Find in Tree and Search in List.
 * It will appear for an amount of time when the user needs to be notified of something,
 * then will disappear.
 */
PTC.jca.table.FindStatus = Ext.extend(Ext.Tip, {
    constructor: function(){
        if (this.id === undefined) {
            this.id = 'findStatusText';
        }
        PTC.jca.table.FindStatus.superclass.constructor.call(this);
    },

    initComponent: function(){
        this.defaultAlign = 'tl-bl'; // Align the top-left of this tip to the bottom-left of the showBy element.
        this.closable = true; // Add a close tool so the user can click and close this tip.
        this.hidden = true; // Start out as hidden, then show it when necessary.
        this.autoWidth = true; // autoWidth true keeps the tip from wrapping.
        // Needs to be fixed. Otherwise this tip will be shown behind other components.
        this.style = {
            position: 'fixed'
        };
        this.hideDelay = 10000; // The delay before this tip is hidden.
        this.hideTimer = null; // Timeout reference so it can be cleared by showBy.
        PTC.jca.table.FindStatus.superclass.initComponent.call(this);
    },

    // Override
    showBy: function(el, position){
        PTC.jca.table.FindStatus.superclass.showBy.call(this, el);

        // Hide this tip's shadow. It doesn't look good, so remove it.
        this.getEl().shadow.hide();

        // Clear the hide timer if it is ticking.
        if (this.hideTimer) {
            clearTimeout(this.hideTimer);
        }

        // Hide the tip after a delay.
        this.hideTimer = this.hide.defer(this.hideDelay, this);
    },

    /**
     * Shows the status tooltip with the given text below the find in table text box.
     * @param {Ext.grid.GridPanel} table
     * @param {String} text
     */
    showMessage: function(table, text){
        this.setTitle(text);
        this.showBy(table.searchInListTextBox.getEl());
    }
});

/**
 * Input for Search in List. Contains two triggers: a search trigger and a clear trigger. The search trigger is
 * always visible, while the clear trigger is only visible if the table is filtered.
 */
PTC.jca.table.SearchField = Ext.extend(Ext.form.TwinTriggerField, {
    trigger1Class: 'x-form-clear-trigger',
    trigger2Class: 'x-form-search-trigger',
    hideTrigger1: true, // Hide the clear trigger initially.
    enableKeyEvents: true,
    cachedSearchTerm: "", //For story B-74832.
    listeners: {
        'keypress': function(field, e){
            var key = 0 + e.getKey();
            if (key == e.ENTER) {
                e.preventDefault();
                field.onTrigger2Click(); // An Enter should act exactly like a search click.
            }
        },
        'render': function(){
            this.table = Ext.getCmp(this.tableId);
            this.clearTrigger = this.getTrigger(0);
            this.searchTrigger = this.getTrigger(1);
            // Use getBundleStringAndInserts because it unescapes the quotes.
            this.emptyText = bundleHandler.getBundleStringAndInserts('com.ptc.core.ui.tableRB.SEARCH_IN_TABLE');

            //For story B-74832.
            //add code for set value on session.
            PTC.jca.table.findInTable.setSearchFieldFromSession(this);

            try {
                this.addTriggerTooltips();
            } catch (e) {
                PTC.jca.table.log.info('Tooltips could not be added to the search in list triggers.');
            }

            if (isWizardWindow()) {
                this.table.on('afterlayout', function(table){
                    // Make sure the dom is present and ready before trying to reset width.
                    if (!Ext.isEmpty(table.el) && !Ext.isEmpty(table.el.dom) && !Ext.isEmpty(table.el.dom.style) && (typeof(table.el.dom.style.display) != 'undefined') && (table.el.dom.style.display != 'none')) {
                        // SPR 2240784 - the width will not be reset if the search field is hidden in the overflow toolbar
                        // check if the overflow toolbar is present and id hidden first
                        var moreToolbar = Ext.fly(table.id + ".moreToolbar");
                        if (moreToolbar && moreToolbar.hasClass("x-hide-display")) {
                            moreToolbar.removeClass('x-hide-display');
                            this.resetWidth(120);
                            moreToolbar.addClass('x-hide-display');
                        } else {
                            this.resetWidth(120);
                        }
                    }
                }, this);
            }

        },
        'beforedestroy': function(){
            this.table = undefined;
            Ext.destroy(this.searchTrigger, this.clearTrigger);
        }
    },

    /**
     * Sets the width of the component to 0, then to pix.
     * @param {int} pix, the width this component should be, in pixels.
     */
    resetWidth: function(pix){
        // Set width to 0 first, to force a new width. If just setWidth(pix) is used, it might not actually adjust width.
        this.setWidth(0);
        this.setWidth(pix);
    },

    /**
     * Adds on-hover tooltips to the clear and search trigger.
     */
    addTriggerTooltips: function(){
        var clearTriggerDom = this.clearTrigger.dom;
        Ext.QuickTips.register({
            target: clearTriggerDom,
            text: bundleHandler.get('com.ptc.core.ui.tableRB.CLEAR_SEARCH_IN_TABLE')
        });
        var searchTriggerDom = this.searchTrigger.dom;
        Ext.QuickTips.register({
            target: searchTriggerDom,
            text: bundleHandler.get('com.ptc.core.ui.tableRB.SEARCH_IN_TABLE')
        });
    },

    /**
     * Handles the clear trigger click, clears the current table filter.
     */
    onTrigger1Click: function(){
        this.clearTrigger.hide();
        PTC.jca.table.findInTable.clearSearchInList(this.table);
        //For story B-74832. clear searchTerm value in Session
        PTC.jca.table.clearObjectFromSession(this.tableId.split(".searchInListTextBox")[0], "searchInListTextBox");
    },

    /**
     * Handles the search trigger click, does a filter on the table.
     */
    onTrigger2Click: function(){
        var searchTerm = this.getValue();
        if (searchTerm === '') {
            // Empty string should have the same effect as clearing the filter.
            this.clearTrigger.hide();
            //For story B-74832. clear searchTerm value in Session
            PTC.jca.table.clearObjectFromSession(this.tableId.split(".searchInListTextBox")[0], "searchInListTextBox");
        } else {
            this.clearTrigger.show();
        }
        PTC.jca.table.findInTable.filter(this.table, searchTerm);
    }
});

/**
 * This function will set search term to search field from session.
 * @param {String} tableId
 */
PTC.jca.table.findInTable.setSearchFieldFromSession = function(searchField){
    var tableId = searchField.tableId.split(".searchInListTextBox")[0];
    var savedSearchTerm = PTC.jca.table.getObjectFromSession(tableId, "searchInListTextBox");

    if (savedSearchTerm.length > 0 || PTC.jca.table.isTableViewSelectedOnly(tableId)) {
        searchField.setValue(savedSearchTerm);
        searchField.cachedSearchTerm = savedSearchTerm;
    }
    // +++ Set event for datasourcecomplete.  It will be filtered table. +++
    PTC.jca.table.findInTable.setDataLoadCompleteEvent(tableId);
};

/**
 * This function will set event for data source complete.
 * @param {String} tableId
 */
PTC.jca.table.findInTable.setDataLoadCompleteEvent = function(tableId){
    var table = PTC.jca.table.Utils.getTable(tableId);
    var dataloadComplete = new PTC.jca.table.findInTable.dataLoadComplete(table.store);
    if (table.jcaTableConfig.chunk) {
        table.store.on('datasourcecomplete', PTC.jca.table.findInTable.dataLoadComplete);
    } else {
        table.store.on('load', PTC.jca.table.findInTable.dataLoadComplete);
    }
    table.store.on('add', PTC.jca.table.findInTable.changeMatchCnt);
};

/**
 * This function will set count of objects on a table.
 * @param {String} tableId
 */
PTC.jca.table.findInTable.changeMatchCnt = function(){
    var table = tableUtils.getTable(this.jscaTableID);
    PTC.jca.table.findInTable.showCount(table);
};

/**
 * Perform a filter on the table.
 * @param {Ext.grid.GridPanel} table
 * @param {String} searchTerm
 */
PTC.jca.table.findInTable.filter = function(table, searchTerm){
    // Hide previous search's status text.
    if (table.searchInListStatusText !== undefined) {
        //For story B-74832. Search status box is replaced by search status label. So we have to set text for new search status label.
        table.searchInListStatusText.setText('');
    }
    if (searchTerm !== null && searchTerm !== '') {
        if (!PTC.jca.table.findInTable.clearSelectionConfirmation(table,
                 'com.ptc.netmarkets.util.misc.miscResource.CLEAR_SELECTION_CONFIRM_ON_SEARCH',
                 true/*stashed*/)) {
            return;
        }

        if (!PTC.jca.table.findInTable.clearViewSelectedConfirmation(table,
                'com.ptc.netmarkets.util.misc.miscResource.CLEAR_VIEW_SELECTED_CONFIRM_ON_FILTER')) {
            return;
        }

        if (PTC.jca.table.findInTable.isTableFilteredOnClient(table)) {
            // Silently clear any existing filter and retain any existing selections.
            table.store.clearFilter(true);
        }
        //PTC EXT OVERRIDE
        // check if ColumnFilter is applied or not
        if(PTC.jca.table.gridFilters.isEnabled() === true) {
            var savedColumnFiltersTerms = PTC.jca.table.getObjectFromSession(table.store.jscaTableID, "gridFilters");
            if (savedColumnFiltersTerms && (savedColumnFiltersTerms!="[]")) {
                var confirmMessage = "com.ptc.netmarkets.util.utilResource.CONFIRM_COLUMNFILTER_REMOVED_WHENSEARCH";
                if (!JCAConfirm(null, confirmMessage)) {
                    var searchField = Ext.getCmp(PTC.jca.table.findInTable.getSearchInListTextBoxName(table.store.jscaTableID));
                    searchField.setValue(searchField.emptyText);
                    searchField.clearTrigger.hide();
                    return ;
                }
            }
        }
        //deselecting GridFilters
        PTC.jca.table.gridFilters.clearGridFilters(table);

        PTC.jca.table.stickiness.setSearchInListText(table.id, searchTerm); // setting the search in list stickiness
        if (table.jcaTableConfig && table.jcaTableConfig.findInTableMode === FindInTableMode.CLIENT_AND_SERVER &&
        (PTC.jca.table.findInTable.isTableFilteredOnServer(table) || !PTC.jca.table.Utils.isAllDataLoaded(table))) {
            PTC.jca.table.findInTable.sendSearchRequest(table, searchTerm);
        } else {
            table.searchInString = PTC.jca.table.fit.getSafeSearchTerm(searchTerm);
            table.fireEvent('applySearchInList', table);
        }
    } else {
        if (PTC.jca.table.findInTable.isTableFilteredOnClient(table)) {
            table.fireEvent('clearSearchInList', table, false, true);
        } else if (PTC.jca.table.findInTable.isTableFilteredOnServer(table)) {
                if (!PTC.jca.table.findInTable.clearSelectionConfirmation(table,
                         'com.ptc.netmarkets.util.misc.miscResource.CLEAR_SELECTION_CONFIRM_ON_SEARCH',
                         true/*stashed*/)) {
                    return;
                }
                PTC.jca.table.findInTable.clearSearchInListServerSide(table, true);
            }
    }
};

/**
 * Clears the search filter, sets the status text, and resizes the table.
 * @param {Ext.grid.GridPanel} table
 * @param {Boolean} supressEvent indicates if the filter is to be cleared silently or not
 * @param {Boolean} suppressEmptyText indicates if the search in list text box should not be set with empty text
 */
PTC.jca.table.findInTable.clearSearchInListHandler = function(table, supressEvent, suppressEmptyText){
    table.searchInString = '';
    var selectedOnlyIsOn = table.selectedOnlyChecked;
    if (selectedOnlyIsOn) {
        var selectedOnlyItem = Ext.getCmp(PTC.jca.table.getWTablePanelID(table.id) + '.selectedOnlyViewItem');
        // Silently clearing the search in list filter and apply selection filter.
        table.store.clearFilter(true);
        selectedOnlyItem.fireEvent('applySelectOnlyView', selectedOnlyItem, true);
    } else {
        // Only clearing the search in list filter.
        table.store.clearFilter(supressEvent);
        PTC.jca.table.findInTable.makeRowHidden(table.store);
        // restore selections potentially hidden by the filter
        PTC.jca.table.findInTable.applySelectionSnapshot(table);
        PTC.jca.table.handleSelectAllCheckbox(table.selModel);
    }
    if (table.searchInListStatusText !== undefined) {
        //For story B-74832. Search status box is replaced by search status label. So we have to set text for new search status label.
        table.searchInListStatusText.setText('');
    }

    var searchField = Ext.getCmp(PTC.jca.table.findInTable.getSearchInListTextBoxName(table.store.jscaTableID));

    if (suppressEmptyText !== true) {
        searchField.setValue(searchField.emptyText);
    }

    if (!selectedOnlyIsOn && !supressEvent) {
        // Skip table size update as it would be updated after selectOnlyView filter.
        PTC.jca.table.scroll.updateTableSize(table.store.jscaTableID);
    }
    PTC.jca.table.stickiness.clearSearchInListText(table.id);
};
/**
 * While clearing filter if any rows are hidden then dont display it
 * @param {Ext.data.store} tableStore
 * @param hiddenHTML to add hidden rows
 * @return true if hidden row, else false
 */
PTC.jca.table.findInTable.makeRowHidden = function(tableStore,hiddenHTML){
    var someRowHidden = false;
    var tablePanel;
    if(hiddenHTML !== undefined){
        tablePanel = PTC.jca.table.Utils.getTable(tableStore.jscaTableID);
    }
    if(tableStore.data){
        tableStore.filterBy(function(record, id){
            if (record.get('rowHidden') === true) {
                if(hiddenHTML !== undefined){
                    hiddenHTML.push(PTC.jca.table.handleHiddenRowRenderer(tablePanel, record));
                 }
                 someRowHidden = true;
                return false;
            }
            return true;
        });
        return someRowHidden;
    }
};
/**
 * Set status messages and filter the table.
 * @param {Ext.grid.GridPanel} table
 */
PTC.jca.table.findInTable.applySearchInListHandler = function(table){

    var tableId = table.id;
    if (table.searchInListLoadingWheel === undefined) {
        table.searchInListLoadingWheel = new Ext.LoadMask(Ext.getCmp(tableId + ".searchInListLoadingWheel").getEl(), {
            msg: "",
            msgCls: "findInTableMask"
        });
    }

    if(table.searchInListStatusText === undefined){
        //For story B-74832.
        //Search status box is replaced by search status label. So we need a new search status label.
        table.searchInListStatusText = Ext.getCmp(tableId + ".searchStatusLabel");
    }
    if (table.searchInListTextBox === undefined) {
        table.searchInListTextBox = Ext.getCmp(PTC.jca.table.findInTable.getSearchInListTextBoxName(tableId));
    }

    //For story B-74832.
    //If there is  selected row, It will not set search status text.
    if (!table.isSelectedOnlyItemsFilter) {
        // Loading indicator stuff required for proper alignment/display of loading wheel.
        //Search status box is replaced by search status label. So we have to set default text for new search status label.
        table.searchInListStatusText.setText(bundleHandler.get('com.ptc.core.ui.tableRB.SEARCH_IN_PROGRESS'), false);

    }

    table.searchInListLoadingWheel.show();
    var extraMaskDiv = getElementsByClassNameAndTag("ext-el-mask", table.searchInListLoadingWheel.el.dom, "div")[0];
    if (extraMaskDiv) {
        Ext.removeNode(extraMaskDiv);
    }
    var maskWheelDiv = getElementsByClassNameAndTag("titleBarMask", table.searchInListLoadingWheel.el.dom, "div")[0];
    if (maskWheelDiv) {
        var maskMsgDiv = maskWheelDiv.children[0];
        if (maskMsgDiv) {
            maskMsgDiv.className = "titleBarkMaskMsg";
        }
    }

    // VisibleColumns cache needs to be updated since user can hide/unhide columns on client.
    table.visibleColumns = PTC.jca.ColumnUtils.getVisibleColumns(table.getColumnModel());

    var dataLoading = (typeof table.store.isLoading === 'function' && table.store.isLoading());

    if (table.store.searchInListFilterByFunc === undefined) {
        table.store.searchInListFilterByFunc = function(record, recordId){
            // When select only view is also checked ON verify if record is selected.
            if (table.selectedOnlyChecked === true) {
                if (table.selModel.isIdSelected(recordId) === false) {
                    return false;
                }
            }

            var filterSearchText = table.searchInString;
            var visibleColumns = table.visibleColumns;
            var totalVisibleCols = visibleColumns.length;

            var displayString = null;
            for (var i = 0; i < totalVisibleCols; i++) {
                //dont participate in filtering if a record is marked as rowHidden=true from server side
                if (record && record.get("rowHidden") !== true ) {
                    displayString = jsca.columns.getJSCASearchText(table, visibleColumns[i], record);
                    if (filterSearchText.test(displayString)) {
                        return true;
                    }
                }
            }

            var hiddenColumnsToSearch = table.findInTableHiddenColumns;
            if (hiddenColumnsToSearch) {
                var totalHiddenColumnsToSearch = hiddenColumnsToSearch.length;
                for (var j = 0; j < totalHiddenColumnsToSearch; j++) {
                    if (record && record.get("rowHidden") !== true) {
                        displayString = record.get(hiddenColumnsToSearch[j]);
                        if (filterSearchText.test(displayString)) {
                           return true;
                        }
                    }
                }
            }

            return false;
        };
    }

    // Keep a snapshot of selected records to be restored after filter is removed.
    PTC.jca.table.findInTable.takeSelectionSnapshot(table);

    var eventsSuspendedAlready = table.store.eventsSuspended;
    table.store.suspendEvents();
    try {
        table.store.filterBy(table.store.searchInListFilterByFunc, table.store);
        if (!dataLoading) {
            PTC.jca.table.findInTable.afterSearch(table);
        }
    }
    finally {
        if (!eventsSuspendedAlready) {
            table.store.resumeEvents();
        }
    }

    // Make sure the selection snapshot only contains selected items hidden by the filter, so
    // remove any selections still visible after the filter is applied.
    PTC.jca.table.findInTable.applySelectionSnapshot(table);
    table.store.fireEvent('datachanged', table.store);
};

// Keep a snapshot of selected records to be restored after filter is removed.
PTC.jca.table.findInTable.takeSelectionSnapshot = function(table) {
    if (table.selModel.snapshot) {
        table.selModel.snapshot.addAll(table.selModel.selections.items);
    } else {
        table.selModel.snapshot = table.selModel.selections.clone();
    }
};

PTC.jca.table.findInTable.applySelectionSnapshot = function(table) {
    // restore selections potentially previously hidden by the filter
    if (table.selModel.snapshot) {
        var len = table.selModel.snapshot.getCount();
        if(len > 0){
            //suspend selModel events as this is only to get the selection in the UI
            //no change in selectionModel
            var eventsSuspendedAlready = table.selModel.eventsSuspended;
            table.selModel.suspendEvents();
            try{
                for (var r=len-1; r>=0; r--) {
                    var record = table.selModel.snapshot.itemAt(r);
                    var ridx = table.store.indexOf(record);
                    if (ridx >= 0) {
                        table.selModel.selectRow(ridx, true, null, record, true);
                        table.selModel.snapshot.remove(record);
                    }
                }
            }
            finally {
                if (!eventsSuspendedAlready) {
                    table.selModel.resumeEvents();
                }
            }
        }
        if (table.selModel.snapshot.getCount() === 0) {
            delete(table.selModel.snapshot);
        }
        PTC.jca.table.handleSelectAllCheckbox(table.selModel);
    }
};

//Return Search in List Text box name by passing table id.
PTC.jca.table.findInTable.getSearchInListTextBoxName = function(tableName) {
    return tableName + ".searchInListTextBox";
};


/**
 * @namespace
 */
PTC.jca.table.fit = {}; // create namespace for find in tree
/**
 * Adds an ext toolbar to the tree for allowing a server side find
 * @param {Ext.grid.GridPanel} table (although really meant for trees only, server side specific
 */
PTC.jca.table.installFindInTreeFeature = function(table){
    PTC.jca.table.fit._setDefaultState(table);
    PTC.jca.table.fit._installFitGuiComponents(table);
};

/**
 * Scroll table to result row (and optionally, highlight it)
 * @param {Ext.data.Record} rowRecord
 * @param {Boolean} shouldHilight
 */
PTC.jca.table.fit.showRow = function(rowRecord){
    var table = Ext.getCmp(rowRecord.store.jscaTableID);
    table.getView().focusRowCenter(rowRecord, 0);
    tableUtils.focusRow(table, table.getStore().indexOf(rowRecord), true);
};

/**
 * This is called if all data is already loaded in the data store. It searches through the data store's records
 * either forward or backward (store.findBy would only search forwards) to find the next match. It then makes a call
 * to pretend to be a server response, so PTC.jca.table.fit.searchRequestCallback can be used.
 *
 * Ext.data.Store.findBy() is not sufficient because it does not search backwards through the store.
 *
 */
PTC.jca.table.fit.clientOnlySearch = function(table, searchTerm) {
    var store = table.getStore();

    if (table.fitSafeSearchTermRegEx === null) {
        table.fitSafeSearchTermRegEx = PTC.jca.table.fit.getSafeSearchTerm(searchTerm);
    }

    var rowRecords = PTC.jca.table.fit.getRowsToSearch(table);
    var row;
    for (var i = 0; i < rowRecords.length; i++) {
        row = rowRecords[i];
        if (PTC.jca.table.fit.hasMatchingText(table, row, table.fitSafeSearchTermRegEx)) {
            PTC.jca.table.fit.imitateSearchRequestCallback(table, row, searchTerm);
            return;
        }
    }
    // If it gets here, then no rows have been found.
    PTC.jca.table.fit.imitateSearchRequestCallback(table, null, searchTerm);
};

/**
 * Escape all special regex chars except '*'. also cache safeSearchTerm on table
 * @param {PTC.jca.TreeGrid} table
 * @param {String} searchTerm
 * @return {RegExp}
 */
PTC.jca.table.fit.getSafeSearchTerm = function(searchTerm) {
    searchTerm = searchTerm.trim();//removing the preceding and trailing spaces
    // escape all special characters, except *, since the string will be used to create a regular expression
    var charsToEscapeRegExp = /([\.\+\?\[\^\]\$\(\)\{\}\=\!\:\|\\])/g;
    var safeSearchTerm = searchTerm.replace(charsToEscapeRegExp, '\\$1');
    // We want the * character to represent zero or more of any character.
    // A regular expression is used because replace("*", ".*") would only replaces the first instance.
    safeSearchTerm = safeSearchTerm.replace(/\*/g, ".*");

    // return the safe regex, and also ignore case
    return new RegExp(safeSearchTerm, 'i');
};

/**
 * Gets the rows to search in the order they should be searched
 * @param {PTC.jca.TreeGrid} table
 */
PTC.jca.table.fit.getRowsToSearch = function(table) {
    var store = table.getStore();
    var indexStartSearchFrom;

    var focusedRow = PTC.jca.table.Utils.getFocusedRowIndex(table);

    if (typeof focusedRow === 'undefined' || focusedRow < 0) {
        indexStartSearchFrom = table.fitIsForwardSearch ? 0 : store.getCount() - 1;
    } else {
        indexStartSearchFrom = table.fitIsForwardSearch ? focusedRow + 1 : focusedRow - 1;
    }

    var rowRecords;
    if (table.fitIsForwardSearch) {
        if (indexStartSearchFrom === 0 || indexStartSearchFrom === store.getCount()) {
            // Get the records in order, example 0, 1, 2, 3, 4, 5.
            // This is needed because the following wont work store.getRange(0, -1) or store.getRange(store.getCount)
            rowRecords = store.getRange();
        } else {
            // Allow wrap around search, example 3, 4, 5, 0, 1, 2
            rowRecords = store.getRange(indexStartSearchFrom).concat(store.getRange(0, indexStartSearchFrom - 1));
        }
    } else {
        if (indexStartSearchFrom === -1 || indexStartSearchFrom === store.getCount() - 1) {
            // Get the records in backwards order, example 5, 4, 3, 2, 1, 0.
            rowRecords = store.getRange();
            rowRecords.reverse();
        } else {
            // Wrap around a backwards search, example 2, 1, 0, 5, 4, 3.
            var firstPart = store.getRange(0, indexStartSearchFrom);
            firstPart.reverse();
            var secondPart = store.getRange(indexStartSearchFrom + 1);
            secondPart.reverse();
            rowRecords = firstPart.concat(secondPart);
        }
    }
    return rowRecords;
};

/**
 * Go through each cell of a row, seeing if the cell's text matches.
 * searchTermRegEx should be regex safe. pass it through getSafeSearchTerm first
 * @param {PTC.jca.TreeGrid} table
 * @param {Ext.data.Record} row
 * @param {RegExp} searchTermRegEx
 * @return {Boolean}
 */
PTC.jca.table.fit.hasMatchingText = function(table, row, searchTermRegEx) {
    var colModel = table.getColumnModel();
    for (var i = 0; i < colModel.getColumnCount(); i++) {
        var column = colModel.getColumnAt(i);
        if (PTC.jca.ColumnUtils.isVisibleDataColumn(column)) {
            var text = jsca.columns.getJSCASearchText (table, column, row);
            if (text.match(searchTermRegEx)) {
                return true;
            }
        }
    }
    return false;
};

/**
 * Prepare the objects necessary for pretending to be a server response.
 * @param {PTC.jca.TreeGrid} table
 * @param {String} context
 * @param {String} searchTerm
 */
PTC.jca.table.fit.imitateSearchRequestCallback = function(table, row, searchTerm) {
    // construct an options variable that will hold info that PTC.jca.table.fit.searchRequestCallback needs
    var options = {};
    options.parameters = {};
    options.scope = table.getStore();
    options.parameters.fitSearchTerm = searchTerm;
    var pathInfo = PTC.jca.table.fit.getPathInTree(table.id, row);
    PTC.jca.table.fit.searchRequestCallback(options, pathInfo.oidsInPath, pathInfo.contextsInPath);
};

/**
 * Get an array of contexts and oids that are in the path to the given row.  This method requires all the tree data
 * be on the client.
 * @param {String} tableId
 * @param {Ext.data.Record} row
 * @return  An object with the property contextsInPath which is like ['rootNodeContext','nodeAlongPathContext','rowContext']
 * and oidsInPath which is filled with the oids of each parent like: ['rootOid', 'nodeAlongPathOid', 'rowOid']
 */
PTC.jca.table.fit.getPathInTree = function(tableId, row) {
    var contextsInPath = [];
    var oidsInPath = [];
    var index = 0;
    while (row) {
        oidsInPath[index] = row.get('oid');
        contextsInPath[index++] = PTC.jca.table.Utils.getRowUniqueIdentifier(row.get('jsca_context'));
        // no constant for '_parent'
        row = tableUtils.getTableRowFromContext(tableId, row.get('_parent'));
    }
    return {oidsInPath: oidsInPath, contextsInPath: contextsInPath};
};

/**
 * Did the event involve the parent node of the node we are trying to expand.
 * @param store
 * @param eventData we are assuming the rows involved in the event will be in eventData.data or eventData.chunk.data.
 */
PTC.jca.table.fit.didEventExpandParent = function(store, eventData) {
    // We can only check if the parent was in the event if the node we are looking at isn't a root node.
    if(store.fitOidsInMatchPathIndex >= store.fitOidsInMatchPath.length - 1) {
        return true;
    }
    // Ensure eventData exists, this will stop some events that we don't care about like sort that trigger datachanged.
    if(!eventData) {
        return false;
    }
    var parentContext = store.fitContextsInMatchPath[store.fitOidsInMatchPathIndex + 1];
    var data;
    if(eventData.chunk && Ext.isArray(eventData.chunk.data)) {
        // If the eventData contains a chunk with an array of data it is a datachanged event.
        data = eventData.chunk.data;
    } else if (eventData.data && eventData.data.jsca_context && store.getNodeChildren(store.getById(eventData.data.jsca_context)).length > 0) {
        // If the row doesn't have any children then assume it hasn't been expanded.  An async expand will cause the expandnode event to be
        // fired even though the row really isn't expanded.
        data = [eventData.data];
    } else {
        // There is no array of rows from the event so assume the parent wasn't involved in the event.
        return false;
    }
    var dataLength = data.length;
    // Check if the parent row was involved in the event.
    for(var i = 0; i < dataLength; i++) {
        if(PTC.jca.table.Utils.getRowUniqueIdentifier(data[i].jsca_context) === parentContext) {
            return true;
        }
    }
    return false;
};

/**
 * Process the expand node event
 * This gets called once for each node we have to expand to find the search results
 * @param {Ext.data.Store} store
 */
PTC.jca.table.fit.expandNodeCallback = function(store, eventData, parentExpanded) {
    var table = Ext.getCmp(store.jscaTableID);

    // Is this a real callback from our find in tree search results callback?
    if (store.fitOidsInMatchPathIndex >= 0 && store.fitOidsInMatchPathIndex < store.fitOidsInMatchPath.length) {
        var context = store.fitContextsInMatchPath[store.fitOidsInMatchPathIndex];
        var rowRecord = PTC.jca.table.Utils.getRecordByUniqueIdentifier(store, context);
        // If the row is not in the tree then add it. This should only occur when the tree is updated after this tree
        // was rendered.
        if (!rowRecord && (parentExpanded === true || PTC.jca.table.fit.didEventExpandParent(store, eventData))) {
            rowRecord = PTC.jca.table.fit.addRowToTree(store, context);
            if (rowRecord
                    && PTC.jca.table.Utils.getRowUniqueIdentifier(rowRecord.id) === store.fitContextsInMatchPath[0]
                    && store.fitOidsInMatchHasChildren) {
                rowRecord.data._is_leaf = false;
                table.getView().refresh();
            }
        }
        if (!rowRecord) {
            return;
        }
        // This is a parent of the matching node.
        if (store.fitOidsInMatchPathIndex !== 0) {
            // move on to next context in list
            store.fitOidsInMatchPathIndex--;

            if (store.isExpandedNode(rowRecord) || store.isLeafNode(rowRecord)) {
                // We don't need to expand the row so move on to the next node in the path.
                PTC.jca.table.fit.expandNodeCallback(store, null, true);
            } else {
                // expandNode will fire an event that will trigger this callback after the node is expanded.
                PTC.jca.expandNode(rowRecord, store);
            }
        } else { // This is the matching node so highlight it.
            PTC.jca.table.fit.showRow(rowRecord);
            // Remove the event listeners now since we are done expanding nodes.
            store.un('expandnode', PTC.jca.table.fit.expandNodeCallback);
            if (store.chunkEnabled) {
                store.un('datachanged', PTC.jca.table.fit.expandNodeCallback);
            }
            // Re-enable the default auto-expand.
            PTC.jca.enableAutoExpand(table);

            // after all server posts are done, finally return focus to the text field.
            // this must go here because node expanding takes round trip time.
            // focusing before the node expansion will cause loss of focus when the node expands.
            PTC.jca.table.fit.focusTextField(table);
            table.fitDone = true;
        }
    }
};

/**
 * Dynmically add the node to the tree
 * @param {Ext.data.Store} store
 * @param {Array} context
 */
PTC.jca.table.fit.addRowToTree = function(store, context){
    var params = {
            doAjaxUpdate : true,
            addSorted : true
    };
    // If the row is not the root then set its parent.
    if (store.fitOidsInMatchPathIndex <  store.fitOidsInMatchPath.length - 1) {
        params.parentOid = store.fitOidsInMatchPath[store.fitOidsInMatchPathIndex + 1];
    }
    var oidToAdd = store.fitOidsInMatchPath[store.fitOidsInMatchPathIndex];
    rowHandler.addRows( [ oidToAdd ], store.jscaTableID, null, params);
    return PTC.jca.table.Utils.getRecordByUniqueIdentifier(store, context);
};

/**
 * Process the "find in tree" server response...
 * The response will include a list of oids/nodes that need to be expanded (separated by a '^' character)
 * @param {Object} origOptions The object that comes back from the server
 * @param {String} oidsToExpand Oids separated by a '^'
 * @param {Array} contextsInMatchPath An array of the contexts in the matching path
 */
PTC.jca.table.fit.searchRequestCallback = function(origOptions, oidsInMatchPath, contextsInMatchPath,fitOidsInMatchHasChildren) {

    var origSearchTerm = origOptions.parameters.fitSearchTerm;
    var store = origOptions.scope;
    var table = Ext.getCmp(store.jscaTableID);

    // get the oids to expand from the server
    if (oidsInMatchPath && oidsInMatchPath.length > 0) {

        store.fitOidsInMatchPath = oidsInMatchPath;
        store.fitOidsInMatchPathIndex = oidsInMatchPath.length - 1;
        store.fitOidsInMatchHasChildren = fitOidsInMatchHasChildren;

        // remember last search term and oids
        table.fitPrevSearchTerm = origSearchTerm;

        store.fitContextsInMatchPath = contextsInMatchPath;
        // add listeners so we can know when nodes have been expanded
        store.on('expandnode', PTC.jca.table.fit.expandNodeCallback);
        // If it is a async table also listen for the datachanged event because the expandnode event can't be used
        // because it is fired when events are suspended.  The datachanged even't can't be used in sync trees
        // because it gets called before the node being expanded is set as having been expanded which causes issues
        // scrolling the row into the view.
        if(store.chunkEnabled) {
            store.on('datachanged', PTC.jca.table.fit.expandNodeCallback);
        }
        // expand nodes and highlight the match
        PTC.jca.table.fit.expandNodeCallback(store);

        PTC.jca.table.fit.clearSearchStatus(table);
    } else {
        // hide spinning "loading" indicator
        table.fitSearchStatusBoxWaitMask.hide();

        // Put the autoexpand listener back on.
        PTC.jca.enableAutoExpand(table);

        // no matches were found in the tree
        table.fitSearchStatus.setTitle(bundleHandler.getBundleStringAndInserts(
                'com.ptc.netmarkets.util.utilResource.FIT_NO_MATCH', [ origSearchTerm.escapeHTML() ]));
        table.fitSearchStatus.showBy(table.fitTextField.getEl());
        // return focus to the combo box.
        PTC.jca.table.fit.focusTextField(table);

        table.fitDone = true;
    }
};

/**
 * Waits a set amount of time before putting focus on the search textfield
 *
 * @param {PTC.jca.TreeGrid}
 *            table
 */
PTC.jca.table.fit.focusTextField = function(table) {
    // get the search field from the table's toolbar.
    var textField = Ext.getCmp(table.id + '.fitTextField');

    // focus it and hilight the text, and wait 10ms for IE to catch up.
    textField.focus(/*select all*/true, /*wait 10ms*/true);
};

/**
 * Either send the search request to the server via an Ext load command, or perform a clientside search
 * Should be global because caller is in _installFitGuiComponents
 * @param {PTC.jca.TreeGrid} table
 * @param {String} searchTerm
 */
PTC.jca.table.fit.performSearch = function(table){
    table.fitDone = false;

    // verify that the tree actually has something in it first
    if (table.getStore().getCount() <= 0) {
        return;
    }

    // Show spinning loading indicator when starting a search request
    table.fitSearchStatusBoxWaitMask.show();
    // Set status to "Searching..."
    table.fitSearchStatus.setTitle(bundleHandler.get('com.ptc.core.ui.tableRB.SEARCH_IN_PROGRESS'));
    table.fitSearchStatus.showBy(table.fitTextField.getEl());

    // Fixes look of mask in the toolbar.  Copied from extTable.jsfrag, 03/17/10.
    var extraMaskDiv = getElementsByClassNameAndTag("ext-el-mask", table.fitSearchStatusBoxWaitMask.el.dom, "div")[0];
    if (extraMaskDiv) {
        Ext.removeNode(extraMaskDiv);
    }

    var maskWheelDiv = getElementsByClassNameAndTag("findInTreeMask", table.fitSearchStatusBoxWaitMask.el.dom, "div")[0];
    if (maskWheelDiv) {
        var maskMsgDiv = maskWheelDiv.firstChild;
        if (maskMsgDiv) {
            maskMsgDiv.className = "titleBarkMaskMsg";
        }
    }

    // Need to check if all data is loaded.  If so, don't post to server!
    if (table.jcaTableConfig.findInTableMode === FindInTableMode.CLIENT_ONLY || PTC.jca.table.Utils.isAllDataLoaded(table)) {
        PTC.jca.table.fit.clientOnlySearch(table, table.searchTerm);
    } else {
        PTC.jca.table.fit.sendSearchRequest(table, table.searchTerm);
    }
};

/**
* Prepare for server request, then make it
* @param {PTC.jca.TreeGrid} table
* @param {String} searchTerm
* @param {Object} fitParams - To hold the request params passed in with the request options. Will check if the fitParams is populated before initializing.
*/
PTC.jca.table.fit.sendSearchRequest = function(table, searchTerm, fitParams) {
    // Object for search parameters.
    if(!fitParams) {
       fitParams = {};
    }

    fitParams.fitSearchTerm = searchTerm;
    fitParams.fitSearchDirection = table.fitIsForwardSearch ? "forward" : "backward";
    fitParams.acquire = 'row';

    var focusedRecord = PTC.jca.table.Utils.getFocusedRecord(table);
    if(focusedRecord) {
        var focuedRowContext = focusedRecord.get('jsca_context');
        if (focusedRecord.get('oid').indexOf('$') > 0) {
            focuedRowContext = PTC.jca.table.Utils.parseRowIdentifierWithDoller(focuedRowContext);
            focuedRowContext = focuedRowContext.substring(0, (focuedRowContext.length - 2));
            fitParams.fitStartSearchOid = focusedRecord.get('oid');
        } 
        fitParams.fitStartLocation = focuedRowContext;
    }
    // Add column visibility and sorting parameters.
    var columnsAndSort = PTC.jca.table.Utils.getTableColumnServerParameters(table);
    Ext.apply(fitParams, columnsAndSort);

    var url = PTC.jca.table.Utils.getTableUrl(table.id);
    var options = {
            scope: table.getStore(),
            parameters: fitParams
    };

    options.onSuccess = PTC.jca.table.fit.onSuccess;
    options.onException = PTC.jca.table.fit.onException;

    requestHandler.doRequest(url, options);
};

/**
 * Callback for search request on success
 */
PTC.jca.table.fit.onSuccess = function(transport){
    // find the FIT search results OIDS inside the response text (which may contain misc. stuff from JSPs)
    var origOptions = transport.request.options;
    var begin = transport.responseText.indexOf(FIT_SEARCH_RESULTS_BEGIN);

    if (begin >= 0) {
        var end = transport.responseText.indexOf(FIT_SEARCH_RESULTS_END);
        var jsonResponse = transport.responseText.slice(begin + FIT_SEARCH_RESULTS_BEGIN.length, end);
        var fitResponse = Ext.decode(jsonResponse);
        var contextsInMatchPath = fitResponse.fitContextsInMatchPath;
        // process this list of oids that we found
        PTC.jca.table.fit.searchRequestCallback(origOptions, fitResponse.fitOidsInMatchPath, contextsInMatchPath,fitResponse.fitOidsInMatchHasChildren);
    }
    else { // couldn't find any list of oids, so tell user
        PTC.jca.table.fit.searchRequestCallback(origOptions);
    }
};

/**
 * Callback for search request on exception
 */
PTC.jca.table.fit.onException = function(transport){
    var origOptions = transport.options;
    // tell user that we couldn't find what they were looking for
    PTC.jca.table.fit.searchRequestCallback(origOptions);
};

/**
 * Verify that the user-entered search term is valid.
 * Should be global because caller is in _installFitGuiComponents.
 *
 * @param {Ext.grid.GridPanel} table
*/
PTC.jca.table.fit.getSearchTerm = function(table) {
    // get user-typed text from combobox
    var fitTextFieldTag = table.fitTextField.getEl();
    var searchTerm = fitTextFieldTag.dom.value;

    // Ensure that the search term is reasonable with respect to Ext's tolerances.
    var newLineIndex = searchTerm.indexOf("\n");
    if (newLineIndex >= 0) {
        // preserve first line only of a multi-line paste
        searchTerm = searchTerm.substr(0, newLineIndex);
    }
    // limit search string to reasonable length
    searchTerm = searchTerm.substr(0, 100);

    if (searchTerm != table.fitPrevSearchTerm) {
        table.fitSafeSearchTermRegEx = null;
    }
    return searchTerm;
};

/**
 * Sets the search status to '', and hides the waiting mask
 * @param {PTC.jca.TreeGrid} table
 */
PTC.jca.table.fit.clearSearchStatus = function(table) {
    table.fitSearchStatus.hide();
    table.fitSearchStatus.setTitle('');
    table.fitSearchStatusBoxWaitMask.hide(); // hide loading indicator
};

// declare these callbacks
PTC.jca.table.fit.buttonCB = null;

/**
 * This is private. use PTC.jca.table.installFindInTreeFeature(table);
 * @param {PTC.jca.TreeGrid} table
 */
PTC.jca.table.fit._setDefaultState = function(table){

    // constants that are used by server (to designate begin & end of the path of OIDs from root to found row)
    FIT_SEARCH_RESULTS_BEGIN = "$$$FIT_SEARCH_RESULTS_BEGIN$$$";
    FIT_SEARCH_RESULTS_END = "$$$FIT_SEARCH_RESULTS_END$$$";

    table.fitSafeSearchTermRegEx = null;
    table.fitIsForwardSearch = true;
};

/**
 * This is private. use PTC.jca.table.installFindInTreeFeature(table);
 * @param {PTC.jca.TreeGrid} table
 */
PTC.jca.table.fit._installFitGuiComponents = function(table){

    // start of FIT initialization code:
    var fit_EmptySearchText = bundleHandler.get('com.ptc.netmarkets.util.utilResource.FIT_FIND_IN_PROMPT');

    PTC.jca.table.fit.buttonCB = function(button, event){
        var searchTerm = PTC.jca.table.fit.getSearchTerm(button.table);
        // We want to clear the status on the start of another search, not on focus of textfield. This clear will also
        // be called when a user presses enter, because this callback is called on the keypress enter listener.
        PTC.jca.table.fit.clearSearchStatus(table);
        // update the search direction based on which button was pressed
        if (searchTerm !== "" && searchTerm !== fit_EmptySearchText) {
            button.table.fitIsForwardSearch = button === button.table.fitSearchDownButton;

            // Quit autoexpanding rows until the search is done.
            PTC.jca.disableAutoExpand(table);
            button.table.searchTerm = searchTerm;
            if (button.table.fireEvent("beforePerformSearch", button.table)) {
                PTC.jca.table.fit.performSearch(button.table);
            }
        }
    };

    // Status text/tooltip on the find in tree toolbar.
    var fitSearchStatusText = PTC.jca.table.findInTable.getFindStatusText();

    // Size the textfield at 200px, ideally. If the containing panel is too narrow to accomodate
    // that plus the up/down search buttons and a glimpse of the status message, accept a smaller
    // size within reason.
    var fitTextFieldWidth = Math.max(Math.min(table.container.getWidth() - 90, 200), 80);
    if (table.container.getWidth() === 0) { // if the container width is undefined, use default size
        fitTextFieldWidth = 200;
    }

    // text field for search term
    var fitTextField = new Ext.form.TextField({
        width: fitTextFieldWidth,
        emptyText: getUnescapedText(fit_EmptySearchText),// The value fit_EmptySearchText comes with HTML encoded charactors. To remove that using getUnescapedText()
        value: '',
        selectOnFocus: true,
        id: table.getId() + '.fitTextField',
        tableName: table.getId(),
        table: table,
        enableKeyEvents: true, // to catch editing
        cls: 'invalidDrag', // needed so the user can focus on the text field without a "drag" occuring, this was an issue on the info page
        listeners: {
            'specialkey': function(textField, e){
                var keyValue = 0 + e.getKey(); // add to 0 is essential, else == tests fails inexplicably
                if (keyValue == e.ESC) {
                    textField.reset(); // clear typing, restore prompt text
                    PTC.jca.table.fit.clearSearchStatus(textField.table);
                }
            },
            'keypress': function(textField, e){
                PTC.jca.table.fit.clearSearchStatus(textField.table);

                // this must be in the 'keypress' listener because hiding
                // the event from the browser will only work here, not in 'specialkey'
                var keyValue = 0 + e.getKey(); // add to 0 is essential, else == tests fails inexplicably
                if (keyValue == e.ENTER) {
                    // suppress other events that would happen when a user hits enter
                    e.preventDefault();
                    PTC.jca.table.fit.buttonCB(textField.table.fitSearchDownButton, e); // ENTER == search for next match
                }
            }
        }
    });

    // search up & down buttons (added to the FIT toolbar)
    var fitUpButton = new Ext.Button({
        icon: 'netmarkets/images/upArrow.gif',
        tooltip: bundleHandler.get('com.ptc.netmarkets.util.utilResource.FIT_SEARCH_PREV_TOOLTIP'),
        handler: PTC.jca.table.fit.buttonCB,
        id: table.getId() + '.fitSearchUpButton',
        table: table
    });

    var fitDownButton = new Ext.Button({
        icon: 'netmarkets/images/downArrow.gif',
        tooltip: bundleHandler.get('com.ptc.netmarkets.util.utilResource.FIT_SEARCH_NEXT_TOOLTIP'),
        handler: PTC.jca.table.fit.buttonCB,
        id: table.getId() + '.fitSearchDownButton',
        table: table
    });

    var fitSearchStatusElementToMask = new Ext.Toolbar.TextItem({
        text: '',
        width: 30,
        height: 20
    });

    var fitComponents = [fitSearchStatusElementToMask, fitTextField, fitDownButton, fitUpButton];

    var fitInstalled = false;
    if (table.actionsToolBar) {
        // Find the white space in the middle of the toolbar, then insert Find in Tree after that.
        var toolBarItemsLen = table.actionsToolBar.items.getCount();
        // Iterate through the toolbar items to find the filler component.
        for (var i = 0; i < toolBarItemsLen; i++) {
            if (table.actionsToolBar.getComponent(i).isFill) {
                PTC.jca.table.fit.insertIntoToolbar(table, fitComponents, i);
                fitInstalled = true;
                break;
            }
        }
    }

    if (!fitInstalled) {
        // Create a new toolbar fit couldn't be installed in the existing toolbar.
        table.findInTreeToolBar = new Ext.Toolbar({
            id: table.getId() + '.findInTreeToolBar',
            renderTo: table.tbar,
            cls: 'ecaToolbar',
            items: ['->'].concat(fitComponents) // Add the FIT components defined above, and right-align them.
        });
    }

    // Save some of the FIT variables in the table to simplify accessing objects in callbacks.
    // Set the initial search direction to forward (used if user hits "enter" key first).
    table.fitSearchDownButton = fitDownButton;
    table.fitSearchUpButton = fitUpButton;
    table.fitTextField = fitTextField;
    table.fitSearchStatus = fitSearchStatusText;
    table.fitSearchStatusBoxWaitMask = new Ext.LoadMask(fitSearchStatusElementToMask.getEl(), {
        msg: '',
        msgCls: 'findInTreeMask'
    });
};

/**
 * Inserts all fitComponents into the table's actions toolbar after the specified index.
 * @param {Ext.grid.GridPanel} table
 * @param {Array} fitComponents
 * @param {int} index
 */
PTC.jca.table.fit.insertIntoToolbar = function(table, fitComponents, index) {
    // Found the white space toolbar item. Iterate backwards through the find in tree components above,
    // inserting all of them into the toolbar after the filler.
    var fitComponentLen = fitComponents.length;
    for (var compIndex = fitComponentLen - 1; compIndex > -1; compIndex--) {
        // i + 1 will do an 'insert-after'.
        table.actionsToolBar.insert(index + 1, fitComponents[compIndex]);
    }
    table.actionsToolBar.doLayout(); // Lazy render, so do layout.
};


/**
 * Adjusts for any variable height mistakes, where one rows is gigantic compared to the rest of the rows
 * and throws off the focusRowCenter function by making the focused row still off screen
 * 
 */
Ext.grid.GridView.prototype.focusRowCenterCorrectForMultiRowHeight = function(recordIndex){
   this.doUpdate();
   if (this.variableRowHeight === true) { 
       var y = Ext.get(this.getRow(recordIndex)).getOffsetsTo(this.innerHd)[1];
       if (y > this.scroller.dom.clientHeight || y < 0) {
           this.ensureVisible(recordIndex, 0, false);
       }
   }
};

/**
 * it brings rows to the center of row table if possible and 
 * if not then at least brings the row to visible view area of grid.
 */
Ext.grid.GridView.prototype.focusRowCenter = function(record, offset) {
    PTC.performance.startComponentActionTimer('row focus', this.grid.id); 

    if ( !(this.scroller === undefined || this.scroller === null ) &&
           this.scroller.dom.clientHeight === this.scroller.dom.scrollHeight ) {
        return;
    }

    var store = this.ds;
    var recordIndex = store.indexOf(record);

    // This record is not a rendered no
    // Thus there is no way to bring this row into focus
    if ( recordIndex > -1 ) {

        var visiableRowCount = this.getVisibleRowCount();
        var displacement = Math.floor( visiableRowCount / 2 );

        // Need the visible row could and displacement
        // to be able to calculate the offset from center
        var offsetFromCenter;

        if (typeof offset === 'number') {
            offsetFromCenter = Math.floor( displacement * offset );
        } else {
            offsetFromCenter = 0;
        }

        var renderableIndexes;
        if (typeof this.getAllRenderableRows === 'function') {
            renderableIndexes = this.getAllRenderableRows();
        } else {
            renderableIndexes = [];
            var storeCount = store.getTotalCount();
            for (var i=0; i<storeCount; i++) {
                renderableIndexes.push(i);
            }
        }

        if (this.variableRowHeight === true || renderableIndexes.length > ( this.scroller.dom.clientHeight / this.getCalculatedRowHeight() ) ) {

            if (store.jsca_table.vtip) {
                // Disable the scroll tooltip during programmatic scrolling.
                store.jsca_table.vtip.verticalScrollTip.disable();
            }

            var visiableRows = this.getVisibleRows();
            var visibleIndexes;
            if (visiableRows.indexes === null || visiableRows.indexes === undefined) {
                visibleIndexes = renderableIndexes.slice(visiableRows.first, visiableRows.last);
            } else {
                visibleIndexes = this.getVisibleRows().indexes;
            }

            var middleOfVisibleRows = visibleIndexes[ Math.ceil( (visiableRowCount-1) / 2 ) -1 ];
            var recordIndexInRenderedRows = renderableIndexes.indexOf( recordIndex );
            if(middleOfVisibleRows === undefined){
                this.focusRowCenterCorrectForMultiRowHeight(recordIndex);
            }else{
            if ( recordIndex < middleOfVisibleRows ) {
                // record is above the middle
                var testAbove = renderableIndexes[ recordIndexInRenderedRows - displacement + offsetFromCenter + 1];
                if ( testAbove !== undefined && testAbove !== null && testAbove > 0 ) {
                        this.ensureVisible(testAbove, 0, false);
                        this.focusRowCenterCorrectForMultiRowHeight(recordIndex);
                    } else if(this.variableRowHeight === true) {
                    this.focusRowCenterCorrectForMultiRowHeight(recordIndex);
                } else {
                    this.scrollToTop();
                }

            } else if ( recordIndex > middleOfVisibleRows ) {
                // record is below the middle
                var testBelow = renderableIndexes[ recordIndexInRenderedRows + displacement + offsetFromCenter ];
                var renderedBottomRow = renderableIndexes[ renderableIndexes.length-1 ];
                    //TO DO: on collapse syncFocusEl is not getting called up. May be we need to call it before collapse.
                if ( testBelow !== undefined && testBelow !== null && testBelow > 0 ) {
                        this.ensureVisible(testBelow,0, false);
                } else {
                        this.ensureVisible(renderedBottomRow, 0, false);
                    }
                    this.focusRowCenterCorrectForMultiRowHeight(recordIndex);
                } else{
                    this.focusRowCenterCorrectForMultiRowHeight(recordIndex);
                } 
            }
            

            if (store.jsca_table.vtip) {
                // Wait for the browser to actually scroll to the correct place, then enable the scroll tooltip again.
                setTimeout(function() {store.jsca_table.vtip.verticalScrollTip.enable();}, 20);
            }
        }
    }
    PTC.performance.stopComponentTimer (this.grid.id, null,  'rowFocus');    
};



// Create search namespace
Ext.namespace('PTC.search');
Ext.apply(PTC.search, new Ext.util.Observable());
PTC.search.addEvents('searchFired');

PTC.search.createNewItem = function(pickedObject) {

      var optionDisplayVal = pickedObject["containerInfo.name"];
      var optionInternalVal = pickedObject["oid"];
      var imageStr = pickedObject["typeIcon"];
      if(optionInternalVal.startsWith("OR:") || optionInternalVal.startsWith("VR:")) {
        optionInternalVal = optionInternalVal.substring(3);
      }

      var newItem = null;

      newItem= {
        boxLabel :'<div class="removableCheckBoxLabel"><img src="'+imageStr+'" /> ' +optionDisplayVal+'</div>',
        name :'' +optionInternalVal,
        id:'' + optionInternalVal,
        checked :false,
        disabled:false,
        qtip :''+optionDisplayVal,
        listeners : {
            check :PTC.search.changeListener
        },
        onRemoveFunction: PTC.search.RemoveContextCheckbox,
        label:optionDisplayVal
      };

      return newItem;
}

//story#2657031 - flag for maintaining stickiness on clf browse page.
PTC.search.doNotMaintainStickiness = false;
// This renders the global search text box.
PTC.search.globalSearch = function () {
    // The menu to show advanced search link and history launch page.
    var optionsMenu;
    var lblSearch;
    var toolTipEditHistory;
    var isSearchValidationEnabled = true;
    var menuInitialized = false;
    var twinField;
    var enableEmptySearch = false;
    var showXmlTagSearchDisableMessage = false;
    var loadMenu = new Ext.menu.Menu({
	      id: 'loadMenu',
	      floating: true,
	      autoWidth: true
	});




    function optionsMenuHandler(targetMenuItem,e) {
                    	var url = targetMenuItem.getItemId();
                        if (url.indexOf("OID:") > -1) {
                            var evt=window.event || e
                            if (!evt.target) {
                                evt.target=evt.srcElement;
                            }

                            if (evt.target.tagName == 'A' || evt.target.tagName == 'IMG') {
                                // this is a link click or icon click
                                return;
                            } else {
                                url = buildExecuteUrl(url.substr(4), true);
                                loadAdvSearchPage("event",url);
                                return;
                            }
                        }
                        if (url == 'ptc1/search/historySavedSearchDisplay') {
                            loadSearchPage('object_search_navigation','historySavedNavigation',e);
                            optionsMenu.hide();
                        } else if (url == 'wtcore/jsp/com/ptc/windchill/search/Search.jsp') {
                            loadAdvSearchPage(e,url);
                            optionsMenu.hide();
                        } else {
                       	    loadSearchPage('object_search_navigation','classificationExplorerNavigation',e);
                       	    optionsMenu.hide();
                        }
                    }

    // Display the links
    function displayLinks(response, options) {
        var responseJSON = Ext.util.JSON.decode(response.responseText);
        var addSeperator = false;
        for(var key in responseJSON) {
            if(responseJSON.hasOwnProperty(key)) {
                if (responseJSON[key].link.indexOf("OID:") == -1) {
                    optionsMenu.addSeparator();
                }
                var menuText = responseJSON[key].text;
                var url = responseJSON[key].link;
                 if (url.indexOf("OID:") > -1) {

                    menuText = getMenuText(url.substr(4), menuText, responseJSON[key].toolTip);
                  }

                var ttip = responseJSON[key].toolTip;
                var menuItem = new Ext.menu.Item({
                    text: menuText,
                    itemId : url,
                    icon: '',
                    tooltip: responseJSON[key].toolTip,
                    handler: optionsMenuHandler
                });
                 optionsMenu.addItem(menuItem);

                //Overriding tooltip
                if(ttip && ttip != '')
                {
                    Ext.QuickTips.register({
                      target: menuItem,
                      text: ttip
                   });
                }
            }

        }

    }

 function getMenuText(oid, displayText, toolTip) {
        var executeUrl = buildExecuteUrl(oid, true);
        var editUrl = buildExecuteUrl(oid, false);

        // Trying with table.
        var display = '<table ><tr><td >'
        display += '<div id="'+oid+'" class="x-menu-list-item" style="width:225px;overflow:hidden;text-overflow:ellipsis;"><a ext:qtip="'+ toolTip +'"  " href=javascript:loadAdvSearchPage(null,"' + executeUrl + '"); >' + displayText + '</a></div>';
        display += '</td><td align="right">';
        display += '<a href=javascript:loadAdvSearchPage(null,"' + editUrl + '"); >' + '<img ext:qtip="' + toolTipEditHistory + '" height="15" width="15" BORDER=1 src="netmarkets/jsp/search/edit_pencil.gif"/></a>';
        display += '</td></tr></table>'
        return display;

    }

    function buildExecuteUrl(oid, fireSearch) {

        return "netmarkets/jsp/search/search.jsp?fireSearch=" + fireSearch + "&selectedHistoryItem=" + oid;
    }

    // Load the search page.
    function loadSearch(obj, event) {
    	var typeMenuInitialized = PTC.search.globalTypeSelection.isTypeMenuInitialized();
    	if (!typeMenuInitialized) {
    		PTC.search.globalTypeSelection.refreshTypeShowMenu(false);
    		loadSearch.defer(100,this,[obj,event]);
    		return;
    	}
        var addedTypes = PTC.search.getAddedTypes();
        var selectedTypes = PTC.search.getSelectedTypes();
        var typeParams = 'preSelectionItems=' + addedTypes + '&searchType=' + selectedTypes;
        var trigMenu = PTC.search.globalTypeSelection.getTypeTriggerMenu();
        var typeStore = PTC.search.globalTypeSelection.getTypeMenuStore();
        var allItems = trigMenu.items;
        for (var i = 0, len = allItems.length; i < len;) {
            var mItem = allItems.get(i);
            var typeInternalName = mItem.getItemId()
            var storeRecordIndex = typeStore.find('internalValue', typeInternalName);
            if (storeRecordIndex >= 0) {
                var storeRecord = typeStore.getAt(storeRecordIndex );
                storeRecord.set('checked', mItem.checked)
            }
            i = i + 1;
        }

        var validationResult = PTC.search.validateSpecialTypes(PTC.search.globalTypeSelection.getTypeMenuStore());
        if (validationResult == false) {
            return;
        }
        var keyword = obj.getValue();
        keyword = keyword.toLowerCase();
        if (keyword.startsWith("xml:")){
            if(showXmlTagSearchDisableMessage){
                JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.XML_TAG_SEARCH_DISABLE_MESSAGE");
                    return;
            }
        }
        var multiTypeSelected = (selectedTypes.indexOf(',') > -1 || selectedTypes.indexOf('wt.fc.Persistable') > -1) ;
        var bCheckCriteria = (multiTypeSelected == true) || !enableEmptySearch;
	    if (isSearchValidationEnabled) {
    	    if (bCheckCriteria) {
    		    if (checkCriteria(obj.getValue())) {
    			JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.EMPTY_CRITERAI_MESSAGE");
    			return;
    		    }
    
    	    }
        }
        // If value is blank, we need not fire the search.
        // Just load the search page with the new type selection
        var url;
        PTC.search.fireEvent("searchFired", obj);
        if (obj.getValue() == "" && bCheckCriteria) {
            url = "wtcore/jsp/com/ptc/windchill/search/Search.jsp?globalSearchTextBox=true&" + typeParams;
        } else {
		//Fix for SPR 2166484 -  Unable to search for keywords which contains the letter "#" twice. EncodeUricomponent encodes the following characters: , / ? : @ & = + $ #
		var searchString = encodeURIComponent(obj.getValue());




            url = "wtcore/jsp/com/ptc/windchill/search/Search.jsp?globalSearchTextBox=true&currentPage=search&fireSearch=true&search_keyword=" + searchString + "&keywordkeywordField_SearchTextBox=" + searchString + "&" + encodeURI(typeParams);
            obj.reset( );
            obj.blur();


            // This is to force the trigger blur. The empty text is not
            // rendered back. We need to fire the trigger blur even
            // so that the empty text is rendered back.
            // This is a limitation with ext framework which we had to
            // resolve this way.
            obj.triggerBlur.defer(50, obj);
        }

        loadAdvSearchPage(event,url,obj);

      }


    return {
    	getOptionMenu : function() {
    		return optionsMenu;
    	},
        refreshHistoryRecords : function() {
	        optionsMenu.removeAll(true);
            var globalLinksUrl = 'netmarkets/jsp/search/getGlobalLinks.jsp';
            Ext.Ajax.request({
                url: getBaseHref() + globalLinksUrl,
                success: displayLinks
            });
          optionsMenu.hide();
        },
        fireSearchUsingGlobalTextBox : function(keyword) {
        	var event = "";
        	PTC.search.globalSearch.getGlobalSearchTextBox().setValue(keyword);
        	loadSearch(PTC.search.globalSearch.getGlobalSearchTextBox(),null);
        },
        getGlobalSearchTextBox : function() {
        	return twinField;
        },
        switchMenu : function() {
			loadMenu.hide();
			optionsMenu.show(twinField.el);
        },
        init : function() {
            // Fetch the localized labels.
            lblSearch = bundleHandler.get("com.ptc.windchill.enterprise.search.client.searchClientResource.SEARCH_LABEL");
			var loadingText = bundleHandler.get("com.ptc.core.ui.navigationRB.LOADING");
			var loadingItems = new Ext.menu.Item({
				id: 'loading_menu',
				icon: 'netmarkets/javascript/ext/resources/images/default/grid/loading.gif',
				text: '<div style ="width:125px;">' + loadingText + '</div>'
			});
			loadMenu.add(loadingItems);


            toolTipEditHistory = bundleHandler.get("com.ptc.windchill.enterprise.search.client.searchClientResource.EDIT_CRITERIA_LINK");
            isSearchValidationEnabled = PTC.search.isSearchValidationEnabled;
            enableEmptySearch = PTC.search.enableEmptySearch;
            showXmlTagSearchDisableMessage = PTC.search.showXmlTagSearchDisableMessage;

           optionsMenu = new Ext.menu.Menu({
                id: 'searchHistoryOptionsMenu',
                floating: true,
                cls: 'x-menu-no-icon',
                showSeparator: false
            });

            // Trigger to show the global search text box and launching page.
            twinField = new Ext.form.TwinTriggerField({
                renderTo: 'globalSearch',
                id: 'gloabalSearchField',
                autoWidth: true,
                trigger1Class: 'global-search-trigger',
                trigger2Class: 'global-arrow-trigger',
                emptyText: PTC.util.unescapeHTML(lblSearch) + ' . . .',
                scope: this,
                enableKeyEvents: true,
                listeners: {
                    'keypress': function (GlobalSearch, e) {
                    	PTC.wizard.limitCharsOnKeyPress('gloabalSearchField',0,1000,e);
			if (e.getKey() == e.ENTER) {
			    loadSearch(this,e);
			}

                    }
                },
                onTrigger1Click: function (event) {
                    loadSearch(this, event);
                },

                onTrigger2Click: function () {
                if (!menuInitialized) {
                	loadMenu.show(twinField.el);
                	menuInitialized = true;
                	PTC.search.globalSearch.refreshHistoryRecords();
                	PTC.search.globalSearch.switchMenu.defer(500,this);
                } else {
                	optionsMenu.show(twinField.el);
                }

                }
            });
            Ext.ComponentMgr.register(twinField);
            // Uncomment below if you wish to load the menu on header load.
            //PTC.search.globalSearch.refreshHistoryRecords();

        }
    };
}();



// Get the types added in the global type drop down.
PTC.search.getAddedTypes = function () {
    var addedType = '';
    var menuStore = PTC.search.globalTypeSelection.getTypeMenuStore();
    menuStore.each(function (item) {
        if (addedType != '') {
            addedType = addedType + ',';
        }
        addedType = addedType + item.get('internalValue');
    });
    return addedType;
}



// Get the types selected in the global type drop down.
PTC.search.getSelectedTypes = function () {
    var selectedType = '';
    var trigMenu = PTC.search.globalTypeSelection.getTypeTriggerMenu();
    var allItems = trigMenu.items;
    for (var i = 0, len = allItems.length; i < len;) {
        var mItem = allItems.get(i);
        if (mItem.checked) {
            if (selectedType != '') {
                selectedType = selectedType + ',';
            }
            selectedType = selectedType + mItem.getItemId();
        }
        i = i + 1;
    }

   if(selectedType==''){
           selectedType = "wt.fc.Persistable";
    }
    return selectedType;
}

// Global type dropdown.
PTC.search.globalTypeSelection = function () {
	var maxTypeDisplayCharLimit = 24;
    // Private variables here
    var lblChooseType;
    var lblAllType;
    var trigMenu;
    var menuStore;
    var triggerField;
    var globalTypeUrl = 'netmarkets/jsp/search/getGlobalTypes.jsp';
    // Replace this with the name of the div where you
    // want to render this component.
    var triggerRenderDiv = 'typeChooserTrigger';
    //var triggerRenderDiv = 'globalTypeDropDown';
    var fieldWidth = 155;
    var typeSelection = '';
    var typeMenuInitialized = false;


    function onTypeCheck(item) {
        var enable = false;
        if (isItemPersistable(item)) {
           if (item.checked) {
             enable = true;
           }
           manageState(enable);
        }
        //When you check/uncheck a type other than the persistable, we want to handle 'all types' differently
        else {
          handlingNormalTypes(item);
        }

        updateTriggerField.defer(20, this, [item]);
        // trigMenu.show.defer(20,trigMenu,[triggerField.el]);
    }


    function handlingNormalTypes(item) {
        var allItems = trigMenu.items;
        if (item != null) {
            if (isItemPersistable(item) == false && item.checked == false) {
            changeAllTypesState(false)

            }
        }

    }


    function manageState(enable) {
               if (enable) {

                enableAllMenuItems();

            } else {

                // We are checking now
                disableAllMenuItems();
            }

        }



    function disableAllMenuItems() {
        var allItems = trigMenu.items;
        for (var i = 0, len = allItems.length; i < len;) {
            var mItem = allItems.get(i);
            if (isItemPersistable(mItem) == false && mItem.getXType() == 'menucheckitem') {
                mItem.setChecked(false, false);
                changeAllTypesState(true)
            }
            i = i + 1;
        }
    }

    function enableAllMenuItems() {
        var allItems = trigMenu.items;
        for (var i = 0, len = allItems.length; i < len;) {
            var mItem = allItems.get(i);
            if (isItemPersistable(mItem) == false && mItem.getXType() == 'menucheckitem') {
                mItem.setDisabled(false);
            }
            i = i + 1;
        }
    }



    function isItemPersistable(mItem) {
        var result = false;
        if (mItem == null) {
            return result;
        }
        if (mItem.getItemId() == 'wt.fc.Persistable') {
            result = true;
        }
        return result;

    }

    function onTriggerFocus(obj) {
        PTC.search.globalTypeSelection.refreshTypeShowMenu(true);
        //trigMenu.show(triggerField.el);
    }

    function changeAllTypesState(value)
    {
         var allItems = trigMenu.items;
         var allType = allItems.get("wt.fc.Persistable");
     allType.setChecked(value)
     allType.setDisabled(value)
    }

  function updateTriggerField(item) {

      var allItems = trigMenu.items;
      var displayString = "";
        var selectedTypes = PTC.search.getSelectedTypes();
       //if seleced types contain Persistable type  we want to disable and check 'All types'
        if (selectedTypes == "wt.fc.Persistable") {
        changeAllTypesState(true)
        displayString= PTC.util.unescapeHTML(allItems.get( "wt.fc.Persistable").text);

      } else {
          for (var i = 0, len = allItems.length; i < len;) {
              var mItem = allItems.get(i);

              if (mItem.checked) {
                  if (displayString.length > 0) {
                      displayString = displayString + ", " + PTC.util.unescapeHTML(mItem.text);
                  } else {
                      displayString =PTC.util.unescapeHTML(mItem.text);
                  }
              }
              i = i + 1;
          }
      }
	  var ellipsedDisplay = Ext.util.Format.ellipsis(displayString, maxTypeDisplayCharLimit, false);
      triggerField.setValue(ellipsedDisplay);

        Ext.QuickTips.register({
            target: triggerField,
            text: displayString
        });



      if (item != null) {
          updatePreferenceAtServer();
      }
}

    function updatePreferenceAtServer() {
        var addedTypes = PTC.search.getAddedTypes();
        var selectedTypes = PTC.search.getSelectedTypes();
        var form = getMainForm();
        var CSRF_NONCE = (form.CSRF_NONCE) ? form.CSRF_NONCE.value : "";
        Ext.Ajax.request({
            url: getBaseHref() + 'netmarkets/jsp/search/updateTypePref.jsp',
            success: onTypeUpdatePref(),
            params: {
                preSelectionItems: addedTypes,
                searchType: selectedTypes,
                CSRF_NONCE : CSRF_NONCE
            }
        });

    }

    function onTypeUpdatePref(response, options) {

    }

    function typeStoreLoaded() {
        populateMenu();
        onTypeCheck(null);
    }

    function populateMenu() {
        trigMenu.removeAll();
        var persistableItem = null;
        menuStore.each(function (item) {

            if (item.get('internalValue') == 'wt.fc.Persistable') {
              persistableItem = item;
            } else {
            var menuItem = new Ext.menu.CheckItem({
            text: '<div style="overflow:hidden;text-overflow:ellipsis;">' + item.get('displayValue') + '</div>',
            handler: onTypeCheck,
            hideOnClick: false,
            checked: item.get('checked'),
            itemId: '' + item.get('internalValue')

            });

            trigMenu.addItem(menuItem);
            Ext.QuickTips.register({
                target: menuItem,
                text: menuItem.text
            });

        }
        });



    if (persistableItem != null) {

        trigMenu.addSeparator();
        var persistableMenuItem = new Ext.menu.CheckItem({
            text: '<div style="overflow:hidden;text-overflow:ellipsis;">' + persistableItem.get('displayValue') + '</div>',
            handler: onTypeCheck,
            checked: persistableItem.get('checked'),
            hideOnClick: false,
            itemId: '' + persistableItem.get('internalValue')
        });
        trigMenu.addItem(persistableMenuItem);
         Ext.QuickTips.register({
                target: persistableMenuItem,
                text: persistableMenuItem.text
            });


        if (persistableItem.get('checked') == true) {
            manageState(false);
        }


    }

		trigMenu.addEvents('globalSearchMenuLoaded');
		PTC.menu.fireEvent("globalSearchMenuLoaded", trigMenu);
    }



    return {
        // public properties
        // public methods
        init: function () {
            lblAllType = bundleHandler.getBundleStringAndInserts("com.ptc.windchill.enterprise.search.client.searchClientResource.ALL_TYPE_LABEL");
            lblChooseType = bundleHandler.getBundleStringAndInserts("com.ptc.windchill.enterprise.search.client.searchClientResource.CHOOSE_TYPE_LABEL");
            if (menuStore) {
                menuStore.destroy();
                trigMenu.removeAll();
                trigMenu.destroy();
            }



            menuStore = new Ext.data.JsonStore({
                // store configs
                autoDestroy: true,
                autoLoad: false,
                url: globalTypeUrl,
                storeId: 'typeStore',
                // reader configs
                idProperty: 'internalValue',
                fields: ['internalValue', 'imagePath', 'displayValue', {
                        name: 'checked',
                        type: 'boolean'
                    },
                    'parentType', {
                        name: 'allowMultiSelection',
                        type: 'boolean'
                    },
                    {
                    	name: 'denySingleContextSearch',
                    	type: 'boolean'
                    },
                    {
                        name: 'attributePanel',
                        type: 'boolean'
                    },
                    'callback', {
                        name: 'enabled',
                        type: 'boolean'
                    },
                    'enableIcon', 'disableIcon', 'toolTip']
            });

            menuStore.on('load', typeStoreLoaded, this);

            trigMenu = new Ext.menu.Menu({
                id: 'trigMenu',
                floating: true,
                minWidth:fieldWidth,
                width: fieldWidth
                //cls: 'x-menu-list x-menu-list-white'
            });

            triggerField = new Ext.form.TriggerField({
                renderTo: triggerRenderDiv,
                blankText: lblChooseType,
                emptyText: lblChooseType,
                width: fieldWidth + 16,
                scope: this,
                editable: false,
                triggerClass: 'global-arrow-trigger',
                onTriggerClick: function () {
                    PTC.search.globalTypeSelection.refreshTypeShowMenu(true);
                }
            });


            // Show the drop down on focus
            triggerField.on('focus', onTriggerFocus, this);
            menuStore.load();
            typeMenuInitialized = true;
        },
        loadGlobalTypes: function () {
            menuStore.load();
        },
        getTypeMenuStore: function () {
            return menuStore;
        },
        getTypeTriggerMenu: function () {
            return trigMenu;
        },
        refreshTypeShowMenu: function (expand) {
        	typeMenuInitialized = true;
            PTC.search.globalTypeSelection.loadGlobalTypes();
            if (expand == true) {
            	trigMenu.show(triggerField.el);
            }

        },
        isTypeMenuInitialized : function() {
        	return typeMenuInitialized;
        }

    };
}();


PTC.search.validateSpecialTypes = function (typeStore) {
    /*
      gettin only records where checked value is true. if the no of records returned is >1
      we have to check if any special types are selected
     */
    var parent;
    var specialTypeFlag = false;
    var childFlag = false
    var normalType = false
    var typeSelected = "";
    var filteredRecords = typeStore.query('checked', 'true')
    if (filteredRecords.item('wt.fc.Persistable')) {
        if (filteredRecords.item('wt.fc.Persistable').get('checked') == true) return true;
    }
    if (filteredRecords.getCount() > 1) {
        for (var j = 0; j < filteredRecords.getCount(); j++) {
            if (filteredRecords.items[j].get('allowMultiSelection') == false) {
                //the above if will be true only in case of special types.
                if (specialTypeFlag == false) {
                    parent = filteredRecords.items[j].get('parentType');
                    typeSelected = PTC.search.decodeForHTMLContent(filteredRecords.items[j].get('displayValue'));
                    specialTypeFlag = true;
                } else if (specialTypeFlag == true && filteredRecords.items[j].get('parentType') != parent) {
                    typeSelected = typeSelected + ", " + PTC.search.decodeForHTMLContent(filteredRecords.items[j].get('displayValue'));
                    //in case 2 special types are selected and their parents are different
                } else if (specialTypeFlag == true && filteredRecords.items[j].get('parentType') == parent) {
                    typeSelected = typeSelected + ", " + PTC.search.decodeForHTMLContent(filteredRecords.items[j].get('displayValue'));
                    childFlag = true;
                }
            } else if ((filteredRecords.items[j].get('checked') == true) && (filteredRecords.items[j].get('allowMultiSelection') == true)) { //in case we have two special types of the same parent and have another type
                normalType = true;
            }

        }
    } else if (filteredRecords.getCount() <= 1) {
        return true;
    }
    if ((specialTypeFlag == true && childFlag == true && normalType == false) || (specialTypeFlag == false && normalType == true)) return true;
    else {
        var insertsArr =new Array(typeSelected);
        JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.INDIVIDUAL_SEARCH_TYPE","",insertsArr);
        return false;
    }
}

