/**
 * @namespace
 * For column filtering related functions.
 * @internal
 */
PTC.jca.table.gridFilters = function(tableId){ };

/**
 * Column filter feature is not enabled OOTB because it's not working as desired yet for all columns/tables
 * @return true if enabled via wt.properties, false otherwise
 */
PTC.jca.table.gridFilters.isEnabled = function() {
    return (PTC.properties.getWTProperty("com.ptc.netmarkets.javascript.tableColumnFilteringEnabled") === "true");
};

/**
 * Returns "true" if it is OK to apply grid filters to the specified table.
 * ie. The user agrees to lose any row selections.
 *
 * @param {Ext.grid.GridPanel} table
 * @return "true" if OK to apply grid filters, "false" otherwise.
 */
PTC.jca.table.gridFilters.okToApplyFilters = function(table) {
    if (!PTC.jca.table.findInTable.clearSelectionConfirmation(table,
             'com.ptc.netmarkets.util.misc.miscResource.CLEAR_SELECTION_CONFIRM_ON_SEARCH',
             false/*stashed*/)) {
        return false;
    }
    if (!PTC.jca.table.findInTable.clearViewSelectedConfirmation(table,
             'com.ptc.netmarkets.util.misc.miscResource.CLEAR_VIEW_SELECTED_CONFIRM_ON_FILTER')) {
        return false;
    }
    return true;
};


/**
 * PTC.jca.table.gridFilters.clearGridFilters clear all GridFilters
 * clear stickiness parameter
 * @param {Ext.grid.GridPanel} table
 */
PTC.jca.table.gridFilters.clearGridFilters = function(table){
    PTC.jca.table.setObjectToSession(table.getId(), "gridFilters", null);
    if (table.filters && table.filters.filters) {
        table.filters.filters.each(function (filter) {
            filter.active = false;
        });
    }
};


/**
 * update GridFilters and remove Clear All Filters menu
 * @param {Ext.grid.GridPanel} grid
 */
PTC.jca.table.gridFilters.updateGridFilters = function(grid){

    if(grid){
        var view = grid.getView(),
        hmenu = view.hmenu;
        if(grid.view.hmenu.findById('clearAll')){
            grid.view.hmenu.remove('clearAll');
        }
        PTC.jca.table.gridFilters.updateColumnsTypes(grid, true);
    }
};

/**
 * @param {Object} store
 * @param {Object} columnID
 * @return {Array} unique values that are in the given table column. Determined by scanning table rows.
 */
PTC.jca.table.gridFilters.getColumnUniqueValues = function(store, columnID){
    var table = PTC.jca.table.Utils.getTable(store.jscaTableID);
    var column = table.colModel.getColumnById(columnID);
    var rows = (store.snapshot) ? store.snapshot.items : store.data.items;
    var ret = [];
    var len = rows.length;
    for (var i=0;i<len;i++) {
        var record = rows[i];
        var val = jsca.columns.getJSCASearchText(table, column, record);
        // need something other than '' to make the menu render ok (checkboxes overlapped when '' is set as an option)
        if(val === '') {
            val = '&nbsp;';
        }
        if(val){
            if(ret.indexOf(val)<0){
                ret[ret.length] = val;
            }
        }
    }
    return ret;
};

/**
 * Sets the filter.type is on each column config. The filter type is determined by:
 * 1st) filterType property on the column sent from the server
 * 2nd) scanning table rows and looking at the cell.renderer and typeof cell itself to infer what the filter type should be
 *
 * @param {Ext.grid.GridPanel} grid
 */
PTC.jca.table.gridFilters.setFilterTypes = function(grid) {

    var store = grid.store;
    var columnModel = grid.getColumnModel();
    var rows = (store.snapshot) ? store.snapshot.items : store.data.items;
    var from = 0;
    var to = rows.length;
    var view = grid.getView();
    if (view.scroller) {
        var visibleRows = view.getVisibleRows();
        from = visibleRows.first;
        to = visibleRows.last + 1;
    }
    for (var j = 0, colLen = columnModel.config.length; j < colLen; j++) {
        var column = columnModel.config[j];
        var colID = column.dataIndex;
        if (typeof (column.filter) !== 'undefined') {
            try {
                if (column.filterType) {
                    // use the filtering type declared on the server
                    column.filter.type = column.filterType;
                } else {
                    // scan the actual data to infer the filter type

                    // set column.filter.type to null as indication that we haven't yet inferred any filter type
                    column.filter.type = null;
                    for (var i = from; i < to; i++) {
                        var filterType = 'String';
                        var cellValue = rows[i].get(colID);
                        if (!cellValue || cellValue === '' || cellValue === ' ' || cellValue === '&nbsp;') {
                            // do not infer any filter if cell is undefined/empty, proceed and infer from next row
                            continue;
                        } else if (cellValue.gui && cellValue.gui.isDate) {
                            filterType = 'Date';
                        } else if (cellValue.renderer) {
                            filterType = PTC.jca.table.gridFilters.inferFilterTypeFromRenderer(cellValue.renderer);
                        }
                        if (column.filter.type === null) {
                            // initialize the filter.type to be whatever filterType we just inferred
                            column.filter.type = filterType;
                        } else if (filterType !== column.filter.type) {
                            // on subsequent rows, use String filter if inferred filterType does not match the
                            // previously inferred filter
                            column.filter.type = 'String';
                        }
                        // if 'String' filter was inferred, stop scanning further rows because that is already the most
                        // generic filter
                        if (column.filter.type === 'String') {
                            break;
                        }
                    }
                }
            } finally {
                // if above logic unable to infer any filter due to all cells being empty, or unexpected exception,
                // then just default to String filter
                if (column.filter.type === null) {
                    column.filter.type = 'String';
                }
            }
        }
    }
};

/**
 * @param {string|function} cellRenderer the renderer property off the cell. May be string or function so API handles
 * either. The server sends a string to the client, and that string is converted into function when the cell is first
 * rendered.
 *
 * @return the filter type based on the renderer. Will return 'String' if given renderer is unknown or undefined.
 */
PTC.jca.table.gridFilters.inferFilterTypeFromRenderer = function(cellRenderer){
    switch(cellRenderer) {
        case 'jsca.columns.booleanRenderer':
        case jsca.columns.booleanRenderer:
        case 'jsca.columns.enumeratedTypeRenderer':
        case jsca.columns.enumeratedTypeRenderer:
        case 'jsca.columns.imageRenderer':
        case jsca.columns.imageRenderer:
            return 'List';
        case 'jsca.columns.numericRenderer':
        case jsca.columns.numericRenderer:
            return 'Numeric';
        default:
            return 'String';
    }
};

/**
 * update options for enumeration columns
 * @param {Object} store
 * @param {Object} columnModel
 */
PTC.jca.table.gridFilters.updateColumnEnums = function(store,columnModel){
    var colLen = columnModel.config.length;
    for(var k=0; k<colLen; k++){
        if(columnModel.config[k].filter){
            var filter = columnModel.config[k].filter;
            if(filter.type==="List"){
                if (filter.menu){
                    filter.menu.destroy();
                }
                var options = PTC.jca.table.gridFilters.getColumnUniqueValues(store, filter.dataIndex);
                columnModel.config[k].filter.options = options;
            }
        }
    }
};

/**
 * @return number of records in JCA and Cadx tables
 * @param {Ext.grid.GridPanel} grid
 */
PTC.jca.table.gridFilters.findLength = function(grid){
    var length = 0;
    if (grid && grid.store) {
        length = (grid.store.snapshot) ? grid.store.snapshot.length : grid.store.totalLength;
        if (grid.store.data){
            length = (grid.store.data.length > length) ? grid.store.data.length : length;
        }
    }
    return length;
};

/**
 * update filter types for all columns and reconfigure grid
 * @param {Ext.grid.GridPanel} grid
 * @param {Boolean} forceReconfigure
 */
PTC.jca.table.gridFilters.updateColumnsTypes = function(grid, forceReconfigure){
    if (grid) {
        var length = PTC.jca.table.gridFilters.findLength(grid);
        //columns where filtering is turned off
        var turnedOffColumns = ['smallThumbnail','nitidus_partslink_resultTable_ThumbNail'];

        if((length>0)&&(!grid.jcaTableConfig.tree)&&(grid.jcaTableConfig.findInTableMode!==FindInTableMode.DISABLED)){
            var colModel = grid.getColumnModel();
            var len = colModel.config.length;
            var newFiltersAdded = false;
            for(var i=0;i<len;i++){
                if(!colModel.config[i].filter){
                    if(colModel.config[i].dataIndex && (turnedOffColumns.indexOf(colModel.config[i].dataIndex) < 0)){
                        newFiltersAdded = true;
                        colModel.config[i].filter={"dataIndex" : colModel.config[i].dataIndex};
                    }
                }
            }
            if(newFiltersAdded || forceReconfigure){
                PTC.jca.table.gridFilters.setFilterTypes(grid);
                PTC.jca.table.gridFilters.updateColumnEnums(grid.store, grid.getColumnModel());
                grid.reconfigure(grid.store, grid.getColumnModel());
            }
        }
    }
};

/**
 * set active filters which exists in ??
 * @param {Object} savedFiltersTerms
 * @param {Object} filters
 */
PTC.jca.table.gridFilters.setFiltersFromDataFilter = function(savedFiltersTerms, filters){
    var decodedSavedFiltersTerms = Ext.decode(savedFiltersTerms);
    var len = decodedSavedFiltersTerms.length;
    for(var i=0;i<len;i++){
        var filter = decodedSavedFiltersTerms[i];
        var gridFilter = filters.get(filter.field);
        if(gridFilter){
            var value = null;
            switch(gridFilter.type) {
                case 'Date':
                    var dateValue = new Date(filter.data.value);
                    if (filter.data.comparison === 'gt'){
                        value = {after: dateValue};
                    }else if(filter.data.comparison === 'lt'){
                        value = {before: dateValue};
                    }else{
                        value = {on: dateValue};
                    }
                    if (Object.keys(gridFilter.getValue()).length>0){
                        value = Ext.apply(value, gridFilter.getValue());
                    }
                    gridFilter.setValue(value);
                    break;

                case 'Numeric':
                    var val = filter.data.value;
                    if (filter.data.comparison === 'gt'){
                        value = {gt: val};
                    }else if(filter.data.comparison === 'lt'){
                        value = {lt: val};
                    }else{
                        value = {eq: val};
                    }
                    if (Object.keys(gridFilter.getValue()).length>0){
                        value = Ext.apply(value, gridFilter.getValue());
                    }
                    gridFilter.setValue(value);
                    break;

                case 'List':
                    gridFilter.menu.setSelected(gridFilter.menu.selected, false);
                    gridFilter.menu.setSelected(filter.data.value, true);
                    break;

                default :
                    gridFilter.setValue(filter.data.value);
                    break;
            }
            gridFilter.setActive(true);
        }
    }
};

//PTC EXT OVERRIDE
PTC.jca.table.gridFilters.overrideFilterImplementation = function() {
	Ext.override(Ext.ux.grid.GridFilters, {
        onReconfigure: function() {
            var grid = this.grid;
            var store = grid.store;
            // PTC EXT OVERRIDE - if searchInList filter or view selected only
            // filter applied then do not clear filters
            this.bindStore(this.grid.getStore());
            if (!PTC.jca.table.findInTable.isTableSearchFiltered(grid)
                    && !PTC.jca.table.isTableViewSelectedOnly(grid.id)) {
                store.clearFilter();
                //SPR 4823507 hide the objects of another type after clearing filter and apply sort
                PTC.jca.table.findInTable.makeRowHidden(store);
                store.applySort();
            }
            this.removeAll();
            this.addFilters(this.grid.getColumnModel());
            this.updateColumnHeadings();
            // Update view after grid reconfigure it will apply view change
            grid.getView().doPartialDataChange(true);
        },
        reload : function () {
            //PTC EXT OVERRIDE
            //start performance timer
            PTC.performance.startTimeGauge(this.grid.id, 'Column Filtering');
            this.grid.columnIsBeingFiltered = true;

            //clear Search in table filter if exists
            var searchField = Ext.getCmp(this.grid.store.jscaTableID + ".searchInListTextBox");
            if(searchField){
                searchField.clearTrigger.hide();
                PTC.jca.table.findInTable.clearSearchInList(this.grid);
                PTC.jca.clearStickyFromSession(this.grid.id);
            }

            this.grid.store.clearFilter(true);
            this.grid.store.filterBy(this.getRecordFilter());
            //PTC EXT OVERRIDE
            //turn off filtering wheel mask
            if (this.grid.gridFiltersLoadingWheel !== undefined) {
                this.grid.gridFiltersLoadingWheel.hide();
            }
            this.grid.columnIsBeingFiltered = false;
            //stop performance timer
            PTC.performance.stopTimeGauge(this.grid.id,'Filtering',false,1,true);
        },
        onStateChange : function (event, filter) {
            if (event === 'serialize') {
                return;
            }
            //PTC EXT OVERRIDE
            //clear selection
            if(filter.active && (filter.getValue()!==null && filter.getValue()!== '')){
                if (!PTC.jca.table.gridFilters.okToApplyFilters(this.grid)) {
                    // the user does not want to lose their selected rows
                    filter.setActive(false);
                    return;
                }
            }
            var savedSearchTerm = PTC.jca.table.getObjectFromSession(this.grid.id, "searchInListTextBox");
            if(!(filter.active) && savedSearchTerm){
                return;
            }
            if(savedSearchTerm)
            {
               var confirmMessage = "com.ptc.netmarkets.util.utilResource.CONFIRM_SEARCHREMOVED_WHENAPPLIED_COLUMNFILTER";
               if (!JCAConfirm(confirmMessage)) {
                   filter.setActive(false);
                   return;
               }
            }

            //PTC EXT OVERRIDE
            //setting filtering wheel mask
            if (this.grid.gridFiltersLoadingWheel === undefined) {
                this.grid.gridFiltersLoadingWheel = new Ext.LoadMask(Ext.getCmp(this.grid.id).getEl(),{msg:bundleHandler.get('com.ptc.netmarkets.util.utilResource.FILTERING')});
            }
            this.grid.gridFiltersLoadingWheel.show();

            if (filter == this.getMenuFilter()) {
                this.menu.setChecked(filter.active, false);
            }

            if ((this.autoReload || this.local) && !this.applyingState) {
                this.deferredUpdate.delay(this.updateBuffer);
            }
            this.updateColumnHeadings();

            if (!this.applyingState) {
                this.grid.saveState();
            }
            //PTC EXT OVERRIDE
            //set gridFilters parameter to the session
            PTC.jca.table.setObjectToSession(this.grid.store.jscaTableID, "gridFilters", Ext.encode(this.grid.filters.getFilterData()));

            this.grid.fireEvent('filterupdate', this, filter);
        }
    });

	Ext.override(Ext.ux.grid.filter.StringFilter, {
        /**
        * @private
        * Initialize the filter and install required menu items.
        * Adding 'keyup' event on text field.
        */
        init : function (config) {
            Ext.applyIf(config, {
                enableKeyEvents: true,
                iconCls: this.iconCls
            });
            this.inputItem = new Ext.form.TextField(config);
            this.inputItem.on('keyup', this.onInputKeyUp, this);
            this.menu.add(this.inputItem);
            this.updateTask = new Ext.util.DelayedTask(this.fireUpdate, this);
        },

        /**
        * Validate the provided Ext.data.Record against the filters configuration
        * and support wildcard.
        * Method uses displayed value for record with some structure (i.e. gui).
        * @param {Ext.data.Record} record The record to validate
        * @return {Boolean} true if the record is valid within the bounds
        * of the filter, false otherwise.
        */
        validateRecord : function (record) {
            var val = '';
            var table = PTC.jca.table.Utils.getTable(record.store.jscaTableID);
            var column = table.colModel.getColumnById(this.dataIndex);
            val = jsca.columns.getJSCASearchText(table, column, record);
            // switch empty string into ' ' to allow typing a space to find the rows with empty cells
            if(val === '') {
                val = ' ';
            }

            var wildcardified = this.getValue().replace(/[\-\[\]\/\{\}\(\)\+\?\.\\\^\$\|]/g, "\\$&");
            wildcardified = wildcardified.replace(/\*/g, ".*");
            var srch = new RegExp(wildcardified, "i");
            return srch.test(val);
        }
    });

    Ext.override(Ext.ux.grid.filter.NumericFilter, {
        /**
        * Validate the provided Ext.data.Record against the filters configuration.
        * Method uses comparable value for record with some structure (i.e. gui).
        * @param {Ext.data.Record} record The record to validate
        * @return {Boolean} true if the record is valid within the bounds
        * of the filter, false otherwise.
        */
        validateRecord : function (record) {
            var val = jsca.getComparable(record.get(this.dataIndex));
            if(!PTC.isDefined(val) || !val.toFixed){
                return false;
            }
            //rounding value to 2 digits after the decimal point, because by default NumericFilter operates on numbers rounded to 2 digits after the decimal point.
            val = Number((val).toFixed(2));
            var values = this.getValue();
            if (values.eq !== undefined && val != values.eq) {
                return false;
            }
            if (values.lt !== undefined && val >= values.lt) {
                return false;
            }
            if (values.gt !== undefined && val <= values.gt) {
                return false;
            }
            return true;
        }
    });

    Ext.override(Ext.ux.grid.filter.ListFilter,{
        /**
        * Validate the provided Ext.data.Record against the filters configuration.
        * Method uses displayed value for record with some structure (i.e. gui).
        * @param {Ext.data.Record} record The record to validate
        * @return {Boolean} true if the record is valid within the bounds
        * of the filter, false otherwise.
        */
        validateRecord : function (record) {
            var table = PTC.jca.table.Utils.getTable(record.store.jscaTableID);
            var column = table.colModel.getColumnById(this.dataIndex);
            val = jsca.columns.getJSCASearchText(table, column, record);
            // '&nbsp' used to make menu options render ok, so need convert blank into '&nbsp;' here for filter to work
            if(val === '') {
                val = '&nbsp;';
            }
            return this.getValue().indexOf(val) > -1;
        }
    });

    Ext.override(Ext.ux.grid.filter.DateFilter, {
        /**
        * @private
        * Template method that is to initialize the filter and install required menu items.
        */
        init : function (config) {
            var menuCfg, i, len, item, cfg, Cls;
            //PTC EXT OVERRIDE
            //adding localized labels
            this.afterText = bundleHandler.get('com.ptc.netmarkets.util.utilResource.AFTER');
            this.beforeText = bundleHandler.get('com.ptc.netmarkets.util.utilResource.BEFORE');
            this.onText = bundleHandler.get('com.ptc.netmarkets.util.utilResource.ON');

            menuCfg = Ext.apply(this.pickerOpts, {
                minDate: this.minDate,
                maxDate: this.maxDate,
                format:  this.dateFormat,
                listeners: {
                    scope: this,
                    select: this.onMenuSelect
                }
            });

            this.fields = {};
            for (i = 0, len = this.menuItems.length; i < len; i++) {
                item = this.menuItems[i];
                if (item !== '-') {
                    cfg = {
                        itemId: 'range-' + item,
                        text: this[item + 'Text'],
                        menu: new Ext.menu.DateMenu(
                            Ext.apply(menuCfg, {
                                itemId: item
                            })
                        ),
                        listeners: {
                            scope: this,
                            checkchange: this.onCheckChange
                        }
                    };
                    Cls = Ext.menu.CheckItem;
                    item = this.fields[item] = new Cls(cfg);
                }
                //this.add(item);
                this.menu.add(item);
            }
        },

        /**
        * Validate the provided Ext.data.Record against the filters configuration.
        * Method uses comparable value for record with some structure (i.e. gui).
        * @param {Ext.data.Record} record The record to validate
        * @return {Boolean} true if the record is valid within the bounds
        * of the filter, false otherwise.
        */
        validateRecord : function (record) {
            var val = jsca.getComparable(record.get(this.dataIndex));
            // if val is null return, else Date constructor produces date like: Wed Dec 31 1969 18:00:00 GMT-0600 (CST)
            if(!val) {
                return false;
            }
            val = new Date(val);
            if(isNaN(val.getTime())){
                return false;
            }
            val = val.clearTime().getTime();
            var key, pickerValue;
            for (key in this.fields) {
                if (this.fields[key].checked) {
                    pickerValue = this.getFieldValue(key).clearTime().getTime();
                    if (key == 'before' && pickerValue <= val) {
                        return false;
                    }
                    if (key == 'after' && pickerValue >= val) {
                        return false;
                    }
                    if (key == 'on' && pickerValue != val) {
                        return false;
                    }
                }
            }
            return true;
        }
    });
};


/*
 * Abstraction for Hidden Context Combo.
 * All interaction to hidden context combo *must* happen from here. 
 * */

PTC.search.HiddenContextPicker = new Object();
PTC.search.HiddenContextPicker.pickerId = 'containerTypeList';
/**
 * This function sets the selected contextType, selected contexts on hidden combo box. 
 * 
 */
PTC.search.HiddenContextPicker.setStatus = function(allContextStatus, contextType, selectedContexts) 
{
	var pickerId = this.pickerId;
	if(allContextStatus == true) {		
		$(pickerId + '$label$').value = contextType;
		$(pickerId).value = $(pickerId+'$label$').value;
	}
	else {
		$(pickerId + '$label$').value = 'FIND_CONTEXT';		
		$(pickerId).value = selectedContexts;	
		disableMemberOfCheckBoxes();
		PTC.search.updateMemberShipMessage();
	}
}
/**
 * This function set the status of check-boxes on hidden picker and also update it on server.
 * 
 */
PTC.search.HiddenContextPicker.setStatusFromUserSelection = function() {
	var allContextStatus = Ext.getCmp('all_contexts').checked;
	var contextType = PTC.search.ContexPickerData.allContextsSelectedName;

	var selectedContexts = '';
	for ( var i = 0; i < PTC.search.recentlyUsedContexts.getCount(); i++) {
		var item = Ext.getCmp(PTC.search.recentlyUsedContexts.itemAt(i).id);
		if (item.getValue() == true && item.id != 'all_contexts') {
			if (selectedContexts != '') {
				selectedContexts = selectedContexts + ',';
			}
			PTC.search.ContexPickerData.allContextsCheckedStatus = 0;
			selectedContexts = selectedContexts + item.id;
		}
	}

	//update Hidden context Picker status
	PTC.search.HiddenContextPicker.setStatus(allContextStatus, contextType, selectedContexts);

	// update preferences at server
	if(selectedContexts != ""){
		PTC.search.callContextChangeListenerOnServer(selectedContexts,true);
	}
	else{
		PTC.search.callUpdateAllContextOnServer('updateallContextsSelectedItem', contextType+"##"+(allContextStatus?1:0));
	}
}


/**
 * The namespace for the Windchill homepage functions.
 * @namespace
 * @name PTC.homepage
 */
Ext.namespace("PTC.homepage");

/**
 * Initial home page component ID, this value gets re-initiallized during the construction
 */
PTC.homepage.HOME_PAGE_ID = 'homePageTableContainermainInfoPagePanel';

/**
 * Creates the customizable homepage in the card manager. When a user navigates away from the homepage
 * it will delete itself, so the next time the user returns it will be a new homepage Tab in the card manager.
 * @param {Object} homepageConfig From server, contains defaultItems that MyTabPanel needs.
 */
PTC.homepage.createHomePage = function(homepageConfig) {
    var main_form; 
    // Set the browser window title.
    var title = bundleHandler.get('com.ptc.core.ui.navigationRB.WIN_TITLE_HOME_TAB_WINDCHILL_HOME');
    // SPR 2081891: Fix &Quote in tab title
    title = getUnescapedText(title);
    PTC.navigation.setPageTitle(title);

    var cardPanel = Ext.getCmp(PTC.navigation.cardManager);
    if (!homepageConfig) {
        cardPanel.doLayout();
        return;
    }

    //this has to be called before removing the existing card,
    //using getForm instead of getMainForm ensures we get the mainform for the home page and not some other
    main_form = PTC.util.getForm("homepageDivID");
    if(main_form) {
        PTC.util.removeChildScriptNodes(main_form);
        //SPR 2052457: save actual nodes instead of refs so we can put them back into the mainform later.
        var childNodes = main_form.childNodes;
        var savedChildNodes = [];
        for(var i = 0; i < childNodes.length; i++) {
            if(childNodes[i].nodeName === 'INPUT') {
                savedChildNodes.push(childNodes[i].cloneNode(true));
            }
        }
    }

    var cmp = Ext.getCmp(PTC.homepage.HOME_PAGE_ID);
    if(cmp) {
        PTC.homepage.destroyHomePage.call(cmp);
    }

    // create the contents of the homepage based on if the user is a site administrator or not, the homepage will render with a public and private tab for administrator users
    var panel = (homepageConfig.items.length > 1) ? PTC.homepage.createAdminHomePage(homepageConfig) : PTC.homepage.createNonAdminHomePage(homepageConfig);
	
    var homeMainPanel = PTC.infoPage.getMainPanel({id: 'homePageTableContainer'}, [panel]);
    homeMainPanel.clearCardContents = PTC.homepage.destroyHomePage; 
    PTC.homepage.HOME_PAGE_ID = homeMainPanel.getId();
	
    // Clean up any cardPanel tab that might still be around with the same ID as what we'll be using.
    
    cardPanel.add(homeMainPanel);
    cardPanel.getLayout().setActiveItem(PTC.homepage.HOME_PAGE_ID);    
    PTC.navigation.setActiveContentArea(PTC.homepage.HOME_PAGE_ID);
    cardPanel.doLayout();

    // add the main form element to this element
    if(main_form) {
        Ext.getCmp(PTC.homepage.HOME_PAGE_ID).getEl().dom.appendChild(main_form);
        PTC.util._setMainFormStartingElement(main_form);

        //SPR 2052457: in IE the main_form is cleared out during the call to "cardPanel.getLayout().setActiveItem"
        //even though we still have a reference to it. In FF, the contents of main_form isn't lost so we don't need
        //to copy in the saved nodes, otherwise we will get duplicates
        if(Number(main_form.children.length) === 0) {//the length attribute is a string in IE7...
            for(var j = 0; j < savedChildNodes.length; j++) {
                main_form.appendChild(savedChildNodes[j]);
            }
        }
    }

};

/**
 * Builds a home page panel for a non admin user.  The returned panel will not be displayed as a tab, instead just the tab contents will be displayed.
 * 
 * @private
 * @param {Object} homepageConfig The config object is expected to have items and thirdLevelNavModel as properties, where the 'items' are the list of items to show 
 *                 in the tab and the 'thirdLevelNavModel' is the name of action model for the Customize menu
 * @return {PTC.infoPage.myTab.MyTabPanel} an Info Page Tab, the tab will no be rendered like a true info page tab, only the contents will be displayed  
 */
PTC.homepage.createNonAdminHomePage = function(homepageConfig) {
    homepageConfig.id = 'user-homepage';
    var infoModel = PTC.homepage.buildInfoPageModel(homepageConfig);
    
    var defaultTab = infoModel.tabSet.items[0];
    
    // set isSiteConfig property to trigger a new user defined to be created when the user modifies the OOTB homepage
    Ext.apply(infoModel.myTabConfig, {
    	isSiteConfig : defaultTab.isSiteConfig || defaultTab.isPublic
    });
    
    return PTC.infoPage.getTopTabPanel(infoModel);
};

/**
 * Builds a home page panel for a site administrator.  The returned tab panel will contain a public tab and a private tab.
 * 
 * @private
 * @param {Object} homepageConfig The config object is expected to have items and thirdLevelNavModel as properties, where the 'items' are the list of items to show 
 *                 in the tab and the 'thirdLevelNavModel' is the name of action model for the Customize menu
 * @return {Ext.ux.DockTabPanel} an Info Page Tab set Panel, containing a public and priavte tab  
 */
PTC.homepage.createAdminHomePage = function(homepageConfig) {
    homepageConfig.id = 'admin-homepage';
    var infoModel = PTC.homepage.buildInfoPageModel(homepageConfig);
    var publicTabConfig = PTC.homepage.getPublicTab(infoModel.tabSet.items);
    
    if(publicTabConfig) {
        publicTabConfig.inlineHelpMessage = bundleHandler.get('com.ptc.core.ui.componentRB.SITE_ADMIN_PUBLIC_HOMEPAGE_TAB_INLINE_HELP');
    }
    
    return PTC.infoPage.getTopTabPanel(infoModel);
};

/**
 * Builds an InfoModel object with the properties in the given homepageConfig object.
 * 
 * @private
 * @param {Object} homepageConfig The config object is expected to have items and thirdLevelNavModel as properties, where the 'items' are the list of items to show 
 *                 in the tab and the 'thirdLevelNavModel' is the name of action model for the Customize menu
 * @return {PTC.infoPage.InfoModel}
 */
PTC.homepage.buildInfoPageModel = function(homepageConfig) {

    // instantiating an InfoModel to apply some necessary functions
    var infoModel = Ext.apply(Object.clone(homepageConfig), new PTC.infoPage.InfoModel(), {
        myTabConfig : { /* add homepage tab specific properties so they can applied to the tab config in the tab renderer */
            id : homepageConfig.id || Ext.id(),
            isHomepageTab : true,
            isSiteConfig : false,  /* default to false for all tabs, override for non-admin users when it's the public tab being displayed */
            thirdLevelNavModel : homepageConfig.thirdLevelNavModel
        }
    });


    infoModel.tabSet = Ext.apply({}, {
        objectType : '' /* passing empty as the (tab set) action model is defined in the database and not in an XML file */,
        items : infoModel.items
    });
    
    // adds the id of the homepage tab renderer so that a different tab renderer is used for rendering the public/private tabs
    Ext.each (infoModel.items, function (tab) {
        Ext.apply(tab, {
            allowContextMenu: false, // we want the TOC links to be drag-n-droppable but we don't want the right click menu, there is another check in TabContextMenu to disable the menu for homepage tabs
            closable: false,
            closeAction: ''
        });
    });    
    
    return infoModel;
};

/**
 * Returns the first public tab in the given tabSet
 */
PTC.homepage.getPublicTab = function(tabSet) {
    var publicTab;
    
    for(var i=0, l=tabSet.length; i< l; i++) {
        if(tabSet[i].isPublic) {
            publicTab = tabSet[i];
            break;
        }
    }
    
    return publicTab;
};

/**
 * Destroy the homepage card object
 */

PTC.homepage.destroyHomePage = function() {
    this.removeAll(true);
    Ext.Panel.prototype.clearCardContents.call(this);
    var cardPanel = Ext.getCmp(PTC.navigation.cardManager);
    if(cardPanel) {
        cardPanel.remove(this.id, true);
    }
    this.destroy();
    Ext.garbageCollect();
    return true;
};



/**
 * Looks for 'img' and 'text' properties
 */
jsca.columns.imageRenderer = function(table, column, row) {
    var result = '';
    try {
        var data = jsca.columns.getCellValue(column, row);
    }
    catch (e) {
        jsca.log("no data item found for column id " + column.id);
    }
    return jsca.columns.imageRenderer.getHTML(data);
};

/**
 * renderer shared by JCA and GWT
 * @param data is the cell value. Expected to be either a json object with src, title, url... etc properties
 *          or a string such as "(Unassignable)", "???column_id???", "&nbsp;"... etc
 */
jsca.columns.imageRenderer.getHTML = function(data) {
    var result = '';
    try {
        if (data) {
            if (typeof data === "string" || data instanceof String) {
                // There was a problem with the server data utility or renderer.
                // Display whatever the server sent.
                return data;
            }
            if(data.img) {
                result = '<img src="' + data.img + '"';
                if (data.text) {
                     // "ext:qtip" is for ExtJS, "qtip" is for GWT
                     result += ' ext:qtip="' + data.text + '" qtip="' + data.text + '" ';
                }
                result += jsca.columns.idStr(data.id);
                if (data.styleClasses) {
                    result += data.styleClasses + " ";
                }
                if (data.jsactions) {
                   var jsmap = Object.keys(data.jsactions);
                   for (var i=0,l=jsmap.length; i<l; i++) {
                      var jsval = data.jsactions[jsmap[i]];
                      if (typeof jsval === 'string') {
                         result += (jsmap[i] + "=\"" + jsval + "\" ");
                      }
                   }
                }
                result += '/>';
                if(data.url) {
                    result = '<a href="'+data.url+'">'+result+'</a>';
                }
            }
            result = result + jsca.columns.getHiddenInputs(data.hiddenData);
        }
    }
    catch (e) {
        jsca.log("error creating rendered HTML from data json: " + data);
    }
    return result;
};

/**
 * @function the export renderer for images exports the tooltip.
 */
jsca.columns.imageRenderer.exportRenderer = function(table, column, row) {
    // get the data from the cell value
    var data = jsca.columns.getCellValue(column, row);
    // get the value to export
    var exportText = jsca.columns.imageRenderer.exportRendererForGWT(data);
    return exportText;
};

/**
 * @function the export renderer for GWT tables
 */
jsca.columns.imageRenderer.exportRendererForGWT = function(data) {
    var result = '';
    if (data) {
        if (typeof data === "string" || data instanceof String) {
            // There was a problem with the server data utility or renderer.
            // return whatever the server sent.
            return data;
        }
        if (data.text) {
            // the value we want to export is just the tooltip
             result = data.text;
        }
    }
    return result;
};

/** group images by tooltip */
jsca.columns.imageRenderer.groupFunc=jsca.columns.imageRenderer.exportRenderer;
/** search/filter images by tooltip */
jsca.columns.imageRenderer.searchFunc = jsca.columns.imageRenderer.exportRenderer;


/** @namespace
 * A namespace for info page table management related functions.
 * The infoPageTableMgr will keep track of the tables rendered on the info page,
 * for myTab and Details tab.  This is needed so that if the user wants to put
 * the same table on both tabs, we'll just move it back and forth.
 */
PTC.infoPageTableMgr = {};

PTC.infoPageTableMgr.log = log4javascript.getLogger('PTC.infoPageTableMgr');

// A collection mapping tabId to a list of tables for that tab
PTC.infoPageTableMgr._renderedTables = new Ext.util.MixedCollection();

/**
 * Register a tab to keep track of the tables on.
 * @param {Object} tabId
 */
PTC.infoPageTableMgr.registerTabId = function(tabId){
    PTC.infoPageTableMgr.log.debug('Register Tab with ID: ', tabId);
    PTC.infoPageTableMgr._renderedTables.add(tabId, []);
};

/**
 * Reset our rendered tables list
 */
PTC.infoPageTableMgr.cleanUp = function(){
    PTC.infoPageTableMgr._renderedTables = new Ext.util.MixedCollection();
};

/**
 * Get the tables associated for a certain tab (e.g., "myTab")
 * @param {String} tabId - the id of the tab
 * @return {Array} the rendered tables for the tab with the given id
 */
PTC.infoPageTableMgr._getRenderedTablesForTab = function(tabId){
    PTC.infoPageTableMgr.log.debug('Render tables for tab id: ', tabId);
    return PTC.infoPageTableMgr._renderedTables.get(tabId) || [];
};

/**
 * Gets all tables rendered any tabs other than the tab with the given id.
 *
 * @param {String} tabId - the id of the current tab
 * @return {Array} all the rendered tables for the all other tabs
 */
PTC.infoPageTableMgr._getRenderedTablesForOtherTabs = function(id){
    var result = [];
    PTC.infoPageTableMgr._renderedTables.eachKey(function(key){
        if (key !== id) {
            var tables = PTC.infoPageTableMgr._renderedTables.get(key);
            if (tables) {
                tables.each(function(table){
                    result[result.length] = table;
                });
            }
        }
    });

    PTC.infoPageTableMgr.log.debug('Rendered tables for other tabs: ', result, 'Current Tab: ', id);

    return result;
};

/**
 * Add a table to the rendered tables list
 * @param {String} tabId - the id of the tab the table is being added to
 * @return {TableHolder} The TableHolder object
 */
PTC.infoPageTableMgr._addRenderedTableForTab = function(tabId, TableHolder){
    var tables = PTC.infoPageTableMgr._renderedTables.get(tabId);
    if (!tables) {
        PTC.infoPageTableMgr.log.error("ERROR in PTC.infoPageTableMgr._addRenderedTableForTab: " ,
        "Trying to add tables to a tab that hasn't been registered. Recovering by registering the tab. tabId: " ,
        tabId);
        PTC.infoPageTableMgr.registerTabId(tabId);
        tables = PTC.infoPageTableMgr._renderedTables.get(tabId);
    }
    if (tables) { // this check returns false on customization examples UI
        tables.push(TableHolder);
    }
};

/**
 * Holds data about the table rendered on the info page
 * @param {String} id - id of the table
 * @param {String} containerDiv - where the table will be rendered
 * @param {String} tabId - the tab the table is rendered to
 */
PTC.infoPageTableMgr._TableHolder = function(tableId, containerDiv, tabId){
    this.id = tableId;
    this.containerDiv = containerDiv;
    this.tabId = tabId;
};

/**
 * Adds a table to the list of rendered tables.
 * Should be called whenever adding a table to the info page
 * @param {String} tableId - the id of the table
 * @param {String} containerDiv - the id of the div the table will be rendered to.
 * @param {String} tabId - the Id of the tab the table is being rendered in
 */
PTC.infoPageTableMgr.addRenderedTable = function(tableId, containerDiv, tabId){
    PTC.infoPageTableMgr.log.debug("addRenderedTable() table id: ", tableId, " Tab Id: ", tabId, " ContainerDiv: ", containerDiv);

    var TableHolder = new PTC.infoPageTableMgr._TableHolder(tableId, containerDiv, tabId);
    PTC.infoPageTableMgr._addRenderedTableForTab(tabId, TableHolder);

    var others = PTC.infoPageTableMgr._getRenderedTablesForOtherTabs(tabId);

    if (others) {
        for (var i = 0; i < others.length; i++) {
            var other = others[i];

            if (tableId === other.id) {
                other.putMeBack = true;
                PTC.infoPageTableMgr.log.debug("addRenderedTable() Set 'putMeBack' == true for table: ", other.containerDiv);
                // verify tab content is completely deleted out of the dom
                var containerEl = document.getElementById(other.containerDiv);
                if (containerEl) {
                    PTC.navigation.overwrite(containerEl, '');
                }
            }
        }
    }
};

/**
 * Remove a table from the renderedTables list.
 * Should be called whenever removing a table from the info page.
 * @param {String} containerDiv - the div the table was rendered in
 * @param {String} tabId - the Id of the tab the table was in
 */
PTC.infoPageTableMgr.removeRenderedTable = function(containerDiv, tabId){
    var tables = PTC.infoPageTableMgr._getRenderedTablesForTab(tabId);

    var temp = [];
    for (var i = 0; i < tables.length; i++) {
        if (tables[i].containerDiv !== containerDiv) {
            temp.push(tables[i]);
        }
    }

    PTC.infoPageTableMgr._renderedTables.remove(tabId);
    PTC.infoPageTableMgr._renderedTables.add(tabId, temp);
};

/**
 * Handle the tab change (e.g., from myTab to infoPage)
 * Need to remove tables common to both tabs (so they can appear to be
 * on multiple tabs) that aren't on the switched-to tab, and put them
 * back on the tab we're going to.
 * @param {Ext.TabPanel} tabPanel - the tabPanel for the info page
 * @param {Object} newTab - the tab we're changing to
 * @param {Object} oldTab - the tab we're coming from
 */
PTC.infoPageTableMgr.handleTabChange = function(tabPanel, newTab, oldTab){
    // do not do anything if the active tab didn't change or if the tabPanel is re-docking a dragged panel.
    // redocking doesn't change the active panel, but it does cycle through all the tabs, removing and adding
    if ((oldTab && newTab.id === oldTab.id) || tabPanel.docking === true) {
        PTC.infoPageTableMgr.log.debug("handleTabChange() active tab didn't change or just re-docking.");
        return true;
    }
    PTC.infoPageTableMgr.log.debug("handleTabChange() oldTab: ", (oldTab ? (oldTab.getId ? oldTab.getId() : "couldn't get oldTab id") : undefined), "newTab: ", newTab.getId(), " TabPanel: ", tabPanel);

    // If there is no oldTab, just return true
    if (!oldTab) {
        return true;
    }

    var newTables = PTC.infoPageTableMgr._getRenderedTablesForTab(newTab.getId());
    if ((!newTables || newTables.length === 0) && newTab && newTab.initialConfig) {
        //The tab may not have been rendered yet so also check the default table list
        newTables = newTab.initialConfig.defaultItems;
    }

    // If there are no tables we need to handle, just return true
    if (!newTables || newTables.length === 0) {
        return true;
    }

    var oldTables = PTC.infoPageTableMgr._getRenderedTablesForOtherTabs(newTab.getId());

    var tablesToClean = [];
    var tablesToRefresh = [];
    // Go through the tables list, put back tables that need replacing, and remove tables
    // we need to move (and mark them)
    for (var i = 0; i < newTables.length; i++) {
        for (var ii = 0; ii < oldTables.length; ii++) {
            if (newTables[i].id === oldTables[ii].id) {
                // So we can know later that we need to restore this table
                oldTables[ii].putMeBack = true;
                PTC.infoPageTableMgr.log.debug("handleTabChange() Looping Tables - Set 'putMeBack' == true for table: ", oldTables[ii].containerDiv);
                tablesToClean.push(oldTables[ii]);
            }
        }
        if (newTables[i].putMeBack === true) {
            newTables[i].putMeBack = false;
            PTC.infoPageTableMgr.log.debug("handleTabChange() Looping Tables - Set 'putMeBack' == false for table: ", newTables[i].containerDiv);
            tablesToRefresh.push(newTables[i]);
        }
    }

    var divId, containerDiv;

    // clean the tables
    for (var j = 0; j < tablesToClean.length; j++) {
        PTC.infoPageTableMgr.log.debug("handleTabChange() Cleaning up table: ", tablesToClean[j].id);
        divId = tablesToClean[j].containerDiv;
        if (!divId) {
            return true;
        }
        containerDiv = document.getElementById(divId);
        if (!containerDiv) {
            return true;
        }
        PTC.navigation.overwrite(containerDiv, '');
    }

    // put back the tables we need to
    for (var k = 0; k < tablesToRefresh.length; k++) {
        var table = tablesToRefresh[k];
        var config = PTC.actionModel.getActionConfig(table.id, PTC.infoPage.myTab.getMyTabConfig(tabPanel).thirdLevelNavModel);
        PTC.infoPageTableMgr.log.debug("handleTabChange() Putting back table: ", table.id, " config: ", config);
        if(!config || !config.actionURL) {
            PTC.infoPageTableMgr.log.debug("WARNING handleTabChange() Could not find config/url to put back table: ", table.id);
            return true;
        }
        divId = table.containerDiv;
        if (!divId || !document.getElementById(divId)) {
            return true;
        }
        var dom = document.getElementById(divId);
        PTC.navigation.overwrite(dom, '<div style="background: url(netmarkets/javascript/ext/resources/images/default/shared/blue-loading.gif) no-repeat center center; height: 100px">&nbsp;</div>');
        getElementHtml(Ext.lib.Ajax.serializeForm(getMainForm()), divId, true, config.actionURL, false);
    }

    return true;
};

/**
 * Marks all tables on all info page tabs as "dirty", meaning when the user switches tabs the content on the tab just
 * switched to will be reloaded from the server. The currently active tab will not be updated until the user switches
 * away from and back to the tab.
 */
PTC.infoPageTableMgr.setAllRenderedTablesAsDirty = function() {
    PTC.infoPageTableMgr.log.debug('Setting all tables on infopage as needing to be replaced');

    PTC.infoPageTableMgr._renderedTables.eachKey(function(key) {
        var tables = PTC.infoPageTableMgr._renderedTables.get(key);
        if (tables) {
            tables.each(function(table) {
                table.putMeBack = true;
            });
        }
    });
};


Ext.namespace('PTC.lifeCycleDiagram');

PTC.lifeCycleDiagram.stateDiagramWindowName = 'stateDiagramWindow';

PTC.lifeCycleDiagram.showLifecycleDiagram = function(config) {
	PTC.lifeCycleDiagram.closeLifecycleDiagram();
	var loadingLabel =  bundleHandler.get('com.ptc.core.ui.navigationRB.LOADING');

    var win = new Ext.Window({
        id: PTC.lifeCycleDiagram.stateDiagramWindowName,
        title: config.title,
        layout:'table',
        width: config.width,
        height: config.height,
        autoScroll: true,
        padding: 10,
        items: [{html:'<img src="netmarkets/javascript/ext/ux/statusbar/images/loading.gif"/>'},{html: loadingLabel, cls:'lifeCycleDiagramText'}],
        layoutConfig: {
			columns:2
		}
    });
	
	win.show();

    var lifeCycleState = Ext.ComponentMgr.get('infoPageinfoPageTitleBarLifeCycleState');
    if (lifeCycleState) {
    	lifeCycleState.on('beforedestroy', PTC.lifeCycleDiagram.closeLifecycleDiagram);
    }

    var params = {diagramOid: config.oid};
    var url = getBaseHref() + 'ptc1/wnc/commonComponents/lifecycleStateDiagramController';
    var options = {
			parameters: params,
			asynchronous: true,
			onSuccess: PTC.lifeCycleDiagram.renderLifecycleDiagram
    };
    requestHandler.doRequest(url, options);
};

PTC.lifeCycleDiagram.closeLifecycleDiagram = function() {
	if (Ext.ComponentMgr.get(PTC.lifeCycleDiagram.stateDiagramWindowName)) {
	    Ext.ComponentMgr.get(PTC.lifeCycleDiagram.stateDiagramWindowName).close();
	}
};


PTC.lifeCycleDiagram.renderLifecycleDiagram = function(response) {
    var data = response.responseText;
    var config = Ext.util.JSON.decode(data);
    
    items = PTC.lifeCycleDiagram.createItems(config);

    var window = Ext.ComponentMgr.get(PTC.lifeCycleDiagram.stateDiagramWindowName);
    if (window) {
    	window.removeAll();
	    window.add(items);
	    window.doLayout();
    }
};

PTC.lifeCycleDiagram.createItems = function(config) {
	var items = [];

	for (var i = 0; i < config.nodes.length; i++) {
		var node = config.nodes[i];

		items = items.concat(PTC.lifeCycleDiagram.createParentNodeItems(node, config.selected, i === 0, i === config.nodes.length - 1));

		if (node.subRecords) {
			for (var j = 0; j < node.subRecords.length; j++) {
				items = items.concat(PTC.lifeCycleDiagram.createChildRecordItems(node.subRecords[j], config.selected));
			}
		}
	}

	return items;
};

PTC.lifeCycleDiagram.createParentNodeItems = function(node, parentSelected, first, last) {
	var items = [];

	var iconItem = {html:'<img src="' + node.iconURL + '"/>'};
	if (parentSelected) {
		iconItem.style = 'background:#ffebc6';
	}
	items.push(iconItem);

	var labelItem = {html:node.label, cls:'lifeCycleDiagramText'};
	if (node.selected) {
		labelItem.style = 'font-weight: bold';
	}
	items.push(labelItem);

	if (!last) {
		var barItem = {html:'<img height="9px" width="19px" src="netmarkets/images/lifecyclediagram/step_vertical_line.png"/>'};
		if (parentSelected) {
			barItem.style = 'background:#ffebc6';
		}
		items.push(barItem);
		items.push({});
	}

	return items;
};

PTC.lifeCycleDiagram.createChildRecordItems = function(subRecord, parentSelected) {
	var items = [];

	var recordBarItemStyleClass = 'lifeCycleDiagramVerticalConnector';
	if (parentSelected) {
		recordBarItemStyleClass = 'lifeCycleDiagramVerticalConnectorSelected';
	}
	var recordBarItem = {cellCls: recordBarItemStyleClass};
	items.push(recordBarItem);

	var title = {html:subRecord.title + ':', cls:'lifeCycleDiagramText lifeCycleDiagramSubRecordTitleText'};
	if (subRecord.selected) {
		title.cellCls = 'lifeCycleDiagramSubRecordTitleTextSelected';
	}

	var recordTableItems = [title];
	for (var i = 0; i < subRecord.nodes.length; i++) {
		recordTableItems = recordTableItems.concat(PTC.lifeCycleDiagram.createChildRecordNodeItems(subRecord.nodes[i], subRecord.selected, i === 0, i == subRecord.nodes.length - 1));
	}

	var recordTable =
		{
			layout:'table',
            layoutConfig: {
				columns:1000
			},
			items: recordTableItems
		};

	items.push(recordTable);

	var barItem = {html:'<img height="9px" width="19px" src="netmarkets/images/lifecyclediagram/step_vertical_line.png"/>'};
	if (parentSelected) {
		barItem.style = 'background:#ffebc6';
	}
	items.push(barItem);
	items.push({});

	return items;
};

PTC.lifeCycleDiagram.createChildRecordNodeItems = function(node, parentSelected, first, last) {
	var nodeHorizontalIconClass = '';
	if (parentSelected) {
		if (last) {
			nodeHorizontalIconClass = 'lifeCycleDiagramHorizontalIconSelectedNoBar';
		} else {
			nodeHorizontalIconClass = 'lifeCycleDiagramHorizontalIconSelected';
		}
	} else {
		if (last) {
			nodeHorizontalIconClass = 'lifeCycleDiagramHorizontalIconNoBar';
		} else {
			nodeHorizontalIconClass = 'lifeCycleDiagramHorizontalIcon';
		}
	}

	var items = [];

	var icon = {html:'<img src="' + node.iconURL + '"/>', cellCls: nodeHorizontalIconClass};
	items.push(icon);


	var label = {html:node.label,cls:'lifeCycleDiagramSubRecordText',colspan:3};
	if (parentSelected) {
		label.cellCls = 'lifeCycleDiagramSubRecordTextSelected';
	}
	if (node.selected) {
		label.style = 'font-weight: bold';
	}

	items.push(label);

	return {layout:'table', layoutConfig: {columns: 1}, items:items};
};


/**
 * @namespace
 * PTC.lightbox provides util functions to deal with lightbox window-like
 * UI to render action page content in popup-like modal lightbox window,
 * while masking the top window underneath.
 * It uses Ext.Window class to render the lightbox.
 *
 * To avoid possible issue with name collision for javascript objects for
 * the actions, it uses approach of loading action content into a lightbox iframe.
 * Also, using iframe approach will ensure that all the scripts loaded
 * into lightbox iframe is easily removed from page when Ext.Window.close() removes container
 * div block of lightbox iframe from the content area page when lighbox is deactivated.
 *
 */
PTC.lightbox = function(){
  var that = {}; // 'that' is used to make the object available to the private methods. 'this' is assigned to 'that' in init() method
    var LB_CONTENT_DIV_ID = 'Div'; // this div is container of lbConentIframe
    var LB_CONTENT_IFRAME_ID = 'lbContentIframe'; // lightbox content response is targeted to this iframe
    var LB_CONTENT_MASK_ID = "Mask";
    var EMPTY_HTML = 'templates/htmlcomp/Empty.html';
    // This list contains action names for actions which should be rendered as lightbox.
    // See isActionRenderedAsLightbox method above about usage note of this array.
    var ACTIONS_RENDERED_AS_LIGHTBOX = ['WFCHECKOUT', 
                                        'WFDOWNLOAD', 
                                        'SETSTATE', 
                                        'MULTIEDITATTR', 
                                        'MULTIRENAME', 
                                        'WFCHECKIN', 
                                        'WFUPLOAD', 
                                        'WFSAVEAS', 
                                        'REVISEITEMS', 
                                        'WSEXPORT', 
                                        'WFCANCELCHECKOUT', 
                                        'REPLACEMISSDEP', 
                                        'EDITATTACHMENTS', 
                                        'EDITASSOCIATION',
                                        'AUTO_ASSOCIATE',
                                        'UPDATEWS',
                                        'WF_CONTENT_COMPARE'];
   var LIGHTBOX_SUPPORTTESTED_WS_TABLE_ACTION_NAMES = ['WFREMOVE', 'WFMULTICHECKOUT', 'SETSTATE', 'MULTIEDITATTR', 'MULTIRENAME', 'WFCHECKIN', 'WFUPLOAD', 'WFSAVEAS', 'REVISEITEMSMULTI', 'WFIMPORT', 'WSEXPORT', 'WFCANCELCHECKOUT', 'REDIRECTUPDATEWS','EDITASSOCIATION','AUTO_ASSOCIATE','WFCHECKOUT','WFDOWNLOAD'];					
   // ACTIONS_NOT_RENDERED_MAXIMIZED contains a list of actions that are not rendered as a maximized window		   
   // maximized lightboxes uses different set of options and have ~2 seconds better performance in IE 
   // NOTE: Lightbox intentionally not show/rendered when it is created so a listener can be added 
   //       to the "afterrender" event to added another listener to iframe to watch for FBA login page.
   // TODO: 
   var ACTIONS_NOT_RENDERED_MAXIMIZED = ['CREATE_WS', 'REPLACEMISSDEP'];
   var MAXIMIZED_EXT_WINDOW_OPTIONTS = {		                                         
	closable: false,		                
	resizable: false,
	draggable: false,
	maximized: true,
	header: false, 
	headerAsText: false, 
	hideBorders: true,
	hideLabel: true,
	plain: true,
	preventBodyReset: true,
	shim: false,
	unstyled: true,
	autoScroll: true   		
   };

    if(Ext.isWebKit) {
        //Webkit browsers will not hide plugins below the Shim Iframe.   This listener will hide the plugins
        //if the windows or lightboxes overlap them.
        Ext.util.Observable.observeClass(Ext.Window);

        Ext.Window.on('activate', function(win) {
            var pluginListener = function() {
                PTC.util.handlePlugins(win);
            };

            PTC.util.on('checkplugins', pluginListener);
            PTC.util.firePluginChecks();

            win.on('deactivate', function(win) {
                PTC.util.un('checkplugins', pluginListener);
                PTC.util.firePluginChecks();
            });
        });
    }
   
    /**
   * Returns true if actionname, as specified in options, is found in the
   * specified enabledActionNames array.
   *
   * option object can be specified with following possible values:
   * { actionURL: 'actionURL value',
   *   actionName: 'actionName value'
   * }
   */
    var _isActionRenderedAsLightbox = function(options, enabledActionNames) {
        var actionName = null;
        if ('actionName' in options) {
            actionName = options.actionName;
        } else if ('actionURL' in options) {
            actionName = PTC.lightbox.getActionNameFromURL(options.actionURL);
        }
        if (actionName) {
            if (enabledActionNames.indexOf(actionName.toUpperCase()) !== -1) {
                that.log.debug("Rendering URL for action ", actionName, " as lightbox." );
                return true;
            }
        } else {
            that.log.debug("isActionEnabledForRenderingAsLightbox: Action name not specified. Action not rendered as lightbox");
        }
        return false;
    };

    /**
     * Takes the passed in value and formats to 98% of the value and rounds to nearest o
     */
    var getFormatedSize = function(value) {
      return Ext.util.Format.number(value * 0.98, 0);
    };

    /**
     * Default options used when deactivate() method is called. 
     */
    var initDeactivateOptions = function() {
            that.deactivateOptions = {
                lbWindow: null, // context iframe window. default is not to specify this.
                reloadParent: false, // reload (parent) window from where this lightbox was activated. default is false
                loadURL: null, // explicit URL to be loaded after lightbox has been deactivated. Default is not to specify this. Specify only if it's different from original page URL. 
                saveContent: false, // saves the iframe. Should be specified if lightbox content needs to be safekept for future re-use (for example to re-render safekept lightbox window. Default is false.
                afterJs: null, // calls the js function after closing the window. Default is not to specify this.
                cleanUpTables: true  // whether to clean up tables when removing the iframe.  Setting this to false fixes a memory leak in a jca wizard lightbox. 
            };
    };

    /**
     * reset configuration options of this lightbox
     */
    var resetConfigOptions = function() {
    	that.log.debug('Called PTC.lightbox.resetConfigOptions');
        that.activateOptions = {};
        initDeactivateOptions();
        that.resizeOptions = {
	        resizeHeightWithWindow: false,
	        resizeWidthWithWindow: false,
	        resizingParentWindow: false
      	};
      	that.initialActivatingWindow = null;
    };

    /**
     * log options value for specified options hash object. Do not
     * log too big DOM objects such as Window, Form as per list
     * of specified non loggable options  
     */
    var logOptions = function(options, notLoggableOptions) {
        var optionsHash = $H(options);
        var notLoggableOptionsArray = $A(notLoggableOptions);
        var someFunction = function( pair ){
            var value = pair.value;
            if (notLoggableOptionsArray.indexOf(pair.key) != -1) {
               // Don't log whole DOM object. Rather just log it's name if found.
               try { // avoid cross frame access issue
                 if (value.name) {
                    value = value.name;  
                 } else {
                    value = 'name not found?';  
                 }
               } catch(e) {
                  value = 'name not found?';
               }
            }
            that.log.debug('  ', pair.key, ': ', value);
        };
        optionsHash.each( someFunction, that ); // bind 'this' to each function as default this seems to point to window. See http://www.samsaffron.com/archive/2008/02/09/A+cleaner+way+to+iterate+through+Enumerable+lists+in+Prototype for detail.
    };
    
    /**
     * Returns true if lightbox needs to be masked during initial action page loading.
     */
    var isMaskLightbox = function() {
    	var maskLightbox = true;
    	that.log.debug('isMaskLightbox: maskLightbox: ', maskLightbox);
    	return maskLightbox;
    };

    return /**@scope PTC.lightbox */ {
        // Logger writes messages out to the console and the Method Server log
        log: log4javascript.getLogger('PTC.lightbox'),
        
        // lbContentWindow is map of created lightboxes with following type of entry:
        // key: id of iframe window in which lightbox content is rendered
        // value: Ext.Window object which renders content and masks container window.
        lbContentWindow: new Ext.util.MixedCollection(),
        activateOptions: {},
        deactivateOptions: {},
        resizeOptions: {
          resizeHeightWithWindow: false,
          resizeWidthWithWindow: false,
          resizingParentWindow: false
        },
        initialActivatingWindow: null,

    init: function() {
      // make 'this' visible in private methods as 'that' object
      that = this;      
      return this;
    },

    /**
     * Returns the lightbox window id. This is id of the lightbox iframe. Also, Ext Window id value
     * contains this id as prefix.
     */
        getLightboxWindowId: function() {
          if (typeof this.activateOptions.id != 'undefined') {
            return this.activateOptions.id;
          } else {
            return LB_CONTENT_IFRAME_ID;
          }
        },

    /**
         * Activates lightbox window on top of current window. The lightbox window
         * is not a real full-blown window. It behaves like a modal window with
         * overlay div masking the window from where lightbox is activated.
         * The modal window is a layered div which gets rendered on top of
         * the current window.
         *
         * In order to mask top browser window, activate() must be executed
         * in the execution context of top window. Use getWindow() to get reference
         * to top window.
         *
         * The lighbox behavior is provided using modal window component from
         * Ext-js library.
         *
         * @param options object to specify different options for using this
         *        lightbox. For get type request, href must be provided. For form-post
         *        type request, set target of form to getLightboxWindowId()+).
         * @return activateResult object provides activate result informarion. In most
         *         of cases, this need not be even assigned and looked at. However,
         *         this is used to pass back some of validation details, which can be
         *         used by calling function, as needed.
         * Example Usage: var activateResult = PTC.lightbox.activate( {
         *          activatingWindow: window //window from where this lightbox was activated. Needs to be specified when it's other than top window
         *          requestMethod: 'get'(default) or 'post'
         *          contentHref: href  // required only for get type of request
         *          postingFormName: form name of form whose target needs to be set to getLightboxWindowId() // required only for post request
         *            });
         */
        activate: function(options) {
            var activateResult = {};
            var lbContentIframe;
            this.log.debug('PTC.lightbox.activate options: ');
            // list of options which are not loggable as these are big 
            // objects such as JS Window or Form objects
            var notLoggableOptions = ['activatingWindow', 'form'];
            logOptions(options, notLoggableOptions); //private method and so without 'this' reference

            if (options) {
                this.setOptions(options);
            } else {
                this.log.warn("PTC.lightbox.activate() called without specifying options parameter. Options must be specified to use lightbox.");
                return;
            }
            initDeactivateOptions();

			// register PTC.navigation.historyChange event handler so that when main browser window URL is changed by user, 
			// lightbox is implicitly closed with same usability behavior as if user had:
			// (a) closed lightbox by clicking on Cancel button and (b) entered new URL in browser
	    	PTC.navigation.log.debug('Registering Lightbox history change event - PTC.lightbox.handleHistoryChange');
	    	PTC.navigation.on('historyChange', this.handleHistoryChange, this, {single: true});
	    
            // validate activateOptions and init lightbox
            var activateOptionsValid = this.validateActivateOptions();
            if (!activateOptionsValid) {
                this.activateOptions = null;
                activateResult.activated = false;
                return activateResult;
            }

            var activatedWithinLightboxWindow = this.isActivatedWithinLightboxWindow();
            if (activatedWithinLightboxWindow) {
                // This is case of a lightbox being activated within a lightbox.
                // Default behavior is content to be rendered in the
                // current lightbox iframe itself. This is normally case when
                // user clicks on a tab within page (say 'Advanced' tab in Checkout page)
                if (this.activateOptions.openNewLightbox) {
                    // TODO: Add this support as below by adding logic below AND in other methods:
                    // 1. Provide support to accept lightboxName as activate options.
                    // 2. When lightboxName is not specified, use default getLightboxWindowId() as name
                    // 2. Create lightbox iframe window using lightboxName as iframe window name.
                    // 2a. Store specified lightboxName in list of lightboxesActivated array
                    // 3. Modify isLightbox() & other methods to use lightboxName instead of getLightboxWindowId()
                    // 4. When lightbox is deactivated, remove lightboxName from lightboxesActivated array
                    this.activateOptions.openNewLightbox = false; // This is not supported yet, hence resetting to false for now
                }
                if (this.activateOptions.requestMethod === 'get') {
                    lbContentIframe = this.getLightboxIframeWindow();
                    if (lbContentIframe) {
                        // load requested content href into existing lightbox iframe window itself
                        lbContentIframe.location = this.contentIframeSrc;
                        this.log.debug('Loaded requested content href ' , this.contentIframeSrc, ' into existing lightbox iframe window.');
                    } else {
                        this.log.error('Lightbox Iframe Window could not be found to load content for URL: ', this.contentIframeSrc);
                    }
                }
            // Since we are re-using existing lightbox iframe itself, there
            // is no need to display lightbox in this case.
            }

            if (!activatedWithinLightboxWindow) {
                // Show content in new lightbox window
                this.displayLightbox();
            }

            if (this.activateOptions.requestMethod === 'post') { // this code block is purposely after displayLightbox() for a reason. See below for details.
                // While dealing with form post request, set target of the form
                // to newly created LB_CONTENT_IFRAME iframe window. This is done
                // so that form-post response will be automatically targeted to
                // this iframe window by browser.
                lbContentIframe = this.getLightboxIframeWindow();
                if (!lbContentIframe) {
                    // It seems that iframe has not been appended to DOM yet. Even though displayLightbox()
                    // function was executed, it may take few milliseconds for iframe to be
                    // available in DOM
                    this.log.debug("PTC.lightbox.activate: No iframe created yet with name: ", this.getLightboxWindowId());
                }
                // Safe keep original form target so that it can be reset later
                var postingFormName = this.activateOptions.postingFormName;
                var originalFormTarget = null;
                var activatingWindow = this.getActivatingWindow();
                var lbContentIframeId = this.getLightboxWindowId();
                if (activatingWindow.document.forms[postingFormName]) {
                    this.log.debug('PTC.lightbox.activate: Valid form found for postingFormName: ', postingFormName);
                    originalFormTarget = activatingWindow.document.forms[postingFormName].target;
                    this.log.debug('Submit form target temporarily changed from ', originalFormTarget, ' to ', lbContentIframeId);
                    activatingWindow.document.forms[postingFormName].target = lbContentIframeId; // avoid using setAttribute() as it causes script error in IE for cross-window use case
                } else {
                    // If form was created dynamically, document.forms[postingFormName] does not
                    // work consistently? If current window is same as activating window, we can try to
                    // access form directly as a work-around
                    if (activatingWindow === self) {
                        if ('form' in this.activateOptions) {
                            var postingForm = this.activateOptions.form;
                            originalFormTarget = postingForm.getAttribute('target');
                            postingForm.setAttribute('target', lbContentIframeId);
                            this.log.debug('Submit form target temporarily changed from ', originalFormTarget, ' to ', lbContentIframeId);
                        } else {
                            this.log.warn('PTC.lightbox.activate: No form could be found to target lightbox content. Current window is same as activating window.');
                        }
                    } else {
                        // form object can not be accessed in another window directly as it causes
                        // permisison denied issue
                        this.log.warn('PTC.lightbox.activate: No form could be found to target lightbox content. Current window is different from activating window');
                    }
                }

                if (originalFormTarget) {
                    this.activateOptions.postingFormOriginalTarget = originalFormTarget;
                }
            }
            activateResult.activated = true;
            this.setDeactivateOptions({lbWindow: this.getLightboxIframeWindow() /* context iframe window.*/ });

            return activateResult;
        },

        getLightboxIframeWindow: function() {
            var lightboxWin = null;
            var iframeId = this.getLightboxWindowId();
            this.log.debug('getLightboxIframeWindow: lightbox window iframe id: ', iframeId);
            // We need to check that the lightbox window exists because the frames array 
            // does not remove frames when delete from the DOM.
      if(this.lbContentWindow.containsKey(iframeId)) {
              // commented frame look-up by name. It still returns a value
              // even when iframe has been removed during Ext.Window close operation?
              var iframeElem = document.getElementById(iframeId);
              if (iframeElem) {
                lightboxWin = iframeElem.contentWindow;
              } else {
                this.log.warn('getLightboxIframeWindow: DOM does not have iframe with iframe id ', iframeId, '?');
              }
              lightboxWin = iframeElem ? iframeElem.contentWindow : null;
            } else {
              this.log.debug('getLightboxIframeWindow: lbContentWindow list does not contain item for lightbox window iframe id ', iframeId, '?');
            }
            return lightboxWin;
        },

        /**
       * See if activate request is launched from a lightbox window itself.
       */
        isActivatedWithinLightboxWindow: function() {
            this.log.trace('Called PTC.lightbox.isActivatedWithinLightboxWindow');
            var activatedWithinLightboxWindow = this.isLightbox(this.getActivatingWindow());
            this.log.debug('activatedWithinLightboxWindow: ', activatedWithinLightboxWindow);
            return activatedWithinLightboxWindow;
        },

        /**
         * Return  window from where this lightbox was activated. This is specified when
         * it's other than top window. For top window launch point, it's not specified
         * as keeping such reference is redundant.
         */
        getActivatingWindow: function() {
            return ('activatingWindow' in this.activateOptions) ? this.activateOptions.activatingWindow : this.getParentWindow();
        },

        /**
         * Returns URL of the action page requested to be launched as specified in
         * PTC.lightbox.activate options. If lightbox has already been activated,
         * then use logic as found in getContextAction() to get URL of the document currently
         * loaded in the lightbox.
         */
            getLighboxActivateActionURL: function(options) {
            var actionURL = null;
            var requestMethod = 'get';
            if ('requestMethod' in options) {
                requestMethod = options.requestMethod;
            }
            if (requestMethod === 'get') {
                if ('contentHref' in options) {
                    actionURL = options.contentHref;
                }
            } else if (requestMethod === 'post') {
                if ('postingFormName' in options) {
                    actionURL = this.getActivatingWindow().document.forms[options.postingFormName].getAttribute('action');
                }
            }
            if (!actionURL) {
                this.log.error('PTC.lightbox.getLighboxActivateActionURL: action URL could not be found from specified lightbox activate options.');
            }
            this.log.debug('URL of the action page requested to be launched as lightbox: ', actionURL);
            return actionURL;
        },

        setOptions: function(options) {
        	if (this.initialActivatingWindow === null && 'activateOptions' in this && 'activatingWindow' in this.activateOptions) {
        		// Lazily initialize initialActivatingWindow. 
        		// Note that when another activate() is called from within  lightbox itself (say for some 
        		// sort of refresh action within lightbox), initialActivatingWindow remains unchanged 
        		// to point to initial "real" activating window
        		this.initialActivatingWindow = this.activateOptions.activatingWindow;
        	}
            this.activateOptions = {
                // specify another unique id in activate options if use case requires more than one lightbox 
                // UI same time. This should be rarely used as more than one lightbox same time is not 
                // supported yet.
                id: LB_CONTENT_IFRAME_ID, 
              
                // get or post method used to load content in lightboxIframe iframe.
                // Use GET method for simple get request. When response is generated
                // through post request and is targeted to lightboxIframe, then
                // specify 'post'. contentHref is not required and is ignored for
                // post request.
                requestMethod: 'get',

                // Href URL to load into lightboxIframe using iframe's src attibute. Must be specified
                // for lightbox to be rendered for GET type HTTP request only. For post request,
                // contentHref is not applicable (and ignored) as form post request always
                // posts to form's action and response is expected to be targetted to lightboxIframe.
                contentHref: null,

                // form name of form whose target needs to be set to getLightboxWindowId() iframe.
                // Required only when requestMethod is 'post'.
                postingFormName: null,

                width: getFormatedSize(getWindowWidth()),
                height: getFormatedSize(getWindowHeight()),
                topYPosition: 50, // The Y position of the top edge of the Window on initial showing.
                // Defaults to centering the Window within the height of the Window's container
                positionInCenter: true, // set to true to postion this lightbox in center of host window. topYPosition is ignored in that case.
                title: '', // title of lightbox window as seen by user. Spefific page title should be specified.
                modal: true, // specify false if lightbox is desired to be non-modal (rare)
                layout: 'fit',
                autoScroll: true, // use overflow:'auto' on the panel's body element and show scroll bars automatically when necessary
                openNewLightbox: false, // specify true to render action content into another NEW lightbox window when activate was launched within lightbox window itself. TODO: Add this support
                isExistingLightBox: false, // used to determine is an existing lightbox existing the window for the set lightbox iframe id.
                closable: true, // used to determine if the lightbox should have close/cancel buttons.
                resizable: true, // false causes window to stay fixed in size, and when the content grows larger, add scrollbars
                onBeforeclose: this.onBeforecloseHandler // used to perform some prep processing before the lightbox window closes.
            };
            if (options) {
                Object.extend(this.activateOptions, options);
            }
        },

        /**
         * Returns context action of the document currently loaded in lightbox
         * window. Note that this action may not be same as was originally loaded
         * in lighbox during intial activate() call, as some other URL might
         * have been loaded in it during later interations.
         */
        getContextAction: function() {
            var contextAction = null;
            var contextActionURL = null;
            var lbIframeWindow = this.getLightboxIframeWindow();
            if (lbIframeWindow) {
                contextActionURL = lbIframeWindow.location;
            } else {
                this.log.error('Lightbox iframe window with name ',  getLightboxWindowId() , 'was not found?');
            }
            if (contextActionURL) {
                contextAction = this.getActionNameFromURL(contextActionURL);
            }
            return contextAction;
        },

        /**
         * PSC: following functions are used to mask/unmask lightbox when loading content page
         */
        masklightbox : function(){
          if (!isMaskLightbox()) {
          	// avoid masking during replay to work-around hang issue due to animated image transform overhead (SPR 2067453)
          	this.log.debug('masklightbox: masking not applicable. masklightbox call ignored');
          	return;
          }
          var lightboxParent = null;
          if (PTC.lightbox.isLightbox(self)) {
          lightboxParent = PTC.lightbox.getParentWindow();
          } else {
            lightboxParent = self;
          }
          var lightboxMaskId = this.getLightboxMaskId();
          if (lightboxParent.Ext.fly(lightboxMaskId)) { 
          	lightboxParent.Ext.getDom(lightboxMaskId).style.visibility='visible';
          	this.log.debug('masklightbox: masking lightbox loading with ', lightboxMaskId, 'masking element');
          } else {
          	this.log.debug('masklightbox: load masking not done as ', lightboxMaskId,' not found');
          }
        },

        unmasklightbox : function(){
          if (!isMaskLightbox()) {
          	// avoid masking/unmasking during replay to work-around hang issue due to animated image transform overhead (SPR 2067453)
          	this.log.debug('unmasklightbox: masking was not in effect. Hence unmasklightbox call ignored');
          	return;
          }
          var lightboxParent = null;
          if (PTC.lightbox.isLightbox(self)) {
          lightboxParent = PTC.lightbox.getParentWindow();
          } else {
            lightboxParent = self;
          }
          var lightboxMaskId = this.getLightboxMaskId();
          if (lightboxParent.Ext.fly(lightboxMaskId)) { // masking div should be removed from dom so as not to cause any performance issue
          	lightboxParent.Ext.removeNode(lightboxParent.Ext.getDom(lightboxMaskId));
          	this.log.debug('unmasklightbox: ', lightboxMaskId, 'masking element removed from dom');
          } else {
          	this.log.debug('unmasklightbox: unmask not done as', lightboxMaskId,' not found');
          }
        },

        /**
         * Prepare lightbox content div which is container of iframe in which
         * content is rendered. This content div is used to render content
         * through a lightbox as generated using Ext Window library.
         */
        displayLightbox: function() {
          this.log.trace('Called PTC.lightbox.displayLightbox');
          var lightboxWindowId = this.getLightboxWindowId();
            if(this.lbContentWindow.containsKey(lightboxWindowId)) {
              this.log.debug('Lightbox already existing.');
                this.activateOptions.isExistingLightBox = true;
            } else {
              // Create lbContent div HTML. Lightbox iframe is contained in this div.
              var contentDivHTML = this.createLbContentDivHTML();
              // Create lightbox content window using Ext.Window component.
              // contentDivHTML is set as html for this window.
              this.lbContentWindow.add(lightboxWindowId, this.createContentWindow(contentDivHTML));
            }

            if (this.activateOptions.positionInCenter) {
                var onShow = function( component ){
                    component.center();
                };
                this.lbContentWindow.get(lightboxWindowId).on('show', onShow );
            }

            //PSC: Unmask lightbox immediately if it is not Cadx
            //PSC: check if there is PTC variable just to make sure onLoad was not invoked for Empty.html
            var lightboxExtWindowAfterRender = function(component){
              //PSC: this function is registered on the onload event of the iframe, as first we don't have
              //PTC object at all (Empty.html is the content of the page). When onLoad event occurs for the
              //actual action, we have guarantee that this object is present.
        	  // For Form Based Authentication, code needs to recognize FBA login page and unmask lightbox.
        	  var lightboxIframeOnloadHandler = function(){
            	  var contentWindow = this.getLightboxIframeWindow();
            	  // If page is FBA login page the unmask the lightbox
            	  // This code follows similar pattern as implemented in function reloadIfResponseHasFormBasedAuth
            	  if (this.activateOptions.id === 'fba_relogin' || (contentWindow && contentWindow.document && contentWindow.document.forms.length === 1
                	  && contentWindow.document.forms[0].id === 'login')) {
            		  // Approach 1: Reload whole page to show FBA authentication in top level window 
            		  //   PTC.navigation.reloadWholeWindow();
            		  //   reloadWholeWindow seems to lose context of current navigation page.
            		  //   Is there somethig better to call to preserve current location?
            		  // Approach 2: Unmask page and allow authentication using lightbox
            		  //   This is more 
            		  this.unmasklightbox();
            		  //   Problem with this is the POST to original fill the lightbox iframe fails
            		  //   after authenticaton but that is unrelated to this change.
            		  return;
            	  } 
            	  // Unmask lightbox in all case except empty or is a cadx action
            	  if( contentWindow && contentWindow.PTC && 'htmlcomp' in contentWindow.PTC && !('isCadxAction' in contentWindow.PTC.htmlcomp) ){
	                  this.log.debug('Unmasking lightbox window for this is not cadx action');
	                  this.unmasklightbox();
            	  }
            	  contentWindow = null; // free up reference to allows proper garbage collection
              };
              Ext.fly(this.getLightboxWindowId()).on('load', lightboxIframeOnloadHandler, this);
            };
            this.lbContentWindow.get(lightboxWindowId).on('afterrender', lightboxExtWindowAfterRender, this);
            
            // content is not shown in lightbox window sometimes for embedded browser. 
            // This is likely caused due to action href dummy doNothing() function execution
            // happening before action onclick handler has completed loading content
            // into iframe window. Note that initial lightbox page content is just a div wrapping 
            // iframe element. Hence this content gets loaded fairly quickly. Howerver, actual
            // page content gets further requested as src of iframe and takes a while to
            // load. Meanwhile premature action href dummy doNothing() function execution could
            // cause iframe src content loading to be stopped.
            // As work-around, delay setting iframe src.
            if (this.activateOptions.requestMethod === 'get') {
              var that = this;
              var f = function() {$(that.getLightboxWindowId()).src=that.contentIframeSrc;};
              f.defer(1);
          }

            this.log.debug('displayLightbox: Calling show() method of lightbox window.');
            this.lbContentWindow.get(lightboxWindowId).show();
        },

        getLightboxDivId: function() {
            return this.getLightboxWindowId()+LB_CONTENT_DIV_ID;
        },

        getLightboxMaskId: function() {
          return this.getLightboxWindowId()+LB_CONTENT_MASK_ID;
        },

        /**
         * Create lbConent div HTML. This div is container of lbConentIframe.
         * Note that this div is not created dynamically using DOM API
         * as we don't want it to be part of DOM yet.
         */
        createLbContentDivHTML:  function() {
            // create outer div
            var idHTML = "id='" + this.getLightboxDivId() + "' ";
            var lbContentDivHTML = "<div style='height: 100%; width: 100%;'" + idHTML + "> \n";
            
            if (isMaskLightbox()) {
            	lbContentDivHTML += "  " + this.createLbContentMaskHTML() + "\n";
            } else {
            	this.log.debug("createLbContentDivHTML: Masking div not created as lightbox masking not needed");
            }
            // append inner floating div
            var innerDiv = "  <div style='height: 100%; width: 100%;'> \n";
            lbContentDivHTML+= innerDiv;

            // append <iframe> tag
            lbContentDivHTML+= "    " + this.createLbContentIframeHTML() + "\n";

            // end inner floating div
            lbContentDivHTML+= "  </div>";

            // end outer div
            lbContentDivHTML+= "</div>";

            this.log.debug("lbContentDivHTML:\n ", lbContentDivHTML);
            return lbContentDivHTML;
        },

        /**
         * Create lbConent iframe HTML. The lightbox content response is targeted
         * to this iframe. Don't create this iframe using DOM API, as it would try to
         * load the source content immediately. It should be
         * appended to DOM after overlay and lightbox main container div have been made visible.
         */
        createLbContentIframeHTML:  function() {
            var idHTML = "id='" + this.getLightboxWindowId() + "' ";
            var nameHTML = "name='" + this.getLightboxWindowId() + "' ";

            var srcHTML = "src=";
            if (this.contentIframeSrc) {
                srcHTML+= "'" + EMPTY_HTML + "'";
                
                // delay setting src attribute. This is done as work-around fix for
                // embedded browser where iframe content is not loaded sometimes. 
                //srcHTML+= "'" + this.contentIframeSrc + "'";
            } else {
                srcHTML+= "'" + EMPTY_HTML + "'";
                this.log.warn("PTC.lightbob.createLbContentIframeHTML: contentIframeSrc is null. No content can be loaded in the lightbox.");
            }
            
            var contentIframeHTML = "<iframe " + idHTML + nameHTML + " frameborder=0 style='height: 100%; width: 100%;' " + srcHTML + " </iframe>";
            this.log.debug("contentIframeHTML: ", contentIframeHTML);

            return contentIframeHTML;
        },

        /**
         * Instead of adding masking div with javascript, add it to lightbobx html
         * so it is visible when lightbox window is first shown. masklightbox/unmasklightbox
         * functions only show/hide this div
         */
        createLbContentMaskHTML:  function() {
            var idHTML = "id='" + this.getLightboxMaskId() + "' ";
            var nameHTML = "name='" + this.getLightboxMaskId() + "' ";

            var maskingClass = "controls-disabled contentloading";
            if (PTC.isOldGecko()) { // for old gecko engine based browser (e.g. seamonkey on unix), use different class
              maskingClass = "controls-disabled-unix-browser contentloading";
            } 

            var maskHTML = "<div " + idHTML + nameHTML + " class='" + maskingClass + "' style='width : 100%; height : 100%; visibility : visible;'></div>";
            
            this.log.debug("maskHTML: ", maskHTML);
            return maskHTML;
        },

        validateActivateOptions:  function() {
            // change requestMethod to lowercase for ease of later use
            this.activateOptions.requestMethod = this.activateOptions.requestMethod.toLowerCase();

            if (this.activateOptions.requestMethod === 'post') {
                // for form post request, target of the posting form will be
                // set to LB_CONTENT_IFRAME iframe (after this iframe has been
                // created). The post response will
                // be automatically targeted to this iframe by browser.
                // Ensure that form has been specified in options
                if (this.activateOptions.postingFormName) {
                    this.log.debug('PTC.lightbox.validateActivateOptions: postingFormName is ', this.activateOptions.postingFormName);
                    // ensure that form is valid form
                    var postingForm = this.getFormForLightboxTarget();
                    if (!postingForm) {
                        this.log.warn("PTC.lightbox.validateActivateOptions: Specified form for post type request does not exist. Lightbox can not be shown.");
                    }
                } else {
                    this.log.warn("PTC.lightbox.validateActivateOptions: No form was specified for a post type request. Lightbox can not be shown.");
                    return false;
                }

                // source is not applicable as response is automatically streamed back
                // to this iframe by browser as a result if posted form's target
                // pointing to this iframe
                this.contentIframeSrc = EMPTY_HTML; // dummy URL set to satisfy src attribute's requirement
            } else if (this.activateOptions.requestMethod === 'get') {
                // for simple get request, we can set contentHref to iframe's src
                if (this.activateOptions.contentHref) {
                    this.contentIframeSrc = this.activateOptions.contentHref;
                } else {
                    this.log.warn("PTC.lightbox.validateActivateOptions: No content href was specified for a get type request. Lightbox can not be shown.");
                    return false;
                }
            }
            return true; // indicates if activate options had valid required values
        },

        getFormForLightboxTarget: function() {
            var postingForm = null;
            var activatingWindow = this.getActivatingWindow();
            this.log.debug('PTC.lightbox.getFormForLightboxTarget: activatingWindow is ', activatingWindow.name);
            var postingFormName = this.activateOptions.postingFormName;
            postingForm = activatingWindow.document.forms[postingFormName];
            if (!postingForm) {
                this.log.warn("PTC.lightbox.getFormForLightboxTarget: No form found for specified form name ", postingFormName);
            } else {
                this.log.debug('PTC.lightbox.getFormForLightboxTarget: Valid form found for postingFormName ', this.activateOptions.postingFormName);
                return postingForm;
            }

            // If form was created dynamically, document.forms[postingFormName] does not
            // work consistently? If current window is same as activating window, we can try to
            // access form directly as a work-around
            if (activatingWindow === self) {
                this.log.debug('PTC.lightbox.getFormForLightboxTarget: Current window is same as activating window. Getting form directly from activateOptions.form as a work-around.');
                return this.activateOptions.form;
            }
            return postingForm;
        },

        /**
         * Create lightbox content window using Ext.Window component. Note that
         * Ext.Window is not a real window object. It's just javascript object
         * which provides functionality to manages lightbox and overlay (to mask main
         * page) div(s).
         */
        createContentWindow: function(contentDivHTML) {	    
            var parentWin = PTC.lightbox.getParentWindow(),
	        extWinOptions = {                   
                      title: this.activateOptions.title,
                      modal: this.activateOptions.modal,
                      layout: this.activateOptions.layout,
                      html: contentDivHTML                                                  
                };
	        var maximizeLbWindow = this.activateOptions.requestMethod === 'get' ?            
				this.isActionRenderedAsMaximizedLightbox(this.activateOptions.contentHref) : this.activateOptions.renderMaximized;		                	   
	    // if either the height of the width have been explicitely defined in the activation options then honor then and do not maximize the window
	    if (maximizeLbWindow) {
	          this.log.debug('createContentWindow: using Ext.Window options for maximized lightbox');
		  // using Ext.Window options below is a work around fix for performance SPR #2113356
		  // the performance regression from X-12 is found to be with Ext.Window component, which was not present in X-12
		  // the work-around is to render actions in a maximized lightbox which was found to give a 2 second performance gain
		  // TODO: revisit this section and have one set of Ext.Window properties as we upgrade Ext-Js library with performance improvements
	          Ext.applyIf(extWinOptions, MAXIMIZED_EXT_WINDOW_OPTIONTS);
		  this.activateOptions.positionInCenter = false;
		  this.resizeOptions.resizeMaximizedToParentWin = true;
	    } else {
	          this.log.debug('createContentWindow: using Ext.Window options for resizable lightbox');
	          Ext.applyIf(extWinOptions, {	
		        width: this.activateOptions.width,
		        closable: this.activateOptions.closable,
		        resizable: this.activateOptions.resizable,
		        y: this.activateOptions.topYPosition
		  });
	    }	    
	    //this.activateOptions.positionInCenter	    
            this.resizeWindowToParent();
            var contentWindow =  new Ext.Window(extWinOptions);

            if(typeof this.activateOptions.height != 'undefined') {
               contentWindow.height = getFormatedSize(this.activateOptions.height);
            }

            if (typeof this.activateOptions.onBeforeclose != 'undefined') {
               contentWindow.on('beforeclose', this.activateOptions.onBeforeclose, parentWin.PTC.lightbox); // passed scope object as parentWin
            }
            contentWindow.on('beforedestroy', this.beforeDestroyHandler, parentWin.PTC.lightbox); // passed scope object as parentWin

            contentWindow.on('resize', PTC.lightbox.resizeContent);

            Ext.EventManager.onWindowResize(PTC.lightbox.resizeParentWindow, parentWin, true);
            return contentWindow;
        },

        /**
         * Resizes the initial height and width of the lightbox window to fit inside the parent window. Updates the activateOptions.
         * @param parentWin the parent window the new lightbox.
         */
        resizeWindowToParent: function() {
          var parentWidth = getWindowWidth();
          if(parentWidth <= this.activateOptions.width) {
            this.activateOptions.width = getFormatedSize(parentWidth);
          }
          var parentHeight = getWindowHeight();
            if (typeof this.activateOptions.height != 'undefined' && parentHeight <= this.activateOptions.height) {
            this.activateOptions.height = getFormatedSize(parentHeight);
            this.activateOptions.positionInCenter = true;
            }
        },

        /**
         * Resizes the lightbox window when the parent window is resized.
         */
        resizeParentWindow: function(width,height){
            var parentWin = PTC.lightbox.getParentWindow();
            var lbWindows = parentWin.PTC.lightbox.lbContentWindow;
            var lbWindow = lbWindows.get(PTC.lightbox.getLightboxWindowId());
            if(lbWindow) {
                // check current lightbox size
                var lbSize = lbWindow.getSize(),
                    lbheight = lbSize.height,
                    lbwidth = lbSize.width,
                    newHeight = lbheight,
		    resizeOpts = parentWin.PTC.lightbox.resizeOptions;	
		// resizing here does not make sense, because the lightbox component completly overlays the main window
		// instead let Ext-JS lib events handle the resizing of the lightbox
		if (resizeOpts.resizeMaximizedToParentWin) { 
		    return;
		}
                if(lbheight >= height || resizeOpts.resizeHeightWithWindow) {
                    newHeight = getFormatedSize(height);
                    resizeOpts.resizeHeightWithWindow=true;
                }
                var newWidth = lbwidth;
                if(lbwidth >= width || resizeOpts.resizeWidthWithWindow) {
                    newWidth = getFormatedSize(width);
                    resizeOpts.resizeWidthWithWindow=true;
                }
                resizeOpts.resizingParentWindow=true;
                lbWindow.setSize(newWidth, newHeight);
                lbWindow.center();
            }
        },

        /**
         * Resizes the lightbox window with specified compact width & height. Note
         * that specified values is expected to be less that current size. Lightbox
         * window can not be expanded to bigger than current size using this method. 
         */
        resizeLightboxToCompactSize: function(width,height) {
            var lbWindow = this.lbContentWindow.get(this.getLightboxWindowId());
            if (lbWindow) {
              var oldWidth = lbWindow.getWidth();
              var oldHeight = lbWindow.getHeight();
              var newWidth = (width >= oldWidth) ? oldWidth : width;
              var newHeight = (height >= oldHeight) ? oldHeight : height;
              if( newWidth != oldWidth || newHeight != oldHeight ) {
                lbWindow.setSize(newWidth, newHeight);
                lbWindow.center();
                this.log.debug('resizeLightboxToCompactSize: Resized lightbox window to width ', width, ' and height ', height);
              }
            }
        },

        /**
         * Track resizing the lightbox window.
         */
        resizeContent: function(win, width, height) {
            var parentWin = PTC.lightbox.getParentWindow();
            if(!parentWin.PTC.lightbox.resizeOptions.resizingParentWindow) {
                parentWin.PTC.lightbox.resizeOptions.resizeHeightWithWindow=false;
                parentWin.PTC.lightbox.resizeOptions.resizeWidthWithWindow=false;
            }
            parentWin.PTC.lightbox.resizeOptions.resizingParentWindow=false;
        },

        setDeactivateOptions: function(options) {
          if (options) {
            Object.extend(this.deactivateOptions, options);
          }
        },

        /**
         * This is called before lightbox window is closed during explicit close()
         * call or implicit call when user clicks on close tool button. All the
         * pre close steps are performed here. Note that it is not possible
         * to set options when this method is called as a result of close button click.
         * As a work-around set any required options using this.setDeactivateOptions(options)
         * right after activating the lightbox window.
         */
        onBeforecloseHandler: function() {
            this.log.debug('Called PTC.lightbox.onBeforecloseHandler');

            this.log.debug('PTC.lightbox.deactivateOptions: ');
            // list of options which are not loggable as these are big 
            // objects such as JS Window or Form objects
            var notLoggableOptions = ['lbWindow'];
            logOptions(this.deactivateOptions, notLoggableOptions); //private method and so without 'this' reference

            // note that even though deactivateOptions.lbWindow is not used in this method,
            // this check is useful for use cases when deactivate() method is called
            // erroneously from a non lightbox window. This sanity check helps in
            // avoiding js error by returning with warning log.
            if (!this.deactivateOptions.lbWindow) {
                this.log.warn("Lightbox deactivate could not be done as lbWindow option was not specified.");
                return false;
            }
            if(this.deactivateOptions.saveContent) {
              this.log.debug('onBeforecloseHandler: hiding lightbox window component.');
              this.lbContentWindow.get(this.getLightboxWindowId()).hide();
              // if content needs to be saved, then lightbox Ext.Window is not expected 
              // to be closed and destroyed. Hence ondestroy event
              // handler is implicitly never executed. Call it explicitly so that after 
              // close clean up is done for this use case too.
              this.beforeDestroyHandler();
              return false; // this seems to fix issue of Ext.Window being unexpectedly destroyed with close button click
            } else {
              // if content is not to be saved, then registered ondestroy handler
              // will be implictily executed after lightbox window is closed and
              // destroyed.
              var lbDiv = Ext.getDom(this.getLightboxDivId()); 
              if (lbDiv) {
	          this.deactivateOptions.cleanUpTables = false;
                  PTC.navigation.removeIframes(lbDiv, this.deactivateOptions.cleanUpTables, true /* purge dom obj */);
               }
            }
        },

        /**
         * Close Ext.Window lightbox window component. onBeforeclose handler gets
         * implicitly called before Ext.Window is closed. Note that when user clicks
         * on close tool button in lightbox window, close() method is implcitly
         * called and deactivate() method is NOT called. Accordingly,
         * this method should do just close() call. Any other close related logic
         * should be done in the deactivate (onBeforeclose handler) method.
         *
         * Example Usage: PTC.lightbox.deactivate({
         *                   cancelAction: false, // false when user clicks on Cancel button
         *                   reloadParent: true // true when lightbox lanucher host window needs to be reloaded after lightbox is closed 
         *          });
         * If default options (refer to initDeactivateOptions for detail) is enough, then 
         * just PTC.lightbox.deactivate() can be called without specifying any option.
         *
         * @param deactivateOptions object. Refer to initDeactivateOptions() for
         *                                  default deactivateOptions values
         */
      deactivate: function(options) {
         this.log.debug('Called PTC.lightbox.deactivate');
         this.setDeactivateOptions(options);

         // note that even though deactivateOptions.lbWindow is not used in this method,
         // this check is useful for use cases when deactivate() method is called
         // erroneously from a non lightbox window. This sanity check helps in
         // avoiding js error by returning with warning log.
         if (!this.isLightbox(this.deactivateOptions.lbWindow) ) {
          this.log.warn('deactivate called when window is not even ligtbox? Call ignored.');
          return;
         }
         // Close Ext.Window component. This removes underlying lightbox and overlay divs from DOM.
         // The contained iframe showing lightbox content is also removed from DOM when container
         // lightbox div is removed.
         var lightboxWindowId = this.getLightboxWindowId();
         if (this.lbContentWindow.containsKey(lightboxWindowId)) {
              if(this.deactivateOptions.saveContent === true) {
                  this.onBeforecloseHandler();
              } else {
                  this.log.debug('deactivate: Calling Ext.Window.close() to close lightbox component.');
                  // SPR 2260140 - IE11 specific defer the closing of the lightbox iframe until all the scripts are finished executing
                  var lbWin = this.lbContentWindow.get(lightboxWindowId);
                  lbWin.close.defer(1, lbWin);
              }
         } else {
            this.log.debug('deactivate: Lightbox window ', lightboxWindowId, ' not found in lbContentWindow list? Close operation could not be done.');
         }
      },

        /**
         * The beforeDestroyHandler gets called automatically
         * before lightbox Ext.Window is destroyed as a result of close() call on it. 
         * This gets called as beforedestroy event handler. It does regular clean-up of lightbox
         * related objects by resetting them and performs some post
         * close operations.
         */
        beforeDestroyHandler: function() {
            this.log.debug('Called PTC.lightbox.beforeDestroyHandler');

            // Perform post-deactivate operation, such as refreshing window from where lightbox
            // was activated. If some DOM element needs to be accessed from lightbox-launching
            // window, do it before reloading that window.
            if (this.activateOptions && this.activateOptions.postingFormName) {
                this.resetPostingFormTarget();
            }

            var lightboxWinId = this.getLightboxWindowId();
            if(this.deactivateOptions.saveContent === false) {
                this.lbContentWindow.removeKey(lightboxWinId);
                this.log.debug('beforeDestroyHandler: Removed lightbox window entry for ', lightboxWinId, ' from lbContentWindow map.');

                // The iframe window for lightboxWinId is not fully removed from
                // frames array as frames lookup by lightboxWinId still returns
                // a window element. The Ext.Window.close() method should have
                // destroyed all descendent objects including this frame.
                // As a work-around, explicitly set this to null
                var iframeEl = frames[lightboxWinId];
                if (iframeEl) {
                	this.log.debug('beforeDestroyHandler: frame with iframe id ', lightboxWinId, ' still exists? Remove it again.');
                	iframeEl.src = '';
                	Ext.removeNode(iframeEl);
                }
            } else {
            	this.log.debug('beforeDestroyHandler: saveContent is true. lbContentWindow map entry kept for ', lightboxWinId);
            }

            if(this.deactivateOptions.afterJs !== null) {
                this.log.trace('Calling afterJs callback function.');
                this.deactivateOptions.afterJs();
            }

            //log all the log4javascript messages before navigating to next action page
            PTC.log.sendAllMessages();

            if (this.deactivateOptions && this.deactivateOptions.reloadParent) {
                this.reloadParent();
            }

            // reset configuration options of this lightbox as last thing
            resetConfigOptions();
        },

        /**
         * reset postingForm target, if it was set earlier. Note that postingForm
         * is contained in activatingWindow and so needs to be accessed using activatingWindow
         * as window context.
         */
        resetPostingFormTarget: function() {
            var activatingWindow = this.getActivatingWindow();
            var postingFormName = this.activateOptions.postingFormName;

			try {
				if (activatingWindow.document && activatingWindow.document.forms[postingFormName]) {
					try{
						var originalFormTarget = activatingWindow.document.forms[postingFormName].getAttribute('target');

						if (originalFormTarget) {
							// reset form target to it's original value
							if ('postingFormOriginalTarget' in this.activateOptions) {
								// avoid using setAttribute() as it causes script error in IE for cross-window use case
								activatingWindow.document.forms[postingFormName].target = this.activateOptions.postingFormOriginalTarget;
							}
						}
					} catch(e) {
						this.log.warn('resetPostingFormTarget: error getting the original form target.');
					}
				} else {
					this.log.warn('resetPostingFormTarget: postingForm ', postingFormName,  ' could not be found. Form target could not be reset.');
				}
			} catch(permissionError) {
				//IE gives permission denied error here if the location of parent window is changed
				//try/catch block is added to account for this (SPR #1970681)
				if (permissionError.description && /permission/i.test(permissionError.description)) {
					this.log.warn('permission to activatingWindow.document is denied. window.parent.location was changed');
				} else {
					throw permissionError;			
				}
			}
        },

        /**
         * Reload lightbox iframe window itself. For reloading the window from where
         * lightbox was launched, use reloadParent method.
         */
        reload: function() {
            var lbIframeWindow = this.getLightboxIframeWindow();
            if (lbIframeWindow) {
                // Commented code below as IE gives permission denied error even
                // though same-origin rule is not violated here
                // TODO: Investigate as how we can use this commented code as it's better from performance point of view
                //var lbIframeWindowHref = lbIframeWindow.location.href;
                //lbIframeWindow.location.href = lbIframeWindowHref; // this reloads just the html page. Scripts are not reloaded using this mechanism.
                lbIframeWindow.location.reload(true); // TODO this reloads all the scripts and should be fixed for better solution.
            } else {
                this.log.debug("Lightbox iframe window could not be reloaded as this iframe does not exist.");
            }
        },

        /**
         * Reload the window from where this lightbox was activated.
         */
        reloadParent: function() {
            this.log.debug('Called PTC.lightbox.reloadParent');
            if (this.deactivateOptions.loadURL) {
              // if another URL needs to be loaded, load that in content
              // area itself
                this.log.debug('reloadParent: another URL needs to be loaded. Loading URL: ', this.deactivateOptions.loadURL);
                getWindow().PTC.navigation.loadContent(this.deactivateOptions.loadURL);
                return;
            }
                  
            var activatingWindow = this.getActivatingWindow();
            if (activatingWindow) {
                if (activatingWindow.frameElement) {
                    // If window, from where lightbox was initially activated,
                    // is contained in an iframe, just reload content window of that iframe.
                    this.log.debug("Lightbox was initially activated from a window contained in an iframe. Reloading that window.");

                    // as default behavior, just reload lightbox launcher window. If
                    // lightbox was launched from some iframe window, just reload that iframe
                    // for improved reload performance.
                    if ('hardReload' in this.deactivateOptions && this.deactivateOptions.hardReload === true) {
                    	// hard reload should be avoided as it causes reload of all 
                    	// JS resources. Should be used as workaround when reload 
                    	// does not work due to some unforeseen reason
                    	this.log.debug('reloadParent: performing hard reload');
                    	activatingWindow.location.reload(true);
                    } else {
                    	var activatingWindowHref = activatingWindow.location.href;
                    	activatingWindow.location.href = activatingWindowHref; // this reloads just the html page. Scripts are not reloaded using this mechanism.
                    }
                    this.log.debug("reloadParent: Reloaded iframe window with URL: ", activatingWindow.location.href);
                } else {
                    // lightbox was most likely activated directly from content area in shell
                    // itself. Reload content area.
                    this.log.debug("reloadParent: activated directly from content area in shell. Reloading content area");
                    getWindow().PTC.navigation.reload();
                }
            } else {
                this.log.warn("Could not reload the window from where this lightbox was activated, as such window could not be identified.");
            }
        },

        /**
         * For the specified Window, returns true if this window's
         * content document is loaded into lightbox iframe.
         */
        isLightbox: function(contextWindow) {
            if (contextWindow) {
              try {
                  if (contextWindow.frameElement) { //frameElement provides reference to iframe element container of this window, if there is one.
                    var iframeId = contextWindow.frameElement.getAttribute('name');
                    var parentWin = this.getParentWindow();
                    if(parentWin) {
                      if (iframeId && iframeId === parentWin.PTC.lightbox.getLightboxWindowId()) {
                        return true;
                      } else {
                        this.log.debug('iframe name ', iframeId, ' does not match standard lightbox iframe name ', this.getLightboxWindowId());
                        return false;
                      }
                    }
                  } else {
                    this.log.debug('PTC.lightbox.isLightbox: No iframe element container found for specified window. Perhaps it is not lightbox window.');
                  }
               } catch(e) {
                  // In IE the frameElement may not be a valid interface
                  this.log.info("PTC.lightbox.isLightbox: Could not get frameElement unable to determine if window is a lightbox.");
               }
            }
            return false;
        },

        /**
         * Returns true if specified action in Workspace Listing page is to be rendered as modal lightbox.
         * Eventually all the Workspace Listing page actions, which are currently not rendered as popup, are to be
         * rendered as modal lightbox. For now, return true for those actions
         * which have been testd and tweaked for rendering as lightbox.
         *
         * TODO: Remove this function and it's usage once all the Workspace Listing page actions
         *       have been tested and working as modal lightbox.
         * @param {String} actionURL
         */
        isWsTableActionEnabledForRenderingAsLightbox: function (options) {            
            return _isActionRenderedAsLightbox(options, LIGHTBOX_SUPPORTTESTED_WS_TABLE_ACTION_NAMES);
        },

        /**
         * Returns true if action is to be rendered as lightbox.
         *
         * Eventually, all the cadx actions (from all the launch points) should be
         * render as lightboxare, so as to avoid replacing current shell window with
         * action page.
         *
         * TODO: For now, using hard-coded ACTIONS_RENDERED_AS_LIGHTBOX js array to
         * identify render-as-lightbox actions. Going forward, see if we could use some better
         * configurable approach.  What about leveraging windowType property of
         * NetMarkets-actions.xml file to identify render-as-lightbox? If so, we may not
         * need to use this method for such identification.
         */
        isActionRenderedAsLightbox: function (options) {
            return _isActionRenderedAsLightbox(options, ACTIONS_RENDERED_AS_LIGHTBOX);
        },

	/**
	 * Given the url as an argument - check weather the actions can be rendered as a maximized lightbox for peformance gain
	 * @arg1 - url
	 * @return - bool
	 */
	isActionRenderedAsMaximizedLightbox: function (url) {	    
	    var res = false, actionName = this.getActionNameFromURL(url);
	    actionName = actionName ? actionName.toString().toUpperCase() : false;
	    // first check if the action MUST NOT be rendered maximized
	    if (actionName && ACTIONS_NOT_RENDERED_MAXIMIZED.indexOf(actionName) === -1) {	       
	       // then check weather the action is part of the 2 array in the IF statement below
	       if (ACTIONS_RENDERED_AS_LIGHTBOX.indexOf(actionName) !== -1 ||
	           LIGHTBOX_SUPPORTTESTED_WS_TABLE_ACTION_NAMES.indexOf(actionName) !== -1) {
	           res = true;
	       }
	    }
	    return res;
	},

		/**
		 * event handler for PTC.navigation 'historyChange' event to deactivate the lightbox
		 * This handler gets called when user suddenly navigates away from lightbox page through some user
		 * interaction such as  pasting new URL in address line or clicking  browser favorite link or clicking 
		 * some creo native UI such as workspace listing node
		 */
		handleHistoryChange: function() {		
	   		this.log.debug('PTC.lightbox.handleHistoryChange: url changed ', this.getLightboxWindowId());
	   		var _lbw = this.getLightboxIframeWindow();					
	   		if (_lbw && _lbw.PTC && 'lightbox' in _lbw.PTC) {
				_lbw.PTC.lightbox.deactivate({
					cancelAction: true,
					reloadParent: false
				});
	   		} 		
     	},
     	
        getActionNameFromURL: function(actionURL) {
            var actionName = null;

            if (!actionURL) {
                this.log.debug('actionURL is null?');
                return null;
            }

            // Validate that specified URL is NOT a javascript pseudo URL.
            if (actionURL.toLowerCase().indexOf(PTC.jslint.SCRIPT_URL_STRING) !== -1) {
                this.log.debug('actionURL ', actionURL, 'is a javascript pseudo URL. Action name could not be found.');
                return null;
            }

            // find out action param from the specified URL
            this.log.debug('actionURL: ', JSON.stringify(actionURL)); // stringify used for weird case where value happens to be Object
            var queryParams = actionURL.toLowerCase().toQueryParams();
            if (queryParams.hasOwnProperty('action')) {
                var actionParamValue = queryParams.action;
                this.log.debug('PTC.lightbox.getActionNameFromURL: actionParamValue: ', actionParamValue);
                // when there are more than one action param in query string, actionParamValue 
                // is an array. It is caused due to duplicate action param. Useed 1st value from 
                // this array in that case.
                if (Object.isArray(actionParamValue)) {
                	this.log.debug('PTC.lightbox.getActionNameFromURL: actionParamValue is an array: ', actionParamValue);
                	actionName = actionParamValue[0];
                } else {
                	actionName = actionParamValue;
                }
            }
            if (!actionName) {
                this.log.debug('PTC.lightbox.getActionNameFromURL: Action name could not be found from specified URL ', actionURL);
            } else {
            	this.log.debug('PTC.lightbox.getActionNameFromURL: Action name: ', actionName);
            }
            return actionName;
        },

        /**
         * Render form's  action in lightbox window. Use this method for POST 
         * type of request. Form target is
         * set to lightbox iframe window in PTC.lightbox.activate() method
         * and then reset back to original value when lightbox is de-activated
         * @param {Object} options object specified with following properties:
         * { form: <form element> // required form element object
         *   any other optional options for PTC.lightbox.activate() API
         * }
         */
        renderFormActionAsLightbox: function(options) {
           var returnOptions = {
              target: null,
              submitForm: false
            };

            if (!options) {
                this.log.error('PTC.lightbox.renderFormActionAsLightbox: options not specified. Action can not be rendered as lightbox.');
                return returnOptions;
            }
            if (!('form' in options)) {
                this.log.error('PTC.lightbox.renderFormActionAsLightbox: form not specified. Action can not be rendered as lightbox.');
                return returnOptions;
            }
            // check whether it is ok to render lightbox maximized
	    options = this.isActionRenderedAsMaximizedLightbox(options.form.action) ? Ext.applyIf(options, { renderMaximized : true }) : options; 				    
            var formName = Ext.get(options.form).getAttribute('name');
            if (!formName) {
                this.log.error('PTC.lightbox.renderFormActionAsLightbox Form name not specified. Action can not be rendered as lightbox.');
                return returnOptions;
            }
            this.log.debug('PTC.lightbox.renderFormActionAsLightbox formName: ', formName);
            var theOptions = {
                requestMethod: 'post',
                postingFormName: formName
            };
            Object.extend(theOptions, options);
            this.activate(theOptions);

            // Return the lightbox window id as the form target if lightbox is a new window
            returnOptions.target = this.getLightboxWindowId(); // set form target in case form needs to be re-submiited even in pre-existing lightbox window
            if(!this.activateOptions.isExistingLightBox) {
                returnOptions.submitForm = true;
            } else {
            	this.log.debug('PTC.lightbox.renderFormActionAsLightbox: lightbox pre exists.');
            }
            this.log.debug('renderFormActionAsLightbox: is submitForm value is ', returnOptions.submitForm);
            this.log.debug('renderFormActionAsLightbox: form post response targeted to window named ', returnOptions.target);
            
            this.log.debug('Exiting PTC.lightbox.renderFormActionAsLightbox');
            return returnOptions;
        },

        /**
         * Gets the correct parent window in which windchill resides.
         * This allows the support of portlets, etc. and gives a single
         * api in retrieving the correct windchill window.
     *
         * If we do not have access to the window.top we know we are contained
         * so thus a exception will occur in which we catch.
         */
     getParentWindow: function() {
           try {
           if (window.parent.location.href !== window.location.href && typeof window.parent.PTC !== 'undefined' && typeof window.parent.PTC.navigation !== 'undefined') {
               return window.parent.getWindow();
         } 
        } catch(e) {}
          return window;
   },

   /**
    * Checks if a lightbox wizard is open and calls the handleSubmitResult
    * for the lightbox else the handleSubmitResult is executed in the top window.
    */
     handleSubmitResult: function(originalHandle, status, nextAction, js, URL, dynamicRefreshInfo){
        var lbWindow = (PTC.lightbox.isLightbox(self)) ? null : PTC.lightbox.getLightboxIframeWindow();
        if(lbWindow) {
           lbWindow.handleSubmitResult(status, nextAction, js, URL, dynamicRefreshInfo);
        } else {
           originalHandle(status, nextAction, js, URL, dynamicRefreshInfo);
        }
      }
    };
}().init(); // end of PTC.lightbox;

// In order to mask top browser window, activate() & deactivate() must be executed
// in the execution context of top window. Use getWindow() to get reference
// to top window. Created alias PTC.lightbox.method convinience methods to point to
// top.PTC.lightbox.method itself for all instance methods. Note
// that remaining methods of PTC.lightbox are kind of static mathods and so object instance
// does not matter for them.
// Also, to avoid cross-frame access issues, as best practices, all the method
// call to PTC.lightbox from action pages should be made in execution context
// of top window. This will ensure that all the javascript objects related to
// PTC.lightbox are maintained in one unambiguous window context (i.e. top window
// context) for clean house keeping. However to hide such window context requirement
// from action pages, provide convinience wrapper for all such methods.
if ('wrap' in Function) { // just in case prototype.js is not been loaded yet. Should be rare and fixed.
  
  // Note that all the externally exposed PTC.lightbox API needs to be executed 
  // in the context of main window. This is required so that main window
  // gets masked when lightbox is activated. Also, it ensures that lightbox
  // related state data is set and reset in well-defined window context. 
  // Accordingly following wrap methods change methods execution context to main window on the fly.
  // In future, if any exteranlly exposed PTC.lightbox mathod is written, make sure to 
  // wrap them as per this design.
  
        /* Wrapped - 1 */
        var wrappedActivate = function( originalActivate, options ){
            this.log.trace('Called wrapped PTC.lightbox.activate method.');
            var windchillWin = this.getParentWindow();
            if (self != windchillWin) { // when context is other than top window, execute in context of top window
                var theOptions = {
                    activatingWindow: self // note that activatingWindow is set for iframe use case only purposely. refer to getActivatingWindow jsdoc for details
                };
                if (options) {
                    Object.extend( theOptions, options );
                }
                return windchillWin.PTC.lightbox.activate(theOptions);
            }
            else {
                return originalActivate(options);
            }
        };
        PTC.lightbox.activate = PTC.lightbox.activate.wrap( wrappedActivate );

        /* Wrapped - 2 */
        var wrappedRenderFormActionAsLightbox = function( proceed, options ){
            var windchillWin = this.getParentWindow();
            if (self != windchillWin) { // when context is other than top window, execute in context of top window
                var theOptions = {
                    activatingWindow: self // note that activatingWindow is set for iframe use case only purposely. refer to getActivatingWindow jsdoc for details
                };
                if (options) {
                    Object.extend(theOptions, options);
                }
                return windchillWin.PTC.lightbox.renderFormActionAsLightbox( theOptions );
            }
            else {
                return proceed( options );
            }
        };
        PTC.lightbox.renderFormActionAsLightbox = PTC.lightbox.renderFormActionAsLightbox.wrap( wrappedRenderFormActionAsLightbox );

        /* Wrapped - 3 */
        var wrappedDeactivate = function( proceed, options ) {
            this.log.trace('Called wrapped PTC.lightbox.deactivate method.');
            var windchillWin = this.getParentWindow();
            if (typeof options.lbWindow == 'undefined') {
                options.lbWindow = self;
            }
    
            var lbWindowName = null;
            if ("frameElement" in options.lbWindow && options.lbWindow.frameElement) {
                lbWindowName = options.lbWindow.frameElement.getAttribute('name');
            }
            else {
                this.log.debug('deactivate: window being deactivated does not have frame element?');
                return;
            }
            this.log.debug('deactivate: window being deactivated: ', lbWindowName);
            if (!lbWindowName) {
                this.log.debug('deactivate: lightbox window could not be found? deactivate not done.');
                return;
            }
            // executeCancel is run for wizard popups at a similar point, this must be done here to replicate this
            // functionality for lightboxes.  Otherwise, this would result in a small memory leak.
            options.lbWindow.PTC.jca.table.stickiness.clearAllTablesStickiness();
            if (self != windchillWin) { // when context is other than top window, execute in context of top window
                return windchillWin.PTC.lightbox.deactivate(options);
            }
            else {
                return proceed(options);
            }
        };
        PTC.lightbox.deactivate = PTC.lightbox.deactivate.wrap( wrappedDeactivate );

        /* Wrapped - 4 */
        var wrappedIsLightbox = function( originalIsLightbox, contextWindow ){
            var windchillWin = this.getParentWindow();
            if (self != windchillWin && windchillWin.PTC && windchillWin.PTC.lightbox) { // when context is other than top window, execute in context of top window
                return windchillWin.PTC.lightbox.isLightbox(contextWindow);
            }
            else {
                return originalIsLightbox(contextWindow);
            }
        };
        PTC.lightbox.isLightbox = PTC.lightbox.isLightbox.wrap( wrappedIsLightbox );

        /* Wrapped - 5 */
        var wrappedsetDeactivateOptions = function( proceed, options ){
            var windchillWin = this.getParentWindow();
            if (self != windchillWin) { // when context is other than top window, execute in context of top window
                return windchillWin.PTC.lightbox.setDeactivateOptions(options);
            }
            else {
                return proceed(options);
            }
        };
        PTC.lightbox.setDeactivateOptions = PTC.lightbox.setDeactivateOptions.wrap( wrappedsetDeactivateOptions );
    
        /* Wrapped - 6 */
        var wrappedResizeLightboxToCompactSize = function( proceed, width, height ){
            var windchillWin = this.getParentWindow();
            if (self != windchillWin) { // when context is other than top window, execute in context of top window
                return windchillWin.PTC.lightbox.resizeLightboxToCompactSize(width, height);
            }
            else {
                return proceed(width, height);
            }
        };
        PTC.lightbox.resizeLightboxToCompactSize = PTC.lightbox.resizeLightboxToCompactSize.wrap( wrappedResizeLightboxToCompactSize );
    
        /* Wrapped - 7 */
        var wrappedGetActivatingWindow = function( proceed ){
            var windchillWin = this.getParentWindow();
            if (self != windchillWin) { // when context is other than top window, execute in context of top window
            	// when called directly from within a lightbox, return back initial original 
            	// activating window if it's set. Note that initialActivatingWindow is "not" set when activate()
            	// is triggered from within lightbox itself for some edge cases.
            	if (windchillWin.PTC.lightbox.initialActivatingWindow) {
            		return windchillWin.PTC.lightbox.initialActivatingWindow;
            	} else {
            		return windchillWin.PTC.lightbox.getActivatingWindow();
            	}
            }
            else {
                return proceed();
            }
        };
        PTC.lightbox.getActivatingWindow = PTC.lightbox.getActivatingWindow.wrap( wrappedGetActivatingWindow );

        /* Wrapped - 8 */
	var wrappedIsActionRenderedAsMaximizedLightbox = function( proceed, url ){
	    var windchillWin = this.getParentWindow();
            if (self != windchillWin) { // when context is other than top window, execute in context of top window
                return windchillWin.PTC.lightbox.isActionRenderedAsMaximizedLightbox( url );
            }
            else {
                return proceed( url );
            }	
	};
	PTC.lightbox.isActionRenderedAsMaximizedLightbox = PTC.lightbox.isActionRenderedAsMaximizedLightbox.wrap( wrappedIsActionRenderedAsMaximizedLightbox );
	
        /**
        * We need to wrap the handleSubmitResult because it does not have access to
        * PTC.lightbox and is called inside the top window.
        */
        handleSubmitResult = handleSubmitResult.wrap( PTC.lightbox.handleSubmitResult );
}

/**
 * Private - creates the formPanel for simple lightbox
 * @param {Object} lightboxConfig - configuration data for setup of lightbox form
 */
PTC.lightbox._createSimpleLightBoxForm = function(lightboxConfig){
    var labelWidth = Math.max(lightboxConfig.maxLabelWidth, Ext.util.TextMetrics.createInstance(document.body).getWidth(lightboxConfig.promptText));
    //Expand label and window if necessary for long translations of prompt text
    if(labelWidth > lightboxConfig.maxLabelWidth) {               
       var extraWindowWidth = labelWidth - lightboxConfig.maxLabelWidth;	  
       lightboxConfig.windowWidth = lightboxConfig.windowWidth + extraWindowWidth;       
    }
    var form = new Ext.FormPanel({
        id: lightboxConfig.formId,
        plain: true,
        frame: true,
        defaultType: 'textfield',
        defaults: {
            width: lightboxConfig.fieldWidth
        },
        monitorValid: true,
        labelWidth: labelWidth,
        keys: [{
            key: [10, 13],
            fn: function(){
                OKButton.focus();
                OKButton.fireEvent("click", OKButton);
            }
        }],
        
        items: [{
            id: 'newName',
            name: 'newName',
            fieldLabel: lightboxConfig.promptText,
            labelStyle:'padding-right: 8px;',
            maxLength: lightboxConfig.maxLengthField,
            maxLengthText: lightboxConfig.charsExceededMessage,
            value: lightboxConfig.defaultFieldValue,
            invalidText: lightboxConfig.blankTextMessage,
            msgTarget: 'under',
            selectOnFocus: true,
            validator: function(val){
                if (!val) {
                    return false;
                }
                if (val.trim() === '') {
                    return false;
                }
                return true;
            }
        }],
        buttons: [lightboxConfig.OKButton, lightboxConfig.cancelButton]
    });
    
    return form;
};

/**
 * Creates a simple lightbox input window, used for getting the name perhaps instead of window.prompt
 * @param {Object} windowId
 * @param {Object} formId
 * @param {Object} defaultFieldValue
 * @param {Object} preKey
 * @param {Object} OKButton
 * @param {Object} cancelButton
 */
PTC.lightbox.createSimpleLightBoxWindowAndForm = function(windowId, formId, defaultFieldValue, preKey, OKButton, cancelButton){
    var lightboxConfig = {
        windowId: windowId,
        formId: formId,
        defaultFieldValue: defaultFieldValue,
        maxLabelWidth: 40,
        fieldWidth: 230,
        windowWidth: 310,
        OKButton: OKButton,
        cancelButton: cancelButton,
        promptText: bundleHandler.get('com.ptc.core.ui.navigationRB.' + preKey + '_PROMPT_TEXT'),
        promptTitle: bundleHandler.get('com.ptc.core.ui.navigationRB.' + preKey + '_PROMPT_TITLE'),
        charsExceededMessage: bundleHandler.get('com.ptc.core.ui.navigationRB.' + preKey + '_CHARS_EXCEEDED'),
        blankTextMessage: bundleHandler.get('com.ptc.core.ui.navigationRB.' + preKey + '_NAME_EMPTY'),
        maxLengthField: bundleHandler.get('com.ptc.core.ui.navigationRB.' + preKey + '_MAX_LENGTH_FIELD')
    };
    var form = PTC.lightbox._createSimpleLightBoxForm(lightboxConfig);
    return PTC.lightbox._createSimpleLightBoxWindow(form, lightboxConfig);
};

/**
 * Creates a simple lightbox input window, used for getting the name instead of window.prompt
 * Accepts a configuation object for greater flexibility in customizing your form compared to the function above.
 * @param {Object} lightboxConfig - configuration data for setup of lightbox window and form, fields are:
 *    {String} windowId - id for the lightbox window
 *    {String} formId - id for the lightbox form
 *    {String} defaultFieldValue - default value for the form text field
 *    {String} maxLabelWidth - maximum width of the text field label (prompt text)
 *    {String} fieldWidth - width of the form text field
 *    {String} windowWidth - width of the lightbox window
 *    {String} promptText - label to display before text field
 *    {String} promptTitle - window title
 *    {String} maxLengthField - max lengh of the text field
 *    {String} charsExceededMessage - error message to display when maxLengthField exceeded
 *    {String} blankTextMessage - error message displayed when no text is entered
 *    {Object} OKButton - configuration of the OK button
 *    {Object} cancelButton - configuration of the cancel button
 */
PTC.lightbox.createSimpleLightBoxWindowAndFormFromConfig = function(lightboxConfig){
    // defaults for standard lightbox window and form
    Ext.applyIf(lightboxConfig, {
        maxLabelWidth: 40,
        fieldWidth: 230,
        windowWidth: 310
    });
    var form = PTC.lightbox._createSimpleLightBoxForm(lightboxConfig);
    return PTC.lightbox._createSimpleLightBoxWindow(form, lightboxConfig);
};

/**
 * Private - Create the window wrapper
 * @param {String} windowId
 * @param {Ext.form.FormPanel} form
 * @param {String} preKey
 */
PTC.lightbox._createSimpleLightBoxWindow = function(form, lightboxConfig){

    var win = new Ext.Window({
        id: lightboxConfig.windowId,
        closable: true,
        modal: true,
        resizable: false,
        width: lightboxConfig.windowWidth, // width is required for Ext windows
        autoHeight: true, // let the browser manage height, so that window will grow to accomodate error message
        minimizable: false,
        maximizable: false,
        footer: true,
        plain: true,
        title: lightboxConfig.promptTitle,
        listeners: {
            'show': function(){
                // default 100ms delay not working - use 500 instead
                Ext.getCmp('newName').focus(true, 500);
            }
        },
        items: [form]
    
    });
    
    //SPR 2176852
    win.mon(PTC.navigation, 'historyChange', win.close, win, {single:true});
    
    return win;
};



/**
 * Looks for the following row properties:
 * oid (defaults to the row oid)
 * url (defaults to the info page url)
 * text (defaults to the view info text)
 * img (if specified the image is rendered instead of the text)
 */
jsca.columns.linkRenderer = function(table,column,row) {
    var result = '';
    var data = jsca.columns.getCellValue(column, row);
    var oid = data.oid || getRowItem(row).oid;
    if (oid) {
        var url = data.url || PTC.attributeHelper.get('InfoPage').url;
        result = '<a id="'+oid+'" href="'+url+'?oid='
            + encodeURIComponent(oid)
            + '">';
        var text = data.text || PTC.attributeHelper.get('InfoPage').title;
        if (data.img) {
            result += '<img src="'+data.img
            + '" alt="' + text
            + '" title="' + text
            + '" hspace="0" vspace="0" border="0"/>';
        }
        else {
            result += text;
        }
        result += '</a>';
    }
    result = result + jsca.columns.getHiddenInputs(data.hiddenData);
    return result;
};

undoCheckoutActionListener = function(original, formResult) {
   if (formResult.actionName === 'undocheckout' || formResult.actionName === 'renameOptionSetWizard' || formResult.actionName === 'setState' || formResult.actionName === 'reassignLC') {
       PTC.jca.table.Utils.reload('optionset.mvc.listAssignedOptionSet', null, true );
   }
   return original.call(this, formResult);
};

addActionListener = function(table) {
   table.onObjectsAffected = table.onObjectsAffected.wrap(undoCheckoutActionListener);
};

Ext.ComponentMgr.onAvailable('optionset.mvc.listAssignedOptionSet', addActionListener);


