PTC.ec.loadingSign = null;

PTC.ec.loadingMenuItem = null;

PTC.ec.currentFilterAction = "currentFilterAction";

PTC.ec.editFilterAction = "editFilterAction";

PTC.ec.csPickerAction = "csPickerAction";

var EC_DIALOG_HEIGHT = '550px';
