/**
 * Resets the height of the Iframe having the ID 'the_tpIFrame' to the value in iFrameHeight. Also sets
 * iframeHeightIsSet to "false" upon a successful reset.
 */
function resetIFrameHeight() {
    
    var tpIFrame = parent.document.getElementById('the_tpIFrame');
    if(tpIFrame != null) {
        tpIFrame.style.height = iFrameHeight;
        iframeHeightIsSet = "false";
    }    
}

/**
 * Sets the height of the Iframe having the ID 'the_tpIFrame' to the value in EC_DIALOG_HEIGHT, provided the current
 * height is less than the said value. Returns a "true" if the height is set, or a "false" otherwise. The original
 * height is backed up in iFrameHeight and iframeHeightIsSet is set to "true" if the height is set successfully.
 */
function setIFrameHeight() {
        
    var tpIFrame = parent.document.getElementById('the_tpIFrame');
    if(tpIFrame != null) {
        /* Backup the current Iframe height in a variable for later use; this is not done if
           the Iframe height is already set, as it could result in the value in iFrameHeight
           being overwritten */
        if(iframeHeightIsSet == "false") {
            iFrameHeight = tpIFrame.style.height;
        }

        if(tpIFrame.style.height < EC_DIALOG_HEIGHT) {            
            /* Set the Iframe height to a value large enough to hold the Edit (or Current) Filter dialog fully */
            tpIFrame.style.height = EC_DIALOG_HEIGHT;
            iframeHeightIsSet = "true";
            return "true";
        }
    }

    return "false";
}


/**
 * @namespace
 * a namespace for functions that relate to the Actions menu or Action models that are made into menus
 * (third level nav menu, my tab menu)
 */
PTC.menu = {};

Ext.apply(PTC.menu, new Ext.util.Observable());

// SPR 2174438 : Hide the Visualization plugin when Recently Accessed menu overlaps with it
if(Ext.isWebKit) {
        //Webkit browsers will not hide plugins below the Shim Iframe.   This listener will hide the plugins
        //if the menu overlaps them.	    
        PTC.menu.on("dynamicMenuLoad", function(menu) {
                var pluginListener = function() {
                        PTC.util.handlePlugins(menu);
                };
                
                PTC.util.on('checkplugins', pluginListener);
                PTC.util.firePluginChecks();
                
                menu.on('hide', function(menu) {
                        PTC.util.un('checkplugins', pluginListener);
                        PTC.util.firePluginChecks();
                });
        });
    }

/**
 * Listen to this event to detect when a PTC.menu.DynamicMenu is loaded (the request
 * for the menu items has completed successfully, and the items added to the menu).
 *
 * This listener will apply for all PTC.menu.DynamicMenus.  Any other type of menu does not throw this event.
 *
 * The function registered as a listener for this event will be called with the Ext.menu.Menu as the only parameter
 *
 * @example
 * // This just writes each item loaded in the menu to the console
 * PTC.menu.on("dynamicMenuLoad", function(menu) {
 *    menu.items.each(function(item) {
 *       console.log("menu item", item);
 *   });
 * });
 *
 *
 * @name PTC.menu#dynamicMenuLoad
 * @event
 * @param {Ext.menu.Menu} menu
 */
PTC.menu.addEvents("dynamicMenuLoad", "dynamicMenuShow");

/**
 * Listen to this event to detect when a PTC.menu.DynamicMenuButton has its menu shown (when the button is clicked).
 *
 * This listener will apply for all PTC.menu.DynamicMenuButtons.  Any other type of menu button does not throw this event.
 *
 * The function registered as a listener for this event will be called with the Ext.Button and Ext.menu.Menu as parameters.
 *
 * @example
 * // This just writes the button and each item loaded in the menu to the console
 * PTC.menu.on("dynamicMenuShow", function(button, menu) {
 *    console.log("button", button);
 *    menu.items.each(function(item) {
 *       console.log("menu item", item);
 *   });
 * });
 *
 *
 * @name PTC.menu#dynamicMenuShow
 * @event
 * @param {Ext.Button} button
 * @param {Ext.menu.Menu} menu
 */


/**
 * Uses the given URL to request the javascript of the menu to display, and then displays it.
 * Expects the response string to have an JSON action model. 
 * 
 * theURL - (required) a URL with the necessary parameters to retrieve the correct menu
 * parentId - (required) the id of the parent HTML element to show the menu under. The menu is positioned
 *          just below the element with the given parentId.
 **/
function showDynamicMenu(theURL, id) {
    var menu_link = Ext.get(id);
    var coords = menu_link.getOffsetsTo(document.body);
    var link_dim = menu_link.getSize(menu_link);
    coords[0] += link_dim.width;
    coords[1] += link_dim.height;
    PTC.menu.showMenu(coords, "", theURL);
}

/**
 * Converts an action model config to a menu config
 *
 * To do this it walks through an Action model and adds a menu object around all submenus
 * so that ext can properly process them and render them as flyout submenus
 * 
 * @param model the action model to change
 * @param id optional, additional identification information for the submodel. If the 
 *     same submodel can appear in different menus on the same page at the same time this
 *     can be used to make the ids unique and avoid having the submodels vanish from one
 *     of the menus due to id collision. (SPR 2102114)
 */
PTC.menu.ActionModelToMenu = function(model, id) {
    PTC.actionModel.walkActionModelAndApplyToAll(model, function(submodel) {
        //Making each menu item id unique and avoid having menu items vanish from menu due to id collision.(SPR 2202360) 
        if(submodel.actionID) {
            submodel.id = submodel.actionID;
            if (id !== null && id !== undefined && id !== '') {
                submodel.id +=  '_' + id;
            }
        }
        if(submodel.items) {
            submodel.menu = {items: submodel.items};
        }
    });
};

/**
 * Show the actions menu for a grid row.
 * For left click of Actions link or right click on the row.
 *
 * @param {Ext.grid.GridPanel} grid - an Ext grid panel
 * @param {int} rowIndex - the index of the row that was clicked
 * @param {Ext.EventObject} evt - the even object from the click
 * @param {Ext.data.Record} [row] Optional row to cache the menu response onto so subequent calls to this API with that row would show the cached menu.
 */
PTC.menu.onContextMenu = function(grid, rowIndex, evt){
    if (!evt.hasModifier()) {
        // Prevent the browsers context menu.
        evt.stopEvent();

        //Set proper mainform.
        PTC.util._setMainFormStartingElement(grid.el.id);

        var row = grid.store.getAt(rowIndex);

        PTC.jca.table.Utils.focusRow(grid, rowIndex, grid.getSelectionModel().isSelected(rowIndex));

        var params = PTC.menu._constructParams(row, grid);
        PTC.menu.showActionsMenu(evt, params, row);
    }
};

/**
 * @param {Ext.data.Record} row - an Ext record to get the oid, context and action menu params from
 * @param {Object} table - table the has table id and actions menu column id (usually "nmActions" but could be different)
 */
PTC.menu._constructParams = function(row, table) {
    var params = {};
    if (table.initialConfig.jcaTableConfig) {
        //the order is imp : first look in customActionsMenuColumnId and then in actionsMenuColumnId
        var actionsColumnId = table.initialConfig.jcaTableConfig.customActionsMenuColumnId;
        if(!actionsColumnId){
            actionsColumnId = table.initialConfig.jcaTableConfig.actionsMenuColumnId;
        }
        if(!actionsColumnId) {
            //ensure the "No Actions To Display" message is shown to the user
            params.actions = PTC.menu._FAKE_ACTION_MODEL_NAME;
        } else {
            var cellValue = row.get(actionsColumnId);
            if(cellValue && cellValue.params) {
                params = cellValue.params;
            }
        }
    }
    
    // moved from applyIf below because if the param was already set, the new value was not overriding the old value
    Ext.apply (params, {
        tableID: table.id
    });
    
    Ext.applyIf(params, {
        context : getRowContext(row),
        oid : getRowOid(row),
        actionName : 'actionsMenu' // certain action delegates such as MoveURLActionDelegate expect this parameter
    });
    return params;
};
PTC.menu._FAKE_ACTION_MODEL_NAME = "EMPTY_ACTION_MODEL";

/**
 * Show an actions menu.
 * @param {Event} evt - May be a browser event (left click on actions dropdown) or
 *     Ext Event (right-click on grid row), to get x,y coordinates.
 * @param {Object} params - JSON object or param string,  params.tableID is the ext component id that the menu is displayed in, that may be needed
 *                  by any client side validator.  Although table is the first and most common component used it has been extended 
 *                  TODO: rename the param to be more un-specific about which type of component id it is.
 * @param {Ext.data.Record} [row] Optional row to cache the menu response onto so subequent calls to this API with that row would show the cached menu.
 */
PTC.menu.showActionsMenu = function(evt, params, row){
    var xy = [0,0];
    // If it's an EXT event it will contain a getXY function
    if (typeof evt.getXY === 'function') {
        xy = evt.getXY();
    } else {
        // If it's a browser event handle it differently
        xy[0] = evt.clientX;
        xy[1] = evt.clientY;
    }
    PTC.menu.showMenu(xy, params, '', row);

    return false;
};

/**
 * Show an Ext menu at the given coordinates.
 * An ajax call is made with the given url (or the actions menu url if no url is given)
 * to get the menu items to show for the menu.
 *
 * @param {Array} xy Where to show the menu in coords array [number, number]
 * @param {Object} params JSON object or param string
 * @param {String} [url] Optional url to get the menu; if no url is given, the actions menu url is used
 * @param {Ext.data.Record} [row] Optional row to cache the menu response onto so susbequent calls to this API with that row would show the cached menu.
 */
PTC.menu.showMenu = function(xy, params, url, row) {
    var tableId;
    if (Ext.isString(params)) {
        PTC.menu.contextOid = extractParamValue(params, 'oid');
        tableId = extractParamValue(params, 'tableID');
    } else {
        PTC.menu.contextOid = params.oid;
        tableId = params.tableID;
    }
    url = url || PTC.attributeHelper.get("ActionsMenu").url;
    var options = {
        parameters: params
    };
    var contextMenu;
    var selections = tableUtils.getTableSelectedRowsById(tableId);
    var selectionMatch = PTC.menu._selectionMatch(selections,PTC.menu.contextOid);

    if (selections.length > 1 && selectionMatch) {
        var multiSelectBar = PTC.menu.getMultiSelectBar(tableId, PTC.menu.contextOid);
        if (multiSelectBar) {
            contextMenu = PTC.menu._createMultiSelectMenu(multiSelectBar);
            PTC.menu._showContextMenu(selectionMatch,tableId,xy,contextMenu);
        }

    } else {
        contextMenu = PTC.menu._createDynamicMenu(url, options, row);
        contextMenu.tableId = tableId;

        if (row) {
            // if there is a row, cache the menu response on that row an reuse it for subsequent calls to showMenu
            if (row.cachedMenuResponse) {
                // combination of loadOnce=true and loaded=true makes sure no ajax calls are made when showAt is called
                contextMenu.loaded = true;
                contextMenu.initializeMenu(row.cachedMenuResponse);
                PTC.menu._showContextMenu(selectionMatch,tableId,xy,contextMenu);
                // show menu before positioning to avoid js errors in the position calculation
                contextMenu.positionMenu();
                PTC.menu.fireEvent("dynamicMenuLoad", contextMenu);
                return;
            } else {
                contextMenu.requestOptions.onSuccess = contextMenu.requestOptions.onSuccess.wrap(function(original,
                        response) {
                    original(response, row);
                });
            }
        }

        PTC.menu._showContextMenu(selectionMatch,tableId,xy,contextMenu);
    }
};

/**
 * @private
 * @param {Boolean} selectionMatch  false if user right click on different row other than selected ones.
 * @param {String}  tableId
 * @param {Array}   xy  Where to show the menu in co-ordinates array.
 * @param {Object}  contextMenu
 * show context menu.
 */
PTC.menu._showContextMenu = function(selectionMatch,tableId,xy,contextMenu){
   // User can select rows but right click on different row to perform action. In this case
   // unselect all the rows so that action is performed on right object.
   //  PTC.menu._unselectAllForRightClickMenu(tableId, contextOid);
   if(!(!tableId || tableId === ''))
    {
     var table = PTC.jca.table.Utils.getTable(tableId);
      if(table)
       {
       if(!selectionMatch) {
         if (table.getSelectionModel && table.getSelectionModel()) {
           table.getSelectionModel().clearSelections();
           }
         }
       }
      }
   contextMenu.showAt(xy);
};
/**
 * User can select rows but right click on different row to perform action
 * @private
 *
 */

PTC.menu._selectionMatch = function(selections,contextOid) {
    var selectionMatch = false;
    var i = selections.length;
        while (i--) {
            var soid = getOidFromRowValue(selections[i].value);
            if (soid === contextOid) {
                selectionMatch = true;
                break;
            }
        }
    return selectionMatch;
};

/**
 * destroy a Context Menu .
 * @private
 *
 */
PTC.menu._destroyContextMenu = function(menu) {
        // set the menu context oid to be null on close menu so that next time it is set to right context
        PTC.menu.contextOid = undefined;
        menu.destroy();
    };

/**
 * Create a Context Menu for multi selection.
 * @private
 * @param {Object} multiSelectBar multiselection actions
 */
PTC.menu._createMultiSelectMenu = function(multiSelectBar) {

    var contextMenu;
    contextMenu = new Ext.menu.Menu({
        id: 'gridRowContextMenu',
        items: multiSelectBar.items,
        ignoreParentClicks: true,
        listeners: {
            hide: PTC.menu._destroyContextMenu
        }
    });
    return contextMenu;
};

/**
 * @private
 * Create a Context Menu for single selection.
 * @param {String} [url] Optional url to get the menu; if no url is given, the actions menu url is used
 * @param {Object} param options.
 * @param {Ext.data.Record} [row] Optional row to cache the menu response onto so susbequent calls to this API with that row would show the cached menu.
 */
PTC.menu._createDynamicMenu = function(url, options, row) {

    var contextMenu;
    contextMenu = new PTC.menu.DynamicMenu({
        id: 'gridRowContextMenu',
        loadOnce: row ? true : false,
        requestUrl: url,
        requestOptions: options,
        enableScrolling: false, /* do not scroll the menu by default */
        listeners: {
            hide: PTC.menu._destroyContextMenu
        }
    });
    return contextMenu;
};

/**
 * A menu that retrieves its items from an AJAX request.
 *
 * @class PTC.menu.DynamicMenu
 * @extends Ext.menu.Menu
 * @property {boolean} loadOnce - if true, it will only load the menu items the first time it is displayed. Default is
 * false.
 * @property {String} requestUrl - the controller url
 * @property {Object} requestOptions - See prototype's Ajax.Request for more information.
 */
PTC.menu.DynamicMenu = Ext.extend(Ext.menu.Menu, {
    loadOnce: false,
    loaded: false,
    scrollerHeight: 11,  /* overridden to accomodate custom scroller images */
    padding: 5, /* padding so the menu is slightly inset from edges of the body */
    constructor: function(menuConfig){
        // Initialize default request handling
        menuConfig.requestOptions = menuConfig.requestOptions || {};
        menuConfig.requestOptions.parameters = menuConfig.requestOptions.parameters || {};
        var menu = this;
        Ext.applyIf(menuConfig.requestOptions, {
            /**
             * Loads menu items from response.
             * @param {Object} response - the response object
             */
            onSuccess: function(response, row){
                var responseText = Ext.decode(response.responseText);
                menu.initializeMenu(responseText);
                menu.positionMenu();
                PTC.menu.fireEvent("dynamicMenuLoad", menu);
                if (row) {
                    // make sure to cache the menu response in the same context where the menu was initialized
                    row.cachedMenuResponse = responseText;
                }
            },

            /**
             * Displays an error message as a menu item.
             */
            onFailure: function(){
                menu.removeAll(true);
                menu.addItem({
                    text: bundleHandler.get('com.ptc.core.ui.navigationRB.UNABLE_TO_CONNECT')
                });
            },
            // needed to use GET instead of POST to resolve issue in SPR 1734533
            method: 'get'
        });
        // cacheBuster param needed to prevent IE from caching response of GET request - SPR 2136544
        Ext.applyIf(menuConfig.requestOptions.parameters, {
            cacheBuster: (new Date()).getTime()
        });
        this.loadingItems = {
            id: 'loading_menu_items_panel',
            icon: 'netmarkets/javascript/ext/resources/images/default/grid/loading.gif',
            text: bundleHandler.get('com.ptc.core.ui.navigationRB.LOADING')
        };

        PTC.menu.DynamicMenu.superclass.constructor.call(this, menuConfig);
        this.ignoreParentClicks = true;
        this.on('beforeshow', function(){
            // load if the menu is empty, loadOnce is false or loadOnce is true and the menu has not already been loaded
            if (this.items === undefined || this.items.getCount() === 0 || this.loadOnce === false || this.loaded === false) {
                this.menuLoader();
            }
        }, this);
        this.on('hide', function(){
            if (this.loadOnce === false || this.loaded === false) {
                this.removeAll(true);
            }
        }, this);
    },

    /**
     * The default menu loader sends a request to a controller to retrieve the list of menu items.
     */
    menuLoader: function(){
        this.add(this.loadingItems);
        requestHandler.doRequest(this.requestUrl, this.requestOptions);
    },
    initializeMenu: function(actionModel){
        var menu = this;
        var table = menu.tableId ? Ext.getCmp(menu.tableId) : undefined;
        PTC.menu.ActionModelToMenu(actionModel, menu.id);
        PTC.actionModel.walkActionModelAndApply(actionModel, function(menuItem){
            // wrap the handler from the response to return true so the menu will close after clicking on it
            // examples: Seach in Quick Links, all items in recently accessed menu
            var itemHandler = menuItem.handler;            
            if (itemHandler !== undefined && menuItem.handlerWrapped !== true) {
                // If actionURL exists on the config that means this is a PAGE action, if it is also an info page action, 
                // href should be set on menuItem so the 'Open link in new tab' browser action can work.
                // Otherwise overrides.jsfrag would set a default href of javascript:var abc = doNothing();
                // This is a Fix for SPR 4048291 to allow right click "Open in new tab" to work from recently accessed menu,
                // initially we added href to all menu items but subsequently discovered several lightbox actions broken due to this change such as Rename, Add to WS, etc.
                if(menuItem.actionURL && menuItem.actionURL.indexOf("infoPage") > 0) {
                    menuItem.href = menuItem.actionURL;
                }
            	// convert to function if the itemHandler is a string
            	itemHandler = Ext.isString(itemHandler) ? eval(itemHandler) : itemHandler;
            	
                menuItem.handler = function(target, event){
                    //when the action is launched from the menu, can't walk up the event.target DOM tree to find the table because the menu is outside
                    //the table. Setting jcacontainer on the event, so the table from which the menu was launched can be easily identified.
                    event.jcacontainer=table;
                    target.jcacontainer=table;
                    try{
                        itemHandler(target, event, table);
                    }finally{
                        //reset
                        event.jcacontainer=undefined;
                        target.jcacontainer=undefined;
                    }
                    return true;
                };
                // prevent nested wrappers by introducing "handlerWrapped" flag below
                menuItem.handlerWrapped = true;
            }
        });
        //performance fix - suspends events till all menu items are added so layout happens once instead of N times
        menu.suspendEvents();
        menu.removeAll(true);
        menu.add(actionModel.items);
        menu.loaded = true;
        menu.resumeEvents();
    },
    positionMenu: function(){
        var menu = this;
        menu.doLayout();

        /* Now that the final list of items is added, reposition the menu to fit the body */
        var xy = menu.getPosition();
        var layoutNeeded = false;
        /* if the menu is off the right edge, move it left to fit */
        if (xy[0] + menu.getWidth() > Ext.getBody().getWidth()) {
            xy[0] = Ext.getBody().getWidth() - (menu.getWidth() + menu.padding);
        }
        /* If the menu is taller than the entire body, put it at the top and enable scrolling*/
        if (menu.getHeight() > Ext.getBody().getHeight()) {
            xy[1] = menu.padding;
            menu.enableScrolling = true;
            layoutNeeded = true;
            /**
             * If the menu is short enough to fit the body, but is falling off the bottom,
             * move it up til it fits
             */
        }
        else if (Ext.getBody().getHeight() - menu.getHeight() < xy[1]) {
            xy[1] = Ext.getBody().getHeight() - (menu.getHeight() + menu.padding);
        }

        menu.getEl().setXY(xy);
        /* only do layout if absolutely necessary to avoid the performance hit */
        if (layoutNeeded) {
            menu.doLayout();
        }

    }
});

Ext.ComponentMgr.registerType("dynamicMenu", PTC.menu.DynamicMenu);

/**
 * A menu button that keeps it's menu aligned as menu items are added to it.
 *
 * @class PTC.menu.DynamicMenuButton
 * @extends Ext.Button
 */
PTC.menu.DynamicMenuButton = Ext.extend(Ext.Button, {

    constructor: function(buttonConfig) {
        PTC.menu.DynamicMenuButton.superclass.constructor.call(this, buttonConfig);

        this.menu.on('add', function() {
            this.realignMenu();
        }, this);
        this.on('menushow', function(button, menu) {
            this.realignMenu();
            PTC.menu.fireEvent("dynamicMenuShow", button, menu);
            PTC.action.actionTarget = button;
        }, this);
        this.menu.on('hide', function(menu) {            
            PTC.action.actionTarget = null;
        });
  
    },

    /**
     * Realigns the menu when items are added.
     */
    realignMenu: function() {
        this.menu.el.alignTo(this.el, this.menuAlign);
    }
});

Ext.ComponentMgr.registerType("dynamicMenuButton", PTC.menu.DynamicMenuButton);

/**
 * Close all menus in parent or children of the current window but NOT in the current window.
 *
 * This listener was added so that menus outside an Iframe close when you click in the Iframe.
 * and vice versa menus in an Iframe close if you click outside the Iframe.
 * (see SPR 1881429)
 */
PTC.menu.closeMenusOutsideThisFrame = function() {

    try {
        //when clicking in the main window, close all menus in iframes
        for (var i = 0, l = frames.length; i < l; i++) {
            // skip iframes that don't have Ext (for example, ones created by JS framework libraries)
            if ("Ext" in frames[i]) {
                frames[i].Ext.menu.MenuMgr.hideAll();
            }
        }
        //when clicking inside an iframe, close all menus in the parent and in other iframes
        if (parent.location.href !== window.location.href && "Ext" in parent) {
            parent.Ext.menu.MenuMgr.hideAll();
            //close menus in other iframes on the page (which can be common on cadx info pages)
            for (var j = 0, length = parent.frames.length; j < length; j++) {
                if ("Ext" in parent.frames[j] && parent.frames[j].location.href !== window.location.href) {
                    parent.frames[j].Ext.menu.MenuMgr.hideAll();
                }
            }
        }
    } catch(e) {
        //don't want any exceptions thrown
        //worst that should happen is a menu is left open when it shouldn't be
        jsca.log(e);
    }
};
Event.observe(window.document, 'click', PTC.menu.closeMenusOutsideThisFrame);

/**
 * Returns true if all the items in the menu are selected.
 */
Ext.menu.Menu.prototype.isAllItemsSelected = function(){
    var allSelected = false;

    if(this.items) {
        allSelected = true;
        this.items.each(function(menuItem){
            if (allSelected && !menuItem.checked) {
                allSelected = false;
            }
        });
    }

    return allSelected;
};

/**
 * If focussed row is selected & it isn't the only selected row
 * then return multiSelectBar having actions from the table's action model that are marked as (multiSelect=true && selectRequired=true)
 */
PTC.menu.getMultiSelectBar = function(tableId,contextOid){
    if(tableId){
        var selections = tableUtils.getTableSelectedRowsById(tableId);
        var j,size;
        for(j = 0 ,size = selections.length;j<size;j++){
             if(selections[j].id.indexOf(contextOid) >= 0&& selections.length>1){
                var table = tableUtils.getTable(tableId);
                if (table && tableUtils.isExt()) {
                    var multiSelectBar = table.jcaTableConfig.multiSelectbar;
                    return multiSelectBar;
                }

             }
        }
    }else{
        return;
    }
};


/** @namespace PTC.messaging Namespace for messaging functions and attributes. */
PTC.messaging = {};
PTC.messaging.msgWindow = null;
PTC.messaging.deferFadeoutTime = null;
/** 
 * After user has not touched the message window for X seconds, begin to fade it out.
 * This default is only used if there is some error getting the pref value using the method below.
 * Also, during automated testing this var is increased to ensure message is open long enough for verification
 * 
 * Don't access this var directly, instead call PTC.messaging.getDeferTimeoutMill() to ensure automation logic can override. 
 */
PTC.messaging.deferTimeoutMill = 3000;

PTC.messaging.getDeferTimeoutMill = function() {
    var pref = PTC.util.getPreference('/Display/FeedbackMessageDisplayTime');
    if (pref) {
        PTC.messaging.deferTimeoutMill = parseFloat(pref) * 1000; //Change from seconds to milliseconds
    }
    //memoize so next time API call doesn't bother re-checking pref
    PTC.messaging.getDeferTimeoutMill = function() {return PTC.messaging.deferTimeoutMill;};
    return PTC.messaging.deferTimeoutMill;
};

PTC.messaging.showInlineMessageParent = function (msgObjects) {
    if (window.opener) {
        return PTC.messaging.showInlineMessage(msgObjects);
    }
};
/**
 * Closes and destroys the inline message at the top
 */
PTC.messaging.closeInlineMessage = function(){
    if (PTC.messaging.msgWindow) {
        //if there is any timer running clear the time out before destroying the component. The fadeOut function will be called
        //if this is not done here, which will error out. SPR 2027826.(stopFx did not work)
        clearTimeout(PTC.messaging.deferFadeoutTime);
        PTC.messaging.msgWindow.close();
        PTC.messaging.msgWindow.destroy();
    }
};

/*
 * Destroy the message window only when there are no effects running.
 * 
 * This needs to defer so that the afterFx() function has been completely run.
 * If the defer is not in place then the hasActiveFx() will return saying that
 * the affect is still going.  If we defer then the afterFx() has time to complete
 * and allows for the hasActiveFx() to return false;
 */
PTC.messaging.closeInlineMessageFadeout = function(){
    if (PTC.messaging.msgWindow && !PTC.messaging.msgWindow.isDestroyed) {
        (function(){
            if (!PTC.messaging.msgWindow.getEl().hasActiveFx()) {
                PTC.messaging.closeInlineMessage();
            }
        }).defer(1);
    }
};

/**
 * Displays the inline message in the main window. 
 * Supported message types are: SUCCESS, FAILURE, WARNING, FATAL and INFO.
 *
 * The titles and messages must be plain text.  Any HTML encoding in them
 * that is not known to be safe from XSS attacks will be escaped before
 * they it is displayed. (SPR 4657817)
 * 
 * @param {Array} msgObjects - An array of the message objects config. 
 *
 * @example
 *  PTC.messaging.showInlineMessage([{
 *      MessageTitle: 'Sample Message Title',
 *      Messages: ['Sample Message one.','Sample Message Two'],
 *      MessageType: 'SUCCESS'
 *  }]);
 *
 **/ 
PTC.messaging.showInlineMessage = function(msgObjects) {
    // only show the window if this is an array of message objects 
    if (!msgObjects.length || msgObjects.length <= 0) {
        return;
    }
    
    PTC.messaging.closeInlineMessage();
    var currentWindow = getWindow();
   
    // if lightbox iframe, the message will be sent to be rendered on parent window context
    // so that the timers of fade out etc still work when lightbox iframe is closed quickly. 
    var isLightboxIframe = PTC.lightbox.isLightbox(window);
    if (isLightboxIframe) {
        var parentWindow = PTC.lightbox.getParentWindow().getWindow();
        // direct the message handling to parent window, if this is not already parent top frame
        if (parentWindow !== window) {
            parentWindow.PTC.messaging.showInlineMessage(msgObjects);
            return;
        }
    }
    
    PTC.messaging.msgWindow = new Ext.Window( {
            cls: 'inlineWindow',
            id: 'inlineWindow',
            x:0,
            y:0,
            draggable: false,
            resizable: false,
            title: '',
            shadow: false,
            header: false,
            closable: false,
            padding: '0px 0px 6px 0px',
            focus: Ext.emptyFn  // no need to allow this to get focus, 2099943
    });
    var msgWindow = PTC.messaging.msgWindow;

    var closeButton = new Ext.BoxComponent({
        autoEl: {
            tag: 'div',
            cls: 'x-tool x-tool-close',
            html: ' '
        }
    });
    msgWindow.add(closeButton);
    var msgObjLength = msgObjects.length;
    var needScrollBar = false;
    // show scroll bars in this case.
    if (msgObjLength >= 5){
        needScrollBar=true;
    }
    // assuming there is title and a message line. This variable determines if scroll bar is needed or not.
    var i, totalLength = msgObjLength*2;
    
    for (i = 0; i < msgObjLength; i++) {
        var messagePanel = msgObjects[i];
        var oidsLength = 0;
        if (messagePanel.OidIdentity && messagePanel.OidIdentity.length) {
            oidsLength = messagePanel.OidIdentity.length;
        }
        // keep adding the oid length for all message object.
        totalLength += oidsLength;
        if (totalLength > 12 && needScrollBar !== true) {
            needScrollBar = true;
        }
        msgWindow.add(PTC.messaging._getMsgComponent(messagePanel));
    }
    // limiting the height in order to show the scroll bar. The style already has overflow set to auto.
    if (needScrollBar === true) {
        msgWindow.height = 300;
    }
    
    msgWindow.render(currentWindow.Ext.getBody().dom);
    msgWindow.show();
    var slideInParams = { duration: 0.3 };
    var el = msgWindow.getEl();
    el.slideIn('t', slideInParams);
    
    var closeBtnEl = closeButton.getEl();
    closeBtnEl.addClassOnOver( 'x-tool-close-over' );
    closeBtnEl.on('click',PTC.messaging.closeInlineMessage);
    PTC.messaging.deferFadeoutTime = (PTC.messaging.messageFadeout).defer(PTC.messaging.getDeferTimeoutMill());
};

PTC.messaging.messageFadeout = function(){
    var el = PTC.messaging.msgWindow.getEl();
    el.fadeOut({
        endOpacity: 0.01,
        duration: 3,
        callback: PTC.messaging.closeInlineMessageFadeout
    });
};

PTC.messaging._getMsgComponent = function(msgObj) {
    var msgDiv = new Ext.Container({
        autoEl: {
            tag: 'div',
            cls: 'inlineMessage'
        },
        listeners: {
            render: function(){
                //don't fade when mouse is over the message window (including scrollbar area).
                PTC.messaging.msgWindow.getEl().on('mouseover', PTC.messaging.makeMessagePermanent);
                // if they move out of this div then we start the timer to fade away the message
                PTC.messaging.msgWindow.getEl().on('mouseout', function(){
                    PTC.messaging.deferFadeoutTime = (PTC.messaging.messageFadeout).defer(PTC.messaging.getDeferTimeoutMill());
                });
            }
        }   
     });

    if (msgObj.MessageType) {
        var icon = null;
        if ('SUCCESS' == msgObj.MessageType) {
            icon = 'success_large.png';
        }
        if ('FAILURE' == msgObj.MessageType) {
            icon = 'failure_fixable_large.png';
        }
        if ('WARNING' == msgObj.MessageType) {
            icon = 'warning_large.png';
        }
        if ('FATAL' == msgObj.MessageType) {
            icon = 'failure_nofix_large.png';
        }
        if ('INFO' == msgObj.MessageType) {
            icon = 'info_large.png';
        }
        if (icon) {
            msgDiv.add(new Ext.BoxComponent({
                autoEl: {
                    tag: 'img',
                    src: getBaseHref() + 'netmarkets/images/' + icon,
                    cls: 'inlineIcon'
                }
            }));
        }
    }

    var msgText = "";
    if (msgObj.MessageTitle) {
        var title = msgObj.MessageTitle;
        if (!msgObj.hasOwnProperty('MessageTitleCheckXSS') || (msgObj.MessageTitleCheckXSS === true)) {
            title = PTC.util.HTMLEncoder.encodeForHTMLContent(title);
        }
        msgText += "<b>" + title + "</b><br/>";
    }
    if (msgObj.Messages && msgObj.Messages.length>0 ) {
        for (var i=0; i<msgObj.Messages.length; i++) {
            var msg = msgObj.Messages[i];
            if (!msgObj.hasOwnProperty('MessagesCheckXSS') || (msgObj.MessagesCheckXSS[i] === true)) {
                msg = PTC.util.HTMLEncoder.encodeForHTMLContent(msg);
            }
            msgText += msg + "<br/>";
        }
    }
    msgDiv.add(new Ext.BoxComponent( {
        autoEl: {
            tag: 'div',
            cls: 'msgLabel',
            html: msgText
        }
    }));
    
    
    if (msgObj.OidIdentity && msgObj.OidIdentity.length > 0) {
        var showLinks = !msgObj.showItemIdAsText;
        for (var j = 0; j < msgObj.OidIdentity.length; j++) {
            var oidIdentity = msgObj.OidIdentity[j];
            var displayIdentity = "";
            //not all objects have display identity
            var htmlString =  "";
            
            if(oidIdentity.objType){//if the objType exists
                htmlString = PTC.util.HTMLEncoder.encodeForHTMLContent(oidIdentity.objType);
            }
            
            if (oidIdentity.displayIdentity) {//if the display identity exists
                if (htmlString !== "") { //if objType is already there use the -
                    htmlString = htmlString + " - ";
                }
                var idString = PTC.util.HTMLEncoder.encodeForHTMLContent(oidIdentity.displayIdentity);
                htmlString = htmlString + PTC.util.HTMLEncoder.handleAdjacentSpaces(idString);
            }
            
            var objectIdentityLine = new Ext.Container({
                autoEl: {
                    tag: 'div',
                    cls: 'msgObjIdentityLine'
                }
            });
            if(oidIdentity.icon){//if the icon exists
                objectIdentityLine.add(new Ext.BoxComponent({
                    autoEl: {
                        tag: 'img',
                        src: PTC.util.HTMLEncoder.encodeForHTMLAttribute(getBaseHref() + oidIdentity.icon)
                    }
                }));           
            }
            //not all persistables have info pages (for example Object Initialization Rules)
            var itemIdConfig = {
                tag: 'span',
                html: htmlString,
                cls: 'msgIdentityText'
            };
            if (showLinks) {
                itemIdConfig.tag = 'a';

                //Get the commonParams required to build info page url
                var params = {};
                PTC.messaging._mergeParams(params, msgObj.commonParams);
                PTC.messaging._mergeParams(params, oidIdentity.objectParams);

                itemIdConfig.href = PTC.infoPage.getURL(oidIdentity.oid, params); 
            }
            var itemIdComp = new Ext.BoxComponent({autoEl: itemIdConfig});                

            objectIdentityLine.add(itemIdComp);
            msgDiv.add(objectIdentityLine);
        }
    }

    return msgDiv;
};

/**
 * Merges any key/value pairs in "src" into the set of key/value pairs in "dest".
 *
 * @param {Object} [dest] the destination of the merge
 * @param {Object} [src] the source of the key/value pairs to be merged.
 */
PTC.messaging._mergeParams = function(dest, src) {
    if (src) {
        for (var key in src) {
            if( key !== undefined) {
                dest[key] = src[key];
            }
        }
    }
};


/**
 * Displays a warning message in a lightbox window.
 *
 * @param {String} title to be displayed in message window title.
 * @param {String} message to be displayed in message window body.
 */
PTC.messaging.showWarningMessage = function(title, msg){
    PTC.messaging.showMessage(title, msg, null, Ext.MessageBox.WARNING);
};

/**
 * Displays an Ext lightbox message with the given params. If no args are passed, the default message is displayed.
 * 
 * @param {String} [title] Optional title to be displayed in message window title.
 * @param {String} [msg] Optional message to be displayed in message window body.
 * @param {Object} [buttons] Optional buttons, e.g: "Ok", "Cancel", etc. By default it is only an "Ok" button
 * @param {Object} [icon] Optional icon. By default is shows an error icon
 */
PTC.messaging.showMessage = function(title, msg, buttons, icon){
    Ext.Msg.show({
        title: (title) ? title : bundleHandler.get('com.ptc.netmarkets.util.utilResource.ERROR_PAGE_TITLE'),
        msg: (msg) ? msg : bundleHandler.get('com.ptc.core.ui.errorMessagesRB.UNEXPECTED_MESSAGE'),
        buttons: (buttons) ? buttons : {ok: bundleHandler.get('com.ptc.core.ui.navigationRB.okDialogButton')},
        icon: (icon) ? icon : Ext.MessageBox.ERROR // style overridden in xtheme-windchill.css to use PTC img instead
    });
};

/**
 * Will make the current message hold and stay visible 
 * Useful for selenium testing to make sure holding by mouse in works.  Same handler called by mouseover
 */
PTC.messaging.makeMessagePermanent = function() {
    clearTimeout(PTC.messaging.deferFadeoutTime);
    if (PTC.messaging.msgWindow.getEl().hasActiveFx()) {
        var msgWindow = PTC.messaging.msgWindow;
        var el = msgWindow.getEl();
        el.stopFx();
        el.fadeIn({
            endOpacity: 1,
            duration: 1
        });     
    }
};


/**
 * @namespace for functions related to mini info navigator that
 * shows visualization, attributes and relationships for an object
 */
PTC.miniNavigator = {};

Ext.apply(PTC.miniNavigator, new Ext.util.Observable());

/**
 * Event is dispatched before the page is loaded, return false to deny the page load.
 *
 * @name PTC.miniNavigator#show
 * @event
 * @param {String} oid of the object being shown
 */
PTC.miniNavigator.addEvents ("show");

PTC.miniNavigator.menuTitleID = 'wvsnavdetailsPageActionsMenu';
PTC.miniNavigator.log = log4javascript.getLogger('PTC.miniNavigator');

/**
 * aborts any pending requests - called when new mini navigator is shown or if mini navigator is hidden
 */
PTC.miniNavigator.abortPendingRequests = function(){
    requestHandler.abortAll(PTC.miniNavigator._pendingRequests);
    PTC.miniNavigator._pendingRequests = [];
};
/**
 * to keep track of all pending requests for mini info navigator.
 */
PTC.miniNavigator._pendingRequests = [];
/**
 * calls requestHandler.doRequest() with the given arguments and keeps track of resulting transport object in case
 * request needs to be cancelled
 * @see requestHandler.doRequest(url, options)
 */
PTC.miniNavigator.doRequest = function(){
    var transport = requestHandler.doRequest.apply(this, arguments);
    PTC.miniNavigator._pendingRequests[PTC.miniNavigator._pendingRequests.length] = transport;
    return transport;
};

function WVSAddEvent(obj, type, fn){
    if (obj.attachEvent) {
        obj['e' + type + fn] = fn;
        obj[type + fn] = function(){
            obj['e' + type + fn](window.event);
        };
        obj.attachEvent('on' + type, obj[type + fn]);
    }
    else {
        obj.addEventListener(type, fn, false);
    }
}

function WVSRemoveEvent(obj, type, fn){
    if (obj.detachEvent) {
        obj.detachEvent('on' + type, obj[type + fn]);
        obj[type + fn] = null;
        obj['e' + type + fn] = null;
        //obj.detachEvent( 'on'+type, fn );
    }
    else {
        obj.removeEventListener(type, fn, false);
    }
}

function WVSFindAbsPos(obj){
    var el = Ext.get(obj);
    if (!el) {
        return [0, 0];
    }
    return el.getXY();
}

/**
 *
 * @param {Object} popupObject
 * @return String option param to add to the url
 */
PTC.miniNavigator.getThreeDOption = function(popupObject){
    var threeD = '';
    if (popupObject.show3D) {
        if (popupObject.useNavigation) {
            threeD = "&t=0";
        }
        else {
            threeD = "&t=3";
        }
    }
    return threeD;
};

