var WVSPopup = {
    pinned: false,
    stuck: false,
    options: null,
    baseURL: null,
    helpUrl: null,
    oid: null,
    assocoid: null,
    type: null,
    typenav: false,
    pvaction: "0",
    homeoid: null,
    history: null,
    fhistory: null,
    win: null,
    status: null,
    stdtext: null,
    clashtext: null,
    pviewReady: false,
    pviewOrientation: null,
    pviewMode: "select",
    selectedChild: null,
    showing3D: false,
    show3D: false,
    showdyndoc: false,
    dragx: 0,
    dragy: 0,
    useNavigation: true, // setting
    use3D: true, // setting
    getRef: "", // setting, make "&ref=1" to get reference objects
    height: 428, // Default height of the popup window height of internal +6 for spacing +26 for vispanel title header
    width: 486, // Default width of the popup window
    
    getHelp: function(){
        PTC.help.openHelpWindow(WVSPopup.helpUrl);
    },
    
    getData: function(oid){
    	/*We are possibly trying to get visualization for an object that doesn't have it, eg problem report, if so we still need to 
    	 * set the oid. In IE and Creo thumbDataSuccess is not called so the WVPopup.oid was not being set either there or in MTaddData, 
    	 * since this didn't work in all browsers now we are just setting the WVPopup.oid all the time here. 
    	 * Now we are also down from 2 possible places to set WVPopup.oid, to just this one. 
    	 */
    	WVSPopup.oid = decodeURIComponent(oid);

    	var url = 'servlet/WindchillAuthGW/com.ptc.wvs.server.ui.ThumbnailHelper/getMThumbInfo?oid=' + oid + PTC.miniNavigator.getThreeDOption(WVSPopup) + WVSPopup.getRef;      
    	if (!WVSPopup.fetchServerData(url, {
            onSuccess: WVSPopup.thumbDataSuccess
        })) {
            return;
        }
    },
    
    setShow3DImage: function(show3D){
        if (!WVSPopup.use3D) {
            show3D = false;
        }
        
        WVSPopup.show3D = show3D;
    }
};

WVSPopup.log = log4javascript.getLogger("PTC.wvs");

/**
 * Default ajax request failure handler, logs to the server and shows quick tip about the error
 */
WVSPopup.failure = function(transport){
    var pos = WVSFindAbsPos(_mtTimeOutImg);
    WVSPopup.showStatus(bundleHandler.get('com.ptc.netmarkets.util.utilResource.SERVER_ERROR') + transport.responseText, pos[0] + 24, pos[1] + 16, true);
    WVSPopup.log.error("WVS server request failed", transport.responseText);
};

WVSPopup.fetchServerData = function(theURL, options){
    //Apply default options, common to most requests
    Ext.applyIf(options, {
        method: 'get',
        asynchronous: true,
        onFailure: WVSPopup.failure,
        onException: WVSPopup.failure
    });
    return PTC.miniNavigator.doRequest(theURL, options);
};

/**
 * Success function for the ajax call to get detail info about the object
 * Expects the responseXML to be populated
 */
WVSPopup.thumbDataSuccess = function(xmlhttp){
    if (xmlhttp.responseXML) {
        if (!WVSPopup.updateThumbInfo(xmlhttp.responseXML)) {
            return;
        }
    }
    else {
        return false;
    }
};

function MTnavigateTo(oid, nullFHistory){
    if (typeof(nullFHistory) === "undefined" || nullFHistory) {
        WVSPopup.fhistory = null;
    }
    WVSPopup.pinit();
    WVSPopup.show(oid, -1, -1, true, false, true);
}
/**
 * Sets some basic state, creates the Ext window
 */
WVSPopup._createWinAndBasicSetup = function(){
    WVSPopup.baseURL = PTC.attributeHelper.get("WVSPopup.baseURL");
    WVSPopup.options = PTC.attributeHelper.get("WVSPopup.options");
    WVSPopup.helpUrl = PTC.attributeHelper.get("WVSPopup.helpUrl");
    MTsetViewerOptions();
    WVSPopup.createLayout(WVSPopup.createFrames());
    
    WVSAddEvent(document, 'mousedown', WVSPopup.mouseHide);
    PTC.navigation.on('historyChange', WVSPopup.onPageChange);
    
    if (PTC.wvs.webgl.isEnabledForThumbnailNav() === false) { 
        if (!Ext.isWindows) {
            WVSPopup.use3D = false;
        }
        if (!WVSPopup.isPVInstalled()) {
            WVSPopup.use3D = false;
        }
    }

    if (!WVSPopup.use3D) {
        WVSPopup.useNavigation = false;
    }
};
/**
 * Open the Mini Navigator for the oid at the location x,y
 * @param {String} oid
 * @param {Number} x
 * @param {Number} y
 * @param {Boolean} show3D
 * @param {Boolean} setHome
 * @param {Boolean} setHistory
 */
WVSPopup.show = function(oid, x, y, show3D, setHome, setHistory){
    //showing a new mini navigator, so abort any pending ajax requests for previous mini nav
    PTC.miniNavigator.abortPendingRequests();
    if (!WVSPopup.win) {
        WVSPopup._createWinAndBasicSetup();
    }
    else {
        if (!WVSPopup.win.isVisible()) {
            WVSAddEvent(document, 'mousedown', WVSPopup.mouseHide);
            PTC.navigation.on('historyChange', WVSPopup.onPageChange);
        }
        if (WVSPopup.oid === oid && WVSPopup.win.isVisible() && setHistory) {
                    // don't need to fetch what is already displayed
            return null;
        }
    }
    PTC.miniNavigator.getAndDisplayNavConfig(oid);
    
    if (WVSPopup.oid && setHistory) {
        if (!WVSPopup.history) {
            WVSPopup.history = [];
        }
        if (WVSPopup.history.length === 0 || WVSPopup.history[WVSPopup.history.length - 1] != WVSPopup.oid) {
            WVSPopup.history.push(WVSPopup.oid);
        }
    }
    
    WVSPopup.pviewReady = false;
    WVSPopup.selectedChild = null;
    WVSPopup.hideStatus();
    var rightmenu = Ext.getCmp("wvsrightmenu");
    if (rightmenu) {
        rightmenu.hide();
    }
    WVSPopup.pviewMode = "select";
    
    if (!WVSPopup.use3D) {
        show3D = false;
    }
    
    WVSPopup.show3D = show3D;
    WVSPopup.getData(oid);
    
    WVSPopup.setPosition(x,y);
    
    if (setHome || !WVSPopup.history) {
        WVSPopup.homeoid = oid;
        WVSPopup.history = [];
        WVSPopup.fhistory = null;
    }
    PTC.miniNavigator.fireEvent('show', oid);
    WVSPopup.win.show();
   
};

/**
 * move the popup to the passed in coordinates.
 * @param {Number} x
 * @param {Number} y
 */
WVSPopup.setPosition = function(x, y){
    if (x > 0 && y > 0 && !WVSPopup.pinned) {
        var topEl = Ext.get(top.document);
        var scroll;
        if (topEl) {
            scroll = topEl.getScroll(); // can the window even be scrolled anymore?
        }
        else {
            scroll = {
                top: 0,
                left: 0
            };
        }
        x = x + scroll.left;
        if ((x - scroll.left) < 0) {
            x = scroll.left;
        }
        
        y = y - WVSPopup.height / 2 + scroll.top;
        if ((y - scroll.top) < 0) {
            y = scroll.top;
        }
        if (y + WVSPopup.height - scroll.top > top.document.body.clientHeight - 2) {
            y = top.document.body.clientHeight - 2 - WVSPopup.height + scroll.top;
        }
        
        WVSPopup.win.setPagePosition(x, y);
    }
};

/**
 * For IE consider Creo View installed if ActiveXObject is available (e.g. its IE)
 * Else check if the Creo View plugin is installed.
 */
WVSPopup.isPVInstalled = function() {
    var result = false;
    // Necessary to check if("ActiveXObject" in window) so this check will work in IE 8 mode and IE 11+ Edge mode.
    // In IE 11+ ActiveXObject property is on the window, but is undefined. 
    if("ActiveXObject" in window) {
        PTC.miniNavigator.log.debug("ActiveXObject is available for IE in IE=8 mode or IE=Edge mode.");
        result = true;
    } else if (navigator.plugins) {
        PTC.miniNavigator.log.debug("Check plugins. Non-IE browsers.");
        var len = navigator.plugins.length;
        for (var i = 0; i < len; i++) {
            if (navigator.plugins[i].name === "Creo View") {
                result = true;
            }
        }
    }
    PTC.miniNavigator.log.debug("WVSPopup.isPVInstalled returning " + result);
    return result;
};

WVSPopup.stick = function(){
    var si = Ext.getCmp("wvsstickicon");
    
    if (WVSPopup.stuck) {
        WVSPopup.stuck = false;
        WVSPopup.unpinit();
        si.setTooltip(bundleHandler.get('com.ptc.wvs.server.ui.uiResource.TN_DISABLE_ROLLOVER'));
        si.btnEl.setStyle('background-image', 'url(netmarkets/images/unlock.gif)');
        
        Ext.getCmp("wvssticktext").setText("");
    }
    else {
        WVSPopup.stuck = true;
        WVSPopup.pinit();
        si.setTooltip(bundleHandler.get('com.ptc.wvs.server.ui.uiResource.TN_ENABLE_ROLLOVER'));
        si.btnEl.setStyle('background-image', 'url(netmarkets/images/lock.gif)');
        
        Ext.getCmp("wvssticktext").setText("(" + PTC.util.HTMLEncoder.encodeForHTMLContent(bundleHandler.get('com.ptc.wvs.server.ui.uiResource.TN_ROLLOVER_DISABLED')) + ")");
    }
};

WVSPopup.stickit = function(){
    if (!WVSPopup.stuck) {
        WVSPopup.stick();
    }
};
WVSPopup.unstickit = function(){
    if (WVSPopup.stuck) {
        WVSPopup.stick();
    }
};

WVSPopup.pin = function(){
    if (WVSPopup.pinned) {
        WVSPopup.pinned = false;
        WVSAddEvent(document, 'mousedown', WVSPopup.mouseHide);
    }
    else {
        WVSPopup.pinned = true;
        WVSRemoveEvent(document, 'mousedown', WVSPopup.mouseHide);
    }
};


WVSPopup.pinit = function(){
    if (!WVSPopup.pinned) {
        WVSPopup.pin();
    }
};
WVSPopup.unpinit = function(){
    if (WVSPopup.pinned) {
        WVSPopup.pin();
    }
};

WVSPopup.isNavigateMode = function(){
    return WVSPopup.show3D && WVSPopup.typenav && WVSPopup.useNavigation;
};

WVSPopup.setMode = function(u3d, nav){
    WVSPopup.use3D = u3d;
    WVSPopup.useNavigation = nav;
    if (!WVSPopup.use3d) {
        WVSPopup.useNavigation = false;
    }
};

function MTback(){
    if (WVSPopup.showing3D && !WVSPopup.pviewReady) {
        return;
    }
    if (WVSPopup.history && WVSPopup.history.length > 0) {
        if (!WVSPopup.fhistory) {
            WVSPopup.fhistory = [];
        }
        WVSPopup.fhistory.push(WVSPopup.oid);
        
        WVSPopup.oid = null; // so don't add to history when going back
        MTnavigateTo(WVSPopup.history.pop(), false);
    }
}

function MTforward(){
    if (WVSPopup.showing3D && !WVSPopup.pviewReady) {
        return;
    }
    
    if (!WVSPopup.fhistory || WVSPopup.fhistory.length === 0) {
        return;
    }
    MTnavigateTo(WVSPopup.fhistory.pop(), false);
}

function MTforwardAll(){
    if (WVSPopup.showing3D && !WVSPopup.pviewReady) {
        return;
    }
    
    if (!WVSPopup.fhistory || WVSPopup.fhistory.length === 0) {
        return;
    }
    MTnavigateTo(WVSPopup.fhistory[0]);
}

function MTrefresh(){
    WVSPopup.show(WVSPopup.oid, -1, -1, true, false, false);
}

function MThome(){
    if (WVSPopup.showing3D && !WVSPopup.pviewReady) {
        return;
    }
    if (WVSPopup.homeoid) {
        if (WVSPopup.showing3D && PTC.miniNavigator.is3dPluginPresent()) {
            WVSPopup.pviewOrientation = document.mtpvctl.GetViewLocation();
        }
        WVSPopup.pinit();
        WVSPopup.show(WVSPopup.homeoid, -1, -1, true, true, false);
    }
}

PTC.miniNavigator.getTitleMenuConfig = function(){
    var actionsMenu = PTC.attributeHelper.get("ActionsMenu");
    //this has to map the same id as defined in RenderInfoPageModelTag in getDataValue for nmActions.
    var defaultText = bundleHandler.get('com.ptc.core.ui.navigationRB.MININAVTHUMBPANE');
    var menuButton = {
        xtype: 'dynamicMenuButton',
        cls: 'miniNavTitle',
        id: PTC.miniNavigator.menuTitleID,
        text: defaultText,
        defaultText: defaultText,
        menu: {
            xtype: 'dynamicMenu',
            id: 'wvsViewActionMenu',
            requestUrl: actionsMenu.url,
            //keep showing the same actions till the next time the info page is refreshed
            loadOnce: true,
            requestOptions: {
                parameters: 'actions=wvsCustomPaneWidgets',
                onSuccess: PTC.miniNavigator.menuSuccess
            }
        },
        listeners: {
            'click': function(button){
                //ensure the correct mainform is used 
                PTC.util._setMainFormStartingElement(button.id);
                this.menu.positionMenu();
                PTC.menu.fireEvent("dynamicMenuLoad", this.menu);
            },
            'afterRender': function(button){
                //pre-populate the menu items right away so if the user clicks the menu later the actions are available right away
                PTC.miniNavigator.doRequest(button.menu.requestUrl, button.menu.requestOptions);
            }
        }
    };
    return menuButton;
};

/**
 * The listener for the expand/collpase and drag-and-drop of the mini nav portlets.  If the portal column is already
 *  persisted, it should have an oid on it.
 * 
 * @param {Object} event - either an expand, collapse or drop event.
 */
PTC.miniNavigator.persistMiniTableOrder = function(event) {
    var portalManager = Ext.getCmp(PTC.miniNavigator.cardManager).portalManager;
    // on drop, event will have a column reference
    // on expand or collapse, event will be the portlet
    var column = event.column || event.ownerCt;
    if (!column.oid) {
        portalManager.create();
    } else {
        portalManager.update();
    }
};

/**
 * Sorts the portals based on tabset index as they are added to the panel.
 */
PTC.miniNavigator.sortPortals = function() {
    this.items.sort('ASC', function(a, b) {
        return a.itemIndex - b.itemIndex;
    });
};

PTC.miniNavigator.cardManager = 'mini' + PTC.navigation.cardManager;

function MTLaunchDetailsSuccess(xmlhttp){
    if (xmlhttp.responseText && xmlhttp.responseText.length > 0) {
        if (xmlhttp.responseText.indexOf("javascript") === 0) {
            PTC.jslint.foundEvalReservedWord(xmlhttp.responseText);
        }
        else {
            var mainWindow = PTC.getMainWindow();
            mainWindow.PTC.navigation.loadContent(xmlhttp.responseText, true);
            
            // if the navigator is opened, close it so the info page is shown - SPR 2116786
            // it should only be closed if the navigator is not pinned opened
            if(mainWindow.PTC.navigator.isExpanded()) {
                mainWindow.PTC.navigator.collapseNavigator();
            }
        }
    }
}

/**
 * Fetches the url from the server.  For most objects types, this method could do a PTC.infoPage.goTo instead.
 * But will need to make sure that LifeCycleManagedWtMarkUp goes to clashReport.viewClashReport
 */
function MTLaunchDetails(){
    WVSPopup.hideStatus();
    var theURL = 'servlet/WindchillAuthGW/com.ptc.wvs.server.ui.ThumbnailHelper/getDetailsPageURL?oid=' + WVSPopup.oid;
    
    var coid = extractParamValue(top.location.href, "ContainerOid");
    if (!coid || coid.length === 0) {
        coid = extractParamValue(top.location.href, "oid");
    }
    if (coid && coid.length > 0) {
        theURL += "&coid=" + coid;
    }
    
    var options = {
        onSuccess: MTLaunchDetailsSuccess
    };
    WVSPopup.fetchServerData(theURL, options);
}

