PTC.miniNavigator.Portlet = Ext.extend(Ext.ux.Portlet, {
    constructor: function(config) {
        config = config || {};
        Ext.applyIf(config, {
            setSize: FALSE_FUNC, //only way to force ext not to manage sizes. Width is specified in siteStyles
            collapsible: true,
            listeners: {
                expand: PTC.miniNavigator.persistMiniTableOrder
            }
        });
        this.actionName = config.actionName;
        this.actionType = config.actionType;
        PTC.miniNavigator.Portlet.superclass.constructor.call(this, config);

        // Delay adding collapse listener until after it is rendered because the portlet will fire a collapse event
        // if the initial state is collapsed.
        this.on('afterrender', function() {
            this.on('collapse', PTC.miniNavigator.persistMiniTableOrder);
        }, this, {single: true});
    }
});

