/**
 * Adjusts the height of the attributes panel so that the scrollbar is shown correctly
 * This makes the att panel take the rest of the visible height from the west panel
 */
PTC.miniNavigator.setAttributePanelHeight = function(){
    var westPanel = Ext.getCmp('vis');
    
    var attsPanel = Ext.getCmp('vis_atts_panel');
    var otherPanelsHeight = westPanel.getFrameHeight();
    for (var i = 0, l = westPanel.items.items.length; i < l; i++) {
        var nextPanel = westPanel.items.items[i];
       	var h = nextPanel.getHeight();
        if (nextPanel.id !== attsPanel.id) {
             otherPanelsHeight += nextPanel.getHeight();
        }
    }
    attsPanel.setHeight(westPanel.getOuterSize().height - otherPanelsHeight);
};
PTC.miniNavigator.setAttributePanelHeight = PTC.util.delayAllCalls(PTC.miniNavigator.setAttributePanelHeight);

function MTUpdateTipText(tip, text){
    if (!tip) {
        WVSPopup.log.error(text);
        return;
    }
    if (tip.body) {
        tip.body.update(text);
    }
    else {
        tip.html = text;
    }
}

function MTUpdateToolTipTextFromHTML(tip){
    MTUpdateTipText(tip, tip.target.dom.innerHTML);
    return true;
}

