/**
 * Success function for menu ajax req.
 * @param {Object} response
 */
PTC.miniNavigator.menuSuccess = function(response){
    var actionModel = Ext.decode(response.responseText);
    var menu = Ext.getCmp(PTC.miniNavigator.menuTitleID).menu;
    menu.initializeMenu(actionModel);
    
    if (menu.isVisible()) {
        menu.positionMenu();
    }
    menu.on('afterlayout', function(menu){
        menu.items.each(function(menuItem){
            menuItem.el.on('mouseover', WVSPopup.mousein);
        });
    });
};

