/**
 * shows or hides the vispanel and related buttons based on the info config
 * @param {Object} config
 */
PTC.miniNavigator.updateVisPanel = function(){
    var iConfig = Ext.getCmp('MTWindow').getInfoConfig();
    var visPanel = Ext.getCmp('vis_img_panel');
    var visPanelVisible = visPanel.getEl().isVisible();
    var openInCreoViewButton = Ext.getCmp('wvspvlaunch');
    var copyButton = Ext.getCmp('wvscopy');
    var partDocButton = Ext.getCmp('wvspartdoc');
    if (iConfig.data.showVisualization && !visPanelVisible) {
        visPanel.show();
        openInCreoViewButton.show();
        copyButton.show();
        partDocButton.show();
    }
    else if (!iConfig.data.showVisualization && visPanelVisible) {
        visPanel.hide();
        openInCreoViewButton.hide();
        copyButton.hide();
        partDocButton.hide();
    }
};


/**
 * Create and render panels on the miniNavigator.   Panes such as Item id, attribute layouts, visualization image
 * @param {Object} response response text from miniInfo controller
 */
PTC.miniNavigator.renderPanels = function(response){
    var config = Ext.util.JSON.decode(response.responseText.trim());
    this.setInfoConfig(config);
    // store whether the Navigate Structure tab in the right pane is configured to be visible
    var identity = PTC.infoPage.getIdentityHTML(config);
    var titleCmp = Ext.getCmp('titleText');
    titleCmp.setText('');
    titleCmp.getEl().dom.innerHTML = identity;

    PTC.miniNavigator._renderAttrPanel(config.attributePanelModel);
    PTC.miniNavigator.configureRightPane();
    PTC.miniNavigator.renderRelatedInfo();
    PTC.miniNavigator.updateVisPanel();
    //var win = Ext.getCmp('MTWindow');
    //win.doLayout();

};

/**
 * Sets the active tab based on which menu items are shown.
 * Also adjusts the menu/title at the top of the right pane depending on which tabs are visible.
*/
PTC.miniNavigator.configureRightPane = function() {
    var iConfig = Ext.getCmp('MTWindow').getInfoConfig();
    var cardManager = Ext.getCmp(PTC.miniNavigator.cardManager);
    if (iConfig.data.showNavigateThumbnails && !iConfig.data.showRelatedInfo) {
    	Ext.getCmp(PTC.miniNavigator.cardManager).layout.setActiveItem(0);
    }
    else if (!iConfig.data.showNavigateThumbnails && iConfig.data.showRelatedInfo) {
    	Ext.getCmp(PTC.miniNavigator.cardManager).layout.setActiveItem(1);
    }
    PTC.miniNavigator.resetMenuButton(iConfig, iConfig.tabSet.items[1].components.items);
};

/**
 * Gets the data for and loades the Related Info panels if the Related Info tab is configured to be visible.
 */
PTC.miniNavigator.renderRelatedInfo = function() {
    var iConfig = Ext.getCmp('MTWindow').getInfoConfig();
    var relatedInfo = iConfig.tabSet.items[1];
    if (iConfig.data.showRelatedInfo) {
        //Ext.getCmp(PTC.miniNavigator.cardManager).layout.setActiveItem(1);
        var portalCol = PTC.miniNavigator.getRelatedInfoPortalColumn();
        portalCol.oid = relatedInfo.oid;
        portalCol.tabSetKey = iConfig.tabSet.tabSetKey;
        portalCol.objectType = iConfig.tabSet.objectType;
        PTC.miniNavigator.getRelatedInfoPanels(iConfig, relatedInfo.components.items);
        PTC.miniNavigator.getRelatedInfoPortalColumn().show();
    }
};

/**
 * Create and render the attribute panel layouts.  This config is where the type manager attribute layout is used.
 * Will destroy the current panel if it exists.
 * @param {Object} attributePanelModel config
 */
PTC.miniNavigator._renderAttrPanel = function(attributePanelModel){

    if (WVSPopup.attrPanel) {
        WVSPopup.attrPanel.destroy(true);
        var panel = Ext.getCmp('vis_atts_panel');
        panel.getEl().update(panel.initialConfig.html);
    }
    attributePanelModel.useExistingDUniqueDivs = false;
    attributePanelModel.forceAutoWidth = true;

    //decode url params that came from server
    if(attributePanelModel.storeURL.pve === true){
        attributePanelModel.storeURL.params = PTC.util.decode.paramsForJS(attributePanelModel.storeURL.params);
        attributePanelModel.storeURL.pve=undefined;
    }
    WVSPopup.attrPanel = new PTC.attributePanel.AttributePanel(attributePanelModel);
};
/**
 *
 * @param {String} oid
 */
PTC.miniNavigator.getAndDisplayNavConfig = function(oid){
    var url = PTC.miniNavigator.url + '&oid=' + oid;
    PTC.miniNavigator.doRequest(url, {
        method: 'get',
        // make the window the "this" object of renderPanels
        onSuccess: PTC.miniNavigator.renderPanels.bind(Ext.getCmp('MTWindow')),
        onError: WVSPopup.failure
    });
};

