/**
 * Resizes the 2-D image and element containing the 3-D plugin to the specified size
 *
 * @param {Object} resizablePanel the panel containing both the 2-D and 3-D thumbnails
 * @param {Object} new_width width to set the thumbnail to
 * @param {Object} new_height height to set the thumbnail to
 */
PTC.miniNavigator.adjustThumbnailSize = function(resizablePanel, new_width, new_height){
    if (PTC.miniNavigator.collapsed) { //don't do any calcs if the panel is collapsed
        return;
    }
    var width, height;
    var thumbnailPanel = Ext.getCmp('vis_img_panel');
    PTC.miniNavigator.setAttributePanelHeight();
    
    if (!thumbnailPanel || typeof new_width === 'undefined' || new_width < 0) {
        return;
    }
    thumbnailPanel = thumbnailPanel.body.dom;
    
    var tpEl = Ext.get(thumbnailPanel);
    var currentSize = tpEl.getSize();
    
    //resizing when the viz is minimized was causing problems where only the width was resized to fix this we need use the width and height we had before minimizing
    var width_to_use = currentSize.width;
    if (width_to_use <= 0) {
        width_to_use = PTC.miniNavigator._oldBodyWidth;
    }
    var height_to_use = currentSize.height;
    if (height_to_use <= 0) {
        height_to_use = PTC.miniNavigator._oldBodyHeight;
    }
    
    // calculate how large/small the thumbnail has been resized to, we need to adjust both the height and width by this amount to keep the aspect ratio
    var ratio = new_width / parseInt(width_to_use, 10);
    if (isNaN(ratio) || !isFinite(ratio)) {
        return;
    }
    
    // calculate the new width and height of the thumbnail
    width = Math.round(ratio * parseInt(width_to_use, 10));
    height = Math.round(ratio * parseInt(height_to_use, 10));
    
    // adjust the panel containing the 2-D and 3-D thumbnails
    tpEl.setSize(width, height);
    
    // adjust the 3-D thumbnail
    var threeD_thumbnail = PTC.miniNavigator.get3DThumbnail();
    if (threeD_thumbnail) {
        var threeDEl = Ext.get(threeD_thumbnail);
        threeDEl.setSize(width, height);
    }
    
    // adjust the 2-D thumbnail
    var twoD_thumbnail = PTC.miniNavigator.get2DThumbnail();
    if (twoD_thumbnail) {
        var twoDEl = Ext.get(twoD_thumbnail);
        twoDEl.setSize(width, height);
    }
    
    // adjust the dynamic document thumbnail
    var dynDoc_thumbnail =  PTC.miniNavigator.getDynamicDocThumbnail();
    if (dynDoc_thumbnail) {
    	dynDoc_thumbnail.setSize(width, height);
    }
};
/**
 * Override function for the vis panel collapse to keep the plugin in the dom
 * Just resizes it to be really small.
 */
PTC.miniNavigator.visPanelCollapse = function(){
    PTC.miniNavigator._oldBodyHeight = this.body.getHeight();
    PTC.miniNavigator._oldBodyWidth = this.body.getWidth();
    PTC.miniNavigator.adjustThumbnailSize(Ext.getCmp('vis'), 0);
    PTC.miniNavigator.collapsed = true; //set true after so the method does the resize to 0.0
    this.collapsed = true;
    this.header.addClass(this.collapsedCls);
    return false;
};

/**
 * Override function for the vis panel expand/collapse to keep the plugin in the dom
 */
PTC.miniNavigator.visPanelExpand = function(){
    if (typeof PTC.miniNavigator._oldBodyHeight !== 'undefined') {
        PTC.miniNavigator.collapsed = false; //set false before so the method does the resize
        this.collapsed = false;
        PTC.miniNavigator.adjustThumbnailSize(Ext.getCmp('vis'), this.container.getWidth());
        this.header.removeClass(this.collapsedCls);
    }
};


/**
 * Convenience function for determining whether the 3D plugin is present
 */
PTC.miniNavigator.is3dPluginPresent = function(){
    return (typeof(document.mtpvctl) !== "undefined");
};

/**
 * Event handler for 'contextmenu' event in 'Related Information' miniTables
 * on the miniInfo window.
 *
 * @param {Object} evt
 * @param {Object} evtTarget
 */
PTC.miniNavigator.contextMenuEventHandler = function contextMenuEventHandler(evt, evtTarget){
    if (evt !== null) {
        var relatedCmp = PTC.miniNavigator.getRelatedInfoPortalColumn();
        var panels = relatedCmp.items;
        for (var i = 0, l = panels.length; i < l; i++) {
            // There's an extra layer of 'panels' between the relatedCmp.items "panels"
            // and the MiniTables.  Look in all of them to find the MiniTable objects.
            var relatedSubPanels = panels.items;
            for (var j = 0, m = relatedSubPanels.length; j < m; j++) {
                // There's normally only one MiniTable in the subpanels,
                // but there could be more; process all that are found.
                var miniTables = relatedSubPanels[j].items.items;
                for (var k = 0, n = miniTables.length; k < n; k++) {
                    var miniTable = miniTables[k];
                    PTC.jca.clearSelectedMiniTableRowHighlight(evtTarget, miniTable);
                }
            }
        }
        evt.stopEvent(); // prevent the brower's context menu from appearing
    }
};

/**
 * add listeners to the dom directly for the context menu;
 * @param {Object} relatedCmp
 */
PTC.miniNavigator.onAfterLayout = function(relatedCmp){
    // The 'afterlayout' event is fired twice. Make sure that the handlder is invoked
    // only once by removing it from the list of handlers before (re-)adding it.
    relatedCmp.mun(relatedCmp.getEl(), 'contextmenu', PTC.miniNavigator.contextMenuEventHandler);
    relatedCmp.mon(relatedCmp.getEl(), 'contextmenu', PTC.miniNavigator.contextMenuEventHandler);
};

/**
 * @return true if the related Info panel is currently the active card.
 */
PTC.miniNavigator.isRelatedWidgetPaneOpen = function() {
    var cardManager = Ext.getCmp(PTC.miniNavigator.cardManager);
    return (cardManager.layout.activeItem.id === PTC.miniNavigator.relatedInformation);
};


/**
 * Enables or Disables the menu for the related info card based on whether the current config has
 * panels available for the related Info panel.
 * @param (RenderInfoModelData) config - info config for mini navigator
 * @param {Object} itemArr - array of related panel configs
 */
PTC.miniNavigator.resetMenuButton = function(config, itemArr){
    var menuButton = Ext.getCmp(PTC.miniNavigator.menuTitleID);

    if (itemArr === undefined || itemArr === null || itemArr.length <= 0) {
    	menuButton.hide();
    	//and make sure to be on the other panel, and set title for it user will have to switch back in this fairly rare case
    	var target = {};
    	target.text = menuButton.defaultText;
    	PTC.miniNavigator.showNavPane(null, target);
    }
    else if (config.data.showRelatedInfo && config.data.showNavigateThumbnails) {
    	menuButton.enable();
    	menuButton.show();  // in case it was hidden
    }
    else  {
    	menuButton.disable();
    	if (config.data.showNavigateThumbnails) {
    		//first item in the list is navigate structure
    		menuButton.setText(menuButton.menu.items.items[0].text);
    	} else {
    		//second item in the list is related items.
    		menuButton.setText(menuButton.menu.items.items[1].text);			 
    	}
    	menuButton.show();  // in case it was hidden
    }

    
};

/**
 * Lazy load the related info panel widgets
 */
PTC.miniNavigator._loadRelatedWidgets = function(actionItems){
    function param(key, value) {
        return '&' + key + '=' + value;
    }
    var endIndex = PTC.debug.isJCADebug() ? actionItems.length - 1 : actionItems.length;
    for (var i = 0; i < endIndex; i++) {
        var item = actionItems[i];
        // actionURL should already contain an oid param, so should be safe to just append itemIndex
        var requestURL = item.actionURL + param("itemIndex", i) + param("actionName", item.actionName);
        requestURL += param("actionType", item.actionType) + param("collapse", item.collapse);
        var options = {
            method: 'get',
            asynchronous: true,
            onSuccess: PTC.miniNavigator.renderRelatedInfoPanels
        };
        PTC.miniNavigator.doRequest(requestURL, options);
    }
};

/**
 * load the related info panel widgets
 */
PTC.miniNavigator.loadRelatedWidgets = function(){
    var relatedCmp = PTC.miniNavigator.getRelatedInfoPortalColumn();
    if (relatedCmp.needsLoad === true) {
        relatedCmp.needsLoad = false;
        relatedCmp.on('add', PTC.miniNavigator.sortPortals); // sort panels as they are added
        PTC.miniNavigator._loadRelatedWidgets(relatedCmp.actionItems);
    }
};

/**
 * This function makes request for each related info panels.
 */
PTC.miniNavigator.getRelatedInfoPanels = function(config, relatedInfoItems){
    var relatedCmp = PTC.miniNavigator.getRelatedInfoPortalColumn();
    relatedCmp.removeAll(true); //clean the list out and then get new
    relatedCmp.needsLoad = true;
    relatedCmp.actionItems = relatedInfoItems;
    //PTC.miniNavigator.resetMenuButton(config, relatedInfoItems);
    
    // Only load the widgets if the panel is active
    if (PTC.miniNavigator.isRelatedWidgetPaneOpen()) {
        PTC.miniNavigator.loadRelatedWidgets();
    }
    
    relatedCmp.on('afterlayout', PTC.miniNavigator.onAfterLayout);
};

/**
 * Success handler for related info panel request.
 * As we get the response for each panel we lay them out.
 */
PTC.miniNavigator.renderRelatedInfoPanels = function(response){
    PTC.miniNavigator.log.debug("Processing response for related info url: ", response.request.url);
    var configAndData = Ext.decode(response.responseText.trim());
    var config = configAndData.config;
    config.totalRows = configAndData.data.length;
    config.initialRows = configAndData.data;
    
    PTC.miniNavigator.createRelatedInfoPanels (configAndData.config);
    
    var relatedCmp = PTC.miniNavigator.getRelatedInfoPortalColumn();
    if (relatedCmp) {
        relatedCmp.doLayout();
    }
};

/**
 * Get the html for a mini table title bar. Used by tables like: Where Used, Uses, Attachments, Changes, etc.
 * @param {String} tableName
 * @param {String} count
 * @return {String} html representing the title bar for the mini table
 */
PTC.miniNavigator.getMiniTableTitleBar = function(tableName, count){
    return "<div class='miniTableCount'>" + count + "</div>" +
    "<div class='miniTableTitle' ext:qtip='" +
    tableName +
    "'>" +
    tableName +
    "</div>";
};

/**
 * get collapsed state off mini nav table config
 * @param {Object} jcaTableConfig
 */
PTC.miniNavigator.isMiniTableCollapsed = function(jcaTableConfig) {
	var isCollapsed = jcaTableConfig.collapse;
    if (isCollapsed === undefined) {
        isCollapsed = (jcaTableConfig.totalRows === undefined) || (jcaTableConfig.totalRows === 0);
    }
	return isCollapsed;
};

/**
 * This function creates the mini-table for related info panel
 * and adds them to Related object panel.
 * BUT does not lay them out yet.
 * @param {Object} jcaTableConfig
 */
PTC.miniNavigator.createRelatedInfoPanels = function(jcaTableConfig){
    var relatedPanel = PTC.miniNavigator.getRelatedInfoPortalColumn();
    var jcaDebugInfo = PTC.debug.getJCADebugHTML(jcaTableConfig);
    var miniTableName = jcaTableConfig.tableName;
    var miniTableCount = PTC.jca.miniTableCountMsg(jcaTableConfig.totalRows) + jcaDebugInfo;
	// logic here instead of on server since this is the first time we know how many rows the mini table has
	var isCollapsed = PTC.miniNavigator.isMiniTableCollapsed(jcaTableConfig);
    
    var relatedSubPanelConfig = {
        xtype: 'miniNavPortlet',
        id: 'relatedObjs' + jcaTableConfig.tableID,
        title: PTC.miniNavigator.getMiniTableTitleBar(miniTableName, miniTableCount),
        itemIndex: jcaTableConfig.itemIndex, // pass the tabset index
        actionName: jcaTableConfig.actionName,
        actionType: jcaTableConfig.actionType,
        collapsed: isCollapsed,
        items: [jcaTableConfig]
    };
    
    PTC.miniNavigator.log.trace("inserting minitable " + jcaTableConfig.tableID);
    relatedPanel.add(relatedSubPanelConfig);
};

/**
 * Show the actions menu for the object in the mini nav 
 * @param {Object} target event target
 * @param {Event} event the event
 */
PTC.miniNavigator.showMenu = function(target, event){
    var params ={
        context : 'object$miniNavigator$'+WVSPopup.oid+'$'+WVSPopup.oid+'!*',  // To get elemAddress defined, fixes selectRequired actions
        oid : WVSPopup.oid,
        tableID: 'MTWindow', //To handle the dynamic refreshes
        actionName : 'actionsMenu' // certain action delegates such as MoveURLActionDelegate expect this parameter
    };
    PTC.menu.showActionsMenu(event, params);
};
/**
 * Action refresh handler for the Mini Nav window
 * @param {PTC.action.FormResult} formResult
 */
PTC.miniNavigator.onAfterAction = function(formResult) {
    var result = false;
    if (formResult && formResult.U && formResult.U[WVSPopup.oid]) {
        //If the current oid has been updated to a new oid, then load the new oid (WIP actions)
        WVSPopup.show(formResult.U[WVSPopup.oid][0], -1, -1, true, false, false);
    }
    else if (formResult && formResult.Del && formResult.Del[WVSPopup.oid]) {
        //If the current object has been deleted, then close the mini nav
        WVSPopup.hide();
    }
    else {
        //Everything else should refresh, Errors will cause the miniNav to refresh in case the object is stale.
        //There might need to be some extra messaging in some cases here but no use cases found yet
        MTrefresh();
        if ((formResult.js && formResult.js.length>1) || (formResult.URL && formResult.URL.length>1) ) {
            //Return true for cases where a url or js attribute have been returned
            result = true;
        }
    }
    //The mini nav is a high level component, there are no components above that need to be refreshed
    // Stop the default handler unless there is JS or a URL to handle.    
    return result;
};
