/**
 * Uses the given URL to request some new HTML to display as third level nav content,
 * then replaces the innerHTML of the third level nav div with the new HTML
 * theURL - (required) the URL to use
 **/
function switchTLNContent(theURL, doAsynch){
    if (theURL.indexOf("http") < 0 && theURL.indexOf("/") !== 0) {
        theURL = "/" + theURL;
    }
    var type = extractParamValue(theURL, "tlnType");
    var action = extractParamValue(theURL, "tlnAction");
    var id = "tlnContentArea_" + type + action;

    var actionConfig = {
        id: id,
        actionURL: theURL,
        text: action
    };
    var title = actionConfig.text;
    PTC.infoPage.addThirdLevelNavTab(actionConfig);
    return false;
}

function getUpdateOpenerWindow(){
    try {
        if (opener) {
            return opener.top.window;
        }
        else {
            return top.window;
        }
    }
    catch (e) {
        return top.window;
    }
}

function isResultOfPost(){
    // this checks whether the document came from a post request
    var mform = this.getMainForm();
    return (mform.nmwindowname.value !== "none");
}

function onResizeWindow(){
    // gpurohit: Adjust the height of wizard content area, so that the navigation buttons are always visible.
    // if poppedup window is a wizard call adjustWizardContentAreaHeight() to adjust both contentarea and table height.
    if (isWizardType) {
        adjustWizardContentAreaHeight();
    }
    //else if it is a simple pop-up just update table height of all the tables on the popup window.
    else if( window.location.href.indexOf("portlet=poppedup") >= 0){
        PTC.jca.table.Utils.adjustTableHeight();
    }
}

// IE fires the window resize event too much... stack those calls up so we don't needlessly execute this code several times
onResizeWindow = PTC.util.delayAllCalls(onResizeWindow, 50);

function resizeWindow(bigger){
    var deltaWidth = 100;
    var deltaHeight = 100;

    if (!bigger) {
        deltaWidth *= -1;
        deltaHeight *= -1;
    }
    window.resizeBy(deltaWidth, deltaHeight);
}

//tries to find the selected folder; pops up an alert window if:
//     A. more than one checkbox is selected
//     B. one checkbox is selected, but that object is not a folder
// returns null for A. or B.
// return "nothing selected" if there are no checkboxes selected
function getSelectedContext(){
    var oidString = "nothing selected";

    var sels = getSelectedItems();
    if (sels) {
        var alength = sels.length;
        if (alength > 1) {
            JCAAlert("com.ptc.netmarkets.util.utilResource.TOO_MANY_SELECTED");
            return false;
        }
        else
            if (sels.length == 1) {
                oidString = sels[0].value;
            }
    }

    if (oidString !== "nothing selected" && ! PTC.util.isAFolder(oidString)) {
        JCAAlert("com.ptc.netmarkets.util.utilResource.NO_FOLDER_SELECTED");
        return null;
    }
    return oidString;
}

function getPopupOpenerWindow() {
    if (PTC.lightbox.isLightbox(window)) {
        return window.parent;
    } else {
        // SPR Task: 6414931 The "Checkin and Promote" option window hangs when
        // checking in and promoting a CadDoc from SolidWorks Workgroup Manager
        // In Firefox and Chrome, window.opener becomes null
        // once the user exits or refreshes window. In IE, however,
        // window.opener is not null, and window.opener.foo gives "Permission
        // Denied" instead of null.
        try {
            if (window.opener && window.opener.PTC) {
                return window.opener;
            }
        } catch (e) {
        }
        return null;
    }
}

function switchTab(tab){
    if (callUserSubmitFunction()) {
        // TODO this assumes that there are other parameters which is the case for dialogs.
        clearActionFormData();

        clearDialogFormData();
        var formAction = PTC.util.getFormAction(getMainForm());
        formAction += ("&" + "com.ptc.netmarket.tab=" + tab);
        PTC.util.setFormAction(getMainForm(), formAction);
        PTC.navigation.submitForm();
    }
}

