function setSelectedOption(selectedElementVal, elementId){
    var select = document.getElementById(elementId);
    var select_options_length = select.options.length;
    for (var i = 0; i < select_options_length; i++) {
        if (select.options[i].value == selectedElementVal) {
            select.options[i].selected = true;
        }
        else {
            select.options[i].selected = false;
        }
    }
}

/**
 * size the iframe to fit its content exactly and get rid of the scrollbars
 * added buffer_size parm for CAD detail page rendering - calls to old
 * signature will work as is, anyone that needs less/more height can pass
 * in an appropriate value
 * added check_viz parm for CAD detail page rendering - calls to old
 * signature will work as is, anyone that needs the attributes panel
 * visibility toggled to properly get the height attribute should pass a
 * true
 */
function sizeToContent(frame, buffer_size, check_viz){

    var flipViz = false;
    var xbody = frame.contentWindow.document.body;
    //SPR 1967533 - script error on CSIP/WSIP of Cad doc.
    if(!xbody){
       return;
    }

    if (check_viz === true) {
        if (!$("attributesPanelWrapper").visible()) {
            flipViz = true;
        }
    }

    if (flipViz) { //make attributes panel visible so we can get a height
        $("attributesPanelWrapper").toggle();
    }

    var height = (xbody.offsetHeight > xbody.scrollHeight) ? xbody.offsetHeight : xbody.scrollHeight;
    var width = (xbody.offsetWidth > xbody.scrollWidth) ? xbody.offsetWidth : xbody.scrollWidth;

    if (flipViz) { //rehide the attributes panel
        $("attributesPanelWrapper").toggle();
    }

    var delta = 0;
    if (!frame.deltaAdded) {
        frame.deltaAdded = true;
        delta = (typeof buffer_size === "number") ? buffer_size : 50; // buffer to avoid scrollbars
    }
    else
        if (frame.height != height) {
            //need this to avoid scrollbars after "Expand All" is done for PSB and Actions menu is clicked
            delta = 50;
        }

    frame.height = height + delta;
    frame.width = width + delta;
    frame.scrolling = "auto";
}

function originalBackgroundSBRow(elems, originalBackground){
    try {
        if (elems !== null) {
            var elems_length = elems.length;
            for (var i = 0; i < elems_length; i++) {
                originalBackground.push(elems[i].style.backgroundColor);
            }
        }
    }
    catch (e) {
    }
}

function highlightSBRow(elems, color){
    try {
        if (elems !== null) {
            var elems_length = elems.length;
            for (var i = 0; i < elems_length; i++) {
                elems[i].style.backgroundColor = color;
            }
        }
    }
    catch (e) {
    }
}

function restoreBackgroundSBRow(elems, originalBackground){
    try {
        if (elems !== null) {
            var elems_length = elems.length;
            for (var i = 0; i < elems_length; i++) {
                elems[i].style.backgroundColor = originalBackground[i];
            }

        }
    }
    catch (e) {
    }
}

/** This function scrolls a given Structure Browser row into view area of browser after
 * performing row level actions in Structure Browser.
 */
function sizeAndScrollSBIntoView(frame, rowToScrollTo, formName){

    var noHighlight = false;
    var form = frame.contentWindow.document.forms[formName];

    //If the 'rowToScrollTo' parameter is null, look for the hidden input field with that name,
    //on the form with the 'formName' parameter
    if (rowToScrollTo === null) {
        if (form !== undefined) {
            rowToScrollTo = form.rowToScrollto.value;
        }
    }

    //If row highlight is not desired, send a pipe separated value for the 'rowToScrollTo' parameter, something like <rowToScrollTo>|NoHighlight
    //(Assuming that row id does not have a '|' in it already)
    if (rowToScrollTo !== null && rowToScrollTo !== undefined) {
        var index = rowToScrollTo.indexOf('|');
        if (index >= 0) {
            rowToScrollTo = rowToScrollTo.substring(0, index);
            noHighlight = true;
        }
    }

    sizeToContent(frame);
    // code to scroll the action row into focus
    var elem = frame.contentWindow.document.getElementById(rowToScrollTo);
    if ((rowToScrollTo !== "") && (elem !== null)) {
        var parentElem = elem.parentNode;
        var parent = parentElem.parentNode;
        parentElem.scrollIntoView();
        parentElem.focus();
        if (parent !== null && !noHighlight) {
            var elems = parent.getElementsByTagName("*");
            var originalBackground = [];
            originalBackgroundSBRow(elems, originalBackground);
            var color = '#FFFF99';
            highlightSBRow(elems, color);
            var highlightFn = function(){
                restoreBackgroundSBRow(elems, originalBackground);
            };
            setTimeout(highlightFn, 2000);
        }
    }
}

function setLocation(){
    var mform = this.getMainForm();
    if (mform && mform.xposition !== undefined) {
        var xpos = PTC.browser.getX();
        var ypos = PTC.browser.getY();
        if (xpos > 0 && ypos > 0) {
            mform.xposition.value = xpos;
            mform.yposition.value = ypos;
        }
    }
}
/**
 * @namespace
 */
PTC.help = {};

/**
 * Opens the help window.
 */
PTC.help.openHelpWindow = function(helpUrl) {
    var helpWindow = window.open(helpUrl, 'HelpWindow',
        'toolbar=yes,location=yes,directories=yes,status=yes,menubar=yes,scrollbars=yes,resizable=yes');
    helpWindow.focus();
};

/**
 * Takes just a selector and builds a help JSON model complete with url info
 * uses getHelpButtonConfig, If you have a help model use PTC.help.getHelpButtonConfig
 * @param {String} the help topic such as 'ChartAbout'. This API will construct Windchill Help Center url for topic 'ChartAbout'.
 */
PTC.help.createHelpButtonConfigForSelector = function(selector){
    var helpModel = {selector: selector};
    var baseurl = PTC.properties.getWTProperty("wt.whc.url");
    helpModel.url = baseurl + "/index.html?id=" + selector;
    return PTC.help.getHelpButtonConfig(helpModel);
};


/**
 * Augments the help JSON model with Ext rendering properties. If you don't have a help model see PTC.help.createHelpButtonConfigForSelector
 * @param {Object} a help Model generally one returned by JCA that contains the url and selector
 */
PTC.help.getHelpButtonConfig = function(helpModel) {

    // Check for any overrides.
    PTC.help.getCustomHelpCenterURL(helpModel);

    if (helpModel.url) {
        Ext.applyIf(helpModel, {
            iconCls: 'helpButton',
            handler: function() {
                PTC.help.openHelpWindow(helpModel.url);
            },
            xtype: 'button',
            cls: 'help'
        });
        return helpModel;
    } else {
        return null;
    }
};

/**
 * Allows applications to override the default help center url in some locations. Currently this functionality is
 * desired in Flex and Service Center, in the future there may be more. The url can be overridden by providing
 * 'helpCenter=<wtproperty>' on the url and by providing the url in the specified wtproperty (for example
 * helpUrlProp=wt.whc.schc)
 *
 * SIDE EFFECT: This method will change the helpModel and update helpModel.url if an ovveride property is found.
 *
 * This property value is cached in the attributeHelper cache so we don't have to request it over and over.
 *
 * This method can be overridden to customize help urls in other ways. The url set on the helpModel should be the
 * complete help center url including the base href retrieved from the property and the specific topic information
 * retrieved from the helpModel.
 */
PTC.help.getCustomHelpCenterURL = function(helpModel){
    //null check for helpModel.selector, for more details please check the test "test_getCustomHelpCenterURL_whenSelector_is_null()"
    if (helpModel.selector) {
        var wtproperty;
        try {
            var currentWindow = getWindow();
            // try to find the helpCenter param on current window first
            // then loop across opener windows till either param is found or we run out of openers
            while (!wtproperty && currentWindow) {
                wtproperty = extractParamValue(currentWindow.location.href, "helpCenter");
                
                //In Firefox when a hyperlink is clicked in the window opened by window.open, 
                //window.opener is equal to window. This is to prevent infinite loop in this situation.
                if(currentWindow === currentWindow.opener) {
                    break;
                }
                currentWindow = currentWindow.opener;
            }
        }
        catch (e) {
            // catch any error that might occur from trying o access location.href of opener windows
            PTC.log.debug("Error trying to find helpCenter param, so just assume its undefined.", e);
        }
        var url = null;
        if (wtproperty) {
            url = PTC.properties.getWTProperty(wtproperty);
            if (url) {
                helpModel.url = url + '/index.html?id=' + helpModel.selector;
            }
        }
    }
};

/**
 * Render standalone help button.
 */
PTC.help.helpButton = function(helpModel) {
    var helpButton = PTC.help.getHelpButtonConfig(helpModel);
    if (helpButton) {
        var helpPanel = new Ext.Panel({
            renderTo: 'help_viewport',
            header: false,
            border: false,
            items: [helpButton]
        });
    }
};

