/**
 * @namespace
 * A name space for methods related to accessing WTProperties
 */
PTC.properties = {};

/**
 * access the cache of WTProperties values in the attribute helper cache (someday these could be moved if there get to be too many or is another good reason)
 * If the property desired isn't cached use the WTProperties controller to get it and cache it.
 * @param {String} property a property to get from wt.properties. For example "wt.fhc.url". 
 * @return {String} property value from wt.properties. 
 */
PTC.properties.getWTProperty = function(property) {
    var propertyVal = PTC.attributeHelper.get("WTProperties." + property); // Check the cache.

    if (propertyVal === undefined) {
        var propsurl = "ptc1/WTProperties/";
        var options = {
            method: 'get',
            asynchronous: false,
            parameters: '?property=' + property,
            onSuccess: function(response) {
                propertyVal = response.responseText;
                PTC.properties.setWTProperty(property, propertyVal); // cache the result
            }
        };
        var request = requestHandler.doRequest(propsurl, options);
    }
    return propertyVal;
};

/**
 * Caches a WTProperties value so properties could be initialized by jsps to avoid uneeded ajax calls later.
 * @param {String} property from wt.properties. For example "wt.fhc.url"
 * @param {String} propertyVal value from wt.properties. For example 'http://foo/baz'
 */
PTC.properties.setWTProperty = function(property, propertyVal) {
    PTC.attributeHelper.set("WTProperties." + property, propertyVal); 
};

/**
 * @namespace
 */
PTC.event = {};

/**
 * Fires the given event on the given HTML element.
 *
 * @param {HTMLElement} element - The HTML element that's going to fire the event
 * @param {String} eventName - the event name without the "on" (i.e. "change" to have the "onchange" event fired)
 */
PTC.event.fireEvent = function(element, eventName) {
    var evt;
    if (document.createEvent && element.dispatchEvent) {
        // dispatch for W3C compliant: firefox, IE11, + others
        evt = document.createEvent("HTMLEvents");
        evt.initEvent(eventName, true/*bubbles*/, true/*cancelable*/);
        return !element.dispatchEvent(evt);
    } else if (document.createEventObject && element.fireEvent){
        // dispatch for IE 8 mode
        evt = document.createEventObject();
        return element.fireEvent('on'+eventName, evt);
    } else {
        PTC.log.warn("cannot fire event: " + eventName);
    }
};

if (!('handleSuccesfullTaskRetry' in window)) {
    /**
     * Event console wants to call this method when it retries.  Just need this global function
     * Just in case a page already defined one, check if it does not exist
     */
    handleSuccesfullTaskRetry = function(taskId){
        //enhanced to call synchronizeWS when server is registered
        if (isWf()) {
            var url = getBaseHref() + "ptc1/dataops/taskState?taskId=" + encodeURIComponent(taskId);
            var options = {
                method: 'get',
                asynchronous: true,
                onSuccess: function(transport){
                    if (transport.status == 200 || transport.status === 0) {
                        var responseDoc = transport.responseText.trim();
                        var dataObj = Ext.util.JSON.decode(responseDoc);
                        if (dataObj && dataObj.isServerRegistered && dataObj.taskType && dataObj.taskType === "wt.dataops.delete.DeleteTask") {
                            //this is a delete task and server is registered
                            if (!('synchronizeWS' in window)) {
                                PTC.navigation.loadScript('templates/uwgm/cadx/ws/wsTable.js');
                            }
                            synchronizeWS();
                        }
                    }
                }
            };
            requestHandler.doRequest(url, options);
        }
      PTC.navigation.reload();
    };
}

/**
 * Fix SPR 2164373 by preventing the browser from navigating back to the previous page when
 * the user presses the backspace key outside of an input element.
 * This default behavior causes issues with lightboxes, etc. so now we "eat" the event if it
 * occurs on a non-input element.  This allows text editing in forms, but prevents navigation.
 * Note: The checks for A, TD, and BUTTON elements could be removed, but then the
 * backspace can still cause the browser to navigate back when cursor is not visible.
 */
PTC.event.preventBackspaceKeyFromNavigatingBack = function (event) {
    var e = window.event || event;  // IE uses window.event
    // check if the key was the backspace key (code 8 = backspace char)
    if (e.keyCode === 8 || (e.keyCodeVal && e.keyCodeVal === 8)) {
        // get the target element
        var d = e.srcElement || e.target;
        // if the event happened on a non-input-related tag, then we will "eat" the event
        if ((d.tagName.toUpperCase() == 'HTML') ||   // for "no focus"
            (d.tagName.toUpperCase() == 'BODY') ||   // for main window
            (d.tagName.toUpperCase() == 'DIV')  ||   // for lightboxes
            (d.tagName.toUpperCase() == 'A')    ||   // for menus & comboboxes
            (d.tagName.toUpperCase() == 'TD')   ||   // for table cells
            (d.tagName.toUpperCase() == 'BUTTON') || // for wizard buttons
            (d.tagName.toUpperCase() == 'INPUT' && d.readOnly)) { // for readonly input fields

           // eat this event (prevent browser from doing default behavior)
           if (e.preventDefault) {
                e.preventDefault();
           }
           // IE does not support preventDefault()
           e.returnValue = false;
        }
    }
};
document.onkeydown = PTC.event.preventBackspaceKeyFromNavigatingBack;

