/**
 * PTC.infoPage.myTab.MyTabTOCPanel extends Ext.Panel
 * @property {Object} links - map of item ids to links
 */
Ext.extend(PTC.infoPage.myTab.MyTabTOCPanel, Ext.Panel, {
    links: {},
    /**
     * Add a link to the table of contents.
     * @name PTC.infoPage.myTab.MyTabTOCPanel.addLink
     * @param {Object} linkConfig - link configuration
     * @param {String} [id] The id of the panel to add a TOC link to; defaults to "My Tab"'s id
     */
    addLink: function(linkConfig, id) {
        var linkId = linkConfig.id + '_tocItem';

        var newTOCLink = new Ext.Panel({
            id: linkId,
            cls: 'myTab-link dragDrop-draggable',
            border: false,
            listeners: {
                render: function() {
                    this.mon(this.getEl(), 'click', function() {
                        PTC.infoPage.myTab.getMyTab(id).getTableContainer().scrollTo(linkConfig.id);
                    });
                }
            },
            html: linkConfig.text
        });
        // register an event handler to create drop zone and proxy
        var linkPanel = this.getLinkPanel();
        //OOTB tabs TOC links should not be draggable
        // if the tab is editable allow drag and drop of TOC links
        var tab = this.getTabContentPanel();
        if (tab.editable) {
            linkPanel.on('afterLayout', function(){
                PTC.dd.createDropZone({
                    id: linkId,
                    sGroup: PTC.infoPage.myTab.MyTabPanel.ddLinkGroup
                });
                PTC.dd.createDDProxy({
                    id: linkId,
                    sGroup: PTC.infoPage.myTab.MyTabPanel.ddLinkGroup
                }, PTC.infoPage.myTab.DDLinkProxy);
            }, this, {
                single: true
            });
        }
        // set itemId and divider on the link
        newTOCLink.itemId = linkConfig.id;
        // insert divider and link into the link panel
        linkPanel.insert(0, newTOCLink);
        this.links[linkConfig.id] = newTOCLink.id;
    },
    /**
     * Remove a link from the table of contents.
     * @name PTC.infoPage.myTab.MyTabTOCPanel.removeLink
     * @param {String} itemId - item id
     */
    removeLink: function(itemId) {
        var linkPanel = this.getLinkPanel();
        var link = Ext.getCmp(this.links[itemId]);
        if(linkPanel && link) {
            linkPanel.remove(link);
            delete this.links[itemId];
        }
    },
    /**
     * Inserts the one link before another.
     * @name PTC.infoPage.myTab.MyTabTOCPanel.insertLinkBefore
     * @param {String} movedItemId - the item id of the item being moved
     * @param {String} targetItemId - the item id of the item to place the moved item above
     */
    insertLinkBefore: function(movedItemId, targetItemId) {
        var movedLink = Ext.get(this.links[movedItemId]);
        var targetLink = Ext.get(this.links[targetItemId]);
        movedLink.insertBefore(targetLink);
    },
    /**
     * Inserts the one link after another.
     * @name PTC.infoPage.myTab.MyTabTOCPanel.insertLinkAfter
     * @param {String} movedItemId - the item id of the item being moved
     * @param {String} targetItemId - the item id of the item to place the moved item after
     */
    insertLinkAfter: function(movedItemId, targetItemId) {
        var movedLink = Ext.get(this.links[movedItemId]);
        var targetLink = Ext.get(this.links[targetItemId]);
        movedLink.insertAfter(targetLink);
    },
    /**
     * Get the panel that contains the links.
     * @name PTC.infoPage.myTab.MyTabTOCPanel.getLinkPanel
     * @returns {PTC.infoPage.myTab.MyTabTOCPanel} the link panel
     */
    getLinkPanel: function() {
        return this.items.items[0];
    },
    /**
     * Returns the top level panel that contains the tab items (contents)
     *
     * @private
     * @returns {PTC.infoPage.myTab.MyTabPanel}
     */
    getTabContentPanel: function() {
        return this.findParentByType(PTC.infoPage.myTab.MyTabPanel);
    }
});
Ext.ComponentMgr.registerType("tocPanel", PTC.infoPage.myTab.MyTabTOCPanel);
/**
 * Common endDrag Ext.dd.DDProxy implementation.  Moves items in MyTab panel.
 */
PTC.infoPage.myTab.endDrag = function() {
    if (this.lastTarget) {
        var el = Ext.get(this.getEl());
        var movedItem = Ext.getCmp(el.id);
        var movedItemId = movedItem.itemId;
        // Use the movedItem to find the containg Panel.  Go find the TabPanel, then get the active tab
        var activeMyTab = movedItem.findParentByType(PTC.infoPage.myTab.MyTabPanel);
        var targetId = Ext.getCmp(this.lastTarget.id).itemId;
        if (this.insertAfter) { // if we are dragging down, insert it below
            activeMyTab.insertItemAfter(movedItemId, targetId);
        } else {                // if we are dragging up, insert it above
            activeMyTab.insertItemBefore(movedItemId, targetId);
        }
    }
};
/**
 * The drag and drop table proxy.  Defines event handlers for drag and drop events.
 * @param {String} id - id of the draggable panel.  May contain multiple tables.
 * @param {String} sGroup - the drag and drop group
 * @param {Object} config - additional proxy config
 * @class
 */
PTC.infoPage.myTab.DDTableProxy = function(id, sGroup, config) {
    //TODO: need to remove remaining drag and drop table functionality. For now, all the tables are still being created
    //      with drop zones, but the dragging is currently disabled by commenting out the line below.
    //PTC.infoPage.myTab.DDTableProxy.superclass.constructor.call(this, id, sGroup, config, PTC.dd.DDProxy.isDragDown);
};
/**
 * PTC.infoPage.myTab.DDTableProxy extends Ext.dd.DDProxy
 */
Ext.extend(PTC.infoPage.myTab.DDTableProxy, PTC.dd.DDProxy, {
    /**
     * When resetting the styles, reset the before and after divider styles.
     * @name PTC.infoPage.myTab.DDTableProxy.reset
     */
    reset: function() {
        if (this.lastTarget) {
            this.lastTarget.removeClass('myTab-table-after');
            this.lastTarget.removeClass('myTab-table-before');
        }
        PTC.infoPage.myTab.DDTableProxy.superclass.reset.call(this);
    },
    /**
     * When dragging over a drop zone, style the table with the appropriate before or after divider style.
     * @name PTC.infoPage.myTab.DDTableProxy.onDragOver
     */
    onDragOver: function(e, targetId) {
        PTC.infoPage.myTab.DDTableProxy.superclass.onDragOver.apply(this, arguments);
        if (targetId !== this.getEl().id) {
            var target = Ext.get(targetId);
            var dividerClass = (this.insertAfter) ? 'myTab-table-after' : 'myTab-table-before';
            target.addClass(dividerClass);
        }
    },
    /**
     * Uses the common drop function.
     * @name PTC.infoPage.myTab.DDTableProxy.endDrag
     */
    endDrag: function() {
        PTC.infoPage.myTab.endDrag.apply(this, arguments);
        PTC.infoPage.myTab.DDTableProxy.superclass.endDrag.apply(this, arguments);
    }
});
/**
 * The drag and drop link proxy.  Defines event handlers for drag and drop events on the TOC links.
 * @param {String} id - id of the draggable panel.  May contain multiple tables.
 * @param {String} sGroup - the drag and drop group
 * @param {Object} config - additional proxy config
 * @class
 */
PTC.infoPage.myTab.DDLinkProxy = function(id, sGroup, config) {
    PTC.infoPage.myTab.DDLinkProxy.superclass.constructor.call(this, id, sGroup, config, PTC.dd.DDProxy.isDragRight);
};
/**
 * PTC.infoPage.myTab.DDLinkProxy extends Ext.dd.DDProxy
 */
Ext.extend(PTC.infoPage.myTab.DDLinkProxy, PTC.dd.DDProxy, {
    reset: function() {
       if (this.lastDivider) {
            this.lastDivider.removeClass('myTab-link-divider-over');
        }
        PTC.infoPage.myTab.DDLinkProxy.superclass.reset.call(this);
    },
    onDragOver: function(e, targetId) {
        PTC.infoPage.myTab.DDLinkProxy.superclass.onDragOver.apply(this, arguments);
        var target = Ext.get(targetId);
        var divider = (this.insertAfter) ? target.next() : target;
        divider.addClass('myTab-link-divider-over');
        this.lastDivider = divider;
    },
    /**
     * Uses the common drop function.
     * PTC.infoPage.myTab.DDLinkProxy.endDrag
     */
    endDrag: function() {
        PTC.infoPage.myTab.endDrag.apply(this, arguments);
        PTC.infoPage.myTab.DDLinkProxy.superclass.endDrag.apply(this, arguments);
    }
});
/**
 * Adds a tab to the given tab panel which is expected to be the top tab panel of the info page.
 * Assumes that the info page is already rendered and the tab needs to be inserted into the tab panel.
 *
 * @param {Ext.TabPanel} tabPanel - the tab panel to add a 'New Tab' tab to
 */
PTC.infoPage.myTab.addNewTab = function(tabPanel){
    if (tabPanel) {
        // add the tab to the tabPanel and persist it to the database
        PTC.infoPage.getTabManager(tabPanel).add(PTC.infoPage.myTab.addCallback);
    }
};
/**
 * Callback for add tab function. Makes tab drag and dropable.
 * Extracted for testing purposes
 * @param {Object} newTab tab to add
 * @param {Object} tabPanel tab container
 */
PTC.infoPage.myTab.addCallback = function(newTab, tabPanel){
    //make tab drag 'n' drop
    var dp = new Ext.ux.DockPanel({
        dockonly: true,
        constrainHeader: true
    });
    newTab.dockContainer = tabPanel.id;
    newTab.plugins = [dp];
    dp.init(newTab);
    //Set ability so that when it is clicked it is set as selected.
    newTab.on('activate', function (newTab) {
        PTC.infoPage.getTabManager(newTab.getOwner()).getActiveTab().setActiveTab(newTab);
    });
    //Since it just got created it has active state.  Set it now.
    PTC.infoPage.getTabManager(newTab.getOwner()).getActiveTab().setActiveTab(newTab);
};
/**
 * @param {Ext.TabPanel} tabPanel - an info page tab panel that has a "My Tab" tab
 * @return the original myTabConfig that was used to create "My Tab"
 */
PTC.infoPage.myTab.getMyTabConfig = function(tabPanel) {
    return tabPanel.initialConfig.myTabConfig;
};
/**
 * Returns a config used to create a new tab when a user uses the plus tab action. NOT used when rendering tabs from the
 * server initially.
 * @private
 * @param {Ext.TabPanel} tabPanel the top tab panel of an info page
 * @param {String} oid oid of this new tab from the server (eg. "com.ptc.core.ui.tab.ClientTab:98071")
 * @return {Object} a config object with unique name and id to use for creating another "New Tab" panel
 */
PTC.infoPage.myTab.getNewTabConfig = function(tabPanel, json){
    var defaultConfig = PTC.infoPage.myTab.getMyTabConfig(tabPanel);
    var title = getUnescapedText(PTC.infoPage.myTab.getUniqueTabName(tabPanel));
    var objOid = json.oid.split(":");
    var modelName = 'tab';
    var modelType = PTC.trail.GENERATED_ID + objOid[2];
    var actionID = modelName + '_' + modelType;
    var config = Ext.applyIf({
        //The tabPanelConfig id needs to stay in sync with the actionID set on the model in AbstractTabDelegate.buildActionModelForTab
        id: PTC.infoPage.TabUtils.getTabIdPrefix(tabPanel.infoModel) + '_' + actionID,
        actionID: actionID,
        oid: json.oid,
        title: title,
        otitle:title,
        closable: true,
        editable: true,
        tabCls: PTC.infoPage.myTab.getTabCls(PTC.infoPage.myTab.getTabState({admin:null, isPublic:json.isPublic, editable:true})),
        closeAction: 'close' // DragDrop tabs copies closeAction config to wrapper window.  Leaving it undefined causes an error
    }, defaultConfig);
    return config;
};
/**
 * Returns a unique tab name based on what is already in the tab panel
 * @param {Object} tabPanel panel to loop over to find what is already there
 */
PTC.infoPage.myTab.getUniqueTabName = function(tabPanel) {
    var titles = [];
    tabPanel.items.each(function(item){
        titles[titles.length] = item.title;
    });
    return bundleHandler.getUniqueName("com.ptc.core.ui.navigationRB.INFO_PAGE_NEW_TAB", titles);
};
/**
 * Action ID for the "plus" tab on the info page
 */
PTC.infoPage.myTab.addNewTabActionID = "new_tab_action";
/**
 * Adding the new tab panel action to the TabPanel.
 * <br/><br/>
 * Each time the 'New Tab' action is clicked a clone of the original 'My Tab' config is made.
 * Only the id and title are changed to be unique.
 * Then a panel created with that config is inserted into the tab panel to the left of the '+'.
 * <br/><br/>
 * The original 'My Tab' config is available on the tab panel (e.g. tabPanel.initialConfig.myTabConfig).
 * Its available because when the 'My Tab' panel is created the config is put on the infoModel.
 * Then, the info page code copies the "My Tab" config object onto the tab panel config when initializing the tab panel.
 * <br/><br/>
 *
 * @see PTC.infoPage.myTab.addNewTab
 * @param {String} id - the id of the tab panel to add the 'New Tab' action to
 */
PTC.infoPage.myTab.addNewTabAction = function(id) {
    //For some reason I can not add this as a config because the tab will
    //not show up correctly but by getCmp then it will work properly.
    var tabPanel = Ext.getCmp(id);
    if (!tabPanel) {
        return;
    }
    var newTab = {
        id : PTC.infoPage.myTab.addNewTabActionID,
        iconCls: 'tab-add',
        title: '',
        otitle:'',
        tabCls: 'privateEditableTab',
        tabTip : bundleHandler.getBundleStringAndInserts("com.ptc.core.ui.navigationRB.INFO_PAGE_NEW_TAB", ['']),
        closable : false,
        allowContextMenu: false
    };
    tabPanel.add(newTab);
};
/**
 * Selects/De-selects the given menu item.
 *
 * @param {Ext.CheckItem} menuItem - menu item to toggle
 * @param {Boolean} markAsChecked - true to select, false to de-select
 * @param {Boolean} supressEvent - call the onCheck listeners attached to the menu item
 */
PTC.infoPage.myTab.setSelection = function (menuItem, markAsChecked, supressEvent) {
    if(menuItem && typeof menuItem.setChecked === 'function') {
        menuItem.setChecked(markAsChecked, supressEvent);
    }
};
/**
 * Callback function for when the tab is successfully renamed.
 * Will delegate updates on the TabPanel to ensure that the sizing and scrolling of the
 * TabPanel is correct.
 * @param {Object} panel
 */
PTC.infoPage.myTab._renameTabCallback = function (panel, parameters) {
    var data = Ext.decode (parameters.data);
    panel.otitle= data.name;
    var title = PTC.infoPage.myTab.encodeForTabTitle(data.name);
    panel.setTitle(title);
    if (panel.ownerCt && panel.ownerCt.delegateUpdates) {
        panel.ownerCt.delegateUpdates();
    }
};
/**
 * Closes the tab, menu click handler
 */
PTC.infoPage.myTab.closeActionHandler = function(target, event, selectedTab){
    PTC.infoPage.getTabManager(selectedTab.getOwner()).deleteTab(selectedTab, PTC.infoPage.myTab.MyTabPanel.closeTabHandler);
};
/**
 * Callback function to be invoked when the tab's public/private state is successfully changed.
 * @param {Object} tab This is the tab object
 * @param {Object} parameters These are the tab parameters such as the oid.
 */
PTC.infoPage.myTab.setTabVisibilityCallback = function(tab, parameters){
    var data = Ext.decode(parameters.data);
    var publicIcon = tab.getTabPublicIcon();
    var tabOwner = Ext.get(tab.ownerCt.id + '__' + tab.id);
    if (data.isPublic === true) {
        if (tabOwner) {
            tabOwner.removeClass("privateEditableTab");
        }
        if (publicIcon) {
            publicIcon.removeClass('hidden');
        }
    }
    else {
        if (tabOwner) {
            tabOwner.addClass("privateEditableTab");
        }
        if (publicIcon) {
            tab.getTabPublicIcon().addClass('hidden');
        }
    }
    //Make this menu reload. Unfortunately, the hidden actions are not coming down from the server.
    //Would be better to switch on the client side without hitting the server again.
    tab.cachedMenuResponse = undefined;
};
/**
 * Sets the tab state to "private" (i.e., shown only to the administrator)
 */
PTC.infoPage.myTab.setVisibilityActionHandler = function(selectedTab, visibility){
    PTC.infoPage.getTabManager(selectedTab).updateTab(selectedTab, "", visibility, PTC.infoPage.myTab.setTabVisibilityCallback);
};
/**
 * Sets the tab state to "private" (i.e., shown only to the administrator)
 */
PTC.infoPage.myTab.showHideOnSubtypeActionHandler = function(selectedTab, param){
    isInherit = (param=== 'showOnSubtype')? true : false;
    var params = {tabAction: PTC.infoPage.myTab.TabAction.INHERIT_TAB};
    PTC.infoPage.getTabManager(selectedTab.getOwner()).updateTab(selectedTab, "", "",PTC.infoPage.myTab._showHideOnSubtypeCallback,"",params, isInherit);
};
PTC.infoPage.myTab._showHideOnSubtypeCallback = function(tab){
    //This will hit the server again to fetch alient tab menu.
    tab.cachedMenuResponse = undefined;
};
/**
 * Check whether the rename value provided is a duplicate of the existing tabs name
 * @param {Object} rename field
 * @param {PTC.infoPage.myTab.MyTabPanel} selectedTab - the tab whose rename is happening
 * @return true if found a duplicate, else false
 *@private
 */
PTC.infoPage.myTab._isDuplicateName = function(nameField, selectedTab){
    var val = nameField.getValue().strip();
    var valLC = val.toLowerCase();
    var dupFound = false;
    var tabPanel = PTC.infoPage.myTab._getOwner(selectedTab);
    tabPanel.items.each(function(item){
        if (item != selectedTab){
            var title = (item.otitle)? item.otitle : item.title;
            if(title.toLowerCase() === valLC) {
                dupFound = true;
                return false; //terminate loop
            }
        }
        return true;
    });
    return dupFound;
};
/**
 * get the owner of the tab
 * @param {Ext.ux.DockPanel} tab
 *@private
 */
PTC.infoPage.myTab._getOwner = function(tab){
    return tab.getOwner();
};
/**
 * Builds and renders the Ext.Window that will prompt the user for a new tab name.
 */
PTC.infoPage.myTab.renameActionHandler = function(target, event, selectedTab){
    var OKButtonText = bundleHandler.get('com.ptc.core.ui.navigationRB.okDialogButton');
    var cancelButtonText = bundleHandler.get('com.ptc.core.ui.navigationRB.cancelDialogButton');
    Ext.MessageBox.buttonText.ok = OKButtonText;
    Ext.MessageBox.buttonText.cancel = cancelButtonText;
    var win;
    var windowId = 'renameWindow';
    var OKButton = new Ext.Button({
        text: OKButtonText,
        formBind: true,
        handler: function(button, event){
            var nameField = Ext.getCmp('newName');
            var dupFound = PTC.infoPage.myTab._isDuplicateName(nameField, selectedTab);
            // don't allow a tab to be renamed to the name of another tab
            if (dupFound) {
                nameField.markInvalid(bundleHandler.get('com.ptc.core.ui.navigationRB.RENAME_TAB_DUPLICATE_NAME'));
            } else {
                // save the tab with the new name
                PTC.infoPage.getTabManager(selectedTab.getOwner()).updateTab(selectedTab, nameField.getValue().strip(), "", PTC.infoPage.myTab._renameTabCallback);
                //close ext popup window
                win.close();
            }
        }
    });
    var cancelButton = new Ext.Button({
        text: cancelButtonText,
        handler: function(button, event){
            Ext.getCmp(windowId).close();
        }
    });
    /**
     * Logic to create light box window/form
     */
    var preKey = 'RENAME_TAB';
    var formId = 'renameForm';
    var defaultFieldValue = (selectedTab.otitle)? selectedTab.otitle : selectedTab.title;
    win = PTC.lightbox.createSimpleLightBoxWindowAndForm(windowId, formId, defaultFieldValue, preKey, OKButton, cancelButton);
    win.show();
};



        PTC.jca.MyStuffTabPanel = function(myTabConfig) {
    	//PTC.jca.MyStuffTabPanel.superclass.config.layout='anchor';
    	PTC.jca.MyStuffTabPanel.superclass.constructor.call(this, myTabConfig);
    };
    
    Ext.extend(PTC.jca.MyStuffTabPanel , PTC.infoPage.myTab.MyTabPanel, {
    	/**
         * Adds an item to My Stuff Tab.  This creates the table only. This will not show the link
         * @name PTC.jca.MyStuffTabPanel.addItem
         * @param {Object} itemConfig - the item config
         * @param {Boolean} persistChanges - Saves the itemConfig to server side if true
         */
        addItem: function(itemConfig, persistChanges) {
            var tocLinks = this.getTOCLinks();
            var tableContainer = this.getTableContainer();

            // insert widget
            var table = tableContainer.addWidget({
                id: itemConfig.id,
                actionURL: itemConfig.actionURL,
                actionID: itemConfig.actionID,
                actionName: itemConfig.actionName,
                actionType: itemConfig.actionType,
                actionText: itemConfig.text
            });
            if (persistChanges === true) {
                this.getTabContentManager().add(itemConfig);
            }
        }
    });
    
    /**
      * Create and renders myStuffTab
      */
    PTC.jca.createMyStuff= function(myStuffConfig) {
        var myStuffPanel = Ext.getCmp("navigation_myStuffTab");
        if (!myStuffConfig) {
            myStuffPanel.doLayout();
            return;
        }
        myStuffConfig.layout='anchor';
        var newPanel = new PTC.jca.MyStuffTabPanel(myStuffConfig);
        newPanel.render("myStuffDivID");
        myStuffPanel.on('tabChange', myStuffPanel.doLayout());
    }; 

