/**
 * EXT PTC OVERRIDE: SPR 2078271: Keep these changes until we move up to extjs 4 to get official IE9 support
 */

Ext.isIE6 = Ext.isIE && /msie 6/.test(navigator.userAgent.toLowerCase());
Ext.isIE9 = Ext.isIE && /msie 9/.test(navigator.userAgent.toLowerCase());
//Note that IE10 is for now representing itself as IE8 compat so also checking for trident 6.0.
Ext.isIE10= Ext.isIE && (/msie 10/.test(navigator.userAgent.toLowerCase()) || /trident\/6\.0/.test(navigator.userAgent.toLowerCase()));
//Note that IE11 is also representing itself as IE8 compat so also checking for trident 7.0.
// TODO: Ext.isIE11 is redundant and should be removed soon (it is used in couple of places only).
// use PTC_isIE11 instead. Also, note that in IE11 Ext.isIE is false, which results in Ext.isIE11
// always being false.
Ext.isIE11= Ext.isIE && (/msie 11/.test(navigator.userAgent.toLowerCase()) || /trident\/7\.0/.test(navigator.userAgent.toLowerCase()));
Ext.isIE64BIT = Ext.isIE && /Win64; x64/.test(navigator.userAgent);
//Set by Server later in cases where this reports false, chromeframe can report itself as chrome to the js engine
Ext.isGCF = /chromeframe/.test(navigator.userAgent);
Ext.is = {};
Ext.is.iPad = navigator.userAgent.match(/iPad/i) !== null;

Ext.ns("PTC.overrides");

/**
 * Add the CSS class depending upon the Version and Document mode For IE
 * @param {Ext.Element} the body of the document
 */ 
PTC.overrides.addStyles = function(body) {
    if(Ext.isIE9) {
        body.addClass("ext-ie9");
    } else if (Ext.isIE10) {
        body.addClass("ext-ie10");
    } else if (Ext.isIE11) {
        // TODO: We will never get here since Ext.isIE11 is always false (see notes above, where we set the value of Ext.isIE11).
        // For now this does not cause any issues. Ext.isIE11 check might be replaced with PTC_isIE11 after properly testing the change
        body.addClass("ext-ie11");
    } else if(Ext.isIE8) {
        //Ext will put .isIE8 css for all the IE version greater than 7. 
        //introducing new ext-ie8Only css class, to handle specific ie8 issues.
        body.addClass("ext-ie8Only");
    }

    // To identify at CSS class that browser using the document mode less than the ie9
    if (Ext.isIE && document.documentMode &&  document.documentMode < 9 ){
        body.addClass("ie-docMode8");
    }

    if (isWf && isWf()) {
        body.addClass("embedded");
    }

    var isDTIElement = Ext.fly('isDTI');

    // Add the CSS class depending upon DTI to make inline message look above, not overlapped with main popup window.
    // Fixes SPR 2223877
    if(isDTIElement && isDTIElement.dom.value === 'true') {
        body.addClass("DTI");
    }
};
