/**
 * @param  {Boolean} forceRenderRows(optional)
 * if true force rendering all the visible rows. (e.g. in case of sort, the data in visble rows may be stale as the index may have been changed in the store)
 */
Ext.ux.grid.BufferView.prototype.doUpdate = Ext.ux.grid.BufferView.prototype.doUpdate.wrap(function(proceed,forceRenderRows){
    this.clearVisibleCaches();
    if (this.getVisibleRowCount() > 0) {
        var g = this.grid, cm = g.colModel, ds = g.store;
        var cs = this.getColumnData();
        var vr = this.getVisibleRows();
        var cmcount = cm.getColumnCount();
        var doStripe = g.stripeRows;
        var sm = g.getSelectionModel();
        var allRows = this.getCachedAllRows(null,null);
        var exRows = 0;

        for (var i = vr.first,vrl=vr.last; i <= vrl; i++) {
            var trow = allRows[i];

            //If the the group is collapsed skip rendering of rows within that group.
            if(this.canGroup() && trow) {
                if(exRows === 0) {
                    var sibs = this.getSiblingRows(trow);
                    if(sibs.crows) {
                        i += sibs.crows;
                    }
                    exRows = sibs.erows;
                } else {
                    exRows--; //If a group is not collapsed, skip above block until another group.
                }
            }
            // if row is NOT rendered and is visible, render it
            if (this.isVisible(i, vr)) {
                if(!this.isRowRendered(i, allRows) || forceRenderRows){
                    if (trow !== undefined) {
                        var storeRow = ds.getAt(i);
                        var html = '';
                        if (storeRow !== undefined && storeRow.IS_EMPTY !== true) {
                            html = this.doBFRender(cs, [storeRow], ds, i, cmcount, doStripe, true);
                            this._ghostCache[i] = false;
                        }
                        else {
                            // Allow for rendering empty rows that have not been downloaded yet
                            this._ghostCache[i]=true;
                        }
                        PTC.util.purge(trow, true);
                        trow.innerHTML = html;
                        this.postUpdateRow(trow);
                        if (this.variableRowHeight === true) {
                            trow.style.height = 'auto';
                        }

                        if (this._selectCache[i]===undefined) {
                            this._selectCache[i]=false;
                        }
                        var isSelected = sm.isSelected(storeRow);
                        var nonSelectableClass = 'nonselectable-record';
                        //PTC EXT OVERRIDE  --- START HERE

                        /*
                         * Added a if statement to add remove  CSS related to strike through and nonselectable columns
                         * */
                        if(g.jcaTableConfig.nonSelectRowColumn || g.jcaTableConfig.strikeThroughColumn) {
                            var isSelectable = PTC.jca.table.isRowSelectable(storeRow, ds, g);
                            var isStrikeThrough = PTC.jca.table.rowStrikeThrough.getBooleanValue(storeRow, g.jcaTableConfig.strikeThroughColumn)=="true";

                            if(this._selectableCache[i] != isSelectable){
                                this._selectableCache[i] = isSelectable;
                                if(isSelectable) {
                                    this.fly(trow).removeClass(nonSelectableClass);
                                } else {
                                    this.fly(trow).addClass(nonSelectableClass);
                                }
                            }
                            if(this._strikeThroughCache[i] != isStrikeThrough){
                                this._strikeThroughCache[i] = isStrikeThrough;
                                if(isStrikeThrough){
                                    this.fly(trow).addClass(PTC.jca.table.rowStrikeThrough.getStrikeThroughCSS());
                                }
                                else{
                                    var strikeRowThroughCss = PTC.jca.table.rowStrikeThrough.getStrikeThroughCSS();
                                    while(this.fly(trow).hasClass(strikeRowThroughCss)) {
                                       this.fly(trow).removeClass(strikeRowThroughCss);
                                    }
                                }
                            }
                       }
                      //PTC EXT OVERRIDE  --- END HERE
                       if (this._selectCache[i]!==isSelected) {
                            this._selectCache[i]=isSelected;
                            if (isSelected) {
                                this.fly(trow).addClass(this.selectedRowClass);
                            }
                            else {
                                this.fly(trow).removeClass(this.selectedRowClass);
                            }
                       }
                    }
                }
                else if (trow && this.variableRowHeight === true && this._rowHeightCache[i] === undefined) {
                    trow.style.height = 'auto';
                }
            }  // could set _cache to false here for collapsed node cleanup
        }
        //Cannot wait the deal clear out stale rows
        if(forceRenderRows) {
            this.doClean();
        } else {
            if(this.grid.tree) {
                /* For tree grid view, clear visible row cache so as to avoid rendering of any
                 * rows in collapsed node.(SPRs 2167672)
                 * Clear visible row cache immediately after rendering since doClean is delayed call,
                 * and in between if the rows get rendered again, then there would be stale cache.
                 */
                this.clearVisibleCaches();
             }
            this.clean();
        }
    }
    this.doOverridenUpdate();

});

/**
 * To get the siblings of current row in a group.
 */
Ext.grid.GroupingView.prototype.getSiblingRows = function(row) {
    var sibs = {crows: 0, erows: 0};
  //If the the group is collapsed skip rendering of rows within that group.
    if(this.canGroup() && row) {
        var group = Ext.get(this.getGroupFromRow(row));
        var nxSibs = PTC.overrides._countNextSiblings(Ext.get(row));

        if(nxSibs > 0) {
            if(group.hasClass('x-grid-group-collapsed')) {
                sibs.crows = nxSibs;
            } else {
                sibs.erows = nxSibs;
            }
        }
    }
    return sibs;
};

/**
 * Replaces the prototype next sibling method that was previously being used twice in this file. Search did not find any other uses of nextSiblings.
 * Since both uses are in this file this is private. This method should not be used by any other files. If a need is found for it 
 * elsewhere it should be promoted to a public method.
 */
PTC.overrides._countNextSiblings = function(extElement) {
        var nextSib = extElement.next();
        var count = 0;
        while(nextSib) {
            count++;
            nextSib = nextSib.next();
        }
        return count;
};

Ext.ux.grid.LockingGridView.prototype.processRows = Ext.ux.grid.LockingGridView.prototype.processRows.wrap(function(proceed, startRow, skipStripe) {
//Some code removed for fixing misalignment of rows between locked and unlocked view
    var rows = this.getRows();

    if(!this.ds || this.ds.getCount() < 1 || rows.length<=0){
        return;
    }

    if (!this.isLocked) {
        return Ext.ux.grid.LockingGridView.superclass.processRows.apply(this, Array.prototype.slice.call(arguments, 1));
    }

    var lrows = this.getLockedRows(),
        row,
        lrow;

    skipStripe = skipStripe || !this.grid.stripeRows;
    startRow = startRow || 0;
    var rowHeightSets = [];
    for(var i = 0, len = rows.length; i < len; ++i){
        row = rows[i];
        lrow = lrows[i];
        row.rowIndex = i;
        lrow.rowIndex = i;
        if(!skipStripe){
            row.className = row.className.replace(this.rowClsRe, ' ');
            lrow.className = lrow.className.replace(this.rowClsRe, ' ');
            if ((i + 1) % 2 === 0){
                row.className += ' x-grid3-row-alt';
                lrow.className += ' x-grid3-row-alt';
            }
        }
    }

    if(startRow === 0){
        Ext.fly(rows[0]).addClass(this.firstRowCls);
        Ext.fly(lrows[0]).addClass(this.firstRowCls);
    }
    Ext.fly(rows[rows.length - 1]).addClass(this.lastRowCls);
    Ext.fly(lrows[lrows.length - 1]).addClass(this.lastRowCls);
});

Ext.ux.grid.LockingGridView.prototype.syncRowHeight = function(trow, lrow, rowIndex){
    if (this.variableRowHeight === true) {
        if(rowIndex===undefined){
            rowIndex = trow.rowIndex;
        }
        trow.style.height='auto';
        lrow.style.height='auto';
        var trowHeight =Ext.fly(trow).getHeight();
        var lrowHeight = Ext.fly(lrow).getHeight();
        if(trowHeight>lrowHeight){
            lrow.style.height = (trowHeight - this.borderHeight) +"px";
            trow.style.height = lrow.style.height;
        }else if(trowHeight<lrowHeight){
            trow.style.height = (lrowHeight - this.borderHeight) +"px";
            lrow.style.height = trow.style.height;
        }
        this._rowHeightCache[rowIndex] = Ext.fly(lrow).getHeight();
    }
};

