/**
 * Update the displayed rows based on data store changes that only effected some column values, and did not add/remove rows
 * @param  {Boolean} forceRenderRows(optional)
 * if true force rendering all the visible rows. (e.g. in case of sort, the data in visble rows may be stale as the index may have been changed in the store)
 */
Ext.ux.grid.BufferView.prototype.doPartialDataChange = function(forceRenderRows) {
   this._cache = {};
   var g = this.grid;
   if (!g) {
       return;
   }
   var gridView = g.getView(), ds = g.store, nonSelectableClass = 'nonselectable-record';
   var rows = gridView.getRows();

   this.doUpdate(forceRenderRows);

};


