Ext.override(Ext.menu.Menu, {
    constrainScroll : function(y) {
        var max, full = this.ul.setHeight('auto').getHeight(), returnY = y, normalY, parentEl, scrollTop, viewHeight;
        if (this.floating) {
            //PTC Override to handle case when menu is in an iframe - make sure the menu scrollers appear
            //Can test this scenario by going to the workspace page and opening the toolbar/actions menu with the window very small
            var parentDocument = parent.document;
            var isIframe = Ext.fly(parentDocument).contains(window.frameElement) && parentDocument.viewport !== undefined;

            if (isIframe) {


        //PTC Override To Handle iframe Start Here
            if(this.maxHeight) {
                    max = this.maxHeight;
                }
                else {
               /*
                * SPR 1924466: In case of Iframe the height and the y axis was coming in relative of Frame
                * so the menu max height was getting calculated wrongly and hence the menu height.
                */
                    max =  parentDocument.viewport.getHeight() - ( y + Ext.get(window.frameElement).getTop());
                }
                //PTC Override To Handle iframe End Here.
            }
            else {
                parentEl = Ext.fly(this.el.dom.parentNode);
                scrollTop = parentEl.getScroll().top;
                viewHeight = parentEl.getViewSize().height;
                //Normalize y by the scroll position for the parent element.  Need to move it into the coordinate space
                //of the view.
                normalY = y - scrollTop;
                if (this.maxHeight) {
                    max = this.maxHeight;
                }
                else {
                    max = viewHeight - normalY;
                }
                if (full > viewHeight) {
                    max = viewHeight;
                    //Set returnY equal to (0,0) in view space by reducing y by the value of normalY
                    returnY = y - normalY;
                }
                else if (max < full) {
                    returnY = y - (full - max);
                    max = full;
                }
                }
           }
        else {
            max = this.getHeight();
        }
        // Always respect maxHeight
        if (this.maxHeight) {
            max = Math.min(this.maxHeight, max);
        }
        if(full > max && max > 0){
            this.activeMax = max - this.scrollerHeight * 2 - this.el.getFrameWidth('tb') - Ext.num(this.el.shadowOffset, 0);
            this.ul.setHeight(this.activeMax);
            this.createScrollers();
            this.el.select('.x-menu-scroller').setDisplayed('');
        }
        else {
            this.ul.setHeight(full);
            this.el.select('.x-menu-scroller').setDisplayed('none');
        }
        this.ul.dom.scrollTop = 0;
        return returnY;
    }
});

