/**
 * The visual radio selection is not cleared when clearSelections is called when displaying the context menu.
 * It is cleared when another row is selected by the default HTML behavior of radio groups, 
 * but the menu does not select anything and so this ensures no matter how clearSelections is called,
 * the visual selection is cleared along with the selection in the data store.
 * 
 * Integrity spr 5885359
 */
Ext.ux.grid.RadioSelectionModel.prototype.clearSelections = function(fast, deselectAll){
    var ds = this.grid.store;
    var s = this.selections;
    var items =  s.items;

    for (var i = 0, l = items.length; i < l; i++) {  //used for loop instead of each block because of unresponsive script block
        var r = items[i];
        var rowIndex = ds.indexOfId(r.id);
        this._updateCheckedState(rowIndex, false);
    }
    return Ext.ux.grid.RadioSelectionModel.superclass.clearSelections.call(this, fast, deselectAll);        
};

/**
 * PTC EXT OVERRIDE: Modified to handle the Non-selectable rows case and selection in column lock state grid view.
 */
Ext.override(
    Ext.ux.grid.RadioSelectionModel, {
         selectRow: function(index){
             // PTC EXT OVERRIDE Start: if the row is non-selectable for single select then do no call selectRow function
             var store = this.grid.store;
             // if the index is a number, use it. Otherwise get the index of the object in the data store
             if(!Ext.isNumber(index)) {
                 if (typeof index === 'string') {
                     index = store.indexOfId(index);
                 }
                 else {
                     index = store.indexOf(index);
                 }
             }
             if(!PTC.jca.table.isRowSelectable(store.getAt(index), store)) {
                 return;
             } // PTC EXT OVERRIDE End:

             // call parent
             Ext.ux.grid.RadioSelectionModel.superclass.selectRow.apply(this, arguments);

             // PTC EXT OVERRIDE Start: This will handle if the radio button is present in locked row.
             this._updateCheckedState(index,true);
             // PTC EXT OVERRIDE End:
         },

         //This will handle if the radio button is present in locked row. 
         //It is used by selectRow and clearSelections
        _updateCheckedState: function(index, newCheckedState) {
            var row ;
            var cm = this.grid.colModel;
            var rId = cm.getIndexById(this.id); // Get the column index for the radio button column
            if(this.grid.rendered === true) {
                if(cm.isLocked(rId)) {
                    row = Ext.fly(this.grid.view.getLockedRow(index));
                } else {
                    row = Ext.fly(this.grid.view.getRow(index));
                }
            }
            // check radio
            if (row && row.child('input[type=radio]') && row.child('input[type=radio]').dom) {
              row.child('input[type=radio]').dom.checked = newCheckedState;
            }
        }
    }
);

