/**
 * EXT PTC OVERRIDE: SPR 2097291, Unable to expand the tables located at the bottom of the Information page tabs with Internet Explorer 8.
 * Seems to work ok with IE 11 in Edge mode. 
 */
Ext.override(Ext.dd.DragTracker, {

    onMouseMove: function(e, target){
        // HACK: IE hack to see if button was released outside of window. */
        //PTC EXT OVERRIDE Start; Allowing onDrag to call for IE browser
        if (this.active && Ext.isIE && !e.browserEvent.button) {
            if (this.panelResizer === 1) {
                e.preventDefault();
                this.onMouseUp(e);
                  //making the value 2 as this mousemove requires special treatment in Panel resizer's ondrag method
                this.panelResizer = 2;
                this.onDrag(e);
                return;
            }
            else {
                e.preventDefault();
                this.onMouseUp(e);
                return;
            }

        }
        //PTC EXT OVERRIDE end;
        e.preventDefault();
        var xy = e.getXY(), s = this.startXY;
        this.lastXY = xy;
        if (!this.active) {
            if (Math.abs(s[0] - xy[0]) > this.tolerance || Math.abs(s[1] - xy[1]) > this.tolerance) {
                this.triggerStart();
            }
            else {
                return;
            }
        }
        this.fireEvent('mousemove', this, e);
        this.onDrag(e);
        this.fireEvent('drag', this, e);
    }
});

/**
 * EXT PTC OVERRIDE: SPR 2097291, Unable to expand the tables located at the bottom of the Information page tabs with Internet Explorer 8.
 */
Ext.override(Ext.ux.PanelResizer, {

    onDragStart: function(e){
        this.dragging = true;
        this.startHeight = this.panel.el.getHeight();
        //PTC EXT OVERRIDE Start; setting flag so that DDTracker puts a hack only when called from PanelResizer
        this.tracker.panelResizer = 1;
        //PTC EXT OVERRIDE End;
        this.fireEvent('dragstart', this, e);
    },

    onDrag: function(e){
        //PTC EXT OVERRIDE Start; increase the height of proxy panel so that resizing can happen for the last table on info page
        if (this.tracker.panelResizer === 2) {
            this.panel.setHeight((this.startHeight - this.tracker.getOffset()[1]).constrain(this.minHeight, this.maxHeight) + 150);
        }
        else {
            this.panel.setHeight((this.startHeight - this.tracker.getOffset()[1]).constrain(this.minHeight, this.maxHeight));
        }
        //PTC EXT OVERRIDE End;
        this.fireEvent('drag', this, e);
    }
});

/**
 * EXT PTC OVERRIDE, remove file check so that the file name fields are sent as part of the form-data
 * @param {Object} form
 */
Ext.lib.Ajax.serializeForm = function(form) {
    var fElements = form.elements || (document.forms[form] || Ext.getDom(form)).elements,
        hasSubmit = false,
        encoder = encodeURIComponent,
        element,
        options,
        name,
        val,
        data = '',
        type;

    Ext.each(fElements, function(element) {
        name = element.name;
        type = element.type;

        if(PTC.isInputElements(element) === false) {
            return;
        }

        if (!element.disabled && name){
            if(/select-(one|multiple)/i.test(type)) {
                Ext.each(element.options, function(opt) {
                    if (opt.selected) {
                        data += String.format("{0}={1}&", encoder(name), encoder((opt.hasAttribute ? opt.hasAttribute('value') : opt.getAttribute('value') !== null) ? opt.value : opt.text));
                    }
                });
            } else if(!/undefined|reset|button/i.test(type)) { //PTC - removed file from this list only
                    if(!(/radio|checkbox/i.test(type) && !element.checked) && !(type == 'submit' && hasSubmit)){

                        data += encoder(name) + '=' + encoder(element.value) + '&';
                        hasSubmit = /submit/i.test(type);
                    }
            }
        }
    });
    return data.substr(0, data.length - 1);
};

/**
 * This method will return false if the form element is not input element
 *
 * @param element Form Elment
 * @returns Boolean false if not input element
 */
PTC.isInputElements = function(element) {
    // Code for only input elemnts should get serialized.  "INPUTSELECTOR","SELECTONE", "SEKECTMANY", "OPTIONVALUE",
    // This tag name did not found on any change mgmt UI but kept as it is as this was handled in prototype.js for serialisers method.
    var tags = ["INPUT","SELECT", "TEXTAREA", "INPUTSELECTOR","SELECTONE", "SELECTMANY", "OPTIONVALUE"];
    var tagName = element.tagName;
    if(tagName && tagName.toUpperCase) {
        tagName = tagName.toUpperCase();
        if(tags.indexOf(tagName) === -1) {
            return false;
        }
    }

    return true;
};

/**
 * Override the initialization of the Ext.Button's inner button element to set the access key if it is
 * set in the config of the button object.  This is typcially set in Windchill as the "hotkey" rbinfo property
 * of the NmAction.
 *
 * The accesskey HTML attribute allows keyboard access to buttons.  It is required for
 * Section 508 conformance.
 *
 * http://www.w3.org/TR/html401/interact/forms.html#h-17.11.2
 */
Ext.Button.prototype.initButtonEl = Ext.Button.prototype.initButtonEl.wrap(
    function(proceed, btn, btnEl) {
        var result = proceed.call(this, btn, btnEl);
        if (this.accesskey) {
            btnEl.set({"accesskey":this.accesskey});
        }
        return result;
    }
);

