Ext.override(Ext.ux.maximgb.tg.GridView,{
    //PTC EXT OVERRIDE, combine TreeGrid with bufferview.  The below contains the bufferview changes
        // that skip rows inter-twined with the tree grid skipping rows.
        doRender : function(cs, rs, ds, startRow, colCount, stripe, onlyBody){
            var ts = this.templates, ct = ts.cell, rt = ts.row, rb = ts.rowBody, last = colCount-1;
            var rh = this.getStyleRowHeight();
            var vr = this.getVisibleRows();
            var tstyle = 'width:'+this.getTotalWidth();
            var tstyleWidthOnly = 'width:'+this.getTotalWidth();
            var tsytleAndHeight = tstyle + ';height:'+rh+'px;';
            if (this.variableRowHeight !== true) {
                tstyle = tsytleAndHeight;
            }
            // PTC EXT OVERRIDE, only assign height in pixels for rows that are not displayed, let the displayed rows take
            // their natural height.  May need to remove height from some displayed rows after they are scolled in?
            // rphidden is the rp style with the height style applied
            var buf = [], cb, c, p = {}, rpdisplayed = {tstyle: tstyle}, rphidden ={tstyle:tsytleAndHeight}, r;
            for (var j = 0, len = rs.length; j < len; j++) {
                var rp = rpdisplayed;
                  r = rs[j]; cb = [];
                  if (r === undefined) {
                      r = Ext._EMPTY_RECORD;
                  }

                var rowIndex = (j+startRow);
                var visible = (rowIndex >= vr.first && rowIndex <= vr.last) && this.isVisible(rowIndex, vr);
                if (r.IS_EMPTY===true) {
                    this._ghostCache[rowIndex]=true;
                }
                if (visible || (this._cache[rowIndex] && !visible)) {
                   this._cache[rowIndex] = visible;
                }
                if (visible) {
                    for (var i = 0; i < colCount; i++) {
                        c = cs[i];
                        p.id = c.id;
                        p.css = i === 0 ? 'x-grid3-cell-first ' : (i === last ? 'x-grid3-cell-last ' : '');
                        p.attr = p.cellAttr = "";
                        p.value = c.renderer.call(c.scope, r.get(c.name), p, r, rowIndex, i, ds);
                        p.style = c.style;
                        if (Ext.isEmpty(p.value)) {
                            p.value = "&#160;";
                        }
                        if (this.markDirty && r.dirty && typeof r.modified[c.name] !== 'undefined') {
                            p.css += ' x-grid3-dirty-cell';
                        }
                        // ----- Modification start
                        if (c.id === this.grid.master_column_id) {
                            p.treeui = this.renderCellTreeUI(r, ds);
                            ct = ts.mastercell;
                        }
                        else {
                            p.treeui = '';
                            ct = ts.cell;
                        }
                        if(c.scope.isWrapped){
                            p.css+='x-grid3-cell-wrap';
                            this.variableRowHeight = true;
                        }
                        // ----- End of modification
                        cb[cb.length] = ct.apply(p);
                    }
                    //PTC EXT OVERRIDE, set tstyle with height as auto if variableRowHeight is set to true due to call contents.
                    if(this.variableRowHeight===true){
                        rp.tstyle = tstyleWidthOnly;
                    }
                } else {
                    rp = rphidden;
                }
                var alt = [];
                if (!onlyBody) {
                    if(stripe && ((rowIndex+1) % 2 === 0)){
                        alt[0] = "x-grid3-row-alt";
                    }
                      if(r.dirty){
                        alt[1] = " x-grid3-dirty-row";
                    }
                    rp.cols = colCount;
                    if(typeof this.getRowClass === 'function' ){
                          alt[2] = this.getRowClass(r, rowIndex, rp, ds);
                    }
                    rp.alt = alt.join(" ");
                } else {
                    rp.alt = '';
                }

                rp.cells = cb.join("");

                // ----- Modification start
                if (!ds.isVisibleNode(r, rowIndex)) { //EXT PTC OVERRIDE - pass the index, avoid lookup
                    rp.display_style = 'display: none;';
                }
                else {
                    rp.display_style = '';
                }
                rp.level = ds.getNodeDepth(r);
                // ----- End of modification

                buf[buf.length] = !visible ? ts.rowHolder.apply(rp) : (onlyBody ? rb.apply(rp) : rt.apply(rp));
            }

            return buf.join("");
    },

     _processNodes: function(nodes, indexes, store) {
        for (var i = 0,l=nodes.length; i<l; i++) {
            var record = nodes[i];
            var nodeIndex = record._index;
            if (!nodeIndex) {
               nodeIndex = store.indexOf(record);
            }
            indexes.push(nodeIndex);
            var hasChildren = !store.isLeafNode(record);
            var needToGetChildren = hasChildren && ( store.isExpandedNode(record) );
            if ( needToGetChildren ) {
                this._processNodes(store.getNodeChildren( record ), indexes, store);
            }
        }
     },

    /**
     * PTC addition
     * Gets all the indexes in the store that are expanded
     * @param {Ext.data.Store} store
     * @return Array of indexes
     */
    _allRenderable : function(store) {

        var indexes = [];
        var origCacheState = store.useChildNodeCache;
        try {
            store.enableChildNodeCache();
            if ( !(store === undefined || store === null) ) {
                var rootNodes = store.getRootNodes();
                this._processNodes(rootNodes, indexes, store);
            }
        }
        finally {
            if (!origCacheState) {
                store.disableChildNodeCache();
            }
        }
        return indexes;
    }
});

