Ext.grid.GroupingView.prototype.onRemove = Ext.grid.GroupingView.prototype.onRemove.wrap(function(proceed, ds, record,
        index, isUpdate) {
    proceed.call(this, ds, record, index, isUpdate);
    /*Check if grouping is enabled and applied on table/tree,
    hasGroups() particularly checks if grouping is applied. */
    if (!this.canGroup() || !this.hasGroups()) {
        return;
    }
    // If any row is removed from group, update group header count appropriately.
    var grbd = Ext.getDom(record._groupId + "-bd");
    if (!grbd) {
        PTC.log.error("GroupingView.onRemove: unexpected missing group: " + record._groupId);
    }
    var grrs = grbd ? grbd.children : undefined;

    var groupField = this.getGroupField();
    var colIndex = this.cm.findColumnIndex(groupField);
    var cfg = this.cm.config[colIndex];
    if (cfg !== undefined) {
        var groupRenderer = cfg.groupRenderer || cfg.renderer;
        var tx = this.getGroup(record.get(groupField), record, groupRenderer, index, colIndex, ds);
        var prefix = this.showGroupName ? (cfg.groupName || cfg.header) + ': ' : '';
        var grhdtx = prefix + tx;

        // Get the template for group header text and change it accordingly the latest group row count.
        var t = new Ext.XTemplate(this.groupTextTpl);

        t.compile();
        if (grrs && grhdtx) {
            var html = t.apply({
                text: grhdtx,
                rs: grrs
            });

            // Apply compiled template html to group title element.
            var gte = Ext.DomQuery.select("div[class*=x-grid-group-title]", Ext.getDom(record._groupId));
            if (gte && gte.length > 0 && html) {
                gte[0].innerHTML = html;
            }
        }
    }
    
});

