PTC.partslink.suma.renderSumaCheckBoxes = function(searchString, typeLabel) {
    var selectedTypeArray = new Array();
    var chked = false;

    selectedTypeArray = searchString.split(',');
    for ( var index = 0; index < PTC.partslink.suma.typeArray.length; index++) {
        chked = false;
        for ( var selectedIndex = 0; selectedIndex < selectedTypeArray.length; selectedIndex++) {
            if (selectedTypeArray[selectedIndex].trim() == PTC.partslink.suma.typeArray[index]) {
                chked = true;
            }
        }

        PTC.partslink.suma.sumaCheckBox(PTC.partslink.suma.typeArray[index], typeLabel[index],
                PTC.partslink.suma.imageArray[index], chked);
    }
}

PTC.partslink.suma.checkSumaPartTypesListener = function() {
    // Create the url string for every change in the check box condition
    var str = "";

    for (i = 0, k = 0; i < PTC.partslink.suma.typeArray.length; i++) {
        if ((Ext.getCmp(PTC.partslink.suma.typeArray[i])).getValue()) {
            if (k == 0) {
                str = "partType=" + PTC.partslink.suma.typeArray[i];
            } else {
                str = str + "&partType=" + PTC.partslink.suma.typeArray[i];
            }
            k = k + 1;
        }
    }

    if (k == 0) {
        var noSelectionErrorMsg = document.getElementById('noSelectionErrorMsg').value;
        alert(noSelectionErrorMsg);

        (Ext.getCmp(this.id)).setValue(true);
        return;
    }

    PTC.partslink.suma.submitTypeChange(str);
}

