/**
 *   Used by the com.ptc.windchill.enterprise.part.alternaterep.client.action.UpdateCADAlternateRepAction
 *   to redirect the user to the CAR info page after doing an Update design context action.  It does so
 *   by invoking the refressCCInfo function that is responsible for updating the workgroup manager's cache.
 *   When it completes it's work it invokes the redirectCallback function that is being passed to it
 */
PTC.partAlternateRepUI.redirectToUpdatedCARInfoPage = function viewInfo(oid, workspaceName, topLevelEPMDocumentOid) {
    var redirectURL = "ptc1/tcomp/infoPage?oid=" + oid;
	if(workspaceName != null && workspaceName.trim() != "") {
	    var wsName = {'wsName': workspaceName.trim()};
	    redirectURL += "&" + Ext.urlEncode(wsName);	    
	}
    
	 PTC.partAlternateRepUI["carRedirectUrl"] = redirectURL;

    if( top && top.window && top.window.external && top.window.external.ptc ) {
        // Detected embedded browser
        var redirectCallback = function(){
            window.parent.PTC.navigation.loadContent(PTC.partAlternateRepUI.carRedirectUrl);
        }
        window.WildfireUserAgent="Wildfire";
        window.refreshInfoServerContent=new Array();
        window.refreshInfoServerContent[0] = oid;

        if(topLevelEPMDocumentOid != null && topLevelEPMDocumentOid.trim() != "") {
            window.refreshInfoServerContent[1] = topLevelEPMDocumentOid;
        }

        window.refreshCCInfo(redirectCallback);
    }
    else {
        window.parent.PTC.navigation.loadContent(PTC.partAlternateRepUI.carRedirectUrl);
    }
}

PTC.paste = function(){
    //Will return the objectHandle value
    function getObjectHandle(){
        var objectHandle = opener.getElementByName("objectHandle");
        if (objectHandle && objectHandle !== null) {
            return objectHandle.value;
        }
        else {
            return "";
        }
    }
    return {
        /* Gets the table id from the action oid from the url. */
        getTableID: function(){
            var params = location.search.parseQuery();
            var tableID = null;
            if (typeof params.tableID === 'string') {
                tableID = params.tableID;
            }
            else {
                tableID = params.tableID[0];
            }
            return tableID;
        },
        /**
         * Paste items to the table.
         * @param {String} objects - oid references delimited by '#'.
         * @param {String} tableId - the id of a table
         * @param {String} additionalParams - additional parameters to be passed for paste operation and expected to be a json string.
         */
        pasteItems: function(objects, tableId, additionalParams){
        
            if (additionalParams) {
                var json = Ext.util.JSON.decode(additionalParams);
                if (json && json.refreshOid) {
                    PTC.infoPage.refreshTop(json.refreshOid, true);
                }
            }
            
            if (objects && objects !== null && objects.length > 0) {
                var list = objects.split("#");
                var params;
                if (list.length <= 100) {
                    params = {
                        doAjaxUpdate: true,
                        preventDuplicates: true
                    };
                }
                else {
                    params = {
                        refreshTable: true,
                        preventDuplicates: true
                    };
                }
                rowHandler.addRows(list, tableId, null, params);
            }
        },
        /**
         * Paste items to the table using paste select.
         * @param {String} objects - oid references delimited by '#'.
         * @param {String} tableId - the id of a table
         * @param {String} status - wizard status
         * @param {Function} pasteFunc - the paste function to be called
         * @param {String} additionalParams - additional parameters to be passed for paste operation and expected to be a json string.
         */
        pasteSelectItems: function(objects, tableId, status, pasteFunc, additionalParams){
            pasteFunc(objects, tableId, additionalParams);
            handleWizWindow(status);
        },
        
        launchPasteSelectItems: function(title, message, js){
            if (message !== null) {
				title = title + "\n\n" + message;
			}
            if (wfconfirm_gen(title)) {
                eval(js);
            }
        },
        copyTableRowElements: function(){
            var mform = getMainForm();
            var objHandle = getObjectHandle();
            
            var itemTypeInstanceId = opener.getElementByName(objHandle + "itemTypeInstanceId");
            if (itemTypeInstanceId) {
                appendFormHiddenInput(mform, "itemTypeInstanceId", itemTypeInstanceId.value);
            }
            var editObjRef = opener.getElementByName(objHandle + "editObjectRef");
            if (editObjRef) {
                appendFormHiddenInput(mform, "editObjectRef", editObjRef.value);
            }
            
            var INITIAL_ROWS_PREFIX = 'initialRows_';
            var ADDED_ROWS_PREFIX = 'addRows_';
            var REMOVED_ROWS_PREFIX = 'rmRows_';
            
            var tableId = tableUtils.getUnformattedTableId(PTC.paste.getTableID());
            var initialOidNode = opener.tableUtils.getInitialRows(tableId);
            var addedOidNode = opener.tableUtils.getAddedRows(tableId);
            var removedOidNode = opener.tableUtils.getRemovedRows(tableId);
            
            var initialOidValue = (initialOidNode && initialOidNode !== null) ? initialOidNode.value : '';
            var addedOidValue = (addedOidNode && addedOidNode !== null) ? addedOidNode.value : '';
            var removedOidValue = (removedOidNode && removedOidNode !== null) ? removedOidNode.value : '';
            
            appendFormHiddenInput(mform, INITIAL_ROWS_PREFIX + tableId, initialOidValue);
            appendFormHiddenInput(mform, ADDED_ROWS_PREFIX + tableId, addedOidValue);
            appendFormHiddenInput(mform, REMOVED_ROWS_PREFIX + tableId, removedOidValue);
            
        }
    };
}();


