/**
 * package that provides some performance statistics about various components
 * @namespace
 * @internal
 */
PTC.performance = {};
PTC.performance.logger = log4javascript.getLogger('PTC.performance');
PTC.performance.wizardTimer='wizardTimer';

Ext.apply(PTC.performance, new Ext.util.Observable());

PTC.performance.addEvents(/**
 * Event must be emitted when a component is ready from user's perspective.
 * In case of data source or async components, first chunk may be considered as 'ready'.
 * For sync components, the component may be unusable for user till completely rendered.
 * To fire this event, please use the following syntax
 * PTC.performance.fireEvent('pageReady')
 *
 * @name PTC.performance#pageReady
 * @event
 */
"pageReady");

/**
 * The timer that keeps track of a start time for the last global click
 */
PTC.performance.GLOBAL_CLICK_TIMER = null;

/**
 * filter out null entries to avoid unnecessary data displayed
 * @param {Ext.data.Record} rec
 */
PTC.performance.filterStoreForUndefined = function(rec){
    return rec.get("Time") ? true : false;
};

PTC.performance.Timer = function(name){
    this.name = name;
    this.init();
};

PTC.performance.Timer.prototype.init = function() {
    this.startTime = undefined;
    this.readyTime = undefined;
    this.titleReadyTime = undefined;
    this.stopTime = undefined;
    this.componentTimeBeans = [];
    //flag used to know whether to use start time of when window was launched
    this.initialWizardLaunch = false;
    this.actionDesc = "Timed action started"; // default log marker for test start
};

PTC.performance.Timer.prototype.getElapsedTime = function(){
    return (this.stopTime - this.getStartTime()) / 1000;
};

PTC.performance.Timer.prototype.start = function(){
    this.startTime = new Date().getTime();
    PTC.performance.logger.trace('---restart timer at: ', this.startTime);
};

PTC.performance.Timer.prototype.getStartTime = function() {
    var t = this.startTime;
    if (this.initialWizardLaunch) {
        // if this is the initial wizard load, use the start time from the main
        // window timer that is when the click of the tool-bar action occurred
        if (PTC.lightbox.isLightbox(self)) {
            t = top.PTC.performance.getTimer().startTime;
        } else {
            t = PTC.getMainWindow().PTC.performance.getTimer().startTime;
        }
        PTC.performance.logger.trace('using time off the main window timer: ', t);
    }
    return t;
};

PTC.performance.Timer.prototype.measure = function(){
    this.stopTime = new Date().getTime();
};

/**
 * Explicitly sets ready time for the page on the timer. If called, this overrides
 * ready time calculations. Ready time is displayed on the title bar of the lightbox
 */
PTC.performance.Timer.prototype.setReadyTime = function(){
    this.readyTime = new Date().getTime();
};

PTC.performance.Timer.prototype.getReadyElapsedTime = function(){
    return (this.readyTime - this.getStartTime()) / 1000;
};

PTC.performance.Timer.prototype.getTimeBean = function(timerId){
    var l = this.componentTimeBeans.length;
    var bean;
    for (var i = 0; i < l; i++) {
        if (this.componentTimeBeans[i].timerId === timerId) {
            bean = this.componentTimeBeans[i];
            break;
        }
    }
    return bean;
};

PTC.performance.Timer.prototype.pushTimeBean = function(b){
    this.componentTimeBeans.push(b);
};

/**
 * This is delayedTask method because the rendering can occur multiple times on a page and if the
 * rendering occurs while a component is still rendering, the component gets penalized by the time the
 * performance timer window takes to display.
 */
PTC.performance.Timer.prototype.flushLogs = function(){
   if (!this.renderTask) {
       this.renderTask = new Ext.util.DelayedTask(this._flushLogs);
   }
   this.renderTask.delay(300, null, this);
};
/**
 * Writes the current performance timers to the lightbox and log4j window
 */
PTC.performance.Timer.prototype._flushLogs = function() {
    var basicData = [];
    var addtlData = [];
    var pageReadyTime = -1; // the calculated ready time to be displayed on the light-box title bar
                           // It holds the elapsed time when the last component on the page is ready.

    for (var i = 0, l = this.componentTimeBeans.length; i < l; i++) {
        if (this.componentTimeBeans[i].addtlLogFlag) {
            this.componentTimeBeans[i].addRecords(addtlData);
        } else {
            this.componentTimeBeans[i].addRecords(basicData, addtlData);
        }

        // If 'timer.readyTime' is not set, calculate the ready time from the individual
        // component ready times else just use the 'timer.readyTime'
        if(this.readyTime === undefined) {
            var compReadyTimePer = this.componentTimeBeans[i].getReadyAttrib(); // Time period for the
                                                                                // component to be ready
            if (compReadyTimePer > pageReadyTime) {
                pageReadyTime = compReadyTimePer;
            }
        } else {
            pageReadyTime = this.getReadyElapsedTime();
        }
    }

    var basicStore;
    var addtlStore;
    var timerRef = getWindow().PTC.performance.Timer;
    if (timerRef.enableUI) {
        var chkbox = new Ext.form.Checkbox({
            boxLabel: 'Additional Timers Enabled',
            listeners: {
                'check' : function(chkbox, checked) {
                    PTC.performance.Timer.handleChkBoxEvt(checked, timerDialog);
                }
            }
        });
        if (timerRef.enableAddtl) {
            chkbox.setValue(true);
        }

        var TDStateProvider = new PTC.jca.state.ClientStateProvider();

        var collapsedState = TDStateProvider.get('LBTWinCollapsed');

        if (collapsedState === undefined) {
           TDStateProvider.set('LBTWinCollapsed', false);
           collapsedState = false;
        }
        var timerDialog = new Ext.Window({id: 'timerWindow',
            title: '',
            model: true,
            autoScroll: true,
            collapsible: true,
            expandOnShow: !collapsedState,
            collapsed: collapsedState,
            width: 560,
            height: 205,
            bbar: new Ext.Toolbar({
                width: 560,
                items:[chkbox]
            }),
            listeners: {
                'beforecollapse' : function(){
                    TDStateProvider.set('LBTWinCollapsed', true);
                },
                'beforeexpand' : function(){
                    TDStateProvider.set('LBTWinCollapsed', false);
                }
            }
        });

        var gridTitle = 'Time Measurements [Action started on ' + new Date(this.getStartTime()).format("H:i:s.u") + ']';
        basicStore = PTC.performance.Timer.addGridComp(timerDialog, gridTitle, basicData);

        if (timerRef.enableAddtl) {
            addtlStore = PTC.performance.Timer.addGridComp(timerDialog, 'Additional Time Measurements', addtlData);
        }

        this.refreshTitle(timerDialog, pageReadyTime);
        timerDialog.show();
    }

    if (timerRef.enableLogs) {
        PTC.performance.logAllMessages(basicStore);
        if (timerRef.enableAddtl) {
            PTC.performance.logAllMessages(addtlStore);
        }
        PTC.log.sendAllMessages();
    }
};

PTC.performance.Timer.addGridComp = function(timerDialog, panelTitle, dataToLoad) {
    var store = new Ext.data.GroupingStore({
        reader: new Ext.data.ArrayReader({
            fields: [{name: 'Event'},
                     {name: 'Time'},
                     {name: 'timeBeanId'}]
        }),
        groupField: 'timeBeanId'
    });
    store.loadData(dataToLoad);
    store.filterBy(PTC.performance.filterStoreForUndefined);

    var grid = new Ext.grid.GridPanel({
        groupBy: 'timeBeanId',
        store: store,
        colModel: new Ext.grid.ColumnModel({columns: [{
                id: 'Event',
                header: 'Event',
                width: 160,
                groupable: false
            }, {
                id: 'Time',
                header: 'Time(seconds)',
                width: 160,
                groupable: false
            }, {
                dataIndex: 'timeBeanId',
                header: 'id',
                hidden: true
            }]
        }),
        autoExpandColumn: 'Event',
        height: 'auto',
        autoHeight: true,
        width: 600,
        title: panelTitle,
        view: new Ext.grid.GroupingView({
            //gvalue is the timeBeanId such as "folderBrowser_PDM", "gridContextMenu", "WIZARD" etc.
            groupTextTpl: 'Measurements for {gvalue}'
        })
    });

    timerDialog.add(grid);
    return store;
};

/**
 * Handles the user action on the checkbox to enable additional logging
 * @param {boolean} checked
 * @param {Ext.Window} timerDialog
 */
PTC.performance.Timer.handleChkBoxEvt = function(checked, timerDialog) {
    // Enables the additional logging
    var timerRef = getWindow().PTC.performance.Timer;
    if (timerRef.enableAddtl !== checked) {
       timerRef.enableAddtl = checked;
       PTC.performance.pushToServer(true, timerRef.enableLogs, timerRef.enableAddtl);
    }
};

/**
 * Set the title on timer lightbox window
 */
PTC.performance.Timer.prototype.refreshTitle = function(timerDialog, pageReadyTime) {
    var prefix = "<u>Page Timer</u> -  Ready : ";
    var prefixLog = "Page Timer -  Ready : ";
    var separator = " s  |  Complete : ";
    var suffix = " s";

    var completeTime = (this.stopTime - this.getStartTime())/1000;

    // The page ready time can never remain unset; if it is unset, just use the page complete time
    if (pageReadyTime < 0) {
        pageReadyTime = completeTime;
    }

    timerDialog.titleReadyTime = pageReadyTime;

    var title = (pageReadyTime).toFixed(3) + separator + (completeTime).toFixed(3) + suffix;
    timerDialog.setTitle(prefix + title);

    if (getWindow().PTC.performance.Timer.enableLogs) {
        if (this.actionDesc !== undefined) {
            PTC.performance.logger.debug("Timed activity description : " + this.actionDesc);
            this.actionDesc = undefined; // to avoid redundant entries in the log
        }
        PTC.performance.logger.debug(prefixLog + title);
    }
};

PTC.performance.getTimer = function() {
    var timerRef = getWindow().PTC.performance.Timer;
    if (timerRef.InfoEnabled) {
        var globalTimer = timerRef.GLOBAL_CLICK_TIMER;
        if (!globalTimer) {
            timerRef.GLOBAL_CLICK_TIMER = new PTC.performance.Timer('Navigator_click');
            timerRef.GLOBAL_CLICK_TIMER.start();
            globalTimer = timerRef.GLOBAL_CLICK_TIMER;
        }
        return globalTimer;
    }
};
/**
 * Returns the JSON string for the timer object
 */
PTC.performance.getTimerJSONStr = function() {
    var timerRef = getWindow().PTC.performance.Timer;
    if (timerRef.InfoEnabled) {
        var timerJSON = JSON.stringify(timerRef.GLOBAL_CLICK_TIMER);
        return timerJSON;
    }
};

/**
* Returns a checkpoint time from the timer object
*/
PTC.performance.getTimeMeasureFor = function(componentId, checkpoint) {
    if (getWindow().PTC.performance.Timer.InfoEnabled) {
        var timer = PTC.performance.getTimer();
        var componentTimerBean = timer.getTimeBean(componentId);

        return componentTimerBean.getCheckPointTime(checkpoint);
    }
};

/**
 * restart the timer to make sure measurements are cleared out (for example from step to step in a wizard)
 * otherwise timer lightbox would accumulate all measurements instead of just measurements from last click
 */
PTC.performance.restartTimer = function() {
    if (getWindow().PTC.performance.Timer.InfoEnabled) {
        var timer = PTC.performance.getTimer();
        timer.init();
        timer.start();
        return timer;
    }
};

/**
 * @example
 * PTC.performance.startComponentTimer ('table.foo.bar');
 * PTC.performance.startComponentTimer ('gridContextMenu', 'menu');
 * @param {String} componentId ID or name of the component
 * @param {String} [defaultMessage] optional message for the TimeBean to display instead of 'Time taken since last timer restart'
 * @param {boolean} optional argument. If 'true', all the readings for this timer will be presented in additional logs section.
 *
 * @deprecated use PTC.performance.startTimeGauge instead
 */
PTC.performance.startComponentTimer = function(componentId, defaultMessage, addtlLogFlag){
    return PTC.performance.startTimeGauge(componentId, defaultMessage, addtlLogFlag);
};

/**
 * Wrapper for PTC.performance.startComponentTimer() to match with corresponding stopTimeGauge API.
 * @param {String} scenarioId - it is analogous to componentId and is used for grouping measurements.
 * @param {String} [defaultMessage] optional message for the TimeBean to display instead of 'Time taken since last timer restart'
 * @param {boolean} optional argument. If 'true', all the readings for this timer will be presented in additional logs section.
 */
PTC.performance.startTimeGauge = function(componentId, defaultMessage, addtlLogFlag){
    if(getWindow().PTC.performance.Timer.InfoEnabled) {
        var timer = PTC.performance.getTimer();
        PTC.performance.logger.trace(">START ", componentId, "  defaultMessage:", defaultMessage, " startTime:", timer.startTime);
        var componentTimerBean= timer.getTimeBean(componentId);
        if(!componentTimerBean) {
            componentTimerBean = new PTC.performance.TimeBean(componentId, defaultMessage); // Timer to measure the time required to render empty table.
            timer.pushTimeBean(componentTimerBean);
        } else {
            componentTimerBean.initialize();
        }
        componentTimerBean.start();
        if (addtlLogFlag !== undefined) {
            if (addtlLogFlag) {
                componentTimerBean.addtlLogFlag = true;   // All measurements for this bean will presented in additional section.
            }
        }
    }
    return componentTimerBean;
};

/**
 * Starts a timer for an action contained in a component, such as a sort, or expand.
 * The action timer readings are always displayed in an additional logs section.
 * @param {String} action
 * @param {String} componentId
 *
 * @deprecated use PTC.performance.startTimeGauge instead
 */
PTC.performance.startComponentActionTimer = function(action, componentId){
    if(getWindow().PTC.performance.Timer.InfoEnabled) {
        //this makes sure the global timer is started if not already
        var timer = PTC.performance.getTimer();
        PTC.performance.logger.trace(">START action timer ", componentId, " action: ", action, " startTime:", timer.startTime);

        var componentTimerBean= timer.getTimeBean(componentId);
        if (componentTimerBean) {
            componentTimerBean.startActionTimer(action);
        }
        return componentTimerBean;
    }
};

/**
 * Stops a component timer. Does not support individual measurement redirection to additional logs section;
 * please use PTC.performance.stopTimeGauge() if such functionality is desired.
 * @example
 *   PTC.performance.stopComponentTimer ('table.foo.bar', null,  'firstchunk');
 *   PTC.performance.stopComponentTimer ('gridContextMenu', null,  'menuRendered', 'menu');
 * @param  timerId This would be table Id in case of Table and in case of wizard this will be name of step that is getting load.
 * @param {PTC.performance.TimeBean} [componentTimerBean] optional componentTimerBean object to avoid lookup
 * @param {String} event
 *
 * @deprecated use PTC.performance.stopTimeGauge instead
 */
PTC.performance.stopComponentTimer = function(componentId, componentTimerBean, event){
    if (getWindow().PTC.performance.Timer.InfoEnabled) {
        //flag to avoid flushing logs when its not necessary (page not even done loading anyway)
        var flushLogs = true;
        var timer = PTC.performance.getTimer();
        if (timer && !PTC.isDefined(componentTimerBean)) {
            componentTimerBean = timer.getTimeBean(componentId);
        }
        if (timer && componentTimerBean){
            timer.measure();
            componentTimerBean.measure();
            PTC.performance.logger.trace("<<STOP ", componentId, "  event:", event, " stopTime:", timer.stopTime);
            if (event === 'firstChunk'){
                componentTimerBean.setFirstChunkRenderingTime(timer.getElapsedTime());
                flushLogs = false;
            }
            else if (event === 'dataRendered') {
                if (componentTimerBean.getTotalTableRenderingTime() === undefined) {
                    componentTimerBean.setTotalTableRenderingTime(timer.getElapsedTime());
                }
                else if (componentTimerBean.needsActionTime()) {
                    componentTimerBean.setActionRenderingTime(componentTimerBean.stopTime);
                }
            }
            else if (event === 'emptyTable') {
                componentTimerBean.setEmptyTableRenderingTime(timer.getElapsedTime());
                flushLogs = false;
            }
            else if (event === 'tableResized'){
                if (componentTimerBean.needsActionTime()) {
                    componentTimerBean.setActionRenderingTime(componentTimerBean.stopTime);
                }
            } else if (event === 'rowFocus'){
                if (componentTimerBean.needsActionTime()) {
                    componentTimerBean.setActionRenderingTime(componentTimerBean.stopTime);
                }
            }
            else if (event === 'deltaTime'){
                componentTimerBean.setTimeToRenderFromLastClick(componentTimerBean.getElapsedTime());
            } else {
                //for all other events just record the time taken from last click
                //used for wizard, wizard steps, menu, attribute panel etc.
                componentTimerBean.setTimeToRenderFromLastClick(timer.getElapsedTime());
            }
            if (flushLogs) {
                timer.flushLogs();
            }
        } else {
            PTC.performance.logger.trace("<<STOP called but no timeBean found? ", componentId, "  event:", event, " timeBean: ", componentTimerBean);
        }
    }
};

/**
 * Stops the timer; pairs with PTC.performance.startTimeGauge() API
 * @example
 *   PTC.performance.stopTimeGauge ('DialogPageExt', 'Page Loaded');
 *   PTC.performance.stopTimeGauge ('DialogPageExt', 'Processed init_page', 1);
 * @param  scenarioId - Same as in startTimeGauge, it is analogous to componentId.
 * @param {String} optional checkpoint/event - Identifies a particular point in time while processing
 * @param {boolean} flushLogs - flag to avoid flushing logs when its not necessary
 * @param {Number} time measurement mode
 *                 default/0 -> measure time from last click/action {since the call to PTC.performance.restartTimer())
 *                         1 -> measure time from start of time gauge {since the call to PTC.performance.startTimeGauge())
 * @param {boolean} optional argument. If 'true', this measurement will be presented in additional logs section.
 */
PTC.performance.stopTimeGauge = function(scenarioId, checkpoint, flushLogs, mode, addtlLogFlag){
    if(getWindow().PTC.performance.Timer.InfoEnabled) {
        var timer = PTC.performance.getTimer();
        var componentTimerBean = timer.getTimeBean(scenarioId);
        if(timer && componentTimerBean){
            timer.measure();
            componentTimerBean.measure();
            if (checkpoint === undefined) {
                checkpoint = componentTimerBean.defaultMessage;
            }
            PTC.performance.logger.trace("<<STOP ", scenarioId, "  checkpoint:", checkpoint, " mode 0 Time:", timer.stopTime, " mode 1 Time:", componentTimerBean.stopTime);
            if(mode === 1){
                // measure since the call to PTC.performance.startTimeGauge()
                componentTimerBean.setCheckPointTime(checkpoint, componentTimerBean.getElapsedTime(), addtlLogFlag);
            } else {
                //default - measure since the call to PTC.performance.restartTimer()
                componentTimerBean.setCheckPointTime(checkpoint, timer.getElapsedTime(), addtlLogFlag);
            }
            if (flushLogs) {
                timer.flushLogs();
            }
        } else {
            PTC.performance.logger.trace("<<STOP called but no timeBean found? ", scenarioId, " checkpoint: ", checkpoint);
        }
    }
};


/**
 * @class  TimerBean contains time data on a specific object/component
 * @param {String} timerId
 * @param {String} [defaultMessage] optional default message to override 'Time taken since last timer restart'
 * @internal
 */
PTC.performance.TimeBean = function(timerId, defaultMessage){
    this.timerId = timerId;
    this.defaultMessage = defaultMessage || 'Time taken since last timer restart';
    this.initialize();
};

PTC.performance.TimeBean.prototype.initialize = function(){
    this.timeToRenderFromLastClick = undefined;
    this.emptyTableRenderingTime = undefined;
    this.firstChunkRenderingTime = undefined;
    this.totalTableRenderingTime = undefined;
    this.loadWizardStep = undefined;
    this.loadWizardFromClick = undefined;
    this.startTime = undefined;
    this.stopTime = undefined;
    this.menuRendered = undefined;
    this.actions = []; // array of actions that have occured with id, start, and totalTime attributes
    this.checkpoints = []; // array of checkpoints to support PDSI HTML UI teams requirement
    this.addtlLogFlag = undefined; // undefined => default behaviour; only action measurements in additional logs section
                                   // true => all measurements to display in additional logs section
};

/**
 * Attribute names in the order of preference, that represent its ready time If the value of the attribute is undefined,
 * the next attribute is checked.
 */
PTC.performance.TimeBean.ReadyAttribs = ['firstChunkRenderingTime', 'timeToRenderFromLastClick', 'totalTableRenderingTime'];

/**
 * Retrieves the ready time for the component based on preferred attributes
 */
PTC.performance.TimeBean.prototype.getReadyAttrib = function(){
    for (var attIdx in PTC.performance.TimeBean.ReadyAttribs) {
        if (typeof PTC.performance.TimeBean.ReadyAttribs[attIdx] !== 'function') {
            attr = PTC.performance.TimeBean.ReadyAttribs[attIdx];
            if (this[attr] !== undefined){
                return (this[attr]);
            }
        }
    }
};

/**
 *
 * @param {Array} dataToAdd an array of message data in format [event message, time measurement, component id]
 */
PTC.performance.TimeBean.prototype.addRecords = function(basicData, addtlData) {
    var id = this.timerId;

    if (addtlData === undefined) {
        addtlData = basicData;   // If additional data store is not provided, use the basic data store
    }

    //bunch of table specific measurements
    basicData.push(['Processing Started', this.getProcessingStartTime(), id]);
    basicData.push(['Empty Table Displayed', this.emptyTableRenderingTime, id]);
    basicData.push(['First Chunk Displayed', this.firstChunkRenderingTime, id]);
    basicData.push(['Complete Table Displayed', this.totalTableRenderingTime, id]);

    // time measurements for checkpoints; introduced for HTML UI javascript processing
    if (this.checkpoints) {
        for (var i = 0, il = this.checkpoints.length; i < il; i++) {
            var checkpoint = this.checkpoints[i];
            if (checkpoint.totalActionTime) {
                if (checkpoint.addtlLogFlag) {
                    if (getWindow().PTC.performance.Timer.enableAddtl) {
                        addtlData.push([checkpoint.id, checkpoint.totalActionTime, id]);
                    }
                } else {
                    basicData.push([checkpoint.id, checkpoint.totalActionTime, id]);
                }
            }
        }
    }

    //this default measurement is shared by wizard, wizard step, menu, attribute panel etc.
    basicData.push([this.defaultMessage, this.timeToRenderFromLastClick, id]);

    if (getWindow().PTC.performance.Timer.enableAddtl) {
        // measurements for actions like 'Column Resized'
        if (this.actions) {
            for (var j = 0, jl = this.actions.length; j < jl; j++) {
                var action = this.actions[j];
                if (action.totalActionTime) {
                    addtlData.push([action.id, action.totalActionTime, id]);
                }
            }
        }
    }
};

PTC.performance.TimeBean.prototype.getEmptyTableRenderingTime = function(){
    return this.emptyTableRenderingTime;
};
PTC.performance.TimeBean.prototype.setEmptyTableRenderingTime = function(t){
    this.emptyTableRenderingTime = t;
};
PTC.performance.TimeBean.prototype.getProcessingStartTime = function(){
    var processingStartTime = undefined;
    // Processing start time is shown only for table/tree components
    if (this.emptyTableRenderingTime !== undefined) {
        var timer = PTC.performance.getTimer();
        processingStartTime = (this.startTime - timer.startTime) / 1000;
    }
    return processingStartTime;
};
PTC.performance.TimeBean.prototype.getFirstChunkRenderingTime = function(){
    return this.firstChunkRenderingTime;
};
PTC.performance.TimeBean.prototype.setFirstChunkRenderingTime = function(t){
    this.firstChunkRenderingTime = t;
};
PTC.performance.TimeBean.prototype.getTotalTableRenderingTime = function(){
    return this.totalTableRenderingTime;
};
PTC.performance.TimeBean.prototype.setTotalTableRenderingTime = function(t){
    this.totalTableRenderingTime = t;
};
PTC.performance.TimeBean.prototype.getElapsedTime = function(){
    return (this.stopTime - this.startTime) / 1000;
};
PTC.performance.TimeBean.prototype.setTimeToRenderFromLastClick = function(t){
    this.timeToRenderFromLastClick = t;
};
/**
 * Starts an action specific timer on this component
 * @param {String} action
 */
PTC.performance.TimeBean.prototype.startActionTimer = function(action){
   if (!this.actions) {
       this.actions = [];
   }
   this.actions.push({id:action, startTime:new Date().getTime()});
};

/**
 * Is there an action already in progress?
 * The next rendering time should be applied to the action in progress
 * @param {String} action
 */
PTC.performance.TimeBean.prototype.needsActionTime = function(){
   var foundMissingStop = false;
   if (this.actions) {
       this.actions.each(function(item){
             //Unit tests are fast, total time may be 0!
           if (typeof item.totalActionTime==='undefined') {
               foundMissingStop = true;
           }
       });
   }
   return foundMissingStop;
};
/**
 * The next rendering time should be applied to the action in progress
 * @param {Number} t
 */
PTC.performance.TimeBean.prototype.setActionRenderingTime = function(t){
   this.actions.each( function (item) {
      if (!item.totalActionTime) {
         item.totalActionTime = (t - item.startTime)/1000;
      }
   });
};

/**
* Returns the checkpoint time measurement set on the time bean
* @param {String} checkpoint ID
*/
PTC.performance.TimeBean.prototype.getCheckPointTime = function(checkpoint){
   if (this.checkpoints) {
       var cpl = this.checkpoints.length;
       for (var indx = 0; indx < cpl; indx++) {
           if (this.checkpoints[indx].id === checkpoint) {
               return this.checkpoints[indx].totalActionTime;
           }
       }
   }
};

/**
 * Captures the checkpoint and the time it took to process
 * @param {String} checkpoint description
 * @param {Number} t - time taken to process
 * @param {boolean} alf - flag to indicate if this measurement need to be displayed in additional logs section
 */
PTC.performance.TimeBean.prototype.setCheckPointTime = function(checkpoint, t, alf){
   if (!this.checkpoints) {
       this.checkpoints = [];
   }

   if (alf === undefined) {
       alf = false;
   }

   this.checkpoints.push({id:checkpoint, totalActionTime:t, addtlLogFlag:alf});

};

PTC.performance.TimeBean.prototype.start = function(){
    this.startTime = new Date().getTime();
};

PTC.performance.TimeBean.prototype.measure = function(){
    this.stopTime = new Date().getTime();
};

/**
 * logs the known timers for the a timer/bean
 * @param {Ext.data.Store} store of messages, each record expected to have a field of "Event" and "Time"
 */
PTC.performance.logAllMessages = function(store){
    if (store !== undefined) {
        store.each(function(rec){
            var time = rec.get('Time');
            if (time) {
                var timerId = rec.get('timeBeanId');

                // are the colons necessary here? anyone parsing the logs for this?
                PTC.performance.logger.debug(timerId, ' :: ' + rec.get('Event') + ': ', time);
            }
        });
    }
};

/**
 * Turns on the performance logging
 * Will also tell the server to enable the logging in the session
 * @param {Boolean} enableUI - enables the light-box for displaying the timing data, if true.
 * @param {Boolean} enableLogs - enables the log4javascript logs directed to browser console, if true.
 * @param {Boolean} enableAddtl - enables the additional logs typically useful for debugging, if true.
 * @param {Boolean} pushToServer - pushes the clientLogger as enabled in the session, if true.
 */
PTC.performance.enableClientLogger = function(enableUI, enableLogs, enableAddtl, pushToServer){
    var timerRef = getWindow().PTC.performance.Timer;
    timerRef.InfoEnabled = true;
    timerRef.enableUI = enableUI;
    timerRef.enableLogs = enableLogs;
    timerRef.enableAddtl = enableAddtl;
    var mylogger = log4javascript.getLogger('PTC.performance');
    mylogger.setLevel(log4javascript.Level.DEBUG);
    //start a timer so page refresh time measurements are somewhat accurate
    PTC.performance.getTimer();
    if (pushToServer) {
        PTC.performance.pushToServer(enableUI, enableLogs, enableAddtl);
    }
    PTC.performance.addListeners();
};

PTC.performance.pushToServer = function(enableUI, enableLogs, enableAddtl){
    var doEnable = '';

    if (enableUI) {
        doEnable = 'ui';
    }
    if (enableLogs) {
        doEnable = doEnable + 'log';
    }
    if (enableAddtl) {
        doEnable = doEnable + 'addtl';
    }
    if (!enableUI && !enableLogs) {
        doEnable = false;
    }
    // ignore the response
    var req = new Ajax.Request(getBaseHref() + 'app/?clientLogger=' + doEnable, {
        method: 'get',
        onSuccess: TRUE_FUNC,
        onFailure: TRUE_FUNC
    });
};

/**
 * Allows user to print additional log info. about the action being performed. Can act as a marker to identify
 * the start of a test scenario
 *
 * @param {String} description - Activity description.
 */
PTC.performance.setActionDesc = function(description){
    var timer = PTC.performance.getTimer();
    if (timer) {
        timer.actionDesc = description;
    }
};

/**
 * This method will start the timer and the component timer for Wizard step.
 * This is called from wizard_core.jsfrag - from firstPostLoad() for initial wizard load
 * and also from goNext() or goBack() for when next/back buttons are clicked.
 *
 * @param {String} timerId - id of wizard step
 * @param {boolean} [initialWizardLaunch] - send true if this is the initial wizard launch (false if this is just click of next/back button)
 */
PTC.performance.startWizardTimer = function(timerId, initialWizardLaunch){
    if (getWindow().PTC.performance.Timer.InfoEnabled) {
        if(initialWizardLaunch) {
            //timer for the wizard itself
            PTC.performance.startComponentTimer('WIZARD', 'Wizard Loaded');
            //set this flag so we'll use start time from when the window was launched instead of start time of now
            PTC.performance.getTimer().initialWizardLaunch = true;
        }
        //timer for the wizard step
        PTC.performance.startComponentTimer('WIZ_STEP_' + timerId, 'Step Loaded');
    }
};

PTC.performance.stopWizardTimer = function(stepId) {
    PTC.performance.stopComponentTimer('WIZ_STEP_'+stepId);
};

PTC.performance.stopExpandTimer = function() {
    PTC.performance.stopComponentTimer('expand row');
};

/**
 * Times the expand row action
 * @param {Ext.data.Store} s
 * @param {Ext.data.Record } rec
 */
PTC.performance.expandRowTimerListener = function(s, rec){
    PTC.performance.startComponentTimer('expand row', 'Row Expanded');
    s.on('expandnode',PTC.performance.stopExpandTimer, null, {
        single: true
    });
};

/**
 * Times the expand row action when server call is required
 * @param {Ext.data.Store} s
 * @param {Ext.data.Record } rec
 */
PTC.performance.expandRowServerTimerListener = function(rc, params, tableId){
    var s = Ext.getCmp(tableId).store;
    if(PTC.jca.isAsync(s)){
        s.un('expandnode', PTC.performance.stopExpandTimer);
        s.on('dataSourceComplete', PTC.performance.stopExpandTimer);
    }
};

/**
 * Collapse row timer logic, listener added to tree class
 * @param {Ext.data.Store} s
 * @param {Ext.data.Record } rec
 */
PTC.performance.collapseRowTimerListener = function(s, rec){
    PTC.performance.startComponentTimer('collapse row', 'Row Collapsed');
    s.on('collapsenode', function(){
        PTC.performance.stopComponentTimer('collapse row');
    }, null, {
        single: true
    });
};
/**
 * Allows user to explicitly set ready time for the page on the timer.
 * Alternately 'pageReady' event may be fired.
 */
PTC.performance.setPageReady = function() {
    var timer = PTC.performance.getTimer();
    if (timer) {
        timer.setReadyTime();
    }
};

/**
 * Handles 'pageReady' event : sets the ready time for the page on the timer.
 */
PTC.performance.handleReadyEvent = function() {
    if (getWindow().PTC.performance.Timer.InfoEnabled) {
        var timer = PTC.performance.getTimer();
        if (timer) {
            timer.setReadyTime();
        }
    }
};

/**
 * Adds listeners for performance data collection
 */
PTC.performance.addListeners = function(){
    //intent is to restart the timer every time we 'click'
    //this will reset the start time and clear out any TimeBeans
    //listening to 'mousedown' instead of 'click' event as a way to ensure the timer is restarted
    //prior to startComponentTimer() calls happening from click listeners (no way to guarantee order of click listeners)
    Event.observe(window.document, 'mousedown', function() {PTC.performance.restartTimer();});

    PTC.performance.on('pageReady', PTC.performance.handleReadyEvent);

    Ext.util.Observable.observeClass(Ext.grid.GridPanel);
    // right click actions menu
    Ext.grid.GridPanel.on('rowcontextmenu', function(){
        // HACK - should be fixed if we intend to use selenium for gathering perf data
        // 'mousedown' listener from above is not working for selenium, so needed to explicitly restart timer here. Not ideal.
        PTC.performance.restartTimer();
        PTC.performance.startComponentTimer('gridRowContextMenu', 'Menu Displayed');
    });

    // other menus such as recently accessed & quicklinks etc.
    // the quicklinks menu does not record after the first click, known issue.
    PTC.menu.on("dynamicMenuShow", function(button, menu){
        // HACK - should be fixed if we intend to use selenium for gathering perf data
        // 'mousedown' listener from above is not working for selenium, so needed to explicitly restart timer here. Not ideal.
        PTC.performance.restartTimer();
        PTC.performance.startComponentTimer(button.id, 'Menu Displayed');
        menu.idForPerfLogger = button.id;
    });

    //stop the timers once the wizard is done loading, this is just for initial wizard load
    //the timers for next/back button clicks are stopped in wizard_core.jsfrag stopProgress()
    PTC.wizard.on('wizardLoadComplete', function(){
        PTC.performance.stopComponentTimer('WIZARD');
        PTC.performance.stopWizardTimer(getCurrentStep());
    });

    PTC.menu.on("dynamicMenuLoad", function(menu){
        var id = menu.idForPerfLogger ? menu.idForPerfLogger : menu.id;
        PTC.performance.stopComponentTimer(id);
    });

    // attribute panel
    PTC.attributePanel.on("beforeRender", function(panel) {
        PTC.performance.startComponentTimer(panel.id, 'Attribute Panel Displayed');
        panel.on("afterrender", function(panel) {
            PTC.performance.stopComponentTimer(panel.id);
        });
    });

    // Grab all events of certain classes to keep track of action times.
    PTC.performance.addTreeTimerListeners(Ext.ux.maximgb.tg.AdjacencyListStore,PTC.jca.DataSourceTreePagingStore);
    PTC.performance.addScrollTimerListeners();
};
/**
 * add Tree listeners for expand/collapse to all the classes passed in as arguments
 */
PTC.performance.addTreeTimerListeners = function() {
   for (var i = 0, l = arguments.length; i < l; i++) {
       var treeClass = arguments[i];
       Ext.util.Observable.observeClass(treeClass);
       treeClass.on('beforecollapsenode', PTC.performance.collapseRowTimerListener);
       treeClass.on('beforeexpandnode', PTC.performance.expandRowTimerListener);
       PTC.jca.tree.on('beforeexpandnodeserver', PTC.performance.expandRowServerTimerListener);
   }
};
/**
 * Re-usable doUpdate wrapper to capture scroll to rendering times
 * @param {Function} proceed - original doUpdate function
 */
PTC.performance.tableScrollWrapper = function(proceed,a,b,c){
    var result = proceed.call(this,a,b,c);
    var perfRef = getWindow().PTC.performance;
    if (perfRef.Timer.InfoEnabled && perfRef.tableScrollWrapper._isScrolling) {
        PTC.performance.stopComponentTimer('scroll', null, 'deltaTime');
        perfRef.tableScrollWrapper._isScrolling = false;
    }
    return result;
};
/**
 * Add the necessary events to capture the table scroll down times
 */
PTC.performance.addScrollTimerListeners = function(){
    var perfRef = getWindow().PTC.performance;
    Ext.grid.GridPanel.on('bodyscroll', function(){
        if (perfRef.Timer.InfoEnabled) {
            perfRef.tableScrollWrapper._isScrolling = true;
            PTC.performance.startComponentTimer('scroll', 'Scroll Updated');
        }
    });

    Ext.ux.grid.LockingGridView.prototype.doUpdate = Ext.ux.grid.LockingGridView.prototype.doUpdate.wrap(PTC.performance.tableScrollWrapper);
    Ext.ux.grid.BufferView.prototype.doUpdate = Ext.ux.grid.BufferView.prototype.doUpdate.wrap(PTC.performance.tableScrollWrapper);
};


/** @namespace
* namespace for picker
**/
var searchPicker = new function() {
	this.clickedBtnId = null;
	
	this.setClickedBtnId = function(btnId){
		searchPicker.clickedBtnId = btnId;
	}
	
};


/**
* Object type pickerValidator
**/
function PickerValidator(argSuggestParams) {

	var suggestParams = argSuggestParams;
	var hasFocus = false;
	var validator = this;  // self reference for setTimeout call
	var field = $(suggestParams.suggestId);
	var launchingPicker = false;
	var btnId = null;

	this.setup = function() {
		Event.observe( field, "focus", this.handleOnFocus);           
		Event.observe( field, "blur", this.handleOnBlur);
		validator.setBtnId();
	};

	this.handleOnFocus = function () {
		hasFocus = true;
	};

	this.handleOnBlur = function () {
		hasFocus = false;
		if(launchingPicker == true) { 
			launchingPicker=false; // reset
			return; 
		}
		// 1. check focus after half a second to allow clicking on suggestion value
		// 2. cannot use this in bleow setTimeout, so using closure with self reference
		// 3. Delayed execution also gives chance for other events to execute first. 
		//	Picker button's onClick should execute before below btn clicked check.
		setTimeout(function() { validator.checkFocusAndValidate(); },600);
	};

	this.checkFocusAndValidate = function () {
	
		// check to see of picker btn was clicked
		if(btnId == searchPicker.clickedBtnId) {		
			// picker button was clicked
			searchPicker.clickedBtnId = ''; // reset		
			return;
		}
		if(!hasFocus) {
			validator.validatePicker();
		}    			
	};

	this.validatePicker = function () {
		var fieldValue = field.value;
		if(fieldValue!=null && fieldValue.trim().length > 0) {  // there is some text in field
			var hiddenFieldId = suggestParams.suggestId + "Hidden";
			var hiddenValue = $(hiddenFieldId).value;
			if(hiddenValue==null || hiddenValue.length == 0 ) {  // and hidden value is not set.
				document.body.style.cursor = 'wait'; // show hour glass
				validator.validateAjax();
			}
		}
	};
			
	this.validateAjax = function () {
		// set suggestable value from field
		var parameters = suggestParams.options.parameters;
		parameters = removeParamFromString( "suggestable", '?' + parameters);
		parameters = parameters + '&suggestable=' + field.value;
		
		// make AJAX request
		new Ajax.Request('servlet/SuggestServlet',
			{     method:'post',     
				parameters:parameters,
				onSuccess: validator.handleResults,
				onFailure: validator.handleError  
			}
		);
	};
		
		
	this.handleError = function(){
		// in case of error, reset field.
		document.body.style.cursor = 'auto'; // reset cursor
		field.value = "";
	}
	
	/**
	* Handle AJAX call response. Set results Div.
	*/
	this.handleResults = function(response) {
		if (200 != response.status){
			validator.handleError();
			return;
		}
		var responseText = response.responseText;
		$(suggestParams.suggestId+"Results").innerHTML = responseText;
		validator.checkResultsDiv();
	}
	
	/**
	* Validate results div
	*/
	this.checkResultsDiv = function () {
		var list = $(suggestParams.suggestId+"Results").getElementsByTagName('li');
		node = list[0];
				
		var isLaunchPicker = true;
		if(list.length == 1) {
			isLaunchPicker = false;
			var displayValue = node.firstChild.nodeValue;
			//var valueNodes = node.getElementsByClassName("informal value ");
			var valueNodes = Element.select(node, '.value');
			var value = valueNodes[0].innerHTML.trim();
						
			if(value==null || value=='') { isLaunchPicker = true; }
			else {
				field.value = displayValue;
				validator.setPickerHiddenFields();
			}
		}
		document.body.style.cursor = 'auto'; // reset cursor
		
		if(isLaunchPicker) {
			validator.setFocus();
			validator.launchPicker();
			validator.clearPicker();
		}
		
	};
	
	/*
	* sets picker hidden fields using autoSuggestHandler
	*/
	this.setPickerHiddenFields = function (node) {
		autoSuggestHandler.moveSuggestValue(field, node);
	}
	
	/*
	* Launches picker popup.
	*
	* TODO: Browser popup blocker blocks this lauch. Need to use onClick event. However there is no such event for link.
	*/
	this.launchPicker = function () {	
		launchingPicker = true;
		
		var btnHref = $(btnId).href;
		var launchScript = unescape(btnHref.substring("javascript:".length));
				
		eval(launchScript);
						
	};
	
	this.setBtnId = function() {
		var indxLabel = suggestParams.suggestId.indexOf('$label$');
		var pickerId = suggestParams.suggestId.substring(0, indxLabel);		
		btnId = pickerId+'_FIND_BTN';
	}
	
	/*
	* Sets focus on picker input field.
	*/
	this.setFocus = function() {
		field.focus();
		field.value= field.value;
	};

	/*
	* Sets focus on picker input field.
	*/
	this.clearPicker = function() {
		field.value = '';
	};
		
}

/**
 * Callback function for the type picker wizard launched by the picker component
 * in the type preference handler.  Populates the display names to the visible
 * field and the windchill type names to the appropriate hidden field
 */
TypePickerPreferenceCallback = function(pickerObject, fieldId, fieldTEId) {
    var pickedObjects = pickerObject.pickedObjects;
    var internalFieldToUpdate = $(fieldId);
    var displayFieldToUpdate = $(fieldTEId);
    var newInternalValue = '';
    var newDisplayValue = '';
    for (var i = 0, l = pickedObjects.length; i < l; i++) {
        var theType = pickedObjects[i].theType;
        if ((theType.indexOf("|") > 0) && (theType.indexOf("WCTYPE") == -1)) {
            theType = "WCTYPE|" + theType;
        }
        newInternalValue += theType + ',';
        newDisplayValue += pickedObjects[i].unencodedType + ', ';
    }
    newInternalValue = newInternalValue.substring(0, newInternalValue.length - 1);
    newDisplayValue = newDisplayValue.substring(0, newDisplayValue.length - 2);
    internalFieldToUpdate.value = newInternalValue;
    displayFieldToUpdate.value = newDisplayValue;
}


/**
 * @internal
 * @namespace for functionality related to progress bars
 */
PTC.progressBar = {};

/**
 * The cell data is expected to be in one of three forms: a valid progress bar, progress bar with errors,
 * or a blank/missing value.
 *
 * A valid progress bar config has the following properties:
 *   comparable (a numeric value)
 *   tooltip (a string)
 *   percentComplete (a value nominally between 0.0 and 1.0)
 *
 * A progress bar with errors has the following properties:
 *   comparable (a very small numeric value)
 *   tooltip (a string)
 *   errorTag (a string for the table cell)
 *   errorMsgs (an list of strings for the tooltip)
 *
 * A blank/missing value has the following properties:
 *   comparable (a very large numeric value)
 *
 * @table a table or an attribute panel
 * @column a column of the table, or object representing a 'column' of the attribute panel
 * @row a row of the table, or object representing a 'row' of the attribute panel
 */
PTC.progressBar.renderer = function(table, column, row) {
    try {
        var data = jsca.columns.getCellValue(column, row);
    }
    catch (e) {
        jsca.log("no data item found for column id " + column.id);
    }
    return PTC.progressBar.renderer.getHTML(data);
};

/**
 * renderer shared by JCA and GWT
 * @param data is the cell value (see jsdoc on PTC.progressBar.renderer for expected cell data values)
 */
PTC.progressBar.renderer.getHTML = function(data) {
    var result = '';
    try {
        if (!data) {
            var msg = "no progress bar data found";
            var tipText = PTC.util.HTMLEncoder.encodeForHTMLAttribute(msg);
            var errorLabel = bundleHandler.get('com.ptc.core.ui.componentRB.PROGRESS_BAR_ERROR');
            return PTC.progressBar.styleAsError(errorLabel, tipText);
        }

        // display any generic error message from the server data utility or rendering process
        if (typeof data  === "string" || data instanceof String) {
            // There was a problem with the server data utility or renderer.
            // Display whatever the server sent.
            return data;
        }

        var tooltip = PTC.progressBar.getTooltip(data, true);
        // "ext:qtip" is for ExtJS, "qtip" is for GWT
        var tooltipHTML = ' ext:qtipencode=false ext:qtip="'+tooltip+'" qtip="'+tooltip+'"';

        if (data.errorTag) {
            // display text sent from the server rather than progress bar,
            // it will be plain text intead of styled as bold,red error text
            var message = PTC.util.HTMLEncoder.encodeForHTMLContent(data.errorTag);
            result = '<span'+tooltipHTML+'>'+message+'</span>';
        } else if (data.percentComplete === undefined) {
            // no value was defined on the server, display whitespace on the client
            result = '&nbsp;';
        } else if ((0 <= data.percentComplete) && (data.percentComplete <= 1.0)) {
            // a normal, in-range progress bar!
            result = '<progress value="'+data.percentComplete+'" max="1"'+tooltipHTML+'></progress>';
        } else if (data.percentComplete < 0) {
            // add end marker for out of range value plus style class to change border/font to red
            // prefix the bar with "<<"  (could use double-less-than '&#8810;' or '&lt;&lt;')
            result = '&#8810; <progress class="progress-error" value="'+data.percentComplete
                     + '" max="1"'+tooltipHTML+'></progress>';
            result = PTC.progressBar.styleAsError(result, tooltip);
        } else { // (data.percentComplete > 1.0)
            // add end marker for out of range value plus style class to change border/font to red
            // suffix the bar with ">>"  (could use double-greater-than: &#8811; or '&gt;&gt;')
            result = '<progress class="progress-error" value="'+data.percentComplete
                     + '" max="1"'+tooltipHTML+'></progress> &#8811;';
            result = PTC.progressBar.styleAsError(result, tooltip);
        }
    }
    catch (e) {
        jsca.log("error creating rendered HTML from data json: " + data);
    }
    return result;
};

/**
 * Wrap up the given text in span with tooltip that allows newlines and error style class.
 * @param {string} text is a message or some progress bar html to style as an error. Expected to already be encoded to use as html content.
 * @param {string} [tooltip] optional tooltip to add to the wrapping element. Expected to already be encoded to use as html content.
 * @return {string} the given text wrapped inside span styled to display as error text (red/bold)
 *                      and with ext qtip tooltip that can properly display the error messages on multiple lines.
 */
PTC.progressBar.styleAsError = function(text, tooltip) {
    var tooltipHTML = tooltip ? ' ext:qtipencode=false ext:qtip="'+tooltip+'" qtip="'+tooltip+'"' : '';
    return '<span class="progress-error"'+tooltipHTML+'>'+text+'</span>';
};

/**
 * @param {object} data the progress bar cell whose tooltip is to be returned
 * @param {boolean} encoded indicates whether the result should be encoded for embedding as qtip in HTML content
 * @return {string} the full tooltip for the specified progress bar cell, including any error messages
 */
PTC.progressBar.getTooltip = function(data, encoded) {
    var tooltip = '';
    if (data) {
        if (data.tooltip) {
            if (encoded) {
                tooltip = PTC.util.HTMLEncoder.encodeForHTMLAttribute(data.tooltip);
            } else {
                tooltip = data.tooltip;
            }
        }

        // Include any server-detected errors
        var errors = data.errorMsgs;
        if (errors && errors.length > 0) {
            var i;
            for (i = 0; i < data.errorMsgs.length; i++) {
                if (encoded) {
                    if (tooltip.length > 0) {
                        tooltip += "<br>";
                    }
                    tooltip += PTC.util.HTMLEncoder.encodeForHTMLAttribute(errors[i]);
                } else {
                    tooltip += " " + errors[i];
                }
            }
        }
    }

    if (tooltip.length <= 0) {
        tooltip = " ";
    } else if(encoded) {
        // The tooltip text must be double encoded to produce the desired text since Ext decodes the qtip.
        // The <br>s will still take effect because Ext decodes the text.
        tooltip = PTC.util.HTMLEncoder.encodeForHTMLAttribute(tooltip);
    }
    return tooltip;
};

/** export the tooltip */
PTC.progressBar.renderer.exportRenderer = function(table, column, row) {
    // get the data from the cell value
    var data = jsca.columns.getCellValue(column, row);
    // get the value to export
    var exportText = PTC.progressBar.renderer.exportRendererForGWT(data);
    return exportText;
};

/**
 * @function the export renderer for GWT tables
 */
PTC.progressBar.renderer.exportRendererForGWT = function(data) {
    var result = '';
    if (data) {
        // display any generic error message from the server data utility or rendering process
        if (typeof data  === "string" || data instanceof String) {
            // There was a problem with the server data utility or renderer.
            // Display whatever the server sent.
            return data;
        }
        // the value we want to export is just the tooltip
        result = PTC.progressBar.getTooltip(data, false);
    }
    return result;
};

/** search/filter progressbar by tooltip */
PTC.progressBar.renderer.searchFunc = function(table, column, row) {
    var data = jsca.columns.getCellValue(column, row);
    var tooltip = PTC.progressBar.getTooltip(data, false);
    if (data && data.errorTag) {
        // for searching, include the "Error" tag displayed in the table cell
        tooltip += " " + data.errorTag;
    }
    return tooltip;
};


/** group by percentComplete in 10% increments */
// Note: the column-level groupFunc() must return a string.
// Otherwise, the value is ignored by PTC.jca.groupingRenderer.
PTC.progressBar.renderer.groupFunc = function(table, column, row) {
    var data = jsca.columns.getCellValue(column, row);
    if (data && data.errorTag) {
        return "" + data.errorTag;  // the table cell "error" tag
    }
    var pct = data ? data.percentComplete : undefined;
    if (pct === undefined) {
        var noneLabel = bundleHandler.get('com.ptc.core.ui.componentRB.PROGRESS_BAR_NONE_GROUP_LABEL');
        return noneLabel;
    }
    var groupSize = 10;
    var groupBase = Math.floor(pct * 100 / groupSize) * groupSize;
    var groupLabel = bundleHandler.getBundleStringAndInserts('com.ptc.core.ui.componentRB.PROGRESS_BAR_GROUP_LABEL',
                                                             [groupBase, (groupBase + groupSize)]);
    return groupLabel;
};


/*
* This is a PTC's custiomized progressbar using Ext Progres bar. progress bar component. 
* This prograssbar has three components 1. Step label 2. Progress Bar 3. Percentage Label.
* This progressbar can be updated via it's 'update' method.
*/

Ext.namespace('PTC');
PTC.Progressbar = function(renderToId) {

    Ext.util.CSS.createStyleSheet('.pbarLabel {text-align:right; height:10px;}');
    Ext.util.CSS.createStyleSheet('.statusLabel {text-align:left; height:10px;}');
    var statusLabel = bundleHandler.get('com.ptc.core.htmlcomp.htmlcompResource.STATUS_LABEL');
    var topLabelCtrl = new Ext.form.Label({
        cellCls: 'pbarLabel',
        text: '',
        colspan:'2'
    });
    var statusLabelCtrl = new Ext.form.Label({
        cellCls: 'statusLabel'
    });
    var progressBarCtrl = new Ext.ProgressBar({
        width: 300,
        colspan: '2'
    });

    var bottomLabelCtrl = new Ext.form.Label({
        cellCls: 'pbarLabel'
    });
  
    var innerContainer = new Ext.Container({
        layout: 'table',
        layoutConfig: { columns:2 },
        style: {margin: '10px'},
        items: [
          topLabelCtrl,
          progressBarCtrl,
          statusLabelCtrl,
          bottomLabelCtrl
          ]
        });

    var mainContainer = new Ext.Container({
        renderTo: renderToId,
        layout: 'table',
        layoutConfig: {
        columns: 1
        },
        style: {borderColor:'#6495ED', width:'320px', borderStyle:'solid', borderWidth:'1px', position:'relative',margin:'auto', top:'50%', 'margin-top':'-30px'}
      });

    mainContainer.add(innerContainer);
    mainContainer.doLayout();
    
    // Fix SPR 2216797: Set status label with 'update' because if status label is set by constructor the encoded characters like &quot; is not decoded.
    statusLabelCtrl.update(statusLabel);

     return {
  	/*
	* update method has two parameters - 'topLabel' and other is 'percentage'. 
	* topLabel is dispalyed as it is. The percentage is used to Update the Ext progrssbar.
	* percentageLabel is build up using 'percentage' parameter and shown at the bottom of progressbar
	*/
       update: function (topLabel,percentage){
        var percentageLabel = bundleHandler.get('com.ptc.core.htmlcomp.htmlcompResource.PERCENTAGE_COMPLETED');
        percentageLabel = percentageLabel.replace("{0}",percentage);
        topLabelCtrl.update(topLabel);
        bottomLabelCtrl.update(percentageLabel);
        progressBarCtrl.updateProgress(percentage/100, '');
     },
     /*
       erase the progress bar from its container
     */
     remove: function () {
         mainContainer.destroy();
     }
  };
};



function createLocationValidation(evt) {
	var sels = getSelectedItems();
	if(sels.length > 1){
		JCAAlert("com.ptc.projectmanagement.plannable.plannableResource.MULTIPLE_TASKS_SELECTED_ERROR");      
		return false;
	}
	if(sels[0])
	{
		var normalizedOid = normalizeForTree(sels[0].value);	
		if (isPlan(normalizedOid)) {
		    JCAAlert("com.ptc.projectmanagement.plannable.plannableResource.INVALID_LOCATION_PLAN_SELECTED");
		    return false;
		}
	}
	return true;
}    

function normalizeForTree (oidString) {
   var result = null;
   if (oidString && oidString.indexOf) {
      var startIdx = oidString.lastIndexOf('$');
      if (startIdx != -1) {
         var caretIdx = oidString.lastIndexOf('^');
         if (caretIdx != -1) {
            startIdx = caretIdx;
         }
         startIdx++;
         var endIdx = oidString.indexOf('!*', startIdx);
         if (endIdx == -1) {
            endIdx = oidString.length;
         }
         result = oidString.substring(startIdx,endIdx);
      }
      else {
         result = oidString;
      }
   }
   return result;
}



