Ext.namespace('PTC.search.AttributeLightbox');

PTC.search.AttributeLightbox.attributeCallBackFunction=function ()
{

	//get index of launching group.
	var groupIdValue = document.getElementById("groupId").value;

	//get groups in query builder.
	var nggroupEle =  window.parent.document.getElementById("nggroup"+groupIdValue);;

	//find parent element where angular scope is linked.
	var parentFound = false;
    var parent = nggroupEle;

	//selectedOidsArray contains all the selectedRows.
	var selections = tableUtils.getTable('search.querybuilder.attrtable').getSelectionModel().getSelections();
	var len = selections.length;
	var isChecked= false;
	for (var i = 0; i < len; i++)
	{
		var oid = selections[i].get('oid');
		if (oid) {
			isChecked = true;
			while(!parentFound) {
				parent = parent.up();
				if(!parent) break;
				if(parent.angularScope) {
					parentFound = true;
				}
			}
			if(parent) {
				var groupScope = parent.angularScope;
				groupScope.addMultipleConditions(groupScope,oid);
				parent.angularScope.$apply();
			}
		}else {
			// log an error but do not blow up if row not found
			PTC.log.error('no row found in the  table with the context: ' + selectedOidsArray[i].value);
		}
	}
	if (!isChecked) {
			JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.ATTRIBUTE_LIGHTBOX_ALERT_MESSAGE");
			return false;
	}else{
		closeAttributeLightBox();
	}
	return true;
}

function closeAttributeLightBox(){
	PTC.lightbox.deactivate({lbWindow: self});
}




/**
* Radio Button Group Renderer
* Calls the radio button renderer for rendering each radio button.
*/
jsca.columns.radioButtonGroupRenderer = function(table,column,row) {
    var result = '';
    var data = jsca.columns.getCellValue(column, row);

    var buttons = data.radioButtons;
    // HTML names of radio buttons in different groups must be different, ignoring case.
    // See RadioButtonGroupRenderer for fix that was made for spr 2184720.  That fix
    // has not been applied in this method yet as it was unclear whether it was needed.       
    if (buttons) {
        for (var i = 0, l = buttons.length; i < l; i++) {
            result += jsca.columns._radioButtonRenderer(buttons[i]);
            result += '<br />';
        }
    }
 
    if(data.id) {
        result = '<span id="'+data.id+'">'+result+'</span>';
    }
    result = result + jsca.columns.getHiddenInputs(data.hiddenData);
    return result;
};

/**
 * Radio Button Renderer
 */
jsca.columns.radioButtonRenderer = function(table,column,row) {
    var data = jsca.columns.getCellValue(column, row);
    return jsca.columns._radioButtonRenderer(data);
};

/**
 * Internal renderer that is common with grouping renderer
 * @param data - Gui data object for a single button
 * @return {String} html for the button
 * @private
 */
jsca.columns._radioButtonRenderer = function (data) {
    var result = '';
    if (data.checked && data.enabled) {
        if(data.origOldValues === undefined){
            data.origOldValues = "<input type=\"hidden\" "
                  + (data.id ? jsca.columns.idStr(data.id + jsca.columns.OLDSTR) : '')
                  + jsca.columns.nameStr(data.name + jsca.columns.OLDSTR)
                  + jsca.columns.valueStr(data.value) + "/>";
        }
        result += data.origOldValues;
    }

    if(data.enabled) {
        result += ((data.renderLabel && !data.renderLabelOnRight) ? data.label : "" )
            + "<input "+ jsca.columns.idStr(data.id) + "type=\"radio\" "
            + jsca.columns.nameStr(data.name)
            + (data.disabled ? 'disabled ' : '');
        if (data.tooltip) {
            result += jsca.columns.tooltipStr(data.tooltip);
        }

        result += data.jsActions;

        result += jsca.columns.valueStr(data.value)
            + (data.checked ? 'checked ' : '')
            + data.styleClasses + "/>"
            + (( data.renderLabel && data.renderLabelOnRight) ? data.label : "" );

    } else {

        if (data.checked) {
            result += "<img src=\"" + data.checkedGif + "\" hspace=0 vspace=0 border=0 height=13 width=13> ";
        }
        else {
            result += "<img src=\"" + data.uncheckedGif + "\" hspace=0 vspace=0 border=0 height=23 width=16>";
        }
    }

    result = result + jsca.columns.getHiddenInputs(data.hiddenData);
    return result;
};

