/* Function to launch Define Mapping window
 */
PTC.receivedDelivery.launchDefineMapping=function(rdOID,context,soid){
	if (navigator.appName.indexOf("Microsoft")==-1) {
		windefineMapping=window.open('ptc1/fedInfraUI/defineMapping?&wizardActionClass=com.ptc.windchill.fedInfra.mapping.forms.DefineMappingTableFormProcessor&portlet=poppedup&wizardActionMethod=execute&oid='+rdOID+'&context='+context+'&soid='+soid,
										null,'resizable=yes,scrollbars=yes,menubar=no,toolbar=no,location=no,status=yes,left=50,top=50,height=650,width=1000');
	}
	else{
	windefineMapping=window.open('../fedInfraUI/defineMapping?&wizardActionClass=com.ptc.windchill.fedInfra.mapping.forms.DefineMappingTableFormProcessor&portlet=poppedup&wizardActionMethod=execute&oid='+rdOID+'&context='+context+'&soid='+soid,
										null,'resizable=yes,scrollbars=yes,menubar=no,toolbar=no,location=no,status=yes,left=50,top=50,height=650,width=1000');
	}

};

/* Function to close Define Mapping and Preview Mapping UI on click of OK Button
 */
PTC.receivedDelivery.onOKClickCloseDefineMapping=function() {
	if(windefineMapping){
	    // SPR 6604536 Edge specific condtion as windefineMapping.open is not working in EDGE browser
		if(navigator.userAgent.indexOf("Edge") != -1){
			if(!windefineMapping.closed){
				windefineMapping.close();
			}
		}
		else if(windefineMapping.open && !windefineMapping.closed){
			windefineMapping.close();
		}
	}
	window.close();
};

PTC.receivedDelivery.validateSelection=function(evt,action){
    var sels = PTC.jca.table.Utils.getSelectedItmesByEvent(evt);
    var alength = sels.length;
    if( sels.length === 0 && action != 'VIEWIMPORTLOG') {
        JCAAlert("com.ptc.netmarkets.util.utilResource.NONE_CHECKED");
        Event.stop(evt);
        return false;
    }
    if( sels ) {
        if(alength != 1) {
        	if(action == 'PREVIEW') {
        		JCAAlert("com.ptc.windchill.rd.receivedDeliveryResource.RD_TABLE_PREVIEW_ACTION_SELECTED_ALERT");
            	return false;
        	}
        	else if(action == 'IMPORT'){
            	JCAAlert("com.ptc.windchill.rd.receivedDeliveryResource.RD_TABLE_PREVIEW_ACTION_SELECTED_ALERT");
            	return false;
            }else if(action == 'REPREPAREFILES'){
	        JCAAlert("com.ptc.windchill.rd.receivedDeliveryResource.RD_TABLE_REPREPARE_ACTION_SELECTED_ALERT");
            	return false;
	    }

        }
    }
    return true;
};


