//Namespace for the javascript
Ext.namespace('PTC.search.teaser');

/*
 * Define Global variables
 */
PTC.search.teaser.contentPane = 'PTC.search.teaser_centerContentPane';
PTC.search.teaser.url = 'ptc1/getteaser/highlightContent';
PTC.search.teaser.delayedShow = new Ext.util.DelayedTask();

PTC.search.teaser.delayedClose = new Ext.util.DelayedTask(function() {
	PTC.search.teaser.win.hide();
});

PTC.search.teaser.defaultHideDelay = -1;

/*
 * Method to show teaser which is called on mouseover of teaser column in Result
 * Search Table
 */
PTC.search.teaser.showTeaser = function(keyword, objectId, name, number, mouseEvent,
		delay) {

	// make default show flyout delay 0.5 second
	delay = 500;
	PTC.search.teaser.cancelled = false;
	var targetObject = mouseEvent.target || mouseEvent.srcElement;
	PTC.search.teaser.delayedShow.delay(delay, PTC.search.teaser.show,
			null, [ keyword, objectId, name, number, targetObject, mouseEvent ]);

};

/*
 * Method to cancel teaser which is called on mouseout of teaser column in
 * Result Search Table
 */
PTC.search.teaser.cancelTeaser = function(hideDelay) {

	if (hideDelay === undefined) {
		PTC.search.teaser.defaultHideDelay = 500;
	} else if (hideDelay !== PTC.search.teaser.defaultHideDelay) {
		PTC.search.teaser.defaultHideDelay = hideDelay;
	}
	PTC.search.teaser.delayedShow.cancel();
	PTC.search.teaser.cancelled = true;
};

/*
 * Makes an Ajax request to populate the Teaser. Also sets an event to
 * close the teaser after a short bit upon mousing off of the target DOM object.
 * This delayed close is canceled when mousing into the teaser.
 */
PTC.search.teaser.show = function(keyword, objectId,name, number, targetObject, event) {

	if (!PTC.search.teaser.win) {

		
		PTC.search.teaser.win = new Ext.Window({
			header : false,
			title : bundleHandler.get('com.ptc.windchill.enterprise.search.client.searchClientResource.TEASER_LABEL'),
			id : 'PTC.search.teaserWindow',
			cls : 'PTC.search.teaserWindowStyle',
			width : 400,
			autoHeight : true,
			shadow : true,
			shadowOffset : 6,
			plain : true,
			draggable : false,
			closable : false,
			resizable : false,
			items : new Ext.Panel({
				id : 'PTC.search.teaser_centerContentPanel',				
				style : 'margin : 5px',
				html : '<div id="' + PTC.search.teaser.contentPane+ '"></div>'
			})
		});
		PTC.search.teaser.win.on('resize', function() {
			PTC.search.teaser.win.syncShadow();
		}, this, {
			delay : 2
		});
		PTC.search.teaser.win.on('move', function() {
			PTC.search.teaser.win.syncShadow();
		}, this, {
			delay : 2
		});
		PTC.search.teaser.win.on('show', function() {
			PTC.search.teaser.win.syncShadow();
		}, this, {
			delay : 2
		});
	}

	Ext.fly(targetObject).on(
			'mouseout',
			function() {
				PTC.search.teaser.delayedClose.delay(PTC.search.teaser.defaultHideDelay);
			}, this, {
				single : true
			});
	
	//Parameters which needs to be passed to teaserController
	var params = "keyword=" + encodeURIComponent(keyword) + "&objectId="+ encodeURIComponent(objectId) + "&name="+ encodeURIComponent(name)+"&number="+ encodeURIComponent(number);
	
	PTC.navigation.addOpenRequest(getElementHtml(params,
			'PTC.search.teaser_centerContentPane', true,PTC.search.teaser.url, false,
			function(response) {
				//alert(response);
				PTC.navigation.onSuccessRequest(response);
				PTC.search.teaser.delayedClose.cancel(); // Might still be a delayed job to close the previous one
				
				if (!PTC.search.teaser.cancelled) {

					// reposition window after totally rendered if necessary
					PTC.search.teaser.win.on('show', function() {
						
						var dx = Ext.EventObject.getPageX();
						var dy = Ext.EventObject.getPageY();
						var iwHeight = 0;

						if (window.innerHeight) {
							iwHeight = window.innerHeight;
						} else if (document.documentElement
								&& document.documentElement.clientHeight) {
							iwHeight = document.documentElement.clientHeight;
						} else if (document.body) {
							iwHeight = document.body.clientHeight;
						}

						var wy = window.screenY;
						var foHeight = PTC.search.teaser.win.getHeight();
						var shift = 0;

						if (iwHeight < foHeight + dy) {
							shift = (foHeight + dy) - iwHeight;
						}

						PTC.search.teaser.win.setPosition(dx + 6, dy- shift);
					}, this, {
						delay : 100,
						single : true
					});

					PTC.search.teaser.win.show();
					// initial window positioning
					var x = Ext.EventObject.getPageX();
					var y = Ext.EventObject.getPageY();
					PTC.search.teaser.win.setPosition(x + 6, y);
					var win = Ext.fly('PTC.search.teaserWindow');
					win.on('mouseenter', function() {
						PTC.search.teaser.delayedClose.cancel();
					}, this, {
						single : true
					});
					win.on('mouseleave', function() {
						PTC.search.teaser.win.hide();
					}, this, {
						single : true
					});

				}

			}, function(response) {
				jsca.error("Error with teaser request for object",
						keyword, objectId, name, number, response);
			}));
};


