/**
 * @class Handles the addition and removal of oids.
 */
var rowHandler = function() {
    var REMOVED_ROW_CLASSNAME = 'tableremovedrowbg';
    var addedOidNode;
    var removedOidNode;
    var initialOidNode;
    var visuallyRemove = false;
    var preventDuplicates = false;
    var tableID;
    var existingOids = oidUtils.newOidSet();
    var removedOids = oidUtils.newOidSet();
    var addedOids = oidUtils.newOidSet();
    var initialOids = oidUtils.newOidSet();
    // used to keep track of the list oids to be appended to the add or remove hidden field
    var appendOidList = oidUtils.newOidSet();
    var removeCallback = function(oid) {      
        var nonPersisted = addedOids.remove(oid);
        //removed oids only appended if they were not in addRow field
        if(nonPersisted) {
            appendOidList.remove(oid);
            if(initialOidNode) {
                initialOids.remove(oid);
            }
        }
    };
    var addCallback = function(oid) {
        var removed = removedOids.remove(oid);
        if (removed) {
            var removedNode = existingOids.node(oid);
            if (removedNode) {
                removedNode.disabled = false;
            }
            // added oids should only be appended in not in the removeRow field
            if (appendOidList.contains(oid)) {
                appendOidList.remove(oid);
            }
        } else if (preventDuplicates && existingOids.contains(oid)) {
            addedOids.remove(oid);
            appendOidList.remove(oid);
        }
    };
    function appendOidString(inputField, oidString) {
        if (!inputField) {
            return;
        }
        var currentString = inputField.value;
        if (currentString && currentString[currentString.length-1] !== '#') {
            inputField.value += '#';
        }
        inputField.value += oidString;
    }
    /**
     * @param {Array} oidList - is an array of oids to add as rows.
     * @param {Object} params - is extra params to add to the ajax request.
     * @param {Object} o2vMap - OR to VR map.
     * For the row to be visually added send param doAjaxUpdate=true,
     * otherwise the row is just added to the store and would be part of form data submitted.
     * To prevent duplicates send preventDuplicates=true.
     */
    function add(oidList, params, o2vMap) {
        var result = false;
        //Remove the added oids from the removed oids if they exist
        if(removedOidNode && removedOidNode.value && params.dynamicAction !== 'U') {
            removedOids.addString(removedOidNode.value);
        }
        // SPR 2109071: when updating rows, we do NOT want to add the oid(s) to the added list because the addRows_ field
        // is only meant for new oids, not updated ones.
        if (params.dynamicAction !== 'U') {
            appendOidList.addAll(oidList);
            addedOids.addAll(oidList);
            addedOids.iterate(addCallback);
        }
        //In case any oids were removed from the removed list update the value
        if (removedOids.isModified()) {
            removedOidNode.value = removedOids.toString();
        }
        var oidString = '';
        if (params.doAjaxUpdate || addedOidNode) {
            //If the table does not have a addRows_ field, no sense in creating the data for it.
            oidString = addedOids.toString();
        }
        if (!oidString && params.dynamicAction === 'U') {
            //Added oids not modified, but still need to pass the oidstring along
            oidString = oidList.join('#');
        }
        if (oidString !== '') {
            var appendString = appendOidList.toString();
            if (appendString !== undefined && appendString !== '') {
                appendOidString(addedOidNode, appendString);
            }
            if (params.doAjaxUpdate) {
                // set mform to the mainform that contains the table we are adding to
                params.mform = getMainForm(tableID);
                params.disableSelected = true;
                params.refreshOnNoOp = true;
                params.isAjaxEnabled = 'row';
                params.anonymousParams = ['', '', 'addedOid', oidString];
                //all the calculation has been done w.r.t add/remove rows and the respective nodes are updated
                //We need to make sure that the values are maintained even after the AJAX call updates
                //for that we are holding the updated values and resetting in the onSuccess call.
                //Integrity SPR 2891563
                var updated_removedNodeValue = null;
                if(removedOidNode !== null){
                    updated_removedNodeValue = removedOidNode.value;
                }
                var updated_addedOidNodeValue = null;
                if(addedOidNode !== null){
                    updated_addedOidNodeValue = addedOidNode.value;
                }
                var table = tableUtils.getTable(tableID);
                table.o2vMap = o2vMap;
                var customOnSuccess = params.onSuccess;
                params.onSuccess=function(result,options){
                    if(updated_removedNodeValue !== null){
                        removedOidNode.value = updated_removedNodeValue;
                    }
                    if(updated_addedOidNodeValue !== null){
                        addedOidNode.value = updated_addedOidNodeValue;
                    }
                    //resetting as the AJAX call is complete
                    if(table /*useful in jasmine tests*/){
                        table.transport= undefined;
                        table.o2vMap=undefined;
                    }
                    if (typeof customOnSuccess === 'function'){
                        customOnSuccess(result,options);
                    }
                };
                var transport=requestHandler.handleRequest(tableID, params);
                if(table /*useful in jasmine tests*/){
                    table.transport= transport;
                }
            } else {
                //we are not making ajax request, update the hidden field
                if (params.refresh) {
                    // assumes Wizard.js is included on page.
                    if (currentStepStrName) {
                        refreshCurrentStep(params.iframeForm);
                        result = true;
                    } else {
                        getUpdateOpenerWindow().PTC.navigation.reload();
                    }
                } else if (params.refreshTable) {
                     table = tableUtils.getTable(tableID);
                     if(!(PTC.jca.table.Utils.isjsttd(table)) && table.store.getCount() < 1) {
                      //SPR 4909413
                     //Clear the sticky width, if store has no data yet so that depending upon data the column width will be calculated when doAjaxUpdate=false
                        table.clearStickyConfigWidth();
                     }
                    refreshCurrentElementID(tableUtils.getFormattedTableId(tableID));
                }
            }
        }
        return result;
    }
    
    /*
     * verifyEachItem method will determine whether valid ioid or contextStr of Item already exists in removedOids or not
     */

    function verifyEachItem(item){
         var ioid = item.get('oid');
         var contextStr = item.get('jsca_context');
         if (ioid !== null && ioid !== undefined && (removedOids.contains(ioid) || (contextStr !== undefined && removedOids.contains(contextStr)))) {
             return true;
         }
         return false;
    }

    function remove(oidList) {
        if(addedOidNode && addedOidNode.value) {
            addedOids.addString(addedOidNode.value);
        }
        if(initialOidNode && initialOidNode.value) {
            initialOids.addString(initialOidNode.value);
        }
        appendOidList.addAll(oidList);
        removedOids.addAll(oidList);
        removedOids.iterate(removeCallback);
        if (addedOids.isModified()) {
            addedOidNode.value = addedOids.toString();
            if(initialOidNode && initialOids.isModified()) {
                initialOidNode.value = initialOids.toString();
            }
        }
        var appendString = appendOidList.toString();
        if (appendString !== '') {
            appendOidString(removedOidNode, appendString);
        }
        var table = tableUtils.getTable(tableID);
        if (table) {
            var rowStore = table.getStore();
            var toRemoveArray = [];
            var removalListFromSnapshot= [];
            rowStore.each(function (item) {
                if(verifyEachItem(item)){
                    toRemoveArray.push(item);
                }
            });
            // If items are selected before applying filter, those need to be considered for removal
            if(table.selModel.snapshot){
                table.selModel.snapshot.each(function(eachItem){
                    if(verifyEachItem(eachItem)){
                        toRemoveArray.push(eachItem);
                        removalListFromSnapshot.push(eachItem);
                    }
                });
                for(var i=0; i< removalListFromSnapshot.length;i++){
                    table.selModel.snapshot.remove(removalListFromSnapshot[i]);
                }
             }
            var massUpdate = toRemoveArray.length > 8 && table.disableMassUpdateOnRemove !== true;
            if (massUpdate) {
                // if there are too many rows, do one mass ui update instead.
                rowStore.suspendEvents();
            }
            rowStore.remove(toRemoveArray);
            if (massUpdate) {
                rowStore.resumeEvents();
                rowStore.fireEvent('datachanged', rowStore);
            }
            PTC.jca.table.scroll.updateTableSize(tableID, true);
        }
        //make sure none of the removed rows are selected
        jsca.unSelectAll(null,tableID);
        return false;
    }
    function init(table_id) {
        tableID = table_id;
        if (existingOids.isModified()) {
            existingOids.clear();
        }
        if (removedOids.isModified()) {
            removedOids.clear();
        }
        if (addedOids.isModified()) {
            addedOids.clear();
        }
        if (appendOidList.isModified()) {
            appendOidList.clear();
        }
        if (initialOids.isModified()) {
            initialOids.clear();
        }
        
        initialOidNode = tableUtils.getInitialRows(tableID);
        addedOidNode = tableUtils.getAddedRows(tableID);
        removedOidNode = tableUtils.getRemovedRows(tableID);
        preventDuplicates = false;
        visuallyRemove = false;
    }
    function initExistingOids(existingRows) {
        var allOids = getAllOidsInTable();
        if (allOids) {
            existingOids = allOids;
        } else {
            if (!existingRows) {
                existingRows = oidUtils.getTableOids(tableID);
            }
            if (existingRows) {
                existingOids.addAll(existingRows);
            }
        }
    }
    /**
     * When there is an hidden initialRows field for the table
     * the initialRows plus the addedRows minus the removedRows
     * should be used to determine existing rows in the table.
     * This is needed in Wizards to know all the oids in
     * the table when it is paged.
     * @return {oidUtils.newOidSet} 
     */
    function getAllOidsInTable() {
        if(initialOidNode) {
            var initialOids = oidUtils.newOidSet();
            initialOids.addString(initialOidNode.value);
            var addOids = oidUtils.newOidSet();
            if (addedOidNode) {
                addOids.addString(addedOidNode.value);
            }
            var rmOids = oidUtils.newOidSet();
            if (removedOidNode) {
                rmOids.addString(removedOidNode.value);
            }
            var idx = 0;
            var addList = [];
            for (var oid in addOids.data) {
                if (typeof oid !== 'function') { //Removes JSLint warning for in.  Makes sure what we're adding into the array is data and not a function
                    addList[idx++] = oid;
                }
            }
            initialOids.addAll(addList);
            var rmList = [];
            idx = 0;
            for (oid in rmOids.data) {
                if (typeof oid !== 'function') { //Removes JSLint warning for in.  Makes sure what we're adding into the array is data and not a function
                    rmList[idx++] = oid;
                }
            }
            initialOids.removeAll(rmList);
            return initialOids;
        }
        return null;
    }
    return /** @scope rowHandler*/ {
        /**
        * Add rows to a table.
        * @param {Array} oidList - is an array of oids to add as rows.
        * @param {String} table_id
        * @param {Array} [tableRows] - (optional) is an array of all current rows to improve performance of the api
        * @param {Object} params - is extra params to add to the ajax request. 
        * @param {Object} o2vMap - OR to VR map
        * For the row to be visually added send param doAjaxUpdate=true, 
        * otherwise the row is just added to the store and would be part of form data submitted. 
        * To prevent duplicates send preventDuplicates=true. 
        * 
        * @example
        * var oids = ['OR:wt.part.WTPart:123', 'OR:wt.part.WTPart:456'];
        * rowHandler.addRows(oids, 'someTableId', null, {doAjaxUpdate : true});
        */
        addRows : function(oidList, table_id, tableRows, params, o2vMap) {
            init(table_id);
            preventDuplicates = (params && params.preventDuplicates);
            initExistingOids(tableRows);
            params.addRows = true;
            add(oidList, params, o2vMap);
        },
        /**
        * Update rows of a table.
        * @param {Array} oidList - is an array of oid strings to add as rows.
        * @param {String} table_id - the id of a table (recent.updates.table or table__recent.updates.table_TABLE)
        * @param {Object} params - is extra params to add to the ajax request.
        */
        updateRows : function(oidList, table_id, params) {
            if(isWizardWindow()) {
                PTC.wizard.saveTableData.writeAllTableRows();
            }
            init(table_id);
            preventDuplicates = (params && params.preventDuplicates);
            params.updateRows = true;
            params.dynamicAction='U'; // Specify that rows are updated
            add(oidList, params);
        },
        /**
        * Removes the selected rows from table. If need a confirmation pop-up, please provide the content 
        * for it (rbinfokey, inserts)
        * @param {Object} tableItem
        * @param {Object} rbinfokey Required key to use to lookup a localized message
        * @param {Object} [inserts] The inserts for the localized message
        */
        removeRowsFromParentTable : function(tableItem, rbinfokey, inserts) {
            var table_id = tableUtils.findTableID(tableItem);
            var selectedItems = getJCASelectedTableItems(table_id);
            if (!selectedItems  || selectedItems.length === 0 ) {
                JCAAlert('com.ptc.netmarkets.util.utilResource.NONE_CHECKED');
            } else {
                /**
                 * Consider refactoring to remove any obsolete logic that has to do with graying out rows
                 */
                var cont = true;
                if(rbinfokey !== undefined){
                    cont = JCAConfirm(tableItem, rbinfokey, inserts);
                }
                if(cont){
                    rowHandler.removeRows(selectedItems, table_id, true);
                    tableUtils.updateFooterCount(table_id,getJCASelectedTableItems(table_id).length);
                }
            }
            tableItem = (tableItem) ? tableItem : event;
            Event.stop(tableItem);
            return false;
        },
        /**
        * Remove rows from the table, rows is an array of oids.
        * @param {Array} rows - an array of oids.
        * @param {String} table_id
        * @param {boolean} visually_remove
        */
        removeRows : function(rows, table_id, visually_remove) {
            init(table_id);
            visuallyRemove = visually_remove;
            remove(rows);
        },
        /**
        * @private
        * Use only for JSUnit testing
        */
        addedOids : addedOids,
        /**
        * @private
        * Use only for JSUnit testing
        */
        getExistingOids : function(tableId, tableRows) {
            init(tableId);
            initExistingOids(tableRows);
            return existingOids;
        }
    };
}();


/**
 * This function highlights the specificed table row. It does not unhighlight
 * the previously highlighted row. If the function is called on multiple rows on a table
 * then all these rows will get highlighted
 * @param {String} rowOid
 * @param {String} css class for the highlight (if not specified, "tablehighlightrowbg" will be used)
 * @param {String} tableId
 */
function highlightTableRow(rowOid, highlightClassName, tableId){
    if (!highlightClassName) {
        highlightClassName = "tablehighlightrowbg";
    }
    if (tableId) {
        var row = tableUtils.getTableRowFromOid(tableId, rowOid);
        
        // Used new API to highlight a table row
        getRowHighlightClassName = function(r, idx, rowParams, ds) {
            if(row && row == r){
                return highlightClassName;
            }
            return "";
        };

        tableUtils.setRowClassFunction(tableId, getRowHighlightClassName);
    }
}

/**
 * This function highlights the specificed table row. It does not unhighlight
 * the previously highlighted row. If the function is called on multiple rows on a table
 * then all these rows will get highlighted
 * @param {String} rowOid
 * @param {String} css class for the highlight (if not specified, "tablehighlightrowbg" will be used)
 * @param {String} tableId
 */
function highlightTreeRow(rowOid, highlightClassName, tableId){
    return highlightTableRow(rowOid, highlightClassName, tableId);
}


/**
 * Convert certain characters (<, >, and ") to their HTML character equivalents for literal display in web pages.
 * Note: This is very similar to Ext.util.Format.htmlEncode(), but it allows & characters.
 * @param {String} value The string to encode
 * @return {String} The encoded text
 */
jsca.htmlEncodeCheckboxIdForSafety = function(value){
    // only attempt to change the value if it is a string
    if (value && (typeof value == 'string' || value instanceof String)) {
        return String(value).replace(/>/g, "&gt;").replace(/</g, "&lt;").replace(/"/g, "&quot;");
    } else {
        return value;
    }
};

/**
 * adds hidden checkboxes to the DOM and maintains their 'checked' state
 * so Form.serialize() and mainform.submit() will both work the same as for a jca table
 * @param {Object} table - table object
 * @param {Object} row
 * @param {String} tableId
 * @param {boolean} isSelected
 */
jsca.updateHiddenCheckbox = function(table, row, tableId, isSelected){

    // Updated to maintain selected hidden checkboxes across multiple pages.
    var checkboxId = getRowContext(row, table);

    // Prevent XSS issue with jsca_context param
    // (it is possible that getRowContext() could return embedded HTML tags that
    // could be evaluated when inserting the hidden input in the DOM.)
    checkboxId = jsca.htmlEncodeCheckboxIdForSafety(checkboxId);

    var thisCheckBox = getWindow().Ext.getDom(checkboxId);
    if (thisCheckBox) {
        if (isSelected) {
            thisCheckBox.checked = true;
            //return id of the element
            return checkboxId;
        }
        else {
            thisCheckBox.parentNode.removeChild(thisCheckBox);
        }
    }
    else {
        if (isSelected) {
            //return id of the element to be added to the hidden checkboxes div
            return checkboxId;
        }
    }
};

/**
 * update the sticky object collection of specific table id's selected rows.
 * 
 * @param {String} tableId
 * @param {items} List Of rows clicked
 * @param {boolean} isSelected if selectRowEvent fire.
 */
PTC.jca.table.updateViewSelectedOnlyItemsCacheValue = function(tableId, allClickedRows, isSelected) {

    var selectedOnlyItem = Ext.getCmp(PTC.jca.table.getWTablePanelID(tableId) + '.selectedOnlyViewItem');
    if (!selectedOnlyItem || selectedOnlyItem.checked !== true) {
        return;
	}
    var selectedOnlyItems;
    if (!allClickedRows || allClickedRows.length < 1) {
        if(isSelected === false) {
            //Handling unselect all rows on current page, In this case we should set empty array.
            selectedOnlyItems = [];
            PTC.jca.table.setObjectToSession(tableId, selectedOnlyItem.id, selectedOnlyItems);
        }
        return;
    }
    selectedOnlyItems = PTC.jca.table.findInTable.getSavedSelectedOidList(tableId);
    if (selectedOnlyItems === null) {
        return;
    }
    var dataLength = allClickedRows.length;
    for ( var i = 0; i < dataLength; i++) {
        if (isSelected) {
            selectedOnlyItems.push(allClickedRows[i].data.oid);
        } else {
            selectedOnlyItems.remove(allClickedRows[i].data.oid);
        }
	}
    PTC.jca.table.setObjectToSession(tableId, selectedOnlyItem.id, selectedOnlyItems);
};
/**
 * adds hidden checkboxes to the DOM
 * 
 * @param {Object[]}
 *            newBoxes - checkboxes id
 * @param {String}
 *            tableId
 * @param {boolean}
 *            needToOverwrite : depending upon value of needToOverwrite, hidden div will be overwritten or appended
 */
PTC.jca.addSelectionCheckbox = function(newBoxes,tableId,needToOverwrite){
    var id = 'checkboxesFor_' + tableId;
    var parent = getWindow().$(id);
    if (!parent) {
       parent = Ext.DomHelper.append(getWindow().getMainForm(),{tag: 'span', id: id, style: 'display:none;'}, true );
    }
    var inputs = [];
    for (i = 0, l = newBoxes.length; i < l; i++) {
        var checkboxId = newBoxes[i];
        //innerhtml is faster
        inputs.push('<input type="checkbox" checked="true" id="'+checkboxId+'" name="pjl_selPJLsa1__1" value="'+checkboxId+'" />');
    }
    if (needToOverwrite) {
         Ext.DomHelper.overwrite(parent, inputs.join(""));
    }
    else {
        Ext.DomHelper.append(parent, inputs.join(""));
    }
};
jsca.rowSelectionHandler = function(tableId, allClickedRows, rowClicked, isSelected, table, allRowsAffected, snapshotItems){
    if (rowClicked || isSelected) {
        // don't set the mainform if elements are being cleared globally.
    PTC.util._setMainFormStartingElement(tableId);
    }
    if (!table) {
        table = tableUtils.getTable(tableId);
    }
    if (isSelected) {
        if (rowClicked && !(table.isShiftSelect === true)) {
            //select one row by sending just one row through the select all code below
            allClickedRows = [rowClicked];
        }
        // Handle checkbox selection and  modify dom
        if (allClickedRows && allClickedRows.length > 0) {
            var newBoxes = [];

            for (var i = 0, l = allClickedRows.length; i < l; i++) {
                var row = allClickedRows[i];
                if (!allRowsAffected) {
                var newSelectedCheckbox = jsca.updateHiddenCheckbox(table, row, tableId, isSelected);
                    if (newSelectedCheckbox) {
                        newBoxes[newBoxes.length] = newSelectedCheckbox;
                    }
                }
                else {
                     newBoxes.push(getRowContext(row, table));
                }
            }
            //now add all the new checkboxes to the parent; doing this after all the checkboxes are created since
            //modifying the DOM between each $(checkboxId) call was not performant
            if (newBoxes.length > 0) {
                 PTC.jca.addSelectionCheckbox (newBoxes,tableId,(allRowsAffected && !snapshotItems));
            }
        }
    }
    else {
        if (rowClicked && !(table.isShiftSelect === true)) {
            //deselect one row by sending just one row through the deselect all code below
            allClickedRows = [rowClicked];
        }
        if (allClickedRows && allClickedRows.length > 0) {
            // Loop through all the rows in hidden div and remove those durning shift select .
            for (i = 0, l = allClickedRows.length; i < l; i++) {
                row = allClickedRows[i];
                jsca.updateHiddenCheckbox(table, row, tableId, isSelected);
            }
            table.isShiftSelect = false;
         } else {
            //unselect all rows on current page
            var parent = getWindow().$('checkboxesFor_' + tableId);
            if (parent) {
               if(snapshotItems){
                     // ON DeselectAll from filter screen, only selected checkbox before filtering should be retained 
                     PTC.jca.addSelectionCheckbox (snapshotItems, tableId, true);
               }
               else{
                     // no longer have selection across pages, therefore blow away the div
                     parent.innerHTML = '';
               }
           }
        }
    }

    //On row select or de-select update viewSelected Items cache accordingly.
    PTC.jca.table.updateViewSelectedOnlyItemsCacheValue(tableId, allClickedRows, isSelected);

};

function getJSCASelectedTableItems(tableID){
    var result = [];
    var selectedRowsDiv = getWindow().document.getElementById("checkboxesFor_" + tableID);
    if (selectedRowsDiv) {
        for (var j = 0, k = selectedRowsDiv.childNodes.length; j < k; j++) {
            if (selectedRowsDiv.childNodes[j].checked) {
                result.push(oidUtils.normalize(selectedRowsDiv.childNodes[j].value));
            }
        }
    }

    return result;
}

/**
 * Override function to allow record to be be passed as 4th extra argument to improve performance.
 * PTC EXT OVERRIDE
 *
 * @param {Number} index - a record index(Number)
 * @param {boolean} keepExisting
 * @param {boolean} preventViewNotify
 * @param {Ext.data.Record} record
 * @param {Boolean} force - allow selection locked rows
 */
Ext.grid.RowSelectionModel.prototype.selectRow = function(index, keepExisting, preventViewNotify, record, force){
        //PTC ADDED
        var r = null;
        if(record !== undefined){
            // avoid calling indexOf if the index is passed as an argument for performance gain - SPR 2185513
            if (!index) {
            	index = this.grid.store.indexOf(record);
            }
            r = record;
        }

        if(r === null){
            r = this.grid.store.getAt(index);
        }

        if( this.isLocked() ||  (r && r.isLocked() && force !== true) ||
           (index < 0 || index >= this.grid.store.getCount()) || (keepExisting && this.isSelected(index))){
            return;
        }

        //END PTC ADDED
        if(r && this.fireEvent('beforerowselect', this, index, keepExisting, r) !== false){
            if(!keepExisting || this.singleSelect){
                this.clearSelections();
            }
            this.selections.add(r);
            this.last = this.lastActive = index;
            if(!preventViewNotify){
                this.grid.getView().onRowSelect(index);
            }
            this.fireEvent('rowselect', this, index, r);
            this.fireEvent('selectionchange', this);
        }
};

/**
 * Returns the selected records (inclusive of the selections in snapshot)
 * @return {Array} Array of selected records
 */
Ext.grid.RowSelectionModel.prototype.getSelections = Ext.grid.RowSelectionModel.prototype.getSelections.wrap(function(proceed){
    var selections = proceed();
    var snap = this.snapshot;
    if(snap && snap.items && snap.items.length >0){
        selections = selections.concat(snap.items);
    }
    return selections;
});

/**
 * Selection Model for multiple select tables.
 * Extends from Ext.grid.CheckboxSelectionModel
 */
PTC.jca.table.CheckboxSelectionModel = function() {
	// call parent constructor
	PTC.jca.table.CheckboxSelectionModel.superclass.constructor.call(this);
};

/**
 * This will register the init events for CheckboxSelectionModel or RadioSelectionModel, this method also register event for lockedInnerHd.
 */
Ext.grid.RowSelectionModel.prototype.registerGridRenderInitEvents = function() {
     var view = this.grid.getView();
     view.mainBody.on('mousedown', this.onMouseDown, this);
     if(!this.singleSelect) {
         Ext.fly(view.innerHd).on('mousedown', this.onHdMouseDown,this);
     }
     if(view.lockedBody)
     {
         view.lockedBody.on('mousedown', this.onMouseDown, this);
         if(!this.singleSelect) {
             Ext.fly(view.lockedInnerHd).on('mousedown',this.onHdMouseDown, this);
         }
     }
};

Ext.extend(PTC.jca.table.CheckboxSelectionModel, Ext.grid.CheckboxSelectionModel, {
	//PTC EXT OVERRIDE:-- register event for lockedInnerHd also
        //  hack KeyNav object so it doesn't consume up/down arrow events:
	initEvents : function() {
	    Ext.grid.CheckboxSelectionModel.superclass.initEvents.call(this);
            if (this.rowNav) {
                // SPR 5838344:
                // The native Ext handlers for up/down arrow keys in a row selection model
                // do not correctly return true/false to indicate whether they handled the
                // event.  Then, the default action is to stop the event.  Unfortunately
                // all of this happens before any native browser handling (e.g. moving the
                // cursor in a textarea box).
                //
                // An online posting gives a clue on how to override the default behavior:
                //     http://forums.ext.net/showthread.php?37151-CLOSED-GridPanel-and-KeyNav
                // But, the only supported options are "stopEvent", "preventDefault" and
                // "stopPropagation".  None of these allows the handling to proceed.
                // So we trick the Ext code into calling an innocuous function,
                // Ext.EventObject.isNavKeyPress(), rather than stopping the event.
                this.rowNav.defaultEventAction = "isNavKeyPress";
            }
            this.grid.on('render', function() {
		    this.registerGridRenderInitEvents();
	    }, this);
	},

	/**
	 * Provide "Shift-Select" functionality for checkboxes.
	 * Override the "Mouse-Down" event handler of the
	 * selection model provided by Ext.
	 * PTC EXT OVERRIDE
	 */

	 onMouseDown : function(e, t) {
	     if (e.button === 0 && t.className == 'x-grid3-row-checker') {
	         e.stopEvent();
	         var row = e.getTarget('.x-grid3-row');
	         if (row) {
	             var index = row.rowIndex;
	             var isSelected = this.isSelected(index);
	             var view = this.grid.getView();
	             if (e.shiftKey && !this.singleSelect && this.last !== false) {
	                 var last = this.last;
	                 if (!isSelected) {
                         this.suspendEvents(false);
	                     this.selectRange(last, index, true);
                         this.resumeEvents();
                         this.fireEvent('rowmassselection', this, this.selections.items);
                         view.fireEvent('selectrange', this);
	                     view.focusRow(index);
	                 } else {
	                 	/**
	                 	 * If the selected row is above the last selected row,
	                 	 * change the params to deselectRange function so that
	                 	 * the for loop inside deselectRange function works
	                 	 * properly.
	                 	 */
                         this.suspendEvents(false);
                         var deselectedRecs;
	                 	 if (last > index) {
	                 	     this.deselectRange(index, last, false);
                              deselectedRecs = this.grid.store.getRange(index, last);
	                 	 } else {
	                 	     this.deselectRange(last, index, false);
                             deselectedRecs = this.grid.store.getRange(last, index);
	                 	 }
                         this.resumeEvents();
                         this.fireEvent('rowmassdeselection', this, deselectedRecs);
	                 	 view.focusRow(index);
	                 	 index--;
	                 }
	             } else {
	                 if (isSelected) {
	                     this.deselectRow(index);
                         if(view.tracker){
                             //DDTracker checks on preventDefault flag to swallow the 
                             //event,preventDefault was undefined so text selection wasnt happening,making preventDefault false now allows text selection etc to happen
                             view.tracker.preventDefault = false;
                         }
	                 } else if (!isSelected || this.getCount() > 1) {
	                     this.selectRow(index, true);
	                     view.focusRow(index);
	                 }
	             }
	             this.last = index;
	         }
	     }
	 },
     listeners: {
        'selectionchange': PTC.jca.table.handleSelectAllCheckbox
	 }
});

/**
 * Selection Model for single select tables.
 * Extends from user extension Ext.ux.grid.RadioSelectionModel
 * @param {Object} config
 */
PTC.jca.table.RadioSelectionModel = function(config) {
	// call parent constructor
	PTC.jca.table.RadioSelectionModel.superclass.constructor.call(this, config);
};

Ext.ns('Ext.ux.grid');
if (Ext.ux.grid.RadioSelectionModel !== undefined) {
Ext.extend(PTC.jca.table.RadioSelectionModel, Ext.ux.grid.RadioSelectionModel, {
    initEvents : function() {
        Ext.ux.grid.RadioSelectionModel.superclass.initEvents.call(this);
        this.grid.on('render', function() {
            this.registerGridRenderInitEvents();
        }, this);
    },
    onMouseDown : function(e, t) {
        var radio_id = this.id + "_" + this.grid.id;
    	if (e.button === 0 && t.name === radio_id) {//Select row when click on radio and left mouse button is clicked
            e.stopEvent();
            var row = e.getTarget('.x-grid3-row');
            if(row !== undefined) {
                var index = row.rowIndex;
                this.selectRow(index, true);
            }
        }
    }
});
}



//lock for record, this will enable the row to be non-selectable
Ext.data.Record.prototype.lock  = function() {
    this.locked = true;
};

//release lock on record
Ext.data.Record.prototype.unlock  = function() {
    this.locked = false;
};

//isLocked 
Ext.data.Record.prototype.isLocked  = function() {
    return (this.locked !== undefined && this.locked !== null && this.locked === true);
};


//readonly row
Ext.grid.RowSelectionModel.prototype.readOnlyRow = function(record, readonly){
    var view = this.grid.getView();
    var store = this.grid.store;
    var rowIndex;
    if (Ext.isNumber(record)) {
        rowIndex = record;
        record   = store.getAt(rowIndex);
    } else {
        rowIndex = store.indexOf(record);
    }

    if(readonly) {
        record.lock();
    } else {
        record.unlock();
    }

    return view.getRow(rowIndex);
};

//disable row
Ext.grid.RowSelectionModel.prototype.disableRow = function(record, disable){
    var row = this.readOnlyRow(record, disable);

    if(!this.disableRowClassFunction){
        this.disableRowClassFunction = function(r, idx, rowParams, ds) {
            if(r.isLocked()) {
                return 'x-item-disabled';
            } else {
                return '';
            }
        };
        tableUtils.setRowClassFunction(this.grid.jcaTableConfig.tableID, this.disableRowClassFunction, true);
    }

    return row;
};

Ext.grid.RowSelectionModel.prototype.deselectRow = function(index, preventViewNotify, record){

    //PTC ADDED
    var r = null;
    if(record !== undefined){
        index = this.grid.store.indexOf(record);
        r = record;
    }

    if(r === null){
        r = this.grid.store.getAt(index);
    }
    if(r && r.isLocked()){
        return;
    }
    //END PTC ADDED

    if(this.isLocked()){
        return;
    }
    if(this.last == index){
        this.last = false;
    }
    if(this.lastActive == index){
        this.lastActive = false;
    }
    r = this.grid.store.getAt(index);
    if(r){
        this.selections.remove(r);
        if (this.snapshot) {
            this.snapshot.remove(r);
        }
        if(!preventViewNotify){
            this.grid.getView().onRowDeselect(index);
        }
        this.fireEvent('rowdeselect', this, index, r);
        this.fireEvent('selectionchange', this);
    }
};


/** @namespace PTC.jca.table.rowStrikeThrough Namespace for functions and attributes. */
PTC.jca.table.rowStrikeThrough = {};
PTC.jca.table.rowStrikeThrough.log = log4javascript.getLogger('PTC.jca.table.rowStrikeThrough');

PTC.jca.table.rowStrikeThrough.getStrikeThroughCSS = function(){
    return "strikethroughRow";
};

PTC.jca.table.rowStrikeThrough.getBooleanValue = function(row, columnId) {
    if(!PTC.isDefined(columnId)){
        return 'false';
    }
    var rawValue = row.get(columnId);
    if(rawValue.gui) {
        if(rawValue.gui.comparable === 'true' || rawValue.gui.rawValue === 'TRUE') {
            return 'true';
        } else if(rawValue.gui.comparable === 'false' || rawValue.gui.rawValue === 'FALSE') {
            return 'false';
        }
    }
    if(typeof rawValue === 'boolean') {
        return rawValue.toString();
    }
    return (rawValue === 'true') ? rawValue : 'false';
};

PTC.jca.table.rowStrikeThrough.setBooleanValue = function(row, columnId, value) {
    if(!PTC.isDefined(columnId)){
        return;
    }

    /* Need to preserve the original value */
    if(!(row.strikeThroughOriginal === 'true' || row.strikeThroughOriginal === 'false')) {
        row.strikeThroughOriginal = PTC.jca.table.rowStrikeThrough.getBooleanValue(row, columnId);
    }
    
    var rawValue = row.get(columnId);
    if(rawValue.gui && typeof value === 'boolean') {
        var strValue = Boolean(value).toString();
        if(rawValue.gui.comparable !== undefined) {
            rawValue.gui.comparable = strValue;
        } else {
            rawValue.gui.rawValue = strValue.toUpperCase();
        }
    } else if(typeof rawValue === 'boolean') {
        rawValue = value;
    } else {
        rawValue = Boolean(value).toString();
    }
};

/**
 * Sets CSS class "strikethroughRow" to row depending upon the strikeThroughColumn attribute.
 */
PTC.jca.table.rowStrikeThrough.setRowClass = function(grid) {
    var getRowClassName = function(r, idx, rowParams, ds) {
        PTC.jca.table.rowStrikeThrough.log.debug("Applied strike-through CSS class for row with id: ", r.id);
        var value = PTC.jca.table.rowStrikeThrough.getBooleanValue(r, grid.jcaTableConfig.strikeThroughColumn);

        if(value == 'true'){
            // Return CSS class for strike-through row style.
            this._strikeThroughCache[idx] = true;
            return PTC.jca.table.rowStrikeThrough.getStrikeThroughCSS();
        }
        this._strikeThroughCache[idx] = false;
        return "";
    };

    if(getRowClassName){
        tableUtils.setRowClassFunction(grid.jcaTableConfig.tableID, getRowClassName, true);
    }
  
};

/*
 * Returns array of modified rows whose strikeThroughColumn value has been changed.
 * @param {String} tableId
 * @return Array of modified records
 */
PTC.jca.table.rowStrikeThrough.getChangedRows = function(tableId) {
    var table = PTC.jca.table.Utils.getTable(tableId);
    if (!table) {
        return null;
    }
    var collection = table.store.queryBy(function(record, id) {
        //Put an additional check to ensure that strikeThroughOriginal is defined.
        //Without this check, the unchanged rows would also get into the collection
        if (PTC.isDefined( record.strikeThroughOriginal)  && PTC.jca.table.rowStrikeThrough.getBooleanValue(record, table.jcaTableConfig.strikeThroughColumn) !== record.strikeThroughOriginal){
            return true;
        }
        return false;
    });

    return collection.items;
};

/**
 * Marks or clears strike-through for selected rows/supplied rows for a particular table depending upon strikeThrough parameter.
 *
 * @param {String} tableId - Table ID
 * @param {boolean} strikeThrough - boolean value to determine whether to strike-through a row or not.
 * @param {Array} records - (Optional) Array of record Ids for which strikeThrough value is applied
 */
PTC.jca.table.rowStrikeThrough.setRows = function(tableId, strikeThrough, records) {
     
    
    PTC.jca.table.rowStrikeThrough.log.debug((strikeThrough ? "Strike-through rows" : "Clear strike-through") , "for table: " ,tableId);
    var table = PTC.jca.table.Utils.getTable(tableId);
    if (!table) {
        return;
    }
    var strikeThroughColumn = table.jcaTableConfig.strikeThroughColumn;
    //Check if strike-through column is configured or not, if not then notify user and return.
    if(!strikeThroughColumn) {
    	JCAAlert("com.ptc.core.ui.tableRB.STRIKETHROUGH_NOT_CONFIGURED");
    	return;
    }
 
    if(!records || records.length < 1) {
        //Get selected records from table selection model.
        records = table.getSelectionModel().getSelections();
        table.getSelectionModel().clearSelections();
    }
    if(!records || records.length === 0) {
        return;
    }
    PTC.jca.table.rowStrikeThrough.log.debug("Number of rows for applying strike-through: ", records.length);
    // To improve performance. If records are less than 10 then use refresh row otherwise refresh entire view.
    var refreshRows = records.length < 10 ? true : false;
   
    for(var i = 0, l = records.length; i < l; i++) {
        var record = typeof records[i] === 'string' ? table.store.getById(records[i]) : records[i];
        //Apply the new strikethrough
        PTC.jca.table.rowStrikeThrough.setBooleanValue(record, strikeThroughColumn, strikeThrough);
        if(refreshRows) {
            table.getView().refreshRow(record);
        }
    }
    if(!refreshRows) {
        table.getView().refresh();
    }

    //Update hidden divs.
    PTC.jca.table.rowStrikeThrough.updateHiddenDivForModified(tableId);

    
};

/**
 * Returns stirke-through rows for a table depending upon boolean strikeThrough parameter.
 *
 * @param {String} tableId - Table ID
 * @param {boolean} strikeThrough - boolean value to determine whether to return rows having strike-through or not.
 * @return Array of records
 */
PTC.jca.table.rowStrikeThrough.getRows = function(tableId, strikeThrough) {
    var table = PTC.jca.table.Utils.getTable(tableId);
    if (!table) {
        return null;
    }
    var strikeThroughColumn = table.jcaTableConfig.strikeThroughColumn;
    var collection = table.store.queryBy(function(record, id) {
        var value = (PTC.jca.table.rowStrikeThrough.getBooleanValue(record, strikeThroughColumn) === 'true');
        if(value === strikeThrough) {
            return true;
        }
        return false;
    });

    return collection.items;
};

/**
 * Marks or clears strike-through for focused row for a particular table.
 *
 * @param {String} tableId - Table ID
 * @param {boolean} strikeThrough - boolean value to determine whether to strike-through a row or not.
 */
PTC.jca.table.rowStrikeThrough.setFocusedRow = function(tableId, strikeThrough) {
    var table = PTC.jca.table.Utils.getTable(tableId);
    var records = [];
    var focusedRecord = PTC.jca.table.Utils.getFocusedRecord(table);
    if(focusedRecord) {
        records.push(focusedRecord.id);
    }
    PTC.jca.table.rowStrikeThrough.setRows(tableId, strikeThrough, records);
};
/**
 * Maintains hidden divs for modified strike-through cell in rows so that this information will be available at server side.
 */
PTC.jca.table.rowStrikeThrough.updateHiddenDivForModified = function(tableId) {
    var records = PTC.jca.table.rowStrikeThrough.getChangedRows(tableId);
    
    var strikeThroughRowsDiv =  'strikeThroughRowsFor_' + tableId;
    var parent = $(strikeThroughRowsDiv);
    if (!parent) {
        var div = document.createElement('div');
        div.id = strikeThroughRowsDiv;
        div.style.display = 'none';
        getMainForm(PTC.jca.table.Utils.getTable(tableId).getEl().dom).appendChild(div);
        parent = div;
    }
    var inputs = [];
    if(records) {
        var strikeThroughColumn = PTC.jca.table.Utils.getTable(tableId).store.jsca_table.jcaTableConfig.strikeThroughColumn;
        for (var i = 0, l = records.length; i < l; i++) {
            var id = records[i].id;
            var value = PTC.jca.table.rowStrikeThrough.getBooleanValue(records[i], strikeThroughColumn);
            inputs.push('<input id="' + id + '" name="'+ tableId +'_strikeThroughRows" value="' + id + "=" + value + '" />');
        }
    }
    parent.innerHTML = inputs.join("");
};


/**
 * Strike-through infrastructure maintains a cache on client side so that on server side it comes toknow about changed
 * strike-through records when the form is submitted. If the action that persist the strike-through changes is either "component"
 * or "page" level, the cache is updated by the infrastructure, but if the action is "row" level, it requires an explicit update.
 * For example, suppose there is an action which marks strike-through on a table row and there is an another action say "apply"
 * which operates on rows and persist the strike-through status on server side. In this case, update RecordsAndCache should be
 * called to make sure that client side cache is updated to be in sync with server.
 * @param {String} tableId - Table ID
 * @param {Array} records - Array of record Ids or store record objects whose change has been persisted by the "row" level action.
 *                          This need to be provided ONLY if the "row" level action didn't update the records in client store
 *                          while bringing the updated row from the server. The records strike-through original value will be reset
 *                          to the current value.
 */

PTC.jca.table.rowStrikeThrough.updateRecordsAndCache = function(tableId, records){
    if(records && tableId) {
    var table = PTC.jca.table.Utils.getTable(tableId);
    var strikeThroughColumn = table.store.jsca_table.jcaTableConfig.strikeThroughColumn;
    for (var i = 0, l = records.length; i < l; i++) {
        var record = typeof records[i] === 'string' ? table.store.getById(records[i]) : records[i];
        var value = PTC.jca.table.rowStrikeThrough.getBooleanValue(record, strikeThroughColumn);
        //reset the original value
        record.strikeThroughOriginal = value;
    }
    }
    // Update hidden div
    PTC.jca.table.rowStrikeThrough.updateHiddenDivForModified(tableId);
};


/**
 allow more flexibility on what the row item is for the row, could be the row itself
 also note that there may be a bug somewhere else that this is masking where the cell itself is passed instead of the row.
 */
function getRowItem(row){
    var item = null;
    if (row && row.item !== undefined) {
        item = row.item;
    }
    
    if (!item && row !== null && row.data !== undefined) {
        return row.data;
    }
    if (!item) {
        return row;
    }
    return item;
}

/**
 * Should the implementation change, the table object may be used to help construct the context
 * row - Row object to get a context for
 * table - currently unused.
 */
function getRowContext(row, table){
    if (row === null) {
        return null;
    }
    return row.get('jsca_context');
}

function getRowOid(row){
    if (row === null) {
        return null;
    }
    return row.get('oid');
}


/**
 * Namespace for functions related to saving all the formdata in the table and submitting it when the wizard is complete.
 */
PTC.wizard.saveTableData = {};

PTC.wizard.saveTableData.log = log4javascript.getLogger("PTC.wizard.saveTableData");

/**
 *
 * @return DOM DIV node where the hidden data will be stored
 */
PTC.wizard.saveTableData._getHiddenTableDataDiv = function(){
      // check if the global variable is defined AND that the hidden DIV input is still in the DOM
    if (PTC.wizard.saveTableData.HIDDEN_TABLE_DATA === undefined ||
        !document.getElementById('PTC_wizard_saveTableData')) {
        var aDiv = document.createElement("div");
        aDiv.id = 'PTC_wizard_saveTableData';
        aDiv.style.display = "none";
        getMainForm().appendChild(aDiv);
        PTC.wizard.saveTableData.HIDDEN_TABLE_DATA = aDiv;
    }
    return PTC.wizard.saveTableData.HIDDEN_TABLE_DATA;
};

/**
 * registers the listeners to enable the persisting of hidden row data to be put into the form.
 */
PTC.wizard.saveTableData.register = function(){
    setUserSubmitFunction(PTC.wizard.saveTableData.writeAllTableRows);
    //reload wizard step is called for all component refreshes of tables in wizards
    //If that changes, then a componentRefresh event listener will need to be added on each table.
    PTC.wizard.on('beforeReloadStep', PTC.wizard.saveTableData.writeAllTableRows);
};

//Wait for the page to be ready before checking isWizardWindow()
//otherwise mainform may not be loaded yet (and there is logic in isWizardWindow() to check mainform)
PTC.onReady(function(){
    if (isWizardWindow()) {
        PTC.wizard.saveTableData.register();
    }
});

/**
 * Gets the hidden rows for a table
 * @param {Ext.grid.GridPanel} table
 */
PTC.wizard.saveTableData._getTableHiddenHTML = function (table) {
    var html = '';
    var view = table.getView();

    if (view instanceof Ext.ux.grid.BufferView) {
        var store = table.getStore();
        var storeIsFiltered = store.isFiltered();
        // getting the visible row count from the BufferView is sometimes off by a little.  Reduce the chance of missing any hidden
        // rows be reducing the count.  the fastRender function will not render it if it really is visible.
        var visibleRowCount = view.getVisibleRowCount() - 3;

        var totalRows = store.getCount();
        PTC.wizard.saveTableData.log.debug('value of storeIsFiltered', storeIsFiltered);
        PTC.wizard.saveTableData.log.debug('visible row count is', visibleRowCount);
        PTC.wizard.saveTableData.log.debug('total number of rows is' + totalRows);

        if (visibleRowCount < totalRows || storeIsFiltered) {
            //write out hidden rows
            PTC.wizard.saveTableData.log.debug('will write out hidden table rows');
            var cs = view.getColumnData();
            var cols = table.getColumnModel();

            var rs = store.getRange(0, totalRows);
            var colCount = view.cm.getColumnCount();
            var origIsVisible = view.isVisible;
            try {
                view.isVisible = function (rowIndex, vr) {
                    return !this.isRowRendered(rowIndex);
                };
                if (typeof view.fastRender !== 'function') {
                    view.fastRender = PTC.wizard.saveTableData.fastRender;
                }
                html = view.fastRender(cs, rs, store, 0, colCount, cols);
            }
            finally {
                view.isVisible = origIsVisible;
            }
        }
    }
    table.fireEvent('submit', table);

    return html;
};

/**
 * puts the html into the hidden div
 * @param {String} html
 */
PTC.wizard.saveTableData.writeHTMLToHiddenDiv = function(html){
    var div = PTC.wizard.saveTableData._getHiddenTableDataDiv();
    PTC.util.purge(div, true);
    div.innerHTML = html;
};

/**
 * collects all the tables and writes all the hidden rows to an empty div.
 * This is meant to be called right before the form submission
 */
PTC.wizard.saveTableData.writeAllTableRows = function(){
    var tables = PTC.jca.table.Utils.getTables();
    var html = [];
    tables.each(function(table){
        if (typeof table.submitAllTableData === 'function') {
            html.push(table.submitAllTableData());
        }
    });
    PTC.wizard.saveTableData.writeHTMLToHiddenDiv(html.join(''));
    return true;
};
/**
 * Extend and override this method to customize how the table data is saved.
 * It is not required to return the html string to save for the table.
 * @return html string that contains data to add to the FORM
 */
Ext.grid.GridPanel.prototype.submitAllTableData = function(){
    return PTC.wizard.saveTableData._getTableHiddenHTML(this);
};

/**
 * @param {PTC.jca.TableGrid} table the table to render
 * @param {Ext.data.Record} rec the record to render
 * @param {Number} rowIndex the row index
 * @param {Number} colCount the number of columns
 * @param {Array} cs array of column configurations
 * @param {Ext.grid.ColumnModel} cols the column model for this table
 * @param {Ext.grid.Store} store the data store
 * 
 * @return {Array} an array representing the html rendered
 */
PTC.wizard.saveTableData.doRendering = function(table, rec, rowIndex, colCount, columnConfigs, cols, store){
    var actionId = table.grid.initialConfig.jcaTableConfig.actionsMenuColumnId;
    var col;
    var p = {};
    var cb = [];
    for (var i = 0; i < colCount; i++) {
        col = columnConfigs[i];
        if (cols.config[i].modifiable && col.id !== actionId) {
            p.id = col.id;
            p.attr = p.cellAttr = '';
            p.value = col.renderer.call(col.scope, rec.get(col.name), p, rec, rowIndex, i, store);
            cb[cb.length] = p.value;
        }
    }
    return cb;
};

/**
 * Simpliflied renderer for faster processing of only editable columns 
 * @param {Array} cs array of column configurations
 * @param {Array} rs an array of Records
 * @param {Ext.Data.Store} ds the data store
 * @param {Number} startRow the row to start from
 * @param {Number} colCount the number of columns
 * @param {Ext.grid.ColumnModel} cols the column model for this table
 * @return {String} a string representing the HTML for the un-rendered table rows
 */
PTC.wizard.saveTableData.fastRender = function(cs, rs, ds, startRow, colCount, cols){
    var buf = [], c, p = {}, r;
    var actionId = this.grid.initialConfig.jcaTableConfig.actionsMenuColumnId;

    for (var j = 0, len = rs.length; j < len; j++) {
        r = rs[j];
        var rowIndex = (j + startRow);

        var needsRendering = this.isVisible(rowIndex);
        if (!needsRendering) {
            PTC.wizard.saveTableData.log.debug("row for index ", rowIndex, " already visible, won't render again");
            // already rendered.  Note that the isVisible method has been overridden to return
            continue;
        }
        if (needsRendering) {
            PTC.wizard.saveTableData.log.debug("row for index ", rowIndex, " is not visible, will call renderer");
            var result = PTC.wizard.saveTableData.doRendering(this, r, rowIndex, colCount, cs, cols, ds);
            buf[buf.length] = result.join("");
        }
    }
    
    // need to render any filtered rows (either through "search in table" or "view selected only") so they 
    // get submitted with the form.
    var filteredRows = PTC.wizard.saveTableData.renderFiltered(this, ds, colCount, cols, cs, actionId);
    buf[buf.length] = filteredRows.join("");
    
    return buf.join('');
};

PTC.wizard.saveTableData.renderFiltered = function(table, ds, colCount, cols, cs, actionId){
    var buffer = [];
    var p = {};
    var filteredOutRecords = PTC.jca.table.Utils.getFilteredOutTableRows(ds);
    
    for (var i = 0, length = filteredOutRecords.length; i < length; i++) {
        var result = PTC.wizard.saveTableData.doRendering(table, filteredOutRecords[i], -1, colCount, cs, cols, ds);
        buffer[buffer.length] = result.join("");
    }
    
    return buffer;
};

/**
 *  If a dom element changed, call the setAttribute function on the dom element with the changed
 *  value so that the innerHTML property gets updated.
 *
 *  innerHTML is handled differently in IE and other browsers.
 *  IE treats the innerHTML as the current state of the page and updates it automatically for you whenever the DOM
 *  is changed. The other browsers (Firefox, Chrome) treat the innerHTML as the original state of the page and
 *  do not update it on user actions, they do however update on javascript modifications.
 *  Because of this when the browser is not IE the users actions have to be repeated in javascript to get the
 *  DOM updated so that we can save changed innerHTML to the store.
 * @param {DOMElement} dom
 */
PTC.wizard.saveTableData.setTableValue = function(dom){
    var tag = dom.tagName.toLowerCase();
    switch (tag) {
        case 'input':
        case 'button':
            var type = dom.type;
            if (type === 'radio' || type === 'checkbox') {
                var rg = document.getElementsByName(dom.name);
                $A(rg).each(function(item){
                    if (item.checked) {
                        item.setAttribute('checked', 'true');
                    } else {
                        item.removeAttribute('checked');
                    }
                    //SPR 2171359 - need an explicit set for IE9
                    item.setAttribute('value', item.value);
                });
            }
           else {
                //For IE11 this is causing the cursor to keep jumping to the end if there's no change, so don't do it if there is no change.
                if (dom.getAttribute("value") !== dom.value) {
                    dom.setAttribute('value', dom.value);
                }
            }
            break;
        case 'textarea':
            // IE/EDGE treats the innerHTML as the current state of the page and updates it 
            // automatically for you whenever the DOM is changed, So no change is required. 
            
            // SPR: 7042317: "New Conditional Rule" and "Assign Advanced Expression" UIs: 
            // Cursor jumps if operators "<" and ">" are used in Windchill PDMLink 11.0 M30
            
            // SPR Task: 7110521: REGBB: Edge Specific : Cursor jump backwords in Expression 
            // box of Advance Assign Expression window
            if(!(PTC.util.PTC_isIE)){
                dom.innerHTML = dom.value;
            }
            break;
        case 'select':
            $A(dom.options).each(function(item){
                if (!item.selected && (item.getAttribute('selected') || item.getAttribute('selected') === '')) {
                    item.removeAttribute('selected');
                }
                else if (item.selected) {
                    item.setAttribute("selected", true);
                }
            });
            break;
        default: break;
    }
};

/**
 * Saves the html of the cell back onto the gui component js object
 * @param {Object} cell The js gui component
 * @param {DOMElement} dom The dom related to the cell
 * @param {DOMElement} [parent] optionally send in the parent, else its assumed parent will be first grid inner cell
 *   DIV node found up the DOM tree.  Grid cells have DIV parents, but attribute panel cells will have TD parents.
 *   This method must be called with a parent node from non-grid components.
 */
PTC.wizard.saveTableData.saveHTMLBackToGuiComponent = function(cell, dom, parent){
    parent = parent || Ext.fly(dom).parent('.x-grid3-cell-inner', 10);
    cell.gui.html = parent.innerHTML;
    if (cell.gui.comparable !== undefined) {
        // To preserve sorting order, if a new value is typed in save it as the comparable
        // as well if there is a comparable object already.
        cell.gui.comparable = dom.value;
    }
    
};

/**
 * If an onChange event occurs inside a table cell, then try to save the changed value into
 * the table store so that buffer view won't display old value after scroll, sort, etc.
 * Since the edit components displayed in the wizards have not all been converted to javascript
 * or to ext the default save handling is simply saving the innerHTML
 * of the component into the store whenever the change event is fired.
 * Components which are converted or are being developed new can include their own change event handlers
 * that save only the value. The change event handles have been hooked up at the table level
 * rather than at the individual component level as the Standards specify that these events should
 * propogate up and this works for Firefox and Chrome.
 *
 * Individual Cell components can customize how the value gets updated in the rows data,
 * simply specify an updateCellValue(cell, value) function on the cell object to have it override
 * the default behavior.  The value passed in is the value typed in by the user.  The default cell
 * objects follow the pattern of having the cell.gui.value be the attribute to display
 *
 * @param {Ext.EventObject} evt - this parameter is unused. Note - It will be defined when dom elements are changed by the user
 *                               but will be null when 'valueChanged' event is fired. 
 * @param {DOMElement} Dom Element item
 */
PTC.wizard.saveTableData.domChangeEventListener = function(evt, item){
    var tag = item.tagName.toLowerCase();
    if (tag === 'input' || tag === 'select' || tag === 'textarea') {
        var table = this;
        var view = table.getView();
        var colindex = view.findCellIndex(item);
        if(tag === 'input') {
            var headerElement = new Ext.Element(view.getHeaderCell(colindex), false);
            var applyToAllRows = headerElement.contains(item);
            if(applyToAllRows === true){
                // if the item is in the header, values need to be save to all rows in store
                PTC.wizard.saveTableData.saveAllRowsValues(table, colindex, item);
                return;
            }
        }
        var rowindex = view.findRowIndex(item);
        if (colindex >= 0 && rowindex >= 0) {
            var record = table.getStore().getAt(rowindex);
            if(record !== undefined){
                var cell = record.get(table.getColumnModel().config[colindex].id);
                //For now adding undefined check to fix SPR 2025220.
                if(cell !== undefined){
                    PTC.wizard.saveTableData.saveNewValueToCell(item, cell);
                    table.fireEvent('domchange', table, item, record, cell);
                }
             }
         }
    }
};

/**
 * Usually used for grids, but this API is also used to save attribute values back into an attribute panel store
 * 
 * @param {DOMElement} item - dom element whose value just changed
 * @param {Object} cell - json cell object 
 * @param {DOMElement} [parent] optionally send in the parent, else its assumed parent will be first DIV node found up the DOM tree.
 *             grid cells have DIV parents, but attribute panel cells will have TD parents.  
 */
PTC.wizard.saveTableData.saveNewValueToCell = function(item, cell, parent){
        // In Firefox/Chrome/IE 11 (!Ext.isIE) innerHTML is NOT updated automatically for any elements. 
        // The call to setTableValue is to 'force update' innerHTML. 
        // In IE 8 mode (Ext.isIE), innerHTML does update automatically for most elements, but does NOT for radio buttons and checkboxes.
        // In IE 11 mode innerHTML does not update automatically for comboxes as well.
        var innerHTML_needsToBeUpdated = !Ext.isIE || Ext.fly(item).is("[type=radio]") || Ext.fly(item).is("[type=checkbox]");

        // SPR  5749723: [Internet Explorer IE-11 Specific] The Primary indicator flag gets reset to NO from Yes when user adds
        // new entry in the Related Personnel and Location Table.
        // Note, in IE11 Ext.isIE is false. One of the reason is that IE11 is not officially supported prior to ExtJS 4.2.2.
        // Also, windchill code depends on Ext.isIE to be false for IE11 to run properly in number of places, so this should
        // not be corrected at this point (IE11 acts more like a Chrome than Internet Explorer).
        if (PTC_isIE11 && Ext.fly(item).dom.type==="select-one") {

            // Ext.fly(item).is("[type=select-one]") returns false so cannot be used for combobox check.

            // Note, this fix works for IE11, however we might need to test this for IE that comes after IE11, say IE11+.
            // Probably we will need to add another check for IE11+ or fix Ext.isIE for IE11+, or probably IE11+ will work
            // just fine without this block being executed.

            innerHTML_needsToBeUpdated = true;
        }

        //PTC.wizard.saveTableData.toggleCheckboxes works only for one check and it does NOT handle multiple checks for checkboxes but setTableValue does. 
        //Manage Security client is an example of multiple checkboxes in editable table.    
        if (innerHTML_needsToBeUpdated) {
            PTC.wizard.saveTableData.setTableValue(item);
        }
        if (typeof cell.updateCellValue === 'function') {
            var itemValue = PTC.util.HTMLEncoder.encodeForHTMLContent(item.value);
            cell.updateCellValue(cell, itemValue);
        } else if (cell.gui) { //if a value change in combo box changes the cell to text display then there will not be any cell.gui.Example-Type Picker in QMS Complaint wizard
           if(cell.gui.value !== undefined || cell.gui.html === undefined) {
              cell.gui.value = item.value;
           } else if (cell.gui.html !== undefined) {
              PTC.wizard.saveTableData.saveHTMLBackToGuiComponent(cell, item, parent);
           }
        } else {
           PTC.wizard.saveTableData.log.debug('Unable to save new value to cell as cell.gui is undefined or there is no updateCellValue fn on cell', cell);
        }
};

/**
 * Save an HTMLElement's value to the backing store in a wizard table.
 * @param {HTMLElement} item the HTMLElement that changed that needs to have its updated value saved to the store
 */
PTC.wizard.saveTableData.saveToStore = function(item){
    if (!item) {
        return;
    }
    
    // Just raise the appropriate browser event.
    // - Note that Firefox will not throw a change event on a disabled input field.
    // - SPR 2148822-02. In IE, Calendar pop-up was not closing when added as the only entry in multiple
    //   attribute entry table.  Calling the fire event in the try block resolves the issue.
    try {
        PTC.event.fireEvent(item, "change");
    } catch (e) {
        PTC.wizard.saveTableData.log.debug("item id value is unspecified", item.id);
    }
};

/**
 * @private
 * Method used to check, fired event is valid or not. fix for SPR#2261222
 * @param {Ext.Object} targetObject
 */
PTC.wizard.saveTableData.callOnChangeHandler = function(targetObj) {
    return (targetObj.value !== targetObj.innerHTML);
};

/**
 * Event listener for dom events that will update the table store when values are entered.
 * @param {DOMElement} element to register changes to
 */
PTC.wizard.saveTableData.registerDomChangeEvents = function(){    
    //component could be a grid or an attribute panel
    var component = this;
    //handler that will determine how to save the changes to the component's store
    var onChangeHandler = this.domChangeEventListener;
    //element to register changes to - for attribute panel it's just el.dom, for table its the view.el.dom
    var element = component.el.dom;
    if(component.getView === 'function') {
        element = component.getView().el.dom;
    }

    /**
     * Capture changes to input fields and make sure theare saved in the store, the delay is less than the clean delay
     * so the row should never be cleaned before it was saved.
     */
    var taskUpdateFunc = function(evt, item) {
        if (item._jcaOnChangeTask === undefined) {
            item._jcaOnChangeTask = new Ext.util.DelayedTask(onChangeHandler);
        }
        //delay only 50ms is fast enough so attribute panel onchange listener is called before user clicks OK in details popup wizard
        item._jcaOnChangeTask.delay(50, null, component, [evt, item]);
        return true;
    };
    Ext.EventManager.on(element, 'change', function(evt, item){
        if (item._jcaOnChangeTask !== undefined) {
            item._jcaOnChangeTask.cancel();  // don't need to update 2x, task is backup plan
        }
      //Checking, whether fired event is valid or not. fix for SPR#2261222
        if(PTC.wizard.saveTableData.callOnChangeHandler(evt.target)) {
           return onChangeHandler.call(component, evt, item);
        }
    }, component);

    //Even for Firefox, if one immediately scrolls the grid after changing a value, the onchange won't fire right
    // away and the clean event may remove the row while it still had focus, losing the changes.
    Ext.EventManager.on(element, 'keyup', taskUpdateFunc, component);

    // Ext.isIE flag will be true for IE 8 mode and false for IE 11. 
    if (Ext.isIE || PTC_isIE11) {
        /**
         * The onchange event is not propagated to the parent DIV in IE 8 mode as it is specified in the Web Standards.
         * Because of this different event handling had to be used for IE 8 mode than for FireFox/Chrome/IE 11.
         * In IE 8 mode rather than handling change events we are handling keypress and click events.
         * These events are fired more frequently so they have been wrapped in a Ext DelayedTask
         * so that only the last one in a time period will be processed to save the data.
         */

       // SPR 5749723: We need to do this in IE11 as well.
       Ext.EventManager.on(element, 'click', taskUpdateFunc, component);
    }

    component.on('render', function(){
        PTC.wizard.saveTableData.registerDomChangeEvents.call(component, element);
    }, component);
};

/**
 * Saves the checkbox cell values to each row in the store
 */
PTC.wizard.saveTableData.saveAllRowsValues = function(table, colindex, item){
    if (colindex > 0) {
        var store = table.getStore();
        var checkboxOn = item.checked;
        store.each(function(record){
            var cell = record.get(table.getColumnModel().config[colindex].id);
            PTC.wizard.saveTableData.toggleCheckboxes(cell, checkboxOn);
        });
    }
};

/**
 * Adds or removes checked attribute in cell html of store
 * 
 * @param {Object} cell
 * @param {boolean} checkboxOn
 */
PTC.wizard.saveTableData.toggleCheckboxes = function(cell, checkboxOn){
    if(cell && cell.gui && cell.gui.html){
        var cellHtml = cell.gui.html;
        var mid = cellHtml.indexOf('type=\"checkbox\"');
        if(mid < 0){
            return; // return if it's not checkbox
        }

        var start = cellHtml.lastIndexOf('<input', mid);
        var end = cellHtml.indexOf('>', mid);
        var checkboxTag = cellHtml.substring(start, (end + 1));
        var checkedStr = 'checked';
        var beforeCheckBox = cellHtml.substring(0, start);
        var afterCheckBox = cellHtml.substring(end + 1, cellHtml.length);

        if(checkboxOn){
            if(checkboxTag.indexOf(checkedStr) < 0){
               checkboxTag = checkboxTag.replace('<input', '<input checked');
            } else {
               //checkbox is already checked, return
               return;
            }
        } else {
            checkboxTag = checkboxTag.replace(checkedStr, '');
        }
        cell.gui.html = beforeCheckBox + checkboxTag + afterCheckBox;
    }
};

/**
 * Calls the domChangeEventListener on the container (Grid/Panel) where the dom element (i.e. attribute) is in.
 * This way the saveTableData code is notified and can do the needful for saving value back to the Grid/Panel store. 
 * For example, the multi valued input component calls this when the '-' button is clicked, values are changed 
 * to blank/false/un-selected by js code. 
 * 
 * @param element - the dom element that changed value, such as an input field, textarea, select box, etc.
 */
PTC.wizard.saveTableData.callDomChangeListener = function (element) {
    var tableId = tableUtils.findParentTableNodeId(element);
    
    // get the table if the attribute was in a table, otherwise get the Attribute Panel
    var component = (tableId) ? Ext.getCmp(tableId) : PTC.attributePanel.findParentAttributePanel(element);
    
    // call the dom change event listener, to update the grid/panel store with the new element value
    if(component && component.domChangeEventListener) {
        component.domChangeEventListener(null, element);   
    }
};



// properties used when a table view is changed, used to maintain the scroll location of the content area
PTC.jca.table.scroll.SCROLL_TO_TABLE = '';
PTC.jca.table.scroll.SCROLL_TO_OFFSET = '';

/**
 * Future consideration: Move the entire scroll specific code to a generic namespace.
 * For e.g. 'PTC.jca.scroll' instead of 'PTC.jca.table.scroll'.
 */
PTC.jca.table.scroll.contentAreaPanel = null;
PTC.jca.table.scroll.log = log4javascript.getLogger('PTC.jca.table.scroll');

PTC.jca.table.scroll.updateTableWidth = function(wTablePanel, width, height) {
    if (wTablePanel) {
        var tableGrid = wTablePanel.getGridPanel();
        // SPR 1978633: script error when switching between diff product folder browsers
        if (tableGrid) {
            PTC.jca.ColumnUtils.resizeAllColumns(tableGrid, width, height);
        }
    }   
};

/**
 * Update the size of the table for the given tableId
 * @param {String} tableId
 * @param {Boolean} [heightOnly] Pass true to update the height of the table, not the width. Defaults to false
 * @param {Number} [width] Pass a width value to set the table width. Defaults to false. 
 *      Don't need to set the width when the table first loads, but do need to set the width when the window resizes. 
 */
PTC.jca.table.scroll.updateTableSize = function(tableId, heightOnly, width,tabRefresh){
    if (tableId) {
        var cmp = Ext.getCmp(PTC.jca.table.getWTablePanelID(tableId));
        var newHeight;
        if (cmp) {
            if (!cmp._updateSizeTask || tabRefresh === true) {
                cmp._updateSizeTask = new Ext.util.DelayedTask(function(tableId, heightOnly, width) {
                    // each chunk load does not need to update size, in fact try to only update size 1 time
                    var cmp = Ext.getCmp(PTC.jca.table.getWTablePanelID(tableId));
                    if (!cmp) {
                        return;
                    }

                    var grid = cmp.getGridPanel();
                    // Checking for grid Width. If it's 0, that means that the grid is rendered on a hidden panel
                    // and we do not need to update the table.
                    if(grid.getInnerWidth()>0){
                    // remove the extra 4 pixels we add when setting the new height
                    var oldHeight = grid.getHeight()-4;
                        var cachedTableHeight = grid.getCachedTableHeight();
                        if (cachedTableHeight) {
                           newHeight = cachedTableHeight;
                        } else {
                           newHeight = PTC.jca.table.scroll.calculateTableHeight(cmp);
                        }
                        // remove any horizontal scrollbar caused by the stretcher column before proceeding further.
                        grid.colModel.setColumnWidth(grid.colModel.getIndexById(PTC.jca.table._STRETCHER_ID), 1);
                        if (heightOnly !== true) {
                            PTC.jca.ColumnUtils.resizeAllColumns(grid, null, newHeight, true);
                            var defaultTableHeight= cmp._defaultHeight?cmp._defaultHeight:0;
                            newHeight-=defaultTableHeight;
                            defaultTableHeight= PTC.jca.table.scroll.getDefaultTableHeight(cmp,true);
                            newHeight+=defaultTableHeight;
                        }

                        if (Math.abs(newHeight - oldHeight) > 15 || grid.alwaysSetHeight === true) {
                            // changing height is expensive, don't change if its trivial
                            grid.setHeight(newHeight + 4);//adding some extra pixel as on resize table event to avoid vertical scrollbars.
                            grid.alwaysSetHeight = false;
                        }
                        //resize last column only after set the height of grid to avoid any extra Hscrollbar in consideration.
                        PTC.jca.ColumnUtils.resizeLastColumn(grid, null, newHeight);
                    }
                });
            }
            cmp._updateSizeTask.delay(10, null, null, [tableId, heightOnly, width]);
        }
    }
};
    
/**
 * This function returns the default height of the table.
 * Following table components are considered while calculating default height:
 *    1) Titlebar
 *    2) Menubar
 *    3) Toolbar
 *    4) Column header height
 *    5) Horizontal toolbar height (if present)
 *    6) Pagingbar
 *   
 * @param {Object} wTablePanel
 * @return {Integer} default table height
 */
PTC.jca.table.scroll.getDefaultTableHeight = function(wTablePanel, recalculate) {
    if (wTablePanel._defaultHeight && !recalculate) {
        // caching the height because during datasource chunk rendering, the table becomes very large and asking for
        // the heigh is very expensive and this is not a value that changes.  Reset this value on bodyresize incase 
        // of scrollbars.
        return wTablePanel._defaultHeight;
    }
    var gPanel = wTablePanel.getGridPanel();
    var defaultHeight = 0;
    // TODO: Try to remove this hard coded horizontal scroll bar height.
    var defaultScrollBarHeight = 19;
    
    var headerDiv = getElementsByClassNameAndTag("x-grid3-header", gPanel.getEl().dom, "div")[0];    
    var panels = [gPanel.tbar, Ext.fly(headerDiv), gPanel.bbar, gPanel.footer];
    panels.each(function(panel) {
        if (panel) {
            defaultHeight += panel.getHeight();
        }
    });
    
    var gView = gPanel.getView();
    var tableBodyWidth = gPanel.getColumnModel().getTotalWidth(false);

    if (gPanel.getEl().dom) {
        var tableWidth = gPanel.getWidth();
        
        if (tableBodyWidth >= tableWidth) {
            // If horizontal scrollbar is present, consider its height as well.
            defaultHeight += defaultScrollBarHeight;
        }
    }
    if (defaultHeight > 40) {
        wTablePanel._defaultHeight = defaultHeight;
    }
    return defaultHeight;
};

/**
 * Clear the content area handle as soon as the user moves to some other page.
 */
PTC.navigation.on("historyChange", function() {
    if (PTC.jca.table.scroll.contentAreaPanel !== undefined) {
        PTC.jca.table.scroll.contentAreaPanel = undefined;
    }    
});

/**
 * This function allows users to specify their own customized Ext panel (if any), 
 * other than the default ones, where the table/tree is placed.
 * @param {Object} contentArea
 */
PTC.jca.table.scroll.setContentArea = function (contentArea, component) {
    if(component)
    {
        component.contentAreaPanel=contentArea;
    }
};

/**
 * This function returns the handle of the parent content area in which the table resides.
 * @return {Ext.Element} handle to parent content area
 */
PTC.jca.table.scroll.getContentArea = function(element) {
    var ca;
    if(element){
        if(element.contentAreaPanel){
            ca = element.contentAreaPanel;
        } else {
            var parentDiv = element.findParentNode("div.x-panel");
            if (parentDiv !== null) {
                PTC.jca.table.scroll.log.debug("parentDiv id: " + parentDiv.id);
                ca = Ext.getCmp(parentDiv.id);
                if(ca && ca.getHeight()===0)
                {
                    ca =ca.getEl().findParentNode("div.x-panel");   
                }
            }
            // If contentArea not found and its a wizard step then set wiz_step_contents as content area.
            if(!PTC.isDefined(ca) && isWizardWindow()) {
                ca = Ext.get("wiz_step_contents");
            }
        }
    }else{
        ca = Ext.getCmp(PTC.navigation.cardManager);
        if (ca) {
            ca = ca.layout.activeItem;
        }
    }
    if (ca && typeof ca.getEl === 'function') {
        ca = ca.getEl();
    }
    PTC.jca.table.scroll.setContentArea(ca,element);
    return ca;
};


/**
 * @param {Object} wTablePanel
 * @return {Integer} (top + bottom) margin height of a table.
 */
PTC.jca.table.scroll.getTableMarginHeight = function(wTablePanel) {
    var tableMargin = 0;
    var tableId = tableUtils.getFormattedTableId(wTablePanel.getGridPanel().getId());
    var tableOuterFrame = Ext.get(tableId);
    if (tableOuterFrame) {
        tableMargin = tableOuterFrame.getMargins("tb");
    }
    //adding 15 pixel more to avoid borderline conditions.
    return tableMargin + 15;
};

/**
 * This function returns the minimum height of a table. The table height cannot be reduced beyond this limit.
 * Design consideration: Atleast 3 rows should be displayed. 
 * @param {PTC.jca.WTablePanel} wTablePanel
 * @return {Number} minimum height of a table.
 */
PTC.jca.table.scroll.getMinimumTableHeight = function(wTablePanel) {
    return PTC.jca.table.scroll.getDefaultTableHeight(wTablePanel) + (wTablePanel.rowHeight * 3);
};

/**
 * This function calculates and returns appropriate height of the table based on its parent content area.
 * @param {Object} wTablePanel
 * @return {Integer} height of the table 
 */
PTC.jca.table.scroll.calculateTableHeight = function(wTablePanel) {
    var defaultHeight = PTC.jca.table.scroll.getDefaultTableHeight(wTablePanel);
    var gPanel = wTablePanel.getGridPanel();
    var gridPanel_dom = gPanel.getEl().dom;
    var gView = gPanel.getView();
    var rHeight = typeof gView.getCalculatedRowHeight === 'function' ? gView.getCalculatedRowHeight() : wTablePanel.rowHeight;
    
    // Calculate table height based on total number of rows. For tree total number of rows in store are not same as rendered row.
    var iViewRows=0;
    if(gPanel.tree){
        iViewRows=gView.getAllRenderableRows().length;
    }else{
        iViewRows=gPanel.store.getCount();
    }
    if (iViewRows === 0) {
        defaultHeight += 2 * rHeight;
        return defaultHeight;
    }
    var gridHeight = 0;
    var newHeight = 0;
    /**
     * For editable columns (mostly in Wizards), the row height may vary.
     * Is there any way to know whether the table is editable or not?
     * TODO: Need to get rid of hard coded value '10'. 
     */
    // considering view height also just for performance measure in case for variable row height tables 
    // height of table is not needed to be calculated more than its maximum possible size.
    var contentArea = PTC.jca.table.scroll.getContentArea(gPanel.getEl());
    
    var contentAreaHeight = 0;
    if (contentArea !== null || contentArea !== undefined) {
        //  so non-shell/non-wizard pages work ok
        //      SPR 1967533 - script errors on CSIP/WSIP of cad doc.
        if (contentArea && typeof contentArea.getInnerHeight === 'function') {
            contentAreaHeight = contentArea.getInnerHeight();
        } else if (contentArea && typeof contentArea.getHeight === 'function') {
            contentAreaHeight = contentArea.getHeight();
        } else {
            contentAreaHeight = getWindow().getWindowHeight();
        }
    }

    if (iViewRows <= 10 || gView.variableRowHeight) {
        for (var i = 0; i < iViewRows; i++) {
            var record = gView.getRowsForTableTree(i);
            if (record !== undefined) {
                gridHeight += (("offsetHeight" in record) && (record.offsetHeight > 0))
                                    ? record.offsetHeight : record.getHeight();
            }else {
                gridHeight += rHeight;
            }
            if(gridHeight >= contentAreaHeight){
                break;
            }
        }
    } else {
        gridHeight = iViewRows * rHeight;
    }
    gView.cumulativeRowHeight= gridHeight;
    newHeight = gridHeight + defaultHeight;
    
    if (contentArea === null || contentArea === undefined) {
        /*If rows are less than three, consider scroll bar height while calculating the table height 
          to show rows without getting hidden as vertical scrollbar will get rendered after three rows. */
        if (iViewRows < 15) {
            newHeight += rHeight;
            return newHeight;
        }
    }
    
    //while calculating height of table we should consider height of extra rows which are rendered to show group information,
    if(gPanel.store.groupField)
    {
        // trying to avoid hard coding of height of new rows added due to groupig.
        var firstGroupRow = gView.getGroups()[0].firstChild;
        var groupRowHeight = firstGroupRow? Ext.get(firstGroupRow).getHeight():0;
        var groupingRows = gView.getGroups().length;
        iViewRows+=groupingRows;
        newHeight += (groupingRows*groupRowHeight);
    }
    
    // If no of rows are 1 then set height of grid so to accommodate 1 extra blank row. This is needed to give proper
    // space to render horizontal scrollbar if needed.
    // In case if variablerowHeight is true and one row is taking more space than default space required for 2 rows we
    // should set height for one row only. Also if there are no rows in grid default behaviour should exist.
    if (iViewRows < 2) {
        var minHeight = (2 * rHeight) + defaultHeight;
        return minHeight > newHeight ? minHeight : newHeight;
    }
    //if no of rows are 3 or less than 3 then set the actual height of the grid. No need to consider content area as we
    //have to show minimum r rows in any case. 
    if(iViewRows<4)
    {
        return newHeight;
    }
    
    // Get the table offset height.
    var offsetHeight = gridPanel_dom.offsetTop;
        
    // Check if the total table height is more than the available content area.
     var tableMarginHeight = PTC.jca.table.scroll.getTableMarginHeight(wTablePanel);
    if ((newHeight + offsetHeight + tableMarginHeight) > contentAreaHeight) {
        newHeight = contentAreaHeight - offsetHeight - tableMarginHeight;
        var oldHeight = gPanel.getHeight();
        // setheight on gridpanel is not called if difference is less than 15 pixcel.But in this case to avoid the 
        // scroll to content panel we need to setheight if the height is less than 15 pixcel 
        gPanel.alwaysSetHeight = oldHeight > newHeight;

        var minimumTableHeight = PTC.jca.table.scroll.getMinimumTableHeight(wTablePanel);
        if (newHeight <= minimumTableHeight) {
            return minimumTableHeight;
        }
    }
    return newHeight;
};

PTC.jca.table.scroll.handleScrollingGrids = function(wTablePanel, rowStore) {
    wTablePanel.gridPanel.autoHeight = false;
    /**
     * Resize the table after store load. 
     * This is only for non Data source enabled tables and not for data source enabled tables and trees.
     */
    rowStore.on({
        'load': function(store, records, options) {
            if (!wTablePanel.getGridPanel().jcaTableConfig.chunk && !(wTablePanel.getGridPanel().tree)) {
                PTC.jca.table.scroll.updateTableSize(wTablePanel.getGridPanel().getId());
            }
        }
    });
};

/**
 * To Handle the Verticle Scroll Tip First Visible row Index.
 * @param gridView 
 * @param scrollTop postion of Scroll Top 
 */
PTC.jca.table.scroll.getFirstVisibleRowIdx = function(gridView, scrollTop){
    // Get Visible Rows
    var visibleRows = gridView.getVisibleRows();
    var firstRowIdx = 0;
    if (visibleRows !== null || visibleRows !== undefined) {
        firstRowIdx = visibleRows.first;
    }
    // Adjust the visible row index according to position.
    if(firstRowIdx > 0) {
        firstRowIdx = visibleRows.indexes?visibleRows.indexes[2]:firstRowIdx+2;
    }
    if(firstRowIdx === 0 && scrollTop  > 0) {
        firstRowIdx = visibleRows.indexes?visibleRows.indexes[1]:firstRowIdx+1;
    }
    return firstRowIdx;
};
/**
 * This method will return the column Index.
 * If the sort string is present then it will return columnId of primary sort column.
 * If the sort string is NOT present then currently we are checking if we have name/ number
 * column present in it and return the columnId of it.
 */
PTC.jca.table.scroll.getVerticalScrollTipColumnId = function(gridPanel, tableId) {
    var multiSortStr = PTC.jca.getMultiColumnSortString(tableId);
    var columnDisplay;
    var colModel = gridPanel.getColumnModel();
    if (multiSortStr === null || multiSortStr === undefined) { // Sort column is not specified
        var colCount = colModel.getColumnCount();
        var columnIndex;
        for (columnIndex=0 ; columnIndex < colCount; columnIndex++) {
            if (!colModel.isHidden(columnIndex)) {
                var tempColumn = colModel.getColumnId(columnIndex);
                //TODO: Find the first Text Column
                if((tempColumn === "name" || tempColumn === "number"))
                {
                    columnDisplay = tempColumn;
                    break;
                }
             }
        }
    } else { // Sort column is specified
        var multiSortArray = multiSortStr.split(PTC.jca.SORT_DELIMITER);
        columnDisplay = multiSortArray[0];
    }
    /*
     * If the column is editable the value of Modifiable comes as a true. In case of Editable columns
     * Vertical scroll tooltip is not required.
     */
    if(columnDisplay &&  colModel.getColumnById(columnDisplay) && colModel.getColumnById(columnDisplay).modifiable === true) {
        return null;
    }

    return columnDisplay;
 };


/**
 * Detects if the window contains a scrollbar and returns the width the table should subtract for it.
 * Otherwise it will return a default value to match padding / default gaps.
 * @param {Mixed} obj Ext.Element or Ext.Component
 */
PTC.jca.table.scroll.getWindowScrollbarWidth = function(obj){
    var scrollbarWidth = 10;
    // convert the objec to a domElement
    obj = PTC.util.getDom(obj);
    // the document could be checked in addition, offset + scrollheight
    if (obj && obj.scrollHeight >= obj.clientHeight) {
        scrollbarWidth = Ext.getScrollBarWidth() + scrollbarWidth;
    }
    return scrollbarWidth;
 };


