// The function identifies the position of a html element
// It climbs up the document tree to calculate the offset position
function getOffsetTop(el) {
    var ot = el.offsetTop;
    while ((el = el.offsetParent) !== null) {
        ot += el.offsetTop;
    }
    return ot;
}

