function validateResultPerPage() {
    var pageName = getElementByName("pageCount");
    var pageValue = pageName.value;

    var pageMaxCount = getElementByName("maxPageCont");
    var arrayList = new Array(pageMaxCount);
    var pagemaxValue = pageMaxCount.value;

    // To strip leading and trailing spaces
    pageValue = pageValue.replace(/(^\s+|\s+$)/g, '');
    if (pageValue === null || pageValue.length === 0 || pageValue <= 0 || isNaN(pageValue)
            || pageValue != Math.round(pageValue)) {
        JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.MESSAGE_RESULT_PER_PAGE");
        return false;

    }

    if (pagemaxValue === null || pagemaxValue.length === 0 || parseInt(pagemaxValue) < parseInt(pageValue)) {
        JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.RESULT_PER_PAGEMAX_CAP", pagemaxValue);
        return false;

    }

    return true;
}

function checkBoxValidation() {

    var containerName = document.getElementById('containerTypeList');
    var containerValue = containerName.value;
    var member = getElementByName('memberOfContainer');
    var organization = getElementByName('searchInUserOrg');

    var mainForm = getMainForm();
    var action = mainForm.action;

    if (containerValue === "" || containerValue === "wt.inf.library.WTLibrary"
            || containerValue === "wt.pdmlink.PDMLinkProduct" || containerValue === "wt.projmgmt.admin.Project2") {

        // added null checks for these two checkboxe's value as it was throwing a javascript error in Ondemand situation
        // when the two checkboxes
        // don't get rendered
        if (member) {
            member.disabled = false;
        }// end if member !=null

        if (organization) {
            organization.disabled = false;
        }// end if organization!=null

        // remove containerRef from URL as this is interpreted as context in validators
        // whereas this is not passed to search since containerType is selcted in this combo
        mainForm.action = removeParamFromString("containerRef", action);
    }// end if containervalue ==""
    else {
        // context oid is being selected again.
        // put this context oid back in URL.
        var delim = (action.indexOf('?') == -1) ? '?' : '&';
        mainForm.action = action + delim + 'containerRef=' + containerValue;
        if (member) {
            member.checked = false;
            member.disabled = true;
        }// end if member !=null

        if (organization) {
            organization.checked = false;
            organization.disabled = true;
        }// end if organization!=null
    }
}

