// function from preSearchResults.jsp
function contentsRefreshOnTVMClose(table_id) {
    if (isSearchTable(table_id)) {

        if (Ext.getDom('searchResultsPage')) {
            PTC.search.loadResultsTableComp();
        } else {
            if (typeof (getMainForm().customizeQueryPage) !== 'undefined') {
                window.location.href = window.location.href;
            } else if (typeof (getMainForm().executingProeSearch) !== 'undefined') {
                document.location.reload();
                return;
            } else if (getMainForm().searchFired) {
                fireSearch();
            } else {
                getMainForm().fireSearch.value = 'false';
                PTC.search.refreshPage();
            }
        }

        return false;
    }
    return true;
}

function isSearchTable(table_id) {
    var table = document.getElementById(table_id);
    var searchTable = false;
    if (table !== undefined) {
        var parent = table.parentNode;
        var count = 0;
        // for better performance checking parent up to 5 levels only as search table div won't be any higher
        while (parent !== undefined && parent !== null && !searchTable && count++ < 5) {
            if (parent.id == 'searchResultTableDiv') {
                searchTable = true;
            }
            parent = parent.parentNode;
        }
    }
    return searchTable;
}

