function validateSearch() {
    // set report template hidden field before search
    PTC.search.ReportTemplate.reportTemplatePreSearch();

    PTC.search.performance.logger.fire('logPerformanceEvent', {
        eventName: 'Validate Search'
    });
    if (searchButton.disabled === true) {
        return false;
    }

    var validateEmptyAndXMLTagSearchFired = false;
    var validationResult = false;

    searchButton.setDisabled(true);
    try {
        $('searchButtonLoaderDiv').show();
        populateContainerRefForActions();
        // Fixing SPR 1847665-01. This function should actually validate
        // for empty query but right now the validations is not happening
        // as for X-20 we need to change all of the empty query validation.

        validationResult = PTC.search.validateSpecialTypes(PTC.search.dataStore);
        if (validationResult === false) {
            return;
        }

        validationResult = PTC.search.validateSingleContextSearch(PTC.search.dataStore);
        if (validationResult === false) {
            return;
        }

        var isEmptyQuertValidationEnabled = document.getElementById("isEmptyQuertValidationEnabled");
        var isScopeSearchEnabled = document.getElementById("isXMLTagSearchEnabled");
        if ((PTC.isDefined(isEmptyQuertValidationEnabled) && isEmptyQuertValidationEnabled.value === "true")
                || (PTC.isDefined(isScopeSearchEnabled) && isScopeSearchEnabled.value === "false")) {
            validateEmptyAndXMLTagSearchFired = PTC.search.checkForEmptyAndXMLTagSearch();
            // alert("emptySearchFired==="+emptySearchFired);
            // alert("validationResult==="+emptySearchFired);
            if (validateEmptyAndXMLTagSearchFired === true) {
                PTC.search.performance.logger.fire('logPerformanceEvent', {
                    eventName: 'Validate Search',
                    isEndEvent: true
                });
                return false;
            }
        }
        if (validationResult === false) {
            PTC.search.performance.logger.fire('logPerformanceEvent', {
                eventName: 'Validate Search',
                isEndEvent: true
            });
            return false;
        }

    } finally {
        // enable search button
        if (validationResult === false || validateEmptyAndXMLTagSearchFired === true) {
            enableSarchButton();
        } else {
            setTimeout("enableSarchButton()", 10000);
        }
    }

    // dummy function to avoid javascript error on customizeQuery page
    // if view is changed from view manager
    PTC.search.performance.logger.fire('logPerformanceEvent', {
        eventName: 'Validate Search',
        isEndEvent: true
    });
    return true;
}

// Check if types are selected for which single context selection is not allowed then show alert message.
PTC.search.validateSingleContextSearch = function(typeStore) {
    var denySingleContextSearch = false;
    var typeSelected = "";
    var filteredRecords = typeStore.query('checked', 'true');
    if (filteredRecords.item('wt.fc.Persistable')) {
        if (filteredRecords.item('wt.fc.Persistable').get('checked') === true) {
            return true;
        }
    }
    var cb = Ext.getCmp('all_contexts');
    for (var j = 0; j < filteredRecords.getCount(); j++) {
        if (filteredRecords.items[j].get('denySingleContextSearch') === true) {
            if (cb.checked === false) {
                if (typeSelected === '') {
                    typeSelected = PTC.search.decodeForHTMLContent(filteredRecords.items[j].get('displayValue'));
                } else {
                    typeSelected = typeSelected + ", "
                            + PTC.search.decodeForHTMLContent(filteredRecords.items[j].get('displayValue'));
                }
                denySingleContextSearch = true;
            }
        }
    }
    if (!denySingleContextSearch) {
        return true;
    } else {
        var insertArr = new Array(typeSelected);
        JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.DENY_SINGLE_CONTEXT_SEARCH", "",
                insertArr);
        return false;
    }
};

