/* Should be used to load history & saved search and classification search pages */
function loadSearchPage(maintab, subtab, event, url) {
    // Calling the open navigator as call back so that the
    // even getting passed is also completed. Else navigator collapses if we launch it from
    // search field glass.
    // doNotMaintainStickiness flag is to indicate whether to maintain stickiness on clf browse or not.
    if (subtab === 'classificationExplorerNavigation') {
        PTC.search.doNotMaintainStickiness = true;
    }
    openNavigator.defer(5, this, [maintab, subtab, url]);
}

function openNavigator(maintab, subtab, url) {
    PTC.navigator.setActiveSubTab(maintab, subtab, url, true);
}
/* Should be used to load advanced search page */
function loadAdvSearchPage(event, url) {
    if (typeof (resultParams) !== 'undefined' && !Ext.isEmpty(resultParams.searchResultsViewId)) {
        // Seems strange that resultParams is search specific, yet global. This entire frag could make use of a search
        // namespace.
        // Need to clear any existing filters before search executes.
        PTC.jca.table.stickiness.clearTableStickiness(resultParams.searchResultsViewId);
        PTC.search.clearSearchInTable();
    }
    loadSearchPage('object_search_navigation', 'advancedNavigation', event, url);
}

function validateNumericValue(event, textBoxName) {
    var tb = $(textBoxName);
    var value = Ext.util.Format.trim(tb.value);
    var result = /^-?\d+$/.test(value);
    // Negative values are not supported for this validation
    if (result) {
        if (value < 0) {
            result = false;
        }
    }
    result = (result || value === '');
    if (!result) {
        JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.INVALID_NUMBER");
        var isIE = navigator.userAgent.indexOf("MSIE") > -1;
        if (isIE) {
            event.cancelBubble = true;
        } else {
            event.stopPropagation();
        }
        setTimeout(function() {
            tb.focus();
            tb.select();
        }, 20);
    }
}

