/**
 * Extends the Ext.form.Checkbox adding the gui functionality of changing bg color and displaying an 'x' image on mouse
 * hover and providing a hook to call a function to handle removeing the checkbox.
 * 
 * Additional Config Options: onRemoveFunction {function} The function to be called when the delete icon is clicked.
 * This function needs to handle removing the checkbox from the gui and any additional work to maintain the correct
 * state. The function is called in the context of the checkbox (i.e. the 'this' reference points to the checkbox whose
 * 'x' was clicked).
 * 
 * NOTE: This implementation assumes that 'id' and 'boxLabel' are set in the config object passed to the constructor and
 * will fail if those properties are not set!
 */
PTC.search.RemovableCheckbox = Ext.extend(Ext.form.Checkbox, {
    onRemoveFunction: function() {
    },
    onMouseEnterFunction: function(e, t, o) {
        deleteDiv = Ext.get(this.getId() + '_deleteDiv');
        deleteDiv.show();

        // t refers the enclosing Div. Hence adding the tooltip for this enclosing div.
        if (this.qtip) {
            t.title = PTC.search.decodeForHTMLContent(this.qtip);
        }
    },
    onMouseLeaveFunction: function(e, t, o) {
        deleteDiv = Ext.get(this.getId() + '_deleteDiv');
        deleteDiv.hide();
    },

    onAfterRenderFunction: function(elem) {
        enclosingElem = elem.getResizeEl();
        enclosingElem.addClassOnOver('removableCheckboxHover');
        enclosingElem.on('mouseenter', this.onMouseEnterFunction, elem);
        enclosingElem.on('mouseleave', this.onMouseLeaveFunction, elem);
    },

    constructor: function(config) {
        // check to see if the boxLabel already has the delete span image, e.g. the object is being cloned.
        if (config.boxLabel.indexOf('_deleteDiv') === -1) {
            config.boxLabel = config.boxLabel + '  <span class=\'removeActionStyle\' id=\'' + config.id
                    + '_deleteDiv\' style=\'display:block;float:right;padding-top:5px;padding-right:5px;\'>'
                    + '<a href="javascript:PTC.search.RemoveCheckboxCallback(\'' + config.id + '\');">'
                    + '<img src=\'netmarkets/images/cancel9x9.gif\' /></a></span>';
        }
        // can only set these js event handlers on the containing element after the checkbox is rendered by Ext; since
        // the containing element in not present in the DOM until then.
        if (config.listeners) {
            listeners = config.listeners;
            listeners.afterrender = {
                fn: this.onAfterRenderFunction
            }, config.listeners = listeners;
        } else {
            config.listeners = {
                afterrender: {
                    fn: this.onAfterRenderFunction
                }
            }
        }
        config.style = 'float:left; width:20px;';
        config.labelStyle = 'float:left; width:140px; white-space: nowrap;';
        PTC.search.RemovableCheckbox.superclass.constructor.call(this, config);
        if (config.onRemoveFunction) {
            this.onRemoveFunction = config.onRemoveFunction;
        }
    }
});

/**
 * Globally defined callback for the clicking the 'x' images of a RemovableCheckbox. Gets the checkbox via the passed in
 * ID and then calls the remove function configured for that checkbox
 */
PTC.search.RemoveCheckboxCallback = function(id) {
    var checkbox = Ext.getCmp(id);
    checkbox.setValue(false);
    checkbox.onRemoveFunction();
}

/**
 * Function to handle removing a checkbox from the context area
 */
PTC.search.RemoveContextCheckbox = function() {
    this.suspendEvents(false);
    if (this.getValue()) {
        this.setValue(false);
        this.fireEvent('check', this, false);
    }
    var id = this.getId();
    PTC.search.recentlyUsedContexts.removeKey(id);
    this.destroy();
    // remove the context from the recently visited list
    Ext.Ajax.request({
        url: 'ptc1/contextComp/removeContextFromList.jsp',
        params: {
            contextToRemove: id
        },
        mode: 'POST'
    });
    PTC.search.setMyFavAndAllContextStatus();
}

