PTC.search.checkForEmptyAndXMLTagSearch = function() {
    var sForm = Ext.Ajax.serializeForm(getMainForm());
    var isEmptySearch = true;
    var isXMLTagSearchFiredAndDisabled = false;
    var ajaxOptions = {
        asynchronous: false,
        method: "POST",
        onSuccess: function(response) {
            var jsonData = Ext.util.JSON.decode(response.responseText.trim());
            var resultMessage = jsonData.message;

            // Handle session timeout
            if (resultMessage == "Session Timeout") {
                JCAAlert('com.ptc.windchill.enterprise.search.client.searchClientResource.SESSION_EXPIRED_MSG');
                return false;
            }

            var emptySearchFired = jsonData.emptySearchFired;
            var typesList = jsonData.removeTypesMessage;
            isEmptySearch = emptySearchFired;
            isXMLTagSearchFiredAndDisabled = jsonData.isXMLTagSearchFiredAndDisabled;
            // the below banner message is shown when the typesList contains some parent types that should be removed.
            // Story B-100525
            var title = bundleHandler
                    .get('com.ptc.windchill.enterprise.search.client.searchClientResource.PARENT_TYPE_SELECTED_MESSAGE_TITLE');
            var message = bundleHandler
                    .get('com.ptc.windchill.enterprise.search.client.searchClientResource.PARENT_TYPE_SELECTED_MESSAGE');
            if (typesList.length > 0) {
                PTC.search.showBannerMessage(title, [message + " : " + typesList], "WARNING");
            }
            if (isEmptySearch == true && resultMessage != ("Do Nothing")) {
                alert(resultMessage);
            }
            if (isXMLTagSearchFiredAndDisabled == true) {
                alert(resultMessage);
            }
        },
        parameters: sForm
    };

    requestHandler.doRequest('netmarkets/jsp/search/validateSearch.jsp', ajaxOptions);
    if (isEmptySearch || isXMLTagSearchFiredAndDisabled)
        return true;

}

