function item1Handler(item) {

    var lastUiID = 0;
    if (qbCriteriaStore.getCount() > 0) {
        lastUiID = qbCriteriaStore.getAt(qbCriteriaStore.getCount() - 1).data.UiID + 1;
    }
    var required = false;

    var recs = qbCriteriaStore.query('beanID', item.internalValue);

    if (recs.length > 0)
        required = recs.get(0).get('required');

    Ext.Ajax.request({
        url: getBaseHref() + 'netmarkets/jsp/search/addNewQBRow.jsp',
        success: loadTable,
        params: {
            searchtypes: document.getElementById('searchType').value,
            isAdd: 'true',
            criteria: item.internalValue,
            containerTypeList: getContainerTypeList(),
            rownum: lastUiID,
            required: required,
            displayVal: item.text,
            displayUnit: item.displayUnit,
            dataType: item.dataType,
            searchCompAttrId: item.searchCompAttrId
        }
    });

}

function loadTable(response, options) {

    var responseJSON = Ext.util.JSON.decode(response.responseText);
    var storeRowJson = Ext.util.JSON.decode(responseJSON.storeRow);

    var rowElement = document.getElementById('qbtable').insertRow(-1);
    Element.update(rowElement, responseJSON.htmlRow);
    rowElement.id = 'qbrow' + options.params['rownum'];
    rowElement.onmouseover = highlightRow;
    rowElement.onmouseout = deHighlightRow;

    qbCriteriaStore.add(new qbCriteriaStore.recordType({
        "UiID": storeRowJson.UiID,
        "beanID": storeRowJson.beanID,
        "required": storeRowJson.required,
        "displayVal": storeRowJson.displayVal,
        "displayUnit": storeRowJson.displayUnit,
        "dataType": storeRowJson.dataType,
        "searchCompAttrId": storeRowJson.searchCompAttrId
    }));
    document.getElementById('criteriaJSON').value = jsonEncodeStore(qbCriteriaStore);

}

function highlightRow() {
    var type = this.getAttribute("type");
    if (type != 'group') {
        this.childNodes[0].className = 'QBRowHighlight';
        this.childNodes[1].className = 'QBRowHighlight';
        this.childNodes[2].className = 'QBRowHighlight';
        this.childNodes[3].childNodes[0].className = 'QBRowHighlight';
        if (this.childNodes[3].childNodes[0].lastChild.tagName == 'SPAN') {
            this.childNodes[3].childNodes[0].lastChild.style.visibility = 'visible';
        }
    }
}

function deHighlightRow() {
    var type = this.getAttribute("type");
    if (type != 'group') {
        this.childNodes[0].className = '';
        this.childNodes[1].className = '';
        this.childNodes[2].className = '';
        this.childNodes[3].childNodes[0].className = '';
        if (this.childNodes[3].childNodes[0].lastChild.tagName == 'SPAN') {
            this.childNodes[3].childNodes[0].lastChild.style.visibility = 'hidden';
        }
    }
}

function deleteMyRow(rowId, uiId) {
    var mytable = document.getElementById('qbtable');
    var rowElement = document.getElementById(rowId);
    var rowindex = rowElement.rowIndex;
    mytable.deleteRow(rowindex);
    qbCriteriaStore.removeAt(rowindex);
    document.getElementById('criteriaJSON').value = jsonEncodeStore(qbCriteriaStore);
}

