// This function would extract the feedback suggestion
// and would display it.
function handleFeedback(feedbacks) {

    var lblSuggestMessage = bundleHandler.get(
            "com.ptc.windchill.enterprise.search.client.searchClientResource.QUERY_SUGGESTION_MESSAGE", null, true);
    var suggest = '';
    var aLink;
    var suggestionFound = false;
    for (i = 0; i < feedbacks.length; i++) {
        var feedback = feedbacks[i];
        if (PTC.isDefined(feedback) && PTC.isDefined(feedback.message)) {
            if (feedback.message.indexOf('SpellSuggest:') > -1) {
                var suggestWord = feedback.message.substr(13);
                suggestionFound = true;
                aLink = "<a href='javascript:executeSuggestionQuery(\"" + escape(suggestWord) + "\")'> <I>"
                        + suggestWord + " </I></a>";
                suggest = suggest + aLink + '&nbsp;';
            } else if (feedback.message.indexOf('ResultIncomplete:') > -1) {
                var msg = feedback.message.substr(17);
                Ext.Msg.alert('Incomplete results', msg);
            } else if (feedback.message.indexOf('Performance:') > -1) {
                var performanceData = eval(feedback.message.substr(12));
                console.log(performanceData);
                PTC.search.performance.logger.processServerData(performanceData);
            } else if (feedback.message.indexOf(PTC.search.feedback.IndexServerDown) > -1) {
                // Index server down, show warning message.
                var msg = feedback.message.substr(PTC.search.feedback.IndexServerDown.length);
                var title = bundleHandler
                        .get('com.ptc.windchill.enterprise.search.client.searchClientResource.WARN_INDEX_SERER_DOWN_FALLBACK_TO_DB_SEAR_TITLE');
                PTC.search.showBannerMessage(title, [msg], 'WARNING');
            }
        }
    }
    if (suggestionFound == true && $('suggestionDiv') != null) {
        $('suggestionDiv').update(lblSuggestMessage + suggest);
    }

}

