// var reqMessage = "[I18N]Required Information Is Missing";

function checkEmptyQuery()
{

   var isEmptySearch = false;
   var isCriteriaEmpty = true;

   var keywordUiID = "keywordField";
   var keywordElement = eval("getElementsById"+keywordUiID+"()");
   var keywordValue = keywordElement[0].value;


   var isEmptySearch = false;
   var isCriteriaEmpty = true;


    var context = "";
		if(searchJSObject.isNetworkSearch || searchJSObject.isRelatedItemSearch)
		{
			context = "";
		}
	else

        {
        	context = $(searchJSObject.idContainerTypeList).value;
        }

                var searchType = $(searchJSObject.idSearchType).value;
   	  if (searchType == "") {
			     isEmptySearch = true;
			     JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.EMPTY_CRITERAI_MESSAGE");
			     return false;
   	  }


      if(context == ""){
                //If search type is All Item Types then the value is reurned as wt.fc.Persistable
                if((searchType.toLowerCase() == "wt.fc.persistable") || (searchType.indexOf(",") > -1)){
                    //Now check if Criteria is empty

             if(!isEmptySearch){
                        if(!checkCriteria(keywordValue) && isCriteriaEmpty){
                            isCriteriaEmpty = false;

                        }
               }

			 if(isCriteriaEmpty){
			     isEmptySearch = true;
			     JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.EMPTY_CRITERAI_MESSAGE");
			     return false;
 		   }
     	  }
		}

       if(!isEmptySearch){
		  return true;
	   }

}

function checkCriteria (inputVar)
{
   // variable fetch the value of PTC.search.singleWildCard global variable (which reads the value of property wt.query.singleWildCard from wt.properties file)
   var singleWildCard = PTC.search.singleWildCard;

   var whitespace = " \t\n\r*%"+singleWildCard;

   var i;

   //To strip leading and trailing spaces
    inputVar = inputVar.replace(/(^\s+|\s+$)/g,'');

   if (inputVar == null || inputVar.length == 0) {
       return false;
   }

   // Search through string's characters one by one
   // until we find a non-whitespace character.
   // When we do, return false; if we don't, return true.

   for (i = 0; i < inputVar.length; i++)
   {
		// Check that current character isn't whitespace.
		var c = inputVar.charAt(i);

		if (whitespace.indexOf(c) == -1) return false;
   }
   // All characters are whitespace.
   return true;
}


