/**
 * Namespace for the search javascript
 */
Ext.namespace('PTC.search.folder');
Ext.apply(PTC.search.folder, new Ext.util.Observable());

/**
 * Renders the search in folder component on the table.
 * @param {PTC.jca.TreeGrid} table
 */
PTC.search.folder.folderSearch = function (table) {
	PTC.search.folder._installSIFGuiComponents(table);
};

/**
 * @private
 * This is private. use PTC.jca.table.folderSearch(table);
 * @param {PTC.jca.TreeGrid} table
 */
PTC.search.folder._installSIFGuiComponents = function(table){
    // start of FIT initialization code:
    var sif_EmptySearchText = bundleHandler.get('com.ptc.windchill.enterprise.search.client.searchClientResource.SEARCH_IN_FOLDER_PROMPT');

    // Status text/tooltip on the find in tree toolbar.
    var sifSearchStatusText = PTC.jca.table.findInTable.getFindStatusText();

    // Size the textfield at 200px, ideally. If the containing panel is too narrow to accomodate that accept a smaller size within reason.
    var sifTextFieldWidth = Math.max(Math.min(table.container.getWidth() - 90, 200), 80);
    if (table.container.getWidth() === 0) { // if the table width is undefined, use default size
        sifTextFieldWidth = 200;
    }

    // text field for search term
    var sifTextField = new Ext.form.TwinTriggerField({
        width: sifTextFieldWidth,
        emptyText: getUnescapedText(sif_EmptySearchText),// The value sif_EmptySearchText comes with HTML encoded characters. To remove that using getUnescapedText()
        value: '',
        selectOnFocus: true,
        id: table.getId() + '.sifTextField',
        tableName: table.getId(),
        table: table,
        enableKeyEvents: true, // to catch editing
        trigger1Class: 'x-form-clear-trigger',
        trigger2Class: 'global-search-trigger',
        hideTrigger1: true,
        cls: 'invalidDrag', // needed so the user can focus on the text field without a "drag" occuring, this was an issue on the info page
        listeners: {
        	'render': function() {
              this.clearTrigger = this.getTrigger(0);
              this.searchTrigger = this.getTrigger(1);
        	},
            'specialkey': function(textField, e){
            	PTC.search.folder.displayClearTrigger(table);
                var keyValue = 0 + e.getKey(); // add to 0 is essential, else == tests fails inexplicably
                if (keyValue == e.ESC) {
                	this.clearTrigger.hide();
                	PTC.search.folder.clearText(table);
                }
            },
            'keypress': function(textField, e){
            	// PTC.search.folder.displayClearTrigger(table);
                // this must be in the 'keypress' listener because hiding the event from the browser will only work here, not in 'specialkey'
                var keyValue = 0 + e.getKey(); // add to 0 is essential, else == tests fails inexplicably
            	if (keyValue == e.ENTER) {
                    // suppress other events that would happen when a user hits enter
                    e.preventDefault();
                    textField.onTrigger2Click();
                }
            },
            'beforeDestroy': function(){
            	this.table = undefined;
            	Ext.destroy(this.searchTrigger, this.clearTrigger);
            }
        },

        onTrigger1Click: function(){
        	this.clearTrigger.hide();
        	PTC.search.folder.clearText(table);
        },

        onTrigger2Click: function(event){
        	PTC.search.folder.fireSearch(table, event);
        }
    });

    var sifComponents = [sifTextField];

    var sifInstalled = false;
    if (table.actionsToolBar) {
        // Find the white space in the middle of the toolbar, then insert Search in Folder after that.
        var toolBarItemsLen = table.actionsToolBar.items.getCount();
        // Iterate through the toolbar items to find the filler component.
        for (var i = 0; i < toolBarItemsLen; i++) {
            if (table.actionsToolBar.getComponent(i).isFill) {
            	PTC.search.folder.insertIntoToolbar(table, sifComponents, i);
                sifInstalled = true;
                break;
            }
        }
    }

    if (!sifInstalled) {
        // Create a new toolbar sif couldn't be installed in the existing toolbar.
        table.searchInFolderToolBar = new Ext.Toolbar({
            id: table.getId() + '.searchInFolderToolBar',
            renderTo: table.tbar,
            cls: 'ecaToolbar',
            items: ['->'].concat(sifComponents) // Add the SIF components defined above, and right-align them.
        });
    }

    // Save some of the Search In Folder variables in the table to simplify accessing objects in callbacks.
    table.sifTextField = sifTextField;
    table.sifSearchStatus = sifSearchStatusText;
};

/**
 * @private
 * Clears the text in the Search in folder textbox and resets the text to the empty string.
 * The internal value of the textbox component is also reset.
 * @param {PTC.jca.TreeGrid} table
 */
PTC.search.folder.clearText = function(table) {
	table.sifTextField.reset();
	table.sifTextField.setValue("");
};

/**
 * @private
 * Displays the Clear button on the text box.
 * @param {PTC.jca.TreeGrid} table
 */
PTC.search.folder.displayClearTrigger = function(table) {
	var searchTerm = table.sifTextField.getValue();
	if(searchTerm === '') {
		table.sifTextField.clearTrigger.hide();
	} else {
		table.sifTextField.clearTrigger.show();
	}
};

/**
 * Returns a string with the parameters set according to the row selected in the table.
 * @param {PTC.jca.TreeGrid} table
 */
PTC.search.folder.SIF_containerContext = "";

PTC.search.folder.getSelected = function(table) {
    var returnString;
	var folderOid = table.store.highlightContext;;
	if(PTC.isDefined(folderOid)) {
		if (folderOid.indexOf("Cabinet") !== -1) {  //adding OR: to containerRef for SPR 2147148
			returnString = "&globalKey=context&containerRef=OR:"+PTC.search.folder.SIF_containerContext+"&contextKeyword=";
		} else {
			returnString = "&globalKey=folder&oid="+folderOid+"&folderKeyword=";
		}
	} else {
		returnString = "&globalKey=context&containerRef="+PTC.search.folder.SIF_containerContext+"&contextKeyword=";
	}
    return returnString;
};

/**
 * Check if search is valid or not, if not then show validation else render results
 * @param able.sifTextField.getValue();
 */

PTC.search.folder.checkValid = function(searchTerm)
{
  var checkValidInput = false;
  var ajaxOptions =
  {
       asynchronous: false,
       method: "POST",
       onSuccess: function(response )
       {

       var jsonData = Ext.util.JSON.decode(response.responseText.trim());
       var message = jsonData.message;
       var result1 = jsonData.result;

	   checkValidInput = result1;

	   if(!checkValidInput)
       {
            alert(message);
       }
       },
       parameters:{keyword: searchTerm}
    };

   requestHandler.doRequest('ptc1/foldersearch/validateKeyword',ajaxOptions);
   return checkValidInput;
}



/**
 * Fires search. Passes all the parameters to the Search.jsp page.
 * @param {PTC.jca.TreeGrid} table
 * @param event
 */
PTC.search.folder.fireSearch = function(table, event) {
	var searchTerm = table.sifTextField.getValue();
	var checkValid = PTC.search.folder.checkValid(searchTerm);

	if(checkValid){
		searchTerm = encodeURIComponent(searchTerm);
		var urlString = "wtcore/jsp/com/ptc/windchill/search/Search.jsp?folderSearchTextBox=true&fireSearch=true";
		var additionalSearchParam = PTC.search.folder.getSelected(table);
		var url = urlString + "&searchType=wt.fc.Persistable"+additionalSearchParam+searchTerm;
		loadAdvSearchPage(event,url);
	}
	else {
		return false;
	}

};

/**
 * Inserts all search in folder components into the table's actions toolbar after the specified index.
 * @param {Ext.grid.GridPanel} table
 * @param {Array} SIFComponents
 * @param {int} index
 */
PTC.search.folder.insertIntoToolbar = function(table, SIFComponents, index) {
    // Found the white space toolbar item. Iterate backwards through the search in folder components above,
    // inserting all of them into the toolbar after the filler.
    var SIFComponentLen = SIFComponents.length;
    for (var compIndex = SIFComponentLen - 1; compIndex > -1; compIndex--) {
        // i + 1 will do an 'insert-after'.
        table.actionsToolBar.insert(index + 1, SIFComponents[compIndex]);
    }
    table.actionsToolBar.doLayout(); // Lazy render, so do layout.
};

PTC.search.folder.enableSifComponent = false;

