var searchPageInfo = {};

searchPageInfo.contentPane = 'searchInfo_centerContentPane';

searchPageInfo.url = getBaseHref() + 'app/#netmarkets/jsp/search/searchInfoPage.jsp';
searchPageInfo.delayedShow = new Ext.util.DelayedTask();
searchPageInfo.delayedClose = new Ext.util.DelayedTask(function(){searchPageInfo.win.hide();});
searchPageInfo.defaultHideDelay = -1;


searchPageInfo.queueMiniInfo = function(oid, mouseEvent, delay) {

   

    // make default show flyout delay 1 second
    delay = 1000;


    searchPageInfo.cancelled = false;

    var targetObject = mouseEvent.target || mouseEvent.srcElement;

    searchPageInfo.delayedShow.delay(delay, searchPageInfo.show, null, [oid, targetObject, mouseEvent]);

};

searchPageInfo.cancelMiniInfo = function(hideDelay) {
    if(hideDelay === undefined) {
        searchPageInfo.defaultHideDelay = 500;
    }
    else if(hideDelay !== searchPageInfo.defaultHideDelay) {
        searchPageInfo.defaultHideDelay = hideDelay;
    }
    searchPageInfo.delayedShow.cancel();
    searchPageInfo.cancelled = true;
};

/*
 * Makes an Ajax request to populate the search info. Also sets an event to close the search info after a short bit
 * upon mousing off of the target DOM object. This delayed close is canceled when mousing into the search info.
 */
searchPageInfo.show = function(oid, targetObject, event) {

    if (PTC.getMainWindow() && PTC.getMainWindow().PTC && PTC.getMainWindow().PTC.performance) {
        PTC.getMainWindow().PTC.performance.startTimeGauge('SearchMiniInfoPage', 'Page Displayed');
    }
    
    if(!searchPageInfo.win){

        searchPageInfo.win = new Ext.Window({
            header      : false,
            id          : 'searchInfoWindow',
            cls         : 'searchInfoWindowStyle',
            width       : 400,
            autoHeight  : true,
            shadow      : true,
            shadowOffset: 6,
            plain       : true,
            draggable   : false,
            closable    : false,
            resizable   : false,
            items       : new Ext.Panel({
                id: 'searchInfo_centerContentPanel',
                html: '<div id="' + searchPageInfo.contentPane + '"></div>'
            })
        });
        searchPageInfo.win.on('resize', function() { searchPageInfo.win.syncShadow(); }, this, {delay : 2});
        searchPageInfo.win.on('move', function() { searchPageInfo.win.syncShadow(); }, this, {delay : 2});
        searchPageInfo.win.on('show', function() { searchPageInfo.win.syncShadow(); }, this, {delay : 2});
    }

    Ext.fly(targetObject).on('mouseout', function(){ searchPageInfo.delayedClose.delay(searchPageInfo.defaultHideDelay); }, this, {single: true});
    var params = "oid=" + encodeURIComponent(oid);
    PTC.navigation.addOpenRequest(getElementHtml(params, 'searchInfo_centerContentPane', true, searchPageInfo.url, false,
        function(response) {

            PTC.navigation.onSuccessRequest(response);
            searchPageInfo.delayedClose.cancel();  //Might still be a delayed job to close the previous one
            if(!searchPageInfo.cancelled) {


                // reposition window after totally rendered if necessary

                searchPageInfo.win.on('show', function() { 

                   var dx = Ext.EventObject.getPageX();

                   var dy = Ext.EventObject.getPageY();

                    var iwHeight = 0;
            		                   
                    if (window.innerHeight) {
                        iwHeight=window.innerHeight;
                    }
                   else if (document.documentElement && document.documentElement.clientHeight) {
                       iwHeight=document.documentElement.clientHeight;
                   }
                   else if (document.body) {
                        iwHeight=document.body.clientHeight;
                    }

                   var wy = window.screenY;

                   var foHeight = searchPageInfo.win.getHeight();

                   var shift = 0;

                   if (iwHeight < foHeight+dy) {

                      shift = (foHeight+dy)-iwHeight;

                   }

                   searchPageInfo.win.setPosition(dx+6, dy-shift); }, this, {delay : 100, single : true});
					
                searchPageInfo.win.show();
                // initial window positioning

                var x = Ext.EventObject.getPageX();

                var y = Ext.EventObject.getPageY();

                searchPageInfo.win.setPosition(x+6, y);

                var win = Ext.fly('searchInfoWindow');
                win.on('mouseenter', function() { searchPageInfo.delayedClose.cancel(); }, this, {single: true});
                win.on('mouseleave', function() { searchPageInfo.win.hide(); }, this, {single: true});

                
            }
    if (PTC.getMainWindow() && PTC.getMainWindow().PTC && PTC.getMainWindow().PTC.performance) {
        PTC.performance.stopTimeGauge('SearchMiniInfoPage', 'Page Displayed', true, 1);
    }



        },
        function(response) {
            jsca.error("Error with search info request for object", oid, response);
    }));
};




PTC.search.dataStore=null;
/*
 * Function to show All types checkbox and My Favourite types checkbox.
 */
function showAllTypesnMyFavCheckbox(allTypesLabel,myFavLabel,addTypeLabel){
    var checkAllTypes = false;
    var checkMyFavTypes = false;
    
    if (PTC.isDefined(Ext.getCmp('wt.fc.Persistable'))) {
        var oldItem = Ext.getCmp('wt.fc.Persistable');
        checkAllTypes = Ext.getCmp('wt.fc.Persistable').checked; //check if all types is already checked
        oldItem.destroy();
    }
    
    if (PTC.isDefined(Ext.getCmp('myFavTypes'))) {
        var oldItem = Ext.getCmp('myFavTypes');
        checkMyFavTypes = Ext.getCmp('myFavTypes').checked; //check if all types is already checked
        oldItem.destroy();
    }
    var chkItem = new Ext.form.Checkbox({
        name: 'wt.fc.Persistable',
        id: 'wt.fc.Persistable',
        checked: checkAllTypes,
        boxLabel: '<img src="netmarkets/jsp/search/small_blank_value.gif">'+allTypesLabel,
        renderTo: 'allTypesDiv',
        qtip: allTypesLabel,
        listeners: {
            check: checkListenerForAllTypes
        }
    });
    var chkItem1 = new Ext.form.Checkbox({
        name: 'myFavTypes',
        id: 'myFavTypes',
        checked: checkMyFavTypes,
        boxLabel: '<img src="netmarkets/jsp/search/small_blank_value.gif">'+myFavLabel+'&nbsp;&nbsp;&nbsp;&nbsp;<a href="javascript:launchTypePicker();">'+addTypeLabel+'</a>',
        renderTo: 'myFavTypesDiv',
        qtip: myFavLabel,
        listeners: {
            check: checkListenerForMyFavTypes
        }
    });
}


function selectCheckBoxes(response, options){
    var target = Ext.util.JSON.decode(response.responseText);
    var typeListStore = new Ext.data.JsonStore({
        // store configs
        autoDestroy: true,
        idProperty: 'internalValue',
        fields: ['internalValue', 'imagePath', 'displayValue', {
            name: 'checked',
            type: 'boolean'
        },
        'parentType', {
            name: 'allowMultiSelection',
            type: 'boolean'
        },
        {
            name: 'attributePanel',
            type: 'boolean'
        },
        'callback', {
            name: 'enabled',
            type: 'boolean'
        },
        'enableIcon', 'disableIcon', 'toolTip']
    });
    typeListStore.loadData(target);
    
    var allTypes = typeListStore.getById('wt.fc.Persistable');
    if(allTypes){
        typeListStore.remove(allTypes)
    }
    if(PTC.search.dataStore){
    	PTC.search.dataStore.add(typeListStore.getRange());
    }
    else{
    	PTC.search.dataStore = typeListStore;
    }
    PTC.search.dataStore.sort("displayValue", "ASC");
    
    PTC.search.dataStore.each(showCheckBox);
    
    if (allTypes && !allTypes.get('checked') && Ext.getCmp('wt.fc.Persistable').checked || !allTypes) {
        changeStateOfAllTypesCheckBox(false);
    }
    
 // If all the types are checked under my fav then check my fav checkbox as well. This would be necessary when the
    // page is reloaded.
    var checkMyFavTypes = true;
    if (PTC.search.dataStore.getCount() == 0) {
        checkMyFavTypes = false;
    } else {
        for ( var i = 0; i < PTC.search.dataStore.getCount(); i++) {
            var comboVarToSet = Ext.getCmp(PTC.search.dataStore.getAt(i).data.internalValue);
            if (PTC.search.dataStore.getById(PTC.search.dataStore.getAt(i).data.internalValue).get('checked') == false) {
                checkMyFavTypes = false;
                break;
            }
        }
    }
    Ext.getCmp('myFavTypes').suspendEvents();
    Ext.getCmp('myFavTypes').setValue(checkMyFavTypes);
    Ext.getCmp('myFavTypes').resumeEvents();
    
    if (allTypes && allTypes.get('checked') && !checkMyFavTypes) {
        changeStateOfAllTypesCheckBox(true);
    }
    
    if(busySign!=null){
        busySign.hide();
    }
    
}


function showCheckBox() {
    var icon;
	var label=this.data.displayValue;
    if (this.data.attributePanel == true && this.data.enabled == true && this.data.checked == true) {
        //we want to show enabled icon if the above cond is true
		icon = "<img  src=\"" + this.data.imagePath + "\" /> " + label + "<img onmouseover=\"timeLag=setInterval('"+ this.data.callback +";', 600);\" onmouseout=\"clearInterval(timeLag);\" src=\"" + this.data.enableIcon + "\"   /> "
        } else if ((this.data.attributePanel == true && this.data.enabled == false && this.data.checked == false) || (this.data.attributePanel == true && this.data.enabled == false && this.data.checked == true) || (this.data.attributePanel == true && this.data.enabled == true && this.data.checked == false)) {
        //we want to show disabled icon if the above cond is true
		icon = "<img  src=\"" + this.data.imagePath + "\" /> " + label + "<img src=\"" + this.data.disableIcon + "\"   /> "
    } else {
		icon = "<img  src=\"" + this.data.imagePath + "\" /> " + label;
    }
    icon = "<div class='removableCheckBoxLabel' >"+icon+"</div>";
    if (PTC.isDefined(Ext.getCmp(this.data.internalValue))) {
        var oldItem = Ext.getCmp(this.data.internalValue);
        oldItem.destroy();
    }

    var item = new PTC.search.RemovableCheckbox({
            name: this.data.internalValue,
            id: this.data.internalValue,
            boxLabel: icon,
            checked: this.data.checked,
            labelStyle: 'font-weight:bold;',
            renderTo: 'typePickerItems',
            qtip: label,
            listeners: {
                check: function(checkbox, checked) {
                   //delay this function call so that if this is being fired because the user clicked on the remove
                   //icon, the remove function has time to complete and this function will not be called due to
                   //the remove function destroying the component.  This is neccissary as this function will distrupt
                   //the remove functionality
                   checkListenerForNormalTypes.defer(100, this, [checkbox, checked]);
                }
            },
            onRemoveFunction: PTC.search.removeTypeCheckbox
        });
        item.wrap.addClass("chk-same-line");
        item.wrap.addClass("removableCheckBoxItem");
        if (item.checked) {
            if (document.getElementById('searchType').value == '') {
            	document.getElementById('searchType').value = "" + this.data.internalValue;
            } else {
            	document.getElementById('searchType').value = document.getElementById('searchType').value + "," + this.data.internalValue;
            }
        }
        if (document.getElementById('preSelectionItems').value == '') {
        	document.getElementById('preSelectionItems').value = "" + this.data.internalValue;
        } else {
        	document.getElementById('preSelectionItems').value = document.getElementById('preSelectionItems').value + "," + this.data.internalValue;
        }
}

function launchTypePicker() {
    $("typePickerLaunchAction").click();
}

/*
 * Function removes a type checkbox, sets the correct hidden form fields to remove the type from the preference list
 * server-side and calls the function to propogate these values to the server and refresh the search page accordingly
 */
PTC.search.removeTypeCheckbox = function() {
   this.inRemove = true;
   var firstItem = true;
   var firstPreselectItem = true;
   getMainForm().searchType.value = "";
   getMainForm().preSelectionItems.value = '';
   
   /*
    * If all the types are manually remove from the type picker, All types should get checked and my fav types should be unchecked
    */
   if(PTC.search.dataStore.getCount() == 1){
	   Ext.getCmp('wt.fc.Persistable').setValue(true);
	   /*changeStateOfAllTypesCheckBox(true);
	   Ext.getCmp('myFavTypes').suspendEvents();
	   Ext.getCmp('myFavTypes').setValue(true);
	   Ext.getCmp('myFavTypes').resumeEvents();*/
   }
   
   for (var i = 0; i < PTC.search.dataStore.getCount(); i++) {
      if (PTC.search.dataStore.getAt(i).data.internalValue !== this.getId()) {
         if (firstPreselectItem) {
            getMainForm().preSelectionItems.value = PTC.search.dataStore.getAt(i).data.internalValue;
            firstPreselectItem = false;
         } else {
            getMainForm().preSelectionItems.value += (',' + PTC.search.dataStore.getAt(i).data.internalValue);
         }
         if (PTC.search.dataStore.getAt(i).data.checked) {
            if (firstItem == true) {
            	getMainForm().searchType.value = "" + PTC.search.dataStore.getAt(i).data.internalValue;
               firstItem = false;
            } else {
            	getMainForm().searchType.value = getMainForm().searchType.value + "," + PTC.search.dataStore.getAt(i).data.internalValue;
            }
         }
      }
   }
   //destory the component so that the check listener doesn't fire
   PTC.search.dataStore.remove(PTC.search.dataStore.getById(this.id));
   this.destroy();
   selectMyFavTypes();
   PTC.search.checkAllTypesChecked();
   PTC.search.refreshPageOnTypeChange();
}



/*
 * Listener for my favourite types. The checkbox will behave as Select All/Select None. 
 * On checking "My favourite Types", all ctypes will be checked. On unchecking, all types will be unchecked. 
 * Even if one type in unchecked, "my favourite Types" should be unchecked. 
 * If all Types are unchecked and one Type is checked, "My favourite Types" remains unchecked.
 */
function checkListenerForMyFavTypes(){
	//IF All types is already chcked and then my fav types is checked, we need to deselect all types.
	if (PTC.isDefined(Ext.getCmp('wt.fc.Persistable')) && Ext.getCmp('wt.fc.Persistable').checked) {
		var oldItem = Ext.getCmp('wt.fc.Persistable');
		oldItem.setValue('false');
	}

	var value="";
	getMainForm().searchType.value = "";
	
	if (Ext.getCmp('myFavTypes').checked) {
		getMainForm().searchType.value =changeStateOfCheckbox(true);
	}else {
		changeStateOfCheckbox(false); //When my fav type is uncheked all the types in the list are unchecked hence we need to set 'All types' by default in the hidden field
		changeStateOfAllTypesCheckBox(true);
	}
	PTC.search.refreshPageOnTypeChange();
}

function changeStateOfAllTypesCheckBox(state){
	var allTypesCheckBox = Ext.getCmp('wt.fc.Persistable');
	// We need to suspend the events here as the value is changed programitically. 
	allTypesCheckBox.suspendEvents();
	allTypesCheckBox.setValue(state);
	allTypesCheckBox.resumeEvents();
	if(state == true){
		getMainForm().searchType.value = "wt.fc.Persistable";
		  for ( var i = 0; i < PTC.search.dataStore.getCount(); i++) {
		        var comboVarToSet = Ext.getCmp(PTC.search.dataStore.getAt(i).data.internalValue);
		        comboVarToSet.suspendEvents();
		        PTC.search.dataStore.getAt(i).data.checked = false;
		        comboVarToSet.setValue(false);
		        comboVarToSet.resumeEvents();
		    }
	}
}

/*
 * Utility function to change the state of the checkbox
 */

function changeStateOfCheckbox(state){
	var value="";
	for (var i = 0; i < PTC.search.dataStore.getCount(); i++) {
		var comboVarToSet = Ext.getCmp(PTC.search.dataStore.getAt(i).data.internalValue);
		// We need to suspend the events here as the value is changed programitically. 
		comboVarToSet.suspendEvents();
		PTC.search.dataStore.getAt(i).data.checked=state;
		comboVarToSet.setValue(''+state);
		comboVarToSet.resumeEvents();
		value = value + "," + PTC.search.dataStore.getAt(i).data.internalValue;
	}
	return value.substring(1);

}



function checkListenerForAllTypes() {
    //when all types is selected we need to disable the remaining types.
    if (Ext.getCmp('wt.fc.Persistable').checked) {
		//When All types is checked, we want to deselect My Favourite types checkbox as well.
		if (PTC.isDefined(Ext.getCmp('myFavTypes')) && Ext.getCmp('myFavTypes').checked) {
			var myFavTypes = Ext.getCmp('myFavTypes');
			myFavTypes.suspendEvents();
			myFavTypes.setValue('false');
			myFavTypes.resumeEvents();
		}
        for (var i = 0; i < PTC.search.dataStore.getCount(); i++) {
            var comboVarToSet = Ext.getCmp(PTC.search.dataStore.getAt(i).data.internalValue);
            // We need to suspend the events here as the value is changed programitically. 
            comboVarToSet.suspendEvents();
            PTC.search.dataStore.getAt(i).data.checked=false;
            comboVarToSet.setValue(false);
            comboVarToSet.resumeEvents();
        }
        getMainForm().searchType.value = "wt.fc.Persistable";
    } 
    PTC.search.refreshPageOnTypeChange();
}

function checkListenerForNormalTypes(checkbox, checked) {
    //when normal types is selected we need to update the 'searchType' list for the purpose of searching.
    if (checkbox.inRemove) {
       return;
    }
    
  //When a normal type is unchecked from the list, we want to uncheck  'My Favourite Types' if not already unchecked.
	if(!checked){
		if (PTC.isDefined(Ext.getCmp('myFavTypes')) && Ext.getCmp('myFavTypes').checked) {
			var oldItem = Ext.getCmp('myFavTypes');
			oldItem.suspendEvents();
			oldItem.setValue('false');
			oldItem.resumeEvents();
		}
	}
    
    var firstItem = true;
    var enableAllTypes = false;
    var ind = PTC.search.dataStore.indexOfId(this.initialConfig.name)
    PTC.search.dataStore.getAt(ind).data.checked = !(PTC.search.dataStore.getAt(ind).data.checked);
    getMainForm().searchType.value = "";
	var allObjecTypesAreChecked = true;
    
    for (var i = 0; i < PTC.search.dataStore.getCount(); i++) {
        try {
            var chkBox = Ext.getCmp(PTC.search.dataStore.getAt(i).data.internalValue);
            if (chkBox.getValue()) {
                enableAllTypes = true;
                if (firstItem == true) {
                	getMainForm().searchType.value = "" + PTC.search.dataStore.getAt(i).data.internalValue;
                    firstItem = false;
                } else {
                	getMainForm().searchType.value = getMainForm().searchType.value + "," + PTC.search.dataStore.getAt(i).data.internalValue;
                }
            }
        } catch(ex) {
            alert(ex);
        }
	}

    selectMyFavTypes();
    PTC.search.checkAllTypesChecked();
    if (enableAllTypes) {
        Ext.getCmp('wt.fc.Persistable').suspendEvents();
        Ext.getCmp('wt.fc.Persistable').setValue(false);
        Ext.getCmp('wt.fc.Persistable').resumeEvents();;
    }
    PTC.search.refreshPageOnTypeChange();
}
/*
 * If all the object types are checked one by one, we want the my favourite types checke box to be checked too.
 * The following function takes care of the same.
 */
function selectMyFavTypes(){
	var allObjecTypesAreChecked=true;
	for (var i = 0; i < PTC.search.dataStore.getCount(); i++) {
		var chkBox = Ext.getCmp(PTC.search.dataStore.getAt(i).data.internalValue);
		if (!chkBox.checked) {
			allObjecTypesAreChecked = false;
			break;
		}
	}
	if(allObjecTypesAreChecked && PTC.search.dataStore.getCount()){
		Ext.getCmp('myFavTypes').suspendEvents();
		Ext.getCmp('myFavTypes').setValue(true);
		Ext.getCmp('myFavTypes').resumeEvents();

	}
}

PTC.search.checkAllTypesChecked = function (){
	var allObjectTypesAreChecked=true;
	for (var i = 0; i < PTC.search.dataStore.getCount(); i++) {
		var chkBox = Ext.getCmp(PTC.search.dataStore.getAt(i).data.internalValue);
		if (chkBox.checked) {
			allObjectTypesAreChecked = false;
			break;
		}
	}
	if(allObjectTypesAreChecked){
		var cb =Ext.getCmp('wt.fc.Persistable');
		cb.suspendEvents();
		cb.setValue(true);
		getMainForm().searchType.value = 'wt.fc.Persistable';
		cb.resumeEvents();
	}
}

function setSearchTypeOnSearchPage(Objects, pickerID, targetId) {

	var searchType = getMainForm().searchType.value;
	if (searchType.search(/wt.fc.Persistable/) > -1) {
	   searchType = searchType.replace('wt.fc.Persistable', '');
	}
	getMainForm().searchType.value = searchType;
	
	var elements = Objects.pickedObjects;
	var pickedSelection = elements.length;
	var theTypeNew='';
	    
	for (i = 0; i < elements.length; i++) {
		var theType = elements[i].theType;
		if (theType == "wt.fc.Persistable") {
			getMainForm().searchType.value = "wt.fc.Persistable";
			break;
		} else {
				
			theTypeNew+=theType+",";
			
		
			if ((theType.indexOf("|") > 0) && (theType.indexOf("WCTYPE") == -1)) {
				theType = "WCTYPE|" + theType;
			}

			if (getMainForm().searchType.value === '') {
				getMainForm().searchType.value = theType;
			} else {
				getMainForm().searchType.value = getMainForm().searchType.value + "," + theType;
			}

	        if (getMainForm().preSelectionItems.value === '') {
	            getMainForm().preSelectionItems.value=theType;
	        } else {
	            getMainForm().preSelectionItems.value=getMainForm().preSelectionItems.value  + "," + theType;
	        }
		}
	}
	
	var form = getMainForm();
    var CSRF_NONCE = (form.CSRF_NONCE) ? form.CSRF_NONCE.value : "";
    Ext.Ajax.request({
        url: getBaseHref() + 'app/advancedSearch/typePicker/getSelectedTypeList',
        success: selectCheckBoxes,
        params: {
                typePickerItems: theTypeNew,
                searchType: theTypeNew,
                mergeTypes: false,
                CSRF_NONCE : CSRF_NONCE
        }

    });

    PTC.search.refreshPageOnTypeChange();	
}



