// Define Search Results object
function SearchResultsJSParams(){
   this.searchResultsViewId = '';
   this.isSortAction = false;
   this.webappName = '';
   this.quickSearch = false;
   this.isPagingExists = false;  // paging exists on page
   this.pagedListAction = false; // Paged List (used for toggle "Full List" to "Paged List")
   this.initDone = false;

   this.pagingAction = false;    // paging action done
   this.fullListAction = false;  // full list action done
	this.currentTime = new Date().getTime();

   this.detectPaging = function() {
      if($('table__'+this.searchResultsViewId+'_TABLE_nextButton')){
         this.isPagingExists = true;
      }
   }

   this.isTwoPassAction = function(){
      // if paging action or full list action then it's single pass
      if(this.pagingAction || this.fullListAction) return false;

      // if no paging on page then also single pass
      if(!this.isPagingExists) return false;

      // default to two pass
      return true;

   }

   this.reset = function(){
      this.isSortAction = false;
      this.pagedListAction = false;

      this.pagingAction = false;
      this.fullListAction = false;
   }

   this.preSubmitIt = function(){
      this.reset();
      var actionName = arguments[0];
      // detect "Paged List" action
      if('seeAll'==actionName) {
         var i=0;
         var doPaging = false;
         while(i<arguments.length){
            if(arguments[i++]=='doPaging' && arguments[i]=='true') {
               doPaging = true;
               break;
            }
         }
         this.isPagingExists = doPaging;
         this.pagedListAction = doPaging;
      }
      else {
         // detect any of the paging actions
         var i=0;
         var pagingOffsetParam = this.searchResultsViewId + 'fi';
         var pagingCountParam = this.searchResultsViewId + 'lmt';
         var pageOffset = 0;
         var pageCount = 0;
         var pagingAction = false;
         while(i<arguments.length){
            if(arguments[i]==pagingOffsetParam) {
               pageOffset = arguments[i+1];
               pagingAction = true;
            }
            else if (arguments[i]==pagingCountParam) {
               pageCount = arguments[i+1];
            }
            i++;
         }
         if(pagingAction){
            if(pageCount > 0) { this.pagingAction = true; }
            else if(pageCount == '-1') { this.fullListAction = true;}
         }
      }
   }


   this.init = function(){
      if(!this.quickSearch || this.initDone) return;
      this.detectPaging();

      //Override framework functions to provide some extra handling

      oldSortTable = sortTable;
      sortTable = searchSortTable;

      oldSubmitIt = submitIt;
      submitIt=searchSubmitIt;

      this.initDone = true;
   }

   this.postTableRefreshHandler = function(tableId){
		var newTime = new Date().getTime();
		if(tableId == this.searchResultsViewId && $(this.searchResultsViewId+'_table_empty').visible()){
			if(getMainForm().clear1.value=="false" && getMainForm().actionMethod.value!='typeChange'){
				//Here we check whether the table action was carried out after 20 minutes. If so, then the session expiry message is alerted
				if((newTime - this.currentTime)/60000 >20)
					JCAAlert("com.ptc.windchill.enterprise.search.client.searchClientResource.SESSION_EXPIRED_MSG");
			}
		}
		this.currentTime = newTime;

      if(!this.quickSearch) return;
      if(tableId==this.searchResultsViewId) {
         //if sort action then refresh result table to get all pages
         this.detectPaging();
         if(this.isTwoPassAction()) {
            getAllPages();
         }
      }
      this.reset();
   }

   this.preSortTable = function(){
      this.reset();
      resultParams.isSortAction = true;
   }
}

