/**
 * This method ensures that the Configurable Link table actions use the correct configurableLinkType.
 */
function setConfigurableLinkType(type, actionName, event) {
	var linkType = document.getElementById("configurableLinkType");
	if(linkType == null) {
		var newLinkType = document.createElement("input");
		newLinkType.setAttribute("type", "hidden");
		newLinkType.setAttribute("name", "configurableLinkType");
		newLinkType.setAttribute("id", "configurableLinkType");
		newLinkType.setValue(type);
		document.getElementById("mainform").appendChild(newLinkType);
	} else {
		linkType.setValue(type);
	}
	return onClickValidation(event, actionName);
}


