/**
 * 
 * @param {Ext.grid.GridPanel} table 
 * @param {Object} column - and object with some column properties such as column id and width
 * @param {Ext.data.Record} row 
 * @param {Function} rendererFunc - the rendering function to use. There are different renderering functions for display, export, search, dom dump.
 */
jsca.columns.simpleRenderer_internal = function(table, column, row, rendererFunc, getRowFunc, getCellFunc) {
    var result = '';
    var data = row.get(column.id);

    // If the data is null, just return the default empty string
    if (!data && typeof data !== 'boolean' && typeof data !== 'number') {
        return result;
    }

    // if data is a string just return it
    if (typeof data === 'string') {
        return data;
    }
    else if (typeof data === 'number' || typeof data === 'boolean') {
        return '' + data;
    }

    result = rendererFunc(data, table, column, row, getRowFunc, getCellFunc);

    return result;
};

jsca.columns.simpleRenderer = function(table, column, row) {
   return jsca.columns.simpleRenderer_internal(table, column, row, multiRendererJSCA);
};

jsca.columns.simpleRenderer.searchFunc = function(table, column, row) {
    var result = jsca.columns.simpleRenderer_internal(table, column, row, multiRendererJSCA.searchFunc);
    if(Ext.isString(result)) {
        result =  getUnescapedText(result);
    }
    return result;
};

jsca.columns.simpleRenderer.groupFunc = function(table, column, row) {
    return jsca.columns.simpleRenderer_internal(table, column, row, multiRendererJSCA.groupFunc);
};

jsca.columns.simpleExportRenderer = function(table, column, row, getRowFunc, getCellFunc) {
   return jsca.columns.simpleRenderer_internal(table, column, row, multiExportRendererJSCA, getRowFunc, getCellFunc);
};


 function saveRecentlyUsedContexts(objects) {
       var oid;
       if(objects) {

       var picked = objects.pickedObject;
       var name = picked[0].name;
       oid = picked[0].oid;
       var containerName = picked[0].containerName;

       var axlContextList = document.getElementById("axlSourcingContext$label$");
       var y = document.createElement('option');
       y.text= name + " ("+containerName+")";
       var found = false ;
       for(i = 0 ; i < axlContextList.length ; i++){
         if(axlContextList.options[i].text == y.text){
           axlContextList.selectedIndex=i;
           found = true ;
           break ;
         }
       }
        if(!found){
         y.value = oid;
         axlContextList.options.add(y,0) ;
         axlContextList.selectedIndex=0;
         }
       }
       else {

       	var axlContextList = document.getElementById("axlSourcingContext$label$");
       	var i = axlContextList.selectedIndex;
       	oid = axlContextList.options[i].value;
       	}

       var url = getBaseHref() +'app/sourcingcontext/recentlyused';
       var loader = new ajax.ContentLoader(url, false, null, 'POST', "selectedOid="+oid);
   }


/**
 * Renders a spinner field in the given table, column and row.
 *
 * @param {Ext.grid.GridPanel} table
 * @param {Object} column - and object with some column properties such as column id and width
 * @param {Ext.data.Record} row
 *
 * @see Ext.ux.form.SpinnerField
 */
jsca.columns.spinnerFieldRenderer = function(table, column, row){
    var result = "";
    var data = jsca.columns.getCellValue(column, row);
    if (data.enabled) {
        if (typeof row.get === 'function' && row.get(column.id)) {
           // setting the updateCellValue function to track the DOM changes
           row.get(column.id).updateCellValue = jsca.columns.textBoxRenderer.updateCellValue;
        }

        var id = (data.id) ? data.id : row.get('oid') + "_spinnerField";
        var name = (data.name) ? data.name : id;
        var width = (data.width && data.width !== "auto") ? data.width : 10;
        if (data.incrementValue) {
            data.incrementValue = parseFloat(data.incrementValue);
        }
        if (data.alternateIncrementValue) {
            data.alternateIncrementValue = parseFloat(data.alternateIncrementValue);
        }
        if (data.maxValue) {
            data.maxValue = parseFloat(data.maxValue);
        }
        if (data.minValue) {
            data.minValue = parseFloat(data.minValue);
        }

        result = "<input id='" + id + "' name='" + name + "' size=" + width + "></input>";
        var extFieldStr = Ext.util.JSON.encode(data);
        var script = "<script>jsca.columns.renderSpinnerField('" + id + "', " + extFieldStr + ");</script>";
        var oldSpinnerComp = Ext.getCmp(data.id);
        if (oldSpinnerComp) {
           oldSpinnerComp.destroy();
        }
        PTC.jca.table.Utils.evalCellContent(table, script);
    }
    return result;
};

/**
 * Given the id of the initially rendered input field for the spinner field and
 * the extField that represents a spinner field sets the input field to the
 * spinner field.
 *
 * @param id The id of the rendered
 * @param extField An object that represents the spinner field. The "xtype" attribute
 *                 should be set to "ptcspinnerfield".
 *
 * @see jsca.columns.spinnerFieldRenderer
 * @see Ext.ux.form.SpinnerField
 */
jsca.columns.renderSpinnerField = function(id, extField){
    if ($(id) && extField) {
        extField.applyTo = id;
        extField.validator = jsca.columns.spinnerFieldValidator;
        extField.validationDelay = 750; // increased delay to allow user to type in a value the default is 250
        var oldSpinnerComp = Ext.getCmp(extField.id);
        if (!oldSpinnerComp) {
            Ext.ComponentMgr.create(extField);
        }
    }
};

/**
 * Validates the value prior to calling the spinner field validation.
 * This is done so that the form can not be submitted with bad values
 * when the minimum is equal to or greater than zero. When the values
 * entered are out of bounds the value is either set to the minimum
 * value or maximum value which ever is closest. When negative numbers
 * are not valid the "-" is automatically set to "".
 *
 * @param value The value of the spinner field.
 */
jsca.columns.spinnerFieldValidator = function(value){
    if (value !== "") {
        value = parseFloat(value);
        if (isNaN(value) && this.minValue >= 0) {
	    this.setValue("");
        } else if (value > this.maxValue) {
            this.setValue(this.maxValue);
        } else if (value < this.minValue) {
            this.setValue(this.minValue);
        }
    }
    return true;
};


