PTC.folderBrowser.setPostCancelHandlerInfo = function (store)
{
    if (PTC.folderBrowser.tree && PTC.folderBrowser.tree.id === store.jscaTableID)
    {
        var oidToExpand = {};
        var fb = PTC.folderBrowser;
        if (! store.postCancelHandlerInfo)
        {
            store.postCancelHandlerInfo = {};
        }
        if (fb.table)
        {
            store.postCancelHandlerInfo.oid = fb.table.getStore ().baseParams.oid[0];
        }
    }
};

PTC.folderBrowser.callbacks.beforeRenderTable = function (table)
{
    var fb = PTC.folderBrowser;

    // Set the currently loaded table
    fb.table = table;

    // Wrap the updateData function to allow filtering out rows that should not be displayed in the current folder
    var wTableId = PTC.jca.table.getWTablePanelID (table.id);
    var wTable = Ext.getCmp (wTableId);

    if (wTable)
    {
        wTable.updateData = wTable.updateData.wrap (function (proceed, data)
        {
            if (Ext.isArray (this.gridPanel.filteredRows))
            {
                var validRows = [];
                for (var ir = 0; ir < data.rows.length; ir++)
                {
                    if (this.gridPanel.filteredRows.indexOf (data.rows[ir].oid) === -1)
                    {
                        validRows.push (data.rows[ir]);
                    }
                }
                data.rows = validRows;
            }

            if (data.rows.length > 0)
            {
                return proceed.call (this, data);
            }
            return;
        });
    }

    // Set functions on the table
    var afterDestroy = function ()
    {
        fb.table = null;
    };

    fb.table.on ('destroy', afterDestroy);

    // The tree is already rendered.  Run the onRenderTree again to set needed values and functions
    if (fb._isTreeRendered === true)
    {
        fb.callbacks.onRenderTree ();
    }
};

PTC.folderBrowser.callbacks.onRenderTree = function ()
{
    var fb = PTC.folderBrowser;

    // Set the tree as loaded AFTER the table is rendered
    // If this is not done getView() on the tree will blow in Ext framework
    fb._isTreeRendered = true;

    // Make sure the table is available before setting values
    if (fb.table !== null)
    {
        // Table functions that should only be applied to the table when the folder browser tree is also present.
        var contextOid = fb.table.getStore ().baseParams.oid[0];
        var separator = contextOid.indexOf ("~");
        if (separator > 0)
        {
            contextOid = contextOid.substring (0, separator);
        }

        // The view may not be rendered yet.  Could convert to use event "viewready" after upgrade to EXT 3.2
        // onAvailable is when the component is created, so may not be rendered yet
        fb.contextFocusNode (fb.tree, contextOid, PTC.folderBrowser._highlightStyle);

        // Ensure that after sorting, the focus is maintained on the correct element.
        fb.tree.on ('sortchange', PTC.folderBrowser.setTreeFocusAfterSort);
    }
};

/**
 * Highlight method (for tree)
 *
 */
PTC.folderBrowser.contextFocusNode = function (tree, param, highlightStyle)
{
    var store = tree.getStore ();
    var view = tree.getView ();

    view.getRowClass = function (record, index, rowParams, store)
    {
        // If store is not set, this is a dummy record.
        if (! (store === undefined || store === null))
        {
            var oid = record.get ('oid');
            if (! (oid === undefined || oid === null) && store.highlightContext === oid)
            {
                return highlightStyle;
            }
        }
    };

    var oid;
    if (! Ext.isString (param))
    {
        return; // Invalid param, abort processing
    }
    else
    {
        // 'param' is a String; set param to the oid to highlight

        oid = param;

    }

    var index = store.findExact ('oid', oid);

    //////////////////
    // Begin Kludge //
    //////////////////

    var kludgeResult = PTC.folderBrowser._kludge (index, oid);
    index = kludgeResult.index;
    oid = kludgeResult.oid;


    ////////////////
    // End Kludge //
    ////////////////

    var isRenderedRow = false;
    if (index > -1)
    {
        // Check if the record is loaded in the store and has a rendered row.
        var row = view.getRow (index);
        isRenderedRow = ! (row === undefined || row === null);

        // Store old highlighted context so it can be unhighlighted later
        if (store.highlightContext !== undefined && store.highlightContext !== null)
        {
            var oldIndex = store.findExact ('oid', store.highlightContext);
        }

        // Set the new highlight context
        store.highlightContext = oid;
    }

    if (isRenderedRow)
    {
        var record = store.getAt (index);
        store.expandToNode (record);
        // Focus on context node
        view.focusRowCenter (record);
        PTC.folderBrowser._folderCache.addToCache (oid, store.getNodeAncestors (record));
        if (! store.isExpandedNode (record))
        {
            PTC.folderBrowser._folderCache.appendCache (oid, PTC.folderBrowser.table.getStore ().data.items);
        }

        // Unhighlight previous context
        if (! (oldIndex === null || oldIndex === undefined))
        {
            view.refreshRow (oldIndex);
        }
        view.refreshRow (index);

    }
    else if ((store.isLoading === undefined) || (Ext.isFunction (store.isLoading) && store.isLoading ()) || (index > -1 && !isRenderedRow) || (index === -1))
    {
        // All data has not yet been returned from the server.
        // Append another single call function to process this data.

        var contextFocusNodeDelegate = PTC.folderBrowser.contextFocusNode.createDelegate (this, [tree, param, highlightStyle], 0);
        view.on ('refresh', contextFocusNodeDelegate, this,
            {
                buffer: PTC.folderBrowser._processDelay,
                single: true
            });
    }
    else
    {
        // This object could not be found after all data was loaded
        //FIXME: Probably should log an error ...
    }
};

/**
 * When the page is loaded from the context of a Cabinet, the oid set in
 * the baseParams is not the oid of a SubFolder or Cabinet but instead
 * that of the containing Project2, PDMLinkProduct, etc.  By comparing
 * the baseParam oids of both the table and tree and checking whether
 * 'ContainerOid' is undefined, we can be reasonably assured that the
 * page was loaded at the Cabinet level.
 *
 */
PTC.folderBrowser._kludge = function (index, oid)
{
    if (PTC.folderBrowser.table && PTC.folderBrowser.tree)
    {
        var tableStore = PTC.folderBrowser.table.getStore();
        var treeStore = PTC.folderBrowser.tree.getStore();

        if ((index === -1) &&
            (tableStore.baseParams.ContainerOid === undefined) &&
            (treeStore.baseParams.ContainerOid === undefined) &&
            (treeStore && treeStore.isLoading !== undefined) &&
            (treeStore && Ext.isFunction(treeStore.isLoading) && ! treeStore.isLoading ()))
        {
            var contextOid = treeStore.baseParams.oid[0];
            if (oid === contextOid)
            {
                index = 0;
                if (treeStore.getAt (0) === undefined)
                {
                    index = -1;  // The first row has not been rendered yet
                }
                else
                {
                    oid = treeStore.getAt (0).get ('oid');
                }
            }
        }
    }

    return {
        oid: oid,
        index: index
    };
};

/**
 * This method ensures that after sorting the tree, the focus is maintained on the correct folder.
 *
 */
PTC.folderBrowser.setTreeFocusAfterSort = function ()
{
    var fb = PTC.folderBrowser;
    var view = fb.tree.getView ();
    var store = fb.tree.getStore ();

    if (! PTC.isDefined (store.highlightContext))
    {
        return;
    }

    var oldIndex = Ext.select ("." + PTC.folderBrowser._highlightStyle, true, fb.tree.getEl ().dom).elements[0].dom.rowIndex;

    if (oldIndex > -1)
    {
        Ext.fly (view.getRow (oldIndex)).removeClass (PTC.folderBrowser._highlightStyle);
    }

    var newIndex = store.findExact ('oid', store.highlightContext);
    if (newIndex > -1)
    {
        Ext.fly (view.getRow (newIndex)).addClass (PTC.folderBrowser._highlightStyle);
    }
};

PTC.folderBrowser.callbacks.beforeRenderTree = function (tree)
{
    var fb = PTC.folderBrowser;

    // Set the currently loaded tree
    fb.tree = tree;
    var afterDestroy = function ()
    {
        fb._isTreeRendered = false;
        fb.tree = null;
    };

    // Reset all queues and context oid from old tree
    fb.tree.on ('render', fb.callbacks.onRenderTree);
    fb.tree.on ('destroy', afterDestroy);

    // Set the currently loaded table.  This is needed if these components
    // are refreshed before navigation happens on the folder browser.
    PTC.folderBrowser.loadNewFolder (window.location.href);
    var treeStore = fb.tree.getStore ();
    treeStore.on ('handlecanceltreeds', PTC.folderBrowser.setPostCancelHandlerInfo);

    treeStore.getNotRemovedIDs = function (store)
    {
        var index = Ext.select ("." + PTC.folderBrowser._highlightStyle, true, fb.tree.getEl ().dom).elements[0].dom.rowIndex;
        var retainElements = [];
        retainElements.push (store.getAt (index));
        return retainElements;
    };
};

