/**
 * Augment the form result with an additional method needed by the folder browser.
 * Returns the number of cabinets that have objects added to them, in the folder browser we need to know if the objects are
 * added to more than one cabinet to avoid showing in the wrong one. See onAvailabe method below for use.
 */
PTC.action.FormResult.prototype.getAddedCabinetCount = function() {
	var locations = this.getAddedLocations();
	var count = 0;
	for (var i = 0; i < locations.size(); i++) {
		if (locations[i].indexOf("Cabinet") >= 0 ) {
			count++;
		}
	}
	return count;
};

/** Added function to check if the url contains cabinet if it does it will return true using which the oid will be set to containerOid for folder cache mechanism works correctly.
 * The url change was made to handle SPR 2185808
 * @param url of the page
 * @returns oid
 * */
PTC.folderBrowser.getCorrectOid = function (url){
    var oid = getOidFromURL (url);
    var oidCabinet = jsca.isCabinetOid(oid);
    if(oidCabinet === true && (url.indexOf("folderNavigatorParameter")!== -1)){
        oid =  PTC.folderBrowser.getContainerOid (url);
    }
    return oid;
};

if (!PTC.cat) {
  PTC.cat = {};
}

PTC.cat.StructureComponentLauncher = {

  appNames: {},
  appNameByIdOfDivToMatch: {},
  
  getGWTTab : function(tabPanel) {
    if (!tabPanel || !tabPanel.items) {
      return undefined; // testing
    } 
    var i = tabPanel.items.items.length;
    while (i--) {
      var tab = tabPanel.items.items[i];
      if (tab.id && tab.id.endsWith('StructureGWT')) {
        //can use tab.hasLayout===true to know if its been loaded
        return tab;
      }
    }
    return undefined;
  },


  launch: function(appName, iframeId, iframeJSPRelativeURL, idOfDivToMatch, containerOid, organizationOid) { 

    PTC.cat.StructureComponentLauncher.appNames[appName] = iframeId;
    PTC.cat.StructureComponentLauncher.appNameByIdOfDivToMatch[idOfDivToMatch] = appName;
    
    if (!PTC.cat.StructureComponentLauncher[appName] || PTC.cat.StructureComponentLauncher[appName + "LastLoadedOrg"] != organizationOid) {
      // SPR 2200656: When the organization id changes for the same application, 
      // remove the existing iframe and then load a new one
      if(PTC.cat.StructureComponentLauncher[appName]) {
        PTC.cat.StructureComponentLauncher.removeIframe(appName, iframeId);
      }
      

      PTC.cat.StructureComponentLauncher[appName + "LastLoadedOrg"] = organizationOid;
      
      
      PTC.cat.StructureComponentLauncher.loadSC(appName, iframeId, iframeJSPRelativeURL, idOfDivToMatch);
    }
    else {
        if(!PTC || !PTC.infoPage || !PTC.infoPage['scConfigLoadComplete' + appName]) {
        
          PTC.cat.StructureComponentLauncher.refreshPage(idOfDivToMatch, iframeId);
        return;
      }
    
      try {
      checkAndLoadSC(appName, containerOid);
    }
      catch(err) {
        PTC.cat.StructureComponentLauncher.refreshPage(idOfDivToMatch, iframeId);
        return;
      }
    }

    PTC.cat.StructureComponentLauncher.bringToFront(appName, iframeId, iframeJSPRelativeURL, idOfDivToMatch);
    },
    
    refreshPage: function(idOfDivToMatch, iframeId) {
    
      var ifrm = document.getElementById(iframeId);
      
      if (!ifrm) {
        return;
      }
      
      var message = 'Last structure was not completely loaded, the page will be refreshed momentarily.';
      try {
        message = ifrm.contentWindow['PTC_GWTBUNDLE_com_ptc_cat_gxt_client_GXTMessages']['KSTRUCTURE_PAGE_REFRESHING'];
      } catch (err) { }
      
      var elementOfDivToMatch = document.getElementById(idOfDivToMatch);
              
        if (elementOfDivToMatch && elementOfDivToMatch.firstChild) {
          while ( elementOfDivToMatch.firstChild ) {
            elementOfDivToMatch.removeChild( elementOfDivToMatch.firstChild );
          }
              
        var blockingDiv = document.createElement('div');
        blockingDiv.style.width = '100%';
        blockingDiv.style.height = '100%';
        blockingDiv.style.textAlign = 'center';
        blockingDiv.innerHTML = '<BR><BR><BR><BR><BR><BR><BR><BR>' + message;
        elementOfDivToMatch.appendChild(blockingDiv);
        
        setInterval(function()  {location.reload()},3000);
        
        return;
      }
    },
    
    bringToFront: function(appName, iframeId, iframeJSPRelativeURL, idOfDivToMatch) {
    
      if (PTC.cat.StructureComponentLauncher[appName]) {
      
        var scIFrame = document.getElementById(iframeId);
        if (scIFrame) {
          scIFrame.style.display="block";
          scIFrame.style.visibility="visible";
        }
        
        var element_of_content_div = Ext.getCmp(idOfDivToMatch);
        
        if (!PTC.cat.StructureComponentLauncher[idOfDivToMatch] ||
                PTC.cat.StructureComponentLauncher[idOfDivToMatch].iframeId != iframeId) {
        
          PTC.cat.StructureComponentLauncher[idOfDivToMatch] = 
            function(component, adjWidth, adjHeight, rawWidth, rawHeight) {
            
            scIFrame.setAttribute("width", adjWidth + "px");
          scIFrame.setAttribute("height", adjHeight + "px");
          
          var position = component.getPosition();
          scIFrame.style.left = position[0] + "px";
          scIFrame.style.top = position[1] + "px";
          };
          PTC.cat.StructureComponentLauncher[idOfDivToMatch].iframeId=iframeId;
        }
        else {
          
          element_of_content_div.un('resize', PTC.cat.StructureComponentLauncher[idOfDivToMatch]);
        }

      element_of_content_div.on('resize', PTC.cat.StructureComponentLauncher[idOfDivToMatch]);
      
      if (element_of_content_div.isVisible() && element_of_content_div.getWidth() > 0) {
        scIFrame.setAttribute("width", element_of_content_div.getWidth() + "px");
        scIFrame.setAttribute("height", element_of_content_div.getHeight() + "px");
        var position = element_of_content_div.getPosition();
        scIFrame.style.left = position[0] + "px";
        scIFrame.style.top = position[1] + "px";
      }
      
      if (PTC.cat.StructureComponentLauncher["restart" + appName]) {
      PTC.cat.StructureComponentLauncher["restart" + appName]();
      }
      }
    },
    
    sendToBack: function(clear) {
    
      for (appName in PTC.cat.StructureComponentLauncher.appNames) {
    
        if (PTC.cat.StructureComponentLauncher.appNames[appName]) {
          var scIFrame = document.getElementById(PTC.cat.StructureComponentLauncher.appNames[appName]);
          if (scIFrame) {
            // Do not use display = none in FF, it causes viz plugin to reload (SPR 2206258)
            // It is required to do this in Chrome to prevent issues on navigating to folder browser from 
            // Structure tab (SPR 2221200)
            if (Ext.isChrome) {
                scIFrame.style.display="none";
            }
            scIFrame.style.visibility="hidden";
          }
        }
        
        if (PTC.cat.StructureComponentLauncher["sendToBack" + appName]) {
          PTC.cat.StructureComponentLauncher["sendToBack" + appName]();
        }
        
        if (clear && PTC.cat.StructureComponentLauncher["clear" + appName]) {
          PTC.cat.StructureComponentLauncher["clear" + appName]();
        }
    }
    },
    
    loadSC: function(appName, iframeId, iframeJSPRelativeURL, idOfDivToMatch, containerOid, OrganizationOid) {
    
    ifrm = document.createElement("IFRAME");
    ifrm.setAttribute("id", iframeId);
    
    var element_of_content_div = Ext.getCmp(idOfDivToMatch);
    
    ifrm.setAttribute("width", element_of_content_div.getWidth() + "px");
    ifrm.setAttribute("height", element_of_content_div.getHeight() + "px");
    
    ifrm.setAttribute("marginwidth", "0");
    ifrm.setAttribute("marginheight", "0");
    
    ifrm.setAttribute("hspace", "0");
    ifrm.setAttribute("vspace", "0");
    
    ifrm.setAttribute("frameborder", "0");
    ifrm.setAttribute("scrolling", "no");
    
    ifrm.style.position = "absolute";
    
    var position = element_of_content_div.getPosition();
    ifrm.style.left = position[0] + "px";
    ifrm.style.top = position[1] + "px";
    
    var main_base_element = document.getElementById("basehref");
    
    document.body.appendChild(ifrm);
    
    var iframe_document = ifrm.document;
    if (!iframe_document) {
      iframe_document = ifrm.contentDocument;
    }
    
    var base_element = iframe_document.createElement('base');
    
    base_element.id = "basehref";
    base_element.href = main_base_element.href;
    
    iframe_document.getElementsByTagName("head")[0].appendChild(base_element);
    
    var ifrm_base_element = iframe_document.getElementById("basehref");
    
    // We need to send the jsDebug parameter over to the server, and set the gwt code server parameter 
    // on the iframe so it can connect to the server
    var split_url = window.location.href.split("?");    
    // Hack to work around funky URL in the Selenium environment where there are two '?' marks in the URL
    if (split_url.length == 3) {
        split_url[1] = split_url[1] + "?" + split_url[2];
    }
    var debug_portion = "";
    var amp = "";
    var jsDebugFlag = extractParamValue(window.location.href, 'jsDebug');
    if (jsDebugFlag && !(jsDebugFlag == "")) {
      debug_portion = "jsDebug=" + jsDebugFlag;
      amp = "&";
    }
    
    var gwt_codesvr = extractParamValue(window.location.href, 'gwt.codesvr'); //"127.0.0.1:9997";
    if (gwt_codesvr && !(gwt_codesvr == "")) {
      debug_portion = debug_portion + amp + "gwt.codesvr=" + gwt_codesvr;
    }
    
    if (debug_portion && !(debug_portion == "")) {
      debug_portion = "?" + debug_portion;
    }
    
      ifrm.setAttribute("src", iframeJSPRelativeURL + debug_portion);
      PTC.cat.StructureComponentLauncher[appName] = true;
    },
    
    removeIframe: function(appName, iframeId) {
      // Fire this event so that the removeIframe listener in 
      // CATHistoryImpl whose scope is wnd.parent gets removed
      PTC.navigation.fireEvent("removeIframe", parent.document);
      try {
        var iframeEl = document.getElementById(iframeId);
        var iframeWin = iframeEl.contentWindow;
        
        if (iframeWin && iframeWin.PTC) {
      iframeWin.PTC.navigation.removeIframes.call(iframeWin, iframeWin.document, true, true);
        }
        if (iframeWin && iframeWin.document) {
          PTC.util.purge(iframeWin.document);
        }
        
        iframeEl.src = '';
      }
      catch (e) {
        // Some iframes may throw an access error trying to access the document or content window
        PTC.log.error("removeDuplicateIframe() Error occurred while removing iframe:", e);
      }
      Ext.removeNode(iframeEl);
    },
    
    removeApp: function(appName, iframeId, idOfDivToMatch) {
      
      delete PTC.cat.StructureComponentLauncher[appName];
      
      var scIFrame = document.getElementById(iframeId);
      
      scIFrame.id = "hiddenMSRFrame";
      
      PTC.navigation.removeIframes(scIFrame, false, false);
      
      scIFrame.style.visibility="hidden";
  }
};


PTC.infoPage.on("afterRender", function() {

  var tabSwitchListener = function(tabpanel, newTab, old) {
    if(newTab && newTab.id.indexOf("GWT")>0) {
      if (newTab.id != "infoPage_myTab_msr_modelStructureGWT" || !PTC.cat.StructureComponentLauncher.isESR) {

        var appName = PTC.cat.StructureComponentLauncher.appNameByIdOfDivToMatch[newTab.id];
        var iframe = PTC.cat.StructureComponentLauncher.appNames[appName];
      }
      
      if(!PTC || !PTC.infoPage || !PTC.infoPage['scConfigLoadComplete' + appName]) {
        
          PTC.cat.StructureComponentLauncher.refreshPage(newTab.id, iframe);
        return;
      }

      PTC.cat.StructureComponentLauncher.bringToFront(appName, iframe, null, newTab.id);
    }else{
      PTC.cat.StructureComponentLauncher.sendToBack(false);
    }
   };
   
   var tabPanel = PTC.infoPage.getTabPanel();

   if(tabPanel){
     var gwtTab = PTC.cat.StructureComponentLauncher.getGWTTab(tabPanel);
     if (gwtTab) {
       // Support handling of any JCA actions that occur inside the GWT iframe
       gwtTab.on("afterAction", function(formResult) {

         // Force a no-op so the GWT tab isn't refreshed. A refresh isn't necessary
         // because the GWT app is already aware of all of the changes that has occurred.
         // Also, a refresh can cause a race condition with any server operation that is 
         // fired off in this method call sequence, causing instability in the GWT app.
         // Also, reloadContents will still be used for actions that occur outside of the GWT app.
         var oldReload = gwtTab._reloadContents;
         gwtTab._reloadContents = function() {
           gwtTab._reloadContents = oldReload;
         };     

         // Stop default infoPage handling as refresh top has already been called, it is unnecessary
         formResult.hasInfoPageBeenProcessed = true;
         
         return !formResult.hasAnyOids();
       });
     }

     tabPanel.on('beforetabchange', tabSwitchListener);
   }

   tabPanel = Ext.getCmp("newEPMDocObjectUtilityinfoPanelID");
   
   if(tabPanel){
      tabPanel.on('beforetabchange', tabSwitchListener);
   }
});

