PTC.cat.StructureComponentTestHarness = {

	//Accepts a String that will be parsed into a JSON Array. Each element of the JSON array is expected end with an
	//API call with a Controller. Like "PTC.cat.selectRow("PSB.tree",1);"
	runStatements: function(statementsJSONArray) {
    	
    	PTC.cat.StructureComponentTestHarness.statementArray = JSON.parse(statementsJSONArray);
    	PTC.cat.StructureComponentTestHarness.statementIndex = -1;
    	PTC.cat.StructureComponentTestHarness.runningStatements = true;
    	
    	PTC.cat.StructureComponentTestHarness.runNextStatement();
		PTC.cat.StructureComponentTestHarness.logList = [];
		PTC.cat.StructureComponentTestHarness.runTimeLog = "";
	},
	
	runNextStatement: function() {
	
		if (PTC.cat.StructureComponentTestHarness.statementIndex != -1) {
			PTC.cat.StructureComponentTestHarness.runTimeLog += PTC.cat.StructureComponentTestHarness.statementIndex + "-" + (((new Date()).getTime() - PTC.cat.StructureComponentTestHarness.statementStartTime) + ",");
		}
		PTC.cat.StructureComponentTestHarness.statementStartTime = (new Date()).getTime();
		PTC.cat.StructureComponentTestHarness.statementIndex++;
    
		if (PTC.cat.StructureComponentTestHarness.statementIndex < PTC.cat.StructureComponentTestHarness.statementArray.length) {
    		
    		(new Function(PTC.cat.StructureComponentTestHarness.statementArray[PTC.cat.StructureComponentTestHarness.statementIndex]))();
    		
    		var intervalId = null;

    		function earlyCompleteCheck() {
    			clearInterval(intervalId);
    			PTC.cat.callbackToTestHarnessIfNecessary();
    		}
    		
    		intervalId = setInterval(earlyCompleteCheck, 1);
    	}
    	else {
    		PTC.cat.StructureComponentTestHarness.runningStatements = false;
    		PTC.cat.StructureComponentTestHarness.failedTestStatement = false;
			PTC.cat.StructureComponentTestHarness.failureMessage = false;
			PTC.cat.StructureComponentTestHarness.statementArray = false;
    	}
	},
	
	onSuccess: function() {
		if (PTC.cat.StructureComponentTestHarness.runningStatements) {
			PTC.cat.StructureComponentTestHarness.runNextStatement();
		}
	},

	onFailure: function(failureMessage) {
		if (! PTC.cat.StructureComponentTestHarness.failureExpected) {
			PTC.cat.StructureComponentTestHarness.failedTest = true;
			PTC.cat.StructureComponentTestHarness.runningStatements = false;
			if (PTC.cat.StructureComponentTestHarness.statementArray != false) {
				PTC.cat.StructureComponentTestHarness.failedTestStatement = PTC.cat.StructureComponentTestHarness.statementArray[PTC.cat.StructureComponentTestHarness.statementIndex];	
			}
			PTC.cat.StructureComponentTestHarness.statementArray = false;
		}
		PTC.cat.StructureComponentTestHarness.failureMessage = failureMessage;
	},

	getRunningStatements: function() {
		return PTC.cat.StructureComponentTestHarness.runningStatements;
	},
	
	getFailedTestStatement: function() {
		return PTC.cat.StructureComponentTestHarness.failedTestStatement;
	},
	
	getFailedTest: function() {
		return PTC.cat.StructureComponentTestHarness.failedTest;
	},

	hasStructureLoadCompeleted: function() {
		return window.parent.PTC.cat.StructureComponentTestHarness.scStartComplete && window.parent.PTC.cat.StructureComponentTestHarness.scStarted;
	},
	
	getFailureMessage: function() {
		return PTC.cat.StructureComponentTestHarness.failureMessage;
	},
	
	setTimeoutFailure: function() {
		//This method will cause the currently running test statement to add its run time to the run time log
		PTC.cat.StructureComponentTestHarness.runTimeLog += (PTC.cat.StructureComponentTestHarness.statementIndex + "(" + PTC.cat.StructureComponentTestHarness.statementArray[PTC.cat.StructureComponentTestHarness.statementIndex] + ")-" + ((new Date()).getTime() - PTC.cat.StructureComponentTestHarness.statementStartTime) + ",");
	},
	
	testResults: function() {
		var testFailedOn = PTC.cat.StructureComponentTestHarness.failedTestStatement;
		var testFailInformation = PTC.cat.StructureComponentTestHarness.failureMessage;
		if (testFailedOn == false && testFailInformation == false) {
			alert("Test Passed");
		} else {
			alert("The current test failed on test statement at index " + PTC.cat.StructureComponentTestHarness.statementIndex + ": " + testFailedOn + "\n" + testFailInformation);
		}
		PTC.cat.StructureComponentTestHarness.failedTestStatement = false;
		PTC.cat.StructureComponentTestHarness.failureMessage = false;
	},
	
	setDebugger: function(statement, failureMessage) {
		PTC.cat.StructureComponentTestHarness.failedTestStatement = statement;
		PTC.cat.StructureComponentTestHarness.failureMessage = failureMessage;
	},
	
	debugInformation: function() {
		var testFailedOn = PTC.cat.StructureComponentTestHarness.failedTestStatement;
		var testFailInformation = PTC.cat.StructureComponentTestHarness.failureMessage;
		if (testFailedOn == false && testFailInformation == false) {
			alert("***DEBUGGER***\nDebug Test Passed!");
		} else {
			alert("***DEBUGGER***\nSTATEMENET at index " + PTC.cat.StructureComponentTestHarness.statementIndex + ": " + testFailedOn + "\nFailure Message: " + testFailInformation);
		}
		PTC.cat.StructureComponentTestHarness.failedTestStatement = false;
		PTC.cat.StructureComponentTestHarness.failureMessage = false;
	},
	
	getDebugLog: function() {
		return PTC.cat.StructureComponentTestHarness.logList;
	},
	
	getStringifiedDebugLog: function() {
		return JSON.stringify(PTC.cat.StructureComponentTestHarness.logList);
	},
	
	writeToLog: function(text) {
		PTC.cat.StructureComponentTestHarness.logList.push(text);
	},
	
	setFailureExpected: function() {
		PTC.cat.StructureComponentTestHarness.failureExpected = true;
	},
	
	clearFailureExpected: function() {
		PTC.cat.StructureComponentTestHarness.failureExpected = false;
		PTC.cat.StructureComponentTestHarness.failureMessage = false;
	},
	
	failureExpected: false,
	failedTest: false,
	failedTestStatement: false,
	failureMessage: false,
	statementArray: false,
	runningStatements: false,
	scStartComplete: false,
	scStarted: false,
	logList: []
};

