/*
 * Method to validate that at least one object has been selected in the subscriptions table before showing
 * the delete confirmation message
 *
 * @param evt the user action triggering this method to be called. For example, the click event clicking the delete
 *            action on the subscriptions table
 * @return true if the action should succeed, false if it should be blocked
 */
PTC.subscription.validateSelectRequired=function(evt) {
    var sels = PTC.jca.table.Utils.getSelectedItmesByEvent(evt);
    if( sels.length === 0) {
        JCAAlert("com.ptc.netmarkets.util.utilResource.NONE_CHECKED");
        Event.stop(evt);
        return false;
    }
    JCAConfirm(evt, "com.ptc.netmarkets.util.utilResource.CONFIRM_DELETE");
    return true;
};



/**
 * @namespace
 * Namespace for helper functions to add table row html strings into a table in IE 8 mode.
 * These functions can be deleted once we no longer support IE 8 mode.
 * @internal
 */
PTC.tableResponseHandler = {};
PTC.tableResponseHandler.getNextColumn = function(newRowHTML) {
    var TH_TAG = '<th';
    var TD_TAG = '<td';
    var TH_END_TAG = '</th>';
    var TD_END_TAG = '</td>';
    var CLASS_FLAG = 'class=\"';
    var NOWRAP = 'NOWRAP';
    var SCOPE = 'scope=\"';

    var newColumn = [];
    newColumn.className = '';
    newColumn.noWrap = false; // Default
    newColumn.scope = '';
    newColumn.innerHTML = "";
    newColumn.remainingHTML = newRowHTML;

    var tempHTML = newColumn.remainingHTML.toLowerCase();
    var indexth = tempHTML.indexOf(TH_TAG);
    var indextd = tempHTML.indexOf(TD_TAG);
    if (indexth < 0) {
        indexth = 10000;
    }
    if (indextd < 0) {
        indextd = 10000;
    }
    if (indexth <= indextd) {
        indextd = indexth;
    }
    var indextdend = newColumn.remainingHTML.indexOf('>');
    var innerTag = newColumn.remainingHTML.substring(indextd + 1, indextdend);

    // Check for the NoWrap
    var attrIndex = innerTag.indexOf(NOWRAP);
    if (attrIndex >= 0) {
        newColumn.noWrap = true;
    }

    // Check for the class style
    var endIndex;
    attrIndex = innerTag.indexOf(CLASS_FLAG);
    if (attrIndex >= 0) {
        attrIndex = attrIndex + CLASS_FLAG.length;
        endIndex = innerTag.indexOf('\"', attrIndex);
        newColumn.className = innerTag.substring(attrIndex, endIndex);
    }

    // Check for scope
    attrIndex = innerTag.indexOf(SCOPE);
    if (attrIndex >= 0) {
        attrIndex = attrIndex + SCOPE.length;
        endIndex = innerTag.indexOf('\"', attrIndex);
        newColumn.scope = innerTag.substring(attrIndex, endIndex);
    }

    newColumn.remainingHTML = newColumn.remainingHTML.substring(indextd);
    newColumn.remainingHTML = newColumn.remainingHTML.substring(newColumn.remainingHTML.indexOf('>') + 1);

    tempHTML = newColumn.remainingHTML.toLowerCase();
    indexth = tempHTML.indexOf(TH_END_TAG);
    indextd = tempHTML.indexOf(TD_END_TAG);
    if (indexth < 0) {
        indexth = 10000;
    }
    if (indextd < 0) {
        indextd = 10000;
    }
    if (indexth <= indextd && indexth != 10000) {
        indextd = indexth;
    }
    newColumn.innerHTML = newColumn.remainingHTML.substring(0, indextd);
    newColumn.remainingHTML = newColumn.remainingHTML.substring(indextd + TD_END_TAG.length);

    return newColumn;
};

PTC.tableResponseHandler.insertNewRowHTMLForIE = function(newNode, newRowHTML) {
    var hasMore = true;
    var childIndex = 0;

    while (hasMore) {

        var newColumn = PTC.tableResponseHandler.getNextColumn(newRowHTML);
        newRowHTML = newColumn.remainingHTML;

        if (!newRowHTML || newRowHTML.length < 5) {
            hasMore = false;
        }
        if (newColumn.innerHTML) {
            var newEle = document.createElement('td');
            newEle.className = newColumn.className;
            newEle.noWrap = newColumn.noWrap;
            newEle.scope = newColumn.scope;
            newNode.appendChild(newEle);
            newEle.innerHTML = newColumn.innerHTML;
        }
    }
    return newNode;
};


// Singleton pattern for ClientStateProvider object.
PTC.jca.table.SessionProvider = function(){
    this.provider = new PTC.jca.state.ClientStateProvider({
        domstorage: 'session'
    });
};
/**
 * @class
 * It will return ClientStateProvider by singleton design pattern.
 */
PTC.jca.table.SessionProvider.instance = null; // Will contain the one and only instance of the class
PTC.jca.table.SessionProvider.getInstance = function(){
    if (!PTC.jca.table.SessionProvider.instance) {
        PTC.jca.table.SessionProvider.instance = new PTC.jca.table.SessionProvider();
    }
    return PTC.jca.table.SessionProvider.instance;
};

PTC.jca.table.SessionProvider.prototype.get = function(uniqueKey){
    return this.provider.get(uniqueKey, "");
};

PTC.jca.table.SessionProvider.prototype.set = function(uniqueKey, object){
    this.provider.set(uniqueKey, object);
};

PTC.jca.table.SessionProvider.prototype.clear = function(uniqueKey){
    this.provider.clear(uniqueKey);
};
/**
 * This function will save object to session.
 * @param {String} tableId
 * @param {String} elementName
 * @param {object} object
 */
PTC.jca.table.setObjectToSession = function(tableId, elementName, object){

    var provider = PTC.jca.table.SessionProvider.getInstance();
    var uniqueKey = PTC.jca.table.findInTable.findUniqueKey(tableId, elementName);
    provider.set(uniqueKey, object);
};

/**
 * This function will return saved object from session.
 * @param {String} tableId
 * @return {String} object
 */
PTC.jca.table.getObjectFromSession = function(tableId, elementName){

    var provider = PTC.jca.table.SessionProvider.getInstance();
    var uniqueKey = PTC.jca.table.findInTable.findUniqueKey(tableId, elementName);
    return provider.get(uniqueKey);
};

/**
 * This function will clear object from session.
 * @param {String} tableId
 * @return {String} savedSearchTerm
 */
PTC.jca.table.clearObjectFromSession = function(tableId, elementName){
    var provider = PTC.jca.table.SessionProvider.getInstance();
    var uniqueKey = PTC.jca.table.findInTable.findUniqueKey(tableId, elementName);
    provider.clear(uniqueKey);
};


