        /**
         * Remove all rows from the table, specified by tableId
         * This will also clear the values from the following three hidden fields:
         *     addRows_<tableId>
         *     rmRows_<tableId>
         *     initialRows_<tableId>
         *
         * @param tableId - String table id.
         */
        removeAll: function(tableId) {
            var table = PTC.jca.table.Utils.getTable(tableId);
            if (table) {
            	table.getStore().removeAll();
            }
            var addRows = document.getElementById(ADDED_ROWS_PREFIX + tableId);
            if(addRows) {
                addRows.value = "";
            }
            var rmRows = document.getElementById(REMOVED_ROWS_PREFIX + tableId);
            if(rmRows) {
                rmRows.value = "";
            }
            initialRows = document.getElementById(INITIAL_ROWS_PREFIX + tableId);
            if(initialRows) {
                initialRows.value = "";
            }
        },
        /**
         * Returns true/false if the dom NODE is a row in the table with the class JCA_tablerow
         * @param node - checkbox dom node
         */
        isTableCheckBox: function(node){
            return (node.className.match(new RegExp('(^|\\s)' + TABLE_ROW_CLASS + '(\\s|$)')));
        },

        /**
         * Unselect any table rows not in the current table.
         * Don't unselect anything if nothing is selected in the current table
         * because the action will report that nothing is selected and fail.
         *
         * @param tableID - String table id.
         * @param isActionsMenu - boolean, true if this is action menu
         **/
        deSelectOtherTableRows: function(tableID, isActionsMenu){
            var tables = this.getTables();
            tableID = this.getUnformattedTableId(tableID);
            for (var i=0,l=tables.length; i<l; i++) {
                var item = tables[i];
                if (isActionsMenu || item.id !== tableID) {
                    // TODO: Need to provide a generic API to remove all selections across pages.
                    var clearAllButton = Ext.getCmp(item.id + '_clearacrosspg');
                    if (clearAllButton && !clearAllButton.disabled) {
                        clearAllButton.fireEvent("click", clearAllButton);
                    }
                    else {
                        item.getSelectionModel().clearSelections();
                    }
                }
            }
        },

        /**
         * Toggles disabled attribute of selected rows from tables other than the table on which the action is performed
         * It also disables hidden input fields which stores the selected checkBoxes reference.
         * @param {String} tableID
         *                   Id of table on which action is performed
         * @param {boolean} disable
         *                   if true disable selected rows from other tables
         *                   if false enable the selected rows, if already disabled
         */
        toggleDisabledSelectedRows: function(tableID, disable){
            var tables = this.getTables();
            tableID = this.getUnformattedTableId(tableID);
            tables.each(function(item){
                if (item.id !== tableID) {
                    var selectionModel = item.getSelectionModel();
                    if (disable) {
                        selectionModel.lock();// takes care of clearSelection call
                    }
                    else if (selectionModel.isLocked()) {
                        selectionModel.unlock();
                    }
                    var selectedItems = null;
                    if(item.getSelectionModel() && (typeof item.getSelectionModel().getSelections == 'function')) {
                        selectedItems = item.getSelectionModel().getSelections();
                    }
                    if (selectedItems) {
                        var selectedRows = PTC.jca.table.Utils.getTableSelectedRowsById(item.id, false,true);
                        for (var i = 0, l=selectedRows.length; i < l; i++) {// elements in hidden div
                            selectedRows[i].disabled = disable;
                        }
                        for (i = 0,l=selectedItems.length; i < l; i++) {// dom objects for the checkboxes
                            selectedItems[i].disabled = disable;
                            var domObject = Ext.fly(selectedItems[i].id);
                            if (domObject) {
                                domObject.disabled = disable;
                            }
                        }
                    }
                }
            });

        },
        
