        /**
         * turns a div table id into the simple table id used as in the jsp tags
         *  table__jca.sometable__TABLE -> jca.sometable
         */
        getUnformattedTableId: function(tableID){
            if (!tableID) {
                return tableID;
            }
            var tID = tableID;
            var startIdx;
            var endIdx;
            if (tableID.indexOf(TABLE_PREFIX) != -1) {
                startIdx = tableID.indexOf(TABLE_PREFIX);
                startIdx += TABLE_PREFIX.length;
                tID = tableID.substring(startIdx, tableID.length);
            }
            if (tableID.indexOf(TABLE_SUFFIX) != -1) {
                endIdx = tID.indexOf(TABLE_SUFFIX);
                tID = tID.substring(0, endIdx);
            }
            return tID;
        },

        getTableIdFromViewPullDown: function(unFormattedTableId){
            if (!unFormattedTableId) {
                return unFormattedTableId;
            }
            var tID = unFormattedTableId;
            var endIdx;
            if (unFormattedTableId.indexOf(PULLDOWN_SUFFIX) != -1) {
                endIdx = tID.indexOf(PULLDOWN_SUFFIX);
                tID = tID.substring(0, endIdx);
            }
            return tID;
        },

        /**
         * Gets the table view drop-down combo box component.
         * @param {String} tableID
         */
        getTableViewComboBox: function(tableID) {
            return Ext.getCmp(tableID + PULLDOWN_SUFFIX);
        },

        /**
         * turns a simple table id (as in the jsp tags) into a div table id
         *  jca.sometable -> table__jca.sometable__TABLE
         */
        getFormattedTableId: function(tableID){
            if (!tableID) {
                return tableID;
            }
            var tID = tableID;
            if (tableID.indexOf(TABLE_PREFIX) == -1) {
                tID = TABLE_PREFIX + tID;
            }
            if (tableID.indexOf(TABLE_SUFFIX) == -1) {
                tID = tID + TABLE_SUFFIX;
            }
            return tID;
        },

