/**
 * Returns an array of checkboxes with information stored in checkboxes present within
 * the hidden DIV. Any disabled checkbox will not be considered as selected by default
 *
 * @param {String} jcaTableId - (required) id of the table
 * @param {boolean} [isChecked] When true returns an array with the first selected item found.
 * @param (boolean) [addDisabled] - is set to true, disabled selected records are also considered else ignored
 * @return {Array} - an array of "checkbox" objects that have values like JCA checkboxes would
 *
 */
PTC.jca.table.Utils.getTableSelectedRowsById = function(jcaTableId, isChecked,addDisabled){
    var jscaRows = [];//create some fake checkboxes
    var tableId = this.getUnformattedTableId(jcaTableId);
    var selectedRowsDiv = getWindow().document.getElementById("checkboxesFor_" + tableId);
    if (selectedRowsDiv) {
        var count = 0;
        var selectedNodes = selectedRowsDiv.childNodes;
        for (var i = 0, k = selectedNodes.length; i < k; i++) {
            var selected = selectedNodes[i];
            if (selected.checked && (!selected.disabled || addDisabled)) {
                jscaRows[count++] = selected;
                if (isChecked) {
                    return jscaRows;
                }
            }
        }
    }
    return jscaRows;
};


