/**
 * Gets the table object.
 * @param {String} id - the id of the table (if id is not a string, id is just returned)
 */
PTC.jca.table.Utils.getTable = function(id){
    if (typeof id !== 'string') {
        // mixed input, may already be the table
        return id;
    }
    id = PTC.jca.table.Utils.getUnformattedTableId(id);

    if (typeof Ext !== 'undefined') {
        // Try to get the table from the Ext cache directly
        var t = Ext.getCmp(id);
        if (t !== undefined && t instanceof Ext.grid.GridPanel) {
            return t;
        }
    }
    var table = null;
    var tables = PTC.jca.table.Utils.getTables();
    for (var i=0,l=tables.length; i<l; i++) {
        var item = tables[i];
        if (item && id === item.id) {
            table = item;
        }
    }
    return table;
};
