function OLD_getTableById(tableId){
    for (var i = 0, l = tableArray.length; i < l; i++) {
        if (tableArray[i].id == tableId) {
            return tableArray[i];
        }
    }
    return null;
}

getTableById = PTC.jca.table.Utils.getTable;

PTC.jca.table.Utils.isExt = function(){
    if (typeof Ext !== 'undefined') {
        var divs = Ext.DomQuery.select("div[class*='x-grid-panel']");
        if (divs && divs.length > 0) {
            return true;
        }
    }
    return false;
};
/**
 * Returns an array of Ext tables found with the given root node.
 *
 * @param {Object} [root] Optional parent DOM node to start the search, uses document if root is null.
 */
PTC.jca.table.Utils.getExtTables = function(root){
    var tables = [];
    if (typeof Ext !== 'undefined') {
        var divs = Ext.DomQuery.select("div[class*='x-grid-panel']", root);
        for (var i=0,l=divs.length; i<l; i++) {
            var item = divs[i];
            var tableGrid = Ext.getCmp(item.id);
            if (tableGrid !== undefined) {
                tables.push(tableGrid);
            }
        }
    }
    return tables;
};
/**
 * Get the data load user conformation when result limit hits
 * @param {Object} store - Table store object.
 * @param {String} key - Key for which the message is to be displayed
 * @param {String} tableId - tableId to get the store if not avialbel.
 */
PTC.jca.table.Utils.getDataLoadUserConfirmation = function(store,key,tableId){
    if(store === undefined || store === null){
        var table = tableUtils.getTable(tableId);
       store = table.getStore();
   }
   if (store.resultLimitReached || store.resultLimitCrossed) { // Check if result limit is reached/crossed
       var proceed = JCAConfirm(key);
       store.showPopUp = proceed;
        if (!proceed) {
           return false;
        }else{
        // Flag added to indicate that data above the result limit is getting downloaded.
         store.resultLimitCrossed  = true;
             return true;
        }
   }
   return true;
};
