/**
 * Remove a row from the table
 * @param {Mixed} table - table or tableId
 * @param {String} att - The oid or context string of the row to remove
 */
PTC.jca.table.Utils.removeRow = function(table, att){
    if (typeof table === 'string') {
        table = this.getTable(table);
    }
    if (table) {
        var currentRecord = this._getTableRow(table, att);
        if (currentRecord) {
            jsca.unSelectAll(null, table.id);
            return table.store.remove(currentRecord);
        }
    }
};

