/**
 * Get the url from the store to update a table
 * @param {Object} id of the table
 */
PTC.jca.table.Utils.getTableUrl = function(id){
    var table = this.getTable(id);
    var url = null;
    if (table && table.store !== undefined && table.store.proxy !== undefined && table.store.proxy.url !== undefined) {
        url = Ext.urlAppend(table.store.proxy.url, Ext.urlEncode(table.store.baseParams));
    }
    if (!url && table && table.jcaTableConfig !== undefined) {
        // for Data sourced tables...
        url = Ext.urlAppend(table.jcaTableConfig.storeURL.url, Ext.urlEncode(table.store.baseParams));
    }
    return url;
};
/**
 * Removes any tables and attribute panels under the root object and frees memory
 * @param {Object} [root] Optional dom node to use as the start of the selector, if null entire document is searched
 */
PTC.jca.table.Utils.cleanUp = function(root) {
    var ts = this.getExtTables(root);
    if (root && root.id) {  //Div passed
        var rootTable = tableUtils.getTable(root.id);
        if (rootTable) {
            ts.push(rootTable);
        }
    }
    if (ts && ts.length > 0) {
        for (var i = 0, l = ts.length; i < l; i++) {
            var item = ts[i];
            PTC.jca.table.Utils.destroyTable(item);
        }

        Ext.garbageCollect();
    }
    PTC.jca.deleteAllCmpsWithCls(root, '.attribute-apanel');
};

/**
 *
 * @param {Ext.grid.GridPanel} table
 */
PTC.jca.table.Utils.destroyTable = function(table){
    if (table.updateSizeTask) {
        if (table.updateSizeTask.cancel) {
            table.updateSizeTask.cancel();
        }
        delete table._updateSizeTask;
    }
    if (table.updateSelCountMsg) {
        if (table.updateSelCountMsg.task) {
           table.updateSelCountMsg.task.cancel();
           delete table.updateSelCountMsg.task;
        }
        delete table.updateSelCountMsg;
    }
    if (table.view && table.view.syncHeaderScroll) {
        if (table.view.syncHeaderScroll.task) {
            table.view.syncHeaderScroll.task.cancel();
            delete table.view.syncHeaderScroll.task;
        }
        delete table.view.syncHeaderScroll;
    }
    if (table._heightFuncTimer) {
        clearTimeout(table._heightFuncTimer);
        delete table._heightFuncTimer;
    }
    
    if (Ext.isIE8) {
        //Mixed content problem: 2154818.      common buttons
        PTC.util.deleteComponentWithBackgroundSrc(Ext.getCmp(table.id + "_toggle"));  //toggle button
        PTC.util.deleteComponentWithBackgroundSrc(Ext.getCmp('footer_' + table.id + "_cancelDataSourceButton")); //Cancel button
        PTC.util.deleteComponentWithBackgroundSrc(Ext.getCmp('header_' + table.id + "_cancelDataSourceButton")); //Cancel button

        //All Others...
        if (table.el.dom) {
            var buttons = table.el.dom.getElementsByTagName("BUTTON");
            var i = buttons.length;
            while (i--) {
               buttons[i].outerHTML = '';
            }
        }
    }

    //clear information stored in state manager
    Ext.state.Manager.clear(table.id);
    var wTableId = PTC.jca.table.getWTablePanelID(table.id);
    var wTable = table.wtableRef;
    if (!wTable) {
        wTable = Ext.getCmp(wTableId);
    }
    if(table.transport){
        //if there is any open ajax request, abort it
        try {
            requestHandler.abort(table.transport);
        } catch(e) {
            PTC.jca.table.log.error('Exception aborting ajax call ', table.transport, e);
        }
    }
    var store = table.store;
    if (store && store.chunk) {
        if(typeof store.isLoading === 'function' && store.isLoading() === true){
          PTC.jca.DataSourceRegistry.cancelServerDataSources([store.chunk.id]);
        }
    }
    if (store && store.dataChangeTask) {
       if (store.dataChangeTask.cancel) {
           store.dataChangeTask.cancel();
       }
       delete store.dataChangeTask;
    }
    if(store && store.selectPreSelectOids){
        if (store.selectPreSelectOids.cancel) {
           store.selectPreSelectOids.cancel();
       }
       delete store.selectPreSelectOids;
    }
    if (table.vtip) {
        table.vtip.destroy();
        delete table.vtip;
        }
    if (table.gsm) {
       table.gsm.destroy();
       delete table.gsm;
    }
    table.destroy();

    var selModel = table.getSelectionModel();
    if (selModel) {
        if (selModel._handleSelectAllCheckboxTask) {
            if (selModel._handleSelectAllCheckboxTask.cancel) {
                selModel._handleSelectAllCheckboxTask.cancel();
            }
            delete selModel._handleSelectAllCheckboxTask;
        }
        selModel.destroy();
    }

    if (wTable) {
        if (wTable.updateTitle && wTable.updateTitle.task) {
            wTable.updateTitle.task.cancel();
            delete wTable.updateTitle.task;
            delete wTable.updateTitle;
        }
        Ext.ComponentMgr.unregister(wTable);
        if (table.toolbars && table.toolbars.length) {
            for (i = 0, l = table.toolbars.length; i < l; i++) {
                if (table.toolbars[i]) {
                    table.toolbars[i].destroy();
                }
                delete table.toolbars[i];
            }
        }
        PTC.action.un('objectsaffected', table.onObjectsAffected, table);
        wTable.destroy();
        Ext.destroy(wTable.searchInListToolbar, wTable.help, wTable.helpButton, wTable.pickView, wTable.titleBar,
         wTable.pagingBar,wTable.optionsButton, wTable.toolBar, wTable.menuBar, wTable.viewsCombo, wTable.gridPanel,
         wTable.tbar, wTable.fbar, wTable.appFiltersCombo);
        delete wTable.searchInListToolbar;
        delete wTable.help;
        delete wTable.helpButton;
        delete wTable.pickView;
        delete wTable.titleBar;
        delete wTable.pagingBar;
        delete wTable.optionsButton;
        delete wTable.toolBar;
        delete wTable.menuBar;
        delete wTable.viewsCombo;
        delete wTable.appFiltersCombo;
        delete wTable.gridPanel;
    }
};

/**
 * This method will return string boolean value for given columnId and Row.
 *
 * @param row
 * @param columnId
 * @param defaultValue
 *
 */
PTC.jca.table.getColumnBooleanStringValue = function(row, columnId, defaultValue) {
    var rawValue = row.get(columnId);
    if(rawValue && rawValue.gui) {
        rawValue = rawValue.gui.comparable;
    }
    else if (typeof rawValue === 'boolean') {
        rawValue = rawValue.toString();
    }
    else if (typeof rawValue === 'string') {
        rawValue = rawValue;
    }
    else {
        rawValue = defaultValue;
    }
    return rawValue;
};

/**
 * @param {Object} record - the table row
 * @param {Object} rowStore
 * @return true if the given row is selectable, false otherwise
 */
PTC.jca.table.isRowSelectable = function(record, rowStore, grid) {
    if(!record) {
	    return true;
    }
    var nonSelectableColumn = null;
	if(rowStore) {
        if(!grid) {
            grid = rowStore.jsca_table;
            if (!grid) {
                grid = PTC.jca.table.Utils.getTable(rowStore.jscaTableID);
            }
        }
        if(grid) {
            var jcaTableConfig = grid.jcaTableConfig;
            //For MVC table get the value of nonSelectableColumn.
            nonSelectableColumn = jcaTableConfig.nonSelectRowColumn ? PTC.jca.table.getColumnBooleanStringValue(record, jcaTableConfig.nonSelectRowColumn, 'false') : nonSelectableColumn;
        }
    }

    if(nonSelectableColumn === 'true'  || record.get('selectableRow') === false) {
    	if(grid) {
            grid.hasNonSelectableRow = true;
    	}
        return false;
    }

    return true;
};

