jsca.columns.textAreaRenderer = function(table,column,row) {
    var result = '';
    var data = jsca.columns.getCellValue(column, row);
    if (data.enabled)
    {
        if (typeof row.get === 'function' && row.get(column.id)) {
            row.get(column.id).updateCellValue = jsca.columns.textAreaRenderer.updateCellValue;
        }
        result = '<textarea ' + jsca.columns.idStr(data.id) + jsca.columns.nameStr(data.name)
                + 'rows=\"' + data.rows
                + '\" cols=\"' + data.cols + '\" '
                + jsca.columns.disabledStr(data.disabled)
                + jsca.columns.readOnlyStr(data.readOnly)
                + jsca.columns.tooltipStr(data.tooltip)
                + jsca.columns.jsActionsStr(data.jsActions)
                + 'style=\"' + data.style + '\" '
                + data.styleClasses + ' />'
                + data.displayValue + '</textarea>';

        //hidden input
        if(data.origOldValues === undefined){
            data.origOldValues = '<input type=\"hidden\" '
                + jsca.columns.idStr(data.id + jsca.columns.OLDSTR)
                + jsca.columns.nameStr(data.name + jsca.columns.OLDSTR)
                + jsca.columns.valueStr(data.value) + '/>';
        }
        result += data.origOldValues;
    } else {
        result = data.value;
    }
    result = result + jsca.columns.getHiddenInputs(data.hiddenData);
    return result;
};

