/**
 * Looks for the following row properties:
 * val (the value to be displayed in the textbox)
 * name (the HTML name of the textbox)
 * maxlength (the max # of characters that can be entered)
 */
jsca.columns.textBoxRenderer = function(table,column,row) {
    var result = '';
    var data = jsca.columns.getCellValue(column, row);
    var oid = data.oid || getRowItem(row).oid;

    if(data.enabled) {
        if (typeof row.get === 'function' && row.get(column.id)) {
            // setting the updateCellValue function to track the DOM changes
            row.get(column.id).updateCellValue = jsca.columns.textBoxRenderer.updateCellValue;
        }
        result = '<input ';
        if (data.id) {
            result += jsca.columns.idStr(data.id);
        }

        result += jsca.columns.typeStr(data.type)
                + jsca.columns.nameStr(data.name)
                + jsca.columns.jsActionsStr(data.jsActions)
                + jsca.columns.valueStr(data.value);
        if (data.readOnly) {
            result += jsca.columns.readOnlyStr(data.readOnly);
        }
        result += jsca.columns.disabledStr(data.disabled);
        if (data.tooltip) {
            result += jsca.columns.tooltipStr(data.tooltip);
        }
        if (data.styleClasses) {
            result += data.styleClasses;
        }
        if (data.width) {
            result += jsca.columns.sizeStr(data.width);
        }
        if (data.maxlength) {
            result += jsca.columns.maxlengthStr(data.maxlength);
        }
        result += '/>';

        //Hidden field
        if(data.origOldValues === undefined){
            data.origOldValues = '<input '
                + jsca.columns.typeStr('hidden')
                + jsca.columns.idStr(data.id + jsca.columns.OLDSTR)
                + jsca.columns.nameStr(data.name + jsca.columns.OLDSTR)
                + jsca.columns.valueStr(data.value);
        }
        result += data.origOldValues;

        if (data.size) {
            result += jsca.columns.sizeStr(data.size);
        }
        if (data.width) {
            result += jsca.columns.sizeStr(data.width);
        }
        if (data.maxlength) {
            result += jsca.columns.maxlengthStr(data.maxlength);
        }
        result += '/>';

    } else {
        result += '<input '
                + jsca.columns.typeStr('hidden')
                + jsca.columns.idStr(data.id)
                + jsca.columns.nameStr(data.name)
                + jsca.columns.valueStr(data.value);
        if (data.size) {
            result += jsca.columns.sizeStr(data.size);
        }
        if (data.width) {
            result += jsca.columns.sizeStr(data.width);
        }
        if (data.maxlength) {
            result += jsca.columns.maxlengthStr(data.maxlength);
        }

        result += '/>';
    }

    result = result + jsca.columns.getHiddenInputs(data.hiddenData);
    return result;
};

