/**
 * Looks for the following row properties:
 * title (basically formattedTooltip)
 * formattedValue (text value to display)
 */
jsca.columns.textDisplayComponentRenderer = function(table, column, row) {
    var result = '';
    var data = jsca.columns.getCellValue(column, row);

    if (data.id || data.tooltip || data.styleClasses) {
        result += "<span ";
        result += jsca.columns.idStr(data.id);
        if (data.styleClasses) {
            result += data.styleClasses;
            result += " ";
        }
        if (data.tooltip) {
        result += jsca.columns.tooltipStr(data.tooltip);
        }
        result += ">";
        if (data.value) {
            result += data.value;
        }
        result += "</span>";
    } else if (data.value) {
        result = data.value;
    } // end if span

    
    //add truncation.
    //If there is a newline.  Cut off at the newline and add the "..." link.
    //Was decided with Nalie 6/24/08 meeting.
    if ((data.needToUseMore && data.needToTruncate) || data.containsNewLine) {
        result = jsca.columns.textDisplayComponentRenderer.addMoreLink(data, data.truncatedValue, data.escapedValue, data.containsNewLine, data.moreLink);
    }
    result = result + jsca.columns.getHiddenInputs(data.hiddenData);
    return result;
};

/**
 * The given object should be of this form: 
 * @param {Object} hiddenData - an object that contains data necessary to render some hidden fields. 
 * 
 * @example
 * hiddenData = {
 *  hiddenFields: {    //one hidden field is rendered per hiddenField property
 *    foo: bar
 *  }, 
 *  hiddenClass: "",   //style class to put on each hidden field 
 *  isHiddenId: false, //true to add both name and id, false to just add name
 *  objectHandle: ""   //object handle to add to name if its not already part of the name string
 * }
 * 
 * @return an HTML string of hidden inputs (e.g. '&lt;input type="hidden" name="foo" value="bar"/>') 
 */
jsca.columns.getHiddenInputs = function(hiddenData){
    var result = '';
    if (hiddenData && hiddenData.hiddenFields) {
        for (var property in hiddenData.hiddenFields) {
            if (property) {
                var value = hiddenData.hiddenFields[property];
                var name = property.escapeHTML().replace("\"", "&quot;");
                if (hiddenData.objectHandle && name.indexOf(hiddenData.objectHandle) < 0) {
                    name = hiddenData.objectHandle + name;
                }
                var id = hiddenData.isHiddenId ? 'id="' + name + '" ' : '';
                var css = hiddenData.hiddenClass ? 'class="' + hiddenData.hiddenClass + '" ' : '';
                result = result + '<input type="hidden" name="' + name + '" value="' + value + '" ' + id + css + '/>';
            }
        }
    }
    return result;
};


/**
 * Adds the correct information to the data object so that it can be retrieved for adding the "..." link to the
 * hidden cell span.
 *
 * It also will add the "..." to the end of the text if it is needed.
 *
 * @param {Object} visibleText - This is the value that is displayed in the cell.
 * @param {Object} fullText - This is the value shown in the javascript pop-up.
 * @param {Object} title - This is the title to be used for the "..."
 */
jsca.columns.textDisplayComponentRenderer.addMoreLink = function(data, visibleText, fullText, containsNewLine, linkTitle){
    data.truncationURL = PTC.jslint.SCRIPT_URL_STRING + 'showFullText(\'' + escape(fullText) + '\', true)';
    data.truncationTitle = linkTitle;
    data.addDotLink = true;

    //If it contains a new line then we want to add the "..." to the end of the string.
    if(containsNewLine) {
        return visibleText + '<a title="' + linkTitle + '" href="#" onClick="showFullText(\'' + escape(fullText) + '\', true); return false;">' + "..." + '</a>';    
    }

    return fullText;
};






