/**
 * @class The tree handler hides child tree nodes when the tree is collapsed, and
 * refreshes the nodes from the server when the tree is expanded
 *
 */
var treeHandler = function() {
    return /**@scope treeHandler*/ {
        processExpandCollapseNode : function (param, oidString, conString,contextString, extraparams, uniqueCompKey) {
            //Collapse.jsp is calling method which handles expand, collapse, implode and explode.
            var url = 'netmarkets/jsp/object/collapse.jsp';
            var bparams = param+'='+encodeURIComponent(oidString)+'&conString='+encodeURIComponent(conString)+'&contextString='+encodeURIComponent(contextString)+ extraparams;
            if(uniqueCompKey !== undefined){
               bparams = bparams + '&uniqueCompKey='+encodeURIComponent(uniqueCompKey);
            }
            if (!extraparams) {
                extraparams = "";
            }
            var options = {
                parameters: bparams
            };
            requestHandler.doRequest(url, options);
        },
        asyncCollapse : function (oidString, conString,contextString, extraparams, uniqueCompKey) {
            treeHandler.processExpandCollapseNode('c', oidString, conString,contextString, extraparams, uniqueCompKey);
        },
        expandNode : function (oidString, conString,contextString, extraparams, uniqueCompKey) {
             treeHandler.processExpandCollapseNode('e', oidString, conString,contextString, extraparams, uniqueCompKey);
        }
   };
}();


/**
 * Gets a trail id for expand/collapse images in JS trees.
 *
 * Note: getCellValue() is never called (as it is called by
 * JSCA renderers) so we need to call addTrailId() or getTrailId();
 *
 *@return full id string like 'id="someTrailId" '
 */
function JSCATrailId(column, row, image) {
    var cell = {};
    var cellValue = getRowItem(row)[column.id].cellValue;
    if(cellValue) {
       if (typeof cellValue.gui !== 'undefined') {
          cell = cellValue.gui;
       }
       else if (typeof cellValue[0] !== 'undefined'){
          cell = cellValue[0].gui;
       }
       else {
          cell = cellValue;
       }
    } else {
        cell = getRowItem(row)[column.id][0].gui;
    }

    jsca.columns.addTrailId(column, row, cell);

    //If there is no id just ignore adding this.
    if (cell && cell.id) {
        if (image.indexOf("collapsed") > 0) {
            cell.id += "__" + "collapsed";
        }
        else {
            cell.id += "__" + "expanded";
        }
    }
    
    return jsca.columns.trailIdStr(column, cell);
}


