function setSearchType(Objects, pickerID, targetId) {

	getMainForm().searchType.value = "";
	var elements = Objects.pickedObjects;
	var pickedSelection = elements.length;
	for (i = 0; i < pickedSelection; i++) {
		if (elements[i].theType.indexOf("wt.fc.Persistable") > -1) {
			getMainForm().searchType.value = "wt.fc.Persistable";
			break;
		}
		var theType = elements[i].theType;

		if ((theType.indexOf("|") > 0) && (theType.indexOf("WCTYPE") == -1))
			theType = "WCTYPE|" + theType;
		if (i == 0) {
			getMainForm().searchType.value = theType;
		} else {
			getMainForm().searchType.value = getMainForm().searchType.value
					+ "," + theType;
		}

	}
	clearCriteria();
	// set the framework parameters
	getMainForm().actionClass.value = "com.ptc.netmarkets.search.NmSearchCommands";
	getMainForm().actionMethod.value = "typeChange";
	getMainForm().executeLocation.value = "inbegin";
	if (getMainForm().fireSearch)
		getMainForm().fireSearch.value = "false";
	if ($('refreshByAction')) {
		$('refreshByAction').value = "false";
	}
	if (isPicker()) {
		refreshCurrentStep();
	} else {
		setActionNumber();
		PTC.navigation.submitForm();
	}
}



