function beforeSelectType(combo, record, index) {
	var selectionOptionVal = record.get('value');
	if (selectionOptionVal == 'Full Result List') {
		launchJCAPopupAction.defer(50, this, [ 'typePicker' ]);
		combo.collapse();
		return false;
	}
	return true;
}

function onTypeChanged() {
	if (callTypeChange)  {
			getMainForm().actionClass.value = "com.ptc.netmarkets.search.NmSearchCommands";
			getMainForm().actionMethod.value = "typeChange";
			PTC.navigation.submitForm();
		showBusySign();      
	}
}

function callTypeChange() {
	var oldval = getMainForm().searchType.value;
	var newval = $('searchForTypes$lable$').value;

	if (oldval == newval) {
		return;
	}

	if (newval != 'undefined' && newval == "Full Result List") {
		m = launchJCAPopupAction('typePicker');

	} else {

		getMainForm().actionClass.value = "com.ptc.netmarkets.search.NmSearchCommands";
		getMainForm().actionMethod.value = "typeChange";
		getMainForm().searchType.value = newval;
		PTC.navigation.submitForm();
	}
}

