function validateText(event, rejectTheseChars) {
    var myCode = event.keyCode;

    if(myCode === 0 || myCode === undefined) {
        myCode = event.which;
    }

    var myChar = String.fromCharCode(myCode);
    var valid = rejectTheseChars.indexOf(myChar) == -1;

    event.returnValue = valid;

    return valid;
}


// validate selected folder for object creation; pops up an alert window if:
//     A. more than one checkbox is selected
//     B. one checkbox is selected, but that object is not a folder
// returns false for A. or B otherwsie it returns true
function validateCreateLocation(evt) {
   var oidString = "nothing selected";
   
   var sels = PTC.jca.table.Utils.getSelectedItmesByEvent(evt);
   if( sels ) {
      var alength = sels.length;
      if(alength == 1) {
           oidString = sels[0].value;
      } else if(alength >= 2) {
           JCAAlert("com.ptc.netmarkets.util.utilResource.TOO_MANY_SELECTED");
           // to do, investigate why Firefox getting event not found exception here and not other js using event object
           try {
              evt = (evt) ? evt : event;
              Event.stop( evt );
           } catch(e) {
           //ignore me
           }
           return false;
      }
   }

   if( oidString != "nothing selected" && ! PTC.util.isAFolder( oidString ) ) {
      JCAAlert("com.ptc.netmarkets.util.utilResource.NO_FOLDER_SELECTED");
      // to do, investigate why Firefox getting event not found exception here and not other js using event object
      try {
         evt = (evt) ? evt : event;
         Event.stop( evt );
      } catch(ex) { //JSLint warning, only allows one variable in a function for catch statements
         //ignore me
      }
      return false;
   }
   return true;
}



// validate selected objects for multi object checkout or add to workspace
// returns false if no WTPart and/or EPMDocuments and/or Baselines are selected
function validateSelection(evt, action) {
   evt = (evt) ? evt : event;
   var validObjSelected                  = false;
   var invalidObjSelected                = false;
   var partsSelected                     = false;
   var epmDocsSelected                   = false;
   var baselinesSelected                 = false;
   var target                            = (evt.target) ? evt.target : evt.srcElement;
   var divnode                           = getParentNodeByTag (target, "DIV");
   divnode                               = getParentNodeByTag (divnode.parentNode, "DIV");

   if ( !containsClass( divnode, "frame") && divnode.parentNode ) {
         divnode = getParentNodeByTag (divnode.parentNode, "DIV");
   }
   var tableid = tableUtils.findTableID(evt);
   if (!tableid) {
      tableid = tableUtils.findParentTableNodeId(divnode);
   }
   var sels = getJCASelectedTableItems(tableid);

   if( sels.length === 0) {
      JCAAlert("com.ptc.netmarkets.util.utilResource.NONE_CHECKED");
      Event.stop(evt);
      return false;
   }
   if( sels ) {
      var alength = sels.length;
      for (var i=0; i<alength; i++) {
         if (sels[i].checked && sels[i].name.indexOf("pjl_sel")>=0){
            var rowVal = getOidFromRowValue(sels[i].value);
             //Note that Article is french for part.
            var partNames = [].concat(PTC.attributeHelper.get ("partClasses")); //concat to turn jso to full non-null array
            var thisRowIsAPart = false;
            var j = partNames.length;
            while (j--) {
                if (rowVal.indexOf(partNames[j])>=0) {
                    thisRowIsAPart = true;
                }
            }
            if (thisRowIsAPart) {
                partsSelected = true;
            }
            else if ( rowVal.indexOf("wt.epm.EPMDocument" ) > -1 ) {
               epmDocsSelected = true;
            }
            else if ( rowVal.indexOf("wt.vc.baseline.ManagedBaseline") > -1) {
               baselinesSelected = true;
            }
            else {
               invalidObjSelected=true;
            }
         }
      }
   }
   validObjSelected = partsSelected || epmDocsSelected || baselinesSelected;
   var msgKey ="";
   if ( validObjSelected && invalidObjSelected ) {

      //mixed objects selected
      if (action == 'rename')
      {
        msgKey = "com.ptc.windchill.enterprise.folder.folderResource.MULTI_RENAME_INVALID";
      }else if (action == 'saveas')
      {
        msgKey = "com.ptc.windchill.enterprise.folder.folderResource.MULTI_SAVEAS_INVALID";
      }else if (action == 'checkout')
      {
        msgKey = "com.ptc.windchill.enterprise.folder.folderResource.MULTI_CHECKOUT_INVALID" ;
      }else //'addToWS'
      {
        msgKey = "com.ptc.windchill.enterprise.folder.folderResource.MULTI_ADDTOWORKSPACE_INVALID";
      }

      if (!JCAConfirm(msgKey)) {
         Event.stop(evt);
         return false;
      }
   }
   if ( !validObjSelected  ) {
      
      if (action == 'rename')
      {
        msgKey = "com.ptc.windchill.enterprise.folder.folderResource.MULTI_RENAME_ALL_INVALID";
      }else if (action == 'saveas')
      {
        msgKey = "com.ptc.windchill.enterprise.folder.folderResource.MULTI_SAVEAS_ALL_INVALID";
      }else if (action == 'checkout')
      {
        msgKey = "com.ptc.windchill.enterprise.folder.folderResource.MULTI_CHECKOUT_ALL_INVALID" ;
      }else //'addToWS'
      {
        msgKey = "com.ptc.windchill.enterprise.folder.folderResource.MULTI_ADDTOWORKSPACE_ALL_INVALID";
      }
      
      JCAAlert(msgKey);
      Event.stop(evt);
   }
   return validObjSelected;
}

