////////////// JsonForm converter
// Generate a temp form from Json.
// Below is Sample code to use. Submit will submit form to given target.
//
//  var myForm = new JsonForm(formName, action, jsonFields, target);
//  myForm.submit();
//
function JsonForm(formName, action, jsonFields, target){
    var myForm;
    var formFields = jsonFields;

    this.submit = function submit(){
        myForm = createForm();
        addFields();
        document.body.appendChild(myForm);
        myForm.submit();
        document.body.removeChild(myForm);
    };


    function createForm(){      
        var retForm = new Element('Form', { 'name'   : formName,
            'id'     : formName,
            'action' : action,
            'method' : 'post',
            'target' : target
        });

        return retForm;
    }

    function addFields(){
        var value;
        for(var key in formFields){
            if(formFields.hasOwnProperty(key)) {
             value = formFields[key];
             AddElement(key, value);        
          }
        }
    }
    
    function AddElement(xName, xValue){
        var theNewElem = new Element('input', { 'type' : 'hidden',
            'name': xName,
            'value' : xValue
        });
        myForm.appendChild(theNewElem);
    }
}

///////////// JsonForm END


/**
 * execute the validation for the action, setup already by action code
 * @param {Object} mform The DOM Form object
 * @param {Boolean} isPopup if the validation is validating a popupAction 
 */
PTC.validation.doOnClickValidation = function (mform, isPopup) {
   var retval = true;
   if (mform) {
      //Don't need to pass validation_key, it was curried on.
      if (mform.onClickValidationTemp !== undefined && !(mform.onClickValidationTemp(isPopup))) {
         // stop processing if the validation returns false because that means they clicked "no" on the confirm dialog
         retval = false;
      }
      if (mform.onClickValidationTemp !== undefined) {
         mform.onClickValidationTemp = undefined;
      }
   }
   return retval;
};

var __userSubmitFunction = [];

/**
 * Adds event listener to the form submission.  The event fires on the ok/apply button in a wizard
 * @param {Function} func
 */
function setUserSubmitFunction(func) {
   __userSubmitFunction[__userSubmitFunction.length] = func;
}

function removeUserSubmitFunction(func) {
   if(__userSubmitFunction) {
      var  __userSubmitFunction_length= __userSubmitFunction.length;
      for(var i = 0; i < __userSubmitFunction_length; i++ ) {
         if ( __userSubmitFunction[i] === func ) {
            __userSubmitFunction.splice(i,1);
         }
      }
   }
}

/**
 * Fires the onSubmit event
 */
function callUserSubmitFunction() {
   if(__userSubmitFunction) {
      var  __userSubmitFunction_length= __userSubmitFunction.length;
      for(var i = 0; i < __userSubmitFunction_length; i++ ) {
         if ( __userSubmitFunction[i]() === false ) {
            return false;
         }
      }
   }
   return true;
}


function createDocName() {
   var docName = getMainForm().file.value;

   if(getMainForm().name.value === "") {
      var sepChar = '\\';
      if(docName.lastIndexOf('/') >= 0) {
         sepChar = '/';
      }
      if(docName.lastIndexOf('.') > 0) {
         docName = docName.substring(docName.lastIndexOf(sepChar) + 1, docName.lastIndexOf('.'));
      }
      else {
         docName = docName.substring(docName.lastIndexOf(sepChar) + 1, docName.length);
      }

      getMainForm().name.value = docName;
   }
}
