/**
 * Creates a special tooltip while scrolling in a bufferview to contain the display text of the sorted column
 * @param {Object} config  (Requires GridPanel in key "gridPanel")
 */
PTC.jca.verticalScrollTip = function(config){
    this.gridPanel = config.gridPanel;
    this.verticalScrollTip = new Ext.ToolTip({
        target: this.gridPanel.getView(),
        width: 150,
        dismissDelay:700, //Delay in milliseconds before the tooltip automatically hides
        scrollTip: ""
    });

    // Give the table a reference to the tip.
    this.gridPanel.vtip = this;

    this.verticalScrollTip.on('beforeshow', PTC.jca.verticalScrollTip.onBeforeShow);
    this.verticalScrollTip.on('render', PTC.jca.verticalScrollTip.onRender);
};

/**
 * This method will remove the anchor class so that there will not be anchor pointing to tooltip.
 */
PTC.jca.verticalScrollTip.onRender = function removeAnchorCls(){
    var anchorEI = this.anchorEl;
    if(anchorEI) {
        anchorEI.removeClass(['x-tip-anchor', this.anchorCls]);
    }
};
/**
 *
 * @param {Object} tip
 */
PTC.jca.verticalScrollTip.onBeforeShow = function updateTipBody(tip){
    if (tip.body === undefined || tip.body === null) {
        tip.html = tip.scrollTip;
    }
    else {
        tip.body.dom.innerHTML = tip.scrollTip;
    }
};
/**
 * Extracts the text of the cell that should be shown in the tip.
 * Could be enhanced to fetch the innerText instead of returning empty string for some Date cases in Workspace.
 * 
 * @param {Ext.grid.GridPanel} table
 * @param {String} columnId
 * @param {Ext.data.Record} row
 * @param {Object} cell
 */
PTC.jca.verticalScrollTip.getTipTextFromCell = function(table, columnId, row, cell) {
    // Constant for maximum number of characters for tooltip
    var MAX_TOOLTIP_SIZE = 150;

    var cellValue = cell && Ext.isString(cell) ? cell : null;

    if (!cellValue || !Ext.isString(cellValue)) {
        var visibleCellGui = cell.tooltip ? cell : cell.gui;
        cellValue = visibleCellGui ? visibleCellGui.tooltip : null;
    }

    if (!cellValue || !Ext.isString(cellValue)) {
        var column = table.getColumnModel().getColumnById(columnId);

        // Make an attempt to find the text, that would be used by Find_in filter or export.
        cellValue = jsca.columns.getJSCASearchText(table, column, row);
    }

    if (!cellValue || !Ext.isString(cellValue)) { // non-strings blow up here
        return "";
    }

    if (cellValue.indexOf("<") > -1) { //TO avoid double encoding
        cellValue = PTC.util.HTMLEncoder.encodeForHTMLContent(cellValue);
    }

    if (cellValue && cellValue.length > MAX_TOOLTIP_SIZE) {
        cellValue = cellValue.substring(0, MAX_TOOLTIP_SIZE);
    }

    return cellValue;
};  

/**
 * Create an ToolTip Object for showing the Vertical Scroll Tip on Table To set the content of tolltip dynamically
 * 
 * @param {Number} scrollLeft
 * @param {Number} scrollTop
 */
PTC.jca.verticalScrollTip.prototype.updateVerticalScrollTip = function(scrollLeft, scrollTop){

    // To avoid any action when disabled or horizontal scroll bar moved
    if (this.gridPanel.vtip.verticalScrollTip.disabled || scrollTop < 1) {
        return;
    }
    var gridView = this.gridPanel.getView();
    var rowStore = this.gridPanel.getStore();
    var visibleRowsCount = gridView.getVisibleRowCount();
    var totalRows = rowStore.getCount();
    var scroller = gridView.scroller;
    if (gridView.isLocked) {
        scroller = gridView.lockedScroller;
    }
    /*
     * value to adjust the Tooltip to scroll Top Position scroll top height is calculated upon how much it moved up from
     * scroller area. Vertical scroller appears on the grid panel's inner height.
     */
    var adjScrollTop = scroller.getHeight() / this.gridPanel.getInnerHeight();
    scrollTop = scrollTop * adjScrollTop;
    // Vertical scroller will move in proportion of total number of rows per visible row count.
    var adjScrollTopFactor = totalRows / (visibleRowsCount - 1);
    var scrollTopToIncrease = 0;
    if (adjScrollTopFactor > 0) {
        scrollTopToIncrease = (scrollTop / (adjScrollTopFactor));
    }
    // Get the Index of First row which is visible
    var firstVisibleRowIdx = PTC.jca.table.scroll.getFirstVisibleRowIdx(gridView, scrollTop);
    // Get the Column Id
    var columnDisplay = PTC.jca.table.scroll.getVerticalScrollTipColumnId(this.gridPanel,
            this.gridPanel.initialConfig.jcaTableConfig.tableID);
    // if the column id is null then do not show the tool tip
    if (columnDisplay === null) {
        return;
    }
    // Get the cell value
    var visibleRow = this.gridPanel.getStore().getAt(firstVisibleRowIdx);
    if (!visibleRow) {
        return;
    }
    var visibleCell = visibleRow.get(columnDisplay);
    if (!visibleCell) {
        return;
    }
    var cellValue = PTC.jca.verticalScrollTip
            .getTipTextFromCell(this.gridPanel, columnDisplay, visibleRow, visibleCell);
    // If cell value is blank then do not show the tool tip
    if (!cellValue) { 
        return;
    }

    this.verticalScrollTip.scrollTip =  cellValue;

    var toolTipx = (scroller.getX() + this.gridPanel.getOuterSize().width) - 170;
    var toolTipy = scroller.getY() + scrollTopToIncrease;
    this.verticalScrollTip.showAt([toolTipx, toolTipy]);
};

PTC.jca.verticalScrollTip.prototype.destroy = function(){
    this.gridPanel = undefined;
    Ext.destroy(this.verticalScrollTip);
    delete this.verticalScrollTip;
};


