function visNavAjaxCall(url) {
    var xmlhttp = newHttp();
    xmlhttp.open("POST", url, false);
    setHeaders(xmlhttp);
    xmlhttp.send(null);
    return xmlhttp.responseText;
}

function loadInPVPanel(parentDiv, url) {
    var response = visNavAjaxCall(url);
    var parent = document.getElementById(parentDiv);
    if (parent != null) {
        var vizPanel = "vizPanel";
        vizObj[vizPanel] = parent.id;

        parent.innerHTML = response;
        //if (response.length > 0) {
        ////eval(response);
        //response.evalScripts();
        //}
        var scripts, scriptsFinder = '<script[^>]*>([\\S\\s]*?)<\/script>';
        var myregexp = new RegExp(scriptsFinder, "gi");
        while (scripts = myregexp.exec(response)) {
            var jsBlock = scripts[1];
            eval(jsBlock);
        }
    }
}

function loadInPVPanelInIframe(frameId, url) {
    var response = visNavAjaxCall(url);
    var frame = document.getElementById(frameId);
    frame.src="netmarkets/jsp/cat/viz.jsp?"+url;
}


PTC.wip = {};
PTC.wip.actions = ['checkout', 'checkin', 'editcheckin', 'undocheckout'];
/**
*  add/remove rows from the checkouts table for the wip actions
*/
PTC.wip.checkoutsTableObjectsAffectedWrapper = function(original, formResult) {

   if(formResult && (!formResult.afterActionHandled || formResult.afterActionHandled[this.id] !== true)) {
       if (formResult.actionName === 'undocheckout' || formResult.actionName === 'list_undocheckout' 
           || formResult.actionName === 'checkin' || formResult.actionName === 'editCheckin') {
           var oids = formResult.getUpdatedOids();
           oids = oids.concat(formResult.getLocations());
           oids = oids.uniq();

           var recs = PTC.jca.table.Utils._getRecordsFromOids(this, oids, formResult);

           if (recs.length>0 && this.getStore()) {
              this.getStore().remove(recs);
           }
           return true;
       }

       else if (formResult.actionName === 'checkout') {
           var added_new_rows = formResult.getUpdatedOids();

           if(added_new_rows.length > 0) {
              clearActionFormData();

              rowHandler.addRows(added_new_rows, this.id, null, {
                   doAjaxUpdate : true,
                   addSorted : true
              });
           }
           return true;
       }
   }
   return original.call(this, formResult);
};

/**
 *  Handles actions that occur inside the table
 */
PTC.wip.checkoutsTableAfterActionWrapper = function(original, formResult) {
    PTC.wip.checkoutsTableObjectsAffectedWrapper.call(this, original, formResult);
    var handled = PTC.wip.actions.indexOf(formResult.actionName) >= 0;
    formResult.afterActionHandled = formResult.afterActionHandled || {};
    formResult.afterActionHandled[this.id] = handled;
    return !handled;
};


PTC.wip.addCheckoutTableListeners = function (table) {
   table.onObjectsAffected = table.onObjectsAffected.wrap(PTC.wip.checkoutsTableObjectsAffectedWrapper);
   table.onAfterAction = table.onAfterAction.wrap(PTC.wip.checkoutsTableAfterActionWrapper);
};

/**
 * Verify at least one object is selected and if at least one is, confirm that the user wants to check out.
 */
PTC.wip.validateMultiCheckout = function( event ) {
    return PTC.wip.validateMultiWIPAction(event, 'com.ptc.windchill.enterprise.wip.WIPResource.CHECK_OUT_CONFIRM');
};

/**
 * Verify at least one object is selected and if at least one is, confirm that the user wants to undo check out.
 */
PTC.wip.validateMultiUndoCheckout = function( event ) {
    return PTC.wip.validateMultiWIPAction(event, 'com.ptc.windchill.enterprise.wip.WIPResource.UNDO_CHECK_OUT_CONFIRM');
};

PTC.wip.validateMultiWIPAction = function( event , confirmationKey ) {
    var nItemsSelected = event.jcacontainer.getSelectionModel().selections.getCount();
    if(nItemsSelected == 0) {
        JCAAlert('com.ptc.netmarkets.util.utilResource.NONE_CHECKED');
        return false;
    } else {
        return JCAConfirm(event, confirmationKey);
    }
};

PTC.onAvailable('checkedout.work.table', PTC.wip.addCheckoutTableListeners);



function setFormEncTypeIfFile(mform){
    var sels = mform.getElementsByTagName('input');

    if( sels ) {
        // Set the form to have encoding of multi-part if there is a file field
        var alength = sels.length;
        for (var i=0; i<alength; i++) {
            if (sels[i].type=="file") {    
                var docName = sels[i].value;
                if (docName && docName.length > 2 && !sels[i].disabled) {
                    mform.enctype="multipart/form-data";
                    mform.encoding="multipart/form-data";
                }
            }
        }
    }
}

function gotoStep(step) {
   if(callUserSubmitFunction()) {
      // TODO this assumes that there are other parameters which is the case for dialogs.
      clearActionFormData();
      clearDialogFormData();      
      var mform = getMainForm();
      mform.new_wizard_step.value = step; 
      setFormEncTypeIfFile(mform);
      mform.submit(); // never see old wizards in new shell
   }
}
 
/**
 * Enable/disable all wizard buttons at the bottom
 * @param {Object} button
 * @param {Object} disabledvalue
 */
function JCADChangeAButton(button, disabledvalue) {
    if( typeof button === "string") {
        button = Ext.getCmp(button);
    }
    if(button) {
        if(disabledvalue) {
            button.disable();
        } else {
            button.enable();
        }
    }
}

function disableButtons(newValue) {
    if(newValue === null || newValue === undefined) {
        newValue = true;
    }
    var buttons = ['PJL_wizard_ok', 'PJL_wizard_apply', 'PJL_wizard_cancel', 'PJL_wizard_previous', 'PJL_wizard_next', 'PJL_wizard_revert'];

    buttons.each(function(item) {
        JCADChangeAButton(item, newValue);
    });
}

function okClicked() {
    if(getMainForm().okButton.disabled) {
        return false;
    } else {
        disableButtons();
        return true;
    }
}

function enableButtons() {
    disableButtons(false);
}

function clearIt() {
    this.getMainForm().APPLY.value = "yes";
}

