function launchFolderPickerCallbackFunction(contextValues){
    var dispLocation = contextValues.displayLocation;
    var context = contextValues.contextName;
    var contextId = contextValues.contextId;
    var folderOID = contextValues.folderOID;

    PTC.wizard.log.debug('launchFolderPickerCallbackFunction - folder picker picked context values: ', Ext.encode(contextValues));

    locationSelectHiddenElem.value = folderOID.substr(3);
    folderLocation.value = dispLocation;
    PTC.wizard.saveTableData.saveToStore(folderLocation);
    //Allows for the tooltip to show the new path.
    folderLocation.setAttribute('ext:qtip', dispLocation);
}

/**
 * Set LocationSelect query param value to value of locationSelectElem dom element, if specified. 
 * If not specified, default to value of dom element with name selectedFolderFromFolderContext
 *
 * @param {String} url 
 */
function createLocationPickerURL(url){
    var newUrl = "";
    if (document.getElementById("containerRef") && (url.indexOf("containerVisibilityMask") < 0)) {
        newUrl += "&containerVisibilityMask=" + document.getElementById("containerRef").value;
    }
    var locationSelectVal = document.getElementsByName(locationSelectHiddenElem.name)[0];
    if (locationSelectVal) {
        newUrl += "&LocationSelect=" + locationSelectVal.value;
    }
    return newUrl;
}

function launchFolderPicker( url, myLoc, locationSelectHiddenFieldName) {
    var fields = document.getElementsByName(locationSelectHiddenFieldName);
    folderLocation = myLoc;
    if (fields) {
        locationSelectHiddenElem = fields[0];
    }
    var urlStr = createLocationPickerURL(url);
    PTC.wizard.log.debug('launchFolderPicker - folder picker URL: ', urlStr);
    launchABrowseMenu( url, myLoc, launchFolderPickerCallbackFunction, urlStr );
}

var IFRAME_BEGIN_ID = "popCreateWizard_";

/**
 *
 * @namespace
 * @internal
 */
PTC.wizardIframes = (function(){
    var iframeId = '';
    var useOrigIframeId = false;
    var restoreIframeOnClose = false;

    var getAcionURLParams = function(options){
        var url = options.form.action;
        return Ext.urlDecode(URL_utils.getParams(url));
    };

    var iframeExist = function(){
        var iframe = getIframe();
        if (iframe && iframe !== null) {
            return true;
        }
        return false;
    };

    /**
     * Initializes the lightbox deactivate options.  If an iframe already exists for the
     * current generated iframe id then the lightbox window should be hidden and not destroyed.
     */
    var setDeactivateOptions = function(){
        var iframeExists = iframeExist();
        restoreIframeOnClose = iframeExists;
        PTC.lightbox.setDeactivateOptions({
            afterJs: PTC.wizardIframes.closeHandler,
            reloadParent: false,
            saveContent: iframeExists,
            cleanUpTables: false
        });
    };

    var beforeWizardLoad = function(){
        setDeactivateOptions();
        if (restoreIframeOnClose) {
            var win = PTC.wizardIframes.getIframeWindow();
            PTC.wizardIframes.historyManager.saveWizardState(win);
        }
    };

    /**
     * Gets the iframe from the parent window if the current window is a lightbox.
     */
    var getIframe = function(){
        var isLightBox = PTC.lightbox.isLightbox(self);
        var win = self;
        if (isLightBox) {
            win = PTC.lightbox.getParentWindow();
        }
        var iframe = win.document.getElementById(iframeId);
        return iframe;
    };
    /**
     * Generates an iframe id from the action url in the activate options of a lightbox.
     */
    var getIframeId = function(origFunction){
        if (useOrigIframeId) {
            return origFunction();
        }
        if (iframeId !== '') {
            return iframeId;
        }
        var activateOptions = PTC.lightbox.activateOptions;
        if (activateOptions && activateOptions.form) {
            var params = getAcionURLParams(activateOptions);
            if (params && params.isIframeWizard === 'true') {
                if (params.resizeIframeWizard === 'false') {
                    resizeIframeWizard = false;
                }
                if (params.mode === 'CREATE') {
                    iframeId = IFRAME_BEGIN_ID + "CREATE" + (new Date()).getTime();
                }
                else
                    if (params.oid) {
                        var oid = (params.oid.length === 2) ? params.oid[0] : params.oid;
                        oid = encodeURIComponent(oid);
                        iframeId = addIframeIdPrefix(oid);
                    }
                if (iframeId !== '') {
                    beforeWizardLoad();
                    return iframeId;
                }
            }
        }

        return origFunction();
    };
    
    var addIframeIdPrefix = function(iframeId){
        return (iframeId.indexOf(IFRAME_BEGIN_ID) === 0) ? iframeId : IFRAME_BEGIN_ID + iframeId;
    };

    var wrapSetOptions = function(original, options){
        var iframeOptions = {};
        if (options) {
            Object.extend(iframeOptions, options);
        }
        iframeOptions.closable = true;
        var params = getAcionURLParams(iframeOptions);
        if (params && params.resizeIframeWizard === 'false') {
            /* Set the lightbox to always be 98% of the window size */
            var parentHeight = getWindowHeight();
            iframeOptions.height = parentHeight * 0.98;
            var parentWidth = getWindowWidth();
            iframeOptions.width = parentWidth * 0.98;
            iframeOptions.resizable = false;
            iframeOptions.positionInCenter = true;
            PTC.lightbox.resizeOptions.resizingParentWindow = true;
            PTC.lightbox.resizeOptions.resizeHeightWithWindow = true;
            PTC.lightbox.resizeOptions.resizeWidthWithWindow = true;
        }
        original(iframeOptions);
    };

    return {

        /**
         * Set to indicate that the from is being submitted and not closed or cancelled.
         */
        isSubmit: false,

        removeIframes: function(original){
            PTC.lightbox.lbContentWindow.clear();
            PTC.navigation.removeIframes(document, false, false);
            Ext.garbageCollect();
            if (original) {
                original();
            }
        },

        /**
         * Initialize the store of popup wizards as iframes.
         */
        initStoreIframes: function(){
            /* Prevent memory leak in wizard with iframes  */
            clearInterval(Ext.Element.collectorThreadId);
            PTC.lightbox.getLightboxWindowId = PTC.lightbox.getLightboxWindowId.wrap(getIframeId);
            PTC.lightbox.setOptions = PTC.lightbox.setOptions.wrap(wrapSetOptions);
            PTC.lightbox.handleSubmitResult = PTC.lightbox.handleSubmitResult.wrap(PTC.wizardIframes.handleSubmitResult);
            wfWindowClose = wfWindowClose.wrap(PTC.wizardIframes.removeIframes);
            deleteDownstreamFormContent = deleteDownstreamFormContent.wrap(PTC.wizardIframes.submitHandler.deleteDownstreamFormContent);
        },

        /**
         * Returns the current generated iframe id.
         */
        getWizardIframeId: function(){
            return iframeId;
        },

        /**
         * Handles the form processing result if the current window is a iframe wizard.
         */
        handleSubmitResult: function(originalHandle, status, nextAction, js, URL, dynamicRefreshInfo){
            if (PTC.lightbox && !PTC.lightbox.isLightbox(getWindow()) && iframeId === '') {
                useOrigIframeId = true;
            }
            originalHandle(status, nextAction, js, URL, dynamicRefreshInfo);
            useOrigIframeId = false;
        },

        /**
         * Does some post processing when deactivating the wizards. If an iframe already existed from a
         * previous session and the close or cancel is selected then the wizard state needs to be restored.
         */
        closeHandler: function(){
            if (restoreIframeOnClose && !PTC.wizardIframes.isSubmit) {
                var win = PTC.wizardIframes.getIframeWindow();
                PTC.wizardIframes.historyManager.restoreWizardState(win);
            }
            iframeId = '';
            useOrigIframeId = false;
            restoreIframeOnClose = false;
            PTC.wizardIframes.isSubmit = false;
        },

        /**
         * Returns the current window for the current iframeId if it exists otherwise returns null.
         */
        getIframeWindow: function(){
            var iframe = getIframe();
            var iframeWindow = null;
            if (iframe && iframe !== null) {
                iframeWindow = iframe.contentWindow;
            }
            return iframeWindow;
        },

        /**
         * Sets the startStep as the active step.
         */
        setInitialStepActive: function(win){
            if (win.steps) {
                win.PTC.wizard.setActiveStep(win.steps[0]);
            }
        },
     
        removeIframe : function(oid){
            var currentIframeId = iframeId;
            iframeId = oid;
            // get Iframes and remove the iframe if it exists.
            //var iframes = getWindow().document.getElementsByTagName("iframe");
            // The iFrame ids are stored with www-url-encoded format, so we need
            // to convert any ":" to "%3A" encoded values.
            if (oid.indexOf(":") > 0) {
                iframeId = encodeURIComponent(oid);
                }
            iframeId = addIframeIdPrefix(iframeId);
            var iframe = Ext.getDom(iframeId);
            if(iframe && iframe.contentWindow) {
                PTC.lightbox.deactivate({
                    lbWindow: iframe.contentWindow,
                    saveContent : false
                });
            }
            iframeId = currentIframeId;
        },
        
        /**
         * Multiple object method to remove iframes no longer needed in a wizard.
         */
        removeMultiIframes: function(oids) {
            for (var i = 0, l = oids.length; i < l; i++) {
                PTC.navigation.fireEvent("removeIframe", parent.document);
                try {
                  var id = oids[i].id;
                  var iframeEl = getWindow().document.getElementById(id);
                  var iframeWin = iframeEl.contentWindow;
                  if (iframeWin && iframeWin.PTC) {
                      iframeWin.PTC.navigation.removeIframes.call(iframeWin, iframeWin.document, true, true);
                  }
                  if (iframeWin && iframeWin.document) {
                      PTC.util.purge(iframeWin.document);
                  }
                  iframeEl.src = '';
                }
                catch (e) {
                  // Some iframes may throw an access error trying to access the document or content window
                  PTC.log.error("removeDuplicateIframe() Error occurred while removing iframe:", e);
                }
                Ext.removeNode(iframeEl);
                iframeEl = null;
            }
        }
    };
})();

PTC.wizardIframes.submitHandler = (function(){
    var wizardProperties = {
        storeIframes: false
    };

    var serializeIframes = function(iframes){
        var iframeDiv = appendIframeDiv("wizardIframesDiv");
        var level = 0;
        var html = "";
        for (var i = 0, l = iframes.length; i < l; i++) {
            if (isIframeWizard(iframes[i])) {
                level++;
                var params = submitIframeForm(iframes[i], level, html);
                html = getChildIframes(params.iframeDoc, level, params.html);
            }
        }
        PTC.navigation.overwrite(iframeDiv, html);
    };

    var getChildIframes = function(iframeDoc, level, html){
        // find iframe within iframe
        if (iframeDoc) {
            var innerIframes = iframeDoc.getElementsByTagName('iframe');
            var newLevel = 0;
            for (var i = 0, l = innerIframes.length; i < l; i++) {
                if (isIframeWizard(innerIframes[i])) {
                    newLevel++;
                    var params = submitIframeForm(innerIframes[i], level + "." + newLevel, html);
                    html = params.html;
                }
            }
        }
        return html;
    };

    var isIframeWizard = function(element){
        var id = element.id;
        var iframeDoc = "";
        if (id) {
            var index = id.indexOf(IFRAME_BEGIN_ID);
            if (index === 0 && element.tagName === "IFRAME") {
                return true;
            }
        }
        return false;
    };

    var submitIframeForm = function(element, level, html){
        var id = element.id;
        var params = [];
        params.iframeDoc = "";
        params.html = "";
        if (id) {
            var index = id.indexOf(IFRAME_BEGIN_ID);

            if (index === 0 && element.tagName == "IFRAME") {
                params.iframeDoc = element.contentWindow.document;
                var inputId = level + "_" + id;
                // For some reason the "name" is getting lost in the mainform
                // This prevents it from being serialized.
                var v = params.iframeDoc.getElementById("iframeId");
                if (v) {
                    v.setAttribute("name", v.id);
                }
                var mform = params.iframeDoc.getElementById("mainform");
                params.html = html + getIframeHiddenInput(inputId, Ext.lib.Ajax.serializeForm(mform));
            }
        }
        return params;
    };

    var getIframeHiddenInput = function(id, value){
        var html = '<input type="hidden" name="' + id + '" id="' + id + '" value="' + value + '">';
        return html;
    };

    var appendIframeDiv = function(id){
        var div = document.getElementById(id);
        if (!div) {
            var newDiv = document.createElement("div");
            newDiv.id = id;
            newDiv.style.display = "none";
            var mform = getMainForm();
            mform.appendChild(newDiv);
            return newDiv;
        }
        return div;
    };

    var wrapWfWindowClose = function(){
        var closeOptions = {
            lbWindow: self
        };
        if (parent.PTC.wizardIframes.isSubmit) {
            closeOptions.saveContent = true;
        }
        PTC.lightbox.deactivate(closeOptions);
    };

    return {
        initWizard: function(options){
            var params = location.search.parseQuery();
            var storeIframes = (params.isIframeWizard) ? true : false;
            if (storeIframes) {
                /* Prevent iframe memory leak */
                clearInterval(Ext.Element.collectorThreadId);
                wizardProperties = {
                    storeIframes: storeIframes,
                    updateRow: true,
                    updateRowParentForm: false
                };
                if (options) {
                    Object.extend(wizardProperties, options);
                }
                wfWindowClose = wfWindowClose.wrap(wrapWfWindowClose);
                isWizardWindow = TRUE_FUNC;
                PTC.wizard.focusOnReadyFunc();
            }
        },

        /**
         * Determines if the form data for the popwizard should be stored inside an iframe to be persisted later.
         */
        storeFormAsIframe: function(){
            return wizardProperties.storeIframes;
        },

        submitIframe: function(){
            goProgress();
            clearActionFormData();
            resetIEButtons();

            var parentWin = PTC.lightbox.getParentWindow();
            var iframeId = parentWin.PTC.wizardIframes.getWizardIframeId();
            var mform = getMainForm();
            appendFormHiddenInput(mform, "iframeId", iframeId);

            stopProgress();
            enableButtons();
            resetNextBackButton(currentStepStrName);
            isApply = false;
            PTC.wizardIframes.setInitialStepActive(self);

            var iframeForm = Ext.lib.Ajax.serializeForm(mform);
            parentWin.PTC.wizardIframes.submitHandler.handleUpdate(iframeForm, wizardProperties.updateRow, wizardProperties.updateRowParentForm);

            wfWindowClose();
            return false;
        },

        handleUpdate: function(wizardForm, updateRow, updateRowParentForm){
            var iframeId = PTC.wizardIframes.getWizardIframeId();
            var list = [this.convertURLIframeOid(iframeId)];
            var tableId = iframeTableId;
            var params;
            if (updateRowParentForm) {
                var openerForm = Ext.lib.Ajax.serializeForm(getMainForm());
                params = {
                    doAjaxUpdate: true,
                    preventDuplicates: true,
                    iframeForm: openerForm
                };
            }
            else {
                params = {
                    doAjaxUpdate: true,
                    preventDuplicates: true,
                    iframeForm: wizardForm
                };
            }

            if (updateRow) {
                PTC.wizardIframes.submitHandler.updateIframeRow(list, tableId, params);
            }
            PTC.wizardIframes.isSubmit = true;
        },

        updateIframeRow: function(list, tableId, params){
            rowHandler.updateRows(list, tableId, params);
        },

        removeIframeRowElement: function(oid, tableID, deleteIframe){
            rowHandler.removeRows([oid], tableID, true);
            if (deleteIframe) {
                PTC.wizardIframes.removeIframe(oid);
            }
        },

        checkForIframes: function(){
            var iframes = getWindow().document.getElementsByTagName('iframe');
            if (iframes && iframes.length > 0) {
                serializeIframes(iframes);
            }
        },

        deleteDownstreamFormContent: function(orig) {
            var status = orig();
            var iframes = getWindow().document.getElementsByTagName('iframe');
            var iframeWizards = [];
            if (iframes && iframes.length > 0) {
                for (var i = 0, l = iframes.length; i < l; i++) {
                    var iframe = iframes[i];
                    if (isIframeWizard(iframe)) {
                        iframeWizards.push(iframe);
                    }
                }
                if(iframeWizards.length !== 0){
                    PTC.wizardIframes.removeMultiIframes(iframeWizards);                        
                }
            }
            return status;
        },

        convertURLIframeOid: function(iframe_id){
            var oid = iframe_id;
            if (oid.indexOf(IFRAME_BEGIN_ID) === 0 && oid.indexOf("CREATE") < 0) {
                oid = oid.substring(IFRAME_BEGIN_ID.length);
                if (oid.indexOf("%3A") > 0) {
                    oid = decodeURIComponent(oid);
                }
            }
            return oid;
        }
    };
})();

/**
 * History manager for wizard iframes. Records the wizard state prior to launching a
 * non persisted object wizard. On close or cancel of the wizard the previous recorded
 * state is restored.
 */
PTC.wizardIframes.historyManager = (function(){
    var TAGS = ["INPUT", "SELECT", "TEXTAREA"];
    var DRIVER_ATTRIBUTES_PANE = 'driverAttributesPane';
    var READ_ONLY_DRIVER_ATTRIBUTES_PANE = 'readOnlyDriverAttributesPane';
    var formFields = new Ext.util.MixedCollection();
    var savedTables = new Ext.util.MixedCollection();

    var getId = function(obj){
        var id = (obj.name && obj.name !== null && obj.name !== "") ? obj.name : obj.id;
        return id;
    };

    var copyFromElement = function(dest, element, propMap){
        dest = {
            readOnly: {},
            props: {}
        };

        propMap.props.each(function(prop){
            dest.props[prop] = element[prop];
        });
        propMap.readOnly.each(function(prop){
            dest.readOnly[prop] = element[prop];
        });

        return dest;
    };

    var copyToElement = function(element, source){
        for (var prop in source.props) {
            if (source.props.hasOwnProperty(prop)) {
                element[prop] = source.props[prop];
            }
        }
        return element;
    };

    /**
     * When relaunching a create wizard for subsquent edits the driver attributes cannot
     * be editable. This is because when the type of the object is changed the attribute fields
     * have a randomly generated number that is not consistent when the type is changed back. This
     * method will hide the driver attributes panel and will display a read only property panel
     * if a url is specified for the iframe window
     * PTC.wizardIframes.historyManager.readonlyDriverAttributeURL.
     */
    var disableDriverAttributes = function(win){
        var objectHandle = win.PTC.wizard.getCurrentObjectHandle();
        var div = win.document.getElementById(objectHandle + DRIVER_ATTRIBUTES_PANE);
        var readOnlyId = objectHandle + READ_ONLY_DRIVER_ATTRIBUTES_PANE;
        if (div && !win.document.getElementById(readOnlyId)) {
            div.style.display = 'none';
            var url = win.PTC.wizardIframes.historyManager.readonlyDriverAttributeURL;
            if (url) {
                var newDiv = win.document.createElement("div");
                newDiv.id = readOnlyId;
                div.parentNode.insertBefore(newDiv, div);
                if (objectHandle) {
                    url += '?currentObjectHandle=' + objectHandle;
                }
                win.refreshElement(readOnlyId, url);
            }
        }
    };

    /**
     * Saves the current state of the wizard form fields.
     */
    var saveFormFields = function(doc){
        var formFieldMap = new Ext.util.MixedCollection();
        TAGS.each(function(tag){
            var inputs = doc.getElementsByTagName(tag);
            var inputs_length = inputs.length;
            for (var i = 0; i < inputs_length; i++) {
                var input = inputs[i];
                var readOnlyProps = ["type", "id", "name"];
                var props = ["value"];
                if (tag === "INPUT" && input.type && (input.type === "checkbox" || input.type === "radio")) {
                    props.push("checked");
                }
                else
                    if (tag === "SELECT") { /*Combo Box*/
                        props.push("selectedIndex");
                    }
                var obj = copyFromElement({}, input, {
                    readOnly: readOnlyProps,
                    props: props
                });
                var id = getId(obj.readOnly);
                if (id && id !== null && id !== "") {
                    if (formFieldMap.containsKey(id)) {
                        var currentObject = formFieldMap.get(id);
                        if (!Ext.isArray(currentObject)) {
                            var objects = [];
                            objects.push(currentObject);
                            currentObject = objects;
                        }
                        currentObject.push(obj);
                        formFieldMap.replace(id, currentObject);
                    }
                    else {
                        formFieldMap.add(id, obj);
                    }
                }
            }
        });
        return formFieldMap;
    };

    /**
     * Restores the saved state of the wizard form fields.
     */
    var restoreFormFields = function(doc, formFieldMap, doCleanUp){
        TAGS.each(function(tag){
            var inputs = doc.getElementsByTagName(tag);
            var inputs_length = inputs.length;
            for (var i = 0; i < inputs_length; i++) {
                var input = inputs[i];
                var id = getId(input);
                if (id && formFieldMap.containsKey(id)) {
                    var obj = formFieldMap.get(id);
                    if (Ext.isArray(obj)) {
                        var temp = obj.shift();
                        formFieldMap.replace(id, obj);
                        if (obj.length === 0) {
                            formFieldMap.removeKey(id);
                        }
                        obj = temp;
                    }
                    else {
                        formFieldMap.removeKey(id);
                    }
                    input = copyToElement(input, obj);
                }
                else
                    if (doCleanUp && input.type && input.type === 'hidden') {
                        // Clean up hidden fields that didn't exists before.
                        input.value = '';
                    }
            }
        });
    };

    /**
     * Saves the current state of the table data stores and column models.
     */
    var saveTableState = function(win){
        var tables = win.PTC.jca.table.Utils.getExtTables();
        tables.each(function(table){
            table.getSelectionModel().clearSelections();
            // Create a list of current data items in the store
            var dataItems = [];
            var rowData = win.PTC.jca.table.Utils.getRowData(table);
            rowData.each(function(item){
                dataItems.push(item);
            });

            var isFullList = true;
            var isPagedList = true;
            var fullList = getFullList(table, table.jcaTableConfig.fullList);
            if (fullList) {
                isFullList = fullList.hidden;
            }
            var pagedList = getPagedList(table, table.jcaTableConfig.pagedList);
            if (pagedList) {
                isPagedList = pagedList.hidden;
            }

            var savedTable = {
                dataItems: dataItems,
                pageSize: 0,
                totalRecords: 0,
                start: 0,
                savedData: null,
                hiddenFullList: isFullList,
                hiddenPagedList: isPagedList
            };

            // save table data for paged objects
            var toolBar = table.getBottomToolbar();
            if (toolBar) {
                savedTable.pageSize = (toolBar.pageSize) ? toolBar.pageSize : -1;
                savedTable.totalRecords = (toolBar.store) ? toolBar.store.totalLength : 0;
                savedTable.start = (toolBar.cursor && toolBar.cursor !== 0) ? toolBar.cursor : 0;
            }

            var tableElement = win.document.getElementById(table.id);
            var savedData = [];
            if (tableElement.SAVE_DIV) {
                var saveObj = tableElement.SAVE_DIV;
                var savedNodes = saveObj.childNodes;
                savedNodes.each(function(node){
                    savedData.push(node);
                });
            }
            savedTable.savedData = savedData;
            savedTables.add(table.id, savedTable);
        });
    };

    /**
     * Restores the saved state of the table data stores and column models.
     */
    var restoreTableState = function(win){
        var tables = win.PTC.jca.table.Utils.getExtTables();
        tables.each(function(table){
            if (savedTables.containsKey(table.id) && table.id !== "attributesTable") {
                var params = {
                    win: win,
                    table: table,
                    savedTable: savedTables.get(table.id)
                };
                restorePagedData(win, table, params);
                restoreRows(params);
            }
        });
    };

    var restorePagedData = function(win, table, params){
        // restore table data for paged objects
        if (params.savedTable.savedData) {
            var tableElement = win.document.getElementById(table.id);
            if (tableElement.SAVE_DIV) {
                var saveObj = tableElement.SAVE_DIV;
                var savedNodes = saveObj.childNodes;
                savedNodes.each(function(node){
                    if (node) {
                        saveObj.removeChild(node);
                    }
                });
                var restoreData = params.savedTable.savedData;
                restoreData.each(function(node){
                    saveObj.appendChild(node);
                });
            }
        }
    };

    /**
     * check if item should be added or removed
     */
    var restoreRows = function(params){
        var table = params.table;
        var savedTable = params.savedTable;
        var win = params.win;
        var clonedTableData = null;
        table.getSelectionModel().clearSelections();
        if (savedTable.pageSize > 0) {
            var o = {
                records: savedTable.dataItems,
                success: true,
                totalRecords: savedTable.totalRecords
            };

            var toolBar = table.getBottomToolbar();
            var options = {
                params: {
                    limit: savedTable.pageSize,
                    start: savedTable.start,
                    aquire: 'row'
                },
                callback: function(){
                    var fullList = getFullList(table, table.jcaTableConfig.fullList);
                    if (fullList) {
                        if (savedTable.hiddenFullList) {
                            fullList.hide();
                        }
                        else {
                            fullList.show();
                        }
                    }
                    var pagedList = getPagedList(table, table.jcaTableConfig.pagedList);
                    if (pagedList) {
                        if (savedTable.hiddenPagedList) {
                            pagedList.hide();
                        }
                        else {
                            pagedList.show();
                        }
                    }
                }
            };
            toolBar.pageSize = savedTable.pageSize;
            table.store.loadRecords(o, options, true);
        }
        else {
            table.store.removeAll();
            //remove event is used to reset the header and footer
            table.store.fireEvent('remove', table.store, [], 0);
            table.store.add(savedTable.dataItems);
        }
    };

    var getFullList = function(table){
        return getList(table, table.jcaTableConfig.fullList);
    };
    var getPagedList = function(table){
        return getList(table, table.jcaTableConfig.pagedList);
    };

    /**
     Return full list or paged list from the table object
     */
    var getList = function(table, config){
        var toolBar = table.getBottomToolbar();
        var list;
        if (config) {
            var idx = config.id || config.tooltip;
            if (toolBar.items.containsKey(idx)) {
                list = toolBar.items.get(idx);
            }
        }
        return list;
    };

    var reset = function(){
        formFields.clear();
        savedTables.clear();
    };

    var clearTableRows = function(win){
        var tables = win.PTC.jca.table.Utils.getExtTables();
        tables.each(function(table){
            if (savedTables.containsKey(table.id) && table.id !== "attributesTable") {
                table.store.removeAll();
            }
        });
    };

    var cleanUpTable = function(win){
        var tables = win.PTC.jca.table.Utils.getExtTables();
        tables.each(function(table){
            table.getSelectionModel().clearSelections();
        });
    };

    return {
        /**
         * URL to render a read only property panel in place of the driver attributes.
         */
        readonlyDriverAttributeURL: null,
        /**
         * Given a window saves the form fields ("INPUT", "SELECT" and "TEXTAREA"), the table
         * store rows and hides the driver attributes in create wizards.
         */
        saveWizardState: function(win){
            goProgress();
            reset();
            disableDriverAttributes(win);
            formFields = saveFormFields(win.document);
            saveTableState(win);
            clonedTableData = win.PTC.util.tableDataManager.cloneTableData();
            stopProgress();
        },

        /**
         * Given a window restores the saved form fields ("INPUT", "SELECT" and "TEXTAREA") and
         * the table store rows.
         */
        restoreWizardState: function(win){
            goProgress();
            clearTableRows(win);//removing rows for performance
            PTC.wizardIframes.setInitialStepActive(win);
            restoreTableState(win);
            restoreFormFields(win.document, formFields, true);
            cleanUpTable(win);
            win.PTC.util.tableDataManager.replaceTableData(clonedTableData);
            reset();
            stopProgress();
        }
    };
})();


