Ext.apply(PTC.wizard, new Ext.util.Observable());
/**
 * Event is dispatched before the step is re-loaded, return false to deny the step to re-load.
 * captures calls to refreshStep, reloadPane, refreshCurrentStep, and most importantly captures component refresh actions that happen
 * in the step
 *
 * @name PTC.wizard#beforeReloadStep
 * @event
 * @param {String} id - Wizard step id
 */
/**
 * Event is dispatched after the wizard step is rendered.  This is useful if you need to interact with the DOM after the step has been
 * completely rendered.
 *
 * @example
 * // when "myWizardStepId" wizard step is rendered, do some DOM manipulation
 * PTC.wizard.on("wizardStepReady", function(wizStepId) {
 *   if (wizStepId === "myWizardStepId") {
 *      var myEl = document.getElementById("someElement");
 *      var height = myEl.style.height;
 *      alert("height of someElement is " + height);
 *   }
 * });
 *
 * @name PTC.wizard#wizardStepReady
 * @event
 * @param {String} id - Wizard step id
 */
/**
 * Event is dispatched after a step is re-loaded.
 *
 * @name PTC.wizard#afterReloadStep
 * @event
 * @param {String} id - Wizard step id
 */
/**
 * Event is dispatched after the type picker is changed and the itemTypeInstanceId has been updated.
 *
 * @name PTC.wizard#afterTypePickerChange
 * @event
 */
/**
 * Event is dispatched after dynamic refresh info is handled.
 *
 * Use this event for updating other tables
 * The dynamic refresh info passed to this event will be the original dynamic refresh info
 *
 * @name PTC.wizard#afterHandleDynamicRefreshInfo
 * @event
 * @param {Object} dynamicRefreshInfo - See the comment for getDynamicRefreshJSON in FormResult.java for the expected structure of this object
 */
/**
 * Event is dispatched before attribute table (or panel) load ajax request is made.
 *
 * This event can be used, for example, to set/update needed post params for attribute panel load ajax request
 *
 * @name PTC.wizard#beforeLoadAttributeTable
 * @event
 */
/**
 * Event is dispatched after the attribute table (or panel) load ajax request has succeeded and panel has been unmasked.
 *
 * This event can be used, for example, to hook up an onchange js listener to one of the newly rendered form fields in the panel.
 *
 * @name PTC.wizard#afterLoadAttributeTable
 * @event
 */

 PTC.wizard.addEvents("wizardLoadComplete", "wizardStepReady", "beforeReloadStep", "afterReloadStep", "afterTypePickerChange", "afterHandleDynamicRefreshInfo", "beforeLoadAttributeTable", "afterLoadAttributeTable");

function doNothing(){
    return true;
}


/** returns true if there are any editable fields inside the given element, false otherwise  **/
anyEditableFields = function(parent){
    var tagNames = ['select', 'input', 'textarea', 'button'];
    var lengthJ = tagNames.length;
    for (var j = 0; j < lengthJ; j++) {
        var elements = parent.getElementsByTagName(tagNames[j]);
        if (elements) {
            var length = elements.length;
            for (var i = 0; i < length; i++) {
                var element = elements[i];
                if (!containsClass(element, 'hidden') && element.type != 'hidden' && !element.disabled) {
                    return true;
                }
            }
        }
    }

    // check for toolbar actions. Sometimes you have a table with no entries,
    // but toolbar actions to add an entry. In this case we want to report
    // that there are editable fields.
    elements = parent.getElementsByTagName('a');
    if (elements) {
        length = elements.length;
        for (i = 0; i < length; i++) {
            element = elements[i];
            if (containsClass(element, 'toolbariconfont') && !containsClass(element, 'hidden')) {
                return true;
            }
        }
    }

    return false;
};

/**
 * This function will return Window height for popup wizards.
 */
function getWindowHeight(){
    var windowHeight = 0;
    var win = getWindow();
    try {
        if (typeof(win.innerHeight) == 'number') {
            windowHeight = win.innerHeight;
        }
        else if (win.document.documentElement && win.document.documentElement.clientHeight) {
            windowHeight = win.document.documentElement.clientHeight;
        }
        else if (win.document.body && win.document.body.clientHeight) {
            windowHeight = win.document.body.clientHeight;
        }
    }
    catch (e) {
        PTC.wizard.log.debug("JS Exception calling getWindowHeight", e);
    }
    PTC.wizard.log.debug('getWindowHeight: height: ', windowHeight);
    return windowHeight;
}

/**
 * Get the size of the wizard body step area, basically window height - embedded help, padding, and 2% for the wizard buttons
 * @return {Number} height
 */
PTC.wizard.getWizardStepBodyHeight = function(){
    var windowHeight = getWindowHeight() * 0.98;
    var embeddedHelpHeight = $('embeddedHelp') ? $('embeddedHelp').offsetHeight : 0;
    windowHeight = Math.floor(windowHeight); // remove the fraction
    // for small wizards, the 98% ratio is not quite right.  The size ends up being too high by 2 or 4 pixels
    // get rid of the extra scrollbar in these cases.
    if (windowHeight < 400) {
        windowHeight -= 4;
    }
    var wizardPaddingHeight = PTC.wizard.getContentAreaPaddingHeight();
    var calculatedHeight = (windowHeight - wizardPaddingHeight) - embeddedHelpHeight;
    return calculatedHeight;
};

/** This function will adjust the height of wizard content area,
 *   so that the navigation buttons are always visible.
 */
function adjustWizardContentAreaHeight(){
    if (window.steps) {
        var contentAreaDiv = document.getElementById(currentStepStrName);

        var calculatedHeight = PTC.wizard.getWizardStepBodyHeight();

        if (calculatedHeight > 0 && contentAreaDiv) {
            contentAreaDiv.style.height = parseInt(calculatedHeight, 10) + 'px';
        }
        PTC.jca.table.Utils.adjustTableHeight(contentAreaDiv);
        PTC.wizard.StepLinksPanelUtil.fireBodyResizeEvent();

    }
}

/**
 * updates the hidden content header with the current step title for section 508.
 * "Content area. <Step Title>"
 */
function updateWizardContentHeader(){
    var step = document.getElementById(currentStepStrName + "stepTitleDiv");
    var wizContentHeader = document.getElementById('wizardContentHeader');
    if (step && wizContentHeader) {
        var stepTitle = step.innerText ? step.innerText : step.textContent;
        wizContentHeader.innerHTML = stepTitle;
    }
}

function getStyleFromId(id){
    var object = document.getElementById(id);
    if (object && object.style) {
        return object.style;
    }
    else if (object) {
        return object;
    }
    //else wfalert("object of id: " + id + " does not exist on the page.");
}

/**
 * constructor for a wizard step object to set its attributes.
 */
function wizardStep(json){
    this.isAsync = false;


    if (json.preloadJS) {
        json.preloadJS = PTC.util.convertStringToFunc(json.preloadJS);
    }
    else {
        json.preloadJS = doNothing;
    }

    if (json.postloadJS) {
        json.postloadJS = PTC.util.convertStringToFunc(json.postloadJS);
    }
    else {
        json.postloadJS = doNothing;
    }


    if (json.afterJS) {
        json.afterJS = PTC.util.convertStringToFunc(json.afterJS);
    }
    else {
        json.afterJS = doNothing;
    }

    Ext.applyIf(this, json);
    if (this.required === true) {
        this.isComplete = false;
        incompleteSteps++;
    }
    else {
        this.isComplete = true;
    }
    this.visited = false;
    this.isDirty = !json.preloadPage;

    this.label = json.label;
    this.embeddedHelp = json.embeddedHelp;
}

/**
 *  This function updates the embedded help.
 *  When the steps are traversed, the embedded help for the current step will be displayed.
 *  @deprecated
 */
function updateEmbeddedText(){
    var steps_length = steps.length;
    for (var i = 0; i < steps_length; i++) {
        if (currentStepStrName == steps[i]) { // Current step
            var embeddedHelpDiv = document.getElementById("embeddedHelp");
            if (wizardSteps[steps[i]].embeddedHelp == "null") {
                embeddedHelpDiv.style.visibility = "hidden";
                getStyleFromId("embeddedHelp").display = "none";
            }
            else {
                embeddedHelpDiv.style.visibility = "visible";
                getStyleFromId("embeddedHelp").display = "block";
                embeddedHelpDiv.innerHTML = wizardSteps[steps[i]].embeddedHelp;
            }
        }
    }
}



/**
 * This function will return Window width for popup wizards.
 */
function getWindowWidth(){
    var windowWidth = 0;
    var win = getWindow();
    if (typeof(win.innerWidth) == 'number') {
        windowWidth = win.innerWidth;
    }
    else {
        if (win.document.documentElement && win.document.documentElement.clientWidth) {
            windowWidth = win.document.documentElement.clientWidth;
        }
        else if (win.document.body && win.document.body.clientWidth) {
            windowWidth = win.document.body.clientWidth;
        }
    }

    return windowWidth;
}


/**
 * Calculates the height of the areas surrounding the wizard content area, including
 * the title bar area, step area, frame, and footer area.
 *
 * @return the height calculated; will return 0 if it can't calcuate the height
 */
PTC.wizard.getContentAreaPaddingHeight = function(){
    var totalHeight = 0;

    // This function sometimes gets invoked through the window resize event, which
    // IE throws several times for some reason.  Make sure the element exists before accessing
    // its properties, otherwise just use 0.
    var title = Ext.getDom('titleBar');
    var titleHeight = title ? title.offsetHeight : 0;

    var stepHeader = Ext.getDom('stephdr');
    var stepHeight = stepHeader ? stepHeader.offsetHeight : 0;

    var frame = Ext.query('#contentArea .x-box-tl')[0];
    // offset by 2px because IE adds 2px when the horizontal scrollbar is added
    var frameHeight = frame ? frame.offsetHeight + 2 : 0;

    var footer = Ext.getDom('footerPanel');
    var footerHeight = footer ? footer.offsetHeight : 0;

    // total padding height around the content area is the title area plus the step area,
    // plus the the area below the content area (should be about twice the size as the content plus title)
    totalHeight = (stepHeight + titleHeight + footerHeight) + (frameHeight * 2);

    return totalHeight;
};

var findButtonByActionID = function(btnActionID){
    var footerPanel = Ext.getCmp('footerPanel');
    if (footerPanel) {
        return footerPanel.fbar.findById(btnActionID);
    }
};

/**
 *  Disables/enables the back button based on whether the given step
 *  is the first step or a later step
 */
function setBackButton(stepId){
    if (stepId == steps[0]) {
        //disable first back
        var prevBtn = findButtonByActionID("PJL_wizard_previous");
        prevBtn.disable();
    }
    else {
        prevBtn = findButtonByActionID("PJL_wizard_previous");
        prevBtn.enable();
    }
}

/**
 * find the index of a step id
 */
function findStepIndex(id){
    var i = 0;
    if ("steps" in window) {
        var steps_length = steps.length;
        for (i = 0; i < steps_length; i++) {
            if (steps[i] == id) {
                return i;
            }
        }
    }
    //window.wfalert("Error: Couldn't find step id");
    return -1;
}

function recalcIncomplete(){
    incompleteSteps = 0;
    var steps_length = steps.length;
    for (var i = 0; i < steps_length; i++) {
        if (!wizardSteps[steps[i]].hidden) {
            //alert(steps[i] + " " + wizardSteps[steps[i]].required + " " + !wizardSteps[steps[i]].isComplete + " " + wizardSteps[steps[i]].isDirty);
            if ((wizardSteps[steps[i]].required && !wizardSteps[steps[i]].isComplete) || (wizardSteps[steps[i]].isDirty && wizardSteps[steps[i]].required)) {
                incompleteSteps++;
            }
            else if (wizardSteps[steps[i]].isAsync && !wizardSteps[steps[i]].isComplete) {
                incompleteSteps++;
            }
        }
    }
    return incompleteSteps;
}

/**
 * Force the finish and apply buttons to be disabled
 */
function disableOkButton(){
    var okButton = findButtonByActionID("PJL_wizard_ok");
    var applyButton = findButtonByActionID("PJL_wizard_apply");
    if (okButton) {
        okButton.disable();
    }
    if (applyButton) {
        applyButton.disable();
    }
}

/**
 * Force the finish and apply buttons to be enabled
 */
function enableOkButton(){
    var okButton = findButtonByActionID("PJL_wizard_ok");
    var applyButton = findButtonByActionID("PJL_wizard_apply");
    if (okButton) {
        okButton.enable();
    }
    if (applyButton) {
        applyButton.enable();
    }
}

/**
 * Sets the ok button to be displayed or not based on the current state.
 */
function resetOkButton(){
    var incompleteSteps = recalcIncomplete();
    if (incompleteSteps > 0) {
        //disable finish button if the step is a non preloaded step  account for preloaded as well
        disableOkButton();
    }
    else {
        enableOkButton();
    }
}

/**
 * Sets the next/back button to be displayed or not based on the current state.
 */
function resetNextBackButton(stepId){
    var stepState = PTC.wizard.getNextPrevious(stepId);

    var nextButton = findButtonByActionID("PJL_wizard_next");
    var prevButton = findButtonByActionID("PJL_wizard_previous");
    if (nextButton) {
        if (!stepState.hasNext) {
            nextButton.disable();
        }
        else {
            nextButton.enable();
        }
    }
    //disable first back
    if (prevButton) {
        if (!stepState.hasPrevious) {
            prevButton.disable();
        }
        else {
            prevButton.enable();
        }
    }
}

PTC.wizard.getNextPrevious = function(stepId) {
    // How to tell if optional step exists further on?
    var stepState = {
       hasPrevious: false,
       hasNext: false
    };
    var foundCurrent = false;

    var steps_length = steps.length;
    for (var i = 0; i < steps_length; i++) {
        // FOR SOME REASON, wizardSteps.length is 0 when it has value, that's why steps is used??
        if (!wizardSteps[steps[i]].hidden) {
            if (stepId == steps[i]) {
                foundCurrent = true;
            }
            else if (!foundCurrent) {
                stepState.hasPrevious = true;
            }
            else if (foundCurrent) {
                stepState.hasNext = true;
            }
        }
    }
    return stepState;
};

//Dynamic object creation - minding the namespace issues...
var ajax = {};

/**
 * Generic method for getting formData, but will not work for table specific ajax requests.
 * @see PTC.jca.table.Utils.getTableFormData
 */
function getFormData(dom){
    var curUrl = window.location.href;
    var wizStepParams = "";
    if (currentStepStrName) {
        //ensure the parameters on the URL of the current wizard step are also included in the form data
        wizStepParams = URL_utils.getParams(wizardSteps[currentStepStrName].url);
    }
    var returnData = "";
    var mform = getMainForm(dom);
    if (mform) {
        returnData = Ext.lib.Ajax.serializeForm(mform);
        //The form.action is similar to the url, but has specific info that may have changed such as the folder oid
	    returnData += URL_utils.getParams(PTC.util.getFormAction(mform));
    }
    else {
        returnData += URL_utils.getParams(curUrl);
    }

    returnData += wizStepParams;
    return returnData;
}

function requestParamExists(param, url){
    if (param && (url.indexOf("?" + param + "=") >= 0 || url.indexOf("&" + param + "=") >= 0)) {
        return true;
    }
    else {
        return false;
    }
}

/**
 * recursively removes the given param from the given URL string
 * (assumes the URL is like "...?param1=value1&param2=value2...")
 */
function removeParamFromString(origParam, url){
    var param = origParam;
    var newURL = url;
    var withoutQMark = false;
    if (newURL && newURL.indexOf("?") < 0) {
        withoutQMark = true;
    }
    while (requestParamExists(origParam, url)) {
        if (url.indexOf("?" + origParam + "=") >= 0) {
            param = "?" + origParam + "=";
        }
        else {
            param = "&" + origParam + "=";
        }
        newURL = url.substring(0, url.indexOf(param));
        var afterParam = url.substring(url.indexOf(param) + 1);//plus one to get past the & or ?
        if (afterParam) {
            var endIndex = afterParam.indexOf("&");
            if (endIndex > 0) {
                if (newURL === '') {
                    newURL = '?' + afterParam.substring(endIndex + 1);
                }
                else if (newURL.indexOf("?") < 0) {
                    if (withoutQMark) {
                        newURL = "?" + newURL + '&' + afterParam.substring(endIndex + 1);
                    }
                    else {
                        newURL = newURL + "?" + afterParam.substring(endIndex + 1);
                    }
                }
                else {
                    newURL += afterParam.substring(endIndex);
                }
            }
        }
        url = newURL;
    }
    return newURL;
}

/**
 * Returns a url that can be used to get the correct response for
 *         dynamically updating wizard steps, tables, or panels
 *
 * removes anchors from the urls.
 * adds all params from the current url to the url that gets returned
 * adds other necessary params to the url (like dynamicStepLoad=true etc.)
 *
 * Given this input->getPageUrl("http://www.stepurl.com", "aStepId", "http://www.webster.com?foo=bar#someAnchor");
 * This url is returned->'netmarkets/jsp/components/loadWizardStep.jsp?stepurl=http://www.stepurl.com&bodyurl=true&foo=bar&stepId=aStepId&dynamicStepLoad=true'
 *
 * @param url is the url of the page to update (e.g. a wizard step jsp or third level nav jsp)
 * @param stepId is the id of the wizard step, table, or panel to be updated
 * @param curUrl is just used for jsunit tests to send in the current url
 * @return a url that can be used to get the correct response for
 *         dynamically updating wizard steps, tables, or panels
 */
function getPageUrl(url, stepId, curUrl){
    //This modifies the url to add the base to the beginning
    if (!curUrl) {
        curUrl = window.location.href;
    }
    var originalParams = url.substring(url.indexOf("?") + 1).toQueryParams();

    var additionalParams = curUrl.substring(curUrl.indexOf("?"));//leave the question mark on until after removeParamFromString
    additionalParams = URL_utils.removeAnchor(additionalParams);
    //make sure certain params are not duplicated so TP 3rd level nav actions work. To fix SPRs 1193445, 1334897
    if (originalParams.oid) {
        additionalParams = removeParamFromString("oid", additionalParams);
    }
    if (originalParams.portlet) {
        additionalParams = removeParamFromString("portlet", additionalParams);
    }
    CADX_PARAMS.each(function(param){
        //if param was already on the original url then remove it from additional params so it doesn't get duplicated
        if (originalParams[param]) {
            additionalParams = removeParamFromString(param, additionalParams);
        }
    });

    additionalParams = additionalParams.substring(additionalParams.indexOf("?") + 1); //strip off the ?
    if (additionalParams.endsWith('&')) {
       additionalParams.substring(0, additionalParams.length-2);
    }

    url = URL_utils.removeAnchor(url);

    var base = getBaseHref();
    if (url.charAt(0) === '/') {
      url = url.substring(1);
    }
    url = (url.indexOf(base) === 0) ? url: base + url;
    url = Ext.urlAppend(url, additionalParams);
    url = Ext.urlAppend(url, "stepId=" + stepId + "&dynamicStepLoad=true");

    return url;
}

function reloadPane(div, stepId, iframeForm, successFunc, doAsync){
    // check to make sure the stepId is actually a key in wizardSteps -- RoleBased UI could have hidden it.
    if (div && stepId && wizardSteps && stepId in wizardSteps) {
        if (PTC.wizard.fireEvent('beforeReloadStep', stepId) !== false) {
            var params = getFormData();
            if (iframeForm && iframeForm.length > 0) {
                params = params + iframeForm;
            }
            params = params + "&isWizard=true";
            if (typeof doAsync === 'undefined') {
               // defaults to false because it was originally developed that way so code calling this api
               // depends on the step being updated before continuing.
               doAsync = false;
            }
            //defer ensures successFunc is called after the responseProcessor.process() API - see SPR 2095199
            var deferredSuccessFunc;
            if (typeof successFunc === 'function') {
                deferredSuccessFunc = function(){
                    successFunc.defer(1, this, arguments);
                };
            }

            getElementHtml(params, div, doAsync, getPageUrl(wizardSteps[stepId].url, stepId), false, deferredSuccessFunc);
            PTC.wizard.fireEvent('afterReloadStep', stepId);
        }
    }
}

/**
 * Returns an array of all the form elements of type select, input, or
 * textarea in the steps following the current step
 */
function getDownstreamFormElements(){
    var elementArr = [];
    var currentIdx = findStepIndex(currentStepStrName);
    var nSteps = steps.length;
    var tagNames = ['select', 'input', 'textarea'];
    var nTags = tagNames.length;
    for (var si = (currentIdx + 1); si < nSteps; si++) {
        var stepDiv = document.getElementById(steps[si]);
        if (stepDiv) {
            for (var ti = 0; ti < nTags; ti++) {
                var children = stepDiv.getElementsByTagName(tagNames[ti]);
                if (children) {
                    var nChildren = children.length;
                    for (var ci = 0; ci < nChildren; ci++) {
                        elementArr.push(children[ci]);
                    }
                }
            }
        }
    }
    return elementArr;
}

/**
 * Sets the disabled attribute of the form elements in the steps
 * following the current step to the given value (true or false).
 * Caches the existing values for the disabled attribute so they
 * can be reset later.
 */
function setDownstreamFormElementsDisabled(val){
    if (isWizardType && wizardTypeValue == "wizard") {
        var downstreamElements = getDownstreamFormElements();
        var nElements = downstreamElements.length;
        for (var ele = 0; ele < nElements; ele++) {
            downstreamElements[ele].cachedDisabledVal = downstreamElements[ele].disabled;
            downstreamElements[ele].disabled = val;
        }
    }
}

/**
 * Resets the disabled attributes of the form elements in the steps
 * following the current step to the cached values
 */
function resetDownstreamFormElementsDisabled(){
    if (isWizardType && wizardTypeValue == "wizard") {
        var downstreamElements = getDownstreamFormElements();
        var nElements = downstreamElements.length;
        for (var ele = 0; ele < nElements; ele++) {
            if ((downstreamElements[ele].disabled || downstreamElements[ele].disabled === false) &&
            (downstreamElements[ele].cachedDisabledVal || downstreamElements[ele].cachedDisabledVal === false)) {
                downstreamElements[ele].disabled = downstreamElements[ele].cachedDisabledVal;
            }
            downstreamElements[ele].cachedDisabledVal = null;
        }
    }
}

/**
 * *********************************
 * Turns on the progress indicator.
 * *********************************
 * Optionally you can have a message which will be displayed
 * according to the UI standards while the progress bar is going.
 * You can set the message on the wizard tag in order to have it show up.
 *
 * Global variable for the message: progressMessage.
 * Note: We did it this way so that if you have a dynamic message it would
 * be more straight forward using the global variable.
 *
 * http://rdwiki.ptcnet.ptc.com/mediawiki/index.php?title=UI_X-10_Messaging#Displaying_Busy_Indicator_or_Hourglass
 */
function goProgress(){

    if (!('progressMessage' in window) || progressMessage === '') {
        progressMessage = bundleHandler.get('com.ptc.core.ui.navigationRB.LOADING');
    }
    var config = {
        msg: progressMessage
    };
    PTC.wizard.loadMask = new Ext.LoadMask('wiz_step_contents', config);
    PTC.wizard.loadMask.show();
}

/**
 * Turns off the progress indicator
 */
function stopProgress(){
    steps.each(function(item){
        if (getStyleFromId(item + "Pane").display === "inline") {
            if (item !== currentStepStrName) {
                getStyleFromId(item + "Pane").display = "none";
            }
        }
        else if (item === currentStepStrName) {
            getStyleFromId(item + "Pane").display = "inline";
        }
    });

    if (PTC.wizard.loadMask) {
        PTC.wizard.loadMask.hide();
    }

    PTC.performance.stopWizardTimer(currentStepStrName);
}

/**
 * enables all the buttons
 */
function resetIEButtons(){
    // SPR 2038699-01, in IE8 and 9 sometimes the window goes behind the parent when Apply is used, this will bring it back to the front.
    if (isApply) {
        window.focus();
    }
}

/**
 * This function deprecated, as it applied only to IE6 and IE7
 */
function disableIEButtonsOnSubmit(){
    // no-op
}

/**
 * Enables the wizard specific form params
 *   1961510: it is disabled to keep it separate from actions that occur in steps
 * @returns [HTMLInputElement] the fields that were enabled
 */
PTC.wizard.enableWizardSpecificFields = function() {
    var i, wizardSpecificFormFields = [], form = getMainForm();

    var wizardSpecificParams = ['wizardActionClass', 'wizardActionMethod', 'wizardValidationKey'];
    var wizardStepDelegates = Ext.DomQuery.jsSelect('input[name*=FormProcessorDelegate]');

    i = wizardStepDelegates.length;
    while(i--) {
        wizardSpecificFormFields.push(wizardStepDelegates[i]);
    }

    i = wizardSpecificParams.length;
    while(i--) {
        if(form[wizardSpecificParams[i]]) {
            wizardSpecificFormFields.push(form[wizardSpecificParams[i]]);
        }
    }
    i = wizardSpecificFormFields.length;
    while(i--) {
        wizardSpecificFormFields[i].disabled = false;
    }
    return wizardSpecificFormFields;
};

/**
 * Look through the dom elements looking for file input fields that are not null
 * and if any are found, set the encoding to multipart/form-data
 */
PTC.wizard.setFormEncoding = function() {
    var mform = getMainForm(), sels = document.getElementsByTagName('input');
    var alength = sels.length;
    for (i = 0; i < alength; i++) {
        if (sels[i].type == "file") {
            var docName = sels[i].value;
            if (docName && docName.length > 2 && !sels[i].disabled) {
                mform.enctype = "multipart/form-data";
                mform.encoding = "multipart/form-data";
            }
        }
    }
};

function isOKEnabled(){
    var okButton = findButtonByActionID("PJL_wizard_ok");
    if (okButton) {
        return (okButton.disabled === false);
    }
    else {
        return true;
    }
}


/**
 * Called when user clicks the Ok/Finish button. Verifies required fields are filled in if any, calls afterJS validation
 * if any, server side validation if any, and user submit func if any.
 * 
 * @param {boolean} skipRequiredFieldValidation if true, required attributes are not verified to have values before
 * submittal, but 'afterJS' and 'afterVK' server-side validation is done.
 * 
 * @return true if all verifications succeed, false otherwise.
 */
function checkSubmitStatus(skipRequiredFieldValidation){
    var status = true;
    if (!skipRequiredFieldValidation) {
        if (steps.length === 1 || wizardTypeValue === "wizard") { //added by himanshu to enable ok button on start up of clerk
           status = PTC.wizard.checkRequired(false);
        }
        else {
           status = PTC.wizard.checkClerkRequired(false);
        }
    }

    if (status && !(wizardSteps[currentStepStrName].afterJS("SUBMIT"))) {
        status = false;
    }

    if (status && wizardSteps[currentStepStrName].afterServerVK) {
        if (!PTC.validation.callAJAXValidation(wizardSteps[currentStepStrName].afterServerVK)) {
            status = false;
        }
    }

    if (status && !callUserSubmitFunction()) {
        status = false;
    }
    return status;
}

/**
 *  Submits the wizard for server side processing.  A successful result will automatically close
 * the window by default.   See the params for changing default behavior
 *
 * @param {Object} config - Object containing optional parameters such as:
 *      skipAllValidation - to bypass client side vaildation
 *      skipRequiredFieldValidation - if true, required attributes are not
 *          verified to have values before submittal, but 'afterJS' client validation and 'afterVK' server-side
 *          validation is done
 *      successFunc - optional function to handle the successful formResult.  If not specified
 *          the function handleSubmitResult will be used.
 *      finished {boolean} - default true, specifies the wizard is finished and should be closed.
 *          if false, the wizard will remain open and rely on the afterActionHandler to handle the window
 *
 *   Note that there is no error function parameter yet, this will be possible to add when an ajax request is used
 *      to submit the form.   The current successFunc config can be easily re-applied to the ajax change.
 * @param {boolean} resubmit - whether the wizard is resubmitted after an authentication
 * @returns {boolean} validation status flag, true if client side validation passed, false if not
 */
PTC.wizard.submitWizard = function(config, resubmit) {
    config = config || {};
    Ext.applyIf(config, {finished:true, skipAllValidation:false, skipRequiredFieldValidation: false});

    var i, skipAllValidation = config.skipAllValidation, skipRequiredFieldValidation=config.skipRequiredFieldValidation,
        finished = config.finished;

    /* Finish the wizard by executing it  on the server*/
    prepareToSubmitPopupForm(null);

    var mform = getMainForm();

    var savedEnctype = mform.enctype;
    var savedEncoding = mform.encoding;

    PTC.wizard.setFormEncoding();
    PTC.wizard.setURLForSubmit(mform);

    disableButtons();

    var status;
    try {
        var wizardSpecificFormFields = PTC.wizard.enableWizardSpecificFields();

        if (skipAllValidation) {
            status = true;
        }
        else {
            status = checkSubmitStatus(skipRequiredFieldValidation);
        }

        PTC.wizard.finished = finished;
        if (typeof config.successFunc === 'function') {
            PTC.wizard.actionHandler = config.successFunc;
        }
        else {
            delete PTC.wizard.actionHandler;
        }
        var isSubbmittingIframe = false;
        if(status && PTC.wizardIframes.submitHandler.storeFormAsIframe()) {
            PTC.wizardIframes.submitHandler.submitIframe();
            isSubbmittingIframe = true;
        } else if(status) {
            /*okClicked();*/
            if(!PTC.wizard._isAuthenticatedWizardForm(config, resubmit)){
                return false;
            }
            goProgress();
            PTC.wizardIframes.submitHandler.checkForIframes();
            mform.submit();
        } else {
            enableButtons();
            resetNextBackButton(currentStepStrName);
            isApply = false;
            PTC.wizard.finished = false;
            clearActionFormData();
        }
    } finally {
        mform.enctype = savedEnctype;
        mform.encoding = savedEncoding;
        i = wizardSpecificFormFields.length;
        //For IFrames launched from the wizard, the form fields should not be disabled as these are needed when submitting the main wizard.
        if (!isSubbmittingIframe) {
        while (i--) {
            //Re-disable wizard specific form fields
            wizardSpecificFormFields[i].disabled = true;
          }
        }
    }
    return status;
};

/**
 * Is the current wizard's opener a login page ?
 * @private
 * @returns {boolean} true if login page, false if not
 */
PTC.wizard._isOpenerLoginPage = function() {
    var _opener = getWindow().opener;
    try{
       if(_opener && _opener.document){
          var opener_forms = _opener.document.forms;
          if(opener_forms && opener_forms.length === 1 &&  opener_forms[0].id === PTC.navigation.FORM_BASED_AUTH_FORMID){
             return true;
          }
       }
    } catch(e) {
        PTC.wizard.log.debug("Got permission denied exception", e);
    }
    return false;
};

/**
 * Check whether the wizard form is authenticated (can happen if the opener is logged off)
 * If its a resubmit of the wizard, return true
 * If the window opener is login page, enable the wizard buttons and make an AJAX call to breadcrumb 
 *    - If ajax response is a login page, then PTC.navigation.handleResponseHasFormBasedAuth loads the response in a lightbox 
 *      for user to provide credentials
 *    - If not, then the success function will resubmit the wizard with a flag, so that the same handling is skipped for that.
 * @private
 * @param {Object} config - Object containing optional parameters required for submitting the wizard
 * @param {boolean} resubmit - whether the wizard is resubmitted after an authentication
 * @returns {boolean} false if [resubmit !== true && opener is login page], true if not
 */
PTC.wizard._isAuthenticatedWizardForm = function(config, resubmit) {
    if(resubmit !== true && PTC.wizard._isOpenerLoginPage()){
        //enable the wizard buttons
        enableButtons();

        //make an ajax call to server to get login page response
        var pingUrl = 'ptc1/breadcrumb/';

        //if the response is not a login page, then resubmit the wizard with a flag
        var successFunc = function(response){
            PTC.wizard.submitWizard(config, true);
            return true;
        };
        var options = {
            onSuccess: successFunc,
            method: 'post',
            asynchronous: true,
            parameters: 'url'
        };
        requestHandler.doRequest(pingUrl, options);
        //handled
        return false;
    }
    //not handled
    return true;
};

/**
 *  Submits the main form
 * @deprecated - use PTC.wizard.submitWizard
 *
 * @param skipAllValidation - if true, validation of attribute values is not done,
 *          including 'afterVK' server-side validation
 * @param skipRequiredFieldValidation - if true, required attributes are not
 *          verified to have values before submittal but 'afterVK' server-side
 *          validation is done
 */
function onSubmitMain(skipAllValidation, skipRequiredFieldValidation){
    var params = {skipAllValidation: skipAllValidation, skipRequiredFieldValidation: skipRequiredFieldValidation};
    return PTC.wizard.submitWizard(params);
}

/**
 * Sets up the correct URL for submitting the given form, modifying query params as necessary.
 * This will convert query params to hidden inputs if URL length limit for IE is exceeded.
 *
 * @param {HTMLElement} mform is the mainform about to be submitted
 */
PTC.wizard.setURLForSubmit = function(mform) {
    if(mform && !mform.addedUrlWizardParams) {
        var curUrl = getWindow().location.href;
        var curIdx = curUrl.indexOf('?');

        if (curIdx != -1) {
            var formAction = PTC.util.getFormAction(mform);
            if (formAction.indexOf("soid") > 0) {
                curUrl = removeParamFromString("soid", curUrl);
            }
            // Do not need to copy the nonce from the url, it is already in the form
            curUrl = removeParamFromString("CSRF_NONCE", curUrl);
            if (formAction.length + curUrl.length < 2070) {
                formAction += '&' + curUrl.substring(curIdx + 1);
                PTC.util.setFormAction(mform, formAction);
            }
            else {
                // IE can't support urls longer than 2083, put the extra params into the form.
                var curlParams = $H(curUrl.substring(curIdx + 1).toQueryParams());

                curlParams.each(function(item){
                    var value = item.value;
                    var key = decodeURIComponent(item.key);
                    if(typeof value === 'string') {
                        appendFormHiddenInput(mform, key, decodeURIComponent(value));
                    } else if(value && value.length && value.length > 0){
                        for(var i=0,l=value.length;i<l;i++) {
                            appendFormHiddenInput(mform, key, decodeURIComponent(value[i]));
                        }
                    }
                    else {
                        appendFormHiddenInput(mform, key, "");
                    }
                });
            }
        }

        // do not add params twice since that will make the url too long for ie
        mform.addedUrlWizardParams = true;
    }
};

/**
 *  Submits the main form.  Wraps onSubmitMain().
 *
 * @param skipAllValidation - if true, validation of attribute values is not done,
 *          including 'afterVK' server-side validation
 * @param skipRequiredFieldValidation - if true, required attributes are not
 *          verified to have values before submittal but 'afterVK' server-side
 *          validation is done
 */
function onSubmit(skipAllValidation, skipRequiredFieldValidation){
    PTC.getMainWindow().PTC.performance.restartTimer();
    PTC.getMainWindow().PTC.performance.startComponentTimer('WizardSubmit', 'Wizard Action Completed');

    isApply = false;

    // The Event model in IE prior to IE11 Edge mode.
    if (window.event) {
        Event.stop(window.event);
    }

    formSubmitted = onSubmitMain(skipAllValidation, skipRequiredFieldValidation);
    return formSubmitted;
}

/**
 * Handles the enter key for the SPR 2215108(Error message when pressing ENTER in the first page ..).
 */
PTC.wizard.isEnterKeyPressed = function(){

    if(Ext.EventObject !== null) {
        var keyValue = Ext.EventObject.getKey();
        var isEnabled = isOKEnabled();
        if(!isEnabled && (keyValue === Ext.EventObject.ENTER) ) {
            return false;
        }
    }
    return true;
};

//2182298 - FF/Chrome do not notice the changes to the form if it occurs to the enter key stack frame.
// Important hidden fields are being enabled on the fly
// Deferring the call to be outside of the enter key event allows the form post to work.
onSubmit = onSubmit.wrap(function(p, a,b,c) {
    if(!PTC.wizard.isEnterKeyPressed()) {
        return false;
    }
    p.defer(1, this, [a,b,c]);
    return false;  // Stops the automatic form post
});

/**
 * Update the required lable in the wizard footer.
 * If no required attributes are displayed for a given step, the text won't be displayed.
 */
function updateRequiredLabel(){
    var requiredField = Ext.getDom('requiredfieldDisplay');
    var stepDom = Ext.getDom(currentStepStrName);
    if (currentStepStrName && requiredField && stepDom) {
        var required = Ext.DomQuery.selectNode('.required', stepDom); //get element that className is "required"
        if (required) {
            requiredField.style.display = 'inline';
        }
        else {
            requiredField.style.display = 'none';
        }
    }
}

/**
 * Success function if the step is successfully changed.
 * ajax response handler
 */
PTC.wizard.setActiveStepSuccessHandler = function(stepId, wizardAction){
  if (isWizardType && wizardTypeValue == "wizard") {
        resetOkButton();
    }

    if (isWizardType && wizardTypeValue == "wizard") {
        resetNextBackButton(currentStepStrName);
        setBackButton(stepId);
    }

    stepIndex = findStepIndex(currentStepStrName);
    try {
    wizardSteps[stepId].postloadJS(wizardAction);
    } catch(e) {
        //just log the error so we can still attempt to hide the progress indicator and display the step
        PTC.log.error("Error occurred calling postloadJS function: ", e);
    }

    stopProgress();
    //once the step is loaded, the isAsync flag should be set to false
    wizardSteps[stepId].isAsync=false;

    // Project #: 14218746
    // gpurohit: Added code to display embedded help text (if specified any) for each wizard step.
    updateEmbeddedText();
    // Project #: 14218746
    // gpurohit: Added code to stabilize wizard functionalities and solve some SPRs.

    //Hide the required label if no required attributes exists.  Story B-45268.
    updateRequiredLabel();

    wizardSteps[stepId].isActive = true;

    PTC.wizard.StepLinksPanelUtil.alignActiveStep();
    PTC.wizard.StepLinksPanelUtil.attachOnClickHandlers();

    adjustWizardContentAreaHeight();

    PTC.wizard.fireEvent("wizardStepReady", stepId);
};
/**
 * Makes a specific step active.  Fires the wizardStepReady event.
 * @param stepId Id of the step in the wizard
 * @param [wizardAction] Optional indicator if the user is attempting to go back or forward in the wizard.
 */
PTC.wizard.setActiveStep = function(stepId, wizardAction){

    wizardSteps[currentStepStrName].visited = true;

    if (stepId == currentStepStrName) {
        return;
    }
    if (!wizardSteps[stepId]) {
        return;
    }

    if (!currentStepStrName) {
        currentStepStrName = steps[stepIndex];
        stepIndex = findStepIndex(currentStepStrName);
    }

    // gpurohit: If the user is navigating backwards by clicking on step title or step icon,
    //           the required field validation should not take place.
    var newStepIndex = findStepIndex(stepId);
    if (newStepIndex < stepIndex) {
        wizardAction = 'BACK';
    }
    var isBackButton = wizardAction == 'BACK';
    if (isWizardType && wizardTypeValue == "wizard") //Added by himanshu bcoz in clerk we don't validate on tab naviagation
    {
        var requiredFieldsComplete = PTC.wizard.checkRequired(isBackButton);
        if (!requiredFieldsComplete) {
            if (!isBackButton) {
                // only disallow the step movement for next and ok
                return;
            }
            else {
                // the user needs to come back and fill out required fields still.
                wizardSteps[currentStepStrName].isComplete = false;
            }
        }
        else{
            // SPR Task: 5695341 Marking the step to be complete if required fields are filled
            wizardSteps[currentStepStrName].isComplete = true;
        }
    }

    if (isWizardType && wizardTypeValue == "clerk") {
        enableOkButton();
    }

    if (!(wizardSteps[currentStepStrName].afterJS(wizardAction))) {
        return;
    }

    goProgress(); // Display progress bar till the ajax action is complete
    if (wizardSteps[currentStepStrName].afterServerVK) {
        // Some validators validate all the form content.  For wizards (not clerks) disable downstream step elements
        // so we don't try to validate downstream data that may be in the DOM as a result of user clicking Back
        // to get to current step.  We don't want to prevent the user from going back when there is
        // invalid data on current step and we don't want to prevent the user from going forward even though
        // there is invalid data on downstream steps (that the user has to correct).
        setDownstreamFormElementsDisabled(true);
        if (!PTC.validation.callAJAXValidation(wizardSteps[currentStepStrName].afterServerVK, wizardAction)) {
            if ((isWizardType && wizardTypeValue == "clerk") || !isBackButton) {
                // only disallow the step movement for next and ok
                stopProgress();
                resetDownstreamFormElementsDisabled();
                return;
            }
            else {
                // the user needs to come back and fix invalid values
                wizardSteps[currentStepStrName].isComplete = false;
            }
        }
        resetDownstreamFormElementsDisabled();
    }

    if (stepId != nextStep && nextStep !== null) {
        stepId = nextStep;
        nextStep = null;
    }
    if (!wizardSteps[stepId].preloadJS(wizardAction)) {
        stopProgress();
        return;
    }

    if (wizardSteps[stepId].beforeServerVK) {
        if (!PTC.validation.callAJAXValidation(wizardSteps[stepId].beforeServerVK)) {
            stopProgress();
            return;
        }
    }


    //getStyleFromId(currentStepStrName + "Pane").display = "none";
    wizardSteps[currentStepStrName].isActive = false;

    currentStepStrName = stepId;
    if (wizardSteps[stepId].isDirty) { // Preload steps are dirty at first
        wizardSteps[stepId].isDirty = false;

        // Make the step visible before rendering because Ext components rendered into an invisible element
        // will be given 0 size.  Loading mask will still be displayed until stopProgress() is called. See SPR 2099053.
        getStyleFromId(stepId + "Pane").display = "inline";

        //Async is being passed as true only in the case where a valid wizardAction is declared.
        //that reduces possible impacts of callers of this api, most do not pass action as "next" or "back".
        reloadPane(stepId, stepId, null, PTC.wizard.setActiveStepSuccessHandler.createCallback(stepId, wizardAction), typeof wizardAction !== 'undefined');
    }
    else if (!wizardSteps[stepId].isAsync) {
        wizardSteps[stepId].isComplete = true;
        wizardSteps[stepId].isDirty = false;
        PTC.wizard.setActiveStepSuccessHandler(stepId, wizardAction);
    }
    else {
        PTC.wizard.setActiveStepSuccessHandler(stepId, wizardAction);
    }
};
/**
 * Moved, change the step of the wizard
 * @name setActiveStep
 * @changecomment [x-22] replaced with PTC.wizard.setActiveStep
 */
setActiveStep = PTC.wizard.setActiveStep; // preserve old references for now
PTC.wizard.goNext = function(){

    var origNextStep = null;
    if (nextStep === null) {
        nextStep = PTC.wizard.getNextStep();
        origNextStep = nextStep;
    }
    PTC.performance.startWizardTimer(nextStep);
    try {
        PTC.wizard.setActiveStep(nextStep, "NEXT");
    }
    finally {
        if (origNextStep == nextStep) {
            // only reset when the developer code has not changed what should be next
            nextStep = null;
        }
    }
};
