/**
 * Setup the initial object event observers for the various step navigation.
 * Upon hitting an observed navigation call the function
 * @param {Function} navObserveFunction - click listener
 * @param {boolean} [ready] is the wizard ready.  To avoid infinite loops if this
 *                   function is called outside of a wizard
 */
function setupWizardNavigationObservers(navObserveFunction, ready){
    // avoid infinite loops in the main window
    if (ready !== true) {
        // wait until steps are available
        PTC.onReady(function(){
            setupWizardNavigationObservers(navObserveFunction, true);
        });
        return;
    }
    if (!("steps" in window)) {
        return;
    }
    var steps_length = steps.length;
    for (var i = 0; i < steps_length; i++) {
        var _step = getStepTextLink(steps[i]);
        var _div = getStepBoxLink(steps[i]);

        if (_step) {
            Event.observe(_step, 'click', navObserveFunction);
        }
        if (_div) {
            Event.observe(_div, 'click', navObserveFunction);
        }
    }

    var nextButton = findButtonByActionID("PJL_wizard_next");
    var prevButton = findButtonByActionID("PJL_wizard_previous");
    nextButton.on('click', navObserveFunction);
    prevButton.on('click', navObserveFunction);
}

/**
 * @return String id of the next step to be displayed in the wizard.
 */
PTC.wizard.getNextStep = function(){

    var tmp;

    if (steps.length <= stepIndex + 1) {
        return null;
    }

    if (!currentStepStrName || !nextStep) {
        tmp = steps[stepIndex + 1];
    }
    else {
        tmp = nextStep;
    }

    var i = 0;
    // careful tmp var is a string, not an int
    while (wizardSteps[tmp].hidden && ((stepIndex + i) < steps.length)) {
        i++;
        tmp = steps[stepIndex + i];
    }
    return tmp;
};

/**
 * set a step to need a refresh should it display again
 */
function setStepDirty(stepId){
    if (wizardSteps[stepId].isDirty === false) {
        wizardSteps[stepId].isDirty = true;
        wizardSteps[stepId].visited = false;
        resetOkButton();
    }
}

/**
 * Sets the next step in the wizard to be refreshed when displayed.
 */
function setNextStepDirty(){
    var tmp = PTC.wizard.getNextStep();
    if (tmp && tmp.length > 0) {
        setStepDirty(tmp);
    }

    return true;
}

/**
 * Make the wizard go back one step
 */
function goBack(){
    var backStep = PTC.wizard.getPreviousStep();
    PTC.performance.startWizardTimer(backStep);
    nextStep = null;
    PTC.wizard.setActiveStep(backStep, "BACK");
}

PTC.wizard.getPreviousStep = function(stepId) {
    var backStep, backStepIndex;
    if (stepId) {
        backStepIndex = findStepIndex(stepId) - 1;
    } else if (!currentStepStrName || !nextStep) {
        currentStepStrName = steps[stepIndex];
    }

    if (!backStepIndex) {
        backStepIndex = stepIndex - 1;
    }
    if (backStepIndex < 0) {
        backStepIndex += 1;
    }

    backStep = steps[backStepIndex];

    var i = 0;
    while (wizardSteps[backStep].hidden && backStepIndex > 0) {
        i++;
        backStep = steps[backStepIndex - i];
    }

    // Could this go Out of BOunds??
    if (wizardSteps[backStep].hidden) {
        backStep = steps[backStepIndex + 1];
    }
    return backStep;
};

PTC.wizard.isPreviousStepActive = function(stepId) {
    var previousStep = PTC.wizard.getPreviousStep(stepId);
    if (previousStep && wizardSteps[previousStep]) {
        var val = wizardSteps[previousStep].isActive;
        if (val) {
            return val;
        }
    }
    return false;
};

