/**
 *  This function takes a url and turns it into an absolute URL.
 */
function getAbsoluteUrl(url){
    //This is getting the base URL (by ID) that is put into the HTML by begin.jsp
    var base = window.document.getElementById("basehref");

    //This modifies the url to add the base to the beginning
    url = base.href.substring(0, base.href.length - 11) + url;
    return url;
}

/**
 *  Checks if the current window is a "popup wizard" (wizards, clerks, dialogs, popups etc.)
 *  NOTE: this is a jca function and does not return true for template processor wizards.
 *
 *  This function is set to TRUE_FUNC in beginPopup.jspf,
 *  so any pages that include beginPopup.jspf or beginWizard.jspf will be a "wizard".
 *  (and set to FALSE_FUNC in shell.jsp)
 *
 *  Still need the logic in the function in case there are wizards that somehow don't include those jspfs.
 */
function isWizardWindow(){
    var wiz_window = getWindow();
    var portletPoppedUp = wiz_window.location.href.indexOf("portlet=poppedup") > -1;
    if (!portletPoppedUp && getMainForm()) {
        var formAction = PTC.util.getFormAction(getMainForm());
        // Some popups like pickers have posted formdata up, the url is bad but the form.action contains the params.
        portletPoppedUp = formAction.indexOf("portlet=poppedup") > -1;
    }
    var returnVal = false;

    try {
        //It is not sufficient to check only for opener and an opener base href equal to the current window base href.
        //In IE, if the launch page for the action is opened in a new browser window or tab
        //those will be true even if the launch window isn't a wizard.  See spr 1544988
        if ((typeof popupWindow !== 'undefined') || portletPoppedUp) {
            //checking != 'undefined instead of === 'function' because IE thinks the opener.getBaseHref is typeof 'object'
            if (wiz_window.opener && (typeof wiz_window.opener.getBaseHref !== 'undefined') && (wiz_window.opener.getBaseHref() === wiz_window.getBaseHref())) {
                returnVal = true;
            }else if(isWizardType){//In some scenarios wizard will not have any opener. for e.g. MultiDoc create wizard through DTI.
                returnVal=true;
            }
        }
    }
    catch (e) {
        // IE sometimes gives error messages about the client being disconnected from its host, when accessing properties of the opener.
        // Just return false in that case.
        return false;
    }
    return returnVal;
}

function handleWizWindow(status){
    switch (status) {
        case 0: // SUCCESS
        case 2: // NON_FATAL_ERROR
            if (!isApply && getPopupOpenerWindow() && getWindow().location.href.indexOf("portlet=poppedup") >= 0) {
                if (PTC.lightbox.isLightbox(window)) {
                    PTC.lightbox.deactivate({
                        cancelAction: true,
                        reloadParent: false
                    });
                }
                else {
                    //SPR 6197316 clear popup action data set on opener form that was set during popupActionMainImpl()
                    getPopupOpenerWindow().PTC.action.clearPopUpActionFormData();
                    wfWindowClose1();
                }
            }
            else if (parent && parent.currentStepStrName) {
                parent.stopProgress();
                parent.enableButtons();
                parent.resetNextBackButton(currentStepStrName);
                PTC.wizard.loadMask.hide();
                if (!PTC.lightbox.isLightbox(window)) {
                    var wizardClass = getMainForm().wizardActionClass;
                    // SPR 4530390 New Folder wizard should clear Name field after Apply button
                    // This condition is necessary to protect against clearing Org field in New User wizard  
                    if (   (wizardClass)
                        && (wizardClass.value == "com.ptc.windchill.enterprise.folder.forms.CreateFolderFormProcessor") ) {
                        getMainForm().reset();
                    }
                }
            }
            break;
        case 1: // FAILURE
            PTC.wizard.finished = false;
            if (parent && parent.currentStepStrName) {
                parent.stopProgress();
                parent.enableButtons();
                parent.resetNextBackButton(currentStepStrName);
                if (PTC.lightbox.isLightbox(window)) {
                    PTC.wizard.loadMask.hide();
                }

            }
            break;
        default: // Unknown action
            throw new Error('Unknown wizard status');
    }
}

/**
 *
 */
PTC.wizard.initializeFormResult = function (status, nextAction, js, URL, frConfig) {
   frConfig = frConfig || {}; // double check its defined

    // Remove the table prefix and suffix that is present from create wizards
    if (!(frConfig === undefined || frConfig === null)) {
        frConfig.tableID = tableUtils.getUnformattedTableId(frConfig.tableID);
    }

    frConfig.status = status;
    frConfig.nextAction = nextAction;
    frConfig.URL = URL;
    frConfig.js = js;
    frConfig.ajaxEnabled = extractParamValue(window.location.href, 'AjaxEnabled');
    var formResult = new PTC.action.FormResult(frConfig);
    return formResult;
};

/**
 * Handles the response of the wizard submission,
 * the response is mostly a form result string object that tells the browser what to do.  Not quite jSON yet though.
 */
function handleSubmitResult(status, nextAction, js, URL, frConfig){
   var table, continueProcessing = true;

   // Capture the timer now, before the result is processed.  Otherwise, this window
   // and its namespace (e.g. PTC.*) might be garbage collected before we get to the bottom
   // of this function and attempt to stop the timer.
   var myMain = PTC.getMainWindow();
   var perfTimer = null;
   if (myMain && myMain.PTC && myMain.PTC.performance) {
      perfTimer = myMain.PTC.performance;
      perfTimer.startComponentTimer('handleSubmitResult', 'Update from Wizard Completed');
   }

   clearActionFormData();
   var customEventHandler = PTC.wizard.actionHandler;
   delete PTC.wizard.actionHandler;

   var formResult = PTC.wizard.initializeFormResult(status, nextAction, js, URL, frConfig);

   if (typeof customEventHandler === 'function') {
       //Custom handler, called once
       continueProcessing = customEventHandler(formResult);
   }

    continueProcessing = PTC.wizard.fireOnAfterAction(formResult) && continueProcessing;

    var formResultEnum = PTC.cat.FormResult;
    var callback = PTC.cat.WizardHelper.getCallback(getWindow());
    if (PTC.wizard.finished && nextAction === formResultEnum.REFRESH_OPENER && callback) {
        //Only call the CAT callback if its the wizard finish button, and its a refresh
        try {
            callback.call(this, formResult);
        } catch(ecallback) {
            //2142574 - during page refresh the structure tab is lost and callback undefined in IE9 only
            PTC.log.warn('CAT callback returned an error message, this can mean the page has started refreshing and lost its scope', ecallback);
        }
        handleWizWindow(status);
        return;
    }

    if (!continueProcessing) {
        if (PTC.wizard.finished) {
           handleWizWindow(status);
        }
        return ;
    }

    //TODO set this to error level in x24 and remove the component refresh code below
    PTC.action.log.warn("Legacy Handler is being used, the action ", formResult.actionName,
                       ' should return a formResult with oids or have components handle the action specifically.', formResult);

    switch (nextAction) {
        case formResultEnum.REFRESH_OPENER:
            var refreshed = false;
            if (parent) {

                if (PTC.wizard.finished) {
                    if (status !== 1) {
                        //If there is an error, no need to refresh as the wizard did not complete.
                        refreshOpenerOnly();
                    }
                    refreshed = true;
                }
                if ((parent.currentStepStrName || window.currentStepStrName) && (PTC.wizard.finished || status === 1) ) {
                    handleWizWindow(status);
                    refreshed = true;
                }
                // If window is a lightbox, this will allow it to be closed/deactivated
                else if (PTC.lightbox.isLightbox(window) && window.currentStepStrName && window.PTC.wizard.finished) {
                   handleWizWindow(status);
                   refreshed = true;
                }
            }

            if(!refreshed) {
                //Component refresh of a table.  Non-wizard action that did not provide oids on the formResult
                table = tableUtils.getTable(formResult.getTableId());
                if(table) {
                    PTC.jca.table.Utils.reload(table);
                }
            }

            break;
        case 3: // JAVASCRIPT
            if (status == 1) { //FAILURE
                handleWizWindow(status);
            }
            try {
                eval(js);
            }
            catch (evalexception) {
                PTC.wizard.log.error(evalexception);
            }
            break;
        case 4: // NONE
            if (PTC.wizard.finished) {
                // don't close the wizard if the actions is an on-page action inside one of the wizard tables.
                handleWizWindow(status);
            }
            else if (!parent.currentStepStrName) {
                //Component refresh of a table.  Non-wizard action that did not provide oids on the formResult
                table = tableUtils.getTable(formResult.getTableId());
                if(table) {
                    PTC.jca.table.Utils.reload(table);
                }
            }

            break;
        case 5: // REFRESH_OPENER_AND_SUBMIT_IFRAMES
            refreshOpenerOnly();
            eval(js);
            handleWizWindow(status);
            break;
        case 2: // LOAD_OPENER_URL
            if (parent.currentStepStrName && PTC.wizard.finished) {
                  handleWizWindow(status);
                  refreshed = true;
            }
            break;
        case 6: // FORWARD
        case 7: // NON_SUBMIT
            // the LOAD_OPENER_URL and FORWARD cases are handled in PTC.wizard._handleForwardFormResult()
            break;
        case 8: // RE_SUBMIT CURRENT Page
              PTC.navigation.submitForm();
            break;
        default: // Unknown action
            throw new Error('Next wizard action unknown');
    }

    if (status === 1 && PTC.wizard.loadMask && PTC.wizard.loadMask.el
        && PTC.wizard.loadMask.el.isVisible && PTC.wizard.loadMask.el.isVisible()) {
        //If there was an error, make sure the progress window is not visible anymore
        //Some cases fall through
        stopProgress();
    }

    if (perfTimer) {
        perfTimer.stopComponentTimer('handleSubmitResult', null, 'deltaTime');
    }
}

