/**
 *   Sets the isDirty attribute of all downstream non-preloaded wizard steps to true
 *   so they will be reloaded the next time the user navigates to them.
 **/
function markDownstreamNonPreloadedWizStepsDirty(){
    var currentIdx = findStepIndex(currentStepStrName) + 1;
    var length = steps.length;
    for (var si = currentIdx; si < length; si++) {
        var stepId = steps[si];
        if (!wizardSteps[stepId].preloadPage) {
            setStepDirty(stepId);
        }
    }
    PTC.wizard.StepLinksPanelUtil.updateStepImages();
}

/**
 *  Deletes the content of step div tags downstream from the current step
 *  if the step is marked dirty.
 */
function deleteDownstreamFormContent(){
    var currentIdx = findStepIndex(currentStepStrName);
    var length = steps.length;
    for (var si = (currentIdx + 1); si < length; si++) {
        var step = document.getElementById(steps[si]);
        if (wizardSteps[steps[si]].isDirty) {
            var stepContent = window.document.getElementById(step.id);

            // removing any other remaining items from the step
            PTC.navigation.overwrite(stepContent, "");
        }
    }
}

function resetTypeInstanceId(elementVal, currentObjectHandle, template){
    if (!elementVal) {
        return;
    }
    var params = 'pickerVal=' + elementVal;
    if (template) {
        var element = document.getElementsByName("templateOid")[0];
        element.value = elementVal;
        element = document.getElementsByName("PrePopulateObjectList")[0];
        element.value = elementVal;
        params += "&template=" + template;
    }
    var options = {
        asynchronous: false,
        parameters: params
    };
    var url = "netmarkets/jsp/components/resetItemTypeInstanceId.jsp";
    var transport = requestHandler.doRequest(url, options);
    var newTypeInstanceId = transport.responseText;
    element = document.getElementById(currentObjectHandle + PTC.wizard.ITIID);
    element.value = newTypeInstanceId;
}

/**
 *  Called when the value of the type picker in create wizards changes.
 *  Resets the itemTypeInstance id hidden field, marks all downstream
 *  non-preloaded steps dirty, and deletes the form content of non-preloaded downstream steps.
 */
function pickerGo(value, currentObjectHandle, template){
    //Picker value not sent in
    if (!value) {
        return;
    }

    resetTypeInstanceId(value, currentObjectHandle, template);
    if (isWizardType && wizardTypeValue == "wizard") {
        markDownstreamNonPreloadedWizStepsDirty();
    }
    deleteDownstreamFormContent();

    // Fires when type changes
    PTC.wizard.fireEvent('afterTypePickerChange');
}


/**
 *   Sets the isDirty attribute of all downstream wizard steps to true
 *   so they will be reloaded the next time the user navigates to them.
 **/
function markDownstreamWizStepsDirty(){
    var currentIdx = findStepIndex(currentStepStrName) + 1;
    var length = steps.length;
    for (var si = currentIdx; si < length; si++) {
        setStepDirty(steps[si]);
    }
    PTC.wizard.StepLinksPanelUtil.updateStepImages();
}
/**
 *When the user changes the context, delete downstream form data and
 *recompute the default type based on the new context.
 * @param {string} pickerId The id of the Picker object
 * @param {string} strContainerRef The Context string
*/
function onContextChange(pickerId, strContainerRef){

    //the obj handle of the context picker or empty string if it has no handle
    var pickerObjHandle = "";
    var indexOfPickerId = pickerId.lastIndexOf("containerRef");
    var objHandle = pickerId.slice(0, indexOfPickerId);

    if (objHandle && objHandle.length > 0) {
        pickerObjHandle = objHandle;
    }

    var eleContainerRef = document.getElementById(pickerObjHandle + "containerRef");
    eleContainerRef.value = strContainerRef;

    //Create and fill handles list
    //If context had a handle, only need to recompute default type for fields with that handle.
    //Else need to find all possible fields and recompute default type for them.
    var handles = [];
    if (pickerObjHandle === '') {
        var domElements = document.getElementsByName('objectHandle');
        if (domElements && domElements.length) {
            //Then it has to be a NodeList objet. Convert it to Array
            for(var idx=0,len=domElements.length;idx<len;++idx) {
                handles.push(domElements[idx].value);
            }
        }
        
        handles.push('');
    } else {
        //this case happens when creating a part from workspace, pickerObjHandle is string like "!~objectHandle~partHandle~!"
        handles[0] = pickerObjHandle;
    }

    for (var i=0, j=handles.length; i < j; i++) {
        var handle = handles[i];
        var eleTypeInstanceID = document.getElementById(handle + "itemTypeInstanceId");
        if(!eleTypeInstanceID) {
            PTC.wizard.log.debug('Not able to find a type picker with the handle "' + handle + '"');
            continue;
        } 
                
        var eleDefaultType = document.getElementsByName(handle + "typePickerInitValue")[0];
        var eleBaseTypeID = document.getElementsByName(handle + "baseTypeIdentifier")[0];       

        var params = "baseTypeID=" + eleBaseTypeID.value + "&containerRef=" + strContainerRef;
        var options = {
            asynchronous: false,
            parameters: params
        };

        // call RecomputeDefaultTypeController to get JSON containing default type info
        var url = getBaseHref() + "ptc1/recomputeDefaultType";
        var transport = requestHandler.doRequest(url, options);

        // Grab the returned default type & type instance from the JSON
        // An example of what reponseText would be like:
        //{"defaultType":"OR:wt.pdmlink.PDMLinkProduct:49421","typeInstanceID":"WCTYPE|wt.change2.WTChangeOrder2~~NEW|7851073291875795472"}
        var response = Ext.util.JSON.decode( transport.responseText );
        // update the dom element values
        eleDefaultType.value = PTC.util.unescapeHTML(response.defaultType);
        eleTypeInstanceID.value = PTC.util.unescapeHTML(response.typeInstanceID);
    }
    //this method is invoked when the context changes - we need to clean downstream always.
    markDownstreamNonPreloadedWizStepsDirty();
    deleteDownstreamFormContent();
}

function contextChanged(objects, pickerId){
    //Call the context picker default call back API

    if (document.getElementById(pickerId + "$label$").options) {
        contextPickerCallBackJCACombo(objects, pickerId);
    }

    var strContainerRef = objects.pickedObject[0].oid;
    var strContainerRefValue = objects.pickedObject[0].name;

    //Call the onContextChange API which will set the container information in the request.
    onContextChange(pickerId, strContainerRef, strContainerRefValue);
}

function callContextChange(pickerId){

    var test = $(pickerId + '$label$').value;

    $(pickerId).value = $(pickerId + '$label$').value;
    onContextChange(pickerId, $(pickerId).value);
}

/**
 * Flag to determine if the limitChars msg is already being shown to the user or not. We do not want to show a second
 * msg if the user goes outside the field (onblur) to click on the previously shown msg.
 * @private
 */
PTC.util.isLimitCharsMsgShowing = false;

/**
 * @private Determines if string length is longer than max length. If so, show the user an error msg saying they've gone
 * over the limit
 * @param {object} strLength length of string you want to check
 * @param {Object} maxLength maximum allowed length
 * @param {Object} e Event (onkeypress or onblur in limitChars case)
 * @param {String} key is the resource bundle key to use such as
 *      'com.ptc.core.ui.errorMessagesRB.NEW_TEXT_AREA_LENGTH_EXCEED_BYTE' if no key is given then default key is used:
 *      'com.ptc.core.ui.errorMessagesRB.NEW_TEXT_AREA_LENGTH_EXCEED_CHARACTER'
 */
PTC.wizard.isNotGreaterThanMax = function(strLength, maxLength, e, key){
    key = key || 'com.ptc.core.ui.errorMessagesRB.NEW_TEXT_AREA_LENGTH_EXCEED_CHARACTER';
    var strL = parseInt(strLength,10);
    var maxL = parseInt(maxLength,10);
    // make sure both sent in numbers are valid. If the max is 0, that means there is no limit and we return true
    if (!isNaN(strL) && !isNaN(maxL) && maxL !== 0) {
        if (strL > maxL) {
            if (!PTC.util.isLimitCharsMsgShowing) {
                PTC.util.isLimitCharsMsgShowing = true;
                Event.stop(e);
                var params = [strLength, maxLength];
                JCAAlert(key, "", params);
                PTC.util.isLimitCharsMsgShowing = false;
                return false;
            }
        }
    }
    return true;
};

/**
 * @private
 * Gets a dom element by name and returns it's value. If the element cannot be found, null is returned.
 * @param {String} fieldName
 * @return {String} value of dom element
 */
PTC.wizard.getElementValueByName = function(fieldName) {
    var elem = PTC.wizard.getElementByName(fieldName);
    if (elem === null) {
        return null;
    }
    return elem.value;
};

/**
 * @private
 * Gets a dom element by name. If the element cannot be found, null is returned.
 * @param {String} fieldName
 * @return {String} dom element
 */
PTC.wizard.getElementByName = function(fieldName) {
    var elems = document.getElementsByName(fieldName);
    if (!elems || elems.length === 0 || !elems[0]) {
        return null;
    }
    // if there was more than one field found with the given name, just use the 1st one found by default
    return elems[0];
};

/**
 * if the next key attempting to be entered by the user in a text box or text area exceeds the allowed char limit,
 * an error alert is given
 * @param {Object} fieldName html field name (eg. input, textarea, etc.)
 * @param {Object} maxByteLength maxium allowed bytes (necessary for multibyte chars)
 * @param {Object} maxStringLength max amount of latin chars allows in field
 * @param {Object} e user key e from the browser (most likely a "onkeypress" in this case)
 */
PTC.wizard.limitCharsOnKeyPress = function(fieldName, maxByteLength, maxStringLength, e){
    var result = true;
    // check if all necessary params were sent in
    if (fieldName && e) {
        var keynum = e.keyCode ? e.keyCode /*IE*/ : e.which /*Firefox*/;

        //do not limitChars if user is pressing keys like delete, directional, etc.
        if (PTC.util.isCharInputKey(e)) {
            // If text is selected in the field, it will replace this text so allow it
            if (PTC.util.eventTargetHasSelection(e)) {
                return true;
            }

            var elVal = PTC.wizard.getElementValueByName(fieldName);
            if (elVal === null) {
                return true;
            }

            var newChar = String.fromCharCode(keynum);

            // first check against string length, as string length is always less than byte length
            var fieldStringLength = elVal.length;
            var toAddStringLength = newChar.length;
            result = PTC.wizard.isNotGreaterThanMax((fieldStringLength + toAddStringLength), maxStringLength, e);
            if (!result) { // return early if string is longer than max
                return result;
            }

            /*Fix for SPR 6080909. For SQL server, the value of maximum bytes per character is forced to be one. Therefore, in case of
             * characters with byte length of more than one byte, user won't be allowed to use the maximum character length
             * allowed for the field. Therefore the check for byte length is required in case of Oracle server only. Moreover,
             * in case of SQL server, maxByteLength is always equal to maxStringLength, therefore only a check for maxStringLength
             * will suffice*/
            if(maxByteLength!=maxStringLength){
                 // next check if the length exceeds the max byte length
                 var newTotalByteLength = PTC.util.getByteLength(elVal) + PTC.util.getByteLength(newChar);
                 var key='com.ptc.core.ui.errorMessagesRB.NEW_TEXT_AREA_LENGTH_EXCEED_BYTE';
                 result = PTC.wizard.isNotGreaterThanMax(newTotalByteLength, maxByteLength, e, key);
            }
        }
    }
    return result;
};

/**
 * Used for onblur of text boxes and text areas. If, onblur, the text exceeds the allowed lengths, return an error msg.
 * @param {Object} fieldName
 * @param {Object} maxByteLength
 * @param {Object} maxStringLength
 * @param {Object} e
 */
PTC.wizard.limitChars = function(fieldName, maxByteLength, maxStringLength, e){
    var result = true;
    if (fieldName) {
        var el = PTC.wizard.getElementByName(fieldName);
        if (el === null) {
            return result;
        }
        var elVal = el.value;

        // first check against string length, as string length is always less than byte length
        var orig_onBlurFunc = PTC.wizard.unsetOnBlurFunc(el);
        result = PTC.wizard.isNotGreaterThanMax(elVal.length, maxStringLength, e);
        if (result) {  // return early if string is longer than max
            // next check if the length exceeds the max byte length
             var key='com.ptc.core.ui.errorMessagesRB.NEW_TEXT_AREA_LENGTH_EXCEED_BYTE';
            result = PTC.wizard.isNotGreaterThanMax(PTC.util.getByteLength(elVal), maxByteLength, e, key);
        }
        if (!result) {
            PTC.wizard.resetOnBlurFunc(el, orig_onBlurFunc);
        }
    }

    return result;
};

/**
 * Used for onblur of NumericInputComponent which does not have units. If, onblur, the element value is not valid, return an error message.
 * @param {Object} elem
 * @param {Object} errorMsgRb
 * @param {Object} regEx
 */
function validateForNaN(elem, errorMsgRB, regEx){
    var value = elem.value;
    var result = PTC.wizard.validateInputValue(elem, value, regEx, errorMsgRB, []);
    return result;
}

/**
 * Helper function that searches for the pattern "regEx" anywhere in the string "value" and displays
 * an alert if it is found.  The alert message is formed from "errorMsgRB" with any "{0}" parameters
 * substituted with values from "inserts"
 *
 *
 * @param {DOMElement} elem - input field being validated.  Field will have focus after the Error message.
 * @param {String} value - value to search for pattern matches
 * @param {String} regEx - regular expression that should test true for an invalid input
 * @param {String} errorMsgRb - error message or resource bundle ID
 * @param {String} inserts - optional array of strings (first string is used to substitute the {0} in the errorMsgRB)
 * @return "true" if the pattern was not matched, "false" otherwise.
 *
 * @see PTC.lwc.helpers.validateForNaN_WithInserts
 */
PTC.wizard.validateInputValue = function(elem, value, regEx, errorMsgRB, inserts){
    var re = new RegExp(regEx);
    if (value) {
        if (re.test(value)) {
            var orig_blurFunc = PTC.wizard.unsetOnBlurFunc(elem);
            JCAAlert(errorMsgRB, "", inserts);
            PTC.wizard.resetOnBlurFunc(elem,orig_blurFunc);
            return false;
        }
    }
    return true;
};

/**
 * Helper function to unset the onblur function and reset after sometime
 * @param {DOMElement} elem - input field being validated.  Field will have focus after the Error message.
 *
 * @see PTC.wizard.resetOnBlurFunc
 */
PTC.wizard.unsetOnBlurFunc = function(elem) {
    var orig_onBlur = elem.onblur;
    elem.onblur = undefined;
    return orig_onBlur;
};

/**
 * Helper function to unset the onblur function and reset after sometime
 * @param {DOMElement} elem - input field being validated.  Field will have focus after the Error message.
 *
 * @see PTC.wizard.unsetOnBlurFunc
 */
PTC.wizard.resetOnBlurFunc = function(elem, onBlurFunc) {
      setTimeout(function(){
                PTC.wizard.setSelect(elem.name);
                elem.onblur = onBlurFunc;
       }, 5);
};
/**
 * Will focus and select the dom element with the given name.
 * If more than one dom element has the given name, only the 1st would be focused/selected.
 * @param {String} field - name of the dom element to focus and select.
 */
PTC.wizard.setSelect = function(field){
    var elems = document.getElementsByName(field);
    if (!elems || elems.length < 1) {
        return false;
    }

    var elem = elems[0];
    elem.focus();
    elem.select();
    return false;
};
setSelect = PTC.wizard.setSelect;

function populatedependentAttributeValue(refAttrElement, hiddenAttrName, dependentAttrColumnId){
    var dependantAttrElement = document.getElementById(dependentAttrColumnId);
    var refAttrvalue = refAttrElement.value;

    var hiddenElements = document.getElementsByName(hiddenAttrName);
    if (hiddenElements && hiddenElements.length > 0) {
        var hiddenElement = hiddenElements[0];
        hiddenElement.value = refAttrvalue;
    }

    if (dependantAttrElement && refAttrvalue && refAttrvalue.indexOf(":") > 0) {
        var displayValue = refAttrvalue.substring(0, refAttrvalue.indexOf(":"));
        dependantAttrElement.value = displayValue;
    }
}

function loadNonRequiredSteps(doAsync){
    var params = getFormData();

    var steps_length = steps.length;
    for (var i = 0; i < steps_length; i++) {
        var stepId = steps[i];
        var s = wizardSteps[stepId];
        // If the page is not preloaded AND it is dirty and not required load it now.
        if (s) { //added by himanshu for clerk while first step is skipped it doesn't get properties need to chekc
            if (s.preloadPage === false && s.isDirty === true && !s.required) {
                s.isDirty = (s.isDirty) ? false : s.isDirty;
                if (doAsync) {
                    s.isAsync = true;
                }
                getElementHtml(params, stepId, doAsync, getPageUrl(s.url, stepId));
            }
        }
    }
    return true;
}

/**
 * This method will load all of the remaining steps which are marked as
 * preload="false", which are not required and have not been loaded yet.
 * The "isDirty" flag will be set to false.
 * The incomplete steps will be recalculated after this function is called.
 */
function loadAllRemainingNonRequiredSteps(){
    PTC.performance.setPageReady(); // Mark the page as ready before loading non-required steps
    return loadNonRequiredSteps(true);
}

function doResubmit(url, hiddenInputName){
    var postForm = document.createElement("FORM");
    postForm.id = "postFormForwarder";
    postForm.name = "postFormForwarder";
    postForm.method = "POST";
    postForm.action = url;

    var hiddenInput = document.createElement("INPUT");
    hiddenInput.type = "hidden";
    hiddenInput.name = hiddenInputName;
    hiddenInput.id = hiddenInputName;
    hiddenInput.value = $('externalFormData').value;

    postForm.appendChild(hiddenInput);
    document.body.appendChild(postForm);

    $('postFormForwarder').submit();
}

function defaultWizardKeyUpListener(event){
    var target = Event.element(event);
    if (event.keyCode == Event.KEY_RETURN || event.which == Event.KEY_RETURN) {
        if (!target || (target.tagName !== "SELECT" && target.tagName !== "TEXTAREA")) {
            if (isOKEnabled()) {
                // Submit the form if not submitted.
                if (!formSubmitted) {
                    var okButton = findButtonByActionID("PJL_wizard_ok");
                    if (okButton) {
                        //the onclick function may have extra logic than just submitting the page like submit now/submit later dialogs.
                        okButton.onclick.call(event);
                    }
                    else {
                        return onSubmit();
                    }
                }
            }
        }
    }
}

PTC.wizard.initialize = function(data){
    wizardTypeValue = data.wizardType;
    isWizardType = true;

    var stepData = data.steps;

    for (var i = 0; i < stepData.length; i++) {
        var stepId = stepData[i].stepId;
        wizardSteps[stepId] = new wizardStep(stepData[i]);
    }
};
/**
 * Will destory and purge the wizard document as much as possible
 * Fixes some memory in IE
 */
PTC.wizard.unloadWizard = function(){
  steps = null;
  wizardSteps = null;
  PTC.navigation.unloadShell();//unload wizard shell
  try {
      if (opener && opener.actionwin) {
          opener.actionwin = null;
      }
  }
  catch (e) {
      // If the opener has changed locations, might get access error setting the actionwin
  }
  Ext.EventManager.un(window, 'unload', PTC.wizard.unloadWizard);
  PTC.wizard.unloadWizard = null;
};

/**
 * constructor for a wizard step, used by the wizardTag
 */
PTC.wizard.loadWizard = function(data){
    PTC.performance.startWizardTimer(data[4].steps[0].stepId, /*initial wizard load*/true);
    var wizStepContents = Ext.get("wiz_step_contents");
    wizStepContents.setVisible(false);
    PTC.wizard.initialize(data[4]);
    if (PTC.navigation._attemptAggressiveCleanup) {
       Ext.EventManager.on(window, 'unload', PTC.wizard.unloadWizard);
    }
    Ext.onReady(function(){

        var titleBarButtons = [{
            xtype: 'tbtext',
            text: data[0]
        }, '->'];
        var helpButton = PTC.help.getHelpButtonConfig(data[1]);
        if (helpButton) {
            titleBarButtons.push(helpButton);
        }

        var titleBar = new Ext.Toolbar({
            id: 'titleBar',
            cls: 'x-panel-header wizard-title-text',
            items: titleBarButtons
        });


        var stepHeader = new PTC.wizard.StepLinksPanel({
            id: 'stephdr',
            border: false,
            cls: 'stepHeader',
            steps: window.steps

        });

        var embeddedHelpDiv = {
            border: false,
            xtype: 'panel',
            cls: 'clear_float',
            html: data[2]
        };

        var footerItems = [{
            xtype: 'tbtext',
            id: 'requiredfieldDisplay',
            text: data[3].requiredfieldDisplay
        }, '->'];
        data[3].items.each(function(item){
            footerItems.push(item);
        });

        var footer = new Ext.Panel({
            id: 'footerPanel',
            border: false,
            buttonAlign: 'left',
            fbar: footerItems
        });

        var contentArea = new PTC.jca.table.TableContainer({
            id: 'contentArea',
            contentEl: wizStepContents.dom,
            frame: true,
            baseCls: 'x-box',
            bufferResize: 100
        });

        var wizardPanel = new Ext.Panel({
            renderTo: 'wizard_viewport',
            baseCls: 'wizardPanel',
            items: [stepHeader, embeddedHelpDiv, contentArea, footer],
            tbar: titleBar
        });
        wizStepContents.setVisible(true);
        PTC.wizard.firstPostLoad();
        if(Ext.isGecko) { //True if the detected browser uses the Gecko layout engine (e.g. Mozilla, Firefox)
            //If parent window kept idle and try to open the wizard in firefox popup goes behind the parent
            //so calling focus on wizard window when wizard is ready
            setTimeout(function(){window.focus();}, 100);
        }
    });
};
/**
 * @namespace
 */
PTC.wizard.attributePanelLoader = function(){

    function getAttributePanel(){
        return Ext.get(PTC.wizard.getCurrentObjectHandle() + 'setAttributesTablePane');
    }

    return {
        /**
         * Clear the form data in the Attribute Panel div, so that type instance will be created correctly
         * on change of the type of the object to be created.
         */
        clearAttributePanelDiv: function(){
            var attributePanelDiv = getAttributePanel();
            if (attributePanelDiv && attributePanelDiv.dom) {
                PTC.navigation.overwrite(attributePanelDiv.dom, "");
            }
        },

        /**
         * Loads the Attribute table or panel, given the url of the attribute table.
         */
        loadAttributeTable: function(){
            PTC.wizard.fireEvent('beforeLoadAttributeTable');
            if (PTC.wizard.loadAttributeTableURL !== null) {
                try {
                    // SPR 2225744 disable ok/apply buttons so user can't attempt to submit wizard before reload completes
                    disableOkButton();

                    var objectHandle = PTC.wizard.getCurrentObjectHandle();

                    // verify all driver attributes have a value
                    var status = PTC.wizard.checkRequired(true, true, objectHandle + 'driverAttributesPane');
                    PTC.wizard.log.debug('PTC.wizard.checkRequired returned ', status);

                    // clear the div containing the attribute panel so the UIValidation doesn't valid these fields
                    this.clearAttributePanelDiv();

                    var validationId = 'defineItem';

                    var callAJAXValidation = true;
                    //for better performance skip validation the first time attributes display
                    //user cannot have entered invalid type/driver values yet
                    //Also if status is already false we are not going to render the attribute panel no further validation needed
                    var shouldValidate = objectHandle + "_loadAttributeTableCalled";
                    if(status && PTC.wizard.attributePanelLoader[shouldValidate]) {
                        callAJAXValidation = PTC.validation.callAJAXValidation(validationId, "BACK");
                        PTC.wizard.log.debug('PTC.validation.callAJAXValidation returned ', callAJAXValidation);
                    } else {
                        PTC.wizard.log.debug('PTC.validation.callAJAXValidation skipped since this is the first load of attributes table');
                    }
                    PTC.wizard.attributePanelLoader[shouldValidate] = true;

                    status = (status === true && callAJAXValidation);
                    if (status === true) {
                        PTC.wizard.attributePanelLoader.goAttributeTableProgress();
                        PTC.wizard.log.debug("PTC.wizard.loadAttributeTable URL: ", PTC.wizard.loadAttributeTableURL);
                        var url = PTC.wizard.loadAttributeTableURL;
                        if (objectHandle) {
                            url = PTC.wizard.loadAttributeTableURL + '?currentObjectHandle=' + objectHandle;
                        }
                        refreshElement(objectHandle + 'setAttributesTablePane', url, false, true, PTC.wizard.attributePanelLoader.loadAttributeTableOnSuccessful);
                    }
                    else {
                        PTC.wizard.log.debug('status is false. Masking attribute panel.');
                        PTC.wizard.attributePanelLoader.stopAttributeTableProgress();
                        PTC.wizard.attributePanelLoader.maskAttributePanel();
                    }
                }
                catch (e) {
                    PTC.wizard.log.debug("Exception encountered while loading attributes table ", e);
                }
            }
            return true;
        },

        /**
         * Success function called after ajax call for attribute table/panel has succeeded.
         */
        loadAttributeTableOnSuccessful: function() {
            PTC.wizard.attributePanelLoader.unmaskAttributePanel();
            PTC.wizard.fireEvent("afterLoadAttributeTable");

           //SPR Task: 6199329 Re-enable ok/apply buttons with a delay to give time for the attributeTable to render.
            setTimeout(function(){resetOkButton();}, 200);
        },

        /**
         * Puts a loading indicator in the area that the panel will show up.  This is the same loading indicator that is used for tables on infopage tabs.
         */
        goAttributeTableProgress: function() {
            var attributePanelDiv = getAttributePanel();
            if (attributePanelDiv && attributePanelDiv.dom) {
                var newHTML = '<div style="background: url(netmarkets/javascript/ext/resources/images/default/shared/blue-loading.gif) no-repeat center center; height: 100px">&nbsp;</div>';
                PTC.navigation.overwrite(attributePanelDiv.dom, newHTML);
            }
        },

        stopAttributeTableProgress: function() {
            var attributePanelDiv = getAttributePanel();
            if (attributePanelDiv && attributePanelDiv.dom) {
                PTC.navigation.overwrite(attributePanelDiv.dom, '');
            }
        },

        /**
         * Reloads the general attributes panel below the driver attributes.
         * Does nothing if the attributes table URL is not defined
         * If that URL is not defined, its assumed that the attributes are on a separate step.
         */
        reloadAttributesTable: function(){
            if (PTC.wizard.loadAttributeTableURL !== null) {
                PTC.wizard.attributePanelLoader.loadAttributeTable();
            }
            else {
                PTC.wizard.log.debug('reloadAttributesTable was not done as PTC.wizard.loadAttributeTableURL is null');

                //SPR Task: 6199329 Re-enable ok/apply buttons as not making server trip.
                resetOkButton();
            }
        },

        /**
         *  Masks the general attribute panel in create and edit wizards if it has contents
         */
        maskAttributePanel: function(){
            var attributePanelDiv = getAttributePanel();
            if (attributePanelDiv && attributePanelDiv.dom.hasChildNodes()) {
                attributePanelDiv.mask(getBundleString("com.ptc.netmarkets.util.utilResource.MISSING_REQUIRED_DRIVER_ATTRIBUTES"), 'panel-mask');
            }
        },
        /**
         *  Unmasks the general attribute panel in create and edit wizards if it has contents
         */
        unmaskAttributePanel: function(){
            var attributePanelDiv = getAttributePanel();
            if (attributePanelDiv && attributePanelDiv.dom.hasChildNodes()) { // needed to add this check
                attributePanelDiv.unmask();
            }
        }

    };
}();

//SPR 4835634 org picker value is not changing before the reload call because the event that changes it is after, so delay the reload call.
PTC.wizard.attributePanelLoader.reloadAttributesTable = PTC.util.delayAllCalls(PTC.wizard.attributePanelLoader.reloadAttributesTable, 200);
/**
 *  Utility to work with StepLinksPanel.
 *
 */
PTC.wizard.StepLinksPanelUtil = function(data){
    function getStepHeader(){
        return Ext.getCmp('stephdr');
    }

    return {

        repaintStepPanel: function(){
            getStepHeader().repaintStepLinkPanel();

        },
        //Fire bodyresize event on
        fireBodyResizeEvent: function(){
            var sh = getStepHeader();
            if (sh) {
                sh.fireEvent('bodyresize', 40);
            }
        },

        updateStepImages: function(){
            if (wizardTypeValue === 'wizard') {
                getStepHeader().updateStepIcons();
            }
        },

        alignActiveStep: function(){
            var header = getStepHeader();
            if (wizardTypeValue === 'wizard') {
                header.updateStepIcons();
            }
            else if (wizardTypeValue === 'clerk') {
                header.setActiveTab(currentStepStrName);
            }
            header.positionActiveStep(currentStepStrName);
        },

        attachOnClickHandlers: function() {
            var header = getStepHeader();
            if (header) {
                header.attachOnClickHandler();
            }
        }
    };
}();


/**
 *  PTC.wizard.StepLinksPanel extends Ext.Panel
 *  StepLinksPanel is a container that renders the step header for wizards.The stepNames need to be
 *  passed as the config with other panel specific config parameters.
 *
 * @extends Ext.Panel
 * @constructor
 * @param {Object} config The configuration options - stepNames and wizardType in addition to  panel config parameters
 */
PTC.wizard.StepLinksPanel = Ext.extend(Ext.Panel, {

    scrollEnabled: false,

    startPos: 0,

    scrollPosition: 0,

    scrollWidth: 0,

    stepComponents: null,

    stepIndex: 0,

    stepLinksPanel: null,

    leftScroller: null,

    rightScroller: null,

    firstStep: null,

    lastStep: null,

    /**
     * @param {Object} config -  The configuration options - stepNames and wizardType in addition to  panel config parameters.
     *       stepNames : steps in an array
     *       wizardType : type of Wizard - valid values - 'wizard' and  'clerk'
     */
    constructor: function(config){

        PTC.wizard.StepLinksPanel.superclass.constructor.call(this, config);

        this.stepNames = config.steps;

        //handle render event where the step components are added to the panel.
        this.on('render', function(headerPanel){
            //call parent render function to apply any render specific configurations.
            PTC.wizard.StepLinksPanel.superclass.render.apply(this, arguments);

            //Sets the template for the wizard and clerks step components.
            if (!this.wizard_ItemTpl) {
                var wizard_tt = new Ext.Template('<li class={stepLinkCls} id={stepLinkId} tabindex=0>' +
                '<div class={stepIconCls} id={stepIconId}>{stepNumber}</div>{stepName}</li>');
                wizard_tt.disableFormats = true;
                wizard_tt.compile();
                this.wizard_ItemTpl = wizard_tt;
            }

            if (!this.clerk_ItemTpl) {
                var clerk_tt = new Ext.Template('<li id="{stepTabId}">' +
                '<a class="x-tab-right" onclick="PTC.wizard.setActiveStep(\'{stepId}\');return false;"> <em class="x-tab-left">' +
                '<span class="x-tab-strip-inner {stepTabCls}"><span class="x-tab-strip-text">{stepName}</span></span>' +
                '</em></a></li>');

                clerk_tt.disableFormats = true;
                clerk_tt.compile();
                this.clerk_ItemTpl = clerk_tt;
            }

            this.renderLinkPanel(headerPanel);

        }, this);

        /**
         * Delay and combine multiple calls for these functions together to avoid timing issues.
         */
        this.attachOnClickHandler = PTC.util.delayAllCalls(this.attachOnClickHandler, 250);
        this.updateStepIcons = PTC.util.delayAllCalls(this.updateStepIcons, 250);
        this.afterLayoutHandler = PTC.util.delayAllCalls(this.afterLayoutHandler, 250);

        this.on('afterlayout', this.afterLayoutHandler, this, {
            delay: 200
        });
        this.on('afterlayout', function() {
            if (wizardTypeValue === 'wizard') {
                this.attachOnClickHandler();
                PTC.wizard.StepLinksPanelUtil.updateStepImages();
            }
        }, this, {single: true});

        //on resize of wizard, step header compoents are realigned and checked if scroll button are needed.
        this.on('bodyresize', function(){
            this.checkIfScrollButtonsNeeded();
            if (this.scrollEnabled && (this.scrollPosition < this.getMaxScrollPosition())) {
                this.scrollHeaderPanel();
            }
        }, this);
    },

    /**
     * on afterLayout, we cache all the attributes of the step components of step header component.
     */
    afterLayoutHandler: function(){
        this.strip = this.el;
        this.cacheStepComponentData();
    },

    /*
     * renders the link panel with step components.
     */
    renderLinkPanel: function(){

        if (steps.length === 1) {
            this.addClass('empty');
            return;
        }

        var components = [];
        this.scrollWidth = 0;

        this.stepComponents = components;
        this.stripWrapHolder = this.el.createChild({
            id: 'stripWrapHolder',
            cls: 'stepPanel'
        });

        if (wizardTypeValue === 'wizard') {
            this.stripWrap = this.stripWrapHolder.createChild({
                id: 'stripWrap',
                cls: 'x-header-strip-wrap',
                cn: {
                    tag: 'ul',
                    id: 'stripTabWrap',
                    cls: 'header-strip',
                    html: this.getStepComponentsHtml()
                }
            });

            var firstStep = PTC.wizard.getStepLink(this.stepNames[0]);
            var lastStep = this.findLastVisibleStep();

            if (firstStep === lastStep) {
                firstStep.addClass('single');
            }
            else {
                if (firstStep) {
                    firstStep.addClass('first');
                }

                if (lastStep) {
                    lastStep.addClass('last');
                }
            }
        }
        else if (wizardTypeValue === 'clerk') {
            this.stripWrap = this.stripWrapHolder.createChild({
                id: 'stripWrap',
                cls: 'x-tab-strip-wrap',
                cn: {
                    tag: 'ul',
                    id: 'stripTabWrap',
                    cls: 'x-tab-strip x-tab-strip-top',
                    html: this.getStepComponentsHtml()
                }
            });

        }


        this.strip = this.el;
        this.checkIfScrollButtonsNeeded();
        this.cacheStepComponentData();
        this.positionActiveStep(currentStepStrName);

        if (wizardTypeValue === 'clerk') {
            this.setActiveTab(this.activeTab);
        }
    },

    /**
     * finds and returns the last step that is not hidden
     */
    findLastVisibleStep: function(){
        var i = this.stepNames.length - 1;
        var lastStep = null;
        while (i >= 0 && lastStep === null) {
            var stepName = this.stepNames[i];
            var step = wizardSteps[stepName];
            if (step && !step.hidden) {
                lastStep = PTC.wizard.getStepLink(stepName);
            }
            i--;
        }
        return lastStep;
    },

    /**
     * creates a step component for each step.
     */
    getStepComponentsHtml: function(stepId){
        var html = '';
        var template;
        if (wizardTypeValue === 'wizard') {
            this.stepIndex = 0;
            template = this.wizard_ItemTpl;
        }
        else if (wizardTypeValue === 'clerk') {
            template = this.clerk_ItemTpl;
        }

        this.stepNames.each(function(stepId){
            if (!wizardSteps[stepId].hidden) {
                this.stepIndex++;
                var stepCmp = {};
                this.stepComponents[stepId] = stepCmp;
                var args = this.getTemplateArgs(stepId);
                html = html + template.apply(args);
                if (wizardTypeValue === 'clerk' && wizardSteps[stepId].isActive) {
                    this.activeTab = stepId;
                }
            }
        }, this);

        return html;
    },

    /**
     * get the arguments for the template to apply.
     */
    getTemplateArgs: function(stepId){
        if (wizardTypeValue === "wizard") {
            var stepIconCls = this.getClsClassForIcon(stepId);
            this.stepComponents[stepId].iconCls = stepIconCls;

            return {
                stepId: stepId,
                stepLinkId: stepId + '_link',
                stepIconId: stepId + '_icon',
                stepLinkCls: 'wizardstepLinks',
                stepIconCls: stepIconCls,
                stepNumber: this.stepIndex,
                stepName: wizardSteps[stepId].label
            };
        }
        else if (wizardTypeValue === "clerk") {
            return {
                stepId: stepId,
                stepTabId: stepId + '_tab',
                stepTabCls: 'stepClerkTab',
                stepName: wizardSteps[stepId].label
            };

        }

    },

    /**
     * get class to be applied for the icon that indicates the status of the step, given a step id.
     */
    getClsClassForIcon: function(stepId){
        var stepIconCls;

        if (wizardSteps[stepId].isActive) {
            stepIconCls = 'stepIcon-active';
        }
        else if (wizardSteps[stepId].visited) {
            stepIconCls = 'stepIcon-visited';
        }
        else {
            stepIconCls = 'stepIcon-nonVisited';
        }
        return stepIconCls;
    },


    /*
     * Gets the panel that hold the step components
     */
    getHeaderPanel: function(){
        return Ext.get('stripTabWrap');
    },
    /**
     * Repainting the StepLinkPanel in case of dynamically adding or removing of the step..
     */
    repaintStepLinkPanel: function(){
        this.stepIndex = 0;
        Ext.get('stripWrapHolder').remove();
        this.renderLinkPanel();
        this.updateStepIcons();

    },

    /**
     * Scrolls the stepLinkPanel by the average step length.
     */
    onScrollRight: function(){
        var len = this.stepNames.length;
        var scroll = this.scrollWidth / len;
        this.scrollPosition = this.scrollPosition - scroll;
        this.scrollHeaderPanel();

    },

    /**
     * Scrolls the stepLinkPanel by the average step length.
     */
    onScrollLeft: function(){
        var len = this.stepNames.length;
        var scroll = this.scrollWidth / len;
        this.scrollPosition = this.scrollPosition + scroll;
        this.scrollHeaderPanel();

    },

    /**
     * creates right and left scroll buttons.
     */
    createScrollBars: function(el){
        var height = el.getHeight();
        this.leftScroller = el.insertFirst({
            id: 'stepLeftScroller',
            tag: 'div',
            cls: 'stepLeftScroller'
        });

        this.leftScroller.on({
            'click': this.onScrollLeft,
            scope: this
        });

        this.leftScroller.addClassOnOver('ele-mouse-over');
        this.leftScroller.setHeight(height);
        this.rightScroller = el.insertFirst({

            id: 'stepRightScroller',
            tag: 'div',
            cls: 'stepRightScroller'
        });

        this.rightScroller.on({
            'click': this.onScrollRight,
            scope: this
        });

        this.rightScroller.addClassOnOver('ele-mouse-over');
        this.rightScroller.setHeight(height);
    },

    /**
     * Hides the scroll buttons.
     */
    hideScrollBars: function(){
        this.scrollEnabled = false;
        var sw = Ext.get('stripWrap');
        if (sw) {
            Ext.get('stripWrap').dom.style.left = this.startPos + 'px';
            var scrollLeftCmp = Ext.get('stepLeftScroller');
            if (scrollLeftCmp !== 'undefined' && scrollLeftCmp !== null) {
                scrollLeftCmp.hide();
            }

            var scrollRightCmp = Ext.get('stepRightScroller');
            if (scrollRightCmp !== 'undefined' && scrollRightCmp !== null) {
                scrollRightCmp.hide();
            }
        }
    },

    /**
     * show the scroll buttons.
     */
    showScrollBars: function(){

        this.scrollEnabled = true;
        var scrollLeftCmp = Ext.get('stepLeftScroller');
        var scrollRightCmp = Ext.get('stepRightScroller');
        if ((scrollLeftCmp !== 'undefined' && scrollLeftCmp !== null) ||
        (scrollRightCmp !== 'undefined' && scrollRightCmp !== null)) {
            scrollLeftCmp.show();
            scrollRightCmp.show();
        }
        else {
            this.createScrollBars(this.strip);
            this.scrollPosition = this.startPos;
            this.scrollHeaderPanel();

        }

    },

    /**
     * Move the links panel to given direction and position.
     */
    scrollHeaderPanel: function(){

        if (this.scrollPosition <= this.getMaxScrollPosition()) {
            this.scrollPosition = this.getMaxScrollPosition();
        }

        if (this.scrollPosition >= this.startPos) {
            this.scrollPosition = this.startPos;
        }
        this.updateScrollButtons();

        Ext.get('stripWrap').dom.style.left = this.scrollPosition + 'px';
    },

    /**
     * get the maximum scroll position
     */
    getMaxScrollPosition: function(){
        var windowWidth = getWindowWidth();

        // the displayable window width is whole width of the window minus 2 times size of scroll bars
        return windowWidth - this.scrollWidth - 80;
    },

    /**
     * determine if the step link icon should be clickable or not
     * @param {String} stepId
     */
    isStepIconClickable: function(stepId) {
        var value = !wizardSteps[stepId].hidden &&
                    ((stepId === currentStepStrName) ||
                        isOKEnabled() || wizardSteps[stepId].visited ||
                            PTC.wizard.isPreviousStepActive(stepId));
        return value;
    },

    /**
     * Update step icon on changing the status of the step.
     */
    updateStepIcon: function(stepId){
        if (wizardTypeValue == "wizard") {
            var stepIcon = Ext.get(stepId + '_icon');
            if (stepIcon) {
                var stepIconCls = this.getClsClassForIcon(stepId);
                stepIcon.replaceClass(this.stepComponents[stepId].iconCls, stepIconCls);
                this.stepComponents[stepId].iconCls = stepIconCls;
            }
            var stepLink = PTC.wizard.getStepLink(stepId);
            if (stepLink) {
                if (wizardSteps[stepId].isActive) {
                    stepLink.addClass('active');
                } else {
                    stepLink.removeClass('active');
                }
                if (this.isStepIconClickable(stepId)) {
                    stepLink.isClickable = true;
                    stepLink.addClass('enabled');
                } else { // need to remove enabled class
                    stepLink.isClickable = false;
                    stepLink.removeClass('enabled');
                }
            }
        }
    },

    /**
     * Update all step icons upon changing the status of the steps.
     */
    updateStepIcons: function(){
        this.stepNames.each(function(stepId){
            this.updateStepIcon(stepId);
        }, this);
    },

    /**
     * attach listeners to the step components so that it navigates to the respective step
     */
    attachOnClickHandler: function(){
        var thisItem = this;
        this.stepNames.each(function(stepId){
            if (!wizardSteps[stepId].hidden) {
                var stepLink;
                stepLink = PTC.wizard.getStepLink(stepId);
                if (stepLink) {
                    stepLink.stepId = stepId;
                    PTC.wizard.registerClickHandler(stepLink, stepId);
                }
            }
        });
    },

    /**
     * checks if the scroll buttons need to be displayed.
     */
    checkIfScrollButtonsNeeded: function(){
        if (getWindowWidth() < this.scrollWidth + 10) {
            this.showScrollBars();
        }
        else {
            this.hideScrollBars();
        }
    },

    /**
     * Enables or disables the scroll buttons based on the current scroll position.
     */
    updateScrollButtons: function(){
        var pos = this.scrollPosition;
        if (pos === 0) {
            this.leftScroller.addClass('scroller-disabled');
            this.rightScroller.removeClass('scroller-disabled');
        }
        else if (pos === this.getMaxScrollPosition()) {
            this.leftScroller.removeClass('scroller-disabled');
            this.rightScroller.addClass('scroller-disabled');
        }
        else {
            this.leftScroller.removeClass('scroller-disabled');
            this.rightScroller.removeClass('scroller-disabled');
        }
    },


    /**
     * cache the step component data.
     */
    cacheStepComponentData: function(){
        var compSize = 0;
        var components = this.stepComponents;
        this.stepNames.each(function(item){

            var stepDiv;
            if (wizardTypeValue === 'wizard') {
                stepDiv = PTC.wizard.getStepLink(item);
            }
            else if (wizardTypeValue === 'clerk') {
                stepDiv = Ext.get(item + '_tab');
            }

            if (stepDiv !== undefined && stepDiv !== null) {
                compSize += stepDiv.getWidth();

                components[item].Xaxis = stepDiv.getX() - this.scrollPosition;
                components[item].YAxis = stepDiv.getY();
                components[item].width = stepDiv.getWidth();
            }
        }, this);

        this.scrollWidth = compSize;
        this.positionActiveStep(currentStepStrName);

    },

    /**
     * sets the styling for the active tab
     */
    setActiveTab: function(stepId){
        var activeTabLink = Ext.get(this.activeTab + '_tab');
        if (activeTabLink !== 'undefined' && activeTabLink !== null) {
            activeTabLink.removeClass('x-tab-strip-active');
        }

        var stepLink = Ext.get(stepId + '_tab');
        stepLink.addClass('x-tab-strip-active');
        this.activeTab = stepId;
    },

    /**
     * position the active step, if the active step is not visible.It checks if the active step
     * component is visible the window. It gets the position of the div that is in the left
     * corner and the right corner of the window. If the active step is outside the limits , the
     * scroll position is calculated so that the active step is in the middle.
     */
    positionActiveStep: function(stepId){
        if (stepId === '') {
            return;
        }

        if (this.scrollEnabled) {

            var x = this.stepComponents[stepId].Xaxis + this.stepComponents[stepId].width;
            var leftCornerPoint = this.scrollPosition * -1;
            var rightCornerPoint = (this.scrollPosition * -1) + (getWindowWidth() - 20);
            if (((x - this.stepComponents[stepId].width) < leftCornerPoint) ||
            x > rightCornerPoint) {
                this.scrollPosition = (getWindowWidth() / 2) - x;
                this.scrollHeaderPanel();
            }

        }

        return true;
    },

    /**
     * This is to disable the text selection on double click.
     */
    disableSelection: function(){
        var target = $("stephdr");
        if (typeof target.onselectstart != "undefined") { //IE route
            target.onselectstart = function(){
                return false;
            };
        }
        else if (typeof target.style.MozUserSelect != "undefined") { //Firefox route
            target.style.MozUserSelect = "none";
        }
        else { //All other route (ie: Opera)
            target.onmousedown = function(){
                return false;
            };
        }

        target.style.cursor = "default";
    }

});

/**
 * Register the click handler for a step link
 * @param {Ext.Element} stepLink the Ext.Element that represents the the step link
 * @param {String} stepId the id of the step to register the click event on
 */
PTC.wizard.registerClickHandler = function(stepLink, stepId){
    // Because we attach events after layout of the wizard, which can be fired several times,
    // we need to unregister the stepLinkHandler prior to attaching it, so we don't end up
    // with multiple calls into our listener.
    stepLink.un("click", PTC.wizard.stepLinkClickHandler);
    stepLink.on("click", PTC.wizard.stepLinkClickHandler, stepLink);
    stepLink.un("keypress", PTC.wizard.stepLinkKeyPressHandler);
    stepLink.on("keypress", PTC.wizard.stepLinkKeyPressHandler, stepLink);

};

/**
 * The handler for the step link click event
 * @param {Ext.EventObject} event
 * @param {Ext.Element} target the element that was the target of the event
 */
PTC.wizard.stepLinkClickHandler = function(event, target){
    if (this.isClickable) {
        PTC.wizard.setActiveStep(this.stepId);
    }
    else {
        return false;
    }
};

/**
 * The handler for the step link enter key event
 * @param {Ext.EventObject} event
 * @param {Ext.Element} target the element that was the target of the event
 */
PTC.wizard.stepLinkKeyPressHandler = function(event, target){
    var keynum = event.getKey();
    if (keynum === event.RETURN) {
        PTC.wizard.stepLinkClickHandler.call(this, event, target);
    }
};


/**
 * @return {String} the object handle for the current wizard step,
 *      empty string is returned if there is no object handle for the current step or if the step is not found
 */
PTC.wizard.getCurrentObjectHandle = function(){
    var step = wizardSteps[getCurrentStep()];
    if (step && step.objectHandle) {
        return step.objectHandle;
    }
    //Step not found, just return empty string to be safe.
    //This API is getting called from the attribute panel rendering, and attribute panels are not always in wizards...
    return '';
};


/**
 * Finishes creating the wizard, shows the first step, initializes the buttons and set the isReady flag to true.
 */
PTC.wizard.firstPostLoad = function(){
    try {
        // if the global steps variable is  null, return because the wizard is
        // exiting with error message.
        if (!steps) {
            return;
        }
        if (steps.length === 1) { // This is a one step wizard i.e. dialog, hence do not display next, prev buttons
            var nextButton = findButtonByActionID("PJL_wizard_next");
            if (nextButton) {
                nextButton.hide();
            }
            var prevButton = findButtonByActionID("PJL_wizard_previous");
            if (prevButton) {
                prevButton.hide();
            }
        }
        PTC.external.init();
        initPopupForm();
        if (startStep) {
            stepIndex = findStepIndex(startStep);
        }

        var steps_length = steps.length;
        for (var i = 0; i < steps_length; i++) { // Initialize isComplete flag
            if ((steps.length > 1) && (wizardTypeValue == "wizard")) {
                wizardSteps[steps[i]].isComplete = false;
            }
            else {

                wizardSteps[steps[i]].required = true;
                wizardSteps[steps[i]].isAsync = true;
                wizardSteps[steps[i]].isComplete = true; // ok button disable in last step issue resolved
                wizardSteps[steps[i]].isDirty = false;
            }
        }

        currentStepStrName = steps[stepIndex];
        wizardSteps[currentStepStrName].preloadJS();
        wizardSteps[currentStepStrName].postloadJS();
        wizardSteps[currentStepStrName].isComplete = true;
        wizardSteps[currentStepStrName].isDirty = false;
        recalcIncomplete();
        if (steps.length > 1) {
            if (wizardTypeValue === "wizard") { //added by himanshu to enable ok button on start up of clerk
                if (incompleteSteps > 0 && steps.length > 1) {
                    disableOkButton();
                } else {
                    enableOkButton(); //SPR 2055367 with CDRL packages there was a case where it was defaulted to disabled wrong here. Added this case to resolve the SPR.
                }
                resetNextBackButton(currentStepStrName);
            }
        }
        getStyleFromId(currentStepStrName + "Pane").display = "inline";
        // updates the hidden wizard header with the current step title (for section 508)
        updateWizardContentHeader();

        //update the header description too. SPR 1969928
        updateEmbeddedText();

        // gpurohit: Adjust the height of wizard content area, so that the navigation buttons are always visible.
        adjustWizardContentAreaHeight(); //need to see what we have to do in case of clerk
        //loading first step content, it was put in a div and needs to move into the ext layout.
        //Probably long term we will want to change this some, but it's loaded with a jsp today so this will work for now
        PTC.wizard.isReady = true;
        PTC.checkAndFireReady();
    }
    finally {
        //Hide the required label if no required attributes exists. Story B-45268.
        //Needed to do in finally block so that attribute table/panel is loaded first and then we look for required attribute.SPR 2026664
        updateRequiredLabel.defer(10); //defer for slow tables etc.
        PTC.wizard.isReady = true;
        PTC.wizard.fireEvent('wizardLoadComplete');
    }
};

/**
 * Gets the Dom element for the wizard step link
 * @param {String} stepName
 * @return {Ext.Element} the Ext element wrapper for the step link
 */
PTC.wizard.getStepLink = function(stepName){
    return Ext.get(stepName + '_link');
};

/**
 * Try to focus on the first editable element in the page
 * This uses only required elements because for most wizards, the first element is required anyway
 * App teams can write their own focus code to get something better, its really easy in each case to get
 * it right but hard to do generically since items can be hidden or knowing which item comes before the others.
 *
 * To override in a specific case,  expect app teams to register their own function on PTC.isReady and remove this
 * one (PTC.un('ready', PTC.wizard.focusOnReadyFunc);  or override/wrap this function.
 * @return {boolean} if an element was focused
 */
PTC.wizard.focusFirstInput = function(){
    // Instead of getting all visible input elements on the current step, get required ones since it saves all kinds of logic
    // to figure our which is visible and first.  This seems to work well enough for the generic case
    var inputs = Ext.DomQuery.jsSelect('.required', Ext.getDom(currentStepStrName));
    for (var i = 0, l = inputs.length; i < l; i++) {
        var item = inputs[i];
        var tagname = item.tagName.toLowerCase();
        var fly = Ext.fly(item);
        if ((tagname === 'input' || tagname === 'select' || tagname === 'textarea') && fly.isVisible(true)) {
            fly.focus(50); // defer 100 slightly here for some cases in IE.
            return true;
        }
    }
    return false;
};

/**
 * Attempt a few tries at finding and focusing on the first input element. Will try for ~2 seconds
 * (considering the time required to load other non dynamic steps in the wizard)
 * @param {Number} trycount - to keep it from running forever but not have strigent timing issues.
 */
PTC.wizard.focusOnReadyFunc = function(trycount){
    if (!trycount || trycount <= 0) {
        trycount = 1;
    }
    var focused = PTC.wizard.focusFirstInput();
    PTC.wizard.log.debug('Try ' + trycount + ' focusFirstInput ' + focused);
    if (!focused && trycount < 10) {
        trycount++;
        PTC.wizard.focusOnReadyFunc.defer(200, null, [trycount]);
    }
};

PTC.onReady(function(){
    if (isWizardWindow()) {
        PTC.wizard.focusOnReadyFunc();
    }
});

/**
 * Will try to show a split pane component on a wizard.  May need to call this if the split pane component
 * is not on the first wizard step.
 * @param {String} panelIdToRenderTo the Id of the Ext.Panel that the split pane is component rendered in.
   @param {Object} panelSize JSON object that has a 'left' and/or a 'right' attribtute for the split pane component.  ({left: 20, right:80})
 * @param {String} orientation either 'vertical' or 'horizontal'
 */
PTC.wizard.showSplitPaneOnWizardStep = function(panelIdToRenderTo, panelSize, orientation) {
    var panel = Ext.getCmp(panelIdToRenderTo);
    if (!panel) {
        return;
    }

    // step may be rendered as hidden, so need to call doLayout so component calculates size correctly
    panel.doLayout();

    var twoPanesId = PTC.navigation.contentTabID + "_twoPanes_" + orientation;

    // If the resizePanes method was called when it is not visible,
    // it will not have correct sizes, so need to call again.
    var resized = PTC.navigation.resizePanes(Ext.getCmp(twoPanesId), panelSize, orientation);
    if (resized) {
        // if resized, will need to layout the container again.
        // TODO - figure out a better workflow for the two-pane rendering in the wizard, that doesn't
        // rely on having to call doLayout and size calculations as much.  Maybe smarter ExtJS 4 layouts will help us?
        panel.doLayout();
    }
};

/**
 *Fires the afteraction event on the necessary target component
 * @param {PTC.action.FormResult} formResult
 * @param {String} windowName of the window where the action response is consumed
 * @param {boolean} forwardedToNewURL flag to know whether or not to fire afterAction event (true if window was forwarded to new URL)
 * @return true to continue processing and false to stop
 */
PTC.wizard._fireOnAfterAction = function(formResult, windowName, forwardedToNewURL){

    var result = true;

    // fire the 'afteraction' event on the action target
    if(!forwardedToNewURL) {
        var target = PTC.action.actionTarget || PTC.action.getActionTarget(windowName);
        if(!target && formResult) {
            target = formResult.getTableId();
        }
        PTC.wizard.log.debug("action target is: ", target);
        if( typeof target === 'string') {
            var table = PTC.util.getCmpInAllPTCnameSpaces(target);
            if(!table) {
                table = PTC.util.getCmpInAllPTCnameSpaces(PTC.jca.table.Utils.getUnformattedTableId(target));
            }
            target = table;
        }
        if (!target) {
            //The checkin action launched from the Edit action is target-less.   Perhaps the default listener in the page
            //could handle this?  The mainform is a good likely candidate to start the event but under multiple actions running
            //at the same time this could be the wrong target.
            var dom = Ext.get(getMainForm()).up('.x-panel');
            if (dom && dom.id) {
               target = PTC.util.getCmpInAllPTCnameSpaces(dom.id);
            }
        }

        /* SPR 2204437: If target ext component is stale i.e. without having any DOM references,
           get the latest reference so that afteraction event will bubble up properly in owner containers. */
        if(target && !target.doc) {
            target = PTC.util.getCmpInAllPTCnameSpaces(target.id);
        }

        if(target) {
            result = target.fireEvent('afteraction', formResult);
            if(!result) {// stop going up if someone tells
                result = false;
            }
        }
        else {
            PTC.action.log.warn('Could not find a target object for the afterAction Event', formResult.actionName, windowName, formResult);
        }
    }
    PTC.action.actionTarget = null;
    PTC.action.removeActionTarget(windowName);
    var allWindows = PTC.util.getAllPTCWindows();
    var iframes = PTC.util.getAllPTCIframes();
    allWindows = allWindows.concat(iframes);

    var i = allWindows.length;
    while (i--) {
       var win = allWindows[i];
       if(win && win.PTC.action) {
           win.PTC.action.fireEvent('objectsaffected', formResult);
       }
    }
    return result;
};

/**
 * Fires the afteraction event on either this or the opener window for wizards
 * Will call the event in the opener window for wizards
 * @param {PTC.action.FormResult} formResult
 * @return true to continue processing and false to stop
 */

PTC.wizard.fireOnAfterAction = function(formResult) {
    var wizOpener = getPopupOpenerWindow();

    //To step of out the psb iframe, we used to always call getWindow but it may not be gauranteed on all
    // pages that call into jca actions, this maintains backwards compatibility while not enforcing
    // pages to have to implement more functions than necessary.
    try {
        if (wizOpener && typeof wizOpener.getWindow === 'function') {
            wizOpener = wizOpener.getWindow();
        }
    } catch (ex) {
       //accessing properties on opener may cause an issue
    }
    // handle form results with LOAD_OPENER_URL or FORWARD info in it
    var forwarded = PTC.wizard._handleForwardFormResult(formResult, wizOpener);

    try {
        if(PTC.wizard.finished && isWizardWindow() && wizOpener && wizOpener.PTC) {
            return wizOpener.PTC.wizard._fireOnAfterAction(formResult, window.name, 'LOAD_OPENER_URL' === forwarded);
        } else {
            return PTC.wizard._fireOnAfterAction(formResult, window.name, 'FORWARD' === forwarded);
        }
    } catch (e) {
        // accessing properties on opener may cause an issue even if checking for null
        PTC.log.error(e);
    }
    return true;
};


/**
 * This will handle cases where the FormResult contains a URL to forward onto.  FormResults that contain oids to add/update/delete are handled
 * by the 'afteraction' and 'objectsaffected' event listeners.
 * @param {PTC.action.FormResult} formResult
 * @param {window} wizOpener - the opener of this wizard window (may be undefined for in page actions)
 * @return {String} 'FORWARD' if we forwarded the current window to a new URL, 'LOAD_OPENER_URL' if the opener was forwarded, false otherwise
 */
PTC.wizard._handleForwardFormResult = function(formResult, wizOpener) {
    var result = false;
    var nextAction = formResult.nextAction;

    // if there's a url on the FormResult, this is equivalent to the next action being set to LOAD_OPENER_URL or FORWARD
    if((nextAction === 2 /* LOAD_OPENER_URL */ || nextAction === 6 /* FORWARD */) && formResult.URL) {
        var win = getWindow();
        result = 'FORWARD';
        if(nextAction === 2 /* LOAD_OPENER_URL */ && wizOpener && isWizardWindow()) {
            win = wizOpener;
            result = 'LOAD_OPENER_URL';
        }
        var url = formResult.URL;
        // redirectRecipient is for file download
        if(url.indexOf("redirectRecipient") < 0) {
            win.PTC.navigation.loadContent(url, true);
        } else {
            win.location.href = url;
        }

        // try to unselect items only in the table where the action occurred, however if the tableID is not passed
        // on the form result unselect items in all tables
        if(formResult.getTableId()) {
            jsca.unSelectAll(null, formResult.getTableId());
        } else {
            unSelectAll();
        }
    }

    // remove these legacy properties, we don't want downstream listeners to rely on them
    formResult.URL = undefined;
    formResult.nextAction = undefined;

    return result;
};
/**
 * Closes the lightbox or wizard depending on the type
 */
PTC.wizard.close= function() {
    if (PTC.lightbox.isLightbox(window)) {
        PTC.lightbox.deactivate({lbWindow: self});
    }
    else {
        wfWindowClose();
    }
};

/**
 * Loads an object's Attribute Panel (only when it's necessary) in a wizard.  The Attributes Panel will get loaded if there is a default value
 * defined for the 'Type' property and the Attributes Panel has not already been requested. This is called when the wizard is initially loaded.
 *
 * @param {String} objectHandle for the object whose Attributes will be reloaded
 * @param {String} urlForDriverAttributes URL to use to reload the new Attributes Panel
 * @internal
 */
PTC.wizard.loadAttributesPanel = function(objectHandle, urlForDriverAttributes) {
    if(!Ext.isDefined(objectHandle) || !urlForDriverAttributes) {
        PTC.wizard.log.warn('Not able to reload the Attributes Panel because the objectHandle or the urlForDriverAttributes params were not provided', {objectHandle: objectHandle, urlForDriverAttributes: urlForDriverAttributes});
    }

    var typesListEl = Ext.getDom(objectHandle + 'createType');
    if(typesListEl && typesListEl.length === 0) {
       // show a message and close the wizard if there are no types available
       JCAAlert("com.ptc.core.ui.errorMessagesRB.NO_TYPES");
       wfWindowClose1();
       return;
    }

    var typeFromTypePickerEl = Ext.getDom(objectHandle + 'typeFromTypePicker');
    if(typeFromTypePickerEl) {
        // reset the itemTypeInstanceId to whatever is selected in the type picker
        // if the selected type is not the "--Select a Type--", load the driverAttributes & attributes panel 
        if(typeFromTypePickerEl.value !== '') {
            var itemTypeInstanceIdEl = document.getElementById(objectHandle + "itemTypeInstanceId");

            // reset the itemTypeInstanceIdEl to whatever is selected in the type picker
            itemTypeInstanceIdEl.value = typeFromTypePickerEl.value;
            // retrieve the content for the driver attributes panel
            refreshDriverAttributes(urlForDriverAttributes);
        }
    } else {
        // this else block is for wizards that do not include the type picker
        //    (for example, the New Cad document wizard from Workspace table)
        //    do ajax call to update the hidden input to correct type instance id for whatever was in typeEle
        PTC.wizard.log.debug('wizard does not include standard type picker at top. Seems that custom type picker is used.');

        if (typesListEl) {
            resetTypeInstanceId(typesListEl.value, objectHandle);
        } else {
            PTC.wizard.log.warn('createType hidden field for object type not found? resetTypeInstanceId could not be called');
        }
        // retrieve the content for the driver attributes panel, which triggers load of attributes panel
        refreshDriverAttributes(urlForDriverAttributes);
    }
};


