Ext.ns('PTC.wvs');

PTC.wvs = function(){

var logger = log4javascript.getLogger("PTC.wvs");

return {

    isFireFox: ((navigator.userAgent.indexOf('Firefox') > -1) ? true : false),
    isChrome: (navigator.userAgent.indexOf('Chrome') > -1 && navigator.userAgent.indexOf('Edge') == -1) ? true : false,
    isIE: (navigator.userAgent.indexOf("MSIE") != -1 || navigator.userAgent.indexOf("Trident") != -1) ? true : false,
    is64bitIE: (navigator.userAgent.indexOf("Trident") != -1 && navigator.userAgent.indexOf("Win64") != -1) ? true : false,
    isEdge: (navigator.userAgent.indexOf('Edge') > -1) ? true : false, 
    isMac: (navigator.userAgent.indexOf('Mac') > -1) ? true : false,

// This function will return Windchill Base URL.
getBaseURL: function()  {
            if ('baseURI' in document) {
                return document.baseURI;
            }
            else {
                var baseTags = document.getElementsByTagName ("base");
                if (baseTags.length > 0) {
                    return baseTags[0].href;
                }
                else if (location.href.length>0) {
                var url = location.href;
        		var pathname = location.pathname;
        		var index1 = url.indexOf(pathname);
        		var index2 = url.indexOf("/", index1 + 1);
        		var baseLocalUrl = url.substr(0, index2);
        		return baseLocalUrl + "/";
                }
		else {
		console.error ("The function getBaseURL() is not able to return the Windchill base URL. \n It is returning the full URL:" + window.location.href);
		}
            }
        },
    /**
     * Get the WVS Gateway URL - Used for AJAX calls to server side methods.
     *
     * serverClass - Full class name of the server side class that contains the method to invoke. The class 
     *               must implement RemoteAccess. e.g "com.ptc.windchill.enterprise.wvs.batchClash.utils.BatchClashHelper"
     *
     * methodToInvoke - Method that exists in the serverClass that takes two arguments - HttpServletRequest _request and 
     *                  HttpServletResponse _response. e.g "updateModelFromFormData" in BatchClashHelper.
     *
     */
    getWVSGatewayURL: function(serverClass, methodToInvoke) {
        var pageNoParam = '';
        var queryString = location.search.substring(1);
        if (PTC.isDefined(location.search) && queryString.length > 0) {
            var params = queryString.split("&");
            for (var i = 0; i < params.length; i ++) {
                if (params[i].indexOf('unique_page_number=') == 0) {
                    pageNoParam = params[i] + '&';
                }
            }
        }

        return getBaseHref() + 'netmarkets/jsp/wvs/wvsGW.jsp?' + pageNoParam + 'class=' + serverClass + '&method=' + methodToInvoke;
    },
   
    validateIsInteger: function(component, value, errorMsgRB) {    
        var isInteger_re = /^\s*(\+|-)?\d+\s*$/; 
        var testValue;
        
        if ( value != null ){
            if( String( value ).search (isInteger_re) == -1 ) {
                JCAAlert(errorMsgRB);
                return false;
            }
        }
        else if( component.value != null){
            if( String( component.value ).search (isInteger_re) == -1 ) {
                JCAAlert(errorMsgRB);
                setTimeout("setSelect(\"" + component.name + "\");", 0);
                return false;
            } 
        }
        else{
            return false;
        }
        return true;
    },

    validateIsGreaterThanEqualZero: function(component, value, errorMsgRB) {
        var aValue; 
        
        if ( value != null ){
            aValue = parseFloat(value);
            if (aValue < 1 || isNaN( aValue) ) {
                JCAAlert(errorMsgRB);
                return false;
            }
        }
        else if( component != null ){
            aValue = parseFloat(component.value);

            if (aValue < 1 || isNaN( aValue) ) {
                JCAAlert(errorMsgRB);
                setTimeout("setSelect(\"" + component.name + "\");", 0); 
                return false;
            }
        }
        else{
            return false;
        }
        return true;
    },
    
    waitForTestToComplete: function(testFunc, expectedValue, milliSec, callback) {
    
        while (testFunc() !== expectedValue) {
            setTimeout(function() {
                PTC.wvs.waitForTestToComplete(testFunc, expectedValue, milliSec, callback);
            }, milliSec);
            return;
        }
        // Condition finally met, invoke the callback
        callback();
    },
      
    log: function(message) {
           logger.trace(message);
    },
    
    error: function(message) {
           logger.error(message);
    }
};
}();

/**
 * Define a name space for methods related to accessing WVSProperties
 */
PTC.wvs.properties = {};

/**
 * Get the value for a given WVS Property.
 *
 * @param property - A known WVS property to retrieve the value.
 */
PTC.wvs.properties.getProperty = function(property) {
   
    // Check the cache for the property value to avoid un-necessaray AJAX calls.  
    var propertyVal = PTC.attributeHelper.get("WVSProperties." + property); // Check the cache.
    if (propertyVal === undefined) {
        var url = getBaseHref() + 'netmarkets/jsp/wvs/wvsGW.jsp?property=' + property;
        new Ajax.Request( 
            url,
            {
                asynchronous: false,
                method: 'get',
                parameters: {},
                onSuccess: function(transport) {
                    var result = eval("(" + transport.responseText + ")");
                    if (result != null && result.property_value != null) {
                        propertyVal = result.property_value;
                        
                        PTC.wvs.log(property + "=" + propertyVal);
                        // Cache the value of the property.
                        PTC.attributeHelper.set("WVSProperties." + property, propertyVal);
                    }
                },

                onFailure: function() {
                    PTC.wvs.error("Error: An error occurred when attempting to perform an ajax call to " + url);
                }
             }
        ); // End new Ajax.Request
    }
    else {
        PTC.wvs.log("retrieved from cache -> " + property + "=" + propertyVal);
    }
    return propertyVal;
};


PTC.wvs.webgl = function(){

    // ------------------------
    // Private APIs / Variables
    // ------------------------
    
    var logger = log4javascript.getLogger("PTC.wvs.webgl");
     
    // Maintain a cache for each session that is created for a specific DIV.
    var sessionCache = new Array();
    
    var contextMenuEventHandlerCache = new Array();
    var mouseDownPointerX = 0;
    var mouseDownPointerY = 0;
    
    // Create a new session for a specified DIV. If a session has already been
    // provided for a DIV, the existing session is returned rather than creating
    // a new one.
    function createSession(divID) {
        logger.trace("in create session for ID: " +divID);
        
        var returnSession = null;
        if (divID in sessionCache) {
            if(logger.isDebugEnabled()) {
                console.time("CreateSession-recreate_called");
            }
           logger.trace("session exists for DIV: " + divID);
           returnSession = sessionCache[divID];

           var canvas = getCanvas(returnSession);
           if (canvas == null) {
              logger.trace("canvas does NOT exist for cached session. Deleting session.");
              ThingView.DeleteSession(returnSession);
              returnSession = undefined;
              returnSession = ThingView.CreateSession(divID);
              returnSession.SetTopBottomBackgroundColor(0xFFFFFFFF, 0xFFFFFFFF);
              addContextMenuEvent(divID, returnSession); // Add any registered context menu events.
              setDefaultOptions(returnSession);
 
              sessionCache[divID] = returnSession;
           }
           else {
              logger.trace("canvas exists for cached session");
           }
           if(logger.isDebugEnabled()) {
               console.timeEnd("CreateSession-recreate_called");
           }
        }
        else {

            if(logger.isDebugEnabled()) {
                console.time("CreateSession-first_time_called");
            }
           logger.trace("creating new session for ID: " + divID);
           returnSession = ThingView.CreateSession(divID);
           returnSession.SetTopBottomBackgroundColor(0xFFFFFFFF, 0xFFFFFFFF);
           addContextMenuEvent(divID, returnSession); // Add any registered context menu events.
           setDefaultOptions(returnSession);               

           sessionCache[divID] = returnSession;

           if(logger.isDebugEnabled()) {
           console.timeEnd("CreateSession-first_time_called");
           }
        }
        return returnSession;
    }

    function initializeThingViewInstance(callBack) {

       if (typeof ThingView == 'undefined') {
          logger.trace("Loading thingview.js");

          // The PTC.navigation.loadScript fails to execute the loaded thingview.js because
          // the file contains a "use strict" declaration at the top of the file. Instead,
          // the following will ensure the JS is loaded and the ThingView instance is created
          // in global space.          
          var head = document.getElementsByTagName('head').item(0);
          var id = document.createElement("SCRIPT");
          var loaderLib = "wtcore/jsp/wvs/js/ptc/thingview/thingview.js";
                
          id.src = loaderLib;
          head.appendChild(id);
          id.onload = callBack;
       }
       else {
          callBack();
       }
    }
    
    function addContextMenuEvent(divID, sessionRef) {
        
        if (divID in contextMenuEventHandlerCache) {
                  
            // Obtain a reference to the canvas element that is associated
            // to the given session.
            canvas1 = getCanvas(sessionRef);
            
            if ( typeof canvas1 !== 'undefined') { 
                // Add a mouse down listener to capture the location of the mouse
                // pointer on the canvas when the right click takes place.
                canvas1.addEventListener('mousedown', function(e){
                    logger.trace(e.pointerX());
                    logger.trace(e.pointerY());
                    mouseDownPointerX=e.pointerX();
                    mouseDownPointerY=e.pointerY();
                    
                    if(e.which ==2) { // disable middle mouse button click to prevent scrolling
                        e.preventDefault();
                    }
                }, false);
                    
                canvas1.addEventListener('contextmenu', function(e){
                    logger.trace(e.pointerX());
                    logger.trace(e.pointerY());
              
                    if (e.pointerX() == mouseDownPointerX && e.pointerY() == mouseDownPointerY) {
                        var eventHandlers = contextMenuEventHandlerCache[divID];
                        for (var i = 0; i < eventHandlers.length; i++) {
                            eventHandlers[i](e); // Invoke the provided event handler.
                        }
                    }
                }, false);
            }   
            
        }
    }
    
    // Hide the div tag so that it is not shown on the html page 
    // used to hide either the 2d div tag or the 3d div tag
    // depending on what url is present
    function hideDivTag(divID){
        logger.trace("hide DIV: " + divID);
        document.getElementById(divID).style.visibility = 'hidden';
        document.getElementById(divID).style.display = 'none';
    }

    // Set default options on the session 
    function setDefaultOptions(sessionRef) {
        try {            
            logger.trace("setDefaultOptions ");                   
            //Set Navigation Mode to CREO_VIEW
            initializeNavigationMode(sessionRef);
            // Set Orthographic (ie: Disable Perspective)
            sessionRef.SetOrthographicProjection(1.0);
            // Disable drag mode
            sessionRef.SetDragMode(Module.DragMode.NONE);
            // Allow rotations more than 180.0 degrees
            sessionRef.SetDoNotRoll(false);
            // Show Spin Center
            sessionRef.ShowSpinCenter(true);
        }
        catch(e) {
            logger.error("Failed loading default view options: " + e);
        }
    }
    
    /**
     * Finds and sets the navigation mode from wvs property \"wvs.webgl.navigationmode\".
     * If mode is invalid then default CREO_VIEW mode will be used. 
     */
    function initializeNavigationMode(sessionRef) {
        
        var modeStr = PTC.wvs.properties.getProperty("wvs.webgl.navigationmode");
        var modeObj = Module.NavMode[modeStr.toUpperCase()];
        
        if(modeObj === undefined) {
            logger.error("\"" + modeStr + "\" is not a valid navigation mode. Switching back to default.");
            sessionRef.SetNavigationMode(Module.NavMode.CREO_VIEW);
        }
        else {
            logger.debug("Navigation mode is now set to " + modeStr);
            sessionRef.SetNavigationMode(modeObj);
        }
        
    }
    
    function getCanvas(sessionRef) {
        if (typeof Module !== 'undefined') {
            var session_html = Module.castToSession_html(sessionRef);
            var canvasID = session_html.GetCanvasName();
            return document.getElementById(canvasID);
        }
    }
    
    return {

    // ------------------------
    // Public APIs / Variables
    // ------------------------
    
    thingViewInitSuccess: false,
    
    log: logger,
    
    /**
     * Get a reference to a 3D viewer session uniquely identified by a DIV ID. A new session
     * will be created if one doesn't exist for a DIV ID.
     * 
     * @param {String} A DIV ID to obtain a 3D viewer session.
     * @param {function} A callback function to be invoke when the session has been created or an existing one found in
     *                   the cache. The callback function will be invoked passing a reference to the session.
     *
     */
    getSession: function(divID, callBack) {
      
       initializeThingViewInstance(function() {
          logger.debug("ThingView is defined. File version = " + ThingView.GetFileVersion());
          if (PTC.wvs.webgl.thingViewInitSuccess == false) {
              logger.trace("ThingView.init - begin initialization");
              if(logger.isDebugEnabled()) {
                  console.time('ThingView.Init');
              }
              ThingView.init("wtcore/jsp/wvs/js/ptc/thingview/", function() {
                  ThingView.SetInitFlags(
                          Module.ThingViewInitFlags.LOAD_PVS_PROPERTIES.value |
                          Module.ThingViewInitFlags.CLEAR_UNUSED_SHAPES_ON_DESTRUCTION.value |
                          Module.ThingViewInitFlags.ENABLE_HIDDEN_RC_SHAPE_INSTANCE.value |
                          Module.ThingViewInitFlags.USE_ADVANCED_SELECTION_MANAGER.value |
                          Module.ThingViewInitFlags.LOAD_ITEMSLIST.value |
                          Module.ThingViewInitFlags.ENABLE_INSTANCE_SYSTEM_PROPERTIES.value |
                          Module.ThingViewInitFlags.ENABLE_FEATURE_MANAGER.value
                      );
                  if(logger.isDebugEnabled()) {
                  console.timeEnd('ThingView.Init')
                  }

                 PTC.wvs.webgl.thingViewInitSuccess=true;
                 callBack(createSession(divID));
                 if(isIE) {
                     ThingView.SetHighMemoryUsageValue(10);
                 } else {
                     ThingView.SetHighMemoryUsageValue(300);
                 }                 
              });
          }
          else {
              logger.trace("ThingView.init is already been initialized.");
              callBack(createSession(divID));
          }
       });
    },
    
    /**
     * Get a reference to an existing session.
     *
     * @param {String} A DIV ID referring to an existing 3D viewer session.
     *
     */
    getSessionRef: function(divID) {
       return sessionCache[divID];
    },
    
    /**
     * Register a context menu event listener for a viewer defined by a given DIV ID.
     *
     * @param {String} A DIV ID referring to a unique viewer that already has been created or will be created.
     * @param {function} A function to be invoked when the context event is fired i.e. Right
     *                   mouse button. When rendering the 3D viewer, the function will only be invoked if the
     *                   mouse down and mouse up locations are the same.
     */
    addContextMenuEventListener: function(divID, eventHandler) {
    
        if (divID in contextMenuEventHandlerCache) {
            contextMenuEventHandlerCache[divID].push(eventHandler);
        }
        else {
            var eventHandlers = new Array();
            eventHandlers.push(eventHandler);
            contextMenuEventHandlerCache[divID] = eventHandlers;
        }
        
        // Ensure a session already created for the given DIV has
        // the event added.
        if (PTC.wvs.webgl.getSessionRef(divID) != null) {
            addContextMenuEvent(divID, PTC.wvs.webgl.getSessionRef(divID));
        }
    },
    
    /**
     * Renders a Thumbnail Viewer at a specified location.
     *
     * @param {String} A DIV ID referring to the location in the DOM to insert the thumbnail viewer at.
     * @param {String} A URL to a 3D thumbnail file (PVT). Can be set to null when rendering a 2D viewer only.
     * @param {String} A URL to a 2D thumbnail file (JPG)
     * @param {String} A width attribute denoting the width of the viewer in pixels or a percentage i.e. "260px" or "100%"
     * @param {String} A height attribute denoting the height of the viewer in pixels or a percentage i.e. "150px" or "100%"
     * @param {Object} An object containing 3D viewing options including background color and orientation.
     * @param {String} A URL denoting an on click action
     * @param {function} A callback function to be invoke when the viewer has been rendered. Assuming a 3D URL has been
     *                   specified to render the WebGL viewer, the callback function will be invoked passing a reference
     *                   to the session.
     *
     */
    insertThumbnailViewerAt: function(divID, thumb3durl, thumb2durl, width, height, options3d, doAction, callBack) {
        
        logger.trace("in insertThumbnailAt"); 
        logger.trace("divID = " + divID);
        logger.trace("thumb3durl = " + thumb3durl);
        logger.trace("thumb2durl = " + thumb2durl);
        logger.trace("width = " + width);
        logger.trace("height = " + height);
        logger.trace("options3d = " + options3d);
        logger.trace("doAction = " + doAction);
        
        if( width.indexOf("%") < 0 && width.indexOf("px") < 0 ) width += "px";
        if( height.indexOf("%") < 0 && height.indexOf("px") < 0 ) height += "px";
        var divID_3d = divID + "_3d";
        var divID_2d = divID + "_2d";
        var htmlstring = "";
        
        var div_2d = document.getElementById(divID_2d);
        if(div_2d == null ){ 
            logger.trace("Creating 2d div.");
            htmlstring  += '<div id="'+divID_2d+'" style="position:relative;top:0;left:0;border-width:0px;border-style:none;width:'+width + ';height:'+height+'"></div>';
        } else {
            logger.trace("2d div already in DOM.");
            div_2d.style.width=width;
            div_2d.style.height=height;
        }
        
        var div_3d = document.getElementById(divID_3d);
        if(div_3d == null ){  
           logger.trace("Creating 3d div."); 
           htmlstring += '<div id="'+divID_3d+'" style="position:relative;top:0;left:0;border-width:0px;border-style:none;width:'+width + ';height:'+height+'"></div>';
        } else {
            logger.trace("3d div already in DOM.");
            div_3d.style.width=width;
            div_3d.style.height=height;
        }
        
        // Add the new divs to the DOM
        if (div_2d == null && div_3d == null)
           document.getElementById(divID).innerHTML = htmlstring;
        
        // Either render the 2d or the 3d image
        if(thumb3durl) {
            // render the 3d thumbnail using webgl
            try {
                logger.trace("Loading the 3d image.");
                
                PTC.wvs.webgl.render3dThumbnailAt(divID_3d, thumb3durl, options3d, function(sessionRef){                   
                    // Adding an event listener to the Canvas so that when left click, Creo View is launched
                    var canvas1 = getCanvas(sessionRef);
                    var clickCount = 0;
                    if(!PTC.wvs.isMac) {
                    canvas1.addEventListener('click', function(event) {
                        
                        if(event.which === 1 ){ 
                            clickCount++;
                            if (clickCount === 1) {
                                singleClickTimer = setTimeout(function() {
                                    clickCount = 0;
                                    window.location=doAction;
                                }, 400);
                            } else if (clickCount === 2) {
                                clearTimeout(singleClickTimer);
                                // No action done for double click
                                // The library will zoom for the double click
                                clickCount = 0;
                                }
                            }
                        }, false);
                    }

                    // Ensure RMB click will perform a Zoom All if the mouse position is
                    // unchanged from mouse down to mouse up
                    PTC.wvs.webgl.addContextMenuEventListener(divID_3d, function(e) {
                        PTC.wvs.webgl.getSessionRef(divID_3d).ZoomView(Module.ZoomMode.ZOOM_ALL, 1000.0);
                        
                    });

                    // Calling the passed in callback with the newly created session
                    callBack(sessionRef);
                });
                
                // Hide the 2d div
                hideDivTag(divID_2d);
            } catch (err){
                logger.error("Error loading the 3d library so loading 2d image.", err);
                
                // Hide the 3d div 
                hideDivTag(divID_3d);
                
                // Add the 2d image the the 2d div tag for rendering
                document.getElementById(divID_2d).innerHTML = '<A HREF="'+doAction+'"><IMG SRC="'+thumb2durl+'" style="border-height:0;border-width:0;border-style:none;" width=100% height=100% ></IMG></A>';
            }
        } else {
            // Hide the 3d div 
            hideDivTag(divID_3d);
            
            // Add the 2d image the the 2d div tag for rendering
            logger.trace("No 3d image was provided, loading 2d image.");            
            document.getElementById(divID_2d).innerHTML = '<A HREF="'+doAction+'"><IMG SRC="'+thumb2durl+'" style="border-height:0;border-width:0;border-style:none;" width=100% height=100% ></IMG></A>';
        }
    },

    /**
     * Renders a 3D Thumbnail Viewer at a specified location.
     *
     * @param {String} A DIV ID referring to the location in the DOM to insert the thumbnail viewer at.
     * @param {String} A URL to a 3D thumbnail file (PVT).
     * @param {Object} An object containing 3D viewing options including background color and orientation.
     * @param {function} A callback function to be invoke when the viewer has been rendered. Assuming a 3D URL has been
     *                   specified to render the WebGL viewer, the callback function will be invoked passing a reference
     *                   to the session.
     *
     */        
    render3dThumbnailAt: function(divID, thumbnailUrl, options3d, callBack) {
        PTC.wvs.webgl.getSession(divID, function(sessionRef) {

            try {
                //Stop selecting the model 
                sessionRef.AllowModelSelection(false); 
                //Stop selecting individual parts 
                sessionRef.AllowPartSelection (false);
                //Stop showing gnomon
                sessionRef.ShowGnomon(false); 
                //Set canvas color
                PTC.wvs.webgl.setCanvasColor(sessionRef, options3d.backgroundColor);
            } 
            catch (e) {
                logger.error("setOptions failed: " + e);
            }         

            SimpleModelClass = Module.Model.extend("Model", {
                OnLoadComplete: function () {
                    
                    sessionRef.model=this;                   
                    try {
                        PTC.wvs.webgl.setOptions3d(sessionRef, options3d);               
                        // Set zoom
                        sessionRef.ZoomView(Module.ZoomMode.ZOOM_ALL, 1000.0);
                        
                        
                    }
                    catch (e) {
                        logger.error("Failed doing Zoom View: " + e);
                    }
                    callBack(sessionRef);
                }
            });

            if (sessionRef.model != null) {
                sessionRef.RemoveAllModels(true);
            }


            mymodel = new SimpleModelClass();
            mymodel.type="Model";
            sessionRef.AddModel(mymodel);
            try {
                var widgetParams = new Module.NameValueVec();
                widgetParams.push_back({name:"sourceUrl",value:thumbnailUrl});
                widgetParams.push_back({name:"baseUrl",value:getBaseURL()});

                mymodel.LoadFromWCURL(widgetParams, true, true);
            } 
            catch (e) {
                logger.error("Failed loading thumbnail URL: " + e);
            }         
        });
    },
    
    /**
     * Set 3D viewer options
     *
     * @param {Session} A reference to a session to have the options applied to
     * @param {Object} An object containing 3D viewing options including background color and orientation.
     */
    setOptions3d: function(sessionRef, options3d) {
        try {
            if(options3d) {
                // Set zoom Background color
                if(options3d.backgroundColor) {
                    
                    var bgColorNum = parseInt(options3d.backgroundColor, 16);
                    var bgGradColorNum = parseInt(options3d.backgroundColor, 16);
                    if(options3d.backgroundGradientColor != null && options3d.backgroundGradientColor !== "" && options3d.backgroundGradientColor !== "null") {
                        var bgGradColorNum = parseInt(options3d.backgroundGradientColor, 16);
                    }
                    
                    logger.trace("bgColorNum = " + bgColorNum);
                    logger.trace("bgGradColorNum = " + bgGradColorNum);
                    
                     // First param should be background color (default - white) that appears in the top
                    // and second should be gradient color which will appear at the bottom.
                    // This is to match the gradient appearance as in the 2D image
                     sessionRef.SetTopBottomBackgroundColor(bgColorNum,bgGradColorNum);

                }
                // Set view orientation
                if(options3d.orientation) {
                    var s = options3d.orientation.split(" ");
                    logger.trace("s = " + s);
                    logger.trace("s.size() = " + s.size());
                    if(s.size() == 9){
                        sessionRef.SetViewMatrix(s[0] + " " + s[1] + " " + s[2] + " 0 " + 
                                                 s[3] + " " + s[4] + " " + s[5] + " 0 " + 
                                                 s[6] + " " + s[7] + " " + s[8] + " 0 " +
                                                 "0 " +       "0 " +       "0 " + "1" );
                    }
                    else if(s.size() == 16){
                        sessionRef.SetViewMatrix(options3d.orientation);
                    }
                }                   
            }
        }
        catch(e) {
            logger.error("Failed loading 3D view options: " + e);
        }
    },

    /**
     * Set the color on the associated session canvas.
     *
     * @param {Session} A reference to a session to have the color applied to
     * @param {Object} An object referring to a hex color.
     */    
    setCanvasColor: function(sessionRef, hexColor) {
        if(hexColor) {
            var r = hexColor >> 24 & 0xFF;
            logger.trace("r = " + r);
            var g = hexColor >> 16 & 0xFF;
            logger.trace("g = " + g);
            var b = hexColor >> 8 & 0xFF;
            logger.trace("b = " + b);

            var color = ("rgb(" + r + "," + g + "," + b + ")");
            logger.trace("color = " + color);
            getCanvas(sessionRef).style.backgroundColor = color;            
        }
    },

    /**
     * Is the WebGL library enabled for the Thumbnail Navigation client
     *
     * @return {boolean} True if enabled
     */
    isEnabledForThumbnailNav: function() {
       var useWebGL = true;
       if (PTC.wvs.isIE) {
          if ("true" === PTC.wvs.properties.getProperty("wvs.thumbnailnav.use.plugin.ie")) {
             useWebGL = false;
          }
       }
       else if (PTC.wvs.isFireFox) {
          if ("true" === PTC.wvs.properties.getProperty("wvs.thumbnailnav.use.plugin.firefox")) {
             useWebGL = false;
          }
       }
       else {
          if ("true" === PTC.wvs.properties.getProperty("wvs.thumbnailnav.use.plugin.other")) {
             useWebGL = false;
          }
       }
       return useWebGL;
    },
    
    /**
     * Is the WebGL library enabled for the Visualization Tab
     *
     * @return {boolean} True if enabled
     */
    isEnabledForVisTab: function() {
       var useWebGL = true;
       if (PTC.wvs.isIE) {
          if ("true" === PTC.wvs.properties.getProperty("wvs.visualizationtab.use.plugin.ie")) {
             useWebGL = false;
          }
       }
       else if (PTC.wvs.isFireFox) {
          if ("true" === PTC.wvs.properties.getProperty("wvs.visualizationtab.use.plugin.firefox")) {
             useWebGL = false;
          }
       }
       else {
          if ("true" === PTC.wvs.properties.getProperty("wvs.visualizationtab.use.plugin.other")) {
             useWebGL = false;
          }
       }
       
       return useWebGL;
    },    
    
    /**
     * Returns the cache size for IE, Firefox or other browsers set in their respective wvs property.
     *   IE : use "wvs.visualizationtab.webgl.cache.size.ie"
     *   FireFox :  use "wvs.visualizationtab.webgl.cache.size.firefox"
     *   Other Browsers : use "wvs.visualizationtab.webgl.cache.size.other"
     *   
     *   If the above ones are not set, then the global cache size set from "wvs.visualizationtab.webgl.cache.size" is used.
     * 
     */
    getCacheSizeForVizTab: function() {
       
        var browserCacheSize;
        
        if(PTC.wvs.isIE) {
            browserCacheSize = parseInt(PTC.wvs.properties.getProperty("wvs.visualizationtab.webgl.cache.size.ie"));
        }
        else if (PTC.wvs.isFireFox) {
            browserCacheSize =  parseInt(PTC.wvs.properties.getProperty("wvs.visualizationtab.webgl.cache.size.firefox")); 
         }
        else {
            browserCacheSize =  parseInt(PTC.wvs.properties.getProperty("wvs.visualizationtab.webgl.cache.size.other"));
        }
        
        if(browserCacheSize >0) {
            return browserCacheSize;
        }
        
        return parseInt(PTC.wvs.properties.getProperty("wvs.visualizationtab.webgl.cache.size"));
        
    }
    
        
    
}
}();

/*
 * Namespace for the action that sends content files of a Representable to the Browser.
 */
PTC.wvs.ListRepFiles = {};

/**
 * Extends the Ext.menu.Item class when creating a menu containing the content files of a Representation.
 * ListRepFilesController establishes many of the attributes of this object.
 */
PTC.wvs.ListRepFiles.ContentMenu = Ext.extend(Ext.menu.Item, {
    initComponent: function() {
        
        // In order to pass the Representation to the Controller, we need to determine where we've been
        // invoked from. This action is only accessible as a row action of a Representation
        // in the Representations and Markups Tree Table or as a row action of a Representation on the
        // Clipboard.
        var theOid = null;
        var t = Ext.getCmp('repsAndMarkupsTableId');
        if (typeof(t) == 'undefined') {
            t = Ext.getCmp('clipboardList');
        }
        
        // The row that has the focus must be a Representation (guaranteed by the validator of the
        // action - ListRepFilesValidator).
        if (typeof(t) != 'undefined') {
            var rowIndex = PTC.jca.table.Utils.getFocusedRowIndex(t);
            if (!isNaN(rowIndex) && (rowIndex >= 0)) {
                var record = t.getStore().getAt(rowIndex);
                theOid = record.data.oid;
            }
        }

        var params = "";
        if (theOid != null) {
           params = params + "?oid=" + theOid + "&cacheBustParam=" + new Date().getTime();
        } else {
            PTC.wvs.log("ERROR PTC.wvs.ListRepFiles.ContentMenu UNABLE to find Representation");
        }
        var options = {
            parameters: params
        };

        this.menu = new PTC.menu.DynamicMenu({
            id: 'listRepFilesMenu',
            loadOnce: true,
            bubbleEvents: ['remove'],
            requestOptions: options,
            requestUrl: getBaseHref() + 'ptc1/listRepFiles/'
        });
        PTC.wvs.ListRepFiles.ContentMenu.superclass.initComponent.call(this);
    }
});
Ext.reg('listRepFiles', PTC.wvs.ListRepFiles.ContentMenu);

/**
 * Extends Ext.menu.Item class to represent one Content File of the Representation.
 * When the Item is clicked, the corresponding file is sent to the Browser.
 */
PTC.wvs.ListRepFiles.ContentMenuItem = Ext.extend(Ext.menu.Item, {
    mClickUrl: null, // The Controller populates this parameter which is the URL
                     // of the WVS servlet (SaveWVSObjectHelper.saveWVSObject() that
                     // writes the file to the Browser.

    initComponent: function() {
        
        this.listeners = {
            'click': function(item, e) {
                if (item.mClickUrl != null) {
                    // If not Chrome, we make the request in a new Window.
                    if (!Ext.isChrome) {
                        var newwindow = wfWindowOpen(item.mClickUrl, "_blank", "resizable=1,height=690,width=780,scrollbars=0,toolbar=0,menubar=0,location=0,directories=0,status=0");
                        newwindow.focus();
                    } else {
                        window.location.href = item.mClickUrl;
                    }
                } else {
                    alert("ERROR: url for click is missing");
                }
            }
        };
        PTC.wvs.ListRepFiles.ContentMenuItem.superclass.initComponent.call(this);
    }
});
Ext.reg('listRepFilesInput', PTC.wvs.ListRepFiles.ContentMenuItem);


