XmlObject.switchAttributePanelToReloadScreen = function (htmlId) {
	var attributePanelDiv = Ext.get(htmlId);
	if(attributePanelDiv && attributePanelDiv.dom)  {
    	var newHTML = "<div style=\"background: url(netmarkets/javascript/ext/resources/images/default/shared/blue-loading.gif) no-repeat center center; height: 100px\">&nbsp;</div>";
    	PTC.navigation.overwrite(attributePanelDiv.dom, newHTML);
	}
};

XmlObject.reloadHtmlElement = function (htmlId, url, extraParams, doFade, doAsync, successFunc, failFunc) {
	doAsync = doAsync || false;
	if (doFade === null || doFade === undefined) {
	    doFade = true;	
	}
	var mainForm = getMainForm();
	var formData = Ext.lib.Ajax.serializeForm(mainForm);
	formData = formData + "&portlet=component";
	if (extraParams === null || extraParams === undefined) {
		extraParams = "";
	}
	if (extraParams != "") {
		formData = extraParams + "&" + formData; // ˝«extraParams·ĹÔÚÇ°ĂćŁ¬±ŁÖ¤extraParamsÖĐµÄ˛ÎĘý»á¸˛¸ÇformDataÖĐµÄ±íµĄ˛ÎĘý
	}
	var contextDropDownURL = getPageUrl(url, htmlId);
	getElementHtml(formData, htmlId, doAsync, contextDropDownURL, doFade, successFunc, failFunc);
};

/**
 * ×˘ŇâŁşŐâ¸öşŻĘýŇŃľ­±»XmlObject.refreshAttributePanel()Čˇ´úŁ¬˝öŇňÎŞ±ŁłÖŔúĘ·łĚĐňµÄĽćČÝĐÔ¶řĽĚĐř±ŁÁô,
 * ÇëĘąÓĂXmlObject.refreshAttributePanel()˝řĐĐĚć´ú!!!
 *
 * Ë˘ĐÂÓĂ»§´«ČëµÄ˛ÎĘýÖ¸¶¨µÄAttributePanel,ĘľŔýŁş
 * XmlObject.reloadAttributePanel("ext.ptc.xworks.examples.taskform.ExampleApplicationForm1AttributePanelBuilder", "attributePanel", {}, function() {});
 * 
 * @param {string} attributePanelBuilder - ±ŘĐëŁ¬Ö¸¶¨attributePanelBuilderµÄID
 * @param {string} componentId - ±ŘĐëŁ¬Ö¸¶¨AttributePanelµÄcomponentId
 * @param {string|object} extraParams - żÉŃˇµÄ,·˘ËÍµÄHTTPÇëÇó˛ÎĘý
 * @param {function} successCallback  - żÉŃˇŁ¬Ö´ĐĐłÉą¦şóµÄ»Řµ÷şŻĘý
 * @author lizhou
 */

XmlObject.reloadAttributePanel = function(attributePanelBuilder, componentId, extraParams, successCallback) {
	XmlObject.refreshAttributePanel(attributePanelBuilder, componentId, extraParams, true, true, successCallback, function() {});
};

/**
 * Ë˘ĐÂÓĂ»§´«ČëµÄ˛ÎĘýÖ¸¶¨µÄAttributePanel
 * 
 * @param {string} attributePanelBuilder - ±ŘĐëŁ¬Ö¸¶¨attributePanelBuilderµÄID
 * @param {string} componentId - ±ŘĐëŁ¬Ö¸¶¨AttributePanelµÄcomponentId
 * @param {string|object} extraParams - żÉŃˇµÄ,·˘ËÍµÄHTTPÇëÇó˛ÎĘý
 * @param {boolean} doAsync - żÉŃˇŁ¬AjaxÇëÇóĘÇ·ń˛ÉÓĂŇě˛˝·˝Ę˝
 * @param {boolean} doFade - żÉŃˇŁ¬ĘÇ·ń˛ÉÓĂ˝Ą±äµÄĎÔĘľĐ§ąűŔ´ĎÔĘľAttributePanel
 * @param {function} successCallback  - żÉŃˇŁ¬Ö´ĐĐłÉą¦şóµÄ»Řµ÷şŻĘý
 * @param {function} failCallback - żÉŃˇŁ¬Ö´ĐĐĘ§°ÜşóµÄ»Řµ÷şŻĘý
 */
XmlObject.refreshAttributePanel = function(attributePanelBuilder, componentId, extraParams, doAsync, doFade, successCallback, failCallback) {
	if (componentId == undefined || componentId == "" || componentId == null) {
		componentId = "attributePanel";
	}
	var divId = componentId + "_" + attributePanelBuilder + "__AttributesTablePaneOuter_";
	// In Windchill 10.2, the id of div html for AttributePanel has a random number suffix, so ...
	// Windchill 11.0 no this issue!
	tableDiv = $$("div[id^='" + divId + "']"); // Use Prototype to select div html elements
	//console.log(typeof tableDiv); //output object
	if (tableDiv && tableDiv.length > 0) {
		for (var i = 0; i < tableDiv.length; i++) {
			//console.log(tableDiv[i].id);
			divId = tableDiv[i].id;
			break;
		}
	} else {
		window.alert("Cannot find a div html element:" + divId);
		return;
	}

	var url = "/ptc1/comp/" + attributePanelBuilder;
	XmlObject.switchAttributePanelToReloadScreen(divId);
	
	// ´¦ŔíextraParams
	var extraParamsString = "";
	extraParams = extraParams || "";
	if (typeof extraParams == "string") {
		extraParamsString = extraParams;
	}
	if (typeof extraParams == "object") {
		extraParamsString = Object.toQueryString(extraParams);
	}
	if (!typeof doAsync === 'boolean') {
		doAsync = true; // Ä¬ČĎ˛ÉÓĂŇě˛˝µÄ·˝Ę˝ÇëÇó
	}
	if (!typeof doFade === 'boolean') {
		doFade = true; // Ä¬ČĎ˛ÉÓĂŇě˛˝µÄ·˝Ę˝ÇëÇó
	}
	if (!typeof successCallback === 'function') {
		successCallback = function() {};
	}
	if (!typeof failCallback === 'function') {
		failCallback = function() {};
	}
	XmlObject.reloadHtmlElement(divId, url, extraParamsString, doFade, doAsync, successCallback, failCallback);
};

