/**
 * Ěć»»OOTBµÄshowFullText()şŻĘý,˝âľö2¸öÎĘĚâŁşIEÖĐÎŢ·¨µ÷Őű´°żÚ´óĐˇŁ¬Ä¬ČĎµÄ´°żÚąýĐˇµÄÎĘĚâ
 *
 * @param {Object} displayText - ĐčŇŞĎÔĘľµÄHTMLÄÚČÝ
 * @param {Object} encoded - HTMLÄÚČÝĘÇ·ńŇŃľ­±»±ŕÂëÁË
 */
XmlObject.showFullText = function(displayText, encoded) {
	if (encoded) {
		displayText = unescape(displayText);
	}

	// Need to fix the links to open in the parent window.  When openning the link in the showFullText window the page is distorted and not resizeable.
	//Fixed for SPR: 1865559 [RA]
	displayText = displayText.replace(/href\s*=\s*\"(.*?)\"/g, "target='_parent' onclick='opener.location=\""+getBaseHref()+"$1\";window.close();' href='#'");

	var htmlString=""+
		"<html>"+
		"<head>"+
		"<title>"+ "&nbsp" +"</title>"+
		"</head>"+
		"<body>" +
		"<div align=\"left\">" +
		"<table width=\"90%\">" +
		"<tr>" +
		"<td id='moreLinkDisplayText'>" + displayText + "</td>" +
		"</tr>" +
		"</table>" +
		"</div>" +
		"</body>" +
		"</html>";

	var newWindow = window.open('','popupwindow','width=640,height=400,scrollbars=yes,resizable=yes');
	var moreLinkDisplayTextTableCell = newWindow.document.getElementById('moreLinkDisplayText');
	if(moreLinkDisplayTextTableCell){
		moreLinkDisplayTextTableCell.innerHTML = displayText;
	}
	else{
		newWindow.document.write(htmlString);
	}
};

/**
 * żŘÖĆ±í¸ńÖĐµÄÁĐĘÇ·ńĎÔĘľ
 *
 * @param {string} tableId - tableµÄID
 * @param {boolean} hidden - ÁĐĘÇ·ńŇţ˛Ř,ĐčŇŞŇţ˛ŘÔňÉčÖĂÎŞtrue
 * @param {string} columnIds - ĐčŇŞŇţ˛ŘµÄÁĐµÄID,Ö§łÖ¶ŕ¸öID
 */
XmlObject.setTableColumnHidden = function(/*string*/ tableId, /*boolean*/ hidden, /*string...*/ columnIds) {
	if (!tableId) {
		console.log("ERROR:tableId must be specified!");
		return;
	}
	var table = tableUtils.getTable(tableId);
	hidden = hidden || false;
	if (arguments.length < 3) {
		console.log("ERROR:columnIds must be specified!");
	}
	var columnModel = table.getColumnModel();
	for (var i = 2; i < arguments.length; i++) {
		var columnId = arguments[i];
		if (!columnId) {continue};
		var columnCount = columnModel.getColumnCount();
		for (var idx = 1; idx <= columnCount; idx++) {
			var column = columnModel.getColumnAt(idx);
			if (!column) continue;
			if (columnId == column.id) {
				columnModel.setHidden(idx, hidden);
				break;
			}
		}
	}
};

/**
 * ÇĐ»»´«ČëµÄtableId¶ÔÓ¦µÄ±í¸ńµÄ»î¶ŻĘÓÍĽÎŞ´«ČëµÄÖ¸¶¨µÄĘÓÍĽ
 *
 * @param {string} tableId - tableµÄID
 * @param {boolean} force - ÎŢÂŰµ±Ç°µÄ»î¶ŻĘÓÍĽĘÇ˛»ĘÇ´«ČëµÄĘÓÍĽŁ¬¶ĽË˘ĐÂĘÓÍĽÖŘĐÂĽÓÔŘ±í¸ń
 * @param {string} viewNames - ÓÉÓÚ˛»Í¬ÓďŃÔĎÂĘÓÍĽĂűłĆ˛»Ň»ŃůŁ¬żÉŇÔÖ§łÖ´«Čë¶ŕÖÖÓďŃÔĎÂµÄĘÓÍĽĂűłĆŁ¬Ö»ŇŞČÎŇâĆĄĹäĽ´˝řĐĐĘÓÍĽÇĐ»»
 */
XmlObject.changeTableView = function(/*string*/ tableId, /*boolean*/ force, /*string...*/ viewNames) {
	if (!tableId) {
		return;
	}
    var viewComboBox = PTC.jca.table.Utils.getTableViewComboBox(tableId);
    if (!viewComboBox) {
    	return; // Table¸ů±ľľÍĂ»ÓĐĘÓÍĽĎÂŔ­ÁĐ±í
    }
    if (arguments.length < 3) {
    	console.log("ERROR:new view names must be specified!");
    }
    var viewArray = [];
    for (var i = 2; i < arguments.length; i++) {
    	viewArray.push(arguments[i]);
    }
    for (var i = 0; i < viewArray.length; i++) {
    	if (viewArray[i] == viewComboBox.defaultActionName && !force) {
    		// Čçąűµ±Ç°ĘÓÍĽŇŃľ­ĘÇĎëÇĐ»»µ˝µÄĘÓÍĽŁ¬ÇŇ˛»ÇżÖĆĽÓÔŘŁ¬ÔňÍËłö˛»ÇĐ»»
    		return;
    	}
    }
    viewComboBox.items.each(function(item) {
    	for (var i = 0; i < viewArray.length; i++) {
	    	if (viewArray[i] == item.text) {
	    		item.handler(); // µ÷ÓĂitemÉĎµÄhandler˝řĐĐĘÓÍĽÇĐ»»
	    		return false;
	    	}
    	}
    });
};

// ¸´ÖĆOOTBµÄfunction getTableHtml(params, divID, doAsync)şŻĘýÔöĽÓÁË»Řµ÷şŻĘý
XmlObject._reloadTableHtml = function(params, divID, doAsync, doFade, successCallback, failCallback) {
   var url = PTC.util.getFormAction(getMainForm());

   if ((currentStepStrName || currentStepStrName === '') && wizardSteps && (wizardSteps[currentStepStrName] || wizardSteps[currentStepStrName] === '')) {
       url  = getPageUrl(wizardSteps[currentStepStrName].url, currentStepStrName);
   }
   var table = PTC.jca.table.Utils.getTable(divID);
   if (table) {
       if (table.fireEvent("beforeComponentRefresh", divID, params) === false) {
           return false;
       }
   }

   if (tableUtils.getTableUrl(table)) {
      // Use table store url directly...
      url = tableUtils.getTableUrl(table);
      params = tableUtils.addTableRefreshParams(table, params);
   }
   else if (params.indexOf("leftPaneOnly")>0) {
     url = window.location.href;
   }
   else if(window.TLN_CONTENT_URL && $("tlnContentArea") && hasParentById ( $(divID), "tlnContentArea")) {
      url = window.TLN_CONTENT_URL;
   }
   return getElementHtml(params, divID, doAsync, url, doFade, successCallback, failCallback);
};

/**
 * ÖŘĐÂË˘ĐÂ˛˘ĽÓÔŘŐű¸ö±í¸ń×éĽţŁ¬¶ř˛»Ö»ĘÇreload data store
 *
 * @param {string} tableId - tableµÄID
 * @param {string or object} params - Ë˘ĐÂĘ±ĐčŇŞ´«ČëµÄ˛ÎĘý,żÉŇÔĘąŇ»¸öQueryString×Ö·ű´®Ł¬»ňŐßĘÇŇ»¸öJSON Object
 * @param {boolean} doAsynch - Ë˘ĐÂĘ±ĘÇ·ń˛ÉÓĂŇě˛˝µÄ·˝Ę˝˝řĐĐÇëÇó,true±íĘľŇě˛˝ÇëÇó
 * @param {boolean} doFade - Ë˘ĐÂĘ±ĘÇ·ńĎÔĘľ˝Ą±äĐ§ąűŁ¬true±íĘľĎÔĘľ˝Ą˝řĐ§ąű
 * @param {function(transport)} successCallback - ČçąűĽÓÔŘłÉą¦Ę±µÄ»Řµ÷şŻĘý
 * @param {function(transport)} failCallback - ČçąűĽÓÔŘĘ§°ÜĘ±µÄ»Řµ÷şŻĘý
 */
XmlObject.refreshTable = function(tableId, params, doAsync, doFade, successCallback, failCallback) {
	tableUtils.removeAll(tableId);//ŇĆłý±í¸ńÖĐËůÓĐĘýľÝĐĐ
	//Ext.getCmp(PTC.jca.table.getWTablePanelID(tableId)).updateTitle();// ¸üĐÂ±íÍ·µÄ¶ÔĎóĘýÁż
	//tableUtils.updateHeader(tableId); //¸üĐÂ±íÍ·µÄ¶ÔĎó¸öĘý
	//tableUtils.updateFooterCount(tableId, getJCASelectedTableItems(tableId).length); //¸üĐÂ±íµ×¶ËµÄ¶ÔĎó¸öĘý
	
    var tableDiv = tableUtils.getFormattedTableId(tableId);
    var formData = tableUtils._formDataForHandleViewChange(tableId);
    if (!(typeof successCallback === 'function')) {
    	successCallback = function() {};
    }
	if (!(typeof failCallback === 'function')) {
    	failCallback = function() {};
    }
	
	var paramString = "";
   	params = params || {};
    if (typeof params == "string") {
    	paramString = params;
    } else if (typeof params == "object") {
    	paramString = Object.toQueryString(params); // ĘąÓĂProtoTypeµÄşŻĘý˝«´«ČëµÄparamsĐňÁĐ»ŻÎŞQuery String
    } else {
    	paramString = "";
    }
    if (typeof doAsync !== 'boolean') {
		doAsync = true;
	}
	if (typeof doFade !== 'boolean') {
		doFade = true;
	}
	// tv.tableid is used for jca tables, sv=<index> is for old legacy nm tables in classic projects
	paramString = 'refreshTable=' + tableDiv + formData + "&" + paramString;
    XmlObject._reloadTableHtml(paramString, tableDiv, doAsync, doFade, successCallback, failCallback);
};

/**
 * ¶ÔOOTBµÄrequestHandler.doRequestşŻĘý˝řĐĐ·â×°,ĘąµĂÔÚWindchillÖĐ·˘ĆđAJAXÇëÇóĘ±Ľě˛ésessionStorageÖĐĘÇ·ń´ćÔÚżÉŇÔÎŞXWORKS_PAGESESSIONIDµÄ
 * ĎîŁ¬Čçąű´ćÔÚ˝«Ćä¶ÔÓ¦µÄÖµĚíĽÓÎŞHTTPÇëÇóµÄµÄHeader:XWORKS_PAGESESSIONID·˘ËÍµ˝·ţÎńĆ÷¶Ë
 *
 */
requestHandler.doRequest = requestHandler.doRequest.wrap(function(orgiFunc, url, options) {
	if (typeof sessionStorage !== "undefined") {
		var pageSessionId = sessionStorage.getItem("XWORKS_PAGESESSIONID");
		if (pageSessionId != null && pageSessionId != undefined && pageSessionId != "") {
			if (!options.requestHeaders) {
				options.requestHeaders = {};
			}
			options.requestHeaders["XWORKS_PAGESESSIONID"] = pageSessionId;
		}
	} else {
		console.log("***WARING***:sessionStorage is not supported by the browser, cannot get XWORKS_PAGESESSIONID!");
	}
	return orgiFunc(url, options);
});

/**
 * ¶ÔOOTBµÄgetMainForm()şŻĘý˝řĐĐ·â×°,ÔÚWindchillÖĐµÄ±íµĄĚá˝»Ę±Ľě˛ésessionStorageÖĐĘÇ·ń´ćÔÚżÉŇÔÎŞXWORKS_PAGESESSIONIDµÄ
 * ĎîŁ¬Čçąű´ćÔÚ˝«Ćä¶ÔÓ¦µÄÖµĚíĽÓÎŞ±íµĄµÄŇţ˛ŘÔŞËŘŇ»˛˘Ěá˝»
 *
 */
getMainForm = getMainForm.wrap(function(orgiFunc, domElement) {
	var mform = orgiFunc(domElement);
    //If the main form somehow lost its nonce, add it back
    if (typeof sessionStorage !== "undefined") {
    	var pageSessionId = sessionStorage.getItem("XWORKS_PAGESESSIONID");
    	if (pageSessionId != null && pageSessionId != undefined && pageSessionId != "") {
			if (!mform.XWORKS_PAGESESSIONID || !mform.XWORKS_PAGESESSIONID.value) {
				if (!mform.XWORKS_PAGESESSIONID || !(mform.XWORKS_PAGESESSIONID[0] && mform.XWORKS_PAGESESSIONID[0].value)) {
					// Čçąű±íµĄÖĐĂ»ÓĐXWORKS_PAGESESSIONID±íµĄÔŞËŘŁ¬Ôň˛ĺČëŇ»¸öĐÂµÄXWORKS_PAGESESSIONID±íµĄÔŞËŘ
			        JCAappendFormHiddenInput(mform, "XWORKS_PAGESESSIONID", pageSessionId);
			    }
			} else if (mform.XWORKS_PAGESESSIONID && (mform.XWORKS_PAGESESSIONID[0] && mform.XWORKS_PAGESESSIONID[0].value)) {
				//ČçąűŇŃÓĐĂűÎŞXWORKS_PAGESESSIONIDµÄ±íµĄÔŞËŘŁ¬Ôň¸üĐÂĆäÖµ
				form.XWORKS_PAGESESSIONID[0].value = pageSessionId;
			}
    	}
    } else {
    	console.log("***WARING***:sessionStorage is not supported by the browser, cannot get XWORKS_PAGESESSIONID!");
    }
    return mform;
});

/**
 * ¶ÔOOTBµÄrequestHandler.getParamString()şŻĘý˝řĐĐ·â×°,ÔÚWindchillÖĐµÄÎŞActionÉúłÉURLĘÇsessionStorageÖĐĘÇ·ń´ćÔÚżÉŇÔÎŞXWORKS_PAGESESSIONIDµÄ
 * ĎîŁ¬Čçąű´ćÔÚ˝«Ćä¶ÔÓ¦µÄÖµĚíĽÓÎŞURLµÄ˛éŃŻ˛ÎĘý
 *
 */
requestHandler.getParamString = requestHandler.getParamString.wrap(function(orgiFunc, params) {
	var result = orgiFunc(params);
	if (result && result.indexOf("XWORKS_PAGESESSIONID") == -1) { // Ľě˛éURLÖĐĂ»ÓĐXWORKS_PAGESESSIONID˛éŃŻ˛ÎĘý
		if (typeof sessionStorage !== "undefined") {
		    var pageSessionId = sessionStorage.getItem("XWORKS_PAGESESSIONID");
	    	if (pageSessionId != null && pageSessionId != undefined && pageSessionId != "") {
	    		result = requestHandler.addURIParam(result, "XWORKS_PAGESESSIONID", pageSessionId);
	    	}
		} else {
			console.log("***WARING***:sessionStorage is not supported by the browser, cannot get XWORKS_PAGESESSIONID!");
		}
	}
	return result;
});


/**
 * @namespace
 * @internal
 */
PTC.trail = Ext.ns('PTC.trail');
PTC.trail.domDump = Ext.ns('PTC.trail.domDump');
PTC.trail.log = log4javascript.getLogger('PTC.trail');

/**
 * A string constant used for ids.
 */
PTC.trail.GENERATED_ID = "jcaGen_";

/**
 * @return false. Trail record/replay mechanism is obsolete as of X-24+,
 *                the trail selenium hybrid testing approach is used instead.
 * @deprecated
 *
 * TODO:
 * cleanup all usages (most left in wt_ma_services VOB) and remove these FALSE_FUNC/TRUE_FUNC definitions entirely.
 */
PTC.trail.isTrailEnabled = FALSE_FUNC;

PTC.trail._loadSupport = TRUE_FUNC;
PTC.trail.waitBeforeCallingFunction = TRUE_FUNC;
PTC.trail.button = {};
PTC.trail.button.record = TRUE_FUNC;
Ext.namespace('PTC.trail.form.combo');
PTC.trail.form.combo.record = TRUE_FUNC;
PTC.trail.tab = {};
PTC.trail.tab.record = TRUE_FUNC;
PTC.trail.wizard = {};
PTC.trail.wizard.wizardLoadCompleteHandler = TRUE_FUNC;

/**
 * a list of dom dump handlers
 * @internal
 */
PTC.trail.DomDumpHandlers = [];

/**
 * Adds the given dom dump handler to a list. The handler is a function that returns a string to be output to the dom dump file.
 * <br>
 * When the wildfire_dom_dump_x20.js file is used for a dom dump, it iterates across each handler in the list of handlers and calls each one.
 * If there is a js file given with a particular handler, that js file is dynamically loaded before the handler is called.
 *
 * Write a handler function that is smart enough to not throw exceptions if the elements to be dumped are not found.
 *
 * @example
 * //add the dom dump handler somewhere in production code
 * PTC.trail.addDomDumpHandler("Table_Dom_Dump", "PTC.trail.table.domDumpHandler", "/netmarkets/javascript/util/domDump/table.js");
 *
 * //then in a separate js file define the function (this js file is not loaded until the dom dump is invoked)
 * PTC.trail.dumpTables = function() {
 *  var tableDump = "Tables ";
 *  //loop across tables and add to the tableDump string.....
 *  return tableDump;
 * }
 *
 * @param {String} handlerId - an id to store the handler with so we can check for duplicates (or so the handler can later be overriden)
 * @param {String} handlerFunctionName - the dom dump handler function to call
 * @param {String} [jsFile] Optional js file where the handler is defined, filepath fully qualified or relative to codebase
 */
//using addDomDumpHandler approach instead of an approach where we'd fire a "domDump" event since listeners are not guaranteed to be called in the same order
//need to ensure the dump handlers are called in the same order from run to run and browser to browser.
PTC.trail.addDomDumpHandler = function(handlerId, handlerFunctionName, jsFile){
    var handlers = PTC.trail.DomDumpHandlers;
    for(var i = 0, l = handlers.length; i < l; i++) {
        var handler = handlers[i];
        if (handlerId === handler.id) {
            //change the existing handler
            handler.func = handlerFunctionName;
            handler.jsFile = jsFile;
            return;
        }
    }

    //add the new handler
    PTC.trail.DomDumpHandlers[handlers.length] = {
        id: handlerId,
        func: handlerFunctionName,
        jsFile: jsFile
    };
};

PTC.trail.addDomDumpHandler("Info_Page_Dom_Dump", "PTC.trail.infoPage.domDumpHandler", "/netmarkets/javascript/util/trail/domDump/infoPage.js");
PTC.trail.addDomDumpHandler("Table_Dom_Dump", "PTC.trail.table.domDumpHandler", "/netmarkets/javascript/util/trail/domDump/table.js");
PTC.trail.addDomDumpHandler("AttributePanel_Dom_Dump", "PTC.trail.attributes.domDumpHandler", "/netmarkets/javascript/util/trail/domDump/attributesPanel.js");

/**
 * Executes the dom dump.
 * Loops across all registered dom dump handlers and return the resulting strings
 *
 * Can call PTC.trail.domDump.execute() from firebug/IE console to debug dom dump issues.
 *
 * @return String of the dom dump output
 */
// For more information on trail dom dumps see this wiki
// http://rdwiki.ptcnet.ptc.com/mediawiki/index.php?title=Trail_Test_Automation_Tips#Where_does_QA_keep_the_dom_dump_files.3F
PTC.trail.domDump.execute = function() {
    // PTC.automation.isAutomationTest returning false for embedded browser?
    // As work-around, force set it for dom dump from hydrid selenium test run.
    // TODO remove this work-around once PTC.automation.isAutomationTest is fixed for embedded browser
    PTC.automation.forceSetAutomationTestState();

    // SPR 2002385 - if any lightbox wizard is open, just dom dump content of that wizard
    var lightbox = document.getElementById('lbContentIframe');
    if(lightbox) {
      return frames['lbContentIframe'].PTC.trail.domDump.execute();
    }

    var result = '';
    PTC.trail.DomDumpHandlers.each(function(handler) {
        try {
            if (handler.jsFile) {
                //load the js file where the handler is defined
                PTC.navigation.loadScript(handler.jsFile);
                // load js file into valid iframes too as these are needed for performing
                // domp dump for content from iframe window
                var iframeCount = frames.length;
                for(var index=0; index<iframeCount; index++) {
                    // focus into genuine iframes (and not ones created by JS framework libraries)
                    if("PTC" in frames[index]) {
                        var frame = frames[index];
                        //load the dom dump handler js file
                        frame.PTC.navigation.loadScript(handler.jsFile);
                    }
                }
            }

            //convert the handler func from string to function
            var func = eval(handler.func);
            //call the dom dump handler
            var dump = func();

            //this workaround needed due to poor initial design of dom dump
            //all new dom dump handlers will add nothing to result string if they return empty string dump
            if(handler.id === 'AttributePanel_Dom_Dump' || handler.id === 'Table_Dom_Dump' || handler.id === 'Info_Page_Dom_Dump') {
                if(dump === '') {
                    dump = 'Nothing dumped from ' + handler.id + ' handler.';
                }
            }

            if(dump === '') {
                PTC.trail.log.debug('Nothing dumped to result string from ' + handler.id + ' handler.');
            } else {
                result += '*--' + handler.id + '--*\n';
                result += dump + '\n\n';
            }
        } catch(e) {
            result += '\nException trying to dump with handler function ' + handler.func + '\n' + e;
            PTC.trail.log.error(e);
        }
    });
    PTC.trail.log.debug(result);
    return result;
};

/**
 * Writes the dom dump output to the dom dump file.
 */
PTC.trail.domDump.write = function() {
    var result = PTC.trail.domDump.execute();
    var cmd = "0debug_void?QcrDump?" + result;
    top.window.external.ptc(cmd);
};


